INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('percy jackson the olympians the lightning thief', 2010, 'Though it may seem like just another Harry Potter knockoff, Percy Jackson benefits from a strong supporting cast, a speedy plot, and plenty of fun with Greek mythology.', TO_DATE('2010-02-06', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('please give', 2010, 'Nicole Holofcener''s newest might seem slight in places, but its rendering of complex characters in a conflicted economic landscape is varied, natural, and touching all the same.', TO_DATE('2010-01-25', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('10', 2000, 'Blake Edwards'' bawdy comedy may not score a perfect 10, but Dudley Moore''s self-deprecating performance makes this midlife crisis persistently funny.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('12 angry men twelve angry men', 2000, 'Sidney Lumet''s feature debut is a superbly written, dramatically effective courtroom thriller that rightfully stands as a modern classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('20000 leagues under the sea', 2000, 'One of Disney''s finest live-action adventures, 20,000 Leagues Under the Sea brings Jules Verne''s classic sci-fi tale to vivid life, and features an awesome giant squid.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('10000 bc', 2008, 'With attention strictly paid to style instead of substance, or historical accuracy, 10,000 B.C. is a visually impressive but narratively flimsy epic.', TO_DATE('2008-03-01', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the 39 steps', 1935, 'Packed with twists and turns, this essential early Alfred Hitchcock feature hints at the dazzling heights he''d reach later in his career.', TO_DATE('1935-08-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lost city', 2005, 'Its heart is in the right place, but what starts as a promising exercise devolves into an overlong, unevenly directed disappointment.', TO_DATE('2005-09-03', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adams rib', 2000, 'Matched by Garson Kanin''s witty, sophisticated screenplay, George Cukor, Spencer Tracy, and Katherine Hepburn are all in top form in the classic comedy Adam''s Rib.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bridge of san luis rey', 2005, 'Despite an all-star cast and some impressive visuals, The Bridge of San Luis Rey is a lifeless, slow-going adaptation of Thornton Wilder''s classic novel.', TO_DATE('2005-06-08', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('criminal', 2004, 'If you saw Nine Queens, it may feel redundant, but the snappy performances make it fun to watch.', TO_DATE('2004-08-22', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deep blue', 2003, 'Full of visually striking footage, Deep Blue may be too intense for younger viewers, but fans of nature documentaries will find much to enjoy.', TO_DATE('2003-11-04', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the adventures of robin hood', 2000, 'Errol Flynn thrills as the legendary title character, and the film embodies the type of imaginative family adventure tailor-made for the silver screen.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tristan isolde', 2006, 'Competent but somewhat static, Tristan & Isolde doesn''t achieve the sweeping romanticism that it aims for.', TO_DATE('2006-01-10', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('running scared', 2006, 'This film runs with frenetic energy punctuated by gratuitous violence but sorely lacks in plot, character development and stylistic flair.', TO_DATE('2006-02-17', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ultraviolet', 2006, 'An incomprehensible and forgettable sci-fi thriller, Ultraviolet is inept in every regard.', TO_DATE('2006-03-03', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('arthur and the invisibles arthur and the minimoys', 2006, 'Arthur wastes its big-name voice talent on a predictable script and substandard CG animation.', TO_DATE('2006-12-26', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eternal', 2004, 'Even by the standards of camp, Eternal fails to entertain.', TO_DATE('2004-11-06', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the matador', 2005, 'This humorously amoral, oddball comic thriller features strong performances by Pierce Brosnan and Greg Kinnear as a flamboyant, aging hit-man and an out of work suburban businessman, respectively.', TO_DATE('2005-02-09', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the intruder lintrus', 2005, 'The impressionistic narrative may confound the viewer, but Denis crafts wonderfully poetic, dreamlike imagery.', TO_DATE('2005-03-22', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saint ralph', 2005, 'Saint Ralph is an amiable tear-jerker that walks a fine line between being inspirational and being hokum.', TO_DATE('2005-04-07', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the baxter', 2005, 'The Baxter is good-natured, but there are simply not enough laughs to fuel this comedy.', TO_DATE('2005-07-17', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oliver twist', 2005, 'Polanski''s version of Dickens'' classic won''t have audiences asking for more because while polished and directed with skill, the movie''s a very impersonal experience.', TO_DATE('2005-08-18', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the alamo', 2000, 'John Wayne proves to be less compelling behind the camera than he is before it in The Alamo, a blustery dramatization of the fort''s last stand that feels more like a first draft.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('g', 2005, 'Race and class struggles come to the Hamptons in this reworking of The Great Gatsby with a hip-hop flavor. Unfortunately, too many subplots and a lack of believable characters spoil an otherwise novel concept.', TO_DATE('2005-09-16', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alfie', 2001, 'Anchored by Michael Caine''s charmingly droll performance, Alfie is an equally raucous and heart-rending portrait of romance in the Swinging ''60s.', TO_DATE('2001-05-12', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aliens', 2000, 'While Alien was a marvel of slow-building, atmospheric tension, Aliens packs a much more visceral punch, and features a typically strong performance from Sigourney Weaver.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all about eve', 2000, 'Smart, sophisticated, and devastatingly funny, All About Eve is a Hollywood classic that only improves with age.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('when do we eat', 2006, 'A crass, sitcom-ish holiday comedy, When Do We Eat? presents all the over-the-top dysfunctional family hijinks one would expect from the genre.', TO_DATE('2006-03-09', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mostly unfabulous social life of ethan green', 2006, 'Ethan Green makes for an annoying protagonist, the jokes aren''t funny, and everyone is as flat as the paper the comic is printed on.', TO_DATE('2006-06-12', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dirty', 2006, 'Dirty is an unoriginal L.A. cop drama that wears its tired influences on its sleeves.', TO_DATE('2006-01-20', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stay alive', 2006, 'A by-the-numbers teen horror flick, Stay Alive fails to exploit its premise for any real scares.', TO_DATE('2006-03-24', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all of me', 2000, 'A high-concept farce carried by Carl Reiner''s deft direction and the precise timing of its leads, All of Me is a body-swap comedy worth holding onto.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('independent lens', 2006, 'Black Gold is an eye-opening account of the winners and losers in the global coffee trade.', TO_DATE('2006-08-04', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all the kings men', 2000, 'Broderick Crawford is spellbinding as politician Willie Stark in director Robert Rossen''s adaptation of the Robert Penn Warren novel about the corrosive effects of power on the human soul.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('street fight', 2006, 'Street Fight takes an immersive ground-level look at a pivotal political race that proves illuminating, entertaining, and inspiring in equal measure.', TO_DATE('2006-02-22', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the motel', 2006, 'A coming-of-age dramedy whose familiar outline is filled in with rewarding empathy and character detail, The Motel marks an impressive feature debut for writer-director Michael Kang.', TO_DATE('2006-05-06', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('once in a lifetime the extraordinary story of the new york cosmos', 2006, 'You don''t have to be a soccer fan to enjoy this stylish, breezy slice of 1970s sports history.', TO_DATE('2006-05-06', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('requiem', 2006, 'This harrowing, naturalistic drama holds you in its grip through Huller''s intense performance.', TO_DATE('2006-04-25', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amazing grace', 2006, 'Amazing Grace is your quintessential historical biopic: stately, noble, and with plenty of electrifying performances.', TO_DATE('2006-09-13', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cocaine cowboys', 2006, 'As frenetic, thrilling, and lacking in subtletly as its drug of focus...and just as likely to prompt some hard questions after it''s gone.', TO_DATE('2006-10-06', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the situation', 2006, 'An ambitious but preachy drama that fails to convincingly parcel its thriller and romance elements.', TO_DATE('2006-10-18', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('slipstream', 2007, 'Slipstream is a failed experiment; confusing instead of coherent.', TO_DATE('2007-01-21', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('delirious', 2007, 'A funny, energetic satire of the paparazzi life and the entertainment industry, Delirious is another winner for indie helmer Tom DiCillo.', TO_DATE('2007-01-23', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('interview', 2007, 'Captivating performances from Steve Buscemi and Sienna Miller make a seemingly simple premise gripping and entertaining.', TO_DATE('2007-01-24', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ten', 2007, 'Although a few of the sketches that make up The Ten are humorous, the uneven and random tone of the film cause it to fall apart.', TO_DATE('2007-01-19', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the happening', 2008, 'The Happening begins with promise, but unfortunately descends into an incoherent and unconvincing trifle.', TO_DATE('2008-06-10', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('molière', 2007, 'Moliere is a sophisticated, witty biopic of the great satirist.', TO_DATE('2007-02-02', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alexandra', 2007, 'At once ethereal and tangible, Aleksandr Sokurov''s humane Chechen War drama features a spectacular turn by opera star Galina Vishnevskay.', TO_DATE('2007-05-24', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cool school', 2007, 'A breezy and lively modern art documentary, revealing that LA is not a cultural wasteland when it comes to fine art.', TO_DATE('2007-07-02', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('disneys a christmas carol', 2009, 'Robert Zemeckis'' 3-D animated take on the Dickens classic tries hard, but its dazzling special effects distract from an array of fine performances from Jim Carrey and Gary Oldman.', TO_DATE('2009-11-02', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deep water', 2006, 'Equal parts mystery and biography, Deep Water is both an engrossing documentary and an affecting treatise on human folly and obsession.', TO_DATE('2006-09-03', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beverly hills chihuahua', 2008, 'Despite hitting some sweet notes, Beverly Hills Chihuahua is little more than disposable family entertainment.', TO_DATE('2008-09-18', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fireflies in the garden', 2008, 'Despite boasting a stellar cast, Fireflies in the Garden is just tedious, dull and predictable melodrama. Instantly forgettable.', TO_DATE('2008-02-10', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the eye', 2008, 'Featuring wooden performances and minimal scares, The Eye is another tedious remake of an Asian horror film.', TO_DATE('2008-01-31', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my best friends girl', 2008, 'My Best Friend''s Girl spends too much time being vulgar and offensive, leaving little room for laughs.', TO_DATE('2008-09-18', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the midnight meat train', 2008, 'A creative and energetic adaptation of a Clive Barker short story, with enough scares and thrills to be a potential cult classic.', TO_DATE('2008-05-02', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lucky ones', 2008, 'The Lucky Ones features heartfelt performances, but is undone by the plot''s overwrought parade of coincidence and contrivance.', TO_DATE('2008-09-11', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('run fatboy run', 2007, 'Run, Fat Boy, Run features sporadic laughs, but is ultimately too formulaic and predictable.', TO_DATE('2007-08-17', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whiteout', 2009, 'Kate Beckinsale is as lovely as ever, and does her best with the material, but moribund pacing and an uninspired plot leave Whiteout in the cold.', TO_DATE('2009-09-10', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wild child', 2008, 'More mild than wild. This tween comedy mess falls flat on its face due to poor characters, poor direction and poor jokes.', TO_DATE('2008-08-14', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('king corn', 2007, 'King Corn takes a thought-provoking look at modern mass food production that deftly balances information and entertainment.', TO_DATE('2007-10-09', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('l avocat de la terreur terrors advocate', 2007, 'Terror''s Advocate is a fascinating portrayal of a controversial political figure; both morally unsettling and emotionally gripping.', TO_DATE('2007-05-18', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('darfur now', 2007, 'Although Darfur Now is not always engaging as cinema, the film succeeds in bringing attention to the crisis in Darfur.', TO_DATE('2007-09-14', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rails ties', 2007, 'Despite the strong cast, Rails & Ties is an emotionally overwrought, not entirely believable melodrama.', TO_DATE('2007-09-02', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr untouchable', 2007, 'The sheer presence of the arrogant and charismatic Nicky Barnes makes Mr. Untouchable a compelling movie experience.', TO_DATE('2007-10-19', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('canvas', 2007, 'Canvas is a faithful portrayal of mental illness highlighted by terrific performances.', TO_DATE('2007-09-04', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saawariya', 2007, 'It''s pleasing to the eye, but Saawariya struggles to fill its runtime with a story whose clichés unfortunately outnumber its points of interest.', TO_DATE('2007-11-08', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flawless', 2007, 'Michael Caine''s excellent performance makes Flawless something more than an average heist movie.', TO_DATE('2007-10-03', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what happens in vegas', 2008, 'What Happens in Vegas has a few laughs, but mostly settles for derivative romantic comedy conventions and receives little help from a pair of unlikable leads.', TO_DATE('2008-05-01', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('appaloosa', 2008, 'A traditional genre western, Appaloosa sets itself apart with smart psychology, an intriguing love triangle, and good chemistry between the leads.', TO_DATE('2008-09-07', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('good', 2008, 'Though ambitious, Good stumbles in the transition from stage to screen, and Mortensen''s performance isn''t enough to cover its flaws.', TO_DATE('2008-09-08', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the visitor', 2007, 'The Visitor is a heartfelt, humanistic drama that deftly explores identity, immigration, and other major post-9/11 issues.', TO_DATE('2007-09-10', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('married life', 2007, 'Married Life has excellent performances and flashes of dark wit, but it suffers from tonal shifts and uneven pacing.', TO_DATE('2007-09-11', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('untraceable', 2008, 'Despite Diane Lane''s earnest effort, Untraceable manages to be nothing more than a run-of-the-mill thriller with a hypocritical message.', TO_DATE('2008-01-13', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the informers', 2009, 'As miserable and insipid as its protagonists, The Informers fails to provide anything to think about after the sheen of fake blond is gone.', TO_DATE('2009-01-22', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('meeting resistance', 2007, 'Meeting Resistance offers a nuanced ground-level view of war''s effects on an invaded people -- and the ways in which they decide to fight back.', TO_DATE('2007-10-16', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the freshman', 1990, 'Buoyed by the charm of Matthew Broderick in the title role and Marlon Brando as a caricature of his Godfather persona, The Freshman benefits from solid casting, a clever premise, and sweet humor.', TO_DATE('1990-07-20', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gutayubaljadeul a bloody aria', 2007, 'Pulpy, bloody and violent, this Korean shock-fest is blackly comedic but disappointing overall.', TO_DATE('2007-10-12', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kenny', 2008, 'Kenny uses its seemingly lowbrow mockumentary premise as the foundation for a well-acted and surprisingly thoughtful character study.', TO_DATE('2008-01-03', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rocker', 2008, 'With a predictable and lightweight story, the earnest efforts of the cast are squandered by The Rocker''s bland script.', TO_DATE('2008-06-17', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the perfect holiday', 2007, 'The Perfect Holiday is the perfect example of Christmas movie clichés run amok.', TO_DATE('2007-12-01', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la graine et le mulet the secret of the grain couscous', 2007, 'A complex portrait of an immigrant family, The Secret of the Grain is a sprawling, intimate film with many fine performances.', TO_DATE('2007-09-03', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('land of the lost', 2009, 'Only loosely based on the original TV series, Land of the Lost is decidedly less kid-friendly and feels more like a series of inconsistent sketches than a cohesive adventure comedy.', TO_DATE('2009-06-01', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rec', 2007, 'Plunging viewers into the nightmarish hellscape of an apartment complex under siege, [Rec] proves that found footage can still be used as an effective delivery mechanism for sparse, economic horror.', TO_DATE('2007-11-05', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('look', 2007, 'Though Adam Rifkin''s voyeuristic film sometimes feels like only a clever gimmick, it''s for the most part a compelling thriller with political overtones.', TO_DATE('2007-11-06', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the box', 2009, 'Imaginative but often preposterous, The Box features some thrills but largely feels too piecemeal.', TO_DATE('2009-10-21', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('man in the chair', 2007, 'A committed performance from Christopher Plummer can''t save Man in the Chair''s troubled and cliched script.', TO_DATE('2007-11-24', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('21', 2008, '21 could have been a fascinating study had it not supplanted the true story on which it is based with mundane melodrama.', TO_DATE('2008-03-08', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the duchess of langeais ne touchez pas la hachedont touch the axe', 2007, 'At times plodding and dialogue heavy, The Duchess of Langeais is nevertheless an intriguing and rewarding dissection of class and gender relations.', TO_DATE('2007-02-15', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ben x', 2007, 'Thoughtful and provocative Dutch film concerned with autism, online gaming and bullying, though loses steam in the final act.', TO_DATE('2007-12-05', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('body of lies', 2008, 'Body of Lies relies on the performances of Russell Crowe and Leonardo DiCaprio to elevate it beyond the conventional espionage thriller.', TO_DATE('2008-10-03', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the grand', 2008, 'The Grand has moments of comic ingenuity, but the jokes in this poker satire often miss.', TO_DATE('2008-01-07', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hammer', 2007, 'The Hammer perseveres as both an above-average sports comedy and a perfect starring vehicle for Carolla.', TO_DATE('2007-04-26', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shutter', 2008, 'Being a remake of a Thai horror film instead of Japanese doesn''t prevent Shutter from being another lame Asian horror remake.', TO_DATE('2008-03-20', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('priest', 2011, 'Sleek and stylish, but those qualities are wasted on a dull, derivative blend of sci-fi, action, and horror.', TO_DATE('2011-05-05', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the broken', 1800, 'A British chiller lacking in strongly drawn characters, The Broken feels unfinished and undercooked.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the escapist', 2008, 'A tense, smart prison break movie, The Escapist is a sharp debut from director Rupert Wyatt.', TO_DATE('2008-01-21', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sugar', 2008, 'Sugar is an exceptionally-crafted film -- part sports flick, part immigrant tale -- with touching and poignant drama highlighted by splendid performances.', TO_DATE('2008-01-24', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('quid pro quo', 2008, 'Despite a stunning performance by Vera Farmiga, Quid Pro Quo never develops its effective parts into a convincing whole.', TO_DATE('2008-01-23', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red', 2008, 'This vengeance film leans heavily on attack-and-avenge scenarios but performances by Brian Cox''s and Tom Sizemore''s take the stink out of any weaker scripting.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the road', 2009, 'The Road''s commitment to Cormac McCarthy''s dark vision may prove too unyielding for some, but the film benefits from hauntingly powerful performances from Viggo Mortensen and Kodi McPhee.', TO_DATE('2009-09-03', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gforce', 2009, 'G-Force features manic action, but fails to come up with interesting characters or an inspired plot.', TO_DATE('2009-07-23', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the other man', 2008, 'Despite the best efforts of a talented cast, The Other Man is talky, witless, and tension-free.', TO_DATE('2008-09-08', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the duchess', 2008, 'While The Duchess treads the now-familiar terrain of the corset-ripper, the costumes look great and Keira Knightley''s performance is stellar in this subtly feminist, period drama.', TO_DATE('2008-09-02', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the women', 2008, 'The Women is a toothless remake of the 1939 classic, lacking the charm, wit and compelling protagonists of the original.', TO_DATE('2008-09-03', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('public enemies', 2009, 'Michael Mann''s latest is a competent and technically impressive gangster flick with charismatic lead performances, but some may find the film lacks truly compelling drama.', TO_DATE('2009-06-24', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('julia', 2008, 'Tilda Swinton delivers a powerful performance in Julia, a tense thriller and a dark character study.', TO_DATE('2008-02-13', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('angel heart', 2000, 'Angel Heart lures viewers into its disturbing, brutal mystery with authentic noir flair and a palpably hypnotic mood.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('old dogs', 2009, 'Its cast tries hard, but Old Dogs is a predictable, nearly witless attempt at physical comedy and moral uplift that misses the mark on both counts.', TO_DATE('2009-11-23', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('surrogates', 2009, 'Though it sports a slick look and feel, Surrogates fails to capitalize on a promising premise, relying instead on mindless action and a poor script.', TO_DATE('2009-09-23', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the promotion', 2008, 'With a workplace-related theme worthy of satire, The Promotion features some sharp witticisms but ultimately disappoints.', TO_DATE('2008-03-10', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('notorious', 2009, 'A biopic that lacks the luster of its subject, Notorious is generic rise-and-fall fare that still functions as a primer for those less familiar with the work and life of the hip hop icon.', TO_DATE('2009-01-05', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('soul men', 2008, 'Soul Men features lively performances from Bernie Mac and Samuel L. Jackson and some hilarious moments, but ultimately suffers from an unoriginal script.', TO_DATE('2008-11-01', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('igor', 2008, 'With an animation style that apes Tim Burton, and a slew of cultural references that aren''t clear enough to reach the crowds, Igor''s patched together antics make it hard to see who the film is trying to please.', TO_DATE('2008-09-11', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sin nombre', 2009, 'Part harrowing immigration tale, part gangster story, this debut by writer/director Cary Fukunaga is sensitive, insightful and deeply authentic.', TO_DATE('2009-02-24', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the stone angel', 2008, 'Despite fine performances from Ellen Burstyn and newcomer Christine Horne, The Stone Angel fails to escape formulaic melodrama territory.', TO_DATE('2008-05-09', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alvin and the chipmunks the squeakquel', 2009, 'This Squeakquel may entertain the kiddies, but it''s low on energy and heavily reliant on slapstick humor.', TO_DATE('2009-12-18', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('un conte de noël a christmas tale', 2008, 'A sharp black comedy about a chaotic family holiday gathering, A Christmas Tale is always involving, thanks to an impressive ensemble cast.', TO_DATE('2008-05-16', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('1000 times good night', 2013, 'Beautifully filmed and powerfully acted, 1,000 Times Good Night achieves absorbing fact-based drama without overindulging in Hollywood contrivances.', TO_DATE('2013-12-07', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('push', 2009, 'The sci-fi thriller Push is visually flashy but hyperkinetic and convoluted.', TO_DATE('2009-02-02', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('felon', 2008, 'Felon offers a rather hackneyed depiction of prison life, but is held together by a pleasantly complex plot and solid performances from Kilmer and Dorff.', TO_DATE('2008-07-14', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scar', 2007, 'A nasty, witless and unoriginal entry into the torture porn canon with hopeless acting and a waste of modern 3D technology.', TO_DATE('2007-05-20', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the unborn', 2009, 'David Goyer''s Unborn is a tame genre effort with cheap thrills and scares that border on silliness.', TO_DATE('2009-01-06', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chocolate', 2008, 'Chocolate is a bizarre martial arts flick, with a slushy plot, an unusual protagonist, and breathtaking stunts.', TO_DATE('2008-02-06', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('splinter', 2008, 'Never taking itself too seriously, Splinter scores as a fast-paced, fun thriller with more than enough scares.', TO_DATE('2008-09-17', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('leaves of grass', 2009, 'Edward Norton delivers one of his finest performances in Leaves of Grass, but he''s overpowered by the movie''s many jarring tonal shifts.', TO_DATE('2009-09-15', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the proposal', 2009, 'Sandra Bullock and Ryan Reynolds exhibit plenty of chemistry, but they''re let down by The Proposal''s devotion to formula.', TO_DATE('2009-06-12', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gigantic', 2008, 'This overly quirky, incessantly whimsical indie is too self-conscious for its own good.', TO_DATE('2008-11-07', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('orphan', 2009, 'While it has moments of dark humor and the requisite scares, Orphan fails to build on its interesting premise and degenerates into a formulaic, sleazy horror/thriller.', TO_DATE('2009-07-22', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my sisters keeper', 2009, 'My Sister''s Keeper gets fine performances from its adult and child actors, but the director''s heavy-handed approach turns a worthy emotional subject into an overly melodramatic tearjerker.', TO_DATE('2009-06-22', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hangover', 2009, 'With a clever script and hilarious interplay among the cast, The Hangover nails just the right tone of raunchy humor, and the non-stop laughs overshadow any flaw.', TO_DATE('2009-05-23', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the stepfather', 2009, 'This tepid remake of the 1987 cult classic lacks the tension and satirical undercurrents of the original.', TO_DATE('2009-10-15', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('okuribito departures', 2009, 'If slow and predictable, Departures is a quiet, life affirming story.', TO_DATE('2009-01-19', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boogie summer holiday', 2009, 'Tough, bittersweet and sharply observed Romanian drama, with impressive and intelligent directing.', TO_DATE('2009-01-16', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('prima ballerina', 2009, 'A straightforward documentary about five Russian ballerinas, Bertrand Normand''s Ballerina is enlivened by a fairy-tale sensibility.', TO_DATE('2009-01-14', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('season of the witch', 2011, 'Slow, cheap-looking, and dull, Season of the Witch fails even as unintentional comedy.', TO_DATE('2011-01-02', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shuttle', 2008, 'While this debut by Edward Anderson is economical and occasionally effective, Shuttle offers little catharsis after its tense ride.', TO_DATE('2008-03-08', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miss march', 2009, 'Even by the modest standards of the teen sex comedy genre, the crass, poorly-madeMiss March misses the mark.', TO_DATE('2009-03-11', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an american affair', 2009, 'With a plot both undercooked and cliche riddled, An American Affair unsuccessfully mixes a coming-of-age story and a presidential conspiracy thriller.', TO_DATE('2009-02-17', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grace', 2009, 'Though not entirely effective as a conventional horror flick, Grace is still a graphic, disturbing, and artful exploration of twisted maternal instinct.', TO_DATE('2009-02-02', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the red baron der rote baron', 2008, 'It doesn''t lack ambition, and it boasts undeniably thrilling source material, but The Red Baron is brought down by its overly sentimental script and a number of historical inaccuracies.', TO_DATE('2008-03-31', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happy tears', 2009, 'Replete with quirky indie cliches, Happy Tears wastes some fine performances from Demi Moore, Parker Posey, and Rip Torn on stale formula.', TO_DATE('2009-02-06', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mammoth mammut', 2009, 'While it features a sterling cast, Mammoth''s elephantine scope is too sprawling for it to maintain dramatic focus.', TO_DATE('2009-02-13', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crude', 2009, 'Dynamic, tightly arranged, and deliberately provocative, Joe Berlinger''s Crude is a sobering, enraging wake-up call.', TO_DATE('2009-06-29', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the messenger', 2009, 'A dark but timely subject is handled deftly by writer/directer Owen Moverman and superbly acted by Woody Harrleson and Ben Foster.', TO_DATE('2009-10-08', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('venkovský ucitel the country teacher', 2008, 'Bohdan Slama''s stunningly filmed dramedy is loaded with full-bodied characters and quietly sincere performances.', TO_DATE('2008-03-20', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the apartment', 2000, 'Director Billy Wilder''s customary cynicism is leavened here by tender humor, romance, and genuine pathos.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fame', 2009, 'Fame is ultimately undone by its choppy editing, its incomplete characterizations, and its apparent desire to appeal to the High School Musical generation.', TO_DATE('2009-09-24', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('outrage', 2009, 'Outrage walks a difficult moral and ethical line -- and not always successfully -- but despite its flaws, it''s a fascinating, provocative look at homosexuality in American politics.', TO_DATE('2009-04-28', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('skin', 2009, 'Sophie Okonedo, Sam Neill, and Alice Krige do wonderful work in Skin, delivering performances whose strength is underlined by the incredible real-life events upon which the movie is based.', TO_DATE('2009-07-24', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('helen', 2009, 'This enigmatic debut British/Irish feature is beautifully photographed and has an intriguing premise, marking its makers out as talent to watch.', TO_DATE('2009-05-01', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bakjwi thirst', 2009, 'The stylish Thirst packs plenty of bloody thrills to satisfy fans of both vampire films and director Chan Wook Park.', TO_DATE('2009-04-30', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blood the last vampire', 2009, 'Based on a classic anime series, Blood: The Last Vampire is a tedious, shoddily acted, amateurish picture that loses all charm in the transition to live-action.', TO_DATE('2009-06-09', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shrink', 2009, 'Kevin Spacey''s performance is almost sharp enough to save this Hollywood dramedy from itself, but in the end, he''s dragged down by a cliched script and indifferent direction.', TO_DATE('2009-07-21', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ong bak 2', 2009, 'It suffers from comparisons to its predecessor -- not to mention Tony Jaa''s less-than-nimble direction -- but Ong Bak 2 has all the extravagant violence and playful style that fans of the original will expect.', TO_DATE('2009-07-20', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tron legacy', 2010, 'Tron Legacy boasts dazzling visuals, but its human characters and story get lost amidst its state-of-the-art production design.', TO_DATE('2010-10-16', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chloe', 2009, 'Despite its promising pedigree and a titillating premise, Chloe ultimately fails to deliver the heat -- or the thrills -- expected of a sexual thriller.', TO_DATE('2009-09-18', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hole', 2009, 'A welcome throwback to the suburban teen thrillers of the 1980s, The Hole is a scary, enjoyable return to form for director Joe Dante.', TO_DATE('2009-09-13', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('high life', 2009, 'High Life is as visually arresting as it is challenging, confounding, and ultimately rewarding - which is to say it''s everything film fans expect from director Claire Denis.', TO_DATE('2009-09-15', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('around the world in 80 days', 1956, 'It''s undeniably shallow, but its cheerful lack of pretense -- as well as its grand scale and star-stuffed cast -- help make Around the World in 80 Days charmingly light-hearted entertainment.', TO_DATE('1956-10-17', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wonderful world', 2009, 'Matthew Broderick gives an appealing performance and director Joshua Goldin''s script contains unexpected bursts of honest emotion, but Wonderful World''s good intentions can''t make up for its lack of originality.', TO_DATE('2009-12-30', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('collapse', 2009, 'Collapse can''t prove its subject''s theories, but it poses too many terrifyingly sobering questions to turn away from or ignore.', TO_DATE('2009-11-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last song', 2010, 'As shamelessly manipulative as any Nicholas Sparks production, The Last Song is done no favors by its miscast and overmatched star, Miley Cyrus.', TO_DATE('2010-03-25', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('babies', 2010, 'Babies is a joyous celebration of humankind that''s loaded with adorable images, but it lacks insight and depth.', TO_DATE('2010-04-29', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lottery ticket', 2010, 'There''s a worthwhile message at the heart of Lottery Ticket, but it''s buried under stale humor, tired stereotypes, and obvious clichés.', TO_DATE('2010-08-13', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('going the distance', 2010, 'It''s timelier and a little more honest than most romantic comedies, but Drew Barrymore and Justin Long''s screen chemistry doesn''t make up for Going the Distance''s overall flatness.', TO_DATE('2010-08-19', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('life as we know it', 2010, 'Katherine Heigl and Josh Duhamel make a charming couple with plenty of chemistry, but that isn''t enough to make up for Life as We Know It''s formulaic plot and poorly written script.', TO_DATE('2010-10-03', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frozen', 2010, 'Writer/director Adam Green has the beginnings of an inventive, frightening yarn in Frozen, but neither the script nor the cast are quite strong enough to truly do it justice.', TO_DATE('2010-01-23', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('prodigal sons', 2010, 'Fascinating and heartbreakingly honest, Kimberly Reed''s family documentary uses its stranger-than-fiction story to speak near-universal truths about family bonds and human identity.', TO_DATE('2010-02-21', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ghost writer', 2010, 'While it may lack the revelatory punch of Polanski''s finest films, Ghost Writer benefits from stylish direction, a tense screenplay, and a strong central performance from Ewan McGregor.', TO_DATE('2010-02-15', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('repo men', 2010, 'Repo Men has an intriguing premise, as well as a likable pair of leads, but they''re wasted on a rote screenplay, indifferent direction, and mind-numbing gore.', TO_DATE('2010-03-16', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('daddy longlegs', 2010, 'Raw, honest, and jarring, Daddy Longlegs sets a spellbinding new standard for DIY cinema.', TO_DATE('2010-05-11', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('winters bone', 2010, 'Bleak, haunting, and yet still somehow hopeful, Winter''s Bone is writer-director Debra Granik''s best work yet -- and it boasts an incredible, starmaking performance from Jennifer Lawrence.', TO_DATE('2010-01-26', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kids are all right', 2010, 'Worthwhile as both a well-acted ensemble piece and as a smart, warm statement on family values, The Kids Are All Right is remarkable.', TO_DATE('2010-01-26', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stolen', 2010, 'With plot points Stolen from countless superior films, this would-be thriller squanders a solid cast on overly serious and suspense-free storytelling.', TO_DATE('2010-03-03', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('predators', 2010, 'After a string of subpar sequels, this bloody, action-packed reboot takes the Predator franchise back to its testosterone-fueled roots.', TO_DATE('2010-07-05', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stonewall uprising', 2010, 'Stonewall Uprising offers a compelling primer on a pivotal moment in American history, using the memories of those who lived through it.', TO_DATE('2010-06-13', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('arthur', 2002, 'Dudley Moore brings a boozy charm to Arthur, a coming of age tale for a wayward millionaire that deploys energetic cast chemistry and spiffy humor to jovial effect.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('assault on precinct 13', 2000, 'Lean, taut and compellingly gritty, John Carpenter''s loose update of Rio Bravo ranks as a cult action classic and one of the filmmaker''s best.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bad news bears', 1976, 'The Bad News Bears is rude, profane, and cynical, but shot through with honest, unforced humor, and held together by a deft, understated performance from Walter Matthau.', TO_DATE('1976-04-07', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bang the drum slowly', 2001, 'Bang the Drum Slowly is a touching melodrama that explores the inner workings of a baseball club and its players'' personalities with remarkable depth.', TO_DATE('2001-04-26', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beauty and the beast la belle et la bête', 2000, 'With its magical optical effects and enchanting performances, Jean Cocteau''s Beauty and the Beast remains the most surreal -- and soulful -- of the fairy tale''s film adaptations.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the big sleep', 2000, 'A perfect match of screenplay, director, and leading man, The Big Sleep stands as a towering achievement in film noir whose grim vitality remains undimmed.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the birds', 1963, 'Proving once again that build-up is the key to suspense, Alfred Hitchcock successfully turned birds into some of the most terrifying villains in horror history.', TO_DATE('1963-03-28', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black christmas', 2002, 'The rare slasher with enough intelligence to wind up the tension between bloody outbursts, Black Christmas offers fiendishly enjoyable holiday viewing for genre fans.', TO_DATE('2002-02-28', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the black hole', 2000, 'While lavishly crafted and brimming with ambitious ideas, The Black Hole probes the depths of space with an unexciting story and hokey melodrama.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black rain', 2001, 'Black Rain has its fair share of Ridley Scott''s directorial flair, but its paint-by-numbers story never rises above genre conventions.', TO_DATE('2001-08-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black sunday', 2003, 'A smart, tense thriller from director John Frankenheimer, Black Sunday succeeds on a technical level, even if it fails to bring its characters to vivid life.', TO_DATE('2003-05-20', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blind date', 2000, 'Blind Date has all the ingredients for a successful madcap comedy, but the end results suggest director Blake Edwards has lost his once-reliable touch.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('der blaue engel the blue angel', 2000, 'Marlene Dietrich steals more than one show in this backstage tragedy about a lowly professor besotted with a cruel and enigmatic singer.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('born yesterday', 2002, 'Marrying screwball romance with political satire, Born Yesterday is a substantive romp with a ferociously smart performance by Judy Holliday as an uncouth bombshell.', TO_DATE('2002-07-14', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bounty', 2000, 'Thanks in large part to its cast, and Anthony Hopkins in particular, The Bounty''s retelling of the mutiny on the HMS Bounty is an intelligent, engaging adventure saga.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the boys from brazil', 2000, 'Its story takes some dubious turns, but a high-caliber cast and a gripping pace fashion The Boys from Brazil into an effective thriller.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brewsters millions', 2002, 'With Richard Pryor''s trademark ribald humor tamped down, Brewster''s Millions feels like a missed opportunity to update a classic story.', TO_DATE('2002-05-04', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brians song', 2002, 'Buoyed by standout performances from James Caan and Billy Dee Williams, Brian''s Song is a touching tale of friendship whose central relationship transcends its standard sports movie moments.', TO_DATE('2002-08-14', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brief encounter', 2000, 'Brief Encounter adds a small but valuable gem to the Lean filmography, depicting a doomed couple''s illicit connection with affecting sensitivity and a pair of powerful performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('broken blossoms', 2000, 'Thought-provoking and beautifully filmed, D.W. Griffith''s Broken Blossoms presents a master at the top of his form.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('butch cassidy and the sundance kid', 2000, 'With its iconic pairing of Paul Newman and Robert Redford, jaunty screenplay and Burt Bacharach score, Butch Cassidy and the Sundance Kid has gone down as among the defining moments in late-''60s American cinema.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bye bye birdie', 2000, 'A poppy satire on pop music, Bye Bye Birdie is silly, light, and very, very pink.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cape fear', 2001, 'An exemplary thriller powered by Robert Mitchum''s chilling performance and Bernard Herrmann''s sinister score, Cape Fear seethes with perfectly modulated tension.', TO_DATE('2001-09-26', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('carnival of souls', 2000, 'Carnival of Souls offers delightfully chilling proof that when it comes to telling an effective horror story, less can often be much, much more.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('carrie', 2000, 'Carrie is a horrifying look at supernatural powers, high school cruelty, and teen angst -- and it brings us one of the most memorable and disturbing prom scenes in history.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('casablanca', 1943, 'An undisputed masterpiece and perhaps Hollywood''s quintessential statement on love and romance, Casablanca has only improved with age, boasting career-defining performances from Humphrey Bogart and Ingrid Bergman.', TO_DATE('1943-06-01', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('casino royale', 2002, 'A goofy, dated parody of spy movie clichés, Casino Royale squanders its all-star cast on a meandering, mostly laugh-free script.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cat on a hot tin roof', 2000, 'Paul Newman and Elizabeth Taylor are at the height of their glamor and performing prowess in this feverish adaptation of Tennessee Williams'' play, with a subtext of sexual repression providing an electric undercurrent.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cat people', 2000, 'Influential noir director Jacques Tourneau infused this sexy, moody horror film with some sly commentary about the psychology and the taboos of desire.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cat people', 2000, 'Paul Schrader''s kinky reimagining of Cat People may prove too grisly and lurid for some audiences, but its provocative style and Natassja Kinski''s hypnotic performance should please viewers who like a little gasoline with their fire.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('charade', 1963, 'A globetrotting caper that prizes its idiosyncratic pieces over the general puzzle, Charade is a delightful romp with Cary Grant and Audrey Hepburn''s sparkling chemistry at the center of some perfectly orchestrated mayhem.', TO_DATE('1963-12-05', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('charlottes web', 2001, 'That''s some pig, with spirited vocal performances and a charmingly family-friendly adaptation of E.B. White''s winsome story spun around him.', TO_DATE('2001-06-09', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('children of the corn', 2002, 'Children of the Corn''s strong premise and beginning gets shucked away for a kiddie thriller that runs in circles.', TO_DATE('2002-06-23', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a christmas story', 1983, 'Both warmly nostalgic and darkly humorous, A Christmas Story deserves its status as a holiday perennial.', TO_DATE('1983-11-18', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cimarron', 1931, 'Cimarron is supported by a strong performance from Irene Dunne, but uneven in basically every other regard, and riddled with potentially offensive stereotypes.', TO_DATE('1931-01-26', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cleopatra', 2001, 'Cleopatra is a lush, ostentatious, endlessly eye-popping epic that sags collapses from a (and how could it not?) four-hour runtime.', TO_DATE('2001-03-21', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('colors', 1988, 'Colors takes a hard-hitting yet nuanced look at urban gang violence, further elevated by strong performances from a pair of well-matched leads.', TO_DATE('1988-04-15', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('commando', 2000, 'The ultimate ''80s Schwarzenegger movie, replete with a threadbare plot, outsized action, and endless one-liners.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('creature from the black lagoon', 2000, 'A solid, atmospheric creature feature that entertains without attempting to be deeper than it needs.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dangerous liaisons', 1988, 'Stylish, seductive, and clever, Stephen Frears'' adaptation is a wickedly entertaining exploration of sexual politics.', TO_DATE('1988-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('day of the dead', 2000, 'Day of the Dead may arguably be the least haunting entry in George A. Romero''s undead trilogy, but it will give audiences'' plenty to chew on with its shocking gore and scathing view of society.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the day the earth stood still', 1951, 'Socially minded yet entertaining, The Day the Earth Stood Still imparts its moral of peace and understanding without didacticism.', TO_DATE('1951-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('death in venice', 2003, 'Luchino Visconti''s Death in Venice is one of his emptier meditations on beauty, but fans of the director will find his knack for sumptuous visuals remains intact.', TO_DATE('2003-01-23', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('doctor zhivago', 2000, 'It may not be the best of David Lean''s epics, but Dr. Zhivago is still brilliantly photographed and sweepingly romantic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dr jekyll and mr hyde', 2001, 'A classic. The definitive version of the Robert Louis Stevenson novella from 1931, with innovative special effects, atmospheric cinematography and deranged overacting.', TO_DATE('2001-09-25', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how the grinch stole christmas', 2000, 'How the Grinch Stole Christmas brings an impressive array of talent to bear on an adaptation that honors a classic holiday story -- and has rightfully become a yuletide tradition of its own.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dracula', 2000, 'Bela Lugosi''s timeless portrayal of Dracula in this creepy and atmospheric 1931 film has set the standard for major vampiric roles since.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dragnet', 2000, 'While it''s sporadically funny and certainly well-cast, Dragnet is too clumsy and inconsistent to honor its classic source material.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dressed to kill', 2001, 'With arresting visuals and an engrossingly lurid mystery, Dressed to Kill stylishly encapsulates writer-director Brian De Palma''s signature strengths.', TO_DATE('2001-08-28', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('duel', 2000, 'Duel makes brilliant use of its simple premise, serving up rock-solid genre thrills while heralding the arrival of a generational talent behind the lens.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dune', 1984, 'This truncated adaptation of Frank Herbert''s sci-fi masterwork is too dry to work as grand entertainment, but David Lynch''s flair for the surreal gives it some spice.', TO_DATE('1984-12-14', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the elephant man', 2000, 'David Lynch''s relatively straight second feature finds an admirable synthesis of compassion and restraint in treating its subject, and features outstanding performances by John Hurt and Anthony Hopkins.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the enforcer', 2000, 'Though the slightest hints of series fatigue begin to emerge, The Enforcer delivers riveting action and better humor than its predecessors.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('escape from new york', 2000, 'Featuring an atmospherically grimy futuristic metropolis, Escape from New York is a strange, entertaining jumble of thrilling action and oddball weirdness.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fahrenheit 451', 2000, 'Fahrenheit 451 is an intriguing film that suffuses Truffaut''s trademark wit and black humor with the intelligence and morality of Ray Bradbury''s novel.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fatal attraction', 1987, 'A potboiler in the finest sense, Fatal Attraction is a sultry, juicy thriller that''s hard to look away from once it gets going.', TO_DATE('1987-09-11', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('father of the bride', 2000, 'With a terrific script, great performances from Spencer Tracy and Elizabeth Taylor, and assured direction from Vincent Minnelli, Father of the Bride endures as a sparkling comedy of its era.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flash gordon', 1980, 'Campy charm and a knowing sense of humor help to overcome a silly plot involving a spacefaring ex-football player, his adoring bevy of groupies, and a supervillain named Ming the Merciless.', TO_DATE('1980-12-05', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fly', 2001, 'Deliciouly funny to some and eerily presicient to others, The Fly walks a fine line between shlocky fun and unnerving nature parable.', TO_DATE('2001-07-25', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fly', 2000, 'David Cronenberg combines his trademark affinity for gore and horror with strongly developed characters, making The Fly a surprisingly affecting tragedy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('footloose', 2000, 'There''s not much dancing, but what''s there is great. The rest of the time, Footloose is a nice hunk of trashy teenage cheese.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frantic', 2000, 'A tense, on-point thriller in the vein of Polanski''s earlier work.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('freaky friday', 1976, 'Freaky Friday is too well-behaved to live up to its comedic potential, but sprightly turns by Barbara Harris and Jodie Foster give the body-swapping farce some charm.', TO_DATE('1976-12-17', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fright night', 2000, 'Fright Night deftly combines thrills and humor in this ghostly tale about a man living next to a vampire.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('from here to eternity', 2000, 'It has perhaps aged poorly, but this languidly paced WWII romance remains an iconic, well-acted film, featuring particularly strong performances from Burt Lancaster and Montgomery Clift.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frosty the snowman', 2004, 'Frosty the Snowman is a jolly, happy sing-along that will delight children with its crisp animation and affable title character, who makes an indelible impression with his corncob pipe, button nose, and eyes made out of coal.', TO_DATE('2004-12-10', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fury', 2000, 'Brian De Palma reins in his stylistic flamboyance to eerie effect in The Fury, a telekinetic slow burn that rewards patient viewers with its startling set pieces.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gallipoli', 2001, 'Peter Weir''s devastating anti-war film features a low-key but emotionally wrenching performance from Mel Gibson as a young soldier fighting in one of World War I''s most deadly and horrifying battles.', TO_DATE('2001-11-06', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the general', 2000, 'Brilliantly filmed and fueled with classic physical comedy, The General captures Buster Keaton at his timeless best.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the getaway', 2001, 'The Getaway sees Sam Peckinpah and Steve McQueen, the kings of violence and cool, working at full throttle.', TO_DATE('2001-10-23', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gloria', 2000, 'A comparatively commercial entry from director John Cassavetes, Gloria''s pulpy pleasures are elevated by his observant touch and Gena Rowlands'' galvanizing star performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('glory', 2000, 'Bolstered by exceptional cinematography, powerful storytelling, and an Oscar-winning performance by Denzel Washington, Glory remains one of the finest Civil War movies ever made.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the great gatsby', 2002, 'The Great Gatsby proves that even a pair of tremendously talented leads aren''t always enough to guarantee a successful adaptation of classic literary source material.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hairspray', 2000, 'Hairspray is perhaps John Waters'' most accessible film, and as such, it''s a gently subversive slice of retro hilarity.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('halloween', 2000, 'Scary, suspenseful, and viscerally thrilling, Halloween set the standard for modern horror films.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hamlet', 2000, 'A well-executed labor of love from star and director Laurence Olivier, Hamlet not only proved that Shakespeare could be successfully adapted to the big screen, it paved the way for further cinematic interpretations.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hardcore', 2000, 'Director Paul Schrader''s preoccupations with alienation and faith are given a compelling avatar in George C. Scott''s superb performance, although some audiences may find Hardcore too soft to live up to its provocative promise.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the haunting', 2000, 'Both psychological and supernatural, The Haunting is a chilling character study.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heaven can wait', 1978, 'A throwback to the high-gloss screwball comedies of the 1940s, Heaven Can Wait beguiles with seamless production values and great comic relief from Charles Grodin and Dianne Cannon.', TO_DATE('1978-06-28', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hidden fortress kakushitoride no sanakunin', 2001, 'A feudal adventure told from an eccentric perspective, The Hidden Fortress is among Akira Kurosawa''s most purely enjoyable epics.', TO_DATE('2001-06-10', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hills have eyes', 2000, 'When it''s not bludgeoning the viewer with its more off-putting, cruder elements, The Hills Have Eyes wields some clever storytelling and a sly sense of dark humor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('100 streets', 2016, '100 Streets strands its talented cast - led by a clearly overqualified Idris Elba - in the midst of a well-meaning but fatally contrived drama.', TO_DATE('2016-10-19', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('house of wax', 2000, 'House of Wax is a 3-D horror delight that combines the atmospheric eerieness of the wax museum with the always chilling presence of Vincent Price.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('house on haunted hill', 2000, 'Campy by modern standards but spooky and atmospheric, House on Haunted Hill is a fun, well-executed cult classic featuring a memorable performance from genre icon Vincent Price.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hud', 2000, 'A Western that swaps out the Hollywood glamor for shades of moral gray, Hud is a sobering showcase for a sterling ensemble of actors at the top of their respective games.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hunchback of notre dame', 2002, 'A heart-rending take on the classic book, with a legendary performance by Lon Chaney.', TO_DATE('2002-03-28', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('imitation of life', 1958, 'Douglas Sirk enriches this lush remake of Imitation of Life with racial commentary and a sharp edge, yielding a challenging melodrama with the power to devastate.', TO_DATE('1958-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the importance of being earnest', 2000, 'An artfully assembled cast, lovely set design, and direction solidly in service of the source material make The Importance of Being Earnest an adaptation that works.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in cold blood', 2000, 'In Cold Blood is a classic docudrama with a fictional thriller''s grip -- and a pair of terrific lead performances from Robert Blake and Scott Wilson.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('indiscreet', 2002, 'Indiscreet spins rom-com gold out of a premise just sturdy enough to set the stage for typically delightful work from its wonderfully well-matched leads.', TO_DATE('2002-07-30', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('intolerance', 2000, 'A pioneering classic and one of the most influential films ever made, D.W. Griffith''s Intolerance stands as the crowning jewel in an incredible filmography.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('invasion of the body snatchers', 2000, 'One of the best political allegories of the 1950s, Invasion of the Body Snatchers is an efficient, chilling blend of sci-fi and horror.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('invasion of the body snatchers', 2000, 'Employing gritty camerawork and evocative sound effects, Invasion of the Body Snatchers is a powerful remake that expands upon themes and ideas only lightly explored in the original.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the invisible man', 2000, 'James Whale''s classic The Invisible Man features still-sharp special effects, loads of tension, a goofy sense of humor, and a memorable debut from Claude Rains.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the island of dr moreau', 2000, 'The Island of Dr. Moreau takes a reasonably entertaining pass at adapting its classic source material, although key scenes are let down by struggles with special effects.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('its alive', 2002, 'Tough and unpleasant, It''s Alive throttles the viewer with its bizarre mutant baby theatrics.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jason and the argonauts', 2000, 'Don Chaffey''s Jason and the Argonauts is an outlandish, transportive piece of nostalgia whose real star is the masterful stop-motion animation work of Ray Harryhausen.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the jazz singer', 2000, 'Neil Diamond''s foray into acting is a total miss in this gaudy and unconvincing remake, with Laurence Olivier on hand to deliver an excruciatingly campy performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jesus christ superstar', 2000, 'Jesus Christ Superstar has too much spunk to fall into sacrilege, but miscasting and tonal monotony halts this musical''s groove.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('julius caesar', 2000, 'A sterling cast gives Shakespeare''s tale of betrayal and reprisals body and fine form, with Marlon Brando displaying a galvanizing command over the Bard''s language.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('king kong', 2000, 'King Kong explores the soul of a monster -- making audiences scream and cry throughout the film -- in large part due to Kong''s breakthrough special effects.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('king kong', 2000, 'King Kong represents a significant visual upgrade over the original, but falls short of its classic predecessor in virtually every other respect.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the king of comedy', 2000, 'Largely misunderstood upon its release, The King of Comedy today looks eerily prescient, and features a fine performance by Robert DeNiro as a strangely sympathetic psychopath.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('king of kings', 2000, 'With enough narrative depth to anchor the expected spectacle, King of Kings is a true blessing for fans of Biblical epics.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lady vanishes', 2000, 'One of Alfred Hitchcock''s last British films, this glamorous thriller provides an early glimpse of the director at his most stylishly entertaining.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ladykillers', 2002, 'The Ladykillers is a macabre slow-burn with quirky performances of even quirkier characters.', TO_DATE('2002-01-27', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('laura', 2000, 'A psychologically complex portrait of obsession, Laura is also a deliciously well-crafted murder mystery.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('legend', 2000, 'Not even Ridley Scott''s gorgeously realized set pieces can save Legend from its own tawdry tale -- though it may be serviceable for those simply looking for fantasy eye candy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lion in winter', 2000, 'Sharper and wittier than your average period piece, The Lion in Winter is a tale of palace intrigue bolstered by fantastic performances from Peter O''Toole, Katharine Hepburn, and Anthony Hopkins in his big-screen debut.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the little drummer boy', 2018, 'The Little Drummer Boy is a mature addition to the Rankin-Bass catalogue, with a powerful conclusion that compensates for the special''s dour storytelling and unpolished animation.', TO_DATE('2018-12-04', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little shop of horrors', 2000, 'Remixing Roger Corman''s B-movie by way of the Off-Broadway musical, Little Shop of Horrors offers camp, horror and catchy tunes in equal measure -- plus some inspired cameos by the likes of Steve Martin and Bill Murray.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lolita', 2000, 'Kubrick''s Lolita adapts its seemingly unadaptable source material with a sly comedic touch and a sterling performance by James Mason that transforms the controversial novel into something refreshingly new without sacrificing its essential edge.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the longest yard', 2001, 'Equal parts tough and funny, and led by a perfectly cast Burt Reynolds, The Longest Yard has an interesting political subtext and an excellent climax -- even if it takes too long to get there.', TO_DATE('2001-01-01', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('m', 2000, 'A landmark psychological thriller with arresting images, deep thoughts on modern society, and Peter Lorre in his finest performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the magic flute trollflöjten', 2000, 'Fleet and joyous, Ingmar Bergman''s filmed staging of Mozart''s The Magic Flute captures the opera''s mirth and satire with Scandinavian flair.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the magnificent ambersons', 2000, 'Assembled with bold visual craft and penetrating insight, The Magnificent Ambersons further establishes writer-director Orson Welles as a generational talent.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the magnificent seven', 1960, 'The Magnificent Seven transplants Seven Samurai into the Old West with a terrific cast of Hollywood stars -- and without losing any of the story''s thematic richness.', TO_DATE('1960-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the maltese falcon', 2000, 'Suspenseful, labyrinthine, and brilliantly cast, The Maltese Falcon is one of the most influential noirs -- as well as a showcase for Humphrey Bogart at his finest.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a man for all seasons', 2000, 'Solid cinematography and enjoyable performances from Paul Scofield and Robert Shaw add a spark to this deliberately paced adaptation of the Robert Bolt play.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the manchurian candidate', 2000, 'A classic blend of satire and political thriller that was uncomfortably prescient in its own time, The Manchurian Candidate remains distressingly relevant today.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('manhunter', 2000, 'Michael Mann introduces audiences to Hannibal Lecter for the first time in Manhunter, a modish thriller that fleshes out Thomas Harris'' heinous creations with an elegant, chilling detachment.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mannequin', 2000, 'Mannequin is a real dummy, outfitted with a ludicrous concept and a painfully earnest script that never springs to life, despite the best efforts of an impossibly charming Kim Cattrall.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marty', 2000, 'Scriptwriter Paddy Chayefsky''s solid dialogue is bolstered by strong performances from Ernest Borgnine and Betsy Blair in this appealingly low-key character study.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('meteor', 2000, 'Meteor is a flimsy flick with too much boring dialogue and not enough destruction. At least the pinball game is decent.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('metropolis', 2000, 'A visually awe-inspiring science fiction classic from the silent era.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mission', 2000, 'The Mission is a well-meaning epic given delicate heft by its sumptuous visuals and a standout score by Ennio Morricone, but its staid presentation never stirs an emotional investment in its characters.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('moby dick', 2001, 'It may favor spectacle in place of the deeper themes in Herman Melville''s novel, but John Huston''s Moby Dick still makes for a grand movie adventure.', TO_DATE('2001-09-04', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('moonraker', 1979, 'Featuring one of the series'' more ludicrous plots but outfitted with primo gadgets and spectacular sets, Moonraker is both silly and entertaining.', TO_DATE('1979-06-29', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mummy', 2000, 'Relying more on mood and atmosphere than the thrills typical of modern horror fare, Universal''s The Mummy sets a masterful template for mummy-themed films to follow.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mutiny on the bounty', 1935, 'The historical inaccuracies in this high-seas adventure are more than offset by its timeless themes, larger-than-life performances from Clark Gable and Charles Laughton, and Frank Lloyd''s superb direction.', TO_DATE('1935-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my man godfrey', 2000, 'A class satire in a class of its own, My Man Godfrey''s screwball comedy is as sharp as the social commentary is biting.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('near dark', 2000, 'Near Dark is at once a creepy vampire film, a thrilling western, and a poignant family tale, with humor and scares in abundance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a night at the opera', 2000, 'Watermelons may go out of season, but in A Night at the Opera, the Marx Brothers'' daffy laughs are never anything less than uproariously fresh.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('night of the living dead', 2000, 'George A. Romero''s debut set the template for the zombie film, and features tight editing, realistic gore, and a sly political undercurrent.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('no way out', 2000, 'Roger Donaldson''s modern spin on the dense, stylish suspense films of the 1940s features fine work from Gene Hackman and Sean Young, as well as the career-making performance that made Kevin Costner a star.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('obsession', 2000, 'Obsession suffers in comparison to the Alfred Hitchcock masterpiece that it mirrors, but director Brian De Palma''s unique preoccupations give this thriller its own compulsive, twisted fingerprint.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the odd couple', 2001, 'Enlivening Neil Simon''s crackerjack script with their harmonious rapport, Jack Lemmon and Walter Matthau are a perfect pairing as The Odd Couple.', TO_DATE('2001-02-13', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the omen', 2000, 'The Omen eschews an excess of gore in favor of ramping up the suspense -- and creates an enduring, dread-soaked horror classic along the way.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pennies from heaven', 2000, 'A complicated little musical, Pennies from Heaven is a dazzling, tragic spectacle.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('peter pan', 2000, 'Though it doesn''t delve deeply into the darkness of J.M. Barrie''s tale, Peter Pan is a heartwarming, exuberant film with some great tunes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('phantom of the opera', 2002, 'Decades later, it still retains its ability to scare -- and Lon Chaney''s performance remains one of the benchmarks of the horror genre.', TO_DATE('2002-06-27', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the pink panther', 2002, 'Peter Sellers is at his virtuosically bumbling best in The Pink Panther, a sophisticated caper blessed with an unforgettably slinky score by Henry Mancini.', TO_DATE('2002-07-27', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('piranha', 2000, 'Performed with a wink and directed with wry self-awareness, Piranha is an unabashed B-movie with satirical bite.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pit and the pendulum the pit and the pendulum', 1961, 'A chilling visual treat, Pit and the Pendulum unites genre masters Roger Corman and Vincent Price with delightfully dark results.', TO_DATE('1961-08-12', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('planet of the apes', 2000, 'Planet of the Apes raises thought-provoking questions about our culture without letting social commentary get in the way of the drama and action.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('point blank', 2000, 'Shot with hard-hitting inventiveness and performed with pitiless cool by Lee Marvin, Point Blank is a revenge thriller that exemplifies that exemplifies the genre''s strengths with extreme prejudice.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('poltergeist', 2000, 'Smartly filmed, tightly scripted, and -- most importantly -- consistently frightening, Poltergeist is a modern horror classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('popeye', 2003, 'Altman''s take on the iconic cartoon is messy and wildly uneven, but its robust humor and manic charm are hard to resist.', TO_DATE('2003-05-24', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the poseidon adventure', 2001, 'The Poseidon Adventure exemplifies the disaster film done right, going down smoothly with ratcheting tension and a terrific ensemble to give the peril a distressingly human dimension.', TO_DATE('2001-02-27', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the postman always rings twice', 2000, 'The Postman Always Rings Twice spins a sultry web of mystery with a gripping adaptation of a classic noir tale.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the producers', 2000, 'A hilarious satire of the business side of Hollywood, The Producers is one of Mel Brooks'' finest, as well as funniest films, featuring standout performances by Gene Wilder and Zero Mostel.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('prom night', 2002, 'Horror aficionados might have a ball with Prom Night, but a lack of mystery and inability to capitalize on the dance hall setting makes for a generic night of mayhem.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('promised land', 2012, 'The earnest and well-intentioned Promised Land sports a likable cast, but it also suffers from oversimplified characterizations and a frustrating final act.', TO_DATE('2012-12-05', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rear window', 2000, 'Hitchcock exerted full potential of suspense in this masterpiece.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red dawn', 2002, 'An appealing ensemble of young stars will have some audiences rooting for the Wolverines, but Red Dawn''s self-seriousness can never conceal the silliness of its alarmist concept.', TO_DATE('2002-02-07', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red heat', 2000, 'Red Heat''s overreliance on genre formula is bolstered by Walter Hill''s rugged direction and a strong touch of humor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the red shoes', 1948, 'The Red Shoes is one of the best-looking movies ever, and blends multiple moods and styles with balletic grace.', TO_DATE('1948-09-06', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red sonja', 2000, 'Dull, poorly directed, and badly miscast, Red Sonja is an uninspired conclusion to Schwarzenegger''s barbarian trilogy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('return to oz', 2000, 'Return to Oz taps into the darker side of L. Frank Baum''s book series with an intermittently dazzling adventure that never quite recaptures the magic of its classic predecessor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('risky business', 2000, 'Featuring one of Tom Cruise''s best early performances, Risky Business is a sharp, funny examination of teen angst that doesn''t stop short of exploring dark themes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('road house', 2000, 'Whether Road House is simply bad or so bad it''s good depends largely on the audience''s fondness for Swayze -- and tolerance for violently cheesy action.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('robin hood', 2000, 'One of the weaker Disney adaptations, Robin Hood is cute and colorful but lacks the majesty and excitement of the studio''s earlier efforts.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('robocop', 2000, 'While over-the-top and gory, Robocop is also a surprisingly smart sci-fi flick that uses ultraviolence to disguise its satire of American culture.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rocky', 2000, 'This story of a down-on-his-luck boxer is thoroughly predictable, but Sylvester Stallone''s script and stunning performance in the title role brush aside complaints.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('romeo and juliet', 2000, 'The solid leads and arresting visuals make a case for Zeffirelli''s Romeo and Juliet as the definitive cinematic adaptation of the play.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rudolph the rednosed reindeer', 2002, 'Rudolph the Red-Nosed Reindeer is a yule-tide gem that bursts with eye-popping iconography, a spirited soundtrack, and a heart-warming celebration of difference.', TO_DATE('2002-07-20', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('running scared', 2000, 'Running Scared struggles to strike a consistent balance between violent action and humor, but the chemistry between its well-matched leads keeps things entertaining.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sabrina', 1954, 'With its humorous script and its stars'' immense charm, Sabrina remains a resonant romantic gem.', TO_DATE('1954-09-09', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scanners', 2000, 'Scanners is a dark sci-fi story with special effects that''ll make your head explode.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scarface', 2000, 'This Scarface foregoes his "little friend" and packs a different kind of heat, blending stylish visuals, thrilling violence, and an incredible cast.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shadow of a doubt', 2000, 'Alfred Hitchcock''s earliest classic -- and his own personal favorite -- deals its flesh-crawling thrills as deftly as its finely shaded characters.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shaft', 2000, 'This is the man that would risk his neck for his brother, man. Can you dig it?', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('short circuit', 2000, 'Amiable and good-natured but also shallow and predictable, Short Circuit is hardly as deep or emotionally resonant as E.T. -- though Johnny Five makes for a charming robot protagonist.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a shot in the dark', 2001, 'A Shot in the Dark is often regarded as the best of the Pink Panther sequels, and Peter Sellers gives a top-notch performance that makes slapstick buffoonery memorable.', TO_DATE('2001-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sleeping beauty', 2000, 'This Disney dreamscape contains moments of grandeur, with its lush colors, magical air, one of the most menacing villains in the Disney canon.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sorcerer', 2002, 'Sorcerer, which obstinately motors along on its unpredictable speed, features ambitious sequences of insane white-knuckle tension.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spartacus', 1960, 'Featuring terrific performances and epic action, Kubrick''s restored swords-and-sandals epic is a true classic.', TO_DATE('1960-10-07', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stagecoach', 1939, 'Typifying the best that the Western genre has to offer, Stagecoach is a rip-roaring adventure given dramatic heft by John Ford''s dynamic direction and John Wayne''s mesmerizing star turn.', TO_DATE('1939-03-02', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stakeout', 2000, 'Richard Dreyfuss and Emilio Estevez make for great company during this Stakeout, a bawdy procedural that mines great pleasure from the odd couple''s comedic chemistry.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a star is born', 2000, 'A Star is Born is a movie of grand scope and intimate moments, featuring Judy Garland''s possibly greatest performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a star is born', 2000, 'A lack of memorable music, chemistry between its leads, and an overlong runtime prompts this modish iteration of A Star is Born to fizzle out quickly.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('101 dalmatians', 2000, 'With plenty of pooches and a memorable villain (Cruella De Vil), this is one of Disney''s most enduring, entertaining animated films.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sting', 2000, 'Paul Newman, Robert Redford, and director George Roy Hill prove that charm, humor, and a few slick twists can add up to a great film.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the stranger', 2001, 'The sins of World War II reemerge in an idyllic American setting in this diabolically effective noir, buoyed by Orson Welles'' virtuosic direction and performance.', TO_DATE('2001-12-16', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a streetcar named desire', 1951, 'A feverish rendition of a heart-rending story, A Streetcar Named Desire gives Tennessee Williams'' stage play explosive power on the screen thanks to Elia Kazan''s searing direction and a sterling ensemble at the peak of their craft.', TO_DATE('1951-09-18', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sunshine boys', 2000, 'Thanks to the sparkling chemistry between its stars and Herbert Ross'' gentle direction, this sweetly ambling comedy ranks among Neil Simon''s finest screen adaptations.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('suspicion', 2000, 'Not even notorious studio meddling can diminish the craft and tantalizing suspense of Suspicion, a sly showcase for Joan Fontaine''s nervy prowess and Alfred Hitchcock''s flair for disquiet.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('swing time', 2000, 'Ginger Rogers and Fred Astaire are brilliant in Swing Time, one of the duo''s most charming and wonderfully choreographed films.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the taming of the shrew', 2000, 'It may not be reverent enough for purists, but This Taming of the Shrew is too funny -- and fun -- for the rest of us to resist.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ten commandments', 2000, 'Bombastic and occasionally silly but extravagantly entertaining, Cecil B. DeMille''s all-star spectacular is a muscular retelling of the great Bible story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('them', 2000, 'One of the best creature features of the early atomic age, Them! features effectively menacing special effects and avoids the self-parody that would taint later monster movies.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shivers they came from within the parasite murders', 1975, 'Shivers uses elementally effective basic ingredients to brilliant effect - and lays the profoundly unsettling foundation for director David Cronenberg''s career to follow.', TO_DATE('1975-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thief', 2000, 'Thief is an invigorating cut of neon noir - proudly pulpy, steeped in authenticity, and powered by a swaggering James Caan at the peak of his charisma.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the thing from another world', 2000, 'As flying saucer movies go, The Thing From Another World is better than most, thanks to well-drawn characters and concise, tense plotting.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the thing', 1982, 'Grimmer and more terrifying than the 1950s take, John Carpenter''s The Thing is a tense sci-fi thriller rife with compelling tension and some remarkable make-up effects.', TO_DATE('1982-07-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('three amigos', 2000, 'Three Amigos! stars a trio of gifted comedians and has an agreeably silly sense of humor, but they''re often adrift in a dawdling story with too few laugh-out-loud moments.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the time machine', 2000, 'Its campy flourishes tend to subdue its dramatic stakes, but The Time Machine brings H.G. Wells'' story to life with plenty of sci-fi charm and a colorful sense of visual design.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tommy', 2002, 'Tommy is as erratic and propulsive as a game of pinball, incorporating The Who''s songs into an irreverent odyssey with the visual imagination that only director Ken Russell can conjure.', TO_DATE('2002-10-11', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('top secret', 2000, 'Top Secret! finds the team of Zucker-Abrahams-Zucker sending up everything from spy movies to Elvis musicals with reckless, loony abandon.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('touch of evil', 2000, 'Artistically innovative and emotionally gripping, Orson Welles'' classic noir is a visual treat, as well as a dark, sinister thriller.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('le procès the trial', 2000, 'Orson Welles may take big liberties in his adaptation of The Trial, but the auteur constructs an absurd nightmare that is unmistakably Kafkaesque -- grounded by an excellent Anthony Perkins as the befuddled Josef K.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the trip', 2003, 'The Trip''s groovy effects and compelling message can''t overcome the rough acting, long meandering stretches, and pedestrian plot.', TO_DATE('2003-06-04', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('twelve oclock high', 2001, 'Twelve O''Clock High is a high-stakes, high-tension war drama powered by great, well-written characters.', TO_DATE('2001-08-21', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('twins', 2000, 'Though it offers a few modest pleasures for undemanding viewers, Twins leans too heavily on the wackiness of its premise to overcome its narrative shortcomings.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('valley girl', 2000, 'With engaging performances from its two leads, Valley Girl is a goofy yet amiable film that both subverts and celebrates the cheerful superficiality of teen comedies.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('village of the damned', 2002, 'Chilling performances and a restrained, eerie atmosphere make this British horror both an unnerving parable of its era and a timeless classic.', TO_DATE('2002-04-29', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the warriors', 2000, 'As violent as it is stylish, The Warriors is a thrilling piece of pulp filmmaking.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('weird science', 2000, 'Hardly in the same league as John Hughes'' other teen movies, the resolutely goofy Weird Science nonetheless gets some laughs via its ridiculous premise and enjoyable performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('white christmas', 1800, 'It may be too sweet for some, but this unabashedly sentimental holiday favorite is too cheerful to resist.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('willard', 2003, 'Willard has an intriguing character study lurking within - but much of those elements, like many of the movie''s characters, are swallowed up by rats.', TO_DATE('2003-03-17', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('witness', 2002, 'A wonderfully entertaining thriller within an unusual setting, with Harrison Ford delivering a surprisingly emotive and sympathetic performance.', TO_DATE('2002-08-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wuthering heights', 2000, 'Sumptuous design and perfect casting makes Wuthering Heights an exemplar of old Hollywood studio filmmaking, even if to a fault.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blue steel', 2000, 'Blue Steel''s increasingly over-the-top story beggars disbelief, but this cop drama is elevated by an appealing cast and Kathryn Bigelow''s stylish direction.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mystery train', 2000, 'Mystery Train meanders by design, but it never goes off the rails, retaining its deadpan cool throughout.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('revolution', 2000, 'Unlikely to inspire any fervor with its miscast ensemble and ponderous script, Revolution is a star-spangled bummer.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('henry v', 2000, 'Pehaps Kenneth Branagh''s most fully realized Shakespeare adaptation, Henry V is an energetic, passionate, and wonderfully acted film.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alice in wonderland', 2002, 'A good introduction to Lewis Carroll''s classic, Alice in Wonderland boasts some of the Disney canon''s most surreal and twisted images.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dick tracy', 2000, 'Dick Tracy is stylish, unique, and an undeniable technical triumph, but it ultimately struggles to rise above its two-dimensional artificiality.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('navy seals', 2000, 'A non-winning military recruitment progaganda movie that happens to star Charlie Sheen and Michael Biehn.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('102 dalmatians', 2000, 'This sequel to the live-action 101 Dalmatians is simply more of the same. Critics say it also drags in parts, potentially boring children, and that it''s too violent for a G-rated movie.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghost', 2000, 'Ghost offers viewers a poignant romance while blending elements of comedy, horror, and mystery, all adding up to one of the more enduringly watchable hits of its era.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gun crazy deadly is the female', 2000, 'Well-acted and strikingly filmed, Gun Crazy (Deadly Is the Female) delves into the darkness of human nature with noir-fueled B-movie flair.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the jungle book', 2002, 'With expressive animation, fun characters, and catchy songs, The Jungle Book endures as a crowd-pleasing Disney classic.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the long goodbye', 2001, 'An ice-cold noir that retains Robert Altman''s idiosyncratic sensibilities, The Long Goodbye ranks among the smartest and most satisfying Marlowe mysteries.', TO_DATE('2001-03-27', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('goodfellas', 2000, 'Hard-hitting and stylish, GoodFellas is a gangster classic -- and arguably the high point of Martin Scorsese''s career.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('after hours', 2000, 'Bursting with frantic energy and tinged with black humor, After Hours is a masterful -- and often overlooked -- detour in Martin Scorsese''s filmography.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('white fang', 1991, 'This glossy edition of White Fang shaves off the rough-hewn edges that made Jack London''s epic story so distinct, but gorgeous photography and heartfelt performances make this an appealing adventure.', TO_DATE('1991-01-18', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('awakenings', 1990, 'Elevated by some of Robin Williams'' finest non-comedic work and a strong performance from Robert De Niro, Awakenings skirts the edges of melodrama, then soars above it.', TO_DATE('1990-12-19', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diabolique les diaboliques', 2000, 'Cruel, dark, but undeniably effective, Diabolique is a suspense thriller as effective as Hitchcock''s best work and with a brilliant twist ending.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('come and see idi i smotri', 2000, 'As effectively anti-war as movies can be, Come and See is a harrowing odyssey through the worst that humanity is capable of, directed with bravura intensity by Elem Klimov.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hot shots', 1991, 'Hot Shots! hits most of its parodic targets with aplomb, excelling as a daffy good time thanks to inspired gags and Charlie Sheen''s crack comedic timing.', TO_DATE('1991-07-31', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the commitments', 1991, 'The Commitments is a vibrantly funny and blissfully heartfelt ode to the power of music.', TO_DATE('1991-08-14', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('poison', 1991, 'Claustrophobic and quirky horror, this is a decently dirty debut for director Todd Haynes.', TO_DATE('1991-04-05', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cape fear', 1991, 'Smart and stylish, Cape Fear is a gleefully mainstream shocker from Martin Scorsese, with a terrifying Robert De Niro peformance.', TO_DATE('1991-11-13', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jfk', 1991, 'As history, Oliver Stone''s JFK is dubious, but as filmmaking it''s electric, cramming a ton of information and excitement into its three-hour runtime and making great use of its outstanding cast.', TO_DATE('1991-12-20', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man in the moon', 2000, 'It''s sentimental, and some viewers may feel manipulated by the melodramatic final act, but The Man in the Moon offers a finely drawn coming-of-age story with an excellent cast -- including Reese Witherspoon in her film debut.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('father of the bride', 1991, 'While it doesn''t quite hit the heights of the original, this remake of the 1950 classic is pleasantly enjoyable, thanks in large part to winning performances from Steve Martin and Martin Short.', TO_DATE('1991-01-01', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the italian job', 2000, 'The Italian Job is a wildly fun romp that epitomizes the height of Britannia style.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beethoven', 1992, 'Fluffy and incorrigible, Beethoven is a good boy who deserves a better movie.', TO_DATE('1992-04-03', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cutting edge', 1992, 'Part contrived romance, part hackneyed sports drama, The Cutting Edge shows how difficult it can be to figure skate through cheese.', TO_DATE('1992-01-01', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deep cover', 1992, 'Deep Cover rises above standard-issue crime thriller fare thanks to a smartly cynical script and powerhouse performances from its unorthodox but well-matched leads.', TO_DATE('1992-04-15', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a midnight clear', 2000, 'Beautifully filmed and wonderfully acted, A Midnight Clear is a holiday war film in search of a wider audience.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boomerang', 1992, 'Boomerang injects some fresh color into the corporate rom-com formula, but the frothy fun is undercut by off-putting gender dynamics and misjudged gags.', TO_DATE('1992-07-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('of mice and men', 1992, 'Of Mice and Men honors its classic source material with a well-acted adaptation that stays powerfully focused on the story''s timeless themes.', TO_DATE('1992-10-02', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cool world', 2000, 'Cool World throws a small handful of visual sparks, but they aren''t enough to distract from the screenplay''s thin characters and scattered plot.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('singles', 1992, 'Smart, funny, and engagingly scruffy, Singles is a clear-eyed look at modern romance that doubles as a credible grunge-era time capsule.', TO_DATE('1992-09-18', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last of the mohicans', 1992, 'The Last of the Mohicans is a breathless romantic adventure that plays loose with history -- and comes out with a richer action movie for it.', TO_DATE('1992-09-25', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('husbands and wives', 1992, 'Husbands and Wives is a blistering, emotionally raw snapshot of two marriages self-destructing.', TO_DATE('1992-10-18', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('matinee', 1992, 'Smart, funny, and disarmingly sweet, Matinee is a film that film buffs will love -- and might even convert some non-believers.', TO_DATE('1992-06-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unforgiven', 1992, 'As both director and star, Clint Eastwood strips away decades of Hollywood varnish applied to the Wild West, and emerges with a series of harshly eloquent statements about the nature of violence.', TO_DATE('1992-08-03', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('leap of faith', 2001, 'Steve Martin''s layered performance transcends the somewhat undercooked narrative of Leap of Faith.', TO_DATE('2001-02-13', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('malcolm x', 1992, 'Anchored by a powerful performance from Denzel Washington, Spike Lee''s biopic of legendary civil rights leader Malcolm X brings his autobiography to life with an epic sweep and a nuanced message.', TO_DATE('1992-11-18', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scent of a woman', 1992, 'It might soar on Al Pacino''s performance more than the drama itself, but what a performance it is -- big, bold, occasionally over-the-top, and finally giving the Academy pause to award the star his first Oscar.', TO_DATE('1992-12-23', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the vanishing', 1993, 'The Vanishing copies the form of its pulse-pounding predecessor but loses much of its thrilling function along the way, leaving American audiences with one more rote remake.', TO_DATE('1993-06-01', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('born yesterday', 1993, 'Not even Melanie Griffith''s charisma can inject fresh energy into this ill-conceived remake, which awkwardly retreads through the classic original''s story without any of its charm.', TO_DATE('1993-03-26', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stalker', 2002, 'Stalker is a complex, oblique parable that draws unforgettable images and philosophical musings from its sci-fi/thriller setting.', TO_DATE('2002-03-05', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cliffhanger', 2000, 'While it can''t escape comparisons to the movies it borrows from, Cliffhanger is a tense, action-packed thriller and a showcase for the talents that made Sylvester Stallone a star.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the firm', 2000, 'The Firm is a big studio thriller that amusingly tears apart the last of 1980s boardroom culture and the false securities it represented.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the secret garden', 1993, 'The Secret Garden honors its classic source material with a well-acted, beautifully filmed adaptation that doesn''t shy from its story''s darker themes.', TO_DATE('1993-03-18', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('strictly ballroom', 1992, 'As emotionally rich as it is eye-catching, Strictly Ballroom uses its infectious energy as the fuel for a modern dance classic with all the right moves.', TO_DATE('1992-02-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('much ado about nothing', 2000, 'Kenneth Branagh''s love for the material is contagious in this exuberant adaptation.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('airborne', 1800, 'Airborne skates downhill with a threadbare story, flat characters, and wince-inducing dialogue.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gettysburg', 2000, 'Gettysburg''s reverent approach to history is balanced with the committed work of a talented cast - and the hard-hitting dramatization of a bloody turning point in the Civil War.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('high noon', 2000, 'A classic of the Western genre that broke with many of the traditions at the time, High Noon endures -- in no small part thanks to Gary Cooper''s defiant, Oscar-winning performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fugitive', 1993, 'Exhilarating and intense, this high-impact chase thriller is a model of taut and efficient formula filmmaking, and it features Harrison Ford at his frantic best.', TO_DATE('1993-08-06', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fearless', 1800, 'This underrated gem from director Peter Weir features an outstanding performance from Jeff Bridges as a man dealing with profound grief.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cool runnings', 2000, 'Cool Runnings rises above its formulaic sports-movie themes with charming performances, light humor, and uplifting tone.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the three musketeers', 2000, 'Its starry trio of do-gooders may promise to fight "one for all, all for one," but this Three Musketeers is a slickly unmemorable update bound to satisfy very few.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heaven earth', 1994, 'Heaven & Earth is a well-intentioned glimpse into an underrepresented perspective on Vietnam, but Oliver Stone''s solemn storytelling keeps audiences at a fatal distance from Hiep Thi Le''s enigmatic heroine.', TO_DATE('1994-06-01', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('snow white and the seven dwarfs', 2000, 'With its involving story and characters, vibrant art, and memorable songs, Snow White and the Seven Dwarfs set the animation standard for decades to come.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kid', 2003, 'Charles Chaplin'' irascible Tramp is given able support from Jackie Coogan as The Kid in this slapstick masterpiece, balancing the guffaws with moments of disarming poignancy.', TO_DATE('2003-04-22', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wyatt earp', 1994, 'Easy to admire yet difficult to love, Wyatt Earp buries eye-catching direction and an impressive cast in an undisciplined and overlong story.', TO_DATE('1994-06-24', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mask', 2000, 'It misses perhaps as often as it hits, but Jim Carrey''s manic bombast, Cameron Diaz'' blowsy appeal, and the film''s overall cartoony bombast keep The Mask afloat.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wolf', 1994, 'Wolf misses the jugular after showing flashes of killer instinct early on, but engaging stars and deft direction make this a unique horror-romance worth watching.', TO_DATE('1994-06-17', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the shadow', 2000, 'Bringing a classic pulp character to the big screen, The Shadow features impressive visual effects, but the story ultimately fails to strike a memorable chord.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beloved', 2000, 'A powerful, emotional and successful film adaptation of the original novel.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rudyard kiplings the jungle book', 1994, 'Rudyard Kipling''s The Jungle Book may not hew as closely to the book as its title suggests, but it still offers an entertaining live-action take on a story best known in animated form.', TO_DATE('1994-12-23', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('junior', 1994, 'Even with an abundance of talent behind and in front of the camera, Junior doesn''t quite deliver enough laughs to nurse its zany high-concept idea.', TO_DATE('1994-11-23', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('street fighter', 1994, 'Though it offers mild entertainment through campy one-liners and the overacting of the late Raul Julia, Street Fighter''s nonstop action sequences are not enough to make up for a predictable, uneven storyline.', TO_DATE('1994-12-22', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little women', 2000, 'Thanks to a powerhouse lineup of talented actresses, Gillian Armstrong''s take on Louisa May Alcott''s Little Women proves that a timeless story can succeed no matter how many times it''s told.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shallow grave', 1995, 'This black-humored thriller features characters who are more obnoxious than clever. During the second half, the movie descends into gratuitous violence.', TO_DATE('1995-06-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('three colors red trois couleurs rouge', 2000, 'A complex, stirring, and beautifully realized portrait of interconnected lives, Red is the captivating conclusion to a remarkable trilogy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nobodys fool', 2000, 'It''s solidly directed by Robert Benton and stacked with fine performances from an impressive cast, but above all, Nobody''s Fool is a showcase for some of Paul Newman''s best late-period work.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wild bunch', 2000, 'The Wild Bunch is Sam Peckinpah''s shocking, violent ballad to an old world and a dying genre.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the quick and the dead', 1995, 'The Quick and the Dead isn''t quite the draw that its intriguing premise and pedigree suggest, but fans of nontraditional Westerns should have some rootin'' tootin'' fun.', TO_DATE('1995-02-10', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the old dark house', 2000, 'A deft blend of well-chosen ingredients, The Old Dark House is a delightfully scary horror comedy that benefits from James Whale''s suspenseful direction.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('village of the damned', 2000, 'With John Carpenter at the helm and an eclectic onscreen ensemble, this Village of the Damned should be distinguished by more than its improved special effects.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a little princess', 1995, 'Alfonso Cuarón adapts Frances Hodgson Burnett''s novel with a keen sense of magic realism, vividly recreating the world of childhood as seen through the characters.', TO_DATE('1995-08-04', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mad love', 1995, 'Mad Love tries to juggle mental illness with meet-cute, and the end result is a misguided rom-com whose sparks resolutely fail to fly.', TO_DATE('1995-05-26', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad boys', 1995, 'Bad Boys stars Will Smith and Martin Lawrence have enjoyable chemistry; unfortunately, director Michael Bay too often drowns it out with set pieces and explosions in place of an actual story.', TO_DATE('1995-05-19', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('smoke', 1995, 'Smoke draws in a stellar ensemble, holds the audience''s attention with a robust blend of connected stories, and sends viewers out on a pleasurable high.', TO_DATE('1995-06-09', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pocahontas', 2000, 'Pocahontas means well, and has moments of startling beauty, but it''s largely a bland, uninspired effort, with uneven plotting and an unfortunate lack of fun.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('babe', 2000, 'The rare family-friendly feature with a heart as big as its special effects budget, Babe offers timeless entertainment for viewers of all ages.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the prophecy', 2000, 'The Prophecy has its moments, but any fantasy thriller starring Christopher Walken as a murderous angel should be a good deal more engaging than this.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('braveheart', 1995, 'Distractingly violent and historically dodgy, Mel Gibson''s Braveheart justifies its epic length by delivering enough sweeping action, drama, and romance to match its ambition.', TO_DATE('1995-05-26', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the scarlet letter', 1995, 'The Scarlet Letter strays far from its classic source material to tell a story that strains for steamy sensuality and leaves the audience red with unintentional laughter.', TO_DATE('1995-10-13', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('home for the holidays', 1995, 'Much like a real-life visit Home for the Holidays, this Thanksgiving-set dramedy can get a little bumpy -- but it also has its share of fondly memorable moments.', TO_DATE('1995-11-03', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kicking and screaming', 1995, 'Witty and watchable yet undeniably flawed, Kicking and Screaming marks writer-director Noah Baumbach as an emerging talent with intriguing potential.', TO_DATE('1995-10-06', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('persuasion', 1995, 'Well-acted and absorbing, Persuasion offers a loose Jane Austen adaptation that captures the essence of the author''s timeless appeal.', TO_DATE('1995-09-27', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('to die for', 2000, 'Smart, funny, and thoroughly well-cast, To Die For takes a sharp - and sadly prescient - stab at dissecting America''s obsession with celebrity.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('it takes two', 1995, 'Rob Base and DJ EZ Rock told us that It Takes Two to make a thing go right, but this unpleasant Olsen twins comedy proves that the opposite can also be true.', TO_DATE('1995-11-17', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('casino', 2000, 'Impressive ambition and bravura performances from an outstanding cast help Casino pay off in spite of a familiar narrative that may strike some viewers as a safe bet for director Martin Scorsese.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jumanji', 1995, 'A feast for the eyes with a somewhat malnourished plot, Jumanji is an underachieving adventure that still offers a decent amount of fun for the whole family.', TO_DATE('1995-12-15', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('richard iii', 1995, 'This re-imagining of Shakespeare''s Crookback King relocates the story in 1930 and features an indelible star turn for Ian McKellen as the monstrous and magnetic King Richard.', TO_DATE('1995-12-29', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heat', 1995, 'Though Al Pacino and Robert De Niro share but a handful of screen minutes together, Heat is an engrossing crime drama that draws compelling performances from its stars -- and confirms Michael Mann''s mastery of the genre.', TO_DATE('1995-12-15', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the addiction', 2000, 'Abel Ferrara''s 1995 horror/suspense experiment blends urban vampire adventure with philosophical analysis to create a smart, idiosyncratic, and undeniably odd take on the genre.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sabrina', 1995, 'Sydney Pollack''s Sabrina doesn''t do anything the original didn''t do better, but assured direction and a cast of seasoned stars make this a pleasant enough diversion.', TO_DATE('1995-12-15', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heavy metal', 2000, 'It''s sexist, juvenile, and dated, but Heavy Metal makes up for its flaws with eye-popping animation and a classic, smartly used soundtrack.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sudden death', 2000, 'Sudden Death may not be a classic, but exciting set pieces and strong work from Jean-Claude Van Damme help this action thriller pay off part of its Die Hard debt.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dead man walking', 1995, 'A powerful, thought-provoking film that covers different angles of its topic without resorting to preaching, Dead Man Walking will cause the viewer to reflect regardless of their political viewpoint.', TO_DATE('1995-12-29', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('broken arrow', 1996, 'John Woo adds pyrotechnic glaze to John Travolta''s hammy performance, but fans may find Broken Arrow to be a dispiritingly disposable English-language entry for the action auteur.', TO_DATE('1996-02-09', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('restoration', 2000, 'Restoration spins an engaging period yarn out of its bestselling source material, brought to life through the efforts of an eclectic ensemble cast led by Robert Downey Jr.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black sheep', 2000, 'Chris Farley and David Spade reunite to diminishing returns in Black Sheep, a comedic retread that succumbs to a woolly plot and sophomoric jokes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('othello', 1995, 'Perhaps less than the sum of its parts, Othello is still highly entertaining, and features excellent performances from Laurence Fishburne and Kenneth Branagh.', TO_DATE('1995-12-22', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diabolique', 1996, 'This seedy remake of a classic French chiller goes through the motions in recreating the original''s diabolical plot, but without the genuine suspense or stylistic finesse.', TO_DATE('1996-03-22', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the quest', 2000, 'Jean-Claude Van Damme makes a forgettable directorial debut with The Quest, a bland retread of better heroes'' journeys.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('primal fear', 1996, 'Primal Fear is a straightforward yet entertaining thriller elevated by a crackerjack performance from Edward Norton.', TO_DATE('1996-04-05', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('twister', 1996, 'A high-concept blockbuster that emphasizes special effects over three-dimensional characters, Twister''s visceral thrills are often offset by the film''s generic plot.', TO_DATE('1996-05-10', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fear', 1996, 'Fear has an appealing young cast, but their efforts aren''t enough to consistently distract from an increasingly overblown - and illogical - teen stalker story.', TO_DATE('1996-04-12', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the arrival', 1996, 'Stylish and inventive, The Arrival offers a surprisingly smart spin on the alien invasion genre.', TO_DATE('1996-05-31', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last supper', 1996, 'It struggles to find a balance between its humor and its message, but The Last Supper''s sharp script and well-chosen cast offer just enough nourishment for fans of black comedy.', TO_DATE('1996-04-05', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cold comfort farm', 1996, 'Cold Comfort Farm sends up high-minded classics with a wit and impressive restraint that rivals its inspirations.', TO_DATE('1996-05-10', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('independence day', 2000, 'The plot is thin and so is character development, but as a thrilling, spectacle-filled summer movie, Independence Day delivers.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rock', 1996, 'For visceral thrills, it can''t be beat. Just don''t expect The Rock to engage your brain.', TO_DATE('1996-06-07', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the phantom', 2000, 'The script gives Billy Zane little to work with, and thus he plays the Phantom as a friendly but completely one-dimensional hero.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('matilda', 1996, 'Danny DeVito-directed version of Matilda is odd, charming, and while the movie diverges from Roald Dahl, it nonetheless captures the book''s spirit.', TO_DATE('1996-08-02', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the island of dr moreau', 1996, 'Timid and unfocused in its storytelling, The Island Of Dr. Moreau is more lackluster misfire than morbid curiosity.', TO_DATE('1996-08-23', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a time to kill', 1996, 'Overlong and superficial, A Time to Kill nonetheless succeeds on the strength of its skillful craftsmanship and top-notch performances.', TO_DATE('1996-07-24', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kingpin', 1996, 'Kingpin has its moments, but they''re often offset by an eagerness to descend into vulgar mean-spiritedness.', TO_DATE('1996-07-26', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chain reaction', 1996, 'Ironic given the scientific breakthrough at the story''s core, Chain Reaction is a man-on-the-run thriller that mostly sticks to generic formula.', TO_DATE('1996-08-02', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jack', 1996, 'Robin Williams'' childlike energy is channeled in all the wrong places with Jack, a bizarre tragedy that aims for uplift but sinks deep into queasy schmaltz.', TO_DATE('1996-08-09', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('freeway', 2000, 'A modern update on the tale of Little Red Riding Hood, Freeway is an audacious black comedy with a star-making performance from the young Reese Witherspoon.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fan', 1996, 'Tony Scott''s visceral flash proves to be an ill fit for The Fan, a queasy tale of obsession that succeeds at making audiences uncomfortable, but strikes out when it comes to delivering the thrills.', TO_DATE('1996-06-01', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harriet the spy', 1996, 'Harriet the Spy is a rapid-fire mystery movie that doesn''t have much to offer beyond the two decent lead performances.', TO_DATE('1996-07-10', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('house arrest', 2000, 'Constructed out of cliches, thinly written characters, and fundamental misunderstandings of human nature, House Arrest is a dull (and borderline irresponsible) waste of a talented cast.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hunchback of notre dame', 1996, 'Disney''s take on the Victor Hugo classic is dramatically uneven, but its strong visuals, dark themes, and message of tolerance make for a more-sophisticated-than-average children''s film.', TO_DATE('1996-06-21', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bulletproof', 1996, 'In addition to its ability to deflect gunfire, Bulletproof proves sadly impervious to humor, logic, or worthwhile viewing.', TO_DATE('1996-09-06', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('emma', 2000, 'Emma marks an auspicious debut for writer-director Douglas McGrath, making the most of its Jane Austen source material -- and a charming performance from Gwyneth Paltrow.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('selena', 1997, 'Selena occasionally struggles to tell its subject''s story with depth or perspective, but those flaws are rendered largely irrelevant by Jennifer Lopez in the title role.', TO_DATE('1997-03-21', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lone star', 1996, 'Smart and absorbing, Lone Star represents a career high point for writer-director John Sayles -- and ''90s independent cinema in general.', TO_DATE('1996-06-21', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('101 dalmatians', 2000, 'Neat performance from Glenn Close aside, 101 Dalmatians is a bland, pointless remake.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ransom', 2000, 'Directed with propulsive intensity by Ron Howard, Ransom is a fiery thriller packed with hot-blooded performances and jolting twists.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scream', 1996, 'Horror icon Wes Craven''s subversive deconstruction of the genre is sly, witty, and surprisingly effective as a slasher film itself, even if it''s a little too cheeky for some.', TO_DATE('1996-12-20', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('michael', 2000, 'John Travolta plays an angel in Nora Ephron''s maudlin Michael, a grating comedy that doesn''t tap into the heavenly charms of her best work.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in love and war', 1996, 'Formulaic and trite, In Love and War unconvincingly recreates Ernest Hemingway''s early life with all the stuffy tropes that the author would have excised in a second draft.', TO_DATE('1996-12-18', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the crucible', 1996, 'This staid adaptation of The Crucible dutifully renders Arthur Miller''s landmark play on the screen with handsome production design and sturdy performances, if not with the political anger and thematic depth that earned the drama its reputation.', TO_DATE('1996-12-13', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hamlet', 2000, 'Kenneth Branagh''s sprawling, finely textured adaptation of Shakespeare''s masterpiece lives up to its source material, using strong performances and a sharp cinematic focus to create a powerfully resonant film that wastes none of its 246 minutes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('private parts', 1997, 'A surprisingly endearing biopic about the controversial shock-jock Howard Stern that is equally funny and raunchy.', TO_DATE('1997-03-07', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mother', 1996, 'Albert Brooks'' pugnacious insight is in fine form throughout Mother, a gentle showcase for the comedic curmudgeon and a sweetly acidic Debbie Reynolds.', TO_DATE('1996-03-14', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('iron monkey', 2001, 'Iron Monkey may not have the poetic lyricism of Crouching Tiger, it makes up for it in fun and energy.', TO_DATE('2001-08-15', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mchales navy', 2000, 'About as funny as a keelhauling, McHale''s Navy will leave most viewers feeling they''ve been the victim of a particularly dishonorable discharge.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('volcano', 1997, 'Volcano''s prodigious pyrotechnics and Tommy Lee Jones'' crotchety sneers at lava aren''t quite enough to save this routine disaster film.', TO_DATE('1997-04-25', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('get carter', 2000, 'Darkly entertaining and tightly wound, Get Carter is a gritty revenge story done right.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('traveller', 2000, 'Though it may not explore its core issues as deeply as some may like, Traveller is nevertheless a smart and funny portrait of a relatively unfamiliar subculture with some strong performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('batman robin', 2000, 'Joel Schumacher''s tongue-in-cheek attitude hits an unbearable limit in Batman & Robin resulting in a frantic and mindless movie that''s too jokey to care much for.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('breakdown', 1997, 'A brainy and suspenseful -- if somewhat uneven -- thriller.', TO_DATE('1997-05-02', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('george of the jungle', 1997, 'George of the Jungle is faithful to its source material -- which, unfortunately, makes it a less-than-compelling feature film.', TO_DATE('1997-07-16', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('contact', 1997, 'Contact elucidates stirring scientific concepts and theological inquiry at the expense of satisfying storytelling, making for a brainy blockbuster that engages with its ideas, if not its characters.', TO_DATE('1997-07-11', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('steel', 2000, 'Steel is a badly-acted movie that indulges not only in superhero cliches, but also the sappy TV-movie-of-the-week ones.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shall we dance shall we dansu', 1997, 'Elegantly told by director Masayuki Suo and warmly performed, Shall We Dance? is a delightful celebration of stepping out of one''s comfort zone and cutting a rug.', TO_DATE('1997-07-11', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the game', 1997, 'The ending could use a little work but this is otherwise another sterling example of David Fincher''s iron grip on atmosphere and storytelling.', TO_DATE('1997-09-12', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seven years in tibet', 1997, 'Seven Years in Tibet tells its fascinating true-life story with a certain stolid grace, even if it never quite comes to life the way it could.', TO_DATE('1997-10-08', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anastasia', 1997, 'Beautiful animation, an affable take on Russian history, and strong voice performances make Anastasia a winning first film from Fox animation studios.', TO_DATE('1997-11-14', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('firestorm', 2000, 'Firestorm failed to ignite ex-pro footballer Howie Long''s career...or anything else for that matter.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rainmaker', 1997, 'Invigorated by its talented cast and Francis Ford Coppola''s strong direction, The Rainmaker is a satisfying legal drama -- and arguably the best of Hollywood''s many John Grisham adaptations.', TO_DATE('1997-11-20', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fallen', 1997, 'Has an interesting premise. Unfortunately, it''s just a recycling of old materials, and not all that thrilling.', TO_DATE('1997-06-01', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('great expectations', 1998, 'Great Expectations is all surface tension: beautiful people shot in beautiful locations without any depth or emotion.', TO_DATE('1998-01-30', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the borrowers', 1998, 'Rousing and inventive, The Borrowers is a delightfully spirited children''s adventure.', TO_DATE('1998-02-13', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man in the iron mask', 1998, 'Leonardo DiCaprio plays dual roles with diminishing returns in The Man in the Iron Mask, a cheesy rendition of the Musketeers'' epilogue that bears all the pageantry of Alexandre Dumas'' text, but none of its romantic panache.', TO_DATE('1998-03-13', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nightwatch', 1998, 'Nightwatch loses much of what made its inspiration entertaining - and proves that when remaking a foreign film, hiring the original director is no guarantee of success.', TO_DATE('1998-04-17', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('twilight', 1998, 'It suffers from a frustratingly deliberate pace, but with nuanced performances from Paul Newman, Gene Hackman, Susan Sarandon, and Reese Witherspoon to fall back on, Twilight can''t help but be compelling.', TO_DATE('1998-03-06', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hush', 2000, 'A ridiculous but wholly predictable potboiler with performances ranging from comatose to hysterical.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a perfect murder', 1998, 'A slick little thriller that relies a bit too much on surprise events to generate suspense.', TO_DATE('1998-06-05', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('les miserables', 1998, 'This intelligent, handsomely crafted adaptation of Victor Hugo''s classic novel condenses the story''s developments without blunting its emotional impact.', TO_DATE('1998-05-01', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('madeline', 1998, 'It may be a tad tedious for older viewers, but Madeline''s clever, adventurous heroine is likely to charm its intended audience.', TO_DATE('1998-06-10', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the parent trap', 1998, 'Writer-director Nancy Meyers takes the winning formula of the 1961 original and gives it an amiable modern spin, while young star Lindsay Lohan shines in her breakout role.', TO_DATE('1998-07-29', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('out of sight', 2000, 'Steven Soderbergh''s intelligently crafted adaptation of the Elmore Leonard novel is witty, sexy, suprisingly entertaining, and a star-making turn for George Clooney.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the avengers', 1998, 'A TV spinoff that lacks enough energy to spin, The Avengers is an ineptly written, woefully miscast disaster.', TO_DATE('1998-08-14', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the negotiator', 1998, 'The Negotiator''s battle of wits doesn''t wholly justify its excessive length, but confident direction by F. Gary Gray and formidable performances makes this a situation audiences won''t mind being hostage to.', TO_DATE('1998-07-29', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blade', 1998, 'Though some may find the plot a bit lacking, Blade''s action is fierce, plentiful, and appropriately stylish for a comic book adaptation.', TO_DATE('1998-08-21', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mafia', 1998, 'Mafia! promises audiences a spaghetti plate of gangster farce, but only delivers egg noodles and ketchup.', TO_DATE('1998-07-24', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rounders', 1998, 'Richly atmospheric and colorful performances contributed to the movie''s entertainment value.', TO_DATE('1998-09-11', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('funny games', 2000, 'Violent images and blunt audience provocation make up this nihilistic experiment from one of cinema''s more difficult filmmakers.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('soldier', 2000, 'A boring genre film and a waste of a good set.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tango', 2000, 'Tango makes a few false moves, but this dance-driven fantasy steps just the right side of the line between stultifying and seductive.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the thin red line', 2000, 'The Thin Red Line is a daringly philosophical World War II film with an enormous cast of eager stars.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('elizabeth', 2000, 'No mere historical drama, Elizabeth is a rich, suspenseful journey into the heart of British Royal politics, and features a typically outstanding performance from Cate Blanchett.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happiness', 1998, 'Happiness is far from a cheerful viewing experience, but its grimly humorous script and fearless performances produce a perversely moving search for humanity within everyday depravity.', TO_DATE('1998-10-16', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('life is beautiful la vita è bella', 2000, 'Benigni''s earnest charm, when not overstepping its bounds into the unnecessarily treacly, offers the possibility of hope in the face of unflinching horror.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mighty joe young', 2000, 'Beguiling effects transcend a predictable plot.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('at first sight', 1999, 'Interesting premise, but too long and conventional.', TO_DATE('1999-01-15', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('supernova', 2000, 'This is an insult to the Sci-fi genre with no excitement and bad FX.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lolita', 2000, 'If it can''t quite live up to Nabokov''s words, Adrian Lyne''s Lolita manages to find new emotional notes in this complicated story, thanks in large part to its solid performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('true crime', 1999, 'True Crime has the potential for a gripping character-driven mystery, but a pedestrian story and a miscast Clint Eastwood undermine its effectiveness.', TO_DATE('1999-03-19', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('psycho', 1998, 'Van Sant''s pointless remake neither improves nor illuminates Hitchcock''s original.', TO_DATE('1998-12-04', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the siege', 1998, 'An exciting, well-paced action film.', TO_DATE('1998-11-06', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the impostors', 1999, 'The Impostors might have benefited from a more consistently witty script, but writer-director Stanley Tucci acquits himself nicely as an orchestrator of screwball comedy in this uneven debut.', TO_DATE('1999-06-01', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('virus', 2000, 'Despite its great special effects, this movie''s predictability greatly undermines its intensity.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('life', 2000, 'Entertaining if not over-the-top humor from a solid comic duo provides plenty of laughs.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lost and found', 2000, 'Aside from a few laughs, everything else is entirely predictable, including the jokes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('go', 2000, 'With its sharp dialogue and raucous visuals, Go entertains at an exhilarating pace.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mummy', 2000, 'It''s difficult to make a persuasive argument for The Mummy as any kind of meaningful cinematic achievement, but it''s undeniably fun to watch.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the winslow boy', 1999, 'Smart and engaging, The Winslow Boy finds David Mamet bringing his talents to bear on period drama, with easily commendable results.', TO_DATE('1999-04-30', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the king and i', 1999, 'Charmless and shoddily animated, The King and I pales in comparison to its classic namesake in every way.', TO_DATE('1999-03-19', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('payback', 2000, 'Sadistic violence and rote humor saddle a predictable action premise.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bent', 2000, 'Bent juggles heavy topics with style, though its heavy-handedness at times feels more like exploitation than exploration.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ill be home for christmas', 2000, 'Neither parent nor child will find any merriment in this mess.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('underground', 2000, 'Offering an insightful look at Communist Eastern Europe through the microcosm of a long friendship, Underground is an exhausting, exhilarating epic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the thirteenth floor', 1999, 'Bad script and confusing plot undermine the movie''s impressive visuals.', TO_DATE('1999-05-28', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jack frost', 2000, 'Sentimental schmaltz and uninspired storytelling sink this film.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deep blue sea', 2000, 'Deep Blue Sea is no Jaws, but action fans seeking some toothy action can certainly do -- and almost certainly have done -- far worse for B-movie thrills.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the haunting', 2000, 'Sophisticated visual effects fail to offset awkward performances and an uneven script.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dick', 2000, 'A clever, funny slice of alternate history, Dick farcically re-imagines the Watergate era and largely succeeds, thanks to quirky, winning performances from Michelle Williams, Kirsten Dunst and Will Ferrell.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('william shakespeares a midsummer nights dream', 1999, 'Faultless production and shining performances display the Bard''s talent propitiously.', TO_DATE('1999-05-14', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an ideal husband', 2000, 'Brevity is the soul of wit, eh? This adaptation gets to the nitty gritty of Wilde''s stage piece and plays on eternal human foibles.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in too deep', 2000, 'This shallow police film doesn''t establish any kind of rhythm.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the best man', 1999, 'With a strong cast and a host of well-defined characters, The Best Man is an intelligent, funny romantic comedy that marks an impressive debut for writer/director Malcolm D. Lee.', TO_DATE('1999-10-22', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('man on the moon', 1999, 'Jim Carrey is eerily dead-on in his portrayal of Andy Kaufman, which helps to elevate Man on the Moon above the script''s formulaic biopic cliches.', TO_DATE('1999-12-22', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anna and the king', 2000, 'Beautiful cinematography can''t prevent Anna and the King from being boring and overly lengthy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('double jeopardy', 1999, 'A talented cast fails to save this unremarkable thriller.', TO_DATE('1999-09-24', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hurricane', 2000, 'Thanks in large part to one of Denzel Washington''s most powerful on-screen performances, The Hurricane is a moving, inspirational sports drama, even if it takes few risks in telling its story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diamonds', 1999, 'Kirk Douglas'' flinty performance fails to overshadow an otherwise dull and cliche-ridden affair.', TO_DATE('1999-12-10', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the end of the affair', 2000, 'Neil Jordan has good direction with solid performances from Ralph Fiennes and Julianne Moore.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mansfield park', 2000, 'Solid performances, bold direction.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('superstar', 1999, 'Dumb script and flat jokes made this another SNL misfire.', TO_DATE('1999-10-08', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('house on haunted hill', 1999, 'Unsophisticated and unoriginal film fails to produce scares.', TO_DATE('1999-10-29', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tumbleweeds', 2000, 'Strong performances add authenticity and depth.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bachelor', 2000, 'Clichéd, witless and irritating, The Bachelor proves Chris O''Donnell is no Buster Keaton.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last night', 1998, 'An engrossing, poignant film, Last Night examines the end of the world through humorous and thought-provoking dialogue.', TO_DATE('1998-06-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a dog of flanders', 2000, 'Bleak tale, terrible acting.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eye of the beholder', 2000, 'Improbable and muddled.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the celebration festen', 2000, 'As sharp and ruthless as the family dynamic that powers its plot, The Celebration blends tragedy and comedy to brilliant effect.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boiler room', 2000, 'Its ending is disappointingly tidy, but Boiler Room boasts just enough sharp writing and brisk pacing to make getting there worthwhile.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what planet are you from', 2000, 'Though What Planet Are You From? has some laughs, it''s too inconsistent and bland for critics to give it their recommendations.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whatever it takes', 2000, 'Whatever It Takes is another run-of-the-mill teeny-bopper romance flick. Cliche jokes and a tired plot capture few laughs.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('high fidelity', 2000, 'The deft hand of director Stephen Frears and strong performances by the ensemble cast combine to tell an entertaining story with a rock-solid soundtrack.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('where the heart is', 2000, 'Poor script and messy plot undermines the decent cast.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('committed', 2000, 'Critics say Committed is one of those films that shows promise -- some sort of vision -- of what the movie could have been. The key word is "could." As it is, the script is predictable, the story becomes tedious, and it''s simply not funny. Heather Graham shows she can play a central character, but she''s not enough to make Committed successful.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dinosaur', 2000, 'While Dinosaur''s plot is generic and dull, its stunning computer animation and detailed backgrounds are enough to make it worth a look.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('screwed', 2000, 'Despite having real comics in the cast, this tedious and painfully unfunny movie desperately needs a screenplay.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hamlet', 2000, 'Stiff performances fail to produce any tension onscreen.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('road trip', 2000, 'Some humor is hit or miss, depending on the audience tastes, but the movie is funny overall. Mixed reviews for the cast, especially for MTV''s Tom Green.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('running free', 2000, 'The narration in Running Free detracts from its beauty, and pushes the film to the point of absurdity.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gone in 60 seconds gone in sixty seconds', 2000, 'Even though Oscar-bearers Nicolas Cage, Angelina Jolie, and Robert Duval came aboard for this project, the quality of Gone in 60 Seconds is disappointingly low. The plot line is nonsensical, and even the promised car-chase scenes are boring.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('george washington', 2000, 'Languid and melancholy, George Washington is a carefully observed rumination on adolescence and rural life.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shaft', 2000, 'With a charismatic lead, this new Shaft knows how to push the right buttons.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the patriot', 2000, 'The Patriot can be entertaining to watch, but it relies too much on formula and melodrama.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the in crowd', 2000, 'A dull, soapy potboiler that lacks the energy to qualify as a guilty pleasure, The In Crowd is undone by slow pacing, poor acting, and a stunning lack of originality.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 2.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('loser', 2000, 'In the grand tradition of teen flicks, Loser comes across as another predictable and underwritten movie with nothing new to offer.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saving grace', 2000, 'The plot and basis for jokes are slight, but Saving Grace is indeed saved by some charming performances, most notably Brenda Blethyn''s.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the art of war', 2000, 'Excessively noisy and overly reliant on genre clichés, The Art of War wastes its star''s charisma on a ridiculous, convoluted plot and poorly edited action sequences.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the crew', 2000, 'Though the four actors are good together, the jokes are stale and not funny.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('10 cloverfield lane', 2016, 'Smart, solidly crafted, and palpably tense, 10 Cloverfield Lane makes the most of its confined setting and outstanding cast -- and suggests a new frontier for franchise filmmaking.', TO_DATE('2016-03-08', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('10 things i hate about you', 2000, 'Julia Stiles and Heath Ledger add strong performances to an unexpectedly clever script, elevating 10 Things (slightly) above typical teen fare.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('10 years', 2011, 'A sweet ensemble comedy about a high school reunion, 10 Years is well cast but unfortunately predictable and short on three dimensional characters.', TO_DATE('2011-09-14', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('10th wolf', 2006, 'A scattered mob movie that employs every mafia cliche and fails to establish an identity of its own.', TO_DATE('2006-08-11', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bait', 2000, 'Even though Jamie Foxx shines in Bait, the movie suffers from music video roots and a formulaic script that strains credibility.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('duets', 2000, 'Duets suffers from sloppy direction and stretches credibility. Also, the characters are uninteresting and it''s hard to care about what happens to them.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beautiful', 2000, 'Sally Field''s directing debut suffers from an inconsistent tone, implausible script, and a protagonist that critics say is one of the most loathsome to come around in a long time.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('under suspicion', 2000, 'Though Hackman and Freeman turn in solid performances, Under Suspicion moves at a plodding rate and has a disappointing ending.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('get carter', 2000, 'Michael Caine shows up to collect a paycheck, and so does everyone else in this rote, middling remake.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the contender', 2000, 'The Contender wears its political heart on its sleeve, but strong performances and a solid screenplay help the end result add up to a gripping drama from either side of the aisle.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ladies man', 2000, 'The Ladies Man joins the growing list of mediocre movies based on SNL skits. It just doesn''t have enough material to last the length of the movie.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lost souls', 2000, 'Though Kaminski''s film is visually stylish, Lost Souls is just another derivative entry in the Apocalypse genre, with lackluster direction, unengaging characters, and no scares.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bedazzled', 2000, 'Though it has its funny moments, this remake is essentially a one-joke movie with too many flat spots.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blow dry', 2000, 'Heartwarming, but over-the-top and too formulaic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('malena', 2000, 'Malena ends up objectifying the character of the movie''s title. Also, the young boy''s emotional investment with Malena is never convincing, as she doesn''t feel like a three-dimensional person.', TO_DATE('2000-12-14', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the gift', 2000, 'With a reported budget of around 10 million, The Gift is obviously a labor of love for those involved. Unfortunately, the A-list cast can''t prevent the movie from becoming a by-the-numbers whodunit with an ending that''s all but unsatisfactory.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('traffic', 2000, 'Soderbergh successfully pulls off the highly ambitious Traffic, a movie with three different stories and a very large cast. The issues of ethics are gray rather than black-and-white, with no clear-cut good guys. Terrific acting all around.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('double take', 2000, 'Despite a good performance by Orlando Jones, the movie is ruined by a ridiculous, messy plot and fails to generate laughs.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the pledge', 2000, 'Though its subject matter is grim and may make viewers queasy, The Pledge features an excellent, subtle performance by Jack Nicholson.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('panic', 2000, 'This quirky little film about a gangster in therapy feels fresh and well-crafted.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hannibal', 2000, 'While superbly acted and stylishly filmed, Hannibal lacks the character interaction between the two leads which made the first movie so engrossing.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('down to earth', 2000, 'A toned down Chris Rock fails to bring a limp script to life as the movie moves from one gag to the next.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sweet november', 2000, 'Schmaltzy and manipulative, Sweet November suffers from an implausible plot and non-existent chemistry between its leads.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the brothers', 2001, 'Often seen as a Waiting to Exhale with men, The Brothers is amiable. However, it feels superficial and somewhat of a retread.', TO_DATE('2001-03-20', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heartbreakers', 2000, 'Though the actors pour a lot of energy into their roles, Heartbreakers is too drawn out, and the romantic subplot doesn''t blend well. Also, the con women aren''t particularly sympathetic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('someone like you', 2000, 'A light and predictable, if somewhat shallow, romantic comedy that''s easy to sit through because of the charming leads.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hamlet', 2001, 'While its staging is more competent than revelatory, Hamlet offers a nuanced lead performance from actor/director Campbell Scott.', TO_DATE('2001-08-17', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lie', 2001, 'L.I.E. is a well-acted and unsettling look at a boy''s relationship with a pedophile.', TO_DATE('2001-02-13', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('driven', 2001, 'Underdeveloped characters, silly plot dynamics, and obvious CG effects.', TO_DATE('2001-04-23', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ace in the hole the big carnival', 2002, 'Spearheaded by an excellent Kirk Douglas, Ace in the Hole is an incisive and sardonic satire that, much like its opportunistic hero, never lets moral compunction get in the way of a good story.', TO_DATE('2002-09-03', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brother', 2001, 'There is too much hollow bloodshed in Brother, and the characters are stereotypically flat.', TO_DATE('2001-02-07', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('angel eyes', 2000, 'Though the earlier part of the movie suggested something more, the movie turns out to be nothing more than a schmaltzy romance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the animal', 2001, 'While less offensive and more charming than recent gross-humored comedies, The Animal is still rather mediocre.', TO_DATE('2001-05-30', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('evolution', 2000, 'Director Reitman tries to remake Ghostbusters, but his efforts are largely unsuccessful because the movie has too many comedic misfires.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fast and the furious', 2000, 'Sleek and shiny on the surface, The Fast and the Furious recalls those cheesy teenage exploitation flicks of the 1950s.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pearl harbor', 2000, 'Pearl Harbor tries to be the Titanic of war movies, but it''s just a tedious romance filled with laughably bad dialogue. The 40 minute action sequence is spectacular though.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the road home wo de fu qin mu qin', 2001, 'Beautifully filmed, The Road Home is a simple touching and tender love story.', TO_DATE('2001-03-07', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('planet of the apes', 2001, 'This remake of Planet of the Apes can''t compare to the original in some critics'' mind, but the striking visuals and B-movie charms may win you over.', TO_DATE('2001-07-23', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the score', 2001, 'Though the movie treads familiar ground in the heist/caper genre, Robert DeNiro, Edward Norton, and Marlon Brando make the movie worth watching.', TO_DATE('2001-07-10', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heist', 2001, 'Heist didn''t cover any new ground, but the cast and Mamet''s expertise with witty banter make it worthwhile.', TO_DATE('2001-08-20', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the others', 2001, 'The Others is a spooky thriller that reminds us that a movie doesn''t need expensive special effects to be creepy.', TO_DATE('2001-07-22', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hamlet', 1990, 'It may lack some of the depth and complexity of the play, but Mel Gibson and Franco Zeffirelli make a surprisingly successful team.', TO_DATE('1990-12-19', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big trouble', 2002, 'With its large cast and frantic comic pacing, Big Trouble labors for slapstick-style hilarity, but it never really gains steam.', TO_DATE('2002-03-13', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sidewalks of new york', 2001, 'Though well-acted, Sidewalks of New York generally comes off as a second-rate Woody Allen film. The characters seem self-absorbed, the problems trite.', TO_DATE('2001-05-03', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wash', 2001, 'Sloppily-made, amateurish, and scarce on laughs, The Wash can''t compare to Richard Pryor''s 1976 Car Wash.', TO_DATE('2001-11-14', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('collateral damage', 2002, 'Despite its timely subject matter, Collateral Damage is an unexceptional and formulaic action thriller.', TO_DATE('2002-02-03', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the count of monte cristo', 2002, 'Though it may not reach for any new artistic heights, The Count of Monte Cristo is an old-fashioned yet enjoyable swashbuckler.', TO_DATE('2002-01-04', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('on the line', 2001, 'An inept attempt at a romantic comedy aimed at ''Nsync fans.', TO_DATE('2001-10-18', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('invincible', 2002, 'Sluggish and flawed, this is a minor work in Herzog''s career.', TO_DATE('2002-04-17', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('texas rangers', 2001, 'As far as westerns go, Texas Rangers is strictly mediocre stuff.', TO_DATE('2001-11-30', 'YYYY-MM-DD'), 2.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('iris', 2001, 'A solidly constructed drama, Iris is greatly elevated by the strength of its four lead performances.', TO_DATE('2001-11-16', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('james dean', 2003, 'James Franco''s uncanny portrayal of James Dean keeps this biopic engrossing, even as it emphasizes the Hollywood icon''s myth over his more nuanced life story.', TO_DATE('2003-07-22', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('behind enemy lines', 2001, 'The plot for Behind Enemy Lines is more jingoistic than credible, and the overload of flashy visual tricks makes the action sequences resemble a video game.', TO_DATE('2001-11-21', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scoobydoo', 2002, 'Though Lillard is uncannily spot-on as Shaggy, Scooby Doo is a tired live-action update, filled with lame jokes.', TO_DATE('2002-06-10', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crossroads', 2002, 'A cliched and silly pop star vanity project, Crossroads is strictly for Britney fans only.', TO_DATE('2002-02-12', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the new guy', 2002, 'Incoherent, silly, and unoriginal, The New Guy offers up the same old teen gross-out comedy cliches.', TO_DATE('2002-05-07', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the time machine', 2002, 'This Machine has all the razzle-dazzles of modern special effects, but the movie takes a turn for the worst when it switches from a story about lost love to a confusing action-thriller.', TO_DATE('2002-03-04', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rookie', 2002, 'A heart-warming sports flick, The Rookie greatly benefits from understated direction and the emotional honesty Dennis Quaid brings to the role of Jim Morris.', TO_DATE('2002-02-27', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('showtime', 2002, 'Showtime starts out as a promising satire of the buddy cop genre. Unfortunately, it ends up becoming the type of movies it is satirizing.', TO_DATE('2002-03-11', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('human nature', 2001, 'As quirky as Being John Malkovich but not as funny, Human Nature feels too forced and unengaging.', TO_DATE('2001-05-21', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('murder by numbers', 2002, 'A predictable police procedural that works better as a character study rather than a thriller.', TO_DATE('2002-04-10', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('enigma', 2001, 'The well-crafted, twist-filled Enigma is a thinking person''s spy thriller.', TO_DATE('2001-09-04', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('joshua', 2002, 'Joshua is well-intentioned, but too heavy-handed.', TO_DATE('2002-04-14', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('enough', 2002, 'Enough exploits the serious issue of spousal abuse to make an illogical, unintelligent thriller.', TO_DATE('2002-05-11', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('insomnia', 2002, 'Driven by Al Pacino and Robin Williams'' performances, Insomnia is a smart and riveting psychological drama.', TO_DATE('2002-05-02', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('they', 2002, 'They fails to sustain the level of creepiness necessary to rise above other movies in the horror genre.', TO_DATE('2002-10-13', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trapped', 2002, 'With its plot about child kidnapping and endangerment, Trapped is an exploitative thriller, more queasy than suspenseful.', TO_DATE('2002-09-20', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('derailed', 2002, 'Derailed is one of those familiar and pulpy cautionary tales that depend largely on implausible coincidences and preposterous twists.', TO_DATE('2002-11-08', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('swept away', 2002, 'Muddled and lacking the political context of the original, Swept Away offers further proof that Madonna can''t act.', TO_DATE('2002-10-07', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all or nothing', 2002, 'All or Nothing''s depiction of the working-class can be depressingly bleak, but the performances are wonderfully true to life.', TO_DATE('2002-05-18', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('femme fatale', 2002, 'The thriller Femme Fatale is overheated, nonsensical, and silly.', TO_DATE('2002-05-21', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the quiet american', 2002, 'Thoughtful and wonderfully acted, The Quiet American manages to capture the spirit of Green''s novel.', TO_DATE('2002-08-09', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('empire', 2002, 'In terms of the gangster genre, Empire''s story is yet another tired retread.', TO_DATE('2002-10-09', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adaptation', 2002, 'Dizzyingly original, the loopy, multi-layered Adaptation is both funny and thought-provoking.', TO_DATE('2002-11-06', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pinocchio', 2002, 'Roberto Benigni misfires wildly with this adaptation of Pinocchio, and the result is an unfunny, poorly-made, creepy vanity project.', TO_DATE('2002-10-08', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nicholas nickleby', 2002, 'Thanks to a strong cast of experienced actors and director Douglas McGrath''s steady hand, Nicholas Nickleby is a worthy and respectful adaptation of the Dickens novel.', TO_DATE('2002-11-07', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hunted', 2003, 'An all too familiar chase movie that''s not worth the talents involved.', TO_DATE('2003-03-11', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anger management', 2003, 'Thought not without its funny moments, Anger Management is ultimately stale and disappointingly one-note, especially considering its capable cast.', TO_DATE('2003-04-03', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spellbound', 2002, 'A suspenseful, gripping documentary that features an engaging cross section of American children.', TO_DATE('2002-10-20', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('carrie', 2013, 'This made-for-TV adaptation of Stephen King''s classic fails to impress or bring anything new to the table, - or to the prom - paling even more in comparison to the 1970''s memorable version.', TO_DATE('2013-10-09', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('le divorce', 2003, 'A mixed bag of uneven tones that feels flat.', TO_DATE('2003-07-19', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grind', 2003, 'Mediocre skateboard stunts are padded by a half-baked plot and one-dimensional characters.', TO_DATE('2003-01-15', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cabin fever', 2003, 'More gory than scary, Cabin Fever is satisfied with paying homage to genre conventions rather than reinventing them.', TO_DATE('2003-03-11', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('luther', 2003, 'This cinematic treatment of Martin Luther''s life is more dull than inspiring.', TO_DATE('2003-09-01', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dummy', 2003, 'Dummy is a sweet family comedy that succeeds due to charming performances, even if the final product feels slightly undercooked.', TO_DATE('2003-03-19', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('good boy', 2003, 'Good Boy! should appeal to kids. Adults, however, might consider it a dog.', TO_DATE('2003-10-05', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('house of the dead', 2003, 'A grungy, disjointed, mostly brainless mess of a film, House of the Dead is nonetheless loaded with unintentional laughs.', TO_DATE('2003-10-09', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mayor of the sunset strip', 2003, 'A fascinating, poignant look at the cult of celebrity.', TO_DATE('2003-10-15', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the missing', 2003, 'An expertly acted and directed Western. But like other Ron Howard features, the movie is hardly subtle.', TO_DATE('2003-11-17', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big fish', 2003, 'A charming father-and-son tale filled with typical Tim Burton flourishes, Big Fish is an impressive catch.', TO_DATE('2003-11-20', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the company', 2003, 'Its deliberately unfocused narrative may frustrate some viewers, but The Company finds Altman gracefully applying his distinctive eye to the world of dance.', TO_DATE('2003-09-03', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('peter pan', 2003, 'Solid if far from definitive, this version of Peter Pan is visually impressive, psychologically complex and faithful to its original source.', TO_DATE('2003-12-09', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('torque', 2004, 'Silly and noisy, Torque is stylish fun for the MTV crowd.', TO_DATE('2004-01-12', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the reckoning', 2003, 'A talky, ponderous movie.', TO_DATE('2003-04-30', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the girl next door', 2004, 'The movie borrows heavily from Risky Business, though Hirsch and Cuthbert are appealing leads.', TO_DATE('2004-02-04', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ned kelly', 2003, 'More depth about the legendary outlaw would be welcome, but as it is, Ned Kelly is a reasonably entertaining Western.', TO_DATE('2003-03-16', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('envy', 2004, 'Jack Black and Ben Stiller fail to wring laughs from a script that''s essentially one extended poop joke.', TO_DATE('2004-03-30', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the punisher', 2004, 'A good cast fails to elevate this overly violent and by-the-numbers revenge flick.', TO_DATE('2004-03-30', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('valentin', 2003, 'A coming-of-age tale that''s more cloying than affecting.', TO_DATE('2003-05-22', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the terminal', 2004, 'The Terminal transcends its flaws through the sheer virtue of its crowd-pleasing message and a typically solid star turn from Tom Hanks.', TO_DATE('2004-05-24', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('king arthur', 2004, 'The magic is gone, leaving a dreary, generic action movie.', TO_DATE('2004-04-26', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('uncovered the war on iraq', 2004, 'A political doc that methodically and effectively argues its case.', TO_DATE('2004-08-11', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lightning in a bottle', 2004, 'Lightning in a Bottle pays dazzling tribute to the blues by capturing its power and excitement through backstage interviews and performance footage.', TO_DATE('2004-03-18', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beauty shop', 2005, 'Despite a strong performance by Queen Latifah, Beauty Shop is in need of some style pointers.', TO_DATE('2005-03-10', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hostage', 2005, 'Grisly and cliched, audiences may feel they''re being held Hostage.', TO_DATE('2005-03-01', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('are we there yet', 2005, 'This supposed family comedy staring the usually blameless Ice Cube and Nia Long has provoked most critics to write, "Is it over yet?"', TO_DATE('2005-01-07', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hide and seek', 2005, 'Robert De Niro and especially Dakota Fanning have earned some praise for their work in Hide and Seek, but critics have called the rest of the film derivative, illogical and somewhat silly.', TO_DATE('2005-01-25', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cursed', 2005, 'A predictable plot and cheesy special effects make Cursed a less-than-scary experience.', TO_DATE('2005-02-24', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sky high', 2005, 'This highly derivative superhero coming-of-age flick is moderately entertaining, family-friendly fluff.', TO_DATE('2005-07-26', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('appurushîdo appleseed', 2004, 'While visually arresting, Appleseed''s narrative and dialogue pondering existentialism is ponderous, awkward, and clumsy.', TO_DATE('2004-12-20', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sahara', 2005, 'A mindless adventure flick with a preposterous plot.', TO_DATE('2005-03-12', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crash', 2004, 'A raw and unsettling morality piece on modern angst and urban disconnect, Crash examines the dangers of bigotry and xenophobia in the lives of interconnected Angelenos.', TO_DATE('2004-09-22', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the honeymooners', 2005, 'This pointless remake of the classic TV series only offers generic characters and gags.', TO_DATE('2005-06-07', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stealth', 2005, 'Loud, preposterous, and predictable, Stealth borrows heavily and unsucessfully from Top Gun and 2001.', TO_DATE('2005-07-22', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the skeleton key', 2005, 'Thanks to its creaky and formulaic script, The Skeleton Key is more mumbo-jumbo than hoodoo and more dull than scary.', TO_DATE('2005-06-29', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red eye', 2005, 'With solid performances and tight direction from Wes Craven, Red Eye is a brisk, economic thriller.', TO_DATE('2005-07-30', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bomb the system', 2005, 'Given the movie''s premise, one would assume it''s gritty and street-smart, but in reality it''s a slave to stale cliches and formula.', TO_DATE('2005-01-15', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hellbent', 2005, 'Hellbent is proof that gay slasher films can be just as tedious and mediocre as straight ones.', TO_DATE('2005-04-29', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('venom', 2005, 'A voodoo horror flick without the mojo, Venom is chock full of gory impalings of interchangeable teenage girls and hunky guys by an unstoppable zombie whose unimaginative rampage quickly lulls us to sleep.', TO_DATE('2005-09-13', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('capote', 2005, 'Philip Seymour Hoffman''s riveting central performance guides a well-constructed retelling of the most sensational and significant period in author Truman Capote''s life.', TO_DATE('2005-09-03', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nine lives', 2005, 'Nine Lives is bolstered by a strong cast and features many insightful glimpses into the lives of women.', TO_DATE('2005-09-10', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('good night and good luck', 2005, 'A passionate and concise cinematic civics lesson, Good Night, And Good Luck has plenty to say about today''s political and cultural climate, and its ensemble cast is stellar.', TO_DATE('2005-09-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kids in america', 2005, 'An awkward blend of teen comedy and social commentary, Kids in America largely fails to provoke thought or laughter.', TO_DATE('2005-10-18', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rent', 2005, 'Fans of the stage musical may forgive Rent its flaws, but weak direction, inescapable staginess and an irritating faux-boho pretension prevent the film from connecting on screen.', TO_DATE('2005-11-13', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jarhead', 2005, 'This first person account of the first Gulf War scores with its performances and cinematography but lacks an emotional thrust.', TO_DATE('2005-10-23', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the new world', 2005, 'Despite arresting visuals and strong lead performances, The New World suffers from an unfocused narrative that will challenge viewers'' attention spans over its 2 1/2 hours.', TO_DATE('2005-11-30', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pride and prejudice', 2005, 'Sure, it''s another adaptation of cinema''s fave Jane Austen novel, but key performances and a modern filmmaking sensibility make this familiar period piece fresh and enjoyable.', TO_DATE('2005-08-26', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ringer', 2005, 'Despite a few laughs and good intentions, The Ringer is too predictable to really score the points it aims for.', TO_DATE('2005-12-21', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('breakfast on pluto', 2005, 'Well-acted if monotonous drama about a transvestite prostitute in London during the 1970s.', TO_DATE('2005-08-29', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('curious george', 2006, 'Curious George is a bright, sweet, faithful adaptation of the beloved children''s books.', TO_DATE('2006-02-03', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big mommas house 2', 2006, 'Unfunny and unoriginal. In other words, a perfect piece of evidence for opponents of pointless movie sequels.', TO_DATE('2006-01-19', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the promise master of crimson armor wu ji', 2006, 'An incoherent plot and ridiculously obvious CGI effects doom this effort from the usually outstanding Chinese director Chen Kaige.', TO_DATE('2006-01-03', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hoodwinked', 2005, 'This fractured fairytale doesn''t have the wit or animation quality to compete with the likes of the Shrek franchise.', TO_DATE('2005-01-13', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('glory road', 2006, 'As formulaic as sports movies get, this underdog story still triumphs on the strength of its inspiring story.', TO_DATE('2006-01-06', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('date movie', 2006, 'In an attempt to parody rom-com cliches, Date Movie ultimately makes a mockery of itself, with juvenile toilet humor and empty pop culture references.', TO_DATE('2006-02-06', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('why we fight', 2005, 'A provocative and timely film that explores the military/industrial complex and the motivating forces that lead us to war.', TO_DATE('2005-02-02', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('casanova', 2005, 'This frothy, oddly bloodless film does a disservice to the colorful life of the real Casanova.', TO_DATE('2005-10-08', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('doogal', 2006, 'Overloaded with pop culture references, but lacking in compelling characters and plot, Doogal is too simpleminded even for the kiddies.', TO_DATE('2006-02-10', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('summer storm sommersturm', 2005, 'Strong performances and an inclusive approach to sexual awakening aren''t enough to make Summer Storm a truly memorable coming-of-age story.', TO_DATE('2005-03-11', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adam steve', 2005, 'Gross-out comedy and true love make for an awkward mix in this clunky romance.', TO_DATE('2005-04-24', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('on a clear day', 2005, 'Another blue-collar inspirational feel-good British dramedy, On A Clear Day succeeds on the strength of lead actor Peter Mullan''s performance and Gaby Dellal''s competent direction.', TO_DATE('2005-02-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('clean', 2004, 'In one of her best roles, Cheung gives a believable and arresting performance as a recovering addict.', TO_DATE('2004-09-21', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('london', 2005, 'Hampered by pretension and undermined by unlikable characters, London proves that the novelty of seeing actors play against type isn''t enough to rescue a deeply flawed film.', TO_DATE('2005-09-20', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little fish', 2005, 'Fueled by powerful work from a strong cast led by Cate Blanchett, Little Fish is a hard-hitting story worth watching -- and a major step forward for director Rowan Woods.', TO_DATE('2005-09-14', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('evil ondskan', 2003, 'Evil''s attempts to unpack the causes and effects of violence aren''t always successful, but the well-acted end result still has an unsettling impact.', TO_DATE('2003-10-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the devil and daniel johnston', 2005, 'Whether you think this mentally ill cult musician is worthy of being called a "genius," this document of his life is crafted with sincere respect and is fascinating to watch.', TO_DATE('2005-03-21', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('see no evil', 2006, 'See No Evil is packed with cliches from countless other teen slasher films, making for a predictable, scare-free waste of time.', TO_DATE('2006-05-19', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marie antoinette', 2006, 'Lavish imagery and a daring soundtrack set this film apart from most period dramas; in fact, style completely takes precedence over plot and character development in Coppola''s vision of the doomed queen.', TO_DATE('2006-05-25', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('goal the dream begins goal the impossible dream', 2005, 'Impressive sports action sequences are the highlight, as the run-of the-mill story invokes every known sports movie cliche.', TO_DATE('2005-08-21', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sleeping dogs lie', 2006, 'Though Sleeping Dogs Lie treats its subject and characters humanely, it''s unable to overcome the low-budget production and Bobcat Goldthwait''s pedestrian directing.', TO_DATE('2006-01-23', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the oh in ohio', 2006, 'A muddled sex-comedy that feels oddly sexless, The Oh in Ohio packs in too many ideas without establishing a clear identity or objective.', TO_DATE('2006-03-16', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('christmas in the clouds', 2005, 'An agreeably familiar story with some welcome quirky twists, Christmas in the Clouds offers all the comforting entertainment its title suggests.', TO_DATE('2005-09-24', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hoax', 2006, 'The Hoax is an enormously appealing film, thanks to the uniformly excellent performances and Lasse Hallström''s zippy direction.', TO_DATE('2006-10-16', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('for your consideration', 2006, 'As the object of satire gets bigger the jokes become thinner, and Christopher Guest isn''t as droll or insightful here than when he was lampooning smaller subjects.', TO_DATE('2006-09-10', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('free zone', 2005, 'The symbolism in this cinematic metaphor on conflicts in the Middle East becomes so overbearing that it''s hard to care about the characters or their plight.', TO_DATE('2005-05-19', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('standing still', 2005, 'This coming-of-age film''s young, attractive cast helps to mitigate the stultifying dialogue and uninspired direction.', TO_DATE('2005-06-07', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('superhero movie', 2008, 'Superhero Movie is not the worst of the spoof genre, but relies on tired gags and lame pop culture references all the same.', TO_DATE('2008-03-28', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('look both ways', 2005, 'With animated sequences adding imaginative quirkiness to the mix, this movie about death and disaster is insightful, empathic, and more uplifting than one would think.', TO_DATE('2005-09-18', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bobby', 2006, 'Despite best intentions from director Emilio Estevez and his ensemble cast, they succumb to a script filled with pointless subplots and awkward moments working too hard to parallel contemporary times.', TO_DATE('2006-09-05', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cavite', 2005, 'A gritty, low-budget thriller, Cavite takes us on a heart-pounding ride through the seedy Filipino underworld.', TO_DATE('2005-03-22', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('coastlines', 2006, 'Coastlines features solid lead performances, but is hindered by an unconvincing love triangle and scattered direction. Not up to the standard of Victor Nunez''s previous directorial efforts.', TO_DATE('2006-04-29', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unconscious', 2005, 'A comedy that tackles outrageous subjects (pornography, transvestism, bisexuality and drug abuse) with both grace and mischievous glee.', TO_DATE('2005-04-30', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trade', 2007, 'With an exploitative style that seems more suited for TV shows like CSI, Trade''s message about the reality of child exploitation is easily lost.', TO_DATE('2007-01-25', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red doors', 2005, 'Flawed yet filled with finely detailed characters, Red Doors is a glimpse of the Asian-American experience that suggests great promise for writer-director Georgia Lee.', TO_DATE('2005-06-21', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('driving lessons', 2006, 'Though it has charm, Driving Lessons is a middling offering in the genre where the youngster coming of age meets a quirky senior who teaches valuable lessons about life.', TO_DATE('2006-08-05', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ballets russes', 2005, 'Even if you know little about ballet, there is much to love about this documentary''s captivating archival footage and its interviews with elderly former dancers who have much to share.', TO_DATE('2005-09-10', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the invisible', 2007, 'Dull and confusing execution makes this ghost story utterly forgettable and unintentionally funny.', TO_DATE('2007-04-27', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bridge', 2006, 'Tactlessly morbid or remarkably sensitive? Deeply disturbing or viscerally fascinating? Critics are divided on Eric Steele''s unique documentary on the Golden Gate Bridge, wonder of the modern world and notorious suicide destination.', TO_DATE('2006-10-10', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('conversations with god', 2006, 'At some point in the conversation, God must have asked for a subtler, deeper film.', TO_DATE('2006-10-22', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('perfect stranger', 2007, 'Despite the presence of Halle Berry and Bruce Willis, Perfect Stranger is too convoluted to work, and features a twist ending that''s irritating and superfluous. It''s a techno-thriller without thrills.', TO_DATE('2007-04-08', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vitus', 2006, 'Though not highly original, Vitus is slightly redeemed by its charm and compelling performances.', TO_DATE('2006-11-29', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('definitely maybe', 2008, 'With a clever script and charismatic leads, Definitely, Maybe is a refreshing entry into the romantic comedy genre.', TO_DATE('2008-01-24', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wanted', 2008, 'Wanted is stylish, energetic popcorn fare with witty performances from Angelina Jolie (playing an expert assassin), James McAvoy, and Morgan Freeman that help to distract from its absurdly over-the-top plot.', TO_DATE('2008-06-20', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('silk', 2007, 'Silk contains a simple love triangle story but director Francois Gerard goes to painstaking lengths to turn it into a protracted and wearisome art film.', TO_DATE('2007-09-08', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('license to wed', 2007, 'Featuring one of Robin Williams'' most shtick-heavy performances, the broad and formulaic License to Wed wrings little out of its slightly creepy, unappealing premise.', TO_DATE('2007-06-28', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fred claus', 2007, 'A slew of talent is wasted in this contrived and overly sentimental Christmas film, which can''t quite get the balance between slapstick humor and schmaltzy uplift.', TO_DATE('2007-07-12', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('antikörper antibodies', 2005, 'It''s derivative and its more ambitious aspirations don''t amount to much, but Antibodies remains a reasonably diverting and well-made thriller.', TO_DATE('2005-05-12', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('funny games', 2007, 'Though made with great skill, Funny Games is nevertheless a sadistic exercise in chastising the audience.', TO_DATE('2007-10-23', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the jane austen book club', 2007, 'Though at times formulaic and sentimental, Jane Austen Book Club succeeds on the strength of its likable ensemble cast. Even those not familiar with Jane Austen''s work may find much to enjoy this lighthearted romance.', TO_DATE('2007-09-10', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lars and the real girl', 2007, 'Lars and the Real Girl could''ve so easily been a one-joke movie. But the talented cast, a great script, and direction never condescends to its character or the audience.', TO_DATE('2007-09-08', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('descent', 2007, 'Descent has the potential to make a statement about sexual violence, but falls flat by focusing on revenge rather than Rosario Dawson''s emotional state.', TO_DATE('2007-06-22', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hollywood dreams', 2007, 'Yet another film about a small town girl trying to make it in the City of Angels, Hollywood Dreams'' improvisation and absurdity tests viewers'' patience.', TO_DATE('2007-05-15', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the final season', 2007, 'The Final Season recycles clichés we''ve seen in countless other sports movies, making for an unoriginal and uninspiring addition to the genre.', TO_DATE('2007-10-09', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('take', 2008, 'A story of redemption held together with flashbacks, Take has moments of emotional intensity, but is ultimately undone by preachiness.', TO_DATE('2008-01-25', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('you kill me', 2007, 'Featuring wonderful performances from Ben Kingsley and Tea Leoni, You Kill Me is a charming, funny take on the familiar inner-lives-of-hit-men premise.', TO_DATE('2007-04-30', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amu', 2007, 'Amu uses one woman''s experiences to train a lens on a painful period in Indian history with heartbreaking clarity.', TO_DATE('2007-02-16', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hunting party', 2007, 'The Hunting Party is tonally awkward: its shifts from dark satire to serious political thriller create an uneven film, despite best efforts from its game leads.', TO_DATE('2007-07-25', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alvin and the chipmunks', 2007, 'Though cutely rendered, Alvin and the Chipmunks suffers from bland potty humor and a rehashed kids'' movie formula.', TO_DATE('2007-12-11', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the express', 2008, 'The Express crosses the goal line as an inspirational sports drama, although fans of the genre will recognize many -- if not most -- of its clichés.', TO_DATE('2008-09-29', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rape of europa', 2007, 'The Rape of Europa grapples with a subject that''s vast and powerful enough to fill several films -- and emerges with a story as fascinating as it is infuriating.', TO_DATE('2007-02-02', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blindness', 2008, 'This allegorical disaster film about society''s reaction to mass blindness is mottled and self-satisfied; provocative but not as interesting as its premise implies.', TO_DATE('2008-05-14', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mad money', 2008, 'A laborious, unfunny and implausible heist film.', TO_DATE('2008-01-14', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the haunting in connecticut', 2009, 'Though it features a few scares and some creepy atmosphere, The Haunting in Connecticut ultimately relies too much on familiar horror cliches to achieve its goals.', TO_DATE('2009-03-18', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('billy the kid', 2007, 'Jennifer Venditti''s doc Billy the Kid turns "special" into a double edged sword, forging a sharply honest film around a strangely enigmatic -- if awkward -- kid named Billy.', TO_DATE('2007-12-02', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('angels demons', 2009, 'Angels and Demons is a fast-paced thrill ride, and an improvement on the last Dan Brown adaptation, but the storyline too often wavers between implausible and ridiculous, and does not translate effectively to the big screen.', TO_DATE('2009-05-07', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lovely bones', 2009, 'It''s stuffed full of Peter Jackson''s typically dazzling imagery, but The Lovely Bones suffers from abrupt shifts between horrific violence and cloying sentimentality.', TO_DATE('2009-11-24', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the great buck howard', 2008, 'By turns fluffy and biting, this show biz comedy is given girth by comic heavyweight John Malkovich and made all the more charming by Emily Blunt.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bank job', 2008, 'Well cast and crisply directed, The Bank Job is a thoroughly entertaining British heist thriller.', TO_DATE('2008-02-11', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zack and miri make a porno', 2008, 'Zack and Miri Make a Porno is a modest success for Kevin Smith, due in large part to the charm of Seth Rogen and Elizabeth Banks.', TO_DATE('2008-09-07', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('over her dead body', 2008, 'With few laughs and little romantic chemistry, Over Her Dead Body lacks the ingredients of a successful romantic comedy.', TO_DATE('2008-01-29', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('imagine that', 2009, 'Despite a promising turn by newcomer Yara Shahidi, Imagine That is another pedestrian family comedy that squanders Eddie Murphy''s comedic talents.', TO_DATE('2009-06-08', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghost town', 2008, 'Ricky Gervais'' consistently sharp performance and beautifully dry execution transform this otherwise mainstream comedy into an endearing, funny, and altogether snappy romantic comedy. With ghosts.', TO_DATE('2008-09-08', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('college', 2008, 'A pale imitation of the raunchy frat comedies of old, College aims low and misses.', TO_DATE('2008-08-29', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('changeling', 2008, 'Beautifully shot and well-acted, Changeling is a compelling story that unfortunately gives in to convention too often.', TO_DATE('2008-05-20', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mister lonely', 2007, 'Less biting or offensive than Korine''s earlier works, this frustratingly dull film still maintains the director''s trademark odd beauty.', TO_DATE('2007-05-24', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hell ride', 2008, 'Hell Ride misses out on the rusting zeitgeist of the biker genre, sucking the glee from a saucy premise.', TO_DATE('2008-01-28', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('partition', 2007, 'A disappointing melodrama focussing on the partition of India and Pakistan. Strange cross-culture casting doesn''t help the pedestrian script and direction.', TO_DATE('2007-02-02', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('smart people', 2008, 'Despite its sharp cast and a few laughs, Smart People is too thinly plotted to fully resonate.', TO_DATE('2008-01-21', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('state of play', 2009, 'A taut, well-acted political thriller, State of Play overcomes some unsubtle plot twists with an intelligent script and swift direction.', TO_DATE('2009-04-13', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trumbo', 2007, 'Trumbo celebrates the life and work of blacklisted screenwriter Dalton Trumbo with measures of humor and sadness.', TO_DATE('2007-09-10', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deal', 2008, 'Employing multiple cinematic clichés and milking stale performances, Deal proves inadequate for even the lowly regarded poker movie genre.', TO_DATE('2008-04-23', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chapter 27', 2007, 'Despite Jared Leto''s committed performance, Chapter 27 fails to penetrate to mind of Mark David Chapman, John Lennon''s killer.', TO_DATE('2007-01-24', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('step brothers', 2008, 'Step Brothers indulges in a cheerfully relentless immaturity that will quickly turn off viewers unamused by Ferrell and Reilly -- and delight those who find their antics hilarious.', TO_DATE('2008-07-18', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('noise', 2007, 'Noise starts with an interesting premise, but fails to build it into a cohesive whole.', TO_DATE('2007-02-02', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('elegy', 2008, 'An intelligent, adult, and provocative Philip Roth adaptation that features classy performances, Elegy is never quite the sum of its parts.', TO_DATE('2008-06-14', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ice age dawn of the dinosaurs ice age 3', 2009, 'Ice Age: Dawn of the Dinosaurs boasts some excellent animation -- in particular, the dinosaurs are wonderfully realized -- but its story is tired and monotonous.', TO_DATE('2009-06-21', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('high school musical 3 senior year', 2008, 'It won''t win many converts, but High School Musical 3 is bright, energetic, and well-crafted.', TO_DATE('2008-10-18', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('encounters at the end of the world', 2007, 'Encounters at the End of the World offers a poignant study of the human psyche amid haunting landscapes.', TO_DATE('2007-09-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('phoebe in wonderland', 2008, 'Blessed with a good cast, Phoebe''s heart is in the right place, but its execution is dicey.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wolfman', 2010, 'Suitably grand and special effects-laden, The Wolfman suffers from a suspense-deficient script and a surprising lack of genuine chills.', TO_DATE('2010-02-07', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happygolucky', 2008, 'Mike Leigh''s latest partially-improvised film is a light-hearted comedy with moments that bite, and features a brilliant star turn by Sally Hawkins.', TO_DATE('2008-02-13', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('viva', 2008, 'Though it''s lengthy and doesn''t always walk the line between schlock and kitschy homage successfully, Viva''s lovely visuals and knowing humor are undeniable.', TO_DATE('2008-03-07', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my winnipeg', 2007, 'My Winnipeg is a charmingly irreverent ''docu-fantasy'' from the unpredictable mind of Guy Maddin.', TO_DATE('2007-09-08', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('space chimps', 2008, 'Space Chimps'' cheap animation and overabundance of monkey puns feels especially dated in a post-Wall-E world.', TO_DATE('2008-07-16', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hounddog', 2007, 'Despite a noble effort from Dakota Fanning, Hounddog is overwrought, cliche-ridden and downright exploitative.', TO_DATE('2007-01-23', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('never forever', 2007, 'Smartly constructed by writer-director Gina Kim and brought to life by a strong cast led by Vera Farmiga, Never Forever is an unexpectedly engaging melodrama.', TO_DATE('2007-01-26', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the princess and the frog', 2009, 'The warmth of traditional Disney animation makes this occasionally lightweight fairy-tale update a lively and captivating confection for the holidays.', TO_DATE('2009-11-24', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cloudy with a chance of meatballs', 2009, 'Quirky humor, plucky characters and solid slapstick make this family comedy a frenetically tasty time at the movies.', TO_DATE('2009-09-15', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lou reeds berlin', 2007, 'Julian Schnabel expertly captures the dark melancholy of Lou Reed''s misunderstood concept album in this moving concert documentary.', TO_DATE('2007-09-19', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('patti smith dream of life', 2008, 'Elegiac and personal, Patti Smith: Dream of Life paints an enduring and sometimes rough portrait of the titular chanteuse, complete with footage onstage and at home.', TO_DATE('2008-01-23', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lakeview terrace', 2008, 'This thriller about a menacing cop wreaking havoc on his neighbors is tense enough but threatens absurdity when it enters into excessive potboiler territory.', TO_DATE('2008-09-08', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('quarantine', 2008, 'Quarantine uses effective atmosphere and consistent scares to stand above the crop of recent horror films.', TO_DATE('2008-09-16', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reprise', 2006, 'With Reprise, first-time director Joachim Trier effectively captures the spirit of young adulthood, and announces his arrival as a filmmaker to be watched.', TO_DATE('2006-07-03', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('before the rains', 2007, 'While lushly photographed and politically suggestive, this soapy melodrama lacks emotional resonance.', TO_DATE('2007-09-22', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my name is bruce', 2007, 'My Name Is Bruce succeeds or fails based entirely upon the viewer''s opinion of Bruce Campbell, an unreasonable burden for even the most accomplished actor.', TO_DATE('2007-09-30', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mirrors', 2008, 'Inconsistency and listless plot make this K-horror remake a less-than-frightening time at the movies.', TO_DATE('2008-08-14', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oss 117 le caire nid despions oss 117 cairo nest of spies', 2006, 'This clever spy spoof plays politics and movie conventions for laughs and features a great turn by Jen Dujardin as a smarmy-suave nouveau-Bond.', TO_DATE('2006-04-26', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hofshat kaits my father my lord', 2007, 'This beautiful Israeli film is both a moving family drama and a potent examination of the trials of faith.', TO_DATE('2007-06-11', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ballast', 2008, 'A searing debut by director Lance Hammer, this subtle and contemplative Mississippi set drama lingers long after its conclusion.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paris', 2008, 'Alternately a sharp ensemble dramedy and a love letter to the titular city, Paris is uneven but often striking.', TO_DATE('2008-03-31', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fantastic mr fox', 2009, 'Fantastic Mr. Fox is a delightfully funny feast for the eyes with multi-generational appeal -- and it shows Wes Anderson has a knack for animation.', TO_DATE('2009-10-14', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the perfect game', 2008, 'It''s bogged down with an unfocused script and countless sports movie cliches, but The Perfect Game still manages to charm with its unabashed sweetness and a stirring final act.', TO_DATE('2008-08-03', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shutter island', 2009, 'It may not rank with Scorsese''s best work, but Shutter Island''s gleefully unapologetic genre thrills represent the director at his most unrestrained.', TO_DATE('2009-12-15', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ninja assassin', 2009, 'Overly serious and incomprehensibly edited, Ninja Assassin fails to live up to the promise of its title.', TO_DATE('2009-10-22', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('recount', 2008, 'Recount deftly brings a controversial chapter of electoral history to dramatic life with a compelling cast, although some viewers may take issue with its conclusions.', TO_DATE('2008-05-27', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i love you beth cooper', 2009, 'Heavily reliant on stereotypes and shallow teen comedy clichés, I Love You Beth Cooper is a humorless affair that fails to capture the charm of its source novel.', TO_DATE('2009-07-08', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the 11th hour', 2007, 'Well-researched and swimming in scientific data, this global warming documentary offers some practical and wide-ranging solutions to our climate crisis.', TO_DATE('2007-05-20', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the informant', 2009, 'A charismatic turn by star Matt Damon and a consistently ironic tone boost this quietly funny satire about a corporate whistle-blower.', TO_DATE('2009-09-09', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('robocop', 2008, 'While it''s far better than it could have been, José Padilha''s RoboCop remake fails to offer a significant improvement over the original.', TO_DATE('2008-10-31', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wrecking crew', 2011, 'The Wrecking Crew may not achieve the greatness of the many classic songs its subjects helped bring to life, but it remains a heartfelt, overdue tribute to overshadowed brilliance.', TO_DATE('2011-07-29', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dorian gray', 2009, 'Despite a lavish and polished production, Dorian Gray is tame and uninspired with a lifeless performance by Ben Barnes in the title role.', TO_DATE('2009-09-09', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nobel son', 2008, 'Despite the best efforts of a strong cast, Nobel Son is over-plotted and self-consciously odd.', TO_DATE('2008-11-28', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('17 again', 2009, 'Though it uses a well-worn formula, 17 Again has just enough Zac Efron charm to result in a harmless, pleasurable teen comedy.', TO_DATE('2009-04-04', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the tooth fairy', 2010, 'Dwayne Johnson brings the full force of his charm (and his appropriately pale chompers) to the title role, but flat direction and a committee-written script render The Tooth Fairy unacceptably dull.', TO_DATE('2010-01-09', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the greatest', 2009, 'It''s burdened by a predictable, overly melodramatic story, but The Greatest benefits from strong performances by its talented cast.', TO_DATE('2009-05-09', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark streets', 2008, 'Dark Streets is a film noir musical that''s too gimmicky for its own good.', TO_DATE('2008-12-07', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('green zone', 2010, 'Matt Damon and Paul Greengrass return to the propulsive action and visceral editing of the Bourne films -- but a cliched script and stock characters keep those methods from being as effective this time around.', TO_DATE('2010-03-05', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('easy virtue', 2008, 'A lightweight and pithy Noel Coward adaptation with plenty of sparkle and fizz.', TO_DATE('2008-10-03', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dear zachary a letter to a son about his father', 2008, 'Dear Zachary is a both a touching tribute to a fallen friend and a heart-wrenching account of justice gone astray, skillfully put to film with no emotion spared.', TO_DATE('2008-03-05', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('under the sea 3d', 2009, 'Technically and visually dazzling...', TO_DATE('2009-02-10', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('me and orson welles', 2008, 'Me and Orson Welles boasts a breakout performance by Christian McKay and an infectious love of the backstage drama that overcomes its sometimes fluffy tone.', TO_DATE('2008-09-08', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the children', 2008, 'Unsettling and spine-chilling low-budget British horror, with effective and disturbing scares.', TO_DATE('2008-11-27', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last house on the left', 2009, 'Excessive and gory, this remake lacks the intellectual punch of the 1972 original.', TO_DATE('2009-03-10', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the crazies', 2010, 'Tense, nicely shot, and uncommonly intelligent, The Crazies is a horror remake that, unusually, works.', TO_DATE('2010-02-24', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('9', 2009, 'Although its story is perhaps too familiar and less complex than some might wish, 9 is visually spectacular, and director Shane Acker''s attention to detail succeeds in drawing viewers into the film''s universe.', TO_DATE('2009-08-18', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the three stooges', 2012, 'While nowhere near as painful as it could have been, The Three Stooges fails to add fresh laughs to the Stooges'' inestimable cinematic legacy.', TO_DATE('2012-04-11', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lodger', 2009, 'An accomplished cast can''t save a derivative suspense flick that manages to confuse and bore rather than thrill.', TO_DATE('2009-01-12', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('creation', 2009, 'This Charles Darwin biopic is curiously dispassionate, but Creation contains some of director Jon Amiel''s best work, and Paul Bettany''s performance is not to be missed.', TO_DATE('2009-09-11', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tennessee', 2008, 'Despite some beautiful scenery, Tennessee can''t extend its simple premise beyond typical independent road trip movie tropes.', TO_DATE('2008-12-04', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the taking of pelham 1 2 3', 2009, 'Despite a strong cast, The Taking of Pelham 1 2 3 suffers under the excesses of Tony Scott''s frantic direction, and fails to measure up to the 1974 original.', TO_DATE('2009-06-05', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('obsessed', 2009, 'The inevitable Fatal Attraction comparisons aside, Obsessed is a generic, toothless thriller both instantly predictable and instantly forgettable.', TO_DATE('2009-04-24', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('katyn', 2009, 'Masterfully crafted by an experienced directorial hand, Katyn is a powerful, personal depiction of wartime tragedy.', TO_DATE('2009-02-12', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adam', 2009, 'Hugh Dancy''s elegant performance as a man with Asperger''s Syndrome elevates Adam, an offbeat but touching romantic comedy.', TO_DATE('2009-01-22', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tyson', 2009, 'A fascinating, emotional, and frank confessional from Iron Mike that sheds a sympathetic light on one of boxing''s most controversial icons.', TO_DATE('2009-02-05', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the boys are back', 2009, 'Great performances by Clive Owen and The Boys save this melodrama from entering into the sappy territory it might have in less competent hands.', TO_DATE('2009-09-15', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('splice', 2010, 'It doesn''t take its terrific premise quite as far as it should, but Splice is a smart, well-acted treat for horror fans.', TO_DATE('2010-01-26', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('its complicated', 2009, 'Despite fine work by an appealing cast, It''s Complicated is predictable romantic comedy fare, going for broad laughs instead of subtlety and nuance.', TO_DATE('2009-12-10', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cove', 2009, 'Though decidedly one-sided, The Cove is an impeccably crafted, suspenseful expose of the covert slaughter of dolphins in Japan.', TO_DATE('2009-03-03', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('1208 east of bucharest a fost sau na fost', 2006, 'With a witty script full of satirical overtones and dry humor, 12:08 East of Bucharest is a thoroughly enjoyable Romanian comedy.', TO_DATE('2006-05-25', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mary and max', 2009, 'Mary and Max is a lovingly crafted, startlingly inventive piece of animation whose technical craft is equaled by its emotional resonance.', TO_DATE('2009-01-15', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('puss in boots', 2011, 'It isn''t deep or groundbreaking, but what it lacks in profundity, Puss in Boots more than makes up for with an abundance of wit, visual sparkle, and effervescent charm.', TO_DATE('2011-10-21', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('el baño del papa the popes toilet', 2007, 'An offbeat charmer, The Pope''s Toilet is a humorous, well-crafted tale with plenty of heart and a poignant social message.', TO_DATE('2007-05-24', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the twilight saga eclipse', 2010, 'Stuffed with characters and overly reliant on uninspired dialogue, Eclipse won''t win The Twilight Saga many new converts, despite an improved blend of romance and action fantasy.', TO_DATE('2010-06-28', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('antichrist', 2009, 'Gruesome, explicit and highly controversial; Lars Von Triers arthouse-horror, though beautifully shot, is no easy ride.', TO_DATE('2009-05-18', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('extract', 2009, 'Extract has some very funny moments and several fine performances, but the film feels slighter and more uneven than Mike Judge''s previous work.', TO_DATE('2009-08-19', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the debt', 2010, 'Its time-shifting narrative creates distracting casting problems, but ultimately, The Debt is a smart, well-acted entry in a genre that could use more like it.', TO_DATE('2010-09-05', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('everybodys fine', 2009, 'A calm, charismatic performance from Robert De Niro nearly saves the movie, but ultimately, Everybody''s Fine has the look and feel of a stereotypical Christmas dramedy.', TO_DATE('2009-11-04', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last night', 2010, 'Last Night doesn''t opt for easy answers, but the framework and characters overall are too slight and plain to be compelling.', TO_DATE('2010-09-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('howl', 2010, 'James Franco gives it his all as beat poet Allen Ginsberg, but Howl never develops enough of a focus to do his performance justice.', TO_DATE('2010-01-22', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('life during wartime', 2009, 'With Life During Wartime, Todd Solondz delivers an unexpected semi-sequel to Happiness in typically uncompromising fashion.', TO_DATE('2009-10-30', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the friends of eddie coyle', 2003, 'The Friends of Eddie Coyle sees Robert Mitchum in transformative late-career mode in a gritty and credible character study.', TO_DATE('2003-05-02', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('remember me', 2010, 'Its leads are likeable, but Remember Me suffers from an overly maudlin script and a borderline offensive final twist.', TO_DATE('2010-03-04', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('uncle nino', 2005, 'Critics say that despite a warm, well-meaning message about the importance of family ties, Uncle Nino is utterly corny and predictable.', TO_DATE('2005-02-04', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what goes up', 2009, 'What Goes Up squanders the charisma of Steve Coogan with a lazy screenplay, contrived plotting, and overall poor production.', TO_DATE('2009-05-12', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('home', 2009, 'Disconcerting and sometimes eerie, this enigmatic French film is an assured directorial debut.', TO_DATE('2009-03-30', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('triangle', 2009, 'Triangle sails into some strange waters, but this intelligent, well-acted horror outing anchors its idiosyncrasies in a satisfyingly scary story.', TO_DATE('2009-09-03', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('get him to the greek', 2010, 'Thanks to a suitably raunchy script and a pair of winning performances from Jonah Hill and Russell Brand, Get Him to the Greek is one of the year''s funniest comedies.', TO_DATE('2010-02-12', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the end of the line', 2009, 'A thought-provoking and insightful documentary about the dangers of commercial fishing.', TO_DATE('2009-06-10', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the eclipse', 2009, 'An intriguingly unusual ghost story, Conor McPherson''s Eclipse blends supernatural suspense with romance to create a satisfying, character-driven whole.', TO_DATE('2009-10-08', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the blind side', 2009, 'It might strike some viewers as a little too pat, but The Blind Side has the benefit of strong source material and a strong performance from Sandra Bullock.', TO_DATE('2009-11-16', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('furry vengeance', 2010, 'A thin premise stretched far beyond serviceable length, Furry Vengeance subjects Brendan Fraser -- and the audience -- to 92 minutes of abuse.', TO_DATE('2010-04-27', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('warrior', 2011, 'Warrior relies on many of the clichés that critics of the genre love to mock -- and it transcends them with gripping action, powerful acting, and heart.', TO_DATE('2011-08-10', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beyond a reasonable doubt', 2009, 'Hackneyed and over dramatic, this undercooked courtroom drama suffers from bad dialogue and a twist ending you''ll see from a distance.', TO_DATE('2009-09-03', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a prophet un prophete', 2009, 'Featuring an impressive star turn by newcomer Tahar Rahim, A Prophet is a French gangster film filled with arresting, immediate details.', TO_DATE('2009-05-16', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('homecoming', 2009, 'A lazy collection of obsession thriller clichés, Homecoming will leave viewers wishing they''d opted for a lopsided football game and some awkward dancing instead.', TO_DATE('2009-07-13', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big fan', 2009, 'Featuring Patton Oswalt''s sympathetic portrayal, Big Fan humorously and effectively captures the dark and lonely world of a sports fanatic.', TO_DATE('2009-01-22', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('salt', 2010, 'Angelina Jolie gives it her all in the title role, and her seasoned performance is almost enough to save Salt from its predictable and ludicrous plot.', TO_DATE('2010-07-17', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('did you hear about the morgans', 2009, 'It gets a certain amount of mileage out of the inherent likability of its stars, but with an unfunny script and a lack of onscreen chemistry, Did You Hear About the Morgans? falls flat.', TO_DATE('2009-12-15', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('worlds greatest dad', 2009, 'World''s Greatest Dad is a risky, deadpan, dark comedy that effectively explores the nature of posthumous cults of celebrity.', TO_DATE('2009-03-03', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('no impact man the documentary', 2009, 'Half enviro-saving doc, half publicity stunt, No Impact Man is inspiring and fun to both casual activists and hardcore recyclers.', TO_DATE('2009-07-24', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('death in love', 2008, 'Death in Love has the depth of its convictions, but not even the game efforts of a talented cast are enough to overcome this drama''s stilted story and unlikable characters.', TO_DATE('2008-01-25', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('x games 3d the movie', 2009, 'Though fans of the event will likely enjoy X-Games 3D: The Movie, most will find it a poorly put together, skin deep, extended advertisement for the extreme sports competition.', TO_DATE('2009-08-18', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the way we get by', 2009, 'The Way We Get By is a thoughtful, poignant look at some unsung American heroes.', TO_DATE('2009-03-19', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('five minutes of heaven', 2009, 'Oliver Hirschbiegel''s dramatic take on "The Troubles" is an actor''s showcase -- and Liam Neeson and James Nesbitt are more than up to the challenge.', TO_DATE('2009-01-19', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brothers', 2009, 'It plays more like a traditional melodrama than the Susanne Bier film that inspired it, but Jim Sheridan''s Brothers benefits from rock-solid performances by its three leads.', TO_DATE('2009-11-23', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the collector', 2009, 'Increasingly tedious displays of gore makes this torture porn home-invasion-horror more programmatic than provocative.', TO_DATE('2009-07-26', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('despicable me', 2010, 'Borrowing heavily (and intelligently) from Pixar and Looney Tunes, Despicable Me is a surprisingly thoughtful, family-friendly treat with a few surprises of its own.', TO_DATE('2010-06-09', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the meerkats', 2009, 'A cheerful and cute - though never overly mawkish - nature-doc about... you guessed it... Meerkats.', TO_DATE('2009-08-07', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anita oday the life of a jazz singer', 2007, 'This rich documentary chronicles the highs and lows of one of the medium''s finest singers, utilizing remarkable archive footage and insightful interviews with O''Day herself.', TO_DATE('2007-08-03', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('earth days', 2009, 'This engaging and well-organized eco-doc maps the successes and failures of the American environmental movement, thanks to sharp interviews and remarkable archive footage.', TO_DATE('2009-07-28', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amreeka', 2009, 'A dramedy that''s got a taste for the tragic as well as the poignantly comic, Amreeka adds a new sweetness to the hope and distress of the immigrant experience.', TO_DATE('2009-02-13', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i sell the dead', 2009, 'A horror comedy that''s almost as chilling as it is funny, I Sell the Dead relies on its dark humor and offbeat charm to overcome its low budget shortcomings.', TO_DATE('2009-04-06', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my one and only', 2009, 'A breezy road movie with characters both glamorous and familiar, My One and Only is a colorful period look at the early life of actor George Hamilton.', TO_DATE('2009-02-13', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the horse boy', 2009, 'It traces a familiar, albeit inspirational arc, but The Horse Boy tells a moving tale of parental devotion with grace and sensitivity.', TO_DATE('2009-09-03', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fifty dead men walking', 2008, 'Though somewhat uneven in places, Fifty Dead Men Walking is a gripping portrayal of Ireland''s violent history, carried by the strong performances of its lead actors.', TO_DATE('2008-09-10', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('art copy', 2009, 'Art & Copy doesn''t probe deeply enough, or think critically enough about its subject.', TO_DATE('2009-08-17', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('triangle tie saam gok', 2007, 'Semi-comic-action thriller Triangle teams three leading Hong Kong directors together with confusing results. For asian cinema aficionados only.', TO_DATE('2007-05-18', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('franklyn', 2008, 'Gerald McMorrow''s bold debut is a complex and ambitious film that highlights the director''s potential, but its multi-layered story takes time to develop and might be frustrating for some.', TO_DATE('2008-10-16', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('passing strange', 2009, 'Spike Lee''s document of the Tony Award-winning musical Passing Strange is every bit as compelling onscreen as it was on stage.', TO_DATE('2009-08-13', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we live in public', 2009, 'This documentary about Josh Harris'' surveillance-as-art project exposes the problems of privacy in the internet age and asks provocative questions about the power of ego in a place where everything is on display.', TO_DATE('2009-03-30', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kickass', 2010, 'Not for the faint of heart, Kick-Ass takes the comic adaptation genre to new levels of visual style, bloody violence, and gleeful profanity.', TO_DATE('2010-02-23', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blind date', 2008, 'Despite the chemistry of stars Patricia Clarkson and Stanely Tucci, Blind Date''s stagey direction and underdeveloped story make it feel more like a rehearsal than a performance.', TO_DATE('2008-01-21', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a single man', 2009, 'Though the costumes are beautiful and the art direction impeccable, what stands out most from this debut by fashion designer Tom Ford is the leading performance by Colin Firth.', TO_DATE('2009-10-18', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bounty hunter', 2010, 'Gerard Butler and Jennifer Aniston remain as attractive as ever, but The Bounty Hunter''s formula script doesn''t know what to do with them -- or the audience''s attention.', TO_DATE('2010-03-15', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('che part one the argentine', 2008, 'Though lengthy and at times plodding, Soderbergh''s vision and Benicio Del Toro''s understated performance ensure that Che always fascinates.', TO_DATE('2008-05-22', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alice in wonderland', 2010, 'Tim Burton''s Alice sacrifices the book''s minimal narrative coherence -- and much of its heart -- but it''s an undeniable visual treat.', TO_DATE('2010-02-25', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the losers', 2010, 'The Losers is loud, fast, and unrelentingly violent -- but it''s also funny and well-acted, which will make all the difference for some action fans.', TO_DATE('2010-04-20', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('127 hours', 2010, 'As gut-wrenching as it is inspirational, 127 Hours unites one of Danny Boyle''s most beautifully exuberant directorial efforts with a terrific performance from James Franco.', TO_DATE('2010-09-04', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('twelve monkeys 12 monkeys', 1995, 'The plot''s a bit of a jumble, but excellent performances and mind-blowing plot twists make 12 Monkeys a kooky, effective experience.', TO_DATE('1995-12-27', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('12 oclock boys', 2013, 'Visually striking and grippingly fast-paced, 12 O''Clock Boys asks thought-provoking questions with admirable subtlety and restraint.', TO_DATE('2013-03-12', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('12 rounds', 2009, 'Energetic but empty, 12 Rounds'' preposterous plot hurtles along at a rapid pace, but can''t disguise the derivative script.', TO_DATE('2009-03-14', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('12 strong', 2018, '12 Strong has a solid cast, honorable intentions, and a thrilling, fact-based story - all of which are occasionally enough to balance a disappointing lack of depth or nuance.', TO_DATE('2018-01-16', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('12 years a slave', 2013, 'It''s far from comfortable viewing, but 12 Years a Slave''s unflinchingly brutal look at American slavery is also brilliant -- and quite possibly essential -- cinema.', TO_DATE('2013-08-31', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('13 assassins', 2010, 'Takashi Miike''s electric remake of Eiichi Kudo''s 1963 period action film is a wild spectacle executed with killer, dizzying panache.', TO_DATE('2010-09-13', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('13 going on 30', 2004, 'Although the plot leaves a lot to be desired, 13 Going on 30 will tug at your inner teenager''s heartstrings thanks in large part to a dazzling performance from Jennifer Garner.', TO_DATE('2004-04-11', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('13 hours the secret soldiers of benghazi', 2016, '13 Hours: The Secret Soldiers of Benghazi is a comparatively mature and restrained effort from Michael Bay, albeit one that can''t quite boast the impact its fact-based story deserves.', TO_DATE('2016-01-13', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('13 sins', 2014, '13 Sins may be derivative of other horror films that made their moral points with more finesse, but it atones with a grim sense of humor and sleek style.', TO_DATE('2014-03-08', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('13 tzameti', 2005, 'This starkly minimalist nail-biter of a thriller relentlessly builds up the tension and keeps the audience guessing.', TO_DATE('2005-07-28', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the 13th warrior', 2000, 'Atmospheric, great sets and costumes, but thin plot.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('1408', 2007, 'Relying on psychological tension rather than overt violence and gore, 1408 is a genuinely creepy thriller with a strong lead performance by John Cusack.', TO_DATE('2007-06-13', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('1492 conquest of paradise', 1992, 'Historically inaccurate and dramatically inert, Ridley Scott''s retelling of Christopher Columbus'' exploits is an epic without grandeur or insight.', TO_DATE('1992-10-09', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('15 minutes', 2000, 'As critical as it is about sensationalism in the media, 15 Minutes itself indulges in lurid violence, and its satire is too heavy-handed to be effective.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('16 blocks', 2006, 'Despite strong performances from Bruce Willis and Mos Def, 16 Blocks is a shopworn entry in the buddy-action genre.', TO_DATE('2006-02-24', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('1917', 2019, 'Hard-hitting, immersive, and an impressive technical achievement, 1917 captures the trench warfare of World War I with raw, startling immediacy.', TO_DATE('2019-11-25', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('1922', 2017, 'Thanks to director Zak Hilditch''s patient storytelling and strong work from lead Thomas Jane, 1922 ranks among the more satisfying Stephen King adaptations.', TO_DATE('2017-09-24', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('1941', 2000, 'Steven Spielberg''s attempt at screwball comedy collapses under a glut of ideas, confusing an unwieldy scope for a commensurate amount of guffaws.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('1984', 2000, '1984 doesn''t fully emerge from the shadow of its source material, but still proves a solid, suitably discomfiting adaptation of a classic dystopian tale.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('1985', 2018, '1985 pays tribute to a generation of lost lives with a powerfully made look at how HIV and the social attitudes surrounding homosexuality affect one man''s choices.', TO_DATE('2018-03-12', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('1br', 2019, '1BR''s occasionally ordinary storytelling is more than outweighed by tight direction, interesting ideas, and an effective blend of horror and thoughtful drama.', TO_DATE('2019-07-22', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('20000 days on earth', 2014, 'Revealing yet respectful, 20,000 Days on Earth is essential viewing for any Nick Cave fan.', TO_DATE('2014-01-23', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('2001 a space odyssey', 2000, 'One of the most influential of all sci-fi films -- and one of the most controversial -- Stanley Kubrick''s 2001 is a delicate, poetic meditation on the ingenuity -- and folly -- of mankind.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('2010', 2000, '2010 struggles to escape from the shadow of its monolithic predecessor, but offers brainy adventure in a more straightforward voyage through the cosmos.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('2012', 2009, 'Roland Emmerich''s 2012 provides plenty of visual thrills, but lacks a strong enough script to support its massive scope and inflated length.', TO_DATE('2009-10-24', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('20 feet from stardom', 2013, 'Rich, insightful, and occasionally heartbreaking, 20 Feet From Stardom is an energetic tribute to the passion, talent, and hard work of backup singers.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('20th century women', 2016, '20th Century Women offers Annette Bening a too-rare opportunity to shine in a leading role -- and marks another assured step forward for writer-director Mike Mills.', TO_DATE('2016-10-07', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('211', 2018, '211''s disjointed assortment of action clichés and uninspired set pieces adds up to roughly zero.', TO_DATE('2018-06-02', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('21 and over', 2013, 'Though it strives to mimic The Hangover, 21 and Over is too predictable, too unabashedly profane, and too inconsistently funny to carry the torch.', TO_DATE('2013-02-27', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('21 grams', 2003, 'Alejandro González Iñárritu deftly weaves an uncommonly structured narrative with panache in 21 Grams, a stylish, haunting drama full of fine performances.', TO_DATE('2003-09-07', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('21 jump street', 2012, 'A smart, affectionate satire of ''80s nostalgia and teen movie tropes, 21 Jump Street offers rowdy mainstream comedy with a surprisingly satisfying bite.', TO_DATE('2012-03-04', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('22 july', 2018, '22 July offers a hard-hitting close-up look at the aftereffects of terrorism, telling a story with a thriller''s visceral impact and the lingering emotional resonance of a drama.', TO_DATE('2018-09-05', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('22 jump street', 2014, 'Boasting even more of the bromantic chemistry between its stars -- and even more of the goofy, good-natured humor that made its predecessor so much fun -- 22 Jump Street is the rare sequel that improves upon the original.', TO_DATE('2014-06-03', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('24 city er shi si cheng ji', 2008, 'One of China''s most talented directors blurs the lines between non-fiction, drama, and musical theater in this vivid portrait of a country in cultural flux.', TO_DATE('2008-05-17', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('24 hour party people', 2002, 'The colorful, chaotic 24 Hour Party People nimbly captures the spirit of the Manchester music scene.', TO_DATE('2002-04-10', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my soul to take', 2010, 'Dull, joyless, and formulaic, My Soul to Take suggests writer/director Wes Craven ended his five-year filmmaking hiatus too soon.', TO_DATE('2010-10-07', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('25th hour', 2002, 'An intelligent and well-acted film despite the usual Spike Lee excesses.', TO_DATE('2002-12-10', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('27 dresses', 2007, 'The filmmakers perfectly follow the well-worn romantic comedy formula, rendering 27 Dresses clichéd and mostly forgettable.', TO_DATE('2007-12-27', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('28 days', 2000, 'Even though 28 Days is tackling a difficult subject, it comes off light and superficial, and maybe even a little preachy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('28 days later', 2002, 'Kinetically directed by Danny Boyle, 28 Days Later is both a terrifying zombie movie and a sharp political allegory.', TO_DATE('2002-10-31', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('28 weeks later', 2007, 'While 28 Weeks Later lacks the humanism that made 28 Days Later a classic, it''s made up with fantastic atmosphere and punchy direction.', TO_DATE('2007-05-03', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('2 days in new york', 2012, '2 Days in New York breezes past its shortcomings thanks to an enjoyably madcap plot and the sweet chemistry between its well-matched stars.', TO_DATE('2012-01-25', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('2 days in paris', 2007, 'Delpy proves not only to be an adept actress, but makes her mark as a writer and director in this thought-provoking comedy that breaks the romantic comedy mold.', TO_DATE('2007-03-21', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('2 days in the valley', 1996, 'A labyrinthine thriller with a host of memorable characters, 2 Days in the Valley is an uneven but intriguing thriller/black comedy.', TO_DATE('1996-09-27', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('2 fast 2 furious', 2003, 'Beautiful people and beautiful cars in a movie that won''t tax the brain cells.', TO_DATE('2003-03-13', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('2 guns', 2013, 'Formulaic and often jarringly violent, 2 Guns rests its old-school appeal on the interplay between its charismatic, well-matched stars.', TO_DATE('2013-07-30', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('300', 2007, 'A simple-minded but visually exciting experience, full of blood, violence, and ready-made movie quotes.', TO_DATE('2007-02-13', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('3000 miles to graceland', 2000, 'While the premise sounds promising, the movie turns out to be a tedious and unnecessarily violent heist movie that''s low on laughs and leaves no cliche unturned.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('300 rise of an empire', 2014, 'It''s bound to hit some viewers as an empty exercise in stylish gore, and despite a gonzo starring performance from Eva Green, 300: Rise of an Empire is a step down from its predecessor.', TO_DATE('2014-03-03', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('30 days of night', 2007, 'While 30 Days of Night offers a few thrills, it ultimately succumbs to erratic execution.', TO_DATE('2007-09-24', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('30 minutes or less', 2011, 'It''s sporadically funny and it benefits from a talented cast, but 30 Minutes or Less suffers from a disjointed narrative, and too often mistakes crude gags for true lowbrow humor.', TO_DATE('2011-08-05', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('31', 2016, '31 delivers all the high-energy gore Rob Zombie fans have come to expect, but a lack of fresh ideas and likable characters mean only the already converted need apply.', TO_DATE('2016-01-24', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('310 to yuma', 2007, 'This remake of a classic Western improves on the original, thanks to fiery performances from Russell Crowe and Christian Bale as well as sharp direction from James Mangold.', TO_DATE('2007-08-17', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('360', 2011, 'Spreading itself thin across a sprawling narrative without a unifying focus, 360 just keeps running in circles.', TO_DATE('2011-09-19', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('37 seconds', 2019, '37 Seconds is a rare and refreshing film that depicts disability with honesty, warmth, and empathy.', TO_DATE('2019-03-12', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('3 days to kill', 2014, '3 Days to Kill uneasily mixes technically accomplished action sequences with an underdeveloped family conflict.', TO_DATE('2014-02-20', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('3 from hell', 2019, '3 from Hell may be of interest to fans of the trilogy, but those not already on board with Rob Zombie''s gory saga will find little to lure them in here.', TO_DATE('2019-09-17', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('3 generations', 2015, '3 Generations squanders a worthy premise on a thinly written story that focuses on dramatic signposts at the expense of genuine character development.', TO_DATE('2015-09-12', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('3 hearts 3 coeurs', 2014, '3 Hearts skips a few narrative beats, but this thoroughly French romance is brought to life by the full-blooded performances of a first-rate cast.', TO_DATE('2014-09-15', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('3iron', 2005, 'A tender and moving romance from Spring, Summer, Fall, Winter... And Spring''s director Kim Ki-Duk.', TO_DATE('2005-02-26', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('3 ninjas', 2000, '3 Ninjas might be exciting enough for younger action enthusiasts, but they deserve better -- and there''s no shortage of superior options to choose from.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('3 women', 2000, '3 Women is a strange, eerie portrait of late-''70s womanhood that upends and then defies all expectations.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the 400 blows les quatre cents coups', 2000, 'A seminal French New Wave film that offers an honest, sympathetic, and wholly heartbreaking observation of adolescence without trite nostalgia.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('40 days and 40 nights', 2002, 'As romantic comedies go, 40 Days and 40 Nights is smutty, sexist, and puerile.', TO_DATE('2002-02-23', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the 40 year old virgin', 2005, 'Steve Carell''s first star turn scores big with a tender treatment of its titular underdog, using raunchy but realistically funny comedy to connect with adult audiences.', TO_DATE('2005-08-11', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('42', 2013, '42 is an earnest, inspirational, and respectfully told biography of an influential American sports icon, though it might be a little too safe and old-fashioned for some.', TO_DATE('2013-04-10', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('42nd street', 2000, 'Bubsy Berkeley does it again in 42nd Street, a brilliant depression-era romp with stellar musical numbers and impeccable choreography.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('44 inch chest', 2009, 'An actor''s movie with a strong cast, 44 Inch Chest can''t quite redeem its static plotting and tonal shifts.', TO_DATE('2009-10-21', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('45 years', 2015, '45 Years offers richly thought-provoking rewards for fans of adult cinema -- and a mesmerizing acting showcase for leads Charlotte Rampling and Tom Courtenay.', TO_DATE('2015-02-06', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('47 meters down', 2016, '47 Meters Down doesn''t take its terrifying premise quite as far as it should, but its toothy antagonists still offer a few thrills for less demanding genre enthusiasts.', TO_DATE('2016-08-29', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('47 meters down uncaged', 2019, '47 Meters Down: Uncaged may not be as ruthlessly efficient as its finned villains, but fans of shark peril thrillers should find it just chummy enough.', TO_DATE('2019-08-14', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('47 ronin', 2013, '47 Ronin is a surprisingly dull fantasy adventure, one that leaves its talented international cast stranded within one dimensional roles.', TO_DATE('2013-12-22', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('48 hrs', 2000, 'Marking an auspicious feature film debut for Eddie Murphy, 48 Hrs. is a briskly paced action comedy that succeeds largely due to the outstanding chemistry between its two leads.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('4 chetyre', 2005, 'Boldly ambitious and bracingly passionate, 4 opens an inscrutable window onto modern-day Russia -- and announces director Ilya Khrzhanovsky as a major talent.', TO_DATE('2005-10-22', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('4 little girls', 2000, '4 Little Girls finds Spike Lee moving into documentary filmmaking with his signature style intact -- and all the palpable fury the subject requires.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('4 months 3 weeks and 2 days', 2007, 'Featuring gut-wrenching performances from Anamaria Marinca and Laura Vasiliu, 4 Months is a gripping portrayal of life in Communist Romania.', TO_DATE('2007-05-17', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('500 days of summer', 2009, 'A clever, offbeat romantic comedy, 500 Days of Summer is refreshingly honest and utterly charming.', TO_DATE('2009-01-20', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('5050', 2011, 'A good-hearted film about a difficult topic, 50/50 maneuvers between jokes and drama with surprising finesse.', TO_DATE('2011-09-08', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('50 first dates', 2004, 'Gross-out humor overwhelms the easy chemistry between Adam Sandler and Drew Barrymore, who bring some energy and yucks to this tale of a girl with short-term memory loss and the guy who tries to get her to love him.', TO_DATE('2004-02-10', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('51 birch street', 2005, 'A filmmaker''s investigation of his parents'' marriage renders an ordinary subject surprisingly powerful.', TO_DATE('2005-10-07', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('52 tuesdays', 2014, '52 Tuesdays honors the complexity of familial bonds and gender identity with an intimate, well-acted, and overall empathetic drama.', TO_DATE('2014-01-26', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('54', 2000, 'Robbed of its integral LGBTQ themes, 54 is a compromised and disjointed glance at the glory days of disco.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('56 up', 2012, 'Director Michael Apted continues to utilize cinema as a window into the lives of everyday people, and in the reflection of this documentary we can glimpse our own aging humanity.', TO_DATE('2012-06-03', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('5 flights up', 2014, '5 Flights Up is a bit of a narrative fixer-upper, but when it comes to watching Diane Keaton and Morgan Freeman share screen time, you really can''t beat the view.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('5 to 7', 2014, '5 to 7 too often settles for rom-com clichés, but they''re offset by its charming stars, sensitive direction, and a deceptively smart screenplay.', TO_DATE('2014-04-25', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('6 balloons', 2018, 'Delicately sketched but thematically rich, 6 Balloons rises on Abbi Jacobson''s gripping performance -- and marks writer-director Marja-Lewis Ryan as a talent to watch.', TO_DATE('2018-03-13', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('6 souls', 2010, 'The most mind-bending aspect of 6 Souls is Julianne Moore''s participation, the overqualified star wasted on a goofy horror premise that generates more guffaws than scares.', TO_DATE('2010-04-19', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('6 underground', 2019, '6 Underground is loud, frenetic, and finally preposterous -- which is either bad news or a hearty recommendation, depending how one feels about the movies of Michael Bay.', TO_DATE('2019-12-11', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('71', 2014, 'Powerfully directed and acted, ''71 stays true to its fact-based origins while remaining as gripping as any solidly crafted action thriller.', TO_DATE('2014-02-12', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('7852 hitchcocks shower scene', 2017, '78/52: Hitchcock''s Shower Scene takes a look at one of modern cinema''s most memorable moments, offering insights of value to cineastes and casual viewers alike.', TO_DATE('2017-01-24', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('7 days in entebbe', 2018, '7 Days in Entebbe has a worthy story to tell, but loses sight of its most compelling elements in a dull dramatization of riveting real-life events.', TO_DATE('2018-02-19', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('8 12', 2000, 'Inventive, thought-provoking, and funny, 8 1/2 represents the arguable peak of Federico Fellini''s many towering feats of cinema.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('8 the mormon proposition', 2010, 'It''s unabashedly biased, but this look at the fight over gay marriage in California is impassioned and provocative.', TO_DATE('2010-06-02', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('88 minutes', 2007, '88 Minutes is a shockingly inept psychological thriller that expertly squanders the talent at hand.', TO_DATE('2007-03-31', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('8 mile', 2002, 'Even though the story is overly familiar, there''s enough here for an engaging ride.', TO_DATE('2002-08-07', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('8mm', 2000, 'Its sadistic violence is unappealing and is lacking in suspense and mystery.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('999', 2008, 'Its storyline isn''t as wondrous as its visuals, but $9.99 has a sophistication and handmade charm that sets it apart from the animated pack.', TO_DATE('2008-09-04', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('99 homes', 2014, 'Fueled by powerful acting and a taut, patiently constructed narrative, 99 Homes is a modern economic parable whose righteous fury is matched by its intelligence and compassion.', TO_DATE('2014-08-29', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('9 12 weeks', 2000, '9 1/2 Weeks'' famously steamy sex scenes titillate though the drama unfolding between the beddings is relatively standard for the genre.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rum diary', 2011, 'It''s colorful and amiable enough, and Depp''s heart is clearly in the right place, but The Rum Diary fails to add sufficient focus to its rambling source material.', TO_DATE('2011-10-14', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a good old fashioned orgy', 2011, 'Its titillating title promises ribald laughs, but the lazily written, indifferently acted, and only sporadically funny A Good Old Fashioned Orgy fails to consummate.', TO_DATE('2011-05-02', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a bad moms christmas', 2017, 'Featuring twice the moms but roughly half the laughs, A Bad Moms Christmas is a slapdash holiday sequel that falls short of the original with a disappointing dearth of good cheer.', TO_DATE('2017-10-31', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a band called death', 2013, 'A Band Called Death is not only a fascinating portrait of a pioneering rock group, but also a tribute to family ties and perseverance in the face of hardship.', TO_DATE('2013-03-21', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a better life', 2011, 'Powered by a terrific performance from Demián Bichir, A Better Life is an immigrant story told with simplicity and an ample amount of heart.', TO_DATE('2011-06-15', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a bigger splash', 2015, 'Absorbing, visually arresting, and powerfully acted by an immensely talented cast, A Bigger Splash offers sumptuously soapy delights for fans of psychological adult drama.', TO_DATE('2015-09-06', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a bread factory part one for the sake of gold', 2018, 'Epic yet intimate, A Bread Factory, Part One: For the Sake of Gold delivers the sprawling storytelling and nourishing drama audiences might expect from its imposing title.', TO_DATE('2018-10-23', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a brighter summer day', 2002, 'A fantastic cinematic and artistic achievement, Edward Yang''s A Brighter Summer Day depicts youth, ideals, violence and politics in a melancholic, tender light, culminating in a complex portrait of Taiwanese identity.', TO_DATE('2002-11-25', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a brilliant young mind', 2014, 'A Brilliant Young Mind is tender and perceptive -- and intelligent enough to find a wealth of dramatic riches buried under well-trod narrative ground.', TO_DATE('2014-09-08', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a cat in paris', 2011, 'A Cat in Paris depicts a stylish, imaginative world with a wonderful soundtrack and Hitchcockian overtones.', TO_DATE('2011-01-03', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a christmas prince', 2017, 'Predictable but sweet, A Christmas Prince is pleasant enough to pass the time during the holiday season.', TO_DATE('2017-11-28', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a ciambra', 2017, 'A powerful character study, A Ciambra burns slowly, letting its compelling cast carry what could otherwise be just another coming-of-age story.', TO_DATE('2017-05-19', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a coffee in berlin', 2013, 'Amiably slight, A Coffee in Berlin compensates for its lack of narrative drive with a sure-handed screenplay and echoes of early Woody Allen.', TO_DATE('2013-06-24', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a cure for wellness', 2017, 'A Cure for Wellness boasts a surfeit of visual style, but it''s wasted on a derivative and predictable story whose twists, turns, and frights have all been more effectively dealt before.', TO_DATE('2017-02-06', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a dangerous method', 2011, 'A provocative historical fiction about the early days of psychoanalysis, A Dangerous Method is buoyed by terrific performances by Michael Fassbender, Keira Knightley, and Viggo Mortensen.', TO_DATE('2011-09-02', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a dark song', 2016, 'A Dark Song offers atmospheric, unsettling horror -- and marks writer-director Liam Gavin as one to watch.', TO_DATE('2016-10-04', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a dogs journey', 2019, 'A Dog''s Journey is as sentimental as one might expect, but even cynical viewers may find their ability to resist shedding a tear stretched to the puppermost limit.', TO_DATE('2019-05-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a dogs purpose', 2017, 'A Dog''s Purpose offers an awkward blend of sugary sentiment and canine suffering that tugs at animal-loving audiences'' heartstrings with shameless abandon.', TO_DATE('2017-01-24', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a dogs way home', 2019, 'A Dog''s Way Home may not quite be a family-friendly animal drama fan''s best friend, but this canine adventure is no less heartwarming for its familiarity.', TO_DATE('2019-01-10', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a fantastic fear of everything', 2012, 'Aside from a few chuckles and Simon Pegg''s reliably affable screen presence, A Fantastic Fear of Everything has embarrassingly little to offer.', TO_DATE('2012-05-11', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a fantastic woman una mujer fantástica', 2017, 'Subtle and tender, A Fantastic Woman handles its timely, sensitive subject matter with care.', TO_DATE('2017-02-13', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a field in england', 2013, 'Recklessly assembled and occasionally compelling in spite of itself, A Field in England showcases a singularly brilliant voice in British cinema.', TO_DATE('2013-06-11', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a five star life', 2014, 'Modest to a fault, A Five Star Life is worth seeing chiefly for Margherita Buy''s marvelous work in the central role.', TO_DATE('2014-07-12', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a futile and stupid gesture', 2018, 'A Futile and Stupid Gesture entertainingly recreates the birth of an influential comedic movement, even if it struggles to cover its creative ground.', TO_DATE('2018-01-24', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a ghost story', 2017, 'A Ghost Story deftly manages its ambitious themes through an inventive, artful, and ultimately poignant exploration of love and loss.', TO_DATE('2017-01-22', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a girl walks home alone at night', 2014, 'A Girl Walks Home Alone at Night blends conventional elements into something brilliantly original -- and serves as a striking calling card for writer-director Ana Lily Amirpour.', TO_DATE('2014-01-21', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a glimpse inside the mind of charles swan iii', 2013, 'Tiresomely self-indulgent and lacking any storytelling cohesion, this Glimpse Inside the Mind finds little food for thought.', TO_DATE('2013-01-09', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a good day to die hard', 2013, 'A Good Day to Die Hard is the weakest entry in a storied franchise, and not even Bruce Willis'' smirking demeanor can enliven a cliched, uninspired script.', TO_DATE('2013-02-13', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a good woman is hard to find', 2019, 'A Good Woman Is Hard to Find, but it isn''t difficult to see a star in the making while watching Sarah Bolger''s powerful performance in this gritty thriller.', TO_DATE('2019-07-23', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a guide to recognizing your saints', 2006, 'A Guide to Recognizing Your Saints is a lively, powerful coming-of-age tale with winning performances and sharp direction from first-timer Dito Montiel.', TO_DATE('2006-01-23', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a guy thing', 2002, 'Wasting the talent of its leads, this predictable romantic comedy relies on cheap laughs.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a haunted house', 2013, 'A Haunted House seeks to offend every sensibility, but it''s greatest sin: not being funny!', TO_DATE('2013-01-07', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a haunted house 2', 2014, 'Sloppy, vulgar, and manic, A Haunted House 2 might be worth a chuckle or two, but mostly it''s a string of pop culture references and crude gags that fail to hit their intended targets.', TO_DATE('2014-04-17', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a hijacking', 2012, 'A tense, gripping thriller, A Hijacking avoids action movie cliches and instead creates a palpable sense of dread by mixing gritty realism with atmospheric beauty.', TO_DATE('2012-09-17', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a hologram for the king', 2016, 'A Hologram for the King amiably ambles through a narrative desert, saved by an oasis of a performance from the ever-dependable Tom Hanks.', TO_DATE('2016-04-19', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a jihad for love', 2008, 'This powerful documentary explores an important subject -- homosexuality in the Muslim world -- with humanity and courage.', TO_DATE('2008-05-19', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a kid like jake', 2018, 'A Kid Like Jake poses some truly interesting possibilities -- many of which are lost in its overly cautious approach to an admittedly sensitive subject.', TO_DATE('2018-01-24', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a late quartet', 2012, 'An outstanding ensemble cast lends weight and depth to A Late Quartet''s melodramatic script, and the result is insightful and emotionally satisfying.', TO_DATE('2012-09-09', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a league of ordinary gentlemen', 2005, 'Even if bowling isn''t your sport, this colorful documentary is still an entertaining watch.', TO_DATE('2005-03-29', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a letter to momo', 2013, 'Sweet, sad, and visually striking, A Letter to Momo is a hand-drawn experience for animation fans to savor.', TO_DATE('2013-10-29', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a little bit of heaven', 2011, 'A Little Bit of Heaven subjects viewers to a whole bunch of schmaltz - and strands Kate Hudson and Gael García Bernal in a fatally misguided film.', TO_DATE('2011-02-02', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a little chaos', 2014, 'Stylish and well-acted without ever living up to its dramatic potential, A Little Chaos is shouldered by the impressive efforts of a talented cast.', TO_DATE('2014-09-10', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a long way down', 2014, 'Tonally jumbled and conceptually ill-advised, A Long Way Down bungles its source material and wastes a talented cast.', TO_DATE('2014-02-10', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a man called ove en man som heter ove', 2016, 'A Man Called Ove''s winsome sincerity -- and Rolf Lassgård''s affectingly flinty performance in the title role -- keep it from succumbing to excess sentimentality.', TO_DATE('2016-03-09', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a man escaped un condamné à mort sest échappé ou le vent souffle où il veut', 2000, 'A Man Escaped is blockbuster Bresson, a well-acted POW drama that builds with subtle, seat-gripping tension.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a man named pearl', 2007, 'Though it lacks moviemaking polish, A Man Named Pearl is redeemed by the interest -- and uplift -- generated by its subject.', TO_DATE('2007-08-31', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a million little pieces', 2018, 'While solidly cast and competently helmed, A Million Little Pieces amounts to little more than a well-intentioned but unpersuasive echo of a deeply problematic memoir.', TO_DATE('2018-09-11', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a million ways to die in the west', 2014, 'While it offers a few laughs and boasts a talented cast, Seth MacFarlane''s overlong, aimless A Million Ways to Die in the West is a disappointingly scattershot affair.', TO_DATE('2014-05-25', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a monster calls', 2016, 'A Monster Calls deftly balances dark themes and fantastical elements to deliver an engrossing and uncommonly moving entry in the crowded coming-of-age genre.', TO_DATE('2016-09-09', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a most violent year', 2014, 'Gritty, gripping, and weighted with thought-provoking heft, A Most Violent Year represents another strong entry in writer-director J.C. Chandor''s impressive filmography.', TO_DATE('2014-11-06', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a most wanted man', 2014, 'Smart, subtle, and steadily absorbing, A Most Wanted Man proves once again that John le Carre books make for sharp, thoughtful thrillers.', TO_DATE('2014-01-17', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a night in old mexico', 2014, 'A Night in Old Mexico gives Robert Duvall a too-rare starring showcase -- then frustratingly wastes it on a contrived story that''s often unworthy of his talents.', TO_DATE('2014-03-11', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a nightmare on elm street 2 freddys revenge', 2000, 'An intriguing subtext of repressed sexuality gives Freddy''s Revenge some texture, but the Nightmare loses its edge in a sequel that lacks convincing performances or memorable scares.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a nightmare on elm street 3 dream warriors', 2000, 'A Nightmare on Elm Street 3: Dream Warriors offers an imaginative and surprisingly satisfying rebound for a franchise already starting to succumb to sequelitis.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a nightmare on elm street 4 the dream master', 2000, 'A Nightmare on Elm Street 4: The Dream Master marks a relative high point in this franchise''s bumpy creative journey, although the original remains far superior.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a nightmare on elm street 5 the dream child', 2000, 'A Nightmare on Elm Street feels exhausted by this cheesy fifth entry, bogged down by a convoluted mythology while showing none of the chilling technique that kicked off the franchise.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a perfect day', 2015, 'Aid workers get their due in A Perfect Day, which is just different and well-acted enough to overcome its logy pace and narrative clichés.', TO_DATE('2015-05-25', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a perfect getaway', 2009, 'While smarter than the average slasher film, A Perfect Getaway eventually devolves into a standard, predictable, excessively violent thriller.', TO_DATE('2009-08-04', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a place at the table', 2012, 'A Place at the Table is a well-reported documentary that raises important questions about the state of hunger in America culture.', TO_DATE('2012-01-24', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a prayer before dawn', 2017, 'A Prayer Before Dawn is far from an easy watch, but this harrowing prison odyssey delivers rich rewards -- led by an outstanding central performance from Joe Cole.', TO_DATE('2017-05-22', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a private war', 2018, 'A Private War honors its real-life subject with a sober appraisal of the sacrifices required of journalists on the front lines - and career-best work by Rosamund Pike.', TO_DATE('2018-09-13', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a quiet passion', 2016, 'A Quiet Passion offers a finely detailed portrait of a life whose placid passage may not have been inherently cinematic, but is made more affecting by Cynthia Nixon''s strong performance.', TO_DATE('2016-02-15', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a quiet place', 2018, 'A Quiet Place artfully plays on elemental fears with a ruthlessly intelligent creature feature that''s as original as it is scary -- and establishes director John Krasinski as a rising talent.', TO_DATE('2018-03-10', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a room with a view', 1985, 'The hard edges of E.M. Foster novel maybe sanded off, but what we get with A Room with a View is an eminently entertaining comedy with an intellectual approach to love.', TO_DATE('1985-12-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a royal night out', 2015, 'Undeniably slight yet thoroughly charming, A Royal Night Out uses a fascinating historical footnote as a springboard into a fun dramedy diversion.', TO_DATE('2015-05-05', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a screaming man', 2010, 'A Screaming Man deftly uses its personal look at a family dynamic to offer pointed political observations, confirming writer-director Mahamat-Saleh Haroun as a major talent.', TO_DATE('2010-07-06', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a secret love', 2020, 'In telling one couple''s story, A Secret Love pays understated yet powerful tribute to a lifetime of choices and sacrifices made in the name of enduring devotion.', TO_DATE('2020-04-24', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a separation', 2011, 'Morally complex, suspenseful, and consistently involving, A Separation captures the messiness of a dissolving relationship with keen insight and searing intensity.', TO_DATE('2011-06-15', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a serious man', 2009, 'Blending dark humor with profoundly personal themes, the Coen brothers deliver what might be their most mature -- if not their best -- film to date.', TO_DATE('2009-09-14', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a shaun the sheep movie farmageddon', 2019, 'A Shaun the Sheep Movie: Farmageddon retains the charm of its small-screen source material while engagingly expanding the title character''s world.', TO_DATE('2019-09-16', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a simple favor', 2018, 'Twisty, twisted, and above all simply fun, A Simple Favor casts a stylish mommy noir spell strengthened by potent performances from Anna Kendrick and Blake Lively.', TO_DATE('2018-09-09', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a single shot', 2013, 'It has a bleak sense of atmosphere and a terrific performance by Sam Rockwell, but A Single Shot is undercut by its predictable story and slow pace.', TO_DATE('2013-04-26', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a slippingdown life', 2004, 'Lili Talyor is the best thing in this uninvolving and unconvincing drama.', TO_DATE('2004-01-22', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a smile like yours', 2000, 'Flat and unfocused, A Smile Like Yours aims for romantic comedy but settles for tired sitcom formula.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a song for martin', 2002, 'Grueling but honest depiction about the ravages of Alzheimer''s. Yep, it''s a downer.', TO_DATE('2002-01-03', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a star is born', 2018, 'With appealing leads, deft direction, and an affecting love story, A Star Is Born is a remake done right -- and a reminder that some stories can be just as effective in the retelling.', TO_DATE('2018-08-31', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a street cat named bob', 2016, 'A Street Cat Named Bob uses a fact-based feelgood tale as the inspiration for an unapologetically heartwarming movie that should move all but the most cynical of viewers.', TO_DATE('2016-11-02', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a summer in genoa', 1800, 'Michael Winterbottom''s tale of grief and mourning, though frustrating in places, is intelligent filmmaking with superb central performances.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a tale of love and darkness', 2015, 'A Tale of Love and Darkness suggests greater things for debuting writer-director Natalie Portman -- even if its reach slightly exceeds her creative grasp.', TO_DATE('2015-07-20', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a tale of two sisters', 2004, 'Restrained but disturbing, A Tale of Two Sisters is a creepily effective, if at times confusing, horror movie.', TO_DATE('2004-06-05', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ateam', 2010, 'The A-Team assembles a top-rate cast only to ditch the show''s appealingly silly premise for explosive yet muddled blockbuster filmmaking.', TO_DATE('2010-06-07', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a thousand words', 2012, 'Dated jokes (A Thousand Words was shot in 2008) and removing Eddie Murphy''s voice -- his greatest comedic asset -- dooms this painful mess from the start.', TO_DATE('2012-03-07', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a thousand years of good prayers', 2008, 'Though it may not be as profound as its pacing would suggest, A Thousand Years of Good Prayers delicately examines familial issues in an earnest fashion.', TO_DATE('2008-09-14', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a touch of sin', 2013, 'Its screenplay isn''t as graceful as the choreography of its action sequences, but A Touch of Sin offers enough stylishly satisfying violence to muscle past its rough spots.', TO_DATE('2013-05-16', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a town called panic panique au village', 2009, 'A Town Called Panic is a raucous, endlessly creative animated romp with a quirky, adult sense of humor.', TO_DATE('2009-12-07', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a united kingdom', 2016, 'Well-acted, solidly crafted, and all-around worthy, A United Kingdom presents an absorbing look at a singular true-life love story.', TO_DATE('2016-09-10', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a very british gangster', 2007, 'With a fascinating character as its subject, A Very British Gangster makes for entertaining, frightening, and informative viewing.', TO_DATE('2007-01-24', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a very long engagement', 2004, 'A well-crafted and visually arresting drama with a touch of whimsy.', TO_DATE('2004-10-15', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a vigilante', 2018, 'Led by Olivia Wilde''s fearless performance and elevated by timely themes, A Vigilante is an uncompromising thriller that hits as hard as its protagonist.', TO_DATE('2018-03-12', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a walk among the tombstones', 2014, 'A Walk Among the Tombstones doesn''t entirely transcend its genre clichés, but it does offer Liam Neeson one of his more compelling roles in recent memory, and that''s often enough.', TO_DATE('2014-09-15', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a walk in the woods', 2015, 'Amiable yet less compelling than any road trip movie starring Robert Redford and Nick Nolte should be, A Walk in the Woods is ultimately a bit too pedestrian.', TO_DATE('2015-01-23', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a walk into the sea danny williams and the warhol factory', 2007, 'A portrait piece of Danny Williams, set amongst New Yorks Factory, home of Andy Warhol, provides insight and flavour of the time and the setting, with an unresolved mystery at its heart.', TO_DATE('2007-12-07', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a war krigen', 2015, 'Tense, intelligent, and refreshingly low-key, A War is part frontline thriller, part courtroom drama -- and eminently effective in both regards.', TO_DATE('2015-11-14', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a white white day hvítur hvítur dagur', 2019, 'A White, White Day plunges viewers into the darkness of grief and jealousy, led by Ingvar Eggert Sigurðsson''s brilliantly layered performance.', TO_DATE('2019-05-16', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a woman a gun and a noodle shop san qiang pai an jing qi a simple noodle story the first gun', 2010, 'Zhang Yimou''s broad reinterpretation of the Coen Brothers'' Blood Simple struggles to bring anything new to the twisty murder mystery and instead ladles on an excess of stilted comedy.', TO_DATE('2010-07-13', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a woman is a woman une femme est une femme', 2000, 'One of the last times Godard could make film paradoxes with glee, A Woman Is a Woman is a mocking, genuine tribute to musicals.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a wrinkle in time', 2018, 'A Wrinkle in Time is visually gorgeous, big-hearted, and occasionally quite moving; unfortunately, it''s also wildly ambitious to a fault, and often less than the sum of its classic parts.', TO_DATE('2018-03-07', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('abandon', 2002, 'The plotline for Abandon is too disjointed and muddled to offer much in the way of thrills.', TO_DATE('2002-10-15', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the abandoned', 2006, 'The Abandoned spends so much time setting up the creepy atmosphere, that it forgets to inhabit it with genuine spooks or scares.', TO_DATE('2006-11-20', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('abbott and costello meet frankenstein', 2000, 'A zany horror spoof that plays up and then plays into the best of Universal horror cliches.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('abcs of death 2', 2014, 'ABCs of Death 2 delivers some inventively gory thrills, offering a surprising (albeit still somewhat uneven) upgrade over its predecessor.', TO_DATE('2014-09-19', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('abduction', 2011, 'A soulless and incompetent action/thriller not even a veteran lead actor could save, let alone Taylor Lautner.', TO_DATE('2011-09-20', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('abe', 2019, 'Aided by sensitive direction and Noah Schnapp''s work in the title role, Abe is a simple family drama whose subtle touches enhance its surprising depths.', TO_DATE('2019-01-27', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aberdeen', 2000, 'Though the characters are difficult to watch at times, Aberdeen burns with ferocious honesty and strong performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('abominable', 2019, 'Working with admittedly familiar ingredients, Abominable offers audiences a beautifully animated and overall engaging adventure that the whole family can enjoy.', TO_DATE('2019-09-08', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('about a boy', 2002, 'About a Boy benefits tremendously from Hugh Grant''s layered performance, as well as a funny, moving story that tugs at the heartstrings without tilting into treacle.', TO_DATE('2002-03-25', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('about adam', 2001, 'Although some of the characters'' motivation may not be that clear, the movie is still a funny and sexy charmer.', TO_DATE('2001-02-07', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('about alex', 2014, 'About Alex pointedly provokes comparisons to The Big Chill, but the script doesn''t have enough substance to support them -- or give its talented cast enough to work with.', TO_DATE('2014-04-23', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('about elly', 2009, 'About Elly offers viewers performances as powerful as its thought-provoking ideas, and adds another strong entry to Asghar Farhadi''s impressive filmography.', TO_DATE('2009-07-27', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('about last night', 1986, 'About Last Night will perturb fans of the original stage play by sanding down its pricklier edges, but an amiable cast and sexual frankness make this a pleasantly grounded romantic comedy.', TO_DATE('1986-07-01', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('about last night', 2014, 'About Last Night wanders even further from the David Mamet play that inspired the original, but it benefits from an engaging cast and a screenplay that smartly balances romance and comedy.', TO_DATE('2014-02-10', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('about schmidt', 2001, 'In this funny, touching character study, Nicholson gives one of the best performances of his career.', TO_DATE('2001-12-04', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('about time', 2013, 'Beautifully filmed and unabashedly sincere, About Time finds director Richard Curtis at his most sentimental.', TO_DATE('2013-06-30', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('abraham lincoln vampire hunter', 2012, 'Abraham Lincoln: Vampire Hunter has visual style to spare, but its overly serious tone doesn''t jibe with its decidedly silly central premise, leaving filmgoers with an unfulfilling blend of clashing ingredients.', TO_DATE('2012-06-19', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('absolute power', 1997, 'Absolute Power collapses under its preposterous plotting despite an all-star cast and Clint Eastwood''s deft direction.', TO_DATE('1997-02-14', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('absolute wilson', 2006, 'Absolute Wilson is an excellent introduction to the artist Robert Wilson, even if it can''t quite capture the spirit of his work.', TO_DATE('2006-10-22', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('absolutely anything', 2015, 'Given the impressive array of talent involved in Absolutely Anything -- and the near-total lack of laughs it provokes -- this Monty Python reunion can only be regarded as a disappointment.', TO_DATE('2015-08-10', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('absolutely fabulous the movie', 2016, 'Absolutely Fabulous: The Movie picks up pretty much where its source material left off, delivering an adaptation that, as fans of this British export might say, does what it says on the tin.', TO_DATE('2016-06-29', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('abuse of weakness', 2013, 'Abuse of Weakness'' fact-based plot proves that truth can be stranger than fiction -- and provide grist for compelling character studies.', TO_DATE('2013-09-06', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('accepted', 2006, 'Like its characters who aren''t able to meet their potential, Accepted''s inconsistent and ridiculous plot gets annoying, despite a few laughs.', TO_DATE('2006-07-30', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('accidental love', 2015, 'Cobbling together an unfinished satire on the healthcare system and contorting it into a dopey romance, Accidental Love is a cynical repurposing of unrealized potential.', TO_DATE('2015-02-10', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the accidental tourist', 1988, 'Generous with its characters'' foibles and virtues, The Accidental Tourist is a thoughtful drama vested with insight into the complications of relationships.', TO_DATE('1988-12-23', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ace ventura pet detective', 2000, 'Jim Carrey''s twitchy antics and gross-out humor are on full, bombastic display in Ace Ventura: Pet Detective, which is great news for fans of his particular brand of comedy but likely unsatisfying for anyone else.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ace ventura when nature calls', 1995, 'Nature Calls in this Ace Ventura sequel, and it''s answered by the law of diminishing returns.', TO_DATE('1995-11-10', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('acod', 2013, 'Despite its impressive cast and some sharp observations, A.C.O.D. is neither funny enough nor poignant enough to work as a potent comedy or incisive satire.', TO_DATE('2013-01-24', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('across the universe', 2007, 'Psychedelic musical numbers can''t mask Across the Universe''s clichéd love story and thinly written characters.', TO_DATE('2007-08-30', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('act of valor', 2012, 'It''s undeniably reverent of the real-life heroes in its cast, but Act of Valor lets them down with a clichéd script, stilted acting, and a jingoistic attitude that ignores the complexities of war.', TO_DATE('2012-02-21', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('action point', 2018, 'Ouch.', TO_DATE('2018-06-01', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ad astra', 2019, 'Ad Astra takes a visually thrilling journey through the vast reaches of space while charting an ambitious course for the heart of the bond between parent and child.', TO_DATE('2019-08-29', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adam', 2019, 'Much like its well-meaning but clueless protagonist, Adam occasionally seems to be in over its head -- but its good intentions make those fumbles easier to forgive.', TO_DATE('2019-01-25', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adam resurrected', 2008, 'Such an unusual tale might have made for a compelling drama, but Adam Resurrected suffers from narrative confusion and an emotional detachment at its core.', TO_DATE('2008-09-09', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adam sandler 100 fresh', 2018, 'An energetic Sandler jumps back into the spotlight with fresh songs, stories, and spoofs in Adam Sandler: 100% Fresh, a wonderful return to form for a beloved comedian.', TO_DATE('2018-10-24', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adam sandlers eight crazy nights', 2002, 'Sandler returns to his roots in this nauseating concoction filled with potty humor and product placements.', TO_DATE('2002-11-07', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adams apples', 2006, 'Good and evil collide with interesting results in Adam''s Apples, a dark Biblical allegory that''s alternatively funny and shocking.', TO_DATE('2006-01-22', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the addams family', 2000, 'The movie is peppered with amusing sight gags and one-liners, but the disjointed script doesn''t cohere into a successful whole.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('addams family values', 2000, 'New, well-developed characters add dimension to this batty satire, creating a comedy much more substantial than the original.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adieu au langage goodbye to language', 2014, 'As visually thrilling as it is inscrutable, Goodbye to Language 3D offers a late-period masterpiece from a legendary director still very much in control of his craft.', TO_DATE('2014-05-21', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the adjustment bureau', 2011, 'First-time writer/director George Nolfi struggles to maintain a consistent tone, but The Adjustment Bureau rises on the strong, believable chemistry of its stars.', TO_DATE('2011-02-24', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('admission', 2013, 'Admission has a pair of immensely likable leads in Tina Fey and Paul Rudd, but it wastes them on a contrived (and clumsily directed) screenplay.', TO_DATE('2013-03-06', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adopt a highway', 2019, 'Adopt a Highway might have done more to fill in its sparsely sketched story, but Ethan Hawke''s performance is often enough to fill in the blanks.', TO_DATE('2019-03-11', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adoration', 2008, 'A complex and thought-provoking work, Atom Egoyan''s Adoration works well as both mystery and engaging drama.', TO_DATE('2008-05-22', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adore', 2013, 'Naomi Watts and Robin Wright give it their all, but they can''t quite make Adore''s trashy, absurd plot believable.', TO_DATE('2013-01-21', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adrift', 2018, 'Adrift sails smoothly between love story and survival drama, thanks in large part to a gripping central performance from Shailene Woodley.', TO_DATE('2018-05-31', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adult beginners', 2014, 'Perfectly pleasant yet never particularly engaging, Adult Beginners is a mild middle-of-the-road comedy content to coast on the charms of its talented cast.', TO_DATE('2014-09-10', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('advanced style', 2014, 'Colorful, witty, and uplifting, Advanced Style celebrates life and pays tribute to those who flout convention.', TO_DATE('2014-05-06', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adventureland', 2009, 'Full of humor and nostalgia, Adventureland is a sweet, insightful coming-of-age comedy that will resonate with teens and adults alike.', TO_DATE('2009-01-20', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('adventures in babysitting', 2000, 'Sweet and spry, Adventures in Babysitting gets by on its amiable tone.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the adventures of baron munchausen', 1800, 'Bursting with Terry Gilliam''s typically imaginative flourishes, this story of a possibly deranged Baron recounting his storied life is a flamboyant and witty visual treat.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the adventures of elmo in grouchland', 2000, 'This fun and moral tale entertains both first-time Seasame Street watchers and seasoned veterans.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the adventures of ichabod and mr toad', 2000, 'This Disney two-fer may not be the most reverent literary adaptation, but it''s remarkably crafted and emotionally resonant.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the adventures of pluto nash', 2002, 'The Adventures of Pluto Nash is neither adventurous nor funny, and Eddie Murphy is on autopilot in this notorious box office bomb.', TO_DATE('2002-08-09', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the adventures of priscilla queen of the desert', 1994, 'While its premise is ripe for comedy -- and it certainly delivers its fair share of laughs -- Priscilla is also a surprisingly tender and thoughtful road movie with some outstanding performances.', TO_DATE('1994-08-10', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the adventures of rocky bullwinkle', 2000, 'Though the film stays true to the nature of the original cartoon, the script is disappointing and not funny.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aeon flux', 2005, 'Aeon Flux lacks the gravity-defying pace of its animated predecessor, and, despite some flash, is largely a dull affair.', TO_DATE('2005-12-01', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the affair of the necklace', 2001, 'A film about court intrigue, The Affair of the Necklace turns out to be more dull than juicy. Swank seems flat and miscast in the central role of Jeanne.', TO_DATE('2001-11-21', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an affair to remember', 2002, 'There''s not too much to it besides Cary Grant and Deborah Kerr, but that''s still enough to make this An Affair to Remember.', TO_DATE('2002-07-30', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('afflicted', 2013, 'It isn''t without its share of clichés, but Afflicted proves there''s still life in the found-footage horror genre.', TO_DATE('2013-09-18', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('affliction', 1997, 'Dark and bleak, the "kick-ass" performances, especially Nolte''s "effective" portrayal of an abused soul, is the reason to see this film.', TO_DATE('1997-06-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('afghan star', 2009, 'An enlightening and sobering documentary on Afghanistan''s very own X-Factor.', TO_DATE('2009-03-27', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('african cats', 2011, 'It isn''t quite as majestic as its subjects, but African Cats boasts enough astounding footage -- and a big enough heart -- to keep things entertaining.', TO_DATE('2011-04-17', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('after', 2019, 'Tepid and tired, After''s fun flourishes are let down by its generic story.', TO_DATE('2019-04-11', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('after earth', 2013, 'After Earth is a dull, ploddingly paced exercise in sentimental sci-fi -- and the latest setback for director M. Night Shyamalan''s once-promising career.', TO_DATE('2013-05-29', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('after innocence', 2005, 'This understated yet emotionally devastating documentary lets the stories of its subjects speak for themselves.', TO_DATE('2005-02-02', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('afterlife', 2010, 'It has an interesting premise and admirable ambitions, but After.Life fails to deliver enough twists or thrills to sustain its creepy atmosphere.', TO_DATE('2010-03-15', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('after love léconomie du couple', 2016, 'After Love isn''t easy viewing, but its brutally honest examination of a crumbling family offers powerful performances and penetrating insights that make it well worth the effort.', TO_DATE('2016-05-13', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('after midnight something else', 2019, 'Part creature feature, part romance, After Midnight somehow manages to combine its disparate ingredients and come up with something special.', TO_DATE('2019-04-27', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('after the storm umi yori mo mada fukaku', 2016, 'After the Storm crosses cultural lines to offer timeless observations about parental responsibilities, personal bonds, and the capacity for forgiveness.', TO_DATE('2016-05-19', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('after the sunset', 2004, 'A slick but bland thriller.', TO_DATE('2004-11-06', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('efter brylluppet after the wedding', 2006, 'The cast brings After the Wedding''s melodramatic script to life, creating a movie that is emotionally raw and satisfying.', TO_DATE('2006-02-24', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('after the wedding', 2019, 'After the Wedding benefits from solid casting and strong source material, yet proves stubbornly resistant to spark to emotional life.', TO_DATE('2019-01-25', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('after tiller', 2013, 'After Tiller applies empathy, honesty, and graceful understatement to a discussion that all too often lacks them all.', TO_DATE('2013-04-24', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aftermath poklosie', 2013, 'It represents an occasionally uneven collision of genres, but all in all, Wladyslaw Pasikowski''s Aftermath delves into Holocaust guilt with power and efficiency.', TO_DATE('2013-10-25', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('afternoon delight', 2013, 'Afternoon Delight''s uncertain tone is entertainingly offset by smart dialogue and standout starring work from Kathryn Hahn.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('afterschool', 2008, 'Antonio Campos''Afterschool is an intelligent, ambitious debut that boasts strong performances and plenty of ideas.', TO_DATE('2008-09-29', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aftershock', 2012, 'Aftershock hints at an inventive twist on horror tropes, but ultimately settles for another round of mind-numbing depravity that may alternately bore and revolt all but the most ardent gore enthusiasts.', TO_DATE('2012-09-09', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('against the ropes', 2004, 'A bland, dumbed-down package of sports cliches.', TO_DATE('2004-01-15', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the age of innocence', 1993, 'Equal measures romantic and wistful, Martin Scorsese''s elegant adaptation of The Age of Innocence is a triumphant exercise in both stylistic and thematic restraint.', TO_DATE('1993-10-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('agent cody banks', 2003, 'Should satisfy young teens, but offers nothing new for those who are familiar with the formula.', TO_DATE('2003-03-01', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('agent cody banks 2 destination london', 2004, 'Young kids may find this London adventure fun, but older kids may find it too simplistic.', TO_DATE('2004-02-04', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('agora', 2009, 'Noble goals and a gripping performance from Rachel Weisz can''t save Agora from its muddled script, uneven acting, and choppy editing.', TO_DATE('2009-05-18', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aguirre the wrath of god aguirre der zorn gottes', 2000, 'A haunting journey of natural wonder and tangible danger, Aguirre transcends epic genre trappings and becomes mythological by its own right.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ai artificial intelligence', 2000, 'A curious, not always seamless, amalgamation of Kubrick''s chilly bleakness and Spielberg''s warm-hearted optimism, A.I. is, in a word, fascinating.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aileen life and death of a serial killer', 2003, 'This chilling, unsettling documentary provides an eye-opening look at both Wuornos and the American justice system.', TO_DATE('2003-05-21', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aint them bodies saints', 2013, 'While conventional in plot, Ain''t Them Bodies Saints is a visually poetic film that pays homage to the New Hollywood directors of the 1970s and promises big things from director David Lowery.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('air force one', 1997, 'This late-period Harrison Ford actioner is full of palpable, if not entirely seamless, thrills.', TO_DATE('1997-07-25', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('air guitar nation', 2006, 'It''s up for debate how serious or ironic its subjects are, but Air Guitar Nation is nonetheless a funny and exciting documentary with a killer soundtrack.', TO_DATE('2006-03-09', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('airplane', 2000, 'Though unabashedly juvenile and silly, Airplane! is nevertheless an uproarious spoof comedy full of quotable lines and slapstick gags that endure to this day.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ajami', 2009, 'This multi-character drama balances intimate portrayals and broad political implications to paint a bracing and moving portrait of the Middle East conflict.', TO_DATE('2009-11-19', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aka jane roe', 2020, 'AKA Jane Roe''s myopic scope pulls a few too many punches, but it is nevertheless a fascinating profile of a controversial public figure.', TO_DATE('2020-05-20', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('akeelah and the bee', 2006, 'A warm, family-friendly underdog story, featuring terrific supporting performances from Keke Palmer, Laurence Fishburne, and Angela Bassett.', TO_DATE('2006-03-20', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('akira', 2000, 'Akira is strikingly bloody and violent, but its phenomenal animation and sheer kinetic energy helped set the standard for modern anime.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i saw the devil', 2010, 'Never flinching during its descent into depravity, I Saw the Devil is a pulverizing thriller that will give bloody satisfaction to audiences who like their revenge served with fiery rage.', TO_DATE('2010-09-16', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aladdin', 2019, 'Aladdin retells its classic source material''s story with sufficient spectacle and skill, even if it never approaches the dazzling splendor of the animated original.', TO_DATE('2019-05-22', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the alamo', 2004, 'Too conventional and uninvolving to be memorable.', TO_DATE('2004-03-31', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alan partridge', 2013, 'The Alan Partridge movie ditches the TV series'' nuanced humor for something broader, and succeeds in presenting the character on a global scale.', TO_DATE('2013-07-24', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('albert nobbs', 2011, 'Albert Nobbs tells a worthy story with an outstanding performance at its core, even if the end result is often somewhat less than the sum of its admirable parts.', TO_DATE('2011-09-12', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('albino alligator', 2000, 'Matt Dillon''s intense performance is the best aspect of Albino Alligator, a mannered thriller that pantomimes the tropes of film noir to phony effect.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alex emma', 2003, 'A dull and unfunny comedy where the leads fail to generate any sparks.', TO_DATE('2003-06-16', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alex cross', 2012, 'Tyler Perry and Matthew Fox do their best, but they''re trampled by Rob Cohen''s frustrating direction and a tasteless, lazily written screenplay.', TO_DATE('2012-10-15', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alex of venice', 2014, 'Alex of Venice does immensely likable things with its overly familiar parts, adding up to an agreeable calling card for debuting director Chris Messina.', TO_DATE('2014-04-20', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alex rider operation stormbreaker', 2006, 'Alex Rider: Operation Stormbreaker is strictly children''s fare, as it lacks originality, excitement, and believabiltity.', TO_DATE('2006-07-16', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alex strangelove', 2018, 'Alex Strangelove offers a refreshingly insightful -- and fittingly adult -- take on teen sexuality enlivened by smart humor and a fearlessly progressive approach.', TO_DATE('2018-04-15', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alexander', 2004, 'Even at nearly three hours long, this ponderous, talky, and emotionally distant biopic fails to illuminate Alexander''s life.', TO_DATE('2004-07-06', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alexander and the terrible horrible no good very bad day', 2014, 'Affably pleasant without ever trying to be anything more, Alexander and the Terrible, Horrible, No Good, Very Bad Day is a fine -- albeit forgettable -- family diversion.', TO_DATE('2014-10-02', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alfie', 2004, 'This unnecessary remake wants Alfie to have his cake and eat it, too, but a lack of sexual fizz and a sour performance by Jude Law conspire to deliver audiences a romantic comedy that isn''t romantic or funny.', TO_DATE('2004-10-19', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ali', 2001, 'Though perhaps no film could fully do justice to the fascinating life and personality of Muhammad Ali, Mann''s direction and Smith''s performance combine to pack a solid punch.', TO_DATE('2001-11-07', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ali wong hard knock wife', 2018, 'Ali Wong emerges a mother still perturbed in Hard Knock Wife, a hilariously honest hour of comedy that highlights the joys and oh boys of motherhood with fearless energy and just the right amount of squirmy detail.', TO_DATE('2018-05-10', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alice doesnt live here anymore', 2000, 'Alice Doesn''t Live Here Anymore finds Martin Scorsese wielding a somewhat gentler palette than usual, with generally absorbing results.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alice through the looking glass', 2016, 'Alice Through the Looking Glass is just as visually impressive as its predecessor, but that isn''t enough to cover for an underwhelming story that fails to live up to its classic characters.', TO_DATE('2016-05-10', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alien', 1979, 'A modern classic, Alien blends science fiction, horror and bleak poetry into a seamless whole.', TO_DATE('1979-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alien3', 1800, 'Alien3 takes admirable risks with franchise mythology, but far too few pay off in a thinly scripted sequel whose stylish visuals aren''t enough to enliven a lack of genuine thrills.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alien covenant', 2017, 'Alien: Covenant delivers another satisfying round of close-quarters deep-space terror, even if it doesn''t take the saga in any new directions.', TO_DATE('2017-05-06', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alien nation', 2000, 'Alien Nation takes the interesting premise of extraterrestrials living among us and doesn''t do enough with it, emphasizing a police procedural plotline over the more intriguing sci-fi elements.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alien resurrection', 1997, 'Alien Resurrection marks a slight improvement over its predecessor, but still lacks the emotional stakes that helped make the franchise''s first two entries sci-fi/horror classics.', TO_DATE('1997-11-26', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alien trespass', 2009, 'An earnest attempt to parody campy 1950s sci-fi films, Alien Trespass eventually loses its charm among tedious dialogue and cheesy special effects.', TO_DATE('2009-02-05', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('avp alien vs predator', 2004, 'Gore without scares and cardboard cut-out characters make this clash of the monsters a dull sit.', TO_DATE('2004-07-05', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aliens in the attic', 2009, 'Inoffensive and kid-friendly this mundane family comedy is light on imagination.', TO_DATE('2009-07-31', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aliens of the deep', 2005, 'An amazing array of images from beneath the sea.', TO_DATE('2005-01-18', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alis wedding', 2017, 'Ali''s Wedding uses its very specific setting to explore universal ideas about relationships -- and in delightfully smart, funny fashion.', TO_DATE('2017-06-15', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alita battle angel', 2019, 'Alita: Battle Angel''s story struggles to keep up with its special effects, but fans of futuristic sci-fi action may still find themselves more than sufficiently entertained.', TO_DATE('2019-01-31', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alive inside', 2014, 'It''s somewhat clumsily expressed, but Alive Inside offers such an uplifting message that it''s ultimately hard to resist.', TO_DATE('2014-01-28', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all about my mother todo sobre mi madre', 2000, 'Almodovar weaves together a magnificent tapestry of femininity with an affectionate wink to classics of theater and cinema in this poignant story of love, loss and compassion.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all about steve', 2009, 'All About Steve is an oddly creepy, sour film, featuring a heroine so desperate and peculiar that audiences may be more likely to pity than root for her.', TO_DATE('2009-09-02', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all about the benjamins', 2002, 'A sloppy, poorly directed action-comedy, All About the Benjamins is too derivative and gratuitously violent.', TO_DATE('2002-02-19', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all cheerleaders die', 2013, 'All Cheerleaders Die sets out to subvert horror tropes, but ends up falling victim to many of the same trashy cliches it''s trying to mock.', TO_DATE('2013-09-30', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all day and a night', 2020, 'All Day and a Night addresses worthy issues with thoughtfulness and care, although its effectiveness is undermined by a disappointingly familiar story.', TO_DATE('2020-04-30', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all eyez on me', 2017, 'Despite Demetrius Shipp Jr.''s fine lead performance, All Eyez on Me is mostly a surface-skimming, by-the-numbers biopic of a larger-than-life icon.', TO_DATE('2017-06-14', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all good things', 2010, 'It''s well-acted, and the true story that inspired it offers plenty of drama -- which is why it''s so frustrating that All Good Things is so clichéd and frustratingly ambiguous.', TO_DATE('2010-11-11', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all i see is you', 2016, 'All I See Is You hints at a number of intriguing questions with its premise, but they dissolve in a stylish yet empty psychodrama that fails to connect.', TO_DATE('2016-09-11', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all i wish a little something for your birthday', 2018, 'All I Wish strands Sharon Stone in the midst of a subpar romantic comedy that will only leave most viewers wishing Hollywood would offer her a better starring vehicle.', TO_DATE('2018-03-20', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all is bright', 2013, 'Well-acted but uneven, All Is Bright strands a pair of strong performances from Paul Giamatti and Paul Rudd in a meandering script.', TO_DATE('2013-04-22', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all is lost', 2013, 'Anchored by another tremendous performance in a career full of them, All Is Lost offers a moving, eminently worthwhile testament to Robert Redford''s ability to hold the screen.', TO_DATE('2013-05-22', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all is true', 2018, 'Impressively cast and beautifully filmed, All Is True takes an elegiac look at Shakespeare''s final days.', TO_DATE('2018-12-18', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all is well alles ist gut', 2018, 'Eva Trobisch''s debut film is a painful study of female trauma that extends a compassionate, while uncomfortable look to its main character, fiercely impersonated by the excellent Aenne Schwarz.', TO_DATE('2018-07-02', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all stars', 2013, 'An enthusiastic cast and colorfully choreographed dance sequences can''t save All Stars from its toothless, derivative story.', TO_DATE('2013-04-22', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all that heaven allows', 2001, 'Big heart, big drama, and even bigger colors, All That Heaven Allows is tip top Douglas Sirk.', TO_DATE('2001-06-27', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all the bright places', 2020, 'Though it at times buckles under the emotional weight of its source material, All The Bright Place succeeds on the strength of Elle Fanning and Justice Smith''s charming and tender performances.', TO_DATE('2020-02-25', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all the kings men', 2006, 'With a scenery-chewing performance from Sean Penn, an absence of political insight, and an overall lack of narrative cohesiveness, these Men give Oscar bait a bad name.', TO_DATE('2006-09-10', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all the money in the world', 2017, 'All the Money in the World offers an absorbing portrayal of a true story, brought compellingly to life by a powerful performance from Christopher Plummer.', TO_DATE('2017-12-19', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all the presidents men', 2002, 'A taut, solidly acted paean to the benefits of a free press and the dangers of unchecked power, made all the more effective by its origins in real-life events.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all the pretty horses', 2000, 'This adaptation of Cormac McCarthy''s novel comes off as rather flat and uninvolving. Scenes feel rushed and done in shorthand, and the romance between Damon and Cruz has no sparks.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all the queens men', 2001, 'All the Queen''s Men never capitalizes on its gender-bending conceit, instead relying on low-hanging jokes that never elicit a chuckle.', TO_DATE('2001-10-22', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all the real girls', 2003, 'Has enough honest moments to warrant a look.', TO_DATE('2003-01-21', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all the right moves', 2002, 'All the Right Moves is an uncommonly grim coming-of-age drama that overcomes numerous clichés with its realistic approach to its characters and setting.', TO_DATE('2002-03-08', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all the way', 2016, 'Anchored by Bryan Cranston''s phenomenal performance as LBJ, All the Way is an engrossing portrayal of a complicated man during a pivotal moment in US history.', TO_DATE('2016-05-04', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alle anderen everyone else', 2010, 'Alle Anderen (Everyone Else) taps into the unpredictable energy between two couples to throw finely detailed - and richly rewarding - sparks of emotional truth.', TO_DATE('2010-04-06', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('allied', 2016, 'Allied has its moments, but doesn''t quite achieve epic wartime romance status -- a disappointment made more profound by the dazzling talent assembled on either side of the camera.', TO_DATE('2016-11-21', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('allure', 2018, 'Allure has visual style and an intriguing Evan Rachel Wood on its side, but a clumsily told story leaves this sexually charged thriller less than the sum of its parts.', TO_DATE('2018-03-13', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('almost christmas', 2016, 'While far from the worst holiday dramedy audiences could hope for, Almost Christmas isn''t distinctive enough to prompt a visit to the theater -- or annual yuletide viewings.', TO_DATE('2016-11-08', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('almost famous', 2000, 'Almost Famous, with its great ensemble performances and story, is a well-crafted, warm-hearted movie that successfully draws you into its era.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('almost heroes', 2000, 'A sorry swan song for the talented Chris Farley, Almost Heroes is a directionless comedy that doesn''t even come close to triumph.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('almost human', 2013, 'Almost Human lands with an impressively grisly B-movie splatter, but a fatally flawed screenplay undermines much of its impact.', TO_DATE('2013-10-15', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aloft', 2014, 'Glacially paced and ineptly plotted, Aloft crushes the game efforts of a talented cast under a dreary viewing experience whose title proves sadly ironic.', TO_DATE('2014-02-14', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aloha', 2015, 'Meandering and insubstantial, Aloha finds writer-director Cameron Crowe at his most sentimental and least compelling.', TO_DATE('2015-05-28', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alone', 2020, 'Alone''s minimalistic approach makes this heightened thriller a gripping and suspenseful experience.', TO_DATE('2020-08-28', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alone in the dark', 2005, 'Inept on almost every level, Alone in the Dark may not work as a thriller, but it''s good for some head-slapping, incredulous laughter.', TO_DATE('2005-01-26', 'YYYY-MM-DD'), 1.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alone with her', 2007, 'Alone With Her is a tense psychological thriller that overcomes its contrivances with fine performances and a perpetually unsettling mood.', TO_DATE('2007-01-09', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('along came a spider', 2000, 'Derivative and contains too many implausible situations.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('along came polly', 2004, 'Though the supporting actors are funny, Stiller and Aniston don''t make a believable couple, and the gross-out humor is gratuitous.', TO_DATE('2004-01-02', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alpha', 2018, 'Well-acted and beautifully filmed, Alpha offers a canine-assisted epic adventure that blends rousing action with an extra helping of canine charm.', TO_DATE('2018-08-11', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alpha and omega', 2010, 'With bland visuals and a dull, predictable plot, Alpha and Omega is a runt in 2010''s animated litter.', TO_DATE('2010-09-01', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alpha dog', 2006, 'A glossy yet unflinching portrait of violent, hedonistic teenagers. Bruce Willis and Sharon Stone chew the scenery, while Justin Timberlake gives a noteworthy performance.', TO_DATE('2006-01-28', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alphaville', 2000, 'While Alphaville is by no means a conventional sci-fi film, Jean-Luc Godard creates a witty, noir-ish future all his own.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('altered states', 2000, 'Extraordinarily daring for a Hollywood film, Altered States attacks the viewer with its inventive, aggressive mix of muddled sound effects and visual pyrotechnics.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alvin and the chipmunks chipwrecked', 2011, 'Lazy, rote, and grating, Chipwrecked is lowest-common-denominator family entertainment that''s strictly for the very, very, very young at heart.', TO_DATE('2011-12-10', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('alvin and the chipmunks the road chip', 2015, 'In some respects, Alvin and the Chipmunks: The Road Chip is a marginal improvement over prior installments, although this in no way qualifies as a recommendation.', TO_DATE('2015-12-16', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('always', 2000, 'Its central romance takes occasional dives into excessive sentimentality, but Always otherwise flies high thanks to director Steven Spielberg''s rousing feel for adventure.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('always be my maybe', 2019, 'Carried by the infectious charms of Ali Wong and Randall Park, Always Be My Maybe takes familiar rom-com beats and cleverly layers in smart social commentary to find its own sweet groove.', TO_DATE('2019-05-28', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('always shine', 2016, 'The tense and well-acted Always Shine tells an absorbing story while making a sharp, thought-provoking statement on women''s roles in Hollywood.', TO_DATE('2016-04-17', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('always woodstock', 2014, 'Despite a likable cast, Always Woodstock''s lightweight plot and grating lack of romantic tension never engage.', TO_DATE('2014-11-09', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amadeus', 2000, 'A lavish, entertaining, powerful film about the life and influence, both positive and negative, of one of Western culture''s great artists.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amanda knox', 2016, 'Amanda Knox honors its subject with an absorbing -- if slightly incomplete -- look at the details and troubling implications of her arrest and subsequent fight for freedom.', TO_DATE('2016-09-10', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amandla a revolution in fourpart harmony', 2002, 'The powerful singing in Amandla makes for an uplifting, compelling documentary.', TO_DATE('2002-10-03', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amarcord', 2000, 'Ribald, sweet, and sentimental, Amarcord is a larger-than-life journey through a seaside village and its colorful citizens.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amazing grace', 2018, 'Brilliantly capturing a remarkable performer near the peak of her prodigious power, Amazing Grace is a thrilling must-watch documentary for Aretha Franklin fans.', TO_DATE('2018-11-13', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amelia', 2009, 'Amelia takes the compelling raw materials of its subject''s life and does little with them, conventionally ticking off Earhart''s accomplishments without exploring the soul of the woman.', TO_DATE('2009-10-18', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amélie', 2001, 'The feel-good Amelie is a lively, fanciful charmer, showcasing Audrey Tautou as its delightful heroine.', TO_DATE('2001-08-14', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amen', 2002, 'Amen loses some of its impact to a protracted running time and deliberate pace, but Ulrich Tukur''s powerful performance helps bring the story''s worthy themes to life.', TO_DATE('2002-09-13', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('america imagine the world without her', 2014, 'Passionate but poorly constructed, America preaches to the choir.', TO_DATE('2014-06-28', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('america the beautiful', 2008, 'This doc doesn''t expose any new territory about our unattainable standards of beauty, but does manage to entertain with an effective and accessible tone by filmmaker/subject Darryl Roberts.', TO_DATE('2008-05-16', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american the bill hicks story', 2010, 'A treasure trove of archival material and interviews, American: The Bill Hicks Story is an exuberant celebration about a unique, sorely missed voice in comedy.', TO_DATE('2010-03-17', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american animals', 2018, 'American Animals tangles with a number of weighty themes, but never at the expense of delivering a queasily compelling true crime thriller.', TO_DATE('2018-01-20', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american assassin', 2017, 'American Assassin hits a few easy targets, but without enough style or wit to truly bring its characters to life -- or stand out in a crowded field of more compelling spy thrillers.', TO_DATE('2017-09-13', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american beauty', 2000, 'Flawlessly cast and brimming with dark, acid wit, American Beauty is a smart, provocative high point of late ''90s mainstream Hollywood film.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american buffalo', 1996, 'It lacks the dynamism of other adaptations of his work, but American Buffalo still offers the tenacious characterizations and hard-hitting dialogue that are hallmarks of David Mamet''s writing.', TO_DATE('1996-09-13', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american dreamz', 2006, 'A cheerfully silly satire with an unfortunate lack of focus, American Dreamz takes aim at numerous targets, but isn''t pointed enough for relevant social commentary.', TO_DATE('2006-03-20', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american factory', 2019, 'American Factory takes a thoughtful -- and troubling -- look at the dynamic between workers and employers in the 21st-century globalized economy.', TO_DATE('2019-01-26', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american folk', 2017, 'American Folk may not wholly meet its ambition as a statement on a mourning United States, but charming performances and a stellar soundtrack make it a modest pleasure.', TO_DATE('2017-02-14', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('der amerikanische freund the american friend', 2000, 'The American Friend is a slow burning existential thriller that does justice to the Patricia Highsmith source novel.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american gangster', 2007, 'American Gangster is a gritty and entertaining throwback to classic gangster films, with its lead performers firing on all cylinders.', TO_DATE('2007-09-25', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american gigolo', 2000, 'While Paul Schrader''s clinical direction and Richard Gere''s muted performance don''t stir much passion, American Gigolo succeeds as a stylish character study.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american graffiti', 2000, 'One of the most influential of all teen films, American Graffiti is a funny, nostalgic, and bittersweet look at a group of recent high school grads'' last days of innocence.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american gun', 2005, 'Despite its intriguing premise, this earnest anti-gun polemic is too melodramatic to resonate.', TO_DATE('2005-09-13', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american hardcore', 2006, 'American Hardcore is an informative and highly entertaining look at the heyday of punk in the early 1980s.', TO_DATE('2006-01-23', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an american haunting', 2005, 'Well, it looks good. But wasn''t it supposed to be scary?', TO_DATE('2005-11-11', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american history x', 2000, 'American History X doesn''t contend with its subject matter as fully as it could, but Edward Norton''s performance gives this hard-hitting drama crucial weight.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american honey', 2016, 'American Honey offers a refreshingly unconventional take on the coming-of-age drama whose narrative risks add up to a rewarding experience even if they don''t all pay off.', TO_DATE('2016-05-14', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american hustle', 2013, 'Riotously funny and impeccably cast, American Hustle compensates for its flaws with unbridled energy and some of David O. Russell''s most irrepressibly vibrant direction.', TO_DATE('2013-12-04', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an american in paris', 2000, 'The plot may be problematic, but such concerns are rendered superfluous by Gene Kelly and Leslie Caron''s star power, the Gershwins'' classic songs, and Vincente Minnelli''s colorful, sympathetic direction.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american made', 2017, 'American Made''s fast-and-loose attitude with its real-life story mirrors the cavalier -- and delightfully watchable -- energy Tom Cruise gives off in the leading role.', TO_DATE('2017-08-17', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american mary', 2012, 'It suffers a bit from some uneven acting and an underwhelming climax, but American Mary utilizes pitch black humor and striking visuals to deliver gory, freaky thrills for body horror enthusiasts.', TO_DATE('2012-08-30', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american movie', 1999, 'Well worth watching for film buffs and anyone who believes in following your dreams, American Movie is a warm, funny, and engrossing ode to creative passion.', TO_DATE('1999-11-05', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american outlaws', 2001, 'With corny dialogue, revisionist history, anachronistic music, and a generically attractive cast, American Outlaws is a sanitized, teenybopper version of Jesse James.', TO_DATE('2001-08-14', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american pastoral', 2016, 'American Pastoral finds debuting director Ewan McGregor''s reach exceeding its grasp with a well-intentioned Philip Roth adaptation that retains the form, but little of the function, of its source material.', TO_DATE('2016-09-09', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american pie', 2000, 'So embarrassing it''s believable, American Pie succeeds in bringing back the teen movie genre.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american pie 2', 2001, 'Being a sequel, American Pie 2 doesn''t retain the freshness of the original, nor is it as funny.', TO_DATE('2001-08-06', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the american president', 1995, 'A charming romantic comedy with political bite, Rob Reiner''s American President features strong lead performances and some poignant observations of politics and media in the 1990s.', TO_DATE('1995-11-17', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american psycho', 2000, 'If it falls short of the deadly satire of Bret Easton Ellis''s novel, American Psycho still finds its own blend of horror and humor, thanks in part to a fittingly creepy performance by Christian Bale.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american reunion', 2012, 'It''ll provide sweetly nostalgic comfort food for fans of the franchise, but American Reunion fails to do anything truly new or interesting -- or even very funny -- with the characters.', TO_DATE('2012-04-03', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an american rhapsody', 2001, 'Though obviously a labor of love, American Rhapsody is an uneven, heavy-handed effort, particularly in the second half.', TO_DATE('2001-07-16', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american sniper', 2014, 'Powered by Clint Eastwood''s sure-handed direction and a gripping central performance from Bradley Cooper, American Sniper delivers a tense, vivid tribute to its real-life subject.', TO_DATE('2014-11-12', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american son', 2019, 'Kerry Washington capably anchors American Son with her nervy turn as a concerned mother, but the staginess of the production ill-serves its heavy-handed social commentary.', TO_DATE('2019-09-05', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american splendor', 2003, 'Exhilarating both stylistically and for its entertaining, moving portrayal of an everyman, American Splendor is a portrait of a true underground original.', TO_DATE('2003-01-30', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american swing', 2009, 'While American Swing covers a fascinating subject, its amateur documentary treatment does it no favors.', TO_DATE('2009-02-17', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an american tail', 2000, 'Exquisitely animated, An American Tail is a sweet, melancholy, immigrants story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american teen', 2008, 'American Teen skates some thin ice with its documentary ethics but, in the end, presents a charming and stylish (if packaged) tale.', TO_DATE('2008-01-19', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american ultra', 2015, 'American Ultra has some interesting ideas, but like its stoned protagonist, it''s too easily distracted to live up to its true potential.', TO_DATE('2015-08-18', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american violet', 2008, 'Though its politics are as obvious as its outcome, American Violet is an earnest docudrama about the justice system with a powerful performance from Nicole Behairie.', TO_DATE('2008-10-18', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american wedding', 2003, 'Raunchier and even more gross than the first two American Pies, American Wedding ought to please fans of the series.', TO_DATE('2003-03-13', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an american werewolf in london', 1981, 'Terrifying and funny in almost equal measure, John Landis'' horror-comedy crosses genres while introducing Rick Baker''s astounding make-up effects.', TO_DATE('1981-08-21', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('americas heart and soul', 2004, 'Louis Schwartzberg''s sprawling tour across America highlights the heartland''s visual beauty, but this resolutely uncritical inquiry in the nation''s soul is frustratingly shallow.', TO_DATE('2004-06-28', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('americas sweethearts', 2001, 'Despite its famous cast, the movie lacks sympathetic characters and is only funny in spurts.', TO_DATE('2001-05-09', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amira sam', 2015, 'Amira & Sam doesn''t quite live up to its premise -- or the chemistry of its stars -- but its flaws are overcome by its sweet, subversive charm.', TO_DATE('2015-01-25', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amistad', 1997, 'Heartfelt without resorting to preachiness, Amistad tells an important story with engaging sensitivity and absorbing skill.', TO_DATE('1997-12-12', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the amityville horror', 2005, 'A so-so remake of a so-so original.', TO_DATE('2005-04-12', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amityville the demon', 2002, 'A gimmicky Amityville retread with insufferable characters.', TO_DATE('2002-08-26', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amores perros', 2000, 'The brutality of Amores Perros may be difficult to watch at times, but this intense, gritty film packs a hard wallop.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amour', 2012, 'With towering performances and an unflinching script from Michael Haneke, Amour represents an honest, heartwrenching depiction of deep love and responsibility.', TO_DATE('2012-05-20', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amour fou', 2014, 'Amour Fou risks overpowering its deceptively impactful story with its remarkable visuals, but ultimately forms a fascinating whole.', TO_DATE('2014-05-21', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amulet', 2020, 'If its chilly sense of dread never quite becomes spine-tingling terror, Amulet remains smart, solidly disquieting fun for genre fans seeking slow-building horror.', TO_DATE('2020-01-27', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amy', 2015, 'As riveting as it is sad, Amy is a powerfully honest look at the twisted relationship between art and celebrity -- and the lethal spiral of addiction.', TO_DATE('2015-05-16', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('amy schumer growing', 2019, 'Amy Schumer''s standup matures in an hour filled with concise insights into aging and matrimony, marked with only slight Growing pains as the comedian refreshes her comedic voice.', TO_DATE('2019-03-13', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an acceptable loss', 2019, 'An Acceptable Loss attempts a political thriller approach to a serious issue, but ends up sacrificing thrills -- as well as a satisfying story -- in the bargain.', TO_DATE('2019-01-10', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an alan smithee film burn hollywood burn', 2000, 'A witless Hollywood satire whose hammy, obvious jokes are neither funny nor insightful of the movie business.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an american carol', 2008, 'An American Carol suffers not so much from its perceived political bias, but from the fact that it simply is not very funny.', TO_DATE('2008-10-03', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an education', 2009, 'Though the latter part of the film may not appeal to all, An Education is a charming coming-of-age tale powered by the strength of relative newcomer Carey Mulligan''s standout performance.', TO_DATE('2009-01-22', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an evening with beverly luff linn', 2018, 'An Evening with Beverly Luff Linn unites an intriguing array of comedic talents for a thoroughly unusual outing that proves itself disappointingly difficult to recommend.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an inconvenient sequel truth to power', 2017, 'An Inconvenient Sequel: Truth to Power makes a plea for environmental responsibility that adds a persuasive -- albeit arguably less impactful -- coda to its acclaimed predecessor.', TO_DATE('2017-01-19', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anaconda', 2000, 'Anaconda''s pulpy pleasures are constricted by its own absurdity, but creature feature fans may enjoy its brazen silliness.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anacondas the hunt for the blood orchid', 2004, 'A cheesy monster B-movie.', TO_DATE('2004-08-25', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('analyze that', 2002, 'The one joke premise is stretched a bit thin in this messy sequel, but a few laughs can be had here and there.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('analyze this', 2000, 'Analyze This is a satisfying comedy with great performances by De Niro and Crystal.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anamorph', 2008, 'Thin on plot but heavy on academic references, Anamorph proves more derivative than terrifying.', TO_DATE('2008-04-16', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anatomy of a murder', 2000, 'One of cinema''s greatest courtroom dramas, Anatomy of a Murder is tense, thought-provoking, and brilliantly acted, with great performances from James Stewart and George C. Scott.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anchorman the legend of ron burgundy', 2004, 'Filled with inspired silliness and quotable lines, Anchorman isn''t the most consistent comedy in the world, but Will Ferrell''s buffoonish central performance helps keep this portrait of a clueless newsman from going off the rails.', TO_DATE('2004-05-06', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anchorman 2 the legend continues', 2013, 'It''s just as uneven and loosely structured as the first Anchorman -- and while Anchorman 2: The Legend Continues may not be quite as quotable, it''s nearly as funny as its predecessor.', TO_DATE('2013-12-03', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('and everything is going fine', 2010, 'Even if And Everything Is Going Fine isn''t one of Soderbergh''s more commercial efforts, this collection of judiciously edited performance footage of the late monologist Spalding Gray gave the director a chance to show a rarely-seen side of his artistry.', TO_DATE('2010-12-06', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('and justice for all', 2000, 'A volcanic Al Pacino holds court in this histrionic legal drama, the star grounding a tonally imbalanced script with the conviction of his impassioned performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('and now ladies gentlemen', 2003, 'The plot is convoluted and awash in suds.', TO_DATE('2003-06-05', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('and so it goes', 2014, 'And So It Goes aims for comedy, but with two talented stars stuck in a half-hearted effort from a once-mighty filmmaker, it ends in unintentional tragedy.', TO_DATE('2014-07-14', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('and then we danced', 2019, 'Led by an outstanding performance from Levan Gelbakhiani, And Then We Danced defeats prejudice with overwhelming compassion.', TO_DATE('2019-05-16', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the andromeda strain', 2000, 'Although its urgent subject matter warrants less a deliberate pace, The Andromeda Strain brings Michael Crichton''s techno-thriller to the big screen with striking intelligence and an engrossing sense of paranoia.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anesthesia', 2015, 'Anesthesia''s incredible cast is wasted on a sloppily-assembled drama whose grand ambitions are undermined by a flawed screenplay.', TO_DATE('2015-04-23', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('angel has fallen', 2019, 'Cut from the same rough cloth as its predecessors, Angel Has Fallen rounds out a mostly forgettable action trilogy in fittingly mediocre fashion.', TO_DATE('2019-08-20', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('angela', 2005, 'The clunky dialogue and shallow characters fail to capitalize upon Angel-A''s stunning, poetic cinematography.', TO_DATE('2005-12-21', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('angelas ashes', 2000, 'In spite of its attempts to accurately record Frank McCourt''s memoirs, the onscreen adaptation fails to capture any of the drama or humor of his life.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('angels wear white', 2017, 'Angels Wear White can be uncomfortable viewing, but its grim subject matter is balanced by a smartly constructed story elevated by powerful acting.', TO_DATE('2017-09-07', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('angels with dirty faces', 2000, 'James Cagney''s explosive charisma and Pat O''Brien''s steadfast decency are a match made in heaven in this touching battle for a community''s soul.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('angus thongs and perfect snogging', 2008, 'Based on two of British writer Louise Rennison''s popular books, Angus, Thongs and Perfect Snogging is a pleasant and funny tween comedy, comfortable for UK audiences as well as stateside crowds.', TO_DATE('2008-07-21', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aniara', 2018, 'Dazzling, but a little dull, ANIARA''s impeccable production design is undermined by its underwhelming philosophical pondering.', TO_DATE('2018-09-08', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anima', 2019, 'Thom Yorke''s eerie compositions blend perfectly with Paul Thomas Anderon''s ethereal direction to form a bewitching meditation on alienation and what it means to connect.', TO_DATE('2019-06-26', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('animal kingdom', 2010, 'With confident pacing, a smart script, and a top-notch cast, Animal Kingdom represents the best the Australian film industry has to offer.', TO_DATE('2010-02-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('animals', 2014, 'Animals'' drug-fueled storyline is undeniably grim, but its sensitive approach to its difficult themes -- and its talented cast -- make watching it well worth the discomfort.', TO_DATE('2014-03-21', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anna', 2019, 'Anna finds writer-director Luc Besson squarely in his wheelhouse, but fans of this variety of stylized action have seen it all done before -- and better.', TO_DATE('2019-06-19', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anna and the apocalypse', 2017, 'Anna and the Apocalypse finds fresh brains and a lot of heart in the crowded zombie genre - not to mention a fun genre mashup populated by rootable characters.', TO_DATE('2017-09-23', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anna karenina', 2012, 'Joe Wright''s energetic adaptation of Tolstoy''s classic romance is a bold, visually stylized work -- for both better and worse.', TO_DATE('2012-09-03', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('annabelle', 2014, 'Annabelle borrows unabashedly from better horror films, content to leave viewers with a string of cheap jolts that fail to build on the far more effective The Conjuring.', TO_DATE('2014-10-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('annabelle comes home', 2019, 'Fun for fans even if it isn''t as frightening as some of its predecessors, Annabelle Comes Home suggests there''s still some life left in the Conjuring franchise.', TO_DATE('2019-06-24', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('annabelle creation', 2017, 'Annabelle: Creation adds another strong chapter to the Conjuring franchise - and offers further proof that freaky-looking dolls remain reliably terrifying.', TO_DATE('2017-06-19', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('annapolis', 2006, 'Stocked with leading men who look the part but lacking an iota of original plot, Annapolis is merely a watery shadow of superior seafaring military dramas.', TO_DATE('2006-01-24', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('annie', 2000, 'John Huston proves an odd choice to direct, miring Annie in a sluggish, stagebound mess of an adaptation, but the kids are cute and the songs are memorable.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('annie', 2014, 'The new-look Annie hints at a progressive take on a well-worn story, but smothers its likable cast under clichés, cloying cuteness, and a distasteful materialism.', TO_DATE('2014-12-14', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('annie hall', 2000, 'Filled with poignant performances and devastating humor, Annie Hall represents a quantum leap for Woody Allen and remains an American classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('annihilation', 2018, 'Annihilation backs up its sci-fi visual wonders and visceral genre thrills with an impressively ambitious -- and surprisingly strange -- exploration of challenging themes that should leave audiences pondering long after the end credits roll.', TO_DATE('2018-02-21', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the anniversary party', 2000, 'This Party features a killer cast and many funny scenes, but the movie feels like nothing more than an excuse for the actors to emote.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anomalisa', 2015, 'Anomalisa marks another brilliant and utterly distinctive highlight in Charlie Kaufman''s filmography, and a thought-provoking treat for fans of introspective cinema.', TO_DATE('2015-09-05', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anon', 2018, 'Lacking enough depth to fulfill its evident ambitions or enough excitement to work as a sci-fi action thriller, Anon lives down to its title in the most glumly predictable ways.', TO_DATE('2018-05-03', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anonymous', 2011, 'Roland Emmerich delivers his trademark visual and emotional bombast, but the more Anonymous stops and tries to convince the audience of its half-baked theory, the less convincing it becomes.', TO_DATE('2011-09-10', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('another 48 hrs', 2000, 'Even the return of Eddie Murphy, Nick Nolte, and director Walter Hill can''t hide the lazy, patchwork quality of Another 48 Hrs.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('another earth', 2011, 'Another Earth is often weighed down by placid pacing and ponderousness, but this soulful sci-fi nevertheless offers plenty of profound concepts to ponder.', TO_DATE('2011-02-01', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('another happy day', 2011, 'Another Happy Day features outstanding performances (Ellen Barkin''s especially) but the characters are too unpleasant to endure.', TO_DATE('2011-01-30', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('another year', 2010, 'Characterized by strong performances and the director''s trademark feel for the nuances of everyday life, Another Year marks another solid entry in Mike Leigh''s career of kitchen-sink English drama.', TO_DATE('2010-05-25', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the answer man arlen faber', 2009, 'The Answer Man takes an interesting premise and overloads it with implausible scenarios, indie comedy cliches, and an all-too-familiar story arc that only occasionally benefits from its typically capable actors.', TO_DATE('2009-04-02', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ant bully', 2006, 'Sometimes inventive and witty, this animated adventure into an ant-sized world is a pleasant diversion.', TO_DATE('2006-07-24', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('antman and the wasp', 2018, 'A lighter, brighter superhero movie powered by the effortless charisma of Paul Rudd and Evangeline Lilly, Ant-Man and The Wasp offers a much-needed MCU palate cleanser.', TO_DATE('2018-06-27', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('antebellum', 2020, 'Antebellum fails to connect its images with any meaning, making for a largely unpleasant experience lacking any substantial scares.', TO_DATE('2020-08-31', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('antibirth', 2016, 'Antibirth''s outstanding performances anchor its wilder flights of fancy, making this surreal horror outing from writer-director Danny Perez more than a garish curiosity.', TO_DATE('2016-01-26', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('antitrust', 2000, 'Due to its use of cliched and ludicrous plot devices, this thriller is more predictable than suspenseful. Also, the acting is bad.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('antiviral', 2012, 'Antiviral is well-crafted body horror, packed with interesting -- if not entirely subtle -- ideas.', TO_DATE('2012-05-20', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('antman', 2015, 'Led by a charming performance from Paul Rudd, Ant-Man offers Marvel thrills on an appropriately smaller scale -- albeit not as smoothly as its most successful predecessors.', TO_DATE('2015-07-08', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('antonia antonias line', 1995, 'Magical and morbid, Antonia picturesque landscapes and proficient performances elevate a somewhat pedestrian parable.', TO_DATE('1995-09-12', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('antwone fisher', 2002, 'Washington''s directing debut is a solidly crafted, emotionally touching work.', TO_DATE('2002-09-18', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('antz', 2000, 'Featuring a stellar voice cast, technically dazzling animation, and loads of good humor, Antz should delight both children and adults.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anvil the story of anvil', 2008, 'A touching, uplifting and inspirational rockumentary about an aging metal band, both hilarious and heart-warming in equal measure.', TO_DATE('2008-01-28', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('any given sunday', 1999, 'Sometimes entertaining, but overall Any Given Sunday is a disappointment coming from Oliver Stone.', TO_DATE('1999-12-22', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anything else', 2003, 'Too many elements from better Woody Allen films are being recycled here.', TO_DATE('2003-08-28', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('anywhere but here', 2000, 'The strong chemistry between Susan Sarandon and Natalie Portman as a mother and daughter trying to make a fresh start in L.A. helps to elevate Anywhere But Here above its occasional forays into melodrama.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('apocalypse now', 1979, 'Francis Ford Coppola''s haunting, hallucinatory Vietnam War epic is cinema at its most audacious and visionary.', TO_DATE('1979-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('apocalypse now redux', 2001, 'The additional footage slows down the movie somewhat (some say the new cut is inferior to the original), but Apocalypse Now Redux is still a great piece of cinema.', TO_DATE('2001-07-10', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('apocalypto', 2006, 'Apocalypto is a brilliantly filmed, if mercilessly bloody, examination of a once great civilization.', TO_DATE('2006-11-23', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('apollo 11', 2019, 'Edifying and inspiring in equal measure, Apollo 11 uses artfully repurposed archival footage to send audiences soaring back to a pivotal time in American history.', TO_DATE('2019-01-25', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('apollo 13', 1995, 'In recreating the troubled space mission, Apollo 13 pulls no punches: it''s a masterfully told drama from director Ron Howard, bolstered by an ensemble of solid performances.', TO_DATE('1995-06-30', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('apollo 18', 2011, 'A boring, suspense-free Paranormal Activity rip-off that feels long even at just 90 minutes.', TO_DATE('2011-09-02', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('apostle', 2018, 'Apostle resists easy scares in favor of a steady, slow-building descent into dread led by a commanding central performance from Dan Stevens.', TO_DATE('2018-09-22', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('appropriate behavior', 2014, 'Warm, funny, and quietly profound, Appropriate Behavior serves as a thoroughly compelling calling card for writer, director, and star Desiree Akhavan.', TO_DATE('2014-01-19', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('après vous after you', 2004, 'This farcical French comedy of errors is well-acted, but the absurdities feel too forced to make such a light confection work.', TO_DATE('2004-05-10', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('april and the extraordinary world avril et le monde truqué', 2015, 'Bursting with a colorful imagination befitting its promise-packed title, April and the Extraordinary World offers spectacular delights for animation fans willing to venture off the beaten path.', TO_DATE('2015-07-08', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('apt pupil', 2000, 'A somewhat disturbing movie that works as a suspenseful thriller, yet isn''t completely satisfying.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aqua teen hunger force colon movie film for theaters', 2007, 'The non sequitur humor of Aqua Teen Hunger Force will surely appeal to its built-in fanbase, but for the uninitiated, the premise wears thin.', TO_DATE('2007-03-22', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aquamarine', 2006, 'A lighthearted, gum-smacking, boy-crazy film with a hopeful message for young girls.', TO_DATE('2006-02-19', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('arachnophobia', 1990, 'Arachnophobia may not deliver genuine chills, but it''s an affectionate, solidly built tribute to Hollywood''s classic creature features.', TO_DATE('1990-07-18', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('arbitrage', 2012, 'Arbitrage is both a tense thriller and a penetrating character study, elevated by the strength of a typically assured performance from Richard Gere.', TO_DATE('2012-01-22', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('archipelago', 2010, 'Sad, funny, and wise in equal measure, Archipelago finds writer-director Joanna Hogg in remarkably strong, confident form.', TO_DATE('2010-12-07', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the architect', 2006, 'A glum drama that''s so self-affected it fails to affect.', TO_DATE('2006-11-22', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('archive', 2020, 'Archive executes its fairly basic program efficiently, offering sci-fi fans an engaging meditation on love and human nature.', TO_DATE('2020-07-07', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('arctic', 2018, 'Arctic proves that a good survival thriller doesn''t need much in the way of dialogue to get by -- especially when Mads Mikkelsen is the one doing the surviving.', TO_DATE('2018-05-11', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('arctic tale', 2007, 'Arctic Tale features breathtaking nature cinematography, but is undone by its over-cutesy narration.', TO_DATE('2007-06-19', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('are we done yet', 2007, 'Are We Done Yet? plays it way too safe with generic slapstick and uninspired domestic foibles.', TO_DATE('2007-03-31', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('are you here', 2013, 'Given the amount of talent assembled on both sides of the camera, Are You Here falls bewilderingly flat.', TO_DATE('2013-09-09', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('argo', 2012, 'Tense, exciting, and often darkly comic, Argo recreates a historical event with vivid attention to detail and finely wrought characters.', TO_DATE('2012-09-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the aristocats', 2000, 'Though The Aristocats is a mostly middling effort for Disney, it is redeemed by terrific work from its voice cast and some jazzy tunes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the aristocrats', 2005, 'Can a joke stand up to repeated tellings? Hilarious and revealing of the way comedy works, The Aristocrats demonstrates that it''s possible.', TO_DATE('2005-02-02', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('arizona dream', 2000, 'Inscrutably strange, yet undeniably compelling, Arizona Dream is anchored by magnetic performances from Johnny Depp and Faye Dunaway.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('arkansas', 2020, 'Arkansas has an appealing low-key charm, but this character-driven neo-noir is too diffuse and derivative to leave much of an impression.', TO_DATE('2020-05-01', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('arlington road', 2000, 'A suspenseful thriller led by strong cast performances built around a somewhat implausible story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('armadillo', 2010, 'Capturing both the lulls and terror during warfare, Armadillo is a viscerally filmed documentary that brings audiences alarmingly close to the frontlines of combat.', TO_DATE('2010-09-17', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('armageddon', 2000, 'Lovely to look at but about as intelligent as the asteroid that serves as the movie''s antagonist, Armageddon slickly sums up the cinematic legacies of producer Jerry Bruckheimer and director Michael Bay.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jackpot', 2012, 'With plenty of dark humor to leaven the bloody mayhem, Jackpot is an entertaining murder mystery with a suitably quirky Scandinavian twist.', TO_DATE('2012-04-20', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('armored', 2009, 'This B-grade thriller has a good cast and director but is undone by plot holes and messy conclusion.', TO_DATE('2009-11-26', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('army of darkness', 1993, 'Army of Darkness is a madcap adventure worth taking thanks to Bruce Campbell''s hammy charm and Sam Raimi''s acrobatic direction, although an intentional lack of shocks make this a discordant capper to the Evil Dead franchise.', TO_DATE('1993-02-19', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('army of shadows larmée des ombres', 2003, 'Originally made in 1969, this recently reissued classic is a masterful examination of the inner workings of the World War II resistance efforts.', TO_DATE('2003-04-15', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('around the bend', 2004, 'Around the Bend sets a destination of earnest generational drama, but settles for the most derivative route to get there, veering off course into trite sentimentality.', TO_DATE('2004-09-02', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('around the world in 80 days', 2004, 'Hit-and-miss family fare that bares only the slightest resemblance to Verne''s novel.', TO_DATE('2004-04-19', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('arrival', 2016, 'Arrival delivers a must-see experience for fans of thinking person''s sci-fi that anchors its heady themes with genuinely affecting emotion and a terrific performance from Amy Adams.', TO_DATE('2016-09-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('arsenal', 2017, 'Aside from an opportunity to watch a mustachioed Nicolas Cage acting from under a wig and behind a prosthetic nose, Arsenal has depressingly little to offer.', TO_DATE('2017-01-03', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('art and craft', 2014, 'The spotlight it shines on an apparently troubled mind may strike some viewers as exploitative, but Art and Craft remains a thoroughly gripping glimpse into the life of a legendary art forger.', TO_DATE('2014-04-28', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the art of the steal', 2009, 'Deeply esoteric and unapologetically one-sided, The Art of the Steal proves a documentary doesn''t have to make an objective argument as long as it argues well.', TO_DATE('2009-12-25', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('art school confidential', 2006, 'Art School''s misanthropy is too sour, its targets too flat and cliched, and Clowes and Zwigoff stumble when trying to build a story around the premise.', TO_DATE('2006-01-23', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('arthur', 2011, 'An irritating, unnecessary remake that demonstrates the libertine charm Russell Brand exudes in supporting roles turn against him when he''s star of the show.', TO_DATE('2011-04-05', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('arthur 2 on the rocks', 2000, 'Arthur''s boozy charm curdles into a bad hangover in this unnecessary sequel.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('arthur christmas', 2011, 'Aardman Animations broadens their humor a bit for Arthur Christmas, a clever and earnest holiday film with surprising emotional strength.', TO_DATE('2011-11-06', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('arthur miller writer', 2017, 'Director Rebecca Miller delivers a homespun documentary about one of America''s most iconic playwrights, utilizing intimate footage and personal insight to craft a warm retrospective of her father''s life.', TO_DATE('2017-12-03', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('arthur newman', 2012, 'Despite the natural charisma of its leads, Arthur Newman does little with its intriguing setup, and the result is bland and unconvincing.', TO_DATE('2012-09-12', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('as above so below', 2014, 'After an intriguing setup that threatens to claw its way out of found-footage overkill, As Above/So Below plummets into clichéd mediocrity.', TO_DATE('2014-08-20', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('as good as it gets', 2000, 'James L. Brooks and Jack Nicholson, doing what they do best, combine smart dialogue and flawless acting to squeeze fresh entertainment value out of the romantic-comedy genre.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('as i lay dying', 2013, 'As I Lay Dying finds director, star, and co-writer James Franco attempting to adapt one of William Faulkner''s weightier works, with disappointingly muddled results.', TO_DATE('2013-05-20', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ash is purest white', 2018, 'Ash Is Purest White finds writer-director Zhangke Jia revisiting familiar themes while continuing to observe modern Chinese society with an urgent, empathetic eye.', TO_DATE('2018-05-12', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('popiól i diament ashes and diamonds', 2001, 'A stylish thriller flavored with post-war political subtext, Ashes and Diamonds is incendiary intellectual cinema that still delivers genre thrills.', TO_DATE('2001-04-26', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ashes of time redux', 1800, 'Wong Kar Wai''s redux, with a few slight changes from his 1994 classic, is a feast for the eyes, if a little difficult to follow.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ask the dust', 2006, 'Though Hayek is luminous, Farrell seems miscast, and the film fails to capture the gritty, lively edginess of the book upon which it''s based.', TO_DATE('2006-02-03', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the asphalt jungle', 2000, 'The Asphalt Jungle is an expertly told crime story with attention paid to the crime and characters in equal measure.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ass backwards', 2013, 'June Diane Raphael and Casey Wilson are sharp comedic performers, but their co-written script gives them little to work with in this meandering farce.', TO_DATE('2013-01-24', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('assassination nation', 2018, 'Assassination Nation juggles exploitation and socially aware elements with mixed results, but genre fans may find it too stylish and viscerally energetic to ignore.', TO_DATE('2018-01-23', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the assassination of jesse james by the coward robert ford', 2007, 'On the strength of its two lead performances Assassination is an expertly crafted period piece, and an insightful look at one of the enduring figures of American lore.', TO_DATE('2007-08-31', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('assassination tango', 2002, 'Slow to start, this quirky film eventually overstays its welcome.', TO_DATE('2002-09-21', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('assassins creed', 2016, 'Assassin''s Creed is arguably better made (and certainly better cast) than most video game adaptations; unfortunately, the CGI-fueled end result still is still a joylessly overplotted slog.', TO_DATE('2016-12-19', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('assault on precinct 13', 2005, 'This remake has been praised by some as an expertly made B-movie, and dismissed by others as formulaic.', TO_DATE('2005-01-12', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('assisted living', 2003, 'An unconventional, heartfelt blend of fact and fiction.', TO_DATE('2003-07-24', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('astro boy astroboy', 2009, 'While it isn''t terribly original, and it seems to have a political agenda that may rankle some viewers, Astro Boy boasts enough visual thrills to please its target demographic.', TO_DATE('2009-10-08', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('astronaut', 2019, 'Astronaut can''t quite escape the gravitational pull of its story''s sentimental overtones, but Richard Dreyfuss keeps the film in a pleasantly diverting orbit.', TO_DATE('2019-06-24', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the astronaut farmer', 2006, 'The Astronaut Farmer is a charming, inspirational drama that successfully avoids modern cinematic cliches while appealing to the optimistic dreamer in all of us.', TO_DATE('2006-10-15', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the astronauts wife', 1999, 'Despite the best efforts of its talented leads, The Astronaut''s Wife moves at a snail''s pace and fails to generate enough intrigue to keep viewers engaged.', TO_DATE('1999-08-27', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('asylum', 2005, 'This catastrophic adaptation of Patrick McGrath''s novel gets sillier and more implausible as it goes along.', TO_DATE('2005-07-16', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('at any price', 2012, 'At Any Price features a terrific performance from Dennis Quaid, and it offers further evidence of Ramin Bahrani''s unique eye for detail, but film is weighted down by an overly melodramatic story.', TO_DATE('2012-09-12', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('at eternitys gate', 2018, 'Led by mesmerizing work from Willem Dafoe in the central role, At Eternity''s Gate intriguingly imagines Vincent Van Gogh''s troubled final days.', TO_DATE('2018-09-04', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('at the devils door', 2014, 'At the Devil''s Door has no shortage of creepy style -- unfortunately, that isn''t enough to distract from an uninspired story that never capitalizes on its potential.', TO_DATE('2014-08-04', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('atanarjuat the fast runner atanarjuat', 2002, 'Compelling human drama and stunning cinematography make The Fast Runner an absorbing experience.', TO_DATE('2002-01-10', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('atl', 2006, 'Strong lead performances and catchy musical interludes rescue this coming-of-age story from its formulaic script and uneven direction.', TO_DATE('2006-01-31', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('atlantic city', 2002, 'Bittersweet and reflective, Atlantic City is a modest romance given raw power by Burt Lancaster and Susan Sarandon''s heartfelt performances along with director Louis Malle''s eccentric eye for detail.', TO_DATE('2002-06-05', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('atlantics', 2019, 'An unpredictable supernatural drama rooted in real-world social commentary, Atlantique suggests a thrillingly bright future for debuting filmmaker Mati Diop.', TO_DATE('2019-05-16', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('atlantis the lost empire', 2000, 'Atlantis provides a fast-paced spectacle, but stints on such things as character development and a coherent plot.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('atlas shrugged part i', 2011, 'Passionate ideologues may find it compelling, but most filmgoers will find this low-budget adaptation of the Ayn Rand bestseller decidedly lacking.', TO_DATE('2011-04-05', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('atlas shrugged part ii', 2012, 'Poorly written, clumsily filmed and edited, and hampered by amateurish acting, Atlas Shrugged: Part II does no favors to the ideology it so fervently champions.', TO_DATE('2012-10-11', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('atomic blonde', 2017, 'Atomic Blonde gets enough mileage out of its stylish action sequences -- and ever-magnetic star -- to make up for a narrative that''s somewhat less hard-hitting than its protagonist.', TO_DATE('2017-03-13', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the atomic cafe', 2001, 'The Atomic Cafe deconstructs the beginnings of the Nuclear Age with pitch-black humor and a dread-inducing view of history.', TO_DATE('2001-09-26', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('atonement', 2007, 'Atonement features strong performances, brilliant cinematography, and a unique score. Featuring deft performances from James MacAvoy and Keira Knightley, it''s a successful adaptation of Ian McEwan''s novel.', TO_DATE('2007-04-19', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('attack the block', 2011, 'Effortlessly mixing scares, laughs, and social commentary, Attack the Block is a thrilling, brisky-paced sci-fi yarn with a distinctly British flavor.', TO_DATE('2011-03-14', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('attenberg', 2011, 'At once playfully eccentric and poignantly bittersweet, Attenberg adds a refreshing sideways spin to the arthouse coming-of-age drama.', TO_DATE('2011-01-20', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('audition ôdishon', 1999, 'An audacious, unsettling Japanese horror film from director Takashi Miike, Audition entertains as both a grisly shocker and a psychological drama.', TO_DATE('1999-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('august osage county', 2013, 'The sheer amount of acting going on in August: Osage County threatens to overwhelm, but when the actors involved are as talented as Meryl Streep and Julia Roberts, it''s difficult to complain.', TO_DATE('2013-09-10', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('august rush', 2007, 'Though featuring a talented cast, August Rush cannot overcome the flimsy direction and schmaltzy plot.', TO_DATE('2007-10-23', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('austenland', 2013, 'Despite an intriguing premise and fine performances from a talented cast, Austenland succumbs to outworn romcom cliches and slapstick gags.', TO_DATE('2013-01-19', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('austin powers in goldmember', 2002, 'While the narrative structure is messy and doesn''t make much sense, the third installment of the Austin Powers franchise contains enough inspired bits to entertain.', TO_DATE('2002-07-22', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('austin powers international man of mystery', 1997, 'A light and goofy comedy which provides laughs, largely due to performances and screenwriting by Myers.', TO_DATE('1997-05-02', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('austin powers the spy who shagged me', 2000, 'Provides lots of laughs with Myers at the healm; as funny or funnier than the original.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('australia', 2008, 'Built on lavish vistas and impeccable production, Australia is unfortunately burdened with thinly drawn characters and a lack of originality.', TO_DATE('2008-11-17', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('author the jt leroy story', 2016, 'Author: The JT LeRoy Story serves as a worthy primer on its fascinating subject as well as an insightful look at the ever-evolving nature of modern celebrity.', TO_DATE('2016-01-25', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('auto focus', 2002, 'Kinnear and Dafoe help make this downward spiral of one man''s life a compelling watch.', TO_DATE('2002-07-20', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('autómata', 2014, 'Beautiful to look at but narratively hollow, Autómata short-circuits its handful of intriguing ideas with an overload of sci-fi clichés.', TO_DATE('2014-09-25', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('autumn in new york', 2000, 'Although the film isn''t as bad as feared (it wasn''t pre-screened for reviews), it''s not that good, either. Most noticable flaws are the sappy romantic cliches and lack of chemistry between Gere and Ryder.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('höstsonaten autumn sonata', 2001, 'A melancholy meditation on the unresolvable tension between parent and child, Autumn Sonata is a fitting swan song for the great Ingrid Bergman.', TO_DATE('2001-06-05', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('avatar', 2009, 'It might be more impressive on a technical level than as a piece of storytelling, but Avatar reaffirms James Cameron''s singular gift for imaginative, absorbing filmmaking.', TO_DATE('2009-12-10', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('avengement', 2019, 'Avengement compensates for a lack of narrative originality with thrilling sequences of violent, bone-crunching action, elevated by Scott Adkins'' brutally intense performance.', TO_DATE('2019-05-18', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('avengers age of ultron', 2015, 'Exuberant and eye-popping, Avengers: Age of Ultron serves as an overstuffed but mostly satisfying sequel, reuniting its predecessor''s unwieldy cast with a few new additions and a worthy foe.', TO_DATE('2015-04-19', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('avengers endgame', 2018, 'Exciting, entertaining, and emotionally impactful, Avengers: Endgame does whatever it takes to deliver a satisfying finale to Marvel''s epic Infinity Saga.', TO_DATE('2018-11-05', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('avengers infinity war', 2018, 'Avengers: Infinity War ably juggles a dizzying array of MCU heroes in the fight against their gravest threat yet, and the result is a thrilling, emotionally resonant blockbuster that (mostly) realizes its gargantuan ambitions.', TO_DATE('2018-04-25', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the aviator', 2004, 'With a rich sense of period detail, The Aviator succeeds thanks to typically assured direction from Martin Scorsese and a strong performance from Leonardo DiCaprio, who charts Howard Hughes'' descent from eccentric billionaire to reclusive madman.', TO_DATE('2004-07-07', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aliens vs predator requiem avp 2', 2007, 'The increased gore and violence over the first Alien vs. Predator can''t excuse Requiem''s disorientating editing, excessively murky lighting, and lack of new ideas.', TO_DATE('2007-12-24', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('await further instructions', 2018, 'A yuletide nightmare full of familial angst and slithering scares, Await Further Instructions is a genre treat that pretty much any horror fan will want in their stocking.', TO_DATE('2018-06-27', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('awake', 2007, 'Awake has an interesting premise but would have benefited from tighter performances and more efficient direction and editing.', TO_DATE('2007-11-30', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('away from her', 2006, 'An accomplished directorial debut by Sarah Polley, Away From Her is a touching exploration of the effects of Alzheimer''s, in which the tender wisdom of Polley''s script is beautifully complemented by a wonderful performance from Julie Christie.', TO_DATE('2006-09-12', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('away we go', 2009, 'Built on a set of quirks and charms that are as noticeable as they are interchangeable, Away We Go is a sweet but uneven road trip.', TO_DATE('2009-05-21', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the awful truth', 2000, 'Great comic direction by Leo McCarrey and memorable onscreen chemistry from stars Cary Grant and Irene Dunne make this screwball comedy a charmer.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('axl', 2018, 'Clumsily recalling numerous superior movies about unlikely human/robot friendships, A.X.L. is an obsolete adventure made from frequently malfunctioning parts.', TO_DATE('2018-08-23', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aziz ansari right now', 2019, 'Aziz Ansari balances sharp social commentary with just enough earnest introspection to craft a special that, while not without its baggage, shows how far the comedian has come - and how far he may still have to go.', TO_DATE('2019-07-09', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('baadasssss', 2004, 'An entertaining and intriguing tribute to a father from his son.', TO_DATE('2004-03-18', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('der baader meinhof komplex the baader meinhof complex', 2008, 'Intricately researched and impressively authentic slice of modern German History, with a terrific cast, assured direction, and a cracking script.', TO_DATE('2008-09-29', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('babe pig in the city', 2000, 'Not quite as good as the original and has some dark subject material that might not be appropriate for children.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('babel', 2006, 'In Babel, there are no villains, only victims of fate and circumstance. Director Alejandro Gonzalez Iñarritu weaves four of their woeful stories into this mature and multidimensional film.', TO_DATE('2006-05-23', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('babettes feast babettes gæstebud', 2001, 'Charming and melancholy, Babette''s Feast is a timeless Scandinavian treat that explores the complex relationships between people, beliefs, and what it means to be an artist.', TO_DATE('2001-09-24', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('baby boom', 2000, 'Baby Boom struggles to impart its feminist ideals, but Diane Keaton''s winsome leading work helps keep things breezily entertaining.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('baby boy', 2000, 'Preachy and repetitive in parts, Baby Boy still manages to exude authenticity, thanks to its competent cast.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('baby driver', 2017, 'Stylish, exciting, and fueled by a killer soundtrack, Baby Driver hits the road and it''s gone -- proving fast-paced action movies can be smartly written without sacrificing thrills.', TO_DATE('2017-03-12', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('baby geniuses', 1999, 'Flat direction and actors who look embarrassed to be onscreen make Baby Geniuses worse than the premise suggests.', TO_DATE('1999-03-12', 'YYYY-MM-DD'), 2.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('baby mama', 2008, 'Baby Mama is a lightweight, predictable comedy that ekes by on the strength of its performers.', TO_DATE('2008-04-19', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('babylon ad', 2008, 'A poorly constructed, derivative sci-fi stinker with a weak script and poor action sequences.', TO_DATE('2008-08-20', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the babysitters', 2007, 'Though built on an audacious and controversial premise, Babysitters teeters between exploitation and grossness due to uneven execution.', TO_DATE('2007-09-17', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('babyteeth', 2019, 'Powerfully acted and sensitively directed, Babyteeth offers audiences a coming-of-age story that''s messier -- and more rewarding -- than most.', TO_DATE('2019-09-04', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bachelorette', 2012, 'It has its moments, but Bachelorette ultimately plays it too safe with its trio of unlikable leads, betraying them with a predictably sentimental final act that undermines the bracingly honest humor preceding it.', TO_DATE('2012-01-24', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('back to school', 2000, 'Back to School gives Rodney Dangerfield plenty of room to riff -- and supports the freewheeling funnyman with enough of a story to keep things interesting between punchlines.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('back roads', 2018, 'Uneven yet ultimately intriguing, Back Roads serves as a memorable calling card for star and debuting director Alex Pettyfer''s talent behind the camera.', TO_DATE('2018-04-21', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('back to burgundy ce qui nous lie', 2017, 'Back to Burgundy finds its own subtle terroir in the well-trod ground of family drama -- and should prove particularly intoxicating viewing for oenophiles.', TO_DATE('2017-08-28', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('back to the future', 1985, 'Inventive, funny, and breathlessly constructed, Back to the Future is a rousing time-travel adventure with an unforgettable spirit.', TO_DATE('1985-07-03', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('back to the future part ii', 2000, 'Back to the Future II is far more uneven than its predecessor, but its madcap highs outweigh the occasionally cluttered machinations of an overstuffed plot.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('back to the future part iii', 2000, 'Back to the Future Part III draws the trilogy to a satisfying close with a simpler, sweeter round of time-travel antics.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the backup plan', 2010, 'Jennifer Lopez is as appealing as ever, but The Back-Up Plan smothers its star with unrelatable characters and a predictable plot.', TO_DATE('2010-04-08', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('backcountry', 2014, 'Tense, well-acted, and at once atmospheric as well as brutally impactful, Backcountry marks a memorably assured debut from writer-director Adam MacDonald.', TO_DATE('2014-11-04', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('backtrack', 2015, 'Adrien Brody remains a compelling presence, but those contemplating a screening of this muddled paranormal thriller are advised to Backtrack immediately.', TO_DATE('2015-11-17', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bad and the beautiful', 2000, 'Melodrama at its most confident, The Bad and the Beautiful is an ode to moviemaking that offers unblinking insight into the ugly egos that have shaped Hollywood history.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad boys for life', 2020, 'Loaded up with action and a double helping of leading-man charisma, Bad Boys for Life reinvigorates this long-dormant franchise by playing squarely to its strengths.', TO_DATE('2020-01-15', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad boys ii', 2003, 'Two and a half hours of explosions and witless banter.', TO_DATE('2003-07-14', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad company', 2002, 'Chris Rock and Anthony Hopkins fail to generate the sparks necessary to save the movie from a generic and utterly predictable script.', TO_DATE('2002-06-03', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad education', 2004, 'A layered, wonderfully-acted, and passionate drama.', TO_DATE('2004-03-12', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad education', 2019, 'Anchored by an outstanding Hugh Jackman, Bad Education finds absurd laughs -- and a worthy message -- in the aftermath of a real-life scandal.', TO_DATE('2019-09-09', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad lieutenant', 1992, 'Bad Lieutenant will challenge less desensitized viewers with its depiction of police corruption, but Harvey Keitel''s committed performance makes it hard to turn away.', TO_DATE('1992-11-20', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad lieutenant port of call new orleans', 2009, 'Befitting its unorthodox origins, this Bad Lieutenant benefits from Werner Herzog''s typically fearless direction and a delightfully unhinged Nicolas Cage in the title role.', TO_DATE('2009-09-03', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad milo', 2013, 'Bad Milo! sets some deliriously low expectations with its gross premise -- and then manages to match most of them in sick, entertaining style.', TO_DATE('2013-09-02', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad moms', 2016, 'Bad Moms boasts a terrific cast and a welcome twist on domestic comedy -- and they''re often enough to compensate for the movie''s unfortunate inability to take full advantage of its assets.', TO_DATE('2016-07-27', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad news bears', 2005, 'This too-faithful remake aims low for laughs, turning off the easily offendable; despite another lovably irascible contribution by Thornton, it lacks the ensemble strength and originality of the 1976 version.', TO_DATE('2005-07-15', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad reputation', 2018, 'Bad Reputation offers fans and novices a solidly entertaining overview of Joan Jett''s trailblazing career, albeit one that might leave some viewers craving a deeper look.', TO_DATE('2018-01-25', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad samaritan', 2018, 'Bad Samaritan delivers a handful of genre thrills -- and a stellar central performance by David Tennant -- that help offset iffy direction and a disappointingly mundane story.', TO_DATE('2018-05-02', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad santa', 2003, 'A gloriously rude and gleefully offensive black comedy, Bad Santa isn''t for everyone, but grinches will find it uproariously funny.', TO_DATE('2003-11-13', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad santa 2', 2016, 'Loaded up with the same scatological and misanthropic humor as its predecessor but precious little of its heart or genuine wit, Bad Santa 2 presents a foulmouthed shadow of Christmas past.', TO_DATE('2016-11-16', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad taste', 2000, 'Peter Jackson''s early low-budget shocker boasts a disgusting premise - aliens harvesting humans for fast food - that gives the budding auteur plenty of room for gross-out visuals and absurd cleverness.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad teacher', 2011, 'In spite of a promising concept and a charmingly brazen performance from Cameron Diaz, Bad Teacher is never as funny as it should be.', TO_DATE('2011-06-01', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad times at the el royale', 2018, 'Smart, stylish, and packed with solid performances, Bad Times at the El Royale delivers pure popcorn fun with the salty tang of social subtext.', TO_DATE('2018-09-28', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad turn worse', 2013, 'It wears its influences on its sleeve, but Bad Turn Worse still boasts more than enough pulpy thrills to justify its place at the table.', TO_DATE('2013-09-24', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bad words', 2013, 'Scabrously funny and gleefully amoral, Bad Words boasts one of Jason Bateman''s best performances -- and proves he''s a talented director in the bargain.', TO_DATE('2013-09-07', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('badlands', 2000, 'Terrence Malick''s debut is a masterful slice of American cinema, rife with the visual poetry and measured performances that would characterize his work.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('baggage claim', 2013, 'Baggage Claim hits the same notes as a number of successful romantic comedies without establishing much personality of its own.', TO_DATE('2013-09-20', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('baghead', 2008, 'Pitting actors against murderers in a self-aware struggle for stardom, Baghead successfully skates the borders of horror and comedy.', TO_DATE('2008-01-27', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bait', 2012, 'Bait isn''t entirely lacking in the shark action department, but a silly story and thinly sketched characters may leave audiences bored between bloody attacks.', TO_DATE('2012-09-13', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last circus', 2011, 'The Last Circus is an uneven but winningly insane blend of hard violence, sex, black humor, and social satire.', TO_DATE('2011-04-22', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ball of fire', 2000, 'A splendidly funny twist on the story of Snow White, Ball of Fire boasts a pair of perfect leads in Gary Cooper and Barbara Stanwyck.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ballad of jack and rose', 2005, 'Heavy on the symbolism and overly contrived.', TO_DATE('2005-02-04', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ballet 422', 2014, 'Ballet 422 offers a transfixing, intimate look at professional dance that should satisfy fans of the form as well as curious neophytes.', TO_DATE('2014-05-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ballistic ecks vs sever', 2002, 'A startlingly inept film, Ballistic: Ecks vs. Sever offers overblown, wall-to-wall action without a hint of wit, coherence, style, or originality.', TO_DATE('2002-09-16', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ballplayer pelotero', 2012, 'Gripping and surprisingly nuanced, Ballplayer: Pelotero is a frank exploration of the nature of corruption in baseball recruitment.', TO_DATE('2012-06-26', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('balls of fury', 2007, 'Tasteless, yet harmless, Balls of Fury nevertheless fails to generate enough laughs despite its lowbrow intentions.', TO_DATE('2007-08-23', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('au hasard balthazar', 2003, 'Au Hasard Balthazar uses one animal''s lifelong journey to trace a soberly compelling -- and ultimately heartbreaking -- outline of the human experience.', TO_DATE('2003-04-25', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('balto', 2000, 'Balto is a well-meaning adventure with spirited animation, but mushy sentimentality and bland characterization keeps it at paw''s length from more sophisticated family fare.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('balzac and the little chinese seamstress', 2002, 'This delicately told fable about the power of literature is a lyrical delight.', TO_DATE('2002-10-31', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bambi', 2000, 'Elegantly animated and deeply touching, Bambi is an enduring, endearing, and moving Disney classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('banana split', 2018, 'Banana Split serves up a sweet comedic dish that serves as a delightful calling card for co-writer and star Hannah Marks.', TO_DATE('2018-10-02', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('band aid', 2017, 'Band Aid tells a solidly affecting story of a relationship on the rocks -- and marks star Zoe Lister-Jones, who also wrote and directed, as a tremendous triple threat worth watching.', TO_DATE('2017-01-24', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bandits', 2001, 'The story may not warrant its lengthy running time, but the cast of Bandits makes it an enjoyable ride.', TO_DATE('2001-09-25', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bandslam', 2009, 'Bandslam is an intelligent teen film that avoids teen film cliches, in an entertaining package of music and coming-of-age drama.', TO_DATE('2009-08-08', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the banger sisters', 2002, 'Hawn and Sarandon are terrific together, but the hoary plot is predictable and contrived.', TO_DATE('2002-08-17', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bangkok dangerous', 2008, 'With murky cinematography, a meandering pace, a dull storyline, and rather wooden performances, The Pang Brothers'' Hollywood remake of Bangkok Dangerous is unsuccessful.', TO_DATE('2008-08-22', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('baran', 2001, 'The lyrical Baran is a moving film, both for its love story and political underpinnings.', TO_DATE('2001-09-26', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('barb wire', 2000, 'Barb Wire could''ve been fun camp, but Pamela Anderson can''t deliver her lines with any dramatic or comedic impact.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('barbara', 2012, 'Smart, solidly grafted, and thoroughly gripping, Barbara offers a deliberately paced, subtly powerful character study.', TO_DATE('2012-09-18', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('barbarella', 2000, 'Unevenly paced and thoroughly cheesy, Barbarella is nonetheless full of humor, entertaining visuals, and Jane Fonda''s sex appeal.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the barbarian invasions les invasions barbares', 2003, 'A moving and heart-felt film from director Denys Arcand.', TO_DATE('2003-05-21', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('barbershop', 2002, 'Besides bringing on the laughs, Barbershop displays a big heart and demonstrates the value of community.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('barbershop 2 back in business', 2004, 'The humor is less sharp and more warm-hearted this time around, and the characters are enjoyable to revisit.', TO_DATE('2004-02-03', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('barbershop the next cut', 2016, 'Heartfelt, thought-provoking, and above all funny, Barbershop: The Next Cut is the rare belated sequel that more than lives up to the standard set by its predecessors.', TO_DATE('2016-04-12', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('barefoot in the park', 1967, 'Barefoot in the Park may strike some modern viewers as dated, but what it lacks in timeliness, it more than makes up with the effervescent chemistry between its stars.', TO_DATE('1967-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('barneys version', 2010, 'With a magnificent performance by Paul Giamatti, Barney''s Version offers much comedy and insight to the complexities of modern romance.', TO_DATE('2010-09-13', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('barneys great adventure', 1800, 'Barney''s friends are big and small / They come from lots of places / But after this film, their parents / Will be left with pained faces.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('barnyard', 2006, 'Unimaginative and unfunny, this tale of barnyard mischief borders on ''udder'' creepiness and adds little to this summer''s repertoire of animated films.', TO_DATE('2006-08-02', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('barry', 2016, 'Barry opens a speculative window into a future president''s formative college years, offering a flawed yet compelling glimpse of American history in the making.', TO_DATE('2016-09-11', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('barry lyndon', 2000, 'Cynical, ironic, and suffused with seductive natural lighting, Barry Lyndon is a complex character piece of a hapless man doomed by Georgian society.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bart got a room', 2008, 'Just enough sweetness and good performances lighten up the high school-set tensions, creating a family-appropriate teen comedy.', TO_DATE('2008-04-27', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bartleby', 2001, 'Bartleby is a rather dull affair, stretched over a too-long running time.', TO_DATE('2001-03-27', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('barton fink', 1991, 'Twisty and unsettling, the Coen brothers'' satirical tale of a 1940s playwright struggling with writer''s block is packed with their trademark sense of humor and terrific performances from its cast.', TO_DATE('1991-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('baseketball', 2000, 'Baseketball isn''t just a succession of fouls thanks to the comedic zip of David Zucker''s direction, but sophomoric gags and a lack of performance hustle by Trey Parker and Matt Stone makes this satire a clumsy bunt.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('basic', 2003, 'Basic gets so needlessly convoluted in its plot twists that the viewer eventually loses interest.', TO_DATE('2003-03-23', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('basic instinct', 1992, 'Unevenly echoing the work of Alfred Hitchcock, Basic Instinct contains a star-making performance from Sharon Stone but is ultimately undone by its problematic, overly lurid plot.', TO_DATE('1992-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('basic instinct 2', 2006, 'Unable to match the suspense and titilation of its predecessor, Basic Instinct 2 boasts a plot so ludicrous and predictable it borders on "so-bad-it''s-good."', TO_DATE('2006-02-28', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('basket case', 2002, 'While Basket Case definitely delivers all the gonzo gore promised by its cracked premise, it''s really set apart by its rich vein of genuine pathos.', TO_DATE('2002-10-13', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('baskin', 2015, 'Baskin complements its gory thrills with heavy atmosphere and deliberate pacing, adding up to a horror outing that plays with the mind as enthusiastically as it ruins the appetite.', TO_DATE('2015-09-17', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('basmati blues', 2018, 'Like the genetically modified grain at the center of its story, Basmati Blues is probably best locked in storage and saved for cases of cinematic famine.', TO_DATE('2018-02-04', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bathtubs over broadway', 2018, 'Bathtubs Over Broadway pulls back the curtains on a delightfully entertaining -- and surprisingly affecting -- glimpse into a largely forgotten corner of pop culture.', TO_DATE('2018-08-28', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('batkid begins', 2015, 'Sweet and unabashedly sentimental, Batkid Begins is an uplifting look at a selfless act that brought a city together.', TO_DATE('2015-05-04', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('batman begins', 2005, 'Brooding and dark, but also exciting and smart, Batman Begins is a film that understands the essence of one of the definitive superheroes.', TO_DATE('2005-06-03', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('batman beyond return of the joker', 2001, 'This feature length entry in the Batman Beyond mythos sends off the Mark Hamill-voiced Joker in thrilling fashion, hitting the same caped crusading peaks of the original series.', TO_DATE('2001-07-24', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('batman forever', 2000, 'Loud, excessively busy, and often boring, Batman Forever nonetheless has the charisma of Jim Carrey and Tommy Lee Jones to offer mild relief.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('batman mask of the phantasm', 2000, 'Stylish and admirably respectful of the source material, Batman: Mask of the Phantasm succeeds where many of the live-action Batman adaptations have failed.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('batman return of the caped crusaders', 2016, 'Adam West''s groovy interpretation of the The Caped Crusader returns in a new medium, popping in the realm of animation with the irascible energy of an exclamation-accented onomatopoeia.', TO_DATE('2016-10-10', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('batman returns', 2000, 'Director Tim Burton''s dark, brooding atmosphere, Michael Keaton''s work as the tormented hero, and the flawless casting of Danny DeVito as The Penguin and Christopher Walken as, well, Christopher Walken make the sequel better than the first.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('batman the killing joke', 2016, 'This stilted retelling of the Joker''s origin adds little to its iconic source material, further diminished by some questionable story additions that will have fans demanding justice for Barbara Gordon.', TO_DATE('2016-07-23', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('batman the movie', 1966, 'Batman: The Movie elevates camp to an art form -- and has a blast doing it, every gloriously tongue-in-cheek inch of the way.', TO_DATE('1966-07-30', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('batman v superman dawn of justice', 2016, 'Batman v Superman: Dawn of Justice smothers a potentially powerful story -- and some of America''s most iconic superheroes -- in a grim whirlwind of effects-driven action.', TO_DATE('2016-03-22', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bats', 1999, 'Neither scary nor creepy.', TO_DATE('1999-10-22', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('battle los angeles', 2011, 'Overlong and overly burdened with war movie clichés, Battle: Los Angeles will entertain only the most ardent action junkies.', TO_DATE('2011-03-08', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('battle for haditha', 2007, 'This narrative retelling of the real life tragedy in Haditha is gripping and immediate but may sacrifice the subtleties of history for dramatic impact.', TO_DATE('2007-09-11', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('battle for terra', 2008, 'Despite its earnest aspirations to be a thought-provoking sci-fi alternative, Battle for Terra lacks both a cohesive story and polished visuals, and fails to resonate.', TO_DATE('2008-05-07', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('battle for the planet of the apes', 2000, 'Bereft of bright ideas and visually shabby, Battle for the Planet of the Apes takes a celebrated franchise and blows it all up -- the maniacs!', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('battle in seattle', 2007, 'Well intentioned and passionate, this docu-drama about the 1999 WTO protests is heavier on politics than character development.', TO_DATE('2007-09-11', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the battle of shaker heights', 2003, 'LaBeouf is appealing, but The Battle of Shaker Heights feels too watered down and disjointed.', TO_DATE('2003-08-15', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('battle of the sexes', 2017, 'Battle of the Sexes turns real-life events into a crowd-pleasing, well-acted dramedy that ably entertains while smartly serving up a volley of present-day parallels.', TO_DATE('2017-09-03', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('battle of the year', 2013, 'With a hopelessly hokey plot and unintentionally hilarious dialogue, Battle of the Year is flimsy even by the standards of the dance movie genre.', TO_DATE('2013-09-18', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('battle royale', 2001, 'Battle Royale is a controversial and violent parable of adolescence, heightening teenage melodrama with life-or-death stakes.', TO_DATE('2001-06-25', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('battlefield earth', 2000, 'Ugly, campy, and poorly acted, Battlefield Earth is a stunningly misguided, aggressively bad sci-fi folly.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('battleship', 2012, 'It may offer energetic escapism for less demanding filmgoers, but Battleship is too loud, poorly written, and formulaic to justify its expense -- and a lot less fun than its source material.', TO_DATE('2012-02-08', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('battleship potemkin', 2000, 'A technical masterpiece, Battleship Potemkin is Soviet cinema at its finest, and its montage editing techniques remain influential to this day.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('baywatch', 2017, 'Baywatch takes its source material''s jiggle factor to R-rated levels, but lacks the original''s campy charm -- and leaves its charming stars flailing in the shallows.', TO_DATE('2017-05-22', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('be cool', 2005, 'Be Cool is tepid, square, and lukewarm; as a parody of the music business, it has two left feet.', TO_DATE('2005-02-26', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('be kind rewind', 2008, 'Slighter and less disciplined than Gondry''s previous mind-benders.', TO_DATE('2008-01-18', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('be natural the untold story of alice guyblaché', 2018, 'Be Natural: The Untold Story of Alice Guy-Blaché aims an overdue spotlight on a cinematic innovator''s career, with the added benefit of absorbing historical context.', TO_DATE('2018-05-14', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the beach', 2000, 'Critics say The Beach is unfocused and muddled, a shallow adaptation of the novel it is based on. Points go to the gorgeous cinematography, though.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beach rats', 2017, 'Empathetic and powerfully acted, Beach Rats takes a clear-eyed yet dreamlike look at a young man''s adolescent turmoil.', TO_DATE('2017-01-23', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bean', 1997, 'Bean boasts a terrifically talented physical comedian in the title role, but his constant mugging and silly slapstick quickly wear thin.', TO_DATE('1997-10-17', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beanpole dylda', 2019, 'Filmed with impressive skill and brought to life by unforgettable performances, Beanpole takes a heartbreakingly empathetic look at lives shattered by war.', TO_DATE('2019-05-16', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beastly', 2011, 'Fundamentally misguided, poorly written, and badly acted, Beastly adds little to the legacy of its timeless source material.', TO_DATE('2011-03-02', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beasts of the southern wild', 2012, 'Beasts of the Southern Wild is a fantastical, emotionally powerful journey and a strong case of filmmaking that values imagination over money.', TO_DATE('2012-01-21', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('de battre mon coeur sest arrêté the beat that my heart skipped', 2005, 'Stylish and visceral, this able remake is infused with realism, grit, and a taut performance by star Romain Duris.', TO_DATE('2005-04-08', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a hard days night', 2000, 'A Hard Day''s Night, despite its age, is still a delight to watch and has proven itself to be a rock-and-roll movie classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('help', 2002, 'Help! finds the Fab Four displaying their infectious charm and humor in an enjoyably madcap adventure.', TO_DATE('2002-07-29', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('yellow submarine', 2000, 'A joyful, phantasmagoric blend of colorful animation and the music of the Beatles, Yellow Submarine is delightful (and occasionally melancholy) family fare.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beats', 2019, 'Beats is an entertaining - if all too familiar - coming-of-age story that is elevated by Anthony Anderson''s excellent performance.', TO_DATE('2019-06-17', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beats rhymes life the travels of a tribe called quest', 2011, 'This documentary focuses less on the music and more on the personality clashes and in-group tensions to great, compelling effect.', TO_DATE('2011-01-25', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beautiful boxer', 2005, 'Beautiful Boxer blends boxing and identity politics to create a striking, if overdrawn, portrait of self discovery.', TO_DATE('2005-01-15', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the beautiful country', 2004, 'The plight of Asian refugees is sensitively rendered, and the movie builds, with the help of Nolte, to a wrenchingly poignant conclusion.', TO_DATE('2004-03-18', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beautiful creatures', 2001, 'Implausible, uneven, and gratuitously violent, this esotrogen-powered crime caper lacks the finesse of Thelma and Louise or Guy Ritchie''s work.', TO_DATE('2001-02-23', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beautiful creatures', 2013, 'Charming romantic leads and esteemed supporting cast aside, Beautiful Creatures is a plodding YA novel adaptation that feels watered down for the Twilight set.', TO_DATE('2013-02-10', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beautiful girls', 1996, 'A warm, thoughtful dramedy about male insecurity, Beautiful Girls is buoyed by an excellent cast - particularly Natalie Portman in a stunning early role.', TO_DATE('1996-02-09', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beautiful losers', 2008, 'An insightful if fawning documentary that explores a group of 90s NYC artists.', TO_DATE('2008-05-12', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a beautiful mind', 2001, 'The well-acted A Beautiful Mind is both a moving love story and a revealing look at mental illness.', TO_DATE('2001-11-07', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beautiful thing', 1996, 'An engaging slice of life drama that happens to double as a gay coming-of-age story, Beautiful Thing captures its place and time with deceptive depth and skill.', TO_DATE('1996-10-11', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beauty and the beast', 1991, 'Enchanting, sweepingly romantic, and featuring plenty of wonderful musical numbers, Beauty and the Beast is one of Disney''s most elegant animated offerings.', TO_DATE('1991-11-22', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beauty and the beast', 2017, 'With an enchanting cast, beautifully crafted songs, and a painterly eye for detail, Beauty and the Beast offers a faithful yet fresh retelling that honors its beloved source material.', TO_DATE('2017-03-03', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beavis and butthead do america', 1996, 'Beavis and Butt-Head Do America is unabashedly offensive, unapologetically stupid, and unexpectedly funny.', TO_DATE('1996-12-20', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('because i said so', 2007, 'Overly reliant on caricatures and lacking any human insight, Because I Said So is an unfunny, cliche-ridden mess.', TO_DATE('2007-01-14', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('because of winndixie', 2005, 'An old-fashioned, if bland, adaptation of Kate DiCamillo''s novel.', TO_DATE('2005-02-03', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('becky', 2020, 'Becky isn''t quite able to sustain enough intensity to fully take advantage of its premise, though it serves up entertainingly nasty thrills for genre fans.', TO_DATE('2020-05-26', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('becoming', 2020, 'It may not get as personal as some viewers might have hoped, but Becoming offers an uplifting look at a pivotal moment in its subject''s public life.', TO_DATE('2020-05-04', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('becoming astrid unga astrid', 2018, 'Becoming Astrid pays tribute to a beloved character''s creator with a biopic that proves the story behind the scenes is just as timelessly engaging.', TO_DATE('2018-02-21', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('becoming jane', 2007, 'Although Becoming Jane is a well-crafted period piece, it lacks fresh insight into the life and works of Jane Austen. The film focuses too much on wardrobe and not enough on Austen''s achievements.', TO_DATE('2007-03-03', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bedknobs and broomsticks', 2002, 'Bedknobs and Broomsticks often feels like a pale imitation of a certain magical guardian and her wards, but a spoonful of Angela Lansbury''s witty star power helps the derivativeness go down.', TO_DATE('2002-06-23', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bedtime stories', 2008, 'Though it may earns some chuckles from pre-teens, this kid-friendly Adam Sandler comedy is uneven, poorly paced, and lacks the requisite whimsy to truly work.', TO_DATE('2008-12-19', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bee movie', 2007, 'Bee Movie has humorous moments, but its awkward premise and tame delivery render it mostly forgettable.', TO_DATE('2007-10-29', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bee season', 2005, 'Bee Season is an intelligent, but frustratingly distant and diffuse drama about family dysfunction.', TO_DATE('2005-09-06', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('been rich all my life', 2006, 'The remarkable resilience, energy, strength, and charisma of these women captivate, and their experiences are a historical treasure.', TO_DATE('2006-06-08', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beerfest', 2006, 'Beerfest features some laugh-inducing gags, but is too long and the pacing too uneven to form a coherent, functioning comedy.', TO_DATE('2006-08-15', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beeswax', 2009, 'Andrew Bujalski''s third effort will test the patience of some filmgoers, but it represents a warm, funny, and honest introduction to the mumblecore movement.', TO_DATE('2009-07-24', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beetle queen conquers tokyo', 2009, 'Offbeat and wondrously shot, Beetle Queen Conquers Tokyo makes persuasive macro observations about Japanese culture through a microcosmic study of insects.', TO_DATE('2009-06-11', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beetlejuice', 2000, 'Brilliantly bizarre and overflowing with ideas, Beetlejuice offers some of Michael Keaton''s most deliciously manic work - and creepy, funny fun for the whole family.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('before i fall', 2017, 'Before I Fall''s familiar ingredients are enlivened by a fresh YA perspective and a strong performance from emerging star Zoey Deutch.', TO_DATE('2017-01-21', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('before i go to sleep', 2014, 'If it doesn''t completely avoid thriller clichés, Before I Go to Sleep still offers a stylish, fast-paced, and well-acted diversion.', TO_DATE('2014-08-21', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('before midnight', 2013, 'Building on the first two installments in Richard Linklater''s well-crafted Before trilogy, Before Midnight offers intelligent, powerfully acted perspectives on love, marriage, and long-term commitment.', TO_DATE('2013-01-21', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('before night falls', 2000, 'An impressionistic, fragmented look at Reinaldo Arenas, Before Night Falls'' imagery manages to evoke a sense of the writer''s artistry, and Bardem''s strong performance holds the film together. Finally, a biopic done well.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('before sunrise', 1995, 'Thought-provoking and beautifully filmed, Before Sunrise is an intelligent, unabashedly romantic look at modern love, led by marvelously natural performances from Ethan Hawke and Julie Delpy.', TO_DATE('1995-01-27', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('before sunset', 2004, 'Filled with engaging dialogue, Before Sunset is a witty, poignant romance, with natural chemistry between Hawke and Delpy.', TO_DATE('2004-03-16', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('before the devil knows youre dead', 2007, 'A tense and effective thriller, Before the Devil Knows You''re Dead marks a triumphant return to form for director Sidney Lumet.', TO_DATE('2007-09-04', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('before we go', 2014, 'Chris Evans'' directorial debut is modest to a fault, with a threadbare story and minimal style leaving his and Alice Eve''s likable performances adrift in New York City with nowhere to go.', TO_DATE('2014-09-14', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('begin again', 2013, 'Writer-director John Carney''s return to musical drama isn''t quite as potent as it was with Once, but thanks to charming work from its well-matched leads, Begin Again is difficult to resist.', TO_DATE('2013-09-08', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beginners', 2010, 'Wearing its twee heart on its sleeve, Beginners explores the depths of modern, multi-generational romance with wit and depth.', TO_DATE('2010-09-13', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('behind the candelabra', 2013, 'Affectionate without sacrificing honesty, Behind the Candelabra couples award-worthy performances from Michael Douglas and Matt Damon with some typically sharp direction from Steven Soderbergh.', TO_DATE('2013-05-15', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('behind the mask the rise of leslie vernon', 2006, 'A smart mockumentary that presents a gory, funny, and obviously affectionate skewering of the slasher genre.', TO_DATE('2006-03-13', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('being 17 quand on a 17 ans', 2016, 'Being 17 rides the roiling emotions of adolescence through a coming-of-age melodrama whose narrative turbulence smartly reflects the confusion of its protagonists.', TO_DATE('2016-07-18', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('being evel', 2015, 'Insightful and swiftly paced, Being Evel is an entertaining, well-crafted overview of an unforgettable character.', TO_DATE('2015-01-26', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('being flynn', 2012, 'Robert De Niro gives a sincere, gripping performance, but Being Flynn is an uneasy mix of drama and comedy that fails to emotionally resonate as a whole.', TO_DATE('2012-02-20', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('being frank', 2018, 'Being Frank suggests Jim Gaffigan may have a real future as a dramatic actor -- if only he''s offered projects that don''t suffer from so much wasted potential.', TO_DATE('2018-03-12', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('being john malkovich', 1999, 'Smart, funny, and highly original, Being John Malkovich supports its wild premise with skillful direction and a stellar ensemble cast.', TO_DATE('1999-10-29', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('being julia', 2004, 'Annette Bening delivers a captivating performance in Being Julia, a sophisticated comedy that follows a 1930s stage diva who experiences an identity crisis at age 40.', TO_DATE('2004-09-09', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('being there', 1979, 'Smart, sophisticated, and refreshingly subtle, Being There soars behind sensitive direction from Hal Ashby and a stellar Peter Sellers performance.', TO_DATE('1979-12-19', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beirut', 2018, 'Beirut tells a complex, tightly plotted tale of international intrigue, further elevated by strong central performances from Jon Hamm and Rosamund Pike.', TO_DATE('2018-01-23', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bel ami', 2012, 'Bel Ami contains some soapy pleasures but it overall rushes through the narrative and suffers from a vague central performance by Robert Pattinson.', TO_DATE('2012-02-18', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bella beauty', 2006, 'Critics labeled Bella as a simplistic and mostly pedestrian, but positive word of mouth gave this tiny indie surprising theatrical legs.', TO_DATE('2006-09-10', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('belle', 2013, 'It boasts all the surface beauty that fans of period pictures have come to expect, but Belle also benefits from its stirring performances and subtle social consciousness.', TO_DATE('2013-09-11', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bellflower', 2011, 'This fevered, stylish vision of the end of the world stitches multiple genres together and marks writer/director/star Evan Glodell as a true talent to watch.', TO_DATE('2011-02-04', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beloved sisters', 2014, 'Smart, vivid, and powerfully acted, Beloved Sisters injects new life into its pretty period tropes and soapy plotting.', TO_DATE('2014-09-15', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('below', 2002, 'Below is a creepy, claustrophobic exercise in style.', TO_DATE('2002-10-04', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('benhur', 2016, 'How do you fight an idea? By filming a remake that has too few of its own, and tries to cover it up with choppy editing and CGI.', TO_DATE('2016-08-17', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ben is back', 2018, 'Refreshingly understated, Ben Is Back subverts family drama stereotypes - and provides a forum for terrific performances from Lucas Hedges and Julia Roberts.', TO_DATE('2018-09-09', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the benchwarmers', 2006, 'A gross-out comedy that is more sophomoric than funny, The Benchwarmers goes down swinging.', TO_DATE('2006-04-06', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bend it like beckham', 2002, 'Inspiring, compassionate, and with a sly undercurrent of social commentary, Bend It Like Beckham is a lively feel-good movie that genuinely charms.', TO_DATE('2002-04-18', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beneath the planet of the apes', 2000, 'Beneath the Planet of the Apes delivers more action than its predecessor -- unfortunately, at the expense of the social subtext that elevates the franchise''s best entries.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('benhur', 2000, 'Uneven, but in terms of epic scope and grand spectacle, Ben-Hur still ranks among Hollywood''s finest examples of pure entertainment.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('benjamin', 2018, 'Inspired by first-time feature filmmaker Simon Amstell''s own experiences, Benjamin is a heartfelt ode to the search for human connection.', TO_DATE('2018-10-26', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('benji off the leash', 2004, 'Benji: Off the Leash! features an adorable dog and a solid message about how to treat animals, but is too dull and amateurish a viewing experience to recommend for all but the youngest viewers.', TO_DATE('2004-08-03', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beowulf', 2007, 'Featuring groundbreaking animation, stunning visuals, and a talented cast, Beowulf has in spades what more faithful book adaptations forget to bring: pure cinematic entertainment.', TO_DATE('2007-08-04', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('berberian sound studio', 2012, 'Its reach may exceed its grasp, but with Berberian Sound Studio, director Peter Strickland assembles a suitably twisted, creepy tribute to the Italian Giallo horror movies of the ''70s that benefits from a strong central performance by Toby Jones.', TO_DATE('2012-06-28', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('berlin syndrome', 2017, 'Berlin Syndrome offers thriller fans an uncommonly well-written descent into dangerous obsession, enlivened by taut direction and a committed performance from Teresa Palmer.', TO_DATE('2017-01-21', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bernie', 2011, 'Richard Linklater''s Bernie is a gently told and unexpectedly amusing true-crime comedy that benefits from an impressive performance by Jack Black.', TO_DATE('2011-06-17', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bessie', 2015, 'Strong performances, led by Queen Latifah, overpower a middling script in the entertaining and informative Bessie.', TO_DATE('2015-05-09', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('best in show', 2000, 'A fine example of writer-director-star Christopher Guest''s gift for improv comedy, Best in Show boasts an appealingly quirky premise and a brilliantly talented cast.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('best of enemies', 2015, 'Smart, fascinating, and funny, Best of Enemies takes a penetrating -- and wildly entertaining -- look back at the dawn of pundit politics.', TO_DATE('2015-01-23', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('best worst movie', 2009, 'Good-natured and mirthful, Best Worst Movie is a sweet deconstruction of how a cinematic folly can become a triumph.', TO_DATE('2009-07-30', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the best years of our lives', 2000, 'An engrossing look at the triumphs and travails of war veterans, The Best Years of Our Lives is concerned specifically with the aftermath of World War II, but its messages speak to the overall American experience.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bethlehem', 2013, 'Balancing complex Middle Eastern politics against a universal human drama, director Yuval Adler fashions Bethlehem into a thought-provoking, well-acted character study.', TO_DATE('2013-09-13', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('better living through chemistry', 2014, 'Better Living Through Chemistry proves suburban satire and a talented cast can be mixed together to produce a disappointingly tepid blend.', TO_DATE('2014-03-09', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('better luck tomorrow', 2002, 'A promising work by Lin, the energetic Better Luck Tomorrow is disturbing and thought-provoking.', TO_DATE('2002-02-13', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('better watch out', 2016, 'Carried by its charismatic young cast, Better Watch Out is an adorably sinister holiday horror film.', TO_DATE('2016-09-27', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('between two ferns the movie', 2019, 'Between Two Ferns: The Movie shows the strain of stretching a series of web shorts to feature length, but should still satisfy fans of the source material.', TO_DATE('2019-09-20', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('between worlds', 2018, 'While definitely in line with some of Nicolas Cage''s stranger efforts, Between Worlds is too silly and messy to call it good, even in a weird way.', TO_DATE('2018-09-23', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beverly hills cop', 2000, 'The buddy cop movie continues its evolution unabated with this Eddie Murphy vehicle that''s fast, furious, and funny.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beverly hills cop ii', 2000, 'Eddie Murphy remains appealing as the wisecracking Axel Foley, but Beverly Hills Cop II doesn''t take him -- or the viewer -- anywhere new enough to justify a sequel.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beverly hills cop iii', 2000, 'Despite being set at an amusement park, Beverly Hills Cop III forgets to have any fun as it churns out uninspired violence and witless gags, with an uncharacteristically lethargic Eddie Murphy not helping matters.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beverly hills ninja', 1997, 'Far from silent but comedically deadly, Beverly Hills Ninja proves painfully unfunny.', TO_DATE('1997-01-17', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beware of mr baker', 2012, 'Free of the hagiographic overtones that dog many documentary profiles, Beware of Mr. Baker presents a clear-eyed, thoroughly gripping look at one of rock''s greatest -- and most personally problematic -- musicians.', TO_DATE('2012-03-16', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bewitched', 2005, 'Bewitched is haunted by scattered laughs and a lack of direction.', TO_DATE('2005-06-15', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beyond borders', 2003, 'Beyond Borders is good-intentioned, but the use of human suffering as a backdrop for a romance comes across as sanctimonious and exploitative.', TO_DATE('2003-10-16', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beyond the gates', 2005, 'Complex, human characters and on-location shooting give Beyond the Gates palpable tension and urgency.', TO_DATE('2005-09-18', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beyond the hills', 2012, 'Although some viewers may mistake its deliberate pace for passionless filmmaking, Beyond the Hills offers an intelligent, powerfully acted examination of the tension between secular life and religious faith.', TO_DATE('2012-05-19', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beyond the lights', 2014, 'Thanks to smart direction and a powerhouse performance from Gugu Mbatha-Raw, Beyond the Lights transcends its formulaic storyline to deliver thoroughly entertaining drama.', TO_DATE('2014-09-08', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beyond the mat', 2000, 'Even if you aren''t a fan, Beyond the Mat provides a riveting, perceptive look into the world of professional wrestling by taking a closer look at the people beneath the personas.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beyond the reach', 2014, 'Beyond the Reach promises goofy genre pleasures, but fails to deliver, losing the viewer -- and a villainous turn from Michael Douglas -- in a misguided story that stumbles to the finish.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beyond the sea', 2004, 'Kevin Spacey''s bio of singer Bobby Darin is either a fearless piece of showmanship or an embarrassing vanity project, according to critics.', TO_DATE('2004-09-13', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beyond the valley of the dolls', 2000, 'Confidently campy and played with groovy conviction, Beyond the Valley of the Dolls is an exuberant expression of both the hilarity and terror that comes with free love.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('beyond the visible hilma af klint', 2020, 'An illuminating feast for the eyes, Beyond the Visible - Hilma af Klint makes a persuasive case for its subject''s spot in the firmament of modern art.', TO_DATE('2020-03-12', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bicentennial man', 1999, 'Bicentennial Man is ruined by a bad script and ends up being dull and mawkish.', TO_DATE('1999-12-17', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bicycle thieves ladri di biciclette the bicycle thief', 2000, 'An Italian neorealism exemplar, Bicycle Thieves thrives on its non-flashy performances and searing emotion.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big', 1988, 'Refreshingly sweet and undeniably funny, Big is a showcase for Tom Hanks, who dives into his role and infuses it with charm and surprising poignancy.', TO_DATE('1988-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big ass spider', 2013, 'Big Ass Spider! delivers on the promise of its outlandish title with a tongue-in-cheek creature feature that embraces its B-movie silliness with utterly entertaining results.', TO_DATE('2013-03-18', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big bad love', 2001, 'A boozy depiction of a struggling writer, Big Bad Love is too messy and self-indulgent.', TO_DATE('2001-11-07', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big bad wolves', 2013, 'With just enough black humor to lighten the disturbing subject matter, Big Bad Wolves is as rewarding as it is challenging.', TO_DATE('2013-04-23', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the big bounce', 2004, 'Lazily crafted and light on substance, The Big Bounce takes few chances and strands its promising cast in a subpar adaptation that fails to do its source material justice.', TO_DATE('2004-01-26', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the big chill', 2000, 'The Big Chill captures a generation''s growing ennui with a terrific cast, a handful of perceptive insights, and one of the decade''s best film soundtracks.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big daddy', 2000, 'Adam Sandler acquits himself admirably, but his charm isn''t enough to make up for Big Daddy''s jarring shifts between crude humor and mawkish sentimentality.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the big easy', 2000, 'Loaded with atmosphere and drenched in the sizzling chemistry between Dennis Quaid and Ellen Barkin, The Big Easy remains one of the strongest -- and steamiest -- thrillers of the 1980s.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big eden', 2001, 'Though unrealistic, Big Eden has all the charm and sweetness of a fairy tale.', TO_DATE('2001-05-29', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big eyes', 2014, 'Well-acted, thought-provoking, and a refreshing change of pace for Tim Burton, Big Eyes works both as a biopic and as a timelessly relevant piece of social commentary.', TO_DATE('2014-11-14', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big fat liar', 2002, 'Though there''s nothing that offensive about Big Fat Liar, it is filled with Hollywood cliches and cartoonish slapstick, making it strictly for kids.', TO_DATE('2002-02-04', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big game', 2014, 'Big Game''s enthusiastic throwback vibe will appeal to fans of low-budget ''80s action movies, but co-writer/director Jalmari Helander adds a level of smarts and skill that make it more than just an homage.', TO_DATE('2014-09-06', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big hero 6', 2014, 'Agreeably entertaining and brilliantly animated, Big Hero 6 is briskly-paced, action-packed, and often touching.', TO_DATE('2014-10-23', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the big hit', 1998, 'The Big Hit seeks to blend the best of Hong Kong and American action cinema, but ends up offering a muddled mush that mostly misses.', TO_DATE('1998-04-24', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big miracle', 2012, 'Big Miracle uses real-life events as the basis for a surprisingly satisfying family drama.', TO_DATE('2012-01-31', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big mommas house', 2000, 'Big Momma''s House is funny in some parts, but it is essentially a one-joke movie.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big mommas like father like son', 2011, 'Unnecessary, unfunny, and generally unwelcome, Big Mommas: Like Father, Like Son offers more of the same for fans of Martin Lawrence''s perplexingly popular series.', TO_DATE('2011-02-14', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big night', 1996, 'The performances in Big Night are wonderful, and the food looks delicious.', TO_DATE('1996-09-20', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the big picture', 2000, 'The Big Picture aims at targets that might not be familiar to viewers who aren''t well-versed in movie-biz chicanery, but hits most of them so solidly that laughter is the only option.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the big red one', 2000, 'The reconstruction of Samuel Fuller''s epic account of his days in North Africa in World War II elevates the film into the pantheon of great war movies.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big star nothing can hurt me', 2012, 'Big Star: Nothing Can Hurt Me offers a persuasive argument for its subjects'' cult classic oeuvre -- and presents a painfully passionate lament for their untapped potential.', TO_DATE('2012-11-16', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the big tease', 2000, 'The Big Tease may be predictable, but the buoyant performances keep you laughing once you give in to the silliness.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big top peewee', 2000, 'Its endearingly oddball lead character gives it his all, but Big Top Pee-Wee simply lacks the whimsical magic of its predecessor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('big trouble in little china', 1986, 'Brimming with energy and packed with humor, Big Trouble in Little China distills kung fu B-movies as affectionately as it subverts them.', TO_DATE('1986-07-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bigger stronger faster', 2008, 'Bigger, Stronger, Faster* is a fascinating, informative, entertaining and especially introspective account of the American ''enhancement'' culture.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('biggie and tupac', 2002, 'This is a compelling documentary, even for those who aren''t fans of rap.', TO_DATE('2002-06-12', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('biker boyz', 2003, 'Waste of a good cast. For a movie about bike racing, it never gets up to speed.', TO_DATE('2003-01-27', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bikram yogi guru predator', 2019, 'By exposing the corrupt systems which enabled him, Bikram: Yogi, Guru, Predator paints a disturbing -- and necessary -- portrait of the cycles of abuse endured by countless followers of the charlatan at its center.', TO_DATE('2019-09-10', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bill ted face the music', 2020, 'As wholesomely goofy as its heroes, Bill and Ted Face the Music is a rare long-belated sequel that largely recaptures the franchise''s original charm.', TO_DATE('2020-08-27', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bill teds bogus journey', 1991, 'Bill and Ted''s Bogus Journey has the same stars -- and cheerfully wacky sense of humor -- as its predecessor, but they prove a far less effective combination the second time around.', TO_DATE('1991-07-19', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bill and teds excellent adventure', 1989, 'Keanu Reeves and Alex Winter are just charming, goofy, and silly enough to make this fluffy time-travel Adventure work.', TO_DATE('1989-02-17', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bill cunningham new york', 2011, 'Suffused with happiness and modest charm, Bill Cunningham New York offers a touching, gently humorous portrait of its subject without invading his jealously guarded privacy.', TO_DATE('2011-03-10', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('billy elliot', 2000, 'Billy Elliot is a charming movie that can evoke both laughter and tears.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('billy lynns long halftime walk', 2016, 'Billy Lynn''s Long Halftime Walk has noble goals, but lacks a strong enough screenplay to achieve them -- and its visual innovations are often merely distracting.', TO_DATE('2016-10-14', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('billy madison', 2000, 'Audiences who enjoy Adam Sandler''s belligerent comic energy may find him in joyously obnoxious form as Billy Madison, but this thinly-plotted starring vehicle surrounds its star with an aggressively pedestrian movie.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('billys hollywood screen kiss', 1998, 'Insubstantial yet charming, Billy''s Hollywood Screen Kiss tells a love story that''s as rooted in classic Hollywood as it is in timely themes.', TO_DATE('1998-07-24', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('biodome', 2001, 'Like its two obnoxious protagonists, this dreadfully unfunny Pauly Shore vehicle should remain separated from society.', TO_DATE('2001-08-01', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bird', 1988, 'Forest Whitaker inhabits Charlie Parker with aplomb in this moving love letter to the music icon, told by director Clint Eastwood with a moody style that visually evokes the wistful rhythm of jazz.', TO_DATE('1988-10-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bird box', 2018, 'Bird Box never quite reaches its intriguing potential, but strong acting and an effectively chilly mood offer intermittently creepy compensation.', TO_DATE('2018-11-13', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bird people', 2014, 'Bird People is admirably ambitious, but its handful of high-flying moments don''t add up to a consistently compelling film.', TO_DATE('2014-05-19', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('luccello dalle piume di cristallo the bird with the crystal plumage', 2001, 'Combining a deadly thriller plot with the stylized violence that would become his trademark, The Bird with the Crystal Plumage marked an impressive horror debut for Dario Argento.', TO_DATE('2001-10-26', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the birdcage', 1996, 'Mike Nichols wrangles agreeably amusing performances from Robin Williams and Nathan Lane in this fun, if not quite essential, remake of the French comedy La Cage aux Folles.', TO_DATE('1996-03-06', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('birdman', 2014, 'A thrilling leap forward for director Alejandro González Iñárritu, Birdman is an ambitious technical showcase powered by a layered story and outstanding performances from Michael Keaton and Edward Norton.', TO_DATE('2014-08-27', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('birds of prey and the fantabulous emancipation of one harley quinn', 2020, 'With a fresh perspective, some new friends, and loads of fast-paced action, Birds of Prey captures the colorfully anarchic spirit of Margot Robbie''s Harley Quinn.', TO_DATE('2020-02-05', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('birth', 2004, 'A well-mounted production is undermined by a muddled, absurd storyline of questionable taste.', TO_DATE('2004-09-09', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the birth of a nation', 2000, 'A deeply flawed cinematic landmark, The Birth of a Nation undermines its groundbreaking technical achievements with repugnant racist imagery.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('birthday girl', 2000, 'Kidman shows her range in this quirky movie, but the shift in tone from romantic comedy to thriller may leave viewers unsatisfied.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bitch', 2017, 'Bitch has an intriguing premise and a strong start that hints at greater things for writer-director-star Marianna Palka, even if its reach ultimately exceeds its grasp.', TO_DATE('2017-01-22', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bitter harvest', 2017, 'Bitter Harvest lives down to its title with a clichéd wartime romance whose clumsy melodrama dishonors the victims of the real-life horrors it uses as a backdrop.', TO_DATE('2017-02-13', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('die bitteren tränen der petra von kant the bitter tears of petra von kant', 2000, 'A thoughtful drama that grows even more powerful in retrospect, The Bitter Tears of Petra von Kant sensitively depicts a woman''s tortured search for connection.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('biutiful', 2010, 'Javier Bardem''s searing performance helps to elevate Biutiful, as does Alejandro González Iñárritu''s craftsmanship, but the film often lapses into contrivance and grimness.', TO_DATE('2010-05-25', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black and white', 2000, 'The atmosphere is affecting, and the story, at times, is compelling, but with a lean script and limp direction, Black and White doesn''t add up to much.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black 47', 2018, 'Black ''47 anchors its grim and gritty action in deceptively deep genre storytelling, although its epic ambitions arguably exceed its grasp.', TO_DATE('2018-02-17', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the black balloon', 2008, 'A tender and witty portrayal of a family coping with autism, The Black Balloon is heartfelt without being schmaltzy or moralizing.', TO_DATE('2008-03-03', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black book', 2006, 'A furious mix of sex, violence, and moral relativism, Black Book is shamelessly entertaining melodrama.', TO_DATE('2006-09-13', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the black cauldron', 2000, 'Ambitious but flawed, The Black Cauldron is technically brilliant as usual, but lacks the compelling characters of other Disney animated classics.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black christmas', 2006, 'A gratuitous remake of the 1974 slasher, Black Christmas pumps out the gore and blood with zero creativity, humor, or visual flair.', TO_DATE('2006-11-29', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black christmas', 2019, 'Better than the 2006 remake yet not as sharp as the original, this Black Christmas stabs at timely feminist themes but mostly hits on familiar pulp.', TO_DATE('2019-12-11', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the black dahlia', 2006, 'Though this ambitious noir crime-drama captures the atmosphere of its era, it suffers from subpar performances, a convoluted story, and the inevitable comparisons to other, more successful films of its genre.', TO_DATE('2006-08-30', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black death', 1800, 'Black Death delivers the fire and brimstone violence its subject matter warrants, while posing some interesting questions of faith and religion.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black dynamite', 2009, 'A loving and meticulous send-up of 1970s blaxsploitation movies, Black Dynamite is funny enough for the frat house and clever enough for film buffs.', TO_DATE('2009-01-22', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black hawk down', 2001, 'Though it''s light on character development and cultural empathy, Black Hawk Down is a visceral, pulse-pounding portrait of war, elevated by Ridley Scott''s superb technical skill.', TO_DATE('2001-12-09', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black knight', 2001, 'Black Knight feels like a lazily constructed movie, filled with lame gags and constant mugging from Lawrence.', TO_DATE('2001-10-29', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black mask', 1800, 'Stylish setting and masterfully choreographed fight scenes, but the story is low on credibility and high on excessive violence and gore.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black mass', 2015, 'Black Mass spins a gripping yarn out of its fact-based story -- and leaves audiences with one of Johnny Depp''s most compelling performances in years.', TO_DATE('2015-09-04', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black nativity', 2013, 'It''s sweetly amiable and solidly performed, but Black Nativity suffers from director Kasi Lemmons'' heavy-handed treatment of its celebrated source material.', TO_DATE('2013-11-25', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black or white', 2014, 'Black or White has more on its mind than your average family drama, but the film''s approach to its thought-provoking themes too often lives down to its title.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black orpheus orfeu negro', 2001, 'Colorful, atmospheric, and infections, Black Orpheus takes an ancient tale and makes it fresh anew, thanks in part to its bewitching bossa nova soundtrack.', TO_DATE('2001-06-05', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black panther', 2018, 'Black Panther elevates superhero cinema to thrilling new heights while telling one of the MCU''s most absorbing stories -- and introducing some of its most fully realized characters.', TO_DATE('2018-02-06', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black rock', 2012, 'It springs from smarter ideas than your average chase thriller, but ultimately, Black Rock falls back on disappointingly familiar ingredients.', TO_DATE('2012-01-24', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black sea', 2014, 'Black Sea may not be particularly deep, but thanks to Kevin Macdonald''s judicious direction and a magnetic performance from Jude Law, it remains an efficiently well-crafted thriller.', TO_DATE('2014-11-25', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black sheep', 2006, 'With an outrageous premise played completely straight, Black Sheep is a violent, grotesque, and very funny movie that takes B-movie lunacy to a delirious extreme.', TO_DATE('2006-09-10', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black snake moan', 2007, 'Uninhibited performances, skillful direction, and a killer blues soundtrack elevate Black Snake Moan beyond its outlandish premise.', TO_DATE('2007-01-25', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black sunday', 2002, 'Mario Bava''s official narrative debut is a witchy nightmare steeped in gothic splendor, shot in chiaroscuro black and white and punctuated with startling gore.', TO_DATE('2002-09-02', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black swan', 2010, 'Bracingly intense, passionate, and wildly melodramatic, Black Swan glides on Darren Aronofsky''s bold direction -- and a bravura performance from Natalie Portman.', TO_DATE('2010-09-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('black white gray a portrait of sam wagstaff and robert mapplethorpe', 2007, 'Vital documentation of an unsung 70''s art patron and his famous photographer lover. A vivid and tragic story.', TO_DATE('2007-10-16', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blackfish', 2013, 'Blackfish is an aggressive, impassioned documentary that will change the way you look at performance killer whales.', TO_DATE('2013-01-29', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blackhat', 2015, 'Thematically timely but dramatically inert, Blackhat strands Chris Hemsworth in a muddled misfire from director Michael Mann.', TO_DATE('2015-01-13', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blackkklansman', 2018, 'BlacKkKlansman uses history to offer bitingly trenchant commentary on current events -- and brings out some of Spike Lee''s hardest-hitting work in decades along the way.', TO_DATE('2018-05-14', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blackthorn', 2011, 'Blackthorn invites comparisons to a classic Western -- and survives, thanks largely to a charismatic performance by a well-chosen Sam Shepard.', TO_DATE('2011-04-25', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blade ii', 2002, 'Though Blade II offers more of what worked in the original, its plot and character development appear to have been left on the cutting room floor.', TO_DATE('2002-03-10', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blade of the immortal mugen no jûnin', 2017, 'Blade of the Immortal highlights Takashi Miike''s flair for balletic violence, making up what it lacks in strict originality with rich characterizations and kinetic thrills.', TO_DATE('2017-04-28', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blade runner', 2000, 'Misunderstood when it first hit theaters, the influence of Ridley Scott''s mysterious, neo-noir Blade Runner has deepened with time. A visually remarkable, achingly human sci-fi masterpiece.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blade runner 2049', 2017, 'Visually stunning and narratively satisfying, Blade Runner 2049 deepens and expands its predecessor''s story while standing as an impressive filmmaking achievement in its own right.', TO_DATE('2017-09-29', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blade trinity', 2004, 'Louder, campier, and more incoherent than its predecessors, Blade: Trinity seems content to emphasize style over substance and rehash familiar themes.', TO_DATE('2004-07-06', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blades of glory', 2007, 'Thanks to the spirited performances of a talented cast - particularly Will Ferrell and Jon Heder as rivals-turned-teammates -- Blades of Glory successfully spoofs inspirational sports dramas with inspired abandon.', TO_DATE('2007-03-27', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blair witch', 2016, 'Blair Witch doles out a handful of effective scares, but aside from a few new twists, it mainly offers a belated rehash of the original -- and far more memorable -- first film.', TO_DATE('2016-07-23', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the blair witch project', 2000, 'Full of creepy campfire scares, mock-doc The Blair Witch Project keeps audiences in the dark about its titular villain, proving once more that imagination can be as scary as anything onscreen.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blame it on rio', 2001, 'It isn''t clear who is most culpable for this creepy comedy''s sheer wrongness, but its smarmy laughs and uncomfortable romance will leave audiences feeling guilty long afterward.', TO_DATE('2001-08-16', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blancanieves', 2012, 'Smartly written and beautiful to behold, Blancanieves uses its classic source material to offer a dark tale, delightfully told.', TO_DATE('2012-12-12', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blank city', 2010, 'Blank City pays affectionate tribute to the No Wave filmmakers'' movement -- and the bygone New York City that birthed it.', TO_DATE('2010-11-09', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blast from the past', 2000, 'Cute idea, but not consistently funny.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blaze', 2018, 'As lyrical and bittersweet as the music its subject left behind, Blaze takes a decidedly unconventional -- yet richly rewarding -- approach to the musical biopic.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blazing saddles', 2000, 'Daring, provocative, and laugh-out-loud funny, Blazing Saddles is a gleefully vulgar spoof of Westerns that marks a high point in Mel Brooks'' storied career.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bleak street la calle de la amargura', 2015, 'Opulent and odd, Bleak Street isn''t quite weird enough to work.', TO_DATE('2015-10-16', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bleed for this', 2016, 'Bleed for This rises on the strength of Miles Teller''s starring performance to deliver a solid fact-based boxing drama that takes a few genre clichés on the chin but keeps on coming.', TO_DATE('2016-09-02', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blended', 2014, 'Lurching between slapstick and schmaltz without showing much of a commitment to either, Blended commits the rare Sandler sin of provoking little more than boredom.', TO_DATE('2014-05-18', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bless the child', 2000, 'Bless the Child squanders its talented cast on a plot that''s more likely to inspire unintentional laughs than shivers.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blind', 2014, 'A beautifully composed drama whose narrative intricacy is matched by its depth, Blind sounds an ambitious note of triumph for writer-director Eskil Vogt.', TO_DATE('2014-01-19', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blind dating', 2007, 'Nicely cast but clumsily directed, Blind Dating smothers its leads'' chemistry in a wildly uneven and mostly unmemorable romantic comedy with far too little of either.', TO_DATE('2007-05-05', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blind spot hitlers secretary', 2002, 'The testimony of Junge is more than enough to make this bare-bones documentary fascinating.', TO_DATE('2002-09-27', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blinded by the light', 2019, 'Like a life-affirming rock anthem, Blinded by the Light hits familiar chords with confidence and flair, building to a conclusion that leaves audiences cheering for an encore.', TO_DATE('2019-01-28', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blindsight', 2006, 'A powerful glimpse of the possibilities for transcendence in straightforward documentary filmmaking -- and extreme physical disability.', TO_DATE('2006-09-22', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blindspotting', 2018, 'As timely as it is overall impactful, Blindspotting blends buddy comedy with seething social commentary, and rises on the strength of Daveed Diggs'' powerful performance.', TO_DATE('2018-01-19', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bliss', 2019, 'Bliss may be too narratively and visually intense for less adventurous viewers, but should trigger the titular state in those with a taste for hard-hitting horror.', TO_DATE('2019-05-02', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blitz', 2011, 'A middling crime thriller largely assembled from wearyingly familiar parts, Blitz sacks a game Jason Statham''s performance behind the line of genre scrimmage.', TO_DATE('2011-05-14', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dave chappelles block party', 2005, 'Dave Chappelle''s Block Party is a raucous return to the spotlight for the comic, buoyed by witty, infectious humor and outstanding musical performances.', TO_DATE('2005-09-15', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blockers', 2018, 'Blockers puts a gender-swapped spin on the teen sex comedy -- one elevated by strong performances, a smartly funny script, and a surprisingly enlightened perspective.', TO_DATE('2018-03-12', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blood', 2012, 'While well-acted and skillfully directed, Blood never quite manages to draw its themes and characters into a coherent, compelling whole.', TO_DATE('2012-10-11', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blood and chocolate', 2007, 'Cheap CG effects and laughable dialogue make Blood and Chocolate worse than the usual werewolf flick.', TO_DATE('2007-01-10', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blood and money', 2020, 'Blood and Money gives Tom Berenger a too-rare opportunity to take the spotlight -- along with a middling script that falls back too often on action movie clichés.', TO_DATE('2020-05-12', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blood diamond', 2006, 'Blood Diamond overcomes poor storytelling with its biting commentary and fine performances.', TO_DATE('2006-11-15', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blood done sign my name', 2010, 'Even among civil rights movies, Blood Done Sign My Name is remarkably earnest, but its big heart can''t cover for the bland acting and TV-style melodrama that blunts the movie''s impact.', TO_DATE('2010-01-25', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blood father', 2016, 'Blood Father meets every expectation a film fan could have for a latter-day Mel Gibson action thriller with its title -- and even, in some respects, handily exceeds them.', TO_DATE('2016-05-21', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blood on her name', 2019, 'A satisfyingly dark noir elevated by stellar acting and a sharp screenplay, Blood on Her Name thrills in the moment and lingers in the memory.', TO_DATE('2019-07-18', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blood quantum', 2019, 'Blood Quantum blends bloody horror with sociopolitical subtext, taking a fresh bite out of the crowded zombie genre in the bargain.', TO_DATE('2019-09-07', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blood simple', 2000, 'Brutally violent and shockingly funny in equal measure, Blood Simple offers early evidence of the Coen Brothers'' twisted sensibilities and filmmaking ingenuity.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blood ties', 2013, 'Blood Ties boasts a fine cast and palpable period detail, but ultimately fails to do much of anything new with its formulaic story.', TO_DATE('2013-05-19', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blood work', 2002, 'Blood Work is a routine, but competently made thriller marred by lethargic pacing.', TO_DATE('2002-07-28', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bloodrayne', 2005, 'BloodRayne is an absurd sword-and-sorcery vid-game adaptation from schlock-maestro Uwe Boll, featuring a distinguished (and slumming) cast.', TO_DATE('2005-08-25', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bloodshot', 2020, 'Bloodshot gives Vin Diesel a solid opportunity to indulge in old-school action that should satisfy fans, even if the end result is disappointingly mediocre.', TO_DATE('2020-03-09', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bloodsport', 2002, 'This is where it all began for the Muscles from Brussels, but beyond Van Damme''s athleticism, Bloodsport is a cliched, virtually plotless exercise in action movie recycling.', TO_DATE('2002-01-27', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bloodsucking bastards', 2015, 'Bloodsucking Bastards gets a few gallons of B-movie fun out of its sanguine humor and solid cast, even if it isn''t quite as wild as its title might suggest.', TO_DATE('2015-08-30', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bloody nose empty pockets', 2020, 'An intoxicating blend of documentary and fiction, Bloody Nose, Empty Pockets surveys the bar-going life with a remarkably sober eye.', TO_DATE('2020-01-25', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bloody sunday', 2002, 'Bloody Sunday powerfully recreates the events of that day with startling immediacy.', TO_DATE('2002-03-21', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blow', 2000, 'With elements that seem borrowed from movies like Goodfellas and Boogie Nights, Blow is pretty much been-there-done-that despite another excellent performance from Johnny Depp. It, also, becomes too sentimental at the end.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blow out', 2000, 'With a story inspired by Antonioni''s Blow Up and a style informed by the high-gloss suspense of Hitchcock, DePalma''s Blow Out is raw, politically informed, and littered with film references.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blowup', 2000, 'Exquisitely shot and simmering with unease, Michelangelo Antonio''s Blow-Up is an enigma that invites audiences to luxuriate in the sensual atmosphere of 1960s London chic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blue caprice', 2013, 'Smart, sobering, and quietly chilling, Blue Caprice uses its horrible true-life story -- and some solid performances -- to underscore the dreadful banality of evil.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blue car', 2002, 'A cautionary tale that rings true.', TO_DATE('2002-07-29', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blue crush', 2002, 'The surfing sequences are exhilarating, but the plot is pretty forgettable and trite.', TO_DATE('2002-07-24', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blue is the warmest color', 2013, 'Raw, honest, powerfully acted, and deliciously intense, Blue Is the Warmest Color offers some of modern cinema''s most elegantly composed, emotionally absorbing drama.', TO_DATE('2013-05-23', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blue jasmine', 2013, 'Woody Allen''s Blue Jasmine finds the director in peak late-period form -- and benefiting from a superb cast led by Cate Blanchett.', TO_DATE('2013-07-17', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the blue lagoon', 2000, 'A piece of lovely dreck, The Blue Lagoon is a naughty fantasy that''s also too chaste to be truly entertaining.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blue ruin', 2013, 'Smart, stripped-down, and thrillingly grim, Blue Ruin proves that a well-told revenge story can still leave its audience on the edge of their seat.', TO_DATE('2013-05-21', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blue story', 2019, 'Raw and riveting, Blue Story overcomes its somewhat prosaic story with powerful performances and an impressive clarity of purpose.', TO_DATE('2019-10-18', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blue streak', 2000, 'Martin Lawrence lends his comedic touch, but the movie isn''t much more than standard action-comedy fare.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blue valentine', 2010, 'This emotionally gripping examination of a marriage on the rocks isn''t always easy to watch, but Michelle Williams and Ryan Gosling give performances of unusual depth and power.', TO_DATE('2010-01-25', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blue velvet', 2000, 'If audiences walk away from this subversive, surreal shocker not fully understanding the story, they might also walk away with a deeper perception of the potential of film storytelling.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the blues brothers', 2002, 'Too over the top for its own good, but ultimately rescued by the cast''s charm, director John Landis'' grace, and several soul-stirring musical numbers.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blues brothers 2000', 1997, 'Braving onward without the late John Belushi, Blues Brothers 2000 gets the band back together with a spirited soundtrack, but a mission that''s far less divine.', TO_DATE('1997-06-01', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('blumhouses truth or dare', 2018, 'Truth or Dare''s slick presentation isn''t enough to make this mediocre horror outing much more frightening than an average round of the real-life game.', TO_DATE('2018-04-11', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boarding gate', 2007, 'Boarding Gate has little substance beneath its faux-thriller surface, and marks a step down from director Olivier Assayas'' usual work.', TO_DATE('2007-05-19', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boat trip', 2002, 'Boat Trip is a lame, juvenile farce that''s heavy on stereotypes and desperate antics but short on brains and laughs.', TO_DATE('2002-09-23', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bob le flambeur', 2000, 'Majorly stylish, Bob le Flambeur is a cool homage to American gangster films and the presage to French New Wave mode of seeing.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bobby jones stroke of genius', 2004, 'This earnest, monotonous biopic lacks dramatic tension and simplifies Jones'' life.', TO_DATE('2004-04-27', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bodied', 2017, 'With its thorny themes and aggressive humor, Bodied dares to offend - and justifies its approach with a subversive comedy that edifies as it entertains.', TO_DATE('2017-09-08', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('body at brighton rock', 2019, 'Body at Brighton Rock leaves some of its thrilling potential untapped, but the end result remains a solidly crafted outing that should entertain horror fans.', TO_DATE('2019-03-09', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('body cam', 2020, 'Ambitious yet undercooked, Body Cam can''t quite connect the dots between its genre thrills and socially aware themes.', TO_DATE('2020-05-16', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('body double', 2002, 'Exemplifying Brian De Palma''s filmmaking bravura and polarizing taste, Body Double is a salacious love letter to moviemaking.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('body of evidence', 1992, 'Body of Evidence''s sex scenes may be kinky, but the ludicrous concept is further undone by the ridiculous dialogue.', TO_DATE('1992-06-01', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('body of war', 2007, 'Unapologetically political, this intimate and heart wrenching profile of an Iraq veteran may be rough around the edges but takes a potent stance with determination and compassion.', TO_DATE('2007-10-29', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('body snatchers', 1993, 'Body Snatchers may not topple previous adaptions, but it boasts an effective sense of dread and strong characterizations.', TO_DATE('1993-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bohemian rhapsody', 2018, 'Bohemian Rhapsody hits a handful of high notes, but as an in-depth look at a beloved band, it offers more of a medley than a true greatest hits collection.', TO_DATE('2018-10-23', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bolero', 2003, 'Bolero combines a ludicrous storyline and wildly mismatched cast in its desperate attempts to titillate, but only succeeds in arousing boredom.', TO_DATE('2003-05-20', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bolt', 2008, 'Bolt is a pleasant animated comedy that overcomes the story''s familiarity with strong visuals and likable characters.', TO_DATE('2008-11-14', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bombshell', 2019, 'Bombshell benefits from a terrific cast and a worthy subject, but its impact is muffled by a frustrating inability to go deeper than the sensationalistic surface.', TO_DATE('2019-12-09', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bombshell the hedy lamarr story', 2017, 'Inspiring and tragic, Bombshell is a bittersweet celebration and reclamation of Hedy Lemarr''s journey from Hollywood legend to technology genius.', TO_DATE('2017-04-26', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bone collector', 2000, 'A talented cast is wasted on a bland attempt at a suspenseful, serial killer flick.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bone tomahawk', 2015, 'Bone Tomahawk''s peculiar genre blend won''t be for everyone, but its gripping performances and a slow-burning story should satisfy those in search of something different.', TO_DATE('2015-10-02', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bones', 2001, 'Slow to start, the sleek looking Bones is more silly than scary.', TO_DATE('2001-10-22', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bonfire of the vanities', 2000, 'The Bonfire of the Vanities is a vapid adaptation of a thoughtful book, fatally miscast and shorn of the source material''s crucial sense of irony. Add it to the pyre of Hollywood''s ambitious failures.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bonneville', 2007, 'The amazing cast of Bonneville is paired up with a basic, predictable script and lackluster direction.', TO_DATE('2007-06-21', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bonnie and clyde', 2000, 'A paradigm-shifting classic of American cinema, Bonnie and Clyde packs a punch whose power continues to reverberate through thrillers decades later.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boogeyman', 2005, 'The plot is been-there done-that generic, and none of the shock effects can do anything to build up suspense.', TO_DATE('2005-02-03', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boogie man the lee atwater story', 2008, 'Boogie Man is a complex, absorbing study of the contradictory life and times of architect of modern smear politics.', TO_DATE('2008-09-17', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boogie nights', 2000, 'Grounded in strong characters, bold themes, and subtle storytelling, Boogie Nights is a groundbreaking film both for director P.T. Anderson and star Mark Wahlberg.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('book club', 2018, 'Book Club only intermittently rises to the level of its impressive veteran cast; fortunately, they''re more than enough to bring pedestrian material entertainingly to life.', TO_DATE('2018-05-16', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('book of shadows blair witch 2', 2000, 'This sequel to Blair Witch Project is all formula and no creativity, mechanically borrowing elements from the original and other horror movies.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('booksmart', 2019, 'Fast-paced, funny, and fresh, Booksmart does the seemingly impossible by adding a smart new spin to the coming-of-age comedy.', TO_DATE('2019-03-11', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the boondock saints', 2002, 'A juvenile, ugly movie that represents the worst tendencies of directors channeling Tarantino.', TO_DATE('2002-05-11', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the boondock saints ii all saints day', 2009, 'This sequel to the cult favorite The Boondock Saints is more of the same -- unoriginal, absurd, violent, over-the-top, and occasionally mean-spirited.', TO_DATE('2009-10-25', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('borat cultural learnings of america for make benefit glorious nation of kazakhstan', 2006, 'Part satire, part shockumentary,Borat gets high-fives almost all-around for being offensive in the funniest possible way. Jagshemash!', TO_DATE('2006-04-27', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('border gräns', 2018, 'Thrilling, unpredictable, and brilliantly acted, Border (Gräns) offers a singular treat to genre fans looking for something different.', TO_DATE('2018-05-10', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('borg vs mcenroe', 2017, 'Borg vs McEnroe makes tennis improbably cinematic -- and brings the absolute best out of Shia LaBeouf, who delivers some of the best work of his career.', TO_DATE('2017-09-07', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('borgman', 2013, 'Borgman''s unpredictability may confound as many viewers as it enthralls, but either way, it''s a refreshingly original experiment in off-kilter terror.', TO_DATE('2013-05-19', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boricuas bond', 2000, 'One-sided, too depressing.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('born into brothels', 2004, 'A powerful and uplifting documentary.', TO_DATE('2004-01-27', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('born on the fourth of july', 1989, 'Led by an unforgettable performance from Tom Cruise, Born on the Fourth of July finds director Oliver Stone tackling thought-provoking subject matter with ambitious élan.', TO_DATE('1989-12-20', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('born to be blue', 2015, 'Born to Be Blue benefits from a highlight-reel performance from Ethan Hawke and an impressionistic, non-hagiographic approach to Chet Baker''s life and times.', TO_DATE('2015-09-13', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('born to be wild', 2011, 'The human story of Born To Be Wild is captivating and the accompanying nature footage is utterly cute and charming.', TO_DATE('2011-04-06', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bottle rocket', 2000, 'Bottle Rocket is Reservoir Dogs meets Breathless with a West Texas sensibility.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bottle shock', 2008, 'Bottle Shock fails to properly utilize the inspiring true tale at its core, settling instead for an ordinary, plodding account.', TO_DATE('2008-01-20', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boulevard', 2014, 'Boulevard features a richly layered performance from Robin Williams, but that may be this dour drama''s sole distinctive feature.', TO_DATE('2014-05-20', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bounce', 2000, 'Critics say Bounce is more of a thud. Plot turns feel cliched and contrived, and the romance between Paltrow and Affleck fails to engage.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bound', 1996, 'Bound''s more titillating elements attracted attention, but it''s the stylish direction, solid performances, and entertaining neo-noir caper plot that make it worth a watch.', TO_DATE('1996-10-04', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bourne identity', 2002, 'Expertly blending genre formula with bursts of unexpected wit, The Bourne Identity is an action thriller that delivers -- and then some.', TO_DATE('2002-05-20', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bourne supremacy', 2004, 'A well-made sequel that delivers the thrills.', TO_DATE('2004-07-19', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bourne ultimatum', 2007, 'The Bourne Ultimatum is an intelligent, finely tuned non-stop thrill ride. Another strong performance from Matt Damon and sharp camerawork from Paul Greengrass make this the finest installment of the Bourne trilogy.', TO_DATE('2007-07-14', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bowfinger', 2000, 'A witty commentary on modern film-making, with enough jokes to keep it entertaining throughout.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bowling for columbine', 2002, 'Though it may not always convince, Bowling for Columbine asks important questions and provokes thought.', TO_DATE('2002-06-10', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boxcar bertha', 2000, 'Too derivative of other Roger Corman crime pictures to stand out, Boxcar Bertha feels more like a training exercise for a fledgling Martin Scorsese than a fully formed picture in its own right.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boy', 2010, 'Boy possesses the offbeat charm associated with New Zealand film but is also fully capable of drawing the viewer in emotionally.', TO_DATE('2010-08-20', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boy a', 2007, 'Small in scale but large in impact, Boy A''s career making performances (particularly that by star Andrew Garfield) and carefully crafted characters defy judgment and aggressively provoke debate.', TO_DATE('2007-09-08', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a boy and his dog', 2000, 'An offbeat, eccentric black comedy, A Boy and His Dog features strong dialogue and an oddball vision of the future.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boy and the world o menino e o mundo', 2014, 'Boy and the World''s distinctive animation is visually thrilling -- and it''s backed up with a daring, refreshingly different storyline that should enthrall younger viewers while resonating deeply with adults.', TO_DATE('2014-12-23', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boy culture', 2006, 'Eloquent one-liners and quick pacing make Boy Culture sharper than the typical gay indie flick.', TO_DATE('2006-06-28', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boy erased', 2018, 'Anchored in empathy by writer-director-star Joel Edgerton, Boy Erased proves the road to complex, powerfully performed drama can also be paved with good intentions.', TO_DATE('2018-09-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the boy in the striped pajamas the boy in the striped pyjamas', 2008, 'A touching and haunting family film that deals with the Holocaust in an arresting and unusual manner, and packs a brutal final punch of a twist.', TO_DATE('2008-09-11', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the boy who could fly', 2000, 'Writer-director Nick Castle''s careful command of tone keeps The Boy Who Could Fly from fully surrendering to its story''s sentimental tendencies.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boyhood', 2014, 'Epic in technical scale but breathlessly intimate in narrative scope, Boyhood is a sprawling investigation of the human condition.', TO_DATE('2014-01-21', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boynton beach club', 2006, 'While the movie has been praised for showcasing a cinematically underused and disrespected age group, it also has the small-screen feel of a silly sitcom.', TO_DATE('2006-05-01', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boys and girls', 2000, 'Boys and Girls feels like a cheap rip-off of When Harry Met Sally. The predictable and stale story fails to engage.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boys dont cry', 2000, 'Harrowing yet stirring, Boys Don''t Cry powerfully commemorates the life -- and brutally unjust death -- of transgender teen Brandon Teena.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('boyz n the hood', 2000, 'Well-acted and thematically rich, Boyz N the Hood observes Black America with far more depth and compassion than many of the like-minded films its success inspired.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bra boys', 2008, 'While it looks like shameless publicity for the semi-notorious Aussie surfing gang, the film packs a raw energy into this look at a culture of athleticism and male loyalty.', TO_DATE('2008-04-07', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brads status', 2017, 'Brad''s Status transcends its familiar premise with insightful observations and affecting interplay between stars Ben Stiller and Austin Abrams.', TO_DATE('2017-09-10', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brahms the boy ii', 2020, 'More likely to induce boredom than quicken the pulse, Brahms: The Boy II is chiefly scary for the way it undermines the effectiveness of its above-average predecessor.', TO_DATE('2020-02-21', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bran nue dae', 2010, 'It''s original and high-spirited, but Bran Nue Dae is also uneven and sometimes overly kitschy.', TO_DATE('2010-01-09', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bratz the movie', 2007, 'Full of mixed messages and dubious role-models, Bratz is too shallow even for its intended audience.', TO_DATE('2007-07-28', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brave', 2012, 'Brave offers young audiences and fairy tale fans a rousing, funny fantasy adventure with a distaff twist and surprising depth.', TO_DATE('2012-06-10', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the brave one', 2006, 'Magnetic by between Jodie Foster and Terrence Howard can''t quite compensate for The Brave One''s problematic and unconvincing eye-for-an-eye moral.', TO_DATE('2006-12-30', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brawl in cell block 99', 2017, 'Brawl in Cell Block 99 rides a committed Vince Vaughn performance into the brutally violent -- and undeniably entertaining -- depths of prison-set grindhouse genre fare.', TO_DATE('2017-09-02', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('breach', 2007, 'Powered by Chris Cooper''s masterful performance, Breach is a tense and engaging portrayal of the FBI''s infamous turncoat.', TO_DATE('2007-02-04', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bread tulips', 2001, 'Bread and Tulips is a sweet-natured comedy offering gentle, escapist entertainment.', TO_DATE('2001-04-04', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('break point', 2014, 'Like an old pro playing an outmatched opponent, Break Point scores some solid points -- even if it never bothers to break a sweat along the way.', TO_DATE('2014-03-11', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the breakup', 2006, 'This anti-romantic comedy lacks both laughs and insight, resulting in an odd and unsatisfying experience.', TO_DATE('2006-05-26', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('breakfast at tiffanys', 2000, 'It contains some ugly anachronisms, but Blake Edwards is at his funniest in this iconic classic, and Audrey Hepburn absolutely lights up the screen.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the breakfast club', 1985, 'The Breakfast Club is a warm, insightful, and very funny look into the inner lives of teenagers.', TO_DATE('1985-05-15', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('breakfast with scot', 2007, 'Though Breakfast with Scot is a well-intentioned movie with some charming performances, it suffers from sitcom humor and predictable setups.', TO_DATE('2007-09-06', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('breakin all the rules', 2004, 'This formulaic screwball comedy is weighed down by a contrived, overly complicated plot.', TO_DATE('2004-05-07', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('breaking and entering', 2006, 'This class warfare drama feels contrived and superficial: characters don''t act logically as the movie manipulates them towards deconstructing various social issues.', TO_DATE('2006-09-14', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('breaking away', 2001, 'At once a touching, funny coming-of-age story and a compelling sports film, Breaking Away is a delightful treat.', TO_DATE('2001-05-10', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('breaking in', 2018, 'Breaking In is proof that Gabrielle Union deserves more leading roles -- particularly in films that offer more than this rote, disposable action thriller.', TO_DATE('2018-05-10', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('breaking the waves', 1996, 'Breaking the Waves offers a remarkable testament to writer-director Lars von Trier''s insight and filmmaking skill -- and announces Emily Watson as a startling talent.', TO_DATE('1996-11-29', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('breakthrough', 2019, 'Like its lead character, Breakthrough is fiercely focused on faith -- but its less subtle elements are balanced by strong performances and an uplifting story.', TO_DATE('2019-03-10', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('breathe', 2017, 'Strong performances from Breathe''s well-matched leads help add an edge to a biopic that takes a decidedly heartwarming approach to its real-life story.', TO_DATE('2017-09-12', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('breathe in', 2013, 'Breathe In''s plot never quite sparks the way it should, but it remains thoroughly watchable thanks to strong performances from Felicity Jones and Guy Pearce.', TO_DATE('2013-01-21', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('breathless', 1961, 'Breathless rewrote the rules of cinema -- and more than 50 years after its arrival, Jean-Luc Godard''s paradigm-shifting classic remains every bit as vital.', TO_DATE('1961-02-07', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brian banks', 2018, 'While it remains a reasonably inspiring drama, Brian Banks might have presented a more complex or fully realized version of the real-life story it dramatizes.', TO_DATE('2018-09-26', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brick', 2005, 'This entertaining homage to noirs past has been slickly and compellingly updated to a contemporary high school setting.', TO_DATE('2005-02-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brick lane', 2007, 'Frustratingly slow-moving, but ultimately saved by Chatterjee''s solid acting and Gavron''s gentle patience.', TO_DATE('2007-09-06', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brick mansions', 2014, 'Choppily edited and largely bereft of plot, Brick Mansions wastes a likable cast on a pointless remake of the far more entertaining District B13.', TO_DATE('2014-04-23', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bride and prejudice', 2004, 'A colorful and energetic adaptation of Austen''s classic.', TO_DATE('2004-09-11', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bride of chucky', 1998, 'Bride of Chucky is devoid of any fright and the franchise has become tiresomely self-parodic, although horror fans may find some pleasure in this fourth entry''s camp factor.', TO_DATE('1998-10-16', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bride of frankenstein', 2000, 'An eccentric, campy, technically impressive, and frightening picture, James Whale''s Bride of Frankenstein has aged remarkably well.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bride of the wind', 2001, 'Bride of the Wind drags for its length, and Alma, rather than being the proto-feminist the film wants her to be, comes across more as a dilettante of mediocre talent.', TO_DATE('2001-06-04', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bride wars', 2009, 'Bride Wars takes the already wearisome concept of battling bridezillas, and makes it thoroughly insufferable via a lazy script and wholly detestable characters.', TO_DATE('2009-01-07', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brideshead revisited', 2008, 'Suspenseful and beautifully mounted, Brideshead Revisited does an able job condensing Evelyn Waugh''s novel.', TO_DATE('2008-06-29', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bridesmaids', 2011, 'A marriage of genuine characters, gross out gags, and pathos, Bridesmaids is a female-driven comedy that refuses to be boxed in as Kristen Wiig emerges as a real star.', TO_DATE('2011-03-14', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bridge of spies', 2015, 'Bridge of Spies finds new life in Hollywood''s classic Cold War espionage thriller formula, thanks to reliably outstanding work from Steven Spielberg and Tom Hanks.', TO_DATE('2015-10-04', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bridge on the river kwai', 2000, 'This complex war epic asks hard questions, resists easy answers, and boasts career-defining work from star Alec Guinness and director David Lean.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bridge to terabithia', 2007, 'Bridge to Terabithia is a faithful adaptation of a beloved children''s novel and a powerful portrayal of love, loss, and imagination through children''s eyes.', TO_DATE('2007-02-12', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a bridge too far', 2002, 'A Bridge Too Far is a war movie too long, although top-notch talent on both sides of the camera keeps the end result consistently watchable.', TO_DATE('2002-11-07', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bridges of madison county', 2000, 'Sentimental, slow, schmaltzy, and very satisfying, The Bridges of Madison County finds Clint Eastwood adapting a bestseller with heft, wit, and grace.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bridget joness diary', 2000, 'Though there was controversy over the choice of casting, Zellweger''s Bridget Jones is a sympathetic, likable, funny character, giving this romantic comedy a lot of charm.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bridget jones the edge of reason', 2004, 'Bogged down in slapstick and silliness, Edge of Reason is a predictable continuation of the Bridget Jones story.', TO_DATE('2004-11-04', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bridget joness baby', 2016, 'Bridget Jones''s Baby might be late on arrival, but fans of the series should still find its third installment a bouncing bundle of joy.', TO_DATE('2016-09-05', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brief interviews with hideous men', 2009, 'Ambitious but uneven, John Krasinski''s adaptation of David Foster Wallace''s Brief Interviews with Hideous Men tries hard but doesn''t match the depth of the book.', TO_DATE('2009-01-28', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bright', 2017, 'Bright tries to blend fantasy, hard-hitting cop drama, and social commentary -- and ends up falling painfully short of the mark on all three fronts.', TO_DATE('2017-12-20', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bright leaves', 2003, 'A rich, eccentric documentary about both filmmaking and the tobacco industry.', TO_DATE('2003-10-10', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bright lights starring carrie fisher and debbie reynolds', 2016, 'Bright Lights: Starring Carrie Fisher and Debbie Reynolds is a touching, bittersweet, and ultimately charming love story that serves as a poignantly effective tribute to the strangely complicated, uniquely resilient mother/daughter duo.', TO_DATE('2016-05-15', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bright star', 2009, 'Jane Campion''s direction is as refined as her screenplay, and she gets the most out of her cast -- especially Abbie Cornish -- in this understated period drama.', TO_DATE('2009-05-15', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bright young things', 2003, 'Colored with witty performances and a camp sense of satire, Stephen Fry''s version of Evelyn Waugh''s novel may only be fitfully successful but it does mark a promising debut for the British comic.', TO_DATE('2003-08-21', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brightburn', 2019, 'Although Brightburn doesn''t fully deliver on the pitch-black promise of its setup, it''s still enough to offer a diverting subversion of the superhero genre.', TO_DATE('2019-05-17', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brighton rock', 2010, 'Brighton Rock is a lean noir boasting an appealing trio of stars, but its old-fashioned presentation only reinforces how little it distinguishes itself from the superior original.', TO_DATE('2010-09-13', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brigsby bear', 2017, 'Audiences attuned to Brigsby Bear''s strange frequency will be moved by its earnest -- and endearingly original -- approach to pop culture''s impact and the creative urge.', TO_DATE('2017-01-24', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bring it on', 2000, 'Despite the formulaic, fluffy storyline, this movie is surprisingly fun to watch, mostly due to its high energy and how it humorously spoofs cheerleading instead of taking itself too seriously.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bringing down the house', 2003, 'Though the cast shines, they can''t save this comedy, which is overly contrived and filled with outdated and offensive racial jokes.', TO_DATE('2003-02-22', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bringing out the dead', 1999, 'Stunning and compelling, Scorsese and Cage succeed at satisfying the audience.', TO_DATE('1999-10-22', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bringing up baby', 2000, 'With Katharine Hepburn and Cary Grant at their effervescent best, Bringing Up Baby is a seamlessly assembled comedy with enduring appeal.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('broadcast news', 2000, 'Blockbuster dramatist James L. Brooks delivers with Broadcast News, fully entertaining with deft, deep characterization.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('broadway danny rose', 2001, 'Woody Allen''s hard-working, uphill-climbing Broadway talent agent is rendered memorably with equal parts absurdity and affection.', TO_DATE('2001-10-07', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the broadway melody', 1929, 'The Broadway Melody is interesting as an example of an early Hollywood musical, but otherwise, it''s essentially bereft of appeal for modern audiences.', TO_DATE('1929-02-01', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('broadway the golden age', 2004, 'Broadway: The Golden Age is a breezy, affectionate tribute to a sparkling array of the era''s best and brightest.', TO_DATE('2004-01-07', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brokeback mountain', 2005, 'A beautiful, epic Western, Brokeback Mountain''s love story is imbued with heartbreaking universality thanks to moving performances by Heath Ledger and Jake Gyllenhaal.', TO_DATE('2005-09-05', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brokedown palace', 1999, 'Lacks credibility and tension.', TO_DATE('1999-08-13', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('broken city', 2013, 'Broken City''s thinly sketched, formulaic script offers meager rewards for all but the least demanding noir aficionados.', TO_DATE('2013-01-16', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('broken embraces', 2009, 'Pedro Almodovar''s fourth film with Penélope Cruz isn''t his finest work, but he brings his signature visual brilliance to this noirish tale, and the cast turns in some first-class performances.', TO_DATE('2009-03-18', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('broken english', 2007, 'Though Broken English eventually settles into basic rom-com territory, it''s pleasant and good-natured, and Parker Posey is spellbinding throughout the movie.', TO_DATE('2007-01-21', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('broken flowers', 2005, 'Bill Murray''s subtle and understated style complements director Jim Jarmusch''s minimalist storytelling in this quirky, but deadpan comedy.', TO_DATE('2005-05-17', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the broken hearts club', 2000, 'The Broken Hearts Club often feels like an amalgam of 70s sitcoms -- though a hunky lead and a sweet central romance provide soapy delights.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bronson', 2009, 'Undeniably gripping, Bronson forces the viewer to make some hard decisions about where the line between art and exploitation lies.', TO_DATE('2009-01-23', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a bronx tale', 1993, 'A Bronx Tale sets itself apart from other coming-of-age dramas thanks to a solid script, a terrific cast, and director Robert De Niro''s sensitive work behind the camera.', TO_DATE('1993-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the brood', 2000, 'The Brood is a grotesque, squirming, hilariously shrill exploration of the bizarre and deadly side of motherhood.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brooklyn', 2015, 'Brooklyn buttresses outstanding performances from Saoirse Ronan and Emory Cohen with a rich period drama that tugs at the heartstrings as deftly as it satisfies the mind.', TO_DATE('2015-01-27', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brooklyn castle', 2012, 'Brooklyn Castle is a warm, engaging, and even uplifting documentary about chess-playing whiz kids.', TO_DATE('2012-03-15', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brooklyn rules', 2007, 'Brooklyn Rules'' premise is old hat now, but strong performances from Alec Baldwin and the supporting cast are reasons enough to watch.', TO_DATE('2007-03-27', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brooklyns finest', 2009, 'It''s appropriately gritty, and soaked in the kind of palpable tension Antoine Fuqua delivers so well, but Brooklyn''s Finest suffers from the comparisons its cliched script provokes.', TO_DATE('2009-01-17', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brother bear', 2003, 'Brother Bear is gentle and pleasant if unremarkable Disney fare, with so-so animation and generic plotting.', TO_DATE('2003-10-18', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brother to brother', 2004, 'Led by two fine lead performances, Brother to Brother is a moving and thought-provoking dramatization of the Harlem Renaissance.', TO_DATE('2004-04-27', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brotherhood', 2011, 'Brotherhood''s fast-paced look at a fraternity pledge gone nightmarishly wrong has a kinetic pull that isn''t always strong enough to overcome a hollow narrative.', TO_DATE('2011-01-12', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brothers', 2005, 'This tense, understated drama explores the complications of individual and social ethics stemming from the repercussions of war on one man and his family.', TO_DATE('2005-04-02', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the brothers bloom', 2008, 'Despite strong performances The Brothers Bloom ultimately does not fulfill its lofty ambitions.', TO_DATE('2008-09-05', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the brothers grimm', 2005, 'The Brothers Grimm is full of beautiful imagery, but the story is labored and less than enchanting.', TO_DATE('2005-07-13', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brothers of the head', 2006, 'As bizarre as it is, this mockumentary about a pair of conjoined rockers is surprisingly poignant and filled with authentic period details.', TO_DATE('2006-03-11', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the brothers solomon', 2007, 'Squandering its impressive cast with poorly-directed gags, The Brothers Solomon is a one-joke film stretched well beyond its limits.', TO_DATE('2007-09-05', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('brown sugar', 2002, 'Though predictable and possibly too sweet, Brown Sugar is charming, well-acted, and smarter than typical rom-com fare.', TO_DATE('2002-09-26', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bruce almighty', 2003, 'Carrey is hilarious in the slapstick scenes, but Bruce Almighty gets bogged down in treacle.', TO_DATE('2003-03-13', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bruno', 2009, 'Crude and offensive, but with ample cultural insights and gut-busting laughs, Bruno is another outlandish and entertaining mockumentary from Sacha Baron Cohen.', TO_DATE('2009-06-26', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bubba hotep', 2002, 'The best movie to star both the King and JFK.', TO_DATE('2002-08-21', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bubble boy', 2001, 'Bubble Boy bounces along with lame, offensive jokes that are more tasteless than funny.', TO_DATE('2001-08-20', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bucket list', 2007, 'Not even the earnest performances of the two leads can rescue The Bucket List from its schmaltzy script.', TO_DATE('2007-11-20', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bucky larson born to be a star', 2011, 'A severely misguided and inept comedy incapable of even telling its single joke properly.', TO_DATE('2011-09-09', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('buffalo 66', 1998, 'Self-indulgent yet intriguing, Buffalo ''66 marks an auspicious feature debut for writer-director-star Vincent Gallo while showcasing a terrific performance from Christina Ricci.', TO_DATE('1998-06-26', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('buffalo boys', 2018, 'It''s hampered somewhat by its disappointingly familiar story, but Buffalo Boys makes up for its shortcomings with plenty of exciting action sequences.', TO_DATE('2018-07-19', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('buffalo soldiers', 2001, 'Overall, this caustic comedy hits more of its targets than it misses.', TO_DATE('2001-11-15', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('buffy the vampire slayer', 2000, 'Buffy the Vampire Slayer''s supernatural coming of age tale is let down by poor directing and even poorer plotting -- though Kristy Swanson and Paul Reubens'' game performances still manage to slay.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bug', 2006, 'Disappointing resolution aside, Bug uses its claustrophobic setting and cinéma vérité camerawork to tense, impressive effect.', TO_DATE('2006-05-20', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a bugs life', 2000, 'A Bug''s Life is a rousing adventure that blends animated thrills with witty dialogue and memorable characters - and another smashing early success for Pixar.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bugsy', 2000, 'Stylishly scattered, Bugsy offers cinematic homage to the infamous underworld legend, chiefly through a magnetic performance from Warren Beatty in the title role.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bugsy malone', 2003, 'Delightfully bizarre, Bugsy Malone harnesses immense charm from its cast of child actors playing wise guys with precocious pluck.', TO_DATE('2003-03-06', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bukowski born into this', 2003, 'A thoroughly engrossing documentary examining the life of talented but troubled writer Charles Bukowski.', TO_DATE('2003-01-30', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bull', 2019, 'An intimate two-hander anchored by a pair of well-matched actors, Bull takes an achingly empathetic look at life on the economic margins.', TO_DATE('2019-05-15', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bull durham', 1988, 'Kevin Costner at his funniest and most charismatic in Bull Durham, a film that''s as wise about relationships as it is about minor league baseball.', TO_DATE('1988-06-15', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bullet to the head', 2012, 'Bullet to the Head''s unapologetically trashy thrills evoke memories of its star and director''s proud cinematic pasts -- but sadly, those memories are just about all it has to offer.', TO_DATE('2012-11-14', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bulletproof monk', 2002, 'Venerable action star Chow Yun-Fat is the only saving grace in this silly action flick that more often than not resembles a commercial in style.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bullitt', 2001, 'Steve McQueen is cool as ice in this thrilling police procedural that also happens to contain arguably the greatest movie car chase ever.', TO_DATE('2001-02-13', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bully', 2001, 'With its lingering shots of naked teenage bodies, Bully feels more sordidly exploitative than realistic.', TO_DATE('2001-07-02', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bully', 2011, 'Hard-hitting and gracefully filmed, Bully powerfully delivers an essential message to an audience that may not be able to see it.', TO_DATE('2011-04-26', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bulworth', 1998, 'Star and director Beatty''s ambitious take on race and politics in 20th-century America isn''t perfect, but manages to provide more than its share of thought-provoking laughs.', TO_DATE('1998-05-22', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bumblebee', 2018, 'Bumblebee proves it''s possible to bring fun and a sense of wonder back to a bloated blockbuster franchise -- and sets up its own slate of sequels in the bargain.', TO_DATE('2018-12-09', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bunraku', 2010, 'Bunraku admirably strives for visual panache, but the staging, acting, and effects are dismal with a complete lack of excitement.', TO_DATE('2010-09-14', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('burden', 2016, 'Burden is no groundbreaker, but its straightforward approach allows the eccentric artists'' work to speak for itself, warts and all.', TO_DATE('2016-04-20', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('burden', 2018, 'Burden grapples clumsily with its undeniably worthy themes, but its honorable intentions -- and strong performances -- make it easy to forgive those flaws.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('buried', 2010, 'Wringing a seemingly impossible amount of gripping drama out of its claustrophobic premise, Buried is a nerve-wracking showcase for Ryan Reynolds'' talent.', TO_DATE('2010-01-24', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('burke and hare', 2010, 'Marked by timid scares and flat-footed humor, Burke and Hare is a missed opportunity for its talented cast and a disappointing return for director John Landis.', TO_DATE('2010-10-26', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('burlesque', 2010, 'Campy and clichéd, Burlesque wastes its talented cast (including a better-than-expected Christina Aguilera) on a movie that wavers uncertainly between "bad" and "so bad it''s good."', TO_DATE('2010-11-19', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('burma vj reporter i et lukket land burma vj reporting from a closed country', 2008, 'A powerfully visceral docu-drama highlighting the evils of censorship and the essential need for freedom of speech.', TO_DATE('2008-11-12', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('burn after reading', 2008, 'With Burn After Reading, the Coen Brothers have crafted another clever comedy/thriller with an outlandish plot and memorable characters.', TO_DATE('2008-08-27', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('burning beoning', 2018, 'Burning patiently lures audiences into a slow-burning character study that ultimately rewards the viewer''s patience -- and subverts many of their expectations.', TO_DATE('2018-05-17', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the burning plain', 2008, 'This heavily symbolic, melodramatic multi-narrative drama lacks emotional resonance.', TO_DATE('2008-08-29', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('burning sands', 2017, 'Burning Sands covers familiar territory, but Trevor Jackson''s layered performance and director/co-writer Gerard McMurray''s empathetic approach help set it apart.', TO_DATE('2017-01-25', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('burnt', 2015, 'Burnt offers a few spoonfuls of compelling culinary drama, but they''re lost in a watery goulash dominated by an unsavory main character and overdone clichés.', TO_DATE('2015-10-18', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('burying the ex', 2014, 'Burying the Ex boasts flickers of director Joe Dante''s former flair, but neither the concept nor its execution live up to the standard set by his best efforts.', TO_DATE('2014-09-08', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('bushwick', 2017, 'Bushwick''s sociopolitical subtext gives it more heft than the average action thriller, but those ideas are given short shrift in what amounts to a disappointing shoot-''em-up.', TO_DATE('2017-01-23', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the business of being born', 2008, 'Epstein''s argument in favor of home birthing is certainly biased -- but its biases are so transparent, and so impassioned, that they work in the film''s favor.', TO_DATE('2008-01-08', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the business of strangers', 2001, 'The Business of Strangers showcases a complex, compelling performance by Channing. Her interactions and clashes with Stiles make for riveting viewing.', TO_DATE('2001-02-13', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('but im a cheerleader', 2000, 'Too broad to make any real statements, But I''m a Cheerleader isn''t as sharp as it should be, but a charming cast and surprisingly emotional center may bring enough pep for viewers looking for a light social satire.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the butcher boy', 1998, 'Equal parts comical and harrowing, The Butcher Boy is a sobering tale of abuse told with an imaginative lyricism that is by turns inspired and distracting.', TO_DATE('1998-04-03', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('butt boy', 2019, 'Its puerile premise invites low expectations, but viewers who sit down in search of boldly humorous provocations won''t leave Butt Boy brokenhearted.', TO_DATE('2019-09-23', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('butter', 2011, 'Despite its talented cast and a few funny moments, Butter''s satirical aims are largely undone by a lack of subtlety and air of smugness.', TO_DATE('2011-09-15', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the butterfly effect', 2004, 'The premise is intriguing, but it''s placed in the service of an overwrought and tasteless thriller.', TO_DATE('2004-01-17', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('by the grace of god grâce à dieu', 2019, 'Patient in its approach yet stirring in its conviction, By the Grace of God draws soberly gripping cinema from real-life horror.', TO_DATE('2019-02-09', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('by the sea', 2015, 'By the Sea may intrigue celebrity voyeurs or fans of a certain type of arthouse cinema, but for most viewers, its beauty won''t be enough to offset its narrative inertia.', TO_DATE('2015-11-05', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('byzantium', 2012, 'Director Neil Jordan remains as expert as ever when it comes to setting a chilling mood, but Byzantium struggles to match its creepily alluring atmosphere with a suitably compelling story.', TO_DATE('2012-09-10', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cabaret', 2000, 'Great performances and evocative musical numbers help Cabaret secure its status as a stylish, socially conscious classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cabin fever', 2016, 'No need for a quarantine -- enthusiasm for this inert remake is not contagious.', TO_DATE('2016-02-09', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cabin in the sky', 2000, 'Cabin in the Sky overcomes some questionable storytelling choices thanks to irresistible musical numbers and a brilliantly talented cast.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cable guy', 2000, 'The Cable Guy''s dark flashes of thought-provoking, subversive wit are often -- but not always -- enough to counter its frustratingly uneven storytelling approach.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('caché', 2005, 'A creepy French psychological thriller that commands the audience''s attention throughout.', TO_DATE('2005-05-16', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('caddyshack', 1980, 'Though unabashedly crude and juvenile, Caddyshack nevertheless scores with its classic slapstick, unforgettable characters, and endlessly quotable dialogue.', TO_DATE('1980-07-25', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('caddyshack ii', 2000, 'Handicapped by a family friendly PG rating, even the talents of Caddyshack II''s all-star comic cast can''t save it from its lazy, laughless script and uninspired direction.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cadillac records', 2008, 'What Cadillac Records may lack in originality, it more than makes up for in strong performances and soul-stirring music.', TO_DATE('2008-11-26', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('café society', 2016, 'Café Society''s lovely visuals and charming performances round out a lightweight late-period Allen comedy whose genuine pleasures offset its amiable predictability.', TO_DATE('2016-05-11', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the caine mutiny', 2000, 'Humphrey Bogart is superb as a domineering captain with brittle composure in The Caine Mutiny, an inquisitive courtroom drama teeming with memorable performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cairo time', 2009, 'Though potentially too slowly paced for some, Cairo Time lingers long after the closing credits, largely due to a wonderful performance by Patricia Clarkson.', TO_DATE('2009-10-09', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cake', 2014, 'Cake finds Jennifer Aniston making the most of an overdue opportunity to test her dramatic chops, but it lacks sufficient depth or warmth to recommend for all but her most ardent fans.', TO_DATE('2014-09-09', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('calendar girls', 2003, 'A charming, but cliched comedy reminiscent of The Full Monty.', TO_DATE('2003-06-19', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('california suite', 2000, 'Maggie Smith''s acidic turn is the standout in this stacked ensemble, but broad characterizations and an unsure tone make for a disappointingly uneven adaptation of Neil Simon''s episodic play.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('california typewriter', 2017, 'California Typewriter is an affectionate, nostalgic love letter to the typed word from enthusiasts and experts alike.', TO_DATE('2017-01-06', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('call me by your name', 2017, 'Call Me by Your Name offers a melancholy, powerfully affecting portrait of first love, empathetically acted by Timothée Chalamet and Armie Hammer.', TO_DATE('2017-01-23', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('call me kuchu', 2012, 'Alternately horrific and uplifting, Call Me Kuchu exposes heinous systematic brutality with a clear eye and admirable precision.', TO_DATE('2012-09-17', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('callas forever', 2004, 'An uneven biopic that struggles to convey what made its subject special, Callas Forever is far from a definitive look at the life of this brilliant opera diva.', TO_DATE('2004-06-21', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('calle 54', 2000, 'A loving tribute to Latin Jazz artists where music does the talking.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('calvary', 2014, 'Led by a brilliant performance from Brendan Gleeson, Calvary tackles weighty issues with humor, intelligence, and sensitivity.', TO_DATE('2014-01-20', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cam', 2018, 'Smart and suspenseful, CAM is a techno-thriller that''s far more than the sum of its salacious parts -- and an outstanding showcase for Madeline Brewer in the leading role.', TO_DATE('2018-07-20', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cameraperson', 2016, 'Fresh and inventive yet immediately accessible, Cameraperson distills its subject''s life and career into an experience that should prove immediately absorbing even for those unfamiliar with her work.', TO_DATE('2016-01-26', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('camille claudel 1915', 2013, 'Camille Claudel, 1915 isn''t an easy watch, but Juliette Binoche''s excellent performance makes it worth the effort.', TO_DATE('2013-09-06', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('camp', 2003, 'Campy comedy that squeaks by on its charms.', TO_DATE('2003-02-01', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('camp rock', 2008, 'Camp Rock wants to be the next High School Musical, but its forgettable songs and dull premise hold it back.', TO_DATE('2008-08-18', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('camp xray', 2014, 'Camp X-Ray''s treatment of its subject verges on the shallow, but benefits greatly from a pair of impressive performances from Kristen Stewart and Peyman Moaadi.', TO_DATE('2014-01-19', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the candidate', 2000, 'The Candidate may not get all the details right when it comes to modern campaigning, but it captures political absurdity perfectly -- and boasts typically stellar work from Robert Redford to boot.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('candy', 2006, 'Stars Heath Ledger and Abbie Cornish look better than they should as heroin addicts, and their characters are too absorbed and self-pitying to be totally compelling.', TO_DATE('2006-06-15', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('candyman', 2000, 'Though it ultimately sacrifices some mystery in the name of gory thrills, Candyman is a nuanced, effectively chilling tale that benefits from an interesting premise and some fine performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('candyman farewell to the flesh', 2000, 'Doubling down on gore while largely abandoning the subtext and wit that made the original worthwhile, Candyman: Farewell to the Flesh disappoints.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('caniba', 2017, 'In terms of form as well as content, Caniba is decidedly not for everyone, but its story - and the questions it poses - are hard to ignore.', TO_DATE('2017-09-05', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cannibal the musical alferd packer the musical', 2000, 'If you''re only going to watch one black comedy about a real-life explorer whose fellow travelers ended up eaten, make it Cannibal! The Musical.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cant buy me love', 2000, 'While Can''t Buy Me Love gets some value out of its plucky leads, this romantic comedy struggles to find grace in a cynical conceit that belongs in the bargain bin.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cant hardly wait', 2000, 'Occasionally clever and moderately intelligent, Can''t Hardly Wait also contains too many cheap laughs, recycled plotting, and flat characters.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('capernaum capharnaüm', 2018, 'Capernaum hits hard, but rewards viewers with a smart, compassionate, and ultimately stirring picture of lives in the balance.', TO_DATE('2018-05-18', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('capital in the twentyfirst century', 2019, 'Capital in the Twenty-First Century can''t hope to address its subject with the depth of its source material, but the end result remains an eye-opening overview.', TO_DATE('2019-10-10', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('capitalism a love story', 2009, 'Love him or hate him, Capitalism captures Michael Moore in his muckraking element -- with all the Moore-centric showmanship that entails.', TO_DATE('2009-09-09', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('capone', 2020, 'Tom Hardy makes the most of his opportunity to tackle a challenging role, but Capone is too haphazardly constructed to support his fascinating performance.', TO_DATE('2020-05-11', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('capricorn one', 2000, 'A string of questionable plot contrivances threaten to bury its story, but Capricorn One manages to unfurl an amusing, sharply cynical conspiracy yarn.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('captain abu raed', 2007, 'A poetic and deeply felt debut by director Amin Matalqa, Captain Abu Raed is simultaneously mythic and melodramatic.', TO_DATE('2007-12-11', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('captain america', 2002, 'Lacking a script, budget, direction, or star capable of doing justice to its source material, this Captain America should have been left under the ice.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('captain america civil war', 2016, 'Captain America: Civil War begins the next wave of Marvel movies with an action-packed superhero blockbuster boasting a decidedly non-cartoonish plot and the courage to explore thought-provoking themes.', TO_DATE('2016-04-13', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('captain america the first avenger', 2011, 'With plenty of pulpy action, a pleasantly retro vibe, and a handful of fine performances, Captain America is solidly old-fashioned blockbuster entertainment.', TO_DATE('2011-07-19', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('captain america the winter soldier', 2014, 'Suspenseful and politically astute, Captain America: The Winter Soldier is a superior entry in the Avengers canon and is sure to thrill Marvel diehards.', TO_DATE('2014-03-20', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('captain corellis mandolin', 2001, 'The cinematography is gorgeous, but the movie plays it fast and loose with history and the novel it was adapted from. Mostly, the movie fails because the romance between the leads strains credulity and the story is largely uninvolving.', TO_DATE('2001-04-16', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('captain fantastic', 2016, 'Captain Fantastic''s thought-provoking themes -- and an absorbing starring turn from Viggo Mortensen -- add up to an above-average family drama with unexpected twists.', TO_DATE('2016-01-24', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('captain marvel', 2019, 'Packed with action, humor, and visual thrills, Captain Marvel introduces the MCU''s latest hero with an origin story that makes effective use of the franchise''s signature formula.', TO_DATE('2019-03-05', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('captain phillips', 2013, 'Smart, powerfully acted, and incredibly intense, Captain Phillips offers filmgoers a Hollywood biopic done right -- and offers Tom Hanks a showcase for yet another brilliant performance.', TO_DATE('2013-09-06', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('captain ron', 2000, 'Despite the swashbuckling charms of Kurt Russell''s seafaring antics, Captain Ron capsizes in its hackneyed narrative waters.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('captain underpants the first epic movie captain underpants', 2017, 'With a tidy plot, clean animation, and humor that fits its source material snugly, Captain Underpants: The First Epic Movie is entertainment that won''t drive a wedge between family members.', TO_DATE('2017-05-31', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('captive', 2015, 'Captive undermines committed performances from Kate Mara and David Oyelowo -- and the real-life story they''re dramatizing -- with a thin script doubling as an ad for a self-help book.', TO_DATE('2015-09-17', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('captive state', 2019, 'This sci-fi thriller may not necessarily leave viewers in a Captive State, but it offers reasonably diverting alien invasion action with ambitious political undertones.', TO_DATE('2019-03-14', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('captivity', 2007, 'Lacking scares or psychological insight, Captivity is a distasteful entry in the ''torture porn'' subgenre.', TO_DATE('2007-06-16', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('capturing the friedmans', 2003, 'A haunting depiction of a disintegrating family, and a powerful argument on the elusiveness of truth.', TO_DATE('2003-02-06', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('caramel', 2007, 'Caramel is both an astute cultural study, and a charming comedic drama from a talented newcomer.', TO_DATE('2007-05-22', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('careful what you wish for', 2015, 'Audiences yearning for a modern update on the erotic thriller formula will be sorely disappointed by this turgid incarnation, hobbled by stale plotting and a curious lack of sensuality.', TO_DATE('2015-08-06', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cargo', 2017, 'Cargo takes a refreshingly character-driven approach to the zombie genre that''s further distinguished by its Australian setting and Martin Freeman''s terrific lead performance.', TO_DATE('2017-10-08', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('carlitos way', 1993, 'Carlito''s Way reunites De Palma and Pacino for a more wistful take on the crime epic, delivering a stylish thriller with a beating heart beneath its pyrotechnic performances and set pieces.', TO_DATE('1993-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('carlos', 2010, 'Despite its hefty running time, Carlos moves along briskly, thanks to an engaging story, exotic locales, and a breakout performance by Edgar Ramirez.', TO_DATE('2010-10-11', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('carnage', 2011, 'It isn''t as compelling on the screen as it was on the stage, but Carnage makes up for its flaws with Polanski''s smooth direction and assured performances from Winslet and Foster.', TO_DATE('2011-09-01', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('carnal knowledge', 2000, 'Although it comes lopsidedly from the male gaze, Carnal Knowledge is a sexually frank and ferociously well-acted battle between the sexes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('carol', 2015, 'Shaped by Todd Haynes'' deft direction and powered by a strong cast led by Cate Blanchett and Rooney Mara, Carol lives up to its groundbreaking source material.', TO_DATE('2015-05-16', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('carpool', 1996, 'Not even an HOV lane amid a traffic jam is worth boarding this aggravating and unfunny Carpool.', TO_DATE('1996-08-23', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('carrie', 2013, 'It boasts a talented cast, but Kimberly Peirce''s "reimagining" of Brian De Palma''s horror classic finds little new in the Stephen King novel -- and feels woefully unnecessary.', TO_DATE('2013-10-17', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cars', 2006, 'Cars offers visual treats that more than compensate for its somewhat thinly written story, adding up to a satisfying diversion for younger viewers.', TO_DATE('2006-02-09', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cars 2', 2011, 'Cars 2 is as visually appealing as any other Pixar production, but all that dazzle can''t disguise the rusty storytelling under the hood.', TO_DATE('2011-06-19', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cars 3', 2017, 'Cars 3 has an unexpectedly poignant story to go with its dazzling animation, suggesting Pixar''s most middle-of-the-road franchise may have a surprising amount of tread left.', TO_DATE('2017-06-12', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cartel land', 2015, 'Raw, brutal, and bitter, Cartel Land offers a ground-level look at vigilante efforts to thwart organized crime at the Mexican-American border.', TO_DATE('2015-01-24', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('casa de los babys', 2003, 'Well-acted and thought provoking, if not completely satisfying.', TO_DATE('2003-08-09', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('casa de mi padre', 2012, 'Thinly written and not as funny as it needs to be, Casa de mi Padre would have worked better as a fake trailer or short film; stretched to feature length, it wears out its welcome far too quickly.', TO_DATE('2012-03-11', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('case 39', 2009, 'Director Christian Alvert has a certain stylish flair, but it''s wasted on Case 39''s frightless, unoriginal plot.', TO_DATE('2009-09-10', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cashback', 2006, 'An unlikable protagonist, messy editing, and gratuitous nudity might make audiences ask for their cash back.', TO_DATE('2006-09-16', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('casino jack', 2010, 'Kevin Spacey turns in one of his stronger performances, but Casino Jack is a disappointingly uneven fictionalized account of a fascinating true story.', TO_DATE('2010-09-09', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('casino jack and the united states of money', 2010, 'Casino Jack''s subject matter is enraging, but in the hands of director Alex Gibney, it''s also well-presented and briskly entertaining.', TO_DATE('2010-04-06', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('casino royale', 2006, 'Casino Royale disposes of the silliness and gadgetry that plagued recent James Bond outings, and Daniel Craig delivers what fans and critics have been waiting for: a caustic, haunted, intense reinvention of 007.', TO_DATE('2006-11-05', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('casper', 2000, 'A meandering, mindless family movie that frequently resorts to special effects and transparent sappiness.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cassandras dream', 2007, 'Colin Farrell and Tom Wilkinson act up a storm in Cassandra''s Dream, but Woody Allen''s heavy-handed symbolism and foreshadowing drains the plot of all tension.', TO_DATE('2007-09-05', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cast away', 2000, 'Flawed but fascinating, Cast Away offers an intelligent script, some of Robert Zemeckis'' most mature directing, and a showcase performance from Tom Hanks.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('castle in the ground', 2019, 'While it''s far from a feelgood drama, the well-acted Castle in the Ground approaches addiction with admirable honesty.', TO_DATE('2019-09-06', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('casualties of war', 1989, 'Casualties of War takes a harrowing plunge into the Vietnam War with a well-acted ensemble piece that ranks among director Brian De Palma''s more mature efforts.', TO_DATE('1989-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dr seuss the cat in the hat', 2003, 'Filled with double entendres and potty humor, this Cat falls flat.', TO_DATE('2003-11-18', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('catch22', 2000, 'Catch-22 takes entertainingly chaotic aim at the insanity of armed conflict, supported by a terrific cast and smart, funny work from Buck Henry and Mike Nichols.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('catch a fire', 2006, 'No stranger to the political thriller, director Phillip Noyce tackles apartheid and terrorism with experienced gusto, while Derek Luke and Tim Robbins hand in nuanced performances.', TO_DATE('2006-09-09', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('catch and release', 2006, 'A romantic dramedy with boring, stock characters and contrived situations.', TO_DATE('2006-10-23', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('catch me if you can', 2002, 'With help from a strong performance by Leonardo DiCaprio as real-life wunderkind con artist Frank Abagnale, Steven Spielberg crafts a film that''s stylish, breezily entertaining, and surprisingly sweet.', TO_DATE('2002-07-28', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('catch that kid', 2004, 'An unimaginative heist movie aimed strictly at the preteen set.', TO_DATE('2004-01-31', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('caterina in the big city', 2004, 'This witty movie succeeds as both a modest teen coming-of-age story and a satirical microcosm of Italy''s political climate.', TO_DATE('2004-06-03', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('catfight', 2016, 'Smart, suitably nasty, and well-cast, Catfight lands narrative punches just as fast and hard-hitting as the physical violence doled out onscreen.', TO_DATE('2016-09-11', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('catfish', 2010, 'Catfish may tread the line between real-life drama and crass exploitation a little too unsteadily for some viewers'' tastes, but its timely premise and tightly wound mystery make for a gripping documentary.', TO_DATE('2010-02-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cats', 2019, 'Despite its fur-midable cast, this Cats adaptation is a clawful mistake that will leave most viewers begging to be put out of their mew-sery.', TO_DATE('2019-12-18', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cats dogs', 2001, 'A great concept, but the movie fails to develop the characters and some of the jokes are hit-or-miss.', TO_DATE('2001-06-29', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cats dogs the revenge of kitty galore', 2010, 'Dull and unfunny, this inexplicable sequel offers little more than the spectacle of digitally rendered talking animals with celebrity voices.', TO_DATE('2010-07-26', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cats dont dance', 2000, 'Cats Don''t Dance, but they should easily entertain all-ages audiences thanks to some colorful animation, sharp humor, and a catchy soundtrack.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stephen kings cats eye', 2001, 'An effective if knowingly silly Stephen King anthology that combines comedy and terror.', TO_DATE('2001-01-01', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cats meow', 2001, 'The Cat''s Meow is a deliciously evoked period piece and whodunit.', TO_DATE('2001-11-02', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('catwoman', 2004, 'Halle Berry is the lone bright spot, but even she can''t save this laughable action thriller.', TO_DATE('2004-07-19', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cavalcade', 1933, 'Though solidly acted and pleasant to look at, Cavalcade lacks cohesion, and sacrifices true emotion for mawkishness.', TO_DATE('1933-01-01', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cave', 2005, 'Despite its stylized and impressive sets, this horror-monster movie mish-mash suffers from endless cliches and wildly implausible plotlines.', TO_DATE('2005-08-24', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cave of forgotten dreams', 2010, 'Hauntingly filmed and brimming with Herzog''s infectious enthusiasm, Cave of Forgotten Dreams is a fascinating triumph.', TO_DATE('2010-09-15', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cave of the yellow dog die hohle des gelben hundes', 2006, 'A sparse, hauntingly beautiful journey across continents and cultures.', TO_DATE('2006-10-28', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cbgb', 2013, 'Hey! Ho! No no!', TO_DATE('2013-09-12', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cecil b demented', 2000, 'The idea behind John Waters'' latest has much potential, but the movie ends up being too sloppy and underdeveloped in terms of script and direction. Also, by today''s standards, it fails to shock.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cedar rapids', 2011, 'It''s as conventional as its Midwestern setting, but Cedar Rapids boasts a terrific cast and a script that deftly blends R-rated raunch and endearing sweetness.', TO_DATE('2011-01-25', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('celeste and jesse forever', 2012, 'While it doesn''t subvert the genre as incisively as it thinks it does, Celeste and Jesse Forever is a shrewd rom-com that benefits from its likable cast and trumpets the arrival of Rashida Jones as a bona fide big screen talent.', TO_DATE('2012-01-21', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cell', 2016, 'Shoddily crafted and devoid of suspense, Cell squanders a capable cast and Stephen King''s once-prescient source material on a bland rehash of zombie cliches.', TO_DATE('2016-06-13', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cellular', 2004, 'Though it''s gimmicky and occasionally feels like a high-end cell phone ad, Cellular is also an energetic and twisty thriller.', TO_DATE('2004-09-02', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the celluloid closet', 1996, 'The Celluloid Closet takes a thought-provoking look at the decades of omission and misrepresentation endured by the gay community in mainstream cinema.', TO_DATE('1996-03-15', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cemetery junction', 2010, 'It fails to challenge the well-established conventions of its storyline, but Cemetery Junction benefits from the genuine warmth of its script, as well as its refusal to give in to cheap nostalgia.', TO_DATE('2010-03-16', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the center of the world', 2001, 'For all its tease, the movie doesn''t have more to say than money can''t buy you love.', TO_DATE('2001-03-01', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('center stage', 2000, 'Viewers willing to sit through soapy plot contrivances to see some excellent dancing might enjoy Center Stage; for everyone else, there''s still always Fame.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('centigrade', 2020, 'A survival thriller largely bereft of thrills, Centigrade may leave audiences feeling just as hopelessly trapped as the main characters.', TO_DATE('2020-08-17', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('central station central do brasil', 2000, 'Director Salles transcends road-movie clichés and crafts a film that is as moving as it is universal.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('central intelligence', 2016, 'Kevin Hart and Dwayne Johnson make for well-matched comic foils, helping Central Intelligence overcome a script that coasts on their considerable chemistry.', TO_DATE('2016-06-15', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('centurion', 2010, 'It''s a bloody geyser of Neil Marshall''s typically stylish B-movie action, but Centurion is too focused on hacking and slashing to deliver original dialogue or interesting characters.', TO_DATE('2010-04-06', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('certain women', 2016, 'Certain Women further demonstrates writer-director Kelly Reichardt''s gift for telling the stories of ordinary people with uncommon empathy and skill.', TO_DATE('2016-01-24', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('certified copy copie conforme', 2010, 'The main stars are absolutely perfect in this absorbing, existential drama that dissects human relationships.', TO_DATE('2010-08-29', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cesar chavez', 2014, 'Too in awe of its subject''s great works to present him as a human being, Cesar Chávez settles for trite hagiography.', TO_DATE('2014-02-14', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chalet girl', 2011, 'Chalet Girl is light comedic fun geared for teenage girls, featuring a charming performance from Felicity Jones.', TO_DATE('2011-02-10', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chalk', 2006, 'Chalk approaches its potentially rich subject matter with a light touch, but still emerges with a humorous, heartfelt tribute to a noble profession.', TO_DATE('2006-12-30', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chan is missing', 1982, 'An entertaining mystery that''s also rich in setting and character detail, Chan Is Missing suggests thrilling potential from director/co-writer Wayne Wang.', TO_DATE('1982-06-04', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chandni chowk to china', 2009, 'A thin plot is disguised by high octane dancing and action in this Bollywood crossover comedy.', TO_DATE('2009-01-14', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the changeling', 2002, 'George C. Scott''s somber performance gives this haunted house horror a moving soul to go along with its harrowing scares.', TO_DATE('2002-07-29', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('changing lanes', 2002, 'Though some may find its conclusion unsatisfying, Changing Lanes is a tense, well-crafted exploration of meaty ethical dilemmas.', TO_DATE('2002-04-05', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chaos theory', 2008, 'Ryan Reynolds and Emily Mortimer do what they can, but ultimately Chaos Theory is an overly conventional dramedy.', TO_DATE('2008-03-13', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chaplin', 1992, 'Chaplin boasts a terrific performance from Robert Downey, Jr. in the title role, but it isn''t enough to overcome a formulaic biopic that pales in comparison to its subject''s classic films.', TO_DATE('1992-12-18', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chappaquiddick', 2017, 'Chappaquidick can''t help leaving some of this true story''s most intriguing questions unanswered, but it''s bolstered by outstanding work from Jason Clarke in the central role.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chappie', 2015, 'Chappie boasts more of the big ideas and visual panache that director Neill Blomkamp has become known for -- and, sadly, more of the narrative shortcomings.', TO_DATE('2015-03-04', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chariots of fire', 2000, 'Decidedly slower and less limber than the Olympic runners at the center of its story, the film nevertheless manages to make effectively stirring use of its spiritual and patriotic themes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('charlie and the chocolate factory', 2005, 'Closer to the source material than 1971''s Willy Wonka & the Chocolate Factory, Charlie and the Chocolate Factory is for people who like their Chocolate visually appealing and dark.', TO_DATE('2005-07-10', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('charlie bartlett', 2007, 'With engaging performances marked by an inconsistent tone, Charlie Bartlett is a mixed bag of clever teen angst comedy and muddled storytelling.', TO_DATE('2007-05-01', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('charlie countryman', 2013, 'Shia LaBeouf clearly relishes his role in Charlie Countryman, but his efforts can''t salvage the movie''s shallow script and overstuffed direction.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('charlie says', 2018, 'Charlie Says approaches its infamous subject from a welcome new angle, but suffers from a disappointing lack of depth in its treatment of the story.', TO_DATE('2018-09-04', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('charlie st cloud', 2010, 'Zac Efron gives it his all, but Charlie St. Cloud is too shallow and cloying to offer much more than eye candy for his fans.', TO_DATE('2010-07-25', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('charlie wilsons war', 2007, 'Charlie Wilson''s War manages to entertain and inform audiences, thanks to its witty script and talented cast of power players.', TO_DATE('2007-11-27', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('charlies angels', 2000, 'Mixing tongue-in-cheek cheesecake with glossy action set pieces, Charlie''s Angels is slick and resonably fun despite its lack of originality.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('charlies angels', 2019, 'Earnest and energetic, if a bit uneven, Elizabeth Banks''s pulpy Charlie''s Angels adds new flair to the franchise with fun performances from its three leads.', TO_DATE('2019-11-12', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('charlies angels full throttle', 2003, 'Eye candy for those who don''t require a movie to have a plot or for it to make sense.', TO_DATE('2003-06-20', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('charlotte gray', 2001, 'A dull adaptation of Sebastian Faulk''s novel despite gorgeous cinematography and Cate Blanchett''s best efforts.', TO_DATE('2001-12-16', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('charlottes web', 2006, 'Kids will be entertained by the straightforward plot and cute animals, and adults will be charmed by how quiet and humble the production is, a fine translation of E.B. White''s genteel prose.', TO_DATE('2006-12-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chasing amy', 2000, 'Although Chasing Amy''s depiction of queer sexuality is frustratingly clumsy, it handles an array of thorny themes with a mixture of sensitivity, raw honesty, and writer-director Kevin Smith''s signature raunchy humor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chasing coral', 2017, 'Chasing Coral offers a breathtakingly beautiful look at some of the Earth''s most incredible natural wonders while delivering a sobering warning about their uncertain future.', TO_DATE('2017-01-22', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chasing ice', 2012, 'Chasing Ice captures the urgency of climate change while prevailing as entertainment, thanks the awe-inspiring scenery and James Balog''s charisma.', TO_DATE('2012-01-26', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chasing liberty', 2004, 'Formulaic comfort food for the teen crowd.', TO_DATE('2004-01-05', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chasing madoff', 2011, 'Chasing Madoff admirably highlights Harry Markopolos'' perilous crusade against one of history''s biggest frauds, but the documentary''s disinterest in Madoff himself makes it feel like only half the story.', TO_DATE('2011-08-15', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chasing mavericks', 2012, 'It''s sweet, gentle, and affably modest, but Chasing Mavericks is ultimately pulled under by an unconvincing script and a puzzling lack of energy.', TO_DATE('2012-10-25', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chasing papi', 2003, 'Obnoxious in tone and unable to provide its trio of stars a decent quip, Chasing Papi will have audiences running in the other direction.', TO_DATE('2003-04-14', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chasing trane the john coltrane documentary', 2017, 'Chasing Trane: The John Coltrane Documentary can''t hope to truly capture its subject''s freewheeling creative spirit, but it''s still an engaging overview for fans as well as the uninitiated.', TO_DATE('2017-04-05', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chavela', 2017, 'Chavela pays affecting tribute to its subject with an absorbing documentary that outlines her remarkable life while effectively communicating the power and lingering impact of her art.', TO_DATE('2017-02-12', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('che part two guerrilla', 2008, 'The second part of Soderbergh''s biopic is a dark, hypnotic and sometimes frustrating portrait of a warrior in decline, with a terrific central performance from Del Toro.', TO_DATE('2008-12-27', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cheap thrills', 2013, 'Gleefully nasty and darkly hilarious, Cheap Thrills lives down to its title in the best possible way.', TO_DATE('2013-03-09', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cheaper by the dozen', 2003, 'In this family of twelve children, much chaos ensues, but little hilarity.', TO_DATE('2003-11-28', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cheaper by the dozen 2', 2005, 'A sequel to a remake, Cheaper 2 wastes its solid cast in scenes of over-the-top, predictable humor.', TO_DATE('2005-12-16', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chef', 2014, 'Chef''s charming cast and sharp, funny script add enough spice to make this feel-good comedy a flavorful -- if familiar -- treat.', TO_DATE('2014-03-08', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chef flynn', 2018, 'Chef Flynn might have cut a little deeper into its subject''s story, but this entertaining overview of a precocious talent''s rise to acclaim still has enough flavor to satisfy.', TO_DATE('2018-01-23', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chelsea on the rocks', 2009, 'Abel Ferrara''s loving portrait of New York''s Chelsea Hotel is less interested in telling the story of its famous residents than in exploring the magic of the place that housed so many moments in rock history.', TO_DATE('2009-03-12', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chelsea walls', 2002, 'The meandering Chelsea Walls is more pretentious than poetic.', TO_DATE('2002-04-11', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chéri', 2009, 'A too-short script and a romance lacking in heat detracts from an otherwise haughty charmer.', TO_DATE('2009-02-27', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cherish', 2002, 'The different genres in Cherish don''t mesh well, and the quirkiness sometimes feels too forced.', TO_DATE('2002-04-08', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chernobyl diaries', 2012, 'Despite an interesting premise and spooky atmospherics, Chernobyl Diaries is mostly short on suspense and originality.', TO_DATE('2012-05-24', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cherry 2000', 2001, 'While Cherry 2000 has a certain low-budget appeal, all but the most ardent genre enthusiasts are likely to find its silly story and uneven performances unintentionally amusing.', TO_DATE('2001-03-22', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chiraq', 2015, 'Chi-Raq is as urgently topical and satisfyingly ambitious as it is wildly uneven -- and it contains some of Spike Lee''s smartest, sharpest, and all-around entertaining late-period work.', TO_DATE('2015-11-23', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chicago', 2002, 'A rousing and energetic adaptation of the Broadway musical, Chicago succeeds on the level pure spectacle, but provides a surprising level of depth and humor as well.', TO_DATE('2002-12-04', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chicken little', 2005, 'Disney expends more effort in the technical presentation than in crafting an original storyline.', TO_DATE('2005-10-30', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chicken run', 2000, 'Chicken Run has all the charm of Nick Park''s Wallace & Gromit, and something for everybody. The voice acting is fabulous, the slapstick is brilliant, and the action sequences are spectacular.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chicken with plums', 2011, 'Whimsical and melancholy, Chicken with Plums is visually striking and dreamily compelling despite its occasional narrative missteps.', TO_DATE('2011-09-05', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chico rita', 2010, 'Aimed at adults and animated with zest, Chico & Rita is a romantic delight packed with cultural detail and flavor.', TO_DATE('2010-09-16', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('child 44', 2015, 'There''s a gripping story at the heart of Child 44 and a solid performance from Tom Hardy in the lead, but it all still adds up to a would-be thriller that lacks sufficient thrills.', TO_DATE('2015-04-11', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('child of god', 2013, 'An obviously reverent adaptation that fails to make a case for the source material being turned into a movie, Child of God finds director James Franco outmatched by Cormac McCarthy''s novel.', TO_DATE('2013-09-13', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('children of a lesser god', 2000, 'Children of a Lesser God transcends its transparently noble goals thanks to a pair of absorbing performances from William Hurt and Marlee Matlin.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the children of huang shi', 2008, 'This beautifully photographed but dramatically flat war drama recounts an important chapter in history with little cinematic freshness.', TO_DATE('2008-05-05', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('children of men', 2006, 'Children of Men works on every level: as a violent chase thriller, a fantastical cautionary tale, and a sophisticated human drama about societies struggling to live.', TO_DATE('2006-09-04', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('children of paradise les enfants du paradis', 2000, 'Strong performances abound, and Carne''s wit and grace are evident in this masterful (if long) French epic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('children of the sea kaijû no kodomo', 2019, 'An animated adventure perhaps best appreciated as a visual experience, Children of the Sea is strikingly lovely if less than satisfying on a narrative level.', TO_DATE('2019-06-14', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('childs play', 2000, 'Child''s Play occasionally stumbles across its tonal tightrope of comedy and horror, but its genuinely creepy monster and some deft direction by Tom Holland makes this chiller stand out on the shelf.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('childs play', 2019, 'Child''s Play updates an ''80s horror icon for the Internet of Things era, with predictably gruesome -- and generally entertaining -- results.', TO_DATE('2019-06-19', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('childs pose', 2013, 'It isn''t necessarily an easy watch, but thanks to Netzer''s interesting direction and a riveting performance from Gheorghiu, Child''s Pose is rewarding.', TO_DATE('2013-07-09', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chill factor', 2000, 'Claiming it fails on every level, critics had almost nothing good to say about this movie.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chimes at midnight', 2001, 'A classic story adapted by a filmmaker near his creative peak, Chimes at Midnight unites Welles and Shakespeare - and powerfully distills the best of both.', TO_DATE('2001-09-26', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the china syndrome', 2002, 'With gripping themes and a stellar cast, The China Syndrome is the rare thriller that''s as thought-provoking as it is tense.', TO_DATE('2002-07-27', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chinatown', 2000, 'As bruised and cynical as the decade that produced it, this noir classic benefits from Robert Towne''s brilliant screenplay, director Roman Polanski''s steady hand, and wonderful performances from Jack Nicholson and Faye Dunaway.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chinese puzzle cassetête chinois', 2014, 'Pleasantly easygoing and consistently funny, Chinese Puzzle offers a suitably endearing conclusion to Cédric Klapisch''s Trilogy of Xavier.', TO_DATE('2014-04-09', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chips', 2017, 'CHiPS abandons the endearing innocence of its source material, using the titular cop show''s premise as a setup for aggressively lowbrow gags that prove only mildly arresting at best.', TO_DATE('2017-03-23', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chloe in the afternoon lamour laprèsmidi', 2000, 'Eric Rohmer''s Chloe in the Afternoon doesn''t need sparkly cinematic dross to discover unspoken, universal truths about relationships and love through filmmaking.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chocolat', 2000, 'Chocolat is a charmingly light-hearted fable with a lovely performance by Binoche.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('choke', 2008, 'While bolstered by strong performances from Sam Rockwell and Anjelica Huston, Choke struggles to capture the tone of Chuck Palahniuk''s novel.', TO_DATE('2008-01-26', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('choking man', 2006, 'Quirky animated interludes fail to lift this dull US immigrant indie out of its introverted torpid state.', TO_DATE('2006-12-30', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chopper', 2000, 'Eric Bana''s performance as the charming but twisted Chopper is the highlight of this disturbing portrait about Australia''s notorious author/criminal.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the chorus les choristes', 2004, 'While predictable, this low-key heartwarmer manages to be uplifting without overdoing the sentiment.', TO_DATE('2004-07-29', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a chorus line', 2000, 'On stage, A Chorus Line pulled back the curtain to reveal the hopes and fears of showbiz strivers, but that energy and urgency is lost in the transition to the big screen.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chris don', 2008, 'Chris and Don paints an affecting, enlightening portrait of a one-of-a-kind love affair.', TO_DATE('2008-05-05', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chris rock tamborine', 2018, 'Chris Rock reasserts his credentials as one of comedy''s preeminent figures in Tamborine, an introspective standup act delivered with fresh sensitivity and trademark exuberance.', TO_DATE('2018-02-14', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('christine', 2000, 'The cracks are starting to show in John Carpenter''s directorial instincts, but Christine is nonetheless silly, zippy fun.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('christine', 2016, 'Rising on the strength of Rebecca Hall''s gripping performance, Christine offers an empathetic look at its subject''s public career and painful private life.', TO_DATE('2016-01-24', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('christmas with the kranks', 2004, 'A mirthless movie as fresh as last year''s fruit cake, Christmas with the Kranks is a coarse, garish comedy that promotes conformity.', TO_DATE('2004-11-16', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('christopher robin', 2018, 'Christopher Robin may not equal A.A. Milne''s stories -- or their animated Disney adaptations -- but it should prove sweet enough for audiences seeking a little childhood magic.', TO_DATE('2018-08-02', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chronic', 2015, 'Chronic demands patience from the viewer -- and yields rich dividends with an affecting story and a committed starring performance by Tim Roth.', TO_DATE('2015-09-25', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chronicle', 2012, 'Chronicle transcends its found-footage gimmick with a smart script, fast-paced direction, and engaging performances from the young cast.', TO_DATE('2012-01-20', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the chronicles of narnia the lion the witch and the wardrobe', 2005, 'With first-rate special effects and compelling storytelling, this adaptation stays faithful to its source material and will please moviegoers of all ages.', TO_DATE('2005-01-28', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the chronicles of narnia prince caspian', 2008, 'The Chronicles of Narnia: Prince Caspian is an entertaining family adventure worthy of the standard set by its predecessor.', TO_DATE('2008-05-09', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the chronicles of narnia the voyage of the dawn treader', 2010, 'Its leisurely, businesslike pace won''t win the franchise many new fans, but Voyage of the Dawn Treader restores some of the Narnia franchise''s lost luster with strong performances and impressive special effects.', TO_DATE('2010-11-30', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the chronicles of riddick', 2004, 'As an action movie, Riddick offers some thrills, but as a sequel to Pitch Black, it''s a disappointment.', TO_DATE('2004-04-16', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chrystal', 2004, 'Where Chrystal''s going isn''t always clear, but this slow-burning story proves effective -- and marks writer-director-star McKinnon as a multi-hyphenated talent to watch.', TO_DATE('2004-03-03', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('chuck buck', 2000, 'As poignant as it is unsettling, Chuck & Buck uses the complex dynamic between two men as fuel for untangling a rich assortment of thought-provoking themes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the chumscrubber', 2005, 'This derivative poke at suburbia falls short of delivering a scathing indictment of upper middle-class disconnect.', TO_DATE('2005-04-20', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('churchill', 2017, 'Churchill gets sterling work out of Brian Cox in the leading role, but it isn''t enough to overcome a muddled and ultimately unsuccessful approach to an incredible real-life story.', TO_DATE('2017-05-29', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cidade dos homens city of men', 2007, 'Brutal and unflinching, City of Men is both a harrowing look at Brazil''s favela life, and a touching tale of youths rushed into adulthood.', TO_DATE('2007-12-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cider house rules', 2000, 'The Cider House Rules derives affecting drama from wonderful performances, lovely visuals, and an old-fashioned feel.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cinderella', 2000, 'The rich colors, sweet songs, adorable mice and endearing (if suffering) heroine make Cinderella a nostalgically lovely charmer.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cinderella', 2015, 'Refreshingly traditional in a revisionist era, Kenneth Branagh''s Cinderella proves Disney hasn''t lost any of its old-fashioned magic.', TO_DATE('2015-02-13', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cinderella man', 2005, 'With grittiness and an evocative sense of time and place, Cinderella Man is a powerful underdog story. And Ron Howard and Russell Crowe prove to be a solid combination.', TO_DATE('2005-05-05', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a cinderella story', 2004, 'An uninspired, generic updating of the classic fairy tale.', TO_DATE('2004-07-10', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cinema paradiso nuovo cinema paradiso', 2000, 'Cinema Paradiso is a life-affirming ode to the power of youth, nostalgia, and the the movies themselves.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cinema verite', 2011, 'Cinema Verite is a disappointingly incurious dive into the birth of reality television, but terrific performances and the inherent intrigue behind the making of An American Family keep this drama compelling.', TO_DATE('2011-05-26', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('circumstance', 2011, 'A thought-provoking, insightful look into Iranian youth culture.', TO_DATE('2011-04-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('circus of books', 2019, 'Like the cheekily named store at this documentary''s center, Circus of Books proves there are countless stories below the surface if we''re only willing to look.', TO_DATE('2019-04-29', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cirque du soleil worlds away', 2012, 'Cirque Du Soleil loses its sense of wonder when bottled for the screen, with Worlds Away''s shapeless story and relentless spectacle feeling hollow when divorced from the theatrical experience.', TO_DATE('2012-12-18', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('citizen jane battle for the city', 2016, 'Citizen Jane: Battle for the City offers a compelling overview of an influential activist''s importance -- and underscores why the spirit of her work remains crucial today.', TO_DATE('2016-11-12', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('citizen kane', 1941, 'Orson Welles''s epic tale of a publishing tycoon''s rise and fall is entertaining, poignant, and inventive in its storytelling, earning its reputation as a landmark achievement in film.', TO_DATE('1941-05-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('citizen ruth', 2000, 'Smart and sharply funny, Citizen Ruth is an entertaining look at a tough subject -- and an impressive calling card for debuting director/co-writer Alexander Payne.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('citizenfour', 2014, 'Part real-life thriller, part sobering examination of 21st century civil liberties, Citizenfour transcends ideology to offer riveting, must-see cinema.', TO_DATE('2014-10-10', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('city by the sea', 2002, 'Even though the movie is well acted, it sinks under an abundance of melodrama and cliches.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('city hall', 1996, 'City Hall explores political corruption with commendable intelligence, but this web of scandal struggles to coalesce into satisfying drama.', TO_DATE('1996-02-16', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('city island', 2010, 'Raymond De Felitta combines warmth, humanity, and a natural sense of humor, and is abetted by Andy Garcia and an excellent ensemble cast.', TO_DATE('2010-03-16', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('city lights', 2000, 'One of the best underdog romance movies ever, with an ending that will light up any heart.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('city of angels', 1998, 'City of Angels may not tug the heartstrings as effortlessly as it aims to, but the end results will still leave more than a few viewers in tears.', TO_DATE('1998-04-10', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('city of ember', 2008, 'City of Ember is visually arresting, and boasts a superb cast, but is sadly lacking in both action and adventure.', TO_DATE('2008-09-25', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('city of ghosts', 2002, 'Atmospheric, but that''s about it.', TO_DATE('2002-09-20', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cidade de deus city of god', 2002, 'City of God offers a shocking and disturbing -- but always compelling -- look at life in the slums of Rio de Janiero.', TO_DATE('2002-08-21', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('city of gold', 2016, 'Even for viewers who''ve never read or heard of food critic Jonathan Gold, City of Gold offers a thoroughly entertaining introduction to a talented writer and brilliant career.', TO_DATE('2016-01-17', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the city of lost children la cité des enfants perdus', 2000, 'Not all of its many intriguing ideas are developed, but The City of Lost Children is an engrossing, disturbing, profoundly memorable experience.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the city of your final destination', 2009, 'A stellar cast can''t elevate this leaden adaptation that, while just as beautiful as anything director James Ivory''s made before, comes off as dusty and dry.', TO_DATE('2009-06-08', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('city slickers', 2000, 'With a supremely talented cast and just enough midlife drama to add weight to its wildly silly overtones, City Slickers uses universal themes to earn big laughs.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('city slickers 2 the legend of curlys gold', 1994, 'Lacking any of the charm of its predecessor, City Slickers 2 meanders around the map without ever finding comedy gold.', TO_DATE('1994-06-10', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('civic duty', 2006, 'At times a tense and provocative thriller, Civic Duty struggles to move beyond its one-note premise.', TO_DATE('2006-04-26', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a civil action', 1998, 'Intelligent and unconventional.', TO_DATE('1998-12-25', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cj7', 2008, 'Eccentric and sweet, Stephen Chow''s latest is charming, but too strangely and slackly plotted to work as a whole.', TO_DATE('2008-02-05', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the claim', 2000, 'Though it sometimes feels cold and detached, The Claim is evocative, beautifully shot, and full of understated performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('claires camera la caméra de claire', 2017, 'Claire''s Camera adds another deceptively unassuming entry to writer-director Hong Sang-soo''s oeuvre -- one whose lingering impact belies its brief length.', TO_DATE('2017-05-22', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('claras ghost', 2018, 'As idiosyncratic as it is ambitious, Clara''s Ghost can be as difficult to pin down as a spectral presence -- yet it also has a way of working itself under the skin.', TO_DATE('2018-01-19', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('clash of the titans', 1981, 'A goofy, old-school sword-and-sandal epic, Clash of the Titans mines Greek mythology for its story and fleshes it out with Ray Harryhausen''s charmingly archaic stop-motion animation techniques.', TO_DATE('1981-06-12', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wrath of the titans', 2012, 'Its 3D effects are an improvement over its predecessor''s, but in nearly every other respect, Wrath of the Titans fails to improve upon the stilted acting, wooden dialogue, and chaos-driven plot of the franchise''s first installment.', TO_DATE('2012-03-27', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('clash of the titans', 2010, 'An obviously affectionate remake of the 1981 original, Louis Leterrier''s Clash of the Titans doesn''t offer enough visual thrills to offset the deficiencies of its script.', TO_DATE('2010-03-29', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('clear and present danger', 1994, 'Perfecting the formula established in earlier installments, Clear and Present Danger reunites its predecessor''s creative core to solidly entertaining effect.', TO_DATE('1994-08-03', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('clear history', 2013, 'Its semi-improvised structure finds Larry David squarely in his wheelhouse, but with few laughs and a muddled message, it doesn''t live up to his usual standards.', TO_DATE('2013-08-01', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the clearing', 2004, 'Though it has an excellent cast, this emotionally detached movie is the kind that one admires more than enjoys.', TO_DATE('2004-02-09', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('clemency', 2019, 'Clemency mines serious social issues for gripping drama, brought to life by an outstanding cast led by Alfre Woodard.', TO_DATE('2019-01-28', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cleopatras second husband', 2000, 'Critics say Cleopatra''s Second Husband is unappetizing to watch and moves too slowly. Also, you don''t care what happens to the characters.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('clerks', 2000, 'With its quirky characters and clever, quotable dialogue, Clerks is the ultimate clarion call for slackers everywhere to unite and, uh, do something we guess?', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('clerks ii', 2006, 'Clerks II dishes up much of the graphic humor and some of the insight that made the 1994 original a cult hit.', TO_DATE('2006-05-30', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('click', 2006, 'This latest Adam Sandler vehicle borrows shamelessly from It''s A Wonderful Life and Back To The Future, and fails to produce the necessary laughs that would forgive such imitation.', TO_DATE('2006-06-16', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the client', 1994, 'The Client may not reinvent the tenets of the legal drama, but Joel Schumacher''s sturdy directorial hand and a high-caliber cast bring John Grisham''s page-turner to life with engrossing suspense.', TO_DATE('1994-07-20', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('clifford', 1994, 'Ill-conceived and desperately unfunny, Clifford stars Martin Short as a 10-year-old boy. You read that correctly. That''s the joke.', TO_DATE('1994-04-01', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cliffords really big movie', 2004, 'While a dull affair for parents, Clifford''s Really Big Movie should charm its intended preschool audience.', TO_DATE('2004-02-19', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('clockers', 2000, 'A work of mournful maturity that sacrifices little of its director''s signature energy, Clockers is an admittedly flawed drama with a powerfully urgent message.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('clockstoppers', 2002, 'A pleasant diversion for the young teens, but a waste of time for anyone older.', TO_DATE('2002-03-24', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a clockwork orange', 2000, 'Disturbing and thought-provoking, A Clockwork Orange is a cold, dystopian nightmare with a very dark sense of humor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star wars the clone wars', 2008, 'Mechanical animation and a less-than stellar script make The Clone Wars a pale shadow of George Lucas'' once great franchise.', TO_DATE('2008-07-21', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('close', 2019, 'Close puts a welcome female-fronted spin on the prototypical action thriller; unfortunately, the rest of the movie''s ingredients are tediously predictable.', TO_DATE('2019-01-16', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('close encounters of the third kind', 2000, 'Close Encounters of the Third Kind is deeply humane sci-fi exploring male obsession, cosmic mysticism, and music.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('close enemies freres ennemis', 2018, 'While Close Enemies is a perfectly well-produced film noir, it is too predictable and derivative to make an impact.', TO_DATE('2018-09-05', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('closed circuit', 2013, 'Slick and well acted, Closed Circuit unfortunately never quite works up a full head of steam, with a plot that''s alternately predictable and full of holes.', TO_DATE('2013-08-25', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('closer', 2004, 'Closer''s talented cast and Mike Nichols'' typically assured direction help smooth a bumpy journey from stage to screen.', TO_DATE('2004-07-07', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the closet le placard', 2001, 'A pleasant comedy with a great cast.', TO_DATE('2001-05-04', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('closet monster', 2016, 'Closet Monster is a unique, understated fable, buoyed by a strong performance from Connor Jessup.', TO_DATE('2016-04-21', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cloud atlas', 2012, 'Its sprawling, ambitious blend of thought-provoking narrative and eye-catching visuals will prove too unwieldy for some, but the sheer size and scope of Cloud Atlas are all but impossible to ignore.', TO_DATE('2012-09-08', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('clouds of sils maria', 2014, 'Bolstered by a trio of powerful performances from its talented leads, Clouds of Sils Maria is an absorbing, richly detailed drama with impressive depth and intelligence.', TO_DATE('2014-05-23', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cloudy with a chance of meatballs 2', 2013, 'While not as clever or inventive as its predecessor, Cloudy with a Chance of Meatballs 2 compensates with enough dazzling visuals to keep younger viewers entertained.', TO_DATE('2013-09-25', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cloverfield', 2008, 'A sort of Blair Witch Project crossed with Godzilla, Cloverfield is economically paced, stylistically clever, and filled with scares.', TO_DATE('2008-01-15', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('club dread', 2004, 'Comedy is too hit-or-miss is this slasher spoof.', TO_DATE('2004-02-20', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('clue', 2000, 'A robust ensemble of game actors elevate Clue above its schematic source material, but this farce''s reliance on novelty over organic wit makes its entertainment value a roll of the dice.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('clueless', 2000, 'A funny and clever reshaping of Emma, Clueless offers a soft satire that pokes as much fun at teen films as it does at the Beverly Hills glitterati.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('coach carter', 2004, 'Even though it''s based on a true story, Coach Carter is pretty formulaic stuff, but it''s effective and energetic, thanks to a strong central performance from Samuel L. Jackson.', TO_DATE('2004-12-08', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('coal miners daughter', 2002, 'Like a classic traditional country song, Coal Miner''s Daughter draws on time-tested formula -- and undeniable talent -- to tell a solidly affecting story.', TO_DATE('2002-10-15', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cobb', 1994, 'Tommy Lee Jones''s searing performance helps to elevate Cobb above your typical sports biopic; he''s so effective, in fact, that some may find the film unpleasant.', TO_DATE('1994-12-02', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cobra', 2002, 'A disengaged Sylvester Stallone plays the titular Cobra with no bite in this leaden action thriller, queasily fixated on wanton carnage and nothing else.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cockettes', 2002, 'Absorbing, fascinating, and finally poignant, The Cockettes provides a colorful, eye-opening view of the counterculture 1960s.', TO_DATE('2002-05-10', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cockneys vs zombies', 2012, 'If you''re interested in watching a battle between cockneys and zombies, this is the movie for you.', TO_DATE('2012-08-15', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cocktail', 2000, 'There are no surprises in Cocktail, a shallow, dramatically inert romance that squanders Tom Cruise''s talents in what amounts to a naive barkeep''s banal fantasy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('coco', 2017, 'Coco''s rich visual pleasures are matched by a thoughtful narrative that takes a family-friendly -- and deeply affecting -- approach to questions of culture, family, life, and death.', TO_DATE('2017-10-21', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('coco before chanel', 2009, 'Though it doesn''t quite capture the complexity of its subject''s life, Coco Avant Chanel remains a fascinating, appropriately lovely tribute.', TO_DATE('2009-04-24', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('coco chanel igor stravinsky', 2009, 'It''s well-acted and beautifully filmed, but Jan Kounen''s dramatization of the affair between his famous subjects is curiously short on passion.', TO_DATE('2009-10-13', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('code 46', 2003, 'Code 46 crafts an intriguing hypothetical future and populates it with characters who never engage, producing a slick sci-fi package without any humanity to power it.', TO_DATE('2003-09-05', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('code black', 2013, 'Impassioned and infuriating, Code Black awakens viewers to an endemic problem with no clear solution.', TO_DATE('2013-06-20', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('code name the cleaner', 2007, 'Code Name: The Cleaner is a limp action/comedy flick that alternates between lame, worn-out jokes and cheesy martial arts.', TO_DATE('2007-01-03', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('code unknown code inconnu récit incomplet de divers voyages', 2001, 'Though challengingly cryptic at times, Code Unknown still manages to resonate.', TO_DATE('2001-07-03', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('coffee and cigarettes', 2003, 'Episodes vary in quality, but overall this talky film is quirkily engaging.', TO_DATE('2003-12-03', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('coffee kareem', 2020, 'An awkward blend of kid-friendly premise and thoroughly adult humor, Coffee & Kareem proves a distinctly unarresting odd couple comedy.', TO_DATE('2020-04-02', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('coffy', 2001, 'Pam Grier brings spunk and vinegar to Coffy, supported by director Jack Hill''s combustible mixture of authentic grit and salacious thrills.', TO_DATE('2001-10-23', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cog', 2013, 'C.O.G.''s plot is a bit meandering, but the characters are always compelling and the ending is richly rewarding.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('coherence', 2014, 'A case study in less-is-more filmmaking, Coherence serves as a compelling low-budget calling card for debuting writer-director James Ward Byrkit.', TO_DATE('2014-03-14', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cold comes the night', 2013, 'Despite strong performances from Bryan Cranston and Alice Eve, Cold Comes the Night is undone by a series of illogical plot twists.', TO_DATE('2013-09-15', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cold creek manor', 2003, 'The plot of Cold Creek Manor is too predictable and contrived to generate suspense.', TO_DATE('2003-09-11', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cold in july', 2014, 'Boasting plenty of twists, a suitably seedy tone, and a memorable supporting turn from Don Johnson, Cold in July proves an uncommonly rewarding thriller.', TO_DATE('2014-01-19', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cold mountain', 2003, 'The well-crafted Cold Mountain has an epic sweep and captures the horror and brutal hardship of war.', TO_DATE('2003-09-16', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cold pursuit', 2019, 'Cold Pursuit delivers the action audiences expect from a Liam Neeson thriller -- along with humor and a sophisticated streak that make this an uncommonly effective remake.', TO_DATE('2019-01-28', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cold skin', 2017, 'Cold Skin exerts a strong visual pull, even if all that icy atmosphere isn''t a truly satisfying substitute for a story that dares to go somewhere different.', TO_DATE('2017-10-14', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cold souls', 2009, 'Straddling existential drama and surrealist comedy, Sophie Barthes debut feature is beautifully shot and full of inventive quandaries.', TO_DATE('2009-03-27', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cold weather', 2010, 'For viewers who manage to stay invested in its occasionally aimless story, Cold Weather proves a surprisingly sophisticated blend of mumblecore and indie noir.', TO_DATE('2010-03-18', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('colette', 2018, 'Formally familiar but a brilliant match for its lead, Colette is a thoroughly entertaining biopic and an overdue testament to Keira Knightley''s underrated gifts.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('collateral', 2004, 'Driven by director Michael Mann''s trademark visuals and a lean, villainous performance from Tom Cruise, Collateral is a stylish and compelling noir thriller.', TO_DATE('2004-05-10', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('collateral beauty', 2016, 'Well-meaning but fundamentally flawed, Collateral Beauty aims for uplift but collapses in unintentional hilarity.', TO_DATE('2016-12-13', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('college road trip', 2008, 'Filled with shrill gags and middling slapstick, College Road Trip is woefully short on comic imagination.', TO_DATE('2008-03-03', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('collide', 2017, 'Collide wastes a talented cast on a would-be thriller fatally undermined by eye-rolling dialogue, logical fallacies, and humdrum set pieces.', TO_DATE('2017-02-22', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('colma the musical', 2006, 'Three teens contemplate life after high school while singing their hearts out in this fresh musical.', TO_DATE('2006-05-21', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('colombiana', 2011, 'Zoe Saldana has the chops but she''s taken out by erratic and sloppy filmmaking.', TO_DATE('2011-07-27', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the color of money', 1986, 'That it''s inferior to the original goes without saying, but Paul Newman and Tom Cruise are a joy to watch, and Martin Scorsese''s direction is typically superb.', TO_DATE('1986-10-08', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('color of night', 2000, 'Bruce willie shot aside, the only other things popping out in Color of Night are some ridiculous plot contortions and majorly camp moments.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('color out of space', 2019, 'A welcome return for director Richard Stanley, Color Out of Space mixes tart B-movie pulp with visually alluring Lovecraftian horror and a dash of gonzo Nicolas Cage.', TO_DATE('2019-09-08', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the color purple', 2000, 'It might have been better served by a filmmaker with a deeper connection to the source material, but The Color Purple remains a worthy, well-acted adaptation of Alice Walker''s classic novel.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('colossal', 2016, 'Colossal''s singular strangeness can be disorienting, but viewers who hang on may find that its genre-defying execution -- and Anne Hathaway''s performance -- is well worth the ride.', TO_DATE('2016-09-09', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('color me kubrick', 2006, 'Colour Me Kubrick has a fascinating premise, but provides little insight into Kubrick and the man who impersonated him.', TO_DATE('2006-05-01', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('come as you are', 2019, 'Come As You Are approaches sensitive subjects with heart and humor, taking audiences on a thoroughly entertaining road trip to a crowd-pleasing destination.', TO_DATE('2019-03-10', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('come sunday', 2018, 'Come Sunday benefits greatly from Chiwetel Ejiofor''s central performance, which is often enough to lift an otherwise uneven drama.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('come to daddy', 2019, 'Bloody horror with barbed wit, Come to Daddy anchors its brutal violence in a surprisingly mature approach to provocative themes.', TO_DATE('2019-04-26', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the comebacks', 2007, 'Full of groin-centric humor and tired sports clichés, The Comebacks is poor even by parody movie standards.', TO_DATE('2007-10-19', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('comedian', 2002, 'Comedian is an insightful look at the hard work of creating comedy.', TO_DATE('2002-10-10', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('coming to america', 2000, 'Eddie Murphy was in full control at this point, starkly evident in Coming to America''s John Landis'' coasting direction.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('company man', 2001, 'A flat and misconceived movie with big stars.', TO_DATE('2001-01-31', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('compliance', 2012, 'Anchored by smart, sensitive direction and strong performances, Complicance is a ripped-from-the-headlines thriller that''s equal parts gripping and disturbing.', TO_DATE('2012-01-23', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('computer chess', 2013, 'With its delightfully retro production design, Computer Chess is an inventive, intelligent, and humorous comedy that celebrates the eccentricity and uniqueness of its subject.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('con air', 1997, 'Con Air won''t win any awards for believability - and all involved seem cheerfully aware of it, making some of this blockbuster action outing''s biggest flaws fairly easy to forgive.', TO_DATE('1997-06-06', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('conan the barbarian', 2000, 'Though Conan may take itself too seriously for some, this adventure film about a former slave seeking vengeance is full of quotable Schwarzenegger lines and gritty action.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('conan the barbarian', 2011, 'While its relentless, gory violence is more faithful to the Robert E. Howard books, Conan the Barbarian forsakes three-dimensional characters, dialogue, and acting in favor of unnecessary 3D effects.', TO_DATE('2011-08-15', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('conan the destroyer', 2000, 'Conan the Destroyer softens the edges that gave its predecessor gravitas, resulting in a campy sequel without the comparative thrills.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('concerning violence', 2014, 'As confrontational as it is ultimately rewarding, Concerning Violence is a scathing indictment of past misdeeds -- and a sobering reminder of how far we still have to go.', TO_DATE('2014-01-20', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('concussion', 2013, 'Smart, nuanced, and sexy, Concussion transcends its more awkward moments thanks to Robin Weigert''s remarkable starring performance.', TO_DATE('2013-09-18', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('concussion', 2015, 'Concussion lands a solid, well-acted hit on its impressively timely subject matter, even if its traditional sports drama structure is a little too safe to deserve a full-on dance in the end zone.', TO_DATE('2015-11-11', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the condemned', 2007, 'The Condemned is a morally ambiguous, exceedingly violent and mostly forgettable action film.', TO_DATE('2007-04-18', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('coneheads', 1993, 'Listless, crude, and overall uninspired, Coneheads offers further evidence that stretching an SNL sketch to feature length can be tougher than narfling a garthok.', TO_DATE('1993-07-23', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('confessions of a dangerous mind', 2002, 'Rockwell is spot-on as Barris, and Clooney directs with entertaining style and flair.', TO_DATE('2002-12-07', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('confessions of a shopaholic', 2009, 'This middling romantic comedy underutilizes a talented cast and delivers muddled messages on materialism and conspicuous consumption.', TO_DATE('2009-02-09', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('confessions of a teenage drama queen', 2004, 'Confessions of a Teenage Drama Queen''s superficial tendencies are unlikely to appeal to older viewers -- though its colorful candor is decidedly not intended for them in the first place.', TO_DATE('2004-02-18', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('confetti', 2006, 'This improvised mockumentary has its funny and even sweet moments, but it''s not as witty or sharp as Christopher Guest''s offerings.', TO_DATE('2006-05-04', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('confidence', 2003, 'While it may not be the best con in town, the movie still manages to entertain with its colorful cast.', TO_DATE('2003-01-30', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('confirmation', 2016, 'Stellar performances and gripping subject matter help Confirmation overcome production values that occasionally feel as dated as the infamous real-life case it covers.', TO_DATE('2016-04-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('congo', 1995, 'Mired in campy visual effects and charmless characters, Congo is a suspenseless adventure that betrays little curiosity about the scientific concepts it purports to care about.', TO_DATE('1995-06-09', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('conquest of the planet of the apes', 2000, 'Conquest of the Planet of the Apes is as angry and relevant as any of its predecessors, but budget constraints and a stale script rob this revolution of the scope it requires.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the constant gardener', 2005, 'The Constant Gardener is a smart, gripping, and suspenseful thriller with rich performances from the leads.', TO_DATE('2005-08-03', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('constantine', 2005, 'Despite solid production values and an intriguing premise, Constantine lacks the focus of another spiritual shoot-em-up: The Matrix.', TO_DATE('2005-02-08', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('constantines sword', 2008, 'Exceptional research elevates Constantine''s Sword from a talking heads documentary to a resonant and thought-provoking expose of the church''s dark history.', TO_DATE('2008-04-15', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('contagion', 2011, 'Tense, tightly plotted, and bolstered by a stellar cast, Contagion is an exceptionally smart -- and scary -- disaster movie.', TO_DATE('2011-09-03', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('contempt', 2000, 'This powerful work of essential cinema joins "meta" with "physique," casting Brigite Bardot and director Godard''s inspiration Fritz Lang.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('contraband', 2012, 'It''s more entertaining than your average January action thriller, but that isn''t enough to excuse Contraband''s lack of originality and unnecessarily convoluted plot.', TO_DATE('2012-01-10', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('control', 2007, 'Control is a work of art, thanks to its evocative black and white cinematography and sensational performances from Sam Riley and Samantha Morton. Even those not familiar with Joy Division can still appreciate the beauty of the film.', TO_DATE('2007-05-17', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the conversation', 2000, 'This tense, paranoid thriller presents Francis Ford Coppola at his finest -- and makes some remarkably advanced arguments about technology''s role in society that still resonate today.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('conviction', 2010, 'Less compelling -- and more manipulative -- than it should be, Conviction benefits from its compelling true story and a pair of solid performances from Swank and Rockwell.', TO_DATE('2010-09-11', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cook the thief his wife her lover', 1989, 'This romantic crime drama may not be to everyone''s taste, but The Cook, the Thief, His Wife & Her Lover is an audacious, powerful film.', TO_DATE('1989-09-11', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cookies fortune', 2000, 'Robert Altman''s gift for diffuse storytelling is employed to breezily enjoyable effect in Cookie''s Fortune, a mirthful caper that layers on a generous helping of Southern charm.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cookout', 2004, 'Good-natured but prepared with an absence of craft, The Cookout is an unappetizing collection of warmed-over jokes.', TO_DATE('2004-09-03', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cool hand luke', 2000, 'Though hampered by Stuart Rosenberg''s direction, Cool Hand Luke is held aloft by a stellar script and one of Paul Newman''s most indelible performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cooler', 2003, 'A small movie elevated by superb performances.', TO_DATE('2003-03-06', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cooties', 2015, 'A horror-comedy without enough of either, Cooties is fatally content to skate by on its intriguingly oddball premise.', TO_DATE('2015-05-04', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cop car', 2015, 'Cop Car boasts a terrific premise and a grimly gripping opening act -- and for some viewers, that will be enough to compensate for the movie''s uneven denouement.', TO_DATE('2015-01-26', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cop land', 2000, 'Cop Land matches its star-studded cast with richly imagined characters while throttling the audience with carefully ratcheted suspense, although it lacks the moral complexity of classic crime thrillers.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cop out', 2010, 'Cop Out is a cliched buddy action/comedy that suffers from stale gags and slack pacing.', TO_DATE('2010-02-23', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('copying beethoven klang der stille', 2006, 'A pretentious historical drama that''s ultimately a drag, despite Ed Harris'' powerful performance.', TO_DATE('2006-07-30', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('coraline', 2009, 'With its vivid stop-motion animation combined with Neil Gaiman''s imaginative story, Coraline is a film that''s both visually stunning and wondrously entertaining.', TO_DATE('2009-02-02', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the core', 2003, 'A B-movie with its tongue planted firmly in cheek, The Core is so unintentionally (intentionally?) bad that it''s a hoot.', TO_DATE('2003-03-25', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('coriolanus', 2011, 'Visceral and visually striking, Ralph Fiennes'' Coriolanus proves Shakespeare can still be both electrifying and relevant in a modern context.', TO_DATE('2011-02-15', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('corky romano', 2001, 'Corky Romano continues the trend of bad movies featuring SNL members. The jokes are tired and unfunny, and the slapstick feels forced.', TO_DATE('2001-10-09', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('corporate animals', 2019, 'Corporate culture may seem like easy pickings for satire, but the middling Corporate Animals proves even the broadest targets can be missed.', TO_DATE('2019-01-30', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the corporation', 2004, 'The Corporation is a satisfyingly dense, thought-provoking rebuttal to some of capitalism''s central arguments.', TO_DATE('2004-01-20', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tim burtons corpse bride', 2005, 'As can be expected from a Tim Burton movie, Corpse Bride is whimsically macabre, visually imaginative, and emotionally bittersweet.', TO_DATE('2005-09-07', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the corruptor', 1998, 'This uninspiring cop thriller doesn''t measure up to Chow Yun-Fat''s Hong Kong work.', TO_DATE('1998-06-01', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cosmopolis', 2012, 'Though some may find it cold and didactic, Cosmopolis benefits from David Cronenberg''s precise direction, resulting in a psychologically complex adaptation of Don DeLillo''s novel.', TO_DATE('2012-05-25', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cotton club', 2001, 'Energetic and brimming with memorable performers, The Cotton Club entertains with its visual and musical pizazz even as its plot only garners polite applause.', TO_DATE('2001-06-06', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('countdown', 2019, 'Countdown may offer a few fleeting jolts for horror fans with barren queues, but it lacks enough wit or creativity to leave a lasting impression.', TO_DATE('2019-10-24', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('countdown to zero', 2010, 'Countdown to Zero is more genuinely frightening than many horror movies -- and more soberly enlightening than the average documentary.', TO_DATE('2010-04-20', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the country bears', 2002, 'Despite all the celebrities on hand, this spin-off from a theme park attraction still feels tired and hokey.', TO_DATE('2002-07-20', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('country strong', 2010, 'The cast gives it their all, and Paltrow handles her songs with aplomb, but Country Strong''s cliched, disjointed screenplay hits too many bum notes.', TO_DATE('2010-12-21', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('couples retreat', 2009, 'Despite a talented cast and some reliably pleasant interplay between Jon Favreau and Vince Vaughn, Couples Retreat leaves viewers stranded in an arid, mirthless comedy.', TO_DATE('2009-10-04', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('courage under fire', 1996, 'An emotional and intriguing tale of a military officer who must review the merits of a fallen officer while confronting his own war demons. Effectively depicts the terrors of war as well as its heartbreaking aftermath.', TO_DATE('1996-07-12', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('courageous', 2011, 'While the filmmaking is fairly competent, Courageous is overall worthless to anybody who doesn''t subscribe to its dogmatic agenda.', TO_DATE('2011-09-28', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('court', 2015, 'Court takes a penetrating, timely look at issues facing Indian society while serving as an excellent calling card for debuting writer-director Chaitanya Tamhane.', TO_DATE('2015-03-14', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the court jester', 2000, 'A witty spoof of medieval swashbuckler movies, The Court Jester showcases Danny Kaye at his nimble, tongue-twisting best.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the covenant', 2006, 'The Covenant plays out like a teen soap opera, full of pretty faces, wooden acting, laughable dialogue, and little suspense.', TO_DATE('2006-09-07', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cowboys aliens', 2011, 'Daniel Craig and Harrison Ford are as dependably appealing as ever, but they''re let down by director Jon Favreau''s inability to smooth Cowboys & Aliens'' jarring tonal shifts.', TO_DATE('2011-07-24', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('coyote ugly', 2000, 'Coyote Ugly has an enthusiastically trashy energy and undeniable aesthetic appeal, but it''s nowhere near enough to make up for the film''s shallow, unimaginative story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cq', 2001, 'CQ is a stylish and fun homage to campy 1960s flicks.', TO_DATE('2001-05-16', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cracks', 2009, 'Atomospheric but not much else, Cracks is a formless film in search of compelling drama.', TO_DATE('2009-12-04', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cradle 2 the grave', 2003, 'Dumb and by-the-numbers, but serviceable.', TO_DATE('2003-02-25', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cradle will rock', 2000, 'Witty and provocative.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the craft', 1996, 'The Craft''s campy magic often overrides the feminist message at its story''s core, but its appealing cast and postmodern perspective still cast a sporadic spell.', TO_DATE('1996-05-03', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crank', 2006, 'Crank''s assaultive style and gleeful depravity may turn off casual action fans, but audiences seeking a strong dose of adrenaline will be thrilled by Jason Statham''s raucous race against mortality.', TO_DATE('2006-08-24', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crank 2 high voltage', 2009, 'Crank: High Voltage delivers on its promises: a fast-paced, exciting thrill ride that doesn''t take itself too seriously.', TO_DATE('2009-04-16', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crawl', 2019, 'An action-packed creature feature that''s fast, terrifying, and benefits greatly from a completely game Kaya Scodelario, Crawl is a fun throw-back with just enough self-awareness to work.', TO_DATE('2019-07-10', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the crazies', 2001, 'The Crazies isn''t top-shelf Romero, but its blend of genre thrills and social subtext should still be enough to satisfy discerning horror fans.', TO_DATE('2001-06-05', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crazybeautiful', 2000, 'The story is not new, but the film gets credit for trying to move away from the genre''s cliches. Kirsten Dunst and newcomer Jay Hernandez give believable performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crazy heart', 2009, 'Thanks to a captivating performance from Jeff Bridges, Crazy Heart transcends its overly familiar origins and finds new meaning in an old story.', TO_DATE('2009-12-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crazy in alabama', 2000, 'Melanie Griffith gets kudos for her performance, but the movie just doesn''t seem to come together.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crazy love', 2007, 'Crazy Love''s subjects and story are so compelling that they overcome the doc''s dry, talking heads format.', TO_DATE('2007-01-24', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crazy rich asians', 2018, 'With a terrific cast and a surfeit of visual razzle dazzle, Crazy Rich Asians takes a satisfying step forward for screen representation while deftly drawing inspiration from the classic -- and still effective -- rom-com formula.', TO_DATE('2018-08-09', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crazy stupid love', 2011, 'It never lives up to the first part of its title, but Crazy, Stupid, Love''s unabashed sweetness -- and its terrifically talented cast -- more than make up for its flaws.', TO_DATE('2011-07-21', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('creed', 2015, 'Creed brings the Rocky franchise off the mat for a surprisingly effective seventh round that extends the boxer''s saga in interesting new directions while staying true to its classic predecessors'' roots.', TO_DATE('2015-11-18', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('creed ii', 2018, 'Creed II''s adherence to franchise formula adds up to a sequel with few true surprises, but its time-tested generational themes still pack a solid punch.', TO_DATE('2018-11-16', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('creep', 2014, 'A smart, odball take on found-footage horror, Creep is clever and well-acted enough to keep viewers on the edges of their seats.', TO_DATE('2014-03-20', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('creep 2', 2017, 'Creep 2 has everything that made the original work and more -- more laughs, more awkwardness, more unsettling terror.', TO_DATE('2017-10-16', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('creepshow', 2000, 'It''s uneven, as anthologies often are, but Creepshow is colorful, frequently funny, and treats its inspirations with infectious reverence.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('creepshow 2', 2000, 'Not even the melding of Stephen King and George A. Romero''s writing sensibilities can elevate this spineless anthology, which is too simple in its storytelling and too skimpy on the genuine scares.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('creepy kuripi itsuwari no rinjin', 2016, 'Creepy lives up to its title with a suspenseful and thoroughly unsettling - not to mention well-acted - blend of crime procedural and domestic drama.', TO_DATE('2016-10-17', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cries and whispers', 2001, 'Visually stunning and achingly performed, Ingmar Bergman''s chamber piece is a visceral rumination on death and sisterhood.', TO_DATE('2001-07-25', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crime punishment in suburbia', 2000, 'Despite the beautiful visuals, Crime and Punishment is too somber and pretentious. Also, the acting is of mixed quality.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the crime of padre amaro', 2002, 'Though melodramatic, El Crimen del Padre Amaro''s critique of the Catholic church is a timely one.', TO_DATE('2002-08-18', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('criminal', 2016, 'Despite the valiant efforts of a game and talented cast, Criminal has little to offer beyond the bare minimum expected by the most undemanding of genre enthusiasts.', TO_DATE('2016-04-07', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crimson peak', 2015, 'Crimson Peak offers an engaging -- albeit somewhat slight -- diversion driven by a delightfully creepy atmosphere and director Guillermo del Toro''s brilliant knack for unforgettable visuals.', TO_DATE('2015-10-13', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crimson tide', 1995, 'Boasting taut, high energy thrills and some cracking dialogue courtesy of an uncredited Quentin Tarantino, Crimson Tide finds director Tony Scott near the top of his action game.', TO_DATE('1995-05-12', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crip camp a disability revolution', 2020, 'As entertaining as it is inspiring, Crip Camp uses one group''s remarkable story to highlight hope for the future and the power of community.', TO_DATE('2020-01-24', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crna macka beli macor black cat white cat', 2000, 'Rambling and eccentric, Emir Kusturica''s comedy captures the life and energy of the Gypsy family at the heart of the tale.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crocodile dundee', 2000, 'Infectiously easygoing charm and a leading man in the role he was born to play help Crocodile Dundee make the most of its familiar fish-out-of-water premise.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crocodile dundee ii', 2001, 'Retelling its predecessor''s same joke with diminishing returns, Crocodile Dundee II sees the franchise''s enjoyability go down under.', TO_DATE('2001-01-01', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crocodile dundee in los angeles', 2001, 'A sequel as unnecessary as it is belated, Crocodile Dundee in Los Angeles lacks virtually all of the easygoing humor and charm that delighted fans of the original.', TO_DATE('2001-04-16', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crónicas', 2005, 'An unsettling and absorbing cautionary tale with John Leguizamo playing an unscrupulous TV reporter who uses the medium to further his own goals.', TO_DATE('2005-05-14', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cronos', 2000, 'Guillermo del Toro''s unique feature debut is not only gory and stylish, but also charming and intelligent.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crooklyn', 1994, 'A personal project that warmly reflects on director Spike Lee''s childhood, Crooklyn is an episodic celebration of family and the indelible facets of one''s hometown.', TO_DATE('1994-05-13', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cropsey', 2009, 'Riveting and bone-chillingly creepy, Cropsey manages to be one of the best documentaries and one of the best horror movies of the year.', TO_DATE('2009-06-10', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crossing over', 2009, 'Crossing Over is flagrant and heavy-handed about a situation that deserves more deliberate treatment, and joins its characters with coincidences that strain believability.', TO_DATE('2009-02-04', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crossing the line', 2007, 'An engrossing look at the aftermath of largely forgotten events during the Cold War, Crossing the Line raises questions that will haunt the viewer after the credits roll.', TO_DATE('2007-01-16', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crossover', 2006, 'This heartfelt but incompetent, cliche-ridden sports picture is the cinematic equivalent of an airball.', TO_DATE('2006-08-28', 'YYYY-MM-DD'), 2.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crouching tiger hidden dragon', 2000, 'The movie that catapulted Ang Lee into the ranks of upper echelon Hollywood filmmakers, Crouching Tiger, Hidden Dragon features a deft mix of amazing martial arts battles, beautiful scenery, and tasteful drama.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the crow', 2000, 'Filled with style and dark, lurid energy, The Crow is an action-packed visual feast that also has a soul in the performance of the late Brandon Lee.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the crow salvation', 2000, 'The Crow: Salvation adds nothing new to the series and is plagued by bad acting and dialogue.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the crow city of angels', 2000, 'The Crow: City of Angels is a sloppy pretender that captures neither the mood nor energy of the original.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crown heights', 2017, 'Crown Heights'' heartbreaking fact-based narrative -- and LaKeith Stanfield''s remarkable starring performance -- push this powerful drama past its structural flaws.', TO_DATE('2017-01-23', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crown vic', 2019, 'Led by a solid turn from the well-cast Thomas Jane, Crown Vic gets an impressive amount of mileage out of its familiar cop thriller framework.', TO_DATE('2019-04-29', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cruel intentions', 2000, 'This darkly comic drama and its attractive young cast are easy on the eyes, but uneven performances and an uninspired script conspire to foil Cruel Intentions.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cruising', 2000, 'Cruising glides along confidently thanks to filmmaking craft and Al Pacino''s committed performance, but this hot-button thriller struggles to engage its subject matter sensitively or justify its brutality.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crumb', 1995, 'Crumb is a frank and surreal chronicle of artistic expression and family trauma, offering an unblinking gaze into the mind and work of cartoonist Robert Crumb that will endear as much as it unsettles.', TO_DATE('1995-05-19', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crybaby', 2000, 'John Waters'' musical ode to the teen rebel genre is infectious and gleefully camp, providing star Johnny Depp with the perfect vehicle in which to lampoon his pin-up image.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cry_wolf', 2005, 'Dull and derivative, Cry_Wolf is a subpar slasher that even ardent fans of the genre may find difficult to enjoy.', TO_DATE('2005-09-16', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the crying game', 1992, 'The Crying Game is famous for its shocking twist, but this thoughtful, haunting mystery grips the viewer from start to finish.', TO_DATE('1992-11-25', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('crystal fairy', 2013, 'Slight and unpolished, The Crystal Fairy is held together with Sebastian Silva''s assured direction and a pair of strong, committed performances from Michael Cera and Gaby Hoffman.', TO_DATE('2013-01-18', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('csa the confederate states of america', 2004, 'Through the eyes of a British "documentary", this film takes a satirically humorous, and sometimes frightening, look at the history of an America where the South won the Civil War.', TO_DATE('2004-09-25', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('csny déjà vu', 2008, 'Half concert doc, half political exposition, CSNY: DeJa Vu straddles the old and new slant on politics in music with diligence and not a little self-promotion.', TO_DATE('2008-01-28', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cuban fury', 2014, 'Nick Frost and Chris O''Dowd remain as undeniably likable as ever, but Cuban Fury saddles them with a contrived and predictable plot that''s far too short on laughs.', TO_DATE('2014-01-16', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cube', 1998, 'Cube sometimes struggles with where to take its intriguing premise, but gripping pace and an impressive intelligence make it hard to turn away.', TO_DATE('1998-09-11', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cujo', 2001, 'Cujo is artless work punctuated with moments of high canine gore and one wild Dee Wallace performance.', TO_DATE('2001-01-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cunningham', 2019, 'Cunningham may frustrate viewers hoping for a purer distillation of its subject''s work, but it remains a solid tribute to a brilliant talent.', TO_DATE('2019-09-07', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the curious case of benjamin button', 2008, 'Curious Case of Benjamin Button is an epic fantasy tale with rich storytelling backed by fantastic performances.', TO_DATE('2008-11-24', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('curse of chucky', 2013, 'The franchise hex of disappointing sequels is broken by going back to basics in this chilling entry, restoring a sense of playfulness to the Chucky saga.', TO_DATE('2013-08-02', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the curse of the cat people', 2000, 'Foregoing the horror thrills of its predecessor in favor of childhood fantasy, Curse of the Cat People is a touching and psychologically complex family film couched in a ghost story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('curse of the golden flower', 2006, 'Melodrama, swordplay, and CG armies -- fans of martial arts epic will get what they bargain for, though the baroque art direction can be both mesmerizing and exhaustively excessive.', TO_DATE('2006-11-13', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the curse of the jade scorpion', 2001, 'The writing for Scorpion is not as sharp as Woody Allen''s previous movies as most of the jokes fall flat.', TO_DATE('2001-07-19', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cut bank', 2014, 'Cut Bank contains typically outstanding work from its solid veteran cast, but it''s lost in a dull morass of predictably derivative crime thriller clichés.', TO_DATE('2014-08-24', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cutie and the boxer', 2013, 'A beautifully-made documentary that explores the challenges and richness of both marriage and art through the lens of a fascinating and complex couple.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cutters way', 2001, 'A suitably cynical neo-noir that echoes the disillusionment of its era, Cutter''s Way relies on character-driven drama further elevated by the work of an outstanding cast.', TO_DATE('2001-09-26', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cutthroat island', 1995, 'Cutthroat Island may aspire towards the earnest thrills of classic swashbucklers, but a distinct lack of charm and stilted script make this adventure a joyless hodgepodge of the pirate genre''s flotsam and jetsam.', TO_DATE('1995-12-22', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cyrus', 2010, 'While it may strike some viewers as slight, Cyrus is a successful hybrid of mainstream production values and the mumblecore ideals of directors Jay and Mark Duplass.', TO_DATE('2010-01-28', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dtox eye see you', 2000, 'Whether it''s being presented as D-Tox or Eye See You, this Stallone starring vehicle is a slapdash thriller to actively avoid.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the d train', 2015, 'The D Train offers Jack Black a too-rare opportunity to showcase his range, but its story and characters are too sloppily conceived to hold together as a film.', TO_DATE('2015-02-13', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('da sweet blood of jesus', 2015, 'Da Sweet Blood of Jesus has no shortage of style, but it isn''t enough to make this horror-tinged Spike Lee joint one of his best -- or worth recommending.', TO_DATE('2015-01-14', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the da vinci code', 2006, 'What makes Dan Brown''s novel a best seller is evidently not present in this dull and bloated movie adaptation of The Da Vinci Code.', TO_DATE('2006-05-16', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('daddy day camp', 2007, 'A mirthless, fairly desperate family film, Daddy Day Camp relies too heavily on bodily functions for comedic effect, resulting in plenty of cheap gags but no laughs.', TO_DATE('2007-08-03', 'YYYY-MM-DD'), 1.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('daddy day care', 2003, 'Daddy Day Care does its job of babysitting the tots. Anyone older will probably be bored.', TO_DATE('2003-05-04', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('daddys home 2', 2017, 'A formulaic comedy that''s unlikely to spread much yuletide merriment, Daddy''s Home 2 can only muster a few stray yuks from its talented cast.', TO_DATE('2017-11-09', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('daddys home', 2015, 'Will Ferrell and Mark Wahlberg have proven comedic chemistry, but Daddy''s Home suffers from a dearth of genuinely funny ideas - and lacks enough guts or imagination to explore the satirical possibilities of its premise.', TO_DATE('2015-12-17', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('daddys little girls', 2007, 'Daddy''s Little Girls boasts fine performances and a poignant message, but is ultimately let down by amateurish filmmaking.', TO_DATE('2007-02-14', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dainipponjin big man japan', 2007, 'Hitoshi Matsumoto''s indescribably odd mockumentary is undeniably inspired.', TO_DATE('2007-09-11', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dallas buyers club', 2013, 'Dallas Buyers Club rests squarely on Matthew McConaughey''s scrawny shoulders, and he carries the burden gracefully with what might be a career-best performance.', TO_DATE('2013-09-07', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('damascus cover', 2018, 'Damascus Cover is essentially every bit the hackneyed espionage drama that any veteran of ''90s action thrillers might expect after reading its title.', TO_DATE('2018-07-05', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('damienomen ii', 2000, 'Damien dishes out ghoulish scares and a biblical body count to generate some morbid fun, but this repetitious sequel lacks the sophistication of its predecessor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the damned united', 2009, 'Better than your average football pic, Damned United is carried by another star turn from Michael Sheen as Brian Clough.', TO_DATE('2009-03-26', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('damsel', 2018, 'The beautifully filmed Damsel injects the western genre with a welcome dose of humor and some unexpected twists, although its stately pace may frustrate impatient viewers.', TO_DATE('2018-01-24', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('damsels in distress', 2011, 'Damsels in Distress can sometimes feel mannered and outlandish, but it''s redeemed by director Whit Stillman''s oddball cleverness and Greta Gerwig''s dryly funny performance.', TO_DATE('2011-09-08', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dan in real life', 2007, 'The fine performances elevate Dan in Real Life beyond its sentimental plot.', TO_DATE('2007-10-18', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dance flick', 2009, 'Dance Flick scores a few laughs thanks to the Wayans brothers'' exuberance, but it''s ultimately a scattershot collection of gags without much direction.', TO_DATE('2009-05-21', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dance with me', 1998, 'Shallow script, weak direction.', TO_DATE('1998-08-21', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dancer in the dark', 2000, 'Dancer in Dark can be grim, dull, and difficult to watch, but even so, it has a powerful and moving performance from Bjork and is something quite new and visionary.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dancer upstairs', 2002, 'The Dancer Upstairs benefits from a talented cast and alluring intelligence, although pacing problems prevent this John Malkovich-directed mystery from reaching its full potential.', TO_DATE('2002-08-28', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dances with wolves', 1990, 'Dances with Wolves suffers from a simplistic view of the culture it attempts to honor, but the end result remains a stirring western whose noble intentions are often matched by its epic grandeur.', TO_DATE('1990-11-09', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dancing in jaffa', 2014, 'Dancing in Jaffa uses art to frame a cultural journey that''s equal parts entertaining, uplifting, and edifying.', TO_DATE('2014-04-08', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('danger close', 2019, 'Danger Close is problematic as a history lesson, but still offers viewers an involving look at life in the trenches of a real-life conflict.', TO_DATE('2019-06-19', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dangerous lies windfall', 2020, 'Energetic enough to be diverting but too mediocre to be memorable, Dangerous Lies feigns erotic thrills without ever really working up a sweat.', TO_DATE('2020-04-30', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dangerous lives of altar boys', 2002, 'The inter-cutting of animation by Spawn''s creator, Todd McFarlane, doesn''t always work, but the performances by the young actors capture the pains of growing up well.', TO_DATE('2002-04-08', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dangerous minds', 1995, 'Rife with stereotypes that undermine its good intentions, Dangerous Minds is too blind to see that the ones it hurts are the audience.', TO_DATE('1995-08-11', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('daniel isnt real', 2019, 'Daniel Isn''t Real, but the smart, stylish fun waiting for genre lovers in this well-acted suspense thriller is completely genuine.', TO_DATE('2019-03-11', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('danny collins', 2015, 'Thanks to Al Pacino''s stirring central performance - and excellent work from an esteemed supporting cast -- Danny Collins manages to overcome its more predictable and heavy-handed moments to deliver a heartfelt tale of redemption.', TO_DATE('2015-03-09', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('danny deckchair', 2003, 'Danny Deckchair mines some earnest pleasure from a concept with its head in the clouds and two stars whose chemistry is grounded, but the comedy quickly runs out of air when the premise comes back down to the earth.', TO_DATE('2003-07-19', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unleashed', 2005, 'Jet Li gets to emote in some emotionally awkward scenes, but the gritty fight sequences come through in what is Li''s best English language film.', TO_DATE('2005-02-10', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dantes peak', 1997, 'The movie works when things are on fire, but everything else - from dialogue to characters - is scathingly bad.', TO_DATE('1997-02-07', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('daredevil', 2003, 'While Ben Affleck fits the role and the story is sporadically interesting, Daredevil is ultimately a dull, brooding origin story that fails to bring anything new to the genre.', TO_DATE('2003-02-06', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the darjeeling limited', 2007, 'With the requisite combination of humor, sorrow and outstanding visuals, The Darjeeling Limited will satisfy Wes Anderson fans.', TO_DATE('2007-09-04', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark shadows', 2012, 'The visuals are top notch but Tim Burton never finds a consistent rhythm, mixing campy jokes and gothic spookiness with less success than other Johnny Depp collaborations.', TO_DATE('2012-05-07', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark blue', 2003, 'Kurt Russell gives a good performance. Too bad there''s nothing here that you haven''t seen before.', TO_DATE('2003-01-19', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark blue world', 2001, 'While it''s better than Pearl Harbor, Dark Blue World still spends too much time on a trite love triangle.', TO_DATE('2001-10-31', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark city', 2000, 'Stylishly gloomy, Dark City offers a polarizing whirl of arresting visuals and noirish action.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark crimes', 2018, 'Dark Crimes is a rote, unpleasant thriller that fails to parlay its compelling true story and a committed Jim Carrey performance into even modest chills.', TO_DATE('2018-03-15', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dark crystal', 2000, 'The Dark Crystal''s narrative never quite lives up to the movie''s visual splendor, but it remains an admirably inventive and uniquely intense entry in the Jim Henson canon.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark days', 2000, 'Marc Singer''s documentary about a group of homeless people living beneath the streets of New York City is haunting and uplifting in equal measure.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dark half', 1993, 'The Dark Half is a highly serious psychological study that can be faulted for being more curious than actually scary.', TO_DATE('1993-04-23', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark horse', 2011, 'Typically misanthropic yet curiously satisfying and incisive, Dark Horse is a movie that preaches to the cynical converted.', TO_DATE('2011-09-05', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark matter', 2007, 'The creaky plotting, inscrutable characters, and unconvincing ending make it difficult for audiences to connect with Dark Matter.', TO_DATE('2007-01-30', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark phoenix', 2019, 'Dark Phoenix ends an era of the X-Men franchise by taking a second stab at adapting a classic comics arc -- with deeply disappointing results.', TO_DATE('2019-06-04', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark places', 2015, 'Dark Places has a strong cast and bestselling source material, but none of it adds up to more than a mediocre thriller that gets tripped up on its own twists.', TO_DATE('2015-04-07', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark river', 2017, 'Dark River is just as bleak as its title would suggest, but solidly conceived characters and a standout performance from Ruth Wilson make it worth diving in.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark skies', 2013, 'Dark Skies writer director Scott Stewart has a solid cast, an interesting premise, and some admirable ambitions, but he can''t figure out what to do with any of them, and the result is a dull, muddled effort that will bore all but the most devoted horror buffs.', TO_DATE('2013-02-21', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark tide', 2012, 'Shallow and brackish, Dark Tide fails to rise.', TO_DATE('2012-03-11', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark victory', 2000, 'Bette Davis does it her way with a tour de force performance in Dark Victory, a moving melodrama that snatches triumph from the jaws of mortality.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark water', 2005, 'All the atmospherics in Dark Water can''t make up for the lack of genuine scares.', TO_DATE('2005-06-16', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dark waters', 2019, 'Dark Waters powerfully relays a real-life tale of infuriating malfeasance, honoring the victims and laying blame squarely at the feet of the perpetrators.', TO_DATE('2019-11-13', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('darkest hour', 2017, 'Darkest Hour is held together by Gary Oldman''s electrifying performance, which brings Winston Churchill to life even when the movie''s narrative falters.', TO_DATE('2017-09-02', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('darkman', 1990, 'Gruesome and deliciously broad, Sam Raimi''s Darkman bears the haunted soulfulness of gothic tragedy while packing the stylistic verve of onomatopoeia springing off a comic strip page.', TO_DATE('1990-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('darkness', 2002, 'Yet another predictable variation on the hoary old haunted-house movie, Darkness is an illogical, portentous mess.', TO_DATE('2002-10-08', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('darkness falls', 2003, 'A derivative movie where the scares are few and things don''t make much sense.', TO_DATE('2003-01-17', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('darling', 2016, 'Darling''s classic inspirations will be obvious to most hardcore horror fans, but they''re deployed with enough wit and flair to stand on their own chilling merits.', TO_DATE('2016-03-29', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('date night', 2010, 'An uneasy blend of action and comedy, Date Night doesn''t quite live up to the talents of its two leads, but Steve Carell and Tina Fey still manage to shine through most of the movie''s flaws.', TO_DATE('2010-03-16', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('american experience', 2002, 'An emotionally wrenching portrayal of a family reunion that doesn''t turn out as expected.', TO_DATE('2002-04-08', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('daughters of the dust', 2000, 'Daughters of the Dust addresses its weighty themes with lovely visuals and a light, poetic touch, offering an original, absorbing look at a largely unexplored corner of American culture.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dave', 2000, 'Ivan Reitman''s refreshingly earnest political comedy benefits from an understated, charming script and a breezy performance by Kevin Kline.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dave chappelle sticks stones', 2019, 'Edgy, but empty, Sticks and Stones won''t break any bones, but it won''t elicit many laughs, either.', TO_DATE('2019-08-27', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('david layla', 2007, 'Earnest and well-intentioned, "David & Layla" stumbles over itself too often to achieve its goals.', TO_DATE('2007-06-16', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dawn of the dead', 2004, 'A kinetic, violent and surprisingly worthy remake of George Romero''s horror classic that pays homage to the original while working on its own terms.', TO_DATE('2004-02-17', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dawn of the planet of the apes', 2014, 'With intelligence and emotional resonance to match its stunning special effects, Dawn of the Planet of the Apes expands on its predecessor with an exciting and ambitious burst of sci-fi achievement.', TO_DATE('2014-06-28', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the day after tomorrow', 2004, 'The Day After Tomorrow is a ludicrous popcorn thriller filled with clunky dialogue, but spectacular visuals save it from being a total disaster.', TO_DATE('2004-04-04', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('day for night', 2000, 'A sweet counterpoint to Godard''s Contempt, Truffaut''s Day for Night is a congenial tribute to the self-afflicted madness that is making a movie.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('day night day night', 2006, 'Day Night Day Night is a minimalist drama that refuses to indulge in stereotypes, making it all the more realistic and chilling.', TO_DATE('2006-05-30', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the day of the jackal', 2000, 'The Day of the Jackal is a meticulously constructed thriller with surprising irreverence and taut direction.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the day the earth stood still', 2008, 'Heavy on special effects, but without a coherent story at its base, The Day the Earth Stood Still is subpar re-imagining of the 1951 science-fiction classic.', TO_DATE('2008-09-18', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('day watch', 2007, 'Day Watch is frequently cheesy but it offers enough twists, surprises, and inventive action sequences to maintain viewer interest.', TO_DATE('2007-05-18', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('daybreakers', 2009, 'Though it arrives during an unfortunate glut of vampire movies, Daybreakers offers enough dark sci-fi thrills -- and enough of a unique twist on the genre -- to satisfy filmgoers.', TO_DATE('2009-09-09', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('daylight', 1996, 'The opening''s got a great fiery explosion and Stallone puts in another earnest, sympathetic performance, but all else in Daylight feels designed to annoy the audience into submission.', TO_DATE('1996-12-06', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('daylight robbery', 2008, 'This poorly executed brit crime caper wants to be a Guy Ritchie film, but ends up more like an extended Eastenders episode.', TO_DATE('2008-08-29', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('giorni e nuvole days and clouds', 2007, 'An elegantly acted art house film about a middle class couple''s struggle to hold their lives together, Days and Cloud is both sensitive and engrossing.', TO_DATE('2007-09-05', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('days of glory', 2006, 'Days of Glory is a powerful historical epic that pays homage to a valiant group of soldiers whose sacrifices have largely been forgotten.', TO_DATE('2006-05-25', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('days of heaven', 2000, 'Illuminated by magic hour glow and wistful performances, Days of Heaven is a visual masterpiece that finds eloquent poetry in its spare scenario.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('days of thunder', 2000, 'Days of Thunder has Tom Cruise and plenty of flash going for it, but they aren''t enough to compensate for the stock plot, two-dimensional characters, and poorly written dialogue.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the daytrippers', 1997, 'Its modest scale and scabrous sense of humor may feel more punishing than funny for some, but an excellent cast and authentic sense of place make The Daytrippers a smooth ride.', TO_DATE('1997-03-05', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dazed and confused', 1993, 'Featuring an excellent ensemble cast, a precise feel for the 1970s, and a killer soundtrack, Dazed and Confused is a funny, affectionate, and clear-eyed look at high school life.', TO_DATE('1993-09-10', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('de rouille et dos rust and bone', 2012, 'Surging on strong performances from Marion Cotillard and Matthias Schoenaerts, Rust and Bone is as vibrant and messily unpredictable as life itself.', TO_DATE('2012-05-17', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('de zaak alzheimer the memory of a killer', 2004, 'Even though The Memory of a Killer is standard genre fare, it is also engaging and stylish.', TO_DATE('2004-12-22', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dead man running', 2009, 'Poor performances, stiff dialogue, flat characters, and an unimaginative stab at the mood of the Guy Ritchie crime caper make Dead Man Running into a hooligan tale with little to offer.', TO_DATE('2009-10-30', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dylan dog dead of night', 2011, 'An uninspired, feebly-acted horror/comedy that produces little scares and laughs.', TO_DATE('2011-04-28', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dead alive', 1993, 'The delightfully gonzo tale of a lovestruck teen and his zombified mother, Dead Alive is extremely gory and exceedingly good fun, thanks to Peter Jackson''s affection for the tastelessly sublime.', TO_DATE('1993-02-12', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dead calm', 2000, 'Nicole Kidman''s coiled intensity and muscular direction by Phillip Noyce give this nautical thriller a disquieting sense of dread.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dead man', 2000, 'While decidedly not for all tastes, Dead Man marks an alluring change of pace for writer-director Jim Jarmusch that demonstrates an assured command of challenging material.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dead man down', 2013, 'While the fine cast keeps Dead Man Down watchable throughout, the film is weighted down by absurd plot twists and a slack pace.', TO_DATE('2013-03-07', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dead man on campus', 2000, 'Not much of a story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dead mans shoes', 2004, 'Though enhanced by cramped, gritty camerawork, this unsettling look at violence and revenge lacks the provocative edge needed to give it a substantial kick.', TO_DATE('2004-09-30', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dead men dont wear plaid', 2000, 'Dead Men Don''t Wear Plaid is more eleaborate pastiche than uproarious comedy, but the farce works thanks to the sly lampooning of Hollywood noir and Steve Martin''s performance as a goofy gumshoe.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dead poets society', 2000, 'Affecting performances from the young cast and a genuinely inspirational turn from Robin Williams grant Peter Weir''s prep school drama top honors.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dead pool', 2000, 'While it offers its fair share of violent thrills and tough wit, The Dead Pool ends the Dirty Harry series on an uninspired note.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dead ringers', 2000, 'Dead Ringers serves up a double dose of Jeremy Irons in service of a devilishly unsettling concept and commandingly creepy work from director David Cronenberg.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dead silence', 2007, 'More tasteful than recent slasher flicks, but Dead Silence is undone by boring characters, bland dialogue, and an unnecessary and obvious twist ending.', TO_DATE('2007-03-02', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dead snow død snø', 2009, 'Though it doesn''t cover new ground, Dead Snow is an entertaining mix of camp, scares, and blood and guts.', TO_DATE('2009-02-25', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dead snow 2 red vs dead død snø 2', 2014, 'Dead Snow 2: Red vs. Dead expands the original''s canvas without sacrificing any of its bloody fun, adding up to a sequel that fans of the first are bound to enjoy.', TO_DATE('2014-01-23', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dead zone', 2000, 'The Dead Zone combines taut direction from David Cronenberg and and a rich performance from Christopher Walken to create one of the strongest Stephen King adaptations.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deadpool', 2016, 'Fast, funny, and gleefully profane, the fourth-wall-busting Deadpool subverts superhero film formula with wildly entertaining -- and decidedly non-family-friendly -- results.', TO_DATE('2016-02-06', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deadpool 2', 2018, 'Though it threatens to buckle under the weight of its meta gags, Deadpool 2 is a gory, gleeful lampoon of the superhero genre buoyed by Ryan Reynolds'' undeniable charm.', TO_DATE('2018-05-14', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dealt', 2017, 'An intimate portrait of the awe-inspiring Richard Turner, Dealt produces a royal flush with its compelling subject and some storytelling sleight of hand.', TO_DATE('2017-03-16', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dear dictator', 2017, 'Dear Dictator never comes close to taking advantage of its wildly silly premise -- or the assortment of talented veterans who round out the cast.', TO_DATE('2017-11-22', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dear frankie', 2004, 'Dear Frankie is a small, good-hearted film with fine performances.', TO_DATE('2004-05-19', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dear john', 2010, 'Built from many of the same ingredients as other Nicholas Sparks tearjerkers, Dear John suffers from its cliched framework, as well as Lasse Hallstrom''s curiously detached directing.', TO_DATE('2010-01-29', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dear wendy', 2005, 'A film with numerous ideas but little grasp of how to effectively communicate them, Dear Wendy lacks the intelligence or insight that its difficult subject matter demands.', TO_DATE('2005-02-03', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dear white people', 2014, 'Dear White People adds a welcome new voice to cinema''s oft-neglected discussion of race, tackling its timely themes with intelligence, honesty, and gratifyingly sharp wit.', TO_DATE('2014-01-20', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('death at a funeral', 2007, 'Death At A Funeral is a rousing British farce, with enough slapstick silliness to overcome its faults.', TO_DATE('2007-04-30', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('death at a funeral', 2010, 'It''s amusing and it assembles a talented cast, but Neil LaBute''s surprisingly faithful remake of the 2007 Frank Oz dramedy ultimately falls short of the original.', TO_DATE('2010-04-14', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('death becomes her', 1992, 'Hawn and Streep are as fabulous as Death Becomes Her''s innovative special effects; Zemeckis'' satire, on the other hand, is as hollow as the world it mocks.', TO_DATE('1992-07-31', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('death defying acts', 2007, 'Pretty but dull, with unconvincing turns from Zeta-Jones and Pearce. If you want a period magician movie, seek out The Prestige or The Illusionist instead.', TO_DATE('2007-09-08', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('death note', 2017, 'Death Note benefits from director Adam Wingard''s distinctive eye and a talented cast, but they aren''t enough to overcome a fatally overcrowded canvas.', TO_DATE('2017-07-21', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('death of a president', 2006, 'In this unconvincing fictional documentary, the tense 30 minutes that lead into the title event is outweighed by the boring, melodramatic hour preceding it.', TO_DATE('2006-09-12', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('death proof', 2007, 'Death Proof may feel somewhat minor in the context of Tarantino''s larger filmography, but on its own merits, it packs just enough of a wallop to deliver sufficiently high-octane grindhouse goods.', TO_DATE('2007-05-23', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('death race', 2008, 'Mindless, violent, and lightning-paced, Death Race is little more than an empty action romp.', TO_DATE('2008-08-19', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('death race 2000', 2000, 'Death Race 2000 is a fun, campy classic, drawing genuine thrills from its mindless ultra-violence.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('death sentence', 2007, 'A nonsensical plot and an absurd amount of violence make this revenge pic gratuitous and overwrought.', TO_DATE('2007-08-29', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('death to smoochy', 2002, 'The talent involved can''t save a script that has nowhere to go with its promising premise.', TO_DATE('2002-03-18', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('death wish', 2000, 'Death Wish is undeniably exploitation fare -- and also undeniably effective.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('death wish', 2018, 'Death Wish is little more than a rote retelling that lacks the grit and conviction of the original -- and also suffers from spectacularly bad timing.', TO_DATE('2018-02-22', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deathgasm', 2015, 'Deathgasm plumbs the blood-spattered depths of grindhouse gore with enough giddy glee to satisfy genre enthusiasts looking for a thrill.', TO_DATE('2015-03-16', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('debs', 2004, 'Lacking enough material for a full-length movie, D.E.B.S. is short on both plot and laughs.', TO_DATE('2004-02-18', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('december boys', 2007, 'December Boys'' location and settings are invitingly gorgeous, but the coming-of-age drama that takes place on them is uneventful and far too sentimental.', TO_DATE('2007-09-06', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deception', 2008, 'Deception is a middling, predictable potboiler with mediocre dialogue and ludicrous plot twists.', TO_DATE('2008-04-18', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deck the halls', 2006, 'Relying on flat humor and a preposterous plot, Deck the Halls is an unnecessarily mean-spirited holiday movie that does little to put viewers in a holiday mood.', TO_DATE('2006-11-18', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dedication', 2007, 'Mandy Moore and Billy Crudup''s lack of chemistry in Dedication makes it hard to maintain interest in this confused love story.', TO_DATE('2007-01-24', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the deep end', 2001, 'A well-acted film noir with arresting visuals.', TO_DATE('2001-06-07', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deep impact', 1998, 'A tidal wave of melodrama sinks Deep Impact''s chance at being the memorable disaster flick it aspires to be.', TO_DATE('1998-05-08', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deep red profondo rosso', 2001, 'The kinetic camerawork and brutal over-the-top gore that made Dario Argento famous is on full display, but the addition of a compelling, complex story makes Deep Red a masterpiece.', TO_DATE('2001-07-24', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deep rising', 1998, 'Its fleeting glimpses of creature feature mayhem are certainly dumb fun, but Deep Rising cribs from far too many better movies to stand on its own.', TO_DATE('1998-01-30', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deep sea 3d', 2006, 'Viewers will welcome being whisked away to this magical world of exotic sea life.', TO_DATE('2006-02-22', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deepwater horizon', 2016, 'Deepwater Horizon makes effective use of its titular man-made disaster to deliver an uncommonly serious -- yet still suitably gripping -- action thriller.', TO_DATE('2016-09-13', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deerskin', 2019, 'Led by a daring performance from Jean Dujardin, Deerskin finds writer-director Quentin Dupieux working in a more accessible -- yet still distinctive -- vein.', TO_DATE('2019-05-15', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('defendor', 2009, 'Defendor''s reach occasionally exceeds its grasp, but this unique take on the superhero genre is held together by Woody Harrelson''s solid performance.', TO_DATE('2009-09-01', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('defiance', 2008, 'Professionally made but artistically uninspired, Ed Zwick''s story of Jews surviving WWII in the Belarus forest lacks the emotional punch of the actual history.', TO_DATE('2008-11-08', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('déjà vu', 2006, 'Tony Scott tries to combine action, science fiction, romance, and explosions into one movie, but the time travel conceit might be too preposterous and the action falls apart under scrutiny.', TO_DATE('2006-11-16', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('delgo', 2008, 'Delgo features a blend of plot elements from earlier (and superior) fantasy films, with weaker animation and dull characters.', TO_DATE('2008-12-09', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('delicatessen', 2000, 'Director Jean-Pierre Jeunet deftly combines horror, sci-fi, and humor in Delicatessen, a morbid comedy set in a visually ravishing futuristic dystopia.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deliver us from eva', 2003, 'Though Union and LL Cool J are appealing romantic leads, Deliver Us From Eva is too predictable and contrived.', TO_DATE('2003-01-25', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deliver us from evil', 2006, 'Deliver Us From Evil is a superb documentary and a searing look at an institution protecting its leaders at the expense of its followers. A profoundly disturbing chronicle of a wolf in sheep''s clothing, the film builds a clear-eyed case against pedophile priest Oliver O''Grady, and the Catholic bureaucracy that protected him. The recollections of O''Grady''s victims are nothing short of shocking and heartbreaking.', TO_DATE('2006-09-19', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deliver us from evil', 2014, 'Director Scott Derrickson continues to have a reliably firm grasp on creepy atmosphere, but Deliver Us from Evil''s lack of original scares is reflected in its shopworn title.', TO_DATE('2014-07-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deliverance', 2000, 'Given primal verve by John Boorman''s unflinching direction and Burt Reynolds'' star-making performance, Deliverance is a terrifying adventure.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('delivery man', 2013, 'It has an undeniably sweet charm, and Vince Vaughn is eminently likable in the lead role, but The Delivery Man suffers in comparison to Starbuck, the hit Canadian comedy that inspired it.', TO_DATE('2013-11-12', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('delovely', 2004, 'Musical numbers save movie from cliches.', TO_DATE('2004-05-24', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('delta farce', 2007, 'Too afraid to be a real satire of the Iraq War, Delta Farce instead devolves into a reprehensible, unfunny mix of slapstick, gay panic, and flatulence jokes.', TO_DATE('2007-05-11', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('demolition', 2015, 'Demolition benefits from a stellar cast, even if their solid work isn''t always enough to prop up a confused story that aims for profundity but too often settles for clichés.', TO_DATE('2015-09-10', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('demolition man', 1993, 'A better-than-average sci-fi shoot-em-up with a satirical undercurrent, Demolition Man is bolstered by strong performances by Sylvester Stallone, Wesley Snipes, and Sandra Bullock.', TO_DATE('1993-10-08', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('demon', 2015, 'Ambitious and beautifully shot, Demon delivers a gripping -- and sadly final -- testament to the singular talent possessed by director/co-writer Marcin Wrona.', TO_DATE('2015-09-24', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('demonlover', 2002, 'A stylish but convoluted mess without any sympathetic characters.', TO_DATE('2002-06-05', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('den of thieves', 2018, 'Den of Thieves pays energetic homage to classic heist thrillers of the past; unfortunately, it never comes close to living up to its obvious inspirations.', TO_DATE('2018-01-18', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('denial', 2016, 'If Denial doesn''t quite do its incredible story complete justice, it comes close enough to offer a satisfying, impactful drama -- and another powerful performance from Rachel Weisz.', TO_DATE('2016-09-12', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dennis the menace', 2000, 'Walter Matthau does a nice job as Mr. Wilson, but Dennis the Menace follows the Home Alone formula far too closely.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the departed', 2006, 'Featuring outstanding work from an excellent cast, The Departed is a thoroughly engrossing gangster drama with the gritty authenticity and soupy morality we come to expect from Martin Scorsese.', TO_DATE('2006-09-23', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('depraved', 2019, 'A thrillingly effective update on a classic story, Depraved jolts a familiar monster back to life with a potent blend of timely themes and old-school chills.', TO_DATE('2019-03-20', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('derailed', 2005, 'With miscast stars, a ludicrous plot and an obvious twist, Derailed embodies its name all too aptly.', TO_DATE('2005-11-03', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('derrida', 2002, 'Derrida''s intelligence and engaging personality make him an intriguing documentary subject.', TO_DATE('2002-08-21', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the descent', 2005, 'Deft direction and strong performances from its all-female cast guide The Descent, a riveting, claustrophobic horror film.', TO_DATE('2005-07-05', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('desert bayou', 2007, 'Although the presentation is sometimes clumsy, the compelling interviews and story make Desert Bayou always informative and enthralling.', TO_DATE('2007-09-20', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('desert dancer', 2015, 'Desert Dancer never finds an agreeable rhythm, resulting in a musical drama that doesn''t deliver on the promised spectacle or political commentary.', TO_DATE('2015-04-05', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('desierto', 2015, 'Desierto''s thought-provoking themes and refreshing perspective are unfortunately offset by a predictable plot and thinly written characters.', TO_DATE('2015-10-28', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('desk set', 2000, 'Desk Set reunites one of cinema''s most well-loved pairings for a solidly crafted romantic comedy that charmingly encapsulates their timeless appeal.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('desperate measures', 1997, 'Times aren''t desperate enough for this lame thriller to be called for.', TO_DATE('1997-06-01', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('desperately seeking susan', 2000, 'Desperately Seeking Susan works with its fairy tale depiction of New York and the fun, frothy chemistry generated by its two leads.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('despicable me 2', 2013, 'Despicable Me 2 offers plenty of eye-popping visual inventiveness and a number of big laughs.', TO_DATE('2013-06-16', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('despicable me 3', 2017, 'Despicable Me 3 should keep fans of the franchise consistently entertained with another round of colorful animation and zany -- albeit somewhat scattershot -- humor.', TO_DATE('2017-06-14', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('despite the falling snow', 2016, 'Despite the Falling Snow''s slick production and appealing cast struggle to elevate a feeble script, resulting in a Cold War thriller that never raises the temperature.', TO_DATE('2016-04-07', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('destination wedding', 2018, 'Destination Wedding reunites Keanu Reeves and Winona Ryder for a sour comedy whose initially promising misanthropic twist overpowers the chemistry of its leads.', TO_DATE('2018-08-30', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('destroyer', 2018, 'Destroyer''s grueling narrative is as uncompromising as Nicole Kidman''s central performance, which adds extra layers to a challenging film that leaves a lingering impact.', TO_DATE('2018-09-06', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('detachment', 2011, 'Detachment''s heart is in the right place, but overall it doesn''t offer any solutions to its passionate ranting.', TO_DATE('2011-04-26', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('detention', 2011, 'Director Joseph Kahn''s relentlessly kinetic style gives Detention a rebellious kick, but the overload of ideas keeps this genre mashup from ever cohering into a satisfying whole.', TO_DATE('2011-03-19', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('detroit', 2017, 'Detroit delivers a gut-wrenching -- and essential -- dramatization of a tragic chapter from America''s past that draws distressing parallels to the present.', TO_DATE('2017-07-23', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('detroit rock city', 1999, 'Silly plot, over-the-top directing style.', TO_DATE('1999-08-13', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('detropia', 2012, 'Detropia takes a comprehensive yet intimate -- and above all devastatingly powerful -- look at the rise and economic ruin of an American city.', TO_DATE('2012-01-24', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deuce bigalow male gigolo', 2000, 'According to critics, Deuce Bigalow is just too dumb and filled with old, tired gags.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deuce bigalow european gigolo', 2005, 'A witless follow-up to the surprise 1999 hit, Deuce Bigalow: European Gigolo is raunchy, politically incorrect, and not particularly funny.', TO_DATE('2005-08-09', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('deuces wild', 2002, 'Melodramatic and weighed down with silly dialogue, Deuces Wild is a forgettable, overheated thriller that leaves no cliche unturned.', TO_DATE('2002-04-24', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('devil', 2010, 'It''s better than many of the other films M. Night Shyamalan has been associated with, but Devil never gets more than a few low-budget thrills out of its fiendishly promising premise.', TO_DATE('2010-09-17', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the devil came on horseback', 2007, 'The Devil Came on Horseback is both a strong primer on the complexities of the situation in Darfur and a harrowing first-person doc.', TO_DATE('2007-01-24', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('devil in a blue dress', 1995, 'Humor, interesting characters, and attention to details make the stylish Devil in a Blue Dress an above average noir.', TO_DATE('1995-09-29', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the devils advocate', 2000, 'Though it is ultimately somewhat undone by its own lofty ambitions, The Devil''s Advocate is a mostly effective blend of supernatural thrills and character exploration.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the devils backbone el espinazo del diablo', 2001, 'Creepily atmospheric and haunting, The Devil''s Backbone is both a potent ghost story and an intelligent political allegory.', TO_DATE('2001-09-24', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('devils due', 2014, 'Derivative and mostly uninspired, Devil''s Due adds little to either the found-footage or horror genres that it''s content to mimic.', TO_DATE('2014-01-14', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('devils knot', 2013, 'Devil''s Knot covers fact-based ground that''s already been well-traveled with multiple (and far more compelling) documentaries.', TO_DATE('2013-09-03', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the devils rejects', 2005, 'Zombie has improved as a filmmaker since "House of 1000 Corpses" and will please fans of the genre, but beware -- the horror is nasty, relentless, and sadistic.', TO_DATE('2005-06-12', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dhamma brothers', 2008, 'This thoughtful if rough hewn doc about death row inmates who discover Buddhism inspires hope that all of us are worthy of redemption.', TO_DATE('2008-04-08', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dheepan', 2015, 'Dheepan offers a timely, powerful look at the modern immigrant experience in Europe.', TO_DATE('2015-05-26', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diablo', 2015, 'Diablo has neither the intelligence nor the originality to compete with the revisionist latter-day Westerns it owes obvious debts to.', TO_DATE('2015-12-23', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dial m for murder', 2000, 'Dial M for Murder may be slightly off-peak Hitchcock, but by any other standard, it''s a sophisticated, chillingly sinister thriller -- and one that boasts an unforgettable performance from Grace Kelly to boot.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diamonds are forever', 1971, 'Diamonds are Forever is a largely derivative affair, but it''s still pretty entertaining nonetheless, thanks to great stunts, witty dialogue, and the presence of Sean Connery.', TO_DATE('1971-12-17', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diana', 2013, 'Naomi Watts tries hard in the title role, but Diana buries her efforts under a shoddy script and clumsy direction.', TO_DATE('2013-09-05', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diana kennedy nothing fancy', 2019, 'A documentary that lives up to its title, Diana Kennedy: Nothing Fancy shines an entertaining spotlight on the career and delightful personality of its subject.', TO_DATE('2019-03-11', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diana vreeland the eye has to travel', 2012, 'An affectionate portrait created with visual flair, Diana Vreeland is entertaining, informative, and stylish, due in large part to its charismatic subject.', TO_DATE('2012-05-18', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diane', 2017, 'A small-scale drama rich with meaning, Diane offers audiences an uncommonly empathetic and wise look at life -- and stellar work from Mary Kay Place in the title role.', TO_DATE('2017-08-27', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diary of the dead', 2007, 'As Diary of the Dead proves, time hasn''t subdued George A. Romero''s affection for mixing politics with gore, nor has it given him cinematic grace or subtlety.', TO_DATE('2007-09-08', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diary of a mad black woman', 2005, 'Tyler Perry''s successful play can''t make the move to the screen; this mix of slapstick, melodrama and spirituality lacks a consistent tone.', TO_DATE('2005-02-14', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diary of a wimpy kid', 2010, 'Unlike its bestselling source material, Diary of a Wimpy Kid fails to place a likable protagonist at the center of its middle-school humor -- and its underlying message is drowned out as a result.', TO_DATE('2010-03-16', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diary of a wimpy kid 2 rodrick rules', 2010, 'Moderately witty and acceptably acted, Diary of a Wimpy Kid 2 isn''t much worse than the first installment.', TO_DATE('2010-09-17', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diary of a wimpy kid dog days', 2012, 'Overly familiar and a bit too reliant on slapstick, the sitcom-like Dog Days fails to improve upon previous installments and will likely appeal to few outside its target audience.', TO_DATE('2012-07-31', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diary of a wimpy kid the long haul', 2017, 'With an all-new cast but the same juvenile humor, Diary of a Wimpy Kid: The Long Haul finds the franchise still stuck in arrested -- and largely unfunny -- development.', TO_DATE('2017-05-15', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dickie roberts former child star', 2003, 'A so-so David Spade comedy with a few laughs.', TO_DATE('2003-08-16', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('die another day', 2002, 'Its action may be bit too over-the-top for some, but Die Another Day is lavishly crafted and succeeds in evoking classic Bond themes from the franchise''s earlier installments.', TO_DATE('2002-11-11', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('die hard', 2000, 'Its many imitators (and sequels) have never come close to matching the taut thrills of the definitive holiday action classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('die hard 2', 2000, 'It lacks the fresh thrills of its predecessor, but Die Hard 2 still works as an over-the-top -- and reasonably taut -- big-budget sequel, with plenty of set pieces to paper over the plot deficiencies.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('die hard with a vengeance', 1995, 'Die Hard with a Vengeance benefits from Bruce Willis and Samuel L. Jackson''s barbed interplay, but clatters to a bombastic finish in a vain effort to cover for an overall lack of fresh ideas.', TO_DATE('1995-05-19', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('die wand the wall', 2012, 'Die Wand (The Wall) preserves its source material''s thought-provoking themes -- and serves as a brilliant showcase for Martina Gedeck, whose performance carries the film.', TO_DATE('2012-02-21', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dig', 2004, 'So you wanna be a rock ''n'' roll star? Dig! compellingly chronicles the ups and downs of the Dandy Warhols and the Brian Jonestown Massacre, two ambitious bands whose love/hate relationship embodies many of the potential pratfalls of the music business.', TO_DATE('2004-01-27', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diggers', 2006, 'Though the plot may be familiar, Diggers is just pleasant, charming, and heartwarming enough to make it worth your while.', TO_DATE('2006-09-18', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('digging for fire', 2015, 'Digging for Fire finds director/co-writer Joe Swanberg working from a familiar palette, but in ways that suggest he''s taking new and exciting strides as a filmmaker.', TO_DATE('2015-01-27', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diminished capacity', 2008, 'This low-key comedy about memory loss offers mild pleasures but is too bland to fully resonate.', TO_DATE('2008-01-23', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diner', 2000, 'Diner transports audiences back to the 1950s with a refreshing lack of sentimentality, evoking the thrill of everyday life with its ensemble''s potent chemistry and an authentic sense of spontaneity.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dinner for schmucks', 2010, 'It doesn''t honor its source material -- or its immensely likable leads -- as well as it should, but Dinner for Schmucks offers fitfully nourishing comedy.', TO_DATE('2010-07-16', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dinosaur 13', 2014, 'It''s undeniably slanted and doesn''t cover as much of the story as it should, but Dinosaur 13 makes for gripping documentary viewing, flaws and all.', TO_DATE('2014-01-17', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dior and i', 2014, 'Dior and I will obviously appeal to fashion fans, but this beautifully tailored documentary may draw in even the least sartorially inclined.', TO_DATE('2014-04-25', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('diplomacy', 2014, 'For filmgoers who value character development and smart dialogue over plot, Diplomacy yields rich, powerfully acted rewards.', TO_DATE('2014-10-10', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dirt music', 2019, 'As beautifully filmed as it is emotionally hollow, Dirt Music goes digging for romance but only buries the audience in mounds of melodrama.', TO_DATE('2019-09-09', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dirty dancing', 2000, 'Like its winsome characters, Dirty Dancing uses impressive choreography and the power of song to surmount a series of formidable obstacles.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dirty dancing', 2017, 'Clever casting can''t save Dirty Dancing, a hollow remake that trips over its own good intentions.', TO_DATE('2017-05-01', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dirty dancing havana nights', 2004, 'Cheesy, unnecessary remake.', TO_DATE('2004-02-23', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dirty dozen', 2000, 'Amoral on the surface and exuding testosterone, The Dirty Dozen utilizes combat and its staggering cast of likable scoundrels to deliver raucous entertainment.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dirty grandpa', 2016, 'Like a Werther''s Original dropped down a sewer drain, Dirty Grandpa represents the careless fumbling of a classic talent that once brought pleasure to millions.', TO_DATE('2016-01-21', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dirty harry', 2000, 'As tough and taciturn as its no-nonsense hero, Dirty Harry delivers a deceptively layered message without sacrificing an ounce of its solid action impact.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dirty love', 2005, 'The laugh-free Dirty Love is a comedy dead zone -- it''s aggressively crude and shoddily constructed.', TO_DATE('2005-02-01', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dirty pretty things', 2002, 'An illuminating and nuanced film about the exploitation of illegal immigrants.', TO_DATE('2002-09-21', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dirty rotten scoundrels', 2000, 'A buoyant, clever update of the conman flick Bedtime Story, with plenty of comedic jousting resulting from a winning chemistry between Michael Caine and Steve Martin.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a dirty shame', 2004, 'John Waters casts his provocative eye toward libido in a sex satire that won''t leave audiences feeling too Dirty, but this sophomoric farce doesn''t strike a nerve like his best work -- a real Shame.', TO_DATE('2004-07-29', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dirty wars', 2013, 'Some viewers may find fault with director Rick Rowley''s filmmaking methods, but they aren''t distracting enough to keep Dirty Wars from serving as a terribly compelling argument against elements of American foreign policy.', TO_DATE('2013-01-29', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('disappearance at clifton hill', 2019, 'While admittedly a bit less than the sum of its intriguing parts, Disappearance at Clifton Hill offers an entertaining diversion for noir fans.', TO_DATE('2019-09-03', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('disappearances', 2006, 'Disappearances benefits from a well-cast Kris Kristofferson in the lead role, but his presence isn''t always enough to disguise an increasingly nonsensical story.', TO_DATE('2006-11-09', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('disaster movie', 2008, 'Returning to their seemingly bottomless well of flatulence humor, racial stereotypes, and stale pop culture gags, Jason Friedberg and Aaron Seltzer have produced what is arguably their worst Movie yet.', TO_DATE('2008-08-28', 'YYYY-MM-DD'), 1.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('disconnect', 2012, 'It''s didactic in spots and melodramatic in others, but Disconnect''s strong cast helps make it a timely, effective exploration of modern society''s technological overload.', TO_DATE('2012-09-17', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('disgrace', 2008, 'Featuring outstanding performances from John Malkovich and newcomer Jessica Haines, Disgrace is a disturbing, powerful drama.', TO_DATE('2008-09-06', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dish', 2000, 'A feel good movie without an abundance of mush.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('disneynature bears', 2014, 'Sweet, beautifully filmed, and admirably short on sugarcoating, Bears continues Disneynature''s winning streak.', TO_DATE('2014-04-09', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('disneynature chimpanzee', 2012, 'Chimpanzee often anthropomorphizes its subjects, but it''s a beautifully filmed, remarkably intimate look at the lives of a family of primates.', TO_DATE('2012-04-13', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('disneynature earth', 2007, 'With its spectacular and extensive footage, Earth is both informative and entertaining.', TO_DATE('2007-11-24', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('disneynature monkey kingdom', 2015, 'Monkey Kingdom''s breathtaking footage of primates in the wild is likely to please animal lovers of all ages.', TO_DATE('2015-04-09', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('disneynature oceans', 2010, 'Oceans adds another visually stunning chapter to the Disney Nature library.', TO_DATE('2010-04-19', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('aladdin', 1992, 'A highly entertaining entry in Disney''s renaissance era," Aladdin is beautifully drawn, with near-classic songs and a cast of scene-stealing characters.', TO_DATE('1992-11-11', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('disobedience', 2017, 'Disobedience explores a variety of thought-provoking themes, bolstered by gripping work from leads Rachel Weisz, Rachel McAdams, and Alessandro Nivola.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('disorder maryland', 2015, 'Well-acted and solidly crafted, Disorder (Maryland) relies on patiently established slow-burning tension to set the stage for an intelligent, intimate psychological thriller.', TO_DATE('2015-07-20', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('banlieue 13 ultimatum district 13 ultimatum', 2009, 'District 13 bites off more than it can chew with its political subtext and questionable script, but the many action sequences are never less than entertaining.', TO_DATE('2009-02-05', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('district 9', 2009, 'Technically brilliant and emotionally wrenching, District 9 has action, imagination, and all the elements of a thoroughly entertaining science-fiction classic.', TO_DATE('2009-07-30', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('district b13 banlieue 13', 2005, 'A nonstop thrill ride, District B13''s dizzying action sequences more than make up for any expository flaws.', TO_DATE('2005-09-20', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('disturbia', 2007, 'Aside from its clichéd resolution, Disturbia is a tense, subtle thriller with a noteworthy performance from Shia LaBeouf.', TO_DATE('2007-03-13', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('william kunstler disturbing the universe', 2009, 'It doesn''t even feign impartiality, but this family-made documentary about the famously rabble-rousing attorney shines a light on the life and times of a divisive public figure.', TO_DATE('2009-11-08', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('divergent', 2014, 'With an adherence to YA formula that undercuts its individualistic message, Divergent opens its planned trilogy in disappointingly predictable fashion.', TO_DATE('2014-03-16', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('divide and conquer the story of roger ailes', 2018, 'Divide & Conquer: The Story of Roger Ailes offers an overview of the media mogul''s rise and fall that proves as engrossing as it is deeply disturbing.', TO_DATE('2018-09-13', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('divided we fall', 2001, 'Divided We Fall takes a complex look at World War II, skillfully balancing humor and gravity.', TO_DATE('2001-02-13', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('divine secrets of the yaya sisterhood', 2002, 'Divine Secrets of the Ya-Ya Sisterhood is more melodramatic than emotionally truthful, and uneven in its mixture of time periods, actresses, laughter and tears.', TO_DATE('2002-05-10', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dixie chicks shut up and sing', 2006, 'Though ostensibly an intimate look at the Dixie Chicks after their 2003 anti-Bush remark, the film achieves broader relevance by exploring how media, politics, and celebrities intertwine.', TO_DATE('2006-09-13', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('django unchained', 2012, 'Bold, bloody, and stylistically daring, Django Unchained is another incendiary masterpiece from Quentin Tarantino.', TO_DATE('2012-12-11', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('do i sound gay', 2014, 'Do I Sound Gay? proves to be a light, affable, entertaining look at a largely unexplored issue.', TO_DATE('2014-09-08', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('do not resist', 2016, 'Do Not Resist takes a grim look at American law enforcement that poses crucial - and potentially frightening - questions.', TO_DATE('2016-04-19', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('do the right thing', 1989, 'Smart, vibrant, and urgent without being didactic, Do the Right Thing is one of Spike Lee''s most fully realized efforts -- and one of the most important films of the 1980s.', TO_DATE('1989-06-14', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('doa dead or alive', 2006, 'With a ridiculous plot and comical acting, checking one''s brain at the door is required before watching DOA: Dead or Alive.', TO_DATE('2006-09-02', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('doc hollywood', 2000, 'Doc Hollywood isn''t particularly graceful in its attempt to put a ''90s spin on its Capraesque formula, but a light touch and a charming cast make its flaws easy to forgive.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('doctor strange', 2016, 'Doctor Strange artfully balances its outré source material against the blockbuster constraints of the MCU, delivering a thoroughly entertaining superhero origin story in the bargain.', TO_DATE('2016-10-23', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dodgeball a true underdog story', 2004, 'Proudly profane and splendidly silly, Dodgeball is a worthy spiritual successor to the goofball comedies of the 1980s.', TO_DATE('2004-06-15', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dog day afternoon', 2000, 'Framed by great work from director Sidney Lumet and fueled by a gripping performance from Al Pacino, Dog Day Afternoon offers a finely detailed snapshot of people in crisis with tension-soaked drama shaded in black humor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dog days', 2018, 'Dog Days is frivolous but frothy, sporting a forgettable cast of human characters but a lovable troupe of pooches that ought to delight viewers looking for a gentle affirmation of humanity''s bond with their furry friends.', TO_DATE('2018-08-07', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dog eat dog', 2016, 'Dog Eat Dog''s refreshing bundle of quirks and surfeit of visual style aren''t quite enough to compensate for an aimlessly forgettable story.', TO_DATE('2016-05-20', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dog soldiers', 2002, 'Frightening, funny, and packed with action, Dog Soldiers is well worth checking out for genre fans -- and marks writer-director Neil Marshall as a talent to keep an eye on.', TO_DATE('2002-05-14', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('doghouse', 2009, 'An amateurish, unfunny and unscary British horror-comedy that could be accused of misogyny.', TO_DATE('2009-06-12', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dogtooth kynodontas', 2009, 'It''ll be too disturbing -- and meandering -- for some, but Dogtooth is as disturbing and startlingly original as modern filmmaking gets.', TO_DATE('2009-09-21', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dogtown and zboys', 2001, 'Dogtown and Z-Boys is a colorful, exhilarating look at the skateboarding subculture.', TO_DATE('2001-05-15', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dogville', 2003, 'A challenging piece of experimental filmmaking.', TO_DATE('2003-05-20', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la dolce vita', 2000, 'An epic, breathtakingly stylish cinematic landmark, La Dolce Vita remains riveting in spite of -- or perhaps because of -- its sprawling length.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dolemite is my name', 2019, 'In dramatizing Rudy Ray Moore''s stranger-than-fiction story, Eddie Murphy makes Dolemite Is My Name just as bold, brash, and ultimately hard to resist as its subject.', TO_DATE('2019-09-08', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dolittle', 2020, 'Dolittle may be enough to entertain very young viewers, but they deserve better than this rote adaptation''s jumbled story and stale humor.', TO_DATE('2020-01-11', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dolores claiborne', 1995, 'Post-Misery Kathy Bates proves to be another wonderful conduit for Stephen King''s novels in this patient, gradually terrifying thriller.', TO_DATE('1995-03-24', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dolphin tale', 2011, 'Wisely dialing down the schmaltz, Dolphin Tale is earnest, sweet, and well-told, a rare family film that both kids and parents can enjoy.', TO_DATE('2011-09-16', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dolphin tale 2', 2014, 'Much like its predecessor, Dolphin Tale 2 offers animal antics and sweet, old-fashioned drama that the whole family can enjoy.', TO_DATE('2014-09-06', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dom hemingway', 2013, 'Jude Law is clearly having fun in Dom Hemingway''s title role, but viewers may find this purposely abrasive gangster dramedy isn''t quite as enjoyable from the other side of the screen.', TO_DATE('2013-09-09', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('domestic disturbance', 2001, 'Well-made but extremely predictable, Domestic Disturbance is an average thriller that may work better on TV.', TO_DATE('2001-10-29', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dominion prequel to the exorcist', 2005, 'While director Schrader''s attempt at a literate, internal exposition on evil temptations and human sin is admirable, this prequel suffers from hit-and-miss psychological tension, poor visual effects, and weak writing -- an overambitious failure of a horror movie.', TO_DATE('2005-05-17', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('domino', 2005, 'The life story of model-turned- bounty-hunter Domino Harvey struggles to get out of this overwrought and excessive biopic.', TO_DATE('2005-09-30', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('domino', 2019, 'A rote thriller whose few flourishes serve as bittersweet reminders of its director''s glory days, Domino continues a streak of DePalma disappointments.', TO_DATE('2019-05-17', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('don juan demarco', 2000, 'Don Juan DeMarco proves that a slight story can translate to entertaining cinema if it''s acted out by a pair of well-matched professionals enjoying their craft.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('don jon', 2013, 'Don Jon proves to be an amiable directing debut for Joseph Gordon-Levitt, and a vivacious showcase for his co-star, Scarlett Johansson.', TO_DATE('2013-01-19', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('don mckay', 2009, 'Thomas Haden Church and Elisabeth Shue do their best with what they''re given, but Don McKay is too confused and far-fetched to be taken seriously as a noir, and too inconsistent to work as a black comedy.', TO_DATE('2009-09-01', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('donkey punch', 2008, 'Donkey Punch begins as a promising thriller, but loses credibility while adhering too closely to genre conventions.', TO_DATE('2008-01-27', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('donnie brasco', 1997, 'A stark, nuanced portrait of life in organized crime, bolstered by strong performances from Al Pacino and Johnny Depp.', TO_DATE('1997-02-28', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('donnie darko', 2001, 'Richard Kelly''s debut feature Donnie Darko is a daring, original vision, packed with jarring ideas and intelligence and featuring a remarkable performance from Jake Gyllenhaal as the troubled title character.', TO_DATE('2001-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('donnybrook', 2018, 'Donnybrook has a solid cast and noble intentions, but they''re overwhelmed by surface storytelling and unrelentingly grim violence.', TO_DATE('2018-09-08', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dont be afraid of the dark', 2011, 'While it''s pleasantly atmospheric and initially quite scary, Don''t Be Afraid of the Dark ultimately fails to deliver the skin-crawling chills of the original.', TO_DATE('2011-06-27', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dont breathe', 2016, 'Don''t Breathe smartly twists its sturdy premise to offer a satisfyingly tense, chilling addition to the home invasion genre that''s all the more effective for its simplicity.', TO_DATE('2016-03-12', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dont come knocking', 2005, 'The cinematography conjures beautifully evocative landscapes, but aside from that, the film is meandering and pointless.', TO_DATE('2005-05-19', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dont let go relive', 2019, 'While admirably intelligent and well-cast, Don''t Let Go suffers from a formulaic approach compounded by its uneven writing and an awkward tonal balance.', TO_DATE('2019-01-28', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dont look now', 2000, 'Don''t Look Now patiently builds suspense with haunting imagery and a chilling score -- causing viewers to feel Donald Sutherland and Julie Christie''s grief deep within.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hot pursuit', 2015, 'Shrill and unfunny, Hot Pursuit bungles what should have been an easy opportunity to showcase Reese Witherspoon and Sofia Vergara''s likable odd-couple chemistry.', TO_DATE('2015-05-05', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dont say a word', 2001, 'Don''t Say A Word is slick and competently made, but the movie is routine and stretches believability with many eye rolling moments.', TO_DATE('2001-01-01', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dont stop believin everymans journey', 2012, 'An energetic but thin portrait of the venerable rock band Journey, Don''t Stop Believin'' gets a boost from new singer Arnel Pineda''s charming personality.', TO_DATE('2012-04-26', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dont tell mom the babysitters dead', 1991, 'It has an amusing enough premise, but Don''t Tell Mom the Babysitter''s Dead will just leave viewers pining for the madcap hijinks promised by the title.', TO_DATE('1991-06-07', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dont think twice', 2016, 'Don''t Think Twice offers a bittersweet look at the comedian''s life that''s as genuinely moving as it is laugh-out-loud funny -- and a brilliant calling card for writer-director Mike Birbiglia.', TO_DATE('2016-03-14', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dont worry he wont get far on foot', 2018, 'Don''t Worry, He Won''t Get Far on Foot avoids inspirational biopic clichés thanks to sensitive work from writer-director Gus Van Sant and the admirable efforts of a well-chosen cast.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('doom', 2005, 'The FPS sections are sure to please fans of the video game, but lacking in plot and originality to please other moviegoers.', TO_DATE('2005-10-18', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('doomsday', 2008, 'Doomsday is a pale imitation of previous futuristic thrillers, minus the cohesive narrative and charismatic leads.', TO_DATE('2008-03-14', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the doors', 2000, 'Val Kilmer delivers a powerhouse performance as one of rock''s most incendiary figures, but unfortunately, Oliver Stone is unable to shed much light on the circus surrounding the star.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dope', 2015, 'Featuring a starmaking performance from Shameik Moore and a refreshingly original point of view from writer-director Rick Famuyiwa, Dope is smart, insightful entertainment.', TO_DATE('2015-01-25', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dora and the lost city of gold', 2019, 'Led by a winning performance from Isabela Moner, Dora and the Lost City of Gold is a family-friendly adventure that retains its source material''s youthful spirit.', TO_DATE('2019-07-29', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dormant beauty', 2013, 'As complex and compelling a work as its ripped-from-the-headlines storyline deserves, Dormant Beauty serves as a delightfully thorny testament to director Marco Bellocchio and his talented cast.', TO_DATE('2013-02-20', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dot the i', 2003, 'dot the i starts out as a standard love triangle, but last minute revelations turn the movie into a gimmick.', TO_DATE('2003-04-27', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('double dare', 2004, 'An engaging look at two women fighting to stay employed in a profession dominated by men.', TO_DATE('2004-03-08', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('double dragon', 2002, 'Double Dragon''s clever use of special effects cannot mask the film''s overly simplistic storyline and cheesy dialogue.', TO_DATE('2002-10-22', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('double indemnity', 1944, 'A dark, tautly constructed adaptation of James M. Cain''s novel -- penned by Billy Wilder and Raymond Chandler -- Double Indemnity continues to set the standard for the best in Hollywood film noir.', TO_DATE('1944-09-06', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la double vie de véronique the double life of veronique', 2000, 'Operating on confounding dream logic with Irene Jacob''s beautiful performance as a guide, The Double Life of Veronique offers a moving meditation on perception for audiences willing to indulge its inscrutability.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('double lover lamant double', 2017, 'Double Lover offers kinky pleasures that should thrill fans of classic erotic cinema while adding some uniquely transgressive European twists.', TO_DATE('2017-05-26', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('doubt', 2008, 'Doubt succeeds on the strength of its top-notch cast, who successfully guide the film through the occasional narrative lull.', TO_DATE('2008-11-07', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dougs 1st movie', 1999, 'Doug''s 1st Movie may entertain very young fans of its main character, but essentially amounts to a forgettable feature-length episode of his show.', TO_DATE('1999-03-26', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('down a dark hall', 2018, 'Down a Dark Hall is more stylish than scary, although its foreboding atmosphere may raise a few goosebumps among younger viewers.', TO_DATE('2018-07-12', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('down and derby', 2005, 'Dull, predictable family fare.', TO_DATE('2005-04-14', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('down and out in beverly hills', 2000, 'An enjoyable farce that relocates Jean Renoir''s Boudu Saved From Drowning to ''80s California, offering fine comedic performances from Nick Nolte, Richard Dreyfuss and Bette Midler.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('down by law', 2000, 'Funny, original, and thoroughly cinematic, Down by Law represents writer-director Jim Jarmusch at his most ingratiating and evocative.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('down in the valley', 2005, 'The premise of Old West clashing with modern suburbia is fresh and initially intriguing, but the second act degenerates into a clumsy jumble of events which strain credibility.', TO_DATE('2005-05-17', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('down periscope', 1996, 'Down Periscope takes audiences on an aimless voyage for aquatic hijinks, proving there really aren''t any effective sub-stitutes for a well-written script.', TO_DATE('1996-03-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('down to the bone', 2004, 'A vivid portrayal of the effects of drug abuse that avoids cinematic clichés, Down to the Bone is a winning effort that features Vera Farmiga''s breakout performance.', TO_DATE('2004-01-27', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('down to you', 2000, 'Down to You is ruined by a bland, by-the-numbers plot and an awful script.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('down with love', 2003, 'Looks great, but Zellweger and McGregor have no chemistry together, and the self-satisfied, knowing tone grates.', TO_DATE('2003-04-28', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('downfall der untergang', 2004, 'Downfall is an illuminating, thoughtful and detailed account of Hitler''s last days.', TO_DATE('2004-09-18', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('downhill racer', 2001, 'Downhill Racer plunges the viewer thrillingly into the action of the sport -- and continues to hold the attention as a thoughtful drama.', TO_DATE('2001-10-10', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('downsizing', 2017, 'Downsizing assembles a talented cast in pursuit of some truly interesting ideas -- which may be enough for some audiences to forgive the final product''s frustrating shortcomings.', TO_DATE('2017-08-30', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('downton abbey', 2019, 'Downton Abbey distills many of the ingredients that made the show an enduring favorite, welcoming fans back for a fittingly resplendent homecoming.', TO_DATE('2019-09-09', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dr dolittle', 1998, 'Doctor Dolittle finds some mirth in the novelty of wisecracking critters, but this family feature''s treacly tone is made queasy by a reliance on scatological gags that undercut the intended warmth.', TO_DATE('1998-06-26', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dr dolittle 2', 2000, 'Although there are laughs to be had in Dr. Dolittle 2, its preoccupation with toilet humor and Murphy''s restrained performance makes this a missed opportunity.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dr giggles', 2000, 'Larry Drake''s deranged performance as the titular doctor is just about all that distinguishes Dr. Giggles from its slasher brethren.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dr no', 1962, 'Featuring plenty of the humor, action, and escapist thrills the series would become known for, Dr. No kicks off the Bond franchise in style.', TO_DATE('1962-10-05', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dr strangelove or how i learned to stop worrying and love the bomb', 2000, 'Stanley Kubrick''s brilliant Cold War satire remains as funny and razor-sharp today as it was in 1964.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dr t and the women', 2000, 'In terms of quality, Dr. T and the Women is one of Altman''s good-but-not-great films. In typical Altman style, it features some great ensemble acting, including a wonderful performance by Richard Gere.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dracula 2000', 2000, 'This retelling trys to offer a different spin on the origin of Dracula. Unfortunately, there''s nothing here audiences haven''t seen before.', TO_DATE('2000-12-21', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dracula dead and loving it', 2000, 'Lacking any of the comedic bite that audiences have come to expect from a Mel Brooks farce, this vampire parody just plain ol'' sucks.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dracula untold', 2014, 'Neither awful enough to suck nor sharp enough to bite, Dracula Untold misses the point of its iconic character''s deathless appeal.', TO_DATE('2014-09-30', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('draculas daughter', 2001, 'Dracula''s Daughter extends the Universal horror myth in an interesting direction, but the talky script and mild atmosphere undermine its ambition.', TO_DATE('2001-08-21', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('draft day', 2014, 'It''s perfectly pleasant for sports buffs and Costner fans, but overall, Draft Day lives down to its title by relying too heavily on the sort of by-the-numbers storytelling that only a statistician could love.', TO_DATE('2014-04-08', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('drag me to hell', 2009, 'Sam Raimi returns to top form with Drag Me to Hell, a frightening, hilarious, delightfully campy thrill ride.', TO_DATE('2009-01-28', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dragged across concrete', 2018, 'As grim and grinding as its title, Dragged Across Concrete opts for slow-burning drama instead of high-speed thrills -- and has just the right cast to make it work.', TO_DATE('2018-09-04', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dragon ball super broly', 2019, 'Dragon Ball Super: Broly may seem like colorful chaos to newcomers, but for longtime fans, it represents this long-running franchise near its action-packed apogee.', TO_DATE('2019-01-08', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dragon blade tian jiang xiong shi', 2015, 'Dragon Blade is beautifully staged and choreographed, but between the battles, its talented cast is overwhelmed by a dull story and choppy editing.', TO_DATE('2015-02-26', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dragon the bruce lee story', 1993, 'While its impact is blunted by an overly reverential approach to its subject, Dragon: The Bruce Lee Story remains a reasonably entertaining biopic of the martial arts legend.', TO_DATE('1993-05-07', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dragon wars', 2007, 'Dragon Wars'' special effects can''t make up for an unfocused script and stale acting.', TO_DATE('2007-07-21', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dragonball evolution', 2009, 'Executed with little panache or invention, Dragonball Evolution lacks the magic that made the books upon which it was based a cult sensation.', TO_DATE('2009-03-26', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dragonheart', 1996, 'Dragonheart gives us medieval action, a splendidly mulleted Dennis Quaid, and Sean Connery as a talking dragon -- and, unfortunately, a story that largely fails to engage.', TO_DATE('1996-05-31', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dragonslayer', 2002, 'An atypically dark Disney adventure, Dragonslayer puts a realistic spin -- and some impressive special effects -- on a familiar tale.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dream house', 2011, 'Dream House is punishingly slow, stuffy, and way too obvious to be scary.', TO_DATE('2011-09-30', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dreamcatcher', 2003, 'An incoherent and overly long creature feature.', TO_DATE('2003-03-17', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dreamer inspired by a true story', 2005, 'Though formulaic, this horse story''s saving grace is its strong performances.', TO_DATE('2005-09-09', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dreamgirls', 2006, 'Dreamgirls'' simple characters and plot hardly detract from the movie''s real feats: the electrifying performances and the dazzling musical numbers.', TO_DATE('2006-11-20', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dreamland', 2020, 'While it may entrance audiences in search of the thoroughly strange, Dreamland lives down to its title by failing to cohere in any meaningful way.', TO_DATE('2020-04-08', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dreams', 2000, 'This late-career anthology by Akira Kurosawa often confirms that Dreams are more interesting to the dreamer than their audience, but the directorial master still delivers opulent visions with a generous dose of heart.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dreamscape', 2000, 'Dreamscape mixes several genres -- horror, sci-fi, action -- and always maintains a sense of adventure and humor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dredd', 2012, 'Fueled by bombastic violence and impressive special effects, rooted in self-satire and deadpan humor, Dredd 3D does a remarkable job of capturing its source material''s gritty spirit.', TO_DATE('2012-07-12', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('drillbit taylor', 2008, 'Owen Wilson''s charms can''t save Drillbit Taylor, an unfunny, overly familiar bullied-teen comedy.', TO_DATE('2008-03-16', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('drinking buddies', 2013, 'Smart, funny, and powered by fine performances from Olivia Wilde and Jake Johnson, Drinking Buddies offers a bittersweet slice of observational comedy.', TO_DATE('2013-03-11', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('drive angry', 2011, 'It may deliver the over-the-top action pieces, but Drive Angry prefers to work safely within grindhouse formula than do something truly unique.', TO_DATE('2011-01-21', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('drive', 2011, 'With its hyper-stylized blend of violence, music, and striking imagery, Drive represents a fully realized vision of arthouse action.', TO_DATE('2011-05-20', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('drive hard', 2014, 'Hitting the pavement with an empty tank of inspiration, Drive Hard goes through its action beats in fits and starts before puttering out completely.', TO_DATE('2014-06-25', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('drive me crazy', 1999, 'Unoriginal story.', TO_DATE('1999-10-01', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('driven', 2018, 'Compelling performances from an outstanding cast help Driven take audiences on an enjoyably stranger-than-fiction joyride.', TO_DATE('2018-09-09', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('driveways', 2019, 'Understated yet powerful, Driveways is a character study anchored in fundamental decency -- and a poignant farewell to Brian Dennehy.', TO_DATE('2019-02-12', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('drop dead fred', 2000, 'Tackling mature themes with an infantile sensibility, Drop Dead Fred is an ill-conceived family comedy that is more likely to stir up a headache than the imagination.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('drop dead gorgeous', 2000, 'It''s dark humor sometimes hits, but mostly misses the target.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('drowning mona', 2000, 'A whodunnit that stacks its lists of suspects with wasted character actors, Drowning Mona is a twee farce that will prompt audiences to tune out before the mystery is solved.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('drug war', 2013, 'A taut, solidly constructed action thriller with uncommon intelligence, Drug War delivers exhilarating set pieces without skimping on sophisticated filmmaking.', TO_DATE('2013-04-25', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('drugstore cowboy', 2000, 'Drugstore Cowboy takes us into a violent, transient world with cool, contemplative style.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('drumline', 2002, 'Essentially a sports movie with drums, the energetic Drumline somehow manages to make the familiar seem fresh.', TO_DATE('2002-12-08', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('drunk stoned brilliant dead the story of the national lampoon', 2015, 'Drunk Stoned Brilliant Dead might not be the definitive doc National Lampoon fans are waiting for, but it''s still almost as transgressively funny as the magazine in its heyday.', TO_DATE('2015-01-27', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('duane hopwood', 2005, 'Duane Hopwood proves David Schwimmer has dramatic chops that have been too rarely tested onscreen, but fails to engage as an overall viewing experience.', TO_DATE('2005-10-29', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('duck butter', 2018, 'Duck Butter has a pair of compelling leads and a refreshing female-driven perspective, but its story is ultimately too thin to support a feature-length production.', TO_DATE('2018-04-19', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('duck season temporada de patos', 1800, 'This modest cinematic slice-of-life manages to subtly capture many small but resonant and truthful moments of adolescence.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('duck soup', 2000, 'Fueled by inspired silliness and blessed with some of the Marx brothers'' most brilliant work, Duck Soup is one of its -- or any -- era''s finest comedies.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('duck you sucker a fistful of dynamite giù la testa', 2000, 'Duck, You Sucker is a saucy helping of spaghetti western, with James Coburn and Rod Steiger''s chemistry igniting the screen and Sergio Leone''s bravura style on full display.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dude wheres my car', 2000, 'The movie isn''t funny, the plot is too thin, and the production values feel more like a TV sitcom than a movie.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dudley doright', 1999, 'Gags aren''t that funny.', TO_DATE('1999-08-27', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('due date', 2010, 'Shamelessly derivative and only sporadically funny, Due Date doesn''t live up to the possibilities suggested by its talented director and marvelously mismatched stars.', TO_DATE('2010-10-29', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the duellists', 2000, 'Rich, stylized visuals work with effective performances in Ridley Scott''s take on Joseph Conrad''s Napoleonic story, resulting in an impressive feature film debut for the director.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dukes', 2008, 'Despite the charming principal performances, The Dukes remains little more than an unambitious pet project.', TO_DATE('2008-10-18', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dukes of hazzard', 2005, 'A dumb, goofy, and vacuous adaptation of a TV show where plot is simply an excuse to string together the car chases.', TO_DATE('2005-08-01', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('duma', 2005, 'This is an old-fashioned, richly textured family film that will appeal to children and adults alike.', TO_DATE('2005-04-21', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dumb and dumber', 2000, 'A relentlessly stupid comedy elevated by its main actors: Jim Carrey goes bonkers and Jeff Daniels carries himself admirably in an against-type performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dumb and dumber to', 2014, 'Dumb and Dumber To does have its moments, but not enough of them -- and the Farrelly brothers'' brand of humor is nowhere near as refreshingly transgressive as it once seemed.', TO_DATE('2014-11-12', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dumb and dumberer when harry met lloyd', 2003, 'This lame prequel induces more groans than laughs. Rent the original instead.', TO_DATE('2003-06-07', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dumbo', 2001, 'Dumbo packs plenty of story into its brief runtime, along with all the warm animation and wonderful music you''d expect from a Disney classic.', TO_DATE('2001-02-27', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dumbo', 2019, 'Dumbo is held partly aloft by Tim Burton''s visual flair, but a crowded canvas and overstretched story leave this live-action remake more workmanlike than wondrous.', TO_DATE('2019-03-26', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dumbstruck', 2011, 'Dumbstruck stands as the definitive -- and, not coincidentally, the only -- documentary about ventriloquists.', TO_DATE('2011-04-01', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dumplin', 2018, 'Elevated by a solid soundtrack and a terrific cast, Dumplin'' offers sweetly uplifting drama that adds just enough new ingredients to a reliably comforting formula.', TO_DATE('2018-12-03', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dungeons dragons', 2000, 'Critics say this movie has a cheap look and is badly directed. Despite the presence of talented actors, the performances are really bad, and additionally, some people are offended at Marlon Wayans'' character, calling it a racist throwback to black stereotypes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dunkirk', 2017, 'Dunkirk serves up emotionally satisfying spectacle, delivered by a writer-director in full command of his craft and brought to life by a gifted ensemble cast that honors the fact-based story.', TO_DATE('2017-07-17', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('duplex', 2003, 'It was funnier when it was called Throw Momma From the Train.', TO_DATE('2003-09-12', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('duplicity', 2009, 'Duplicity is well-crafted, smart, and often funny, but it''s mostly more cerebral than visceral and features far too many plot twists.', TO_DATE('2009-03-14', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dust to glory', 2005, 'Amazing footage from the Baja off-road race will give viewers an adrenaline rush.', TO_DATE('2005-02-26', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dying gaul', 2005, 'Though it has a fine cast, The Dying Gaul''s plot feels calculated and too intellectualized.', TO_DATE('2005-04-30', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dying of the light', 2014, 'Dying of the Light envelops the spark of several intriguing talents, leaving audiences lost in a yawning void of uninspired filmmaking.', TO_DATE('2014-11-30', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dysfunktional family', 2003, 'The humor is more profane and offensive than funny.', TO_DATE('2003-02-27', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eagle eye', 2008, 'Eagle Eye is a preposterously plotted thriller that borrows heavily from other superior films.', TO_DATE('2008-09-16', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eagle vs shark', 2007, 'Though there are frequent moments of wit and mordant humor, Eagle vs Shark needs more to distinguish itself from other precious, Napoleon Dynamite-ish comedies.', TO_DATE('2007-01-29', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('early man', 2018, 'Early Man isn''t quite as evolved as Aardman''s best work, but still retains the unique visuals and sweet humor that have made the studio a favorite among animation enthusiasts.', TO_DATE('2018-01-14', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('earth girls are easy', 1989, 'Earth Girls Are Easy is messy, silly, and not particularly bright -- qualities it comes by honestly and deliberately.', TO_DATE('1989-05-12', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('earth to echo', 2014, 'Earth to Echo doesn''t do itself any favors by beggaring comparison to E.T., but for younger viewers, it should prove a reasonably entertaining diversion.', TO_DATE('2014-06-06', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('earthquake', 2000, 'The destruction of Los Angeles is always a welcome sight, but Earthquake offers little besides big actors slumming through crumbling sets.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('earthquake bird', 2019, 'Riley Keough and Alicia Vikander give it their all, but Earthquake Bird suffers from a frustrating inability to bring its literary source material consistently to life.', TO_DATE('2019-10-10', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('easier with practice', 2009, 'This promising debut from writer-director Kyle Patrick Alvarez is anchored by a startlingly honest and tender performance from Brian Geraghty that helps make Easier with Practice more than just another road trip drama.', TO_DATE('2009-06-12', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eastern boys', 2013, 'Thoughtful, unpredictable, and overall gripping, Eastern Boys fills its sprawling running time with compelling themes and sharply drawn characters brought to life by powerful performances and deft direction.', TO_DATE('2013-09-23', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eastern promises', 2007, 'David Cronenberg triumphs again, showcasing the Viggo Mortensen''s onscreen prowess in a daring performance. Bearing the trademarks of psychological drama and gritty violence, Eastern Promises is a very compelling crime story.', TO_DATE('2007-08-30', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('easy a', 2010, 'It owes a huge debt to older (and better) teen comedies, but Easy A proves a smart, witty showcase for its irresistibly charming star, Emma Stone.', TO_DATE('2010-09-10', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('easy rider', 2000, 'Edgy and seminal, Easy Rider encapsulates the dreams, hopes, and hopelessness of 1960s counterculture.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eat drink man woman yin shi nan nu', 1994, 'A richly layered look at the complex interactions between a widowed chef and his daughters, Ang Lee''s generational comedy Eat Drink Man Woman offers filmgoers a tasty cinematic treat.', TO_DATE('1994-08-03', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eat pray love', 2010, 'The scenery is nice to look at, and Julia Roberts is as luminous as ever, but without the spiritual and emotional weight of the book that inspired it, Eat Pray Love is too shallow to resonate.', TO_DATE('2010-08-11', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eat that question frank zappa in his own words', 2016, 'Eat That Question: Frank Zappa in His Own Words offers an illuminating primer for Zappa novices as well as an entertaining retrospective for diehard fans.', TO_DATE('2016-02-02', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eating animals', 2017, 'Eating Animals'' thoughtful analysis and exploration of corporate farming is impressive, given the scope of the topic.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eating out', 2005, 'The cast recites lines of forced wit that aren''t funny, and the clunky plot has too many contrivances.', TO_DATE('2005-04-05', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eating raoul', 2002, 'Eating Raoul serves up its spectacularly lurid tale with a healthy heaping of pitch-black humor and anarchic vigor.', TO_DATE('2002-07-29', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('echo in the canyon', 2018, 'A thoroughly entertaining look at the Laurel Canyon scene as well as the musical history surrounding it, Echo in the Canyon is essential viewing for rock doc fans.', TO_DATE('2018-09-24', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ecstasy', 2012, 'The high never even achieves liftoff in Ecstasy, a tepid adaptation of Irvine Welsh''s novel that will exhaust audiences'' serotonin levels long before the credits roll.', TO_DATE('2012-02-23', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ed wood', 2000, 'Tim Burton and Johnny Depp team up to fete the life and work of cult hero Ed Wood, with typically strange and wonderful results.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eddie murphy raw', 2000, 'Like its title suggests, Eddie Murphy Raw is a searingly unbridled and viciously funny showcase from one of comedy''s best.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eddie the eagle', 2016, 'Eddie the Eagle''s amiable sweetness can''t disguise its story''s many inspirational clichés -- but for many viewers, it will be more than enough to make up for them.', TO_DATE('2016-01-29', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eden', 2012, 'Led by Jamie Chung''s powerful performance, Eden takes a complex and non-exploitative look at the experience of a woman trapped in the horrors of sex trafficking.', TO_DATE('2012-03-15', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eden', 2014, 'Eden uses 1990s club culture as the appropriately intoxicating backdrop for a sensitive, low-key look at aging and the price of pursuing one''s dreams.', TO_DATE('2014-09-05', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eden lake', 2008, 'A brutal and effective British hoodie-horror that, despite the clichés, stays on the right side of scary.', TO_DATE('2008-09-04', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the edge', 1997, 'The Edge is an entertaining hybrid of brainy Mamet dialogue with brawny outdoors action -- albeit one that sadly lacks as much bite as its furry antagonist.', TO_DATE('1997-09-26', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('edge of darkness', 2010, 'For better and for worse, Edge of Darkness offers vintage Mel Gibson, working within the familiar framework of a bloody revenge thriller.', TO_DATE('2010-01-24', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the edge of love', 2008, 'Despite effective performances from Knightley and Miller, The Edge of Love lacks a coherent narrative.', TO_DATE('2008-05-15', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('edge of seventeen', 1999, 'A time capsule assembled with honesty and sensitivity, Edge of Seventeen overcomes youthful fumbles to capture a time of life -- and an era.', TO_DATE('1999-04-30', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('edie', 2018, 'Edie often reduces a remarkable story to a rather ordinary viewing experience, but it''s elevated considerably by Sheila Hancock''s work in the title role.', TO_DATE('2018-05-21', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('edmond', 2006, 'Despite an electrifying performance by William H. Macy, David Mamet''s one-act morality play translates poorly into a film that is overburdened by dialogue.', TO_DATE('2006-03-26', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('edtv', 1999, 'If it''s not as ambitious as The Truman Show in satirizing the voyeuristic nature of television, EdTV is an amiable, witty comedy with fine performances from Matthew McConaughey and Woody Harrelson.', TO_DATE('1999-03-26', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the education of charlie banks', 2007, 'Unevenness and earnestness mire this otherwise sweet, surprising coming of age drama.', TO_DATE('2007-12-18', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('edward scissorhands', 1990, 'The first collaboration between Johnny Depp and Tim Burton, Edward Scissorhands is a magical modern fairy tale with gothic overtones and a sweet center.', TO_DATE('1990-12-07', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eight below', 2006, 'Featuring a stellar cast of marooned mutts, who deftly display emotion, tenderness, loyalty and resolve, Eight Below is a heartwarming and exhilarating adventure film.', TO_DATE('2006-02-05', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eight legged freaks', 2002, 'This homage to the B-movies of the ''50s has a promising first half, but runs out of ideas in the second.', TO_DATE('2002-07-14', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eight men out', 2000, 'Perhaps less than absorbing for non-baseball fans, but nevertheless underpinned by strong performances from the cast and John Sayles'' solid direction.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eighth grade', 2018, 'Eighth Grade takes a look at its titular time period that offers a rare and resounding ring of truth while heralding breakthroughs for writer-director Bo Burnham and captivating star Elsie Fisher.', TO_DATE('2018-01-20', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eisenstein in guanajuato', 2015, 'Eisenstein in Guanajuato is certainly bold, but its provocations aren''t always enough to overcome a lack of depth and clear narrative purpose.', TO_DATE('2015-08-25', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('el aura the aura', 2006, 'The Aura is a highly original and cerebral thriller that maintains its suspense from start to finish.', TO_DATE('2006-08-11', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('el camino a breaking bad movie', 2019, 'Entertaining if not essential, El Camino adds a satisfying belated coda to the Breaking Bad story -- led by a career-best performance from Aaron Paul.', TO_DATE('2019-10-11', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('el cantante', 2006, 'El Cantante adheres to the most basic conventions of the musical biopic, rendering it indistinguishable from others of its ilk.', TO_DATE('2006-09-15', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('el chicano', 2019, 'El Chicano represents a step forward for representation in superhero cinema -- unfortunately, its clichéd story is nothing more than ordinary.', TO_DATE('2019-05-01', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('el mariachi', 2000, 'Made on a shoestring budget, El Mariachi''s story is not new. However, the movie has so much energy that it''s thoroughly enjoyable.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('el norte', 2000, 'Sensitively written, skillfully directed, and powerfully portrayed, El Norte wrings deeply affecting drama from intractable real-life issues.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('el topo', 2002, 'By turns intoxicating and confounding, El Topo contains the creative multitudes that made writer-director Alejandro Jodorowsky such a singular talent.', TO_DATE('2002-07-11', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('elaine stritch shoot me', 2013, 'Brutally honest and utterly compelling, Elaine Stritch: Shoot Me offers a riveting, vanity-free portrait of its legendary subject while offering a few essential truths about the human condition.', TO_DATE('2013-05-21', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('election', 1999, 'Election successfully combines dark humor and intelligent writing in this very witty and enjoyable film.', TO_DATE('1999-05-03', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('triad election hak se wui yi wo wai kwai', 2006, 'Taking its cues from the Godfather series, Triad Election understands how a giddy mix of thrills and gunplay can make for compelling cinema.', TO_DATE('2006-05-13', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('electric boogaloo the wild untold story of cannon films', 2014, 'Electric Boogaloo: The Wild, Untold Story of Cannon Films pays tribute to the titular studio with an affectionate look back that''s arguably more entertaining than much of Cannon''s own B-movie product.', TO_DATE('2014-08-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('elektra', 2005, 'Jennifer Garner inhabits her role with earnest gusto, but Elektra''s tone deaf script is too self-serious and bereft of intelligent dialogue to provide engaging thrills.', TO_DATE('2005-01-11', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('elektra luxx', 2011, 'A bizarre sex comedy full of meandering subplots, some occasional wit, and, unfortunately, not a whole lot of funny jokes.', TO_DATE('2011-02-24', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('elephant', 2003, 'The movie''s spare and unconventional style will divide viewers.', TO_DATE('2003-05-21', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('elevator to the gallows ascenseur pour léchafaud', 2000, 'Louis Malle''s hypnotic debut is a noir with genuine soul, infusing its tale of best laid plans gone awry with wistful performances, swooning cinematography, and a sultry soundtrack.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('elf', 2003, 'A movie full of Yuletide cheer, Elf is a spirited, good-natured family comedy, and it benefits greatly from Will Ferrell''s funny and charming performance as one of Santa''s biggest helpers.', TO_DATE('2003-10-12', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eli', 2019, 'Intermittently effective if not wholly successful, Eli offers horror fans a handful of jump scares in search of a truly terrifying story.', TO_DATE('2019-10-15', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('elisa marcela', 2019, 'While it may be visually attractive, Elisa & Marcela is an underwhelming melodrama that lacks passion and energy.', TO_DATE('2019-02-14', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tropa de elite the elite squad', 2008, 'Brutal, action heavy, Brazilian cop film with a pointless voiceover. Lacks flair, overdoes the violence and is never quite sure where its morals lie.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('elite squad the enemy within', 2011, 'Elite Squad: The Enemy Within is a bleak, violent descent into the Brazilian underbelly, ripping into the favelas with unstoppable and kinetic force.', TO_DATE('2011-02-11', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stonehearst asylum', 2014, 'Stonehearst Asylum offers over-the-top fun for genre aficionados; for others, however, it''s likely to prove a dull disappointment.', TO_DATE('2014-10-12', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('elizabethtown', 2005, 'This story of a floundering shoe designer who returns home for a family tragedy gets lost in undeveloped plot lines and lackluster performances.', TO_DATE('2005-09-06', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ella enchanted', 2004, 'Hathaway is a charming heroine, but the simple storyline gets overwhelmed by silly gimmickry.', TO_DATE('2004-03-27', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('elle', 2016, 'Elle finds director Paul Verhoeven operating at peak power -- and benefiting from a typically outstanding performance from Isabelle Huppert in the central role.', TO_DATE('2016-05-22', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ellie parker', 2005, 'Despite some poignant commentary about struggling actors and Naomi Watts'' inspired performance, Ellie Parker stutters in making the transition from short to feature length.', TO_DATE('2005-10-01', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('elling', 2002, 'Quirky without being overly cutesy, Elling is a gentle, warm comedy.', TO_DATE('2002-04-11', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('elvis nixon', 2016, 'Elvis & Nixon may not do much to expand on its absurdly iconic photographic source material, but it''s rarely less than engaging thanks to its talented starring duo.', TO_DATE('2016-04-14', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('elysium', 2013, 'After the heady sci-fi thrills of District 9, Elysium is a bit of a comedown for director Neill Blomkamp, but on its own terms, it delivers just often enough to satisfy.', TO_DATE('2013-08-01', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('embrace of the serpent el abrazo de la serpiente', 2015, 'As rich visually as it is thematically, Embrace of the Serpent offers a feast of the senses for film fans seeking a dose of bracing originality.', TO_DATE('2015-10-21', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('emma', 2020, 'Other adaptations may do a better job of consistently capturing the spirit of the classic source material, but Jane Austen fans should still find a solid match in this Emma.', TO_DATE('2020-02-03', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('emmanuels gift', 2005, 'A powerful real-life story that''s strong enough to overcome the Hollywood touches added in its telling, Emmanuel''s Gift is an uplifting celebration of the human spirit.', TO_DATE('2005-03-08', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('emperor', 2013, 'Despite a typically strong performance from Tommy Lee Jones, Emperor does little with its fascinating historical palate, and is instead bogged down in a cliched romantic subplot.', TO_DATE('2013-02-26', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the emperors new clothes', 2002, 'The premise of The Emperor''s New Clothes is intriguing, and Holm gives a delightful performance.', TO_DATE('2002-03-08', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the emperors new groove', 2000, 'The Emperor''s New Groove isn''t the most ambitious animated film, but its brisk pace, fresh characters, and big laughs make for a great time for the whole family.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('empire of the sun', 2000, 'One of Steven Spielberg''s most ambitious efforts of the 1980s, Empire of the Sun remains an underrated gem in the director''s distinguished filmography.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('empire records', 2000, 'Despite a terrific soundtrack and a strong early performance from Renee Zellweger, Empire Records is mostly a silly and predictable teen dramedy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star wars episode v the empire strikes back', 1980, 'Dark, sinister, but ultimately even more involving than A New Hope, The Empire Strikes Back defies viewer expectations and takes the series to heightened emotional levels.', TO_DATE('1980-05-21', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('employee of the month', 2006, 'Employee of the Month features mediocre performances, few laughs, and a lack of satiric bite.', TO_DATE('2006-09-28', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a royal affair', 2012, 'A Royal Affair is a lavish and sumptuous costume drama with a juicy story to back it up.', TO_DATE('2012-05-11', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('enchanted', 2007, 'A smart re-imagining of fairy tale tropes that''s sure to delight children and adults, Enchanted features witty dialogue, sharp animation, and a star turn by Amy Adams.', TO_DATE('2007-10-20', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('enchanted april', 1992, 'Mike Newell''s adaptation of Elizabeth von Arnim''s moves at a more generous pace than the 1935 version, allowing excellent performances from Miranda Richardson and Joan Plowright to flourish.', TO_DATE('1992-04-05', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('encino man', 1992, 'Encino Man isn''t the first unabashedly silly comedy to embrace its stupidity and amass a cult following, but whether or not it works for you will largely be determined by your tolerance for Pauly Shore.', TO_DATE('1992-05-22', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('end of days', 2000, 'An overblown thriller with formulaic action scenes and poor acting.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('end of sentence', 2019, 'Steered by a pair of powerful lead performances, End of Sentence is a road trip movie that takes audiences on a satisfying emotional journey.', TO_DATE('2019-07-02', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('end of the century the story of the ramones', 2004, 'Gabba gabba hey! With its focus on the groundbreaking work of the 1970s punk band The Ramones End of the Century makes a solid entry into the growing canon of documentaries that capture Punkology.', TO_DATE('2004-08-11', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('end of the spear', 2006, 'Shoddy filmmaking and a lack of character development derail what could be a potentially compelling tale.', TO_DATE('2006-01-05', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('end of watch', 2012, 'End of Watch has the energy, devotion to characters, and charismatic performances to overcome the familiar pitfalls of its genre and handheld format.', TO_DATE('2012-09-07', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('enders game', 2013, 'If it isn''t quite as thought-provoking as the book, Ender''s Game still manages to offer a commendable number of well-acted, solidly written sci-fi thrills.', TO_DATE('2013-10-21', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('endings beginnings', 2019, 'Endings, Beginnings smothers its talented ensemble cast''s committed work in a carelessly constructed, aimlessly dawdling story.', TO_DATE('2019-09-09', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('endless', 2020, 'While it hopes to make viewers swoon over a bond that defies death, all but the most passionate fans of YA romance may struggle to arouse even puppy love for Endless.', TO_DATE('2020-08-10', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('endless love', 2014, 'Blander than the original Endless Love and even less faithful to the source material, this remake is clichéd and unintentionally silly.', TO_DATE('2014-02-10', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('endless poetry poesía sin fin', 2016, 'Endless Poetry extends writer-director Alejandro Jodorowsky''s singular filmography with another joyously surreal, visually vibrant viewing experience.', TO_DATE('2016-05-15', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('enduring love', 2004, 'While it strains credibility and isn''t ultimately as profound as it might first appear, Enduring Love is still an intriguing thriller fueled by strong performances from Rhys Ifans and Daniel Craig.', TO_DATE('2004-09-10', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('enemy', 2013, 'Thanks to a strong performance from Jake Gyllenhaal and smart direction from Denis Villeneuve, Enemy hits the mark as a tense, uncommonly adventurous thriller.', TO_DATE('2013-09-09', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('enemy at the gates', 2000, 'Atmospheric and thrilling, Enemy at the Gates gets the look and feel of war right. However, the love story seems out of place.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('enemy mine', 2000, 'Enemy Mine extracts thrilling sci-fi pulp from Dennis Quaid and Louis Gossett Jr.''s chemistry and inventive production design, but an overextended story diminishes the power of its central duo''s relationship.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('enemy of the state', 2000, 'An entertaining, topical thriller that finds director Tony Scott on solid form and Will Smith confirming his action headliner status.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('england is mine', 2017, 'England Is Mine''s smartly assembled cast and strong sense of place are often enough to compensate for this unauthorized biopic''s distance from its subject.', TO_DATE('2017-07-02', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the english patient', 1996, 'Though it suffers from excessive length and ambition, director Minghella''s adaptation of the Michael Ondaatje novel is complex, powerful, and moving.', TO_DATE('1996-11-15', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the enigma of kaspar hauser jeder für sich und gott gegen alleevery man for himself and god against all', 2000, 'The Enigma of Kaspar Hauser marks a powerfully humane entry in writer-director Werner Herzog''s acclaimed oeuvre, further bolstered by tremendous work by star Bruno S.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('enough said', 2013, 'Wryly charming, impeccably acted, and ultimately quite bittersweet, Enough Said is a grown-up movie in the best possible way.', TO_DATE('2013-09-08', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('enron the smartest guys in the room', 2005, 'A concise, entertaining documentary about the spectacular failure of Enron.', TO_DATE('2005-04-02', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('entanglement', 2017, 'Entanglement proves there''s still room for charmingly quirky romantic comedies -- even if it flirts with a number of ingredients that typically lead to cutesy disaster.', TO_DATE('2017-06-16', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('enter the dragon', 2000, 'Badass to the max, Enter the Dragon is the ultimate kung-fu movie and fitting (if untimely) Bruce Lee swan song.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('enter the void soudain le vide', 2009, 'Grimy and psychedelic, Enter the Void ushers audiences through an out-of-body experience with the eye for extremity and technical wizardry that Gaspar Noé fans have come to expect.', TO_DATE('2009-05-22', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('entertainment', 2015, 'As brilliantly and uncomfortably confrontational as its protagonist, Entertainment is a boundary-blurring exercise in cinematic misanthropy that more than lives up to its title.', TO_DATE('2015-01-24', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('entourage', 2015, 'Entourage retains many elements of the HBO series, but feels less like a film than a particularly shallow, cameo-studded extended episode of the show.', TO_DATE('2015-06-01', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('entrapment', 2000, 'A poorly developed plot weighs down any potential chemistry between the movie''s leads.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('epic', 2013, 'Though its narrative themes are all too familiar, Epic is beautifully animated and crafted with just enough flair to make for solid family entertainment.', TO_DATE('2013-05-20', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('epic movie', 2007, 'A crude comedy with nothing new or insightful to say about the subjects it satirizes.', TO_DATE('2007-01-20', 'YYYY-MM-DD'), 2.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('equalizer 2', 2018, 'The Equalizer 2 delivers the visceral charge of a standard vigilante thriller, but this reunion of trusted talents ultimately proves a disappointing case study in diminishing returns.', TO_DATE('2018-07-18', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('equilibrium', 2002, 'Equilibrium is a reheated mishmash of other sci-fi movies.', TO_DATE('2002-11-06', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('equity', 2016, 'Equity brings a welcome change of perspective to the financial thriller genre, along with a nuanced story and a terrific cast led by a powerful effort from Anna Gunn.', TO_DATE('2016-01-27', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eragon', 2006, 'Eragon is a fantasy epic that lacks any magic, brought down to earth by unconvincing world-building and a litany of stars who seem bemused by the material.', TO_DATE('2006-12-10', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('erased', 2013, 'Derivative to a fault, Erased squanders some nifty potential and its talented cast in a bland retelling of a story action fans have seen too many times before.', TO_DATE('2013-03-28', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eraser', 1996, 'Eraser''s shoot-''em-up action might show off some cutting edge weaponry, but its rote story is embarrassingly obsolete.', TO_DATE('1996-06-21', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eraserhead', 2000, 'David Lynch''s surreal Eraserhead uses detailed visuals and a creepy score to create a bizarre and disturbing look into a man''s fear of parenthood.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('erin brockovich', 2000, 'Taking full advantage of Julia Roberts''s considerable talent and appeal, Erin Brockovich overcomes a few character and plot issues to deliver a smart, thoughtful, and funny legal drama.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ernest célestine', 2012, 'Sweet and visually charming, Ernest & Celestine offers old-fashioned delights for animation lovers of all ages.', TO_DATE('2012-05-24', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eros', 2005, 'Though Wong''s short lives up to the promise of the title, Antonioni''s is a serious disappointment.', TO_DATE('2005-03-29', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('escape from alcatraz', 2000, 'Escape from Alcatraz makes brilliant use of the tense claustrophobia of its infamous setting -- as well as its leading man''s legendarily flinty resolve.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('john carpenters escape from la', 1996, 'Escape from L.A. has its moments, although it certainly suffers in comparison to the cult classic that preceded it.', TO_DATE('1996-08-09', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('escape from pretoria', 2020, 'Escape from Pretoria doesn''t quite do justice to the fact-based story it''s dramatizing, but that lack of depth is offset by suitably gripping jailbreak action.', TO_DATE('2020-03-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('escape from the planet of the apes', 2000, 'One of the better Planet of the Apes sequels, Escape is more character-driven than the previous films, and more touching as a result.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('escape from tomorrow', 2013, 'Conceptually audacious but only intermittently successful in execution, Escape From Tomorrow is nonetheless visually inventive and darkly surreal.', TO_DATE('2013-01-21', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('escape plan', 2013, 'As much fun as it is to see Sylvester Stallone and Arnold Schwarzenegger team up onscreen, Escape Plan fails to offer much more than a pale imitation of 1980s popcorn thrills.', TO_DATE('2013-10-14', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('escape plan 2 hades', 2018, 'Do not enter.', TO_DATE('2018-06-20', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('escape room', 2019, 'Escape Room fails to unlock much of the potential in its premise, but what''s left is still tense and thrilling enough to offer a passing diversion for suspense fans.', TO_DATE('2019-01-03', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('essential killing', 2010, 'Driven by a uniquely stark mood and propulsive direction, Essential Killing excels due to an unrelentingly visceral performance from Vincent Gallo.', TO_DATE('2010-09-18', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('et the extraterrestrial', 2000, 'Playing as both an exciting sci-fi adventure and a remarkable portrait of childhood, Steven Spielberg''s touching tale of a homesick alien remains a piece of movie magic for young and old.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eternal sunshine of the spotless mind', 2004, 'Propelled by Charlie Kaufman''s smart, imaginative script and Michel Gondry''s equally daring directorial touch, Eternal Sunshine is a twisty yet heartfelt look at relationships and heartache.', TO_DATE('2004-01-20', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('etz limon lemon tree', 2008, 'A positive and personal Israeli film that offers an understated and thought-provoking vision of the West Bank troubles.', TO_DATE('2008-10-09', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('euphoria', 2017, 'While Euphoria''s aims are admirable, it''s musings on life and death are oddly hollow.', TO_DATE('2017-09-09', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('europa report', 2013, 'Claustrophobic and stylish, Europa Report is a slow-burning thriller that puts the science back into science fiction.', TO_DATE('2013-05-24', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eurotrip', 2004, 'A trip worth taking if one''s not offended by gratuitous nudity and bad taste.', TO_DATE('2004-02-18', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('evan almighty', 2007, 'Big on special effects but short on laughs, Evan Almighty underutilizes a star-studded cast that includes Steve Carell and Morgan Freeman.', TO_DATE('2007-06-17', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('evelyn', 2002, 'Though predictable and sometimes overly sentimental, Evelyn still manages to be heartwarming.', TO_DATE('2002-09-11', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('even money', 2006, 'Even Money is so obsessed with portraying the ills of gambling it forgets to develop compelling or likable characters.', TO_DATE('2006-03-19', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('evening', 2007, 'Beautifully filmed, but decidedly dull, Evening is a collossal waste of a talented cast.', TO_DATE('2007-06-14', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('event horizon', 2000, 'Despite a strong opening that promises sci-fi thrills, Event Horizon quickly devolves into an exercise of style over substance whose flashy effects and gratuitous gore fail to mask its overreliance on horror clichés.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ever after a cinderella story', 2000, 'Ever After is a sweet, frothy twist on the ancient fable, led by a solid turn from star Barrymore.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('everest', 2015, 'Everest boasts all the dizzying cinematography a person could hope to get out a movie about mountain climbers, even if it''s content to tread less challenging narrative terrain.', TO_DATE('2015-09-02', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an everlasting piece', 2000, 'This comedy is too slight to leave an impression, and its attempts at whimsy are not as funny as they could have been.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('everly', 2014, 'Everly benefits from Joe Lynch''s stylish direction and Salma Hayek''s starring work, but it''s too thinly written and sleazily violent to fully recommend.', TO_DATE('2014-09-20', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('every day', 2018, 'Every Day wastes its metaphysical premise on shallow storytelling, though its diverse young cast adds flavor to an otherwise bland teen-romance.', TO_DATE('2018-02-22', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('every little step', 2009, 'Fascinating and insightful, Every Little Step is a thoroughly engrossing behind the scenes look at Broadway performers.', TO_DATE('2009-03-22', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('every secret thing', 2014, 'Every Secret Thing has a sterling pedigree both on and off the screen, yet all that talent adds up to little more than a listless, predictable thriller.', TO_DATE('2014-04-25', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('every thing will be fine', 2015, 'Every Thing Will Be Fine finds director Wim Wenders in not so fine form, delivering a film of moral quandary that never leaps off the screen despite its 3-D stylization.', TO_DATE('2015-09-10', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('every which way but loose', 2002, 'The inexplicable pairing of Clint Eastwood with an orangutan is the least of Every Which Way But Loose''s problems -- a slack action-comedy with a haphazardly assembled story.', TO_DATE('2002-05-20', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('everybody knows todos lo saben', 2018, 'Everybody Knows is somewhat less than the sum of its parts despite the efforts of an outstanding cast - and a disappointing step back for writer-director Asghar Farhadi.', TO_DATE('2018-05-08', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('everybody wants some', 2016, 'Nostalgic in the best sense, Everybody Wants Some!! finds Richard Linklater ambling through the past with a talented cast, a sweetly meandering story, and a killer classic rock soundtrack.', TO_DATE('2016-03-11', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('everybodys famous', 2001, 'Though some critics consider Everybody Famous too lightweight to have deserved a slot among the Academy Awards foreign film nominations, this whacky satire of the cult of celebrity makes for loopy, cheerful fun.', TO_DATE('2001-02-13', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('everyday', 2012, 'It suffers from pacing problems and an uneven screenplay, but Michael Winterbottom''s Everyday is also a refreshingly unorthodox and admirably naturalistic take on one family''s struggle to stay together.', TO_DATE('2012-09-13', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('everyday sunshine the story of fishbone', 2011, 'Everyday Sunshine: The Story of Fishbone is an entertaining, heartwarming, and balanced documentary about the influential Los Angeles band.', TO_DATE('2011-04-08', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('everyones hero', 2006, 'Everyone''s Hero is such a predictable and bland tale that it''ll appeal mostly to little kids; others seeking something in Pixar''s league are looking in the wrong ballpark.', TO_DATE('2006-09-13', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('everything everything', 2017, 'Everything, Everything should tug young adult heartstrings fairly effectively, but may not be quite engrossing enough to woo less melodramatically inclined viewers.', TO_DATE('2017-05-18', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('everything is illuminated', 2005, 'Although it excises much from its famously dense source material, Everything is Illuminated is a quirky, ambitious debut film from Liev Schreiber.', TO_DATE('2005-08-25', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('everything must go', 2010, 'It may not improve on the Raymond Carver short story that inspired it, but Everything Must Go resists cliche and boasts a pair of magnetic performances from the perfectly cast Ferrell and Wallace.', TO_DATE('2010-09-12', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eves bayou', 1996, 'Eve''s Bayou marks a striking feature debut for director Kasi Lemmons, layering terrific performances and Southern mysticism into a measured meditation on disillusionment and forgiveness.', TO_DATE('1996-06-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('evil dead 2 dead by dawn', 2000, 'Evil Dead 2''s increased special effects and slapstick-gore makes it as good -- if not better -- than the original.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('evita', 2000, 'Evita sometimes strains to convince on a narrative level, but the soundtrack helps this fact-based musical achieve a measure of the epic grandeur to which it aspires.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('evolution', 2015, 'Creepy, provocative, and aesthetically absorbing, Evolution marks a satisfying step forward for director/co-writer Lucile Hadzihalilovic.', TO_DATE('2015-09-14', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ex machina', 2015, 'Ex Machina leans heavier on ideas than effects, but it''s still a visually polished piece of work -- and an uncommonly engaging sci-fi feature.', TO_DATE('2015-01-16', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('examined life', 2009, 'With Examined Life, Director Astra Taylor has turned a seemingly weighty subject into a fascinating documentary.', TO_DATE('2009-01-23', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('excalibur', 2000, 'John Boorman''s operatic, opulent take on the legend of King Arthur is visually remarkable, and features strong performances from an all-star lineup of British thespians.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('excess baggage', 1997, 'Struggling to find a romantic spark in a seedy premise, Excise Baggage is weighed down by a lot of comedic dead weight.', TO_DATE('1997-08-29', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('excision', 2012, 'Excision effectively blends body horror and adolescent drama, although its visceral aggression definitely isn''t for all tastes.', TO_DATE('2012-01-23', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('exhibition', 2013, 'Exhibition flouts convention with its untrained stars and impressionistic narrative; thankfully, writer-director Joanna Hogg ties it all together into an intimate, beautifully shot drama.', TO_DATE('2013-10-21', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fong juk exiled', 2006, 'Exiled has non-stop action, tension and style -- making it an excellent summer action movie. Johnnie To brings beautiful scenery and camerawork to the film, enhancing the action even more.', TO_DATE('2006-09-06', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('existenz', 1999, 'Gooey, slimy, grotesque fun.', TO_DATE('1999-04-23', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('exit plan selvmords turisten', 2019, 'A would-be thriller that leans a little too hard into its hero''s existential crisis, Exit Plan will leave most viewers looking for the door.', TO_DATE('2019-10-09', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('exit through the gift shop', 2010, 'An amusing, engrossing look at underground art, Exit Through the Gift Shop entertains as it deflates the myths and hype surrounding its subjects.', TO_DATE('2010-01-26', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('exit wounds', 2000, 'It probably goes without saying that Exit Wounds is loaded with plotholes and bad dialogue. Critics also note that Seagal has aged rather badly.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('exodus gods and kings', 2014, 'While sporadically stirring, and suitably epic in its ambitions, Exodus: Gods and Kings can''t quite live up to its classic source material.', TO_DATE('2014-11-29', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the exorcism of emily rose', 2005, 'Loosely based on a true story, The Exorcism of Emily Rose mixes compelling courtroom drama with generally gore-free scares in a ho-hum take on demonic cinema.', TO_DATE('2005-08-27', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the exorcist', 2000, 'The Exorcist rides its supernatural theme to magical effect, with remarkable special effects and an eerie atmosphere, resulting in one of the scariest films of all time.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the exorcist iii', 1990, 'The Exorcist III is a talky, literary sequel with some scary moments that rival anything from the original.', TO_DATE('1990-08-17', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('exorcist ii the heretic', 2001, 'Hokey mystical effects, lousy plotting, and worse acting directly tarnishes the first''s chilling legacy.', TO_DATE('2001-02-27', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('exorcist the beginning', 2004, 'A mediocre, gory horror film, nowhere near the quality of the 1973 original.', TO_DATE('2004-05-25', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('expelled no intelligence allowed', 2008, 'Full of patronizing, poorly structured arguments, Expelled is a cynical political stunt in the guise of a documentary.', TO_DATE('2008-04-14', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('experimenter', 2015, 'Led by a gripping performance from Peter Sarsgaard, Experimenter uses a fact-based story to pose thought-provoking questions about human nature.', TO_DATE('2015-01-25', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('expired', 2007, 'Heartwarming and acidic in turns, this offbeat dramedy about two meter maids in love features solid performances from Samantha Morton and Jason Patric.', TO_DATE('2007-01-20', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('explicit ills', 2008, 'Though its politics can be heavy-handed at times, Mark Webber''s directorial debut is sincere and well-acted.', TO_DATE('2008-03-19', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the exploding girl', 2009, 'Its languid pace and willfully understated narrative may test the patience of some viewers, but Bradley Rust Gray''s gentle direction and a gripping performance from Zoe Kazan lend The Exploding Girl an appealing, melancholy beauty.', TO_DATE('2009-04-29', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('explorers', 2000, 'With a terrific young cast (including Ethan Hawke and River Phoenix) and some typically energetic work from director Joe Dante, Explorers soars past its ''80s kiddie flick competitors with wit, good-looking effects, and tons of charm.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('exposed', 2016, 'Exposed lays its flaws fittingly bare for all but the least discerning viewers to see, starting with a dull yet convoluted plot that utterly overpowers the efforts of an intriguing cast.', TO_DATE('2016-01-22', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('exterminating angels', 2006, 'Explicit and shocking, but there is no substance or statement on human behavior underneath the taboo-breaking.', TO_DATE('2006-05-22', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('extinction', 2015, 'Extinction has a few intriguing ideas, but they -- and some game performances from its talented stars -- are lost in the movie''s muddled plot and frustrating pacing.', TO_DATE('2015-07-20', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('extinction', 2018, 'Extinction has a few intriguing ideas, but they -- and some game performances from its talented stars -- are lost in the movie''s muddled plot and frustrating pacing.', TO_DATE('2018-07-27', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('extraction', 2020, 'Spectacular stunt work and an electric performance from Chris Hemsworth can''t save Extraction from being dragged down by its aimless violence.', TO_DATE('2020-04-22', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('extraordinary measures', 2010, 'Despite a timely topic and a pair of heavyweight leads, Extraordinary Measures never feels like much more than a made-for-TV tearjerker.', TO_DATE('2010-01-12', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('extraterrestrial', 2014, 'Extraterrestial does deliver a certain amount of gory genre thrills, but they''re outweighed by the crushing clichés of its sagging script.', TO_DATE('2014-04-21', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('extreme ops', 2002, 'The various stunts in Extreme Ops don''t compensate for the inane storyline and bad dialogue.', TO_DATE('2002-11-26', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('extremely loud incredibly close', 2011, 'Extremely Loud & Incredibly Close has a story worth telling, but it deserves better than the treacly and pretentious treatment director Stephen Daldry gives it.', TO_DATE('2011-12-19', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('extremely wicked shockingly evil and vile', 2019, 'Extremely Wicked, Shockingly Evil and Vile often transcends its narrative limitations through sheer force of Zac Efron''s compulsively watchable performance.', TO_DATE('2019-01-27', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eye for an eye', 1996, 'Overwrought, thinly written, and all-around unpleasant, Eye for an Eye crudely exploits every parent''s nightmare with deeply offensive results.', TO_DATE('1996-01-12', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eye in the sky', 2015, 'As taut as it is timely, Eye in the Sky offers a powerfully acted -- and unusually cerebral -- spin on the modern wartime political thriller.', TO_DATE('2015-09-11', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eyes of laura mars', 2002, 'Eyes of Laura Mars hints at interesting possibilities, but they''re frittered away by a predictable story that settles for superficial thrills.', TO_DATE('2002-07-27', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eyes wide shut', 2000, 'Kubrick''s intense study of the human psyche yields an impressive cinematic work.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('eyes without a face', 2001, 'A horrific tale of guilt and obsession, Eyes Without a Face is just as chilling and poetic today as it was in 1959.', TO_DATE('2001-02-13', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('f for fake', 2000, 'F for Fake playfully poses intriguing questions while proving that even Orson Welles'' minor works contain their share of masterful moments.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a face in the crowd', 2000, 'A raucous Andy Griffith channels the corruptive influence of celebrity in Elia Kazan''s A Face in the Crowd, a prescient critique of American media.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('faceoff', 2000, 'John Travolta and Nicolas Cage play cat-and-mouse (and literally play each other) against a beautifully stylized backdrop of typically elegant, over-the-top John Woo violence.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('faces', 2003, 'Director John Cassavetes forgoes conventional style in this hard-bitten examination of a marriage, letting his actors tell the story through dialogue and their Faces to refreshing effect.', TO_DATE('2003-04-03', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('faces places visages villages', 2017, 'Equal parts breezily charming and poignantly powerful, Faces Places is a unique cross-generational portrait of life in rural France from the great Agnès Varda.', TO_DATE('2017-05-19', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('facing the giants', 2006, 'The tropes of both football and evangelical movies are gracelessly on parade in this banal, insipid drama.', TO_DATE('2006-09-28', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('facing windows', 2004, 'Polished and sensitively performed, Facing Windows is an unwieldy melodrama that is carried off with style even as its dueling storylines struggle to cohere into a satisfying whole.', TO_DATE('2004-03-18', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('factory girl', 2006, 'Despite a dedicated performance by Sienna Miller, Factory Girl delves only superficially into her character, and ultimately fails to tell a coherent story.', TO_DATE('2006-12-28', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('factotum', 2005, 'Matt Dillon''s performance is the highlight of this somewhat slow but fascinating portrayal of Charles Bukowski''s alter-ego.', TO_DATE('2005-05-17', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the faculty', 1998, 'Rip-off of other sci-fi thrillers.', TO_DATE('1998-12-25', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fading gigolo', 2013, 'Admittedly vulgar and ludicrous, Fading Gigolo gets a decent amount of mileage out of the entertaining chemistry between its starring duo.', TO_DATE('2013-09-09', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fados', 2009, 'Even those unfamiliar with the Portuguese soul music at the heart of Carlos Saura''s film will find it a beautifully enchanting work of cinema.', TO_DATE('2009-01-22', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fahrenheit 119', 2018, 'Fahrenheit 11/9 finds Michael Moore in fine fighting form, delivering a political call to action that ranks among his most effective works.', TO_DATE('2018-09-07', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('failsafe', 2002, 'Fail-Safe strikes an impressive chord with its grim, high-minded exploration of the ultimate Doomsday scenario.', TO_DATE('2002-08-08', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('failure to launch', 2006, 'The few comic gags sprinkled throughout the movie fail to spice up this formulaic rom-com.', TO_DATE('2006-03-03', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fair game', 2010, 'It struggles with the balance between fact-based biopic and taut political thriller, but Fair Game brims with righteous anger -- and benefits from superb performances by Naomi Watts and Sean Penn.', TO_DATE('2010-05-25', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the falcon and the snowman', 2000, 'Stranger than fiction and improbably entertaining, The Falcon and the Snowman shows how easily idealism can be twisted into treason.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('falling down', 1993, 'Falling Down''s popcorn-friendly take on its complex themes proves disquieting -- and ultimately fitting for a bleakly entertaining picture of one man''s angry break with reality.', TO_DATE('1993-02-26', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('falling inn love', 2019, 'Warm and welcoming, Falling Inn Love doesn''t reinvent the wheel, but it will give those looking for a cozy new romantic comedy a nice place to lay their heads.', TO_DATE('2019-08-29', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fame', 2001, 'Just because Fame is a well-acted musical doesn''t mean it flinches against its surprisingly heavy topics.', TO_DATE('2001-04-17', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the family man', 2000, 'Despite good performances by Cage and especially by Leoni, The Family Man is too predictable and derivative to add anything new to the Christmas genre. Also, it sinks under its sentimentality.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('family plot', 2000, 'The Master of Suspense''s swan song finds him aiming for pulpy thrills and hitting the target, delivering a twisty crime story with pleasurable bite.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('family romance llc', 2019, 'A fascinating exploration of human connection, Family Romance, LLC sees Werner Herzog following an unconventional path to existentialism.', TO_DATE('2019-05-18', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the family stone', 2005, 'This family holiday dramedy features fine performances but awkward shifts of tone.', TO_DATE('2005-10-29', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fanboys', 2008, 'This undercooked, sporadically funny road movie is a sop to Star Wars fanatics, but the uninitiated will find little to enjoy.', TO_DATE('2008-07-27', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fanny alexander', 2003, 'Ingmar Bergman conveys the sweep of childhood with a fastidious attention to detail and sumptuous insight into human frailty in Fanny & Alexander, a masterwork that crystalizes many of the directors'' preoccupations into a familial epic.', TO_DATE('2003-03-31', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fantasia 2000', 2000, 'It provides an entertaining experience for adults and children alike.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fantastic beasts and where to find them', 2016, 'Fantastic Beasts and Where to Find Them draws on Harry Potter''s rich mythology to deliver a spinoff that dazzles with franchise-building magic all its own.', TO_DATE('2016-11-12', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fantastic beasts the crimes of grindelwald', 2018, 'Fantastic Beasts: The Crimes of Grindelwald has glimmers of the magic familiar to Harry Potter fans, but the story''s spell isn''t as strong as earlier installments.', TO_DATE('2018-11-08', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fantastic four', 2005, 'Marred by goofy attempts at wit, subpar acting, and bland storytelling, Fantastic Four is a mediocre attempt to bring Marvel''s oldest hero team to the big screen.', TO_DATE('2005-07-05', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fantastic four', 2015, 'Dull and downbeat, this Fantastic Four proves a woefully misguided attempt to translate a classic comic series without the humor, joy, or colorful thrills that made it great.', TO_DATE('2015-08-04', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fantastic four rise of the silver surfer', 2007, 'While an improvement on its predecessor, Fantastic Four: Rise of the Silver Surfer is nevertheless a juvenile, simplistic picture that has little benefit beyond its special effects.', TO_DATE('2007-06-11', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fantastic planet', 2000, 'Fantastic Planet is an animated epic that is by turns surreal and lovely, fantastic and graceful.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fantastic voyage', 2000, 'The special effects may be a bit dated today, but Fantastic Voyage still holds up well as an imaginative journey into the human body.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fantasy island', 2020, 'Fantasy Island tries to show audiences the dark side of wish fulfillment, but mainly serves as a cautionary tale about the dangers of exhuming long-dead franchises.', TO_DATE('2020-02-13', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('far and away', 2000, 'Handsome and simplistic, Far and Away has the beauty of an American epic without the breadth.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('far from heaven', 2002, 'An exquisitely designed and performed melodrama, Far From Heaven earns its viewers'' tears with sincerity and intelligence.', TO_DATE('2002-09-05', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('far from the madding crowd', 2015, 'Far from the Madding Crowd invites tough comparisons to Thomas Hardy''s classic novel -- and its previous adaptation -- but stands on its own thanks to strong direction and a talented cast.', TO_DATE('2015-04-02', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('far from the tree', 2018, 'Far from the Tree takes a piercingly thoughtful look at the family dynamic that makes its points -- and earns its tears -- honestly.', TO_DATE('2018-07-19', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('farewell my queen', 2012, 'Farewell, My Queen transcends its gaudy period trappings to offer an affecting historical drama built on timeless - and timely - themes.', TO_DATE('2012-02-10', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fargo', 1996, 'Violent, quirky, and darkly funny, Fargo delivers an original crime story and a wonderful performance by McDormand.', TO_DATE('1996-03-08', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fascination', 2005, 'Laughably overheated and featuring loads of cheesy dialogue, Fascination is the virtual definition of so-band-it''s-good.', TO_DATE('2005-01-27', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ex', 2006, 'The Ex suffers from inept direction and characters that are either unsympathetic or plain unpleasant to watch.', TO_DATE('2006-12-28', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fast furious', 2009, 'While Fast and Furious features the requisite action and stunts, the filmmakers have failed to provide a competent story or compelling characters.', TO_DATE('2009-03-31', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fast furious 6', 2013, 'With high-octane humor and terrific action scenes, Fast & Furious 6 builds upon the winning blockbuster formula that made Fast 5 a critical and commercial success.', TO_DATE('2013-05-12', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fast furious presents hobbs shaw', 2019, 'Hobbs & Shaw doesn''t rev as high as the franchise''s best installments, but gets decent mileage out of its well-matched stars and over-the-top action sequences.', TO_DATE('2019-07-31', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fast and the furious tokyo drift', 2006, 'Eye-popping driving sequences coupled with a limp story and flat performances make this Drift a disappointing follow-up to previous Fast and Furious installments.', TO_DATE('2006-06-13', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fast cheap out of control', 2000, 'Made with a care and patience that belies its title, Errol Morris'' Fast, Cheap & Out of Control combines the disparate sensibilities of four idiosyncratic subjects to present a fresh, cogent perspective on life.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fast color', 2018, 'A grounded superhero story with more on its mind than punching bad guys, Fast Color leaps over uneven execution with a single Gugu Mbatha-Raw performance.', TO_DATE('2018-03-12', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fast five', 2011, 'Sleek, loud, and over the top, Fast Five proudly embraces its brainless action thrills and injects new life into the franchise.', TO_DATE('2011-04-16', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fast food nation', 2006, 'Despite some fine performances and memorable scenes, Fast Food Nation is more effective as Eric Schlosser''s eye-opening non-fiction book than as Richard Linklater''s fictionalized, mostly punchless movie.', TO_DATE('2006-05-19', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fast times at ridgemont high', 2000, 'While Fast Times at Ridgemont High features Sean Penn''s legendary performance, the film endures because it accurately captured the small details of school, work, and teenage life.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('faster', 2010, 'It''s good to see Dwayne Johnson back in full-throttle action mode, but Faster doesn''t deliver enough of the high-octane thrills promised by its title.', TO_DATE('2010-11-19', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('faster pussycat kill kill', 2000, 'Faster, Pussycat! Kill! Kill! is undoubtedly shlock, but director Russ Meyer''s infectious affection for camp gives this anarchic joyride exhilarating flair.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fat albert', 2004, 'A bland but good-natured adaptation of the cartoon show.', TO_DATE('2004-12-18', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fat city', 2000, 'Fat City is a bleak, mordant, slice of life boxing drama that doesn''t pull its punches.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fat girl', 2001, 'The controversial Fat Girl is an unflinchingly harsh but powerful look at female adolescence.', TO_DATE('2001-09-17', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('father figures', 2017, 'Success has many fathers, but failure is Father Figures.', TO_DATE('2017-12-21', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the father of my children le pere de mes enfants', 2009, 'A tragedy gracefully lifted by tender empathy and moments of joy, Father of My Children is a quiet triumph for writer-director Mia Hansen-Love.', TO_DATE('2009-05-18', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fathers and daughters', 2015, 'Fathers and Daughters'' name-brand cast can''t cover for a screenplay that makes a half-hearted effort at delving into family dynamics but falls back on melodrama.', TO_DATE('2015-10-16', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fathers day', 2000, 'A maudlin misfire, Father''s Day manages the difficult task of making Billy Crystal and Robin Williams woefully unfunny.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fatima', 2020, 'Hard not to respect but difficult to love, Fatima competently dramatizes an incredible true story.', TO_DATE('2020-08-25', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('faults', 2014, 'Faults explores the cult dynamic to fascinating effect, bolstered by an outstanding cast and sharp work from writer-director Riley Stearns.', TO_DATE('2014-03-24', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('favela rising', 2006, 'Frustratingly flawed yet ultimately uplifting, Favela Rising offers an engrossing -- and sobering -- glimpse of a culture that''s far more complex than many viewers might realize.', TO_DATE('2006-05-27', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fay grim', 2006, 'Fay Grim is too concerned with its own farcical premise to present a coherent, involving story.', TO_DATE('2006-09-13', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fear and loathing in las vegas', 2000, 'Visually creative, but also aimless, repetitive, and devoid of character development.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('angst essen seele auf ali fear eats the soul', 2002, 'Regarded as one of the high-water marks in German New Wave cinema of the 1970s, Ali: Fear Eats the Soul is at once an intense portrayal of a relationship and a tribute to one of Rainer Werner Fassbinder''s film heroes, Douglas Sirk.', TO_DATE('2002-01-22', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fear strikes out', 2000, 'Based on the true story of troubled baseball star Jimmy Piersall, Fear Strikes Out is an emotionally compelling drama featuring excellent performances from Anthony Perkins and Karl Malden.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fear x', 2003, 'As hazy, unsettling, and fleetingly insubstantial as a dream, Fear X will lose many viewers in its ambiguities, but is partly propped up by strong work from John Turturro.', TO_DATE('2003-02-13', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('feardotcom', 2002, 'As frustrating as a 404 error, Fear Dot Com is a stylish, incoherent, and often nasty mess with few scares.', TO_DATE('2002-08-28', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jet lis fearless huo yuan jia legend of a fighter', 2006, 'Fearless is a brilliantly choreographed, beautifully filmed endcap to Li''s quarter decade of epic martial arts glory.', TO_DATE('2006-06-15', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('feast', 2005, 'Director Gulager makes the most of what he''s given; the resulting Feast offers up some surprisingly tasty -- if far from nourishing -- morsels.', TO_DATE('2005-10-18', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('feast of love', 2007, 'Though beautifully photographed, Feast of Love offers little beyond a trite, melodramatic character drama.', TO_DATE('2007-09-05', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fed up', 2014, 'Compelling and troubling in equal measure, Fed Up is an advocacy documentary that earns its outrage.', TO_DATE('2014-01-23', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('feel the noise', 2007, 'Despite the different musical genre, Feel the Noise is as generic as any music-themed film that has come before it.', TO_DATE('2007-10-05', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('feeling minnesota', 2000, 'Clumsily derivative, shoddily assembled, and fundamentally miscast, Feeling Minnesota sets out for romantic comedy and gets irrevocably lost along the way.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('feels good man', 2020, 'A cautionary tale on internet culture, Feels Good Man is a compelling look at an artist''s journey to salvage his creation.', TO_DATE('2020-01-27', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('felix meira', 2015, 'Félix & Meira uses its simple structure and slight story as the setup for a sensitive, well-acted romance whose unusual specifics belie universal truths.', TO_DATE('2015-01-31', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('felony', 2013, 'Felony covers familiar ground but does so with uncommon style, thanks to a thought-provoking script, sharp direction, and powerful work from a talented cast.', TO_DATE('2013-09-12', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('female trouble', 2001, 'Director John Waters'' affection for camp brings texture to societal transgression in Female Trouble, a brazenly subversive dive into celebrity and mayhem.', TO_DATE('2001-11-04', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fences', 2016, 'From its reunited Broadway stars to its screenplay, the solidly crafted Fences finds its Pulitzer-winning source material fundamentally unchanged -- and still just as powerful.', TO_DATE('2016-11-22', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ferdinand', 2017, 'Ferdinand''s colorful update on a classic tale doesn''t go anywhere unexpected, but its timeless themes -- and John Cena''s engaging voice work in the title role -- make for family-friendly fun.', TO_DATE('2017-12-07', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la habitación de fermat fermats room', 2008, 'This stylish yet disappointingly predictable Spanish thriller is never as exciting or ingenious as it hopes to be.', TO_DATE('2008-05-07', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ferris buellers day off', 2000, 'Matthew Broderick charms in Ferris Bueller''s Day Off, a light and irrepressibly fun movie about being young and having fun.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('festival express', 2004, 'Festival Express is a spellbinding documentary that nostalgically chronicles five days in the summer of 1970, when a train full of now- legendary rock perfomers jammed its way across Canada.', TO_DATE('2004-03-16', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('festival in cannes', 2002, 'One of Jaglom''s better films, Festival in Cannes is an enjoyable insider''s take on the movie industry.', TO_DATE('2002-01-16', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fever pitch', 2005, 'While not a home run, Fever Pitch has enough charm and on-screen chemistry between the two leads to make it a solid hit.', TO_DATE('2005-04-02', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a few good men', 2000, 'An old-fashioned courtroom drama with a contemporary edge, A Few Good Men succeeds on the strength of its stars, with Tom Cruise, Demi Moore, and especially Jack Nicholson delivering powerful performances that more than compensate for the predictable plot.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fiddler on the roof', 2000, 'A bird may love a fish -- and musical fans will love this adaptation of Fiddler on the Roof, even if it isn''t quite as transcendent as the long-running stage version.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fido', 2006, 'Making the most of its thin premise, Fido is an occasionally touching satire that provides big laughs and enough blood and guts to please gorehounds.', TO_DATE('2006-09-13', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('field of dreams', 2000, 'Field of Dreams is sentimental, but in the best way; it''s a mix of fairy tale, baseball, and family togetherness.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fierce people', 2005, 'Fierce People''s premise of a teenager studying rich people like animals is grating and self-satisfied, and Anton Yelchin''s smug performance makes the film even harder to agree with.', TO_DATE('2005-04-24', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fierce creatures', 1997, 'Fierce Creatures reunites A Fish Called Wanda''s talented ensemble for a comedy that, while not without its moments, suffers from diminishing returns.', TO_DATE('1997-01-24', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fifth element', 1997, 'Visually inventive and gleefully over the top, Luc Besson''s The Fifth Element is a fantastic piece of pop sci-fi that never takes itself too seriously.', TO_DATE('1997-05-09', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fifty shades darker', 2017, 'Lacking enough chemistry, heat, or narrative friction to satisfy, the limp Fifty Shades Darker wants to be kinky but only serves as its own form of punishment.', TO_DATE('2017-02-08', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fifty shades freed', 2018, 'Fifty Shades Freed brings its titillating trilogy to a clumsy conclusion, making for a film franchise that adds up to a distinctly dissatisfying ménage à trois.', TO_DATE('2018-02-07', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fifty shades of black', 2016, 'Wildly erratic even for a spoof movie, Fifty Shades of Black bears the unfortunate distinction of offering fewer laughs than the unintentionally funny film it''s trying to lampoon.', TO_DATE('2016-01-28', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fifty shades of grey', 2015, 'While creatively better endowed than its print counterpart, Fifty Shades of Grey is a less than satisfying experience on the screen.', TO_DATE('2015-02-10', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fight club', 1999, 'Solid acting, amazing direction, and elaborate production design make Fight Club a wild ride.', TO_DATE('1999-10-15', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fighting', 2009, 'Though Fighting has a likable lead performer, and the fight scenes are impressive, the paper-thin plot ultimately unravels.', TO_DATE('2009-04-20', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fighting temptations', 2003, 'The music is the only saving grace in this predictable and eager-to-please comedy.', TO_DATE('2003-09-11', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fighting with my family', 2019, 'Much like the sport it celebrates, Fighting with My Family muscles past clichés with a potent blend of energy and committed acting that should leave audiences cheering.', TO_DATE('2019-01-29', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fill the void', 2012, 'Graceful, complex, and beautifully layered, Fill the Void offers a sympathetic portrait of an insulated culture by exploring universal themes.', TO_DATE('2012-09-06', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('film geek', 2006, 'Charming despite its central character''s unfortunate personality traits, Film Geek serves as a slight yet amusing calling card for writer-director James Westby.', TO_DATE('2006-01-13', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('film stars dont die in liverpool', 2017, 'Film Stars Don''t Die in Liverpool showcases brilliant work from Annette Bening, whose performance is more than enough to outweigh this biopic''s basic narrative.', TO_DATE('2017-09-02', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a film unfinished', 2010, 'A heartbreaking, haunting historical document, A Film Unfinished excavates particularly horrible chapter of Holocaust history, and in doing so, the film provides a glimpse into the Nazi propaganda machine.', TO_DATE('2010-07-06', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('filth', 2013, 'Warped, grimy, and enthusiastically unpleasant, Filth lives up to its title splendidly.', TO_DATE('2013-09-18', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the filth and the fury', 2000, 'The Filth and the Fury is a complete and completely unabashed look at The Sex Pistols, shot in suitably propulsive punk fashion.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('filth and wisdom', 2008, 'Filth and Wisdom, while certainly ambitious, is mostly unconvincing and incoherent.', TO_DATE('2008-02-13', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the final cut', 2004, 'The Final Cut fails to make compelling use of its intriguing premise and talented cast, settling for a middling sci-fi drama that never justifies its pretensions.', TO_DATE('2004-02-12', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('final destination', 2000, 'Despite a panel of X-Files'' alums at the helm and a promising premise, flighty performances and poor execution keep Final Destination from ever taking off.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('final destination 2', 2003, 'This sequel is little more than an excuse to stage elaborate, gory scenes of characters getting killed off.', TO_DATE('2003-01-24', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('final destination 3', 2006, 'Final Destination 3 is more of the same: gory and pointless, with nowhere new to go.', TO_DATE('2006-02-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('final destination 5', 2011, 'It''s still only for the gore-thirsty faithful, but Final Destination 5 represents a surprising return to form for the franchise.', TO_DATE('2011-08-10', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the final destination', 2009, 'With little of the ingenuity of previous installments, The Final Destination is predictable, disposable horror fare.', TO_DATE('2009-08-26', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('final fantasy the spirits within', 2001, 'The movie raises the bar for computer animated movies, but the story is dull and emotionally removed.', TO_DATE('2001-07-09', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('final portrait', 2017, 'Final Portrait finds writer-director Stanley Tucci patiently telling a quietly absorbing story, brought to life by a talented ensemble led by Geoffrey Rush and Armie Hammer.', TO_DATE('2017-02-12', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('find me guilty', 2006, 'Find Me Guilty''s excessive length and heavy-handed narrative keep it from reaching its full potential, but Vin Diesel''s performance is well worth watching.', TO_DATE('2006-02-16', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('finders keepers', 2015, 'As bizarrely hilarious as it is insightful, Finders Keepers is a stranger-than-fiction gem of a documentary that transcends its oddball trappings.', TO_DATE('2015-10-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('finding amanda', 2008, 'Despite a charming turn by Matthew Broderick, Finding Amanda is too flimsily executed to succeed as a dark comedy.', TO_DATE('2008-05-15', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('finding dory', 2016, 'Funny, poignant, and thought-provoking, Finding Dory delivers a beautifully animated adventure that adds another entertaining chapter to its predecessor''s classic story.', TO_DATE('2016-06-10', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('finding fela', 2014, 'Though it doesn''t fully capture the electrifying spirit of its subject, Finding Fela! is a solid overview of the life and work of a musical revolutionary.', TO_DATE('2014-02-12', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('finding forrester', 2000, 'Despite the predictability of its plot and its similarity to Good Will Hunting, Finding Forrester has an honest, solid feel to it and good rapport between Connery and Brown.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('finding nemo', 2003, 'Breathtakingly lovely and grounded by the stellar efforts of a well-chosen cast, Finding Nemo adds another beautifully crafted gem to Pixar''s crown.', TO_DATE('2003-04-29', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('finding neverland', 2004, 'It won''t pass muster for those looking for historical accuracy, but Finding Neverland is a warm, heartfelt drama with a charm all its own -- and Johnny Depp gives a graceful performance as Peter Pan creator J.M. Barrie.', TO_DATE('2004-09-07', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('finding vivian maier', 2014, 'Narratively gripping, visually striking, and ultimately thought-provoking, Finding Vivian Maier shines an overdue spotlight on its subject''s long-hidden brilliance.', TO_DATE('2014-03-04', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('finding your feet', 2018, 'Finding Your Feet wears its heart on its sleeve, elevating undemanding material with a feel-good romance and sweet performances from its over-qualified cast.', TO_DATE('2018-02-15', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('finishing the game', 2007, 'Though Justin Lin''s premise is precocious enough, the sight gags and comic timing are tired in this mockumentary about Asian typecasting in the 1970s.', TO_DATE('2007-01-26', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fire at sea fuocoammare', 2016, 'Fire at Sea offers a clear-eyed yet empathetic look at a corner of the world whose terrain may be unfamiliar to many, but whose people''s story remains universal.', TO_DATE('2016-02-21', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fire birds', 2000, 'Despite the talent on board, Fire Birds is little more than a subpar military adventure sporting video game-like action, outdated philosophy, and uneven acting.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fired up', 2009, 'Though not as raunchy or juvenile as the average teen comedy, Fired Up is also not as funny.', TO_DATE('2009-02-11', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('firehouse dog', 2007, 'Firehouse Dog''s cute premise is ruined with endless fart and poop jokes, and an overlong run time.', TO_DATE('2007-04-03', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('firelight', 2000, 'Predictable and dull.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('firestarter', 2002, 'Firestarter''s concept hews too closely to other known Stephen King adaptations, though it''s got nice special effects (including scenery-chewing George C. Scott).', TO_DATE('2002-01-27', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('firewall', 2006, 'Harrison Ford''s rote performance brings little to this uninspired techno-heist film whose formulaic plot is befuddled with tedious and improbable twists.', TO_DATE('2006-02-02', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fireworks wednesday chaharshanbesoori', 2007, 'Well-written and powerfully acted, Fireworks Wednesday gives audiences an early, assured glimpse of writer-director Asghar Farhadi''s emerging talent.', TO_DATE('2007-06-21', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('first blood', 2000, 'Much darker and more sensitive than the sequels it spawned, First Blood is a thrilling survival adventure that takes full advantage of Sylvester Stallone''s acting skills.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('first cow', 2019, 'First Cow finds director Kelly Reichardt revisiting territory and themes that will be familiar to fans of her previous work -- with typically rewarding results.', TO_DATE('2019-08-31', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('first daughter', 2004, 'First Daughter is a bland and charmless fairy tale that fails to rise above the formula.', TO_DATE('2004-09-22', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('first knight', 1995, 'This unimaginative reimagining of Arthurian legend dispenses with the magic without achieving a convincing realism in the bargain, suffering from fatal miscasting and a lack of romance.', TO_DATE('1995-07-07', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('first love hatsukoi', 2019, 'First Love''s blend of violence, comedy, and romance might seem disparate -- but for director Takashi Miike, it''s just another wildly entertaining entry in a filmography full of them.', TO_DATE('2019-05-17', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('first man', 2018, 'First Man uses a personal focus to fuel a look back at a pivotal moment in human history - and takes audiences on a soaring dramatic journey along the way.', TO_DATE('2018-08-29', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('first position', 2012, 'An upbeat and visually dramatic documentary of children''s ballet, First Position displays the potential of the human spirit when fostered at a young age.', TO_DATE('2012-01-20', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('first reformed', 2017, 'Brought to life by delicate work from writer-director Paul Schrader and elevated by a standout performance by Ethan Hawke, First Reformed takes a sensitive and suspenseful look at weighty themes.', TO_DATE('2017-08-30', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the first saturday in may', 2008, 'This touching documentary about the horses and trainers behind the Kentucky Derby leads up to the two most exciting minutes in sports.', TO_DATE('2008-04-14', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('first sunday', 2008, 'First Sunday may have its heart in the right place, but its funny bone is dislocated.', TO_DATE('2008-01-04', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('first they killed my father', 2017, 'First They Killed My Father tackles its subject matter with grace, skill, and empathy, offering a ground-level look at historic atrocities that resonates beyond its story''s borders.', TO_DATE('2017-09-03', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the first wives club', 2000, 'First Wives Club is headlined by a trio of comedic dynamos, but the script lets them down with tepid plotting and a fatal lack of satirical bite.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a fish called wanda', 2000, 'Smartly written, smoothly directed, and solidly cast, A Fish Called Wanda offers a classic example of a brainy comedy with widespread appeal.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fish tank', 2009, 'Cannes Jury Prize-winner Fish Tank is gritty British realism at its very best, with flawless performances from newcomer Kate Jarvis, and Michael Fassbender.', TO_DATE('2009-05-14', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fisher king', 1991, 'An odd but affecting mixture of drama, comedy and fantasy, The Fisher King manages to balance moving performances from Robin Williams and Jeff Bridges with director Terry Gilliam''s typically askew universe.', TO_DATE('1991-09-20', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fishermans friends', 2019, 'Fisherman''s Friends charts a familiar course, but its feelgood charm and hook-filled soundtrack should be enough to reel viewers in.', TO_DATE('2019-03-11', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fist fight', 2017, 'Fist Fight boasts a surplus of comedic muscle but flails lazily, and far too few of its jokes land with enough force to register.', TO_DATE('2017-02-15', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a fistful of dollars per un pugno di dollari', 2000, 'With Akira Kurosawa''s Yojimbo as his template, Sergio Leone''s A Fistful of Dollars helped define a new era for the Western and usher in its most iconic star, Clint Eastwood.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fitzcarraldo', 2000, 'With a production as audacious as the feat it''s depicting, Fitzcarraldo comes by its awe-inspiring spectacle honestly, even when it declines to examine the darker implications of its hero''s dream.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('five easy pieces', 2000, 'An important touchstone of the New Hollywood era, Five Easy Pieces is a haunting portrait of alienation that features one of Jack Nicholson''s greatest performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('five feet apart', 2019, 'Elevated considerably by Haley Lu Richardson''s performance but bogged down by clichés, Five Feet Apart doesn''t tug at the heartstrings quite as deftly as it should.', TO_DATE('2019-03-14', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flags of our fathers', 2006, 'Flags of Our Fathers is both a fascinating look at heroism, both earned and manufactured, and a well-filmed salute to the men who fought at the battle of Iwo Jima.', TO_DATE('2006-10-07', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flammen citronen flame citron the flame and the lemon', 2008, 'The true story of the Danish resistance in WW2, though lengthy and sprawling, is gripping and competently made.', TO_DATE('2008-03-28', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flannel pajamas', 2006, 'Flannel Pajamas is a talky and overwrought love story that is redeemed by fine performances and character insights.', TO_DATE('2006-01-23', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flash of genius', 2008, 'The touching underdog story of a single guy against a massive corporation, Flash of Genius is a well-paced and well-written tale with a standout performance by star Greg Kinnear.', TO_DATE('2008-09-01', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flash point', 2008, 'Flash Point features some nice mindless martial-arts action, but too much of the already thin story treads familiar ground.', TO_DATE('2008-01-07', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flashbacks of a fool', 2008, 'Despite Daniel Craig''s earnest efforts, Flashbacks of a Fool suffers from an ambitious but underdeveloped script.', TO_DATE('2008-04-17', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flashdance', 2000, 'All style and very little substance, Flashdance boasts eye-catching dance sequences -- and benefits from an appealing performance from Jennifer Beals -- but its narrative is flat-footed.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flatliners', 2000, 'While it boasts an impressive cast, striking visuals, and an effective mood, Flatliners never quite jolts its story to life.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flatliners', 2017, 'Flatliners falls flat as a horror movie and fails to improve upon its source material, rendering this reboot dead on arrival.', TO_DATE('2017-09-28', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flawless', 1999, 'Robert De Niro and Philip Seymour Hoffman''s Flawless performances live up to this dramedy''s title; unfortunately, they''re outweighed by the misguided picture surrounding them.', TO_DATE('1999-11-24', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fletch', 2002, 'Quotably funny -- and fast-paced enough to smooth over the jokes that don''t land -- Fletch is one of the best big-screen vehicles for Chevy Chase''s brand of smug silliness.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fletch lives', 2000, 'Chevy Chase remains ideally suited for the role, but Fletch Lives lacks its predecessor''s wit, relying instead on silly disguises, cheap stereotypes, and largely unfunny gags.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flicka', 2006, 'The rebellious protagonist will rally girls and children, but adults may find Flicka saddled with thin characters, over-the-top dialogue, and a plot that wanders into the countryside and never comes back.', TO_DATE('2006-10-16', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flight', 2012, 'Robert Zemeckis makes a triumphant return to live-action cinema with Flight, a thoughtful and provocative character study propelled by a compelling performance from Denzel Washington.', TO_DATE('2012-10-14', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flight of the navigator', 2000, 'Bolstered by impressive special effects and a charming performance from its young star, Flight of the Navigator holds up as a solidly entertaining bit of family-friendly sci-fi.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flight of the phoenix', 2004, 'What this update lacks in tension, it makes up for with generic action.', TO_DATE('2004-12-13', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('le voyage du ballon rouge the flight of the red balloon', 2007, 'Hou Hsiao-hsien''s remake of the 1956 classic is unhurried, contemplative, and visually rapturous.', TO_DATE('2007-05-17', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flightplan', 2005, 'The actors are all on key here, but as the movie progress, tension deflates as the far-fetched plot kicks in.', TO_DATE('2005-09-08', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the flintstones in viva rock vegas', 2000, 'The prequel to the first full-length feature set in Bedrock, Viva Rock Vegas is a surprising improvement over The Flintstones. Aimed towards an audience of adults and children alike, critics feel Viva will appeal to a broad range of viewers.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flipped', 2010, 'While not without its nostalgic charms, Rob Reiner''s sometimes awkward adaptation of Wendelin Van Draanen''s childhood novel doesn''t reach the heights of the director''s earlier work like Stand By Me.', TO_DATE('2010-08-02', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flirting with disaster', 2000, 'Darkly funny, solidly cast, and surprisingly thoughtful, Flirting with Disaster proved David O. Russell''s Spanking the Monkey was no fluke.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('florence foster jenkins', 2016, 'Florence Foster Jenkins makes poignant, crowd-pleasing dramedy out of its stranger-than-fiction tale -- and does its subject justice with a reliably terrific turn from star Meryl Streep.', TO_DATE('2016-04-13', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reaching for the moon', 2013, 'Reaching for the Moon''s uptight sensibilities sometimes play more pretentious than poetic, but solid performances and sumptuous photography leave a lingering longing for love in the tropics.', TO_DATE('2013-11-05', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flow for love of water', 2008, 'Flow is an informative, disturbing and enthralling film that highlights a criminally underreported problem.', TO_DATE('2008-03-10', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flower', 2017, 'Flower proves Zoey Deutch can bring even the most preposterously written characters vividly to life -- and that she isn''t quite enough to carry a fundamentally flawed film.', TO_DATE('2017-04-20', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flubber', 1997, 'With its overactive focus on special effects and tiresome slapstick, Flubber squanders the immense talent of its cast and crew.', TO_DATE('1997-11-26', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flushed away', 2006, 'Clever and appealing for both children and adults, Flushed Away marks a successful entry into digital animated features for Aardman Animations.', TO_DATE('2006-10-13', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fly away home', 1996, 'Well-acted and beautifully filmed, Fly Away Home offers heartwarming entertainment for moviegoers of all ages.', TO_DATE('1996-09-13', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fly me to the moon', 2008, 'Flatly animated and indifferently scripted, Fly Me To the Moon offers little for audiences not comprised of very young children.', TO_DATE('2008-08-07', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('flyboys', 2006, 'A poorly scripted history-rewriting exercise with mediocre acting and unconvincing CGI battle scenes.', TO_DATE('2006-09-12', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the flying scotsman', 2006, 'The Flying Scotsman''s too-brisk pacing reduces the scale of cyclist Graham Obree''s accomplishments while not uncovering what makes him tick.', TO_DATE('2006-12-28', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('focus', 2015, 'Focus may have a few too many twists and turns, but it nearly skates by on its glamorous setting and the charm of its stars.', TO_DATE('2015-02-18', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fog', 2005, 'The Fog is a so-so remake of a so-so movie, lacking scares, suspense or originality.', TO_DATE('2005-10-14', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('following', 2001, 'Super brief but efficient, Following represents director Christopher Nolan''s burgeoning talent in tight filmmaking and hard-edge noir.', TO_DATE('2001-06-12', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('food inc', 2009, 'An eye-opening expose of the modern food industry, Food, Inc. is both fascinating and terrifying, and essential viewing for any health-conscious citizen.', TO_DATE('2009-05-20', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fools gold', 2008, 'With little chemistry among the performers, humorless gags, and a predictable storyline, Fool''s Gold fails on every level.', TO_DATE('2008-02-02', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('footloose', 2011, 'While it hews closely to the 1984 original, Craig Brewer infuses his Footloose remake with toe-tapping energy and manages to keep the story fresh for a new generation.', TO_DATE('2011-09-27', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('for colored girls', 2010, 'Tyler Perry has assembled a fine cast for this adaptation of the 1975 play, and his heart is obviously in the right place, but his fondness for melodrama cheapens a meaningful story.', TO_DATE('2010-10-22', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('for a few dollars more per qualche dollaro in più', 2000, 'With Clint Eastwood in the lead, Ennio Morricone on the score, and Sergio Leone''s stylish direction, For a Few Dollars More earns its recognition as a genre classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('for a good time call', 2012, 'Brisk, funny, and sweetly raunchy, For a Good Time, Call... adds to the recent string of R-rated female comedies while serving as an overdue coming out party for the charming Ari Graynor.', TO_DATE('2012-01-24', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('for greater glory', 2012, 'It has laudable aspirations, but For Greater Glory ultimately fails to fulfill its goals due to an overstuffed script, thinly written characters, and an overly simplified dramatization of historical events.', TO_DATE('2012-05-20', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('for love of the game', 1999, 'Baseball wins, romance loses.', TO_DATE('1999-09-17', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('for the bible tells me so', 2007, 'A timely and poignant examination of gays, their families and religion.', TO_DATE('2007-01-24', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('for those in peril', 2013, 'Gentle, deeply felt, and strikingly original, For Those in Peril serves as a powerful calling card for first-time writer-director Paul Wright.', TO_DATE('2013-05-18', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('for your eyes only', 1981, 'For Your Eyes Only trades in some of the outlandish Bond staples for a more sober outing, and the result is a satisfying adventure, albeit without some of the bombastic thrills fans may be looking for.', TO_DATE('1981-06-26', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the forbidden kingdom', 2007, 'This hotly-anticipated pairing of martial arts legends Jackie Chan and Jet Li features dazzling fight scenes but is weighed down by too much filler.', TO_DATE('2007-08-07', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('forbidden planet', 2000, 'Shakespeare gets the deluxe space treatment in Forbidden Planet, an adaptation of The Tempest with impressive sets and seamless special effects.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('force majeure', 2014, 'Gleefully uncomfortable, Force Majeure is a relationship drama that''s hard to watch -- and just as difficult to ignore.', TO_DATE('2014-05-23', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('forces of nature', 1999, 'A distinct lack of chemistry between Ben Affleck and Sandra Bullock, coupled with a screwball sensibility that''s a touch too screwy, scupper Forces of Nature''s modest ambition to serve up romantic charm.', TO_DATE('1999-03-19', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('foreign correspondent', 2000, 'Alfred Hitchcock''s Foreign Correspondent features a winning combination of international intrigue, comic relief, and some of the legendary director''s most memorable set pieces.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('forever my girl', 2018, 'Forever My Girl offers a suitably picturesque placeholder for romance fans between Nicholas Sparks films, but other viewers may end up crying for the wrong reasons.', TO_DATE('2018-01-17', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('forget paris', 1995, 'In addition to its titular exhortation, Forget Paris also forgets to offer rom-com fans enough romance or comedy to fill a feature worth remembering.', TO_DATE('1995-05-19', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('forgetting sarah marshall', 2008, 'With ample laughs and sharp performances, Forgetting Sarah Marshall finds just the right mix of romantic and raunchy comedy.', TO_DATE('2008-03-10', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('forgiving dr mengele', 2006, 'A difficult yet essential watch, Forgiving Dr. Mengele follows one woman''s quest for peace at the limits of human compassion.', TO_DATE('2006-01-18', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the forgotten', 2004, 'The premise grows too ridiculous to take seriously.', TO_DATE('2004-09-21', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('formosa betrayed', 2010, 'Though the real-life drama it was inspired by could certainly form the basis for a worthwhile political action thriller, Formosa Betrayed isn''t it.', TO_DATE('2010-02-16', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('forrest gump', 1994, 'Forrest Gump may be an overly sentimental film with a somewhat problematic message, but its sweetness and charm are usually enough to approximate true depth and grace.', TO_DATE('1994-07-06', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the forsaken', 2001, 'It''s all been done before, and done better.', TO_DATE('2001-04-18', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fort tilden', 2014, 'Difficult to watch but ultimately all the more rewarding for it, Fort Tilden offers an intriguing calling card for writer-directors Sarah-Violet Bliss and Charles Rogers.', TO_DATE('2014-03-24', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('four brothers', 2005, 'Despite striking a believable rapport among its principal actors, Four Brothers overwhelms with ultra-violent, vigilante-glorifying action and devolves into too many fractured, insubstantial thematic directions.', TO_DATE('2005-08-07', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('four christmases', 2008, 'Despite a strong cast, this sour holiday comedy suffers from a hackneyed script.', TO_DATE('2008-11-21', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the four feathers', 2002, 'Though beautiful to look at, The Four Feathers lacks epic excitement and suffers from an ambivalent viewpoint.', TO_DATE('2002-09-10', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('four kids and it', 2020, 'Four Kids and It has a few moments of whimsy and charm, but it''s not enough to leave a lasting impression.', TO_DATE('2020-03-30', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('four lions', 2010, 'Its premise suggests brazenly tasteless humor, but Four Lions is actually a smart, pitch-black comedy that carries the unmistakable ring of truth.', TO_DATE('2010-01-25', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('four minutes', 2006, 'This riveting German drama set in a women''s prison has the strong foundation of a solid script and psychologically resonant performances across the board.', TO_DATE('2006-09-22', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('four rooms', 1996, 'Four Rooms comes stocked with a ton of talent on both sides of the camera, yet only manages to add up to a particularly uneven -- and dismayingly uninspired -- anthology effort.', TO_DATE('1996-12-26', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('four weddings and a funeral', 2000, 'While frothy to a fault, Four Weddings and a Funeral features irresistibly breezy humor, and winsome performances from Hugh Grant and Andie MacDowell.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fourth kind', 2009, 'While it boasts a handful of shocks, The Fourth Kind is hokey and clumsy and makes its close encounters seem eerily mundane.', TO_DATE('2009-11-01', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fox and the hound', 2000, 'The Fox and the Hound is a likeable, charming, unassuming effort that manages to transcend its thin, predictable plot.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('foxcatcher', 2014, 'A chilling true crime drama, Foxcatcher offers Steve Carell, Mark Ruffalo, and Channing Tatum a chance to shine -- and all three of them rise to the challenge.', TO_DATE('2014-05-19', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('foxy brown', 2002, 'Rampant amorality and sensationalist flourishes give this crime thriller a rich coat of grime, but Foxy Brown''s powerful center lies in Pam Grier''s commanding performance.', TO_DATE('2002-08-30', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fracture', 2007, 'Though Fracture''s plot is somewhat implausible, the onscreen face-off between Gosling and Hopkins overshadows any faults.', TO_DATE('2007-04-11', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fractured', 2019, 'Led by an arresting Sam Worthington performance, Fractured is a reasonably diverting mystery with enough thrills to make up for a familiar story.', TO_DATE('2019-09-23', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fragments', 2008, 'Sensitive but not insightful, Fragments pieces an ensemble together in the same way Crash did but without the gravitas.', TO_DATE('2008-06-25', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frailty', 2001, 'Creepy and disturbing, Frailty is well-crafted, low-key horror.', TO_DATE('2001-11-19', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('framing john delorean', 2019, 'Stranger than fiction and just as engrossing, Framing John DeLorean tells its incredible true story in appropriately freewheeling fashion.', TO_DATE('2019-04-25', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frances', 2000, 'This sordid biopic emphasizes the indignities visited upon Frances Farmer to the detriment of fleshing her out as a person, but Jessica Lange''s towering performance invests the tragic figure with a humanity that the script lacks.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frances ha', 2012, 'Audiences will need to tolerate a certain amount of narrative drift, but thanks to sensitive direction from Noah Baumbach and an endearing performance from Greta Gerwig, Frances Ha makes it easy to forgive.', TO_DATE('2012-09-12', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('francofonia', 2016, 'Francofonia may test the patience of the uninitiated, but viewers willing to delve into a beautifully filmed look at the intersection of art and war will be richly rewarded.', TO_DATE('2016-02-24', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frank', 2014, 'Funny, clever, and endearingly unusual, Frank transcends its quirky trappings with a heartfelt -- and surprisingly thought-provoking -- story.', TO_DATE('2014-01-18', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frank millers sin city a dame to kill for', 2014, 'A Dame to Kill For boasts the same stylish violence and striking visual palette as the original Sin City, but lacks its predecessor''s brutal impact.', TO_DATE('2014-08-19', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frankensteins monsters monster frankenstein', 2019, 'While Frankenstein''s Monster''s Monster, Frankenstein''s offbeat sense of humor might be too strange for some, those looking for a kooky new comedy will find much to like in its spooky spoofs.', TO_DATE('2019-07-11', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frankenweenie', 2012, 'Frankenweenie is an energetic stop-motion horror movie spoof with lovingly crafted visuals and a heartfelt, oddball story.', TO_DATE('2012-09-20', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frankie alice', 2010, 'Halle Berry gives it her all (and then some), but Frankie & Alice is ultimately too narratively strained and clumsily assembled to do her performance justice.', TO_DATE('2010-12-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frantz', 2016, 'Frantz finds writer-director François Ozon thoughtfully probing the aftermath of World War I through the memories and relationships of loved ones left behind.', TO_DATE('2016-09-04', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('freak show', 2017, 'Freak Show relies on engaging performances and obviously good intentions to cover for its clichéd story and uneven direction -- and for some viewers, it may well be enough.', TO_DATE('2017-02-14', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('freakonomics', 2010, 'More disjointed and less compelling than the book it''s based on, Freakonomics isn''t quite as entertaining or educational as it should be.', TO_DATE('2010-05-03', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('freaks', 2000, 'Time has been kind to this horror legend: Freaks manages to frighten, shock, and even touch viewers in ways that contemporary viewers missed.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('freaks', 2018, 'Stocked with solid performances, Freaks is a clever sci-fi/horror hybrid that suggests a bright future for co-writers/co-directors Zach Lipovsky and Adam Stein.', TO_DATE('2018-09-09', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('freaky friday', 2003, 'Jamie Lee Curtis and Lindsay Lohan charm in Mark Waters'' nicely pitched -- and Disney''s second -- remake of the 1976 hit.', TO_DATE('2003-05-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('freddy got fingered', 2001, 'Unfavorably comparing it with such infamously bad titles as Battlefield Earth, a significant number of critics are calling Tom Green''s extreme gross-out comedy the worst movie they have ever seen.', TO_DATE('2001-04-16', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('freddy vs jason', 2003, 'Fans of the two horror franchises will enjoy this showdown. But for everyone else, it''s the same old slice and dice.', TO_DATE('2003-07-31', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('freddys dead the final nightmare', 2000, 'Reducing the once-terrifying Dream Reaper into a goofy caricature, this joyless climax will leave audiences hoping Freddy stays dead.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('free birds', 2013, 'Technically proficient yet creatively moribund, Free Birds begs unfortunate comparisons with the dim-witted fowl that inspired it.', TO_DATE('2013-10-29', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('free fire', 2016, 'Free Fire aims squarely for genre thrills, and hits its target repeatedly and with great gusto -- albeit with something less than pure cinematic grace.', TO_DATE('2016-09-09', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('free solo', 2018, 'Free Solo depicts athletic feats that many viewers will find beyond reason - and grounds the attempts in passions that are all but universal.', TO_DATE('2018-09-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('free state of jones', 2016, 'Free State of Jones has the noblest of intentions, but they aren''t enough to make up for its stilted treatment of a fascinating real-life story.', TO_DATE('2016-06-20', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('free willy', 2000, 'Free Willy tugs at the heartstrings skillfully enough to leap above the rising tide of sentimentality that threatens to drown its formulaic family-friendly story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('free willy 2 the adventure home', 2000, 'Good-natured yet utterly unsurprising, Free Willy 2: The Adventure Home will strike all but the youngest of viewers as a poorly orca-strated sequel.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('freedom writers', 2007, 'Freedom Writers is a frank, formulaic entry in the inspirational inner-city teacher genre, with an energetic Hilary Swank leading the appealing cast of unknowns.', TO_DATE('2007-01-02', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('freedomland', 2006, 'Poorly directed and overacted, Freedomland attempts to address sensitive race and class issues but its overzealousness misses the mark.', TO_DATE('2006-02-06', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('freeheld', 2015, 'Freeheld certainly means well, but its cardboard characters and by-the-numbers drama undermine its noble intentions.', TO_DATE('2015-09-13', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the french connection', 2000, 'Realistic, fast-paced and uncommonly smart, The French Connection is bolstered by stellar performances by Gene Hackman and Roy Scheider, not to mention William Friedkin''s thrilling production.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the french connection ii', 2002, 'Flawed and more conventional than its predecessor, French Connection II still offers a wealth of dynamic action and gritty characterizations.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frenzy', 2000, 'Marking Alfred Hitchcock''s return to England and first foray into viscerally explicit carnage, Frenzy finds the master of horror regaining his grip on the audience''s pulse -- and making their blood run cold.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frequency', 2000, 'A tight blend of surprises and suspense keeps audiences spellbound.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fresh', 2000, 'Well cast and sharply directed, Fresh serves as an attention-getting calling card for writer-director Boaz Yakin as well as a gripping urban drama.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fresh dressed', 2015, 'Fresh Dressed offers an intelligent, entertaining overview of the fashion that helped define -- and spread -- a culture.', TO_DATE('2015-02-06', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('freshman orientation', 2004, 'This over-the-top comedy suffers from an exhaustive screenplay, which tries too hard to be funny...and fails.', TO_DATE('2004-02-18', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frida', 2002, 'Frida is a passionate, visually striking biopic about the larger-than-life artist.', TO_DATE('2002-08-30', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('friday', 2000, 'What Friday might lack in taut construction or directorial flair, it more than makes up with its vibrant (albeit consistently crass) humor and the charming, energetic performances of its leads.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('friday the 13th the final chapter', 1984, 'As lumberingly single-minded as its homicidal star, Friday the 13th - The Final Chapter adds another rote entry to an increasingly labored franchise.', TO_DATE('1984-04-13', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('friday after next', 2002, 'This Friday installment is more shapeless and stale than its predecessors.', TO_DATE('2002-11-18', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('friday night lights', 2004, 'An acute survey of the football-obsessed heartland that succeeds as both a stirring drama and a rousing sports movie.', TO_DATE('2004-09-24', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('friday the 13th', 2000, 'Rather quaint by today''s standards, Friday the 13th still has its share of bloody surprises and a ''70s-holdover aesthetic to slightly compel.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('friday the 13th part 2', 2000, 'Friday the 13th Part 2 sets the template for the franchise to follow with more teen victims, more gruesome set pieces, and fewer reasons to keep following along.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('friday the 13th part 3', 2000, 'Jason may solidify his iconic wardrobe in this entry, but Friday the 13th Part 3 lacks any other distinguishing features, relying on a tired formula of stab and repeat.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('friday the 13th part vi jason lives', 1986, 'Friday the 13th: Part VI - Jason Lives indeed brings back ol'' Vorhees, along with a sense of serviceable braindead fun.', TO_DATE('1986-08-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('friday the 13th part vii the new blood', 2002, 'As lumbering and bereft of conscious thought as its unstoppable star, Friday the 13th Part VII - The New Blood finds the franchise in desperate need of the title ingredient.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('friday the 13th part viii jason takes manhattan', 2000, 'Jason terrorizes a ship and nearly sinks the franchise in a clunky sequel that feels like self-parody without the charm.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('friday the 13th', 2009, 'Though technically well-constructed, Friday the 13th is a series rehash that features little to distinguish it from its predecessors.', TO_DATE('2009-02-09', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fried green tomatoes', 2000, 'Fried Green Tomatoes'' tearjerking drama is undeniably manipulative, but in the hands of a skilled cast that includes Jessica Tandy and Kathy Bates, it''s also powerfully effective.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('friend request', 2016, 'Friend Request''s attempts to update old-school teen horror for the digital age do not, sadly, include memorable characters, fresh scares, or novel storytelling twists.', TO_DATE('2016-04-18', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('friends with benefits', 2011, 'Friends with Benefits adds nothing new to its well-worn rom-com formula, but the chemistry between Justin Timberlake and Mila Kunis is almost enough to carry the movie by itself.', TO_DATE('2011-07-18', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('friends with kids', 2011, 'Sharp, shrewd, and funny, Friends with Kids features excellent performances that help smooth over some of the story''s more conventional elements.', TO_DATE('2011-09-12', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('friends with money', 2006, 'Strong lead performances, witty dialogue and wry observations cement Friends With Money as another winning dramedy from writer/director Nicole Holofcener.', TO_DATE('2006-01-20', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fright night', 2011, 'It may not have been necessary to remake the 1985 cult classic, but the new Fright Night benefits from terrific performances by Colin Farrell and David Tennant -- and it''s smart, funny, and stylishly gory to boot.', TO_DATE('2011-08-11', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fritz the cat', 2002, 'Fritz the Cat''s gleeful embrace of bad taste can make for a queasy viewing experience, but Ralph Bakshi''s idiosyncratic animation brings the satire and style of Robert Crumb''s creation to vivid life.', TO_DATE('2002-05-14', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('from dusk till dawn', 2000, 'A pulpy crime drama/vampire film hybrid, From Dusk Till Dawn is an uneven but often deliriously enjoyable B-movie.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('from hell', 2001, 'Visually impressive, but this latest Ripper tale is dull and far from scary.', TO_DATE('2001-09-11', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('from justin to kelly', 2003, 'A notorious stinker, From Justin To Kelly features banal songs, a witless plot, and non-existent chemistry between its American Idol-sanctioned leads.', TO_DATE('2003-06-19', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('from paris with love', 2010, 'Thought not without its charms -- chief among them John Travolta''s endearingly over-the-top performance -- From Paris with Love is too muddled and disjointed to satisfy.', TO_DATE('2010-01-28', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('from russia with love', 2000, 'The second James Bond film, From Russia with Love is a razor-sharp, briskly-paced Cold War thriller that features several electrifying action scenes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('from the land of the moon mal de pierres', 2016, 'From the Land of the Moon benefits from striking visuals and strong work from Marion Cotillard, but they''re both ultimately overcome by a story that drifts into wan melodrama.', TO_DATE('2016-05-15', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('from up on poppy hill', 2011, 'Gentle and nostalgic, From Up on Poppy Hill is one of Studio Ghibli''s sweeter efforts -- and if it doesn''t push the boundaries of the genre, it remains as engagingly lovely as Ghibli fans have come to expect.', TO_DATE('2011-10-04', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frontera', 2014, 'Frontera is solidly cast, handsomely mounted, and well-acted; unfortunately, it''s also rather dull and fairly forgettable.', TO_DATE('2014-08-08', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frontiers', 2007, 'Perhaps slapdash with its aspirations toward message-making, this ultra-gory horror flick nonetheless delivers the bloody goods.', TO_DATE('2007-09-13', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frontrunners', 2008, 'Frontrunners offers poignant insights into the high school power structure, with more than a few parallels to the current U.S. election.', TO_DATE('2008-03-17', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frostnixon', 2008, 'Frost/Nixon is weighty and eloquent; a cross between a boxing match and a ballet with Oscar worthy performances.', TO_DATE('2008-10-16', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frozen', 2013, 'Beautifully animated, smartly written, and stocked with singalong songs, Frozen adds another worthy entry to the Disney canon.', TO_DATE('2013-11-03', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frozen ii', 2019, 'Frozen II can''t quite recapture the showstopping feel of its predecessor, but it remains a dazzling adventure into the unknown.', TO_DATE('2019-11-14', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('frozen river', 2008, 'Veteran character actress Melissa Leo delivers a stunning performance in this powerful -- if grim -- indie film.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fruitvale station', 2013, 'Passionate and powerfully acted, Fruitvale Station serves as a celebration of life, a condemnation of death, and a triumph for star Michael B. Jordan.', TO_DATE('2013-01-21', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fugitive pieces', 2008, 'Though the retelling is a bit too subtle, the moving story and solid performances lift Fugitive Pieces beyond standard holocaust tales.', TO_DATE('2008-04-26', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('full battle rattle', 2008, 'Full Battle Rattle is an insightful, eye-opening account of the preparations soldiers must make for their service in Iraq.', TO_DATE('2008-02-09', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('full frontal', 2002, 'An confusing movie made worse by the poor camera work.', TO_DATE('2002-07-22', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('full metal jacket', 2000, 'Intense, tightly constructed, and darkly comic at times, Stanley Kubrick''s Full Metal Jacket may not boast the most original of themes, but it is exceedingly effective at communicating them.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the full monty', 1997, 'Cheeky and infectiously good-natured, The Full Monty bares its big beating heart with a sly dose of ribald comedy.', TO_DATE('1997-08-13', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fun fancy free', 2001, 'Though it doesn''t quite live up to its title, Fun and Fancy Free has its moments, and it''s a rare opportunity to see Mickey, Donald, and Goofy together.', TO_DATE('2001-10-09', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fun size', 2012, 'It occasionally shows surprising flashes of wit, but Fun Size is too safe and formulaic -- not to mention unfunny -- to survive comparisons to the ''80s teen movies it eagerly imitates.', TO_DATE('2012-10-23', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fun with dick and jane', 2005, 'This muddled comedy has a few laughs, but never sustains a consistent tone.', TO_DATE('2005-12-16', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('funny girl', 2001, 'Barbara Streisand elevates this otherwise rote melodramatic musical with her ultra-memorable star turn as Fanny Brice.', TO_DATE('2001-08-27', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('funny people', 2009, 'Funny People features the requisite humor, as well as considerable emotional depth, resulting in Judd Apatow''s most mature film to date.', TO_DATE('2009-07-25', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fur an imaginary portrait of diane arbus', 2006, 'This portrait of a groundbreaking photographer lacks the daring of its subject.', TO_DATE('2006-09-09', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('furious 7', 2015, 'Serving up a fresh round of over-the-top thrills while adding unexpected dramatic heft, Furious 7 keeps the franchise moving in more ways than one.', TO_DATE('2015-03-16', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fury', 2014, 'Overall, Fury is a well-acted, suitably raw depiction of the horrors of war that offers visceral battle scenes but doesn''t quite live up to its larger ambitions.', TO_DATE('2014-10-10', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fx', 2000, 'Smart, twisty, and perfectly cast, the effects-assisted neo-noir F/X reminds viewers that a well-told story is the most special effect of all.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gabrielle', 2013, 'Bolstered by strong, natural performances, Gabrielle''s sincere look at differently abled young adults nimbly walks the line between sweet and cloying.', TO_DATE('2013-09-19', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gaga five foot two', 2017, 'Gaga: Five Foot Two offers an absorbing glimpse of its superstar subject''s backstage life, albeit one weakened by inconsistent focus and a dearth of performance footage.', TO_DATE('2017-09-09', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gainsbourg a heroic life', 2010, 'It might be thinly written and messily made, but Gainsbourg: A Heroic Life is also appropriately glamorous and intense -- and powerfully led by a gripping performance from Erik Elmosnino.', TO_DATE('2010-01-22', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('galaxy quest', 1999, 'Intelligent and humorous satire with an excellent cast -- no previous Trekkie knowledge needed to enjoy this one.', TO_DATE('1999-12-25', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('galveston', 2018, 'Galveston''s talented cast - and confident direction from Mélanie Laurent - help set this uneven crime drama apart from less distinguished genre entries.', TO_DATE('2018-03-12', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gambit', 2012, 'A curiously charmless caper that squanders a starry cast and screenplay by the Coen brothers, this Gambit doesn''t pay off.', TO_DATE('2012-11-08', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('game change', 2012, 'Empathetic performances from a starry cast gives Game Change authenticity and heart, although its political insights often warble between feeling too soon and too late.', TO_DATE('2012-03-28', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('game night', 2018, 'With a talented cast turned loose on a loaded premise -- and a sharp script loaded with dark comedy and unexpected twists -- Game Night might be more fun than the real thing.', TO_DATE('2018-02-21', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('game of death', 2017, 'Game of Death''s over-the-top violence and gore will be too much for some, but genre fans up for some bloody thrills will find it well worth playing.', TO_DATE('2017-07-15', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('game 6', 2006, 'Though packed with Don DeLillo''s witty dialogue and bolstered by strong performances, particularly by lead Michael Keaton, Game 6 also suffers from uneven direction and overwrought symbolism.', TO_DATE('2006-02-04', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gamer', 2009, 'With all of the hyperkinetic action and none of the flair of Mark Neveldine and Brian Taylor''s earlier work, Gamer has little replay value.', TO_DATE('2009-09-03', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gandhi', 2000, 'Director Richard Attenborough is typically sympathetic and sure-handed, but it''s Ben Kingsley''s magnetic performance that acts as the linchpin for this sprawling, lengthy biopic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gangs of new york', 2002, 'Though flawed, the sprawling, messy Gangs of New York is redeemed by impressive production design and Day-Lewis''s electrifying performance.', TO_DATE('2002-12-05', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gangster no 1', 2001, 'Gangster No. 1 is brutally violent, yet also compelling.', TO_DATE('2001-05-30', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gangster squad', 2013, 'Though it''s stylish and features a talented cast, Gangster Squad suffers from lackluster writing, underdeveloped characters, and an excessive amount of violence.', TO_DATE('2013-01-07', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('garden state', 2004, 'Delivering a quirky spin on familiar twentysomething tropes -- with a cannily-placed soundtrack -- Garden State has enough charm to mark a winning debut for first-time director Zach Braff.', TO_DATE('2004-01-18', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('garfield the movie', 2004, 'When the novelty of the CGI Garfield wears off, what''s left is a simplistic kiddie movie.', TO_DATE('2004-04-19', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('garfield a tail of two kitties', 2006, 'Strictly for (very) little kids, A Tale of Two Kitties features skilled voice actors but a plot that holds little interest.', TO_DATE('2006-06-12', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gasland', 2010, 'GasLand patiently and powerfully outlines alarming problems with modern fuel extraction -- and the horrific public health risks that go along with them.', TO_DATE('2010-07-23', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gattaca', 1997, 'Intelligent and scientifically provocative, Gattaca is an absorbing sci fi drama that poses important interesting ethical questions about the nature of science.', TO_DATE('1997-10-24', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gauguin voyage to tahiti', 2017, 'Gaugin: Voyage to Tahiti is beautifully filmed biopic that benefits from a well-chosen lead, but neither are enough to counter the story''s surface treatment and narrative drift.', TO_DATE('2017-09-27', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the gauntlet', 2000, 'Eastwood has a good time playing a dolt in the surprisingly funny Gauntlet, which otherwise has the typical Clint trappings.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gbf', 2013, 'G.B.F. explores high school relationship dynamics and teen stereotypes with a refreshingly humorous touch - and surprisingly subtle smarts.', TO_DATE('2013-09-09', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gemini', 2017, 'A kaleidoscopic neo-noir, Gemini is a visually striking murder mystery with a convoluted but largely compelling plot and an impressive showing from Lola Kirke.', TO_DATE('2017-03-13', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gemini man', 2019, 'Gemini Man''s impressive visuals are supported by some strong performances, but this sci-fi thriller is fatally undermined by a frustratingly subpar story.', TO_DATE('2019-09-26', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gemma bovery', 2014, 'Gemma Bovery''s bursts of charm -- among them Gemma Arterton''s winsome performance in the title role -- are often enough to compensate for its lack of focus.', TO_DATE('2014-09-05', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the generals daughter', 1999, 'Contrived performances and over-the-top sequences offer little real drama.', TO_DATE('1999-06-18', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('genius', 2016, 'Genius seeks to honor worthy subjects, yet never gets close enough to the titular quality to make watching worth the effort.', TO_DATE('2016-02-16', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gentlemans agreement', 2000, 'It occasionally fails to live up to its subject matter -- and is perhaps an ''important'' film more than a ''great'' one -- but the performances from Gregory Peck and Dorothy McGuire are superb.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gentlemen broncos', 2009, 'Unselfconsciously juvenile and overwhelmingly quirky, Gentlemen Broncos offers a lot of potty humor but isn''t terribly funny.', TO_DATE('2009-09-25', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gentlemen prefer blondes', 1953, 'Anchored by Marilyn Monroe and Jane Russell''s sparkling magnetism, Gentlemen Prefer Blondes is a delightfully entertaining 1950s musical.', TO_DATE('1953-07-15', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('george harrison living in the material world', 2011, 'Clocking in at nearly three and a half hours, George Harrison: Living in the Material World is a moving portrait of the so-called Quiet Beatle''s spirituality and troubled existence that highlights the best of Scorsese''s sensibilities.', TO_DATE('2011-09-09', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('georgia rule', 2007, 'Comedic and dramatic in all the wrong places, Georgia Rule is a confused dramedy that wastes the talents of its fine cast.', TO_DATE('2007-05-04', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('geostorm', 2017, 'Lacking impressive visuals, well-written characters, or involving drama, Geostorm aims for epic disaster-movie spectacle but ends up simply being a disaster of a movie.', TO_DATE('2017-10-12', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('geralds game', 2017, 'Carla Gugino carries Gerald''s Game''s small-scale suspense with a career-defining performance.', TO_DATE('2017-09-22', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('geronimo an american legend', 1993, 'Geronimo: An American Legend fails to stir the soul, though its sweeping visuals and historical ambitions mark an intelligent change of pace for director Walter Hill.', TO_DATE('1993-01-01', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gerontophilia', 2014, 'Gerontophilia''s handful of intriguing ideas are let down by tame execution and unconvincing acting that make the movie''s premise feel creepy rather than original.', TO_DATE('2014-01-28', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gerry', 2002, 'The type of uncompromising film that divides filmgoers over whether it is profound or pretentious.', TO_DATE('2002-06-05', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('get a job', 2016, 'Inauthentic and unfunny, Get a Job is paltry to the point that its long-delayed release feels purely the result of its wasted cast having been promoted to greater fame all these years later.', TO_DATE('2016-03-18', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('get hard', 2015, 'A waste of two fine funnymen, Get Hard settles for tired and offensive gags instead of tapping into its premise''s boundary-pushing potential.', TO_DATE('2015-03-17', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('get low', 2009, 'Subtle to a fault, this perfectly cast ensemble drama is lifted by typically sharp performances from Robert Duvall and Bill Murray.', TO_DATE('2009-10-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('get me roger stone', 2017, 'As informative as it is entertaining, Get Me Roger Stone offers a close-up look at the right-wing gadfly who helped shape the 2016 presidential election.', TO_DATE('2017-04-24', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('get on the bus', 1996, 'Get on the Bus finds Spike Lee pulling a page from history with fervor and flair, offering a strong, stirring fact-based drama further elevated by an array of solid performances.', TO_DATE('1996-10-16', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('get on up', 2014, 'With an unforgettable Chadwick Boseman in the starring role, Get On Up offers the Godfather of Soul a fittingly dynamic homage.', TO_DATE('2014-07-28', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('get out', 2017, 'Funny, scary, and thought-provoking, Get Out seamlessly weaves its trenchant social critiques into a brilliantly effective and entertaining horror/comedy thrill ride.', TO_DATE('2017-01-24', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('get real', 1999, 'An authentic portrayal of homosexuality in high school, Get Real is an engaging dramedy that doesn''t sermonize its audience nor trivialize its characters.', TO_DATE('1999-04-30', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('get rich or die tryin', 2005, 'While it may be based upon 50 Cent''s own life experiences, Get Rich Or Die Tryin'' is too similar to many other rags-to-riches stories to resonate.', TO_DATE('2005-11-01', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('get santa', 2014, 'With a bombastic performance from Jim Broadbent, Get Santa brilliantly captures the joys of the Christmas holiday.', TO_DATE('2014-11-28', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('get shorty', 1995, 'With a perfect cast and a sly twist on the usual Hollywood gangster dynamic, Get Shorty delivers a sharp satire that doubles as an entertaining comedy-thriller in its own right.', TO_DATE('1995-10-20', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('get smart', 2008, 'Get Smart rides Steve Carell''s considerable charm for a few laughs, but ultimately proves to be a rather ordinary action comedy.', TO_DATE('2008-06-11', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('get the gringo', 2012, 'Energetic and hard-hitting, Get the Gringo plays squarely to its lead actor''s strengths as a skilled portrayer of men put through physical and emotional hell.', TO_DATE('2012-04-20', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('getaway', 2013, 'Monotonously fast-paced to the point of exhaustion, Getaway offers a reminder of the dangers in attempting to speed past coherent editing, character development, sensible dialogue, and an interesting plot.', TO_DATE('2013-08-26', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gett the trial of viviane amsalem', 2014, 'On paper, GETT: The Trial of Viviane Amsalem might seem less than thrilling, but on the screen, it delivers two hours of nonstop, tightly wound, brilliantly acted drama.', TO_DATE('2014-07-18', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('getting even with dad', 1994, 'Overly formulaic and tonally inconsistent, Getting Even with Dad tries for a sentimental conclusion it doesn''t earn and winds up a slapsticky cash grab aimed at fans of Home Alone.', TO_DATE('1994-06-17', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ghost and the darkness', 1996, 'The Ghost and the Darkness hits its target as a suspenseful adventure, but it falls into a trap of its own making whenever it reaches for supernatural profundity.', TO_DATE('1996-10-11', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghost dad', 1990, 'A startlingly misconceived effort from director Sidney Poitier and star Bill Cosby, Ghost Dad is a listless, glacially-paced comedy that''s alternately schmaltzy and incomprehensible.', TO_DATE('1990-06-29', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghost dog the way of the samurai', 2000, 'An innovative blend of samurai and gangster lifestyles.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghost in the shell', 2000, 'A stunning feat of modern animation, Ghost in the Shell offers a thoughtful, complex treat for anime fans, as well as a perfect introduction for viewers new to the medium.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghost in the shell', 2017, 'Ghost in the Shell boasts cool visuals and a compelling central performance from Scarlett Johansson, but the end result lacks the magic of the movie''s classic source material.', TO_DATE('2017-03-28', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghost in the shell 2 innocence', 2004, 'The animation is lovely, but the plot is complex to the point of inscrutability, leaving Ghost in the Shell 2: Innocence both original and numbing.', TO_DATE('2004-05-22', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghost light', 2018, 'Fittingly given its title, Ghost Light balances dark supernatural elements against quirky comedy to create a satisfying blend of both.', TO_DATE('2018-09-23', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghost rider', 2007, 'Ghost Rider is a sour mix of morose, glum histrionics amidst jokey puns and hammy dialogue.', TO_DATE('2007-02-14', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghost rider spirit of vengeance', 2012, 'With a weak script, uneven CG work, and a Nic Cage performance so predictably loony it''s no longer amusing, Ghost Rider: Spirit of Vengeance aims to be trashy fun but ends up as plain trash.', TO_DATE('2012-02-16', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghost ship', 2002, 'With a plot as creaky as the boat, Ghost Ship fails to deliver the scares.', TO_DATE('2002-10-21', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghost stories', 2017, 'Ghost Stories offers a well-crafted, skillfully told horror anthology that cleverly toys with genre tropes while adding a few devilishly frightful twists.', TO_DATE('2017-10-05', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghost world', 2001, 'With acerbic wit, Terry Zwigoff fashions Daniel Clowes'' graphic novel into an intelligent, comedic trip through deadpan teen angst.', TO_DATE('2001-06-25', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghostbusters 1984 original', 2000, 'An infectiously fun blend of special effects and comedy, with Bill Murray''s hilarious deadpan performance leading a cast of great comic turns.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghostbusters 2', 2000, 'Thanks to the cast, Ghostbusters 2 is reasonably amusing, but it lacks the charm, wit, and energy of its predecessor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghostbusters', 2016, 'Ghostbusters does an impressive job of standing on its own as a freewheeling, marvelously cast supernatural comedy -- even if it can''t help but pale somewhat in comparison with the classic original.', TO_DATE('2016-07-10', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghosts of girlfriends past', 2009, 'A retread of A Christmas Carol, featuring Matthew McConaughey in a retread of his Dazed and Confused role, Ghosts of Girlfriends Past lacks originality, humor, and any semblance of charm.', TO_DATE('2009-04-27', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghosts of mississippi', 2000, 'James Woods is convincing as a white supremacist, but everything else rings false in this courtroom drama, which examines a weighty subject from the least interesting perspective.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghosts of the abyss', 2003, 'The underwater footage is both beautiful and awe-inspiring.', TO_DATE('2003-04-04', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ghosts of war', 2020, 'Ghosts of War blends supernatural horror and period war drama to produce a muddled mashup that proves some ingredients are better left separate.', TO_DATE('2020-07-13', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gi jane', 1997, 'Demi Moore admirably does her duty, but G.I. Jane''s well-intentioned message is obscured by stylistic bombast and an overload of jingoism.', TO_DATE('1997-08-22', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gi joe retaliation', 2013, 'Though arguably superior to its predecessor, G.I. Joe: Retaliation is overwhelmed by its nonstop action and too nonsensical and vapid to leave a lasting impression.', TO_DATE('2013-03-22', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gi joe the rise of cobra', 2009, 'While fans of the Hasbro toy franchise may revel in a bit of nostalgia, G.I. Joe: The Rise of Cobra is largely a cartoonish, over-the-top action fest propelled by silly writing, inconsistent visual effects, and merely passable performances.', TO_DATE('2009-07-30', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('giant', 2000, 'Giant earns its imposing name with a towering narrative supported by striking cinematography, big ideas, and powerful work from a trio of legendary Hollywood leads.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('giant little ones', 2018, 'Giant Little Ones puts a complex and refreshingly nuanced spin on the traditional coming of age drama, further elevated by the admirable efforts of a talented cast.', TO_DATE('2018-09-06', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gifted', 2017, 'Gifted isn''t quite as bright as its pint-sized protagonist, but a charming cast wrings respectably engaging drama out of a fairly predictable premise.', TO_DATE('2017-03-30', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gigi', 2000, 'It may not be one of Vincente Minnelli''s best, but the charming and flawlessly acted Gigi still offers enough visual and musical treats to satisfy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gigli', 2003, 'Bizarre and clumsily plotted, Gigli is a mess. As for its stars, Affleck and Lopez lack chemistry.', TO_DATE('2003-07-28', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gilda', 1946, 'Rita Hayworth carries Gilda on the sheer strength of her screen presence, rendering the film''s somewhat middling story almost irrelevant.', TO_DATE('1946-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gimme danger', 2016, 'Its infectious enthusiasm for its subjects - and Iggy Pop''s ingratiating presence - more than make up for the effortlessly entertaining Gimme Danger''s relative lack of context or depth.', TO_DATE('2016-05-19', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gimme shelter', 1970, 'Equal parts essential and chilling, Gimme Shelter provides a spine-tingling look at how the Rolling Stones'' music paralleled the end of the counterculture movement.', TO_DATE('1970-12-06', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gimme shelter', 2014, 'In spite of its obvious good intentions -- and the compelling true story that inspired it -- the heavy-handed Gimme Shelter can''t overcome its cliche-riddled script.', TO_DATE('2014-01-18', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gimme the loot', 2012, 'Thanks to energetic performances from its young leads, Gimme The Loot captures a slice of city life with warmth and exuberance.', TO_DATE('2012-03-15', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ginger rosa', 2012, 'Elle Fanning gives a terrific performance in this powerful coming-of-age tale about a pair of teenage girls whose friendship is unnerved by the threat of nuclear war.', TO_DATE('2012-09-07', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ginger snaps', 2001, 'The strong female cast and biting satire of teenage life makes Ginger Snaps far more memorable than your average werewolf movie -- or teen flick.', TO_DATE('2001-05-11', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('girl', 2018, 'Girl uses one aspiring dancer''s story as the framework for a poignant drama that approaches its difficult themes with fittingly alluring grace.', TO_DATE('2018-05-14', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la fille coupée en deux the girl cut in two a girl cut in two', 2007, 'Nouvelle Vague master Claude Chabrol balances subtle stabs of humor and biting class criticism to explore a love story and the seedier side of the haute bourgeois.', TO_DATE('2007-09-21', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la fille de monaco the girl from monaco', 2009, 'Undeniably slight, this satiric thriller suffers from an uneven tone and a relative lack of thrills, but solid performances from the cast help keep it afloat.', TO_DATE('2009-03-11', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('girl in progress', 2012, 'Despite a well-intentioned and novel premise, Girl in Progress is plagued by jarring tonal shifts and does little to break its characters out of cliché.', TO_DATE('2012-05-06', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('girl interrupted', 1999, 'Angelina Jolie gives an intense performance, but overall Girl, Interrupted suffers from thin, predictable plotting that fails to capture the power of its source material.', TO_DATE('1999-12-21', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('girl most likely', 2012, 'Largely witless and disappointingly dull, Girl Most Likely strands the gifted Kristen Wiig in a blandly hollow foray into scattershot sitcom territory.', TO_DATE('2012-09-11', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('girl on the third floor', 2019, 'Girl on the Third Floor proves a good old-fashioned haunted house story can still be entertaining -- and put a fresh spin on established genre formula.', TO_DATE('2019-03-11', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the girl who played with fire flickan som lekte med elden', 2010, 'Noomi Rapace and Michael Nyqvist remain extraordinarily well-suited to their roles, but the second installment in Stieg Larsson''s Millennium Trilogy doesn''t pack quite as much punch as the first.', TO_DATE('2010-06-15', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('girl with a pearl earring', 2003, 'Visually arresting, but the story could be told with a bit more energy.', TO_DATE('2003-09-11', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red riding hood', 2011, 'Amanda Seyfried is magnetic in Red Riding Hood''s starring role, but she''s let down by her uninspired leading men and a painfully cliched script.', TO_DATE('2011-03-09', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('girlfight', 2000, 'Michelle Rodriguez gives a compelling performance, despite lack of a boxing background; Karyn Kusama packs a punch with this directorial debut.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the girlfriend experience', 2009, 'Steven Soderbergh''s latest lo-fi production is strikingly crafted but emotionally vague.', TO_DATE('2009-04-28', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('girlhood', 2003, 'An intimate, compassionate look at two teenagers in juvenile hall.', TO_DATE('2003-09-24', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('girlhood', 2014, 'Powerfully acted and smartly scripted, Girlhood offers a fresh perspective on familiar cinematic territory.', TO_DATE('2014-05-16', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('girls cant swim', 2001, 'The well-acted Girls Can''t Swim is a sensitive depiction of two girls'' coming-of-age.', TO_DATE('2001-08-17', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('girls of the sun les filles du soleil', 2018, 'Girls of the Sun has the best of intentions, but this worthy - and thoroughly timely - story is fatally undermined by its clumsily overbearing execution.', TO_DATE('2018-05-13', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('girls trip', 2017, 'Girls Trip is the rare R-rated comedy that pushes boundaries to truly comedic effect -- and anchors its laughs in compelling characters brought to life by a brilliantly assembled cast.', TO_DATE('2017-07-12', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('girls will be girls', 2003, 'Vulgar but entertaining camp.', TO_DATE('2003-03-22', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('girls with balls', 2018, 'While occasionally funny and relentlessly gory, Girls With Balls is neither particularly strong on cheap thrills nor a very remarkable entry to the trash horror genre.', TO_DATE('2018-12-13', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('giuliani time', 2006, 'Though he may be preaching to the choir, Keating provides plenty of evidence to back his claims about the former NYC mayor.', TO_DATE('2006-04-13', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('give me liberty', 2019, 'Give Me Liberty expertly juggles resonant themes and a madcap series of events to produce a chaotic comedy with heart.', TO_DATE('2019-01-25', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gladiator', 2000, 'Ridley Scott and an excellent cast successfully convey the intensity of Roman gladitorial combat as well as the political intrigue brewing beneath.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('glass', 2019, 'Glass displays a few glimmers of M. Night Shyamalan at his twisty world-building best, but ultimately disappoints as the conclusion to the writer-director''s long-gestating trilogy.', TO_DATE('2019-01-09', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the glass house', 2001, 'Due to obvious plot twists and foreshadowing, The Glass House fails to thrill. By the end, it degenerates into ludicrousness.', TO_DATE('2001-09-13', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('glassland', 2015, 'Glassland''s grim setting is leavened by writer-director Gerard Barrett''s compassionate treatment of his characters -- and bolstered by a strong cast led by Toni Collette and Jack Reynor.', TO_DATE('2015-01-26', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gleason', 2016, 'Gleason stands out among sports-themed documentaries by offering a clear-eyed look at its subject''s physical deterioration -- and an intimate portrait of the family affected by his ordeal.', TO_DATE('2016-01-30', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('glee the 3d concert movie', 2011, 'The unconverted will remain just as perplexed as ever, but for gleeful Gleeks, The 3D Concert Movie delivers exactly what it promises.', TO_DATE('2011-08-08', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('glen campbell ill be me', 2014, 'The heartrendingly honest Glen Campbell: I''ll Be Me offers a window into Alzheimer''s that should prove powerful viewing for Campbell fans and novices alike.', TO_DATE('2014-10-21', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('glen or glenda', 2000, 'Glen or Glenda? remains an interesting artifact from one of Hollywood''s more colorful careers -- albeit not one that holds up particularly well as a movie.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('glengarry glen ross', 1992, 'This adaptation of David Mamet''s play is every bit as compelling and witty as its source material, thanks in large part to a clever script and a bevy of powerhouse actors.', TO_DATE('1992-09-29', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the glimmer man', 2000, 'A grimy, humorless glimpse of Steven Seagal''s direct-to-video future, Glimmer Man fails to shine.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('glitter', 2001, 'Glitter is a hodgepodge of movie cliches and bad acting that''s sure to generate unintentional laughs. Unfortunately, the movie is not bad enough to be good.', TO_DATE('2001-08-29', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gloria', 2013, 'Marvelously directed by Sebastian Lelio and beautifully led by a powerful performance from Paulina Garcia, Gloria takes an honest, sweetly poignant look at a type of character that''s all too often neglected in Hollywood.', TO_DATE('2013-09-05', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gloria bell', 2018, 'Free of visual or narrative embellishments, Gloria Bell rests almost completely on Julianne Moore''s performance in the title role -- and she''s gloriously up to the task.', TO_DATE('2018-09-08', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gnomeo and juliet', 2011, 'While it has moments of inspiration, Gnomeo and Juliet is often too self-referential for its own good.', TO_DATE('2011-02-03', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('go back to china', 2019, 'Uneven but entertaining, Go Back to China puts a refreshing cross-cultural spin on the traditional coming-of-age story arc.', TO_DATE('2019-03-09', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('go for sisters', 2013, 'Meandering and diffuse, Go for Sisters proves a letdown for all but the most ardent John Sayles enthusiasts.', TO_DATE('2013-03-18', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('go tigers', 2001, 'Go Tigers! is an absorbing and evenhanded documentary that takes a perceptive look at the world of high school sports and its impact on a community.', TO_DATE('2001-08-02', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('goat', 2016, 'Goat isn''t an easy watch, but its thought-provoking themes, talented cast, and all-out intensity offer rewards for viewers willing to tough it out.', TO_DATE('2016-01-23', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('goats', 2012, 'Goats reaches for profundity but mostly offers inane bleating, with David Duchovny''s beard proving the most distinguishing feature of this bland dramedy.', TO_DATE('2012-01-26', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('god bless america', 2011, 'A darkly comic polemic on modern culture, God Bless America is uneven and somewhat this but the ideas behind this revenge fulfillment journey has primal appeal.', TO_DATE('2011-09-15', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('god grew tired of us', 2006, 'Not just a powerful telling of the journey of exiled Sudanese boys, God Grew Tired of Us is also a poignant account of the determination of the human spirit.', TO_DATE('2006-01-26', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('god help the girl', 2014, 'While it may strike harder-hearted viewers as excessively twee, God Help the Girl floats by on its sweet charm and talented cast.', TO_DATE('2014-01-20', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('god said ha', 2000, 'God Said, Ha! plumbs poignant depths, but Julia Sweeney''s sharp, graceful wit makes this one-woman monologue a wise, big-hearted burst of uplifting -- and perhaps therapeutic -- entertainment.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the godfather', 2000, 'One of Hollywood''s greatest critical and commercial successes, The Godfather gets everything right; not only did the movie transcend expectations, it established new benchmarks for American cinema.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the godfather part ii', 2000, 'Drawing on strong performances by Al Pacino and Robert De Niro, Francis Ford Coppola''s continuation of Mario Puzo''s Mafia saga set new standards for sequels that have yet to be matched or broken.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the godfather part iii', 2000, 'The final installment of The Godfather saga recalls its predecessors'' power when it''s strictly business, but underwhelming performances and confused tonality brings less closure to the Corleone story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gods and generals', 2003, 'Filled with two-dimensional characters and pompous self-righteousness, Gods and Generals is a long, tedious sit. Some may also take offense at the pro-Confederate slant.', TO_DATE('2003-02-14', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gods and monsters', 1998, 'Gods and Monsters is a spellbinding, confusing piece of semi-fiction, featuring fine performances; McKellen leads the way, but Redgrave and Fraser don''t lag far behind.', TO_DATE('1998-11-04', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gods not dead', 2014, 'Deploying sledgehammer theatrics instead of delivering its message with a dose of good faith, God''s Not Dead makes for bad drama and an unconvincing argument to the unconverted.', TO_DATE('2014-03-22', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gods not dead 2', 2016, 'Every bit the proselytizing lecture promised by its title, God''s Not Dead 2 preaches ham-fistedly to its paranoid conservative choir.', TO_DATE('2016-03-30', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gods of egypt', 2016, 'Look on Gods of Egypt, ye filmgoers, and despair! Nothing beside remains. Round the decay of this colossal wreck, boundless and bare. The lone and level sands stretch far away. (Apologies to Shelley.)', TO_DATE('2016-02-24', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gods own country', 2017, 'A quiet, moving rumination on loneliness and newfound intimacy, God''s Own Country marks an outstanding directorial debut for Francis Lee.', TO_DATE('2017-01-21', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gods pocket', 2014, 'Well-cast but frustratingly clichéd, God''s Pocket fails to strike a sensible balance between comedy and drama.', TO_DATE('2014-01-18', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('godsend', 2004, 'A murky thriller with few chills, Godsend features ludicrous dialogue, by-the-numbers plotting, and an excess of cheap shocks.', TO_DATE('2004-04-28', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('godzilla', 2000, 'Without compelling characters or heart, Godzilla stomps on everything that made the original (or any monster movie worth its salt) a classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('godzilla gojira', 2000, 'More than straight monster-movie fare, Gojira offers potent, sobering postwar commentary.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('godzilla 2000', 2000, 'Godzilla 2000 is cheesy, laughable, and good entertaining fun.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('godzilla', 2014, 'With just enough human drama to anchor the sweeping spectacle of giant monsters smashing everything in sight, Gareth Edwards'' Godzilla satisfyingly restores the franchise''s fire-breathing glory.', TO_DATE('2014-05-10', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('godzilla king of the monsters', 2019, 'Godzilla: King of the Monsters delivers spectacular kaiju action -- and reaffirms that cutting-edge effects are still no substitute for a good story.', TO_DATE('2019-05-28', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('godzilla resurgence shin godzilla', 2016, 'Godzilla Resurgence offers a refreshingly low-fi -- and altogether entertaining -- return to the monster''s classic creature-feature roots.', TO_DATE('2016-08-04', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('going clear scientology and the prison of belief', 2015, 'Thoroughly disquieting but impossible to ignore, Going Clear: Scientology and the Prison of Belief is a searing investigative work from a master documentarian.', TO_DATE('2015-01-26', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('going in style', 2017, 'Despite the considerable talent of its leads, Going in Style is light on laughs and plays it safe far too often.', TO_DATE('2017-04-05', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('going my way', 2000, 'Bing Crosby and Barry Fitzgerald are eminently likable, and film is pleasantly sentimental, but Going My Way suffers from a surplus of sweetness.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('going shopping', 2005, 'Much like a bad trip to the mall, Going Shopping starts out fun but eventually degenerates into a shallow and unsatisfying experience.', TO_DATE('2005-09-18', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gold', 2016, 'Gold boasts an impressively committed performance from Matthew McConaughey, but it''s just one glittering nugget in an otherwise uneven heap of cinematic silt.', TO_DATE('2016-12-23', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('elizabeth the golden age', 2007, 'This sequel is full of lavish costumes and elaborate sets, but lacks the heart and creativity of the original Elizabeth', TO_DATE('2007-09-10', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the golden bowl', 2000, 'Coming from the Merchant-Ivory team, The Golden Bowl is visually stunning, but the filmmakers have difficulty in transporting the characterizations of the Henry James novel to the screen.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('golden door nuovomondo', 2006, 'Slow-moving but ultimately rewarding, Golden Door is a profound drama with scenes of fantastical magical realism, lively humor, and stunning images.', TO_DATE('2006-09-15', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('golden exits', 2017, 'Golden Exits tells a small-scale tale whose seemingly mundane trappings belie a satisfying handful of finely tuned observations about modern life and relationships.', TO_DATE('2017-01-23', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('goldeneye', 1995, 'The first and best Pierce Brosnan Bond film, GoldenEye brings the series into a more modern context, and the result is a 007 entry that''s high-tech, action-packed, and urbane.', TO_DATE('1995-11-17', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('goldfinger', 2000, 'Goldfinger is where James Bond as we know him comes into focus - it features one of 007''s most famous lines ("A martini. Shaken, not stirred") and a wide range of gadgets that would become the series'' trademark.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gomorrah gomorra', 2008, 'Portraying organised crime with an unflinching realism, this gritty and searing Italian crime masterpiece pulls no punches.', TO_DATE('2008-02-13', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gone baby gone', 2007, 'Ben Affleck proves his directing credentials in this gripping dramatic thriller, drawing strong performances from the excellent cast and bringing working-class Boston to the screen.', TO_DATE('2007-09-05', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gone fishin', 2000, 'Sloppy, formulaic, and unfunny, Gone Fishin'' marks a painful low point in the careers of its two talented leads.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gone girl', 2014, 'Dark, intelligent, and stylish to a fault, Gone Girl plays to director David Fincher''s sick strengths while bringing the best out of stars Ben Affleck and Rosamund Pike.', TO_DATE('2014-09-21', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gone with the wind', 1939, 'Gone with the Wind''s epic grandeur and romantic allure encapsulate an era of Hollywood filmmaking -- but that can''t excuse a blinkered perspective that stands on the wrong side of history.', TO_DATE('1939-12-15', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gonzo the life and work of hunter s thompson', 2008, 'While not the comprehensive profile of the man that his die-hard fans might have hoped for, Gonzo remains an insightful introduction to the life of rebellious writer Hunter S. Thompson and his influences.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('good boys', 2019, 'Good Boys is undermined by an eagerness to repeatedly indulge in profane humor, but its appealing cast and ultimately thoughtful message often shine through.', TO_DATE('2019-03-12', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('good burger', 2000, 'Good Burger might please hardcore fans of the 1990s Nickelodeon TV series that launched leads Kenan and Kel to stardom, but for all others, it will likely prove a comedy that is neither satisfyingly rare nor well done.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('good bye lenin', 2003, 'Heartfelt and sly, Good Bye, Lenin! succeeds as a satire by foregrounding the personal before the political, yielding a charming comedy full of sociopolitical insight.', TO_DATE('2003-06-03', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('good dick', 2008, 'Marianna Palka''s quirky indie debut centred on two dysfunctional loners is hit and miss, but has enough originality to see it through.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the good german', 2006, 'Though Steven Soderbergh succeeds in emulating the glossy look of 1940s noirs, The Good German ultimately ends up as a self-conscious exercise in style that forgets to develop compelling characters.', TO_DATE('2006-11-12', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the good guy', 2010, 'The Good Guy has an attractive cast, but they aren''t done any favors by the film''s cardboard characters and cliched plot.', TO_DATE('2010-01-27', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('good hair', 2009, 'Funny, informative, and occasionally sad, Good Hair is a provocative look at the complex relationship between African Americans and their hair.', TO_DATE('2009-03-03', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('good kill', 2014, 'Thought-provoking, timely, and anchored by a strong performance from Ethan Hawke, Good Kill is a modern war movie with a troubled conscience.', TO_DATE('2014-09-08', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('good luck chuck', 2007, 'A shortage of laughs and an undercurrent of mean-spiritedness undermine Good Luck Chuck, squandering a decent premise on gross-out humor and shopworn slapstick.', TO_DATE('2007-09-18', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('good morning vietnam', 2000, 'A well-calibrated blend of manic comedy and poignant drama, Good Morning, Vietnam offers a captivating look at a wide range of Robin Williams'' cinematic gifts.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the good night', 2007, 'That The Good Night is the work of a first-time writer/director is apparent, as the story feels disjointed and never connects with the audience.', TO_DATE('2007-01-27', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('good ol freda', 2013, 'Good Ol'' Freda proves that even after all these years, some corners of Beatles history remain unexplored -- and just as fascinating as the chapters we all know by heart.', TO_DATE('2013-09-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the good shepherd', 2006, 'Though ambitious and confidently directed by Robert De Niro, The Good Shepherd is ultimately a tedious drama that holds few surprises and succumbs to self-seriousness.', TO_DATE('2006-12-08', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the good son', 1993, 'The Good Son is never good enough to live up to its unsettling potential, failing to drum up much suspense and unable to make Macaulay Culkin a credible psychopath.', TO_DATE('1993-09-24', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('good time', 2017, 'A visual treat filled out by consistently stellar work from Robert Pattinson, Good Time is a singularly distinctive crime drama offering far more than the usual genre thrills.', TO_DATE('2017-05-25', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('good will hunting', 1997, 'It follows a predictable narrative arc, but Good Will Hunting adds enough quirks to the journey -- and is loaded with enough powerful performances -- that it remains an entertaining, emotionally rich drama.', TO_DATE('1997-12-05', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a good woman', 2004, 'This adaptation of Wilde''s Lady Windermere''s Fan lacks bite due to liberties taken with the source material, coupled with uneven performances.', TO_DATE('2004-11-06', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a good year', 2006, 'A Good Year is a fine example of a top-notch director and actor out of their elements, in a sappy romantic comedy lacking in charm and humor.', TO_DATE('2006-09-10', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('goodbye christopher robin', 2017, 'Goodbye Christopher Robin struggles to balance wartime tension and childlike wonder, but offers valuable insight into the darkness shadowing the creation of a classic children''s tale.', TO_DATE('2017-09-20', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('goodbye lover', 2000, 'Half-baked plot twists disorient rather than build drama.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('goodbye solo', 2008, 'An original and thoughtful human drama, Goodbye Solo looks at relationships and loneliness while proving director Ramin Bahrani''s is an important American voice.', TO_DATE('2008-10-09', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('goodnight mommy ich seh ich seh', 2014, 'Dark, violent, and drenched in dread, Goodnight Mommy is perfect for extreme horror enthusiasts -- or filmgoers who prefer to watch between splayed fingers.', TO_DATE('2014-09-08', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the goods live hard sell hard', 2009, 'Despite the talent in front of and behind the camera, The Goods: Live Hard, Sell Hard largely misfires, proving a squandered opportunity for all involved.', TO_DATE('2009-08-12', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a goofy movie', 2000, 'A Goofy Movie offers enough of its titular ingredient to satisfy younger viewers, even if most parents will agree that this beloved character deserves better.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gook', 2017, 'From its confrontational title to its striking cinematography, this raw cinematic gem uncompromisingly proves writer/director/actor Justin Chon is a filmmaker to watch.', TO_DATE('2017-01-22', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('goon', 2011, 'Goon is a crude slapstick comedy with well-formed characters and a surprising amount of heart.', TO_DATE('2011-09-20', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('goon last of the enforcers', 2017, 'Seann William Scott remains as watchable as ever in the title role, but Goon: Last of the Enforcers repeats its predecessor''s violent and profane formula to diminishing effect.', TO_DATE('2017-03-09', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the goonies', 2000, 'The Goonies is an energetic, sometimes noisy mix of Spielbergian sentiment and funhouse tricks that will appeal to kids and nostalgic adults alike.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('goosebumps', 2015, 'Goosebumps boasts more than enough of its spooky source material''s kid-friendly charm to make up for some slightly scattershot humor and a hurried pace.', TO_DATE('2015-10-05', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('goosebumps 2 haunted halloween', 2018, 'Goosebumps 2: Haunted Halloween offers a handful of treats for very young viewers, but compared to the entertaining original, this sequel is a ding dong to ditch.', TO_DATE('2018-10-10', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gosford park', 2001, 'A mixture of Upstairs, Downstairs, Clue, and perceptive social commentary, Gosford Park ranks among director Altman''s best.', TO_DATE('2001-11-11', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the gospel', 2005, 'While it features outstanding musical numbers, The Gospel reduces a series of worthy themes -- faith, family, forgiveness -- to soapy, banal clichés.', TO_DATE('2005-10-04', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('il vangelo secondo matteo the gospel according to st matthew', 2001, 'The Gospel According to St. Matthew forgoes the pageantry of biblical epics in favor of a naturalistic retelling of the Christ story, achieving a respectful if not reverent interpretation with political verve.', TO_DATE('2001-02-27', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gossip', 2000, 'Gossip drags on far beyond its entertainment value.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gothika', 2003, 'Berry''s acting talents can''t save Gothika from its preposterous plot and bad dialogue.', TO_DATE('2003-11-17', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gotti', 2018, 'Fuhgeddaboudit.', TO_DATE('2018-05-16', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('goyas ghosts', 2006, 'Ornate costumes and a talented cast can''t make up for Ghosts'' glacial pace and confused plot.', TO_DATE('2006-11-13', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grace is gone', 2007, 'A refreshing departure from the current crop of Iraq war dramas, Grace is Gone is a heartfelt, finely acted portrayal of grief and healing.', TO_DATE('2007-01-24', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gracie', 2007, 'Gracie can be rousing and touching in spots, but is ultimately undone by its predictable story arc and a lack of nuance.', TO_DATE('2007-05-02', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the graduate', 2000, 'The music, the performances, the precision in capturing the post-college malaise -- The Graduate''s coming-of-age story is indeed one for the ages.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gran torino', 2008, 'Though a minor entry in Eastwood''s body of work, Gran Torino is nevertheless a humorous, touching, and intriguing old-school parable.', TO_DATE('2008-12-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grand hotel', 1932, 'Perhaps less a true film than a series of star-studded vignettes, Grand Hotel still remains an entertaining look back at a bygone Hollywood era.', TO_DATE('1932-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grand piano', 2013, 'Grand Piano is so tense in its best moments -- and appealingly strange overall -- that it remains rewarding in spite of its flaws.', TO_DATE('2013-09-23', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grand theft parsons', 2003, 'Grand Theft Parsons pays tribute to a rock legend without following biopic formula -- and proves that a unique perspective doesn''t always mean a worthwhile film.', TO_DATE('2003-12-02', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grandma', 2015, 'Boasting a stellar performance from Lily Tomlin and some powerfully empathetic work from writer-director Paul Weitz, Grandma is a dramedy that shouldn''t have to ask you to visit.', TO_DATE('2015-01-26', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grandmas boy', 2006, 'A gross-out comedy that''s more gross than comedic, Grandma''s Boy is lazy and unrewarding.', TO_DATE('2006-01-05', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the grapes of wrath', 2000, 'A potent drama that is as socially important today as when it was made, The Grapes of Wrath is affecting, moving, and deservedly considered an American classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grave of the fireflies hotaru no haka', 2000, 'An achingly sad anti-war film, Grave of the Fireflies is one of Studio Ghibli''s most profoundly beautiful, haunting works.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gravity', 2013, 'Alfonso Cuarón''s Gravity is an eerie, tense sci-fi thriller that''s masterfully directed and visually stunning.', TO_DATE('2013-08-28', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grease', 1978, 'Grease is a pleasing, energetic musical with infectiously catchy songs and an ode to young love that never gets old.', TO_DATE('1978-06-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grease 2', 2000, 'Grease 2 is undeniably stocked with solid songs and well-choreographed dance sequences, but there''s no getting around the fact that it''s a blatant retread of its far more entertaining predecessor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grease live', 2016, 'Grease: Live took the pressure and threw away conventionality -- it belongs to yesterday. There was a chance that it could make it so far; we started believin'' we can be who we are. Grease: Live is the word.', TO_DATE('2016-02-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the great debaters', 2007, 'A wonderful cast and top-notch script elevate The Great Debaters beyond a familiar formula for a touching, uplifting drama.', TO_DATE('2007-12-07', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the great dictator', 2000, 'Charlie Chaplin demonstrates that his comedic voice is undiminished by dialogue in this rousing satire of tyranny, which may be more distinguished by its uplifting humanism than its gags.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('great expectations', 2000, 'Furnished with striking visual detail and told with great narrative economy by director David Lean, Great Expectations is an exemplary adaptation of Charles Dickens'' dense and episodic novel.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('great expectations', 2012, 'Not the best version of the oft-filmed Dickens classic but far from the worst, Mike Newell''s Great Expectations breathes just enough life into the source material to justify yet another adaptation.', TO_DATE('2012-09-12', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the great muppet caper', 2002, 'The Great Muppet Caper is overplotted and uneven, but the appealing presence of Kermit, Miss Piggy and the gang ensure that this heist flick is always breezily watchable.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the great new wonderful', 2006, 'Set in post-9/11 New York, this largely evocative dramedy interweaves the stories of five disconnected individuals who share an unspoken emotional malaise that shadows their attempts at returning to normal life.', TO_DATE('2006-06-19', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the great raid', 2005, 'Though the climax of the film -- the actual raid -- is exciting, the rest of it is bogged down in too many subplots and runs on for too long.', TO_DATE('2005-07-21', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('great world of sound', 2007, 'The Great World Of Sound is a charming and unassuming film, thanks to breakthrough performances from Pat Healy and Kene Holiday.', TO_DATE('2007-01-24', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the great ziegfeld', 1936, 'This biopic is undeniably stylish, but loses points for excessive length, an overreliance on clichés, and historical inaccuracies.', TO_DATE('1936-01-01', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the greatest game ever played', 2005, 'Despite all the underdog sports movie conventions, the likable cast and lush production values make The Greatest Game Ever Played a solid and uplifting tale.', TO_DATE('2005-09-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the greatest show on earth', 2002, 'The Greatest Show on Earth is melodramatic, short on plot, excessively lengthy and bogged down with clichés, but not without a certain innocent charm.', TO_DATE('2002-05-31', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('greed', 2019, 'Greed rarely hits quite as hard as it ought to, but solid laughs and a smartly assembled cast keep this one-percent satire entertaining.', TO_DATE('2019-09-08', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('greedy lying bastards', 2013, 'It''s not particularly subtle, but Greedy Lying Bastards is effective in questioning the motives of climate change deniers.', TO_DATE('2013-02-19', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('green book', 2018, 'Green Book takes audiences on an excessively smooth ride through bumpy subject matter, although Mahershala Ali and Viggo Mortensen''s performances add necessary depth.', TO_DATE('2018-09-11', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('green dragon', 2001, 'Green Dragon struggles to control its sentimental tendencies, but its flaws are just outweighed by an affecting -- and often overlooked -- perspective on the Vietnam War.', TO_DATE('2001-04-20', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the green hornet', 2011, 'It''s sporadically entertaining, but The Green Hornet never approaches the surreal heights suggested by a Michel Gondry/Seth Rogen collaboration.', TO_DATE('2011-01-08', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('green lantern', 2011, 'Noisy, overproduced, and thinly written, Green Lantern squanders an impressive budget and decades of comics mythology.', TO_DATE('2011-06-14', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the green mile', 2000, 'Though The Green Mile is long, critics say it''s an absorbing, emotionally powerful experience.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('green room', 2015, 'Green Room delivers unapologetic genre thrills with uncommon intelligence and powerfully acted élan.', TO_DATE('2015-05-18', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('green street hooligans', 2005, 'When it comes to the subculture of soccer thugs, Green Street Hooligans lacks sufficient insight, and instead comes off as a Fight Club knock-off.', TO_DATE('2005-03-22', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('greenberg', 2010, 'Greenberg''s title character is harder to like than most, but Ben Stiller''s nuanced performance and a darkly funny script help take the misanthropic edge off.', TO_DATE('2010-02-23', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('greener grass', 2019, 'Greener Grass is far from the first comedy to skewer suburbia -- but it might be among the most bizarre and surreally distinctive.', TO_DATE('2019-01-31', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('greenfingers', 2001, 'Greenfingers follows the British feel-good formula of underdogs somehow beating the odds, adding nothing new to this already saturated genre.', TO_DATE('2001-03-29', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('greetings from tim buckley', 2012, 'Slight yet resonant, Greetings from Tim Buckley honors a family''s musical legacy while offering Penn Badgley a remarkable opportunity to display his dramatic gifts.', TO_DATE('2012-09-10', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gremlins', 2000, 'Whether you choose to see it as a statement on consumer culture or simply a special effects-heavy popcorn flick, Gremlins is a minor classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gremlins 2 the new batch', 2000, 'Gremlins 2 trades the spiky thrills of its predecessor for looney satire, yielding a succession of sporadically clever gags that add some flavor to a recycled plot.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('greta', 2018, 'A bonkers B movie occasionally elevated by its A-list talent, Greta dives headlong into camp and struggles to stay afloat.', TO_DATE('2018-09-07', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grey gardens', 1975, 'Edith and Edie Beale are eccentric subjects who offer a generous amount of themselves in Grey Gardens, an inquisitive and nonjudgmental exploration of the isolated socialites'' lifestyle.', TO_DATE('1975-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grey gardens', 2009, 'Grey Gardens offers few new revelations about the eccentric Edie''s, but is elevated thanks to powerhouse performances from Drew Barrymore and Jessica Lange.', TO_DATE('2009-04-16', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gridiron gang', 2006, 'The role of probation officer Sean Porter fits Dwayne "The Rock" Johnson like a glove; however, the execution is so cliched, the youths'' stories (based on real events), fail to inspire.', TO_DATE('2006-08-24', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the grifters', 1990, 'Coolly collected and confidently performed, The Grifters is a stylish caper that puts the artistry in con.', TO_DATE('1990-09-14', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gringo', 2018, 'Gringo rounds up a bafflingly overqualified cast for a misfire of a comedy that''s fatally undermined by its messy plot, poorly conceived characters, and obvious debts to better films.', TO_DATE('2018-03-05', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grizzly man', 2005, 'Whatever opinion you come to have of the obsessive Treadwell, Herzog has once again found a fascinating subject.', TO_DATE('2005-02-02', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('le fils de lépicier the grocers son', 2007, 'A noteworthy performance by Eric Guirado makes this gently pastoral film a moving coming-of-age story.', TO_DATE('2007-11-05', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the groomsmen', 2006, 'Director and star Burns returns to his home turf -- dialogue-driven examinations of the relationships between men and women -- with uneven results.', TO_DATE('2006-07-10', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('groove', 2000, 'Though high on energy and great techno tunes, Groove''s characters and plotlines are too cliched to be engaging.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grosse pointe blank', 1997, 'A high-concept high school reunion movie with an adroitly cast John Cusack and armed with a script of incisive wit.', TO_DATE('1997-04-11', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('groundhog day', 2000, 'Smart, sweet, and inventive, Groundhog Day highlights Murray''s dramatic gifts while still leaving plenty of room for laughs.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grown ups', 2010, 'Grown Ups'' cast of comedy vets is amiable, but they''re let down by flat direction and the scattershot, lowbrow humor of a stunted script.', TO_DATE('2010-06-21', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grown ups 2', 2013, 'While it''s almost certainly the movie event of the year for filmgoers passionate about deer urine humor, Grown Ups 2 will bore, annoy, and disgust audiences of nearly every other persuasion.', TO_DATE('2013-07-10', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the grudge 2', 2006, 'A diminished sequel that makes even less sense than The Grudge 1.', TO_DATE('2006-10-12', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grudge match', 2013, 'Grudge Match is sporadically funny but meandering, and its strong cast largely mired in a plot that''s overrun with clichés.', TO_DATE('2013-12-19', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('grumpy old men', 1993, 'Grumpy Old Men''s stars are better than the material they''re given -- but their comedic chemistry is so strong that whenever they share the screen, it hardly matters.', TO_DATE('1993-12-24', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in bloom', 2014, 'A coming-of-age drama entwined with a political statement, In Bloom underscores its well-worn themes with strong performances and palpable real-world tension.', TO_DATE('2014-01-06', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('guardians of the galaxy', 2014, 'Guardians of the Galaxy is just as irreverent as fans of the frequently zany Marvel comic would expect -- as well as funny, thrilling, full of heart, and packed with visual splendor.', TO_DATE('2014-07-24', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('guardians of the galaxy vol 2', 2017, 'Guardians of the Galaxy Vol. 2''s action-packed plot, dazzling visuals, and irreverent humor add up to a sequel that''s almost as fun -- if not quite as thrillingly fresh -- as its predecessor.', TO_DATE('2017-04-23', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('güeros', 2014, 'A striking effort that synthesizes disparate influences with inventive flair, Güeros marks a bold step forward for modern Mexican cinema.', TO_DATE('2014-04-16', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('guerrilla the taking of patty hearst', 2004, 'Guerilla is a riveting documentary that chronicles in enlightening fashion the 1974 kidnapping of heiress Patty Hearst.', TO_DATE('2004-04-20', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('guess who', 2005, 'Despite the chemistry of its stars, Guess Who, a loose remake of Guess Who''s Coming to Dinner, lacks the political relevance of the original.', TO_DATE('2005-03-17', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('guess whos coming to dinner', 2001, 'More well-intentioned than insightful in its approach to interracial marriage, Guess Who''s Coming to Dinner succeeds thanks to the fizzy chemistry of its star-studded ensemble.', TO_DATE('2001-02-13', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('guest of cindy sherman', 2008, 'The filmmakers'' motivations may be suspect, but this inside look at New York art legend Cindy Sherman -- and, by extension, the culture she inhabits -- is undeniably satisfying.', TO_DATE('2008-05-05', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('guest of honour', 2019, 'David Thewlis'' performance aside, Guest of Honour serves as a frustratingly limited return to form for writer-director Atom Egoyan.', TO_DATE('2019-09-03', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gullivers travels', 2010, 'Though Jack Black is back doing what he does best, Gulliver''s Travels largely fails to do any justice to its source material, relying instead on juvenile humor and special effects.', TO_DATE('2010-12-16', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gun hill road', 2011, 'Equal parts absorbing and educational, Gun Hill Road wears its heart on its sleeve through tender performances that make up for its narrative familiarity.', TO_DATE('2011-01-28', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gun shy', 2000, 'A dark comedy of the low brow nature -- filled with fart and gay jokes. Even Liam Neeson and Sandra Bullock cannot save this failure.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gunga din', 2000, 'Funny, suspenseful, and spectacularly entertaining, Gunga Din is an expertly calibrated adventure flick with some unfortunately outdated ideas about race.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gunnin for that 1 spot', 2008, 'Beastie Boy Adam Yauch proves his worth as a director with Gunnin'' for That #1 Spot, a fun-filled chronicle of the top high school hoopsters of 2006.', TO_DATE('2008-05-02', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('guns akimbo', 2019, 'Frenetic to a fault, Guns Akimbo may leave some viewers reaching for the killswitch -- but for others, its videogame-style violence will have plenty of replay value.', TO_DATE('2019-09-10', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the guns of navarone', 2000, 'Bolstered by a cast of memorable stars and an impressive sense of scale, The Guns of the Navarone fires with vivid characterization and entertaining spectacle.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('guy and madeline on a park bench', 2010, 'Bursting with scrappy energy and shot with preternatural skill, Guy and Madeline on a Park Bench is an auspicious debut for director Damien Chazelle.', TO_DATE('2010-10-19', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gwen', 2018, 'Gwen''s relentlessly grim outlook may wear on some viewers, but it remains a reasonably gripping, solidly assembled descent into atmospheric period horror.', TO_DATE('2018-09-08', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('gypsy 83', 2003, 'This coming-of-age story of alienated youth is too familiar.', TO_DATE('2003-09-24', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('when the road bends tales of a gypsy caravan', 2007, 'A dynamic doc following five Romani bands is a pleasure for the senses thanks to vibrant colors and eclectic music.', TO_DATE('2007-06-04', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('h2 halloween ii', 2009, 'Zombie shows flashes of vision in the follow-up to his Halloween reboot, but they''re smothered by mountains of gore and hackneyed, brutal violence.', TO_DATE('2009-08-28', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hackers', 2000, 'Hackers has a certain stylish appeal, but its slick visuals and appealing young cast can''t compensate for a clichéd and disappointingly uninspired story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hacksaw ridge', 2016, 'Hacksaw Ridge uses a real-life pacifist''s legacy to lay the groundwork for a gripping wartime tribute to faith, valor, and the courage of remaining true to one''s convictions.', TO_DATE('2016-09-04', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hagazussa a heathens curse hagazussa', 2017, 'Hagazussa: A Heathen''s Curse weaves a spooky supernatural story that should satisfy horror fans with more adventurous inclinations.', TO_DATE('2017-10-10', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hail caesar', 2016, 'Packed with period detail and perfectly cast, Hail, Caesar! finds the Coen brothers delivering an agreeably lightweight love letter to post-war Hollywood.', TO_DATE('2016-02-02', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hair', 2000, 'Spiritedly performed by a groovy cast and imaginatively directed by Milos Forman, Hair transports audiences straight to the Age of Aquarius.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hair high', 2004, 'Hair High isn''t first-tier Plympton, but like the rest of the animator''s work, this is an assuredly odd tale that should resonate with fans of strange cinema.', TO_DATE('2004-04-06', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hairspray', 2007, 'Hairspray is an energetic, wholly entertaining musical romp; a fun Summer movie with plenty of heart. Its contagious songs will make you want to get up and start dancing.', TO_DATE('2007-06-30', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hale county this morning this evening', 2018, 'Intimate in scope yet thematically expansive, Hale County This Morning, This Evening draws extraordinary insights out of seemingly ordinary moments.', TO_DATE('2018-01-19', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('half baked', 2000, 'You''d have to be high to dig Half Baked''s half baked production and scattershot sense of humor -- although maybe that was the point of this Dave Chapelle-led joint.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('half magic', 2018, 'Half Magic never quite fulfills its apparent goals, but this comedy from writer-director-star Heather Graham is still occasionally affably diverting.', TO_DATE('2018-01-23', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('half nelson', 2006, 'Half Nelson features powerful performances from Ryan Gosling and Shareeka Epps. It''s a wise, unsentimental portrait of lonely people at the crossroads.', TO_DATE('2006-01-24', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('half of a yellow sun', 2013, 'While it doesn''t quite do justice to the source material, Half of a Yellow Sun adapts Chimamanda Ngozi Adichie''s novel with committed performances and narrative nuance.', TO_DATE('2013-10-21', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('half past dead', 2002, 'Seagal is now too bulky to make a convincing action hero, and Half Past Dead is too silly and incoherent to deliver any visceral kicks.', TO_DATE('2002-11-12', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hall pass', 2011, 'Some filmgoers may be surprised by the Farrellys'' defense of traditional domestic values in Hall Pass -- unfortunately, they''ll probably also be dismayed by the absence of laughs.', TO_DATE('2011-02-22', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('halloween', 2007, 'Rob Zombie doesn''t bring many new ideas to the table in Halloween, making it another bloody disappointment for fans of the franchise.', TO_DATE('2007-08-27', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('halloween', 2018, 'Halloween largely wipes the slate clean after decades of disappointing sequels, ignoring increasingly elaborate mythology in favor of basic - yet still effective - ingredients.', TO_DATE('2018-09-09', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('halloween 4 the return of michael myers', 2000, 'Halloween 4: The Return Of Michaels Myers may bring the series'' masked killer back into the fold, but fails to offer the visceral scares and inventiveness of the original.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('halloween 5 the revenge of michael myers', 2000, 'Halloween 5: The Revenge Of Michael Myers finds the series embracing crude slasher conventions with pedestrian scares, disposable characters, and aimless plotting.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('halloween h20', 1998, 'Halloween: H2O is the best of the many sequels, yet still pales in comparison to the original Halloween.', TO_DATE('1998-07-27', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('halloween ii', 2000, 'Halloween II picks up where its predecessor left off - and quickly wanders into a dead end that the franchise would spend decades struggling to find its way out of.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('halloween iii season of the witch', 2002, 'Its laudable deviation from series formula not withstanding, Halloween III: Season Of The Witch offers paltry thrills and dubious plotting.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('halloween resurrection', 2002, 'The only thing this tired slasher flick may resurrect is nostalgia for when the genre was still fresh and scary.', TO_DATE('2002-07-09', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('halloween the curse of michael myers halloween 6', 2000, 'Halloween: The Curse of Michael Myers trades the simple, brutal effectiveness of the original for convoluted mysticism, with disastrously dull results.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hamlet 2', 2008, 'The script''s biting premise and Steve Coogan''s endearing, off-the-handle performance make Hamlet 2 an hysterical -- if slightly painful -- ride.', TO_DATE('2008-01-23', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hammer', 2020, 'As impactful and simply constructed as the titular tool, Hammer adds a solid second entry to writer-director Christian Sparkes'' filmography.', TO_DATE('2020-05-28', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hampstead', 2017, 'Hampstead plays matchmaker with a pair of talented veterans, but the sum of their efforts isn''t enough to overcome a deeply mediocre story.', TO_DATE('2017-06-14', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hancock', 2007, 'Though it begins with promise, Hancock suffers from a flimsy narrative and poor execution.', TO_DATE('2007-12-28', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hands of stone', 2016, 'Hands of Stone''s strong cast and fascinating real-life story aren''t enough to compensate for a crowded narrative and formulaic script.', TO_DATE('2016-05-17', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('handsome harry', 2009, 'Handsome Harry offers more than enough of a satisfying actors'' showcase for its impressively stocked cast to overcome a handful of storytelling struggles.', TO_DATE('2009-06-22', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hanging up', 2000, 'Though the screenplay and the novel it''s based on were both written by the same person, critics say Hanging Up is an unsuccessful adaptation. The acting is praised as solid, but is ultimately unable to save the film.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hanna', 2011, 'Fantastic acting and crisply choreographed action sequences propel this unique, cool take on the revenge thriller.', TO_DATE('2011-03-30', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hannah montanamiley cyrus best of both worlds concert tour', 2008, 'This high-energy concert film should please Cyrus'' rabid pre-teen fan base -- and may come as a pleasant surprise for parents.', TO_DATE('2008-01-30', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hannah and her sisters', 2000, 'Smart, tender, and funny in equal measure, Hannah and Her Sisters is one of Woody Allen''s finest films.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hannah arendt', 2013, 'Led by a powerful performance from Barbara Sukowa, Hannah Arendt does a commendable job of dramatizing the life of a complex public figure.', TO_DATE('2013-02-14', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hannah gadsby nanette', 2018, 'Hannah Gadsby: Nanette brilliantly moves modern comedy into nakedly honest new territory, pivoting from dry humor to raw, powerful storytelling.', TO_DATE('2018-06-20', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hannah montana the movie', 2009, 'While youthful Miley fans won''t complain, Hannah Montana the Movie is little more than a formulaic Disney Channel episode stretched thin.', TO_DATE('2009-04-07', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hannah takes the stairs', 2007, 'Although not terribly focused, Hannah Takes the Stairs contains refreshing realism.', TO_DATE('2007-03-20', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hannibal rising', 2007, 'Hannibal Rising reduces the horror icon to a collection of dime-store psychological traits.', TO_DATE('2007-01-24', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hansel and gretel witch hunters', 2013, 'Alternately bloody and silly, Hansel and Gretel: Witch Hunters fails as both a fantasy adventure and as a parody of same.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happily never after', 2006, 'Happily N''Ever After has none of the moxy, edge, or postmodern wit of the other fairy-tales-gone-haywire CG movie it so blatantly rips off.', TO_DATE('2006-12-18', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the happiness of the katakuris', 2002, 'If nothing else, Happiness of the Katakuris scores points for its delirious, over-the-top originality.', TO_DATE('2002-06-24', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happy accidents', 2001, 'Happy Accidents has enough quirkiness and charm to rise above the more formulaic entries in the romantic comedy genre.', TO_DATE('2001-06-07', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happy as lazzaro lazzaro felice', 2018, 'Happy as Lazzaro uses a friendship''s ups and downs as a satisfyingly expansive canvas for a picture rich with thematic and cinematic depth.', TO_DATE('2018-05-14', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happy christmas', 2014, 'Intelligent, well-acted, and satisfyingly low-key, Happy Christmas marks another step in prolific filmmaker Joe Swanberg''s creative evolution.', TO_DATE('2014-01-21', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happy death day', 2017, 'Happy Death Day puts a darkly humorous sci-fi spin on slasher conventions, with added edge courtesy of a starmaking performance from Jessica Rothe.', TO_DATE('2017-10-10', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happy death day 2u', 2018, 'A funnier follow-up with a sci-fi bent, Happy Death Day 2U isn''t as fiendishly fresh as its predecessor, but fans of the original may still find this a sequel worth celebrating.', TO_DATE('2018-10-31', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happy endings', 2005, 'Despite strong individual performances, the overlong, disjointed plot of Happy Endings self-indulgently rambles.', TO_DATE('2005-03-07', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happy feet', 2006, 'Visually dazzling, with a thoughtful storyline and catchy musical numbers, Happy Feet marks a successful animated debut from the makers of Babe.', TO_DATE('2006-11-10', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happy feet two', 2011, 'The animation is as eye-popping as ever, but Happy Feet Two''s narrative is too noisily incoherent to recapture the Oscar-winning charm of its predecessor.', TO_DATE('2011-11-14', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happy gilmore', 2000, 'Those who enjoy Adam Sandler''s schtick will find plenty to love in this gleefully juvenile take on professional golf; those who don''t, however, will find it unfunny and forgettable.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happy happy joy joy the ren stimpy story', 2020, 'Despite glossing over some of the darker events in the subject''s life, Happy Happy Joy Joy: The Ren & Stimpy Story is an engaging look at a groundbreaking show.', TO_DATE('2020-01-24', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happy here and now', 2003, 'Happy Here and Now has a rich setting and some interesting ideas, but the story frustratingly refuses to spark to life.', TO_DATE('2003-01-02', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happy people a year in the taiga', 2011, 'Filled with breathtaking images of the foreboding Siberian countryside, Happy People: A Year in the Taiga is a fascinating look at an isolated society.', TO_DATE('2011-12-09', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happy texas', 1999, 'A smart, light-hearted romantic comedy, Happy, Texas uses its well-written script and exceptional cast to prove there''s still life left in the fish-out-of-water caper genre.', TO_DATE('1999-10-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happy valley', 2014, 'Sober, even-handed, and quietly devastating, Happy Valley illuminates the wreckage of a tragedy while leaving viewers room to draw their own conclusions.', TO_DATE('2014-01-20', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harakiri death of a samurai', 2011, 'Hara-Kiri: Death of a Samurai adds an atypically restrained entry to the Takashi Miike filmography that loses little impact in favoring human drama over action.', TO_DATE('2011-05-19', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hard candy', 2005, 'Disturbing, controversial, but entirely engrossing, Hard Candy is well written with strong lead performances, especially that of newcomer Ellen Page. A movie that stays with the viewer long after leaving the theater.', TO_DATE('2005-04-02', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hard eight', 2000, 'An absorbing showcase for Philip Baker Hall, Paul Thomason Anderson''s feature debut is a gamble that pays off handsomely.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hard rain', 2000, 'Hard Rain is an implausible heist movie soaked in disaster movie trappings.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hard target', 1800, 'Hard Target gets a boost from John Woo''s stylish direction, but at heart, it''s still another silly, explosion-dependent action thriller in the Jean-Claude Van Damme oeuvre.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hard to be a god', 2014, 'A sci-fi epic with palpable connections to the present, Hard to Be a God caps director Aleksei German''s brilliant filmography with a final masterpiece.', TO_DATE('2014-10-08', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hard way', 1991, 'The Hard Way''s overly familiar formula is enlivened by a witty script and the excellent comedic chemistry between Michael J. Fox and James Woods.', TO_DATE('1991-06-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hard word', 2002, 'This caper flick lacks the originality necessary to elevate it above other films of its genre.', TO_DATE('2002-05-30', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hardball', 2001, 'Although Hardball contains some touching moments, they are not enough to transcend the sports formula.', TO_DATE('2001-07-31', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hardcore henry', 2015, 'Hardcore Henry seems poised to reinvent the action flick, but without a story or characters worth caring about, its first-person gimmick quickly loses its thrill.', TO_DATE('2015-09-13', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harlem nights', 2000, 'An all-star comedy lineup is wasted on a paper-thin plot and painfully clunky dialogue.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harmonium fuchi ni tatsu', 2016, 'Harmonium''s simple setup lays brilliantly effective groundwork for a well-constructed, powerfully acted look at truth and consequences.', TO_DATE('2016-05-15', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harmontown', 2014, 'Harmontown offers a look at an artist grappling with his own flaws -- as well as some interesting insights about the nature of hardcore fandom in the internet age.', TO_DATE('2014-03-21', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harold kumar escape from guantanamo bay', 2008, 'It may not equal its predecessor, but Harold and Kumar Escape from Guantanamo Bay is still good for some laughs -- and food for thought.', TO_DATE('2008-03-08', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harold kumar go to white castle', 2004, 'The likable leads and subversion of racial stereotypes elevate Harold and Kumar above the typical stoner comedy.', TO_DATE('2004-05-25', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harold and maude', 2000, 'Hal Ashby''s comedy is too dark and twisted for some, and occasionally oversteps its bounds, but there''s no denying the film''s warm humor and big heart.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harpoon', 2019, 'A B-movie with an A-level commitment to entertain, Harpoon should hit the target with horror fans in the mood for gory, darkly humorous antics on the open water.', TO_DATE('2019-01-31', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harrisons flowers', 2002, 'Though it presents the war in shockingly gritty, realistic terms, Harrison''s Flowers uses such scenes as background for a trite love story.', TO_DATE('2002-01-26', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harry brown', 2009, 'Its lurid violence may put off some viewers, but Harry Brown is a vigilante thriller that carries an emotional as well as a physical punch, thanks to a gripping performance from Michael Caine in the title role.', TO_DATE('2009-11-13', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harry potter and the chamber of secrets', 2002, 'Though perhaps more enchanting for younger audiences, Chamber of Secrets is nevertheless both darker and livelier than its predecessor, expanding and improving upon the first film''s universe.', TO_DATE('2002-07-24', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harry potter and the deathly hallows part 1', 2010, 'It can''t help but feel like the prelude it is, but Deathly Hallows: Part I is a beautifully filmed, emotionally satisfying penultimate installment for the Harry Potter series.', TO_DATE('2010-11-11', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harry potter and the deathly hallows part 2', 2011, 'Thrilling, powerfully acted, and visually dazzling, Deathly Hallows Part II brings the Harry Potter franchise to a satisfying -- and suitably magical -- conclusion.', TO_DATE('2011-06-23', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harry potter and the goblet of fire', 2005, 'The main characters are maturing, and the filmmakers are likewise improving on their craft; vibrant special effects and assured performances add up to what is the most complex yet of the Harry Potter films.', TO_DATE('2005-05-11', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harry potter and the halfblood prince', 2009, 'Dark, thrilling, and occasionally quite funny, Harry Potter and the Half-Blood Prince is also visually stunning and emotionally satisfying.', TO_DATE('2009-07-06', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harry potter and the order of the phoenix', 2007, 'It''s not easy to take the longest Harry Potter book and streamline it into the shortest HP movie, but director David Yates does a bang up job of it, creating an Order of the Phoenix that''s entertaining and action-packed.', TO_DATE('2007-06-28', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harry potter and the prisoner of azkaban', 2003, 'Under the assured direction of Alfonso Cuaron, Harry Potter and the Prisoner of Azkaban triumphantly strikes a delicate balance between technical wizardry and complex storytelling.', TO_DATE('2003-12-15', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harry potter and the sorcerers stone', 2001, 'Harry Potter and the Sorcerer''s Stone adapts its source material faithfully while condensing the novel''s overstuffed narrative into an involving -- and often downright exciting -- big-screen magical caper.', TO_DATE('2001-10-29', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harsh times', 2005, 'Despite a dedicated performance by Christian Bale, Harsh Times suffers from a heavy-handed and overly bleak plot.', TO_DATE('2005-09-15', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harts war', 2002, 'Well-made and solidly acted, Hart''s War is modestly compelling. However, the movie suffers from having too many subplots.', TO_DATE('2002-02-06', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harvard beats yale 2929', 2008, 'Harvard Beats Yale 29-29 is compelling viewing even though it spoils the score of the titular college football matchup - and even if you aren''t a fan of the sport.', TO_DATE('2008-09-15', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('harvard man', 2002, 'Harvard Man is a pretentious, incoherent mess.', TO_DATE('2002-04-12', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hatchet', 2006, 'The over-the-top gore, campy acting, and dim cinematography may be part of Hatchet''s self-described old-school ethos, but irony alone can''t sustain a horror film.', TO_DATE('2006-04-27', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hatchet ii', 2010, 'Funnier and more gleefully gory than most slasher sequels, Hatchet II aims for so-bad-it''s-good territory, but can''t quite hack it.', TO_DATE('2010-09-05', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hateship loveship', 2013, 'Kristen Wiig''s vibrant performance is almost worth the price of admission -- and it has to be, because Hateship Loveship doesn''t have much else going for it.', TO_DATE('2013-09-09', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('haunt', 2019, 'Haunt is spooked by the spirits of its obvious influences, but still packs enough thrills and chills to satisfy horror fans up for a haunted house excursion.', TO_DATE('2019-08-24', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the haunted mansion', 2003, 'Neither scary nor funny, The Haunted Mansion is as lifeless as the ghosts in the movie.', TO_DATE('2003-11-22', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('haunter', 2013, 'Haunter''s premise is intriguing enough, though the film''s too low budget to truly pull it off.', TO_DATE('2013-03-10', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the haunting of molly hartley', 2008, 'The Haunting of Molly Hartley is a rather lifeless horror endeavor, with a pedestrian plot and few scares.', TO_DATE('2008-10-31', 'YYYY-MM-DD'), 2.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('house hausu', 2009, 'House is a gleefully demented collage of grand guginol guffaws and bizarre sequences.', TO_DATE('2009-08-28', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('have a good trip adventures in psychedelics', 2020, 'Have a Good Trip: Adventures in Psychedelics is an entertaining enough look at hallucinogenics'' effects, but its shallow treatment can''t help but disappoint.', TO_DATE('2020-05-05', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('haywire', 2011, 'MMA star and first-time actress Gina Carano displays ample action-movie chops in Haywire, a fast-paced thriller with a top-notch cast and outstanding direction from Steven Soderbergh.', TO_DATE('2011-11-07', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('he got game', 1998, 'Though not without its flaws, He Got Game finds Spike Lee near the top of his game, combining trenchant commentary with his signature visuals and a strong performance from Denzel Washington.', TO_DATE('1998-05-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('he loves me he loves me not', 2002, 'This romantic thriller puts Tautou''s sweetheart Amelie image to good use.', TO_DATE('2002-10-15', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('he named me malala', 2015, 'He Named Me Malala spotlights a worthy subject, but without the focus her story deserves.', TO_DATE('2015-09-04', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('head count', 2018, 'Head Count doesn''t wrack up enough punchy scares to be an unqualified success as a horror outing, but an engaging cast and textured characters make it a refreshing genre exercise with something on its mind.', TO_DATE('2018-10-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('head of state', 2003, 'Head of State squanders its potentially ripe premise with watered-down satire and formulaic gags.', TO_DATE('2003-03-19', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('head on', 1999, 'Head On''s narrative rambles at times, but its raw, sensual approach creates a powerful, resonant rumination on identity.', TO_DATE('1999-08-13', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('headhunters', 2011, 'Grisly, twisty, and darkly comic, Headhunters is an exhilaratingly oddball take on familiar thriller elements.', TO_DATE('2011-09-20', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heal the living réparer les vivants', 2016, 'Beautifully filmed and powerfully written, Heal the Living interweaves seemingly disparate narrative threads to present a vibrant portrait of human connection.', TO_DATE('2016-09-04', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heart of a dog', 2015, 'Of a piece with much of director Laurie Anderson''s idiosyncratic output, Heart of a Dog delves into weighty themes with lyrical, haunting grace.', TO_DATE('2015-09-05', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('neil young heart of gold', 2006, 'Proving that it''s neither better to burn out nor fade away, Neil Young: Heart of Gold works both as a concert film and a meditation on mortality.', TO_DATE('2006-01-26', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('question humaine la heartbeat detector', 2007, 'Gripping and provocative psychological thriller about corporate responsibility remains tense throughout and despite its long running time.', TO_DATE('2007-05-19', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heartbreak ridge', 2000, 'With Heartbreak Ridge, director Clint Eastwood gets one of his best performances out of himself, even if the story struggles to engage.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heartburn', 2000, 'Despite an astonishing collection of talent across the board, Heartburn''s aimless plot inspires mild indigestion instead of romantic ardor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heartless', 1800, 'Smart, well-acted, and unsettling, Heartless marks a mostly satisfying return to genre thrills for writer-director Philip Ridley.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hearts and minds', 2000, 'A powerful, unflinching exploration of the Vietnam War, with first-person stories from both sides of the conflict, Hearts and Minds still hits the mark decades after its release.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hearts beat loud', 2018, 'Thoroughly sweet, comfortably familiar, and elevated by the chemistry between Nick Offerman and Kiersey Clemons, Hearts Beat Loud offers feel-good father-daughter drama.', TO_DATE('2018-01-24', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hearts in atlantis', 2001, 'Hearts in Atlantis is well-acted and beautiful to look at, but the movie is nothing more than a mood piece.', TO_DATE('2001-09-10', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hearts of darkness a filmmakers apocalypse', 1991, 'Chronicling the filming of Apocalypse Now through Eleanor Coppola''s empathetic and frank point of view, Hearts of Darkness is a revelatory investigation of moviemaking and how creative obsession can impact an artist''s family.', TO_DATE('1991-05-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wild card', 2015, 'Hardcore Jason Statham fans may enjoy parts of Wild Card, but all other action aficionados need not apply.', TO_DATE('2015-01-14', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heathers', 2000, 'Dark, cynical, and subversive, Heathers gently applies a chainsaw to the conventions of the high school movie -- changing the game for teen comedies to follow.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heaven', 2002, 'The story is the weakest link in this gorgeous and well-acted film.', TO_DATE('2002-04-09', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heaven is for real', 2014, 'Heaven Is for Real boasts a well-written screenplay and a talented cast, but overextends itself with heavy-handed sequences depicting concepts it could have trusted the audience to take on faith.', TO_DATE('2014-04-14', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heaven knows what', 2014, 'Grueling and rewarding in equal measure, Heaven Knows What hits hard -- and serves as a powerful calling card for its captivating star, Arielle Holmes.', TO_DATE('2014-09-11', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heavenly creatures', 2000, 'Dark, stylish, and captivating, Heavenly Creatures signals both the auspicious debut of Kate Winslet and the arrival of Peter Jackson as more than just a cult director.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heavens gate', 2000, 'Heaven''s Gate contains too many ideas and striking spectacle to be a disaster, but this western buckles under the weight of its own sprawl.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heavy', 2000, 'With Pruitt Taylor Vince''s naturalistic performance and sympathetic direction from James Mangold, Heavy soars as an affecting exploration of loneliness.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heavy metal in baghdad', 2008, 'Despite being a Gonzo-esque rockumentary following the fortunes of Iraq''s one and only heavy metal band, Acrassicauda, Heavy Metal is actually a moving and impassioned account of the middle-east crisis.', TO_DATE('2008-04-15', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heavy trip hevi reissu', 2018, 'Heavy Trip''s heartfelt humor and fully realized characters make this a journey well worth taking - and one of the best rock comedies in recent memory.', TO_DATE('2018-03-12', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hector and the search for happiness', 2014, 'Simon Pegg remains as charming as ever, but Hector and the Search for Happiness drowns his appeal in schmaltz.', TO_DATE('2014-08-11', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hedwig and the angry inch', 2001, 'Hedwig and the Angry Inch may very well be the next Rocky Horror midnight movie. It not only knows how to rock, but Hedwig''s story has an emotional poignancy.', TO_DATE('2001-03-15', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heights', 2005, 'Yet another movie about relationships in the Big Apple, Heights is never dull thanks to a competent cast.', TO_DATE('2005-02-10', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('held up', 2000, 'Lackluster performances and fluff humor can''t keep this wreck from sinking.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heli', 2013, 'There''s no denying the seriousness of Heli''s story or the raw power of its more uncomfortable moments, but they''re used in service of a grimly alienating film that many viewers may ultimately find unrewarding.', TO_DATE('2013-05-16', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hell baby', 2013, 'Though its brand of immature comedy may appeal to some, Hell Baby misses the mark with much of its humor, rendering it a largely ineffective -- and often crass -- genre sendup.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hell fest', 2018, 'Hell Fest might give less demanding horror fans a few decent reasons to scream, but it''s neither clever nor frightening enough to leave much of an impression.', TO_DATE('2018-09-28', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hell house', 2002, 'A fascinating, even-handed account of Hell Houses.', TO_DATE('2002-05-13', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hell or high water', 2016, 'Hell or High Water offers a solidly crafted, well-acted Western heist thriller that eschews mindless gunplay in favor of confident pacing and full-bodied characters.', TO_DATE('2016-05-16', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hellbound hellraiser ii', 2000, 'Hellbound: Hellraiser II retains the twisted visual thrill of its predecessor, although seams in the plot are already starting to show.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hellboy', 2003, 'With wit, humor and Guillermo del Toro''s fantastic visuals, the entertaining Hellboy transcends the derivative nature of the genre.', TO_DATE('2003-09-30', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hellboy', 2019, 'Bereft of the imaginative flair that made earlier Hellboys so enjoyable, this soulless reboot suggests Dante may have left a tenth circle out of his Inferno.', TO_DATE('2019-04-10', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hellboy ii the golden army hellboy 2', 2007, 'Guillermo del Toro crafts a stellar comic book sequel, boasting visuals that are as imaginative as the characters are endearing.', TO_DATE('2007-05-24', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hello dolly', 2002, 'Though Streisand charms, she''s miscast as the titular middle-aged widow in Gene Kelly''s sluggish and over-produced final directorial effort.', TO_DATE('2002-12-20', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hello i must be going', 2012, 'Hello I Must Be Going offers an offbeat twist to the romance genre, a solid character study for fans of grown-up drama, and a career-making breakout vehicle for Melanie Lynskey.', TO_DATE('2012-01-20', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hello my name is doris', 2015, 'Hello, My Name Is Doris is immeasurably elevated by Sally Field''s remarkable performance in the title role, which overpowers a surfeit of stereotypical indie quirk.', TO_DATE('2015-04-25', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hellraiser', 2000, 'Elevated by writer-director Clive Barker''s fiendishly unique vision, Hellraiser offers a disquieting - and sadistically smart - alternative to mindless gore.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hemingway gellhorn', 2012, 'Nicole Kidman''s poised performance provides some measure of reclamation for Martha Gellhorn, but this trite historical melodrama reduces Ernest Hemingway and the era that the two war correspondents lived through into a broad caricature.', TO_DATE('2012-05-25', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('henry portrait of a serial killer', 1986, 'Henry: Portrait of a Serial Killer is an effective, chilling profile of a killer that is sure to shock and disturb.', TO_DATE('1986-09-24', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('henry poole is here', 2008, 'Full of Hallmark-truisms and pop songs presented with strained significance, this comic foible intends less to convert than to preach to the choir.', TO_DATE('2008-01-23', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('henry v the chronicle history of king henry the fift with his battell fought at agincourt in france', 2000, 'A patriotic booster, Laurence Olivier''s directorial debut and star turn as Henry V result in a sharply realized and resonant take on Shakespeare''s deeply British warrior king.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('henrys crime', 2010, 'Supporting actors Vera Farmiga and James Caan give the movie a little heft, but Henry''s Crime is an otherwise predictable heist/comedy with slow pacing.', TO_DATE('2010-09-22', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('her', 2013, 'Sweet, soulful, and smart, Spike Jonze''s Her uses its just-barely-sci-fi scenario to impart wryly funny wisdom about the state of modern human relationships.', TO_DATE('2013-10-12', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('herb dorothy', 2008, 'While perhaps not as probing as it could have been, Megumi Sasaki''s languidly paced documentary is as entertaining as it is inspiring.', TO_DATE('2008-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wild grass les herbes folles', 2009, 'Precious to a fault, Wild Grass finds 88-year-old director Alain Resnais as joyously unconstrained as ever.', TO_DATE('2009-05-21', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('herbie fully loaded', 2005, 'Herbie: Fully Loaded is a decent kids movie that is pretty undemanding for adult viewers.', TO_DATE('2005-06-20', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hercules', 1997, 'Fast-paced and packed with dozens of pop culture references, Hercules might not measure up with the true classics of the Disney pantheon, but it''s still plenty of fun.', TO_DATE('1997-06-15', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hercules', 2014, 'Hercules has Brett Ratner behind the cameras and Dwayne Johnson rocking the loincloth -- and delivers exactly what any reasonable person reading that description might expect.', TO_DATE('2014-07-23', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('here comes the boom', 2012, 'Here Comes the Boom benefits from Kevin James''s genial presence but the film doesn''t deliver enough laughs to live up to its title -- or enough satisfying plot to make up the difference.', TO_DATE('2012-10-07', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('here comes the devil', 2012, 'The power of Here Comes the Devil''s atmospheric dread compels, but the plot and mystery are too muddled to leave a lasting impression.', TO_DATE('2012-09-11', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('here on earth', 2000, 'Critics say Here on Earth''s weakness comes from its script. The story may appeal to young teenage girls, but it suffers from being overly sentimental and formulaic. The cinematography, however, is lovely in how it captures its Minnesota setting.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hereafter', 2010, 'Despite a thought-provoking premise and Clint Eastwood''s typical flair as director, Hereafter fails to generate much compelling drama, straddling the line between poignant sentimentality and hokey tedium.', TO_DATE('2010-09-13', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hereditary', 2018, 'Hereditary uses its classic setup as the framework for a harrowing, uncommonly unsettling horror film whose cold touch lingers long beyond the closing credits.', TO_DATE('2018-01-23', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hero', 2002, 'With death-defying action sequences and epic historic sweep, Hero offers everything a martial arts fan could ask for.', TO_DATE('2002-12-20', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hes just not that into you', 2009, 'Despite the best efforts of a talented cast, He''s Just Not That Into You devotes too little time to each of its protagonists, thus reducing them to stereotypes.', TO_DATE('2009-02-02', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hesher', 2010, 'It has a dark sense of humor and a refreshing lack of sentimentality, but like its title character, Hesher isn''t really interested in going anywhere.', TO_DATE('2010-01-25', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hey arnold the movie', 2002, 'Bland, unoriginal, and lacking the wit of the TV series, Hey Arnold is a 30 min cartoon stretched beyond its running time.', TO_DATE('2002-05-13', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hick', 2011, 'Hick''s talented young star is ill served by a film whose story wavers between discomfitingly inappropriate and simply muddled.', TO_DATE('2011-09-20', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hidalgo', 2004, 'The scenery looks great, but this overstuffed horse story contains too much cheese.', TO_DATE('2004-02-01', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hidden blade', 2005, 'A slow and steady samurai flick a la John Ford that brings emotions and psychology to an epic-scale adventure.', TO_DATE('2005-09-15', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hidden figures', 2016, 'In heartwarming, crowd-pleasing fashion, Hidden Figures celebrates overlooked -- and crucial -- contributions from a pivotal moment in American history.', TO_DATE('2016-12-10', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hide', 2009, 'Cleverly written and directed, this is a tight, atmospheric and claustrophobic low budget British thriller.', TO_DATE('2009-05-28', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('high tension switchblade romance', 2003, 'There is indeed a good amount of tension in this French slasher, but the dubbing is bad and the end twist unbelievable.', TO_DATE('2003-10-01', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('high anxiety', 2002, 'Uneven but hilarious when it hits, this spoof of Hitchcock movies is a minor classic in the Mel Brooks canon.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('high art', 2000, 'A surprisingly sultry performance from Ally Sheedy elevates High Art from pretentious melodrama to compelling -- if still a little pretentious -- romance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('high crimes', 2002, 'Ashley Judd and Morgan Freeman make this predictable affair watchable.', TO_DATE('2002-04-02', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('high flying bird', 2019, 'High Flying Bird takes a thoughtful and engrossing look at professional sports that sees Steven Soderbergh continuing to test the limits of new filmmaking technology.', TO_DATE('2019-01-28', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('high life', 2018, 'High Life is as visually arresting as it is challenging, confounding, and ultimately rewarding - which is to say it''s everything film fans expect from director Claire Denis.', TO_DATE('2018-09-10', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('high plains drifter', 2000, 'Clint Eastwood''s sophomore outing as director sees him back in the saddle as a mysterious stranger, as the result is one of his most memorable Westerns.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('highrise', 2015, 'High-Rise may not quite live up to its classic source material, but it still offers an energetic, well-acted, and thought-provoking take on its timely socioeconomic themes.', TO_DATE('2015-09-14', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('high school musical', 2006, 'High School Musical is brazenly saccharine, but it makes up for it with its memorable show tunes, eye-popping choreography, and appealing cast.', TO_DATE('2006-05-27', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('high school musical 2', 2007, 'Surprisingly better than its predecessor, High School Musical 2 returns to enchant tweens with its snappy songs, wicked dance moves, and peppy spirit.', TO_DATE('2007-12-12', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('higher ground', 2011, 'With Higher Ground, star and debuting director Vera Farmiga takes viewers on a challenging spiritual journey whose missteps are easily overcome by its many rich rewards.', TO_DATE('2011-01-25', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('higher learning', 2000, 'It''s hard to fault Higher Learning''s goals; unfortunately, writer-director John Singleton too often struggles to fit his themes within a consistently engaging story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('highlander', 2000, 'People hate Highlander because it''s cheesy, bombastic, and absurd. And people love it for the same reasons.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('highlander 2 the quickening', 2000, 'There should have been only one.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('highlander iii the sorcerer highlander the final dimension', 2000, 'Borderline unwatchable and unspeakably dull, Highlander III is a sloppy third installment that still somehow manages to mark a slight improvement over its predecessor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('highlander endgame', 2000, 'The fourth and supposedly last Highlander movie is a confusing mess, complete with bad acting and dialogue.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hilary and jackie', 1998, 'Brilliant performances, lush cinematography, and complex storytelling deserve audience''s attention.', TO_DATE('1998-12-30', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hillarys america the secret history of the democratic party', 2016, 'Hillary''s America: The Secret History of the Democratic Party finds Dinesh D''Souza once again preaching to the right-wing choir -- albeit less effectively than ever.', TO_DATE('2016-07-15', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hills have eyes', 2006, 'Faster paced for today''s audiences, this Hills remake ratchets up the gore for the hardcore horror fans, but will turn away casual audiences.', TO_DATE('2006-01-30', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hills have eyes 2', 2007, 'The Hills Have Eyes 2 is a completely unoriginal sequel offers plenty of gore and clichés, but few scares.', TO_DATE('2007-03-17', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('himalaya lenfance dun chef caravan', 2001, 'Unlike the overproduced and overbudgeted Hollywood blockbusters, Himalaya is a stunningly photographed movie that offers an intimate look into the lives of a Dolpo tribe.', TO_DATE('2001-03-20', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('himizu', 2012, 'Himizu tells a coming-of-age story writ large, with powerfully realized characters used to explore impactful -- albeit uncomfortable -- ideas on a national scale.', TO_DATE('2012-04-12', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hip hop project', 2006, 'Director Matt Ruskin''s enthusiasm for the project is readily apparent, but his film is unfocused, meandering, and frustrating to watch.', TO_DATE('2006-04-27', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hipsters', 2010, 'Breezy, colorful, and suffused with joy, Hipsters offers audiences an engaging Cold War musical told from the other side of the Iron Curtain.', TO_DATE('2010-09-02', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hiroshima mon amour', 2000, 'Distinguished by innovative technique and Emmanuelle Riva''s arresting performance, Hiroshima Mon Amour is a poignant love story as well as a thoughtful meditation on international trauma.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the golden compass', 2007, 'Without the bite or the controversy of the source material, The Golden Compass is reduced to impressive visuals overcompensating for lax storytelling.', TO_DATE('2007-11-28', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('his girl friday', 2000, 'Anchored by stellar performances from Cary Grant and Rosalind Russell, His Girl Friday is possibly the definitive screwball romantic comedy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the history boys', 2006, 'While not quite having the impact of its original stage version, The History Boys nevertheless is a witty and involving school drama.', TO_DATE('2006-10-05', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('history of the worldpart i', 2002, 'History of the World: Part I may not have enough comedic inspiration to merit a Part II, but the sporadic cleverness of these anachronistic skits are still a testament to Mel Brooks'' gift for farce.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a history of violence', 2005, 'A History of Violence raises compelling and thoughtful questions about the nature of violence, while representing a return to form for director David Cronenberg in one of his more uncharacteristic pieces.', TO_DATE('2005-05-16', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hit run', 2012, 'Though Hit & Run has some surprisingly oft-kilter filmmaking, the action doesn''t add to much and the writing''s a bit smug.', TO_DATE('2012-08-17', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hit and runway', 2001, 'This Odd Couple comedy misses more than hits in terms of laughs, and the plot twists make little sense.', TO_DATE('2001-02-21', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hitch', 2005, 'Despite Hitch''s predictability, Will Smith and Kevin James win praise for their solid, warmhearted performances.', TO_DATE('2005-02-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hitchcock', 2012, 'Though it suffers from tonal inconsistency and a lack of truly insightful retrospection, Hitchcock is elevated by inspired performances from its two distinguished leads.', TO_DATE('2012-11-03', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hitchcocktruffaut', 2015, 'Essential viewing for cineastes while still offering rich rewards for neophytes, Hitchcock/Truffaut offers an affectionate -- and well-crafted -- tribute to a legend.', TO_DATE('2015-09-10', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hitcher', 2007, 'Sean Bean tries giving motive and emotion to The Hitcher, but director Dave Meyers is more interested in cheap shocks, and gratuitous gore and torture.', TO_DATE('2007-01-18', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hitchhikers guide to the galaxy', 2004, 'A frantic and occasional funny adaptation of Douglas Adams'' novel. However, it may have those unfamiliar with the source material scratching their heads.', TO_DATE('2004-01-14', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hitman', 2007, 'Hitman features the unfortunate combination of excessive violence, incoherent plot, and inane dialogue.', TO_DATE('2007-11-20', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hitman agent 47', 2015, 'Hitman: Agent 47 fails to clear the low bar set by its predecessor, forsaking thrilling action in favor of a sleekly hollow mélange of dull violence and product placement.', TO_DATE('2015-08-19', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hobo with a shotgun', 2011, 'It certainly isn''t subtle -- or even terribly smart -- but as a gleefully gory homage to low-budget exploitation thrillers, Hobo with a Shotgun packs plenty of firepower.', TO_DATE('2011-01-22', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hockney', 2014, 'Hockney offers few revelations for viewers familiar with its subject, but it remains an affectionate and thoroughly entertaining look at a British national treasure.', TO_DATE('2014-11-24', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hocus pocus', 1993, 'Harmlessly hokey yet never much more than mediocre, Hocus Pocus is a muddled family-friendly effort that fails to live up to the talents of its impressive cast.', TO_DATE('1993-07-16', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hoffa', 1992, 'Jack Nicholson embodies Hoffa with malevolent relish, but a dearth of meaningful insight knocks this crime epic off the mark by a nose.', TO_DATE('1992-12-25', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hold the dark', 2018, 'Hold the Dark''s unsettling aesthetic offers more of what filmgoers expect from director Jeremy Saulnier - and is often enough to prop up shaky narrative underpinnings.', TO_DATE('2018-09-13', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('holding the man', 2015, 'Heart-wrenching performances center Holding the Man, an achingly beautiful portrayal of love and death that may be too real for some.', TO_DATE('2015-07-20', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('holes', 2003, 'Faithful to its literary source, this is imaginative, intelligent family entertainment.', TO_DATE('2003-04-13', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('holiday inn', 2000, 'With the combined might of Bing Crosby, Fred Astaire, and Irving Berlin working in its favor, Holiday Inn is a seasonal classic -- not least because it introduced "White Christmas" to the world.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hollow man', 2000, 'Despite awesome special effects, Hollow Man falls short of other films directed by Paul Verhoeven. This flick over time degenerates into a typical horror film.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('holly', 2007, 'Despite some execution problems, Holly remains a realistic and gritty look at child sex slavery.', TO_DATE('2007-08-04', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hollywood ending', 2002, 'Although Hollywood Ending contains some zany one-liners, its promising premise is far from developed.', TO_DATE('2002-04-24', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hollywood homicide', 2003, 'Hollywood Homicide suffers from too many subplots and not enough laughs.', TO_DATE('2003-06-06', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hollywood shuffle', 2000, 'Hollywood Shuffle overcomes budgetary constraints with sharp humor and infectious energy, heralding the arrival of an exciting new filmmaking talent in the bargain.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hollywoodland', 2006, 'More than a movie star murder mystery, Hollywoodland takes it slow in order to reveal the intriguing details of the rise and fall of superstar fame.', TO_DATE('2006-08-04', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('holmes and watson', 2018, 'The lowest and vilest alleys in London do not present a more dreadful record of the adventures of Sherlock Holmes and Dr. Watson than does Holmes and Watson.', TO_DATE('2018-12-20', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('holy man', 1998, 'Cloying and unfunny, Holy Man wastes the repartee between Eddie Murphy and Jeff Goldblum on the gospel of toothless satire and unearned sentimentality.', TO_DATE('1998-10-09', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('holy motors', 2012, 'Mesmerizingly strange and willfully perverse, Holy Motors offers an unforgettable visual feast alongside a spellbinding -- albeit unapologetically challenging -- narrative.', TO_DATE('2012-05-23', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the holy mountain', 2002, 'A visual treat rich in symbolism, The Holy Mountain adds another defiantly idiosyncratic chapter to Jodorowsky''s thoroughly unique filmography.', TO_DATE('2002-11-13', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('holy rollers', 2010, 'Despite a promising premise and a solid central performance from Jesse Eisenberg, Holy Rollers lacks the depth necessary to overcome its cliched script.', TO_DATE('2010-01-26', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('holy smoke', 2000, 'Superb performances hindered by weak script and incoherent story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('home', 2015, 'Colorful, silly, and utterly benign, Home is a passable diversion, but there''s no shortage of superior animated alternatives.', TO_DATE('2015-03-08', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('home again', 2017, 'Home Again gathers a talented crowd of rom-com veterans on both sides of the camera -- all of whom have unfortunately done far better work.', TO_DATE('2017-09-05', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('home alone', 1990, 'Home Alone uneven but frequently funny premise stretched unreasonably thin is buoyed by Macaulay Culkin''s cute performance and strong supporting stars.', TO_DATE('1990-11-16', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('home alone 2 lost in new york', 1992, 'A change of venue -- and more sentimentality and violence -- can''t obscure the fact that Home Alone 2: Lost in New York is a less inspired facsimile of its predecessor.', TO_DATE('1992-11-15', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('home alone 3', 2000, 'Macaulay Culkin''s precocious charisma is sorely missed in this hollow sequel, which doubles down on the broad comedy while lacking all the hallmarks that made the original a classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a home at the end of the world', 2004, 'A Home at the End of the World aims for profundity, but settles for stale melodrama, yielding a slew of sensitive performances that are nevertheless in service of characters who prove to be ciphers.', TO_DATE('2004-06-30', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('home fries', 1998, 'Screenwriter Vince Gilligan''s mordant sense of humor strikes a discordant note in Home Fries, a romantic caper full of empty calories.', TO_DATE('1998-11-25', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('home of the brave', 2006, 'The ensemble cast works hard, but hammy direction and a script lacking in nuance ruins this movie''s noble intentions.', TO_DATE('2006-12-06', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('home on the range', 2004, 'Though Home on the Range is likeable and may keep young children diverted, it''s one of Disney''s more middling titles, with garish visuals and a dull plot.', TO_DATE('2004-03-30', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('home room', 2003, 'Honorable intentions and some strong performances aren''t enough to keep Home Room from occasionally slipping into distractingly didactic messaging.', TO_DATE('2003-07-16', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('home sweet hell', 2015, 'Home Sweet Hell mistakes misogyny for subversive wit, aiming for black comedy but ending up with a grueling test of viewer endurance that wastes game efforts from its likable leads.', TO_DATE('2015-02-12', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('homecoming a film by beyoncé', 2019, 'Beychella forever.', TO_DATE('2019-04-17', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('homefront', 2013, 'While it boasts a capable cast, the disappointingly dull Homefront hearkens back to classic action thrillers without adding anything to the genre.', TO_DATE('2013-11-21', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('homeward bound the incredible journey', 1993, 'Disney''s remake of The Incredible Journey successfully replicates, and in some ways improves upon, the simple charms of the original, with its cross-country animal odyssey sure to delight kids.', TO_DATE('1993-02-03', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('honey', 2003, 'An attractive Jessica Alba and energetic dance numbers provide some lift to this corny and formulaic movie.', TO_DATE('2003-11-30', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('honey i shrunk the kids', 2000, 'Even as its special effects take center stage, Honey, I Shrunk the Kids still offers a charming, high-spirited sense of adventure for the whole family.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('honeydripper', 2007, 'Honeydripper''s electric musical numbers and sharp performances make for an exciting film, despite its slow pace.', TO_DATE('2007-09-11', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('honeymoon', 2014, 'Smart, stylish, and nail-bitingly tense, Honeymoon packs more slow-building horror than many bigger-budget productions.', TO_DATE('2014-05-02', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('honeymoon in vegas', 1992, 'Honeymoon in Vegas is a light screwball comedy that has just about what you expect (and nothing you don''t).', TO_DATE('1992-08-28', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('honkytonk man', 2003, 'Clint Eastwood succeeds in revealing his softer side in Honkytonk Man, a surprisingly sweet and heartwarming road movie that hums along at a pleasant pace.', TO_DATE('2003-05-24', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hoodwinked too hood vs evil', 2011, 'It may add 3D to the original, but Hoodwinked Too! is missing the first installment''s wit and refreshingly low-budget charm.', TO_DATE('2011-04-24', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hook', 1991, 'The look of Hook is lively indeed but Steven Spielberg directs on autopilot here, giving in too quickly to his sentimental, syrupy qualities.', TO_DATE('1991-12-11', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hooking up', 2020, 'Hooking Up highlights Sam Richardson and Brittany Snow''s strengths as leads -- and their limitations when saddled with a deeply subpar script.', TO_DATE('2020-03-16', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hoop dreams', 1994, 'One of the most critically acclaimed documentaries of all time, Hoop Dreams is a rich, complex, heartbreaking, and ultimately deeply rewarding film that uses high school hoops as a jumping-off point to explore issues of race, class, and education in modern America.', TO_DATE('1994-10-14', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hoosiers', 2000, 'It may adhere to the sports underdog formula, but Hoosiers has been made with such loving craft, and features such excellent performances, that it''s hard to resist.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hoot', 2006, 'Lacking energy and humor, Hoot is a ho-hum story of eco-awareness that falls flat as a pancake.', TO_DATE('2006-04-26', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hop', 2011, 'It''s impressively animated, but Hop''s script is so uninspired that not even James Marsden''s frantic mugging can give it any bounce.', TO_DATE('2011-03-27', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hope floats', 1998, 'Hope Floats sinks under a deluge of melodramatic turns and syrupy sentimentality, although Sandra Bullock remains a winning star.', TO_DATE('1998-05-29', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hope springs', 2012, 'Led by a pair of mesmerizing performances from Meryl Streep and Tommy Lee Jones, Hope Springs offers filmgoers some grown-up laughs -- and a thoughtful look at mature relationships.', TO_DATE('2012-08-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('horns', 2013, 'Horns is a bit of a tonal jumble, but it offers enough thoughtful horror-comedy -- and strong work from Daniel Radcliffe -- to hook genre enthusiasts.', TO_DATE('2013-09-07', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('horrible bosses', 2011, 'It''s nasty, uneven, and far from original, but thanks to a smartly assembled cast that makes the most of a solid premise, Horrible Bosses works.', TO_DATE('2011-07-05', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('horrible bosses 2', 2014, 'Horrible Bosses 2 may trigger a few belly laughs among big fans of the original, but all in all, it''s a waste of a strong cast that fails to justify its own existence.', TO_DATE('2014-11-12', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('horror of dracula', 2002, 'Trading gore for grandeur, Horror of Dracula marks an impressive turn for inveterate Christopher Lee as the titular vampire, and a typical Hammer mood that makes aristocracy quite sexy.', TO_DATE('2002-10-27', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('horse girl', 2020, 'Horse Girl proves unwilling or unable to explore the deeper themes it addresses, but this unusual drama is anchored by Alison Brie''s committed performance.', TO_DATE('2020-01-28', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the horse whisperer', 1998, 'It might be a bit too eager to tug the heartstrings, but The Horse Whisperer is typically graceful, well-crafted Redford -- on both sides of the camera.', TO_DATE('1998-05-15', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dr seuss horton hears a who', 2008, 'Horton Hears A Who! is both whimsical and heartwarming, and is the rare Dr. Seuss adaptation that stays true to the spirit of the source material.', TO_DATE('2008-02-28', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hostel', 2005, 'Featuring lots of guts and gore, Hostel is a wildly entertaining corpse-filled journey -- assuming one is entertained by corpses, guts, and gore, that is.', TO_DATE('2005-09-16', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hostel part ii', 2007, 'Offering up more of the familiar sadism and gore, Hostel: Part II will surely thrill horror fans.', TO_DATE('2007-06-01', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hostiles', 2017, 'Hostiles benefits from stunning visuals and a solid central performance from Christian Bale, both of which help elevate its uneven story.', TO_DATE('2017-09-03', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hot chick', 2002, 'The Hot Chick''s one-note concept gets stretched thin, and a lot of the jokes fall flat.', TO_DATE('2002-12-09', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hot fuzz', 2007, 'The brilliant minds behind Shaun of the Dead successfully take a shot at the buddy cop genre with Hot Fuzz. The result is a bitingly satiric and hugely entertaining parody.', TO_DATE('2007-02-03', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hot rod', 2007, 'Hot Rod has brazen silliness and a few humorous set pieces on its side, but it''s far too inconsistent to satisfy all but the least demanding slapstick lovers.', TO_DATE('2007-06-30', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hot shots part deux', 1993, 'Audiences who enjoyed the first Hot Shots! will probably be tickled by this second helping, although the barrage of laughs miss more than they hit this time around.', TO_DATE('1993-05-21', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hot summer nights', 2017, 'Hot Summer Nights is easy on the eyes and clearly indebted to some great films, but its strengths -- including a charismatic young cast -- are often outweighed by its uninspired story.', TO_DATE('2017-03-15', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hot tub time machine', 2010, 'Its flagrantly silly script -- and immensely likable cast -- make up for most of its flaws.', TO_DATE('2010-03-11', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hot tub time machine 2', 2015, 'A shallow dip overflowing with juvenile humor, Hot Tub Time Machine 2 is a lukewarm sequel that''s healthiest to avoid.', TO_DATE('2015-02-18', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hotel', 2002, 'Hotel earns a handful of points for sheer ambition, but they aren''t enough to carry the movie over its steep pretensions.', TO_DATE('2002-04-16', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hotel artemis', 2018, 'Hotel Artemis has a few flashes of wit and an intriguing cast, but mostly it''s just a serviceable chunk of slightly futuristic violence -- which might be all its audience is looking for.', TO_DATE('2018-06-06', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hotel for dogs', 2009, 'Hotel for Dogs may appeal to children and dog lovers, but it''s ultimately contrived, predictable, and simplistic.', TO_DATE('2009-01-09', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hotel mumbai', 2018, 'Its depiction of real-life horror will strike some as exploitative, but Hotel Mumbai remains a well-made dramatization of tragic events.', TO_DATE('2018-09-08', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hotel rwanda', 2004, 'A sobering and heartfelt tale about massacre that took place in Rwanda while most of the world looked away.', TO_DATE('2004-09-14', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hotel transylvania', 2012, 'Hotel Transylvania''s buoyant, giddy tone may please children, but it might be a little too loud and thinly-scripted for older audiences.', TO_DATE('2012-09-07', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hotel transylvania 2', 2015, 'Hotel Transylvania 2 is marginally better than the original, which may or may not be enough of a recommendation to watch 89 minutes of corny, colorfully animated gags from Adam Sandler and company.', TO_DATE('2015-09-24', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hotel transylvania 3 summer vacation', 2018, 'Hotel Transylvania 3: Summer Vacation delivers exactly what fans will expect - which means another 97 agreeably lightweight minutes of fast-paced gags and colorful animation.', TO_DATE('2018-06-28', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hottie and the nottie', 2008, 'The Hottie and the Nottie is a crass, predictable, and ineptly staged gross-out comedy that serves little purpose beyond existing as another monument to Paris Hilton''s vanity.', TO_DATE('2008-01-29', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hounds of love', 2016, 'Smartly constructed and powerfully acted, Hounds of Love satisfies as a psychological thriller with a few nasty surprises -- and marks writer-director Ben Young as a promising talent.', TO_DATE('2016-09-02', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hour of the wolf vargtimmen', 2000, 'Ingmar Bergman makes a successful foray into horror with Hour of the Wolf, infusing the demons that spring from creativity with his trademark psychological curiosity.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hours', 2002, 'The movie may be a downer, but it packs an emotional wallop. Some fine acting on display here.', TO_DATE('2002-11-25', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('house at the end of the street', 2012, 'Poorly conceived, clumsily executed, and almost completely bereft of scares, House at the End of the Street strands its talented star in a film as bland as its title.', TO_DATE('2012-09-20', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the house bunny', 2008, 'Anna Faris is game, but she can''t salvage this middling, formulaic comedy.', TO_DATE('2008-08-20', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('house of 1000 corpses', 2003, 'There''s an abundance of gore in this derivative horror movie, but little sense or wit.', TO_DATE('2003-02-17', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('house of d', 2005, 'A sincere but inept coming of age story.', TO_DATE('2005-03-20', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('house of flying daggers', 2004, 'The visual splendor of the movie makes up for the weak story.', TO_DATE('2004-05-20', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('house of fools', 2003, 'House of Fools has a potentially intriguing fact-based story to tell, but an insensitive approach to depicting mental illness undermines its effectiveness.', TO_DATE('2003-02-22', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('house of games', 2000, 'Galvanized by David Mamet''s punchy dialogue and a winding succession of surprises, House of Games is a terse thriller where confidence is currency.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('house of hummingbird beolsae', 2018, 'A striking debut for writer-director Kim Bora, House of Hummingbird delicately captures a turning point in one young woman''s life.', TO_DATE('2018-10-11', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('house of sand and fog', 2003, 'Powerful and thought provoking film.', TO_DATE('2003-11-11', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('house of wax', 2005, 'Bearing little resemblance to the 1953 original, House of Wax is a formulaic but better-than-average teen slasher flick.', TO_DATE('2005-04-26', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('house party', 1990, 'House Party is a light, entertaining teen comedy with an infectious energy.', TO_DATE('1990-03-09', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('housebound', 2014, 'Alternately hilarious, gross, and simply diverting, Housebound is the rare horror-comedy that delivers on both fronts.', TO_DATE('2014-06-13', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('houseguest', 1995, 'Perplexingly unfunny given the involvement of its two hilarious leads, Houseguest wears out its welcome almost immediately.', TO_DATE('1995-01-06', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how do you know', 2010, 'How Do You Know boasts a quartet of likeable leads -- and they deserve better than this glib, overlong misfire from writer/director James L. Brooks.', TO_DATE('2010-12-13', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how green was my valley', 1941, 'Though it perhaps strays into overly maudlin territory, this working-class drama is saved by a solid cast and director John Ford''s unmistakeable style.', TO_DATE('1941-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how high', 2001, 'How High is a sloppily constructed stoner movie filled with lame, vulgar jokes.', TO_DATE('2001-12-02', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how i live now', 2013, 'Led by another strong performance from Saoirse Ronan and a screenplay that subverts YA clichés, How I Live Now blends young love with post-apocalyptic drama.', TO_DATE('2013-09-04', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how she move', 2007, 'Despite a formulaic plot, the energetic and gritty How She Move is elevated by a commanding debut performance by Rutina Wesley.', TO_DATE('2007-01-25', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dr seuss how the grinch stole christmas', 2000, 'Jim Carrey shines as the Grinch. Unfortunately, it''s not enough to save this movie. You''d be better off watching the TV cartoon.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how to be single', 2016, 'How to Be Single boasts the rough outline of a feminist rom-com, but too willingly indulges in the genre conventions it wants to subvert.', TO_DATE('2016-02-03', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how to build a girl', 2019, 'Led by Beanie Feldstein''s charming performance, How to Build a Girl puts a disarmingly earnest spin on the familiar coming-of-age comedy formula.', TO_DATE('2019-09-08', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how to cook your life', 2007, 'This charming doc takes its time while focusing on food, but highlights larger lessons that audiences will reflect upon long after leaving the theater.', TO_DATE('2007-08-18', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how to deal', 2003, 'Soap opera for teens.', TO_DATE('2003-07-14', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how to eat fried worms', 2006, 'This Fear Factor for kids is good-natured and tasty enough.', TO_DATE('2006-08-21', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how to lose a guy in 10 days', 2003, 'Matthew McConaughey and Kate Hudson are charming together, but they can''t overcome How to Lose a Guy in 10 Days'' silly premise and predictable script.', TO_DATE('2003-01-22', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how to lose friends alienate people', 2008, 'A decent performance from Pegg in a disappointing film. Neither sharp nor satirical, Weide''s adaptation relies too heavily on slapstick, and misses the point of the source material in the process.', TO_DATE('2008-05-15', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how to make an american quilt', 1995, 'How to Make an American Quilt is a bit of a patchwork from a storytelling standpoint, but a strong ensemble cast led by Winona Ryder helps hold it all together.', TO_DATE('1995-10-06', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how to survive a plague', 2012, 'Angry, powerful, and stirring, How to Survive a Plague is a brilliantly constructed documentary about the activists who pushed for action to combat the AIDS epidemic.', TO_DATE('2012-01-30', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how to talk to girls at parties', 2017, 'How to Talk to Girls at Parties has energy and ambition, but is ultimately too unfocused to do much with either -- or develop its themes into a cohesive whole.', TO_DATE('2017-05-21', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how to train your dragon', 2010, 'Boasting dazzling animation, a script with surprising dramatic depth, and thrilling 3-D sequences, How to Train Your Dragon soars.', TO_DATE('2010-03-10', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how to train your dragon 2', 2014, 'Exciting, emotionally resonant, and beautifully animated, How to Train Your Dragon 2 builds on its predecessor''s successes just the way a sequel should.', TO_DATE('2014-05-16', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('how to train your dragon the hidden world', 2019, 'The rare trilogy capper that really works, How to Train Your Dragon: The Hidden World brings its saga to a visually dazzling and emotionally affecting conclusion.', TO_DATE('2019-01-02', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('howard the duck', 2000, 'While it has its moments, Howard the Duck suffers from an uneven tone and mediocre performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('howards end', 1992, 'A superbly-mounted adaptation of E.M. Forster''s tale of British class tension, with exceptional performances all round, Howard''s End ranks among the best of Merchant-Ivory''s work.', TO_DATE('1992-03-13', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the howling', 2002, 'The Howling packs enough laughs into its lycanthropic carnage to distinguish it from other werewolf entries, with impressive visual effects adding some bite.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('howls moving castle', 2005, 'Exquisitely illustrated by master animator Miyazaki, Howl''s Moving Castle will delight children with its fantastical story and touch the hearts and minds of older viewers as well.', TO_DATE('2005-02-17', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hubble 3d', 2010, 'Offering a stunning, expansive viewing experience, Hubble 3D takes advantage of IMAX and 3-D technology like no other film.', TO_DATE('2010-03-16', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hudson hawk', 1991, 'Hudson Hawk''s kitchen-sink approach to its blend of action and slapstick results in a surreal, baffling misfire.', TO_DATE('1991-05-24', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hudsucker proxy', 1994, 'Intriguingly strange and visually distinctive, The Hudsucker Proxy is ultimately almost -- but not quite -- as smart and absorbing as it needs to be.', TO_DATE('1994-01-01', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hugo', 2011, 'Hugo is an extravagant, elegant fantasy with an innocence lacking in many modern kids'' movies, and one that emanates an unabashed love for the magic of cinema.', TO_DATE('2011-11-17', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hulk', 2003, 'While Ang Lee''s ambitious film earns marks for style and an attempt at dramatic depth, there''s ultimately too much talking and not enough smashing.', TO_DATE('2003-03-13', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('human capital', 2014, 'Part character study, part socioeconomic fable, Human Capital offers trenchant commentary as well as absorbing drama.', TO_DATE('2014-04-25', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('human capital', 2019, 'Human Capital merely rumbles when it ought to roar to life, but it remains a solidly made opportunity for a strong cast to highlight its impressive talents.', TO_DATE('2019-09-06', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the human centipede first sequence', 2009, 'Grotesque, visceral and hard to (ahem) swallow, this surgical horror doesn''t quite earn its stripes because the gross-outs overwhelm and devalue everything else.', TO_DATE('2009-10-27', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('human flow', 2017, 'Epic in scope yet clear-eyed and intimate, Human Flow offers a singularly expansive -- and sobering -- perspective on the global refugee crisis.', TO_DATE('2017-08-31', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the human stain', 2003, 'Though the acting is fine, the leads are miscast, and the story is less powerful on screen than on the page.', TO_DATE('2003-09-04', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('humpday', 2009, 'Observant and insightful, this indie comedy takes a different tack on the "bromance" but still makes a point without sermonizing.', TO_DATE('2009-01-16', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hunger', 2008, 'Unflinching, uncompromising, vivid and vital, Steve McQueen''s challenging debut is not for the faint hearted, but it''s still a richly rewarding retelling of troubled times.', TO_DATE('2008-09-22', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hunt for red october', 2000, 'Perfectly cast and packed with suspense, The Hunt for Red October is an old-fashioned submarine thriller with plenty of firepower to spare.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hunt for the wilderpeople', 2016, 'The charmingly offbeat Hunt for the Wilderpeople unites a solid cast, a talented filmmaker, and a poignant, funny, deeply affecting message.', TO_DATE('2016-01-25', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hunter killer', 2018, 'Much like the submarine in its story, Hunter Killer cruises the murky action depths, following a perfunctory course into territory that''s been charted many times before.', TO_DATE('2018-10-17', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hush', 2016, 'Hush navigates the bloody waters of home invasion thrillers and incisive slashers for a contemporary horror puree.', TO_DATE('2016-03-13', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hustle flow', 2005, 'Hustle & Flow is gritty and redemptive, with a profound sense of place and exciting music.', TO_DATE('2005-02-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hustler', 2000, 'Paul Newman and Jackie Gleason give iconic performances in this dark, morally complex tale of redemption.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hustlers', 2019, 'Led by a career-best performance from Jennifer Lopez, Hustlers is a uniquely empowering heist drama with depth and intelligence to match its striking visual appeal.', TO_DATE('2019-09-05', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hyde park on hudson', 2012, 'Though bolstered by a thoroughly charming performance by Bill Murray in the central role, Hyde Park on Hudson is an FDR biopic that lets down both its audience and its subject.', TO_DATE('2012-09-01', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hysteria', 2011, 'Hysteria has an amusing subject but its winking, vaguely sarcastic tone doesn''t do the movie any favors.', TO_DATE('2011-09-22', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i am a sex addict', 2006, 'I Am a Sex Addict takes a penetrating look at troublesome compulsions, although its unsurprisingly self-indulgent focus may test the limits of some viewers.', TO_DATE('2006-03-03', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i am big bird the caroll spinney story', 2014, 'Every bit as good-natured as longtime fans might hope, I Am Big Bird: The Carroll Spinney Story offers heartwarming behind-the-scenes perspective on a cultural icon.', TO_DATE('2014-04-30', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i am chris farley', 2015, 'I Am Chris Farley lives up to its title by taking a poignant look at the life of the deceased star that should prove affecting and illuminating for novicers and longtime fans alike.', TO_DATE('2015-07-22', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i am david', 2003, 'I Am David smothers its heartwarming story in narrative contrivances that ultimately render suspension of disbelief - or enjoyment - all but impossible.', TO_DATE('2003-11-19', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i am divine', 2013, 'With warmth and affection, I Am Divine offers an engaging portrait of the complex personality behind a trailblazing cinematic figure.', TO_DATE('2013-03-10', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i am heath ledger', 2017, 'I Am Heath Ledger takes a poignant, absorbing look at the private life and process of a talented star doomed to meet a tragic end.', TO_DATE('2017-04-23', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i am legend', 2007, 'I Am Legend overcomes questionable special effects and succeeds largely on the strength of Will Smith''s mesmerizing performance.', TO_DATE('2007-12-03', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i am love', 2010, 'It stumbles into melodrama, but I Am Love backs up its flamboyance with tremendous visual style and a marvelous central performance from Tilda Swinton.', TO_DATE('2010-03-30', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i am michael', 2015, 'I Am Michael takes a determinedly balanced approach to its complex subject, and although the results don''t always add up, they''re anchored by strong work from James Franco.', TO_DATE('2015-01-24', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i am mother', 2019, 'Suspenseful, well-acted, and intelligent, I Am Mother is an ambitious sci-fi story that largely achieves its impressive aims.', TO_DATE('2019-01-26', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i am not a serial killer', 2016, 'I Am Not A Serial Killer honors the book it''s based on with a well-acted drama that leavens its gore and dark themes with wry humor.', TO_DATE('2016-03-15', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i am not your negro', 2016, 'I Am Not Your Negro offers an incendiary snapshot of James Baldwin''s crucial observations on American race relations -- and a sobering reminder of how far we''ve yet to go.', TO_DATE('2016-09-20', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i am number four', 2011, 'It''s positioned as the start of a franchise, but I Am Number Four''s familiar plot and unconvincing performances add up to one noisy, derivative, and ultimately forgettable sci-fi thriller.', TO_DATE('2011-02-14', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i am sam', 2001, 'Not only does the manipulative I Am Sam oversimplify a complex issue, it drowns it in treacle.', TO_DATE('2001-11-24', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i am trying to break your heart', 2002, 'Besides being a treat for Wilco fans, I Am Trying to Break Your Heart also exposes the workings of a profit-driven music industry.', TO_DATE('2002-08-04', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i am woman', 2019, 'I Am Woman sticks disappointingly close to standard biopic formula, but Tilda Cobham-Hervey''s performance keeps this affectionate, watchable tribute from falling flat.', TO_DATE('2019-09-06', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i can do bad all by myself', 2009, 'Though somewhat formulaic and predictable, Perry succeeds in mixing broad humor with sincere sentimentality to palatable effect.', TO_DATE('2009-09-09', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i can only imagine', 2018, 'I Can Only Imagine''s message will have the most impact among Christian audiences, but overall, its performances and storytelling represent a notable evolution in faith-based cinema.', TO_DATE('2018-03-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i capture the castle', 2003, 'A handsome and charming adaptation of the novel.', TO_DATE('2003-05-07', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i daniel blake', 2016, 'I, Daniel Blake marks yet another well-told chapter in director Ken Loach''s powerfully populist filmography.', TO_DATE('2016-05-12', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i dont feel at home in this world anymore', 2017, 'I don''t feel at home in this world anymore. transcends its unwieldy title to offer timely, intoxicatingly dark observations on gender dynamics and social norms in modern America.', TO_DATE('2017-01-19', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i dont know how she does it', 2011, 'A limp comedy with a hopelessly outdated viewpoint on gender, featuring Sarah Jessica Parker in rote Carrie-mode.', TO_DATE('2011-09-11', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i dreamed of africa', 2000, 'The straightforward retelling of Kuki Gallman''s life in Africa neither moves or entertains the viewer.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i feel pretty', 2018, 'I Feel Pretty has a charming star and the outline of a worthwhile comedy -- but unlike its suddenly confident central character, it suffers from a fundamental lack of conviction.', TO_DATE('2018-04-18', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i frankenstein', 2014, 'Loud, incoherent, and dramatically listless, I, Frankenstein is a remarkably dull fantasy adventure that fails to generate much excitement or interest in its characters.', TO_DATE('2014-01-23', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i give it a year', 2013, 'It''s nowhere near as inventive as its reverse rom-com premise might suggest, but I Give It a Year is disarmingly frank -- and often quite funny.', TO_DATE('2013-01-21', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i hate valentines day', 2009, 'This boilerplate comedy lacks ingenuity or humor and features mediocre dialogue that sounds less like conversation and more like stand-up shtick.', TO_DATE('2009-06-30', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i heart huckabees', 2004, 'I Heart Huckabees certainly isn''t for everyone, but audiences attuned to its quirky wavelength will find a singularly brainy screwball comedy that refuses to pander.', TO_DATE('2004-09-11', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i hope they serve beer in hell', 2009, 'I Hope They Serve Beer in Hell fails in its attempts at raunchy humor, and Tucker Max comes across so unlikable and outrageous that the film''s inevitable story arc feels forced.', TO_DATE('2009-09-21', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i kill giants', 2017, 'I Kill Giants'' moody magical realism sometimes slips into the mundane, but impressive CGI and a powerhouse performance by Madison Wolfe pack an unexpected punch.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i killed my mother', 2009, 'I Killed My Mother''s raw, blunt coming-of-age narrative marks an impressive debut for filmmaker Xavier Dolan.', TO_DATE('2009-07-16', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i know what you did last summer', 1997, 'A by-the-numbers slasher that arrived a decade too late, the mostly tedious I Know What You Did Last Summer will likely only hook diehard fans of the genre.', TO_DATE('1997-10-17', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i know who killed me', 2007, 'Distasteful and ludicrously plotted, I Know Who Killed Me is a career nadir for all involved -- particularly Lindsay Lohan in a dual role.', TO_DATE('2007-07-26', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i lost my body', 2019, 'Beautifully animated and utterly unique, I Lost My Body takes audiences on a singularly strange journey whose unexpected contours lead to a wholly satisfying destination.', TO_DATE('2019-05-17', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i love trouble', 1994, 'There appears to be no Love lost between the fatally mismatched coupling of Julia Roberts and Nick Nolte in this screwball misfire that just isn''t worth the Trouble.', TO_DATE('1994-06-29', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i love you man', 2009, 'I Love You, Man makes the most of its simple premise due to the heartfelt and hilarious performances of Paul Rudd and Jason Segel.', TO_DATE('2009-01-30', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i love you phillip morris', 2009, 'This fact-based romantic comedy has its flaws, but they''re mostly overcome by its consistently sweet, funny tone and one of the best performances of Jim Carrey''s career.', TO_DATE('2009-01-19', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i melt with you', 2011, 'Presenting itself as profound while relying entirely on shock factor, I Melt With You subjects its audience to a misanthropic marathon of bad behavior that''s about as fun as a mid-life crisis.', TO_DATE('2011-01-25', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i now pronounce you chuck larry', 2007, 'Whether by way of inept comedy or tasteless stereotypes, I Now Pronounce You Chuck And Larry falters on both levels.', TO_DATE('2007-07-13', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('iousa', 2008, 'A potent and lithely constructed documentary about America''s financial crisis, I.O.U.S.A grabs you with figures but holds you with irreverent wit.', TO_DATE('2008-01-24', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i origins', 2014, 'Writer-director Mike Cahill remains an intriguingly ambitious talent, but with the uneven sci-fi drama I Origins, his reach exceeds his grasp.', TO_DATE('2014-01-19', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i robot', 2003, 'Bearing only the slightest resemblance to Isaac Asimov''s short stories, I, Robot is still a summer blockbuster that manages to make viewers think -- if only a little.', TO_DATE('2003-12-15', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i saw the light', 2015, 'I Saw the Light boasts a terrifically talented cast, but their performances aren''t enough to enliven an unfocused biopic that never comes close to capturing its subject''s timeless appeal.', TO_DATE('2015-09-11', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i see you', 2019, 'I See You gets tripped up on its own narrative contortions, but a solid cast and an effective blend of scares and suspense make this slow-building mystery worth watching.', TO_DATE('2019-03-12', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i served the king of england', 2007, 'With charm and an eye for life''s bittersweet moments, Czech New Wave master Jiri Menzel paints a picaresque story with whimsy and intellect.', TO_DATE('2007-07-12', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i smile back', 2015, 'I Smile Back serves as a powerful showcase for Sarah Silverman''s dramatic range, but fails to surround her committed performance with a movie worthy of its depth.', TO_DATE('2015-01-26', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i spit on your grave day of the woman', 2000, 'I Spit on Your Grave is as aggressively exploitative as its title suggests, although as a crude rejoinder to misogyny, it packs a certain amount of undeniable power.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i spit on your grave', 2010, 'Well-shot exploitation that has less purpose and utility than in 1978.', TO_DATE('2010-08-31', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i spy', 2002, 'Insipid and mirthless, I-Spy bares little resemblance to the TV series that inspired it.', TO_DATE('2002-10-14', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i still believe', 2020, 'I Still Believe''s palpable good intentions are offset by its predictable handling of a fact-based story that ends up preaching to the choir.', TO_DATE('2020-02-27', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i still know what you did last summer', 1998, 'Boring, predictable, and bereft of thrills or chills, I Still Know What You Did Last Summer is exactly the kind of rehash that gives horror sequels a bad name.', TO_DATE('1998-11-13', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i think i love my wife', 2007, 'Chris Rock''s comedic instincts are muted and the female characters are unsatisfactorily drawn in this uneven sex farce/domestic drama mashup.', TO_DATE('2007-03-07', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i tonya', 2017, 'Led by strong work from Margot Robbie and Alison Janney, I, Tonya finds the humor in its real-life story without losing sight of its more tragic -- and emotionally resonant -- elements.', TO_DATE('2017-09-09', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i trapped the devil', 2019, 'A slow-burning horror story that takes spine-tingling advantage of its setting and cast, I Trapped the Devil marks an auspicious debut for writer-director Josh Lobo.', TO_DATE('2019-04-17', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i used to go here', 2020, 'Elevated significantly by Gillian Jacobs'' central performance, I Used to Go Here tells a familiar story with considerable charm.', TO_DATE('2020-03-13', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i walked with a zombie', 2000, 'Evocative direction by Jacques Tourneur collides with the low-rent production values of exploitateer Val Lewton in I Walked with a Zombie, a sultry sleeper that''s simultaneously smarmy, eloquent and fascinating.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('i wish', 2011, 'Elliptical and deliberately paced yet steadily absorbing, I Wish presents a beguiling portrait of childhood that grounds its sweetly nostalgic glow with well-rounded characters and attention to detail.', TO_DATE('2011-09-21', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ibiza', 2018, 'Ibiza settles into an amiable comedic groove enlivened by its talented stars, even if the end result is fittingly somewhat narratively hazy.', TO_DATE('2018-05-22', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('iboy', 2017, 'iBoy''s original premise and Maisie Williams'' strong performance aren''t enough to overwrite a clichéd narrative, too-serious tone, and overall glitchy execution.', TO_DATE('2017-01-20', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('icarus', 2017, 'Icarus is eye-opening viewing for professional sports enthusiasts, yet it should also prove thoroughly gripping even for filmgoers who might not necessarily be drawn to the subject.', TO_DATE('2017-01-20', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ice age', 2002, 'Even though Ice Age is treading over the same grounds as Monsters, Inc. and Shrek, it has enough wit and laughs to stand on its own.', TO_DATE('2002-02-26', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ice age 2 the meltdown', 2006, 'Despite its impressive animation and the hilarious antics of the saber-toothed squirrel Scrat, Ice Age 2: The Meltdown comes up short on the storytelling front.', TO_DATE('2006-03-25', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ice age collision course', 2016, 'Unoriginal and unfunny, Ice Age: Collision Course offers further proof that not even the healthiest box office receipts can keep a franchise from slouching toward creative extinction.', TO_DATE('2016-06-18', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ice age continental drift', 2012, 'Ice Age: Continental Drift 3D has moments of charm and witty slapstick, but it often seems content to recycle ideas from the previous films.', TO_DATE('2012-06-25', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ice harvest', 2005, 'The Ice Harvest offers a couple of laughs, but considering the people involved, it should be a lot funnier.', TO_DATE('2005-09-22', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ice princess', 2005, 'This likable Disney film gets points for effort, but can''t stick the landing when it comes to originality.', TO_DATE('2005-03-15', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ice storm', 1997, 'Director Ang Lee revisits the ennui-laden decadence of 1970s suburban America with deft humor and gripping pathos.', TO_DATE('1997-09-26', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ichi the killer koroshiya 1', 2002, 'Ichi The Killer is a thoroughly shocking gorefest that will surely entertain those with strong stomachs and a penchant for brutal violence.', TO_DATE('2002-03-05', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ida', 2013, 'Empathetically written, splendidly acted, and beautifully photographed, Ida finds director Pawel Pawlikowski revisiting his roots to powerful effect.', TO_DATE('2013-09-07', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('identity', 2003, 'Identity is a film that will divide audiences -- the twists of its plot will either impress or exasperate you.', TO_DATE('2003-04-20', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('identity thief', 2013, 'Identity Thief''s few laughs are attributable to Melissa McCarthy and Jason Bateman, who labor mightily to create a framework for the movie''s undisciplined plotline.', TO_DATE('2013-02-05', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('idiocracy', 2006, 'Frustratingly uneven yet enjoyable overall, Idiocracy skewers society''s devolution with an amiably goofy yet deceptively barbed wit.', TO_DATE('2006-09-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('idle hands', 2000, 'An uneasy mix of slapstick and gore, Idle Hands lacks the manic energy and comedic inspiration required to pull off its goofy premise.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('idlewild', 2006, 'Idlewild has some truly breathtaking moments, but borrows too heavily from other similar movies, and the disjointed script is not worthy of talents involved.', TO_DATE('2006-08-04', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('if', 2002, 'Incendiary, subversive, and darkly humorous, If.... is a landmark of British countercultural cinema.', TO_DATE('2002-03-03', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('if i stay', 2014, 'Although Chloë Grace Moretz gives it her all and the story adds an intriguing supernatural twist to its melodramatic YA framework, If I Stay is ultimately more manipulative than moving.', TO_DATE('2014-08-17', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('igby goes down', 2002, 'In the vein of The Catcher in the Rye, Igby Goes Down is scathingly witty and sharply observant.', TO_DATE('2002-06-10', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ikiru', 2000, 'Ikiru is a well-acted and deeply moving humanist tale about a man facing his own mortality, one of legendary director Akira Kurosawa''s most intimate films.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('il divo', 2008, 'While the web of corruption in this Italian political thriller can be hard for a non-native to follow, the visuals and the intrigue are compelling and thrilling in equal measure.', TO_DATE('2008-06-24', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ill see you in my dreams', 2007, 'I''ll See You in My Dreams would be worth watching even if Blythe Danner''s central performance was all it had going for it, but this thoughtful drama satisfies on multiple levels.', TO_DATE('2007-07-03', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ill sleep when im dead', 2003, 'I''ll Sleep When I''m Dead''s spare performances and slick style are undermined by a lack of cohesive story, yielding a neatly packaged noir with little substance beneath its polished surface.', TO_DATE('2003-09-17', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('illegal tender', 2007, 'Lackluster acting and a ridiculous plot make the over-the-top Illegal Tender an unrealistic bust.', TO_DATE('2007-08-20', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the illusionist', 2006, 'The Illusionist is an engrossing, well-crafted story of mystery, magic and intrigue that is certain to enchant, if not hypnotize, audiences.', TO_DATE('2006-01-24', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ilo ilo', 2014, 'Quietly compassionate and rich in detail, Ilo Ilo is a strikingly mature debut from writer-director Anthony Chen.', TO_DATE('2014-01-09', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('happily ever after', 2004, 'Though this French film features good acting, it lacks the wit and charm one would expect to see.', TO_DATE('2004-09-17', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('im gonna git you sucka', 2000, 'I''m Gonna Git You Sucka puts a satirical spin on ''70s nostalgia with a comedy whose somewhat scattershot laughs are often offset by pure energetic silliness.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('im not there', 2007, 'I''m Not There''s unique editing, visuals, and multiple talented actors portraying Bob Dylan make for a deliciously unconventional experience. Each segment brings a new and fresh take on Dylan''s life.', TO_DATE('2007-09-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('im so excited', 2013, 'Campy and proudly absurd, I''m So Excited! Pedro Almodóvar''s return to light comedy isn''t quite the successful homecoming that filmgoers might wish for.', TO_DATE('2013-04-18', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('im still here', 2010, 'As unkempt and inscrutable as Joaquin Phoenix himself, I''m Still Here raises some interesting questions about its subject, as well as the nature of celebrity, but it fails to answer many of them convincingly.', TO_DATE('2010-09-07', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('imagine me you', 2005, 'Aside from its lesbian theme, Imagine Me & You can only offer more of the same generic rom-com cliches.', TO_DATE('2005-09-18', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('immortality', 2000, 'Stylish, but emotionally uninvolving.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('immortals', 2011, 'The melding of real sets, CG work, and Tarsem''s signature style produces fireworks, though the same can''t be said for Immortals slack, boring storytelling.', TO_DATE('2011-11-09', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('imperium', 2016, 'The unsettling Imperium boasts troublingly timely themes and a talented cast led by Daniel Radcliffe as an undercover FBI agent infiltrating a ring of white supremacists.', TO_DATE('2016-08-13', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the importance of being earnest', 2002, 'Oliver Parker''s adaptation of Oscar Wilde''s classic play is breezy entertainment, helped by an impressive cast, but it also suffers from some peculiar directorial choices that ultimately dampen the film''s impact.', TO_DATE('2002-04-30', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('impostor', 2001, 'With its low production value and uninspired direction, Impostor comes off as a mixture of The Fugitive and Blade Runner, only not as good or as involving.', TO_DATE('2001-12-22', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the name of the king a dungeon siege tale', 2008, 'Featuring mostly wooden performances, laughable dialogue, and shoddy production values, In the Name of the King fulfills all expectations of an Uwe Boll film.', TO_DATE('2008-01-09', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in a better world', 2010, 'In a Better World is a sumptuous melodrama that tackles some rather difficult existential and human themes.', TO_DATE('2010-12-25', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in a lonely place', 2000, 'Led by extraordinary performances from Humphrey Bogart and Gloria Grahame, In a Lonely Place is a gripping noir of uncommon depth and maturity.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in a valley of violence', 2016, 'In a Valley of Violence offers a smartly conceived homage to classic Westerns that transcends pastiche with absurdist humor and a terrific cast.', TO_DATE('2016-03-13', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in a world', 2013, 'A funny, well-written screwball satire for film buffs, In a World... proves an auspicious beginning for writer, director, and star Lake Bell.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in america', 2002, 'A rich and moving story about an immigrant family adjusting to life in New York.', TO_DATE('2002-09-18', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in out', 1997, 'It doesn''t always find comfortable ground between broad comedy and social commentary, but lively performances -- especially from Kevin Kline and Joan Cusack -- enrich In & Out''s mixture of laughs and sexual tolerance.', TO_DATE('1997-09-19', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in another country', 2012, 'In Another Country offers intelligent observations throughout its trio of overlapping stories -- and demonstrates again just how much Isabelle Huppert''s presence can improve a film.', TO_DATE('2012-05-21', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in between days', 2006, 'In Between Days is a moving, artistic slice-of-life indie film.', TO_DATE('2006-01-24', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in bruges', 2008, 'Featuring witty dialogue and deft performances, In Bruges is an effective mix of dark comedy and crime thriller elements.', TO_DATE('2008-01-17', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in country', 2000, 'With a slow build to a dramatic conclusion, In Country benefits largely from its strong acting, particularly by Emily Lloyd in the lead role.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in dreams', 2000, 'Some interesting visuals, but the movie is as confusing as a dream.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in fabric', 2018, 'In Fabric''s gauzy giallo allure weaves a surreal spell, blending stylish horror and dark comedy to offer audiences a captivating treat.', TO_DATE('2018-09-08', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in fear', 2013, 'Compact and effective, In Fear offers discerning horror fans a smart and disturbing plunge into the depths of cinematic anxiety.', TO_DATE('2013-02-08', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in good company', 2004, 'The witty and charming In Good Company offers laughs at the expense of corporate culture.', TO_DATE('2004-11-16', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in her shoes', 2005, 'Honesty and solid performances make In Her Shoes a solid fit for all audiences.', TO_DATE('2005-08-14', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in my country', 2004, 'A well-intentioned but melodramatic look at post-Apartheid South Africa.', TO_DATE('2004-03-18', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in search of beethoven', 2009, 'With a wealth of insightful talking heads and deft musical performances, In Search of Beethoven is a thorough, thoughtful examination of the great composer''s life and times.', TO_DATE('2009-04-17', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in search of greatness', 2018, 'Gabe Polsky''s persuasive documentary comes close to Greatness, making a strong case for its intriguing thesis and chock full of refreshing insights into some of the world''s most admired athletes.', TO_DATE('2018-10-24', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in search of mozart', 2006, 'In Search of Mozart may not be quite as exhilarating as its subject''s classic compositions, but it offers an enlightening, entertaining primer on the life of a brilliant artist.', TO_DATE('2006-01-31', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in secret', 2013, 'Although it benefits from a strong cast, In Secret''s stars can''t totally compensate for the movie''s sodden pacing and overly familiar story.', TO_DATE('2013-06-07', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the aisles in den gängen', 2018, 'A gently beguiling workplace romance with real heart, In the Aisles elevates its relatable story with a pair of outstanding lead performances.', TO_DATE('2018-02-24', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the army now', 2000, 'This 1994 Pauly Shore vehicle stretches its star''s thin shtick to the breaking point with a laugh-deficient screenplay that borrows shamelessly from Bill Murray''s far superior Stripes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the bedroom', 2001, 'Expertly crafted and performed, In the Bedroom is a quietly wrenching portrayal of grief.', TO_DATE('2001-05-09', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the company of men', 1997, 'Neil LaBute''s pitch-black comedy is a masterful exploration of male insecurity, and it''s elevated by a breakout performance by Aaron Eckhart as a businessman who likes to play psychological games.', TO_DATE('1997-08-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the cut', 2003, 'Director/co-writer Jane Campion takes a stab at subverting the psycho-sexual thriller genre with In the Cut, but gets tangled in her own abstraction.', TO_DATE('2003-08-28', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the fade aus dem nichts', 2017, 'In the Fade proves Diane Kruger is more than up to the task of carrying a movie -- even if the end result doesn''t quite live up to her remarkable work.', TO_DATE('2017-05-26', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the family', 2011, 'In the Family uses one couple''s tragedy to examine the legal meaning of parenthood - and make a persuasive argument for a more inclusive approach to family law.', TO_DATE('2011-11-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the heart of the sea', 2015, 'The admirably old-fashioned In the Heart of the Sea boasts thoughtful storytelling to match its visual panache, even if it can''t claim the depth or epic sweep to which it so clearly aspires.', TO_DATE('2015-12-02', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the heat of the night', 2000, 'Tense, funny, and thought-provoking all at once, and lifted by strong performances from Sydney Poitier and Rod Steiger, director Norman Jewison''s look at murder and racism in small-town America continues to resonate today.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the land of blood and honey', 2011, 'Angelina Jolie displays a deft directorial hand in her feature debut, but In the Land of Blood and Honey''s contrived love story never mixes in comfortably with depictions of the Bosnian genocide.', TO_DATE('2011-12-16', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the land of women', 2006, 'While pleasantly acted, In the Land of Women is a dramatically stilted film with underdeveloped characters.', TO_DATE('2006-05-22', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the line of fire', 1993, 'A straightforward thriller of the highest order, In the Line of Fire benefits from Wolfgang Peterson''s taut direction and charismatic performances from Clint Eastwood and John Malkovich.', TO_DATE('1993-07-09', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the loop', 2009, 'In the Loop is an uncommonly funny political satire that blends Dr. Strangelove with Spinal Tap for the Iraq war era.', TO_DATE('2009-04-14', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the mix', 2005, 'Fans may get a kick out of seeing Usher showcasing his charm on screen, but the movie itself is tone deaf and inconsequential, even by rom-com standards.', TO_DATE('2005-11-22', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the mouth of madness', 2000, 'If it fails to make the most of its intriguing premise, In the Mouth of Madness remains a decent enough diversion for horror fans and John Carpenter completists.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the name of my daughter', 2014, 'Perplexingly less than the sum of its dramatic real-life parts, In the Name of My Daughter doesn''t do enough to support its story -- or Catherine Deneuve''s performance.', TO_DATE('2014-11-17', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the name of the father', 2000, 'Impassioned and meticulously observed, In the Name of the Father mines rousing drama from a factual miscarriage of justice, aided by scorching performances and director Jim Sheridan''s humanist focus.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the pit', 2006, 'Although this doc is shot in a simple style, it is a touching and fascinating look at the lives of Mexican laborers.', TO_DATE('2006-01-30', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the realm of the senses', 2000, 'Sexual taboos are broken and boundaries crossed In the Realm of the Senses, a fearlessly provocative psychosexual tale.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the shadow of the moon', 2007, 'Director David Sington poetically interwove 20th Century''s cosmonautic history with its effect on the public''s view of their country, their heroes and their future.', TO_DATE('2007-01-31', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the shadow of the moon', 2019, 'In the Shadow of the Moon isn''t always successful at balancing its assorted elements, but its struggles may be diverting enough to warrant a stream.', TO_DATE('2019-09-22', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the tall grass', 2019, 'A potentially intriguing premise is rapidly lost in the weeds during In the Tall Grass which struggles to stretch its slim source material to feature length.', TO_DATE('2019-09-21', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the valley of elah', 2007, 'Though some of Paul Haggis''s themes are heavy-handed, In the Valley of Elah is otherwise an engrossing murder mystery and antiwar statement, featuring a mesmerizing performance from Tommy Lee Jones.', TO_DATE('2007-08-30', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in time', 2011, 'In Time''s intriguing premise and appealing cast are easily overpowered by the blunt, heavy-handed storytelling.', TO_DATE('2011-10-26', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('incarnate', 2016, 'Incarnate can''t be accused of lack of ideas -- if only any of them made sense or coalesced in any meaningful or scary way.', TO_DATE('2016-11-30', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('incendiary', 2008, 'A solid performance from Michelle Williams isn''t enough to save this well meaning, but disappointing, cliché ridden drama.', TO_DATE('2008-01-28', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('incendies', 2010, 'It''s messy, overlong, and a touch melodramatic, but those flaws pale before Incendies'' impressive acting and devastating emotional impact.', TO_DATE('2010-09-09', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('inception', 2010, 'Smart, innovative, and thrilling, Inception is that rare summer blockbuster that succeeds viscerally as well as intellectually.', TO_DATE('2010-07-05', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('incident at loch ness', 2004, 'Incident at Loch Ness will undoubtedly be of greatest interest to Herzog fans, but for those in on the inside jokes, it delivers on its weirdly unique premise.', TO_DATE('2004-09-14', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('incident in a ghost land ghostland', 2018, 'Incident in a Ghost Land may satisfy horror fans in search of a nasty kick, but it''s narratively flawed and decidedly not for the squeamish.', TO_DATE('2018-03-20', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an inconvenient truth', 2006, 'This candid, powerful and informative documentary illuminates some of the myths surrounding its dual subjects: global warming and Al Gore.', TO_DATE('2006-01-26', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the incredible shrinking man', 2000, 'A curiously sensitive and spiritual addition to the Universal Monsters line-up, tacking on deep questions about a story who is shrinking to death.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the incredibles', 2004, 'Bringing loads of wit and tons of fun to the animated superhero genre, The Incredibles easily lives up to its name.', TO_DATE('2004-07-06', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('incredibles 2', 2018, 'Incredibles 2 reunites Pixar''s family crimefighting team for a long-awaited follow-up that may not quite live up to the original, but comes close enough to earn its name.', TO_DATE('2018-06-11', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('indecent proposal', 1993, 'Lurid but acted with gusto, Indecent Proposal has difficulty keeping it up beyond its initial titillating premise.', TO_DATE('1993-04-07', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('independence day resurgence', 2016, 'It''s undeniably visually impressive, but like its predecessor, Independence Day: Resurgence lacks enough emotional heft to support its end-of-the-world narrative stakes.', TO_DATE('2016-06-21', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the indian in the cupboard', 2000, 'The Indian in the Cupboard gussies up its classic source material in modern effects without losing sight of the timeless themes at the heart of the story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('indiana jones and the kingdom of the crystal skull', 2008, 'Though the plot elements are certainly familiar, Indiana Jones and the Kingdom of the Crystal Skull still delivers the thrills and Harrison Ford''s return in the title role is more than welcome.', TO_DATE('2008-05-18', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('indiana jones and the last crusade', 2000, 'Lighter and more comedic than its predecessor, Indiana Jones and the Last Crusade returns the series to the brisk serial adventure of Raiders, while adding a dynamite double act between Harrison Ford and Sean Connery.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('indiana jones and the temple of doom', 2000, 'It may be too "dark" for some, but Indiana Jones and the Temple of Doom remains an ingenious adventure spectacle that showcases one of Hollywood''s finest filmmaking teams in vintage form.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('indignation', 2016, 'Indignation proves it''s possible to put together an engaging Philip Roth adaptation -- and offers a compelling calling card for debuting writer-director James Schamus.', TO_DATE('2016-01-25', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('inequality for all', 2013, 'While it arrives in a glut of similarly themed documentaries, Inequality for All distinguishes itself with a compelling presentation of an important message, as well as much-needed splashes of wit.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('infamous', 2006, 'Though comparisons with last year''s Capote may be inevitable, Infamous takes a different angle in its depiction of the author, and stands up well enough on its own.', TO_DATE('2006-08-31', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('infamous', 2020, 'Infamous attempts to level an indictment against modern youth, but only manages to offer a forgettable story with little of interest to say.', TO_DATE('2020-06-10', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('infernal affairs mou gaan dou', 2003, 'Smart and engrossing, this is one of Hong Kong''s better cop thrillers.', TO_DATE('2003-02-05', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('inferno', 2016, 'Senselessly frantic and altogether shallow, Inferno sends the Robert Langdon trilogy spiraling to a convoluted new low.', TO_DATE('2016-10-09', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('infinitely polar bear', 2014, 'Infinitely Polar Bear handles its thorny themes with a somewhat troublesomely light touch, but Mark Ruffalo''s complex performance keeps the drama solidly grounded.', TO_DATE('2014-01-19', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('inglourious basterds', 2009, 'A classic Tarantino genre-blending thrill ride, Inglourious Basterds is violent, unrestrained, and thoroughly entertaining.', TO_DATE('2009-05-20', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ingrid goes west', 2017, 'Led by strong performances from Aubrey Plaza and Elizabeth Olsen, Ingrid Goes West delivers smart, topical humor underlined by timely social observations.', TO_DATE('2017-01-21', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('inherent vice', 2014, 'Inherent Vice may prove frustrating for viewers who demand absolute coherence, but it does justice to its acclaimed source material -- and should satisfy fans of director P.T. Anderson.', TO_DATE('2014-10-04', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('inkheart', 2008, 'Heavy on cliches and light on charm, this kid-lit fantasy-adventure doesn''t quite get off the ground.', TO_DATE('2008-12-11', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the inlaws', 2003, 'Bigger and slicker than the original, but not necessarily better.', TO_DATE('2003-05-09', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('inmate 1 the rise of danny trejo', 2020, 'Inmate #1: The Rise of Danny Trejo uses its subject''s remarkable journey as the basis for a thoughtful and inspiring documentary.', TO_DATE('2020-06-17', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('innerspace', 2000, 'A manic, overstuffed blend of sci-fi, comedy, and romance, Innerspace nonetheless charms, thanks to Martin Short''s fine performance and the insistent zaniness of the plot.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('innocence', 2014, 'Predictable and listlessly paced, Innocence is guilty of wasting its audience''s time and money.', TO_DATE('2014-09-03', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('innocent blood', 1992, 'Awkward tonal shifts and a sluggish pace plague Innocent Blood -- a horror-comedy with anemic scares and laughs.', TO_DATE('1992-09-25', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('inside deep throat', 2005, 'A documentary on the film that brought smut mainstream, Inside Deep Throat is gaining praise as an entertaining look at a pop culture milestone. However, some critics say the film could have gone a little deeper into the people involved.', TO_DATE('2005-01-24', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('inside job', 2010, 'Disheartening but essential viewing, Charles Ferguson''s documentary explores the 2008 Global Financial Crisis with exemplary rigor.', TO_DATE('2010-09-13', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('inside llewyn davis', 2013, 'Smart, funny, and profoundly melancholy, Inside Llewyn Davis finds the Coen brothers in fine form.', TO_DATE('2013-05-18', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('inside man', 2006, 'Spike Lee''s energetic and clever bank-heist thriller is a smart genre film that is not only rewarding on its own terms, but manages to subvert its pulpy trappings with wit and skill.', TO_DATE('2006-03-10', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('inside out', 2015, 'Inventive, gorgeously animated, and powerfully moving, Inside Out is another outstanding addition to the Pixar library of modern animated classics.', TO_DATE('2015-05-18', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the insider', 1999, 'Intelligent, compelling, and packed with strong performances, The Insider is a potent corporate thriller.', TO_DATE('1999-11-05', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('insidious', 2011, 'Aside from a shaky final act, Insidious is a very scary and very fun haunted house thrill ride.', TO_DATE('2011-03-08', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('insidious chapter 2', 2013, 'Insidious: Chapter 2 is decidedly short on the tension and surprises that made its predecessor so chilling.', TO_DATE('2013-09-10', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('insidious chapter 3', 2015, 'Insidious: Chapter 3 isn''t as terrifying as the original, although it boasts surprising thematic depth and is enlivened by another fine performance from Lin Shaye.', TO_DATE('2015-06-03', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('insidious the last key', 2018, 'Insidious: The Last Key offers franchise star Lin Shaye another welcome opportunity to take the lead, but her efforts aren''t enough to rescue this uninspired sequel.', TO_DATE('2018-01-03', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('inspector gadget', 2000, 'Despite an abundance of eyecandy, the film doesn''t amount to much.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('instant family', 2018, 'Instant Family may not quite capture the complexity of real-life adoption, but fittingly for the unconditional bond it honors, this flawed yet well-intentioned dramedy is ultimately worth the investment.', TO_DATE('2018-11-14', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mesrine killer instinct mesrine linstinct de mort', 2008, 'It''s undeniably uneven, but Vincent Cassel''s electrifying performance makes Mesrine: Killer Instinct a gangster biopic worth seeking out.', TO_DATE('2008-11-07', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('insurgent', 2015, 'Shailene Woodley gives it her all, but Insurgent is still a resounding step back for a franchise struggling to distinguish itself from the dystopian YA crowd.', TO_DATE('2015-03-11', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('intacto', 2002, 'The plot gimmick is original, bolstered by stylishly intriguing setpieces.', TO_DATE('2002-02-04', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('intermission', 2003, 'An edgy and energetic ensemble story.', TO_DATE('2003-09-16', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the international', 2009, 'The International boasts some electric action sequences and picturesque locales, but is undone by its preposterous plot.', TO_DATE('2009-02-06', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the interpreter', 2005, 'A polished and intelligent thriller, though marred by plot implausibilities.', TO_DATE('2005-03-31', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('interstellar', 2014, 'Interstellar represents more of the thrilling, thought-provoking, and visually resplendent filmmaking moviegoers have come to expect from writer-director Christopher Nolan, even if its intellectual reach somewhat exceeds its grasp.', TO_DATE('2014-10-27', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('interview with the assassin', 2002, 'Barry is compellingly creepy as the self-named assassin.', TO_DATE('2002-09-25', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('interview with the vampire', 1994, 'Despite lacking some of the book''s subtler shadings, and suffering from some clumsy casting, Interview with a Vampire benefits from Neil Jordan''s atmospheric direction and a surfeit of gothic thrills.', TO_DATE('1994-11-11', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('historias mínimas intimate stories', 2003, 'This modest road movie features naturalistic performances and a heartwarming tone of gentle humanism.', TO_DATE('2003-02-06', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('intimate strangers', 2003, 'Intimate Strangers is Hitchcockian noir with a Gallic twist: Rather than simply imitating the genre''s form, director/screenwriter Patrice Leconte delves into the underlying psychological drama.', TO_DATE('2003-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('into great silence', 2006, 'A meditative, deliberately paced doc capable of absorbing patient viewers into a whole different world.', TO_DATE('2006-03-26', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('into the abyss', 2011, 'Another probing, insightful look at an interesting subject, Werner Herzog explores the American prison system with passion and not politics.', TO_DATE('2011-10-19', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('into the arms of strangers stories of the kindertransport', 2000, 'Although it appears to be nothing more than a "talking heads" documentary you may see on TV, Into the Arms of Strangers, nonetheless, tells a heart-wrenching story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('into the blue', 2005, 'Even the endless shots of bronzed beach babes and buffed dudes can''t keep this soggy scuba flick''s plot from drowning.', TO_DATE('2005-06-23', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('into the forest', 2015, 'Into the Forest grounds its familiar apocalyptic framework with a relatable look at the bond between two sisters, compellingly brought to life by Ellen Page and Evan Rachel Wood.', TO_DATE('2015-09-16', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('into the inferno', 2016, 'Into the Inferno finds director Werner Herzog observing some of the most beautiful -- and terrifying -- wonders of the natural world with his signature blend of curiosity and insight.', TO_DATE('2016-09-05', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('into the night', 2000, 'Despite its two stellar leads, Into the Night finds director John Landis indulging in far too many gimmicks in lieu of a well-rounded story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('into the storm', 2014, 'Clumsily scripted and populated with forgettable characters, Into the Storm has little to offer beyond its admittedly thrilling special effects.', TO_DATE('2014-08-06', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('into the wild', 2007, 'With his sturdy cast and confident direction, Sean Penn has turned a complex work of non-fiction like Into the Wild into an accessible and poignant character study.', TO_DATE('2007-08-31', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('into the woods', 2014, 'On the whole, this Disney adaptation of the Sondheim classic sits comfortably at the corner of Hollywood and Broadway -- even if it darkens to its detriment in the final act.', TO_DATE('2014-12-15', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('intolerable cruelty', 2003, 'Though more mainstream than other Coen films, there are still funny oddball touches, and Clooney and Zeta-Jones sizzle like old-time movie stars.', TO_DATE('2003-03-13', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('introducing the dwights', 2007, 'Despite a predictable storyline, Introducing the Dwights succeeds on the strength of its sweet and earnest portrayal of family dysfunction.', TO_DATE('2007-01-24', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('intruders', 2011, 'Intruders has a fantastic first act but then settles into a bland plot and scare tactics that aren''t all too scary.', TO_DATE('2011-09-14', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('invader zim enter the florpus', 2019, 'Invader Zim quits being banished all over again in Enter the Florpus, an excellent revival that captures the spirit of the cartoon while cranking the doom up to eleven.', TO_DATE('2019-08-16', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the invasion', 2007, 'The Invasion is slickly made, but it lacks psychological insight and thrills.', TO_DATE('2007-05-09', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the invention of lying', 2009, 'It doesn''t quite follow through on its promise, and relies too heavily on shopworn romantic comedy tropes, but The Invention of Lying is uncommonly sly and funny.', TO_DATE('2009-09-14', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('invictus', 2009, 'Delivered with typically stately precision by director Clint Eastwood, Invictus may not be rousing enough for some viewers, but Matt Damon and Morgan Freeman inhabit their real-life characters with admirable conviction.', TO_DATE('2009-11-29', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('invincible', 2006, 'As simple and authentic as the gritty South Philly invirons in which it''s set in, Invincible sends a uplifting and heartfelt message packed with an athletic enthusiasm that shouldn''t be missed.', TO_DATE('2006-08-21', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the invisible circus', 2000, 'Despite Jordana Brewster''s strong performance, The Invisible Circus lacks the necessary dramatic tension to be interesting. Also, the cultural and political contexts of the period are barely explored.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('io', 2019, 'IO has some big ideas but little idea of how to effectively convey them, leaving viewers with a sci-fi drama whose attractive packaging can''t cover its enervating core.', TO_DATE('2019-01-18', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ip man', 2009, 'At once beholden to the established conventions of the genre and delightfully subversive of them, Ip Man is one of the most exciting -- and refreshingly character-driven -- martial arts films in years.', TO_DATE('2009-10-04', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ip man 3', 2015, 'Ip Man 3 isn''t the most tightly plotted biopic a kung fu fan could ask for, but the fight scenes are fun to watch -- and at times, the drama is even genuinely poignant.', TO_DATE('2015-12-18', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ip man 4 the finale', 2019, 'Packed with action and featuring some of Donnie Yen''s finest fighting, Ip Man 4: The Finale serves as a satisfying rebound -- and fitting finale -- for the franchise.', TO_DATE('2019-12-18', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ira and abby', 2007, 'Ira & Abby overcomes the somewhat clichéd plot with witty dialogue and earnest performances.', TO_DATE('2007-07-09', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('iraq in fragments', 2006, 'A stylistically bold, humanist take on the difficulties of post-invasion Iraq.', TO_DATE('2006-01-23', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('iris', 2014, 'A small, insightful feature with a deceptively thoughtful thesis, Iris adds a bittersweet postscript to director Albert Maysles'' filmography.', TO_DATE('2014-11-15', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the iron giant', 2000, 'The endearing Iron Giant tackles ambitious topics and complex human relationships with a steady hand and beautifully animated direction from Brad Bird.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('iron island', 2005, 'A visually creative yet grounded film from Iran, Iron Island is a political allegory that packs a punch.', TO_DATE('2005-09-18', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('iron man', 2008, 'Powered by Robert Downey Jr.''s vibrant charm, Iron Man turbo-charges the superhero genre with a deft intelligence and infectious sense of fun.', TO_DATE('2008-02-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('iron man 2', 2010, 'It isn''t quite the breath of fresh air that Iron Man was, but this sequel comes close with solid performances and an action-packed plot.', TO_DATE('2010-04-07', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('iron man 3', 2013, 'With the help of its charismatic lead, some impressive action sequences, and even a few surprises, Iron Man 3 is a witty, entertaining adventure and a strong addition to the Marvel canon.', TO_DATE('2013-04-19', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ironclad', 2011, 'Ironclad serves up plenty of crunchy gore to sate action aficionados, but the sketchy story clunks like a suit of ill-fitting armor.', TO_DATE('2011-02-24', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ironweed', 2000, 'Jack Nicholson and Meryl Streep play masterfully off each, but Ironweed''s unrelenting bleakness proves to be more monotonous than compelling.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('irrational man', 2015, 'Irrational Man may prove rewarding for the most ardent Joaquin Phoenix fans or Woody Allen apologists, but all others most likely need not apply.', TO_DATE('2015-05-15', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('irresistible', 2020, 'A soft political satire that proves frustratingly less than the sum of its talented parts, Irresistible is anything but.', TO_DATE('2020-06-22', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('irréversible', 2002, 'Though well-filmed, Irreversible feels gratuitous in its extreme violence.', TO_DATE('2002-05-30', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('is the man who is tall happy an animated conversation with noam chomsky', 2013, 'An unlikely pairing of form and style, Michel Gondry''s Is the Tall Man Happy? successfully gives Noam Chomsky''s philosophical musings an expressive canvas with a delightfully anarchic animation style.', TO_DATE('2013-11-18', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('is anybody there', 2008, 'Though Michael Caine gives an excellent performance, Is Anybody There? features a cliche-filled story that ultimately falters.', TO_DATE('2008-10-28', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ishtar', 2000, 'Warren Beatty, Dustin Hoffman, and laughter itself get lost in the desert during a flawed spoof of classic road movies that proves ill-suited for its mismatched and miscast stars.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('island of lemurs madagascar', 2014, 'Brief enough for the youngest viewers yet informative and visually spectacular enough for all ages, Island of Lemurs: Madagascar is educational entertainment for the whole family.', TO_DATE('2014-04-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('isle of dogs', 2018, 'The beautifully stop-motion animated Isle of Dogs finds Wes Anderson at his detail-oriented best while telling one of the director''s most winsomely charming stories.', TO_DATE('2018-02-15', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ismaels ghosts les fantômes dismaël', 2017, 'Ismael''s Ghosts unites an excellent cast -- and their valiant efforts are often enough to counter its somewhat confused and disjointed story.', TO_DATE('2017-05-17', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('isnt it romantic', 2019, 'It follows as many genre conventions as it mocks, but Isn''t It Romantic is a feel-good rom-com with some satirical bite -- and a star well-suited for both.', TO_DATE('2019-02-12', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('isnt she great', 2000, 'Bland material produces entirely forgettable comic performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('it came from outer space', 2000, 'It Came From Outer Space is a pulpy-but-effective psychological sci-fi picture, with a provocative message about xenophobia.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('it', 2017, 'Well-acted and fiendishly frightening with an emotionally affecting story at its core, It amplifies the horror in Stephen King''s classic story without losing touch with its heart.', TO_DATE('2017-09-06', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('it chapter two', 2019, 'It: Chapter Two proves bigger doesn''t always mean scarier for horror sequels, but a fine cast and faithful approach to the source material keep this follow-up afloat.', TO_DATE('2019-09-03', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('it comes at night', 2017, 'It Comes at Night makes lethally effective use of its bare-bones trappings while proving once again that what''s left unseen can be just as horrifying as anything on the screen.', TO_DATE('2017-04-30', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('it follows', 2014, 'Smart, original, and above all terrifying, It Follows is the rare modern horror film that works on multiple levels -- and leaves a lingering sting.', TO_DATE('2014-05-18', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('it happened one night', 1934, 'Capturing its stars and director at their finest, It Happened One Night remains unsurpassed by the countless romantic comedies it has inspired.', TO_DATE('1934-02-22', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('it might get loud', 2008, 'An affectionate tribute to rock''s most distinctive instrument, It Might Get Loud is insightful and musically satisfying.', TO_DATE('2008-09-15', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('it runs in the family', 2003, 'Despite its gimmick casting, the movie ultimately goes nowhere.', TO_DATE('2003-04-21', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the italian', 2006, 'Poignant and unforgettable, The Italian stands out from other European melodramas. Like its extraordinary child lead, this Russian drama about an orphan''s search for his birth mother is small in size and monumental in pathos.', TO_DATE('2006-09-09', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('italian for beginners', 2001, 'Unlike many romantic comedies, the charming Italian for Beginners feels natural and genuinely heart-warming.', TO_DATE('2001-09-27', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the italian job', 2003, 'Despite some iffy plot elements, The Italian Job succeeds in delivering an entertaining modern take on the original 1969 heist film, thanks to a charismatic cast.', TO_DATE('2003-04-17', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('its kind of a funny story', 2010, 'It''s amiable, and it does a surprisingly good job of sidestepping psych ward comedy cliches, but given its talented cast and directors, It''s Kind of a Funny Story should be more than just mildly entertaining.', TO_DATE('2010-09-10', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('its a disaster', 2012, 'A clever black comedy, It''s a Disaster is sometimes uneven but the sharp writing and stellar ensemble cast keeps the film on track.', TO_DATE('2012-06-28', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('its a mad mad mad mad world', 2001, 'It''s long, frantic, and stuffed to the gills with comic actors and set pieces -- and that''s exactly its charm.', TO_DATE('2001-02-13', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('its a wonderful life', 2000, 'The holiday classic to define all holiday classics, It''s a Wonderful Life is one of a handful of films worth an annual viewing.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('its all gone pete tong', 2005, 'Part raucous mockumentary, part drama-filled biopic, It''s All Gone Pete Tong amuses and warms hearts with its touching, comic, and candid look at a musician faced with a career-ending handicap.', TO_DATE('2005-04-06', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('itzhak', 2017, 'Itzhak serves as an entertaining introduction to the life and career of a brilliant artist with a personality as warm as his music.', TO_DATE('2017-10-11', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ivans childhood ivanovo detstvo', 2003, 'Ostensibly an atypical Tarkovsky work (less than 100 minutes!), Ivan''s Childhood carries the poetry and passion that would characterize the director from here on.', TO_DATE('2003-03-10', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ive loved you so long', 2008, 'I''ve Loved You So Long is a sublimely acted family drama as well as a noteworthy directorial debut from Phillipe Claudel.', TO_DATE('2008-08-31', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ivory tower', 2014, 'Although Ivory Tower makes it clear that there isn''t enough room in a 90-minute film to tackle spiraling student loan debt, it also serves as a compelling call for deeper investigation.', TO_DATE('2014-06-09', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ixcanul', 2015, 'Ixcanul opens a window into a little-seen corner of the world -- and finds universal truths about the human condition that should resonate with patient viewers.', TO_DATE('2015-09-23', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('j edgar', 2011, 'Leonardo DiCaprio gives a predictably powerhouse performance, but J. Edgar stumbles in all other departments with cheesy makeup, poor lighting, confusing narrative, and humdrum storytelling.', TO_DATE('2011-11-04', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jack and jill', 2011, 'Although it features an inexplicably committed performance from Al Pacino, Jack and Jill is impossible to recommend on any level whatsoever.', TO_DATE('2011-11-09', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jack brooks monster slayer', 2008, 'A sincere but sometimes-excessive send up of low-rent horror hokum, Jack Brooks: Monster Slayer features some sharp laughs and features a scene-stealing performance by Robert Englund.', TO_DATE('2008-01-28', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jack goes boating', 2010, 'It''s made the journey from stage to screen somewhat worse for wear, but Jack Goes Boating remains a sensitive, well-acted character study.', TO_DATE('2010-01-25', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jack reacher', 2012, 'Jack Reacher is an above-average crime thriller with a smoothly charismatic performance from Tom Cruise.', TO_DATE('2012-12-09', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jack reacher never go back', 2016, 'Monotonously formulaic, Jack Reacher: Never Go Back is one action thriller sequel whose title also serves as a warning.', TO_DATE('2016-10-19', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jack ryan shadow recruit', 2014, 'It doesn''t reinvent the action-thriller wheel, but Jack Ryan: Shadow Recruit offers a sleek, reasonably diverting reboot for a long-dormant franchise.', TO_DATE('2014-01-13', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jack the giant slayer', 2013, 'It''s enthusiastically acted and reasonably fun, but Jack the Giant Slayer is also overwhelmed by digital effects and a bland, impersonal story.', TO_DATE('2013-02-26', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the jackal', 1997, 'The Jackal is a relatively simple chase thriller incapable of adding thrills or excitement as the plot chugs along.', TO_DATE('1997-11-14', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jackass 3', 2010, 'The Jackass gang might be running out of gross-out stunts, but this installment contains plenty of brilliantly brain-dead comedy -- and the 3-D adds a pungent new dimension.', TO_DATE('2010-10-14', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jackass number two', 2006, 'Better than any sequel to a movie of a television show has a right to be, Jackass: Number Two dares you not to laugh.', TO_DATE('2006-09-19', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jackass presents bad grandpa', 2013, 'Never quite as funny as it wants to be, Jackass Presents: Bad Grandpa still offers viewers the timeless pleasures of seeing an old man get his privates stuck in a vending machine.', TO_DATE('2013-10-21', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jackass the movie', 2002, 'There''s a good chance you''ll be laughing hysterically at one stunt, but getting grossed out by the next one in this big screen version of the controversial MTV show.', TO_DATE('2002-10-24', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the jacket', 2005, 'The Jacket is a case of creepy style over substance.', TO_DATE('2005-01-25', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jackie', 2016, 'Jackie offers an alluring peek into a beloved American public figure''s private world -- and an enthralling starring performance from Natalie Portman in the bargain.', TO_DATE('2016-09-07', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jackie brown', 2000, 'Although somewhat lackadaisical in pace, Jackie Brown proves to be an effective star-vehicle for Pam Grier while offering the usual Tarantino wit and charm.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jacobs ladder', 2000, 'Even with its disorienting leaps of logic and structure, Jacob''s Ladder is an engrossing, nerve-shattering experience.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jacobs ladder', 2019, 'A needless remake that quickly loses sight of the themes that elevated the original, this is a Jacob''s Ladder that leads straight to nowhere.', TO_DATE('2019-08-07', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jade', 2000, 'An ostensible erotic thriller that''s largely neither erotic nor thrilling, Jade marks one of several unfortunate low points for aggressively sexual mid-''90s cinema.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jafar panahis taxi', 2015, 'Jafar Panahi''s Taxi offers another round of trenchant societal commentary from a director whose entire filmography stands as a daring act of dissent.', TO_DATE('2015-02-13', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jagged edge', 2000, 'Coolly performed and suspenseful, Jagged Edge is a satisfying enough potboiler that most audiences won''t mind if the twists don''t quite add up.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jakob the liar', 2000, 'Any real story is buried by awkward performances and contrived situations.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('james and the giant peach', 2000, 'The arresting and dynamic visuals, offbeat details and light-as-air storytelling make James and the Giant Peach solid family entertainment.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('james white', 2015, 'Led by powerfully complementary performances from Christopher Abbott and Cynthia Nixon, James White offers an affecting calling card for debuting writer-director Josh Mond.', TO_DATE('2015-01-23', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jane eyre', 2011, 'Cary Fukunaga directs a fiery and elegant adaptation of Charlotte Bronte''s classic novel, and Mia Wasikowska delivers possibly the best portrayal of the title character ever.', TO_DATE('2011-03-04', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jane got a gun', 2016, 'Jane Got a Gun flounders between campy Western and hard-hitting revisionist take on the genre, leaving Natalie Portman''s committed performance stranded in the dust.', TO_DATE('2016-01-05', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('janis little girl blue', 2015, 'Respectful without veering into hagiography and inquisitive without being intrusive, Janis: Little Girl Blue offers an insightful glimpse into the life of a rock ''n'' roll legend.', TO_DATE('2015-10-31', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('japanese story', 2003, 'An emotional film where Toni Collette gets to show her impressive range.', TO_DATE('2003-09-22', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('japon', 2002, 'A slow-moving, visually impressive debut.', TO_DATE('2002-11-13', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jason bourne', 2016, 'Jason Bourne delivers fans of the franchise more of what they''ve come to expect -- which is this sequel''s biggest selling point as well as its greatest flaw.', TO_DATE('2016-07-26', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jason x', 2002, 'Jason goes to the future, but the story is still stuck in the past.', TO_DATE('2002-04-19', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jasons lyric', 1994, 'Jason''s Lyric is a sexually charged film whose violent streak weakens or, depending on your perspective, supports the melodrama.', TO_DATE('1994-09-28', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jauja', 2014, 'Jauja will prove haunting for those lured in by its deliberate pace and lovely visuals, though it may test some viewers'' patience.', TO_DATE('2014-05-22', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jawbreaker', 2000, 'This throwaway comedy falls victim to its hip sensibilities.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jaws', 2000, 'Compelling, well-crafted storytelling and a judicious sense of terror ensure Steven Spielberg''s Jaws has remained a benchmark in the art of delivering modern blockbuster thrills.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jaws 2', 2000, 'Jaws 2 never approaches the lingering thrills of its classic predecessor, but it''s reasonably entertaining for a sequel that has no reason to exist.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jaws 3', 2000, 'A cheese-soaked ocean thriller with no evident reason to exist, Jaws 3 bellows forth with a plaintive yet ultimately unheeded cry to put this franchise out of viewers'' misery.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jaws the revenge', 2000, 'Illogical, tension-free, and filled with cut-rate special effects, Jaws 4 - The Revenge is a sorry chapter in a once-proud franchise.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jay silent bob reboot', 2019, 'Fan-focused to a fault, Jay & Silent Bob Reboot tries to mock the same audience nostalgia it''s mining -- and pulls it off often enough to satisfy the faithful.', TO_DATE('2019-10-15', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jay and silent bob strike back', 2001, 'Fans can expect a good laugh as the cast from Smith''s previous films reunite for Jay and Silent Bob''s last bow. The loose plotting and crude language may be too much for others though.', TO_DATE('2001-07-05', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jayne mansfields car', 2012, 'Jayne Mansfield''s Car assembles an impressive number of talented actors, but the screenplay -- co-written by director and star Billy Bob Thornton -- never gives them much of anything to do.', TO_DATE('2012-02-14', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jcvd van dammage', 2008, 'JCVD is a touching, fascinating piece, with Jean-Claude Van Damme confounding all with his heartfelt performance.', TO_DATE('2008-09-15', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jeanne dielman 23 quai du commerce 1080 bruxelles', 2003, 'Jeanne Dielman, 23 Quai du Commerce, 1080 Bruxelles offers a lingering, unvarnished, and ultimately mesmerizing look at one woman''s existence.', TO_DATE('2003-06-17', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jeepers creepers', 2001, 'Jeepers Creepers has a promising start. Unfortunately, the tension and suspense quickly deflates into genre cliches as movie goes on.', TO_DATE('2001-08-15', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jeepers creepers 2', 2003, 'Jeepers Creepers 2 is competently made, but it doesn''t have the scares of the original.', TO_DATE('2003-08-26', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jeff who lives at home', 2011, 'Sweet, funny, and flawed, Jeff, Who Lives at Home finds the Duplass brothers moving into the mainstream with their signature quirky charm intact.', TO_DATE('2011-09-11', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jeffrey', 1995, 'Jeffrey offends as readily as it amuses, but an outstanding performance from Patrick Stewart keeps it from going completely off the rails.', TO_DATE('1995-08-18', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jem and the holograms', 2015, 'Jem and the Holograms ignores its source material''s goofy charm in favor of bland by-the-numbers drama.', TO_DATE('2015-10-21', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jennifers body', 2009, 'Jennifer''s Body features occasionally clever dialogue, but its horror/comedy premise ultimately fails to be consistently funny or scary enough to satisfy.', TO_DATE('2009-09-10', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jenny slate stage fright', 2019, 'Jenny Slate leans into her Stage Fright in a special that''s raw, honest, and as overwhelmingly delightful as the comedian herself.', TO_DATE('2019-10-23', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jeremiah johnson', 2000, 'Jeremiah Johnson''s deliberate pace demands an investment from the viewer, but it''s rewarded with a thoughtful drama anchored by a starring performance from Robert Redford.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jerichow', 2008, 'Minimal and intriguing, this Teutonic retreading of The Postman Always Rings Twice is tense and ominous throughout.', TO_DATE('2008-09-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the jerk', 2001, 'Crude, crass, and oh so quotable, The Jerk is nothing short of an all-out comedic showcase for Steve Martin.', TO_DATE('2001-04-17', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jerry before seinfeld', 2017, 'Jerry Before Seinfeld finds its star revisiting his earliest material on his hometown stage, offering appropriately familiar - yet still abundant - laughs along the way.', TO_DATE('2017-09-18', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jerry seinfeld 23 hours to kill', 2020, '23 Hours to Kill misses the mark but still finds some funny in a special that''s entertaining, if not always great.', TO_DATE('2020-05-05', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jersey boys', 2014, 'Jersey Boys is neither as inventive nor as energetic as it could be, but there''s no denying the powerful pleasures of its musical moments.', TO_DATE('2014-06-15', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jersey girl', 2004, 'A surprisingly conventional romantic comedy from Kevin Smith, Jersey Girl is warm but often overly sentimental.', TO_DATE('2004-02-17', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jessabelle', 2014, 'Jessabelle hints at a bright future for star Sarah Snook, but clouds her performance with a cliched -- and tasteless -- storyline.', TO_DATE('2014-11-02', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jesus camp', 2006, 'Evangelical indoctrination is given an unflinching, even-handed look in this utterly worthwhile documentary.', TO_DATE('2006-08-14', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jesus son', 1999, 'Slight yet ultimately absorbing, Jesus'' Son makes effective use of its period setting and talented ensemble cast.', TO_DATE('1999-06-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jet lag', 2002, 'A light and fluffy romantic comedy for fans of Juliette Binoche and Jean Reno.', TO_DATE('2002-10-10', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the jewel of the nile', 2000, 'The sense of romantic spark has waned and the prevalence of stereotypes has grown in Jewel of the Nile, although there is still plenty of swooning action for fans of the first adventure.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jexi', 2019, 'It''s hard to tell whether the lack of laughs in Jexi is a bug or a feature, but this AI rom-com is sorely in need of an OS update.', TO_DATE('2019-10-11', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jigsaw', 2017, 'Jigsaw definitely won''t win many converts to the Saw franchise, but for longtime fans, it should prove a respectably revolting -- if rarely scary -- diversion.', TO_DATE('2017-10-26', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jim andy the great beyond featuring a very special contractually obligated mention of tony clifton', 2017, 'Jim & Andy: The Great Beyond offers a fascinating behind-the-scenes glimpse of method acting in action -- and one star''s journey toward something like personal acceptance.', TO_DATE('2017-09-05', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jimi all is by my side', 2013, 'It''s uneven -- and it lacks the primal power of its subject''s classic recordings -- but Jimi: All Is By My Side offers a well-acted alternative take on the Hendrix myth.', TO_DATE('2013-09-11', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jimmy neutron boy genius', 2001, 'What Jimmy Neutron lacks in computer animation, it makes up for in charm and cleverness.', TO_DATE('2001-12-18', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jimmy p', 2013, 'Jimmy P. has interesting ideas and talented stars, but director Arnaud Desplechin can''t seem to figure out how to bring them together.', TO_DATE('2013-05-18', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jindabyne', 2006, 'Jindabyne''s disparate themes may not quite cohere, but the film features fine performances from Linney and Byrne.', TO_DATE('2006-04-27', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jingle all the way', 1997, 'Arnold Schwarzenegger tries his best, but Jingle All the Way suffers from an uneven tone, shifting wildly from a would-be satire on materialism to an antic, slapstick yuk-fest.', TO_DATE('1997-06-01', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jinn', 2018, 'A coming-of-age story distinguished by sensitivity and strong performances, Jinn heralds debuting writer-director Nijla Mu''min as a remarkable talent.', TO_DATE('2018-03-13', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jiro dreams of sushi', 2011, 'Beautiful, thoughtful, and engrossing, Jiro Dreams of Sushi should prove satisfying even for filmgoers who don''t care for the cuisine.', TO_DATE('2011-04-22', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('joan rivers a piece of work', 2010, 'Penetrating Rivers'' coarse image, this compelling documentary offers an honest, behind-the-scenes look at her career -- and at show business in general.', TO_DATE('2010-04-23', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('joan didion the center will not hold', 2017, 'Joan Didion: The Center Will Not Hold pays tribute to an American literary legend with a richly personal perspective that should thrill devotees while enlightening newcomers.', TO_DATE('2017-10-12', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jobs', 2013, 'An ambitious but skin-deep portrait of an influential, complex figure, Jobs often has the feel of an over-sentimentalized made-for-TV biopic.', TO_DATE('2013-01-26', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jodorowskys dune', 2013, 'Part thoughtful tribute, part bittersweet reminder of a missed opportunity, Jodorowsky''s Dune offers a fascinating look at a lost sci-fi legend.', TO_DATE('2013-05-20', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('joe', 2013, 'Rich in atmosphere and anchored by a powerful performance from Nicolas Cage, Joe is a satisfying return to form for its star -- as well as director David Gordon Green.', TO_DATE('2013-08-30', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('joe dirt', 2000, 'If you fall within the target audience of Joe Dirt, you may find it funny. Otherwise, the jokes will seem like a tired retread.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('joe somebody', 2001, 'Amiable, but extremely lightweight and predictable.', TO_DATE('2001-12-15', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('joe strummer the future is unwritten', 2007, 'Displaying Joe Strummer warts and all, The Future is Unwritten succeeds as both an engrossing documentary and a comprehensive examination of one of music''s most legendary figures.', TO_DATE('2007-01-22', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('joe versus the volcano', 1990, 'Joe Versus the Volcano erupts with plenty of screwball energy and thoughtful observations about living to the fullest, but its existential ambition may prove too goofy for some audiences.', TO_DATE('1990-03-09', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('joes apartment', 1996, 'Audiences will want their security deposit back from Joe''s Apartment, a lame comedy whose dancing cockroaches are more charming than the human characters.', TO_DATE('1996-07-26', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('john carpenters ghosts of mars', 2000, 'John Carpenter''s Ghosts of Mars is not one of Carpenter''s better movies, filled as it is with bad dialogue, bad acting, confusing flashbacks, and scenes that are more campy than scary.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('john carpenters vampires', 1998, 'Nothing but one showdown after another.', TO_DATE('1998-10-30', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('john carter', 2012, 'While John Carter looks terrific and delivers its share of pulpy thrills, it also suffers from uneven pacing and occasionally incomprehensible plotting and characterization.', TO_DATE('2012-03-01', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('john dies at the end', 2012, 'Some will find the darkly funny, genre-bending incoherence of John Dies at the End charming; some will feel its zany antics and gore lead to an unsatisfying payoff.', TO_DATE('2012-01-25', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('john lewis good trouble', 2020, 'It''s far more conventional than the life it honors, but John Lewis: Good Trouble remains a worthy tribute to an inspiring activist and public servant.', TO_DATE('2020-06-13', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('john mulaney the sack lunch bunch', 2019, 'With spectacular musical numbers, a smartly silly sensibility, and just the right amount of existential dread, John Mulaney & The Sack Lunch Bunch is a joyous reminder that kindness and comedy can in fact go hand in hand.', TO_DATE('2019-12-19', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('john mulaney kid gorgeous at radio city', 2018, 'John Mulaney incisively describes his own befuddlement with the modern world in this uproariously funny deconstruction of manners, relationships, and religion.', TO_DATE('2018-05-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('john q', 2002, 'Washington''s performance rises above the material, but John Q pounds the audience over the head with its message.', TO_DATE('2002-02-01', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rambo rambo iv', 2008, 'Sylvester Stallone knows how to stage action sequences, but the movie''s uneven pacing and excessive violence (even for the franchise) is more nauseating than entertaining.', TO_DATE('2008-01-23', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('john tucker must die', 2006, 'This derivitive teen comedy tries to go for cute when it could use more bite.', TO_DATE('2006-07-25', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('john wick', 2014, 'Stylish, thrilling, and giddily kinetic, John Wick serves as a satisfying return to action for Keanu Reeves -- and what looks like it could be the first of a franchise.', TO_DATE('2014-09-19', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('john wick chapter 2', 2017, 'John Wick: Chapter 2 does what a sequel should -- which in this case means doubling down on the non-stop, thrillingly choreographed action that made its predecessor so much fun.', TO_DATE('2017-02-06', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('john wick chapter 3 parabellum', 2019, 'John Wick: Chapter 3 - Parabellum reloads for another hard-hitting round of the brilliantly choreographed, over-the-top action that fans of the franchise demand.', TO_DATE('2019-05-10', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('johnny english', 2003, 'A tame spy spoof that elicits infrequent chuckles.', TO_DATE('2003-04-07', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('johnny english reborn', 2011, 'Arguably a marginal improvement on its mostly-forgotten predecessor, Johnny English Reborn nonetheless remains mired in broad, tired spy spoofing that wastes Rowan Atkinson''s once considerable comedic talent.', TO_DATE('2011-09-11', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('johnny english strikes again', 2018, 'Johnny English Strikes Again might get a few giggles out of viewers pining for buffoonish pratfalls, but for the most part, this sequel simply strikes out.', TO_DATE('2018-09-14', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('johnny guitar', 2000, 'Johnny Guitar confidently strides through genre conventions, emerging with a brilliant statement that transcends its period setting -- and left an indelible mark.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('johnny mnemonic', 1995, 'As narratively misguided as it is woefully miscast, Johnny Mnemonic brings the ''90s cyberpunk thriller to inane new whoas -- er, lows.', TO_DATE('1995-05-26', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('johnson family vacation', 2004, 'The poorly crafted Johnson Family Vacation squanders its talented cast in a bland family road comedy that draws unfavorable comparisons to Chevy Chase''s Vacation movies.', TO_DATE('2004-03-31', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('joker', 2019, 'Joker gives its infamous central character a chillingly plausible origin story that serves as a brilliant showcase for its star -- and a dark evolution for comics-inspired cinema.', TO_DATE('2019-08-31', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jonah a veggietales movie', 2002, 'Jonah teaches wholesome messages to children in a funny, bouncy package.', TO_DATE('2002-10-02', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jonah hex', 2010, 'Josh Brolin gives it his best shot, but he can''t keep the short, unfocused Jonah Hex from collapsing on the screen.', TO_DATE('2010-06-17', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jonas brothers the 3d concert experience', 2009, 'Jonas Brothers: The 3-D Concert Experience should please the brothers'' adoring followers, but for non-converts, this concert film is largely flat and unenlightening.', TO_DATE('2009-02-24', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the joneses', 2010, 'It doesn''t pursue its subversive premise as far as it should, but The Joneses benefits from its timely satire of consumer culture -- as well as a pair of strong performances from David Duchovny and Demi Moore.', TO_DATE('2010-03-08', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('joshua', 2007, 'Though Joshua is ultimately too formulaic, its intelligence and suspenseful buildup heighten the overall creep factor.', TO_DATE('2007-01-22', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('joshy', 2016, 'Writer/director Jeff Baena and an able cast of comedic actors strike a unique, disarmingly heartfelt blend of dark humor and tragedy with Joshy.', TO_DATE('2016-01-25', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('josie and the pussycats', 2000, 'This live-action update of Josie and the Pussycats offers up bubbly, fluffy fun, but the constant appearance of product placements seems rather hypocritical.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('journey to the center of the earth', 2002, 'A silly but fun movie with everything you''d want from a sci-fi blockbuster -- heroic characters, menacing villains, monsters, big sets and special effects.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('journey to the center of the earth', 2008, 'Modern visuals and an old fasioned storyline make this family adventure/comedy a fast-paced, kitschy ride.', TO_DATE('2008-06-16', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('journey 2 the mysterious island', 2012, 'Aggressively unambitious, Journey 2 might thrill tween viewers, but most others will find it too intense for young audiences and too cartoonishly dull for adults.', TO_DATE('2012-01-16', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('journey to the west', 2014, 'As sweet, silly, action-packed and ridiculous as director Steven Chow''s best work, Journey to the West serves up dazzling action sequences while playing its disparate elements against each other with thrilling abandon.', TO_DATE('2014-02-28', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('journeys end', 2017, 'Journey''s End brings R.C. Sherriff''s 90-year-old play to the screen with thrilling power, thanks to director Saul Dibb''s hard-hitting urgency and brilliant work from a talented cast.', TO_DATE('2017-09-10', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('joy', 2015, 'Joy is anchored by a strong performance from Jennifer Lawrence, although director David O. Russell''s uncertain approach to its fascinating fact-based tale only sporadically sparks bursts of the titular emotion.', TO_DATE('2015-12-07', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the joy luck club', 1993, 'The Joy Luck Club traces the generational divide, unearthing universal truths while exploring lives through the lens of a specific cultural experience.', TO_DATE('1993-09-08', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('joyeux noël merry christmas', 2005, 'The poignant humanity on display in Joyeux Noel makes its sentimentality forgivable.', TO_DATE('2005-10-08', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('joyful noise', 2012, 'Joyful Noise''s musical numbers are solidly entertaining, and it benefits from Queen Latifah and Dolly Parton''s sizable chemistry; unfortunately, they aren''t enough to make up for the rest of the film.', TO_DATE('2012-01-05', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jt leroy', 2018, 'While it may leave some viewers wishing for a more in-depth exploration of its story and themes, J.T. Leroy offers a diverting dramatization of incredible real-life events.', TO_DATE('2018-09-11', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('juan of the dead', 2012, 'Filled with wild splatter slapstick, Juan of the Dead also deftly uses its zombie premise as an undead Trojan horse for insightful political commentary.', TO_DATE('2012-03-08', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('juanita', 2019, 'Juanita''s refreshing journey of self-actualization may lead to a predictable destination, but a sterling star turn by Alfre Woodard gives this sojourn an invaluable spark.', TO_DATE('2019-03-08', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('judge dredd', 2000, 'Judge Dredd wants to be both a legitimate violent action flick and a parody of one, but director Danny Cannon fails to find the necessary balance to make it work.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('judy', 2019, 'Led by a deeply committed performance from Renée Zellweger, Judy captures the waning days of a beloved performer with clear-eyed compassion.', TO_DATE('2019-08-31', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('judy punch', 2019, 'Judy & Punch revisits classic characters from a fresh perspective, marking debuting writer-director Mirrah Foulkes as a filmmaking talent to watch.', TO_DATE('2019-01-28', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('judy moody and the not bummer summer', 2011, 'Entertaining for some very young viewers, but for those with normal attention spans, Judy Moody is loud hyperactive overload.', TO_DATE('2011-06-03', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jules and jim', 2000, 'Francois Truffaut''s arguable masterpiece in a filmography full of masterpieces ready to be argued for, Jules and Jim is an eternal ode to boundless love.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('julie julia', 2009, 'Boosted by Meryl Streep''s charismatic performance as Julia Child, Julie and Julia is a light, but fairly entertaining culinary comedy.', TO_DATE('2009-07-25', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('julien donkeyboy', 1999, 'Director Harmony Korine takes a big stylistic swing that will miss with most audiences, producing an unfocused and mean-spirited art film with a bitter aftertaste.', TO_DATE('1999-10-15', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('juliet naked', 2018, 'Juliet, Naked''s somewhat familiar narrative arc is elevated by standout work from a charming cast led by a well-matched Rose Byrne and Ethan Hawke.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('julieta', 2016, 'Julieta finds writer-director Pedro Almodóvar revisiting familiar themes -- and doing so with his signature skill.', TO_DATE('2016-04-05', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jumanji the next level', 2019, 'Like many classic games, Jumanji: The Next Level retains core components of what came before while adding enough fresh bits to keep things playable.', TO_DATE('2019-12-07', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jumanji welcome to the jungle', 2017, 'Jumanji: Welcome to the Jungle uses a charming cast and a humorous twist to offer an undemanding yet solidly entertaining update on its source material.', TO_DATE('2017-12-09', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jump tomorrow', 2001, 'The light-hearted romantic comedy Jump Tomorrow charms with its whimsy and sweetness.', TO_DATE('2001-06-07', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jumper', 2008, 'Featuring uninvolving characters and loose narrative, Jumper is an erratic action pic with little coherence and lackluster special effects.', TO_DATE('2008-02-11', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jumping the broom', 2011, 'Its heart is in the right place -- and so is its appealing cast -- but Jumping the Broom is ultimately too cliched and thinly written to recommend.', TO_DATE('2011-04-29', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('junebug', 2005, 'Aided and abetted by a wonderful cast, director Phil Morrison transforms familiar material into an understated and resonant comedy.', TO_DATE('2005-02-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jungfrukällan the virgin spring', 2000, 'The Virgin Spring marks one of Ingmar Bergman''s most controversial dramas, although its uncomfortable exploration of divine justice -- or lack thereof -- is undeniably thought-provoking.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jungle', 2017, 'Daniel Radcliffe does right by Jungle''s fact-based story with a clearly committed performance, even if the film around him doesn''t always match his efforts.', TO_DATE('2017-08-03', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jungle 2 jungle', 1997, 'Tim Allen spends Jungle 2 Jungle annoyed and put upon, mirroring audiences'' reaction as they struggle through this witless family comedy.', TO_DATE('1997-03-07', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the jungle book 2', 2003, 'This inferior rehash of The Jungle Book should have gone straight to video.', TO_DATE('2003-02-08', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('juno', 2007, 'One of the brightest, funniest comedies of the year, Juno''s smart script and direction are matched by assured performances in a coming of age story with a 21st century twist.', TO_DATE('2007-09-02', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jupiter ascending', 2015, 'Pleasing to the eye but narratively befuddled, Jupiter Ascending delivers another visually thrilling misfire from the Wachowskis.', TO_DATE('2015-02-02', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jurassic park', 2000, 'Jurassic Park is a spectacle of special effects and life-like animatronics, with some of Spielberg''s best sequences of sustained awe and sheer terror since Jaws.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jurassic park iii', 2001, 'Jurassic Park III is darker and faster than its predecessors, but that doesn''t quite compensate for the franchise''s continuing creative decline.', TO_DATE('2001-07-09', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jurassic world', 2013, 'Jurassic World can''t match the original for sheer inventiveness and impact, but it works in its own right as an entertaining -- and visually dazzling -- popcorn thriller.', TO_DATE('2013-04-23', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jurassic world fallen kingdom', 2018, 'Jurassic World: Fallen Kingdom adds another set piece-packed entry to the blockbuster franchise, although genuinely thrilling moments are in increasingly short supply.', TO_DATE('2018-06-05', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the juror', 1996, 'Self-serious despite its abundance of trite twists, The Juror is a drab thriller that audiences may hold in contempt.', TO_DATE('1996-02-02', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kærlighed på film just another love story', 2008, 'An intense foreign language noir, Just Another Love Story uses some generic methods to tell its tale of mistaken identity but is sharply entertaining nonetheless.', TO_DATE('2008-01-30', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('just a kiss', 2002, 'With annoying characters and gimmicks, the romantic comedy Just a Kiss is neither touching nor funny.', TO_DATE('2002-07-29', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('just cause', 1994, 'Just Cause you round up a phenomenal cast, that doesn''t mean you have everything you need for a solid legal thriller -- and this film is forgettable proof.', TO_DATE('1994-06-01', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('just friends', 2005, 'There are moments of mirth in this overly broad comedy, but mostly, Just Friends is just not that funny.', TO_DATE('2005-11-17', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('just getting started', 2017, 'A thoroughly unfunny misfire, Just Getting Started manages the incredible feat of wasting more than a century of combined acting experience from its three talented leads.', TO_DATE('2017-12-08', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('just go with it', 2011, 'Just Go With It may be slightly better than some entries in the recently dire rom-com genre, but that''s far from a recommendation.', TO_DATE('2011-02-09', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('just like heaven', 2005, 'Delightfully sweet like a lollipop, Just Like Heaven is a dreamy romantic comedy that may give you a toothache when it attempts to broach difficult end of life issues by throwing a cherry on top.', TO_DATE('2005-09-07', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('just married', 2003, 'Just Married''s plot is predictable, and the overdone pratfalls get tiresome.', TO_DATE('2003-01-01', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('just mercy', 2019, 'Just Mercy dramatizes a real-life injustice with solid performances, a steady directorial hand, and enough urgency to overcome a certain degree of earnest advocacy.', TO_DATE('2019-09-07', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('just my luck', 2006, 'Just My Luck asks little of its leads and less of its audience, adding up to a middling teen rom-com that sorely lacks sparks.', TO_DATE('2006-05-09', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('just visiting', 2000, 'This remake of the French comedy Les Visiteurs ends up being a middling, forgettable effort -- not as good as the original.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('just wright', 2010, 'Well-intentioned but formulaic, Just Wright has winning leads but can''t overcome its preponderance of cliches.', TO_DATE('2010-05-10', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seeking justice', 2011, 'Seeking Justice is nothing more than a typical potboiler with another phoned-in performance by Nicolas Cage.', TO_DATE('2011-11-15', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('justice league', 2017, 'Justice League leaps over a number of DC movies, but its single bound isn''t enough to shed the murky aesthetic, thin characters, and chaotic action that continue to dog the franchise.', TO_DATE('2017-11-15', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('justin bieber never say never', 2011, 'As a tour documentary, it''s rather uninspired -- but as a 3D glimpse of a building pop culture phenomenon, Never Say Never is undeniably entertaining.', TO_DATE('2011-02-08', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('juwanna mann', 2002, 'With its tired premise, Juwanna Mann''s jokes fall flat.', TO_DATE('2002-06-17', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('k19 the widowmaker', 2002, 'A gripping drama even though the filmmakers have taken liberties with the facts.', TO_DATE('2002-06-28', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kabluey', 2008, 'An effecting treatise on modern alienation, Scott Prendergast''s story of a hapless loser who finds recognition by donning a featureless suit is full of whimsy and sorrow.', TO_DATE('2008-04-03', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kaboom', 2010, 'Jumbled and shallow yet easy to watch, Kaboom is a one-night stand that isn''t meant to lead anywhere -- but is fun enough while it lasts.', TO_DATE('2010-05-28', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kaena the prophecy', 2004, 'Though Kaena: The Prophecy is visually inventive, its story is incoherent, derivative, and dull.', TO_DATE('2004-04-29', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kagemusha', 2002, 'Epic in scope and awash with striking color, Kagemusha marks Akira Kurosawa''s successful return to the samurai epic.', TO_DATE('2002-07-09', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kalifornia', 2000, 'Visually strong and featuring a potently feral performance from Brad Pitt, Kalifornia is a tonally uneven thriller marked by all-too-obvious themes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kama sutra a tale of love', 1996, 'Kama Sutra refreshingly approaches sensuality from a female perspective, but audiences will be turned off by this romance''s silly plotting.', TO_DATE('1996-09-11', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kangaroo jack', 2003, 'The humor is gratingly dumb, and Kangaroo Jack contains too much violence and sexual innuendo for a family movie.', TO_DATE('2003-01-11', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the karate kid', 2000, 'Utterly predictable and wholly of its time, but warm, sincere, and difficult to resist, due in large part to Pat Morita and Ralph Macchio''s relaxed chemistry.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the karate kid', 2010, 'It may not be as powerful as the 1984 edition, but the 2010 Karate Kid delivers a surprisingly satisfying update on the original.', TO_DATE('2010-03-17', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the karate kid part ii', 2001, 'Like countless sequels, The Karate Kid Part II tries upping the stakes without straying too far from formula -- and suffers diminishing returns as a result.', TO_DATE('2001-01-01', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kate leopold', 2001, 'Though Jackman charms, Kate and Leopold is bland and predictable, and the time travel scenario lacks inner logic.', TO_DATE('2001-12-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('katy perry part of me', 2012, 'Katy Perry: Part of Me succeeds on the strengths of the pop star''s genuine likability, inspiring work ethic, and dazzling stage show, even if it plays somewhat like a PR puff piece at times.', TO_DATE('2012-06-23', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kazaam', 2000, 'Crafted from a mix of genre clichés, Kazaam doesn''t know what kind of film it wants to be, and Shaq''s larger-than-life charisma is stifled by rote filmmaking and an unimaginative story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('keane', 2004, 'The scrutinizing camera angles of Keane might at first feel too close for comfort, but this powerful portrait of a man distraught by the abduction of his child plumbs the depths of mental illness and the corners of fleabag hotels in an intimate and touching examination of the seedier side of life.', TO_DATE('2004-10-11', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('keanu', 2016, 'Keanu''s absurd premise and compulsively watchable starring duo add up to an agreeably fast-paced comedy that hits more than enough targets to make up for the misses.', TO_DATE('2016-03-13', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kedi', 2016, 'Kedi is a cat fancier''s dream, but this thoughtful, beautifully filmed look at Istanbul''s street feline population offers absorbing viewing for filmgoers of any purr-suasion.', TO_DATE('2016-12-15', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('keep on keepin on', 2014, 'Offering keen observations and infectious warmth, Keep On Keepin'' On is a joy for jazz buffs and novices alike.', TO_DATE('2014-08-06', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('keep the lights on', 2012, 'Keep the Lights On is a mysterious, sexy journey deep into the love affair of two men that always manages to stay true to life.', TO_DATE('2012-01-24', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('keep the river on your right', 2000, 'Keep the River on Your Right places the spotlight on a fascinating individual, Tobias Schneebaum.', TO_DATE('2000-04-15', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('keeping the faith', 2000, 'A dramedy featuring an unusual love triangle, Keeping the Faith is a perceptive look at how religion affects us in everyday life.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('keeping up with the joneses', 2016, 'Keeping Up with the Joneses squanders a decent premise -- and a talented cast full of funny people -- on a witless and largely laugh-free suburban spy adventure.', TO_DATE('2016-10-18', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('keeping up with the steins', 2006, 'Keeping Up With the Steins is one of those comedies that play more like a corny sitcom than a theatrical movie.', TO_DATE('2006-05-09', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kelly cal', 2014, 'Kelly & Cal is a compellingly offbeat treat for fans of character-driven drama -- and a showcase for Juliette Lewis'' formidable gifts.', TO_DATE('2014-08-18', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kellys heroes', 2000, 'Kelly''s Heroes subverts its World War II setting with pointed satirical commentary on modern military efforts, offering an entertaining hybrid of heist caper and battlefield action.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kentucky fried movie', 2000, 'The now obscure pop culture references and spoofed commercials add to Kentucky Fried Movies anarchic, anything-goes spirit and wit.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kes', 2003, 'A harrowing coming of age tale told simply and truly, Kes is a spare and richly humane tribute to the small pockets of beauty to be found in an oppressive world.', TO_DATE('2003-05-28', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kevin hart let me explain', 2013, 'It''s ironically rather short on standup from Mr. Hart himself, but structural problems aside, Kevin Hart: Let Me Explain offers another example of why he''s achieved mainstream success on his own terms.', TO_DATE('2013-07-01', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kevin hart what now', 2016, 'Kevin Hart: What Now? packs in enough of the comedian''s infectious energy to more than compensate for the lulls in a stand-up set that doesn''t quite rank with his best.', TO_DATE('2016-10-12', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('key largo', 2000, 'Humphrey Bogart and Lauren Bacall are at the mercy of Edward G. Robinson''s menacing gangster -- and so is the audience in this enthralling chamber piece.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kickass 2', 2013, 'Kick-Ass 2 falls short in its attempt to emulate the original''s unique blend of ultra-violence and ironic humor.', TO_DATE('2013-08-12', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kicking screaming', 2005, 'The script is mediocre and fails to give Ferrell a proper comedic showcase.', TO_DATE('2005-05-08', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a kid in king arthurs court', 2000, 'Disappointing even by the relaxed standards of live-action children''s entertainment, A Kid in King Arthur''s Court stands as a rare near-total misfire from Disney.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kid stays in the picture', 2002, 'Though not objective by any means, The Kid Stays in the Picture is irresistibly entertaining.', TO_DATE('2002-04-09', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kidnap', 2017, 'Kidnap strays into poorly scripted exploitation too often to take advantage of its pulpy premise -- or the still-impressive talents of its committed star.', TO_DATE('2017-08-01', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kidnapped', 2011, 'Technically impressive yet narratively repellent, the unremittingly grim and violent Kidnapped will prove difficult for many viewers to take.', TO_DATE('2011-04-26', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kidnapping mr heineken', 2015, 'Dull and devoid of characterization, Kidnapping Mr. Heineken is a true crime thriller that rings false.', TO_DATE('2015-02-27', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kids for cash', 2013, 'Dispassionately presented yet frequently enraging, Kids for Cash uses the fallout from one horrific scandal to offer a thought-provoking critique of the justice system in general.', TO_DATE('2013-12-02', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kiki', 2016, 'Kiki compassionately captures a scene on the social margins, offering -- and demanding -- respect and empathy for people to whom it''s too often denied.', TO_DATE('2016-01-26', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kikis delivery service', 2002, 'Kiki''s Delivery Service is a heartwarming, gorgeously-rendered tale of a young witch discovering her place in the world.', TO_DATE('2002-10-09', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kill bill volume 1', 2003, 'Kill Bill is admittedly little more than a stylish revenge thriller -- albeit one that benefits from a wildly inventive surfeit of style.', TO_DATE('2003-05-24', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kill bill volume 2', 2004, 'Kill Bill: Volume 2 adds extra plot and dialogue to the action-heavy exploits of its predecessor, while still managing to deliver a suitably hard-hitting sequel.', TO_DATE('2004-04-05', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kill list', 2011, 'Kill List is an expertly executed slow-burn crime thriller that thrives on tension before morphing into visceral horror.', TO_DATE('2011-03-31', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kill me three times', 2014, 'Kill Me Three Times offers Simon Pegg an opportunity to play against type as a villain; unfortunately, its derivative storyline fails to offer much of anything to viewers.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kill the irishman', 2011, 'Kill the Irishman may not add much in the way of new ingredients to its crowded genre, but the admirable efforts of a solidly assembled cast add extra depth to a familiar story.', TO_DATE('2011-03-04', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kill the messenger', 2014, 'Kill the Messenger''s potent fury over the tale of its real-life subject overrides its factual inaccuracies and occasional narrative stumbles.', TO_DATE('2014-09-26', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kill your darlings', 2013, 'Bolstered by the tremendous chemistry between Daniel Radcliffe and Dane DeHaan, Kill Your Darlings casts a vivid spotlight on an early chapter in the story of the Beat Generation.', TO_DATE('2013-01-20', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kill your friends', 2015, 'Kill Your Friends takes futile stabs at black comedy, all strangled by a glut of tonal jumbles, bad casting, and unremittingly unlikable characters.', TO_DATE('2015-09-12', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('killer elite', 2011, 'A rote, utterly disposable Jason Statham vehicle that just happens to have Clive Owen and Robert De Niro in it.', TO_DATE('2011-09-09', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('killer joe', 2011, 'Violent, darkly comic, and full of strong performances, Killer Joe proves William Friedkin hasn''t lost his touch, even if the plot may be too lurid for some.', TO_DATE('2011-09-08', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('killer klowns from outer space', 2002, 'Killer Klowns from Outer Space''s title promises darkly goofy fun -- and more often than not, the movie delivers.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('killers', 2010, 'Dull, formulaic, and chemistry-free, Killers is an action/comedy that''s largely bereft of thrills or laughs.', TO_DATE('2010-06-04', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the killing', 2000, 'An expertly crafted noir with more on its mind than stylishly staged violence, The Killing establishes Stanley Kubrick as a filmmaker of uncommon vision and control.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the killing fields', 2000, 'Artfully composed, powerfully acted, and fueled by a powerful blend of anger and empathy, The Killing Fields is a career-defining triumph for director Roland Joffé and a masterpiece of American cinema.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('killing ground', 2017, 'Killing Ground unnerves and compels in equal measure with a grimly intense story that may be too disturbing for some but delivers a white-knuckle experience for fans of brutally realistic thrillers.', TO_DATE('2017-01-21', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('killing gunther', 2017, 'Despite a game cast led by an enjoyably over the top Arnold Schwarzenegger, Killing Gunther feels like a sketch overstretched to feature length.', TO_DATE('2017-09-28', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('killing me softly', 2002, 'Respected director Chen Kaige''s first English-language film is a spectacularly misguided erotic thriller, with ludicrous plot twists and cringe-worthy dialogue.', TO_DATE('2002-05-05', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the killing of a chinese bookie', 2000, 'Ben Gazzarra gives a grand performance as a hard-pressed debtor with delusions of grandeur in this naturalistic and tense thriller.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('killing them softly', 2012, 'Killing Them Softly is a darkly comic, visceral thriller that doubles as a cautionary tale on capitalism, whose message is delivered with sledgehammer force.', TO_DATE('2012-05-22', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('killing zoe', 2000, 'Senselessly violent and mean-spirited, Killing Zoe fails to deliver a much needed cleverness to back up its hyper-stylized flourishes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kin', 2018, 'Part family drama, part sci-fi adventure, Kin struggles to balance its narrative until a late twist that suggests it all might have worked better as the first episode of a TV series.', TO_DATE('2018-08-28', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kind hearts and coronets', 2000, 'Performed with chameleonic brio by Alec Guinness, Kind Hearts and Coronets is a triumphant farce.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kindergarten cop', 1990, 'Arnold Schwarzenegger substitutes his action brio with some refreshingly adept comedic timing, but Kindergarten Cop is too grim for children and too cloying for adults.', TO_DATE('1990-12-21', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('king arthur legend of the sword', 2017, 'King Arthur: Legend of the Sword piles mounds of modern action flash on an age-old tale -- and wipes out much of what made it a classic story in the first place.', TO_DATE('2017-05-09', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('king in the wilderness', 2018, 'Refreshingly frank and soberingly insightful, King in the Wild goes beyond the myth and finds the human being who inspired the world.', TO_DATE('2018-01-23', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('king jack', 2015, 'Hard-hitting and honest yet sensitive, King Jack is an uncommonly affecting coming-of-age drama and a powerful calling card for debuting writer-director Felix Thompson.', TO_DATE('2015-06-19', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('king kong', 2005, 'Featuring state-of-the-art special effects, terrific performances, and a majestic sense of spectacle, Peter Jackson''s remake of King Kong is a potent epic that''s faithful to the spirit of the 1933 original.', TO_DATE('2005-12-02', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('king of california', 2007, 'A quirky and often touching comedy about a mature teenager and her manic depressive father, King of California is a charming tale of familial relations and treasure hunting.', TO_DATE('2007-01-27', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('king of devils island', 2011, 'Scandinavian in the most bleakly satisfying way, King of Devil''s Island satisfies with a richly layered narrative and a typically strong performance from Stellan Skarsgard.', TO_DATE('2011-02-14', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the king of kong a fistful of quarters', 2007, 'The King of Kong is funny and compelling with more than a few poignant insights into human behavior. Director Seth Gordon presents the dueling King Kong players in all their obsessive complexity and with perfectly al dente observations.', TO_DATE('2007-03-13', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('king of new york', 1990, 'King of New York covers familiar narrative ground with impressive style -- and leaves plenty of room for its talented cast to deliver gripping performances.', TO_DATE('1990-09-28', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('king of thieves', 2018, 'King of Thieves unites an incredible cast for a heist movie brimming with potential -- most of which, sadly, evaporates long before the end credits have started to roll.', TO_DATE('2018-09-05', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kingdom come', 2001, 'While it has its moments, Kingdom Come is marred by a script that''s low on laughs and uneven in tone.', TO_DATE('2001-04-05', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kingdom of heaven', 2005, 'Although it''s an objective and handsomely presented take on the Crusades, Kingdom of Heaven lacks depth.', TO_DATE('2005-04-27', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kings', 2017, 'Kings has good intentions, a talented cast, and the basis for an incredible fact-based story; unfortunately, they don''t amount to much more than a missed opportunity.', TO_DATE('2017-09-14', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kings ransom', 2005, 'Filled with crass dialogue, unlikable characters, and overdone slapstick gags, King''s Ransom is an utterly inept would-be comedy.', TO_DATE('2005-04-21', 'YYYY-MM-DD'), 2.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kingsman the golden circle', 2017, 'Kingsman: The Golden Circle offers more of everything that made its predecessor so much fun, but lacks the original''s wild creative spark.', TO_DATE('2017-09-18', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kingsman the secret service', 2014, 'Stylish, subversive, and above all fun, Kingsman: The Secret Service finds director Matthew Vaughn sending up the spy genre with gleeful abandon.', TO_DATE('2014-12-27', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kinky boots', 2005, 'Kinky Boots relies heavily on the Full Monty formula of Britcoms, while playing it too safe in a desperate attempt not to offend. Ejiofor''s performance is its redeeming virtue.', TO_DATE('2005-10-08', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kinsey', 2004, 'A biopic of the sex researcher is hailed as adventurous, clever, and subversive, with fine performances by Liam Neeson and Laura Linney.', TO_DATE('2004-09-11', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('winter sleep', 2014, 'Epic in length, thrilling to behold, and utterly absorbing, Winter Sleep demands -- and rewards -- viewers'' patient attention.', TO_DATE('2014-05-16', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kiss kiss bang bang', 2005, 'Tongue-in-cheek satire blends well with entertaining action and spot-on performances in this dark, eclectic neo-noir homage.', TO_DATE('2005-05-13', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kiss of the dragon', 2001, 'A formulaic actioner that''s sure to please action fans. Those looking for plot, believability, or character development will have difficulty finding them.', TO_DATE('2001-06-25', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kiss of the spider woman', 1985, 'Kiss of the Spider Woman weaves an alluring exploration of sexual and societal norms that''s further elevated by strong work from William Hurt and Raul Julia.', TO_DATE('1985-08-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kiss the girls', 1997, 'Detective Alex Cross makes his inauspicious cinematic debut in Kiss the Girls, a clunky thriller that offers few surprises.', TO_DATE('1997-10-03', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kissing jessica stein', 2001, 'A trite but refreshing and comical spin on nature of love.', TO_DATE('2001-09-28', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kit kittredge an american girl', 2008, 'Refreshingly sweet and sincere, Kit''s doll-and-book-inspired do-good mystery may be geared towards the tween girl but will please audiences of all ages.', TO_DATE('2008-06-13', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kitchen stories', 2003, 'By turns touching and funny, this Norwegian import offers quietly absorbing commentary on modern life and friendship.', TO_DATE('2003-10-22', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kite runner', 2007, 'Despite some fine performances, The Kite Runner is just shy of rendering the magic of the novel on to the big screen.', TO_DATE('2007-10-04', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kites', 2010, 'Thoroughly overwrought in true Bollywood fashion, Kites is deeply flawed -- and too effervescently charming to resist.', TO_DATE('2010-05-19', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('klaus', 2019, 'Beautiful hand-drawn animation and a humorous, heartwarming narrative make Klaus an instant candidate for holiday classic status.', TO_DATE('2019-11-05', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('klovn the movie klown', 2012, 'Klown will go too far for many viewers, but anyone with a fondness for seriously dark, aggressive, and overall inappropriate humor may find it impossible to resist.', TO_DATE('2012-06-20', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('klute', 2000, 'Donald Sutherland is coolly commanding and Jane Fonda a force of nature in Klute, a cuttingly intelligent thriller that generates its most agonizing tension from its stars'' repartee.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('knight day', 2010, 'It''s pure formula, but thanks to its breezy pace and a pair of charming performances from Tom Cruise and Cameron Diaz, Knight and Day offers some agreeably middle-of-the-road summer action.', TO_DATE('2010-06-18', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('knight of cups', 2015, 'Knight of Cups finds Terrence Malick delving deeper into the painterly visual milieu he''s explored in recent efforts, but even hardcore fans may struggle with the diminishing narrative returns.', TO_DATE('2015-02-08', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a knights tale', 2000, 'Once you get past the anachronism, A Knight''s Tale becomes a predictable, if spirited, Rocky on horseback.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('knives and skin', 2019, 'Knives and Skin''s daunting ambitions occasionally elude its grasp, but this remains a powerfully written and uniquely timely coming-of-age thriller.', TO_DATE('2019-02-12', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('knives out', 2019, 'Knives Out sharpens old murder-mystery tropes with a keenly assembled suspense outing that makes brilliant use of writer-director Rian Johnson''s stellar ensemble.', TO_DATE('2019-09-08', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('knock down the house', 2019, 'A galvanizing glimpse behind the scenes of a pivotal election, Knock Down the House should prove engrossing for viewers of all political persuasions.', TO_DATE('2019-01-28', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('knock knock', 2015, 'Knock Knock brings a lot of talent to bear on its satirical approach to torture horror, but not effectively enough to overcome its repetitive story or misguidedly campy tone.', TO_DATE('2015-01-24', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('knock off', 1998, 'Muddled plot; stiff acting.', TO_DATE('1998-09-04', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('knockaround guys', 2002, 'Well-acted, but it''s too derivative.', TO_DATE('2002-09-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('knocked up', 2007, 'Knocked Up is a hilarious, poignant and refreshing look at the rigors of courtship and child-rearing, with a sometimes raunchy, yet savvy script that is ably acted and directed.', TO_DATE('2007-03-13', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('knowing', 2009, 'Knowing has some interesting ideas and a couple good scenes, but it''s weighted down by its absurd plot and over-seriousness.', TO_DATE('2009-03-18', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('knuckle', 2011, 'A gritty documentary that captures the brutality and banality of bare-knuckle fights among Irish Travellers.', TO_DATE('2011-02-08', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kodachrome', 2017, 'Kodachrome gains richer hues due to Ed Harris'' colorful performance, which is enough to enliven a solid if predictable father-son road trip drama.', TO_DATE('2017-09-09', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kon tiki', 2012, 'A well-crafted retelling of an epic true story, Kon Tiki is a throwback to old-school adventure filmmaking that''s exciting and entertaining in spite of its by-the-book plotting.', TO_DATE('2012-11-26', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kong skull island', 2017, 'Offering exhilarating eye candy, solid acting, and a fast-paced story, Kong: Skull Island earns its spot in the movie monster''s mythos without ever matching up to the classic original.', TO_DATE('2017-03-02', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('control kontroll', 2004, 'Kontroll is a smart thriller that''s dark, gritty, and funny.', TO_DATE('2004-10-06', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('korengal', 2014, 'Korengal finds documentarian Sebastian Junger taking another clear-eyed -- and poignantly thought-provoking -- look at the human cost of modern warfare.', TO_DATE('2014-05-26', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('koyaanisqatsi life out of balance', 2001, 'Koyaanisqatsi combines striking visuals and a brilliant score to produce a viewing experience that manages to be formally daring as well as purely entertaining.', TO_DATE('2001-09-20', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kpax', 2001, 'For those who have seen One Flew Over the Cuckoo''s Nest or Starman, K-Pax may not hold anything new. The movie works best as a showcase for Kevin Spacey and Jeff Bridges.', TO_DATE('2001-10-16', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kramer vs kramer', 2000, 'The divorce subject isn''t as shocking, but the film is still a thoughtful, well-acted drama that resists the urge to take sides or give easy answers.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('krampus', 2015, 'Krampus is gory good fun for fans of non-traditional holiday horror with a fondness for Joe Dante''s B- movie classics, even if it doesn''t have quite the savage bite its concept calls for.', TO_DATE('2015-12-03', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('krystal', 2018, 'Krystal hinges -- and ultimately stumbles -- on character behavior that beggars belief, defies logic, and finally runs well beyond the average viewer''s ability to care.', TO_DATE('2018-04-08', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kubo and the two strings', 2016, 'Kubo and the Two Strings matches its incredible animation with an absorbing -- and bravely melancholy -- story that has something to offer audiences of all ages.', TO_DATE('2016-08-11', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kumiko the treasure hunter', 2014, 'Powerfully acted and lovely to look at, Kumiko, the Treasure Hunter offers a treat for cinephiles with a taste for the pleasantly peculiar.', TO_DATE('2014-01-24', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kung fu hustle', 2004, 'Kung Fu Hustle blends special effects, martial arts, and the Looney Toons to hilarious effect.', TO_DATE('2004-09-17', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kung fu panda', 2008, 'Kung Fu Panda has a familiar message, but the pleasing mix of humor, swift martial arts action, and colorful animation makes for winning Summer entertainment.', TO_DATE('2008-05-15', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kung fu panda 3', 2016, 'Kung Fu Panda 3 boasts the requisite visual splendor, but like its rotund protagonist, this sequel''s narrative is also surprisingly nimble, adding up to animated fun for the whole family.', TO_DATE('2016-01-16', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kung fu panda 2', 2011, 'The storyline arc may seem a tad familiar to fans of the original, but Kung Fu Panda 2 offers enough action, comedy, and visual sparkle to compensate.', TO_DATE('2011-05-22', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kung pow enter the fist', 2002, 'A short sketch''s worth of jokes stretched into a full-length feature.', TO_DATE('2002-01-18', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kurt cobain about a son', 2006, 'With a constant voiceover of his own words, About A Son is a deeply personal look into Cobain''s life that is sure to please his many fans.', TO_DATE('2006-09-19', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kurt cobain montage of heck', 2015, 'Kurt Cobain: Montage of Heck makes a persuasive case for its subject without resorting to hagiography -- and includes plenty of rare and unreleased footage for fans.', TO_DATE('2015-01-26', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kaidan kwaidan ghost stories', 2000, 'Exquisitely designed and fastidiously ornate, Masaki Kobayashi''s ambitious anthology operates less as a frightening example of horror and more as a meditative tribute to Japanese folklore.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('liceberg', 2006, 'Relying more on inventive slapstick than dialogue for its humor, L''iceberg is an irreverent and charming comedy.', TO_DATE('2006-03-21', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the double hour', 2011, 'Rich in atmosphere and cunningly told, The Double Hour is a pleasurable puzzle that will keep audiences guessing throughout.', TO_DATE('2011-03-22', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la bamba', 2000, 'Elevated by a perceptive performance by a perfectly cast Lou Diamond Phillips, La Bamba distills its subject''s creative energy -- and reflects his music''s enduring appeal.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la belle noiseuse', 1991, 'A sensual and hypnotic masterpiece, La Belle Noiseuse luxuriates in its four-hour run time while holding audience attention.', TO_DATE('1991-09-04', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la cage aux folles', 2001, 'La Cage aux Folles is a fine French-Italian farce with flamboyant, charming characters and deep laughs.', TO_DATE('2001-08-15', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the blue room la chambre bleue', 2014, 'The Blue Room proves a sobering study of the dark side of human nature, as well as a coolly assured directorial effort from star and co-writer Mathieu Amalric.', TO_DATE('2014-05-16', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la cienaga', 2001, 'Dense yet impressively focused, La Cienaga is a disquieting look at domestic dissatisfaction - and a powerful calling card for debuting writer-director Lucrecia Martel.', TO_DATE('2001-09-21', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la confidential', 1997, 'Taut pacing, brilliantly dense writing and Oscar-worthy acting combine to produce a smart, popcorn-friendly thrill ride.', TO_DATE('1997-09-19', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la fée the fairy', 2011, 'Nearly as light and magical as its namesake, La Fée (The Fairy) casts a fizzy comedic spell whose sweet charms include a pleasantly tart undercurrent.', TO_DATE('2011-07-22', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la femme nikita nikita', 1990, 'A zany out-of-control thriller that gives lead Anne Parillaud a big character arc and plenty of emotional room to work within.', TO_DATE('1990-02-21', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la grande illusion grand illusion', 2000, 'Jean Renoir''s Grand Illusion is a masterful anti-war statement, bringing humane insight and an undercurrent of ironic humor to an unusual relationship between captor and captive.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la haine', 1996, 'Hard-hitting and breathtakingly effective, La Haine takes an uncompromising look at long-festering social and economic divisions affecting 1990s Paris.', TO_DATE('1996-02-09', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la la land', 2016, 'La La Land breathes new life into a bygone genre with thrillingly assured direction, powerful performances, and an irresistible excess of heart.', TO_DATE('2016-08-31', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la mujer de mi hermano', 2006, 'No better than an R-rated "telenovela," with the requisite love triangle involving uncommonly attractive players and banal plotlines.', TO_DATE('2006-03-28', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la tête en friche my afternoons with margueritte', 2010, 'It''s sentimental and treacly, but that''s not enough to prevent My Afternoons with Margueritte from being truly affecting.', TO_DATE('2010-11-04', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la vie en rose la mome', 2007, 'The set design and cinematography are impressive, but the real achievement of La Vie en Rose is Marion Cotillard''s mesmerizing, wholly convincing performance as Edith Piaf.', TO_DATE('2007-02-14', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('labor day', 2013, 'Kate Winslet and Josh Brolin make for an undeniably compelling pair, but they can''t quite rescue Labor Day from the pallid melodrama of its exceedingly ill-advised plot.', TO_DATE('2013-08-29', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('labyrinth', 1986, 'While it''s arguably more interesting on a visual level, Labyrinth provides further proof of director Jim Henson''s boundless imagination.', TO_DATE('1986-06-27', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ladder 49', 2004, 'Instead of humanizing the firemen, the movie idolizes them, and thus renders them into cardboard characters.', TO_DATE('2004-09-19', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ladies in black', 2018, 'Ladies in Black gleans socially relevant observations from Australian history with entertaining flair, embroidering a tale that touches on immigration and female empowerment with a fashionable pizazz.', TO_DATE('2018-09-10', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ladies in lavender', 2004, 'A charming, if slight, period drama that quietly showcases fine performances by its two stars.', TO_DATE('2004-09-21', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ladrón que roba a ladrón', 2007, 'The light and comic Ladron que roba a Ladron isn''t deep or hugely substantial, but it''s still a very fun heist flick nonetheless.', TO_DATE('2007-08-30', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lady and the tramp', 2000, 'A nostalgic charmer, Lady and the Tramp''s token sweetness is mighty but the songs and richly colored animation are technically superb and make for a memorable experience.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lady bird', 2017, 'Lady Bird delivers fresh insights about the turmoil of adolescence -- and reveals writer-director Greta Gerwig as a fully formed filmmaking talent.', TO_DATE('2017-09-02', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lady eve', 2000, 'A career highlight for Preston Sturges, The Lady Eve benefits from Barbara Stanwyck and Henry Fonda''s sparkling chemistry -- and a script that inspired countless battle-of-the-sexes comedies.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lady in the water', 2006, 'A far-fetched story with little suspense and unconvincing scenarios, Lady In The Water feels contrived, pretentious, and rather silly.', TO_DATE('2006-07-11', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lady j mademoiselle de joncquières', 2018, 'Deliciously decadent, Lady J is a surprisingly subversive romance with incredible production values.', TO_DATE('2018-09-08', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lady macbeth', 2016, 'Lady Macbeth flashes some surprising toughness beneath its period exterior, bolstered by a mesmerizing -- and unforgiving -- central performance by Florence Pugh.', TO_DATE('2016-09-09', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ladyhawke', 2002, 'There''s pacing problems, but Ladyhawke has an undeniable romantic sweep that''s stronger than most fantasy epics of its ilk.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ladykillers', 2004, 'Hanks'' performance in the lead role is inspired, but this is a relatively minor offering from the Coen brothers.', TO_DATE('2004-03-16', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lagaan once upon a time in india', 2001, 'Lagaan is lavish, rousing entertainment in the old-fashioned tradition of Hollywood musicals.', TO_DATE('2001-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lagerfeld confidential', 2007, 'Lagerfeld Confidential is more vanity project than documentary, revealing little of its evasive subject.', TO_DATE('2007-10-16', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('laggies', 2014, 'Laggies may not do as much with its ideas as it could, but it''s buoyed by a winsome performance from Kiera Knightley, as well as Lynn Shelton''s empathetic direction.', TO_DATE('2014-01-18', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lake city', 2008, 'Lake City fails to make use of its accomplished cast, with the story unraveling amid the competing visions of its dual directors.', TO_DATE('2008-04-30', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lake house', 2006, 'The plot of The Lake House is a little too convoluted, and the film fails to pull off the sweeping romance it aims for.', TO_DATE('2006-06-11', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lake of fire', 2006, 'Lake of Fire''s engaging interviews and powerful black-and-white visuals make for a riveting and honest documentary about a very controversial topic.', TO_DATE('2006-09-14', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lake placid', 2000, 'Betty White''s delightful supporting turn may be worth the price of admission alone, but Lake Placid is swamped by a smarmy script and inability to deliver on the creature feature mayhem.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lakeboat', 2000, 'Though not much happens plot-wise, Lakeboat still has a lot to offer for fans of Mamet.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lambert stamp', 2014, 'A sharp accounting of an era framed through the early adventures of the Who and the managers who helped make them famous, Lambert & Stamp should prove fascinating for fans and novices alike.', TO_DATE('2014-01-21', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('land ho', 2014, 'Gently amusing and agreeably modest in scale, Land Ho! uses its stars'' warm chemistry to impart its poignant, quietly effective message.', TO_DATE('2014-01-23', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('land of mine under sandet', 2016, 'Land of Mine uses an oft-forgotten chapter from the aftermath of World War II to tell a hard-hitting story whose period setting belies its timeless observations about bloodshed and forgiveness.', TO_DATE('2016-06-13', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('land of the dead', 2005, 'George A. Romero''s latest entry in his much-vaunted Dead series is not as fresh as his genre-inventing original, Night of the Living Dead. But Land of the Dead does deliver on the gore and zombies-feasting-on-flesh action.', TO_DATE('2005-06-20', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('landline', 2017, 'Landline''s talented cast -- and a fast-paced approach from director/co-writer Gillian Robespierre -- help this charming multi-generational dramedy overcome a familiar storyline.', TO_DATE('2017-01-21', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lantana', 2001, 'Lantana is an intricately plotted character study that quietly shines with authenticity.', TO_DATE('2001-08-28', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lara croft tomb raider', 2000, 'Angelina Jolie is perfect for the role of Lara Croft, but even she can''t save the movie from a senseless plot and action sequences with no emotional impact.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lara croft tomb raider the cradle of life', 2003, 'Though the sequel is an improvement over the first movie, it''s still lacking in thrills.', TO_DATE('2003-07-22', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('largent', 2000, 'Economically told and sweeping in scope, Robert Bresson''s swan song is a haunting indictment of money''s destructive power.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heartbreaker larnacoeur', 2010, 'While definitely on the fluffier side of French comedy, Heartbreaker benefits from never taking itself too seriously -- and from the performance of the ever-charming Romain Duris.', TO_DATE('2010-06-30', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('larry crowne', 2011, 'Despite the relaxed, easy chemistry of stars Tom Hanks and Julia Roberts, Larry Crowne is surprisingly bland and conventional.', TO_DATE('2011-06-27', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('larry the cable guy health inspector', 2006, 'An aggressively lowbrow vehicle for its titular star, this gross-out comedy fails to "git-r-done."', TO_DATE('2006-03-24', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lassie', 2006, 'A beautifully-made retelling of the classic collie tale, one need not be a dog-lover to fall for Lassie.', TO_DATE('2006-02-11', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last action hero', 1993, 'Last Action Hero has most of the right ingredients for a big-budget action spoof, but its scattershot tone and uneven structure only add up to a confused, chaotic mess.', TO_DATE('1993-06-18', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last airbender', 2010, 'The Last Airbender squanders its popular source material with incomprehensible plotting, horrible acting, and detached joyless direction.', TO_DATE('2010-06-30', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last boy scout', 1991, 'The Last Boy Scout is as explosive, silly, and fun as it does represent the decline of the buddy-cop genre.', TO_DATE('1991-12-13', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last castle', 2001, 'The Last Castle is well acted and rousing for the most part, but the story can''t stand up to close scrutiny.', TO_DATE('2001-10-12', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last chance harvey', 2008, 'Last Chance Harvey is an above-average story that graduates to potent romantic drama based on the chemistry and charm of its top-notch performers.', TO_DATE('2008-11-06', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last days', 2005, 'While the minimalist style is not for all viewers, those who prefer experimentalism will find Last Days hypnotic.', TO_DATE('2005-05-13', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last days in the desert', 2015, 'Last Days in the Desert offers enough stately grandeur and spiritual exploration to offset an occasionally ambiguous narrative.', TO_DATE('2015-01-26', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last days in vietnam', 2014, 'As gripping as it is inspiring, Last Days in Vietnam offers a surprisingly fresh -- and heart-wrenching -- perspective on the end of the Vietnam War.', TO_DATE('2014-01-24', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last detail', 2000, 'Very profane, very funny, very ''70s: Director Hal Ashby lets Jack Nicholson and the cast run loose, creating a unique dramedy that''s far out to sea.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last emperor', 2000, 'While decidedly imperfect, Bernardo Bertolucci''s epic is still a feast for the eyes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last exorcism', 2010, 'It doesn''t fully deliver on the chilly promise of its Blair Witch-style premise, but The Last Exorcism offers a surprising number of clever thrills.', TO_DATE('2010-06-25', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last flag flying', 2017, 'Last Flag Flying balances raw drama against refreshing moments of humor in an impeccably cast film that wrestles with questions of patriotism, family, and grief.', TO_DATE('2017-09-28', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last holiday', 2006, 'Although Queen Latifah''s bountiful life-affirming spirit permeates the film, director Wayne Wang is unable to revive this remake with any real flair.', TO_DATE('2006-01-06', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last house on the left', 2000, 'Its visceral brutality is more repulsive than engrossing, but The Last House on the Left nevertheless introduces director Wes Craven as a distinctive voice in horror.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last king of scotland', 2006, 'Forest Whitaker''s performance as real-life megalomaniac dictator Idi Amin powers this fictionalized political thriller, a blunt and brutal tale about power and corruption.', TO_DATE('2006-09-04', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last kiss', 2006, 'You''ll either find the The Last Kiss to be a phony bore or a refreshing take about young 20-somethings at the crossroads between their carefree lifestyle and responsibility. Zach Braff and the rest of the appealing cast make the case for the latter.', TO_DATE('2006-09-06', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last knights', 2015, 'As blandly unimaginative as its title, Last Knights revisits well-worn sword-and-sandal tropes without adding anything new -- or interesting -- to the genre.', TO_DATE('2015-03-25', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last legion', 2007, 'With miscast leads and unoriginal, uninspired dialogue, The Last Legion pales in comparison to the recent cinematic epics it invokes.', TO_DATE('2007-03-14', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last love', 2013, 'Last Love benefits from a typically strong Michael Caine performance, but it''s ultimately too mawkish and dawdling to make much impact.', TO_DATE('2013-10-11', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last man standing', 1996, 'Last Man Standing''s brooding atmosphere and bursts of artfully arranged action prove intriguing yet ultimately insufficient substitutes for a consistently compelling story.', TO_DATE('1996-09-20', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last men in aleppo', 2017, 'Heartbreaking and hopeful, Last Men in Aleppo paints an urgent portrait of war-torn Syria, putting faces on an ongoing and complicated conflict.', TO_DATE('2017-01-21', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last picture show', 2001, 'Making excellent use of its period and setting, Peter Bogdanovich''s small town coming-of-age story is a sad but moving classic filled with impressive performances.', TO_DATE('2001-02-27', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last samurai', 2003, 'With high production values and thrilling battle scenes, The Last Samurai is a satisfying epic.', TO_DATE('2003-07-29', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last sin eater', 2007, 'This earnest Christian parable is undone by its pompous dialogue and cheap FX.', TO_DATE('2007-02-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last stand', 2013, 'There''s nothing particularly distinguished about it, but for Schwarzenegger fans The Last Stand provides perfectly undemanding entertainment.', TO_DATE('2013-01-12', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last station', 2009, 'Michael Hoffman''s script doesn''t quite live up to its famous subject, but this Tolstoy biopic benefits from a spellbinding tour de force performance by Helen Mirren.', TO_DATE('2009-09-05', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last tango in paris', 2000, 'Naturalistic but evocative, Last Tango in Paris is a vivid exploration of pain, love, and sex featuring a typically towering Marlon Brando performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last temptation of christ', 2000, 'The Last Temptation of Christ is a surprisingly straight and passionate affair, one that also seeks to redeem Scorsese''s ''80s career.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last train home', 2010, 'Last Train Home is a haunting, vivid documentary exploring the human toll of China''s economic boom in intimate, unforgettable detail.', TO_DATE('2010-02-26', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last unicorn', 2000, 'The Last Unicorn lacks the fluid animation to truly sparkle as an animated epic, but offbeat characters and an affecting story make it one of a kind for the true believers.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last vegas', 2013, 'The cast of Last Vegas keep things amiably watchable, but the film is mostly a mellower Hangover retread for the older set.', TO_DATE('2013-10-28', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last winter', 2006, 'The Last Winter creatively and effectively uses horror tactics -- fear, tension, anticipation, and just enough gore -- to shock, but never repulse, its audience.', TO_DATE('2006-09-13', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('last year at marienbad lannée dernière à marienbad', 2000, 'Elegantly enigmatic and dreamlike, this work of essential cinema features exquisite cinematography and an exploration of narrative still revisited by filmmakers today.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('latalante', 2000, 'As poetic as it is realistic, Jean Vigo''s L''Atalante passionately deals with relevant themes through the story of two star-crossed lovers.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('late marriage', 2002, 'An observant black comedy about arranged marriages and tradition.', TO_DATE('2002-03-27', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('latter days', 2004, 'A melodramatic plot and character stereotypes turn the movie into a sitcom.', TO_DATE('2004-01-17', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('laurel canyon', 2002, 'Though the movie itself is flawed, McDormand is fantastic as Jane.', TO_DATE('2002-05-18', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('laurence anyways', 2012, 'Passionate and powerfully acted, Laurence Anyways sometimes strains to achieve its narrative ambitions (and fill its three-hour running time), but ultimately succeeds.', TO_DATE('2012-05-19', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lavender hill mob', 2002, 'Fiendishly funny and clever, The Lavender Hill Mob is a top hat Ealing Studios effort.', TO_DATE('2002-07-30', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lavventura', 2000, 'L''Avventura marks a bewitchingly ambiguous milestone in Antonioni''s career -- and European cinema in general.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('law abiding citizen', 2009, 'Unnecessarily violent and unflinchingly absurd, Law Abiding Citizen is plagued by subpar acting and a story that defies reason.', TO_DATE('2009-10-14', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('law of desire', 2000, 'Law of Desire is kinky fun that''s as explosively bright and provocative as ever.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lawless', 2012, 'Grim, bloody, and utterly flawed, Lawless doesn''t quite achieve the epic status it strains for, but it''s too beautifully filmed and powerfully acted to dismiss.', TO_DATE('2012-05-19', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lawless heart', 2002, 'Unconventional and refreshing, this strikingly un-Hollywood film takes a quiet and heartbreaking look at the warmth and inspiration of friendships lost.', TO_DATE('2002-03-08', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lawnmower man', 2000, 'The Lawnmower Man suffers from a predictable, melodramatic script, and its once-groundbreaking visual effects look dated today.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lawrence of arabia', 2000, 'The epic of all epics, Lawrence of Arabia cements director David Lean''s status in the filmmaking pantheon with nearly four hours of grand scope, brilliant performances, and beautiful cinematography.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('laws of attraction', 2004, 'A bland and forgettable copy of Adam''s Rib.', TO_DATE('2004-03-30', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lay the favorite', 2012, 'A clumsy misstep for director Stephen Frears, Lay the Favorite puts all its chips on endearing quirk only to go bust.', TO_DATE('2012-01-23', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('layer cake', 2004, 'A stylized, electric British crime thriller.', TO_DATE('2004-10-19', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lbj', 2016, 'LBJ loses sight of its complicated subject, ignoring the more intriguing aspects of his personality and career in favor of a frustratingly ordinary biopic treatment.', TO_DATE('2016-09-15', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('le cercle rouge', 2003, 'Melville is at the top of his game, giving us his next-to-last entry into the world of deception, crime, and extreme suspense that made him a maestro of the French heist genre.', TO_DATE('2003-01-07', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('le doulos', 2000, 'Striking cinematography and strong performances make Le Doulos a uniquely cool -- and thoroughly satisfying -- neo-noir.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('le havre', 2011, 'Aki Kaurismäki''s deadpan wit hits a graceful note with Le Havre, a comedy/drama that''s sweet, sad, and uplifting in equal measure.', TO_DATE('2011-09-09', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('le passé the past', 2013, 'Beautifully written, sensitively directed, and powerfully acted, The Past serves as another compelling testament to Asghar Farhadi''s gift for finely layered drama.', TO_DATE('2013-05-17', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('le petit lieutenant', 2005, 'A gritty, languidly paced crime drama that blends old-fashioned ambiance with modern cynicism.', TO_DATE('2005-11-16', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('le samouraï', 2000, 'Le Samouraï makes the most of its spare aesthetic, using stylish -- and influential -- direction, solid performances, and thick atmosphere to weave an absorbing story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('le weekend', 2013, 'Topped with bittersweet humor but possessing surprisingly thorny depths, Le Week-End offers a sophisticated, well-acted portrait of late-life struggles and long-term marriage.', TO_DATE('2013-09-16', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the league of extraordinary gentlemen', 2003, 'Just ordinary. LXG is a great premise ruined by poor execution.', TO_DATE('2003-05-24', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a league of their own', 1992, 'Sentimental and light, but still thoroughly charming, A League of Their Own is buoyed by solid performances from a wonderful cast.', TO_DATE('1992-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lean on pete', 2017, 'Lean on Pete avoids mawkish melodrama, offering an empathetic yet clear-eyed portrayal of a young man at a crossroads that confirms Charley Plummer as a major talent.', TO_DATE('2017-09-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('leap', 2017, 'From its bland story to its unremarkable animation, Leap! does little to distinguish itself from a long list of like-minded -- and superior -- family-friendly alternatives.', TO_DATE('2017-03-29', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('leap year', 2010, 'Amy Adams is as appealing as ever, but her charms aren''t enough to keep Leap Year from succumbing to an overabundance of clichés and an unfunny script.', TO_DATE('2010-01-05', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('leap year año bisiesto', 2010, 'Unpredictable, gripping, and ultimately haunting, Leap Year uses a couple''s fraught emotional journey as the narrative fuel for a probing look at societal mores and human needs.', TO_DATE('2010-11-08', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('learning to drive', 2014, 'The story''s a bit predictable, but Learning to Drive is elevated by typically strong work from stars Patricia Clarkson and Ben Kingsley.', TO_DATE('2014-09-15', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('leatherface', 2017, 'Leatherface may wear the skin of a Texas Chainsaw Massacre prequel, but it proves gutless as an origin story and finds little invention in the horror tropes it''s cannibalizing.', TO_DATE('2017-08-27', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('leatherheads', 2008, 'Despite a good premise and strong cast, this pro football romcom is half screwball and half fumble.', TO_DATE('2008-03-28', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('leave it to beaver', 2000, 'Declining to update the television series'' sensibility for modern audiences while lacking in its requisite charm, Leave it to Beaver should have just left these characters in the past.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('leave no trace', 2018, 'Leave No Trace takes an effectively low-key approach to a potentially sensationalistic story -- and further benefits from brilliant work by Ben Foster and Thomasin McKenzie.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('leaving las vegas', 2000, 'Oscar-awarded Nicolas Cage finds humanity in his character as it bleeds away in this no frills, exhilaratingly dark portrait of destruction.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lebanon levanon', 2009, 'A powerful and personal account of war on the front line, writer-director Samuel Maoz takes the viewer inside an Israeli tank to deliver an exhausting, original film.', TO_DATE('2009-03-26', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lee daniels the butler', 2013, 'Gut-wrenching and emotionally affecting, Lee Daniels'' The Butler overcomes an uneven narrative thanks to strong performances from an all-star cast.', TO_DATE('2013-08-07', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('left behind', 2014, 'Yea verily, like unto a plague of locusts, Left Behind hath begat a further scourge of devastation upon Nicolas Cage''s once-proud filmography.', TO_DATE('2014-10-01', 'YYYY-MM-DD'), 1.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('left behind the movie', 2001, 'Poor production values, slow pacing, and an implausible story makes Left Behind a movie only for the faithful.', TO_DATE('2001-01-17', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('legally blonde', 2001, 'Though the material is predictable and formulaic, Reese Witherspoon''s funny, nuanced performance makes this movie better than it would have been otherwise.', TO_DATE('2001-07-02', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('legally blonde 2 red white blonde', 2003, 'This blonde joke is less funny the second time around.', TO_DATE('2003-04-10', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('legend', 2015, 'As a gangster biopic, Legend is deeply flawed, but as a showcase for Tom Hardy -- in a dual role, no less -- it just about lives up to its title.', TO_DATE('2015-09-03', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the legend of bagger vance', 2000, 'Despite the talent involved in The Legend of Bagger Vance, performances are hindered by an inadequate screenplay full of flat characters and bad dialogue. Also, not much happens, and some critics are offended by how the film glosses over issues of racism.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the legend of drunken master jui kuen ii drunken fist ii', 2000, 'Jackie Chan sends up some amazing and entertaining fight sequences in The Legend of Drunken Master.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the legend of hell house', 2001, 'The Legend of Hell House makes up for its disappointing lack of outright scares with a top notch cast and a suitably macabre atmosphere.', TO_DATE('2001-09-26', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('legend of the guardians the owls of gahoole', 2010, 'Legend of the Guardians'' dark tone and dazzling visuals are to be admired, even if they''re ultimately let down by a story that never lives up to its full potential.', TO_DATE('2010-09-20', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the legend of zorro', 2005, 'Zorro can survive a lot of things, but it looks like he can''t survive marriage.', TO_DATE('2005-10-13', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('legendary', 2010, 'Maudlin, predictable, and clichéd, Legendary pins its talented cast under a heavy layer of formulaic schmaltz.', TO_DATE('2010-07-15', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('legends of oz dorothys return', 2014, 'Faced with the choice between staying in or seeing Legends of Oz: Dorothy''s Return, most filmgoers will be forced to conclude that there''s no place like home.', TO_DATE('2014-05-06', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('legends of the fall', 2000, 'Featuring a swoon-worthy star turn by Brad Pitt, Legends of the Fall''s painterly photography and epic sweep often compensate for its lack of narrative momentum and glut of melodramatic twists.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('legion', 2010, 'Despite a solid cast and intermittent thrills, Legion suffers from a curiously languid pace, confused plot, and an excess of dialogue.', TO_DATE('2010-01-21', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lemony snickets a series of unfortunate events', 2004, 'Although it softens the nasty edges of its source material, Lemony Snicket''s A Series of Unfortunate Events is a gothic visual treat, and it features a hilariously manic turn from Jim Carrey as the evil Count Olaf.', TO_DATE('2004-12-06', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lenfant', 2005, 'The Dardennes continue to excel at presenting works of rigorous naturalism, with detached observations of authentic characters that nevertheless resonate with complex moral issues.', TO_DATE('2005-05-24', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sister', 2012, 'Léa Seydoux and Kacey Mottet Klein are exceptional as downtrodden siblings in this sad and wintry character study.', TO_DATE('2012-05-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lenfer dhenrigeorges clouzot henrigeorge clouzots inferno', 2009, 'Combining visually splendid archival footage and insightful testimonials, Inferno heroically brings Henri-Georges Clouzot''s unfinished vision to light.', TO_DATE('2009-11-06', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lenny', 2002, 'Dustin Hoffman inhabits Lenny Bruce with nervy energy in Bob Fosse''s richly stylized telling of the pioneering comedian''s career and downfall.', TO_DATE('2002-04-13', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('léon the professional', 2000, 'Pivoting on the unusual relationship between seasoned hitman and his 12-year-old apprentice -- a breakout turn by young Natalie Portman -- Luc Besson''s Léon is a stylish and oddly affecting thriller.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('leonard cohen im your man', 2005, 'A moving, if somewhat uneven, look at the legendary singer-songwriter, I''m Your Man treats Cohen''s body of work with the reverence it deserves.', TO_DATE('2005-09-12', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('les plages dagnès the beaches of agnes', 2008, 'An enchanting self-portrait by a veteran director, Beach of Agnes is equal parts playful and profound.', TO_DATE('2008-09-03', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('heartbeats', 2010, 'An art film to the max, Heartbeats intriguing and appealing premise is sometimes buried by director Xavier Dolan''s filmmaking flourishes.', TO_DATE('2010-09-13', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the adventures of pinocchio les aventures de pinocchio', 1996, 'The Adventures of Pinocchio is an admirably faithful adaptation of the source material, but it may be too frightening for younger viewers -- and too dull for older ones.', TO_DATE('1996-07-26', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('les misérables', 2012, 'Impeccably mounted but occasionally bombastic, Les Misérables largely succeeds thanks to bravura performances from its distinguished cast.', TO_DATE('2012-12-06', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('less than zero', 2000, 'A couple of standout performances -- notably Robert Downey, Jr. and James Spader -- and a killer soundtrack can''t quite elevate a somewhat superficial adaptation of Bret Easton Ellis'' story of drugged-out LA rich kids.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('let him have it', 2000, 'Led by a gripping performance from Christopher Eccleston, Let Him Have It sounds a compelling call for justice on behalf of its real-life protagonist.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('let it rain parlezmoi de la pluie', 2008, 'Low-key to a fault, Let It Rain blends subtle political commentary with smart, thoroughly French comedy.', TO_DATE('2008-10-15', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('let it snow', 2019, 'Comfortably cliché, Let It Snow wears its influences on its sleeve, but works anyway thanks an excellent ensemble and just the right amount of holiday cheer.', TO_DATE('2019-11-07', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('let me in', 2010, 'Similar to the original in all the right ways -- but with enough changes to stand on its own -- Let Me In is the rare Hollywood remake that doesn''t add insult to inspiration.', TO_DATE('2010-09-11', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('let the fire burn', 2013, 'Smartly edited and heartbreakingly compelling, Let the Fire Burn uses archival footage to uncover a troubling -- and still deeply resonant -- chapter in American history.', TO_DATE('2013-04-24', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('let the right one in', 2008, 'Let the Right One In reinvigorates the seemingly tired vampire genre by effectively mixing scares with intelligent storytelling.', TO_DATE('2008-01-26', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('let the sunshine in un beau soleil intérieur', 2017, 'Let the Sunshine In pairs a powerful performance from Juliette Binoche with a layered drama that presents director Claire Denis at her most assured.', TO_DATE('2017-05-18', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lethal weapon', 2000, 'The most successful installment in a phenomenally successful series, Lethal Weapon helped redefine action movies for the 1980s and 1990s.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lethal weapon 2', 2000, 'Lethal Weapon 2 may sport a thin plot typical of action fare, but its combination of humor and adrenaline, along with the chemistry between its leads, make this a playful, entertaining sequel.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lethal weapon 3', 1992, 'Murtaugh and Riggs remain an appealing partnership, but Lethal Weapon 3 struggles to give them a worthy new adventure as it cranks up the camp along with the mean-spiritedness.', TO_DATE('1992-05-15', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lethal weapon 4', 1998, 'Jet Li''s arrival breathes fresh life into a tired franchise formula -- but not enough to put Lethal Weapon 4 on equal footing with its predecessors.', TO_DATE('1998-07-10', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lets be cops', 2014, 'Damon Wayans, Jr. and Jake Johnson have comedic chemistry; unfortunately, Let''s Be Cops fails to do anything with it.', TO_DATE('2014-08-12', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lets go to prison', 2006, 'Let''s Go to Prison is guilty on all counts of cliched setups, base humor, and failure to ellicit laughs.', TO_DATE('2006-11-17', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('letter from an unknown woman', 1948, 'Golden Age Hollywood romance doesn''t get much better than Letter From an Unknown Woman, a powerful tale of doomed love.', TO_DATE('1948-04-28', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('letters from iwo jima', 2006, 'A powerfully humanistic portrayal of the perils of war, this companion piece to Flags of our Fathers is potent and thought-provoking, and it demonstrates Clint Eastwood''s maturity as a director.', TO_DATE('2006-12-07', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('letters to god', 2010, 'Letters to God''s heartwarming real-life story is lost in a heavy-handed drama that''s too pat and oppressively earnest to effectively tug the heartstrings.', TO_DATE('2010-04-07', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('letters to juliet', 2010, 'Letters to Juliet has a refreshingly earnest romantic charm, but it suffers from limp dialogue and an utter lack of surprises.', TO_DATE('2010-04-26', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('leviathan', 2014, 'Leviathan lives up to its title, offering trenchant, well-crafted social satire on a suitably grand scale.', TO_DATE('2014-05-26', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('leviathan', 2000, 'A deep-sea thriller with an unusually strong cast and potent ideas, Leviathan quickly plunges into an abyss of weak thrills and lame kills.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('leviathan', 2012, 'It moves to its own inscrutable rhythm, but for filmgoers willing to immerse themselves, Leviathan proves a one-of-a-kind viewing experience.', TO_DATE('2012-09-12', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('liam gallagher as it was', 2019, 'Liam Gallagher: As It Was benefits from its outspoken subject''s rough-hewn charm, even if the indulgent end result neglects to dig below the surface.', TO_DATE('2019-06-06', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('liberal arts', 2012, 'While it''s hard not to wish it had a little more bite, Liberal Arts ultimately succeeds as a good-natured -- and surprisingly clever -- look at the addictive pull of nostalgia for our youth.', TO_DATE('2012-01-23', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the libertine', 2005, 'Despite Johnny Depp''s zealous performance, muddled direction and murky cinematography hinder The Libertine.', TO_DATE('2005-04-25', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('liberty heights', 2000, 'A moving film with moments of humor, Liberty Heights succeeds in capturing the feel of the ''50s with great performances and sensitive direction.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('licence to kill', 1989, 'License to Kill is darker than many of the other Bond entries, with Timothy Dalton playing the character with intensity, but it still has some solid chases and fight scenes.', TO_DATE('1989-07-14', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('life of pi', 2012, 'A 3D adaptation of a supposedly "unfilmable" book, Ang Lee''s Life of Pi achieves the near impossible -- it''s an astonishing technical achievement that''s also emotionally rewarding.', TO_DATE('2012-09-28', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('life', 2015, 'Life may frustrate viewers seeking a James Dean biopic with its subject''s intensity, but it remains a diverting, well-acted effort assembled with admirable craft and ambition.', TO_DATE('2015-02-09', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('life', 2017, 'Life is just thrilling, well-acted, and capably filmed enough to overcome an overall inability to add new wrinkles to the trapped-in-space genre.', TO_DATE('2017-03-18', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('life after beth', 2014, 'In spite of Aubrey Plaza''s committed performance, Life After Beth remains a sketch-worthy idea that''s been uncomfortably stretched to feature length.', TO_DATE('2014-01-20', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the life and death of colonel blimp', 2000, 'A moving evocation of both British values and the passage of time, The Life and Death of Colonel Blimp is an epic portrait of a singular character by Powell and Pressburger.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('life animated', 2016, 'Life, Animated offers a heartwarming look at one family''s journey, and a fascinating message that''s more than enough to outweigh its unanswered questions.', TO_DATE('2016-01-23', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the life aquatic with steve zissou', 2004, 'Much like the titular oceanographer, The Life Aquatic with Steve Zissou''s overt irony may come off as smug and artificial -- but for fans of Wes Anderson''s unique brand of whimsy it might be worth the dive.', TO_DATE('2004-11-21', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('life as a house', 2001, 'A manipulative tearjerker, Life as a House benefits from fine performances from the cast.', TO_DATE('2001-09-04', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the life before her eyes', 2007, 'Despite earnest performances, Life Before Her Eyes is a confusing, painfully overwrought melodrama.', TO_DATE('2007-09-10', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('life itself', 2014, 'Rich in detail and warmly affectionate, Life Itself offers a joyful yet poignant tribute to a critical cinematic legacy.', TO_DATE('2014-01-20', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a life less ordinary', 1997, 'A Life Less Ordinary has an intriguing cast and stylish work from director Danny Boyle, but they''re not enough to overcome the story''s fatally misjudged tonal mishmash.', TO_DATE('1997-10-24', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('life of crime', 2013, 'It may not stand shoulder-to-shoulder with the best Elmore Leonard adaptations, but Life of Crime has enough ambling charm -- and a sharp enough cast -- to get by.', TO_DATE('2013-09-12', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the life of david gale', 2003, 'Instead of offering a convincing argument against the death penalty, this implausible, convoluted thriller pounds the viewer over the head with its message.', TO_DATE('2003-02-11', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the life of emile zola', 1937, 'Well-written, well-meaning and solidly acted, The Life of Emile Zola film may ultimately be more earnest than dramatically engaging.', TO_DATE('1937-10-02', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('life of the party', 2018, 'Life of the Party''s good-natured humor and abundance of onscreen talent aren''t enough to make up for jumbled direction and a script that misses far more often than it hits.', TO_DATE('2018-05-10', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('life or something like it', 2002, 'Though Jolie is appealing, Life or Something Like It is too contrived and predictable to convincingly convey its message of stopping to smell the roses.', TO_DATE('2002-01-27', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('life partners', 2014, 'With two appealing leads adrift in a sitcom-worthy plot, Life Partners doesn''t do quite enough to earn viewers'' commitment.', TO_DATE('2014-04-18', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lifeboat', 2000, 'Hitchcock proves he can wring suspense from the most confined of settings aboard a raft teeming with vivid personalities in this maritime thriller.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lifeforce', 2002, 'Brazenly strange and uneven in its execution, Lifeforce is an otherworldly sci-fi excursion punctuated with off-kilter horror flourishes.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('light it up', 2000, 'Soon into the student uprising, the story starts to feel like a warmed over after-school special.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('light of my life', 2019, 'Its deliberate pace may test the patience, but viewers attuned to Light of My Life''s sober wavelength will be rewarded with a thought-provoking chiller.', TO_DATE('2019-02-09', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('light sleeper', 2000, 'Light Sleeper requires patience, but delivers commensurate rewards -- and boasts an absorbing performance from Willem Dafoe.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lights out', 2016, 'Lights Out makes skillful use of sturdy genre tropes -- and some terrific performances -- for an unsettling, fright-filled experience that delivers superior chills without skimping on story.', TO_DATE('2016-06-09', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('like crazy', 2011, 'It has the schmaltzy trappings of my romantic films, but Like Crazy allows its characters to express themselves beyond dialogue, crafting a true, intimate study.', TO_DATE('2011-01-23', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('like father', 2018, 'Like Father unites an alarmingly talented cast for a predictable rom-com that does nothing to counter the negative stereotypes surrounding the genre.', TO_DATE('2018-08-02', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('like father like son', 2013, 'Sensitively written, smartly directed, and powerfully performed, Like Father, Like Son uses familiar-seeming elements to tell a thought-provoking story.', TO_DATE('2013-05-18', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('like me', 2017, 'Like Me stylishly explores some interesting ideas, even if they''re too often consigned to the background in favor of more ordinary violence and gore.', TO_DATE('2017-03-23', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('like mike', 2002, 'A pleasant and innocuous diversion for kids, but adults may have trouble sitting through the movie''s predictable plotlines and schmaltz.', TO_DATE('2002-06-28', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('like someone in love', 2012, 'In his second film outside his native Iran, director Abbas Kiarostami maintains the mysterious, reflective mood of previous triumphs.', TO_DATE('2012-05-20', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('like water for chocolate como agua para chocolate', 1992, 'Like Water for Chocolate plays to the senses with a richly rewarding romance that indulges in magical realism to intoxicating effect.', TO_DATE('1992-04-16', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lila eve', 2015, 'Lila & Eve gets some mileage out of its formidable stars, with Viola Davis in particular proving that she will commandingly commit to any material, but this is a revenge flick served stale due to a lackluster script.', TO_DATE('2015-01-31', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lila says', 2005, 'Lila Says is a vibrantly told coming-of-age story, helped by the sultry charisma of Giocante.', TO_DATE('2005-05-21', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lilo stitch', 2002, 'Edgier than traditional Disney fare, Lilo and Stitch explores issues of family while providing a fun and charming story.', TO_DATE('2002-06-16', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lilting', 2014, 'Skillfully weaving multiple delicate tonal strands into a quietly affecting whole, Lilting serves as a thoroughly compelling calling card for writer-director Hong Khaou.', TO_DATE('2014-01-17', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the limey', 2000, 'Crafted with eccentric moodiness and style by Steven Soderbergh, The Limey is also a gritty neo-noir showcase for the talent of leading man Terence Stamp.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('limitless', 2011, 'Although its script is uneven, Neil Burger directs Limitless with plenty of visual panache, and Bradley Cooper makes for a charismatic star.', TO_DATE('2011-03-12', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the limits of control', 2009, 'A minimalist exercise in not much of anything, The Limits of Control is a tedious viewing experience with little reward.', TO_DATE('2009-04-23', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lincoln', 2012, 'Daniel Day-Lewis characteristically delivers in this witty, dignified portrait that immerses the audience in its world and entertains even as it informs.', TO_DATE('2012-10-09', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lincoln lawyer', 2011, 'It doesn''t offer any twists on the predictable courtroom thriller formula, but with a charming Matthew McConaughey leading its solid cast, The Lincoln Lawyer offers briskly enjoyable entertainment.', TO_DATE('2011-03-09', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('linda ronstadt the sound of my voice', 2019, 'Linda Ronstadt: The Sound of My Voice offers an engaging overview of its subject''s career that should entertain fans and the uninitiated alike.', TO_DATE('2019-04-27', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('linsanity', 2013, 'Linsanity offers a compelling enough look at its basketball star subject for fans and curious viewers, even if it never really delves below the surface.', TO_DATE('2013-02-05', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lion', 2016, 'Lion''s undeniably uplifting story and talented cast make it a moving journey that transcends the typical cliches of its genre.', TO_DATE('2016-09-11', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lions for lambs', 2007, 'Despite its powerhouse cast, Lions for Lambs feels like a disjointed series of lectures, rather than a sharp narrative, and ends up falling flat.', TO_DATE('2007-10-23', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lipstick dynamite the first ladies of wrestling', 2005, 'This documentary on the early days of women''s wrestling features an array of colorful, compelling personalities.', TO_DATE('2005-03-17', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('listen up philip', 2014, 'As thought-provoking as it is uncompromising, Listen Up Philip finds writer-director Alex Ross Perry taking a creative step forward while hearkening back to classic neurotic comedies of ''70s cinema.', TO_DATE('2014-01-23', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little', 2019, 'A disappointingly uneven but overall agreeable spin on a familiar formula, Little benefits from a big heart -- and a story that makes good use of its talented, well-matched cast.', TO_DATE('2019-04-08', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little accidents', 2014, 'Little Accidents has good intentions -- and a talented cast, led by Elizabeth Banks -- but it drowns them under dour melodrama.', TO_DATE('2014-01-23', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little ashes', 2009, 'It has a beautiful cast, but Little Ashes suffers from an uneven tone and a surplus of unintentionally silly moments.', TO_DATE('2009-02-27', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little black book', 2004, 'An obnoxious, awkward mix of romantic comedy and reality show satire.', TO_DATE('2004-07-29', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little boy', 2015, 'Well-meaning but manipulative on a horrifically misguided scale, Little Boy is the rare faith-based film that many viewers may find legitimately offensive.', TO_DATE('2015-04-06', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little buddha', 1994, 'Little Buddha''s storytelling may be too childlike to best service its audacious plot, but Bernardo Bertolucci''s direction and Vittorio Storaro''s cinematography conspire to deliver a visually strong epic.', TO_DATE('1994-05-25', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little caesar', 2000, 'Little Caesar achieves epic stature thanks to Edward G. Robinson''s volcanic charisma, forging a template for the big-screen mobster archetype that''s yet to be surpassed.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little children', 2006, 'Little Children takes a penetrating look at suburbia and its flawed individuals with an unflinching yet humane eye.', TO_DATE('2006-09-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little fockers', 2010, 'As star-studded as it is heartbreakingly lazy, Little Fockers takes the top-grossing trilogy to embarrassing new lows.', TO_DATE('2010-12-16', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little jerusalem', 2005, 'Little Jerusalem struggles to balance its weightier themes against the character study at its core, but it''s elevated by strong performances from its two talented leads.', TO_DATE('2005-12-16', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little joe', 2019, 'Little Joe''s unorthodox approach may baffle horror fans lured in by its premise -- but like its title character, the end result exerts a creepy thrall.', TO_DATE('2019-05-17', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little man', 2006, 'Another gimmicky comedy from the Wayans brothers, Little Man comes with the requisite raunchiness, but forgot to bring the laughs.', TO_DATE('2006-07-11', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little manhattan', 2005, 'Little Manhattan is a sweet story of young love that provides an enlightening if pragmatic view on love and courtship.', TO_DATE('2005-08-29', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little men', 2016, 'Little Men takes a compassionate look at the ways in which adult problems impact childhood friendships -- and offers another affecting New York drama from director Ira Sachs.', TO_DATE('2016-01-26', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little miss sunshine', 2006, 'Little Miss Sunshine succeeds thanks to a strong ensemble cast that includes Greg Kinnear, Steve Carell, Toni Collette, Alan Arkin, and Abigail Breslin, as well as a delightfully funny script.', TO_DATE('2006-01-21', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little monsters', 2019, 'Led by typically outstanding work from Lupita Nyong''o, Little Monsters is a horror/rom-com hybrid that proves the zombie genre still has fresh brains to savor.', TO_DATE('2019-01-28', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little nicky', 2000, 'Despite the presence of a large, talented cast, the jokes in Little Nicky are dumb, tasteless, and not that funny, and Adam Sandler''s character is grating to watch.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little pink house', 2017, 'Little Pink House rises up on the foundation of Catherine Keener''s strong central performance, even if its fact-based story never quite fills in the framework.', TO_DATE('2017-02-07', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little secrets', 2002, 'Little Secrets is wholesome entertainment for the kids, but also rather bland.', TO_DATE('2002-08-17', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little sister', 2016, 'Little Sister subverts indie drama expectations with a refreshingly off-kilter look at family dynamics that makes its points through solid characterizations and earnest effort.', TO_DATE('2016-03-22', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the little vampire', 2000, 'The Little Vampire can''t seem to find the right pitch, with its muddled, jumpy script and badly executed mix of cuteness and fright.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little voice', 1998, 'Little Voice brings its award-winning source material to the screen in style, elevated by a commanding lead performance from Jane Horrocks.', TO_DATE('1998-12-04', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little white lies', 2010, 'Little White Lies luxuriates in the company of its impressive cast and small-scale dilemmas to its detriment, yielding a comedy of initial charm that meanders into boredom.', TO_DATE('2010-09-12', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little women', 2018, 'This updated version of Little Women may hold some appeal for newcomers, but fans of the classic source material have far better adaptations to choose from.', TO_DATE('2018-09-26', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('little woods', 2018, 'Led by standout work from Tessa Thompson, Little Woods tells a grimly absorbing tale that marks a commendable debut for writer-director Nia DaCosta.', TO_DATE('2018-04-19', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('live and let die', 2000, 'While not one of the highest-rated Bond films, Live and Let Die finds Roger Moore adding his stamp to the series with flashes of style and an improved sense of humor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('live by night', 2016, 'Live by Night boasts visual style and an impressive cast, but they''re lost in a would-be crime saga that finds producer, director, and star Ben Affleck revisiting familiar themes to diminishing effect.', TO_DATE('2016-12-21', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('live die repeat edge of tomorrow', 2014, 'Gripping, well-acted, funny, and clever, Edge of Tomorrow offers entertaining proof that Tom Cruise is still more than capable of shouldering the weight of a blockbuster action thriller.', TO_DATE('2014-05-22', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('live flesh carne trémula', 1998, 'Live Flesh surveys the fallout from an act of violence with a mature melodrama that sees Pedro Almodóvar working in surprisingly restrained form.', TO_DATE('1998-01-16', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('live free or die hard', 2007, 'Live Free or Die Hard may be preposterous, but it''s an efficient, action-packed summer popcorn flick with thrilling stunts and a commanding performance by Bruce Willis. Fans of the previous Die Hard films will not be disappointed.', TO_DATE('2007-06-21', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('livein maid', 2007, 'Live-In Maid is an insightful character piece with standout performances and a poignant slice of Argentina life.', TO_DATE('2007-07-17', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the living daylights', 1987, 'Newcomer Timothy Dalton plays James Bond with more seriousness than preceding installments, and the result is exciting and colorful but occasionally humorless.', TO_DATE('1987-06-29', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('living in emergency stories of doctors without borders', 1800, 'An unflinching, inspiring look at amazing bravery and commitment, Living in Emergency disappoints only in leaving the viewer wanting more.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('living in oblivion', 2000, 'Living in Oblivion dives into the folly of filmmaking with a sharp satire that sends up indie cinema while working as an entertaining independent picture in its own right.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('living out loud', 1998, 'Unoriginal, with one-dimensional characters.', TO_DATE('1998-10-30', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lizzie', 2018, 'Lizzie forces audiences to take a new look at a widely known true-crime story -- even if the well-acted end result is never quite as gripping as it could be.', TO_DATE('2018-01-20', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lizzie mcguire movie', 2003, 'Harmless piece of fluff that ought to satisfy fans of the TV show.', TO_DATE('2003-04-26', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lo and behold reveries of the connected world', 2016, 'Lo and Behold: Reveries of the Connected World finds Werner Herzog bringing his distinctive documentarian gifts to bear on a timely topic with typically thought-provoking results.', TO_DATE('2016-01-23', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('local hero', 2000, 'A charmingly low-key character study brought to life by a tremendously talented cast, Local Hero is as humorous as it is heartwarming.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lock stock and two smoking barrels', 2000, 'Lock, Stock, and Two Smoking Barrels is a grimy, twisted, and funny twist on the Tarantino hip gangster formula.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('locke', 2013, 'A one-man show set in a single confined location, Locke demands a powerful performance -- and gets it from a never-more-compelling Tom Hardy.', TO_DATE('2013-09-03', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lockout', 2012, 'Guy Pearce does the best he can with what he''s given, but Lockout is ultimately too derivative and shallow to build on the many sci-fi thrillers it borrows from.', TO_DATE('2012-04-07', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('logan', 2017, 'Hugh Jackman makes the most of his final outing as Wolverine with a gritty, nuanced performance in a violent but surprisingly thoughtful superhero action film that defies genre conventions.', TO_DATE('2017-02-17', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('logan lucky', 2017, 'High-octane fun that''s smartly assembled without putting on airs, Logan Lucky marks a welcome end to Steven Soderbergh''s retirement -- and proves he hasn''t lost his ability to entertain.', TO_DATE('2017-07-24', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('logans run', 2000, 'Logan''s Run overcomes its campier elements and undercooked plot with a bounty of rousing ideas and dashing sci-fi adventure.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('loggerheads', 2005, 'Loggerheads is an understated, quietly moving character study, bolstered by great performances.', TO_DATE('2005-09-24', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lola versus', 2012, 'It''s fun to see Greta Gerwig mature her acting career but Lola Versus -- with its unpleasant characters and completely familiar script -- does not succeed as her first major leading role.', TO_DATE('2012-04-25', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('london boulevard', 2010, 'In spite of its spotless pedigree and a strong sense of visual style, London Boulevard stumbles over its frenetic pace and crowded, clichéd plot.', TO_DATE('2010-11-28', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('london fields', 2015, 'London Fields bungles its beloved source material and an intriguingly eclectic cast, leaving audiences with a would-be neo-noir of interest only to the morbidly curious.', TO_DATE('2015-09-18', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('london has fallen', 2016, 'London Has Fallen traps a talented cast -- and all who dare to see it -- in a mid-1990s basic-cable nightmare of a film loaded with xenophobia and threadbare action-thriller clichés.', TO_DATE('2016-03-02', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('london river', 2009, 'London River is a showcase of dynamite acting that more than overcomes its politically blunt story.', TO_DATE('2009-11-13', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lone survivor', 2013, 'A true account of military courage and survival, Lone Survivor wields enough visceral power to mitigate its heavy-handed jingoism.', TO_DATE('2013-11-12', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the loneliness of the long distance runner', 2000, 'Dry and full of angst, this British New Wave classic features potent social commentary and a star making performance by Tom Courtenay as a textbook example of the "angry young man."', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lonely hearts', 2006, 'Several genres and plotlines intertwine in Lonely Hearts but don''t connect, creating an uneven and unsatisfying film.', TO_DATE('2006-05-02', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lonesome jim', 2005, 'Though Lonesome Jim is leavened by sweet, understated humor, it''s hard to root for such a morose, self-defeating protagonist.', TO_DATE('2005-02-10', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the long kiss goodnight', 1996, 'Smart, sharp-witted, and fueled by enjoyably over-the-top action, The Long Kiss Goodnight makes up in impact what it lacks in consistent aim.', TO_DATE('1996-10-11', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the long riders', 2001, 'With its pared down storytelling, The Long Riders delivers with an evocative atmosphere and artful brutality.', TO_DATE('2001-04-11', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('long shot', 2019, 'A sharp and deceptively layered comedy that''s further fueled by the odd couple chemistry of its leads, this Long Shot largely hits its marks.', TO_DATE('2019-03-10', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('long way north tout en haut du monde', 2016, 'Smart and refreshingly free of sentimentality, Long Way North takes viewers on a beautifully animated adventure grounded in fully realized characters and genuine emotion.', TO_DATE('2016-06-17', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the longest yard', 2005, 'This Yard has some laughs but missing from this remake is the edginess of the original.', TO_DATE('2005-05-12', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the longshots', 2008, 'The Longshots means well, but it''s a largely formulaic affair, rarely deviating from the inspirational sports movie playbook.', TO_DATE('2008-08-19', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('look whos talking', 1989, 'Look Who''s Talking holds some appeal thanks to its affable stars and Amy Heckerling''s energetic direction, but a silly script doesn''t allow wit to get a word in edgewise.', TO_DATE('1989-10-13', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('look whos talking now', 1993, 'Look Who''s Talking Now: Look away.', TO_DATE('1993-11-05', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('looking for comedy in the muslim world', 2005, 'Although the premise seems ripe for laughs, Albert Brooks isn''t ruthless or clever enough to pull it off.', TO_DATE('2005-12-23', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('looking for eric', 2009, 'Ken Loach''s latest is an uplifting, entertaining and amusing socio-drama featuring a match-winning performance from Eric Cantona.', TO_DATE('2009-05-14', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('looking for richard', 1996, 'Looking for Richard is a smart, fascinating behind-the-scenes look at adapting Shakespeare.', TO_DATE('1996-10-11', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('looking glass', 2018, 'Looking Glass gives Nicolas Cage a chance to turn in an atypically understated performance, but this is still a suspense thriller with a fatal dearth of suspense or thrills.', TO_DATE('2018-01-24', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lookout', 2007, 'The Lookout is a genuinely suspenseful and affecting noir due to the great ensemble cast and their complex, realistic characters.', TO_DATE('2007-02-22', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('looney tunes back in action', 2003, 'The plot is a nonsensical, hyperactive jumble and the gags are relatively uninspired compared to the classic Looney Tunes cartoons.', TO_DATE('2003-11-07', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('looper', 2012, 'As thought-provoking as it is thrilling, Looper delivers an uncommonly smart, bravely original blend of futuristic sci-fi and good old-fashioned action.', TO_DATE('2012-09-06', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('l ora di religione il sorriso di mia madre the religion hour my mothers smile', 2002, 'Castellitto''s performance is the strong center of this surreal, fascinating film about a man''s questioning of his religious beliefs and his relation to his mother.', TO_DATE('2002-06-04', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lord of illusions', 2000, 'Lord of Illusions may come as something of a disappointment in the context of writer-director Clive Barker''s best work, but genre fans should be reasonably diverted.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lord of the rings', 2000, 'Ralph Bakshi''s valiant attempt at rendering Tolkein''s magnum opus in rotoscope never lives up to the grandeur of its source material, with a compressed running time that flattens the sweeping story and experimental animation that is more bizarre than magical.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lord of war', 2005, 'While Lord of War is an intelligent examination of the gun trade, it is too scattershot in its plotting to connect.', TO_DATE('2005-09-06', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lords of chaos', 2018, 'Lords of Chaos presents a grimly compelling dramatization of a real-life music scene whose aggressively nihilistic aesthetic spilled over into fatal acts of violence.', TO_DATE('2018-01-27', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lords of dogtown', 2005, 'Lords of Dogtown, while slickly made and edited, lacks the depth and entertaining value of the far superior documentary on the same subject, Dogtown and Z-Boys.', TO_DATE('2005-05-26', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lore', 2012, 'Newcomer Saskia Rosendahl gives an astonishingly assured performance in the title role, and director Cate Shortland establishes a delicate, disturbingly ominous tone in the powerful World War II drama Lore.', TO_DATE('2012-06-09', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lorenzos oil', 1992, 'A harrowing tribute to the heroism of parental love, Lorenzo''s Oil is kept from abject misery by George Miller''s sensitive direction and outstanding performances from Nick Nolte and Susan Sarandon.', TO_DATE('1992-12-30', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lornas silence', 2008, 'Subtle and emotionally bleak, this gripping thriller features the Dardenne brothers'' recognizable penchant for realism and very strong performances.', TO_DATE('2008-09-03', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('loro', 2018, 'Loro uses the larger-than-life exploits of an infamous public figure to present a messily compelling snapshot of how power attracts -- and corrupts.', TO_DATE('2018-09-07', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('los angeles plays itself', 2004, 'A treat for cinephiles, this documentary is a comprehensive, academic, and enlightening film essay concerning Los Angeles and its depiction in the movies.', TO_DATE('2004-03-04', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('los ojos de julia julias eyes', 2010, 'Smart, suspenseful, and visually distinctive, Julia''s Eyes marks another modern Spanish thriller that quickens the pulse while engaging the mind.', TO_DATE('2010-09-16', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('losing isaiah', 1995, 'Losing Isaiah makes an admirable attempt to tackle complex, worthwhile themes, but loses sight of effective storytelling during a descent into melodrama.', TO_DATE('1995-03-17', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the loss of a teardrop diamond', 2008, 'Stodgy and dispiritingly old-fashioned, Teardrop Diamond proves to be no big loss.', TO_DATE('2008-11-07', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lost and delirious', 2001, 'Lost and Delirious becomes exactly that, as the film sinks into overwrought melodrama and cliched, obvious symbolism.', TO_DATE('2001-04-26', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lost boys', 2000, 'Flawed but eminently watchable, Joel Schumacher''s teen vampire thriller blends horror, humor, and plenty of visual style with standout performances from a cast full of young 1980s stars.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lost boys of sudan', 2004, 'The Lost boys of Sudan works as both a riveting documentary and scathing indictment of colonialism.', TO_DATE('2004-02-18', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lost girls', 2020, 'Raw yet rewarding, Lost Girls overcomes uneven storytelling with powerful performances and a willingness to resist easy catharsis.', TO_DATE('2020-01-29', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lost highway', 1997, 'Marking a further escalation in David Lynch''s surrealist style, Lost Highway is a foreboding mystery that arguably leads to a dead end, although it is signposted throughout with some of the director''s most haunting images yet.', TO_DATE('1997-02-21', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lost in america', 2000, 'A satire of the American fantasy of leaving it all behind, Lost in America features some of Albert Brooks'' best, most consistent writing and cultural jabs.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lost in la mancha', 2002, 'A remarkable behind-the-scenes look at a movie that wasn''t, Lost in La Mancha is an incisive, entertaining document of the difficulties inherent in the moviemaking process.', TO_DATE('2002-07-29', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lost in paris paris pieds nus', 2016, 'Lost in Paris is whimsical to a fault, but its fanciful light-heartedness earns the audience''s indulgence with charming performances and an infectious absurdity.', TO_DATE('2016-09-04', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lost in space', 2000, 'Clumsily directed and missing most of the TV series'' campy charm, Lost in Space sadly lives down to its title.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lost in translation', 2003, 'Effectively balancing humor and subtle pathos, Sofia Coppola crafts a moving, melancholy story that serves as a showcase for both Bill Murray and Scarlett Johansson.', TO_DATE('2003-08-08', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lost river', 2014, 'Lost River suggests that debuting writer-director Ryan Gosling may have a bright future as a filmmaker, but it doesn''t hold together well enough to recommend on its own merit.', TO_DATE('2014-05-20', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lost skeleton of cadavra', 2003, 'Lost Skeleton is clever at spoofing B-movies, but the joke isn''t sustainable for its running time.', TO_DATE('2003-08-30', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lost transmissions', 2019, 'Lost Transmissions finds itself occasionally stranded despite solid performances from Simon Pegg and Juno temple.', TO_DATE('2019-04-29', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lost weekend', 2000, 'Director Billy Wilder''s unflinchingly honest look at the effects of alcoholism may have had some of its impact blunted by time, but it remains a powerful and remarkably prescient film.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lost world jurassic park', 2000, 'The Lost World demonstrates how far CG effects have come in the four years since Jurassic Park; unfortunately, it also proves how difficult it can be to put together a truly compelling sequel.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a lot like love', 2005, 'A tiresome rom-com.', TO_DATE('2005-04-08', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('louder than bombs', 2015, 'Louder Than Bombs finds director Joachim Trier using a capable cast in pursuit of some lofty dramatic goals, even if his ambitions occasionally evade his grasp.', TO_DATE('2015-09-11', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('loudquietloud a film about the pixies', 2006, 'Although it''ll be primarily of interest to longtime fans, LoudQUIETloud: A Film About the Pixies also serves as a decent introduction to the band''s music and enduring appeal.', TO_DATE('2006-03-21', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('louis ck 2017', 2017, 'Though he switches up his attire for a more polished look, Louis C.K. remains controversial, addressing hot topics head on in this edgy and daring special.', TO_DATE('2017-04-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love and other drugs', 2010, 'It''s a pleasure to see Hollywood produce a romance this refreshingly adult, but Love and Other Drugs struggles to find a balance between its disparate plot elements.', TO_DATE('2010-10-27', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love', 2015, 'Love sees writer-director Gaspar Noé delivering some of his warmest and most personal work; unfortunately, it''s also among his most undeveloped and least compelling.', TO_DATE('2015-05-28', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love actually', 2003, 'A sugary tale overstuffed with too many stories. Still, the cast charms.', TO_DATE('2003-10-15', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love after love', 2017, 'Love After Love examines the ways in which profound grief can affect a family''s dynamic -- and refuses to settle for pat Hollywood answers, much to the viewer''s benefit.', TO_DATE('2017-04-23', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love and basketball', 2000, 'Confident directing and acting deliver an insightful look at young athletes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love and death', 2002, 'Woody Allen plunks his neurotic persona into a Tolstoy pastiche and yields one of his funniest films, brimming with slapstick ingenuity and a literary inquiry into subjects as momentous as Love and Death.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love friendship', 2016, 'Love & Friendship finds director Whit Stillman bringing his talents to bear on a Jane Austen adaptation -- with a thoroughly delightful period drama as the result.', TO_DATE('2016-01-24', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love mercy', 2014, 'As unconventional and unwieldy as the life and legacy it honors, Love & Mercy should prove moving for Brian Wilson fans while still satisfying neophytes.', TO_DATE('2014-09-08', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love sex', 2000, 'Famke Janssen''s charm fails to rescue the movie from a dull screenplay.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love crime', 2010, 'Director Corneau''s swan song, Love Crime is smart and typically well-directed, but too thin and formulaic to overcome its melodramatic trappings.', TO_DATE('2010-09-14', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love dont cost a thing', 2003, 'A stale, unnecessary remake of Can''t Buy Me Love.', TO_DATE('2003-12-09', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love gilda', 2018, 'Love, Gilda pays gentle, unequivocal tribute to its subject with more than enough of her genuine spirit to compensate for a lack of critical distance or truly fresh insight.', TO_DATE('2018-04-19', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the love guru', 2008, 'The Love Guru features far too many gross-out gags, and too few earned laughs, ranking as one of Mike Myers'' poorest outings.', TO_DATE('2008-06-14', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love happens', 2009, 'Love Happens is a dull, chemistry-free affair that under-utilizes its appealing leads.', TO_DATE('2009-09-16', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love in the time of cholera', 2007, 'Though beautifully filmed, the makers of Love in the Time of Cholera fail to transfer the novel''s magic to the screen.', TO_DATE('2007-10-08', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love is all you need', 2012, 'Undeniably slight and fluffy, Love Is All You Need is redeemed by its picturesque setting and warm performances by Pierce Brosnan and Trine Dyrholm.', TO_DATE('2012-09-12', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love is strange', 2014, 'Held aloft by remarkable performances from John Lithgow and Alfred Molina, Love Is Strange serves as a graceful tribute to the beauty of commitment in the face of adversity.', TO_DATE('2014-01-19', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love liza', 2002, 'Hoffman''s performance is strong, but the lack of character development and story arc makes Love Liza unsatisfying.', TO_DATE('2002-06-05', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love me if you dare', 2003, 'The romantic leads are too obnoxious and self-centered to generate interest or sympathy.', TO_DATE('2003-12-03', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love ranch', 2010, 'Despite its saucy setup and the always marvelous Helen Mirren, Love Ranch is disappointingly flaccid.', TO_DATE('2010-06-21', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love rosie', 2014, 'Lilly Collins and Sam Claflin are appealing, and they give it their all, but they''re undone by Love, Rosie''s silly, clichéd storyline.', TO_DATE('2014-10-18', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love simon', 2018, 'Love, Simon hits its coming-of-age beats more deftly than many entries in this well-traveled genre -- and represents an overdue, if not entirely successful, milestone of inclusion.', TO_DATE('2018-02-26', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love songs', 2007, 'Love Songs is hampered by a lack of focus, but held together by Honore''s deft direction and an engaging cast.', TO_DATE('2007-05-19', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love stinks', 2000, 'This one-dimensional comedy with recycled laughs will have you holding your nose.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love story', 2000, 'Earnest and determined to make audiences swoon, Love Story is an unabashed tearjerker that will capture hearts when it isn''t inducing eye rolls.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love the coopers', 2015, 'Love the Coopers has a talented cast and a uniquely bittersweet blend of holiday cheer in its better moments, but they''re all let down by a script content to settle for cloying smarm.', TO_DATE('2015-11-12', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love the hard way', 2003, 'Love the Hard Way pits an intriguing ensemble against a cliché-riddled storyline, and the actors lose -- along with the audience.', TO_DATE('2003-04-10', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('love wedding repeat', 2020, 'Love Wedding Repeat takes the rough shape of beloved rom-coms from the past, but its beautiful setting and appealing cast can''t compensate for a sodden story.', TO_DATE('2020-04-09', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lovelace', 2013, 'Amanda Seyfried and Peter Sarsgaard do their best with the material, but Lovelace lacks enough depth and conviction to truly do its fascinating subject justice.', TO_DATE('2013-01-23', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('loveless nelyubov', 2017, 'Loveless uses its riveting portrait of a family in crisis to offer thought-provoking commentary on modern life in Russia -- and the world beyond its borders.', TO_DATE('2017-05-18', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('loverboy', 2005, 'The transition from novel to film is awkwardly executed, and Sedgwick''s character, despite the attempts to make her sympathetic, merely comes across as creepy and crazy.', TO_DATE('2005-04-02', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('loves labours lost', 2000, 'Interesting idea, poor execution.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('loving', 2016, 'Loving takes an understated approach to telling a painful -- and still relevant -- real-life tale, with sensitive performances breathing additional life into a superlative historical drama.', TO_DATE('2016-05-16', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('loving pablo', 2017, 'Loving Pablo bungles its seemingly cinematic real-life story -- and a pair of talented stars -- in producing a lurid biopic that adds nothing to the Escobar subgenre.', TO_DATE('2017-09-06', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('loving vincent', 2017, 'Loving Vincent''s dazzling visual achievements make this Van Gogh biopic well worth seeking out -- even if its narrative is far less effectively composed.', TO_DATE('2017-06-15', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('low down', 2014, 'Rich in mood and on-screen talent but lacking in narrative depth, Low Down tells an oft-told tale with a troubling dearth of imagination.', TO_DATE('2014-01-22', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a low down dirty shame', 1994, 'A trifecta of failure for writer-director-star Keenen Ivory Wayans, A Low Down Dirty Shame lives repeatedly and resolutely down to its title.', TO_DATE('1994-11-23', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lower city cidade baixa', 2005, 'This familiar story of a tension-fraught love triangle wavers between brutality and steamy sex.', TO_DATE('2005-08-26', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lowlife', 2017, 'A darkly funny crime chronicle, Lowlife presents a Los Angeles teeming with memorable characters and propulsive style.', TO_DATE('2017-07-22', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lu over the wall yoake tsugeru rû no uta', 2017, 'Lu Over the Wall can be more fun to watch than to follow, but director Masaaki Yuasa''s distinctive visual style offers colorful compensation for an occasionally scattered story.', TO_DATE('2017-06-05', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('luce', 2019, 'Luce brings a stellar ensemble to bear on a satisfyingly complex story that addresses its timely themes in thought-provoking fashion.', TO_DATE('2019-01-28', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lucia lucia', 2003, 'A relatively simple mid-life crisis story is burdened by overly cumbersome plot devices.', TO_DATE('2003-07-22', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lucky break', 2001, 'Lucky Break fails to do anything new with The Full Monty formula.', TO_DATE('2001-08-20', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lucky grandma', 2019, 'Lucky Grandma gives Tsai Chin a long-overdue opportunity to shine in a leading role -- but it''s audiences who are the truly fortunate ones.', TO_DATE('2019-04-29', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lucky number slevin', 2006, 'Trying too hard to be clever in a Pulp Fiction kind of way, this film succumbs to a convoluted plot, overly stylized characters, and dizzying set design.', TO_DATE('2006-01-22', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lucky numbers', 2000, 'Nora Ephron''s attempt at dark comedy is an uneven product, both in terms of the direction and the acting. The characters are unlikable to the point where you don''t care what happens to them, and Ephron condescends to the material.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lucky them', 2013, 'Lucky Them may not quite live up to Toni Collette''s bravura starring performance, but it''s certainly elevated by it.', TO_DATE('2013-09-11', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lucky you', 2007, 'Lucky You tries to combine a romantic story with the high-stakes world of poker, but comes up with an empty hand.', TO_DATE('2007-05-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lucy', 2014, 'Enthusiastic and silly, Lucy powers through the movie''s logic gaps with cheesy thrills plus Scarlett Johansson''s charm -- and mostly succeeds at it.', TO_DATE('2014-07-22', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lucy in the sky', 2019, 'Natalie Portman gives it her all, but it isn''t enough to overcome Lucy in the Sky''s confused approach to its jumbled story.', TO_DATE('2019-09-12', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lumumba', 2001, 'Ebouaney''s fiery performance makes Lumumba compelling.', TO_DATE('2001-03-15', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lust caution', 2007, 'Ang Lee''s Lust, Caution is a tense, sensual and beautifully-shot espionage film.', TO_DATE('2007-08-29', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lust stories', 2018, 'Directed by four talented Indian filmmakers, Lust Stories offers a refreshing and nuanced portrayal of women''s complex desires.', TO_DATE('2018-06-14', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lymelife', 2008, 'Lymelife features sharp performances, but the story lacks the emotional depth or focus worthy of its talented cast.', TO_DATE('2008-09-08', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('m butterfly', 1993, 'David Cronenberg reins in his provocative sensibility and handles delicate material with restraint, yielding a disappointing adaptation that flattens M. Butterfly into a tedious soap opera.', TO_DATE('1993-10-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ma', 2019, 'Octavia Spencer''s performance overpowers many of Ma''s flaws, but uneven pacing and a labored story keep this thriller from fully realizing its unhinged potential.', TO_DATE('2019-05-29', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my life in pink ma vie en rose', 1997, 'Ma Vie en Rose follows a boy''s exploration of his gender identity with warmth and empathy - for its young protagonist as well as the family affected by his journey.', TO_DATE('1997-12-26', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('macgruber', 2010, 'It too often mistakes shock value for real humor, but MacGruber is better than many SNL films -- and better than it probably should be.', TO_DATE('2010-03-16', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('macbeth', 2000, 'Roman Polanski''s Macbeth is unsettling and uneven, but also undeniably compelling.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('macbeth', 2015, 'Faithful to the source material without sacrificing its own cinematic flair, Justin Kurzel''s Macbeth rises on the strength of a mesmerizing Michael Fassbender performance to join the upper echelon of big-screen Shakespeare adaptations.', TO_DATE('2015-05-23', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('machete', 2010, 'Machete is messy, violent, shallow, and tasteless -- and that''s precisely the point of one of the summer''s most cartoonishly enjoyable films.', TO_DATE('2010-08-29', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('machete kills', 2013, 'While possessed with the same schlocky lunacy as its far superior predecessor, Machete Kills loses the first installment''s spark in a less deftly assembled sequel.', TO_DATE('2013-09-20', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('machine gun preacher', 2011, 'There''s a complex man at the center of Machine Gun Preacher but the movie is too shapeless and emotionally vacant to bring his story to life.', TO_DATE('2011-09-08', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the machinist', 2004, 'Brad Anderson''s dark psychological thriller about a sleepless factory worker is elevated by Christian Bale astonishingly committed performance.', TO_DATE('2004-01-20', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mad dog and glory', 1993, 'Inspired casting and a prevailing sweetness make Mad Dog and Glory an oddball treat.', TO_DATE('1993-03-05', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mad hot ballroom', 2005, 'This heartwarming documentary will win audiences over, as the sheer charm of precocious, enthusiastic children learning to dance resonates from the screen.', TO_DATE('2005-04-09', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mad love', 2002, 'An overwrought bodice-ripper, Mad Love is more silly than dramatic.', TO_DATE('2002-01-17', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mad max', 2000, 'Staging the improbable car stunts and crashes to perfection, director George Miller succeeds completely in bringing the violent, post-apocalyptic world of Mad Max to visceral life.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mad max 2 the road warrior', 1981, 'The Road Warrior is everything a bigger-budgeted Mad Max sequel with should be: bigger, faster, louder, but definitely not dumber.', TO_DATE('1981-12-24', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mad max beyond thunderdome', 2000, 'Beyond Thunderdome deepens the Mad Max character without sacrificing the amazing vehicle choreography and stunts that made the originals memorable.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mad max fury road', 2015, 'With exhilarating action and a surprising amount of narrative heft, Mad Max: Fury Road brings George Miller''s post-apocalyptic franchise roaring vigorously back to life.', TO_DATE('2015-05-11', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('madagascar', 2005, 'Though its story is problematic in spots and its humor is hit-or-miss for the adult crowd, Madagascar boasts impressive visuals and enough spunky charm to keep children entertained.', TO_DATE('2005-05-10', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('madagascar 3 europes most wanted', 2012, 'Dazzlingly colorful and frenetic, Madagascar 3 is silly enough for young kids, but boasts enough surprising smarts to engage parents along the way.', TO_DATE('2012-05-18', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('madagascar escape 2 africa', 2008, 'Madagascar: Escape 2 Africa is an improvement on the original, with more fleshed-out characters, crisper animation and more consistent humor.', TO_DATE('2008-11-03', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('madame', 2017, 'Madame''s retrograde trappings are further weighted down by unlikable characters and an overall inability to do justice to its themes.', TO_DATE('2017-06-19', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('madame bovary', 2014, 'Over the years, Flaubert''s Madame Bovary has proven an exceedingly difficult novel to film -- and this version adds another disappointing entry to the list.', TO_DATE('2014-09-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('madame satã', 2003, 'Madame Satã offers an occasionally absorbing look at a pivotal figure in Brazilian culture, even if its subject deserves a more consistent biopic.', TO_DATE('2003-02-12', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('made', 2001, 'Not as good as Swingers, but it''s still witty and goofy enough for some laughs.', TO_DATE('2001-05-03', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('made in dagenham', 2010, 'Organized around a terrific performance by Sally Hawkins, Made in Dagenham is a stirring call for pay equity replete with heart and wit.', TO_DATE('2010-09-13', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('made of honor', 2008, 'Sharp performances by Patrick Dempsey and Michelle Monaghan can''t save this forgettable, formulaic chick flick from its comic failings.', TO_DATE('2008-04-25', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('madea goes to jail', 2009, 'Divided between sincere melodrama and populist comedy, Madea Goes to Jail fails to provide enough laughs -- or screen time -- for its titular heroine.', TO_DATE('2009-02-20', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('madeas family reunion', 2006, 'Tyler Perry''s Madea''s Family Reunion is sincere in its positive intentions, but leaves something to be desired as a film.', TO_DATE('2006-02-20', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('madelines madeline', 2018, 'Madeline''s Madeline proves experimental cinema is alive and well -- and serves as a powerful calling card for Helena Howard in her big-screen debut.', TO_DATE('2018-01-23', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mother madeo', 2009, 'As fleshy as it is funny, Bong Joon-Ho''s Mother straddles family drama, horror and comedy with a deft grasp of tone and plenty of eerie visuals.', TO_DATE('2009-05-17', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('madison', 2002, 'A pedictable and heavy-handed sports drama.', TO_DATE('2002-10-20', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the madness of king george', 1994, 'Thanks largely to stellar all-around performances from a talented cast, The Madness of King George is a funny, entertaining, and immensely likable adaptation of the eponymous stage production.', TO_DATE('1994-12-28', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mafioso', 2006, 'Mafioso begins as an amusing farce and skillfully transforms into a portentous social drama.', TO_DATE('2006-10-18', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the magdalene sisters', 2002, 'A typical women-in-prision film made untypical because it''s based on real events.', TO_DATE('2002-09-20', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maggie', 2015, 'Maggie lurches a bit clumsily at times, but is partially redeemed by strong performances and an unexpectedly thoughtful tone.', TO_DATE('2015-04-22', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maggies plan', 2015, 'With a typically absorbing performance from Greta Gerwig leading the way, Maggie''s Plan gives rom-com sensibilities a smart, subversive twist.', TO_DATE('2015-09-13', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('magic in the moonlight', 2014, 'While far from a failure, Magic in the Moonlight is too slight to stand with Woody Allen''s finest work.', TO_DATE('2014-07-18', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('magic in the water', 2000, 'There might be Magic in the Water during this family-friendly adventure, but precious little of it ended up on the screen.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('magic magic', 2013, 'Magic Magic finds writer-director Sebastián Silva in familiar risk-taking form, ably abetted by Juno Temple and a smartly assembled ensemble cast.', TO_DATE('2013-01-24', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('magic mike', 2012, 'Magic Mike''s sensitive direction, smart screenplay, and strong performances allow audiences to have their beefcake and eat it too.', TO_DATE('2012-06-25', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('magic mike xxl', 2015, 'Magic Mike XXL has enough narrative thrust and beefy charm to deliver another helping of well-oiled entertainment, even if this sequel isn''t quite as pleasurable as its predecessor.', TO_DATE('2015-06-29', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('magic trip', 2011, 'Magic Trip is overall unenlightening, though there''s an inherent novelty and joy in seeing the unearthed footage of Ken Kesey and his band of Merry Pranksters.', TO_DATE('2011-06-20', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('magician the astonishing life and work of orson welles', 2014, 'It may not quite live up to the superlative in its title, but Magician: The Astonishing Life and Work of Orson Welles serves as a passable primer for those seeking an introduction to the legendary filmmaker.', TO_DATE('2014-12-06', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('magnolia', 2000, 'Magnolia is an ambitious, lengthy work that ultimately succeeds due to interesting stories and excellent ensemble performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('magnum force', 2000, 'Magnum Force ups the ante for the Dirty Harry franchise with faster action and thrilling stuntwork.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maid in manhattan', 2002, 'Too blandly generic, Maid in Manhattan also suffers from a lack of chemistry between Lopez and Fiennes.', TO_DATE('2002-11-30', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maiden', 2018, 'Enthralling viewing even for audiences with little to no knowledge of or interest in sailing, Maiden pays powerful tribute to a true pioneer.', TO_DATE('2018-09-09', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mail order wife', 2004, 'The setup for Mail Order Wife is clever, but the movie is only moderately funny, and it stumbles badly in the third act.', TO_DATE('2004-03-25', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the majestic', 2001, 'Ponderous and overlong, The Majestic drowns in forced sentimentality and resembles a mish-mash of other, better films.', TO_DATE('2001-12-15', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('major dundee', 2000, 'Major Dundee is a Western-type with big war scenes, shot with bombast typical of Sam Peckinpah.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('major league', 2000, 'Major League may be predictable and formulaic, but buoyed by the script''s light, silly humor -- not to mention the well-built sports action sequences and funny performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('major league ii', 1994, 'Striking out on every joke, Major League II is a lazy sequel that belongs on the bench.', TO_DATE('1994-03-30', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('make it happen', 2008, 'Cheap, predictable, formulaic and unimaginative generic dance film. Comes across as Showgirls for simpleton teens, but with much less flesh on show.', TO_DATE('2008-08-07', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mala noche', 2003, 'Mala Noche is a raw and gritty portrait of desire, doomed romance, and rejection -- and marks debuting director Gus Van Sant as a filmmaker with a gratifyingly personal touch.', TO_DATE('2003-05-24', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maleficent', 2014, 'Angelina Jolie''s magnetic performance outshines Maleficent''s dazzling special effects; unfortunately, the movie around them fails to justify all that impressive effort.', TO_DATE('2014-05-27', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maleficent mistress of evil', 2019, 'While it''s far from cursed, Maleficent: Mistress of Evil too rarely supports its impressive cast and visuals with enough magical storytelling to justify its existence.', TO_DATE('2019-10-15', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('malibus most wanted', 2003, 'Malibu''s Most Wanted gets a few laughs, but nowhere near enough to sustain its running time.', TO_DATE('2003-04-14', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mallrats', 1995, 'Mallrats colorfully expands the View Askewniverse, even if its snootchie has lost a few of the bootchies boasted by its beloved predecessor.', TO_DATE('1995-10-20', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mama', 2013, 'If you''re into old-school scares over cheap gore, you''ll be able to get over Mama''s confusing script and contrived plot devices.', TO_DATE('2013-01-15', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mambo italiano', 2003, 'A broad, shrill comedy that plays like a sitcom.', TO_DATE('2003-07-30', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mamma mia', 2008, 'This jukebox musical is full of fluffy fun but rough singing voices and a campy tone might not make you feel like "You Can Dance" the whole 90 minutes.', TO_DATE('2008-06-30', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mamma mia here we go again', 2018, 'Mamma Mia! Here We Go Again doubles down on just about everything fans loved about the original -- and my my, how can fans resist it?', TO_DATE('2018-07-18', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a man apart', 2002, 'Action and drama elements don''t mix well in this clichéd actioner.', TO_DATE('2002-10-27', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('man down', 2016, 'Well-intentioned but overall misjudged, Man Down makes an unfortunately muddled attempt to mine thoughtful drama out of modern warfare''s emotional wreckage.', TO_DATE('2016-11-28', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man from elysian fields', 2002, 'This story about a gigolo isn''t plausible or compelling enough.', TO_DATE('2002-07-29', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('jimmy carter man from plains', 2007, 'Man From Plains is a fascinating look at the former president''s recent endeavors.', TO_DATE('2007-09-06', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('man of tai chi', 2013, 'It may not be groundbreaking, but Man of Tai Chi represents an agreeably old-fashioned picture for martial arts fans -- and a solid debut for first-time director Keanu Reeves.', TO_DATE('2013-07-05', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('man of the house', 2005, 'A high-concept movie that plays out like a mediocre TV sitcom.', TO_DATE('2005-02-25', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('man of the year', 2006, 'Weakened by second-half attempts at thriller and romance, this presidential comedy also fails to hit any sharp political notes, resulting in a confused and unsatisfying mess.', TO_DATE('2006-10-06', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('man on a ledge', 2012, 'Uninspired acting and preposterous plotlines defuse Man on a Ledge''s mildly intriguing premise.', TO_DATE('2012-01-23', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('man on fire', 2004, 'Man on Fire starts out well, but goes over the top in the violent second half.', TO_DATE('2004-04-21', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('man on wire', 2008, 'James Marsh''s doc about artist Phililppe Petit''s artful caper brings you every ounce of suspense that can be wrung from a man on a (suspended) wire.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('man push cart', 2006, 'This compassionate portrait of a New York City street vendor is as beautiful as it is melancholy.', TO_DATE('2006-01-18', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('man up', 2015, 'Thanks to fine performances from Lake Bell and Simon Pegg, Man Up largely strikes the deceptively difficult balance between romance and comedy.', TO_DATE('2015-04-20', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man who fell to earth', 2002, 'Filled with stunning imagery, The Man Who Fell to Earth is a calm, meditative film that profoundly explores our culture''s values and desires.', TO_DATE('2002-03-04', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man who shot liberty valance', 1962, 'Featuring a trio of classic leading men and a rich story captured by a director at the peak of his craft, The Man Who Shot Liberty Valance is one of the finest Westerns ever filmed.', TO_DATE('1962-05-28', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man who wasnt there', 2001, 'Stylish but emotionally distant, The Man Who Wasn''t There is a clever tribute to the film noir genre.', TO_DATE('2001-05-15', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('man with a movie camera', 2000, 'Groundbreaking in its exploration of the medium, Man with a Movie Camera is proof that cinema in and of itself can be a source of grand entertainment and sociological value.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man with the golden gun', 1974, 'A middling Bond film, The Man With the Golden Gun suffers from double entendre-laden dialogue, a noteworthy lack of gadgets, and a villain that overshadows 007.', TO_DATE('1974-12-18', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man with two brains', 2002, 'As spastically uneven as its zany title suggests, The Man with Two Brains isn''t peak Steve Martin -- but it''s still often close enough to enjoy.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man without a past', 2002, 'Kaurismäki delivers another droll comedy full of his trademark humor.', TO_DATE('2002-06-05', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('management', 2008, 'Clever and often beguiling performances by Steve Zahn and Jennifer Aniston can''t revive this sweetly misguided stalker romance.', TO_DATE('2008-09-16', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('manakamana', 2013, 'Its tranquil pace will prove jarring for the blockbuster-inclined, but Manakamana rewards patient viewers with a singularly haunting experience.', TO_DATE('2013-09-07', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('manchester by the sea', 2016, 'Manchester by the Sea delivers affecting drama populated by full-bodied characters, marking another strong step forward for writer-director Kenneth Lonergan.', TO_DATE('2016-01-24', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the manchurian candidate', 2004, 'While not the classic its predecessor is, this update is well-acted and conjures a chilling resonance.', TO_DATE('2004-07-16', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('manda bala send a bullet', 2007, 'The exciting and fast-paced documentary Manda Bala shows many sides of Brazil -- from the humorous and upbeat to the violent and disturbing.', TO_DATE('2007-01-20', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mandela long walk to freedom', 2013, 'It might be too respectful to truly soar, but there''s no denying Idris Elba''s impressive work in Mandela: Long Walk to Freedom -- or the inspirational power of the life it depicts.', TO_DATE('2013-09-09', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('manderlay', 2005, 'Manderlay may work better as a political statement than as a film, making its points at the expense of telling a compelling story.', TO_DATE('2005-05-17', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('all the boys love mandy lane', 2006, 'Mandy Lane has enough wit and craft to spark the horror fan''s interest, but is not sufficiently original for mainstream audiences.', TO_DATE('2006-09-13', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mandy', 2018, 'Mandy''s gonzo violence is fueled by a gripping performance by Nicolas Cage -- and anchored with palpable emotion conveyed between his volcanic outbursts.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('manglehorn', 2014, 'Manglehorn boasts a nicely understated performance from Al Pacino, but that isn''t enough to compensate for a slight story and uneven script.', TO_DATE('2014-08-30', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('manhattan', 2000, 'One of Woody Allen''s early classics, Manhattan combines modern, bittersweet humor and timeless romanticism with unerring grace.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maniac', 2012, 'Shocking and bloody. Maniac is smarter than your average psychological slasher, but it''s often undermined by its excessive gore.', TO_DATE('2012-05-28', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('manic', 2002, 'A grim drama about emotionally damaged teens, Manic''s solid cast helps to elevate the material above cliche.', TO_DATE('2002-01-10', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('manifesto', 2017, 'Laugh-out-loud humor and Cate Blanchett''s tour de force performance(s) make Manifesto worth watching, even if the subject matter is too esoteric for all but a few.', TO_DATE('2017-01-24', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('manito', 2002, 'An intimate and moving picture that captures the life of one of Manhattan''s neighborhoods.', TO_DATE('2002-04-24', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('manolo the boy who made shoes for lizards', 2017, 'Manolo will please fashion fans, though its size and scope may not be a perfect fit for all viewers.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mansome', 2012, 'Mansome is a threadbare documentary with little insight into modern male maintenance, with useless celebrity interviews padding an already slim runtime.', TO_DATE('2012-05-15', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('manufactured landscapes', 2006, 'Manufactured Landscapes leaves the work of drawing conclusions mostly to the viewer, although the imagery makes director Jennifer Baichwal''s arguments well enough on its own.', TO_DATE('2006-09-18', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('manuscripts dont burn', 2013, 'Brave, challenging, and brimming with rage, Manuscripts Don''t Burn is a political statement as much as it is a gripping thriller.', TO_DATE('2013-07-10', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('many adventures of winnie the pooh', 2000, 'Perhaps the most faithful of Disney''s literary adaptations, this cute, charming collection of episodes captures the spirit of A.A. Milne''s classic stories.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maos last dancer', 2009, 'Mao''s Last Dancer has a stirring story to tell, but excessive sentimentality and leaden pacing keep this biopic from hitting its marks gracefully.', TO_DATE('2009-09-23', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mapplethorpe', 2018, 'Mapplethorpe''s conventional biopic approach to a decidedly unconventional artist undermines its efforts to convey the gifts that made its subject special.', TO_DATE('2018-04-23', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maps to the stars', 2014, 'Narratively unwieldy and tonally jumbled, Maps to the Stars still has enough bite to satisfy David Cronenberg fans in need of a coolly acidic fix.', TO_DATE('2014-05-18', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marathon man', 2000, 'Marathon Man runs the gamut from patient mystery to pulse-pounding thriller, aided by Laurence Oliver''s coldly terrifying performance and a brainy script by William Goldman.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marauders', 2016, 'From its clichéd story to Bruce Willis'' rote performance, Marauders is a crime thriller content to settle for merely competent -- a goal it all too rarely achieves.', TO_DATE('2016-06-29', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('march of the penguins', 2005, 'Only the most hardened soul won''t be moved by this heartwarming doc.', TO_DATE('2005-05-07', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marci x', 2003, 'The material is too thin for feature-length and the jokes are socially outdated and clueless.', TO_DATE('2003-08-21', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marebito', 2005, 'The scares are lacking in this J-horror flick, and the plot soon turns half-baked.', TO_DATE('2005-11-06', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('margaret', 2011, 'A surfeit of ideas contributes to Margaret''s excessive run time, but Anna Paquin does a admirable job of guiding viewers through emotional hell.', TO_DATE('2011-09-26', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('margin call', 2011, 'Smart, tightly wound, and solidly acted, Margin Call turns the convoluted financial meltdown of ''08 into gripping, thought-provoking drama.', TO_DATE('2011-01-27', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('margot at the wedding', 2007, 'Despite a great cast, the characters in Margot at the Wedding are too unlikable to enthrall viewers.', TO_DATE('2007-09-01', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maria bamford old baby', 2018, 'Maria Bamford delights with her distinct style and impressive onstage confidence, solidifying her status as a contemporary master of comedy.', TO_DATE('2018-01-05', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maria by callas', 2018, 'Maria by Callas offers an intimate look at the life of a brilliantly talented artist whose absorbing story matches the operatic heights reached by her work.', TO_DATE('2018-05-07', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maria full of grace', 2004, 'In a striking debut, Moreno carries the movie and puts a human face on the drug trade.', TO_DATE('2004-01-27', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marianne leonard words of love', 2019, 'It suffers from a somewhat one-sided approach, but Marianne & Leonard: Words of Love is an absorbing glimpse of a fascinating chapter of its subjects'' lives.', TO_DATE('2019-01-30', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marie curie the courage of knowledge', 2017, 'Marie Curie: The Courage of Knowledge may test the patience of some viewers with its deliberate pacing, but this sensitively made biopic has its well-acted rewards.', TO_DATE('2017-02-14', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marigold', 2007, 'Marigold attempts the difficult trick of combining Bollywood movies and American rom-coms -- and ends up with an awkward blend that will satisfy fans of neither.', TO_DATE('2007-08-16', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marilyn hotchkiss ballroom dancing charm school', 2005, 'Clumsily staged and brimming with melodrama and trite self-help cliches, this dance movie stays stuck at amateur level.', TO_DATE('2005-10-31', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the marine', 2006, 'Overblown in every possible way, The Marine is either so bad it''s good or just really, really bad.', TO_DATE('2006-10-13', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marjorie prime', 2017, 'Intimate in setting yet ambitious in scope, the beautifully acted Marjorie Prime poses thought-provoking questions about memory, humanity, and love.', TO_DATE('2017-01-24', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mark felt the man who brought down the white house', 2017, 'Mark Felt may dramatize the man behind Deep Throat, but its stodgy treatment of history offers little insight into the famous whistleblower.', TO_DATE('2017-09-08', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marley', 2012, 'Kevin Macdonald''s exhaustive, evenhanded portrait of Bob Marley offers electrifying concert footage and fascinating insights into reggae''s greatest star.', TO_DATE('2012-02-13', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marley me', 2008, 'Pet owners should love it, but Marley and Me is only sporadically successful in wringing drama and laughs from its scenario.', TO_DATE('2008-12-19', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marmaduke', 2010, 'Dull and unfunny, Marmaduke offers family filmgoers little more than another round of talking animals and scatological humor.', TO_DATE('2010-06-03', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marnie', 2000, 'A coolly constructed mystery revolving around a character who''s inscrutable to a fault, Marnie finds Hitchcock luring audiences deeper into the dark.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marriage story', 2019, 'Observing a splintering union with compassion and expansive grace, the powerfully acted Marriage Story ranks among writer-director Noah Baumbach''s best works.', TO_DATE('2019-08-29', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('married to the mob', 2000, 'Buoyed by Jonathan Demme''s intuitive direction and Michelle Pfeiffer''s irresistible charisma, Married to the Mob is a saucy mix of broad comedy and gangster drama.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marrowbone', 2017, 'Marrowbone''s effective setting and strong cast can''t make up for thinly conceived characters and a story short on genuine scares.', TO_DATE('2017-09-15', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mars attacks', 1996, 'Tim Burton''s alien invasion spoof faithfully recreates the wooden characters and schlocky story of cheesy ''50s sci-fi and Ed Wood movies -- perhaps a little too faithfully for audiences.', TO_DATE('1996-12-13', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mars needs moms', 2011, 'The cast is solid and it''s visually well-crafted, but Mars Needs Moms suffers from a lack of imagination and heart.', TO_DATE('2011-03-04', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marshall', 2017, 'Marshall takes an illuminating, well-acted look at its real-life subject''s early career that also delivers as an entertainingly old-fashioned courtroom drama.', TO_DATE('2017-09-26', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marshland la isla mínima', 2014, 'As narratively taut as it is richly atmospheric, Marshland keeps viewers guessing throughout a procedural thriller with surprising nuance.', TO_DATE('2014-10-06', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('martha marcy may marlene', 2011, 'Led by a mesmerizing debut performance from Elizabeth Olsen, Martha Marcy May Marlene is a distinctive, haunting psychological drama.', TO_DATE('2011-01-22', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('martian child', 2007, 'Despite some charms, overt emotional manipulation and an inconsistent tone prevents Martian Child from being the heartfelt dramedy it aspires to be.', TO_DATE('2007-10-25', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('martin lawrence live runteldat', 2002, 'Lawrence''s delivery can be funny, but the content is stale.', TO_DATE('2002-08-01', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('martyrs', 2008, 'A real polarising movie, this Gallic torture-porn is graphic, brutal, nasty and gruesome and not to everyone''s taste.', TO_DATE('2008-09-05', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marvels the avengers', 2012, 'Thanks to a script that emphasizes its heroes'' humanity and a wealth of superpowered set pieces, The Avengers lives up to its hype and raises the bar for Marvel at the movies.', TO_DATE('2012-04-19', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marvins room', 1996, 'Marvin''s Room rises above the pack of dysfunctional family dramas thanks to an impeccable cast that includes Meryl Streep, Diane Keaton, and Leonardo DiCaprio.', TO_DATE('1996-12-20', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('marwencol', 2010, 'Inspiring and fascinating, Marwencol depicts its subject with heartfelt tenderness, raising poignant questions about art and personal tragedy along the way.', TO_DATE('2010-10-04', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mary', 2019, 'Misguided from stem to stern, Mary wastes the talents of an outstanding cast -- and makes a soggy mess of its supernatural horror story.', TO_DATE('2019-10-06', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mary and the witchs flower', 2017, 'Mary and the Witch''s Flower honors its creator''s Studio Ghibli roots with a gentle, beautifully animated story whose simplicity is rounded out by its entrancing visuals.', TO_DATE('2017-09-23', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mary magdalene', 2018, 'Mary Magdalene has obvious reverence for its subject; unfortunately, it lacks enough momentum or depth of character to make her story interesting.', TO_DATE('2018-02-27', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mary poppins', 2001, 'A lavish modern fairy tale celebrated for its amazing special effects, catchy songs, and Julie Andrews''s legendary performance in the title role.', TO_DATE('2001-04-17', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mary queen of scots', 2018, 'Mary Queen of Scots delivers uneven period political thrills while offering a solid showcase for the talents of its well-matched leads.', TO_DATE('2018-11-16', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mary reilly', 1996, 'The movie looks good and has its moments. But, overall, the movie borders on boredom.', TO_DATE('1996-02-23', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mary shelley', 2017, 'Mary Shelley smooths out its subject''s fascinating life and fails to communicate the spark of her classic work, undermining fine period detail and a solid Elle Fanning performance.', TO_DATE('2017-09-10', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mary shelleys frankenstein', 2000, 'Mary Shelley''s Frankenstein is ambitious and visually striking, but the overwrought tone and lack of scares make for a tonally inconsistent experience.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maryam', 2002, 'A well-made coming of age drama elevated by its evocative setting, Maryam marks writer-director Ramin Serry as an emerging talent to watch.', TO_DATE('2002-01-30', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mash', 1970, 'Bold, timely, subversive, and above all funny, M*A*S*H remains a high point in Robert Altman''s distinguished filmography.', TO_DATE('1970-12-31', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mask of zorro', 1998, 'Banderas returns as an aging Zorro in this surprisingly nimble, entertaining swashbuckler.', TO_DATE('1998-07-17', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('masked and anonymous', 2003, 'Unintelligible and self-indulgent Bob Dylan vehicle.', TO_DATE('2003-01-30', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('master and commander the far side of the world', 2003, 'Russell Crowe''s rough charm is put to good use in this masterful adaptation of Patrick O''Brian''s novel.', TO_DATE('2003-10-29', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the master of disguise', 2002, 'An ill-concieved attempt to utilize Dana Carvey''s talent for mimicry, The Master of Disguise is an irritating, witless farce weighted down by sophomoric gags.', TO_DATE('2002-07-31', 'YYYY-MM-DD'), 1.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('master z ip man legacy', 2018, 'Master Z: Ip Man Legacy marks a departure from previous entries in the franchise -- but its thrilling action set pieces remain every bit as satisfying.', TO_DATE('2018-10-12', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('masterminds', 2016, 'Masterminds'' great cast and stranger-than-fiction true story are largely wasted on a scattershot comedy with a handful of funny moments and far too much wackiness.', TO_DATE('2016-09-29', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('masters of the universe', 2000, 'Masters of the Universe is a slapdash adaptation of the He-Man mythos that can''t overcome its cynical lack of raison d''etre, no matter how admirably Frank Langella throws himself into the role of Skeletor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('matador', 2000, 'Intertwining murder and seduction, Pedro Almodóvar''s Matador is a provocative thriller that will shock even the most adventurous moviegoers.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('match point', 2005, 'Woody Allen''s sharpest film in years, Match Point is a taut, philosophical thriller about class and infidelity.', TO_DATE('2005-05-17', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('matchstick men', 2003, 'Breezy and well-acted, Matchstick Men focuses more on the characters than on the con.', TO_DATE('2003-08-19', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('material girls', 2006, 'Plagued by paper-thin characterizations and a hackneyed script, Material Girls fails to live up to even the minimum standards of its genre.', TO_DATE('2006-08-17', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the matrix', 1999, 'Thanks to the Wachowskis'' imaginative vision, The Matrix is a smartly crafted combination of spectacular action and groundbreaking special effects.', TO_DATE('1999-03-31', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the matrix reloaded', 2003, 'Though its heady themes are a departure from its predecessor, The Matrix Reloaded is a worthy sequel packed with popcorn-friendly thrills.', TO_DATE('2003-03-17', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the matrix revolutions', 2003, 'A disappointing conclusion to the Matrix trilogy as characters and ideas take a back seat to the special effects.', TO_DATE('2003-06-10', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('matthew barney no restraint', 2006, 'Matthew Barney: No Restraint makes an honest attempt to illuminate its subject''s provocative work, but ultimately fails to capture its inspiration or appeal.', TO_DATE('2006-06-06', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maudie', 2016, 'Maudie''s talented cast -- particularly Sally Hawkins in the title role -- breathe much-needed depth into a story that only skims the surface of a fascinating life and talent.', TO_DATE('2016-09-06', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maurice', 2000, 'Maurice sensitively explores the ramifications of forbidden desire with a powerful love story brought to life by the outstanding efforts of a talented cast.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maverick', 2000, 'It isn''t terribly deep, but it''s witty and undeniably charming, and the cast is obviously having fun.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('max', 2002, 'Well-acted in the execution of its provocative "what-if?" premise.', TO_DATE('2002-09-11', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('max', 2015, 'Max has good intentions and tries to hearken back to classic family-friendly features, but its disjointed, manipulative plot overwhelms the efforts of its talented human and canine stars.', TO_DATE('2015-06-23', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('max keebles big move', 2001, 'Max Keeble may be fun for kids, but bland and unoriginal for adults.', TO_DATE('2001-10-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('max manus man of war', 2008, 'This good old-fashioned Norwegian WW2 film has impressive set pieces and never suffers for a lack of suspense.', TO_DATE('2008-12-19', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('max payne', 2008, 'While it boasts some stylish action, Max Payne suffers severely from an illogical plot and overdirection.', TO_DATE('2008-10-09', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('max steel', 2016, 'Bereft of characterization or even satisfying rock ''em sock ''em, Max Steel feels like futzing with an action figure without any childhood imagination.', TO_DATE('2016-10-14', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maxed out', 2006, 'Maxed Out''s presentation of startling facts and candid interviews put a human face on the issue of debt and financial insecurity.', TO_DATE('2006-03-20', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('may', 2002, 'Above average slasher flick.', TO_DATE('2002-09-09', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mayhem', 2017, 'Mayhem delivers stylish violence by the bloody bucketful -- and grounds all the titular chaos in sharp humor and surprisingly effective real-world economic angst.', TO_DATE('2017-03-15', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maze runner the death cure', 2018, 'Maze Runner: The Death Cure may offer closure to fans of the franchise, but for anyone who hasn''t already been hooked, this bloated final installment is best left unseen.', TO_DATE('2018-01-17', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('maze runner the scorch trials', 2015, 'Maze Runner: The Scorch Trials is an action-packed sequel at the cost of story, urgency, and mystery that the original offered.', TO_DATE('2015-09-07', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mccabe mrs miller', 2000, 'McCabe & Mrs. Miller offers revisionist Western fans a landmark early addition to the genre while marking an early apogee for director Robert Altman.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mcfarland usa', 2015, 'Disney''s inspirational sports drama formula might be old hat, but McFarland, USA proves it still works -- especially with a talented director and eminently likable star in the mix.', TO_DATE('2015-02-04', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mcqueen', 2018, 'McQueen offers an intimate, well-sourced, and overall moving look at a young life and brilliant career that were tragically cut short.', TO_DATE('2018-04-23', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('me and earl and the dying girl', 2015, 'Beautifully scripted and perfectly cast, Me & Earl & the Dying Girl is a coming-of-age movie with uncommon charm and insight.', TO_DATE('2015-01-25', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('me and you and everyone we know', 2005, 'Miranda July''s debut feature is a charmingly offbeat and observant film about people looking for love.', TO_DATE('2005-03-15', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('me before you', 2016, 'Me Before You benefits from Emilia Clarke and Sam Claflin''s alluring chemistry, although it isn''t enough to compensate for its clumsy treatment of a sensitive subject.', TO_DATE('2016-05-24', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('me myself irene', 2000, 'While Jim Carrey''s comedic skills earn some laughs, Me, Myself and Irene sports a tired, unsatisfying plot.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('me without you', 2002, 'At times ponderous, Me Without You is engaging due to the fine work by Williams and Friel.', TO_DATE('2002-01-08', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('me you them', 2001, 'Me You Them tells a warmly comical and touching story, and features a charismatically earthy performance by Casé.', TO_DATE('2001-02-07', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mea maxima culpa silence in the house of god', 2012, 'Examining the intricacies of global scandal through one haunting case, Mea Maxima Culpa is an impassioned and meticulous exposé on abuses of power and institutional sin.', TO_DATE('2012-10-12', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mean creek', 2004, 'Mean Creek is an uncomfortably riveting glimpse into the casual cruelty of youth.', TO_DATE('2004-06-12', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mean dreams', 2016, 'Mean Dreams enlivens its familiar premise with rich details, strong performances from a talented cast playing fully realized characters, and sensitive work from director Nathan Morlando.', TO_DATE('2016-05-15', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mean girls', 2004, 'Elevated by a brilliant screenplay and outstanding ensemble cast, Mean Girls finds fresh, female-fronted humor in the high school experience.', TO_DATE('2004-03-30', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mean machine', 2002, 'Despite some genuine wit, this crowd pleaser is filled with too many cliches.', TO_DATE('2002-01-09', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mean streets', 2000, 'Mean Streets is a powerful tale of urban sin and guilt that marks Scorsese''s arrival as an important cinematic voice and features electrifying performances from Harvey Keitel and Robert De Niro.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('meatballs', 2002, 'Meatballs is a summer camp comedy with few surprises, but Bill Murray''s riffing adds a spark that sets it apart from numerous subpar entries in a frequently uninspired genre.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mechanic', 2011, 'Jason Statham and Ben Foster turn in enjoyable performances, but this superficial remake betrays them with mind-numbing violence and action thriller cliches.', TO_DATE('2011-01-24', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mechanic resurrection', 2016, 'With little to recommend beyond a handful of entertaining set pieces, Mechanic: Resurrection suggests this franchise should have remained in its tomb.', TO_DATE('2016-08-26', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the medallion', 2003, 'The use of special effects diminishes some of Chan''s appeal in this disposable picture.', TO_DATE('2003-08-18', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('medicine for melancholy', 2008, 'Blessed with clever dialogue and poignant observations of class and race, Medicine For Melancholy is a promising debut for director Barry Jenkins.', TO_DATE('2008-05-05', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('meeks cutoff', 2010, 'Moving at a contemplative speed unseen in most westerns, Meek''s Cutoff is an effective, intense journey of terror and survival in the untamed frontier.', TO_DATE('2010-09-09', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('meet the browns', 2008, 'Angela Bassett''s considerable charms can''t compensate for Meet the Browns'' incessant melodrama and scattered narrative threads.', TO_DATE('2008-03-21', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('meet dave', 2008, 'Easy gags and slack direction drag this occasionally clever alien-out-of-planet comedy down to unimaginative lows.', TO_DATE('2008-07-09', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('meet joe black', 1998, 'Meet Joe Black is pretty to look at and benefits from an agreeable cast, but that isn''t enough to offset this dawdling drama''s punishing three-hour runtime.', TO_DATE('1998-11-13', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('meet me in st louis', 2000, 'A disarmingly sweet musical led by outstanding performances from Judy Garland and Margaret O''Brien, Meet Me in St. Louis offers a holiday treat for all ages.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('meet the fockers', 2004, 'Talented cast is wasted as the movie is content with recycling jokes from its predecessor, Meet the Parents.', TO_DATE('2004-12-16', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('meet the parents', 2000, 'Despite sometimes sitcom-like execution, Meet the Parents is a hilarious look at familial relationships that works mostly because the chemistry between its two leads is so effective.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('meet the patels', 2014, 'Meet the Patels works on multiple levels, offering an affably entertaining documentary about one man looking for love while posing thoughtful questions about cultural assimilation and modern romance.', TO_DATE('2014-11-06', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('meet the robinsons', 2007, 'Meet the Robinsons is a visually impressive children''s animated film marked by a story of considerable depth.', TO_DATE('2007-03-23', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('meet the spartans', 2008, 'A tired, unfunny, offensive waste of time, Meet the Spartans scrapes the bottom of the cinematic barrel.', TO_DATE('2008-01-25', 'YYYY-MM-DD'), 2.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mega shark vs giant octopus', 2009, 'With shoddy FX, acting and directing. This isn''t so bad it''s good. It''s just so bad it''s terrible.', TO_DATE('2009-05-14', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('megamind', 2010, 'It regurgitates plot points from earlier animated efforts, and isn''t quite as funny as it should be, but a top-shelf voice cast and strong visuals help make Megamind a pleasant, if unspectacular, diversion.', TO_DATE('2010-10-31', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('megan leavey', 2017, 'Megan Leavey honors its real-life subjects with a sensitive, uplifting drama whose honest emotion more than makes up for its mild approach to the story.', TO_DATE('2017-05-10', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mermaid mei ren yu', 2016, 'The Mermaid requires a willingness to embrace the strange, but backs up its wacky flights of fancy with a big-hearted fairy tale and a resonant message.', TO_DATE('2016-02-20', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('melancholia', 2011, 'Melancholia''s dramatic tricks are more obvious than they should be, but this is otherwise a showcase for Kirsten Dunst''s acting and for Lars von Trier''s profound, visceral vision of depression and destruction.', TO_DATE('2011-05-18', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('melinda and melinda', 2004, 'Woody Allen''s uneven Melinda and Melinda fails to find neither comedy nor pathos in what seems like a rehash of his previous themes.', TO_DATE('2004-10-06', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('memento', 2000, 'Christopher Nolan skillfully guides the audience through Memento''s fractured narrative, seeping his film in existential dread.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('memoir of war la douleur', 2017, 'Memoir of War benefits from a magnetic performance by Mélanie Thierry, whose work is often enough to counter some of the film''s fundamental flaws.', TO_DATE('2017-09-25', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('memoirs of a geisha', 2005, 'Less nuanced than its source material, Memoirs of a Geisha may be a lavish production, but it still carries the simplistic air of a soap opera.', TO_DATE('2005-11-11', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('memoirs of an invisible man', 1992, 'It boasts an intriguing cast and the special effects were groundbreaking, but they can''t compensate for Memoirs of an Invisible Man''s sadly pedestrian script.', TO_DATE('1992-02-28', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('memories of murder', 2003, 'Memories of Murder blends the familiar crime genre with social satire and comedy, capturing the all-too human desperation of its key characters.', TO_DATE('2003-09-16', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('memory the origins of alien', 2019, 'Memory - The Origins of Alien offers an entertaining inside look at the making of a classic -- and compellingly analyzes its creation in the context of its era.', TO_DATE('2019-01-25', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('men in black', 2000, 'Thanks to a smart script, spectacular set pieces, and charismatic performances from its leads, Men in Black is an entirely satisfying summer blockbuster hit.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('men in black ii', 2002, 'Lacking the freshness of the first movie, MIB 2 recycles elements from its predecessor with mixed results.', TO_DATE('2002-06-25', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('men in black iii', 2012, 'It isn''t exactly a persuasive argument for the continuation of the franchise, but Men in Black III is better than its predecessor and manages to exceed expectations.', TO_DATE('2012-05-16', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('men in black international', 2019, 'Amiable yet forgettable, MiB International grinds its stars'' substantial chemistry through the gears of a franchise running low on reasons to continue.', TO_DATE('2019-06-12', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('men of honor', 2000, 'De Niro and Goodings Jr. manage to turn in performances that make this by-the-numbers inspirational movie watchable.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the men who stare at goats', 2009, 'Though The Men Who Stare at Goats is a mostly entertaining, farcical glimpse of men at war, some may find its satire and dark humor less than edgy.', TO_DATE('2009-09-09', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('men women children', 2014, 'Men, Women & Children is timely, but director Jason Reitman''s overbearing approach to its themes blunts the movie''s impact.', TO_DATE('2014-09-06', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('menace ii society', 2000, 'Told with grit and verve by the Hughes brothers in their feature debut, Menace II Society is a gangland epic that breathes with authenticity while steeped in style.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('menashe', 2017, 'Menashe offers an intriguing look at a culture whose unfamiliarity to many viewers will be rendered irrelevant by the story''s universally affecting themes and thoughtful approach.', TO_DATE('2017-01-23', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mental', 2012, 'Mental is a well-acted black comedy that suffers from jarring tonal shifts and a lack of comic discipline.', TO_DATE('2012-09-20', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('william shakespeares the merchant of venice', 2004, 'A respectable if uneven take on the Bard''s The Merchant of Venice.', TO_DATE('2004-09-18', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('merchants of doubt', 2014, 'Merchants of Doubt is a thought-provoking documentary assembled with energy and style, even if it doesn''t dig as deep as it could.', TO_DATE('2014-09-03', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('merci docteur rey', 2004, 'This overly wacky farce strains for sophistication but lacks polish and a coherent narrative.', TO_DATE('2004-08-07', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mercury 13', 2018, 'Mercury 13 offers yet another sobering example of how institutionalized sexism has thwarted countless dreams -- and held nations back from their full potential.', TO_DATE('2018-04-09', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mercury rising', 1998, 'Mercury Rising lays the action on thick, but can never find a dramatic pulse to keep viewers -- or Bruce Willis -- engaged with its maudlin story.', TO_DATE('1998-04-03', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('merry christmas mr lawrence', 2000, 'Worthy themes and strong performances across the board make Merry Christmas, Mr. Lawrence an impactful story about bridging cultural divides.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the merry gentleman', 2008, 'Michael Keaton''s directorial debut, The Merry Gentleman, is a slow character study aided greatly by the performances of Keaton and Kelly MacDonald.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('meru', 2015, 'Gripping visually as well as narratively, Meru is the rare documentary that proves thought-provoking while offering thrilling wide-screen vistas.', TO_DATE('2015-06-05', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mesrine public enemy 1 mesrine lennemi public no 1', 2009, 'Vincent Cassel is mesmerizing in the lead role. Even if it''s less focused than its predecessor, it''s more fun.', TO_DATE('2009-07-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('message in a bottle', 1999, 'Handsome-looking but dramatically inert, Message in a Bottle maroons a formidable cast in a trite romance that lacks spark.', TO_DATE('1999-02-12', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the messenger the story of joan of arc', 2000, 'The heavy-handed narrative collapses under its own weight.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('metallica some kind of monster', 2004, 'Fascinating behind-the-scenes look at how Metallica survives one of their more turbulent periods.', TO_DATE('2004-01-12', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('metallica through the never', 2013, 'Imaginatively shot and edited, Metallica Through the Never is an electrifying, immersive concert film, though its fictional sequences are slightly less assured.', TO_DATE('2013-09-09', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('metropolitan', 1990, 'Metropolitan gently skewers the young socialite class with a smartly written dramedy whose unique, specific setting yields rich universal truths.', TO_DATE('1990-08-03', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mexican', 2000, 'Though The Mexican makes a good attempt at originality, its ponderous length makes it wear out its welcome. Also, those looking forward to seeing Roberts and Pitt paired up may end up disappointed, as they are kept apart for most of the movie.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mi5 spooks the greater good', 2015, 'MI-5 (Spooks: The Greater Good) is a stylish, albeit rather perfunctory, adaptation of a spy thriller perhaps best left on the small screen.', TO_DATE('2015-04-29', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mia madre', 2015, 'Mia Madre explores thought-provoking themes with director/co-writer Nanni Moretti''s reliably skillful blend of comedy and pathos.', TO_DATE('2015-04-16', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miami blues', 1990, 'Laced with hard-boiled thrills and pitch-black comedy, Miami Blues delivers a disarmingly off-kilter crime caper.', TO_DATE('1990-04-20', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miami rhapsody', 1995, 'Miami Rhapsody has a handful of laughs, but wears its influences so heavily that it can''t help but suffer by comparison.', TO_DATE('1995-01-27', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miami vice', 2005, 'Miami Vice is beautifully shot but the lead characters lack the charisma of their TV series counterparts, and the underdeveloped story is well below the standards of Michael Mann''s better films.', TO_DATE('2005-12-20', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('michael', 2011, 'Michael''s dispassionate approach to a sensationalistic story increases its chilling effectiveness without blunting the repellent horror of its subject matter.', TO_DATE('2011-08-13', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('michael clayton', 2007, 'Michael Clayton is one of the most sharply scripted films of 2007, with an engrossing premise and faultless acting. Director Tony Gilroy succeeds not only in capturing the audience''s attention, but holding it until the credits roll.', TO_DATE('2007-08-31', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('michael collins', 1996, 'As impressively ambitious as it is satisfyingly impactful, Michael Collins honors its subject''s remarkable achievements with a magnetic performance from Liam Neeson in the title role.', TO_DATE('1996-10-11', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('michael jacksons this is it', 2009, 'While it may not be the definitive concert film (or the insightful backstage look) some will hope for, Michael Jackson''s This Is It packs more than enough entertainment value to live up to its ambitious title.', TO_DATE('2009-10-27', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mickey blue eyes', 1999, 'High-brow humorists doing low-brow humor never hit their stride.', TO_DATE('1999-08-20', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('micmacs micmacs à tirelarigot', 2009, 'It might be a little too whimsical for its own good, but Micmacs delivers more of the inventive silliness that director Jean-Pierre Jeunet is known for.', TO_DATE('2009-09-22', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mid90s', 2018, 'Mid90s tells a clear-eyed yet nostalgic coming-of-age tale that might mark the start of an auspicious new career for debuting writer-director Jonah Hill.', TO_DATE('2018-09-10', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pranzo di ferragosto midaugust lunch', 2009, 'Thoughtful, warm-hearted, and delightfully free of pretense, Mid-August Lunch offers viewers a light diversion with some surprising depth.', TO_DATE('2009-03-30', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('middle men', 2010, 'Middle Men benefits from a solid cast, particularly Luke Wilson, but its muddled script lets them down.', TO_DATE('2010-07-07', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('middle of nowhere', 2012, 'Wise, compassionate, and beautifully acted, Middle of Nowhere offers an early testament to writer-director Ava DuVernay''s startling talent.', TO_DATE('2012-01-21', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('midnight cowboy', 1969, 'John Schlesinger''s gritty, unrelentingly bleak look at the seedy underbelly of urban American life is undeniably disturbing, but Dustin Hoffman and Jon Voight''s performances make it difficult to turn away.', TO_DATE('1969-05-25', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('midnight express', 2000, 'Raw and unrelenting, Midnight Express is riveting in its realistic depiction of incarceration -- mining pathos from the simple act of enduring hardship.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('midnight family', 2019, 'As narratively urgent as it is technically well-crafted, Midnight Family offers an enthralling and disquieting glimpse of healthcare in modern Mexico.', TO_DATE('2019-01-28', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('midnight in paris', 2011, 'It may not boast the depth of his classic films, but the sweetly sentimental Midnight in Paris is funny and charming enough to satisfy Woody Allen fans.', TO_DATE('2011-05-11', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('midnight in the garden of good and evil', 1997, 'Clint Eastwood''s spare directorial style proves an ill fit for this Southern potboiler, which dutifully trudges through its mystery while remaining disinterested in the cultural flourishes that gave its source material its sense of intrigue.', TO_DATE('1997-11-21', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('midnight run', 1988, 'Enlivened by the antagonistic chemistry between Robert De Niro and Charles Grodin, Midnight Run is an uncommonly entertaining odd couple comedy.', TO_DATE('1988-07-11', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('midnight special', 2016, 'Midnight Special''s intriguing mysteries may not resolve themselves to every viewer''s liking, but the journey is ambitious, entertaining, and terrifically acted.', TO_DATE('2016-02-12', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('midnight sun', 2018, 'Midnight Sun is a typically manipulative and contrived teen romance that''s unfortunately distinguished by its offensively inaccurate portrayal of a real-life disease.', TO_DATE('2018-03-22', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('midnighters', 2017, 'Adding dashes of horror to a noir premise, Midnighters is a genre-bending chiller that delights as often as it scares.', TO_DATE('2017-06-20', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('midnights children', 2012, 'Though Midnight''s Children is beautiful to look at and poignant in spots, its script is too indulgent and Deepa Mehta''s direction, though ambitious, fails to bring the story together cohesively.', TO_DATE('2012-09-07', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('midsommar', 2019, 'Ambitious, impressively crafted, and above all unsettling, Midsommar further proves writer-director Ari Aster is a horror auteur to be reckoned with.', TO_DATE('2019-06-19', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a midsummer nights sex comedy', 2001, 'It may not Woody Allen''s best work, but the frothy, fun A Midsummer Night''s Sex Comedy is still worth a look.', TO_DATE('2001-10-22', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mifune the last samurai', 2016, 'Capturing the breadth of Toshiro Mifune''s storied career, if not fully reckoning with the depth of the man, The Last Samurai is a compelling celebration of one of cinema''s greatest stars.', TO_DATE('2016-10-20', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mighty', 1998, 'Spirited and sweet with an emphasis on the healing power of friendship, The Mighty is a modest charmer that comes by its whimsy honestly.', TO_DATE('1998-10-09', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mighty ducks', 1992, 'The Mighty Ducks has feel-good goals but only scores a penalty shot for predictability.', TO_DATE('1992-09-20', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a mighty heart', 2007, 'Angelina Jolie conveys the full emotional range of a woman in a desperate situation in A Mighty Heart, an urgent yet tactful film about a difficult subject.', TO_DATE('2007-05-21', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mighty quinn', 2000, 'A deft hybrid of laughs, espionage, and music, The Mighty Quinn is a smart, pleasant entertainment that offers an early example of Denzel Washington''s onscreen magnetism.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a mighty wind', 2003, 'Though not as uproariously funny as Guest''s previous movies, A Mighty Wind is also more heartfelt.', TO_DATE('2003-04-04', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mike and dave need wedding dates', 2016, 'Mike and Dave Need Wedding Dates benefits from the screwball premise and the efforts of a game cast, even if the sporadically hilarious results don''t quite live up to either.', TO_DATE('2016-07-05', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the milagro beanfield war', 2000, 'Arguably Robert Redford''s most inchoate work, The Milagro Beanfield War has plenty of beautiful moments, but they don''t quite add up to a worthwhile whole.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('milarepa', 2007, 'Milarepa''s confusing plot structure, simplistic message, and poor production values cause it to fall flat.', TO_DATE('2007-09-01', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mildred pierce', 2000, 'Tied together by a powerhouse performance from Joan Crawford, Mildred Pierce blends noir and social drama to soapily intoxicating effect.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mile 22', 2018, 'Mile 22 lets the bullets fly -- and not much else -- in a thrill-deficient action thriller whose title proves sadly fitting for a film that feels close to a marathon endurance test.', TO_DATE('2018-08-16', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miles ahead', 2015, 'Miles Ahead is worth watching for Don Cheadle''s strong work on both sides of the camera, even if this unconventional biopic doesn''t quite capture its subject''s timeless appeal.', TO_DATE('2015-10-12', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miles davis birth of the cool', 2019, 'Entertaining for longtime fans as well as casually interested viewers, Miles Davis: Birth of the Cool burnishes the legacy of a brilliant artist.', TO_DATE('2019-01-28', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('military wives', 2019, 'Like a favorite song you know by heart, Military Wives offers few surprises -- but its pleasures are no less formidable for their familiarity.', TO_DATE('2019-09-07', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('milk', 2008, 'Anchored by Sean Penn''s powerhouse performance, Milk is a triumphant account of America''s first openly gay man elected to public office.', TO_DATE('2008-11-02', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the milk of sorrow la teta asustada', 2009, 'Claudia Llosa''s deliberate pace and abstract storytelling may frustrate some viewers, but there''s no denying the visual pleasures soaking in The Milk of Sorrow.', TO_DATE('2009-02-19', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('millennium actress sennen joyû', 2002, 'The story of an aging movie actress'' complicated personal saga unfolds in this sophisticated anime film that deftly blurs memory and make-believe into a meditation on the nature of cinema itself.', TO_DATE('2002-11-20', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('millers crossing', 1990, 'Though possibly more notable for its distinctive style than an airtight story, this Coen brothers take on the classic gangster flick features sharp dialogue, impressive cinematography, and a typically quirky cast of characters.', TO_DATE('1990-09-22', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('million dollar arm', 2014, 'Pleasant to a fault, Million Dollar Arm is a middle-of-the-plate pitch that coasts on Jon Hamm''s considerable charm without adding any truly original curves to Disney''s inspirational sports formula.', TO_DATE('2014-04-30', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('million dollar baby', 2004, 'Clint Eastwood''s assured direction - combined with knockout performances from Hilary Swank and Morgan Freeman - help Million Dollar Baby to transcend its clichés, and the result is deeply heartfelt and moving.', TO_DATE('2004-11-23', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the million dollar hotel', 2001, 'Critics say the weirdness of The Million Dollar Hotel is more grating and pretentious than interesting. Also, it takes too long to get to the conclusion.', TO_DATE('2001-01-16', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('millions', 2004, 'A charming children fable even adults can enjoy.', TO_DATE('2004-09-14', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('secret sunshine', 2007, 'Plumbing the depths of tragedy without succuming to melodrama, Chang-dong Lee''s Secret Sunshine is a grueling, albeit moving, piece of beautifully acted cinema.', TO_DATE('2007-05-24', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last mimzy', 2007, 'The Last Mimzy makes efforts to be a fun children''s movie, but unsuccessfully juggles too many genres and subplots -- eventually settling as an unfocused, slightly dull affair.', TO_DATE('2007-01-25', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mindhunters', 2003, 'A retread of Ten Little Indians that lacks the source material''s wit.', TO_DATE('2003-11-24', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mine', 2016, 'Exhausting when it should be thrilling, Mine squanders a committed performance by Armie Hammer with slack suspense and unfocused storytelling.', TO_DATE('2016-12-27', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('minions', 2015, 'The Minions'' brightly colored brand of gibberish-fueled insanity stretches to feature length in their self-titled Despicable Me spinoff, with uneven but often hilarious results.', TO_DATE('2015-06-17', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('minority report', 2002, 'Thought-provoking and visceral, Steven Spielberg successfully combines high concept ideas and high octane action in this fast and febrile sci-fi thriller.', TO_DATE('2002-06-10', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miracle', 2004, 'Kurt Russell''s performance guides this cliche-ridden tale into the realm of inspirational, nostalgic goodness.', TO_DATE('2004-01-16', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miracle at st anna', 2008, 'Miracle at St. Anna is a well-intentioned but overlong, disjointed affair that hits few of the right notes.', TO_DATE('2008-09-07', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miracle mile', 2000, 'Miracle Mile brings about its small-scale doomsday tale with achingly rich bleakness and hypnotically nightmarish fervor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the miracle of morgans creek', 2000, 'The Miracle of Morgan''s Creek finds director Preston Sturges at his most zanily subversive -- not to mention hilarious.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miracle on 34th street', 2000, 'Irrefutable proof that gentle sentimentalism can be the chief ingredient in a wonderful film, Miracle on 34th Street delivers a warm holiday message without resorting to treacle.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miracles from heaven', 2016, 'Miracles from Heaven makes the most out of an outstanding performance from Jennifer Garner, but it isn''t quite enough to keep this faith-based drama from preaching to the choir.', TO_DATE('2016-03-14', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mirai', 2018, 'The simplicity and colorful warmth of Mirai''s animation is underscored by a story with surprising - and deeply affecting - depth and emotional resonance.', TO_DATE('2018-05-16', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miral', 2010, 'Miscast and dramatically inert, Miral is a thin chronicle of geopolitical history that offers only shallow insight into the Israeli-Palestinian conflict and characters with even less depth.', TO_DATE('2010-09-03', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mirror mirror', 2011, 'Like most of Tarsem Singh''s films, Mirror Mirror is undeniably beautiful -- but its treatment of the age-old Snow White fable lacks enough depth or originality to set it apart from the countless other adaptations of the tale.', TO_DATE('2011-10-25', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mirrormask', 2005, 'While visually dazzling, there isn''t enough story to hang all the fancy effects on.', TO_DATE('2005-02-02', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('misery', 1990, 'Elevated by standout performances from James Caan and Kathy Bates, this taut and frightening film is one of the best Stephen King adaptations to date.', TO_DATE('1990-11-30', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('misery loves comedy', 2015, 'Misery Loves Comedy starts with an idea worth exploring, but proves frustratingly unable to enlighten or amuse.', TO_DATE('2015-01-23', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mishima a life in four chapters', 2000, 'Paul Schrader''s directorial masterpiece is a classy and imaginative portrait enriched by a stunning score and impressive cinematography.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miss americana', 2020, 'Miss Americana provides an engaging if somewhat deliberately opaque backstage look at a pop star turned cultural phenomenon.', TO_DATE('2020-01-24', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miss bala', 2011, 'Miss Bala''s subject is loaded enough, but the frantic and muscular filmmaking puts this movie in a whole new league.', TO_DATE('2011-09-08', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miss bala', 2019, 'Miss Bala suggests Gina Rodriguez has a future as an action hero; unfortunately, it also demonstrates how hard it is to balance set pieces against a compelling story.', TO_DATE('2019-01-31', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miss congeniality', 2000, 'Though critics say Bullock is funny and charming, she can''t overcome a bad script that makes the movie feel too much like a fluffy, unoriginal sitcom.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miss congeniality 2 armed and fabulous', 2005, 'Sandra Bullock is still as appealing as ever; too bad the movie is not pageant material.', TO_DATE('2005-03-13', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miss julie', 2014, 'Miss Julie definitely gives Jessica Chastain and Colin Farrell room to shine, but neglects to leave them a solid enough setting to augment their efforts.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miss juneteenth', 2020, 'Like a pageant winner walking across the stage, Miss Juneteenth follows a familiar path -- but does so with charm and grace.', TO_DATE('2020-01-25', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miss peregrines home for peculiar children', 2016, 'Miss Peregrine''s Home for Peculiar Children proves a suitable match for Tim Burton''s distinctive style, even if it''s on stronger footing as a visual experience than a narrative one.', TO_DATE('2016-09-25', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miss pettigrew lives for a day', 2008, 'Miss Pettigrew is a breezy period comedy carried by the strong performances of Amy Adams and Frances McDormand.', TO_DATE('2008-02-21', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miss potter', 2006, 'A charming biopic that maintains its sweetness even in sadder moments.', TO_DATE('2006-12-11', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miss sloane', 2016, 'Miss Sloane sits squarely on the shoulders of Jessica Chastain''s performance -- and she responds with awards-worthy work that single-handedly elevates the film.', TO_DATE('2016-11-11', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('miss you already', 2015, 'Miss You Already isn''t shy about going for filmgoers'' tear ducts, but its solid script and talented cast are often powerful enough to make up for its more manipulative moments.', TO_DATE('2015-09-10', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('missing link', 2019, 'Another beautifully animated triumph for Laika, Missing Link is a visual treat with lots of humor, plenty of heart, and even a little food for thought.', TO_DATE('2019-04-03', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mission impossible', 1996, 'Full of special effects, Brian DePalma''s update of Mission: Impossible has a lot of sweeping spectacle, but the plot is sometimes convoluted.', TO_DATE('1996-05-22', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mission impossible 2', 2000, 'Your cranium may crave more substance, but your eyes will feast on the amazing action sequences.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mission impossible iii', 2006, 'Fast-paced, with eye-popping stunts and special effects, the latest Mission: Impossible installment delivers everything an action fan could ask for. A thrilling summer popcorn flick.', TO_DATE('2006-04-27', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mission impossible fallout', 2018, 'Fast, sleek, and fun, Mission: Impossible - Fallout lives up to the "impossible" part of its name by setting yet another high mark for insane set pieces in a franchise full of them.', TO_DATE('2018-07-12', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mission impossible ghost protocol', 2011, 'Stylish, fast-paced, and loaded with gripping set pieces, the fourth Mission: Impossible is big-budget popcorn entertainment that really works.', TO_DATE('2011-12-07', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mission impossible rogue nation', 2015, 'Mission: Impossible Rogue Nation continues the franchise''s thrilling resurgence -- and proves that Tom Cruise remains an action star without equal.', TO_DATE('2015-07-24', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mission to mars', 2000, 'Beauty only goes skin deep in this shallow but visually stunning film.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mississippi burning', 2000, 'Mississippi Burning draws on real-life tragedy to impart a worthy message with the measured control of an intelligent drama and the hard-hitting impact of a thriller.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mississippi grind', 2015, 'Well-acted and steeped in Southern atmosphere, Mississippi Grind is a road movie and addiction drama that transcends each of its well-worn genres.', TO_DATE('2015-01-25', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mist', 2007, 'Frank Darabont''s impressive camerawork and politically incisive script make The Mist a truly frightening experience.', TO_DATE('2007-11-11', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hallam foe mister foe', 2007, 'Carefully balanced between the dark and the dreamy, Mister Foe is a charged coming-of-age story with whimsy and bite.', TO_DATE('2007-03-28', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mixed nuts', 2000, 'Mixed Nuts may provoke strong allergic reactions in all but the most undemanding filmgoers -- and the most forgiving Steve Martin fans.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mo better blues', 1800, 'Mo'' Better Blues is rich with vibrant hues and Denzel Washington''s impassioned performance, although its straightforward telling lacks the political punch fans expect from a Spike Lee joint.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mo money', 1992, 'Mo'' Money only comes with mo'' problems in this comedically bankrupt outing from the Wayans brothers.', TO_DATE('1992-07-24', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('moana', 2016, 'With a title character as three-dimensional as its lush animation and a story that adds fresh depth to Disney''s time-tested formula, Moana is truly a family-friendly adventure for the ages.', TO_DATE('2016-11-07', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mobsters', 1991, 'Despite an abundance of style and some big names, Mobsters can''t escape its empty plotting, numbing violence, and Gangster Movie 101 concepts.', TO_DATE('1991-07-26', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mod squad', 2000, 'The Mod Squad aims for stylish cool and thrilling adventure, but collapses in an incoherent jumble of dated source material and unintentional hilarity.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('modern romance', 2000, 'Modern Romance contains all the hallmarks of Albert Brooks'' best work: darkly funny, confrontational, and chock full of pithy observations about human behavior.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('modern times', 2000, 'A slapstick skewering of industrialized America, Modern Times is as politically incisive as it is laugh-out-loud hilarious.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('modigliani', 2004, 'Nearly everyone is miscast in this disjointed and slow-moving portrait of Italian artist Amedeo Modigliani.', TO_DATE('2004-10-05', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('moebius', 2013, 'Dark, depraved, and unforgettably sordid, Moebius leavens its perversity with originality and wit.', TO_DATE('2013-09-05', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mohawk', 2017, 'Mohawk delivers effective period horror while skillfully weaving in sociopolitical subtext that pushes the film past genre -- and budgetary -- constraints.', TO_DATE('2017-08-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mojave', 2015, 'Mojave has no shortage of talent on either side of the camera; unfortunately, it amounts to little more than a frustrating missed opportunity.', TO_DATE('2015-12-06', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('molly', 2000, 'Molly never really elevates above uninspired, cliche-ridden moments.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mollys game', 2017, 'Powered by an intriguing story and a pair of outstanding performances from Jessica Chastain and Idris Elba, Molly''s Game marks a solid debut for writer-director Aaron Sorkin.', TO_DATE('2017-09-09', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mom and dad', 2017, 'Mom and Dad''s gonzo premise serves as an effective springboard for a wickedly dark, bloody comedy - and an appropriately over-the-top performance from Nicolas Cage.', TO_DATE('2017-09-10', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mom and dad save the world', 2000, 'There is no saving this off-putting family adventure from its mirthless script, although some inspired production design gives it some visual polish.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mommie dearest', 2001, 'Mommie Dearest certainly doesn''t lack for conviction, and neither does Faye Dunaway''s legendary performance as a wire-wielding monster; unfortunately, the movie is too campy and undisciplined to transcend guilty pleasure.', TO_DATE('2001-07-15', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mommy', 2014, 'As challenging as it is rewarding, Mommy finds writer-director Xavier Dolan taking another impressive step forward.', TO_DATE('2014-05-21', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('moms night out', 2014, 'Cheap-looking, unfunny, and kind of sexist to boot, Moms'' Night Out is a disappointment from start to finish.', TO_DATE('2014-05-02', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mon oncle', 2001, 'Jacques Tati''s most accessible film is a paean to gentle values and observing the small details of life.', TO_DATE('2001-05-15', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mona lisa smile', 2003, 'Though Mona Lisa Smile espouses the value of breaking barriers, the movie itself is predictable and safe.', TO_DATE('2003-11-13', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mondays in the sun los lunes al sol', 2003, 'Javier Bardem gives an outstanding performance in this hought-provoking (though occasionally plodding) movie about the effects of unemployment on a group of former shipyard workers.', TO_DATE('2003-02-11', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('money monster', 2016, 'Money Monster''s strong cast and solidly written story ride a timely wave of socioeconomic anger that''s powerful enough to overcome an occasionally muddled approach to its worthy themes.', TO_DATE('2016-05-11', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('money train', 1995, 'Loud, incoherent, and aimless, Money Train reunites Snipes and Harrelson -- and proves that starring duos are far from immune to the law of diminishing returns.', TO_DATE('1995-11-22', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('moneyball', 2011, 'Director Bennett Miller, along with Brad Pitt and Jonah Hill, take a niche subject and turn it into a sharp, funny, and touching portrait worthy of baseball lore.', TO_DATE('2011-09-08', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mongol', 2007, 'The sweeping Mongol mixes romance, family drama, and enough flesh-ripping battle scenes to make sense of Ghenghis Khan''s legendary stature.', TO_DATE('2007-09-19', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monkey shines an experiment in fear', 2000, 'While not one of horror legend George Romero''s more evolved efforts, Monkey Shines delivers enough primal fear to satisfy more forgiving genre enthusiasts.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monkeybone', 2000, 'Though original and full of bizarre visuals, Monkeybone is too shapeless a movie, with unengaging characters and random situations that fail to build up laughs.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monsieur lazhar', 2011, 'Monsieur Lahzar is a tender and thoughtful portrait of a man with hidden grief and also a compelling exploration of the teacher-student dynamic.', TO_DATE('2011-10-19', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monsieur verdoux', 2000, 'Charles Chaplin adds an undercurrent of malice to his comedic persona in Monsieur Verdoux, an unsettling satire that subverts the tramp''s image to perversely amusing effect.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monsoon wedding', 2001, 'An insightful, energetic blend of Hollywood and Bollywood styles, Monsoon Wedding is a colorful, exuberant celebration of modern-day India, family, love, and life.', TO_DATE('2001-09-28', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monster', 2003, 'Charlize Theron gives a searing, deglamorized performance as real life serial killer Aileen Wuornos in Monster, an intense, disquieting portrait of a profoundly damaged soul.', TO_DATE('2003-11-18', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monster family', 2017, 'Monster Family promises a family-friendly animated monster mash, but succeeds only in delivering a viewing experience so lackluster that parents may find it genuinely frightening.', TO_DATE('2017-10-04', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monster house', 2006, 'Monster House welcoms kids and adults alike into a household full of smart, monstrous fun.', TO_DATE('2006-06-20', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monster hunt zhuo yao ji', 2015, 'This freewheeling adventure may be too daffy for some audiences, but flamboyant creature designs and an irrepressible sense of playfulness make Monster Hunt undeniably fun.', TO_DATE('2015-07-28', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monsterinlaw', 2005, 'While Jane Fonda steals the movie in her return to the screen, a tired script and flimsy performances make this borderline comedy fall flat.', TO_DATE('2005-05-03', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the monster squad', 2000, 'A fun ''80s adventure with a slightly scary twist, The Monster Squad offers tween-friendly horror with just enough of a kick.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monster trucks', 2016, 'Despite flashes of inspiration, the singularly high-concept Monster Trucks shows that it takes more than monsters and trucks to create a compelling feature film.', TO_DATE('2016-12-25', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monsters', 2010, 'It doesn''t quite live up to its intriguing premise, but Monsters is a surprising blend of alien-invasion tropes, political themes, and relationship drama.', TO_DATE('2010-06-20', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monsters and men', 2018, 'Well-acted and visually stylish, Monsters and Men tells its timely story with enough compassion and complexity to make up for occasionally uneven execution.', TO_DATE('2018-01-20', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monsters ball', 2001, 'Somber and thought provoking, Monster''s Ball has great performances all around.', TO_DATE('2001-11-13', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monsters dark continent', 2014, 'Monsters: Dark Continent lacks the fresh approach and thought-provoking subtext of its predecessor, settling instead for tired war movie clichés.', TO_DATE('2014-10-13', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monsters inc', 2001, 'Clever, funny, and delightful to look at, Monsters, Inc. delivers another resounding example of how Pixar elevated the bar for modern all-ages animation.', TO_DATE('2001-10-17', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monsters university', 2013, 'Offering Monsters, Inc. fans a return visit with beloved characters, Monsters University delivers funny and thoughtful family entertainment for viewers of any age.', TO_DATE('2013-06-09', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monsters vs aliens', 2009, 'Though it doesn''t approach the depth of the best animated films, Monsters Vs. Aliens has enough humor and special effects to entertain moviegoers of all ages.', TO_DATE('2009-03-21', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monte carlo', 2011, 'Although it has its charming moments, Monte Carlo is mostly silly, predictable stuff that never pushes beyond the boundaries of formula.', TO_DATE('2011-06-30', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monty python and the holy grail', 2000, 'A cult classic as gut-bustingly hilarious as it is blithely ridiculous, Monty Python and the Holy Grail has lost none of its exceedingly silly charm.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monty pythons life of brian', 1979, 'One of the more cutting-edge films of the 1970s, this religious farce from the classic comedy troupe is as poignant as it is funny and satirical.', TO_DATE('1979-08-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('monty pythons the meaning of life', 2000, 'Monty Python''s the Meaning of Life is rude, ribald, and unafraid to take comedic risks -- which is to say it should more than satisfy fans of the titular troupe.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lécume des jours mood indigo', 2013, 'Mood Indigo is far from Michel Gondry''s most compelling work, but it doesn''t skimp on the visual whimsy and heartfelt emotion fans have come to expect.', TO_DATE('2013-04-23', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('moon', 2009, 'Boosted by Sam Rockwell''s intense performance, Moon is a compelling work of science-fiction, and a promising debut from director Duncan Jones.', TO_DATE('2009-01-16', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('moonlight', 2016, 'Moonlight uses one man''s story to offer a remarkable and brilliantly crafted look at lives too rarely seen in cinema.', TO_DATE('2016-09-02', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('moonlight mile', 2002, 'Though the story feels rather contrived, Moonlight Mile is redeemed by the good performances of its cast.', TO_DATE('2002-08-02', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('moonrise kingdom', 2012, 'Warm, whimsical, and poignant, the immaculately framed and beautifully acted Moonrise Kingdom presents writer/director Wes Anderson at his idiosyncratic best.', TO_DATE('2012-05-16', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('moonstruck', 2000, 'Led by energetic performances from Nicolas Cage and Cher, Moonstruck is an exuberantly funny tribute to love and one of the decade''s most appealing comedies.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('more than a game', 2009, 'Though the film may not delve as deep as some would prefer, More Than a Game is an inspiring documentary featuring likable youngsters, a positive message, and some exciting in-game footage.', TO_DATE('2009-09-16', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('morgan', 2016, 'Morgan neglects to develop its decent premise, opting instead to settle for a garden-variety sci-fi thriller with more action than ideas.', TO_DATE('2016-08-29', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('morning glory', 2010, 'It''s lifted by affable performances from its impeccable cast, and it''s often charming -- but Morning Glory is also inconsistent and derivative.', TO_DATE('2010-11-02', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('morning light', 2008, 'Breathtaking scenery aside, Morning Light is geared more for the sailing enthusiasts than for the average viewers.', TO_DATE('2008-10-11', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mortal engines', 2018, 'Mortal Engines has no shortage of eye-catching special effects, but lacks enough high-octane narrative fuel to give this futuristic fantasy sufficient cinematic combustion.', TO_DATE('2018-12-05', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mortal kombat', 2000, 'Despite an effective otherwordly atmosphere and appropriately cheesy visuals, Mortal Kombat suffers from its poorly constructed plot, laughable dialogue, and subpar acting.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mortal kombat annihilation', 2000, 'With its shallow characters, low budget special effects, and mindless fight scenes, Mortal Kombat - Annihilation offers minimal plot development and manages to underachieve the low bar set by its predecessor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 2.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mortdecai', 2015, 'Aggressively strange and willfully unfunny, the misguided Mortdecai sounds a frightfully low note in Johnny Depp''s post-Pirates filmography.', TO_DATE('2015-01-22', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('moscow belgium aanrijding in moscou', 2008, 'A low-key delight, Moscow, Belgium enlivens its fairly standard story with sharply drawn characters and an outstanding lead performance from Barbara Sarafian.', TO_DATE('2008-06-25', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('moscow on the hudson', 2002, 'With Robin Williams'' affecting portrayal as a Russian immigrant at the center of its fish-out-of-water story, Moscow on The Hudson soars with an abundance of laughs and heart.', TO_DATE('2002-07-28', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mosquito coast', 2000, 'Harrison Ford capably tackles a tough, unlikable role, producing a fascinating and strange character study.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('most beautiful island', 2017, 'Most Beautiful Island plunges audiences into a little-seen sector of society, with writer-director Ana Asensio''s fearless performance leading the way.', TO_DATE('2017-03-14', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('most wanted', 2020, 'Although it suffers in comparison to similar suspense thrillers, Most Wanted benefits from solid casting and a taut, intelligent storytelling approach.', TO_DATE('2020-07-19', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mostly martha bella martha', 2002, 'Mostly Martha may have a predictable plot, but it still feels charming and fresh, and the food will make you hungry.', TO_DATE('2002-07-24', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('motel hell', 2002, 'Eerie and satirical, Motel Hell has no vacancy when it comes to low-brow horror gags.', TO_DATE('2002-07-20', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mother', 2017, 'There''s no denying that mother! is the thought-provoking product of a singularly ambitious artistic vision, though it may be too unwieldy for mainstream tastes.', TO_DATE('2017-09-05', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mother and child', 2009, 'Though it occasionally veers into unnecessary melodrama, Mother and Child benefits from a stellar cast and writer-director Rodrigo Garcia''s finely detailed, bravely unsentimental script.', TO_DATE('2009-09-18', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mother of george', 2013, 'Director Andrew Dosunmu''s style takes some getting used to, but Mother of George compensates with powerful acting, a thoughtful script, and gorgeous visuals.', TO_DATE('2013-08-29', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mother of tears the third mother', 2007, 'As excessive and ketchup laden as predecessors Suspiria and Inferno, Dario Argento''s Mother of Tears completes the trilogy with the same baroque grandeur and soggy 1970s sensibilities.', TO_DATE('2007-09-10', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('motherhood', 2009, 'Despite Uma Thurman''s comic skills, Motherhood''s contrived set-ups and cliched jokes keep this comedy from delivering laughs -- or insights into modern parenting.', TO_DATE('2009-09-01', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mothers day', 2016, 'Arguably well-intended yet thoroughly misguided, Mother''s Day is the cinematic equivalent of a last-minute gift that only underscores its embarrassing lack of effort.', TO_DATE('2016-04-21', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mothman prophecies', 2002, 'A creepy thriller that poses more questions than it answers.', TO_DATE('2002-01-17', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('moulin rouge', 2000, 'A love-it-or-hate-it experience, Moulin Rouge is all style, all giddy, over-the-top spectacle. But it''s also daring in its vision and wildly original.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mountain patrol kekexili', 2005, 'In a setting both visually stunning and cruel, this Eastern film evokes the epic spirit of old-fashioned Westerns.', TO_DATE('2005-08-05', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mountains may depart shan he gu ren', 2015, 'Beautifully filmed, powerfully acted, and rich with meaning, Mountains May Depart represents another outstanding outing from writer/director Zhangke Jia.', TO_DATE('2015-11-19', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mouse hunt', 1997, 'Mouse Hunt gets trapped under the weight of its excessive slapstick antics.', TO_DATE('1997-12-19', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la moustache', 2005, 'Though the premise may be modest on the surface, Carrere uses a man and his mustache that may or may not exist as a springboard into psychological suspense and unsettling questions.', TO_DATE('2005-08-04', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mouth to mouth', 2006, 'Writer-director Alison Murray has a clear connection to the story, but Mouth to Mouth is too disjointed and thinly sketched to satisfy.', TO_DATE('2006-04-25', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('movie 43', 2013, 'A star-studded turkey, Movie 43 is loaded with gleefully offensive and often scatological gags, but it''s largely bereft of laughs.', TO_DATE('2013-01-25', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('moving midway', 2008, 'This strange, heartfelt documentary from film critic Godfrey Cheshire is a fascinating examination of his family roots, as well as an evocative meditation on the complexities of the South.', TO_DATE('2008-03-19', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mowgli legend of the jungle', 2018, 'Mowgli: Legend of the Jungle brings impressive special effects to bear on the darker side of its classic source material, but loses track of the story''s heart along the way.', TO_DATE('2018-11-29', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr 3000', 2004, 'Bernie Mac demonstrates he can play the game even if the movie''s a few innings short of a complete game.', TO_DATE('2004-09-13', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr mrs smith', 2005, 'Although this action-romance suffers from weak writing and one too many explosions, the chemistry generated by onscreen couple Pitt and Jolie is palpable enough to make this a thoroughly enjoyable summer action flick.', TO_DATE('2005-05-26', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr beans holiday', 2007, 'Mr. Bean''s Holiday means well, but good intentions can''t withstand the 90 minutes of monotonous slapstick and tired, obvious gags.', TO_DATE('2007-03-20', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr brooks', 2007, 'The setup is intriguing, but Mr. Brooks overstuffs itself with twists and subplots, becoming more preposterous as it goes along.', TO_DATE('2007-05-23', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr deeds', 2002, 'This update of Capra doesn''t hold a candle to the original, and even on its own merits, Mr. Deeds is still indifferently acted and stale.', TO_DATE('2002-06-13', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr hollands opus', 1995, 'A feel-good story brought to life by a terrific ensemble cast, Mr. Holland''s Opus plucks the heartstrings without shame -- and with undeniable skill.', TO_DATE('1995-12-29', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr holmes', 2015, 'Mr. Holmes focuses on the man behind the mysteries, and while it may lack Baker Street thrills, it more than compensates with tenderly wrought, well-acted drama.', TO_DATE('2015-02-08', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr hulots holiday les vacances de monsieur hulot', 2000, 'Pleasant, lackadaisical, and very charming, Monsieur Hulot lays the groundwork for Jacques Tati''s later, more accomplished films.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr magoo', 2000, 'Leslie Nielsen''s affability can''t save this dunderheaded update of Mr. Magoo, which delivers a stream of slapstick gags so lame that audiences will feel like they''ve stepped on a rake.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr magoriums wonder emporium', 2007, 'Mr. Magorium''s Wonder Emporium''s title is much more fun that the film itself, as the colorful visuals and talented players can''t make up for a bland story.', TO_DATE('2007-11-12', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr mom', 2002, 'Mr. Mom makes up for its stereotype-driven premise with a sweet script and charming work from a well-matched cast led by Michael Keaton and Teri Garr.', TO_DATE('2002-07-29', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr nobody', 2010, 'Mr. Nobody''s narrative tangles may bedevil as much as they entertain, but its big ambitions and absorbing visuals make for an intriguing addition to director Jaco Van Dormael''s filmography.', TO_DATE('2010-07-28', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr peabody sherman', 2014, 'Mr. Peabody & Sherman offers a surprisingly entertaining burst of colorful all-ages fun, despite its dated source material and rather convoluted plot.', TO_DATE('2014-02-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr poppers penguins', 2011, 'Blandly inoffensive and thoroughly predictable, Mr. Popper''s Penguins could have been worse -- but it should have been better.', TO_DATE('2011-06-14', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr right', 2015, 'Sam Rockwell and Anna Kendrick work well together, but Mr. Right is too much of a tonal jumble to take advantage of their chemistry.', TO_DATE('2015-09-17', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr saturday night', 1992, 'Billy Crystal''s flawed directorial debut can''t seem to decide whether it wants the viewer to love its protagonist or hate him, but it features fine work from Crystal and his co-stars.', TO_DATE('1992-09-23', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr smith goes to washington', 2000, 'Mr. Smith Goes to Washington -- and returns with an uplifting ode to idealism that distills the strengths of its director and leading man.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr turner', 2014, 'Led by a masterful performance from Timothy Spall and brilliantly directed by Mike Leigh, Mr. Turner is a superior Hollywood biopic.', TO_DATE('2014-05-15', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr woodcock', 2007, 'Underutilizing a talented cast, Mr. Woodcock lacks the comic energy and timing to make the most of its intriguing premise.', TO_DATE('2007-09-05', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mr wrong', 1996, 'A mean-spirited joke without a punchline, Mr. Wrong is so painfully unfunny that Ellen DeGeneres and Bill Pullman''s lack of chemistry feels like a total drag despite being the point.', TO_DATE('1996-02-16', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mrs brown', 1997, 'Thanks to some top notch acting, the chemistry between its stars, and a witty, thoughtful script, Mrs. Brown delivers a nuanced and entertaining, if not entirely factual, account of a seldom explored historical relationship.', TO_DATE('1997-07-18', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mrs doubtfire', 2000, 'On paper, Mrs. Doubtfire might seem excessively broad or sentimental, but Robin Williams shines so brightly in the title role that the end result is difficult to resist.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mrs henderson presents', 2005, 'Judi Dench and Bob Hoskins shine in this warm, witty period piece.', TO_DATE('2005-09-09', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mrs hyde madame hyde', 2017, 'Madame Hyde has a handful of interesting ideas and a typically radiant performance from Isabelle Huppert, although it''s all still a little less than the sum of its parts.', TO_DATE('2017-08-07', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mrs lowry son', 2019, 'Mrs. Lowry & Son brings a pair of outstanding actors together -- and tests the limits of how much two performances can do to enliven a substandard script.', TO_DATE('2019-07-02', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mrs miniver', 1942, 'An excessively sentimental piece of propaganda, Mrs. Miniver nonetheless succeeds, due largely to Greer Garson''s powerful performance.', TO_DATE('1942-06-04', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mrs palfrey at the claremont', 2005, 'Bittersweet and endearing, this film about aging and unexpected friendship is a lovely vehicle for Joan Plowright.', TO_DATE('2005-11-16', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('much ado about nothing', 2012, 'Lighthearted to a fault, Much Ado About Nothing''s giddy energy and intimate charm make for an entertaining romantic comedy -- and a Shakespearean adaptation that''s hard to resist.', TO_DATE('2012-09-10', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mud', 2012, 'Bolstered by a strong performance from Matthew McConaughey in the title role, Mud offers an engaging Southern drama that manages to stay sweet and heartwarming without being sappy.', TO_DATE('2012-05-26', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mudbound', 2017, 'Mudbound offers a well-acted, finely detailed snapshot of American history whose scenes of rural class struggle resonate far beyond their period setting.', TO_DATE('2017-01-21', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mugabe and the white african', 2010, 'As much legal thriller as objective documentary, this account of a farmer''s battle with Zimbabwe''s regime serves as a powerful and emotional attack upon President Mugabe.', TO_DATE('2010-01-07', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mulan', 1998, 'Exploring themes of family duty and honor, Mulan breaks new ground as a Disney film, while still bringing vibrant animation and sprightly characters to the screen.', TO_DATE('1998-06-19', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mule', 2014, 'Smarter than its scatological premise might suggest, The Mule offers solidly explosive laughs for fans of dark comedy.', TO_DATE('2014-10-16', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mulholland drive', 2001, 'David Lynch''s dreamlike and mysterious Mulholland Drive is a twisty neo-noir with an unconventional structure that features a mesmirizing performance from Naomi Watts as a woman on the dark fringes of Hollywood.', TO_DATE('2001-05-17', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mulholland falls', 1996, 'Mulholland Falls'' vacant characterizations and thin story undercuts its impressive cast and potent style, making for an empty exercise in noir posturing.', TO_DATE('1996-04-26', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('multiplicity', 1996, 'This high-concept experiment only proves that a comedy actually can have too much Michael Keaton.', TO_DATE('1996-07-17', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mumford', 2000, 'Memorable moments are few and far between.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mummy returns', 2000, 'In The Mummy Returns, the special effects are impressive, but the characters seem secondary to the computer generated imagery.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mummy tomb of the dragon emperor', 2008, 'With middling CG effects and a distinct lack of fun, The Mummy: Tomb of the Dragon Emperor finds the series past its prime.', TO_DATE('2008-07-29', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('munich', 2005, 'Munich can''t quite achieve its lofty goals, but this thrilling, politically even-handed look at the fallout from an intractable political conflict is still well worth watching.', TO_DATE('2005-12-07', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the muppet christmas carol', 2000, 'It may not be the finest version of Charles Dickens'' tale to grace the screen, but The Muppet Christmas Carol is funny and heartwarming, and serves as a good introduction to the story for young viewers.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the muppet movie', 2001, 'The Muppet Movie, the big-screen debut of Jim Henson''s plush creations, is smart, lighthearted, and fun for all ages.', TO_DATE('2001-05-30', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('muppet treasure island', 1996, 'Though less Muppet-centric than the original trilogy, Muppet Treasure Island is an energetic, cheerful take on Robert Louis Stevenson''s classic adventure, with typically solid gags.', TO_DATE('1996-02-16', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('muppets from space', 2000, 'If Muppets from Space lacks the magic and wit of its cinematic predecessors, this pleasingly silly space romp is funny and clever enough to make for better-than-average family entertainment.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('muppets most wanted', 2014, 'While it may not reach the delirious heights of The Muppets, Muppets Most Wanted still packs in enough clever gags, catchy songs, and celebrity cameos to satisfy fans of all ages.', TO_DATE('2014-03-11', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the muppets take manhattan', 2001, 'If it''s not quite as sharp as The Muppet Movie, The Muppets Take Manhattan is still a smart, delightfully old-fashioned tale that follows the formula established by the first two movies -- a madcap adventure assisted by a huge group of human stars.', TO_DATE('2001-06-26', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('murder in the first', 1994, 'Despite a strong cast and story inspired by incredible real-life events, Murder in the First is strictly second rate.', TO_DATE('1994-06-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('murder mystery', 2019, 'Murder Mystery reunites Jennifer Aniston and Adam Sandler for a lightweight comedy that''s content to settle for merely mediocre.', TO_DATE('2019-06-13', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('murder on the orient express', 2000, 'Murder, intrigue, and a star-studded cast make this stylish production of Murder on the Orient Express one of the best Agatha Christie adaptations to see the silver screen.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('murder on the orient express', 2017, 'Stylish production and an all-star ensemble keep this Murder on the Orient Express from running off the rails, even if it never quite builds up to its classic predecessor''s illustrious head of steam.', TO_DATE('2017-11-02', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('muriels wedding', 2000, 'Heartfelt and quirky, though at times broad, Muriel''s Wedding mixes awkward comedy, oddball Australian characters, and a nostalgia-heavy soundtrack.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('muscle shoals', 2013, 'Essential for soul fans and entertaining for novices, Muscle Shoals offers a compelling, warts-and-all glimpse at one of the most fascinating stories in modern American music.', TO_DATE('2013-04-23', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the muse', 2000, 'Despite quirky and original writing, the subject matter feels too removed to produce laughs.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('museum hours', 2013, 'Its languid pace may frustrate some viewers, but for patient filmgoers, Museum Hours offers a carefully observed portrait of the human condition.', TO_DATE('2013-06-18', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('music and lyrics', 2007, 'Music & Lyrics is a light and pleasant romantic comedy that succeeds because of the considerable charm of its co-stars. The music segments featuring Hugh Grant are worth the price of admission.', TO_DATE('2007-02-03', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('music from the inside out', 2005, 'Music from the Inside Out lets the act of making music -- and the work that goes into it -- speak for itself, offering an engaging look at the life of an orchestra member along the way.', TO_DATE('2005-04-22', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('music of the heart', 2000, 'Meryl Streep''s depiction of an ordinary person doing extraordinary things transcends, inspires, and entertains.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('music within', 2007, 'Music Within is a well-intentioned but pedestrian production of a story that deserves better treatment.', TO_DATE('2007-10-21', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('must love dogs', 2005, 'Despite good work from its likable leads, the romantic comedy Must Love Dogs is too predictable.', TO_DATE('2005-07-24', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mustang', 2015, 'Mustang delivers a bracing -- and thoroughly timely -- message whose power is further bolstered by the efforts of a stellar ensemble cast.', TO_DATE('2015-09-15', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mutant chronicles', 2008, 'Bad acting, poor CGI and clunky script mean this sci-fi thriller is lacking in all departments including the thrills.', TO_DATE('2008-09-16', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mute', 2018, 'Visually polished but narratively derivative and overall muddled, Mute is a would-be sci-fi epic whose title serves as an unfortunate guide to how it might be best enjoyed.', TO_DATE('2018-02-23', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mutual appreciation', 2005, 'Director Bujalski continues to give cinematic voice to awkward, literate twentysomethings with noteworthy smarts and tenderness.', TO_DATE('2005-12-17', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my dog tulip', 2010, 'A beautifully animated diversion, My Dog Tulip is as comforting and delightful as cuddling with your own canine companion.', TO_DATE('2010-08-24', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my all american', 2015, 'My All American has a genuinely moving real-life story to tell, but writer-director Angelo Pizzo fumbles it into manipulative, melodramatic tearjerker territory.', TO_DATE('2015-11-11', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my amityville horror', 2012, 'My Amityville Horror offers an unsettlingly ambiguous personal perspective on the true story that spawned a horror franchise.', TO_DATE('2012-10-11', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my beautiful laundrette', 1985, 'My Beautiful Laundrette is fast and all over the place because it has so much to say, and show, including a highly watchable fresh-faced Daniel Day-Lewis.', TO_DATE('1985-09-07', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my best friend', 2007, 'Although the plot may sound contrived, the performances of Daniel Auteuil and Dany Boon manage to turn My Best Friend into an earnest and witty romp.', TO_DATE('2007-06-03', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my best friends wedding', 2000, 'Thanks to a charming performance from Julia Roberts and a subversive spin on the genre, My Best Friend''s Wedding is a refreshingly entertaining romantic comedy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my big fat greek wedding', 2002, 'Though it sometimes feels like a television sitcom, My Big Fat Greek Wedding is good-hearted, lovable, and delightfully eccentric, with a sharp script and lead performance from Nia Vardalos.', TO_DATE('2002-04-09', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my big fat greek wedding 2', 2016, 'My Big Fat Greek Wedding 2 is as sweet and harmless as the original, but its collection of sitcom gags and stereotypes never coalesces into anything resembling a story with a purpose.', TO_DATE('2016-03-21', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my blind brother', 2016, 'My Blind Brother takes a refreshingly character-driven approach to its familiar sibling rivalry while adding a somewhat unexpected twist.', TO_DATE('2016-03-15', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my bloody valentine 3d', 2008, 'This gory, senses-assaulting slasher film is an unpretentious, effective mix of old-school horror stylings and modern 3D technology.', TO_DATE('2008-12-16', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my blueberry nights', 2007, 'Though well filmed, My Blueberry Nights is a mixed bag of dedicated performers working with thin material.', TO_DATE('2007-05-16', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my bodyguard', 2002, 'T. Bill debuts as an affectionate director, keenly aware of growing pains.', TO_DATE('2002-01-30', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my bosss daughter', 2003, 'Offensive, incoherent, and ineptly acted and directed.', TO_DATE('2003-08-21', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my brother the devil', 2012, 'A tough, tender tale of familial angst with careful attention to detail, My Brother the Devil is a strong debut from director Sally El Hosaini.', TO_DATE('2012-01-26', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my country my country', 2006, 'This war documentary offers a valuable look at Iraqi life under the U.S. occupation, and finds a compelling central subject in Dr. Riyadh.', TO_DATE('2006-03-21', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my cousin rachel', 2017, 'Excellent cinematography and Rachel Weisz''s entrancing performance keep My Cousin Rachel alluring despite a central mystery that''s rather easily unlocked.', TO_DATE('2017-06-02', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my cousin vinny', 2000, 'The deft comic interplay between Joe Pesci and Marisa Tomei helps to elevate My Cousin Vinny''s predictable script, and the result is a sharp, hilarious courtroom comedy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my darling clementine', 2000, 'Canny and coolly confident, My Darling Clementine is a definitive dramatization of the Wyatt Earp legend that shoots from the hip and hits its target in breezy style.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my date with drew', 2004, 'A love-it-or-hate-it stalkerazzi documentary, My Date With Drew effectively draws on America''s celeb-obsessed pop culture so that viewers either unabashedly identify with it, or are filing restraining orders on Drew Barrymore''s behalf.', TO_DATE('2004-04-03', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my days of mercy', 2017, 'Though My Days of Mercy''s knotty romance drifts into melodrama, it''s grounded by Ellen Page and Kate Mara''s exceptional chemistry.', TO_DATE('2017-09-09', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my dinner with hervé', 2018, 'My Dinner with Hervé offers a standard narrative on celebrity and infamy, but formidable performances by Peter Dinklage and Jamie Dornan find the dimensionality and pathos of Hervé Villechaize the man.', TO_DATE('2018-10-16', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my dog skip', 2000, 'Critics say My Dog Skip is cute, wholesome entertainment for the family. It''s especially designed to appeal to your sentiment, but you might find yourself choking up just the same.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my entire high school sinking into the sea', 2016, 'My Entire High School Sinking Into the Sea''s attention-getting visual style matches debuting writer-director Dash Shaw''s distinctive narrative approach -- and signals a bright future for a promising talent.', TO_DATE('2016-09-11', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my favorite martian', 2000, 'Loud, effects-ridden comedy with no real humor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my favorite year', 2000, 'My Favorite Year is a joyful ode to the early days of television, carried with a deft touch and Peter O''Toole''s uproariously funny performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my fellow americans', 2000, 'It doesn''t commit any impeachable offenses, but My Fellow Americans lacks strong regulatory oversight of its toothless political satire and misuse of comedic talent.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my first mister', 2001, 'Though well-acted, My First Mister succumbs to contrived sentimentality in its last half.', TO_DATE('2001-02-28', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my flesh and blood', 2003, 'Disturbing and heart-wrenching documentary about a 53-years-old woman raising 11 children.', TO_DATE('2003-02-12', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my friend dahmer', 2017, 'My Friend Dahmer opens a window into the making of a serial killer whose conclusions are as empathetic as they are deeply troubling.', TO_DATE('2017-04-24', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my golden days trois souvenirs de ma jeunesse', 2015, 'My Golden Years is a complex, well-acted coming-of-age drama.', TO_DATE('2015-07-20', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my journey through french cinema voyage à travers le cinéma français', 2017, 'Bertrand Tavernier is an engaging guide through this Journey Through French Cinema, curating a revelatory tour through his homeland''s film history with a personal touch that will delight movie fans and the culturally curious alike.', TO_DATE('2017-06-18', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my kid could paint that', 2007, 'Director Amir Bar-Lev grapples with exposing the authenticity of four-year-old Marla''s paintings at the sake of burdening her publicly shamed family to transfixing results.', TO_DATE('2007-01-23', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my left foot', 2000, 'No doubt most will come to My Left Foot for Daniel Day-Lewis'' performance, but the movie''s refusal to go downbeat will keep it in viewer minds afterwards.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my life as a dog mitt liv som hund', 2000, 'A coming-of-age story with uncommon depth and sensitivity, My Life as a Dog is sweet, sincere, and utterly charming.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my life as a zucchini ma vie de courgette', 2016, 'My Life as a Zucchini''s silly title and adorable characters belie a sober story whose colorful visuals delight the senses even as it braves dark emotional depths.', TO_DATE('2016-05-15', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my life in ruins', 2009, 'With stereotypical characters and a shopworn plot, My Life in Ruins is a charmless romantic comedy.', TO_DATE('2009-05-05', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my little pony the movie', 2017, 'Charming and sweet, My Little Pony: The Movie will please its dedicated fanbase, even if it''s unlikely to encourage non-devotees to gallop along for the ride.', TO_DATE('2017-10-05', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my name is khan', 2010, 'My Name Is Khan rests on powerful performances to tell an affecting story that blends timely themes and old-fashioned Bollywood melodrama.', TO_DATE('2010-02-15', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my neighbor totoro', 2001, 'My Neighbor Totoro is a heartwarming, sentimental masterpiece that captures the simple grace of childhood.', TO_DATE('2001-07-25', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my old lady', 2014, 'Although My Old Lady doesn''t quite live up to its stars'' talents, Kevin Kline and Maggie Smith carry the film capably whenever they''re together onscreen.', TO_DATE('2014-09-06', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my own private idaho', 2000, 'A tantalizing glimpse of a talented director and his stars all at the top of their respective games, Gus Van Sant''s loose reworking of Henry IV is smart, sad and audacious.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my son my son what have ye done', 2009, 'Enigmatic and digressive, this mystical potboiler possesses director Werner Herzog''s penchant for offbeat atmosphere, but lacks the absurdist humor and profundity that makes his previous trips into madness compelling.', TO_DATE('2009-09-18', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my summer of love', 2004, 'My Summer of Love is a moody, bittersweet love story featuring outstanding performances from the leads.', TO_DATE('2004-11-23', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my super exgirlfriend', 2006, 'My Super Ex=Girlfriend is an only sporadically amusing spoof on the superhero genre that misses the mark with a nerd-turned-superwoman who embodies sexist clichés.', TO_DATE('2006-07-17', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('my week with marilyn', 2011, 'Michelle Williams shines in My Week with Marilyn, capturing the magnetism and vulnerability of Marilyn Monroe.', TO_DATE('2011-10-09', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mysteries of lisbon', 2010, 'Mysteries of Lisbon achieves an epic heft through an unhurried pace and lush photography, its beguiling episodes culminating in an impressive whole that justifies a lengthy runtime.', TO_DATE('2010-10-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mysteries of pittsburgh', 2008, 'A listless interpretation of Michael Chabon''s first novel, Mysteries of Pittsburgh features none of the source material''s charm, but has coming-of-age film cliches in abundance.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mysterious skin', 2005, 'Bold performances and sensitive, spot-on direction make watching this difficult tale of trauma and abuse a thought-provoking, resonant experience.', TO_DATE('2005-04-02', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mystery alaska', 1999, 'The lack of hockey action and authenticity left critics cold.', TO_DATE('1999-10-01', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mystery men', 2000, 'Absurd characters and quirky gags are brought to life by a talented cast, providing this superhero spoof with lots of laughs.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mystery road', 2013, 'Mystery Road evokes classic Westerns while using its Australian outback setting to delve into a surprisingly layered -- and powerfully impactful -- array of social issues.', TO_DATE('2013-09-23', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mystery science theater 3000 the movie', 2000, 'Mystery Science Theater 3000: The Movie may be thin and uneven, but it''s hilarious in enough of the right spots to do the show''s big-screen transition justice.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mystic pizza', 2000, 'Mystic Pizza is like its namesake food: it''s cheesy, topped with romance, and rises to the occasion.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('mystic river', 2003, 'Anchored by the exceptional acting of its strong cast, Mystic River is a somber drama that unfolds in layers and conveys the tragedy of its story with visceral power.', TO_DATE('2003-05-23', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the myth of the american sleepover', 2011, 'Somber and sweet, The Myth of the American Sleepover authentically evokes adolescence -- and all of the awkwardness and heartbreak that comes with it.', TO_DATE('2011-04-04', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nabbeun namja bad guy', 2003, 'Lurid without enough evident deeper meaning to justify its prurient impulses, Bad Guy runs the gamut from confusing to simply off-putting.', TO_DATE('2003-10-07', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nacho libre', 2006, 'At times hilarious, but other times offensive, Director Jared Hess is unable to recapture the collective charisma of his Napoleon characters, instead relying on a one-joke concept that runs out of steam. Sure to entertain the adolescents, however.', TO_DATE('2006-06-13', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the naked gun 2 12 the smell of fear', 1991, 'Naked Gun 2 1/2: The Smell of Fear delivers a handful of moderate laughs, but overall, its strained antics pale in comparison to its gut-busting predecessor.', TO_DATE('1991-06-28', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the namesake', 2006, 'An ambitious exploration of the immigrant experience with a talented cast that serves the material well.', TO_DATE('2006-09-02', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nancy drew', 2007, 'Emma Roberts is bubbly and charming as Nancy Drew, the junior detective. But despite her best efforts, Nancy Drew still lacks excitement, surprise, and compelling secondary characters.', TO_DATE('2007-06-09', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nancy drew and the hidden staircase', 2019, 'Elevated by a well-cast Sophia Lillis, Nancy Drew and the Hidden Staircase leads audiences into a genially entertaining new take on the venerable character.', TO_DATE('2019-03-10', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nanking', 2007, 'This powerful and horrific documentary brings the atrocities committed at Nanking to light without sugarcoating any of the brutality.', TO_DATE('2007-01-24', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the nanny diaries', 2007, 'The Nanny Diaries'' miscast lead and unrealistic, one-dimensional characters make this class satire far less effective than it should''ve been.', TO_DATE('2007-08-16', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nanny mcphee', 2005, 'A bit alarming at first, Nanny McPhee has a hard edge to counter Mary Poppins-style sweetness, but it still charms us and teaches some valuable lessons.', TO_DATE('2005-07-21', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nanny mcphee returns', 2010, 'Emma Thompson''s second labor of love with the Nanny McPhee character actually improves on the first, delivering charming family fare with an excellent cast.', TO_DATE('2010-03-18', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nanook of the north', 2002, 'An enthralling documentary and a visual feat, Nanook of the North fascinates with its dramatic depiction of life in an extremely hostile environment.', TO_DATE('2002-08-16', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('napoleon dynamite', 2004, 'A charming, quirky, and often funny comedy.', TO_DATE('2004-02-18', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nappily ever after', 2018, 'Smart and socially conscious, Nappily Ever After depicts black female empowerment in a fresh way, but the film relies too heavily on romantic comedy tropes.', TO_DATE('2018-09-20', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('naqoyqatsi naqoyqatsi life as war', 2002, 'The weakest film in Reggio''s trilogy.', TO_DATE('2002-08-21', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('narc', 2002, 'Jason Patric and Ray Liotta are electrifying in this gritty, if a little too familiar, cop drama.', TO_DATE('2002-07-17', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('narco cultura', 2013, 'Disturbing, thought-provoking, and timely, Narco Cultura sheds some crucial light on an important -- and underserved -- subject.', TO_DATE('2013-09-26', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nas time is illmatic', 2014, 'Comprehensive yet brisk, Nas: Time Is Illmatic offers an absorbing look at a hip-hop classic and the life of the artist who made it.', TO_DATE('2014-04-18', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nascar the imax experience', 2004, 'A thrill ride for fans, but those looking for a deeper experience will be choking on exhaust.', TO_DATE('2004-03-09', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nashville', 2000, 'Robert Altman captures the bravado and cynicism of the American dream in Nashville, a sprawling epic bursting with vivid performances and an unforgettable soundtrack.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nasty baby', 2015, 'Nasty Baby juggles an ambitious array of tones, and not always successfully -- but its talented cast and surprising narrative twists leave a lingering impression.', TO_DATE('2015-01-25', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('national lampoons gold diggers', 2004, 'It aspires to Farrelly-level offensiveness, but the PG-13 rating and a dearth of decent gags renders Gold Diggers tame, toothless, and dull.', TO_DATE('2004-08-14', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('national lampoons animal house', 2000, 'The talents of director John Landis and Saturday Night Live''s irrepressible John Belushi conspired to create a rambunctious, subversive college comedy that continues to resonate.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('national lampoons christmas vacation', 2000, 'While Christmas Vacation may not be the most disciplined comedy, it''s got enough laughs and good cheer to make for a solid seasonal treat.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('national lampoons european vacation', 2002, 'European Vacation charts a course through a succession of pretty destinations, but the journey itself lacks the laughs that made the original outing so memorable.', TO_DATE('2002-04-20', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('national lampoons loaded weapon 1', 2000, 'Loaded Weapon 1 hits all the routine targets with soft squibs, yielding a tired parody that cycles through its laundry list of references with little comedic verve.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('national lampoons vacation', 2002, 'Blessed by a brilliantly befuddled star turn from Chevy Chase, National Lampoon''s Vacation is one of the more consistent -- and thoroughly quotable -- screwball comedies of the 1980s.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('national lampoons van wilder', 2002, 'A derivative gross-out comedy that''s short on laughs.', TO_DATE('2002-02-04', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('national security', 2003, 'The action in National Security is mindless, while the humor says nothing insightful about racial issues.', TO_DATE('2003-01-15', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('national treasure', 2004, 'National Treasure is no treasure, but it''s a fun ride for those who can forgive its highly improbable plot.', TO_DATE('2004-10-25', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('national treasure book of secrets', 2007, 'A talented cast goes to waste in the improbable National Treasure: Book of Secrets, which is eerily similar to the first film.', TO_DATE('2007-12-19', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('national velvet', 2000, 'National Velvet makes the most of a breakout performance from Elizabeth Taylor, delivering a timeless family-friendly tearjerker that avoids straying into the sentimental.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the nativity story', 2006, 'The Nativity Story is a dull retelling of a well-worn tale with the look and feel of a high-school production.', TO_DATE('2006-11-22', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the natural', 2001, 'Though heavy with sentiment, The Natural is an irresistible classic, and a sincere testament to America''s national pastime.', TO_DATE('2001-04-17', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('natural born killers', 1994, 'Natural Born Killers explodes off the screen with style, but its satire is too blunt to offer any fresh insight into celebrity or crime -- pummeling the audience with depravity until the effect becomes deadening.', TO_DATE('1994-08-26', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tell no one ne le dis à personne', 2006, 'An intense, well-crafted thriller, Tell No One is equal parts heart-pounding and heart-wrenching.', TO_DATE('2006-05-22', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nebraska', 2013, 'Elegant in its simplicity and poetic in its message, Nebraska adds another stirringly resonant chapter to Alexander Payne''s remarkable filmography.', TO_DATE('2013-05-23', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('necessary roughness', 1991, 'This likeable, goofy football comedy has its moments, but it ultimately adheres too closely to the sports movie playbook to overcome the cliches in the script.', TO_DATE('1991-09-27', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('need for speed', 2014, 'With stock characters and a preposterous plot, this noisily diverting video game adaptation fulfills a Need for Speed and little else.', TO_DATE('2014-03-08', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('neighbors', 2014, 'With plenty of bawdy humor evenly spread between its well-matched stars, Neighbors earns its R rating -- and filmgoers'' laughs.', TO_DATE('2014-03-09', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('neighbors 2 sorority rising', 2016, 'Neighbors 2: Sorority Rising may not be strictly necessary, but it still wrings a surprising amount of humor from a recycled premise with a distaff twist.', TO_DATE('2016-05-04', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nekrotronic', 2018, 'Nekrotonic has plenty of oddball energy, but this horror-comedy hybrid mashes up ingredients without much of a clear idea of what to do with them.', TO_DATE('2018-09-08', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nell', 1994, 'Despite a committed performance by Jodie Foster, Nell opts for ponderous melodrama instead of engaging with the ethical dilemmas of socializing its titular wild child.', TO_DATE('1994-12-14', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('neon bull boi neon', 2015, 'Neon Bull''s hypnotic visual poetry occasionally borders on exploitation, though its reflective nature softens its animalistic gaze.', TO_DATE('2015-10-16', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nerve', 2016, 'Nerve''s fast pace and charming leads help overcome a number of fundamental flaws, adding up to a teen-friendly thriller with enough energy to occasionally offset its muddled execution.', TO_DATE('2016-07-26', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the net', 1995, 'The premise isn''t without potential and Sandra Bullock is as likable as ever, but The Net lacks sufficient thrills -- or plausible plot points -- to recommend catching.', TO_DATE('1995-07-28', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('network', 2000, 'Driven by populist fury and elevated by strong direction, powerful acting, and an intelligent script, Network''s searing satire of ratings-driven news remains sadly relevant more than four decades later.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('never apologize a personal visit with lindsay anderson', 2008, 'Essentially a stage production of Malcolm Macdowell musing over his departed friend, and brit director Lindsey Anderson. Macdowell makes for an engaging raconteur, but only for Anderson fans.', TO_DATE('2008-08-14', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('never back down', 2008, 'Though not without its pleasures, Never Back Down faithfully adheres to every imaginable fight movie cliché.', TO_DATE('2008-02-22', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('never been kissed', 2000, 'Unoriginal and unremarkable high school satire adds little to the genre.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('never been thawed', 2005, 'Pokes fun at the obsessive personalities that make up peculiar American subcultures, but misses its targets too often to be more than merely passable.', TO_DATE('2005-04-11', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('never die alone', 2004, 'DMX''s menacing charisma is put to good use in this stylish but hackneyed modern-day noir.', TO_DATE('2004-01-29', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('never let me go', 2010, 'With Never Let Me Go, Mark Romanek has delivered a graceful adaptation that captures the spirit of the Ishiguro novel -- which will be precisely the problem for some viewers.', TO_DATE('2010-09-05', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('never rarely sometimes always', 2020, 'Powerfully acted and directed, Never Rarely Sometimes Always reaffirms writer-director Eliza Hittman as a filmmaker of uncommon sensitivity and grace.', TO_DATE('2020-01-25', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('never say never again', 1983, 'While the rehashed story feels rather uninspired and unnecessary, the return of both Sean Connery and a more understated Bond make Never Say Never Again a watchable retread.', TO_DATE('1983-10-07', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('never talk to strangers', 2000, 'Never Talk to Strangers -- and never make the mistake of believing this silly stalker mystery is the best available viewing option.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('new best friend', 2002, 'Generic, confusing, and trashy, New Best Friend is a laughably bad, obvious campus whodunit.', TO_DATE('2002-04-09', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('new in town', 2009, 'Cliched and short on charm, New In Town is a pat genre exercise that fails to bring the necessary heat to its Minnesota setting.', TO_DATE('2009-01-23', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('new jack city', 1800, 'Stylishly directed by Mario Van Peebles, New Jack City offsets its melodramatic streak with electrifying action and a cavalcade of effective performances.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a new leaf', 2000, 'Elaine May is a comedic dynamo both behind and in front of the camera in this viciously funny screwball farce, with able support provided by Walter Matthau.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('new years eve', 2011, 'Shallow, sappy, and dull, New Year''s Eve assembles a star-studded cast for no discernible purpose.', TO_DATE('2011-12-05', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('new york doll', 2005, 'Arthur Kane is a fascinating subject in what ultimately proves to be a touching, bittersweet documentary.', TO_DATE('2005-08-20', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('new york i love you', 2009, 'Like many anthologies, New York, I Love You has problems of consistency, but it isn''t without its moments.', TO_DATE('2009-09-30', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('new york minute', 2004, 'Feels more like a calculated product designed to expand the Olsens'' brand than an actual movie. Also, it contains ethnic stereotyping and sexual innuendo.', TO_DATE('2004-03-31', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('newsies', 2000, 'Extra! Extra! Read all about Newsies instead of suffering through its underwhelming musical interludes, although Christian Bale makes for a spirited hero.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the newton boys', 1998, 'The Newton Boys uses a sharp cast and absorbing period detail to help make up for the frustrations of a story puzzlingly short on dramatic tension.', TO_DATE('1998-03-27', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('next', 2007, 'Numerous plot holes and poorly motivated characters prevent Next from being the thought-provoking sci-fi flick it could''ve been.', TO_DATE('2007-04-25', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the next best thing', 2000, 'Story elements clash and acting falls short.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('next day air', 2009, 'Rife with half-baked jokes and excessive violence, Next Day Air is an uninspired stoner comedy.', TO_DATE('2009-05-06', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('next friday', 2000, 'Next Friday lacks the fun of the original Friday. The movie is messy and plotless and relies on unfunny vulgar gags.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('next goal wins', 2014, 'Finding beauty in sports beyond the mere satisfaction of winning, Next Goal Wins is a moving documentary filled with a lovable array of underdogs.', TO_DATE('2014-04-22', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the next karate kid', 2000, 'The Next Karate Kid is noteworthy for giving audiences the chance to see a pre-Oscars Hilary Swank, but other than a typically solid performance from Pat Morita, this unnecessary fourth installment in the franchise has very little to offer.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('next stop wonderland', 2000, 'Endearing performances create characters you care about.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the next three days', 2010, 'Russell Crowe and Elizabeth Banks give it their all, but their solid performances aren''t quite enough to compensate for The Next Three Days'' uneven pace and implausible plot.', TO_DATE('2010-11-10', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nick and norahs infinite playlist', 2008, 'Nick and Norah''s Infinite Playlist combines a pair of charming leads, a classic New York backdrop, and a sweet soundtrack.', TO_DATE('2008-09-06', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nick of time', 1995, 'It isn''t the worst ''90s action thriller, but by bungling a story pitting Johnny Depp against Christopher Walken, the rote Nick of Time ranks among the most disappointing.', TO_DATE('1995-11-22', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nicotina', 2004, 'Nicotina has plenty of action, but all that energy isn''t enough to cover for the forgettable story between the set pieces.', TO_DATE('2004-07-26', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('night at the museum', 2006, 'Parents might call this either a spectacle-filled adventure or a shallow and vapid CG-fest, depending on whether they choose to embrace this on the same level as their kids.', TO_DATE('2006-12-14', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('night at the museum 2 battle of the smithsonian', 2009, 'Night at the Museum: Battle at the Smithsonian is busy enough to keep the kids interested but the slapstick goes overboard and the special effects (however well executed) throw the production into mania.', TO_DATE('2009-05-18', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('night at the museum secret of the tomb', 2014, 'While not without its moments, Night at the Museum: Secret of the Tomb is a less-than-inspired sendoff for the trilogy.', TO_DATE('2014-12-12', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a night at the roxbury', 2000, 'Has the same problems as the worst SNL movies: one-note characters and plots unreasonably stretched to feature length runtime.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('night catches us', 2010, 'A bold, original debut, Night Catches Us personalizes a tumultuous period in American history thanks to strong performances from Anthony Mackie and Kerry Washington.', TO_DATE('2010-03-30', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('night comes on', 2018, 'Steadily drawing viewers into its harrowing tale with equal parts grim intensity and startling compassion, Night Comes On heralds the arrivals of debuting director Jordan Spiro and her magnetic young stars.', TO_DATE('2018-01-20', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('night hunter nomis', 2019, 'Contrived and cliched, Night Hunter wastes a solid cast in pursuit of action-adventure thrills that stubbornly refuse to materialize.', TO_DATE('2019-08-18', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('night moves', 2013, 'A uniquely character-driven thriller with a finely composed cast and some outstanding direction from Kelly Reichardt, Night Moves bolsters its thought-provoking themes with compelling drama.', TO_DATE('2013-08-30', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the night of the hunter', 2000, 'Featuring Robert Mitchum''s formidable performance as a child-hunting preacher, The Night of the Hunter is a disturbing look at good and evil.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('night of the living dead', 1800, 'Night of the Living Dead doesn''t quite reinvent the original''s narrative, but its sleek action and amplified gore turn it into a worthy horror showcase.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('il portiere di notte the night porter', 2002, 'The Night Porter''s salaciousness gives its exploration of historical trauma a bitter aftertaste, but audiences seeking provocation are unlikely to forget the sting of this erotic drama.', TO_DATE('2002-08-06', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('night school', 2018, 'Night School''s funny stars and seemingly promising setup add up to a disappointingly scattershot comedy whose laughs are largely held in detention.', TO_DATE('2018-09-26', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('night shift', 2000, 'Night Shift bristles with pitch-perfect laughs thanks to Ron Howard''s snappy direction and a side-splitting turn from Michael Keaton.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('night watch', 2005, 'This Russian horror/fantasy film pits darkness and light against each other using snazzy CGI visuals to create an extraordinary atmosphere of a dank, gloomy city wrestling with dread.', TO_DATE('2005-04-28', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nightbreed', 1990, 'Nightbreed''s imaginative world-building and startling creature designs are no match for its clumsy, uneven plotting.', TO_DATE('1990-02-16', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nightcrawler', 2014, 'Restless, visually sleek, and powered by a lithe star performance from Jake Gyllenhaal, Nightcrawler offers dark, thought-provoking thrills.', TO_DATE('2014-09-05', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nightingale', 2015, 'Nightingale serves up a breathtaking solo performance by David Oyelowo in a film served well by its modest cinematic style.', TO_DATE('2015-05-25', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the nightmare before christmas', 2000, 'The Nightmare Before Christmas is a stunningly original and visually delightful work of stop-motion animation.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nightmare cinema', 2018, 'Admirably eclectic yet more consistent than most horror anthologies, Nightmare Cinema should entertain viewers in the mood for a good old-fashioned creepshow.', TO_DATE('2018-07-12', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a nightmare on elm street', 2000, 'Wes Craven''s intelligent premise, combined with the horrifying visual appearance of Freddy Krueger, still causes nightmares to this day.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a nightmare on elm street', 2010, 'Visually faithful but lacking the depth and subversive twists that made the original so memorable, the Nightmare on Elm Street remake lives up to its title in the worst possible way.', TO_DATE('2010-04-28', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nights in rodanthe', 2008, 'Derivative and schmaltzy, Nicholas Sparks'' Nights in Rodanthe is strongly mottled by contrivances that even the charisma of stars Diane Lane and Richard Gere can''t repair.', TO_DATE('2008-09-20', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nights of cabiria le notti di cabiria', 2000, 'Giulietta Masina is remarkable as a chronically unfortunate wretch with an indomitable spirit in Federico Fellini''s unrelentingly bleak -- yet ultimately uplifting -- odyssey through heartbreak.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nims island', 2008, 'Despite good intentions, Nim''s Island flounders under an implausible storyline, simplistic stock characters, and distracting product placement.', TO_DATE('2008-03-26', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nine', 2009, 'It has a game, great-looking cast, led by the always worthwhile Daniel Day-Lewis, but Rob Marshall''s Nine is chaotic and curiously distant.', TO_DATE('2009-12-04', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nine lives', 2016, 'Not meow, not ever.', TO_DATE('2016-08-04', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nine months', 1995, 'Nine Months finds writer-director Chris Columbus playing to his worst comedic instincts -- and relying far too heavily on the trademark tics of his miscast leading man.', TO_DATE('1995-07-14', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ninotchka', 2000, 'With Greta Garbo proving her comedy chops in the twilight of her career, Ninotchka is a can''t-miss classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ninth gate', 2000, 'Even though the film is stylish and atmospheric, critics say The Ninth Gate meanders aimlessly and is often ludicrous. And despite the advertising, there''s hardly any chills.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nixon', 1995, 'Much like its subject''s time in office, Nixon might have ended sooner -- but what remains is an engrossing, well-acted look at the rise and fall of a fascinating political figure.', TO_DATE('1995-12-22', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('no', 2012, 'No uses its history-driven storyline to offer a bit of smart, darkly funny perspective on modern democracy and human nature.', TO_DATE('2012-05-25', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('no country for old men', 2007, 'Bolstered by powerful lead performances from Javier Bardem, Josh Brolin, and Tommy Lee Jones, No Country for Old Men finds the Coen brothers spinning cinematic gold out of Cormac McCarthy''s grim, darkly funny novel.', TO_DATE('2007-05-19', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('no end in sight', 2007, 'Charles Ferguson''s documentary provides a good summary of the decisions that led to the mess in post-war Iraq, and offers politically interested audiences something they''d been looking for: a lowdown on the decision making.', TO_DATE('2007-01-25', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('no escape', 2015, 'No Escape''s talented cast and taut B-movie thrills are unfortunately offset by its one-dimensional characters and uncomfortably retrograde worldview.', TO_DATE('2015-08-24', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('no good deed', 2014, 'Dull, derivative, and generally uninspired, No Good Deed wastes its stars'' talents -- and the audience''s time.', TO_DATE('2014-09-12', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('for no good reason', 2012, 'For No Good Reason is a solid but surface-level look at gonzo artist Ralph Steadman''s artistry and eccentricities.', TO_DATE('2012-10-14', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('no mans land', 2001, 'Bleak and darkly humorous, No Man''s Land vividly illustrates the absurdity of war.', TO_DATE('2001-08-30', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('no no a dockumentary', 2014, 'While taking full advantage of its subject''s colorful baseball career, No No: A Dockumentary also imparts broader, thought-provoking messages that should resonate with viewers who aren''t sports fans.', TO_DATE('2014-01-23', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('no one knows about persian cats les chats persans', 2009, 'Bringing a dose of humor and a fresh perspective to a very serious subject, No One Knows About Persian Cats is an exhilarating, quietly powerful tribute to the courage of Iran''s underground musicians.', TO_DATE('2009-05-15', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('no place on earth', 2013, 'No Place on Earth is a haunting and well-researched -- if occasionally uneven -- account of human endurance in Nazi Germany.', TO_DATE('2013-02-22', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('no reservations', 2007, 'This romantic comedy may look good on paper, but it''s too predictable and melancholy for the genre.', TO_DATE('2007-05-24', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('no strings attached', 2011, 'It benefits from the presence of Natalie Portman and director Ivan Reitman''s steady hand, but No Strings Attached doesn''t have the courage or conviction to follow through on its ribald premise.', TO_DATE('2011-01-18', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('no such thing', 2001, 'Stocked with talented stars but lacking any clear idea of what to do with them, No Such Thing is ultimately far too uneven to recommend.', TO_DATE('2001-07-16', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('noah', 2014, 'With sweeping visuals grounded by strong performances in service of a timeless tale told on a human scale, Darren Aronofsky''s Noah brings the Bible epic into the 21st century.', TO_DATE('2014-03-20', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('noble', 2014, 'Noble is undeniably and impassioned, even if it sometimes goes overboard in trying to prove its real-life protagonist lives up to its title.', TO_DATE('2014-09-19', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nobodys fool', 2018, 'Nobody''s Fool has a pair of strong leads and a smattering of scenes that highlight Tiffany Haddish''s talents -- all of which only make the uninspired end results more frustrating.', TO_DATE('2018-11-01', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nocturnal animals', 2016, 'Well-acted and lovely to look at, Nocturnal Animals further underscores writer-director Tom Ford''s distinctive visual and narrative skill.', TO_DATE('2016-09-02', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('noel', 2004, 'Noel strains for holiday uplift, but -- despite the involvement of an outstanding ensemble cast -- settles for treacly sentiment instead.', TO_DATE('2004-10-06', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('noi the albino nói albínói', 2003, 'A darkly humorous, quirky coming-of-age film, enhanced by its Icelandic setting.', TO_DATE('2003-08-19', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the nomi song', 2005, 'A fascinating, if occasionally frustrating, documentary about Klaus Nomi, a cult figure in the New Wave Underground scene during the ''80s.', TO_DATE('2005-01-29', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nonstop', 2014, 'While Liam Neeson is undoubtedly an asset, Non-Stop wastes its cast -- not to mention its solid premise and tense setup -- on a poorly conceived story that hinges on a thoroughly unbelievable final act.', TO_DATE('2014-02-21', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('norbit', 2007, 'Coming off his Oscar-nominated performance in Dreamgirls, the talented-but-inconsistent Eddie Murphy plays three roles in Norbit, a cruel, crass, stereotype-filled comedy that''s more depressing than funny.', TO_DATE('2007-02-07', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('norm of the north', 2016, 'A pioneering feat in the field of twerking polar bear animation but blearily retrograde in every other respect, Norm of the North should only be screened in case of parental emergency.', TO_DATE('2016-01-14', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('norman norman the moderate rise and tragic fall of a new york fixer', 2016, 'Norman''s elegantly told story is brought brilliantly to life by a quietly powerful performance from Richard Gere.', TO_DATE('2016-09-04', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('norman lear just another version of you', 2016, 'Norman Lear: Just Another Version of You pays tribute to its subject''s brilliant legacy with an entertaining primer peppered with his own fascinating reflections.', TO_DATE('2016-01-22', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('norte the end of history', 2013, 'Its four-hour length is undeniably imposing, but Norte, the End of History rewards patient viewers with an absorbing, visually expansive viewing experience.', TO_DATE('2013-10-02', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('north', 1994, 'Laden with schmaltz and largely bereft of evident narrative purpose, North represents an early major disappointment from previously sure-handed director Rob Reiner.', TO_DATE('1994-07-22', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('north by northwest', 1959, 'Gripping, suspenseful, and visually iconic, this late-period Hitchcock classic laid the groundwork for countless action thrillers to follow.', TO_DATE('1959-09-17', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('north country', 2005, 'Though sometimes melodramatic and formulaic, North Country is nonetheless a rousing, powerful story of courage and humanity.', TO_DATE('2005-01-15', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('north dallas forty', 2000, 'Muddled overall, but perceptive and brutally realistic, North Dallas Forty also benefits from strong performances by Nick Nolte and Charles Durning. Football fans will likely find it fascinating.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('north face nordwand', 2008, 'A tense and gripping spectacular piece of snow-bound historical German film-making.', TO_DATE('2008-12-12', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('noordzee texas north sea texas', 2012, 'Strong direction and delicate performances save Noordzee, Texas from its narrative cliches.', TO_DATE('2012-03-26', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('northern soul', 2014, 'Northern Soul overcomes its spotty narrative with a likable cast, rich period atmosphere, and a killer soundtrack that perfectly captures the time.', TO_DATE('2014-10-13', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('northfork', 2003, 'Visually poetic, but may be too dramatically inert for some.', TO_DATE('2003-02-11', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('norwegian wood', 2010, 'Norwegian Wood is a poetic adaptation of the Haruki Murakami novel that uses rapturous visuals to draw viewers in its exploration of young love and lasting death.', TO_DATE('2010-09-03', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nosferatu a symphony of horror nosferatu eine symphonie des grauens nosferatu the vampire', 2000, 'One of the silent era''s most influential masterpieces, Nosferatu''s eerie, gothic feel -- and a chilling performance from Max Schreck as the vampire -- set the template for the horror films that followed.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nosferatu phantom der nacht nosferatu the vampyre', 2000, 'Stunning visuals from Werner Herzog and an intense portrayal of the famed bloodsucker from Klaus Kinski make this remake of Nosferatu a horror classic in its own right.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nostalgia nostalghia', 2000, 'Nostalgia demands patience -- and rewards the investment with a hypnotic viewing experience that finds Tarkovsky in gratifyingly uncompromising form.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nostalgia', 2018, 'Nostalgia combines talented actors and honorable intentions, but poky pacing and a lack of depth make it unlikely the end result will ever inspire the titular emotion.', TO_DATE('2018-01-12', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('not another teen movie', 2001, 'NATM has some funny moments, but the movie requires the audience to have familiarity with the movies being spoofed and a tolerance for toilet and sexual humor to be truly effective.', TO_DATE('2001-12-09', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('not easily broken', 2009, 'Though well-intentioned, Not Easily Broken is bogged down by melodramatic plotting and stereotypical characters.', TO_DATE('2009-01-07', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('not fade away', 2012, 'Exuberant and bittersweet, Not Fade Away is a coming-of-age story set to a British Invasion beat that occasionally meanders but mostly charms.', TO_DATE('2012-10-05', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('not quite hollywood the wild untold story of ozploitation', 2008, 'A raucous, fast-paced celebration of the Ozploitation films that came out of Australia in the 1970s and 1980s.', TO_DATE('2008-07-28', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the notebook', 2004, 'It''s hard not to admire its unabashed sentimentality, but The Notebook is too clumsily manipulative to rise above its melodramatic clichés.', TO_DATE('2004-05-22', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('notes on a scandal', 2006, 'In this sharp psychological thriller, Judi Dench and Cate Blanchett give fierce, memorable performances as two schoolteachers locked in a battle of wits.', TO_DATE('2006-11-20', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('notes on blindness', 2016, 'Notes on Blindness traces one man''s difficult journey and emerges with a reflection on the human condition that''s as uplifting and edifying as it is simply moving.', TO_DATE('2016-01-22', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nothing bad can happen', 2013, 'Nothing Bad Can Happen uses its protagonist''s punishing ordeal to pose questions about faith that are well worth considering, even if the film can''t quite answer them.', TO_DATE('2013-05-28', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nothing but the truth', 2008, 'A well-crafted political thriller, Nothing But the Truth features a strong cast that helps the real-life drama make an effortless transition to the big screen.', TO_DATE('2008-09-08', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nothing but trouble', 1800, 'There''s nothing good in Nothing But Trouble, a grotesque comedy that is more likely to make audiences ill than make them laugh.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nothing like the holidays', 2008, 'The performances are the strength of Nothing Like the Holidays, a rather ordinary holiday comedy with a latin twist.', TO_DATE('2008-11-08', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the notorious bettie page', 2005, 'This biopic only skims the surface of Bettie Page''s life, leaving her as a cipher, and additionally fails to place her iconic status in historical context.', TO_DATE('2005-09-15', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('notting hill', 2000, 'A rom-com with the right ingredients, Notting Hill proves there''s nothing like a love story well told -- especially when Hugh Grant and Julia Roberts are your leads.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('novitiate', 2017, 'Led by a gripping performance from Melissa Leo, Novitiate grapples uncompromisingly -- and ultimately compellingly -- with questions of faith and feminism.', TO_DATE('2017-01-20', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('novocaine', 2001, 'The quirky Novocaine flirts with both dark comedy and noir suspense, but the result is a jarring mix of tones which never quite mesh.', TO_DATE('2001-09-12', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('now voyager', 2000, 'Now, Voyager is a Hollywood swooner with Bette Davis and Paul Henreid in a melodrama to end all melomers.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('now you see me', 2013, 'Now You See Me''s thinly sketched characters and scattered plot rely on sleight of hand from the director to distract audiences.', TO_DATE('2013-05-30', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('now you see me 2', 2016, 'Now You See Me 2 packs in even more twists and turns than its predecessor, but in the end, it has even less hiding up its sleeve.', TO_DATE('2016-06-01', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nowhere boy', 2009, 'Don''t expect any musical insights, but this look at John Lennon''s early life benefits from its restrained, low-key approach and some fine acting from Aaron Johnson.', TO_DATE('2009-10-30', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nurse betty', 2000, 'Quirky in the best sense of the word, Nurse Betty finds director Neil LaBute corralling a talented cast in service of a sharp, imaginative script.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('nutty professor ii the klumps', 2000, 'While Eddie Murphy is still hilarious as the entire Klump family, the movie falls apart because of uneven pacing, a poor script, and skits that rely on being gross rather than funny.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('o', 2001, 'Though well-intentioned and serious in its exploration of teen violence, O is an uneven experiment that doesn''t quite succeed.', TO_DATE('2001-06-15', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('o brother where art thou', 2000, 'Though not as good as Coen brothers'' classics such as Blood Simple, the delightfully loopy O Brother, Where Art Thou? is still a lot of fun.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oasis', 2003, 'Lead actress Moon So-ri''s stand out performance gives this harrowing film much of its power.', TO_DATE('2003-08-18', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oasis supersonic', 2016, 'Oasis: Supersonic foregoes a comprehensive approach to its multi-platinum subjects in favor of an appreciative -- and stirring -- look at their heady early years.', TO_DATE('2016-09-30', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the object of my affection', 1998, 'Despite heartfelt performances from Jennifer Aniston and Paul Rudd, The Object of My Affection suffers from too many plot contrivances and frequent turns into rom-com sappiness.', TO_DATE('1998-04-17', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oblivion', 2013, 'Visually striking but thinly scripted, Oblivion benefits greatly from its strong production values and an excellent performance from Tom Cruise.', TO_DATE('2013-04-09', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('observe and report', 2009, 'Though it has a mean streak, and does not cater to all tastes, Observe and Report has gut-busting laughs and a fully committed Seth Rogen in irresistible form.', TO_DATE('2009-03-18', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('obvious child', 2014, 'Tackling a sensitive subject with maturity, honesty, and wit, Obvious Child serves as a deeply promising debut for writer-director Gillian Robespierre.', TO_DATE('2014-01-20', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oceans 11', 2000, 'Easygoing but lazy, Ocean''s Eleven blithely coasts on the well-established rapport of the Rat Pack royalty.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oceans 8', 2018, 'Ocean''s 8 isn''t quite as smooth as its predecessors, but still has enough cast chemistry and flair to lift the price of a ticket from filmgoers up for an undemanding caper.', TO_DATE('2018-06-05', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oceans eleven', 2001, 'As fast-paced, witty, and entertaining as it is star-studded and coolly stylish, Ocean''s Eleven offers a well-seasoned serving of popcorn entertainment.', TO_DATE('2001-10-29', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oceans thirteen', 2007, 'Ocean''s Thirteen reverts to the formula of the first installment, and the result is another slick and entertaining heist film.', TO_DATE('2007-05-24', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oceans twelve', 2004, 'While some have found the latest star-studded heist flick to be a fun, glossy star vehicle, others declare it''s lazy, self-satisfied and illogical.', TO_DATE('2004-12-07', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('october country', 2009, 'It flirts with voyeurism, but this deeply personal look at a working-class family in upstate New York is piercingly honest and refreshingly unsentimental.', TO_DATE('2009-10-19', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('october sky', 1999, 'Rich in sweet sincerity, intelligence, and good old-fashioned inspirational drama, October Sky is a coming-of-age story with a heart to match its Hollywood craftsmanship.', TO_DATE('1999-02-19', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('octopussy', 1983, 'Despite a couple of electrifying action sequences, Octopussy is a formulaic, anachronistic Bond outing.', TO_DATE('1983-06-10', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oculus', 2013, 'With an emphasis on dread over gore and an ending that leaves the door wide open for sequels, Oculus could be just the first spine-tingling chapter in a new franchise for discerning horror fans.', TO_DATE('2013-09-10', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('odd thomas', 2013, 'Anton Yelchin is the right man for the title role, but Odd Thomas suffers from a jumbled tone.', TO_DATE('2013-08-28', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('of gods and men', 2010, 'Patient and restrained, Of Gods and Men asks deep, profound questions that will linger in the audience''s mind long after the movie.', TO_DATE('2010-09-11', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('off the map', 2003, 'Excellent performances mark this leisurely paced film.', TO_DATE('2003-02-14', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('office christmas party', 2016, 'Its cast of gifted comics is good for a handful of laughs, but Office Christmas Party''s overstuffed plot ultimately proves roughly as disappointing as its clichéd gags and forced sentimentality.', TO_DATE('2016-12-07', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('office space', 2000, 'Mike Judge lampoons the office grind with its inspired mix of sharp dialogue and witty one-liners.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an officer and a gentleman', 2001, 'Old-fashioned without sacrificing its characters to simplicity, An Officer and a Gentleman successfully walks the fine line between sweeping romance and melodrama.', TO_DATE('2001-02-13', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('official secrets', 2019, 'Official Secrets has a familiar structure and an obvious if worthy message, but rises on the strength of Keira Knightley''s powerful performance.', TO_DATE('2019-01-29', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('offside', 2006, 'A spirited film that explores gender politics with comedy, intelligence, and a variety of interesting characters.', TO_DATE('2006-02-17', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oh god', 2000, 'Oh, God!''s Biblical playfulness makes for more cute farce than divine comedy, but George Burns'' sly performance as the Almighty gives this high concept gravitas.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('o horten', 2007, 'Bent Hamer''s latest is a droll, deadpan comedy filled with strange touches and melancholy charm.', TO_DATE('2007-12-26', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('okja', 2017, 'Okja sees Bong Joon-ho continuing to create defiantly eclectic entertainment -- and still hitting more than enough of his narrative targets in the midst of a tricky tonal juggling act.', TO_DATE('2017-05-19', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oklahoma', 2002, 'Aye-yip-aye-yo-ee-ay! The critics are sayin'' you''re doin'' fine, Oklahoma! Oklahoma, O.K.!', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('old joy', 2006, 'A serene, melancholy beauty permeates this meditative portrait of deep friendship and faded glory.', TO_DATE('2006-01-31', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('old school', 2003, 'While not consistently funny, the movie does have its moments.', TO_DATE('2003-02-08', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('old yeller', 2000, 'Old Yeller is an exemplary coming of age tale, packing an emotional wallop through smart pacing and a keen understanding of the elemental bonding between humanity and their furry best friends.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oldboy', 2004, 'Violent and definitely not for the squeamish, Park Chan-Wook''s visceral Oldboy is a strange, powerful tale of revenge.', TO_DATE('2004-06-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oldboy', 2013, 'Suitably grim and bloody yet disappointingly safe and shallow, Spike Lee''s Oldboy remake neither surpasses the original nor adds anything new to its impressive legacy.', TO_DATE('2013-11-26', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oliver', 2000, 'It has aged somewhat awkwardly, but the performances are inspired, the songs are memorable, and the film is undeniably influential.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oliver company', 2000, 'Predictable and stodgy, Oliver & Company isn''t one of Disney''s best, though its colorful cast of characters may be enough to entertain young viewers looking for a little adventure.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oliver twist', 2000, 'David Lean brings the grimy beauty of Charles Dickens'' Victorian England to vivid cinematic life in Oliver Twist, a marvelous adaptation that benefits from Guy Green''s haunting cinematography and Alec Guinness'' off-kilter performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('olympic dreams', 2019, 'Even if it''s mainly distinguished by its unique setting, Olympic Dreams remains a romcom with a heartfelt story and likable leads.', TO_DATE('2019-03-11', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('olympus has fallen', 2013, 'It''s far from original, but Olympus Has Fallen benefits from Antoine Fuqua''s tense direction and a strong performance from Gerard Butler -- which might just be enough for action junkies.', TO_DATE('2013-03-16', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('omar', 2013, 'Twisty and riveting, Omar is a well-directed crime drama with uncommon depth.', TO_DATE('2013-05-23', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the omega man', 2000, 'It may not live up to its classic source material, but The Omega Man transcends its limitations often enough to offer some mildly entertaining post-apocalyptic thrills.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the omen', 2006, 'Even with the force of a "classic" behind it, remake fever can''t hold up the hollowness of this style-drenched Omen.', TO_DATE('2006-05-25', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('on a magical night chambre 212', 2019, 'It isn''t quite as exceptional as the titular evening, but On a Magical Night offers enough Gallic whimsy to satisfy audiences in the mood for some romance.', TO_DATE('2019-05-19', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('on chesil beach', 2017, 'On Chesil Beach presents a well-acted and solidly crafted adaptation of a small yet resonant story with deceptively rich subtext.', TO_DATE('2017-09-07', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('on golden pond', 2000, 'Henry Fonda and Katherine Hepburn are a wondrous duo in On Golden Pond, a wistful drama that movingly explores the twilight years of a loving marriage.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('on guard', 2002, 'A spirited, old-fashioned swashbuckler.', TO_DATE('2002-10-15', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('on her majestys secret service', 1969, 'George Lazenby''s only appearance as 007 is a fine entry in the series, featuring one of the most intriguing Bond girls in Tracy di Vincenzo (Diana Rigg), breathtaking visuals, and some great ski chases.', TO_DATE('1969-12-18', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('on_line', 2002, 'On_Line might have a more balanced perspective than most internet-fueled dramas, but that doesn''t make the story or its characters interesting enough to watch.', TO_DATE('2002-03-01', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('on the basis of sex', 2018, 'On the Basis of Sex is nowhere near as groundbreaking as its real-life subject, but her extraordinary life makes a solid case for itself as an inspirational, well-acted biopic.', TO_DATE('2018-11-09', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('on the beach at night alone bamui haebyuneoseo honja', 2017, 'On the Beach at Night Alone finds writer-director Sang-soo Hong working in a more personal vein -- without losing the singular sensibilities that have informed much of his acclaimed earlier work.', TO_DATE('2017-02-16', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('on the outs', 2005, 'With powerful lead performances, this gritty docudrama about the desperate lives of three young women in Jersey City packs an emotional wallop.', TO_DATE('2005-03-21', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('on the road', 2012, 'Beautiful to look at but a bit too respectfully crafted, On the Road doesn''t capture the energy and inspiration of Jack Kerouac''s novel.', TO_DATE('2012-05-23', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('on the waterfront', 1954, 'With his electrifying performance in Elia Kazan''s thought-provoking, expertly constructed melodrama, Marlon Brando redefined the possibilities of acting for film and helped permanently alter the cinematic landscape.', TO_DATE('1954-07-28', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('once', 2007, 'A charming, captivating tale of love and music, Once sets the standard for the modern musical. And with Dublin as its backdrop, Once is fun and fresh.', TO_DATE('2007-01-25', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('once in the life', 2000, 'Once in a Life is a promising directorial effort by Laurence Fishburne. But the story is too conventional and similar to the many ghetto action/dramas that come before it.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('once upon a deadpool', 2018, 'Once Upon a Deadpool retains enough of the franchise''s anarchic spirit to entertain, but doesn''t add enough to Deadpool 2 to justify its own existence.', TO_DATE('2018-12-11', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('once upon a forest', 2000, 'Inert animation and generically chipper characters rob Once Upon a Forest of any personality despite its well-intentioned message and critter appeal for very young children.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('once upon a time in america', 2000, 'Sergio Leone''s epic crime drama is visually stunning, stylistically bold, and emotionally haunting, and filled with great performances from the likes of Robert De Niro and James Woods.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('once upon a time in anatolia', 2011, 'Cerebral and thrilling, Once Upon a Time in Anatolia is a meditative procedural that maintains feverish intensity throughout its unhurried runtime.', TO_DATE('2011-08-13', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('once upon a time in hollywood', 2019, 'Thrillingly unrestrained yet solidly crafted, Once Upon a Time in Hollywood tempers Tarantino''s provocative impulses with the clarity of a mature filmmaker''s vision.', TO_DATE('2019-05-21', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('once upon a time in mexico', 2003, 'Violent, pulpy, loopy fun, with Depp stealing the show.', TO_DATE('2003-08-31', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('once upon a time in the west', 2000, 'A landmark Sergio Leone spaghetti western masterpiece featuring a classic Morricone score.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('once upon a time in venice', 2017, 'Once Upon a Time in Venice has a little more of a spark than typical late-period Bruce Willis tough guy movies, but it''s still a steep, disappointing tumble from his best work.', TO_DATE('2017-06-09', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('once were warriors', 2000, 'Once Were Warriors isn''t an easy watch, but the raw power of its story -- and the performances of an excellent cast -- reward viewers who rise to the challenge.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ondine', 2010, 'Flawed but charming, Ondine reaffirms writer-director Neil Jordan''s gift for myth, magic, and wonder.', TO_DATE('2010-03-05', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('one day', 2011, 'Despite some fresh narrative twists, One Day lacks the emotion, depth, or insight of its bestselling source material.', TO_DATE('2011-08-14', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('one false move', 2000, 'One False Move makes nary a misstep as it unfurls a seedy caper with hard-hitting action and sly humor, marking an arresting debut for director Carl Franklin.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('one flew over the cuckoos nest', 2000, 'The onscreen battle between Jack Nicholson and Louise Fletcher serves as a personal microcosm of the culture wars of the 1970s -- and testament to the director''s vision that the film retains its power more than three decades later.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('one for the money', 2012, 'Dull and unfunny, One For the Money wastes Katherine Heigl''s talents on a stunningly generic comic thriller.', TO_DATE('2012-01-26', 'YYYY-MM-DD'), 2.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('one from the heart', 1982, 'One from the Heart belies its reputation as a flop with Francis Ford Coppola''s earnest intentions and technical virtuosity, but not even the director''s ardor for the genre is enough to make audiences feel much for these characters.', TO_DATE('1982-02-12', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('one hour photo', 2002, 'Robin Williams is very effective in this creepy, well-shot thriller.', TO_DATE('2002-04-08', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('one missed call', 2008, 'One of the weakest entries in the J-horror remake sweepstakes, One Missed Call is undone by bland performances and shopworn shocks.', TO_DATE('2008-01-03', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('one missed call', 2005, 'One Missed Call has a few interesting ideas and benefits from director Takashi Miike''s eye, but is ultimately too unoriginal to recommend.', TO_DATE('2005-04-08', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('one of us', 2017, 'Harrowing and heartbreaking, One of Us offers an intimate, revealing glimpse inside a notoriously private community and those who would dare defy it.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('one true thing', 2000, 'Solid performances lift this drama to a higher level.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ongbak ong bak muay thai warrior', 2004, 'While Ong-Bak: The Thai Warrior may be no great shakes as a movie, critics are hailing the emergence of a new star in Tony Jaa, whose athletic performance is drawing comparisons with Bruce Lee, Jackie Chan, and Jet Li.', TO_DATE('2004-08-24', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('only god forgives', 2013, 'Director Refn remains as visually stylish as ever, but Only God Forgives fails to add enough narrative smarts or relatable characters to ground its beautifully filmed depravity.', TO_DATE('2013-05-22', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('only human seres queridos', 2006, 'A cheerfully energetic screwball comedy, Only Human milks laughs from its culture-clash premise.', TO_DATE('2006-01-07', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('only lovers left alive', 2013, 'Worth watching for Tom Hiddleston and Tilda Swinton''s performances alone, Only Lovers Left Alive finds writer-director Jim Jarmusch adding a typically offbeat entry to the vampire genre.', TO_DATE('2013-05-25', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('only the brave', 2017, 'Only the Brave''s impressive veteran cast and affecting fact-based story add up to a no-frills drama that''s just as stolidly powerful as the real-life heroes it honors.', TO_DATE('2017-10-11', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('only the strong survive', 2003, 'Though this documentary could be more informative, the performances themselves are wonderful.', TO_DATE('2003-01-24', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('onward', 2020, 'It may suffer in comparison to Pixar''s classics, but Onward makes effective use of the studio''s formula -- and stands on its own merits as a funny, heartwarming, dazzlingly animated adventure.', TO_DATE('2020-02-21', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('opal dream', 2006, 'Earnest performances and Peter Cattaneo''s sympathetic direction gives heart to the simple, timeworn script.', TO_DATE('2006-11-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('open city', 2000, 'Open City fills in the familiar contours of its storyline with three-dimensional characters and a narrative depth that add up to a towering -- and still powerfully resonant -- cinematic achievement.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('open range', 2003, 'Greatly benefiting from the tremendous chemistry between Kevin Costner and Robert Duvall, Open Range is a sturdy modern Western with classic roots.', TO_DATE('2003-08-09', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('open season', 2006, 'Open Season is a cliched palette of tired jokes and CG animal shenanigans that have been seen multiple times this cinematic year.', TO_DATE('2006-09-21', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('open water', 2004, 'A low budget thriller with some intense moments.', TO_DATE('2004-02-18', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('open windows', 2014, 'Open Windows is undeniably ambitious; unfortunately, director Nacho Vigalondo''s reach far exceeds his grasp.', TO_DATE('2014-03-11', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('open your eyes abre los ojos', 1999, 'Director Alejandro Amenábar tackles some heady issues with finesse and clarity in Open Your Eyes, a gripping exploration of existentialism and the human spirit.', TO_DATE('1999-04-16', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('opening night', 2000, 'Opening Night is as dense and difficult as one would expect from John Cassavetes, but even the director''s detractors will be unable to deny the power of Gena Rowlands'' performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('opera', 2001, 'The Opera house location gives plenty to work with for director Dario Argento, who hits his decadently bloody high notes here.', TO_DATE('2001-10-31', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('operation dumbo drop', 1995, 'The Vietnam War would seem an unlikely backdrop for a family-friendly comedy involving an airlifted elephant, and Operation Dumbo Drop lands with a thud.', TO_DATE('1995-07-28', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('operation finale', 2018, 'Operation Finale is well-intentioned, well-acted, and overall entertaining, even if the depth and complexity of the real-life events depicted can get a little lost in their dramatization.', TO_DATE('2018-08-22', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ophelia', 2018, 'Flawed yet intriguing, Ophelia uses Hamlet as the starting point for a noble attempt to offer a misunderstood character long-overdue agency.', TO_DATE('2018-01-23', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the opposite of sex', 2000, 'The Opposite of Sex smartly lightens a bitter story with sharp insights and strong dialogue - as well as a startlingly mature performance from former child actor Christina Ricci.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('or my treasure', 2004, 'Prostitution and its effect on a mother-daughter relationship are told in a naturalistic and nonjudgmental style, building to a powerful conclusion.', TO_DATE('2004-10-04', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('orange county', 2001, 'Smarter than the average teen movie, but a little on the unmemorable side.', TO_DATE('2001-12-02', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oranges and sunshine', 2010, 'Grounded in a heartwrenching fact-based story, steered by Loach''s sensitive direction, and led by a powerful performance from Watson, Oranges and Sunshine sidesteps its pacing problems and occasionally clichéd screenplay.', TO_DATE('2010-10-11', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('orca the killer whale', 2001, 'Content to regurgitate bits of better horror movies, Orca: The Killer Whale is a soggy shark thriller with frustratingly little bite.', TO_DATE('2001-11-06', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ordinary people', 2000, 'Though shot through with bitterness and sorrow, Robert Redford''s directorial debut is absorbing and well-acted.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('orgazmo', 1998, 'More juvenile than provocative, Orgazmo may have enough good-natured raunch to satisfy writer-director Trey Parker''s fans, but its satire is too soft to compete with the South Park co-creator''s best work.', TO_DATE('1998-10-23', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the original kings of comedy', 2000, 'If you want lots of laughs and don''t mind some profanity, The Original Kings of Comedy can deliver.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('original sin', 2001, 'Laughably melodramatic, Original Sin features bad acting, bad dialogue, and bad plotting.', TO_DATE('2001-07-30', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('orlando', 2000, 'Orlando can''t match its visual delights with equally hefty narrative -- but it''s so much fun to watch that it doesn''t need to.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('osama', 2003, 'Osama is bitterly honest, deeply disturbing, and utterly worth watching.', TO_DATE('2003-08-28', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oslo august 31st', 2011, 'An upfront study of a drug addict confronting his demons, Oslo, August 31st makes this dark journey worthwhile with fantastic directing and equally fantastic acting.', TO_DATE('2011-07-20', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('osmosis jones', 2001, 'The animated portion of Osmosis is zippy and fun, but the live-action portion is lethargic.', TO_DATE('2001-08-02', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oss 117 rio ne répond plus lost in rio', 2010, 'Led by another appealing performance from Jean Dujardin, this sequel offers more absurdly fun action -- and more politically incorrect humor -- for fans of ''60s spy films.', TO_DATE('2010-01-15', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the other boleyn girl', 2008, 'Though it features some extravagant and entertaining moments, The Other Boleyn Girl feels more like a soap opera than historical drama.', TO_DATE('2008-02-08', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the other guys', 2010, 'A clever parody of cop-buddy action-comedies, The Other Guys delivers several impressive action set pieces and lots of big laughs, thanks to the assured comic chemistry between Will Ferrell and Mark Wahlberg.', TO_DATE('2010-08-02', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the other sister', 2000, 'Made-for-tv drama evokes anything but real emotion.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('otherhood', 2019, 'Otherhood wastes its three talented leading actresses on a forgettable dramedy about motherhood that lacks humor and feels forced.', TO_DATE('2019-08-01', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ouija', 2014, 'Slowly, steadily, although no one seems to be moving it in that direction, the Ouija planchette points to NO.', TO_DATE('2014-10-23', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ouija origin of evil', 2016, 'Ouija: Origin of Evil swerves its franchise''s planchette unexpectedly to YES with a surprisingly scary and dramatically satisfying follow-up to its lackluster predecessor.', TO_DATE('2016-10-18', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('our brand is crisis', 2005, 'Riveting and enraging, Our Brand Is Crisis peers behind the curtain of modern political campaigning and reveals a story that should be seen by citizens of all persuasions.', TO_DATE('2005-04-22', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('our brand is crisis', 2015, 'Our Brand Is Crisis offers sporadic amusement and benefits from a talented cast, but ultimately lacks enough of a bite to add much of interest to the political satire genre.', TO_DATE('2015-09-12', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('our children', 2012, 'A wrenching, quietly violent psychodrama, Our Children has the courage to ask difficult questions, and the strength to leave the answers to the viewer.', TO_DATE('2012-05-24', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('our family wedding', 2010, 'Our Family Wedding is a mirthless, contrived affair that does little with its promising premise and talented cast.', TO_DATE('2010-03-04', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('our house', 2018, 'Our House sits on a solid foundation of genuine pathos, even if the storytelling structure tends to be frustratingly rickety in spots.', TO_DATE('2018-07-23', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('our idiot brother', 2011, 'It''s decidedly uneven, but like Paul Rudd''s performance in the title role, Our Idiot Brother is too charming to resist.', TO_DATE('2011-01-24', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('our kind of traitor', 2016, 'Our Kind of Traitor relies on solid writing and acting rather than action to deliver its spy-movie thrills -- and thankfully has the pedigree to pull it off on both fronts.', TO_DATE('2016-05-02', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('our lady of the assassins', 2001, 'Director Barbet Schroeder presents a bleak, darkly humorous drama about hopeless love in Medellin, Colombia.', TO_DATE('2001-05-23', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('our little sister umimachi diary', 2015, 'Our Little Sister uses the story of one fractured family to offer universal -- and deeply moving -- observations on the human condition.', TO_DATE('2015-07-20', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('our nixon', 2013, 'Our Nixon offers a privileged personal perspective on a White House soon to be derailed by scandal, giving viewers an intimate look at the people behind the political legend.', TO_DATE('2013-03-17', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('our song', 2000, 'Graced with such a realistic feel that it resembles a documentary, Our Song is a sensitive portrayal of three teenage girls.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('our souls at night', 2017, 'Our Souls at Night honors the quiet strength of its source material by offering a simple yet sturdy canvas for two talented veteran leads to bring its story to life.', TO_DATE('2017-09-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('out cold', 2001, 'A party movie that substitutes surfs for snow, Out Cold will leave viewers just that with its gross-out humor and sophomoric plot.', TO_DATE('2001-11-19', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('out of africa', 1985, 'Though lensed with stunning cinematography and featuring a pair of winning performances from Meryl Streep and Robert Redford, Out of Africa suffers from excessive length and glacial pacing.', TO_DATE('1985-12-18', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('out of blue', 2018, 'Out of Blue smolders without ever really sparking to life -- which, considering the source material and talent assembled, can only be considered a disappointment.', TO_DATE('2018-09-08', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('out of the furnace', 2013, 'While it may not make the most of its incredible cast, Out of the Furnace is still so packed with talent that it''s hard to turn away.', TO_DATE('2013-11-10', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('out of the past', 2000, 'Anchored by a wistful Robert Mitchum, Out of the Past is an exemplary noir steeped in doom and sensuality.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('out of time', 2003, 'A fun and stylish thriller if you can get past the contrivances.', TO_DATE('2003-09-11', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('out stealing horses ut og stjæle hester', 2019, 'Muted but moving, Out Stealing Horses ambitiously explores the human condition through one man''s lifetime of memories.', TO_DATE('2019-02-11', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('outbreak', 1994, 'A frustratingly uneven all-star disaster drama, Outbreak ultimately proves only mildly contagious and leaves few lasting side effects.', TO_DATE('1994-06-01', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('outcast', 2015, 'Unforgivably dull, Outcast fails to deliver virtually all of the goofy fun that should come from a movie starring Nicolas Cage and Hayden Christensen in ancient China.', TO_DATE('2015-02-03', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('outfoxed rupert murdochs war on journalism', 2004, 'Neither fair nor balanced itself, Outfoxed offers an often entertaining indictment of the Fox News Channel.', TO_DATE('2004-07-14', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('outlander', 2009, 'Schizophrenic in subject and lackluster in execution, Outlander might have trouble finding the cult audience for which it was built.', TO_DATE('2009-01-21', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the outlaw josey wales', 2000, 'Recreating the essence of his iconic Man With No Name in a post-Civil War Western, director Clint Eastwood delivered the first of his great revisionist works of the genre.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('outlaw king', 2018, 'Muddy and bloody to a fault, Outlaw King doesn''t skimp on the medieval battle scenes, but tends to lose track of the fact-based legend at the heart of its story.', TO_DATE('2018-09-07', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('outlaws and angels', 2016, 'Outlaws and Angels doesn''t do enough to stand out on the crowded canvas of nouveau Westerns -- doubly disappointing considering there''s an Eastwood in the cast.', TO_DATE('2016-01-28', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('outside in', 2017, 'Brilliantly brought to life by tenderly empathetic performances from Jay Duplass and Edie Falco, Outside In tells a sobering -- yet thoroughly absorbing -- story.', TO_DATE('2017-09-09', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('outside providence', 2000, 'Miscasted performers and humor miss the mark.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the outsiders', 2001, 'The cracks continue to show in Coppola''s directorial style, but The Outsiders remains a blustery, weird, and fun adaptation of the classic novel.', TO_DATE('2001-04-08', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('outsourced', 2006, 'Outsourced is a charming and lighthearted comedy that appeals because of its timeliness and strong cast of likeable characters.', TO_DATE('2006-09-19', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('over the hedge', 2006, 'Even if it''s not an animation classic, Over the Hedge is clever and fun, and the jokes cater to family members of all ages.', TO_DATE('2006-03-30', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('over the top', 2000, 'The definitive film about arm-wrestling truck drivers fighting for custody of their children, Over the Top lives down to its title in the cheesiest of ways.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('overboard', 2000, 'Goldie Hawn and Kurt Russell''s comedic chops elevate waterlogged material, but not even their buoyant chemistry can keep Overboard''s creepy concept afloat.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('overboard', 2018, 'Overboard makes poor use of the ever-charming Anna Faris -- and chooses questionable source material -- to offer a remake that fails to clear the fairly low bar set by the original.', TO_DATE('2018-05-03', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('overlord', 2018, 'Part revisionist war drama, part zombie thriller, and part all-out genre gorefest, Overlord offers A-level fun for B-movie fans of multiple persuasions.', TO_DATE('2018-09-23', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('overnight', 2004, 'This absorbing but wince-inducing documentary is a cautionary tale about the costs of hubris in the world of indie film.', TO_DATE('2004-10-22', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oz the great and powerful', 2013, 'It suffers from some tonal inconsistency and a deflated sense of wonder, but Oz the Great and Powerful still packs enough visual dazzle and clever wit to be entertaining in its own right.', TO_DATE('2013-02-28', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('p2', 2007, 'P2 is full of gore, but low on suspense, featuring a cat-and-mouse plot has been done many times before.', TO_DATE('2007-10-30', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pacific heights', 1990, 'Michael Keaton certainly proves himself as an effective villain, but Pacific Heights sticks too closely to well-worn thriller conventions.', TO_DATE('1990-09-28', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pacific rim', 2013, 'It may sport more style than substance, but Pacific Rim is a solid modern creature feature bolstered by fantastical imagery and an irresistible sense of fun.', TO_DATE('2013-07-07', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pacific rim uprising', 2018, 'Pacific Rim Uprising won''t win any points for subtlety or originality, but it delivers enough of the rock ''em-sock ''em robots-vs.-kaiju thrills that fans of the original will be looking for.', TO_DATE('2018-03-20', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the pacifier', 2005, 'Vin Diesel parodies his tough guy image for the family audience, but the result is only moderately amusing.', TO_DATE('2005-02-26', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paddington 2', 2017, 'Paddington 2 honors its star''s rich legacy with a sweet-natured sequel whose adorable visuals are matched by a story perfectly balanced between heartwarming family fare and purely enjoyable all-ages adventure.', TO_DATE('2017-10-26', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paddington', 2014, 'Paddington brings a beloved children''s character into the 21st century without sacrificing his essential charm, delivering a family-friendly adventure as irresistibly cuddly as its star.', TO_DATE('2014-11-19', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paddleton', 2019, 'It takes its time coming together, but the quietly effective Paddleton pulls off a tricky tonal balancing act, thanks largely to the strengths of its well-chosen leads.', TO_DATE('2019-01-25', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the page turner la tourneuse de pages', 2006, 'Reminiscent of Hitchcock and Chabrol, The Page Turner is elegant yet suspenseful, a revenge potboiler of a high degree.', TO_DATE('2006-05-20', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paid in full', 2002, 'Though well-acted and non-exploitative, Paid in Full treads a very well-worn story.', TO_DATE('2002-10-22', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pain gain', 2013, 'It may be his most thought-provoking film to date, but Michael Bay''s Pain & Gain ultimately loses its satirical edge in a stylized flurry of violent spectacle.', TO_DATE('2013-04-23', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pain and glory dolor y gloria', 2019, 'Pain and Glory finds writer-director Pedro Almodóvar drawing on his own life to rewarding effect -- and honoring his craft as only a master filmmaker can.', TO_DATE('2019-03-19', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the painted veil', 2006, 'Visually, The Painted Veil has all the trappings of a stuffy period drama, but Norton''s and Watts''s deft portrayals of imperfect, complicated characters give the film a modern-day spark.', TO_DATE('2006-12-01', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pale rider', 2000, 'Nearly a decade after The Outlaw Josey Wales, Clint Eastwood returns as a director to the genre that made his name with this elegant, spiritual Western that riffs on the classic Shane.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('palindromes', 2004, 'Unique but cold.', TO_DATE('2004-09-09', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('palo alto', 2013, 'A promising debut for director Gia Coppola, Palo Alto compensates for its drifting plot with solid performances and beautiful cinematography.', TO_DATE('2013-09-05', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pan', 2015, 'Pan finds a few bursts of magic in its prequel treatment of classic characters, though not enough to offset the rushed plot and shrill, CGI-fueled action.', TO_DATE('2015-09-19', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pandorum', 2009, 'While it might prove somewhat satisfying for devout sci-fi fans, Pandorum''s bloated, derivative plot ultimately leaves it drifting in space.', TO_DATE('2009-09-24', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('panic room', 2002, 'Elevated by David Fincher''s directorial talent and Jodie Foster''s performance, Panic Room is a well-crafted, above-average thriller.', TO_DATE('2002-03-19', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pans labyrinth', 2006, 'Pan''s Labyrinth is Alice in Wonderland for grown-ups, with the horrors of both reality and fantasy blended together into an extraordinary, spellbinding fable.', TO_DATE('2006-05-30', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('papa hemingway in cuba', 2016, 'A man can be destroyed but not defeated, although the desultory Papa: Hemingway in Cuba makes one feel as if both can be accomplished by watching a single film.', TO_DATE('2016-04-20', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paparazzi', 2004, 'A crude, ludicrous exploitation movie with a questionable moral.', TO_DATE('2004-09-02', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the paper', 1994, 'Fast and frenetic, The Paper captures the energy of the newsroom thanks to its cast and director on first-rate form.', TO_DATE('1994-03-18', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paper heart', 2009, 'Equal parts charming and refreshing, Paper Heart is a quirky mockumentary led by the endearing Charlyne Yi.', TO_DATE('2009-01-20', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paper moon', 2000, 'Expertly balancing tones, Paper Moon is a deft blend of film nostalgia and finely tuned performances -- especially from Tatum O''Neal, who won an Oscar for her debut.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paper towns', 2015, 'Paper Towns isn''t as deep or moving as it wants to be, yet it''s still earnest, well-acted, and thoughtful enough to earn a place in the hearts of teen filmgoers of all ages.', TO_DATE('2015-07-04', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paper clips', 2004, 'A touching, though somewhat flat, documentary that follows a homogenous class of white Protestant eighth graders as they learn the importance of tolerance by erecting a monument to the 6 million victims of the Holocaust.', TO_DATE('2004-09-29', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('papillon', 2017, 'Papillon puts its own well-acted, solidly produced spin on a previously adapted tale, although it suffers in comparison to the 1973 version.', TO_DATE('2017-09-08', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paradise', 2013, 'Paradise rounds up an impressive array of talent on either side of the camera -- all of whom would presumably prefer that audiences forget their involvement in this misfire.', TO_DATE('2013-09-05', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paradise hills', 2019, 'Its ambitious reach occasionally exceeds its grasp, but Paradise Hills offers fans of thoughtful sci-fi a visually distinctive treat with timely themes.', TO_DATE('2019-01-28', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paradise love', 2012, 'Paradise: Love proves a viewing experience that''s difficult to shake -- albeit one that will leave some discomfited more than truly entertained.', TO_DATE('2012-05-18', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paradise now', 2005, 'This film delves deeply into the minds of suicide bombers, and the result is unsettling.', TO_DATE('2005-08-19', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the parallax view', 2000, 'The Parallax View blends deft direction from Alan J. Pakula and a charismatic Warren Beatty performance to create a paranoid political thriller that stands with the genre''s best.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paranoia', 2013, 'Clichéd and unoriginal, Paranoia is a middling techno-thriller with indifferent performances and a shortage of thrills.', TO_DATE('2013-08-06', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paranoid park', 2007, 'Director Gus Van Sant once again superbly captures the ins and outs of teenage life in Paranoid Park, a quietly devastating portrait of a young man living with guilt and anxiety.', TO_DATE('2007-05-21', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paranormal activity', 2008, 'Using its low-budget effects and mockumentary method to great result, Paranormal Activity turns a simple haunted house story into 90 minutes of relentless suspense.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paranormal activity 2', 2010, 'Paranormal Activity 2 doesn''t cover any new ground, but its premise is still scary -- and in some respects, it''s a better film than the original.', TO_DATE('2010-08-05', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paranormal activity 3', 2011, 'While the jolts and thrills are undeniably subject to the diminishing returns that plague most horror sequels, Paranormal Activity 3 is a surprisingly spine-tingling treat.', TO_DATE('2011-09-29', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paranormal activity 4', 2012, 'While it does manage to wring a few more screams out of the franchise''s surprisingly durable premise, Paranormal Activity 4 provides fans of the series with dismayingly diminishing returns.', TO_DATE('2012-09-27', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paranormal activity the ghost dimension', 2013, 'Paranormal Activity: The Ghost Dimension ties up some of the franchise''s lingering questions, but six films into the series, the thrills are mostly gone.', TO_DATE('2013-02-15', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paranormal activity the marked ones', 2013, 'A change of setting breathes some new life into the franchise, but Paranormal Activity: The Marked Ones fails to provide enough consistent thrills to justify a fifth film in the series.', TO_DATE('2013-12-30', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paranorman', 2012, 'Beautifully animated and solidly scripted, ParaNorman will entertain (and frighten) older children while providing surprisingly thoughtful fare for their parents.', TO_DATE('2012-08-02', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('parasite gisaengchung', 2019, 'An urgent, brilliantly layered look at timely social themes, Parasite finds writer-director Bong Joon Ho in near-total command of his craft.', TO_DATE('2019-05-21', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('parental guidance', 2012, 'Parental Guidance is sweet but milquetoast, an inoffensive trifle that''s blandly predictable.', TO_DATE('2012-12-16', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('parenthood', 2000, 'Bolstered by a delightful cast, Parenthood is a funny and thoughtfully crafted look at the best and worst moments of family life that resonates broadly.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pariah', 2010, 'Pulsing with authenticity and led by a stirring lead performance from Adepero Oduye, Pariah is a powerful coming out/coming-of-age film that signals the arrival of a fresh new talent in writer/director Dee Rees.', TO_DATE('2010-08-24', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('faubourg 36 paris 36', 2008, 'Sweet and light, this homage to French vaudeville -- and Francophilia in general -- is pretty, but its air of nostalgia occasionally borders on the saccharine.', TO_DATE('2008-10-18', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paris can wait bonjour anne', 2016, 'Paris Can Wait''s likable stars are ill-served by a film that lacks interesting ideas or characters and has little to offer beyond striking travelogue visuals.', TO_DATE('2016-09-13', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paris is burning', 1990, 'Paris Is Burning dives into ''80s transgender subculture, with the understated camera allowing this world to flourish and the people to speak (and dance) for themselves.', TO_DATE('1990-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paris je taime', 2006, 'Paris Je T''aime is uneven, but there are more than enough delightful moments in this omnibus tribute to the City of Lights to tip the scale in its favor.', TO_DATE('2006-05-18', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paris texas', 2000, 'A quiet yet deeply moving kind of Western, Paris, Texas captures a place and people like never before (or after).', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('parker', 2013, 'Jason Statham is game as usual, but Parker is a thoroughly generic and convoluted heist movie.', TO_DATE('2013-01-19', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('parkland', 2013, 'Although its decision to look at John F. Kennedy''s assassination through uncommon perspectives is refreshing, Parkland never achieves the narrative cohesion its subject deserves.', TO_DATE('2013-09-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('particle fever', 2014, 'The concepts behind its heady subject matter may fly over the heads of most viewers, but Particle Fever presents it in such a way that even the least science-inclined viewers will find themselves enraptured.', TO_DATE('2014-03-03', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('leaving partir', 2009, 'Laden with melodramatic clichés, Leaving needed a talented star to succeed -- and Kristin Scott Thomas delivers the goods with another superb performance.', TO_DATE('2009-09-14', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('partisan', 2015, 'Well-acted and suitably chilling, Partisan is a dark drama whose confident craft may offer enough for some viewers to look past its flaws.', TO_DATE('2015-01-26', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('party monster', 2002, 'The lurid display of camp soon turns tedious.', TO_DATE('2002-12-10', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a passage to india', 2002, 'A Passage to India is a visually striking exploration of colonialism and prejudice, although it doesn''t achieve the thematic breadth of director David Lean''s finest work.', TO_DATE('2002-03-16', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('passengers', 2016, 'Passengers proves Chris Pratt and Jennifer Lawrence work well together -- and that even their chemistry isn''t enough to overcome a fatally flawed story.', TO_DATE('2016-12-15', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('passion', 2012, 'For better as well as worse, Passion is vintage De Palma sexploitation -- although with a storyline sillier than most, it fails to generate as much heat as his steamiest work.', TO_DATE('2012-09-07', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the passion of joan of arc la passion de jeanne darc', 1928, 'The Passion of Joan of Arc is must-see cinema for Renée Maria Falconetti''s incredible performance alone -- and an all-time classic for innumerable other reasons.', TO_DATE('1928-04-21', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the passion of the christ', 2004, 'Director Mel Gibson''s zeal is unmistakable, but The Passion of the Christ will leave many viewers emotionally drained rather than spiritually uplifted.', TO_DATE('2004-02-13', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('passion play', 2010, 'Passion Play has a terrific cast, but don''t be fooled - the only real question at the heart of this misbegotten mystery is what its stars were thinking.', TO_DATE('2010-09-13', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('passionada', 2003, 'If Passionada doesn''t quite spark its title emotion, the strong chemistry between its charming cast helps make this romantic dramedy a painless proposition.', TO_DATE('2003-04-27', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pat and mike', 2000, 'Katharine Hepburn and Spencer Tracy take competition to a romantic-comic highpoint in this elegantly directed sports comedy by George Cukor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pat garrett billy the kid', 2000, 'Sam Peckinpah tips his hat in mournful salute to the bygone West in this somber showdown, pitting a James Coburn against Kris Kristofferson in a meditative game of cat and mouse.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('patch adams', 2000, 'Syrupy performances and directing make this dramedy all too obvious.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paterno', 2018, 'Paterno, elevated by deft direction from Barry Levinson and a strong Al Pacino performance, presents a hard-hitting dramatization of a gut-wrenching real-life story.', TO_DATE('2018-04-03', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paterson', 2016, 'Paterson adds another refreshingly unvarnished entry to Jim Jarmusch''s filmography -- and another outstanding performance to Adam Driver''s career credits.', TO_DATE('2016-05-15', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('path to war', 2015, 'Path to War brings Lyndon B. Johnson''s full term to vivid life with terrific performances and a screenplay that provides an intimate look into a president''s psyche along with the far-reaching consequences of his decisions.', TO_DATE('2015-08-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pather panchali', 2000, 'A film that requires and rewards patience in equal measure, Pather Panchali finds director Satyajit Ray delivering a classic with his debut.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pathfinder', 2007, 'A few rousing action sequences can''t make up for Pathfinder''s non-existent plot and silly dialogue.', TO_DATE('2007-01-11', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paths of glory', 2000, 'Paths of Glory is a transcendentally humane war movie from Stanley Kubrick, with impressive, protracted battle sequences and a knock-out ending.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('patrick', 2018, 'Its pugnacious protagonist is certainly adorable, but the thoroughly formulaic Patrick will only give paws to the most pup-obsessed film fans.', TO_DATE('2018-06-27', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('patriot games', 1992, 'Patriot Games doesn''t win many points for verisimilitude, but some entertaining set pieces -- and Harrison Ford in the central role -- more than compensate for its flaws.', TO_DATE('1992-06-05', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('patriots day', 2016, 'Patriots Day offers a stirring, solidly crafted tribute to the heroes of a real-life American tragedy without straying into exploitative action thriller territory.', TO_DATE('2016-11-18', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('patton', 2000, 'George C. Scott''s sympathetic, unflinching portrayal of the titular general in this sprawling epic is as definitive as any performance in the history of American biopics.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('patton oswalt annihilation', 2017, 'A disarmingly perceptive exploration of loss, Patton Oswalt: Annihilation finds the comic deftly balancing his off-beat humor with an profoundly cathartic edge.', TO_DATE('2017-10-17', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paul', 2011, 'It doesn''t measure up to Pegg and Frost''s best work, but Paul is an amiably entertaining -- albeit uneven -- road trip comedy with an intergalactic twist.', TO_DATE('2011-01-31', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paul apostle of christ', 2018, 'Paul, Apostle of Christ proves a well-intentioned yet disappointingly diffuse interpretation of a Bible story whose flashes of potential never come close to living up to the source material.', TO_DATE('2018-03-19', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paul blart mall cop', 2009, 'Paul Blart: Mall Cop has some laughs, but its plot is flimsy and lacking in any sustained comic momentum.', TO_DATE('2009-01-13', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paul blart mall cop 2', 2015, 'Bathed in flop sweat and bereft of purpose, Paul Blart: Mall Cop 2 strings together fat-shaming humor and Segway sight gags with uniformly unfunny results.', TO_DATE('2015-04-10', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pavarotti', 2019, 'Pavarotti pays entertaining tribute to a towering cultural figure with a documentary whose evident affection for its subject proves contagious.', TO_DATE('2019-05-29', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pawn sacrifice', 2014, 'Anchored by a sensitive performance from Tobey Maguire, Pawn Sacrifice adds another solidly gripping drama to the list of films inspired by chess wiz Bobby Fischer.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pay it forward', 2000, 'Pay It Forward has strong performances from Spacey, Hunt, and Osment, but the movie itself is too emotionally manipulative and the ending is bad.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('paycheck', 2003, 'Though Dick''s short story has an intriguing premise, Woo reduces it to a lot of meaningless chases, shoot-outs, and explosions.', TO_DATE('2003-12-19', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('peace love misunderstanding', 2011, 'Peace, Love, & Misunderstanding produces many unintentional laughs with its absurdly contrived plot and cheery insistence that everything is just super.', TO_DATE('2011-09-15', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('peaceful warrior', 2006, 'Based on a best-selling memoir, Peaceful Warrior loses something in the transition from page to screen. It hits the viewer over the head with philosophical jargon, and ultimately fails to live up to its source material.', TO_DATE('2006-05-02', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pearl jam twenty', 2011, 'Cameron Crowe''s fawning documentary is a true boon for Pearl Jam fans, but the band''s insistent resistance to fame comes off hollow.', TO_DATE('2011-09-11', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('peeping tom', 2000, 'Peeping Tom is a chilling, methodical look at the psychology of a killer, and a classic work of voyeuristic cinema.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('peeples', 2013, 'Peeples is a warm, amiable farce that offers a few chuckles but mostly falls back on predictable plotting and an overwrought message.', TO_DATE('2013-05-05', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('peewees big adventure', 2000, 'Pee-Wee''s Big Adventure brings Paul Reubens'' famous character to the big screen intact, along with enough inspired silliness to dazzle children of all ages.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('peggy sue got married', 2000, 'Peggy Sue Got Married may seem just another in a line of ''80s boomer nostalgia films, but none of the others have Kathleen Turner keen lead performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the pelican brief', 1993, 'Julia Roberts and Denzel Washington are a compelling team in the overlong Pelican Brief, a pulpy thriller that doesn''t quite justify the intellectual remove of Alan J. Pakula''s direction.', TO_DATE('1993-12-17', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pelle the conqueror pelle erobreren', 2000, 'Pelle the Conqueror details the plight of the immigrant using fine, empathetic strokes, brought to life through the efforts of an outstanding cast led by Max von Sydow.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('penelope', 2006, 'Though Penelope has a charming cast and an appealing message, it ultimately suffers from faulty narrative and sloppy direction.', TO_DATE('2006-09-08', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('penguins of madagascar', 2014, 'Penguins of Madagascar is fast and brightly colored enough to entertain small children, but too frantically silly to offer real filmgoing fun for the whole family.', TO_DATE('2014-11-12', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('people i know', 2003, 'The derivative plot fails to cohere or draw the viewer in.', TO_DATE('2003-01-29', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('people like us', 2012, 'Though calculated and melodramatic, People Like Us benefits from a pair of solid leads and its rare screenplay that caters to adult filmgoers.', TO_DATE('2012-06-12', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('people places things', 2015, 'People Places Things finds writer-director Jim Strouse in peak form -- and makes the most of talented stars who help breathe fresh life into familiar narrative territory.', TO_DATE('2015-01-26', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the people under the stairs', 1991, 'Held aloft by gonzo black comedy and socially conscious subtext, The People Under The Stairs marks a unique -- though wildly uneven -- change of pace for director Wes Craven.', TO_DATE('1991-11-01', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the people vs larry flynt', 2000, 'The People Vs. Larry Flynt pays entertaining tribute to an irascible iconoclast with a well-constructed biopic that openly acknowledges his troublesome flaws.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('peoples republic of desire', 2018, 'People''s Republic of Desire fascinates and repels in equal measure with a sadly illuminating look at the intersection between technology and our relationship with celebrity.', TO_DATE('2018-03-12', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('peppermint', 2018, 'Far from refreshing, Peppermint wastes strong work from Jennifer Garner on a dreary vigilante revenge story that lacks unique twists or visceral thrills.', TO_DATE('2018-09-06', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('percy jackson sea of monsters', 2013, 'It''s pretty and packed with action; unfortunately, Percy Jackson: Sea of Monsters is also waterlogged with characters and plots that can''t help but feel derivative.', TO_DATE('2013-08-05', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('perfect blue', 2000, 'Perfect Blue is overstylized, but its core mystery is always compelling, as are the visual theatrics.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the perfect man', 2005, 'Preposterous and predictable, The Perfect Man manages few laughs with its poorly paced sitcom script, cookie-cutter characters and contrived plotting.', TO_DATE('2005-06-14', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the perfect score', 2004, 'Neither funny nor suspenseful, this heist / teen flick also fails to explore its potentially socially relevant premise.', TO_DATE('2004-01-27', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('perfect sense', 2011, 'Perfect Sense has interesting ideas and charismatic stars, all of which add up to a viewing experience that''s frustratingly less than the sum of its intriguing parts.', TO_DATE('2011-01-26', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the perfect storm', 2000, 'While the special effects are well done and quite impressive, this film suffers from any actual drama or characterization. The end result is a film that offers nifty eye-candy and nothing else.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a perfect world', 1993, 'Despite some formulaic touches, Clint Eastwood''s haunting, ambiguous crime drama is smart and gritty, and features a bravura performance from Kevin Costner as a prison escapee on the run.', TO_DATE('1993-11-24', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('performance', 2000, 'Performance is an exuberant and grimy ode to the sexual revolution, evoking cultural upheaval and identity crisis with rock ''n'' roll verve and a beguiling turn by Mick Jagger.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('perfume the story of a murderer', 2006, 'Perfume is what you''d expect from a Tom Twyker-directed movie glamorizing a serial killer: a kinetic visual feast, with a dark antihero that''s impossible to feel sympathy for.', TO_DATE('2006-09-17', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('permanent midnight', 1998, 'Aimless storytelling undermines the gripping, unsettling subject of this film.', TO_DATE('1998-09-16', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('perriers bounty', 2010, 'It has interesting characters and a strong cast, but Perrier''s Bounty ultimately fails to do anything original with them.', TO_DATE('2010-03-16', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('persepolis', 2007, 'Persepolis is an emotionally powerful, dramatically enthralling autobiographical gem, and the film''s simple black-and-white images are effective and bold.', TO_DATE('2007-05-23', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('person to person', 2017, 'Person to Person''s moments of insight and absorbing character development are scattered among an aimless, disjointed narrative.', TO_DATE('2017-01-20', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('persona', 2000, 'Arguably Bergman''s finest film, Persona explores the human condition with intense curiosity, immense technical skill, and beguiling warmth.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('personal best', 2000, 'Mariel Hemingway has a career-making star turn in this highly physical drama about two Olympic athletes who find each other during competitive training.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('personal velocity three portraits', 2002, 'Uneven, but a keenly observed and well-acted film about three women''s lives.', TO_DATE('2002-08-21', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the pest', 2000, 'The Pest aims for zany comedy with social commentary, misses, and lands squarely at offensive misfire thanks to John Leguizamo''s over-caffeinated performance and a script laden with stereotypes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pet sematary', 2001, 'Pet Sematary is a bruising horror flick that wears its quirks on its sleeves, to the detriment of its scare factor.', TO_DATE('2001-07-25', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pet sematary', 2019, 'Pet Sematary takes its source material in a few different directions, but this remake feels like an exhuming almost as often as it does a revival.', TO_DATE('2019-03-17', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pet sematary two', 2001, 'Not realizing that it had no unfinished business, Pet Sematary rises from the grave once more to beat an undead corpse.', TO_DATE('2001-02-13', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pete davidson alive from new york', 2020, 'Though not without its insights, Alive from New York struggles to find a steady beat.', TO_DATE('2020-02-25', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pete seeger the power of song', 2007, 'Pete Seeger: The Power of Song is both a tribute to a legendary singer and an informative account of the birth of American counterculture.', TO_DATE('2007-09-08', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('peter rabbit', 2018, 'Peter Rabbit updates Beatrix Potter''s classic characters with colorfully agreeable results that should entertain younger viewers while admittedly risking the wrath of purists.', TO_DATE('2018-02-04', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('petes dragon', 2002, 'Boring and slow, this is a lesser Disney work, though the animation isn''t without its charms.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('petes dragon', 2016, 'Pete''s Dragon continues Disney''s current live-action winning streak with an update that gives the original a visual overhaul without overwhelming its sweet, soulful charm.', TO_DATE('2016-07-27', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('phantasm', 2000, 'Phantasm: Remastered adds visual clarity to the first installment in one of horror''s most enduring -- and endearingly idiosyncratic -- franchises.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('phantom', 2013, 'A cast of solid actors do what they can to elevate the material, but Phantom''s script is too clunky and devoid of tension to bear comparison to its thematic predecessors.', TO_DATE('2013-02-22', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the phantom of the opera', 2004, 'The music of the night has hit something of a sour note: Critics are calling the screen adaptation of Andrew Lloyd Webber''s popular musical histrionic, boring, and lacking in both romance and danger. Still, some have praised the film for its sheer spectacle.', TO_DATE('2004-11-28', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('phantom of the opera', 2000, 'Though it lives beneath the 1925 version, Claude Rains plays title character well in this landmark color version of the classic tragedy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('phantom of the paradise', 2001, 'Brian De Palma''s subversive streak is on full display in Phantom of the Paradise, an ebullient rock opera that rhapsodizes creativity when it isn''t seething with disdain for the music industry.', TO_DATE('2001-09-11', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('phantom thread', 2017, 'Phantom Thread''s finely woven narrative is filled out nicely by humor, intoxicating romantic tension, and yet another impressively committed performance from Daniel Day-Lewis.', TO_DATE('2017-12-07', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('phat girlz', 2006, 'Although Phat Girlz has good intentions, it is sloppily made and thin on laughs.', TO_DATE('2006-04-06', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('phil spector', 2013, 'Its top-shelf script and terrific cast ensure that it''s always watchable, but Phil Spector fails to provide truly compelling drama.', TO_DATE('2013-03-29', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('philadelphia', 1993, 'Philadelphia indulges in some unfortunate clichés in its quest to impart a meaningful message, but its stellar cast and sensitive direction are more than enough to compensate.', TO_DATE('1993-12-22', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the philadelphia story', 2000, 'Offering a wonderfully witty script, spotless direction from George Cukor, and typically excellent lead performances, The Philadelphia Story is an unqualified classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('philomena', 2013, 'Based on a powerful true story and led by note-perfect performances from Judi Dench and Steve Coogan, Philomena offers a profoundly affecting drama for adult filmgoers of all ages.', TO_DATE('2013-08-31', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('phoenix', 2014, 'Tense, complex, and drenched in atmosphere, Phoenix is a well-acted, smartly crafted war drama that finds writer-director Christian Petzold working at peak power.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('phone booth', 2002, 'Quick pacing and Farrell''s performance help make Phone Booth a tense nail-biter.', TO_DATE('2002-09-11', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('phyllis and harold', 2010, 'It isn''t as profound as it pretends to be, and it strays uncomfortably close to voyeurism, but Phyllis and Harold is an undeniably engrossing documentary.', TO_DATE('2010-02-09', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pi', 1998, 'Dramatically gripping and frighteningly smart, this Lynchian thriller does wonders with its unlikely subject and shoestring budget.', TO_DATE('1998-07-10', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the pianist', 2002, 'Well-acted and dramatically moving, The Pianist is Polanski''s best work in years.', TO_DATE('2002-07-29', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the piano', 1993, 'Powered by Holly Hunter''s main performance, The Piano is a truth-seeking romance played in the key of erotic passion.', TO_DATE('1993-11-19', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the piano teacher la pianiste', 2001, 'Though it makes for rather unpleasant viewing, The Piano Teacher is a riveting and powerful psychosexual drama.', TO_DATE('2001-11-08', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pick of the litter', 2018, 'Pick of the Litter has all the fluffy adorableness audiences expect from a puppy documentary, along with a story that''s as edifying as it is heartwarming.', TO_DATE('2018-01-17', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pickpocket', 2000, 'Narratively spare and told with clockwork precision, Pickpocket is a carefully observed character study that packs an emotional wallop.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('picnic at hanging rock', 2000, 'Visually mesmerizing, Picnic at Hanging Rock is moody, unsettling, and enigmatic -- a masterpiece of Australian cinema and a major early triumph for director Peter Weir.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pieces of april', 2003, 'Pieces of April transcends its small-scale setting and budget with endearing performances, playful humor, and genuine sweetness, resulting in a touching holiday treat.', TO_DATE('2003-01-30', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('piercing', 2018, 'Stylish with a sadistic streak, Piercing pairs gripping lead performances with a smartly macabre story that delivers unpredictable thrills.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pierrepoint the last hangman', 2005, 'Director Adrian Shergold doesn''t shy away from the darker elements of the movie''s subject, and Timothy Spall is mesmerizing as the title character.', TO_DATE('2005-10-06', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pierrot le fou pierrot goes wild crazy pete', 2002, 'Colorful, subversive, and overall beguiling, Pierrot le Fou is arguably Jean-Luc Godard''s quintessential work.', TO_DATE('2002-07-30', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pieta', 2013, 'It lacks subtlety and depth of character, but Pieta gets by with committed performances and a darkly ambitious, deceptively simple message.', TO_DATE('2013-03-17', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('piglets big movie', 2003, 'Wholesome and charming entertainment for young children.', TO_DATE('2003-03-15', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pin cushion', 2017, 'Pin Cushion explores the prickly dynamics of mother-daughter relationships and female friendships, led by striking work from leads Lily Newmark and Joanna Scanlan.', TO_DATE('2017-09-27', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pina', 2011, 'Pina is an immersive, gorgeously shot tribute to the people who express life through movement.', TO_DATE('2011-04-18', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pineapple express', 2008, 'Both funny and scattershot, this loose-knit action/buddy/stoner comedy bridges genres and keeps a steady tempo of low-ball laughs.', TO_DATE('2008-05-15', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('piñero', 2001, 'Though Bratt is great in the title role, the biopic itself is messy and Piñero grows tiresome.', TO_DATE('2001-09-07', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ping pong playa', 2008, 'A gentle, light, kid friendly comedy about a Chinese-American hoopster turned ping pong pro, Playa is a charming but considerable digression from director Jessica Yu''s previous works.', TO_DATE('2008-07-24', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ping pong summer', 2014, 'This Summer remembrance is brimming with nostalgic flourishes and easygoing charm, but is as stubbornly weightless as a Ping Pong ball.', TO_DATE('2014-01-24', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the pink panther', 2006, 'Though Steve Martin is game, the particulars of the Inspector Clouseau character elude him in this middling update.', TO_DATE('2006-02-06', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pink panther 2', 2009, 'Underutilizing its talented cast, The Pink Panther 2 is little more than a series of lame slapstick gags.', TO_DATE('2009-02-02', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pinocchio', 2000, 'Ambitious, adventurous, and sometimes frightening, Pinocchio arguably represents the pinnacle of Disney''s collected works -- it''s beautifully crafted and emotionally resonant.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pioneer', 2013, 'Pioneer boasts strong acting and a throwback conspiracy thriller vibe, but fails to take it far enough -- and is very slow about not getting there.', TO_DATE('2013-10-16', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('piranha 3d', 2010, 'Playing exactly to expectations for a movie about killer fish run amok, Piranha 3-D dishes out gore, guffaws and gratuitous nudity with equal glee.', TO_DATE('2010-08-19', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('piranha 3dd', 2012, 'It strains to up the gore and self-awareness of it predecessor, and -- despite some game celebrity cameos -- the result is a dispiriting echo of 2010''s horror-comedy.', TO_DATE('2012-05-11', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('piranhas la paranza dei bambini', 2019, 'Piranhas fails to be anything more than another run-of-the-mill gangster drama.', TO_DATE('2019-02-12', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pirate radio the boat that rocked', 2009, 'The good cast and rollicking soundtrack eventually drown when this comic homage to pirate radio loses its quippy steam.', TO_DATE('2009-03-30', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pirates of the caribbean at worlds end', 2007, 'POTC: AWE provides the thrilling action scenes, but mixes in too many characters with too many incomprehensible plot threads.', TO_DATE('2007-05-22', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pirates of the caribbean dead mans chest', 2006, 'Gone is Depp''s unpredictability and much of the humor and originality of the first movie.', TO_DATE('2006-06-28', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pirates of the caribbean dead men tell no tales', 2017, 'Pirates of the Caribbean: Dead Men Tell No Tales proves that neither a change in directors nor an undead Javier Bardem is enough to drain this sinking franchise''s murky bilge.', TO_DATE('2017-05-22', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pirates of the caribbean on stranger tides', 2011, 'It''s shorter and leaner than the previous sequel, but this Pirates runs aground on a disjointed plot and a non-stop barrage of noisy action sequences.', TO_DATE('2011-05-10', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pirates of the caribbean the curse of the black pearl', 2003, 'May leave you exhausted like the theme park ride that inspired it; however, you''ll have a good time when it''s over.', TO_DATE('2003-06-17', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the pirates who dont do anything a veggietales movie', 2008, 'This Veggietale should please the youngest crowds, but the silly script will tire the more discerning viewer.', TO_DATE('2008-01-08', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pitch black', 2000, 'Despite an interesting premise (and a starmaking turn from Vin Diesel), Pitch Black is too derivative and formulaic to fully recommend to sci-fi or action fans.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pitch perfect', 2012, 'Pitch Perfect''s plot is formulaic, but the performances are excellent and the musical numbers are toe-tapping as well.', TO_DATE('2012-09-23', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pitch perfect 2', 2015, 'Pitch Perfect 2 sings in sweet comedic harmony, even if it doesn''t hit quite as many high notes as its predecessor.', TO_DATE('2015-05-03', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pitch perfect 3', 2017, 'Pitch Perfect 3 strains to recapture the magic that helped the original spawn a franchise, but ends up sending this increasingly unnecessary trilogy out on a low note.', TO_DATE('2017-12-19', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pixels', 2015, 'Much like the worst arcade games from the era that inspired it, Pixels has little replay value and is hardly worth a quarter.', TO_DATE('2015-07-22', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a place in the sun', 2000, 'Director George Stevens'' stately treatment of A Place in the Sun buffs out some of the novel''s nuance with blunt moralizing, but riveting performances by Montgomery Clift and company give the drama a bruising punch.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('places in the heart', 2000, 'Places in the Heart is a quiet character piece with grand ambitions that it more than fulfills, thanks to absorbing work from writer-director Robert Benton and a tremendous cast.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('plagues pleasures on the salton sea', 2004, 'Plagues And Pleasures is a thoroughly engrossing account, both humorous and disheartening, of a once bustling community ravaged by ecological change and human greed.', TO_DATE('2004-01-12', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('plan 9 from outer space', 1959, 'The epitome of so-bad-it''s-good cinema, Plan 9 From Outer Space is an unintentionally hilarious sci-fi "thriller" from anti-genius Ed Wood that is justly celebrated for its staggering ineptitude.', TO_DATE('1959-07-02', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('planes', 2013, 'Planes has enough bright colors, goofy voices, and slick animation to distract some young viewers for 92 minutes -- and probably sell plenty of toys in the bargain -- but on nearly every other level, it''s a Disney disappointment.', TO_DATE('2013-08-06', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('planes fire and rescue', 2014, 'Although it''s too flat and formulaic to measure up against the best family-friendly fare, Planes: Fire and Rescue is a passable diversion for much younger viewers.', TO_DATE('2014-07-04', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('planes trains and automobiles', 2000, 'Thanks to the impeccable chemistry between Steve Martin and John Candy, as well as a deft mix of humor and heart, Planes, Trains and Automobiles is a hilarious, heartfelt holiday classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('planet 51', 2009, 'Planet 51 squanders an interesting premise with an overly familiar storyline, stock characters, and humor that alternates between curious and potentially offensive.', TO_DATE('2009-11-16', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('planet bboy', 2007, 'Lee''s dazzling documentary makes a compelling argument for breakdancing as an art form.', TO_DATE('2007-04-26', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('planet terror grindhouse presents robert rodriguezs planet terror', 2007, 'A cool and hip grindhouse throwback, Planet Terror is an unpredictable zombie thrillride.', TO_DATE('2007-10-15', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('plastic', 2014, 'Far-fetched, frantically overstuffed, and unfunny, Plastic seems to use its title as a goal as much as a description.', TO_DATE('2014-04-27', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('platoon', 2000, 'Informed by director Oliver Stone''s personal experiences in Vietnam, Platoon forgoes easy sermonizing in favor of a harrowing, ground-level view of war, bolstered by no-holds-barred performances from Charlie Sheen and Willem Dafoe.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('play it to the bone', 2000, 'Flat characters and uninspired comedy yield forgettable results.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('play misty for me', 2000, 'A coolly calculating psychological thriller that manages to scare the audience even if it is just using textbook thrills.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('play the game', 2009, 'Andy Griffith is his usually likable self, but he''s stranded in a middling comedy that''s surprisingly tasteless and poorly crafted.', TO_DATE('2009-04-01', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('playing by heart', 1998, 'It''s overly talky, but Playing By Heart benefits from witty insights into modern relationships and strong performances from an esteemed cast.', TO_DATE('1998-12-30', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('playing for keeps', 2012, 'Witless, unfocused, and arguably misogynistic, Playing for Keeps is a dispiriting, lowest-common-denominator Hollywood rom-com.', TO_DATE('2012-12-05', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('playing it cool', 2015, 'Playing It Cool pits Chris Evans and Michelle Monaghan''s easy chemistry against a screenplay that tries too hard to be quirky and clever, and the results are disappointingly lukewarm.', TO_DATE('2015-02-26', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('playmobil the movie', 2019, 'Much like the toys it advertises, Playmobil: The Movie seems sadly destined to be regarded as a superficially similar yet less desirable alternative to the competition.', TO_DATE('2019-06-11', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('playtime', 2001, 'A remarkable achievement, Playtime''s packs every scene with sight gags and characters that both celebrates and satirizes the urbanization of modern life.', TO_DATE('2001-08-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pleasantville', 2000, 'Filled with lighthearted humor, timely social commentary, and dazzling visuals, Pleasantville is an artful blend of subversive satire and well-executed Hollywood formula.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('please stand by', 2018, 'Please Stand By hits a number of familiar coming-of-age beats, but adds just enough of a Trek-fueled twist to keep things interesting.', TO_DATE('2018-01-15', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pledge', 2018, 'Pledge leaves a certain amount of potential untapped in its extreme take on collegiate hazing, but the end result is still well-executed enough to be worth a watch.', TO_DATE('2018-08-02', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('poetic justice', 1993, 'Poetic Justice is commendably ambitious and boasts a pair of appealing stars, but they''re undermined by writer-director John Singleton''s frustrating lack of discipline.', TO_DATE('1993-07-23', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('poetry', 2010, 'Poetry is an absorbing, poignant drama because it offers no easy answers to its complex central conflict.', TO_DATE('2010-09-20', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('point and shoot', 2014, 'Thrilling and thought-provoking, Point and Shoot captures one man''s fascinating -- if troublingly narcissistic -- "crash course in manhood."', TO_DATE('2014-05-01', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('point blank', 2019, 'Point Blank has its reasonably diverting moments, but high energy and fast-paced action can''t disguise this remake''s frustratingly middling storytelling.', TO_DATE('2019-07-11', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('point break', 1991, 'Absurd, over-the-top, and often wildly entertaining, Point Break is here to show you that the human spirit is still alive.', TO_DATE('1991-01-01', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('point break', 2015, 'Loaded with dazzling action but bereft of purpose, the Point Break remake will be remembered as the first film to make audiences pine for the simultaneous presences of Keanu Reeves and Gary Busey.', TO_DATE('2015-12-03', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pokémon 3 the movie', 2001, 'Critics say that the third Pokemon movie has a better plot than its two predecessors. This is not enough, however, to recommend it to those not already fans of the franchise.', TO_DATE('2001-04-02', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pokémon 4ever', 2002, 'Only for diehard Pokemon fans.', TO_DATE('2002-10-07', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pokémon detective pikachu', 2019, 'Pokémon Detective Pikachu may not take its wonderfully bizarre premise as far as it could have, but this offbeat adaptation should catch most -- if not all -- of the franchise''s fans.', TO_DATE('2019-05-03', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pokémon the first movie mewtwo vs mew', 1999, 'Audiences other than children will find very little to entertain them.', TO_DATE('1999-11-06', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('polar', 2019, 'An action thriller starring Mads Mikkelsen as the world''s most dangerous assassin should be terrifically entertaining, but Polar proves it''s possible to ruin anything if you try.', TO_DATE('2019-01-23', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the polar express', 2004, 'Though the movie is visually stunning overall, the animation for the human characters isn''t lifelike enough, and the story is padded.', TO_DATE('2004-10-25', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('police academy', 2000, 'Police Academy is rude, crude, and proudly sophomoric -- which is either a condemnation or a ringing endorsement, depending on your taste in comedy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('police academy 4 citizens on patrol', 2000, 'Utterly, completely, thoroughly and astonishingly unfunny, Police Academy 4: Citizens on Patrol sends a once-innocuous franchise plummeting to agonizing new depths.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('politist adj police adjective', 2009, 'Shorn of any manufactured drama or pyrotechnics, Police, Adjective is an absorbing procedural that finds its thrills in the patient bureaucracy of police work.', TO_DATE('2009-05-13', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('police story ging chaat goo si police force', 2000, 'Blending brilliant physical comedy with thrillingly choreographed set pieces, Police Story makes a persuasive case for Jackie Chan as one of the all-time genre greats.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('polina polina danser sa vie', 2017, 'Gorgeous cinematography captures dazzling choreography in an engaging portrait of a dancer''s life, even if Polina can''t quite twirl itself away from clichés.', TO_DATE('2017-02-09', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('polisse', 2011, 'Polisse is a gripping and powerful procedural drama filled with fine acting and unflinching eye for truth and brutality.', TO_DATE('2011-08-13', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pollock', 2000, 'Though Pollock does not really allow audiences a glimpse of the painter as a person, it does powerfully depict the creative process. Harris throws himself into the role and turns in a compelling performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('poltergeist', 2015, 'Paying competent homage without adding anything of real value to the original Poltergeist, this remake proves just as ephemeral (but half as haunting) as its titular spirit.', TO_DATE('2015-05-19', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('polyester', 2001, 'As proudly tacky as its titular fabric, Polyester finds writer-director John Waters moving ever so slightly into the mainstream without losing any of his subversive charm.', TO_DATE('2001-09-08', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pom wonderful presents the greatest movie ever sold', 2011, 'The Greatest Movie Ever Sold plays smartly to Spurlock''s strengths, and the result is a breezy, albeit not particularly enlightening documentary.', TO_DATE('2011-01-25', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pompeii', 2014, 'This big-budget sword-and-sandal adventure lacks the energy and storytelling heft to amount to more than a guilty pleasure.', TO_DATE('2014-02-19', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('poms', 2019, 'While the cast is something to cheer about, Poms squanders its talented stars on a clichéd comedy that disrespects the demographic it''s trying to celebrate.', TO_DATE('2019-05-08', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pontypool', 2009, 'Witty and restrained but still taut and funny, this Pontypool is a different breed of low-budget zombie film.', TO_DATE('2009-03-06', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ponyo', 2009, 'While not Miyazaki''s best film, Ponyo is a visually stunning fairy tale that''s a sweetly poetic treat for children of all ages.', TO_DATE('2009-08-03', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('poohs heffalump movie', 2005, 'A charming and delightful walk through the Hundred Acres Woods for young viewers.', TO_DATE('2005-02-05', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pootie tang', 2001, 'Based as it is on a short skit, Pootie Tang overstays its welcome.', TO_DATE('2001-06-28', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pope francis a man of his word', 2018, 'Pope Francis - A Man of His Word offers a compelling look at the pontiff''s ideas and message, even if its distance from the man means it won''t win many new converts.', TO_DATE('2018-05-14', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('popstar never stop never stopping', 2016, 'Popstar: Never Stop Never Stopping updates the rock mockumentary for the 21st century mainstream -- and hits many of its low-hanging targets with side-splitting impact.', TO_DATE('2016-05-31', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('porno', 2019, 'Porno mines sexual repression to produce a laughably lurid -- and genuinely scary -- outing that should delight genre fans in search of a good time.', TO_DATE('2019-03-10', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('portrait of a lady on fire portrait de la jeune fille en feu', 2019, 'A singularly rich period piece, Portrait of a Lady on Fire finds stirring, thought-provoking drama within a powerfully acted romance.', TO_DATE('2019-05-19', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('poseidon', 2006, 'This remake of The Poseidon Adventure delivers dazzling special effects. Unfortunately, it doesn''t seem that any of the budget was left over to devote to the script.', TO_DATE('2006-04-27', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('possession', 2002, 'It''s perhaps a bit tame and uninspiring, considering its subject matter, but Possession manages enough romance and period intrigue to satisfy most fans of its source material.', TO_DATE('2002-04-09', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('possum', 2018, 'Unsettling and absorbing in equal measure, Possum presents a dark character study rich with rewards for fans of chilling genre fare.', TO_DATE('2018-07-06', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('post grad', 2009, 'A lightweight, unambitious comedy, Post Grad features fine actors that can do little with its middling, uninspiring script.', TO_DATE('2009-08-16', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('post tenebras lux', 2012, 'Post Tenebras Lux conjures striking imagery amidst its formless exploration into darkness and light, but director Carlos Reygadas paints his abstract work with the slowest of brushstrokes.', TO_DATE('2012-05-24', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('postal', 2007, 'An attempt at political satire that lacks any wit or relevance, Postal is nonetheless one of Uwe Boll''s more successful films -- for what it''s worth.', TO_DATE('2007-07-11', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('postcards from the edge', 1990, 'Uniting a pair of powerhouse talents with a smart, sharply written script, Postcards from the Edge makes compelling drama out of reality-inspired trauma.', TO_DATE('1990-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the postman', 1997, 'A massive miscalculation in self-mythologizing by director and star Kevin Costner, The Postman would make for a goofy good time if it weren''t so fatally self-serious.', TO_DATE('1997-12-25', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('poultrygeist night of the chicken dead', 2007, 'Poultrygeist may be relentlessly tasteless and juvenile, but it''s also a lively slice of schlocky fun.', TO_DATE('2007-08-23', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('powder', 1995, 'Powder has some interesting and potentially affecting ideas, but they''re ultimately dust in the wind of a drama that strains far too obviously for uplift.', TO_DATE('1995-10-27', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('power and terror noam chomsky in our times', 2002, 'Chomsky is a compelling, thoughtful speaker.', TO_DATE('2002-11-14', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('practical magic', 2000, 'Practical Magic''s jarring tonal shifts sink what little potential its offbeat story may have -- though Nicole Kidman and Sandra Bullock''s chemistry makes a strong argument for future collaborations.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a prairie home companion', 2006, 'The final film by the great Robert Altman, A Prairie Home Companion, the big screen adaptation of Garrison Keillor''s radio broadcast showcases plenty of the director''s strengths: it''s got a gigantic cast and plenty of quirky acting and dialogue.', TO_DATE('2006-02-13', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('prancer', 2000, 'Prancer''s good-natured holiday cheer -- and a terrific performance from its young star -- are enough to make this yuletide adventure a moderately rewarding watch.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pray the devil back to hell', 2008, 'This political documentary about protests during the Liberian Civil War is an uplifting celebration of the capacity of everyday people to affect great change.', TO_DATE('2008-10-18', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('prayers for bobby', 2019, 'A devastating true story and terrific performance by Sigourney Weaver give Prayers for Bobby palpable power, although some viewers may find this well-intentioned film too calculating in its efforts to wring tears.', TO_DATE('2019-10-03', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the preachers wife', 1996, 'Solid performances and a steady directorial hand help The Preacher''s Wife offer some reliably heartwarming - albeit fairly predictable - holiday cheer.', TO_DATE('1996-12-13', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('precious based on the novel push by sapphire', 2009, 'Precious is a grim yet ultimately triumphant film about abuse and inner-city life, largely bolstered by exceptional performances from its cast.', TO_DATE('2009-05-09', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('predator', 2000, 'Predator: Part sci-fi, part horror, part action -- all muscle.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('predator 2', 1990, 'The thrill of the hunt is gone in this hackneyed sequel.', TO_DATE('1990-11-21', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('predestination', 2014, 'Fun genre fare with uncommon intelligence, Predestination serves as a better-than-average sci-fi adventure -- and offers a starmaking turn from Sarah Snook.', TO_DATE('2014-03-09', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('premature', 2019, 'Premature transcends its familiar trappings with sharp dialogue and a strong sense of setting that further establish Rashaad Ernesto Green as a gifted filmmaker.', TO_DATE('2019-01-27', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('premium rush', 2012, 'It''s built out of familiar parts, but no matter how formulaic Premium Rush''s storyline might seem, it''s elevated by high-octane action and enjoyable performances.', TO_DATE('2012-08-23', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('premonition', 2007, 'Overdosing on flashbacks, and more portentous than profound, the overly obtuse Premonition weakly echoes such twisty classics as Memento, The Sixth Sense, and Groundhog Day.', TO_DATE('2007-02-22', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('presenting princess shaw', 2016, 'Presenting Princess Shaw works as a uniquely uplifting look at internet stardom -- and a compelling glimpse of an artist whose gifts transcend the medium.', TO_DATE('2016-04-06', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the presidents last bang', 2005, 'Although it''s possibly best enjoyed by viewers with some knowledge of South Korean history, The President''s Last Bang entertainingly blends true crime and dark comedy.', TO_DATE('2005-09-14', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the prestige', 2006, 'Full of twists and turns, The Prestige is a dazzling period piece that never stops challenging the audience.', TO_DATE('2006-10-13', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('presumed innocent', 1990, 'Thanks to an outstanding script, focused direction by Alan Pakula, and a riveting performance from Harrison Ford, Presumed Innocent is the kind of effective courtroom thriller most others aspire to be.', TO_DATE('1990-07-27', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pretty in pink', 1986, 'Molly Ringwald gives an outstanding performance in this sweet, intelligent teen comedy that takes an ancient premise and injects it with insight and wit.', TO_DATE('1986-02-28', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pretty persuasion', 2005, 'Pretty Persuasion aims for high satire but falls short of poignancy by depending on too much black humor, with too little redeeming humanity to provide balance.', TO_DATE('2005-01-28', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pretty woman', 2000, 'Pretty Woman may be a yuppie fantasy, but the film''s slick comedy, soundtrack, and casting can overcome misgivings.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('prey for rock roll', 2003, 'Gershon is a fierce rocker, but the plot is a cliche-filled melodrama.', TO_DATE('2003-05-02', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('priceless', 2006, 'Priceless is a light, farcical rom-com that features sharp performances from Audrey Tautou and Gad Elmaleh.', TO_DATE('2006-11-18', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pride', 2007, 'Pride features a typically stellar performance from Terrence Howard, but ultimately falls victim to its over usage of sports movie clichés.', TO_DATE('2007-03-05', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pride', 2014, 'Earnest without being didactic and uplifting without stooping to sentimentality, Pride is a joyous crowd-pleaser that genuinely works.', TO_DATE('2014-05-23', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pride and glory', 2008, 'Formulaic in its plotting and cliched in its dialogue, Pride and Glory does little to distinguish itself from other police procedurals.', TO_DATE('2008-09-11', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pride and prejudice and zombies', 2016, 'Pride and Prejudice and Zombies manages to wring a few fun moments out of its premise, but never delivers the thoroughly kooky mashup its title suggests.', TO_DATE('2016-01-29', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the pride of the yankees', 2001, 'The equally tragic and heroic story of Yankee''s first baseman Lou Gehrig is eloquently told here with an iconic star turn by Gary Cooper.', TO_DATE('2001-05-12', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('primal', 2019, 'Chiefly of interest to Nicolas Cage completists and hardcore B-movie fans, this action thriller suffers from an unfortunate lack of Primal energy.', TO_DATE('2019-11-04', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('primary colors', 1998, 'Well acted and suprisingly funny.', TO_DATE('1998-03-20', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('prime', 2005, 'Though Streep is dependably terrific in her role, the rest of the movie is too sitcom-ish, and the romance itself is dull.', TO_DATE('2005-10-11', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('primer', 2004, 'Dense, obtuse, but stimulating, Primer is a film for viewers ready for a cerebral challenge.', TO_DATE('2004-01-27', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('primeval', 2007, 'Primeval is a low-quality horror film, which due to the inane political messages does not even qualify as campy fun.', TO_DATE('2007-01-12', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('prince avalanche', 2013, 'A step back in the right direction for director David Gordon Green, Prince Avalanche shambles amiably along with a pair of artfully low-key performances from Paul Rudd and Emile Hirsch.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('prince of darkness', 2000, 'Prince of Darkness has a handful of chillingly clever ideas, but they aren''t enough to put John Carpenter''s return to horror at the same level as his classic earlier outings.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the prince of egypt', 1998, 'The Prince of Egypt''s stunning visuals and first-rate voice cast more than compensate for the fact that it''s better crafted than it is emotionally involving.', TO_DATE('1998-12-18', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('prince of persia the sands of time', 2010, 'It doesn''t offer much in the way of substance, but Prince of Persia is a suitably entertaining swashbuckler -- and a substantial improvement over most video game adaptations.', TO_DATE('2010-05-10', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the prince of tides', 1991, 'Although the central romance arguably suffocates the heart of the drama, a moving performance by Nick Nolte and Barbra Streisand''s deft direction give The Prince of Tides a soulful edge.', TO_DATE('1991-12-25', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('princess kaiulani', 2010, 'A middling biopic about an important figure in Hawaiian history, Princes Kaiulani looks and feels like a TV movie of the week and offers about as much insight.', TO_DATE('2010-05-07', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the princess bride', 2000, 'A delightfully postmodern fairy tale, The Princess Bride is a deft, intelligent mix of swashbuckling, romance, and comedy that takes an age-old damsel-in-distress story and makes it fresh.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the princess diaries', 2001, 'A charming, if familiar, makeover movie for young teenage girls.', TO_DATE('2001-07-22', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the princess diaries 2 royal engagement', 2004, 'Anne Hathaway and Julie Andrews bring charm and elegance to the movie, but there''s not enough material for them to work with in this sequel.', TO_DATE('2004-05-25', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('princess mononoke mononokehime', 2000, 'With its epic story and breathtaking visuals, Princess Mononoke is a landmark in the world of animation.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('prisoners', 2013, 'Prisoners has an emotional complexity and a sense of dread that makes for absorbing (and disturbing) viewing.', TO_DATE('2013-08-31', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('private benjamin', 2001, 'Private Benjamin proves a potent showcase for its Oscar-nominated star, with Hawn making the most of a story that rests almost completely on her daffily irresistible charm.', TO_DATE('2001-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('private life', 2018, 'Private Life uses one couple''s bumpy journey to take an affecting look at an easily identifiable - and too rarely dramatized - rite of adult passage.', TO_DATE('2018-01-19', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the private lives of pippa lee', 2009, 'Reverential and offbeat, the road trip film Private lives of Pippa Lee takes emotional detours and is elevated by great performances, particularly that of Robin Wright-Penn.', TO_DATE('2009-07-10', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('private peaceful', 2012, 'Private Peaceful''s deliberate pace will test the patience of many viewers, but its lush visuals and moving screenplay may offer sufficient compensation.', TO_DATE('2012-10-02', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the prize winner of defiance ohio', 2005, 'Noteworthy for Julianne Moore''s performance, Prize Winner is nonetheless a largely indistinct and tentative film that fails to convey the true power of its bittersweet tale.', TO_DATE('2005-09-21', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('problem child', 2000, 'Mean-spirited and hopelessly short on comic invention, Problem Child is a particularly unpleasant comedy, one that''s loaded with manic scenery chewing and juvenile pranks.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('problem child 2', 2000, 'Crude, rude, puerile, and pointless, Problem Child 2 represents a cynical nadir in family-marketed entertainment.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the producers', 2005, 'Despite the rich source material, The Producers has a stale, stagy feel more suited to the theater than the big screen.', TO_DATE('2005-11-18', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('professor marston the wonder women', 2017, 'Professor Marston & The Wonder Women winds a lasso of cinematic truth around a fascinating fact-based tale with strong performances from its three stars.', TO_DATE('2017-09-09', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('project almanac', 2014, 'Project Almanac isn''t without wit or originality, but its thin story and irritating found-footage camerawork ultimately make it difficult to recommend.', TO_DATE('2014-08-23', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('project nim', 2011, 'Equal parts hilarious, poignant, and heartbreaking, Project Nim not only tells a compelling story masterfully, but also raises the flag on the darker side of human nature.', TO_DATE('2011-01-21', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('project x', 2012, 'Unoriginal, unfunny, and all-around unattractive, Project X mines the depths of the teen movie and found-footage genres for 87 minutes of predictably mean-spirited debauchery.', TO_DATE('2012-02-28', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('prom', 2011, 'Given its flatly descriptive title and live-action Disney pedigree, Prom is more nuanced and less cynical -- but also just as corny and cliched -- as you might expect.', TO_DATE('2011-04-26', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('prom night', 2008, 'A dim and predictable remake of an already dull slasher film, this Prom Night fails to be memorable.', TO_DATE('2008-04-09', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('promare', 2019, 'Visually dazzling and narratively exhilarating, Promare is a colorful thrill ride that should entertain adult anime enthusiasts as well as the teens in its target audience.', TO_DATE('2019-05-20', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('prometheus', 2012, 'Ridley Scott''s ambitious quasi-prequel to Alien may not answer all of its big questions, but it''s redeemed by its haunting visual grandeur and compelling performances -- particularly Michael Fassbender as a fastidious android.', TO_DATE('2012-05-30', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('proof', 2005, 'Gwyneth Paltrow and Anthony Hopkins give exceptional performances in a film that intelligently tackles the territory between madness and genius.', TO_DATE('2005-08-18', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('proof of life', 2000, 'Despite its promising premise and superstar cast, Proof of Life is just a routine thriller that doesn''t offer anything new.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the proposition', 2005, 'Brutal, unflinching, and violent, but thought-provoking and with excellent performances, this Australian western is the one of the best examples of the genre to come along in recent times.', TO_DATE('2005-09-15', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('prospect', 2018, 'Fueled by character development and setting instead of special effects, Prospect is a sci-fi story whose style is defined - and enriched -- by its limitations.', TO_DATE('2018-03-12', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('protagonist', 2007, 'Protagonist skillfully intertwines its subjects'' lives through an unexpected common thread -- Euripedes.', TO_DATE('2007-01-25', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the protector tom yum goong warrior king', 2005, 'Despite some impressive fight scenes, this trimmed-down version of the Thai action pic is an off-putting mix of scant plot, choppy editing, and confusing subtitles and dubbing.', TO_DATE('2005-08-11', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('proud mary', 2018, 'Proud Mary proves Taraji P. Henson has more than enough attitude and charisma to carry an action movie -- just not, unfortunately, one this indifferently assembled.', TO_DATE('2018-01-12', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('provoked', 2007, 'Provoked''s story is worth telling, but the hammy dialogue and heavy-handed direction doesn''t give it the refined treatment it deserves.', TO_DATE('2007-04-03', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('proxy', 2013, 'Proxy''s ambitious reach slightly exceeds its grasp, but its subversive narrative and alluringly dreamlike aesthetic make this horror mystery hard to ignore.', TO_DATE('2013-10-03', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ps i love you', 2007, 'Hilary Swank is miscast as the romantic lead in this clichéd film about loss and love.', TO_DATE('2007-12-12', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('psycho', 1960, 'Infamous for its shower scene, but immortal for its contribution to the horror genre. Because Psycho was filmed with tact, grace, and art, Hitchcock didn''t just create modern horror, he validated it.', TO_DATE('1960-06-16', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('psycho ii', 2000, 'Although it can''t hold a cleaver to the classic original, Psycho II succeeds well enough on its own merits to satisfy horror fans.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('puccini for beginners', 2006, 'A Woody Allen-ish film that needs more of the caustic wit expected from the best New York rom coms.', TO_DATE('2006-01-23', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pulp fiction', 2000, 'One of the most influential films of the 1990s, Pulp Fiction is a delirious post-modern mix of neo-noir thrills, pitch-black humor, and pop-culture touchstones.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pulse', 2005, 'Another stale American remake of a successful Japanese horror film, Pulse bypasses the emotional substance of the original and overcompensates with pumped-up visuals and every known horror cliche.', TO_DATE('2005-11-16', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pulse kairo', 2002, 'A sinister spine-tingling techno-thriller whose artistry lies in the power of suggestion rather than a barrage of blood and guts or horror shop special effects.', TO_DATE('2002-02-26', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pumping iron', 2003, 'In addition to offering an enlightening early look into the world of future star/politician Arnold Schwarzenegger, Pumping Iron provides a witty and insightful overview of competitive bodybuilding.', TO_DATE('2003-05-24', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pumpkin', 2002, 'The messy Pumpkin wastes its premise by not making the satire sharp enough.', TO_DATE('2002-03-08', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pumpkinhead', 2000, 'With effects work and solid direction from Stan Winston -- and Lance Henriksen adding welcome gravitas -- Pumpkinhead is a creature feature that stands a cut above.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('punchdrunk love', 2002, 'Odd, touching, and unique, Punch-Drunk Love is also delightfully funny, utilizing Adam Sandler''s comic persona to explore the life of a lonely guy who finds love.', TO_DATE('2002-05-22', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('puncture', 2011, 'There''s a compelling story at the heart of Puncture but viewers will have to pierce through the formulaic storytelling to find it.', TO_DATE('2011-04-24', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('punisher war zone', 2008, 'Punisher: War Zone recalls the excessively violent, dialogue-challenged actioners of the 1980s, and coincidentally feels two decades out of date.', TO_DATE('2008-01-23', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('punks not dead', 2006, 'Susan Dynner''s Punk''s Not Dead is a thrilling and ambitious overview of the history and resilience of punk music, featuring interviews with an array of the genre''s outspoken godfathers.', TO_DATE('2006-06-24', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('puppet master the littlest reich', 2018, 'Puppet Master: The Littlest Reich delivers all the proudly distasteful B-movie antics genre fans might expect from a film about murderous Nazi dolls.', TO_DATE('2018-04-23', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('purple butterfly zi hudie', 2003, 'Ye Lou''s Purple Butterfly is atmospheric and moody, but the story is frustratingly muddled.', TO_DATE('2003-05-28', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('purple noon plein soleil', 1996, 'The talented Tom Ripley is brought to enigmatic life on the screen in Purple Noon, an exquisite thriller wherein the murderous social climber is embodied by an unnerving Alain Delon.', TO_DATE('1996-06-28', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('purple rain', 2000, 'Purple Rain makes for undeniably uneven cinema, but it''s held together by its star''s singular charisma -- not to mention a slew of classic songs.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the purple rose of cairo', 2000, 'Lighthearted and sweet, The Purple Rose of Cairo stands as one of Woody Allen''s more inventive -- and enchantingly whimsical -- pictures.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the pursuit of happyness', 2006, 'Will Smith''s heartfelt performance elevates The Pursuit of Happyness above mere melodrama.', TO_DATE('2006-12-06', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pushing tin', 2000, 'Solid performances by the leads, but the generic ending needs help.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('pyewacket', 2017, 'Pyewacket builds its atmospheric, patiently encroaching chills on a well-told story concerned more with emotional trauma than supernatural threats.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('q', 2000, 'Q''s campy charms may be lost on audiences who want their monsters frightening, but a game cast and lovingly retrograde visual effects give this kaiju romp some majesty.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('quai des orfèvres quay of the goldsmiths jenny lamour', 2002, 'Henri-Georges Clouzot''s engrossing noir explores the troubles of post-war France and the line dividing social struggle and criminality.', TO_DATE('2002-10-22', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('quantum of solace', 2008, 'Brutal and breathless, Quantum Of Solace delivers tender emotions along with frenetic action, but coming on the heels of Casino Royale, it''s still a bit of a disappointment.', TO_DATE('2008-10-20', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('quartet', 2012, 'It''s sweet, gentle, and predictable to a fault, but Dustin Hoffman''s affectionate direction and the talented cast''s amiable charm make Quartet too difficult to resist.', TO_DATE('2012-09-11', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the queen', 2006, 'Full of wit, humor, and pathos, Stephen Frears'' moving portrait looks at life of the British royals during the period after Princess Diana''s death.', TO_DATE('2006-08-24', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('queen and country', 2014, 'Graceful and bittersweet, Queen and Country finds writer-director John Boorman revisiting past glories with warmth and wisdom.', TO_DATE('2014-05-20', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('queen slim', 2019, 'Stylish, provocative, and powerful, Queen & Slim tells a gripping fugitive story steeped in timely, thoughtful subtext.', TO_DATE('2019-11-15', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('queen of earth', 2015, 'Led by a searing performance from Elisabeth Moss, Queen of Earth is a demanding -- and ultimately rewarding -- addition to writer-director Alex Ross Perry''s impressive filmography.', TO_DATE('2015-02-13', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('queen of the damned', 2002, 'A muddled and campy MTV-styled vampire movie with lots of eye candy and bad accents.', TO_DATE('2002-02-12', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('queen of the desert', 2015, 'Queen of the Desert unites some undeniably talented professionals, but it''s difficult to discern what drew them together -- or understand how its compelling real-life story became such a muddled mess.', TO_DATE('2015-02-06', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reinas queens', 2006, 'It hints at something greater, but ultimately, Queens lacks the substance necessary to set it apart from similarly themed Spanish comedies.', TO_DATE('2006-06-02', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('quest for camelot', 1998, 'Diminished by uneven animation and treacly songs, Quest for Camelot is an adventure that ought to be tossed back to the Lady in the Lake.', TO_DATE('1998-05-15', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('quest for fire', 2002, 'Its characters can''t do much more than grunt, but that doesn''t keep Quest for Fire from offering a deeply resonant -- and surprisingly funny -- look at the beginning of the human race.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('quick change', 1990, 'Quick Change makes the most of its clever premise with a smartly skewed heist comedy that leaves plenty of room for its talented cast to shine.', TO_DATE('1990-07-13', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the quiet man', 2000, 'Director John Ford and star John Wayne depart the Western for the Irish countryside, and the result is a beautifully photographed, often comedic romance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('quills', 2000, 'Though hard to watch, this film''s disturbing exploration of freedom of expression is both seductive and thought-provoking.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('quinceañera', 2006, 'This slice-of-life story of a teenage girl in Echo Park is both a sweet crowd-pleaser and a perceptive look at socioeconomic community issues.', TO_DATE('2006-01-23', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('quincy', 2018, 'Quincy presents an undeniably entertaining overview of its subject''s remarkable life and career, albeit one that may leave some viewers wishing it had dug a little deeper.', TO_DATE('2018-09-10', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('quiz show', 1994, 'Robert Redford refracts the sociopolitical and moral issues posed by the subject material through a purely entertaining, well-acted lens.', TO_DATE('1994-09-14', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('r100', 2013, 'R100 definitely isn''t for everyone, but audiences open to writer-director Hitoshi Matsumoto''s fetish-driven thrills will find it a suitably perverse pleasure to watch.', TO_DATE('2013-09-12', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rabbit hole', 2010, 'It''s often painful to watch, but Rabbit Hole''s finely written script and convincing performances make it worth the effort.', TO_DATE('2010-09-15', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rabbitproof fence', 2002, 'Visually beautiful and well-acted, Rabbit-Proof Fence tells a compelling true-life story.', TO_DATE('2002-02-21', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('race', 2016, 'Race is nowhere near as thrillingly fleet or agile as its subject, but the story -- and a winning central performance from Stephan James -- are enough to carry it over the finish line.', TO_DATE('2016-02-17', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('race to witch mountain', 2009, 'Despite the best efforts of a talented cast, Race to Witch Mountain is a tepid reboot that lacks the magic of the original.', TO_DATE('2009-03-11', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rachel getting married', 2008, 'Rachel Getting Married is an engrossing tale of family angst, highlighted by Anne Hathaway''s powerful performance and director Jonathan Demme''s return to form.', TO_DATE('2008-09-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('racing dreams', 2010, 'Racing Dreams offers an absorbing peek at the lives of young NASCAR hopefuls that should resonate with racing enthusiasts as well as viewers with no connection to the sport.', TO_DATE('2010-04-02', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('racing stripes', 2004, 'Racing Stripes might be good for a few laps with younger viewers, but it''s too blandly predictable to truly recommend for an all-ages audience.', TO_DATE('2004-12-22', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('radio', 2003, 'The story is heavy on syrupy uplift and turns Radio into a saint/cuddly pet.', TO_DATE('2003-10-13', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('radio flyer', 2000, 'Overlaying its whimsical concept onto a gritty story of domestic abuse, Radio Flyer is a family film that is too harrowing for children and too saccharine for their parents.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rage carrie 2', 1999, 'As disposable as its predecessor is indispensable, The Rage: Carrie 2 mimics the arc of Stephen King''s classic story without adding anything of value.', TO_DATE('1999-03-12', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a rage in harlem', 2000, 'If it can''t quite live up to its source material, A Rage in Harlem still proves a stylishly effective period thriller.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('raging bull', 2000, 'Arguably Martin Scorsese''s and Robert De Niro''s finest film, Raging Bull is often painful to watch, but it''s a searing, powerful work about an unsympathetic hero.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('raiders of the lost ark', 1981, 'Featuring bravura set pieces, sly humor, and white-knuckle action, Raiders of the Lost Ark is one of the most consummately entertaining adventure pictures of all time.', TO_DATE('1981-06-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('raiders the story of the greatest fan film ever made', 2015, 'As fascinating as it is affecting, Raiders! offers an insightful look at fan culture while presenting a poignant portrait of friendship over the passage of time.', TO_DATE('2015-03-19', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('railroad tigers', 2016, 'Railroad Tigers throws a few sparks hearkening back to Jackie Chan''s glory days as an action comedy star, but they''re smothered by an unfocused story and jarring shifts in tone.', TO_DATE('2016-12-28', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rain man', 2000, 'This road-trip movie about an autistic savant and his callow brother is far from seamless, but Barry Levinson''s direction is impressive, and strong performances from Tom Cruise and Dustin Hoffman add to its appeal.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('raise your voice', 2004, 'A bland, formulaic tween version of Fame.', TO_DATE('2004-10-05', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('raising arizona', 1987, 'A terrifically original, eccentric screwball comedy, Raising Arizona may not be the Coens'' most disciplined movie, but it''s one of their most purely entertaining.', TO_DATE('1987-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('raising cain', 1992, 'Raising Cain doesn''t rank with Brian De Palma''s best work, but John Lithgow''s spellbinding split-personality performance makes this thriller hard to dismiss.', TO_DATE('1992-08-07', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('raising helen', 2004, 'As shallow and formulaic as a sitcom.', TO_DATE('2004-04-24', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('raising victor vargas', 2002, 'A coming-of-age tale marked by its authenticity.', TO_DATE('2002-09-18', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ralph breaks the internet', 2018, 'Ralph Breaks the Internet levels up on its predecessor with a funny, heartwarming sequel that expands its colorful universe while focusing on core characters and relationships.', TO_DATE('2018-11-14', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rambling rose', 1991, 'A touching. bittersweet, and wonderfully-acted film.', TO_DATE('1991-09-10', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rambo first blood part ii', 2000, 'First Blood Part II offers enough mayhem to satisfy genre fans, but remains a regressive sequel that turns its once-compelling protagonist into just another muscled action berserker.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rambo iii', 2000, 'Rambo III finds its justice-dispensing hero far from the thoughtful drama that marked the franchise''s beginning -- and just as far from quality action thriller entertainment.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rambo last blood', 2019, 'Like the sequels that preceded it, Rambo: Last Blood is content to indulge in bloody violence at the expense of its main character''s once-poignant story.', TO_DATE('2019-09-17', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ramona and beezus', 2010, 'If Ramona and Beezus fails to capture the essence of its classic source material, it''s sunny, sweet, and wholesome.', TO_DATE('2010-07-19', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rampage', 2018, 'Rampage isn''t as fun as its source material, but the movie''s sheer button-mashing abandon might satisfy audiences in the mood for a brainless blockbuster.', TO_DATE('2018-04-11', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rampart', 2011, 'Rampart sends viewers plummeting into a nihilistic hell of its protagonist''s creation, yet Woody Harrelson''s performance in the central role is too magnetic to dismiss.', TO_DATE('2011-09-15', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ran', 2000, 'Akira Kurosawa''s sprawling, epic take on King Lear should be required viewing for fans of westerns, war movies, or period films in general.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('random hearts', 2000, 'Even Harrison Ford could not save the dull plot and the slow pacing of the movie.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rango', 2011, 'Rango is a smart, giddily creative burst of beautifully animated entertainment, and Johnny Depp gives a colorful vocal performance as a household pet in an unfamiliar world.', TO_DATE('2011-02-27', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rare exports a christmas tale', 2010, 'Rare Exports is an unexpectedly delightful crossbreed of deadpan comedy and Christmas horror.', TO_DATE('2010-10-23', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rashômon', 1951, 'One of legendary director Akira Kurosawa''s most acclaimed films, Rashomon features an innovative narrative structure, brilliant acting, and a thoughtful exploration of reality versus perception.', TO_DATE('1951-12-26', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rat race', 2001, 'Rat Race moves from one sight gag to another, but only a handful of them are genuinely funny.', TO_DATE('2001-01-01', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ratatouille', 2007, 'Fast-paced and stunningly animated, Ratatouille adds another delightfully entertaining entry -- and a rather unlikely hero -- to the Pixar canon.', TO_DATE('2007-06-16', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ratchet clank', 2016, 'Ratchet & Clank may satisfy very young viewers, but compared to the many superior options available to families and animation enthusiasts, it offers little to truly recommend.', TO_DATE('2016-04-25', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rattlesnake', 2019, 'Carmen Ejogo is stranded in a wasteland both figuratively and literally in this disposable thriller, which lacks the cleverness or specificity to give its thin conceit any bite.', TO_DATE('2019-10-25', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ravenous', 1999, 'Ravenous tries bringing cannibal horror into an Old West setting, ending up with an uneven blend that will fail to satisfy most fans of either genre.', TO_DATE('1999-03-19', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ravenous les affamés', 2017, 'Uncommonly restrained for a movie about a flesh-eating menace, Ravenous offers a satisfyingly nuanced entry in the crowded zombie apocalypse subgenre.', TO_DATE('2017-09-13', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('raw', 2016, 'Raw''s lurid violence and sexuality live up to its title, but they''re anchored with an immersive atmosphere and deep symbolism that linger long after the provocative visuals fade.', TO_DATE('2016-05-15', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ray', 2004, 'An engrossing and energetic portrait of a great musician''s achievements and foibles, Ray is anchored by Jamie Foxx''s stunning performance as Ray Charles.', TO_DATE('2004-09-29', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rbg', 2018, 'RBG might be preaching to the choir of viewers who admire Supreme Court Justice Ruth Bader Ginsberg, but it does so effectively.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reach me', 2014, 'Featuring a bewildering array of talented actors pummeled by disjointed direction and a dull, hackneyed script, Reach Me is so fundamentally misbegotten that its title reads more like a threat.', TO_DATE('2014-11-17', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the reader', 2008, 'Despite Kate Winslet''s superb portrayal, The Reader suggests an emotionally distant, Oscar-baiting historical drama.', TO_DATE('2008-11-30', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ready or not', 2019, 'Smart, subversive, and darkly funny, Ready or Not is a crowd-pleasing horror film with giddily entertaining bite.', TO_DATE('2019-07-28', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ready player one', 2018, 'Ready Player One is a sweetly nostalgic thrill ride that neatly encapsulates Spielberg''s strengths while adding another solidly engrossing adventure to his filmography.', TO_DATE('2018-03-12', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ready to rumble', 2000, 'Humor at its lowest that isn''t funny for kids and is insulting to adults.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('real genius', 2000, 'It follows college tropes, but Real Genius has an optimistic streak that puts you on Val Kilmer''s side all the way.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('real steel', 2010, 'Silly premise notwithstanding, this is a well-made Hollywood movie: Thrilling and exciting action with just enough characterization.', TO_DATE('2010-06-15', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('real women have curves', 2002, 'Real Women Have Curves, physical as well as emotional -- and this coming-of-age story traces them in a vividly warm-hearted look at the Mexican-American experience.', TO_DATE('2002-04-08', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reality', 2012, 'Part dark satire, part compelling drama, Reality occasionally struggles to communicate its message, but it''s never less than entertaining.', TO_DATE('2012-05-18', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reality bites', 2000, 'Reality Bites may be too slick to fulfill its promise as a profound statement on Generation X, but an appealing ensemble and romantic sizzle make for an entertaining dive into the ennui of youth.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reanimator', 2000, 'Perfectly mixing humor and horror, the only thing more effective than Re-Animator''s gory scares are its dry, deadpan jokes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the reaping', 2007, 'It may feature such accomplished actors as Hilary Swank and Stephen Rea, but The Reaping also boasts the apropos tagline "What hath God wrought?" It''s schlocky, spiritually shallow, and scare-free.', TO_DATE('2007-03-31', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rebel in the rye', 2017, 'Rebel in the Rye attempts to dramatize J.D. Salinger''s life and creative process, but falters with a lack of dramatic impetus or a cohesive thesis about the reclusive author.', TO_DATE('2017-01-25', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rebel without a cause', 2000, 'Rebel Without a Cause is a searing melodrama featuring keen insight into ''50s juvenile attitude and James Dean''s cool, iconic performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rebels of the neon god', 2003, 'Rebels of the Neon God announces writer-director Ming-liang Tsai as a fully formed talent -- and remains one of the more accomplished debuts of the decade.', TO_DATE('2003-03-07', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rebound', 2005, 'Rebound ought to entertain its target audience, but there''s nothing here for those who''ve seen The Bad News Bears or its countless derivatives.', TO_DATE('2005-06-29', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rebuilding paradise', 2020, 'From the horror of natural disaster to the spirit summoned behind the titular effort, Rebuilding Paradise stirringly depicts one community''s perseverance.', TO_DATE('2020-01-28', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rec 2', 2009, 'It lacks the surprising jolt of the first installment, but [REC] 2 almost maintains the original''s chilling momentum -- and proves not all horror sequels were made equal.', TO_DATE('2009-09-03', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rec 3 genesis', 2012, '[REC] 3 Genesis discards the handheld POV of its predecessors and loses the franchise''s fresh perspective in the bargain, upping the gags and gore to the detriment of the chills that audiences crave.', TO_DATE('2012-07-19', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rec 4 apocalypse', 2014, 'After a lackluster third entry, [REC] 4 gets the series back on track, at least to the level of the first sequel.', TO_DATE('2014-10-05', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('recess schools out', 2000, 'Though basically a TV cartoon stretched out to movie-length, Recess has enough successful jokes and smart writing to make it a worthwhile view.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the recruit', 2003, 'This polished thriller is engaging until it takes one twist too many into the predictable.', TO_DATE('2003-01-16', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red', 2010, 'It may not be the killer thrill ride you''d expect from an action movie with a cast of this caliber, but Red still thoroughly outshines most of its big-budget counterparts with its wit and style.', TO_DATE('2010-09-28', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red tails', 2012, 'Despite a worthy fact-based story and obvious good intentions, Red Tails suffers from one-dimensional characters, corny dialogue, and heaps of clichés.', TO_DATE('2012-01-17', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red 2', 2013, 'While it''s still hard to argue with its impeccable cast or the fun they often seem to be having, Red 2 replaces much of the goofy fun of its predecessor with empty, over-the-top bombast.', TO_DATE('2013-07-15', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red army', 2014, 'Fun and fascinating, Red Army delivers absorbing documentary drama for hockey fans and sports novices alike.', TO_DATE('2014-05-25', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red dawn', 2012, 'The rebooted Red Dawn lacks the original''s topicality, but at least pays tribute in delivering the same short shrift to character development and general logic.', TO_DATE('2012-09-27', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red dragon', 2002, 'Competently made, but everything is a bit too familiar.', TO_DATE('2002-07-27', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red hill', 2010, 'Though its attempts to rework genre conventions may fall flat with some, Red Hill is a beautifully shot, tightly paced thriller that marks a strong debut for director Patrick Hughes.', TO_DATE('2010-08-09', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red hook summer', 2012, 'Red Hook Summer is just as bold and energetic as Spike Lee''s best work, but its story is undermined by a jarring plot twist in the final act.', TO_DATE('2012-01-23', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red joan', 2018, 'A fascinating real-life story dramatized in perplexingly dull fashion, Red Joan wastes its tale''s incredible intrigue -- as well as the formidable talents of Judi Dench.', TO_DATE('2018-09-08', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red lights', 2004, 'Red Lights is a taut, character-driven thriller, set against the debris-strewn battleground of a failing marriage.', TO_DATE('2004-06-13', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red lights', 2012, 'Wasting the talents of an impressive cast on a predictable mystery, Red Lights lacks the clairvoyance to know what audiences want.', TO_DATE('2012-01-21', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red penguins', 2019, 'Sports and politics collide in Red Penguins, a fascinating documentary exploring the stranger-than-fiction story of professional hockey in post-Soviet Russia.', TO_DATE('2019-09-06', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red planet', 2000, 'While the special effects are impressive, the movie suffers from a lack of energy and interesting characters.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red road', 2006, 'Red Road director Andrea Arnold skillfully parses out just enough plot details at a time to keep the audience engrossed in this seductive thriller.', TO_DATE('2006-05-20', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red rock west', 2000, 'Red Rock West is a hidden neo-noir gem with some delightful cracks in its surface -- and an opportunity to see Lara Flynn Boyle, Nicolas Cage, Dennis Hopper, and J.T. Walsh go toe-to-toe in all their early ''90s glory.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red sparrow', 2018, 'Red Sparrow aims for smart, sexy spy thriller territory, but Jennifer Lawrence''s committed performance isn''t enough to compensate for thin characters and a convoluted story.', TO_DATE('2018-02-16', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('red state', 2011, 'Red State is an audacious and brash affair that ultimately fails to provide competent scares or thrills.', TO_DATE('2011-01-23', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('redacted', 2007, 'Despite DePalma''s obvious commitment to the material and passion for the issues at hand, Redacted suffers from stereotypical characters and a forced faux-doc style.', TO_DATE('2007-09-01', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('redbelt', 2008, 'Mamet''s mixed marital arts morality play weaves between action and intellect but doesn''t always hit its target.', TO_DATE('2008-04-02', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('redline', 2007, 'Redline has plenty of bad acting, laughable dialogue, and luxury cars.', TO_DATE('2007-04-13', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reds', 2002, 'Brawny in both intellect and scope, Reds is an intimate epic that captures the tumult of revolutionary change and the passion of those navigating through it.', TO_DATE('2002-08-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('im reed fish', 2006, 'Painless if largely unmemorable, I''m Reed Fish fails to distinguish itself from countless other small-town comedies populated by amiably quirky characters.', TO_DATE('2006-06-15', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reel paradise', 2005, 'The travails of the Piersons as they try to adjust to a radically different culture while introducing American cinema to it makes for amusing viewing.', TO_DATE('2005-04-29', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ref', 2000, 'Undeniably uneven and too dark for some, The Ref nonetheless boasts strong turns from Denis Leary, Judy Davis, and Kevin Spacey, as well as a sharply funny script.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('regarding henry', 1991, 'Although Harrison Ford makes the most of an opportunity to dig into a serious role, Regarding Henry is undermined by cheap sentiment and clichés.', TO_DATE('1991-07-10', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('regression', 2015, 'Regression boasts a pair of eminently likable leads -- neither of whom are able to dislodge the movie from the mire of psychological thriller mediocrity.', TO_DATE('2015-09-19', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reign of fire', 2002, 'Reign of Fire gains some altitude with its pyrotechnic action and a smolderingly campy Matthew McConaughey, but the feature''s wings are clipped by a derivative script and visual effects that fizzle out.', TO_DATE('2002-07-09', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reign over me', 2007, 'Reign Over Me is a charming, affecting tale of friendship and loss, with solid performances from Adam Sandler as a broken, grief-stricken man and Don Cheadle as his old friend and savior.', TO_DATE('2007-03-16', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reindeer games deception', 2000, 'Despite a decent cast, subpar acting and a contrived plot disappointed reviewers.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('relic', 2020, 'Relic ratchets up its slowly building tension in an expertly crafted atmosphere of dread, adding up to an outstanding feature debut for director/co-writer Natalie Erika James.', TO_DATE('2020-01-26', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('religulous', 2008, 'Religulous is funny and offensive in equal measure, and aims less to change hearts and minds than to inspire conversation.', TO_DATE('2008-08-19', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the remains of the day', 2000, 'Smart, elegant, and blessed with impeccable performances from Anthony Hopkins and Emma Thompson, The Remains of the Day is a Merchant-Ivory classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('remember', 2015, 'Remember risks wandering into exploitative territory, but it''s bolstered by some of Egoyan''s best latter-day directing and a typically stellar performance from Christopher Plummer.', TO_DATE('2015-08-30', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('remember the titans', 2000, 'An inspirational crowd-pleaser with a healthy dose of social commentary, Remember the Titans may be predictable, but it''s also well-crafted and features terrific performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rememory', 2017, 'Rememory has some intriguing themes and a compelling cast to work with, but they''re lost in the fog of a forgettable melodrama.', TO_DATE('2017-01-26', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('renaissance', 2006, 'Renaissance attempts to blend sci-fi wonder with stark noir animation, but is often more fun to look at than to watch.', TO_DATE('2006-06-24', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('renaissance man', 1994, 'Renaissance Man tries to simultaneously be a literary comedy, an inspirational drama, and a star vehicle that caters to Danny DeVito''s strengths, but proves to be a master of none.', TO_DATE('1994-06-03', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rendition', 2007, 'The impressive cast cannot rescue Rendition, which explores complex issues in woefully simplified terms.', TO_DATE('2007-09-06', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reno 911 miami', 2007, 'Reno 911!''s anarchic brand of comedy loses much in translation to the big screen where it feels slapdash and shallow.', TO_DATE('2007-02-20', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('renoir', 2012, 'Appropriately enough, Renoir offers viewers a drama of sumptuous beauty -- which is more than enough to offset its frustratingly slow pace and rather thinly written screenplay.', TO_DATE('2012-05-31', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rentapal', 2020, 'Rent-A-Pal suffers from untapped thematic potential, but Wil Wheaton''s unsettling performance makes this unique horror story worth watching.', TO_DATE('2020-09-07', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the replacements', 2000, 'The cliched characters and obvious outcome make all the fun and excitement amount to nothing.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('replicas', 2018, 'Equal parts plot holes and unintentional laughs, Replicas is a ponderously lame sci-fi outing that isn''t even bad enough to be so bad it''s good.', TO_DATE('2018-10-26', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('repo man', 1984, 'Repo Man is many things: an alien-invasion film, a punk-rock musical, a send-up of consumerism. One thing it isn''t is boring.', TO_DATE('1984-03-02', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('repo the genetic opera', 2008, 'Bombastic and intentionally gross, Repo! The Genetic Opera has a unique style but lacks the wit and substance to be involving.', TO_DATE('2008-04-09', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('repulsion', 1965, 'Roman Polanski''s first English film follows a schizophrenic woman''s descent into madness, and makes the audience feel as claustrophobic as the character.', TO_DATE('1965-10-02', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('requiem for a dream', 2000, 'Though the movie may be too intense for some to stomach, the wonderful performances and the bleak imagery are hard to forget.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rescue dawn', 2006, 'Director Werner Herzog has once again made a compelling tale of man versus nature, and Christian Bale completely immerses himself in the role of fighter pilot (and prisoner of war) Dieter Dengler.', TO_DATE('2006-09-12', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rescuers down under', 1990, 'Though its story is second-rate, The Rescuers Down Under redeems itself with some remarkable production values -- particularly its flight scenes.', TO_DATE('1990-11-16', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reservation road', 2007, 'While the performances are fine, Reservation Road quickly adopts an excessively maudlin tone along with highly improbable plot turns.', TO_DATE('2007-09-07', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reservoir dogs', 2000, 'Thrumming with intelligence and energy, Reservoir Dogs opens Quentin Tarantino''s filmmaking career with hard-hitting style.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('resident evil', 2002, 'Like other video game adapations, Resident Evil is loud, violent, formulaic, and cheesy.', TO_DATE('2002-03-07', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('resident evil afterlife', 2010, 'As dim-witted and lifeless as its undead antagonists, Resident Evil: Afterlife is a wholly unnecessary addition to the franchise.', TO_DATE('2010-09-09', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('resident evil apocalypse', 2004, 'Resident Evil: Apocalypse has lots of action, but not much in terms of plot or creativity.', TO_DATE('2004-09-09', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('resident evil extinction', 2007, 'Resident Evil: Extinction is more of the same; its few impressive action sequences unable to compensate for the pedestrian plot.', TO_DATE('2007-09-18', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('resident evil retribution', 2012, 'Resident Evil: Retribution offers everything one might reasonably expect from the fifth installment in a heavily action-dependent franchise -- which means very little beyond stylishly hollow CGI-enhanced set pieces.', TO_DATE('2012-09-13', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('resident evil the final chapter', 2017, 'Resident Evil: The Final Chapter may prove mind-numbingly chaotic for the unconverted, but for fans of the venerable franchise, it offers a fittingly kinetic conclusion to its violent post-apocalyptic saga.', TO_DATE('2017-01-24', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('resistance', 2020, 'Flawed yet honorable, Resistance pushes past uneven performances and execution to pay sincere tribute to its real-life protagonist.', TO_DATE('2020-03-09', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('breathe', 2014, 'Breathe finds writer-director Mélanie Laurent opening a sensitive, well-acted window into the bittersweet upheaval of adolescence.', TO_DATE('2014-05-22', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('restless', 2011, 'Mia Wasikowska puts in a nuanced performance but nobody else, actors and directors included, are capable of finding a compelling angle beneath the twee veneer.', TO_DATE('2011-05-12', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('restrepo', 2010, 'Forsaking narrative structure for pure visceral power, Restrepo plunges viewers into the experiences of soldiers on the front lines of the Afghan War.', TO_DATE('2010-02-06', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('results', 2015, 'Results moves stubbornly at its own deliberate pace, but the well-chosen cast -- and writer-director Andrew Bujalski''s insightful observations -- offer rich rewards for patient viewers.', TO_DATE('2015-02-13', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('resurrecting the champ', 2007, 'While sluggish in spots, Resurrecting the Champ is a sports/newsroom drama elevated by high-caliber performances by Samuel Jackson, Josh Hartnet, and Alan Alda.', TO_DATE('2007-01-22', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the return', 2006, 'Unoriginality may be an acceptable risk in the Horror genre, but boredom is never okay.', TO_DATE('2006-11-10', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('return', 2011, 'Powered by a compelling central performance by Linda Cardellini, Return offers a painfully compelling look at the emotional struggles faced by war veterans.', TO_DATE('2011-08-11', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the return of the living dead', 2000, 'A punk take on the zombie genre, Return of the Living Dead injects a healthy dose of ''80s silliness to the flesh consuming.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('return to me', 2000, 'David Duchovny and Minnie Driver provide heart-warming romance and comedy in this solid debut by Director Bonnie Hunt.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('return to never land', 2002, 'With its forgettable songs and lackluster story, this new Pan will surely entertain kids, but will feel more like a retread to adults.', TO_DATE('2002-02-09', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('return to the blue lagoon', 2000, 'Despite its lush tropical scenery and attractive leads, Return to the Blue Lagoon is as ridiculous as its predecessor, and lacks the prurience and unintentional laughs that might make it a guilty pleasure.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('revenge', 2017, 'Revenge slices and dices genre tropes, working within an exploitation framework while adding a timely -- yet never less than viscerally thrilling -- feminist spin.', TO_DATE('2017-09-16', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('revenge of the nerds ii nerds in paradise', 2000, 'It reunites most of the original cast and rounds them up for a trip to Fort Lauderdale for spring break, but Revenge of the Nerds II: Nerds in Paradise forgets to pack enough jokes or compelling characters to make it through its 89-minute running time.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reverb', 2009, 'Badly written and directed, this poorly executed British horror suffers a glaring lack of scares and comprehensibility.', TO_DATE('2009-03-02', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('reversal of fortune', 1990, 'Featuring exceptional performances and a cunning script, Reversal of Fortune doubles as a tantalizing mystery and ruthless satire of the rich.', TO_DATE('1990-10-17', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('revolutionary road', 2008, 'Brilliantly acted and emotionally powerful, Revolutionary Road is a handsome adaptation of Richard Yates'' celebrated novel.', TO_DATE('2008-11-18', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('revolver', 2005, 'In attempting to meld his successful previous formulas with philosophical musings, Guy Ritchie has produced an incoherent misfire.', TO_DATE('2005-09-10', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rewind', 2019, 'Rewind pulls at the roots of a family''s horrific trauma with a deeply personal documentary that''s hard to watch, but worth the effort.', TO_DATE('2019-04-28', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rewind this', 2013, 'An ode to abandoned technology with some admirably wide-ranging insights, Rewind This! is entertaining viewing even for those who didn''t live through the VHS era.', TO_DATE('2013-06-16', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rich hill', 2014, 'As compassionate as it is infuriating, Rich Hill offers a sobering glimpse of American poverty.', TO_DATE('2014-01-27', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('richard jewell', 2019, 'Richard Jewell simplifies the real-life events that inspired it -- yet still proves that Clint Eastwood remains a skilled filmmaker of admirable economy.', TO_DATE('2019-11-21', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('richie rich', 2000, 'With Macaulay Culkin barely registering any emotion, Richie Rich feels disjointed and free of a sense of fun and wonderment.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ricki and the flash', 2015, 'Meryl Streep''s outstanding work helps Ricki and the Flash overcome its inconsistent tone and fairly predictable premise.', TO_DATE('2015-08-03', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ricky gervais humanity', 2018, 'Ricky Gervais returns to the stage with his characteristic wit and distinct edginess, but the performance verges on cruel when his mockery seemingly overtakes his own Humanity.', TO_DATE('2018-03-13', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('riddick', 2013, 'It may not win the franchise many new converts, but this back-to-basics outing brings Riddick fans more of the brooding sci-fi action they''ve come to expect.', TO_DATE('2013-08-31', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ride along 2', 2016, 'Ride Along 2 presents a cop-comedy sequel whose well-matched stars can''t break the law of diminishing returns -- or lock up a script that unabashedly steals from the original.', TO_DATE('2016-01-12', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ride along', 2014, 'Kevin Hart''s livewire presence gives Ride Along a shot of necessary energy, but it isn''t enough to rescue this would-be comedy from the buddy-cop doldrums.', TO_DATE('2014-01-14', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ride with the devil', 1999, 'A well-acted, eccentric Civil War film, Ang Lee''s Ride With the Devil is often more visually striking than it is emotionally engaging.', TO_DATE('1999-11-24', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('riding the bullet', 2004, 'Stephen King adaptation veteran director Mick Garris has lofty storytelling goals which ultimately flail and undercut the story''s terror.', TO_DATE('2004-08-10', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('riding alone for thousands of miles', 2006, 'Doesn''t reach the heights of Zhang Yimou''s best, but this is still a heartwarming tale of love and forgiveness from the acclaimed Chinese director.', TO_DATE('2006-06-15', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('riding giants', 2004, 'A great addition to the existing surfing documentaries.', TO_DATE('2004-03-04', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('riding in cars with boys', 2001, 'Riding in Cars With Boys suffers from mixing grit and pathos with cuteness and comedy. Ironically, many critics found Zahn''s character more compelling and three-dimensional than Barrymore''s.', TO_DATE('2001-10-15', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('right at your door', 2006, 'Though Right at Your Door dips into melodrama at the end, it''s an otherwise tense, effective, and eerily plausible doomsday scenario.', TO_DATE('2006-01-24', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('righteous kill', 2008, 'Al Pacino and Robert De Niro do their best to elevate this dowdy genre exercise, but even these two greats can''t resuscitate the film''s hackneyed script.', TO_DATE('2008-09-10', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rim of the world', 2019, 'Rim of the World is too bland to live up to the 80s teen adventures it references, and too full of clichés to be able to set itself apart from them.', TO_DATE('2019-05-24', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ring', 2002, 'With little gore and a lot of creepy visuals, The Ring gets under your skin, thanks to director Gore Verbinski''s haunting sense of atmosphere and an impassioned performance from Naomi Watts.', TO_DATE('2002-07-28', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ring two', 2005, 'Ring Two serves up horror cliches, and not even Hideo Nakata, the director of the movies from which this one is based, can save the movie from a dull screenplay full of absurdities.', TO_DATE('2005-03-07', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ringmaster', 1998, 'A crude, idiotic mess of a film.', TO_DATE('1998-11-25', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rings', 2017, 'Rings may offer ardent fans of the franchise a few threadbare thrills, but for everyone else, it may feel like an endless loop of muddled mythology and rehashed plot points.', TO_DATE('2017-02-02', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ringu ring', 2002, 'Ringu combines supernatural elements with anxieties about modern technology in a truly frightening and unnerving way.', TO_DATE('2002-05-17', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rio', 2011, 'This straightforward movie reaches great heights thanks to its colorful visual palette, catchy music, and funny vocal performances.', TO_DATE('2011-03-29', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rio 2', 2014, 'Like most sequels, Rio 2 takes its predecessor''s basic template and tries to make it bigger -- which means it''s even busier, more colorful, and ultimately more exhausting for viewers outside the youthful target demographic.', TO_DATE('2014-03-27', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rio bravo', 2000, 'Rio Bravo finds director Howard Hawks -- and his stellar ensemble cast -- working at peak performance, and the end result is a towering classic of the Western genre.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rio lobo', 2000, 'Howard Hawks and John Wayne reunite to riff on their own Rio Bravo, and while the results are less memorable the movie does offer a curiously cynical perspective.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ripd', 2013, 'It has its moments -- most of them courtesy of Jeff Bridges'' rootin'' tootin'' performance as an undead Wild West sheriff -- but R.I.P.D. is ultimately too dim-witted and formulaic to satisfy.', TO_DATE('2013-07-18', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ripleys game', 2002, 'Led by a suitably slimy performance from John Malkovich, Ripley''s Game brings Patricia Highsmith''s bestselling sociopath brilliantly to life.', TO_DATE('2002-09-04', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rise of the guardians', 2012, 'A sort of Avengers for the elementary school set, Rise of the Guardians is wonderfully animated and briskly paced, but it''s only so-so in the storytelling department.', TO_DATE('2012-10-11', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rise of the planet of the apes', 2011, 'Led by Rupert Wyatt''s stylish direction, some impressive special effects, and a mesmerizing performance by Andy Serkis, Rise of the Planet of the Apes breathes unlikely new life into a long-running franchise.', TO_DATE('2011-07-31', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('risen', 2016, 'Risen benefits from a lighter tone than many faith-based productions, as well as a unique take on the Greatest Story Ever Told and a terrific turn from star Joseph Fiennes.', TO_DATE('2016-02-15', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a river runs through it', 1992, 'Tasteful to a fault, this period drama combines a talented cast (including a young Brad Pitt) with some stately, beautifully filmed work from director Robert Redford.', TO_DATE('1992-10-09', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rivers and tides andy goldsworthy working with time', 2002, 'Andy Goldsworthy and his art are beautifully captured in this engaging documentary.', TO_DATE('2002-08-06', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rivers edge', 2000, 'A harrowing tale of aimless youth, River''s Edge generates considerable tension and urgency thanks to strong performances from a stellar cast that includes Crispin Glover, Keanu Reeves, and Ione Skye.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rize', 2005, 'The dances in Rize are electric even if the documentary doesn''t go that deeply into the performers'' lives.', TO_DATE('2005-04-30', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the road to el dorado', 2000, 'Predictable story and thin characters made the movie flat.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the road to guantanamo', 2006, 'A gut-wrenching and riveting docu-drama that serves as a stinging indictment of U.S. military justice in an era of ever-increasing scrutiny.', TO_DATE('2006-04-18', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('road to perdition', 2002, 'Somber, stately, and beautifully mounted, Sam Mendes'' Road to Perdition is a well-crafted mob movie that explores the ties between fathers and sons.', TO_DATE('2002-06-21', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('roar', 2012, 'Roar may not satisfy in terms of acting, storytelling, or overall production, but the real-life danger onscreen makes it difficult to turn away.', TO_DATE('2012-02-23', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rob the mob', 2014, 'Bolstered by a pair of likable leads and suffused in a warmly nostalgic glow, Rob the Mob is an uneven crime caper that mostly works.', TO_DATE('2014-03-15', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('robert the bruce', 2019, 'It''s inspired by epic real-life events, but rich cinematography and the best of intentions aren''t enough to carry Robert the Bruce past its leaden pace and bland storytelling.', TO_DATE('2019-06-24', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('robin and marian', 2000, 'Robin and Marian gives the legendary characters a somber sendoff, finding ample success in the romantic chemistry between Sean Connery and Audrey Hepburn while yielding diminishing returns in its attempts at relevant satire.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('robin hood', 2010, 'Ridley Scott''s revisionist take on this oft-told tale offers some fine acting and a few gripping action sequences, but it''s missing the thrill of adventure that made Robin Hood a legend in the first place.', TO_DATE('2010-05-10', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('robin hood', 2018, 'Robin Hood robs from rich source material, but is ultimately just another poor attempt to needlessly gussy up a classic tale with amped-up action and modern special effects.', TO_DATE('2018-11-20', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('robin hood men in tights', 2000, 'Undisciplined, scatological, profoundly silly, and often utterly groan-worthy, Robin Hood: Men in Tights still has an amiable, anything-goes goofiness that has made it a cult favorite.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('robin hood prince of thieves', 2000, 'Robin Hood: Prince of Thieves brings a wonderfully villainous Alan Rickman to this oft-adapted tale, but he''s robbed by big-budget bombast and a muddled screenplay.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('robocop 2', 2000, 'A less satisfying rehash that generally lives down to the negative stereotype of sequels, RoboCop 2 tries to deliver more of everything and ends up with less.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('robocop 3', 2000, 'This asinine sequel should be placed under arrest.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('robot frank', 2012, 'Led by a brilliant performance from star Frank Langella, Robot & Frank works as both a quirky indie drama and as a smart, thoughtful meditation on aging.', TO_DATE('2012-01-22', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('robot stories', 2004, 'Although its four stories vary in quality, Robot Stories is still worth a look for Twilight Zone fans.', TO_DATE('2004-01-10', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('robots', 2005, 'Robots delights on a visual level, but the story feels like it came off an assembly line.', TO_DATE('2005-03-05', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rock dog', 2017, 'Rock Dog is amiable enough, but its second-tier animation and uninspired story add up to a movie whose meager charms are likely to escape all but the youngest and least demanding viewers.', TO_DATE('2017-02-21', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rock of ages', 2012, 'Its exuberant silliness is almost enough to make up for its utter inconsequentiality, but Rock of Ages is ultimately too bland and overlong to justify its trip to the big screen.', TO_DATE('2012-06-10', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rock star', 2001, 'Like its title, Rock Star is rather generic, being not so much about the heavy metal scene than about rock cliches and formula.', TO_DATE('2001-08-21', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rock the kasbah', 2015, 'The Shareef don''t like Rock the Kasbah, and neither will viewers hoping for a film that manages to make effective use of Bill Murray''s knack for playing lovably anarchic losers.', TO_DATE('2015-10-20', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rocket science', 2007, 'Though Rocket Science appears to be a typically quirky indie, the well-rounded performances and director Jeffrey Blitz''s clear affection for his characters gives the film its proper human spark.', TO_DATE('2007-01-21', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rocketeer', 2000, 'An action-packed, if anachronistic, look back at pulp matinee serials, The Rocketeer may ring hollow with viewers expecting more than simple fun and gee-whiz special effects.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rocketman', 2019, 'It''s going to be a long, long time before a rock biopic manages to capture the highs and lows of an artist''s life like Rocketman.', TO_DATE('2019-05-16', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rocknrolla', 2008, 'Mixed reviews for Guy Ritchie''s return to his London-based cockney wideboy gangster movie roots, but most agree, it''s a step in the right direction following two major turkeys.', TO_DATE('2008-09-04', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rockos modern life static cling', 2019, 'Pleasantly strange and surprisingly thoughtful, Rocko''s Modern Life: Static Cling succeeds as both a nostalgic look back and a healthy hop forward.', TO_DATE('2019-08-07', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rocky balboa', 2006, 'Implausible but entertaining and poignant, Rocky Balboa finds the champ in fighting form for the first time in years.', TO_DATE('2006-12-13', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rocky horror picture show', 2000, 'Rocky Horror Picture Show brings its quirky characters in tight, but it''s the narrative thrust that really drives audiences insane and keeps ''em doing the time warp again.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rocky ii', 2001, 'Rocky II is a movie that dares you to root again for the ultimate underdog -- and succeeds due to an infectiously powerful climax.', TO_DATE('2001-04-17', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rocky iii', 2001, 'It''s noticeably subject to the law of diminishing returns, but Rocky III still has enough brawny spectacle to stand in the ring with the franchise''s better entries.', TO_DATE('2001-04-17', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rocky iv', 2000, 'Rocky IV inflates the action to absurd heights, but it ultimately rings hollow thanks to a story that hits the same basic beats as the first three entries in the franchise.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rocky v', 1990, 'Rocky V''s attempts to recapture the original''s working-class grit are as transparently phony as each of the thuddingly obvious plot developments in a misguided installment that sent the franchise flailing into longterm limbo.', TO_DATE('1990-11-16', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rodents of unusual size', 2017, 'Rodents of Unusual Size approaches a variety of timely and thought-provoking subjects from fresh angles -- and a lot of surprisingly large creatures in the bargain.', TO_DATE('2017-11-08', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rodin', 2017, 'Rodin falls prey to the most common pitfall of artist biopics: depicting creative work without ever really unlocking what it means or why it''s important.', TO_DATE('2017-05-23', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('roger dodger', 2002, 'The movie could have benefited from a more experienced director, but a great cast and script overcome any first time jitters the director may have had.', TO_DATE('2002-08-21', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rogue one a star wars story', 2016, 'Rogue One draws deep on Star Wars mythology while breaking new narrative and aesthetic ground -- and suggesting a bright blockbuster future for the franchise.', TO_DATE('2016-12-13', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('role models', 2008, 'Role Models is a frequently crude, always funny comedy with the cast providing solid work throughout.', TO_DATE('2008-10-20', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('roll bounce', 2005, 'Roll Bounce dazzles us with a classic late 1970''s feel, but this coming of age film could have been more than just a spin around the roller rink.', TO_DATE('2005-09-16', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rollerball', 2000, 'In Rollerball, social commentary collides with high-speed action -- and the audience is the winner.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rollerball', 2002, 'Removing the social critique of the original, this updated version of Rollerball is violent, confusing, and choppy. Klein makes for a bland hero.', TO_DATE('2002-02-03', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rolling thunder revue a bob dylan story by martin scorsese', 2019, 'Rolling Thunder Revue: A Bob Dylan Story by Martin Scorsese lives up to its unwieldy title with a delightfully unorthodox look at a pivotal period in its subject''s career.', TO_DATE('2019-06-11', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('roma', 2018, 'Roma finds writer-director Alfonso Cuarón in complete, enthralling command of his visual craft - and telling the most powerfully personal story of his career.', TO_DATE('2018-08-30', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('roman de gare', 2007, 'Claude Lelouch has crafted an engaging thriller about murder and romance with plenty of stylistic panache.', TO_DATE('2007-05-24', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('roman holiday', 1953, 'With Audrey Hepburn luminous in her American debut, Roman Holiday is as funny as it is beautiful, and sets the standard for the modern romantic comedy.', TO_DATE('1953-09-02', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('roman j israel esq', 2017, 'Intriguing yet heavy-handed, Roman J. Israel, Esq. makes the most of -- but never quite lives up to -- Denzel Washington''s magnetic performance in the title role.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('roman polanski wanted and desired', 2008, 'A courtroom drama and an exploration of celebrity and responsibility.', TO_DATE('2008-02-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('romance cigarettes', 2005, 'This movie musical aims for fun and modern, but Romance and Cigarettes is too scattered and uneven to achieve either.', TO_DATE('2005-09-06', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('romancing the stone', 2000, 'Romancing the Stone reaches back to the classic Saturday morning serials of old with an action-filled adventure enlivened by the sparkling chemistry between its well-matched leads.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('romántico', 2006, 'An engrossing documentary look at ordinary lives, Romántico puts relatable individual faces on issues that are far too often dehumanized.', TO_DATE('2006-03-04', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('romeo and juliet', 2013, 'Shakespeare''s classic romance gets a so-so adaptation that''s short on passion and energy.', TO_DATE('2013-10-08', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('romeo must die', 2000, 'In his second Hollywood movie, Jet Li impresses. Unfortunately, when he''s not on screen, the movie slows to a crawl. Though there''s some spark between Jet and Aaliyah, there isn''t any threat of a fire. And as impressive as the action sequences are, some critics feel they are over-edited.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('romper stomper', 1993, 'Relentlessly grim and gripping, Romper Stomper is a disquietingly authentic glimpse into the inner dynamics of a hate group, featuring an electric performance by Russell Crowe.', TO_DATE('1993-01-01', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('romy and micheles high school reunion', 1997, 'Romy and Michele''s High School Reunion has an admittedly slight premise, but it''s elevated by ample heart, an infectiously playful spirit, and the buoyant chemistry of Lisa Kudrow and Mira Sorvino.', TO_DATE('1997-04-25', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ronin', 2000, 'Ronin earns comparisons to The French Connection with strong action, dynamic road chase scenes, and solid performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rookie of the year', 2000, 'Rookie of the Year gets some laughs from its novel premise, but a high strikeout rate on jokes and sentimental fouls keeps this comedy firmly in the minor leagues.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('room', 2015, 'Led by incredible work from Brie Larson and Jacob Tremblay, Room makes for an unforgettably harrowing -- and undeniably rewarding -- experience.', TO_DATE('2015-09-04', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('room 237', 2012, 'Mysterious and provocative, Room 237 is a fascinating journey into the world of obsessive cinephilles.', TO_DATE('2012-01-27', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rope', 1948, 'As formally audacious as it is narratively brilliant, Rope connects a powerful ensemble in service of a darkly satisfying crime thriller from a master of the genre.', TO_DATE('1948-08-23', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rory oshea was here', 2004, 'The dramatic aspects of Rory O''Shea Was Here veer into mawkish, formulaic sentiment, which undercuts the characters'' individuality.', TO_DATE('2004-11-02', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rosemarys baby', 2000, 'A frightening tale of Satanism and pregnancy that is even more disturbing than it sounds thanks to convincing and committed performances by Mia Farrow and Ruth Gordon.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rosencrantz and guildenstern are dead', 1991, 'Rosencrantz and Guildenstern Are Dead struggles in its journey from stage to screen, but a well-chosen trio of veteran talents keep things consistently watchable.', TO_DATE('1991-02-08', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rosenstrasse', 2004, 'Thoughtful drama marred by structural problems.', TO_DATE('2004-01-20', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rosewater', 2014, 'Timely, solidly acted, and unabashedly earnest, Rosewater serves as an impressive calling card for first-time director Jon Stewart.', TO_DATE('2014-08-28', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rosewood', 2000, 'In some respects, Rosewood struggles to present a full picture of the real-life tragedy it dramatizes, but it remains a harrowing depiction of racial violence.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rough night', 2017, 'Rough Night''s gifted stars are certainly good for some laughs, but their talents aren''t properly utilized in a scattered comedy that suffers from too many missed opportunities.', TO_DATE('2017-06-14', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('roving mars', 2006, 'Roving Mars is a decent thrill ride even when it starts feeling like a commercial plug for NASA''s failing space program.', TO_DATE('2006-01-18', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('roxanne', 2000, 'Though its sweetness borders on sappiness, Roxanne is an unabashedly romantic comedy that remains one of Steve Martin''s funniest films.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('roxanne roxanne', 2017, 'Roxanne Roxanne belatedly honors its subject with a gripping character-driven biopic that serves as a primer for a trailblazing career while telling an often tragic story.', TO_DATE('2017-01-25', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('royal wedding', 2000, 'Vintage MGM musical stuff, characterized by Stanley Donen''s fleet direction and some amazing dance performances from star Fred Astaire.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rubber', 2010, 'A clever premise gets plenty of comic blood and violence, but its hampered by some questionable storytelling techniques from director Quentin Dupieux.', TO_DATE('2010-05-28', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ruby sparks', 2012, 'Cleverly written and wonderfully acted, Ruby Sparks overcomes its occasional lags in pace with an abundance of charm and wit.', TO_DATE('2012-06-18', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rudderless', 2014, 'Rudderless asks its cast to carry an awful lot of weight for its occasionally manipulative story; fortunately, this talented bunch -- led by Billy Crudup -- is often more than up to the task.', TO_DATE('2014-01-24', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rudo y cursi', 2009, 'Despite its fair share of sports movie cliches, Rudo y Cursi marks an auspicious directing debut for Carlos Cuarón, and features strong performances from García Bernal and Luna.', TO_DATE('2009-05-03', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rudy', 2000, 'Though undeniably sentimental and predictable, Rudy succeeds with an uplifting spirit and determination.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rugrats go wild', 2003, 'The Rugrats franchise has gone from fresh to formulaic.', TO_DATE('2003-06-07', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rugrats in paris the movie', 2000, 'When the Rugrats go to Paris, the result is Nickelodeon-style fun. The plot is effectively character-driven, and features catchy songs and great celebrity voice-acting.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rugrats movie', 1998, 'Charming characters; loads of fun for kids and adults.', TO_DATE('1998-11-20', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rules dont apply', 2016, 'With Rules Don''t Apply, Warren Beatty takes an overall affable -- but undeniably slight -- look at a corner of old Hollywood under Howard Hughes'' distinctive shadow.', TO_DATE('2016-11-10', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rules of attraction', 2002, 'A tiresome movie about unsympathetic college kids engaging in self-destructive behaviors.', TO_DATE('2002-09-26', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rules of engagement', 2000, 'The script is unconvincing and the courtroom action is unegaging.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rumble fish', 2000, 'Rumble Fish frustrates even as it intrigues, but director Francis Ford Coppola''s strong visual style helps compensate for a certain narrative stasis.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rumble in the bronx', 2000, 'An entertaining Jackie Chan stunt-fest in which the impressive action sequences overcome the low production value and by-the-numbers plot.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rumble the indians who rocked the world', 2017, 'RUMBLE shines a long overdue spotlight on key contributions to the American musical lexicon, satisfying rock scholars while offering a fascinating -- albeit sobering -- primer on the foundations of a genre.', TO_DATE('2017-01-23', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rumor has it', 2005, 'This riff on The Graduate has a solid cast, but is too lightweight to fully register.', TO_DATE('2005-12-02', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('run all night', 2015, 'Liam Neeson is in typically fine form, but Run All Night suffers from a convoluted plot and workmanlike execution.', TO_DATE('2015-03-10', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('run lola run', 2000, 'More fun than a barrel of Jean-Paul Sartre, pic''s energy riffs on an engaging love story and really human performances while offering a series of what-ifs and a blood-stirring soundtrack.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('runaway bride', 2000, 'Cliche story with lack of chemistry between Richard Gere and Julia Roberts.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('runaway jury', 2003, 'An implausible but entertaining legal thriller.', TO_DATE('2003-10-05', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('runaway train', 2000, 'Charging forward with the momentum of a locomotive, Runaway Train makes great use of its adrenaline-fueled premise and star presences of Jon Voight and Eric Roberts.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rundskop bullhead', 2012, 'Anchored by Matthias Schoenaerts'' searing performance, Bullhead is a grim and gripping thriller with the cinematic sinew to match its domineering star''s physicality.', TO_DATE('2012-02-02', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('runner runner', 2013, 'It has an impressive cast and an intriguing premise, but Runner Runner wastes them on a bland, haphazardly assembled thriller with very little payoff.', TO_DATE('2013-09-24', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the running man', 2000, 'The Running Man is winking sci-fi satire with ridiculous clothes and workmanlike direction.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('running with scissors', 2006, 'Despite a few great performances, the film lacks the sincerity and emotional edge of Burroughs'' well-loved memoir.', TO_DATE('2006-10-10', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rupture', 2016, 'Derivative and clumsily assembled, Rupture manages the tricky feat of making arachnophobia seem dull.', TO_DATE('2016-11-02', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rush', 2013, 'A sleek, slick, well-oiled machine, Rush is a finely crafted sports drama with exhilarating race sequences and strong performances from Chris Hemsworth and Daniel Brühl.', TO_DATE('2013-09-02', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rush hour', 1998, 'A kick-ass addition to the cop-buddy film genre.', TO_DATE('1998-09-18', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rush hour 2', 2001, 'Rush Hour 2 doesn''t feel as fresh or funny as the first, and the stunts lack some of the intricacy normally seen in Chan''s films.', TO_DATE('2001-07-22', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rush hour 3', 2007, 'Rush Hour 3 is a tired rehash of the earlier films, and a change of scenery can''t hide a lack of new ideas.', TO_DATE('2007-07-14', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rushmore', 2000, 'This cult favorite is a quirky coming of age story, with fine, off-kilter performances from Jason Schwartzman and Bill Murray.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('russian dolls les poupées russes', 2005, 'Like its predecessor L''Auberge Espagnole, Russian Dolls is charmingly breezy and light.', TO_DATE('2005-12-06', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rust creek', 2019, 'Rust Creek subverts expectations with a surprisingly layered survival drama anchored in a rich setting and a gripping lead performance from Hermione Corfield.', TO_DATE('2019-01-02', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ruthless people', 2000, 'It''s sometimes crude and tasteless, but Ruthless People wrings acid-soaked laughs out of its dark premise and gleefully misanthropic characters.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rv', 2006, 'An unoriginal and only occasionally funny family road-trip movie, RV is a mediocre effort that not even the charisma of Robin Williams can save.', TO_DATE('2006-04-25', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vhs2', 2013, 'It''s as scattershot as its predecessor, but V/H/S/2 rounds up enough horror filmmaking talent to deliver a satisfyingly nasty -- albeit uneven -- dose of gore.', TO_DATE('2013-01-21', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sabans power rangers', 2017, 'Power Rangers has neither the campy fun of its TV predecessor nor the blockbuster action of its cinematic superhero competitors, and sadly never quite manages to shift into turbo for some good old-fashioned morphin time.', TO_DATE('2017-03-15', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sabotage', 2014, 'Sabotage boasts one of Arnold Schwarzenegger''s finer post-political performances, but it''s wasted in a movie driven by grueling violence that punishes seemingly without purpose.', TO_DATE('2014-03-26', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sacco and vanzetti', 2006, 'Engrossing and enraging, Sacco and Vanzetti exhumes an infamous judicial failure with a painful amount of modern relevance.', TO_DATE('2006-08-21', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the saddest music in the world', 2003, 'Guy Maddin perfectly recreates the look and feel of a 1930s in this bizarre picture.', TO_DATE('2003-10-22', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('safe', 2000, 'Safe''s eerie social satire and somewhat sterile stylization is balanced by comedic undertones and an impressive, understated performance from Julianne Moore.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('safe', 2012, 'While hard-hitting and violently inventive, Safe ultimately proves too formulaic to set itself apart from the action thriller pack -- including some of its star''s better films.', TO_DATE('2012-04-22', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('safe haven', 2013, 'Schmaltzy, predictable, and melodramatic, Safe Haven also suffers from a ludicrous plot twist, making for a particularly ignominious Nicholas Sparks adaptation.', TO_DATE('2013-02-10', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('safe house', 2012, 'Safe House stars Washington and Reynolds are let down by a thin script and choppily edited action sequences.', TO_DATE('2012-02-07', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('safety last', 2000, 'Persuasive enough to give audiences acrophobia when they aren''t laughing at Harold Lloyd''s antics, Safety Last! is a marvel of visual effects and slapstick comedy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('safety not guaranteed', 2012, 'Safety Not Guaranteed''s ostensibly modest ambitions are outmatched by the movie''s strong performances, beguiling charm, and heartfelt story.', TO_DATE('2012-01-24', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the saint', 2000, 'The Saint is watchable thanks to Kilmer and Shue, but the muddled screenplay stretches credulity.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saint frances', 2019, 'Saint Frances approaches an array of weighty issues with empathy, humor, and grace -- and marks star and writer Kelly O''Sullivan as a tremendous talent to watch.', TO_DATE('2019-03-11', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saint john of las vegas', 2009, 'Writer-director Hue Rhodes'' debut is a poorly-paced, forgettable comedy that wastes the quirky talents of stars Steve Buscemi and Sarah Silverman.', TO_DATE('2009-11-23', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saint laurent', 2014, 'A well-intentioned but frustratingly diffuse biopic, Saint Laurent proves an ironically poor fit for a look at the life of a fashion icon.', TO_DATE('2014-05-17', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saints and soldiers', 2004, 'While it draws heavily on war movie conventions, Saints and Soldiers has strong performances and a compelling central plot.', TO_DATE('2004-02-02', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('salems lot', 2000, 'Director Tobe Hooper and a devilishly charismatic James Mason elevate this television adaptation of the Stephen King novel, injecting the vampiric tradition with fresh blood and lingering scares.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('salmon fishing in the yemen', 2011, 'Quirky and a little reserved, Salmon Fishing in the Yemen is nonetheless a charming little romantic drama sold by some strong central performances.', TO_DATE('2011-09-18', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the salton sea', 2002, 'A slick Tarantino-inspired movie that is not for everyone.', TO_DATE('2002-02-04', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saludos amigos', 2003, 'One of Disney''s lesser-known animated films, Saludos Amigos may be slight stuff, but it''s still a spirited, energetic travelogue.', TO_DATE('2003-01-08', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('salvador', 2000, 'Despite its somewhat disjointed narrative, Oliver Stone''s Salvador is a vivid and powerful political drama that sets an early tone for the director''s similarly provocative future projects.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('salvo', 2014, 'Stylish and inventive, Salvo parcels out the thrills that genre fans seek while anchoring its story with satisfying, slow-building tension.', TO_DATE('2014-02-24', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('samba', 2014, 'Samba isn''t the finest effort from directors Olivier Nakache and Eric Toledano, but the film''s shortcomings are partly balanced by its big heart and talented cast.', TO_DATE('2014-09-05', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('samsara', 2012, 'It''s a tad heavy-handed in its message, but Samsara''s overwhelmingly beautiful visuals more than compensate for any narrative flaws.', TO_DATE('2012-08-14', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('san andreas', 2015, 'San Andreas has a great cast and outstanding special effects, but amidst all the senses-shattering destruction, the movie''s characters and plot prove less than structurally sound.', TO_DATE('2015-05-25', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sanctum', 2011, 'Sanctum is beautifully photographed, and it makes better use of 3-D technology than most, but that doesn''t make up for its ham-handed script and lifeless cast.', TO_DATE('2011-01-31', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sandlot', 1993, 'It may be shamelessly derivative and overly nostalgic, but The Sandlot is nevertheless a genuinely sweet and funny coming-of-age adventure.', TO_DATE('1993-04-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sandy wexler', 2017, 'Sandy Wexler marks a mild improvement from the Adam Sandler vehicles immediately preceding it -- which in no way serves as an endorsement for non-hardcore fans.', TO_DATE('2017-04-14', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sangre de mi sangre', 2007, 'This suspenseful Mexican drama portrays the immigrant experience with grit and poignancy.', TO_DATE('2007-01-20', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sanjuro tsubaki sanjûrô', 2000, 'Technically impressive and superbly acted, Sanjuro is a funny, action-packed samurai adventure featuring outstanding cinematography and a charismatic performance from Toshiro Mifune.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('santa claus conquers the martians', 2000, 'Ho, ho, oh no.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('santa claus is comin to town', 2005, 'Arriving with light-hearted cheeriness and the best musical numbers, Santa Claus Is Comin To Town is a magical story told by charming wood-figure animation.', TO_DATE('2005-01-04', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the santa clause 3 the escape clause', 2006, 'Playing Jack Frost as an evil cross between Liza Minnelli and Liberace, Martin Short is a welcome presence, but this tired series continues drawing from its bag of bland gags and dumb slapstick.', TO_DATE('2006-11-02', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('santa sangre', 2000, 'Those unfamiliar with Alejandro Jodorowsky''s style may find it overwhelming, but Santa Sangre is a provocative psychedelic journey featuring the director''s signature touches of violence, vulgarity, and an oddly personal moral center.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saraband', 2004, 'If Saraband appears to be a minor entry in Ingmar Bergman''s filmography, it''s still an accomplished piece of work from one of cinema''s greatest masters.', TO_DATE('2004-10-14', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sarah silverman a speck of dust', 2017, 'Led by a natural, effortless and extremely funny performance, Sarah Silverman delivers a special full of excellent jokes.', TO_DATE('2017-05-31', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sarah silverman jesus is magic', 2005, 'Silverman''s brand of humor is dirty, offensive, and, judging from this film, very, very funny.', TO_DATE('2005-09-10', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sarahs key', 2010, 'Sarah''s Key is an absorbing, impeccably-acted Holocaust drama with minor plot issues.', TO_DATE('2010-09-17', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('satanic panic', 2019, 'It isn''t terribly devilish or particularly pulse-quickening, but Satanic Panic remains an entertaining midnight movie that forgiving genre enthusiasts will enjoy.', TO_DATE('2019-06-04', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saturday church', 2017, 'A remarkable debut feature for writer-director Damon Cardasis, Saturday Church explores gender identity with wisdom and striking sensitivity.', TO_DATE('2017-04-23', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saturday night fever', 2000, 'Boasting a smart, poignant story, a classic soundtrack, and a starmaking performance from John Travolta, Saturday Night Fever ranks among the finest dramas of the 1970s.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sausage party', 2016, 'Sausage Party is definitely offensive, but backs up its enthusiastic profanity with an impressively high laugh-to-gag ratio -- and a surprisingly thought-provoking storyline.', TO_DATE('2016-03-15', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('savage grace', 2007, 'Though visually compelling, the lamentable characters in Savage Grace make for difficult viewing.', TO_DATE('2007-05-18', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the savages', 2007, 'Thanks to a tender, funny script from director Tamara Jenkins, and fine performances from Philip Seymour Hoffman and Laura Linney, this film delivers a nuanced, beautifully three-dimensional look at the struggles and comforts of family bonds.', TO_DATE('2007-01-20', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('savages', 2012, 'It''s undeniably messy, but Savages finds Oliver Stone returning to dark, fearlessly lurid form.', TO_DATE('2012-06-28', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('save the last dance', 2001, 'This teen romance flick feels like a predictable rehashing of other movies.', TO_DATE('2001-01-08', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saved', 2004, 'A satirical teen comedy that, unfortunately, pulls its punches.', TO_DATE('2004-01-27', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saving shiloh', 2006, 'The aggressively wholesome Saving Shiloh has honorable intentions, but this simple story of a boy and his dog is overwhelmed by its heavy-handed approach.', TO_DATE('2006-05-11', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saving face', 2005, 'A charming tale of a love affair that overcomes cultural taboos.', TO_DATE('2005-02-02', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saving mr banks', 2013, 'Aggressively likable and sentimental to a fault, Saving Mr. Banks pays tribute to the Disney legacy with excellent performances and sweet, high-spirited charm.', TO_DATE('2013-10-20', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saving private ryan', 1998, 'Anchored by another winning performance from Tom Hanks, Steven Spielberg''s unflinchingly realistic war film virtually redefines the genre.', TO_DATE('1998-07-24', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saving silverman', 2000, 'Dragged down by a plot lacking any sense of logic and obnoxious, unsympathetic characters, this comedy is more crude and mean-spirited than funny.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saw', 2004, 'Saw ensnares audiences with a deceptively clever plot and a myriad of memorable, nasty set pieces, but its lofty ambitions are undercut by a nihilistic streak that feels more mean than profound.', TO_DATE('2004-02-18', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saw 3d', 2010, 'Sloppily filmed, poorly acted, and illogically plotted, Saw 3D leaves viewers trapped in the most lackluster installment of the series.', TO_DATE('2010-10-28', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saw iii', 2006, 'Saw III does little beyond repeating its predecessor''s tropes on a gorier level.', TO_DATE('2006-10-26', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saw iv', 2007, 'Saw IV is more disturbing than compelling, with material already seen in the prior installments.', TO_DATE('2007-10-25', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saw vi', 2009, 'It won''t earn the franchise many new fans, but Saw VI is a surprising step up for what has become an intricately grisly annual tradition.', TO_DATE('2009-10-21', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saw ii', 2005, 'Saw II is likely to please the gore-happy fans of the original, though it may be too gruesome for those not familiar with first film''s premise.', TO_DATE('2005-10-20', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('saw v', 2008, 'If its plot were as interesting as its torture devices, or its violence less painful than its performances, perhaps Saw V might not feel like it was running on fumes.', TO_DATE('2008-10-22', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('say anything', 2000, 'One of the definitive Generation X movies, Say Anything is equally funny and heartfelt -- and it established John Cusack as an icon for left-of-center types everywhere.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('say it isnt so', 2001, 'Those that haven''t tired from Farrelly brothers'' brand of comedy may still find some laughs here. Otherwise, the slow pacing and unimaginative shock gags will start to wear on the viewer.', TO_DATE('2001-02-21', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a scanner darkly', 2006, 'A faithful adaptation of Philip K. Dick''s novel, A Scanner Darkly takes the viewer on a visual and mind-blowing journey into the author''s conception of a drug-addled and politically unstable world.', TO_DATE('2006-04-17', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scarface', 2000, 'Director Brian De Palma and star Al Pacino take it to the limit in this stylized, ultra-violent and eminently quotable gangster epic that walks a thin white line between moral drama and celebratory excess.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scary movie', 2000, 'Critics say Scary Movie overloads on crudity and grossness to get its laughs.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scary movie 2', 2000, 'Instead of being funny, this gross-out sequel plays like a sloppy, rushed-out product.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scary movie 3', 2003, 'Though an improvement over the second Scary Movie, the laughs are still inconsistent.', TO_DATE('2003-10-22', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scary movie 4', 2006, 'Sure to inspire a few chuckles, but not enough to compensate for the recycled material from its predecessors.', TO_DATE('2006-04-06', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scary movie 5', 2013, 'Juvenile even by Scary Movie standards, this fifth installment offers stale pop culture gags that generate few laughs.', TO_DATE('2013-04-09', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scary stories to tell in the dark', 2019, 'Like the bestselling series of books that inspired it, Scary Stories to Tell in the Dark opens a creepy gateway into horror for younger genre enthusiasts.', TO_DATE('2019-08-08', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scatter my ashes at bergdorfs', 2013, 'Scatter My Ashes At Bergdorf''s is a fun documentary which ultimately doubles as an infomercial for the Manhattan store.', TO_DATE('2013-04-29', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('schindlers list', 2000, 'Schindler''s List blends the abject horror of the Holocaust with Steven Spielberg''s signature tender humanism to create the director''s dramatic masterpiece.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('school daze', 2000, 'School Daze is undeniably messy, but thought-provoking themes, strong performances, and Spike Lee''s ingratiating energy help tie it all together.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('school for scoundrels', 2006, 'School for Scoundrels squanders its talented cast with a formulaic, unfocused attempt at a romantic comedy that''s neither romantic nor funny.', TO_DATE('2006-09-14', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('school of rock', 2003, 'Black''s exuberant, gleeful performance turns School of Rock into a hilarious, rocking good time.', TO_DATE('2003-08-13', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('schultze gets the blues', 2004, 'Schultze Gets the Blues is a sweet and charming dark comedy.', TO_DATE('2004-08-02', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scoob', 2020, 'Scoob! is fun enough for youthful viewers and some hardcore fans, but never quite solves the mystery of why audiences shouldn''t watch old episodes instead.', TO_DATE('2020-05-15', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scoobydoo 2 monsters unleashed', 2004, 'Only the very young will get the most out of this silly trifle.', TO_DATE('2004-03-19', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scoop', 2006, 'Rehashing old plot lines and characters, Scoop is a tiresome dipper and another disappointing addition to Woody Allen''s repertoire.', TO_DATE('2006-07-11', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('score a film music documentary', 2016, 'SCORE: A Film Music Documentary offers a long-overdue look at an integral component of cinema whose abbreviated overview of the subject should only leave viewers ready for more.', TO_DATE('2016-10-20', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the scorpion king', 2002, 'Action adventure doesn''t get much cheesier than The Scorpion King.', TO_DATE('2002-04-15', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scott walker 30 century man', 2007, 'Scott Walker: 30 Century Man is a stylish portrait of an influential artist that will fascinate fans and neophytes alike.', TO_DATE('2007-03-06', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scott pilgrim vs the world', 2010, 'Its script may not be as dazzling as its eye-popping visuals, but Scott Pilgrim vs. the World is fast, funny, and inventive.', TO_DATE('2010-07-22', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scouts guide to the zombie apocalypse', 2015, 'Scouts Guide to the Zombie Apocalypse fails to live up to its intriguingly wacky title, instead delivering yet another zombie comedy-thriller with a tired T&A twist.', TO_DATE('2015-10-28', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scratch', 2002, 'Whether you know anything about turntablism or not, Scratch makes for fun and informative viewing.', TO_DATE('2002-01-04', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scream 4', 2011, 'The franchise is showing its age, but Scream 4 is undeniably an improvement over its predecessor, with just enough meta humor and clever kills.', TO_DATE('2011-04-11', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scream 2', 2000, 'As with the first film, Scream 2 is a gleeful takedown of scary movie conventions that manages to poke fun at terrible horror sequels without falling victim to the same fate.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scream 3', 2000, 'Despite some surprising twists, Scream 3 sees the franchise falling back on the same old horror formulas and cliches it once hacked and slashed with postmodern abandon.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('screwball', 2018, 'A smart and entertainingly light handling of a serious topic, Screwball proves well worth a watch for baseball fans as well as true crime enthusiasts.', TO_DATE('2018-09-10', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('scrooged', 2000, 'Scrooged gets by with Bill Murray and a dash of holiday spirit, although it''s hampered by a markedly conflicted tone and an undercurrent of mean-spiritedness.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sea fever', 2019, 'If Sea Fever never quite heats up as much as it could, it remains an engrossing, well-acted sci-fi thriller with effective horror elements.', TO_DATE('2019-09-06', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sea inside mar adentro the sea within', 2004, 'Held aloft by a transfixing performance from Javier Bardem as a terminally ill man who chooses to die, The Sea Inside transcends its melodramatic story with tenderness and grace.', TO_DATE('2004-08-31', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sea of love', 2000, 'Moody and steadily alluring, Sea of Love benefits immeasurably from the window-fogging chemistry between Ellen Barkin and Al Pacino.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seabiscuit', 2003, 'A life-affirming, if saccharine, epic treatment of a spirit-lifting figure in sports history.', TO_DATE('2003-07-16', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the seagulls laughter mávahlátur', 2004, 'Though uneven in spots, this delightful comedy will, nevertheless, put a smile on your face.', TO_DATE('2004-01-23', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the searchers', 2000, 'The Searchers is an epic John Wayne Western that introduces dark ambivalence to the genre that remains fashionable today.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('searching', 2018, 'Searching''s timely premise and original execution are further bolstered by well-rounded characters brought to life by a talented cast.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('searching for bobby fischer', 1993, 'As sensitive as the young man at its center, Searching for Bobby Fischer uses a prodigy''s struggle to find personal balance as the background for a powerfully moving drama.', TO_DATE('1993-08-14', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('searching for sugar man', 2012, 'A fascinating portrait of a forgotten musical pioneer, Searching for Sugar Man is by turns informative and mysterious.', TO_DATE('2012-01-20', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('second act', 2018, 'Second Act proves Jennifer Lopez remains as magnetic as ever on the big screen; unfortunately, the movie''s muddled story isn''t always worthy of her gifts.', TO_DATE('2018-12-05', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('secondhand lions', 2003, 'A wholesome but schmaltzy movie.', TO_DATE('2003-09-03', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seconds', 2001, 'Featuring dazzling, disorienting cinematography from the great James Wong Howe and a strong lead performance by Rock Hudson, Seconds is a compellingly paranoid take on the legend of Faust.', TO_DATE('2001-12-31', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('secret ballot', 2002, 'A moderately funny comedy that will reward patient viewers.', TO_DATE('2002-01-10', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the secret in their eyes el secreto de sus ojos', 2010, 'Unpredictable and rich with symbolism, this Argentinian murder mystery lives up to its Oscar with an engrossing plot, Juan Jose Campanella''s assured direction, and mesmerizing performances from its cast.', TO_DATE('2010-02-27', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('secret in their eyes', 2015, 'Secret in Their Eyes wastes its incredible cast on a remake that fails to improve upon -- or even make a compelling case for its own existence in addition to -- the remarkable original.', TO_DATE('2015-11-18', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the secret life of bees', 2008, 'The Secret Life of Bees has moments of charm, but is largely too maudlin and sticky-sweet.', TO_DATE('2008-09-08', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('daltry calhoun', 2005, 'Watching grass grow would likely be more entertaining than this dull, slight feature about a sod salesman.', TO_DATE('2005-09-18', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('secret obsession', 2019, 'While it may offer some thrills and unintentional laughs, Secret Obsession is mostly a formulaic and dumb thriller.', TO_DATE('2019-07-18', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the secret of moonacre', 2009, 'Despite impressive production values, this is staid, plodding and unimpressive fantasy-fare, with poor performances struggling with an underdeveloped script.', TO_DATE('2009-02-05', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the secret of nimh', 2002, 'The Secret of NIMH is a dark, well-told tale that respects its young audience enough to not tone down its subject matter.', TO_DATE('2002-03-28', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('secret things', 2003, 'Pretentious and trashy.', TO_DATE('2003-12-31', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('secret window', 2004, 'Depp is quirkily entertaining, but the movie runs out of steam by the end.', TO_DATE('2004-02-09', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('secretariat', 2010, 'Rousing, heartwarming, and squarely traditional, Secretariat offers exactly what you''d expect from an inspirational Disney drama -- no more, and no less.', TO_DATE('2010-10-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('secretary', 2002, 'Maggie Gyllenhaal impresses in this romantic comedy with a kinky twist.', TO_DATE('2002-04-08', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('secuestro express', 2005, 'Despite utilizing a visual whirlwind of cinematic tricks, this socio-political thriller falls short of fulfilling its heavier goals but provides a powerful peek into the class issues of modern Venezuela.', TO_DATE('2005-07-14', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('see no evil hear no evil', 2000, 'A film whose title offers words to live by as well as a warning, See No Evil, Hear No Evil proves that even a brilliant comedy duo can team up for an unfunny dud.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('see spot run', 2001, 'See Spot Run has all the elements chidren enjoy in a movie: a lovable dog, bad things happening to stupid adults, and lots of dog poop. For adults, it''s either hit-or-miss.', TO_DATE('2001-02-23', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('see you yesterday', 2019, 'See You Yesterday marries a novel sci-fi premise with urgent social relevance and forges something excitedly new from the union -- providing an impressive showcase for star Eden Duncan-Smith and debut writer-director Stefon Bristol.', TO_DATE('2019-05-04', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seed of chucky', 2004, 'Give Seed of Chucky credit for embracing the increasing absurdity of the franchise -- even if the end results really aren''t all that funny or entertaining.', TO_DATE('2004-11-06', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the seeker the dark is rising', 2007, 'The magic of the book is lost in translation with The Seeker, due to its clumsy plot and lack of heart.', TO_DATE('2007-10-04', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seeking a friend for the end of the world', 2012, 'Tender, charming, and well-acted, Seeking a Friend for the End of the World is unfortunately hamstrung by jarring tonal shifts and a disappointing final act.', TO_DATE('2012-06-18', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('self medicated', 2006, 'Self-Medicated features some nice performances, but is too sentimental and unfocused to be a truly compelling film.', TO_DATE('2006-07-09', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('selfless', 2015, 'Self/less boasts a potential-packed premise, but does frustratingly little with it, settling for lackluster action at the expense of interesting ideas.', TO_DATE('2015-07-04', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('selma', 2014, 'Fueled by a gripping performance from David Oyelowo, Selma draws inspiration and dramatic power from the life and death of Martin Luther King, Jr. -- but doesn''t ignore how far we remain from the ideals his work embodied.', TO_DATE('2014-11-12', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('semipro', 2008, 'Semi-Pro is an intermittently funny, half-hearted attempt at sports satire, and one of Will Ferrell''s weaker cinematic efforts.', TO_DATE('2008-02-19', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('senna', 2011, 'Even for filmgoers who aren''t racing fans, Senna offers heart-pounding thrills -- and heartbreaking emotion.', TO_DATE('2011-01-22', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sentinel', 2006, 'The Sentinel starts off well enough but quickly wears thin with too many plot holes and conventional action sequences.', TO_DATE('2006-04-19', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the isle', 2002, 'A compelling and oddly haunting combination of brutal and beautiful imagery.', TO_DATE('2002-02-27', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seoul station', 2016, 'Thrilling and relentless from start to finish, Yeon Sang-ho''s Seoul Station is a layered and vicious entry into the zombie genre.', TO_DATE('2016-07-05', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('separate lies', 2005, 'Though the characters in this tasteful adult drama keep a stiff upper lip, the moral dilemmas are nuanced and the emotional pain feels real.', TO_DATE('2005-08-25', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('september dawn', 2007, 'With its jarring editing, dull love story, and silly dialogue, September Dawn turns a horrific historical event into a banal movie.', TO_DATE('2007-06-17', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the september issue', 2009, 'This doc about the making of Vogue''s biggest issue and its frosty editor-in-chief is fascinating eye candy and light-on-its-feet fun.', TO_DATE('2009-01-20', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seraphim falls', 2006, 'A brutal, slow-moving drama that unfolds among some great-looking scenery.', TO_DATE('2006-09-15', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('séraphine', 2009, 'Seraphine is a well-crafted French film that effectively captures one woman''s experience with art, religion, and mental illness, and features a brilliant performance from Yolande Moreau.', TO_DATE('2009-05-10', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('serbis service', 2008, 'This darkly comic family drama finds ways of being viscerally graphic and intellectually stimulating at the same time.', TO_DATE('2008-10-13', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('serena', 2014, 'Serena unites an impressive array of talent on either side of the cameras -- then leaves viewers to wonder how it all went so wrong.', TO_DATE('2014-10-13', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('serendipity', 2001, 'Light and charming, Serendipity could benefit from less contrivances.', TO_DATE('2001-09-20', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('serenity', 2005, 'Snappy dialogue and goofy characters make this Wild Wild West soap opera in space fun and adventurous.', TO_DATE('2005-08-23', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('serenity', 2019, 'A high-concept mystery with a twist, Serenity isn''t what it appears to be at first -- unfortunately, it''s also not anywhere near as clever or entertaining as it thinks.', TO_DATE('2019-01-24', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sergio', 2020, 'While the real-life story that inspired Sergio is certainly worthy of a biopic, its misguided approach to its noble subject adds up to a disappointingly shallow drama.', TO_DATE('2020-01-29', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('serious moonlight', 2009, 'Serious Moonlight jumbles a comic tone with tragic circumstances and the result is confused performances from its stars.', TO_DATE('2009-05-06', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the serpent and the rainbow', 2000, 'Although it''s occasionally overwhelmed by excessive special effects, The Serpent and the Rainbow draws on a chilling atmosphere to deliver a intelligent, politically informed story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('serpico', 2000, 'An engrossing, immediate depiction of early ''70s New York, Serpico is elevated by Al Pacino''s ferocious performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('serving sara', 2002, 'A romantic comedy that''s neither funny nor particularly romantic, Serving Sara is a forgettable time waster.', TO_DATE('2002-08-20', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('session 9', 2001, 'Relying more on atmosphere than gore, Session 9 is effectively creepy.', TO_DATE('2001-06-06', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('set fire to the stars', 2014, 'Set Fire to the Stars doesn''t quite do justice to its legendary real-life protagonist, but thanks to Celyn Jones'' spirited performance, it occasionally comes close.', TO_DATE('2014-06-23', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('set it off', 1996, 'It may not boast an original plot, but Set It Off is a satisfying, socially conscious heist film thanks largely to fine performances from its leads.', TO_DATE('1996-11-06', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('set it up', 2018, 'Set It Up follows the long-established outlines of the rom-com template -- and in the process, proves there''s still substantial pleasure to be wrought from familiar formulas.', TO_DATE('2018-06-12', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seven brides for seven brothers', 2001, 'Buoyed by crowd-pleasing tunes and charming performances, Seven Brides for Seven Brothers makes a successful transition from Broadway to screen that''s sure to please the whole family.', TO_DATE('2001-04-25', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seven days in may', 2000, 'John Frankenheimer''s striking direction and a first-rate cast conspire to make Seven Days in May a stark, riveting tale of political intrigue.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seven days in utopia', 2011, 'Seven Days in Utopia finds a noteworthy cast struggling to engage with lackadaisical drama, overwrought themes, and a predictably staged narrative.', TO_DATE('2011-08-30', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seven pounds', 2008, 'Grim and morose, Seven Pounds is also undone by an illogical plot.', TO_DATE('2008-12-16', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seven psychopaths', 2012, 'Seven Psychopaths delivers sly cinematic commentary while serving up a heaping helping of sharp dialogue and gleeful violence.', TO_DATE('2012-09-07', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seven samurai shichinin no samurai', 2000, 'Arguably Akira Kurosawa''s masterpiece, The Seven Samurai is an epic adventure classic with an engrossing story, memorable characters, and stunning action sequences that make it one of the most influential films ever made.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seventeen diecisiete', 2019, 'An endearing dramedy, Seventeen is filled with honesty and sweetness and is sure to move audience.', TO_DATE('2019-09-30', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the seventh seal det sjunde inseglet', 2000, 'Narratively bold and visually striking, The Seventh Seal brought Ingmar Bergman to the world stage -- and remains every bit as compelling today.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seventh son', 2014, 'Seventh Son squanders an excellent cast and some strange storyline ingredients, leaving audiences with one disappointingly dull fantasy adventure.', TO_DATE('2014-12-17', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('severance', 2006, 'A twisted and bloody spoof on office life, Severance nicely balances comedy and nasty horror.', TO_DATE('2006-09-01', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sex drugs rock roll', 2010, 'Sex & Drugs & Rock & Roll pays appropriately uninhibited tribute to a pioneering artist -- and proves Andy Serkis can be every bit as compelling in a non-motion-capture role.', TO_DATE('2010-01-08', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sex and death 101', 2007, 'Sex and Death 101 aspires to be a clever sex comedy, but has little life behind the sex or the death.', TO_DATE('2007-02-08', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sex and lucia', 2001, 'Beneath the gratuitous nudity lies a complex and visually striking movie.', TO_DATE('2001-09-04', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sex and the city', 2008, 'Sex and the City loses steam in the transition to the big screen, but will still thrill fans of the show.', TO_DATE('2008-05-15', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sex and the city 2', 2010, 'Straining under a thin plot stretched to its limit by a bloated running time, Sex and the City 2 adds an unfortunate coda to the long-running HBO series.', TO_DATE('2010-05-23', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sex drive', 2008, 'Sex Drive has some hilarious moments and is well made for a raunchy teen film, but will appeal to few beyond that demographic.', TO_DATE('2008-10-02', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sex lies and videotape', 1989, 'In his feature directorial debut, Steven Soderbergh demonstrates a mastery of his craft well beyond his years, pulling together an outstanding cast and an intelligent script for a nuanced, mature film about neurosis and human sexuality.', TO_DATE('1989-01-20', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sex tape', 2014, 'With neither the conviction to embrace its smutty premise nor enough laughs to function as a worthwhile rom-com, the flaccid Sex Tape suffers from cinematic impotence.', TO_DATE('2014-07-15', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sextuplets', 2019, 'Lazy, messy, and deeply unfunny, Sextuplets is the latest misfire from the collaborative duo of Marlon Wayans and Michael Tiddes.', TO_DATE('2019-08-16', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sexy beast', 2000, 'Sexy Beast rises above other movies in the British gangster genre due to its performances -- particularly an electrifying one by Ben Kingsley -- and the script''s attention to character development.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('seymour an introduction', 2014, 'Seymour Bernstein''s genuineness shines so brightly in Seymour: An Introduction that viewers will forgive debuting director Ethan Hawke''s reverent treatment.', TO_DATE('2014-09-08', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sgt peppers lonely hearts club band', 2000, 'I thought you might like to know that the Beatles (aka the act you''ve known for all these years) are ill-served by this kitschy, aggressively whimsical fantasy film that''s most certainly not a thrill.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sgt stubby an american hero', 2018, 'Sgt. Stubby: An American Hero opens a vibrantly animated window into history with the surprisingly true -- and poignant -- tale of a distinguished canine combat veteran.', TO_DATE('2018-04-09', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shadow', 2018, 'Beautifully filmed and inventively choreographed, Shadow is a thrilling and visually sumptuous wuxia epic that finds director Zhang Yimou near peak form.', TO_DATE('2018-09-06', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shadow conspiracy', 2000, 'Rather than exciting audiences with a thrilling race against time, Shadow Conspiracy suggests there may be a secret cabal duping talented actors into selecting woefully deficient scripts.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shadow dancer', 2012, 'A tense, thought-provoking thriller, Shadow Dancer is bolstered by sensitive direction from James Marsh and a terrific performance from Andrea Riseborough.', TO_DATE('2012-01-25', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shadow of the vampire', 2000, 'Shadow of the Vampire is frightening, compelling, and funny, and features an excellent performance by Willem Dafoe.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shadowboxer', 2005, 'With random characters and a preposterous plot, this bizarre thriller might leave you with your mouth hanging open in disbelief.', TO_DATE('2005-09-09', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shadowlands', 2000, 'Thanks to brilliant performances from Debra Winger and especially Anthony Hopkins, Shadowlands is a deeply moving portrait of British scholar C.S. Lewis''s romance with American poet Joy Gresham.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shadows and fog', 2000, 'Shadows and Fog recreates the chiaroscuro aesthetic of German Expressionism, but Woody Allen''s rambling screenplay retreads the director''s neurotic obsessions with derivative results.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shaft', 2019, 'Decades removed from the original, this multi-generational Shaft struggles to keep its characters interesting -- or anything other than uncomfortably outdated.', TO_DATE('2019-06-13', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the shaggy dog', 2006, 'This Disney retread has neither inspiration nor originality, but may please moviegoers under the age of ten.', TO_DATE('2006-03-04', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shakes the clown', 2000, 'Shakes the Clown has a handful of memorable moments, but they''re scattered in a movie whose best ideas were left undeveloped on their way to the screen.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shakespeare behind bars', 2006, 'Shakespeare Behind Bars is a moving testament to the power -- and universality -- of art.', TO_DATE('2006-03-07', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shakespeare in love', 2000, 'Endlessly witty, visually rapturous, and sweetly romantic, Shakespeare in Love is a delightful romantic comedy that succeeds on nearly every level.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shall we dance', 2004, 'The cast is warmly appealing, but with the loss of cultural context and addition of big-name celebrities, this American version loses the nuances of the original.', TO_DATE('2004-05-10', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('un baiser sil vous plaît shall we kiss', 2008, 'Shall We Kiss? combines just enough romance and laughs to make for a charming French take on Woody Allen comedies.', TO_DATE('2008-06-24', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shallow hal', 2001, 'While surprisingly sweeter and warm-hearted than previous Farrelly outings, Shallow Hal is also less funny and more bland.', TO_DATE('2001-10-29', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shame', 2011, 'Boasting stellar performances by Michael Fassbender and Carey Mulligan, Shame is a powerful plunge into the mania of addiction affliction.', TO_DATE('2011-09-05', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shampoo', 2000, 'Shampoo trains a darkly comic lens on post-Nixon America, aiming at -- and often hitting -- an array of timely targets.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shanghai', 2012, 'Shanghai is crippled by a weak story and fatally undermined by clunky direction, making for a period political drama that lacks all of its key components.', TO_DATE('2012-01-12', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shanghai knights', 2003, 'A silly, anachronistic mess, but the pairing of Chan and Wilson makes the movie fun.', TO_DATE('2003-01-24', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shanghai noon', 2000, 'Although the plot is really nothing to brag about, Jackie Chan and Owen Wilson work well together. The cinematography looks great, and Jackie delivers a hilarious performance. This is an old-fashioned crowd-pleaser.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shanghai triad yao a yao yao dao waipo qiao', 1995, 'Well-acted and beautifully filmed, Shanghai Triad deftly depicts a young man''s coming of age against the backdrop of mob violence and its punishing legacy.', TO_DATE('1995-12-22', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shaolin soccer', 2001, 'The plot is utterly ridiculous, and the soccer in the movie is unlike any ever played anywhere on Earth, but watching Shaolin Soccer, you will probably find it impossible to care.', TO_DATE('2001-09-13', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shark night 3d', 2011, 'A joyless excursion into the water that doesn''t even produce good gore or nudity thanks to the neutered PG-13 rating.', TO_DATE('2011-09-02', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shark tale', 2004, 'Derivative and full of pop culture in-jokes.', TO_DATE('2004-09-13', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sharknado', 2013, 'Proudly, shamelessly, and gloriously brainless, Sharknado redefines "so bad it''s good" for a new generation.', TO_DATE('2013-07-26', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sharknado 2 the second one', 2014, 'The schlock factor for Sharknado 2: The Second One is not as entertaining as its predecessor''s, though fans of the brand will likely enjoy it.', TO_DATE('2014-07-25', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sharknado 3 oh hell no', 2015, 'Sharknado 3: Oh Hell No! bites off more than it can chew, leaving viewers with an overlong mess that isn''t even bad enough to be good.', TO_DATE('2015-07-16', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sharknado the 4th awakens', 2016, 'Sharknado: The 4th Awakens loses the ridiculous charm of its predecessors, leaving only clumsy social commentary and monotonous schtick that''s lost its bite.', TO_DATE('2016-07-22', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sharkwater', 2006, 'In addition to its breathtaking underwater photography, Sharkwater has a convincing, impassioned argument of how the plight of sharks affects everyone.', TO_DATE('2006-09-18', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shattered glass', 2003, 'A compelling look at Stephen Glass'' fall from grace.', TO_DATE('2003-09-09', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shaun of the dead', 2004, 'Shaun of the Dead cleverly balances scares and witty satire, making for a bloody good zombie movie with loads of wit.', TO_DATE('2004-02-17', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shaun the sheep movie', 2015, 'Warm, funny, and brilliantly animated, Shaun the Sheep is yet another stop-motion jewel in Aardman''s family-friendly crown.', TO_DATE('2015-01-24', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the shawshank redemption', 1994, 'The Shawshank Redemption is an uplifting, deeply satisfying prison drama with sensitive direction and fine performances.', TO_DATE('1994-09-10', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shazam', 2019, 'An effortlessly entertaining blend of humor and heart, Shazam! is a superhero movie that never forgets the genre''s real power: joyous wish fulfillment.', TO_DATE('2019-03-23', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('she dies tomorrow', 2020, 'Formally provocative and emotionally raw, She Dies Tomorrow confirms writer-director Amy Seimetz as a filmmaker with a unique -- and timely -- vision.', TO_DATE('2020-03-19', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('she done him wrong', 2000, 'She Done Him Wrong, but putting Cary Grant and Mae West together is pretty much nothing but right.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('she hate me', 2004, 'She Hate Me can''t decide if it wants to be a commentary on corporate greed or a sex farce.', TO_DATE('2004-07-22', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sheltering sky', 1990, 'The Sheltering Sky puts its talented stars at odds with a misguided and largely unsatisfying adaptation of potentially unfilmable source material.', TO_DATE('1990-01-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sherlock gnomes', 2018, 'Sherlock Gnomes is sadly, utterly stumped by the mystery of the reason for its own existence.', TO_DATE('2018-03-23', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sherlock holmes', 2009, 'Guy Ritchie''s directorial style might not be quite the best fit for an update on the legendary detective, but Sherlock Holmes benefits from the elementary appeal of a strong performance by Robert Downey, Jr.', TO_DATE('2009-12-08', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sherlock holmes a game of shadows', 2011, 'Sherlock Holmes: A Game of Shadows is a good yarn thanks to its well-matched leading men but overall stumbles duplicating the well-oiled thrills of the original.', TO_DATE('2011-12-08', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sherpa', 2015, 'A heartbreaking story told with tremendous narrative and visual skill, Sherpa exposes the audience to a side of Mount Everest that many have never seen or considered.', TO_DATE('2015-07-14', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sherrybaby', 2006, 'Maggie Gyllenhaal delivers riveting performance as a recovering drug addict in a depressing and not entirely believable movie.', TO_DATE('2006-01-23', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shes all that', 1999, 'Despite its charming young leads, She''s All That can''t overcome its predictable, inconsistently funny script.', TO_DATE('1999-01-29', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shes funny that way', 2014, 'She''s Funny That Way is an affectionate, talent-filled throwback to screwball comedies of old -- which makes it even more frustrating that the laughs are disappointingly few and far between.', TO_DATE('2014-08-29', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shes gotta have it', 2000, 'With She''s Gotta Have It, Spike Lee delivered his bracing first shot across Hollywood''s bow -- and set the template for the groundbreaking act to follow.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shes having a baby', 2000, 'Kevin Bacon and Elizabeth McGovern struggle to sustain a spark in She''s Having a Baby, a blasé adult romance that lacks the specificity and style of writer-director John Hughes'' more successful forays into teenage angst.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shes out of my league', 2010, 'She''s Out of My League has moments of humor and insight, but it''s bogged down by excessive vulgarity and cartoonishness.', TO_DATE('2010-03-08', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shes the man', 2006, 'Shakespeare''s wit gets lost in translation with She''s the Man''s broad slapstick, predictable jokes, and unconvincing plotline.', TO_DATE('2006-03-10', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shine', 2000, 'Featuring a strong performance from Geoffrey Rush, Shine succeeds in telling a compelling, inspirational story without resorting to cheap sentimentality.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shine a light', 2008, 'It may offer little new for fans, but Martin Scorsese''s document of the Rolling Stones'' electrifying live show should provide satisfaction to audiences.', TO_DATE('2008-02-07', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the shining', 2000, 'Though it deviates from Stephen King''s novel, Stanley Kubrick''s The Shining is a chilling, often baroque journey into madness -- exemplified by an unforgettable turn from Jack Nicholson.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the shipping news', 2001, 'Though solidly made and acted, The Shipping News is rather heavy-handed and dull, especially given the nature of its protagonist.', TO_DATE('2001-12-13', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shirkers', 2018, 'Shirkers uses one woman''s interrogation of a pivotal personal disappointment to offer affecting observations on creativity, lost opportunity, and coming to terms with the past.', TO_DATE('2018-01-23', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shirley', 2020, 'Elevated by outstanding work from Elisabeth Moss, Shirley pays tribute to its subject''s pioneering legacy with a biopic that ignores the commonly accepted boundaries of the form.', TO_DATE('2020-01-25', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shock and awe', 2017, 'Shock and Awe has a worthy story to tell and some fine actors trying to bring it to life; unfortunately, the end results are still as derivative as they are dramatically inert.', TO_DATE('2017-10-02', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shocker', 2002, 'With an intriguing enough premise and horror legend Wes Craven on writer-director duty, the real Shocker here is just how lame the end results turned out to be.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sholem aleichem laughing in the darkness', 2011, 'Sholem Aleichem: Laughing in the Darkness serves as an effective primer on its subject, as well as an evocative portrait of the era in which he lived.', TO_DATE('2011-05-28', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shoot em up', 2007, 'As preposterous and over-the-top as Shoot ''Em Up may be, its humor and non-stop action make for a very enjoyable film.', TO_DATE('2007-07-31', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shooter', 2007, 'With an implausible story and numerous plot holes, Shooter fails to distinguish itself from other mindless action-thrillers.', TO_DATE('2007-03-10', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shooting the mafia', 2019, 'It may not peer as closely or inquisitively as it could have, but Shooting the Mafia pays affectionate tribute to an important -- and fascinating -- subject.', TO_DATE('2019-01-26', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the shootist', 2001, 'Simple in story while sophisticated in texture, The Shootist is a fittingly elegiac swan song for one of Hollywood''s most iconic stars.', TO_DATE('2001-08-04', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the shop around the corner', 2000, 'Deftly directed by Ernst Lubitsch from a smart, funny script by Samson Raphaelson, The Shop Around the Corner is a romantic comedy in the finest sense of the term.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shopgirl', 2005, 'Shopgirl is precariously slight, but it has some intriguing moments, and Danes is luminous.', TO_DATE('2005-09-08', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shoplifters manbiki kazoku', 2018, 'Understated yet ultimately deeply affecting, Shoplifters adds another powerful chapter to director Hirokazu Koreeda''s richly humanistic filmography.', TO_DATE('2018-05-14', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('short cut to nirvana kumbh mela', 2004, 'Short on depth but amazingly insightful, this glimpse into one of the world''s largest spritual gatherings is worth viewing for the eye-opening experience alone.', TO_DATE('2004-11-19', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('short term 12', 2013, 'Short Term 12 is an emphatic, revealing drama that pulls audiences into the perspective of neglected youths.', TO_DATE('2013-03-10', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shorts the adventures of the wishing rock', 2009, 'Shorts has imagination and energy, but most viewers beyond elementary school will likely tire of the kiddie humor and sensory overload.', TO_DATE('2009-08-10', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shot caller', 2017, 'Shot Caller''s weakness for action movie clichés is capably offset by strong work from Nikolaj Coster-Waldau in the central role.', TO_DATE('2017-06-17', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shotgun stories', 2007, 'Thanks to a talented cast and its uncommon depth, Nichols'' debut manages to rise above its overly familiar plot.', TO_DATE('2007-10-12', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('show dogs', 2018, 'Show Dogs may entertain very young viewers, but for anyone else, it threatens the cinematic equivalent of a rolled-up newspaper on the snout.', TO_DATE('2018-05-17', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('showgirls', 2000, 'Vile, contemptible, garish, and misogynistic -- and that might just be exactly Showgirls'' point.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shrek', 2000, 'While simultaneously embracing and subverting fairy tales, the irreverent Shrek also manages to tweak Disney''s nose, provide a moral message to children, and offer viewers a funny, fast-paced ride.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shrek 2', 2003, 'It may not be as fresh as the original, but topical humor and colorful secondary characters make Shrek 2 a winner in its own right.', TO_DATE('2003-12-15', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shrek the third', 2007, 'Shrek the Third has pop culture potshots galore, but at the expense of the heart, charm, and wit that made the first two Shreks classics.', TO_DATE('2007-05-06', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shrek forever after', 2010, 'While not without its moments, Shrek Forever After too often feels like a rote rehashing of the franchise''s earlier entries.', TO_DATE('2010-04-22', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('shut in', 2016, 'Fatally undermined by a clichéd, confused plot and a total absence of thrills, Shut In wastes its talented cast -- and viewers'' time.', TO_DATE('2016-11-08', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('siberia', 2018, 'Icily inhospitable to compelling performances or a sensible narrative, Siberia offers audiences a harsh and seemingly interminable exile from entertainment.', TO_DATE('2018-07-08', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sicario', 2015, 'Led by outstanding work from Emily Blunt and Benicio del Toro, Sicario is a taut, tightly wound thriller with much more on its mind than attention-getting set pieces.', TO_DATE('2015-05-19', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sicario day of the soldado', 2018, 'Though less subversive than its predecessor, Sicario: Day of the Soldado succeeds as a stylish, dynamic thriller -- even if its amoral machismo makes for grim viewing.', TO_DATE('2018-06-21', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sicko', 2007, 'Driven by Michael Moore''s sincere humanism, Sicko is a devastating, convincing, and very entertaining documentary about the state of America''s health care.', TO_DATE('2007-05-19', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('siddharth', 2013, 'Siddharth takes an achingly compassionate and deeply unsettling look at all-too-common circumstances in modern-day India.', TO_DATE('2013-10-22', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('side by side', 2012, 'Keanu Reeves proves a groovy guide through this informative exploration of how technology is transforming cinema, with an even-handed defense for both the old and the new.', TO_DATE('2012-04-26', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('side effects', 2013, 'A smart, clever thriller with plenty of disquieting twists, Side Effects is yet another assured effort from director Steven Soderbergh.', TO_DATE('2013-01-24', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sideways', 2004, 'Charming, thoughtful, and often funny, Sideways is a decidedly mature road trip comedy full of excellent performances.', TO_DATE('2004-09-12', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sierra burgess is a loser', 2018, 'Sierra Burgess Is a Loser, but her movie''s okay - largely thanks to Shannon Purser''s work in the title role, which is strong enough to counter an uneven narrative.', TO_DATE('2018-09-06', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sightseers', 2012, 'Director Ben Wheatley and writer-stars Alice Lowe and Steve Oram deliver a wicked road trip movie that successfully walks the line between dark comedy and horror.', TO_DATE('2012-05-24', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the signal', 2007, 'The Signal is gruesome, funny, and has big thoughts about society, but those disparate elements fail to come together convincingly.', TO_DATE('2007-01-26', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('signs', 2002, 'With Signs, Shyamalan proves once again an expert at building suspense and giving audiences the chills.', TO_DATE('2002-07-21', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('silence', 2016, 'Silence ends Martin Scorsese''s decades-long creative quest with a thoughtful, emotionally resonant look at spirituality and human nature that stands among the director''s finest works.', TO_DATE('2016-12-10', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the silence of the lambs', 1991, 'Director Jonathan Demme''s smart, taut thriller teeters on the edge between psychological study and all-out horror, and benefits greatly from stellar performances by Anthony Hopkins and Jodie Foster.', TO_DATE('1991-02-13', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('silent hill', 2006, 'Silent Hill is visually impressive, but as with many video game adaptations, it''s plagued by inane dialogue, a muddled plot, and an overlong runtime.', TO_DATE('2006-04-20', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('silent hill revelation', 2012, 'Mediocre effort even by the standards of video game adaptations, Silent Hill: Revelation 3D features weak characters and an incomprehensible plot with a shortage of scares.', TO_DATE('2012-10-25', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('silent house', 2012, 'Silent House is more technically proficient and ambitious than most fright-fests, but it also suffers from a disappointing payoff.', TO_DATE('2012-01-03', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('silent light stellet licht', 2010, 'Silent Light demands patience -- and rewards willing viewers with a compassionate and beautifully filmed look at the human condition.', TO_DATE('2010-01-15', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('silent running', 1972, 'It doesn''t fulfill the potential of its ambitious themes, butSilent Running stands as a decidedly unique type of sci-fi journey marked by intimate character work and a melancholic mood.', TO_DATE('1972-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('silver city', 2004, 'Heavy-handed and often dull.', TO_DATE('2004-08-15', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('silver linings playbook', 2012, 'Silver Linings Playbook walks a tricky thematic tightrope, but David O. Russell''s sensitive direction and some sharp work from a talented cast gives it true balance.', TO_DATE('2012-09-10', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('silverado', 2000, 'Boasting rich detail and well-told story, Silverado is a rare example of an ''80s Hollywood Western done right.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('simon birch', 1998, 'Overly mushy; tries too hard to pull at the heart-strings.', TO_DATE('1998-09-11', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('simon killer', 2012, 'Though its bleak themes may be off-putting for some, Simon Killer is an engrossing, effective character study of a brutal, enigmatic figure.', TO_DATE('2012-01-21', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('simon sez', 2000, 'Simon Sez no matter how starved you are for something to watch, there has to be a better option than this dreadfully misguided action thriller.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('simone', 2002, 'The satire in S1m0ne lacks bite, and the plot isn''t believable enough to feel relevant.', TO_DATE('2002-08-14', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('simpatico', 2000, 'Critics say Simpatico''s lengthy plot is too unfocused; the movie becomes confusing and tedious to watch.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a simple plan', 2000, 'A riveting crime thriller full of emotional tension.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('simply irresistible', 1999, 'Simply Irresistible is simply not.', TO_DATE('1999-02-05', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the simpsons movie', 2007, 'The Simpsons Movie contains the hearty laughs, biting satire, and honest portrayal of an American family that makes the show so popular. And it boasts slicker animation and polished writing that hearkens back to the show''s glory days.', TO_DATE('2007-07-21', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sin city', 2005, 'Visually groundbreaking and terrifically violent, Sin City brings the dark world of Frank Miller''s graphic novel to vivid life.', TO_DATE('2005-03-17', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sin noticias de dios dont tempt me', 2001, 'More Hellish than it is Heavenly, Agustín Díaz Yanes'' black comedy about the Earthly duel between two angels doesn''t have enough genuine laughs to support its far-fetched premise.', TO_DATE('2001-12-28', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sinbad legend of the seven seas', 2003, 'Competent, but not magical.', TO_DATE('2003-06-18', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sing', 2016, 'Sing delivers colorfully animated, cheerfully undemanding entertainment with a solid voice cast and a warm-hearted -- albeit familiar -- storyline that lives up to its title.', TO_DATE('2016-09-11', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sing street', 2016, 'Sing Street is a feel-good musical with huge heart and irresistible optimism, and its charmimg cast and hummable tunes help to elevate its familiar plotting.', TO_DATE('2016-01-25', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sing your song', 2011, 'Sing Your Song takes an absorbing -- if decidedly non-critical -- look at an incredible show business career and admirable public life.', TO_DATE('2011-01-21', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('singin in the rain', 2000, 'Clever, incisive, and funny, Singin'' in the Rain is a masterpiece of the classical Hollywood musical.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the singing detective', 2003, 'Delightful performance from Robert Downey Jr. can''t save The Singing Detective''s transition from TV to the big screen.', TO_DATE('2003-02-08', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('single white female', 1992, 'Single White Female benefits from a pair of outstanding leads, neither of whom are well served by a storyline that wavers between thrillingly tense and utterly ridiculous.', TO_DATE('1992-08-14', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sinister 2', 2015, 'Sinister 2 has a few ingredients that will be familiar to fans of the original; unfortunately, in this slapdash second installment, none of them are scary anymore.', TO_DATE('2015-08-19', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sinister', 2012, 'Its plot hinges on typically implausible horror-movie behavior and recycles countless genre cliches, but Sinister delivers a surprising number of fresh, diabolical twists.', TO_DATE('2012-03-11', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sir no sir', 2006, 'A powerful reflection on a pivotal era, from a viewpoint seldom visited, this documentary hits home, especially with its relevance to current events.', TO_DATE('2006-02-15', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sister act', 1992, 'Looking for a sweet musical comedy about a witness to a crime hiding out from killers in a convent? There''s nun better than Sister Act.', TO_DATE('1992-05-29', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sister act 2 back in the habit', 1993, 'Sister Act is off-key in this reprise, fatally shifting the spotlight from Whoopi Goldberg to a less compelling ensemble of pupils and trading its predecessor''s sharp comedy for unconvincing sentiment.', TO_DATE('1993-12-10', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sisterhood of the traveling pants', 2005, 'This adaptation of a beloved novel charms with its heartwarming tale of friendship and young adulthood; realistic portrayals of the lives of teenage girls lend the comedy-drama sincerity, and may capture hearts outside the female-centric demographic.', TO_DATE('2005-05-24', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sisterhood of the traveling pants 2', 2008, 'The workable chemistry among the four leads combined with the enriching message make for a winning Sisterhood of the Traveling Pants 2.', TO_DATE('2008-08-01', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sisters', 2000, 'Clever yet clearly indebted to the masters of the genre, Sisters offers an early glimpse of De Palma at his stylishly crafty peak.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sisters', 2015, 'Sisters'' sharp blend of pathos and vulgarity, along with Tina Fey and Amy Poehler''s effervescent chemistry, are more than enough to make up for the handful of laughs this coming-of-age comedy leaves on the table.', TO_DATE('2015-12-10', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sita sings the blues', 2008, 'A tour de force for filmmaker Nina Paley, Sita Sings the Blues gives the Ramayana its animated due with a visually vibrant, dazzlingly imaginative triumph.', TO_DATE('2008-06-23', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('six days seven nights', 1998, 'A generally enjoyable, if completely forgettable piece of Hollywood fluff.', TO_DATE('1998-06-12', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('six degrees of separation', 1993, 'Though it betrays its theatrical roots, Six Degrees of Separation largely succeeds thanks to astute direction and fine performances -- particularly from an against-type Will Smith.', TO_DATE('1993-12-10', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sixteen candles', 1984, 'Significantly more mature than the teen raunch comedies that defined the era, Sixteen Candles is shot with compassion and clear respect for its characters and their hang-ups.', TO_DATE('1984-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the 6th day', 2000, 'This offering from Arnold Schwarzenegger contains an intriguing, disturbing premise, but the film''s execution is too routine and formulaic to make good use of it.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sixth sense', 1999, 'M Night Shayamalan''s The Sixth Sense is a twisty ghost story with all the style of a classical Hollywood picture, but all the chills of a modern horror flick.', TO_DATE('1999-08-06', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('skate kitchen', 2018, 'Skate Kitchen takes a beguiling slice-of-life approach to its characters, approaching its timely themes with a light hand that serves the story well.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sketches of frank gehry', 2005, 'This affectionate, casually framed portrait of the acclaimed architect reveals him to be an engaging, likeable subject.', TO_DATE('2005-09-21', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('skills like this', 2007, 'Though Skills Like This has little to distinguish, director Monty Miranda shows flashes of wit and talent.', TO_DATE('2007-03-10', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('skin', 2018, 'Skin could stand to go a bit deeper below its surface, but a worthy story and a committed performance from Jamie Bell make this timely drama well worth a watch.', TO_DATE('2018-09-09', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('skins', 2002, 'Though at times melodramatic, Skins'' harsh depiction of life on the reservation is an eye-opener.', TO_DATE('2002-04-08', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('skinwalkers', 2007, 'Skinwalkers is an atrociously-acted project whose unoriginal and ineptly-staged action sequences remind viewers of far better werewolf and action movies.', TO_DATE('2007-08-09', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the skulls', 2000, 'The Skulls is full of nonsense and empty of good script and plot.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sky captain and the world of tomorrow', 2004, 'Sky Captain and the World of Tomorrow is slim on plot and characterization, but the visuals more than make up for it.', TO_DATE('2004-01-20', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('skyfall', 2012, 'Sam Mendes brings Bond surging back with a smart, sexy, riveting action thriller that qualifies as one of the best 007 films to date.', TO_DATE('2012-10-12', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('skyline', 2010, 'A middling sci-fi entry, Skyline offers proof that solid special effects alone cannot overcome a flat storyline filled with uninspired dialogue.', TO_DATE('2010-11-10', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('skyscraper', 2018, 'Well-cast yet derivative, Skyscraper isn''t exactly a towering action thriller feat, but it''s solidly constructed enough to stand among the genre''s more mildly diverting features.', TO_DATE('2018-07-10', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('slacker', 1991, 'Slacker rests its shiftless thumb on the pulse of a generation with fresh filmmaking that captures the tenor of its time while establishing a benchmark for 1990s indie cinema.', TO_DATE('1991-07-05', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('slackers', 2002, 'Another teen comedy with little on its mind but moving to the next gross-out gag, Slackers strains for laughs and features grating characters.', TO_DATE('2002-01-18', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the slammin salmon', 2009, 'Potty humor and juvenile antics keep this workplace comedy from being particularly funny or memorable.', TO_DATE('2009-03-19', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('slap shot', 2002, 'Raunchy, violent, and very funny, Slap Shot is ultimately set apart by a wonderful comic performance by Paul Newman.', TO_DATE('2002-09-20', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('slash', 2016, 'An uncommonly smart, empathetic, and well-acted coming of age story, Slash approaches oft-misunderstood characters and titillating themes with wit and grace.', TO_DATE('2016-03-14', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the slaughter rule', 2002, 'A bleak but original indie, The Slaughter Rule benefits from outstanding performances by Ryan Gosling and David Morse.', TO_DATE('2002-04-08', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('slaughterhouse rulez', 2018, 'An uneven blend of horror and comedy that fails to satisfy on either front, Slaughterhouse Rulez aims for B-movie fun but doesn''t make the grade.', TO_DATE('2018-10-30', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('slay the dragon', 2019, 'Slay the Dragon takes a suitably outraged -- but ultimately optimistic -- look at modern-day gerrymandering that doubles as a heartfelt call to action.', TO_DATE('2019-04-28', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('slc punk', 1998, 'Merging anarchic spirit with straightforward melodrama, SLC Punk is a hit-and-miss odyssey of youthful rebellion elevated by Matthew Lillard''s dramatically potent star turn.', TO_DATE('1998-06-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sleep dealer', 2008, 'Sleep Dealer''s depth and energy are almost enough to overcome a shaky screenplay and pedestrian acting.', TO_DATE('2008-01-25', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sleep furiously', 2009, 'This poetic and tender portrait of a Welsh village is a slow moving yet elegantly accomplished British documentary.', TO_DATE('2009-05-21', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sleep tight', 2012, 'The strong lead performance, clever plot turns, and the unsettling ending makes Sleep Tight worth stalking.', TO_DATE('2012-07-06', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sleepaway camp', 2002, 'Sleepaway Camp is a standard teen slasher elevated by occasional moments of John Waters-esque weirdness and a twisted ending.', TO_DATE('2002-04-03', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sleeping beauty', 2011, 'Sleeping Beauty''s provocative premise and luminous art design is hampered by a clinical, remote presentation, delivering boredom and shock in equal measure.', TO_DATE('2011-05-11', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sleeping with other people', 2015, 'Sleeping with Other People has likable leads and flashes of inspiration, but seems unwilling or unable to surround them with the truly subversive rom-com they deserve.', TO_DATE('2015-01-25', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sleeping with the enemy', 1991, 'A game Julia Roberts gives it her all, but Sleeping with the Enemy is one stalker thriller that''s unlikely to inspire many obsessions of its own.', TO_DATE('1991-02-08', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sleepless', 2017, 'Sleepless wastes a talented cast -- and solid source material -- on a tired crime drama whose clichés rapidly outnumber its thrills.', TO_DATE('2017-01-12', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sleepover', 2004, '''Tween girls will enjoy this sugar coated fluff, but others will find Sleepover a snooze.', TO_DATE('2004-06-19', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sleepwalk with me', 2012, 'Laugh-out-loud funny and endearingly messy, Sleepwalk with Me overcomes its tonal inconsistencies to deliver a sweetly melancholic, amiably reassuring indie crowd-pleaser.', TO_DATE('2012-01-25', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sleepwalking', 2008, 'Despite some sharp performances, Sleepwalking suffers from a grimness of tone and sluggish pacing.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sleepy hollow', 1999, 'It isn''t Tim Burton''s best work, but Sleepy Hollow entertains with its stunning visuals and creepy atmosphere.', TO_DATE('1999-11-19', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sleight', 2016, 'Sleight subverts genre norms, delivering a smart and well-acted -- if ultimately somewhat frustrating -- magical mystery.', TO_DATE('2016-01-24', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('slender man', 2018, 'Slender Man might be thin, but he''s positively robust compared to the flimsy assortment of scares generated by the would-be chiller that bears his name.', TO_DATE('2018-08-09', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sleuth', 2007, 'Sleuth is so obvious and coarse, rather than suspenseful and action-packed, that it does nothing to improve on the original version', TO_DATE('2007-07-21', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sliding doors', 1998, 'Despite the gimmicky feel of the split narratives, the movie is watch-able due to the winning performances by the cast.', TO_DATE('1998-04-24', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sling blade', 1996, 'You will see what''s coming, but the masterful performances, especially Thornton''s, will leave you riveted.', TO_DATE('1996-11-27', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('slither', 2006, 'A slimy, B-movie homage oozing with affection for low-budget horror films, Slither is creepy and funny -- if you''ve got the stomach for it.', TO_DATE('2006-01-23', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sliver', 1993, 'Sliver is an absurd erotic thriller with technobabble and posits prime Sharon Stone as a professional book nerd.', TO_DATE('1993-05-21', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('slow burn', 2005, 'With wooden acting and hammy, overheated dialogue, Slow Burn isn''t so much a noir as it is a mediocre parody of one.', TO_DATE('2005-09-22', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('slow west', 2015, 'Slow West serves as an impressive calling card for first-time writer-director John M. Maclean -- and offers an inventive treat for fans of the Western.', TO_DATE('2015-01-26', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('slumdog millionaire', 2008, 'Visually dazzling and emotionally resonant, Slumdog Millionaire is a film that''s both entertaining and powerful.', TO_DATE('2008-08-30', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('slums of beverly hills', 1998, 'Warm, real, and hilarious.', TO_DATE('1998-08-14', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('small soldiers', 1998, 'Small Soldiers has plenty of visual razzle-dazzle, but the rote story proves disappointingly deficient in director Joe Dante''s trademark anarchic spirit.', TO_DATE('1998-07-10', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('small time crooks', 2000, 'Woody Allen rises from his recent slump with Small Time Crooks. A simple, funny movie, Crooks proves Allen still has the touch that made his name synonymous with off-beat comedy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('small town crime', 2017, 'Small Town Crime makes for a satisfying modern noir outing, largely thanks to the all-around impressive efforts of a solidly stocked cast led by John Hawkes.', TO_DATE('2017-03-12', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('smallfoot', 2018, 'Smallfoot offers a colorful distraction that should keep younger viewers entertained - and a story whose message might even resonate with older audiences.', TO_DATE('2018-09-19', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('smashed', 2012, 'Smashed resists the temptation to play up its serious subject matter for high theatrics, opting instead to let its gentle tone and Mary Elizabeth Winstead''s marvelous performance carry the day.', TO_DATE('2012-01-23', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('smiley face', 2007, 'Although many of the jokes have been done before, Anna Faris''s bright performance and Gregg Araki''s sharp direction make Smiley Face more than your average stoner comedy.', TO_DATE('2007-01-24', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('smoke signals', 1998, 'Smoke Signals tells a familiar story from an underrepresented point of view, proving that a fresh perspective can help subvert long-established expectations.', TO_DATE('1998-06-26', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('smokey and the bandit', 2002, 'Not much in the head but plenty beneath the hood, Smokey and the Bandit is infectious fun with plenty of car wrecks to keep your eyes glued.', TO_DATE('2002-04-23', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('smokin aces', 2007, 'A violent mess of a movie, Smokin'' Aces has some Quentin Tarantino''s style but not much of his wit or humor.', TO_DATE('2007-01-04', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('smurfs the lost village', 2017, 'Smurfs: The Lost Village may satisfy very young viewers and hardcore Smurfaholics, but its predictable story and bland animation continue the franchise''s recent mediocre streak.', TO_DATE('2017-03-26', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('snabba cash easy money', 2010, 'Snabba Cash (Easy Money) cuts a cube of Nordic noir whose taut storytelling packs an extra dose of hard-hitting heft.', TO_DATE('2010-09-12', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('snake eyes', 1998, 'Snake Eyes has a number of ingredients that promise a trashy fun time; unfortunately, they''re lost in an energetic and stylish thriller with a frustratingly hollow core.', TO_DATE('1998-08-07', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('snakes on a plane', 2006, 'Snakes on a Plane lives up to its title, featuring snakes on a plane. It isn''t perfect, but then again, it doesn''t need to be.', TO_DATE('2006-08-16', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the snapper', 2000, 'Warm, funny, and populated by easily relatable characters, The Snapper is a compulsively watchable slice-of-life dramedy with much to recommend.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('snatch', 2000, 'Though perhaps a case of style over substance, Guy Ritchie''s second crime caper is full of snappy dialogue, dark comedy, and interesting characters.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('snatched', 2017, 'Snatched has a pair of terrifically talented stars, but their presence isn''t enough to compensate for this rote comedy''s threadbare plot and scattershot laughs.', TO_DATE('2017-05-09', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('snatchers', 2019, 'Snatchers'' practical effects and strong writing come together to create a sci-fi comedy that''s fun, frenetic, and at times, freakin'' crazy (in the best way).', TO_DATE('2019-03-12', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sneakers', 1992, 'There isn''t much to Sneakers plot and that''s more than made up for with the film''s breezy panache and hi-tech lingo.', TO_DATE('1992-09-09', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('snitch', 2013, 'Though it features one of Dwayne Johnson''s more thoughtful performances, the presentation of Snitch''s underlying message is muddled by lackluster storytelling and some tonal inconsistencies.', TO_DATE('2013-02-19', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('snow angels', 2007, 'With fine acting and considerable emotional depth, Snow Angels aptly captures the highs, and especially the lows of human relationships.', TO_DATE('2007-01-20', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('snow day', 2000, 'Weak assembly of characters and story lines made this movie forgettable and silly.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('snow dogs', 2002, 'A mediocre live-action children''s movie, Snow Dogs is filled with cliched dialogue, tiresome pratfalls, and stale fish-out-of-water jokes.', TO_DATE('2002-01-08', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('snow falling on cedars', 2000, 'Though Snow Falling on Cedars is beautiful to look at, critics say the story becomes dull and tedious to sit through.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('snow white and the huntsman', 2012, 'While it offers an appropriately dark take on the fairy tale that inspired it, Snow White and the Huntsman is undone by uneven acting, problematic pacing, and a confused script.', TO_DATE('2012-05-28', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('snowden', 2016, 'Snowden boasts a thrilling fact-based tale and a solid lead performance from Joseph Gordon-Levitt, even if director Oliver Stone saps the story of some of its impact by playing it safe.', TO_DATE('2016-09-09', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('snowpiercer', 2013, 'Snowpiercer offers an audaciously ambitious action spectacular for filmgoers numb to effects-driven blockbusters.', TO_DATE('2013-07-22', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('so close', 2003, 'This HK actioner oozes with style.', TO_DATE('2003-04-24', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('so goes the nation', 2006, 'Intelligent and even-handed, ...So Goes the Nation takes an impressively comprehensive look behind the scenes of the modern American election process.', TO_DATE('2006-09-27', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('so i married an axe murderer', 2000, 'So I Married an Axe Murderer is a unique rom-com with moments of heart and hilarity -- even if they''re all too scattered to cohere into a consistent whole.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('so much so fast', 2006, 'A poignant documentary about terminal illness that''s as moving as it is honest.', TO_DATE('2006-01-24', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('soapdish', 1991, 'Soapdish may not be as addictive as the serialized dramas it''s spoofing, but a talented cast helps make this affectionate sendup feel fresh.', TO_DATE('1991-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sob', 2002, 'A sustained blast of unbridled vitriol from writer-director Blake Edwards, S.O.B. is one of the blackest -- and most consistently funny -- Hollywood satires ever put to film.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('socrates', 2019, 'Brought brilliantly to life by Christian Malheiros'' soulful performance, Socrates uses one boy''s story to check a nation''s pulse.', TO_DATE('2019-03-13', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('solace', 2015, 'Solace boasts a talented cast and a somewhat intriguing premise, but they''re outweighed by a plodding story that teeters between tired clichés and ludicrous twists.', TO_DATE('2015-09-21', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('solaris', 2002, 'Slow-moving, cerebral, and ambiguous, Solaris is not a movie for everyone, but it offers intriguing issues to ponder.', TO_DATE('2002-11-18', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a soldiers story', 2000, 'A meticulously-crafted murder mystery with incisive observations about race in America, A Soldier''s Story benefits from a roundly excellent ensemble and Charles Fuller''s politically urgent screenplay.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('solitary man', 2009, 'Built around a singularly unpleasant main character, Solitary Man needed a flawless central performance to succeed -- and Michael Douglas delivers.', TO_DATE('2009-10-18', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('solo', 1996, 'Featuring hammy performances and bland characters, Solo is an all too straightforward actioner that''s both predictable and instantly forgettable.', TO_DATE('1996-08-23', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('solo a star wars story', 2018, 'A flawed yet fun and fast-paced space adventure, Solo: A Star Wars Story should satisfy newcomers to the saga as well as longtime fans who check their expectations at the theater door.', TO_DATE('2018-05-15', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the soloist', 2009, 'Though it features strong performances by its lead players, a lack of narrative focus prevents The Soloist from hitting its mark.', TO_DATE('2009-04-15', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('solomon kane', 2009, 'Solomon Kane''s formulaic and bleak narrative is overcome by an entertaining, straightforward adherence to its genre, exciting gore, and a gratifying lead performance by James Purefoy.', TO_DATE('2009-09-14', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('some kind of beautiful', 2015, 'Stranding Pierce Brosnan as a charmless cad, this tone-deaf romantic comedy is Some Kind Of something, but it definitely isn''t beautiful.', TO_DATE('2015-08-02', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('some kind of wonderful', 2000, 'Some Kind of Wonderful is above-average ''80s teen fare for people who need as much John Hughes in their lives as possible.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('some like it hot', 2000, 'Some Like It Hot: A spry, quick-witted farce that never drags.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('some velvet morning', 2013, 'Some Velvet Morning marks writer-director Neil LaBute''s welcome return to the mode of challenging chamber piece, but this misanthropic two-hander is too slight to produce the same bite as the filmmakers'' best works.', TO_DATE('2013-04-30', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('somebody up there likes me', 2012, 'Somebody Up There Likes Me proves there''s still life left in the charmingly offbeat indie dramedy, largely thanks to the efforts of its immensely likable cast.', TO_DATE('2012-03-13', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('someone great', 2019, 'What Someone Great lacks in originality it makes up for in relatability and charm, thanks in large part to the undeniable chemistry between its talented leads.', TO_DATE('2019-04-18', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('someone to watch over me', 2000, 'Its plot is sometimes hard to swallow, but some fine acting and director Ridley Scott''s stylish visual flair make Someone to Watch Over Me an engaging police thriller.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('somers town', 2008, 'Shane Meadows hits the spot with this short but sweet slice of good natured comedy, surprisingly, as it''s essentially an extended black & white advert for a train station.', TO_DATE('2008-04-30', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('somersault', 2004, 'A poignant coming-of-age tale marked by a breakout lead performance from Abbie Cornish and a successful directorial debut from Cate Shortland.', TO_DATE('2004-04-21', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('something borrowed', 2011, 'In spite of solid performances from Kate Hudson and John Krasinski, Something Borrowed is an unpleasant misfire that lives down to its title.', TO_DATE('2011-04-23', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('something in the air', 2012, 'Insightful, solidly acted, and smartly filmed, Something in the Air skillfully captures the idealism of youth without falling back on cheap nostalgia.', TO_DATE('2012-09-17', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('something new', 2006, 'Something New tackles serious questions about race and interracial relationships with genuine appeal and an alluring romance that develops as naturally as the plot.', TO_DATE('2006-01-23', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('something to talk about', 1995, 'Small-town gossip and a battle of the sexes should really add up to more than Something to Talk About, especially with this much talent before the camera.', TO_DATE('1995-08-04', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('something wild', 2000, 'Boasting loads of quirky charm, a pair of likable leads, and confident direction from Jonathan Demme, Something Wild navigates its unpredictable tonal twists with room to spare.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('somethings gotta give', 2003, 'Though it occasionally stumbles into sitcom territory, Something''s Gotta Give is mostly a smart, funny romantic comedy, with sharp performances from Jack Nicholson, Diane Keaton, and Keanu Reeves.', TO_DATE('2003-12-04', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sometimes they come back', 2001, 'Tim Matheson''s gripping performance and a strong mood make Sometimes They Come Back an effective, if not wholly revelatory, Stephen King adaptation.', TO_DATE('2001-10-10', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('somewhere', 2010, 'It covers familiar territory for Sofia Coppola, but Somewhere remains a hypnotic, seductively pensive meditation on the nature of celebrity, anchored by charming performances from Stephen Dorff and Elle Fanning.', TO_DATE('2010-09-06', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sommersby', 1993, 'Sommersby stumbles as a consistently compelling mystery, but typically solid work from Jodie Foster and Richard Gere fuels an engaging romance.', TO_DATE('1993-02-05', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('son of a gun', 2014, 'Gritty, stylish, and smart, Son of a Gun serves up plenty of genre thrills while offering a refreshing change of pace for Ewan McGregor.', TO_DATE('2014-10-12', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('son of frankenstein', 2001, 'Boris Karloff''s final appearance as the Monster is a fitting farewell before the series descended into self-parody.', TO_DATE('2001-11-29', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('son of god', 2014, 'The faithful may find their spirits raised, but on purely cinematic terms, Son of God is too dull and heavy-handed to spark much fervor.', TO_DATE('2014-02-26', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('son of rambow', 2007, 'Undeniable heart and charming young leads save the film''s nostalgic storyline from suffering at the hands predictability.', TO_DATE('2007-01-23', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('son of saul', 2015, 'Grimly intense yet thoroughly rewarding, Son of Saul offers an unforgettable viewing experience -- and establishes director László Nemes as a talent to watch.', TO_DATE('2015-05-14', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('son of the mask', 2005, 'Overly frantic, painfully unfunny, and sorely missing the presence of Jim Carrey.', TO_DATE('2005-02-10', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('son of the pink panther', 2000, 'Roberto Benigni is an undeniably gifted physical comic, but the misguided Son of Pink Panther betrays his energetic efforts with a painfully unfunny script.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('avaze gonjeshkha the song of sparrows', 2008, 'A heartfelt, affecting parable, The Song of Sparrows is another gem from Iranian director Majid Majidi.', TO_DATE('2008-02-13', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('song of the sea', 2014, 'Song of the Sea boasts narrative depth commensurate with its visual beauty, adding up to an animated saga overflowing with family-friendly riches.', TO_DATE('2014-10-17', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('song one', 2014, 'Song One has plenty of earnest charm, but that isn''t enough to overcome its slight, familiar story.', TO_DATE('2014-01-21', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('song to song', 2017, 'As visually sumptuous as it is narratively spartan, Terrence Malick''s Song to Song echoes elements of the writer-director''s recent work -- for better and for worse.', TO_DATE('2017-03-11', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('songcatcher', 2000, 'The story may be a bit too melodramatic, but great performances abound in Songcatcher. The real reason to see the movie, however, is the hypnotic music.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('songs my brothers taught me', 2015, 'A naturalistic drama that quietly earns its emotional resonance, Songs My Brothers Taught Me further establishes writer-director Chloé Zhao as a gifted filmmaker and empathetic storyteller.', TO_DATE('2015-01-28', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sonic the hedgehog', 2020, 'Fittingly fleet and frequently fun, Sonic the Hedgehog is a video game-inspired adventure the whole family can enjoy -- and a fine excuse for Jim Carrey to tap into the manic energy that launched his career.', TO_DATE('2020-02-12', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sophies choice', 2000, 'Sophie''s Choice may be more sobering than stirring, but Meryl Streep''s Oscar-winning performance holds this postwar period drama together.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sorcerers apprentice', 2010, 'It has a likable cast and loads of CGI spectacle, but for all but the least demanding viewers, The Sorcerer''s Apprentice will be less than spellbinding.', TO_DATE('2010-07-09', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sorority boys', 2002, 'A sloppy fratboy movie, Sorority Boys offers up a parade of gross-out gags and sex jokes, while insulting and ogling women.', TO_DATE('2002-03-19', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sorority row', 2009, 'Though it''s slick and stylish, Sorority Row offers nothing new to the slasher genre and misses the mark both in its attempts at humor and thrills.', TO_DATE('2009-09-06', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sorry haters', 2005, 'Robin Wright Penn and Abdel Kechiche''s powerful performances aren''t enough to keep the increasingly unbalanced Sorry, Haters from tottering completely off its axis.', TO_DATE('2005-09-24', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sorry to bother you', 2018, 'Fearlessly ambitious, scathingly funny, and thoroughly original, Sorry to Bother You loudly heralds the arrival of a fresh filmmaking talent in writer-director Boots Riley.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('soul food', 2000, 'Much like the titular cuisine, Soul Food blends a series of savory ingredients to offer warm, generous helpings of nourishment and comfort.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('soul man', 2000, 'Critics had a whole lot less than a truckload of good loving for this woefully misguided take on race in ''80s America.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('soul plane', 2004, 'A raunchy sendup of Airplane! that never really takes off.', TO_DATE('2004-04-05', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('soul power', 2009, 'Featuring some incredible performances from many 70s soul legends, Soul Power is an exhilarating snap-shot of a bygone era.', TO_DATE('2009-02-13', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('soul surfer', 2011, 'There''s an amazing true story at the heart of Soul Surfer -- and unfortunately, it''s drowned by waves of Hollywood cheese.', TO_DATE('2011-03-28', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('soul survivors', 2000, 'Soul Survivors'' stock characters and utter lack of suspense gives viewers little reason to attempt deciphering the confusing plot.', TO_DATE('2000-06-01', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sound and fury', 2000, 'This documentary presents its opposing views in an even-handed yet emotionally engaging manner. Critics say it will provoke much thought, as well as emotions, in the audience.', TO_DATE('2000-10-25', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sound city', 2013, 'Smart, affectionate, and unabashedly sincere, Sound City pairs a great soundtrack with a well-argued ode to one of rock ''n'' roll''s most fondly remembered bygone eras.', TO_DATE('2013-01-19', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sound of music', 2000, 'Unapologetically sweet and maybe even a little corny, The Sound of Music will win over all but the most cynical filmgoers with its classic songs and irresistible warmth.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sound of noise', 2011, 'Sound of Noise is a raucous, irreverent comedy caper with good tunes and a romantic finish.', TO_DATE('2011-02-11', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a sound of thunder', 2005, 'Choppy logic and uneven performances are overshadowed by not-so-special effects that makes the suspension of disbelief a nearly impossible task.', TO_DATE('2005-08-31', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('soundwave', 2020, 'Smart, fun, and tightly assembled, Soundwave offers a welcome reminder that engaging sci-fi stories can be told without relying on blockbuster special effects.', TO_DATE('2020-04-27', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('source code', 2011, 'Finding the human story amidst the action, director Duncan Jones and charming Jake Gyllenhaal craft a smart, satisfying sci-fi thriller.', TO_DATE('2011-03-11', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('south park bigger longer uncut', 2000, 'Its jokes are profoundly bold and rude but incredibly funny at the same time.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('southbound', 2015, 'Southbound doesn''t entirely avoid the jarring shifts common to anthology films, but thanks to some thrilling twists and turns, this horror road movie is a surprisingly smooth ride.', TO_DATE('2015-09-19', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('southland tales', 2007, 'Southland Tales, while offering an intriguing vision of the future, remains frustratingly incoherent and unpolished.', TO_DATE('2007-09-24', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('southpaw', 2015, 'Jake Gyllenhaal delivers an impressively committed performance, but Southpaw beats it down with a dispiriting drama that pummels viewers with genre clichés.', TO_DATE('2015-06-17', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('southside with you', 2016, 'Southside With You looks back on a fateful real-life date with strong performances and engaging dialogue, adding up to a romance that makes for a pretty good date movie in its own right.', TO_DATE('2016-01-24', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('soylent green', 1973, 'While admittedly melodramatic and uneven in spots, Soylent Green ultimately succeeds with its dark, plausible vision of a dystopian future.', TO_DATE('1973-05-09', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('space cowboys', 2000, 'While the plot is overly cliched, the suberb acting by the stars (especially the tense interactions between Clint Eastwood and Tommy Lee Jones) and the spectacular special effects make this a movie worth seeing.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('space jam', 1996, 'While it''s no slam dunk, Space Jam''s silly, Looney Toons-laden slapstick and vivid animation will leave younger viewers satisfied -- though accompanying adults may be more annoyed than entertained.', TO_DATE('1996-11-15', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spaceballs', 2000, 'There''s fine spoofery and amusing characters in Spaceballs, though it''s a far cry from Mel Brooks'' peak era.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spaceship earth', 2020, 'Spaceship Earth achieves liftoff as an engaging behind-the-scenes record of an audacious experiment -- and settles into orbit as poignant proof of the power of a shared dream.', TO_DATE('2020-01-27', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spanglish', 2004, 'Paz Vega shines, and Adam Sandler gives a performance of thoughtfulness and depth, but Spanglish is ultimately undermined by sitcommy plotting and unearned uplift.', TO_DATE('2004-12-08', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the spanish prisoner', 1997, 'The Spanish Prisoner delivers just what fans of writer-director David Mamet expect: a smart, solidly constructed drama that keeps viewers guessing... and entertained along the way.', TO_DATE('1997-09-08', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spare parts', 2015, 'Spare Parts is effective enough to do in a pinch for inspirational sports drama fans - although most of them will have seen these story beats hit more powerfully before.', TO_DATE('2015-01-15', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sparkle', 2012, 'While undeniably melodramatic and old-fashioned, Sparkle transcends its formulaic trappings thanks to Salim Akil''s empathetic direction and strong performances from a committed cast.', TO_DATE('2012-08-15', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spartan', 2004, 'A good cast and Mamet''s mastery over the written language elevate an otherwise conventional thriller.', TO_DATE('2004-02-04', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spawn', 2000, 'Spawn is an overbearing, over-violent film that adds little to the comic book adaptation genre.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('special', 2006, 'This quirky indie comedy''s low budget is readily apparent, but it''s elevated by Michael Rapaport''s dedicated performance.', TO_DATE('2006-01-26', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('special correspondents', 2016, 'Feeble writing and two-dimensional characters make Special Correspondents an unsuccessful, embarrassing endeavor for creator Ricky Gervais.', TO_DATE('2016-04-22', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('species', 2000, 'Species shows flashes of the potential to blend exploitation and sci-fi horror in ingenious ways, but is ultimately mainly interested in flashing star Natasha Henstridge''s skin.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('species ii', 1998, 'Clumsily exploitative and sloppily assembled, Species II fails to clear the rather low bar set by its less-than-stellar predecessor.', TO_DATE('1998-04-10', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spectre', 2015, 'Spectre nudges Daniel Craig''s rebooted Bond closer to the glorious, action-driven spectacle of earlier entries, although it''s admittedly reliant on established 007 formula.', TO_DATE('2015-10-21', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('speed', 1994, 'A terrific popcorn thriller, Speed is taut, tense, and energetic, with outstanding performances from Keanu Reeves, Dennis Hopper, and Sandra Bullock.', TO_DATE('1994-06-10', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('speed 2 cruise control', 2000, 'Speed 2 falls far short of its predecessor, thanks to laughable dialogue, thin characterization, unsurprisingly familiar plot devices, and action sequences that fail to generate any excitement.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('speed racer', 2008, 'Overloaded with headache-inducing special effects, Speed Racer finds the Wachowskis focused on visual thrills at the expense of a coherent storyline.', TO_DATE('2008-04-28', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('speed sisters', 2015, 'Speed Sisters honors its incredible subjects with an absorbing stranger-than-fiction look at a real-life story that''s equal parts thought-provoking and purely entertaining.', TO_DATE('2015-05-12', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spenser confidential', 2020, 'While the buddy cops at the center of Spenser Confidential are plenty affable, the comedy never arrives as this half-hearted vehicle goes purely through the motions.', TO_DATE('2020-03-05', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sphere', 1998, 'Sphere features an A-level cast working with B-grade material, with a story seen previously in superior science-fiction films.', TO_DATE('1998-02-13', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spice world', 1998, 'Spice World''s lack of cohesive plot will likely lose most viewers, but for fans of the titular girl group there''s more than enough fun to be had in their wacky -- albeit superficial -- whirlwind of an adventure.', TO_DATE('1998-01-23', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spiderman far from home', 2019, 'A breezily unpredictable blend of teen romance and superhero action, Spider-Man: Far from Home stylishly sets the stage for the next era of the MCU.', TO_DATE('2019-06-27', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spiderman homecoming', 2017, 'Spider-Man: Homecoming does whatever a second reboot can, delivering a colorful, fun adventure that fits snugly in the sprawling MCU without getting bogged down in franchise-building.', TO_DATE('2017-06-29', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spiderman into the spiderverse', 2018, 'Spider-Man: Into the Spider-Verse matches bold storytelling with striking animation for a purely enjoyable adventure with heart, humor, and plenty of superhero action.', TO_DATE('2018-11-28', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spiderman', 2002, 'Not only does Spider-Man provide a good dose of web-swinging fun, it also has a heart, thanks to the combined charms of director Sam Raimi and star Tobey Maguire.', TO_DATE('2002-04-09', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spiderman 2', 2003, 'Boasting an entertaining villain and deeper emotional focus, this is a nimble sequel that improves upon the original.', TO_DATE('2003-12-15', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spiderman 3', 2007, 'Though there are more characters and plotlines, and the action sequences still dazzle, Spider-Man 3 nonetheless isn''t quite as refined as the first two.', TO_DATE('2007-04-19', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the spiderwick chronicles', 2008, 'The Spiderwick Chronicles is an entertaining children''s adventure, with heart and imagination to spare.', TO_DATE('2008-01-20', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spies in disguise', 2019, 'A cheerfully undemanding animated adventure that''s elevated by its voice cast, Spies in Disguise is funny, fast-paced, and family-friendly enough to satisfy.', TO_DATE('2019-12-16', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spies like us', 2002, 'Despite the comedic prowess of its director and two leads, Spies Like Us appears to disavow all knowledge of how to make the viewer laugh.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spike island', 2012, 'Spike Island has energy and visual style to spare; unfortunately, they''re lost within the movie''s clichéd story and choppy direction.', TO_DATE('2012-10-14', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spinning into butter', 2009, 'Both leaden and stilted, Spinning into Butter is an unsubtle drama with stagy direction and lackluster dialogue.', TO_DATE('2009-03-18', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spirit stallion of the cimarron', 2002, 'A visually stunning film that may be too predictable and politically correct for adults, but should serve children well.', TO_DATE('2002-05-13', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spirited away', 2002, 'Spirited Away is a dazzling, enchanting, and gorgeously drawn fairy tale that will leave viewers a little more curious and fascinated by the world around them.', TO_DATE('2002-08-06', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('split', 2016, 'Split serves as a dramatic tour de force for James McAvoy in multiple roles -- and finds writer-director M. Night Shyamalan returning resoundingly to thrilling form.', TO_DATE('2016-09-27', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the spongebob squarepants movie', 2004, 'Surreally goofy and entertaining for both children and their parents.', TO_DATE('2004-11-13', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spotlight', 2015, 'Spotlight gracefully handles the lurid details of its fact-based story while resisting the temptation to lionize its heroes, resulting in a drama that honors the audience as well as its real-life subjects.', TO_DATE('2015-09-03', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spread', 2009, 'Despite occasional detours into surprisingly dark territory, Spread overall is an ineffectual celebration of vacuous Los Angeles high life rather than a deconstruction of it.', TO_DATE('2009-02-06', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spree', 2020, 'Joe Keery''s magnetic screen presence can''t disguise Spree''s shallow critique of social media culture -- although that lack of depth may be precisely the point.', TO_DATE('2020-01-26', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spring', 2014, 'Rich in atmosphere and intelligence, Spring is a singular horror film with a sneaky, lingering impact.', TO_DATE('2014-09-11', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spring breakers', 2012, 'Spring Breakers blends stinging social commentary with bikini cheesecake and a bravura James Franco performance.', TO_DATE('2012-09-05', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spring summer fall winterand spring', 2004, 'A visually stunning and contemplative piece of work.', TO_DATE('2004-01-12', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('springsteen on broadway', 2018, 'The Boss holds court with arresting charisma and storytelling skill in this one-man show, delivering a rollicking rumination on America''s past, present, and future.', TO_DATE('2018-12-07', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('springtime in a small town xiao cheng zhi chun', 2002, 'Director Tian Zhuangzhuang''s remake of the 1948 Chinese classic may be too measured in pace for some audiences, but it''s a visually sumptuous, well-acted piece.', TO_DATE('2002-10-04', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spun', 2002, 'A chaotic drug movie that has little substance behind the stylistic flash.', TO_DATE('2002-09-18', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sputnik', 2020, 'Effective space alien horror with a Soviet-era twist, Sputnik proves there are still some scary good sci-fi thrillers left in the galaxy.', TO_DATE('2020-08-03', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spy', 2015, 'Simultaneously broad and progressive, Spy offers further proof that Melissa McCarthy and writer-director Paul Feig bring out the best in one another -- and delivers scores of belly laughs along the way.', TO_DATE('2015-03-15', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spy game', 2001, 'The outcome of the kinetic Spy Game is never in doubt, but it is fun watching Robert Redford and Brad Pitt work.', TO_DATE('2001-10-29', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spy hard', 2000, 'Leslie Nielsen''s comic gifts are undisputed, but Spy Hard''s lazy script and slapdash direction fail to take advantage of them.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spy kids', 2000, 'A kinetic and fun movie that''s sure to thrill children of all ages.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spy kids 2 the island of lost dreams', 2002, 'Though the concept is no longer fresh, Spy Kids 2 is still an agreeable and energetic romp.', TO_DATE('2002-08-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spy kids 3d game over', 2003, 'The movie will be found wanting if one is not taken in by the 3-D visuals.', TO_DATE('2003-07-15', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('spy kids all the time in the world in 4d', 2011, 'Burdened by a rote plot and unfunny scatological humor, All the Time in the World suggests that the Spy Kids franchise has run its course.', TO_DATE('2011-08-17', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the spy next door', 2010, 'Lacking a script funny enough to cover up for Jackie Chan''s fading physical gifts, The Spy Next Door fails on every conceivable level.', TO_DATE('2010-01-11', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the spy who loved me', 1977, 'Though it hints at the absurdity to come in later installments, The Spy Who Loved Me''s sleek style, menacing villains, and sly wit make it the best of the Roger Moore era.', TO_DATE('1977-07-13', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the squid and the whale', 2005, 'This is a piercingly honest, acidly witty look at divorce and its impact on a family.', TO_DATE('2005-03-09', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('st agatha', 2018, 'St. Agatha makes admittedly uneven use of its story''s well-worn religious tropes, but the overall effect may still be just chilling enough for horror fans.', TO_DATE('2018-08-30', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('st elmos fire', 2000, 'St. Elmo''s Fire is almost peak Brat Pack: it''s got the cast, the fashion, and the music, but the characters are too frequently unlikable.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('st trinians', 2007, 'Both naughtier and campier than Ronald Searle''s original post war series, this St. Trinian''s leans on high jinks instead of performances or witty dialogue.', TO_DATE('2007-12-10', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('st vincent', 2014, 'St. Vincent offers the considerable pleasure of seeing Bill Murray back in funny form, but drifts into dangerously sentimental territory along the way.', TO_DATE('2014-09-05', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stage beauty', 2004, 'Uneven but enjoyable, Stage Beauty uses historical events as the springboard for a well-acted romance with a charming Shakespearean spin.', TO_DATE('2004-06-12', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stage fright', 2014, 'There might be a good movie to be made from mashing up the slasher and musical genres; unfortunately, Stage Fright isn''t quite it.', TO_DATE('2014-03-11', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stake land', 2010, 'Though the genre is well worn at this point, director Jim Mickle focuses on strong characterization and eerie atmosphere to craft an effective apocalyptic vampire chiller that also manages to pack a mean punch.', TO_DATE('2010-09-19', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stalag 17', 1953, 'Stalag 17 survives the jump from stage to screen with flying colors, thanks to Billy Wilder''s typically sterling direction and a darkly funny script.', TO_DATE('1953-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stalingrad', 2014, 'There''s no arguing with its impressive production values, but Stalingrad should have devoted more attention to the screenplay and spent less on special effects-enhanced spectacle.', TO_DATE('2014-02-14', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stand and deliver', 2000, 'Stand and Deliver pulls off the unlikely feat of making math class the stuff of underdog drama -- and pays rousing tribute to a real-life inspirational figure in the bargain.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stand by me', 1800, 'Stand By Me is a wise, nostalgic movie with a weird streak that captures both Stephen King''s voice and the trials of growing up.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stand clear of the closing doors', 2013, 'Unassuming yet irrevocably absorbing, Stand Clear of the Closing Doors uses a refreshing perspective to explore universal themes.', TO_DATE('2013-07-28', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stand up guys', 2012, 'Stand Up Guys largely wastes its talented cast in a resolutely mediocre comedy hampered by messy direction and a perfunctory script.', TO_DATE('2012-10-12', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('standard operating procedure', 2008, 'Well researched and finely crafted, Standard Operating Procedure is another gem from master documentarian Errol Morris.', TO_DATE('2008-02-13', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('standing in the shadows of motown', 2002, 'A toe-tapping tribute to the band that gave Motown its sound.', TO_DATE('2002-09-03', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('standing up falling down', 2019, 'A familiar story entertainingly told, Standing Up, Falling Down is elevated by the warm chemistry between Billy Crystal and Ben Schwartz.', TO_DATE('2019-04-29', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star trek', 2009, 'Star Trek reignites a classic franchise with action, humor, a strong story, and brilliant visuals, and will please traditional Trekkies and new fans alike.', TO_DATE('2009-04-07', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star trek beyond', 2016, 'Star Trek Beyond continues the franchise''s post-reboot hot streak with an epic sci-fi adventure that honors the series'' sci-fi roots without skimping on the blockbuster action.', TO_DATE('2016-07-15', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star trek first contact', 1996, 'While fans of the series will surely appreciate it, First Contact is exciting, engaging, and visually appealing enough to entertain Star Trek novices.', TO_DATE('1996-11-22', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star trek generations', 1994, 'Generations stands as a mediocre changing of the guard for crews of the Enterprise, with a dull plot that sometimes seems like an expanded episode of the television series.', TO_DATE('1994-11-18', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star trek ii the wrath of khan', 2000, 'Considered by many fans to be the best of the Star Trek movies, Khan features a strong plot, increased tension, and a sharp supporting performance from Ricardo Montalban.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star trek iii the search for spock', 2000, 'Though it may be short on dazzling special effects, The Search for Spock is still a strong Star Trek installment, thanks to affecting performances by its iconic cast.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star trek insurrection', 1998, 'Although not terrible, the sluggishly paced Insurrection plays like an extended episode of the TV series.', TO_DATE('1998-12-11', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star trek into darkness', 2013, 'Visually spectacular and suitably action packed, Star Trek Into Darkness is a rock-solid installment in the venerable sci-fi franchise, even if it''s not as fresh as its predecessor.', TO_DATE('2013-04-23', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star trek iv the voyage home', 2000, 'Star Trek IV: The Voyage Home is perhaps the lightest and most purely enjoyable entry of the long-running series, emphasizing the eccentricities of the Enterprise''s crew.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star trek nemesis', 2002, 'Nemesis has an interesting premise and some good action scenes, but the whole affair feels a bit tired.', TO_DATE('2002-12-10', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star trek the motion picture', 2000, 'Featuring a patchwork script and a dialogue-heavy storyline whose biggest villain is a cloud, Star Trek: The Motion Picture is a less-than-auspicious debut for the franchise.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star trek v the final frontier', 2000, 'Filled with dull action sequences and an underdeveloped storyline, this fifth Trek movie is probably the worst of the series.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star trek vi the undiscovered country', 1991, 'The Undiscovered Country is a strong cinematic send-off for the original Trek crew, featuring some remarkable visuals and an intriguing, character-driven mystery plot.', TO_DATE('1991-12-03', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star wars episode iv a new hope', 1977, 'A legendarily expansive and ambitious start to the sci-fi saga, George Lucas opened our eyes to the possibilities of blockbuster filmmaking and things have never been the same.', TO_DATE('1977-05-25', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star wars episode i the phantom menace', 1999, 'Burdened by exposition and populated with stock characters, The Phantom Menace gets the Star Wars prequels off to a bumpy -- albeit visually dazzling -- start.', TO_DATE('1999-05-19', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star wars episode ii attack of the clones', 2002, 'Star Wars Episode II: Attack of the Clones benefits from an increased emphasis on thrilling action, although they''re once again undercut by ponderous plot points and underdeveloped characters.', TO_DATE('2002-04-24', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star wars episode iii revenge of the sith', 2003, 'With Episode III: Revenge of the Sith, George Lucas brings his second Star Wars trilogy to a suitably thrilling and often poignant -- if still a bit uneven -- conclusion.', TO_DATE('2003-07-22', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star wars episode vi return of the jedi', 2000, 'Though failing to reach the cinematic heights of its predecessors, Return of the Jedi remains an entertaining sci-fi adventure and a fitting end to the classic trilogy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star wars episode vii the force awakens', 2015, 'Packed with action and populated by both familiar faces and fresh blood, The Force Awakens successfully recalls the series'' former glory while injecting it with renewed energy.', TO_DATE('2015-12-15', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star wars the last jedi', 2017, 'Star Wars: The Last Jedi honors the saga''s rich legacy while adding some surprising twists -- and delivering all the emotion-rich action fans could hope for.', TO_DATE('2017-12-12', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('star wars the rise of skywalker', 2019, 'Star Wars: The Rise of Skywalker suffers from a frustrating lack of imagination, but concludes this beloved saga with fan-focused devotion.', TO_DATE('2019-12-18', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stardust', 2007, 'A faithful interpretation that captures the spirit of whimsy, action, and off-kilter humor of Neil Gaiman, Stardust juggles multiple genres and tones to create a fantastical experience.', TO_DATE('2007-07-29', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stardust memories', 2000, 'Woody Allen throws himself a pity party with all the surrealistic trimmings of Federico Fellini in Stardust Memories, a scabrous self-portrait that rankles as often as it impresses stylistically.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('starfish', 2018, 'Led by a strong central performance from Virginia Gardner, Starfish is an intelligent, emotionally affecting, and uniquely expansive sci-fi/horror hybrid.', TO_DATE('2018-09-25', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stargate', 1994, 'Stargate has splashy visuals and James Spader to recommend it, but corny characterization and a clunky script makes this a portal to ho-hum.', TO_DATE('1994-10-28', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('starman', 2000, 'What initially begins as sci-fi transforms into a surprisingly sweet, offbeat drama, courtesy of John Carpenter''s careful direction.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('starred up', 2013, 'Smart, hard-hitting, and queasily realistic, Starred Up is an instant classic of U.K. prison cinema.', TO_DATE('2013-08-30', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('starry eyes', 2014, 'Starry Eyes pokes Hollywood''s seedy underbelly to produce a refreshingly original horror story led by a breakout performance from Alex Essoe.', TO_DATE('2014-03-23', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('starship troopers', 1997, 'A fun movie...if you can accept the excessive gore and wooden acting.', TO_DATE('1997-11-07', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('starsky hutch', 2004, 'It''s uneven and occasionally somewhat aimless, but Starsky & Hutch benefits from Stiller and Wilson''s chemistry and a surprisingly warm-hearted script.', TO_DATE('2004-02-01', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('starter for 10', 2006, 'Starter For 10 is a spirited coming-of-age tale that remains charming and witty even as it veers into darker teritory. The unique setting of a quiz show makes the film wittier than your average romantic comedy.', TO_DATE('2006-02-23', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('starting out in the evening', 2007, 'Starting Out in the Evening features sharp dialogue and moving performances from the talented Frank Langella and Lili Taylor.', TO_DATE('2007-01-23', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('startupcom', 2001, 'Startup.com is more than just a look at the rise and fall of the new economy. At its center is a friendship being tested to the limit, and that''s what makes it worth viewing.', TO_DATE('2001-02-09', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('state and main', 2000, 'State and Main offers plenty of wit and laughs in its lampoons of the movie industry.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('state like sleep', 2018, 'State Like Sleep fails to engage despite the efforts of a talented cast, leaving viewers with a would-be thriller that has an unfortunately descriptive title.', TO_DATE('2018-04-25', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the statement', 2003, 'The movie bores despite a splendid performance by Michael Caine.', TO_DATE('2003-11-14', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stateside', 2004, 'An inept drama that rings false.', TO_DATE('2004-05-07', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the station agent', 2003, 'A sweet and quirky film about a dwarf, a refreshment stand operator, and a reclusive artist connecting with one another.', TO_DATE('2003-02-26', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stations of the cross', 2014, 'A drama of thought-provoking depth as well as a showcase for newcomer Lea van Acken, Stations of the Cross hits hard and leaves a lingering impact.', TO_DATE('2014-06-20', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stay', 2005, 'A muddled brain-teaser, Stay has a solid cast and innovative visuals but little beneath the surface.', TO_DATE('2005-10-14', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('staying alive', 2001, 'This sequel to Saturday Night Fever is shockingly embarrassing and unnecessary, trading the original''s dramatic depth for a series of uninspired dance sequences.', TO_DATE('2001-04-17', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('steal a pencil for me', 2007, 'Steal a Pencil For Me is a unique Holocaust story that pays tribute to the strength of the human spirit in the face of enormous hardship.', TO_DATE('2007-10-12', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('steal this movie', 2000, 'D''Onofrio''s performance fails to do justice to Hoffman, and the depiction of the 60s also rings false.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stealing harvard', 2002, 'There are laughs Stealing Harvard, but they are few and far between. Tom Green''s antics grow old fast.', TO_DATE('2002-09-10', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('steamboy', 2005, 'The story isn''t the greatest, but there''s an abundance of sci-fi eye candy to compensate.', TO_DATE('2005-02-22', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('steel city', 2006, 'A blue-collar drama with an uncommonly strong sense of its characters and setting, Steel City suggests a bright future for debuting writer-director Brian Jun.', TO_DATE('2006-01-23', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('steel magnolias', 2000, 'Steel Magnolias has jokes and characters to spare, which makes it more dangerous (and effective) when it goes for the full melodrama by the end.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('steep', 2007, 'Steep is a mixed bag of breathtaking mountain footage and yawn-inducing banter.', TO_DATE('2007-11-14', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('step into liquid', 2003, 'A perfect companion piece to The Endless Summer.', TO_DATE('2003-07-19', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('step up', 2006, 'This trite teen romance has too little plot and not enough dancing.', TO_DATE('2006-08-09', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('step up 2 the streets', 2008, 'There''s a kinetic appeal to the handsome cast and their smooth moves, but everything else about Step Up 2 the Streets is been there, danced that.', TO_DATE('2008-02-13', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('step up 3', 2010, 'It may not contain believable acting or a memorable plot, but Step Up 3-D delivers solid choreography and stunning visuals.', TO_DATE('2010-07-29', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('step up all in', 2014, 'With slick choreography all too often interrupted by feeble attempts at plot, Step Up: All In would be more fun with all of its dialogue edited out.', TO_DATE('2014-07-16', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('step up revolution', 2012, 'Step Up Revolution treads familiar territory by surrounding its lively and kinetic dance sequences with a predictably generic story.', TO_DATE('2012-07-25', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the stepford wives', 2004, 'In exchanging the chilling satire of the original into mindless camp, this remake has itself become Stepford-ized.', TO_DATE('2004-04-19', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stephen kings it', 2002, 'Though hampered by an uneven second half, It supplies a wealth of funhouse thrills and an idelible turn from Tim Curry as Pennywise.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stephen kings the langoliers', 2000, 'While not without its fair share of thrills, The Langoliers suffers from a meandering pace and dubious characterizations.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stepmom', 2000, 'Solid work from Julia Roberts and Susan Sarandon isn''t enough to save Stepmom from a story whose manipulations dilute the effectiveness of a potentially affecting drama.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('steve jobs', 2015, 'Like the tech giant co-founded by its subject, Steve Jobs gathers brilliant people to deliver a product whose elegance belies the intricate complexities at its core.', TO_DATE('2015-09-06', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('steve jobs man in the machine', 2015, 'Steve Jobs: Man in the Machine offers absorbing viewing, even if it doesn''t delve deeply into its complex subject.', TO_DATE('2015-03-15', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('steve martin and martin short an evening you will forget for the rest of your life', 2018, 'Brimming with sidesplitting laughs and off the wall energy, Steve Martin And Martin Short: An Evening You Will Forget For the Rest of Your Life is a nostalgic celebration of two comedy legends.', TO_DATE('2018-05-24', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stevie', 2003, 'Poignant documentary that''s hard to forget.', TO_DATE('2003-01-29', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stick it', 2006, 'Director Jessica Bendinger is unable to transfer her winning Bring It On formula to the world of gymnastics, despite Missy Peregrym''s strong lead performance.', TO_DATE('2006-04-26', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stigmata', 2000, 'The story is unconvincing and the acting is weak.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('still alice', 2014, 'Elevated by a gripping performance from Julianne Moore, Still Alice is a heartfelt drama that honors its delicate themes with bravery and sensitivity.', TO_DATE('2014-09-09', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('still crazy', 1998, 'Still Crazy can''t completely escape the shadow left by the classic rock mockumentaries of the past, but it earns a commendable number of laughs in its own right.', TO_DATE('1998-12-11', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('still mine', 2013, 'James Cromwell and Geneviève Bujold are outstanding in this tender, affecting, insightful drama about the bonds and sacrifices of marriage.', TO_DATE('2013-05-02', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stillborn', 2017, 'Still/Born puts an intriguing psychological spin on its supernatural horror story, elevated by standout work from star Christie Burke.', TO_DATE('2017-08-15', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stir of echoes', 2000, 'Kevin Bacon''s acting is so genuine that it''s creepy and director David Keopp knows how to create true suspense.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stoker', 2013, 'Its script doesn''t quite carry the dramatic heft of his earlier work, but Park Chan-wook''s Stoker showcases his eye for sumptuous imagery and his affection for dark, atmospheric narratives populated by mysterious characters.', TO_DATE('2013-01-21', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stolen', 2005, 'A real-life whodunit with colorful characters, especially art detective Harold Smith, this documentary is a fascinating peek into the world of art collecting.', TO_DATE('2005-07-07', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stolen summer', 2002, 'Stolen Summer feels like a sugary after-school special stretched out to feature length.', TO_DATE('2002-01-30', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stomp the yard', 2007, 'While Stomp the Yard contains impressive musical and dance numbers, it loses its momentum during the intervening soap opera-style subplots.', TO_DATE('2007-01-05', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stone', 2010, 'Stone boasts a cast that includes Robert De Niro, Edward Norton, and Milla Jovovich, and it features strong dialogue, but it''s ultimately undone by its heavy-handed symbolism and overabundant plot twists.', TO_DATE('2010-09-10', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stoned', 2005, 'Poorly cast and sloppily assembled, Stoned turns one of rock ''n'' roll''s most darkly fascinating mysteries into a cinematic tragedy all its own.', TO_DATE('2005-09-24', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stonewall', 2015, 'As an ordinary coming-of-age drama, Stonewall is merely dull and scattered -- but as an attempt to depict a pivotal moment in American history, it''s offensively bad.', TO_DATE('2015-09-18', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the stoning of soraya m', 2008, 'The Stoning of Soraya M. nearly transcends its deficiencies through the sheer strength of its subject material, but ultimately drowns out its message with an inappropriately heavy-handed approach.', TO_DATE('2008-11-24', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stoploss', 2008, 'Stop-Loss is sincere and complex, and features strong performances, even if it tries to cover too much ground.', TO_DATE('2008-03-12', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stop making sense', 2000, 'Jonathan Demme''s Stop Making Sense captures the energetic, unpredictable live act of peak Talking Heads with color and visual wit.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stop or my mom will shoot', 1992, 'Thoroughly witless and thuddingly unfunny, Stop! Or My Mom Will Shoot gives its mismatched stars very little to work with - and as a result, they really don''t work.', TO_DATE('1992-02-01', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stories we tell', 2012, 'In Stories We Tell, Sarah Polley plays with the documentary format to explore the nature of memory and storytelling, crafting a thoughtful, compelling narrative that unfolds like a mystery.', TO_DATE('2012-09-24', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('storks', 2016, 'Colorful animation and a charming cast help Storks achieve a limited liftoff, but scattershot gags and a confused, hyperactively unspooled plot keep it from truly soaring.', TO_DATE('2016-09-20', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the story of us', 2000, 'A lack of chemistry between Bruce Willis and Michelle Pfeiffer fatally undermines the dull and predictable Story of Us.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('storytelling', 2001, 'Todd Solondz''s Storytelling boasts an audacious narrative structure, but fails to deliver on the mechanics of its namesake, yielding a creative exercise that is more interested in satisfying the author''s interests than the audience''s investment.', TO_DATE('2001-05-15', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('straight outta compton', 2015, 'Straight Outta Compton is a biopic that''s built to last, thanks to F. Gary Gray''s confident direction and engaging performances from a solid cast.', TO_DATE('2015-07-30', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the straight story', 2000, 'With strong performances and director David Lynch at the helm, The Straight Story steers past sentimental byways on its ambling journey across the American heartland.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('straight jacket', 2004, 'Straight Jacket succeeds in its moments of lighthearted comedy, but ultimately collapses under the weight of its serious -- and clumsily imparted -- messages.', TO_DATE('2004-07-13', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stranded i have come from a plane that crashed on the mountains', 2008, 'Stranded is a thoroughly uplifting account of the well-known tragedy, with touching testimony from remaining survivors.', TO_DATE('2008-01-30', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('strange brew', 2000, 'Though lowbrow in intent and outcome, Strange Brew effectively mines laughs from its unique premise and likeable stars.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('strange magic', 2015, 'Like most modern animated movies, Strange Magic is lovely to look at; unfortunately, there isn''t much going on beneath the surface.', TO_DATE('2015-01-21', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('strange wilderness', 2008, 'Strange Wilderness is a laugh-free comedy that''s both aimless and overly crass.', TO_DATE('2008-02-01', 'YYYY-MM-DD'), 2.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a stranger among us', 2000, 'A disappointing misfire for director Sidney Lumet, A Stranger Among Us tries to tell a murder mystery and a fish-out-of-water love story, doing a disservice to both.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stranger by the lake', 2013, 'Sexy, smart, and darkly humorous, Stranger by the Lake offers rewarding viewing for adult filmgoers in search of thought-provoking drama.', TO_DATE('2013-05-19', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stranger than fiction', 2006, 'A fun, whimsical tale about an office drone trying to save his life from his narrator, Stranger Than Fiction features a subdued performances from Will Ferrell that contributes mightily to its quirky, mind-bending affect.', TO_DATE('2006-09-10', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stranger than paradise', 2002, 'A striking debut for director Jim Jarmusch, Stranger than Paradise is an effortlessly cool exploration of finding meaning in the mundane.', TO_DATE('2002-02-28', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('strangerland', 2015, 'Strangerland has a marvelous cast, but their efforts aren''t enough to overcome the story''s blandly predictable melodrama.', TO_DATE('2015-01-24', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stratton', 2017, 'Stratton''s action-thriller ambitions are roundly thwarted by a derivative story, misguided casting, and a low-budget feel underscored by unimpressive set pieces.', TO_DATE('2017-08-30', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('straw dogs', 2011, 'This remake streamlines the plot but ultimately makes a fatal mistake: It celebrates violence.', TO_DATE('2011-09-02', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stray dolls', 2019, 'Stray Dolls doesn''t make it easy to identify with its central characters, but director/co-writer Sonejuhi Sinha''s depiction of the American underbelly is compelling.', TO_DATE('2019-04-28', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('street fighter the legend of chunli', 2009, 'The combination of a shallow plot and miscast performers renders Street Fighter: The Legend of Chun Li a perfectly forgettable video game adaptation.', TO_DATE('2009-02-27', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('street kings', 2008, 'Street Kings contains formulaic violence but no shred of intelligence.', TO_DATE('2008-04-03', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('streets of fire', 2000, 'Streets of Fire may sometimes buckle under the strain of its ambitious fusion of disparate genres, but Walter Hill''s bravura style gives this motorcycle musical fuel to burn.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('striking distance', 2000, 'Weighed down by a rote story and passionless performances, Striking Distance represents one of the lesser ''90s genre outings from action hero Bruce Willis.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stripes', 2002, 'A raucous military comedy that features Bill Murray and his merry cohorts approaching the peak of their talents.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('striptease', 1996, 'Striptease can''t decide whether it is a lurid thriller or a sexy satire - which becomes a moot point as it proves disastrously incapable of pulling either off.', TO_DATE('1996-06-28', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('strong island', 2017, 'Strong Island uses one family''s heartbreaking tragedy to offer a sobering picture of racial injustice in modern America.', TO_DATE('2017-01-23', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stronger', 2017, 'Stronger rises on the power of its well-chosen ensemble to offer an emotionally resonant fact-based story that transcends inspirational drama clichés.', TO_DATE('2017-09-09', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stuart little', 2000, 'Critics say Stuart Little is charming with kids and adults for its humor and visual effects.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stuart little 2', 2002, 'Stuart Little 2 is a sweet, visually impressive sequel that provides wholesome entertainment for kids.', TO_DATE('2002-07-11', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stuber', 2019, 'Though it makes a strong case for future collaborations between Kumail Nanjiani and Dave Bautista, Stuber fails to mesh its contrasting genres, settling for an overtly violent, mildly entertaining diversion that''s far from a five-star ride.', TO_DATE('2019-03-14', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stuck', 2007, 'Steeped in gallows humor, Stuck is a taut, tense examination of a tragic accident.', TO_DATE('2007-09-13', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stuck in love', 2013, 'It struggles to enliven its uneven script, but Stuck in Love boasts enough winning performances from its solid veteran cast to offer an appealing diversion for rom-com enthusiasts.', TO_DATE('2013-05-12', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stuck on you', 2003, 'An unusually sweet and charming comedy by the Farrelly brothers. Fans may miss the distinct lack of bodily fluids though.', TO_DATE('2003-12-08', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the stunt man', 2000, 'The Stunt Man is a preposterously entertaining thriller with a clever narrative and Oscar-worthy (nomination, at least!) Peter O''Toole performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('styx', 2018, 'Anchored by powerful work from Susanne Wolff, Styx provocatively depicts mankind at war with itself and the natural world -- and argues our best weapon is compassion.', TO_DATE('2018-02-16', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('submarine', 2010, 'Funny, stylish, and ringing with adolescent truth, Submarine marks Richard Ayoade as a talent to watch.', TO_DATE('2010-09-16', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('submergence', 2017, 'A slow-moving misfire, Submergence isn''t as deep as it thinks it is -- but still manages to drown its stars in a drama whose admirable ambitions remain almost entirely unfulfilled.', TO_DATE('2017-09-13', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('suburbicon', 2017, 'A disappointing misfire for director George Clooney, Suburbicon attempts to juggle social satire, racial commentary, and murder mystery -- and ends up making a mess of all three.', TO_DATE('2017-09-02', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sucker punch', 2011, 'It''s technically impressive and loaded with eye-catching images, but without characters or a plot to support them, all of Sucker Punch''s visual thrills are for naught.', TO_DATE('2011-03-24', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sudden impact', 2000, 'Sudden Impact delivers all the firepower -- and the most enduring catchphrase -- fans associate with the Dirty Harry franchise, but it''s far from the best film in the series.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('suffragette', 2015, 'Suffragette dramatizes an important -- and still painfully relevant -- fact-based story with more than enough craft and sincerity to overcome its flaws.', TO_DATE('2015-09-04', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sugar spice', 2000, 'Though this cheerleader comedy has an intriguing premise, it''s too empty-headed and saddled with too many lame jokes to live up to it. Also, some critics say the movie is irresponsible in its depiction of teens and guns.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('suicide squad', 2016, 'Suicide Squad boasts a talented cast and a little more humor than previous DCEU efforts, but they aren''t enough to save the disappointing end result from a muddled plot, thinly written characters, and choppy directing.', TO_DATE('2016-08-02', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sukiyaki western django', 2007, 'Inventive and off-kilter, the newest feast from J-Horror director Takashi Miike is super-sensory, self-referential and somewhat excessive.', TO_DATE('2007-09-14', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sully', 2016, 'As comfortingly workmanlike as its protagonist, Sully makes solid use of typically superlative work from its star and director to deliver a quietly stirring tribute to an everyday hero.', TO_DATE('2016-09-02', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sum of all fears', 2001, 'A slick and well-made thriller that takes on new weight due to the current political climate.', TO_DATE('2001-12-04', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('summer wars sama wozu', 2010, 'Family drama mixes with virtual online action in the breezy and entertaining Summer Wars.', TO_DATE('2010-12-22', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('summer catch', 2001, 'A cliched and predictable sports comedy that''s mostly devoid of excitement or laughs, Summer Catch is strictly bush-league.', TO_DATE('2001-08-21', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('lheure dété summer hours', 2008, 'Olivier Assayas'' contemplative family drama handles lofty ideas about art and culture with elegance and lightness.', TO_DATE('2008-07-10', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('summer in february', 2013, 'It boasts beautiful scenery, but in every other respect, Summer in February is a painfully bland period drama.', TO_DATE('2013-06-09', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('summer of sam', 2000, 'Spike Lee offers intense visuals but his storytelling feels crowded and overambitious.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('summerland', 2020, 'In Summerland, the living is a little too easy to raise dramatic stakes -- but Gemma Arterton''s performance adds some much-needed extra heat.', TO_DATE('2020-07-26', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a summers tale', 2000, 'With A Summer''s Tale, Eric Rohmer continues his "Tales of the Four Seasons" in typically Rohmeresque fashion -- and for cineastes, that''s excellent news indeed.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sunday bloody sunday', 1971, 'Led by strong performances from its three leads, Sunday Bloody Sunday takes a sophisticated and groundbreaking look at the complexities of love.', TO_DATE('1971-09-08', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sunlight jr', 2013, 'It doesn''t offer much in the way of uplift, but Sunlight Jr.''s grim storyline is offset by Laurie Collyer''s empathetic screenplay and strong performances from Naomi Watts and Matt Dillon.', TO_DATE('2013-04-24', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sunrise a song of two humans', 1927, 'Boasting masterful cinematography to match its well-acted, wonderfully romantic storyline, Sunrise is perhaps the final -- and arguably definitive -- statement of the silent era.', TO_DATE('1927-09-23', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sunset boulevard', 1950, 'Arguably the greatest movie about Hollywood, Billy Wilder''s masterpiece Sunset Boulevard is a tremendously entertaining combination of noir, black comedy, and character study.', TO_DATE('1950-08-04', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sunset song', 2015, 'Achingly lovely on both visual and narrative grounds, Sunset Song adds another small gem to writer-director Terence Davies'' filmography.', TO_DATE('2015-09-16', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sunshine', 2007, 'Danny Boyle continues his descent into mind-twisting sci-fi madness, taking us along for the ride. Sunshine fulfills the dual requisite necessary to become classic sci-fi: dazzling visuals with intelligent action.', TO_DATE('2007-03-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sunshine cleaning', 2009, 'Despite a sometimes overly familiar plot, Sunshine Cleaning benefits from the lively performances of its two stars.', TO_DATE('2009-02-24', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sunshine state', 2002, 'Wonderfully acted, but the story and pacing can use a little work.', TO_DATE('2002-05-19', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sunshine superman', 2014, 'Sunshine Superman shines a light on a fascinating life with copious amounts of incredible, thrilling footage.', TO_DATE('2014-09-19', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('super', 2010, 'Super''s intriguing premise and talented cast are drowned in a blood-red sea of graphic violence, jarring tonal shifts, and thinly written characters.', TO_DATE('2010-09-11', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('super 8', 2011, 'It may evoke memories of classic summer blockbusters a little too eagerly for some, but Super 8 has thrills, visual dazzle, and emotional depth to spare.', TO_DATE('2011-05-31', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('superbabies baby geniuses 2', 2004, 'A startling lack of taste pervades Superbabies, a sequel offering further proof that bad jokes still aren''t funny when coming from the mouths of babes.', TO_DATE('2004-08-26', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('super dark times', 2017, 'Rich in atmosphere and period detail, Super Dark Times is an effective teen thriller whose true power lies in its approach to deeper themes.', TO_DATE('2017-02-02', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('super size me', 2004, 'Entertaining doc about the adverse effects of eating fast food.', TO_DATE('2004-02-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('super size me 2 holy chicken', 2017, 'Super Size Me 2: Holy Chicken! may not be as filling as its predecessor, but it still manages to offer a moderately enriching overview of unsavory industry practices.', TO_DATE('2017-09-09', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('super troopers', 2001, 'A more-miss -than-hit affair, Super Troopers will most likely appeal to those looking for something silly.', TO_DATE('2001-11-30', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('super troopers 2', 2018, 'Meow that the wait for Super Troopers 2 is finally over, all but the most devoted fans mustache themselves why they waited so long for such cruel and tragic shenanigans.', TO_DATE('2018-04-16', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('superbad', 2007, 'Deftly balancing vulgarity and sincerity while placing its protagonists in excessive situations, Superbad is an authentic take on friendship and the overarching awkwardness of the high school experience.', TO_DATE('2007-07-27', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('supercop', 2000, 'Blending hand-to-hand combat with breathtaking stunts and slapstick comedy, Supercop reminds us why Jackie Chan is one of the world''s great entertainers.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('supercross', 2005, 'While it showcases some cool stunts, Supercross feels like an infomercial for its titular sport, with undeveloped characters and a shopworn plot.', TO_DATE('2005-08-12', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('superfly', 2018, 'Superfly updates the blaxploitation original with a stylish remake that''s exciting and visually arresting enough to offer its own slickly staged action rewards, but disappointingly short on social subtext.', TO_DATE('2018-06-12', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('supergirl', 2000, 'The effects are cheesy and Supergirl''s wide-eyed, cheery heroine simply isn''t interesting to watch for an hour and a half.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('superman ii', 2000, 'The humor occasionally stumbles into slapstick territory, and the special effects are dated, but Superman II meets, if not exceeds, the standard set by its predecessor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('superman iii', 2000, 'When not overusing sight gags, slapstick, and Richard Pryor, Superman III resorts to plot points rehashed from the previous Superman flicks.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('superman iv the quest for peace', 2000, 'The Superman series bottoms out here: the action is boring, the special effects look cheaper, and none of the actors appear interested in where the plot''s going.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('man of steel', 2013, 'Man of Steel''s exhilarating action and spectacle can''t fully overcome its detours into generic blockbuster territory.', TO_DATE('2013-06-10', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('superman returns', 2006, 'Bryan Singer''s reverent and visually decadent adaptation gives the Man of Steel welcome emotional complexity. The result: a satisfying stick-to-your-ribs adaptation.', TO_DATE('2006-06-19', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('superman', 2000, 'Superman deftly blends humor and gravitas, taking advantage of the perfectly cast Christopher Reeve to craft a loving, nostalgic tribute to an American pop culture icon.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('supermensch the legend of shep gordon', 2013, 'Its unabashedly positive tone may strike some viewers as disingenuous, but even if Supermensch doesn''t tell the whole story, it''s an undeniably entertaining one.', TO_DATE('2013-09-12', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('surfs up', 2007, 'Surf''s Up is a laid back, visually stunning animated movie that brings a fresh twist to some familiar conventions. Its witty mockumentary format is fun and inventive, and the CGI is breathtakingly realistic.', TO_DATE('2007-06-02', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('surfwise', 2008, 'An intriguing account of a unique family.', TO_DATE('2008-02-26', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('surveillance', 2009, 'This dark psycho-thriller from Jennifer Lynch, is violent, sharp and baffling, but not to everyone''s taste.', TO_DATE('2009-03-01', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('survival of the dead', 2009, 'Survival of the Dead offers glimmers of Romero''s savage wit, but not nearly enough to make up for his unusually uninspired directing and a lack of new ideas', TO_DATE('2009-09-28', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('surviving christmas', 2004, 'Surviving Christmas is unpleasant characters attacking each other for 90 minutes before delivering a typical, hollow anti-consumerist message', TO_DATE('2004-10-19', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('survivor', 2015, 'Borrowing heavily from better films in service of a predictable story, Survivor will struggle to sustain the interest of even the most avid action thriller fans.', TO_DATE('2015-05-25', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('suspect zero', 2004, 'Other than Ben Kingsley, there''s not much to like in this preposterous thriller.', TO_DATE('2004-07-05', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('suspended animation', 2003, 'Suspended Animation offers some gory good fun for genre fans, even if the end results don''t quite transcend their cheerfully shallow roots.', TO_DATE('2003-08-20', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('suspiria', 2018, 'Suspiria attacks heady themes with garish vigor, offering a viewing experience that''s daringly confrontational - and definitely not for everyone.', TO_DATE('2018-09-01', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('suzi q', 2019, 'Suzi Q is an engaging and edifying stroll through rock pioneer Suzi Quatro''s career.', TO_DATE('2019-10-11', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('swallow', 2019, 'Swallow''s unconventional approach to exploring domestic ennui is elevated by a well-told story and Haley Bennett''s powerful leading performance.', TO_DATE('2019-04-29', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('swamp thing', 2000, 'Unabashedly campy -- often to its detriment -- Swamp Thing is not without its charms, among them Adrienne Barbeau as the damsel in distress.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('swat', 2003, 'A competent, but routine police thriller.', TO_DATE('2003-08-04', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sweeney todd the demon barber of fleet street', 2007, 'Full of pith and Grand Guignol grossness, this macabre musical is perfectly helmed and highly entertaining. Tim Burton masterfully stages the musical in a way that will make you think he has done this many times before.', TO_DATE('2007-12-03', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sweet bean an', 2015, 'Sweet Bean''s deliberate pace demands patience, but the satisfying simplicity of its story -- and Kirin Kiki''s absorbing performance -- yield an array of riches well worth the wait.', TO_DATE('2015-07-20', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sweet hereafter', 1997, 'Director Atom Egoyan examines tragedy and its aftermath with intelligence and empathy.', TO_DATE('1997-11-20', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sweet home alabama', 2002, 'Reese Witherspoon is charming enough, but the road to Alabama is well-traveled.', TO_DATE('2002-08-22', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sweet land', 2006, 'Finding the right balance between subtle and sentimental, Sweet Land moves beyond other similarly-themed dramas with evocative cinematography that plays an equal role to the talented cast.', TO_DATE('2006-10-11', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sweet sixteen', 2002, 'A bleak, but heartbreaking coming-of-age tale that resonates with truth.', TO_DATE('2002-06-05', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sweet smell of success', 2000, 'Sweet Smell of Success boasts a top-notch cast, sharp direction, atmospheric cinematography, and an appropriately jazzy score, making it one of the best noir crime thrillers ever made.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sweet virginia', 2017, 'Smart and well-acted, Sweet Virginia delivers a tense, atmospheric thriller that transcends genre conventions even as it embraces them.', TO_DATE('2017-04-24', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sweetest thing', 2002, 'A collection of hit-or-miss gags tied together by a thin plot.', TO_DATE('2002-04-08', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sweetheart', 2019, 'Carried by Kiersey Clemons'' performance, Sweetheart balances smart subtext and social commentary against effective genre thrills.', TO_DATE('2019-01-30', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('swerve', 2012, 'It aims for pulpy noir thrills, but Swerve never lives up to the twisty promise of its title.', TO_DATE('2012-06-03', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('swimfan', 2002, 'A Fatal Attraction rip-off, Swimfan is a predictable, mediocre thriller.', TO_DATE('2002-08-29', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('swimming pool', 2003, 'A sensual thriller with two engaging performers demanding our undivided attention.', TO_DATE('2003-05-19', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('swimming with men', 2018, 'Swimming with Men touches on thought-provoking themes surrounding modern masculinity, but ultimately never manages to do much more than tread water.', TO_DATE('2018-07-02', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('swimming with sharks', 1995, 'Swimming With Sharks is a smart, merciless Hollywood satire that''s darkly hilarious and observant, thanks to Kevin Spacey''s performance as ruthless studio mogul Buddy Ackerman.', TO_DATE('1995-03-21', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('swing vote', 2008, 'Despite Kevin Costner providing his most charismatic performance in years, Swing Vote fails to find the right mix of political satire and heartfelt drama.', TO_DATE('2008-07-29', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('swingers', 1996, 'Funny, heartfelt, and effortlessly cool, Swingers made stars out of Vince Vaughn and Jon Favreau, established Doug Liman as a director to watch.', TO_DATE('1996-10-18', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('swinging safari', 2017, 'Swinging Safari gathers an entertaining ensemble to offer audiences a messy yet ultimately endearing comedy rich with period detail.', TO_DATE('2017-12-12', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('swiss army man', 2016, 'Disarmingly odd and thoroughly well-acted, Swiss Army Man offers adventurous viewers an experience as rewarding as it is impossible to categorize.', TO_DATE('2016-01-23', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('switchback', 1997, 'Burdened by its heavy load of digressive plots turns and uneven performances, Switchback never gains any sense of narrative momentum.', TO_DATE('1997-10-31', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sword in the stone', 2002, 'A decent take on the legend of King Arthur, The Sword in the Stone suffers from relatively indifferent animation, but its characters are still memorable and appealing.', TO_DATE('2002-04-13', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sword of trust', 2019, 'Expertly drawn characters and a strong senes of humanity make Sword of Trust an enjoyable -- if at times meandering -- journey.', TO_DATE('2019-03-09', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('swordfish', 2000, 'Swordfish is big on explosions, but critics dislike how it skimps on plot and logic. Also, the sight of a person typing at a computer just isn''t that interesting.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sydney white', 2007, 'Amanda Bynes is charming, but Sydney White is a poorly adapted take on Snow White, relying on tired ethnic stereotypes laughs.', TO_DATE('2007-09-13', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sympathy for delicious', 2010, 'Mark Ruffalo''s directorial debut inspires more Sympathy than plaudits due to a convoluted story and unengaging style.', TO_DATE('2010-01-25', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sympathy for lady vengeance', 2005, 'Stylistically flashy and gruesomely violent, Sympathy for Lady Vengeance fits in nicely with the other two films of Park''s revenge trilogy.', TO_DATE('2005-07-29', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sympathy for mr vengeance', 2003, 'Though Park directs with stylistic flair, this revenge thriller is more excessively gruesome than thrilling.', TO_DATE('2003-05-28', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('synchronicity', 2015, 'Synchronicity''s sci-fi reach exceeds its low-budget grasp, but it has some interesting ideas and serves overall as a nifty calling card for writer-director Jacob Gentry.', TO_DATE('2015-07-31', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('synecdoche new york', 2008, 'Charlie Kaufman''s ambitious directorial debut occasionally strains to connect, but ultimately provides fascinating insight into a writer''s mind.', TO_DATE('2008-05-23', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('syriana', 2005, 'Ambitious, complicated, intellectual, and demanding of its audience, Syriana is both a gripping geopolitical thriller and wake-up call to the complacent.', TO_DATE('2005-11-14', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('system crasher systemsprenger', 2019, 'While it may test viewers'' patience, System Crasher is a thoughtful and compassionate portrait of one child''s trauma and anger, featuring an enigmatic Helena Zengel in the lead role.', TO_DATE('2019-02-10', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('t2 trainspotting', 2017, 'T2 Trainspotting adds an intoxicating, emotionally resonant postscript to its classic predecessor, even without fully recapturing the original''s fresh, subversive thrill.', TO_DATE('2017-01-19', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('table 19', 2017, 'Table 19 is marginally more entertaining than actually sitting with a table full of strangers at a wedding -- although most screenings won''t come with an open bar, which makes it a wash.', TO_DATE('2017-03-01', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tabloid', 2010, 'It''s far from his most thought-provoking work, but Tabloid finds Errol Morris as smart, spirited, and engaging as ever.', TO_DATE('2010-09-07', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tadpole', 2002, 'Presenting a sexual awakening with surprising candor, Tadpole is a spiky coming of age tale that benefits from a deeply felt performance by Aaron Stanford and a script that is unafraid to wade into morally choppy waters.', TO_DATE('2002-03-08', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tae guk gi the brotherhood of war', 2004, 'Tae Guk Gi: The Brotherhood of War sends viewers to the front lines of the Korean War, with grim yet rewarding results.', TO_DATE('2004-07-27', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tag', 2018, 'For audiences seeking a dose of high-concept yet undemanding action comedy, Tag might be close enough to it.', TO_DATE('2018-06-09', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tai chi zero', 2012, 'Tai Chi Zero may not have much to offer beyond dazzling action, but its infectious energy means fans of the genre should still come away sufficiently entertained.', TO_DATE('2012-09-27', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the tailor of panama', 2000, 'The Tailor of Panama is a smart, darkly satirical thriller with exuberant performances from Pierce Brosnan and Geoffrey Rush.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('take me home tonight', 2011, 'It has a charming sweetness about it, but Take Me Home Tonight is neither funny nor original enough to live up to the comedies it evokes.', TO_DATE('2011-03-01', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('take me to the river', 2014, 'Scattered and uneven, Take Me to the River never adds up to much in terms of narrative documentary, but the music it honors is more than powerful enough to compensate.', TO_DATE('2014-09-08', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('take shelter', 2011, 'Michael Shannon gives a powerhouse performance and the purposefully subtle filmmaking creates a perfect blend of drama, terror, and dread.', TO_DATE('2011-02-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('take the lead', 2006, 'Banderas is charismatic in the lead, and the dance sequences are captivating, but the story is too familiar and predictable.', TO_DATE('2006-03-29', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('take this waltz', 2011, 'Featuring excellent work from an outstanding cast, the bittersweet drama Waltz proves that in the right hands, a familiar tale can still ring true.', TO_DATE('2011-09-11', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('taken', 2008, 'Taken is undeniably fun with slick action, but is largely a brainless exercise.', TO_DATE('2008-02-26', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('taken 2', 2012, 'Taken 2 is largely bereft of the kinetic thrills -- and surprises -- that made the original a hit.', TO_DATE('2012-09-07', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('taken 3', 2014, 'Hampered by toothless PG-13 action sequences, incoherent direction, and a hackneyed plot, Taken 3 serves as a clear signal that it''s well past time to retire this franchise.', TO_DATE('2014-12-31', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('takers', 2010, 'Takers boasts some gripping set pieces and keeps things moving quickly, but its two-dimensional characters, clichéd script, and brazenly derivative plot make it hard to recommend.', TO_DATE('2010-08-16', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('taking lives', 2004, 'A stylish, but predictable thriller where the only thrills are offered by the sensuous Angelina Jolie.', TO_DATE('2004-03-02', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('taking sides le cas furtwängler', 2001, 'A complex, well-acted meditation on moral obligation and human loyalty, Taking Sides features noteworthy performances from Harvey Keitel and Stellan Skarsgard.', TO_DATE('2001-10-08', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('taking woodstock', 2009, 'Featuring numerous 60s-era clichés, but little of the musical magic that highlighted the famous festival, Taking Woodstock is a breezy but underwhelming portrayal.', TO_DATE('2009-05-16', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the tale of despereaux', 2008, 'Despite its striking visuals, The Tale of Despereaux as a story feels familiar and unimaginative.', TO_DATE('2008-12-11', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tale of tales il racconto dei racconti', 2015, 'Visually splendid and narratively satisfying, Tale of Tales packs an off-kilter wallop for mature viewers in search of something different.', TO_DATE('2015-05-14', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the talent given us', 2005, 'The Talent Given Us is an odd hybrid of reality and fiction, but works due to its engaging characters.', TO_DATE('2005-06-14', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the talented mr ripley', 1999, 'With Matt Damon''s unsettling performance offering a darkly twisted counterpoint to Anthony Minghella''s glossy direction, The Talented Mr. Ripley is a suspense thriller that lingers.', TO_DATE('1999-12-25', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tales from the crypt presents bordello of blood', 2000, 'Bordello of Blood is not as scary or funny as it thinks it is (or should''ve been), and all of Dennis Miller''s lines sound like castoffs from his stand-up material.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tales from the script', 2010, 'Tales from the Script can be frustratingly preoccupied with the pitfalls of screenwriting at the expense of loving the craft, but this documentary overall offers a wealth of professional pointers for aspiring storytellers.', TO_DATE('2010-02-20', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('talk radio', 2000, 'The gripping union of a director and star at the peak of their respective powers, Talk Radio offers the viewer a singularly unlikable character and dares you to look away.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('talk to her', 2002, 'Another masterful, compassionate work from Pedro Almodovar.', TO_DATE('2002-04-15', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('talk to me', 2007, 'A riveting look at the life of legendary DJ "Petey" Greene, Talk to Me goes beyond the typical biopic with explosive performances from Don Cheadle and Chiwetal Ejiofor.', TO_DATE('2007-06-22', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tall tale', 2000, 'Tall Tale draws on American folk legends for a family-friendly adventure with disappointingly little appeal.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('talladega nights the ballad of ricky bobby', 2006, 'Though it occasionally stalls, Talladega Nights'' mix of satire, clever gags, and excellent ensemble performances put it squarely in the winner''s circle.', TO_DATE('2006-07-18', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tallulah', 2016, 'Tallulah''s narrative insight, thoughtfully written characters, and talented cast add up to an absorbing family drama that transcends genre tropes and capably overcomes its flirtations with melodrama.', TO_DATE('2016-01-24', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tamara', 2006, 'Resolutely misguided without ever really crossing into "so bad it''s good" territory, Tamara lacks even the cheap thrills promised by its premise.', TO_DATE('2006-01-07', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tamara drewe', 2010, 'A robust comedic cast and Stephen Frears'' gift for satire elevate Tamara Drewe''s slight scenario into a tart treat.', TO_DATE('2010-05-25', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tammy', 2014, 'Melissa McCarthy remains an engaging screen presence, but her efforts aren''t enough to keep the jumbled Tammy on track.', TO_DATE('2014-07-01', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tammys always dying', 2019, 'It occasionally struggles to deal effectively with its weighty themes, but Tammy''s Always Dying is always anchored by Felicity Huffman''s finely tuned performance.', TO_DATE('2019-09-06', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tampopo', 2000, 'Thanks to director Juzo Itami''s offbeat humor and sharp satirical edge, Tampopo is a funny, sexy, affectionate celebration of food and its broad influence on Japanese culture.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tangerine', 2015, 'Tangerine shatters casting conventions and its filmmaking techniques are up-to-the-minute, but it''s an old-fashioned comedy at heart -- and a pretty wonderful one at that.', TO_DATE('2015-01-24', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tangerines', 2015, 'Tangerines'' impassioned message and the strong work of a solid cast more than make up for the movie''s flawed narrative and uneven structure.', TO_DATE('2015-01-16', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tangled', 2007, 'While far from Disney''s greatest film, Tangled is a visually stunning, thoroughly entertaining addition to the studio''s classic animated canon.', TO_DATE('2007-10-06', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tango cash', 2000, 'Brutally violent and punishingly dull, this cookie-cutter buddy cop thriller isn''t even fun enough to reach "so bad it''s good" status.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tank girl', 2000, 'While unconventional, Tank Girl isn''t particularly clever or engaging, and none of the script''s copious one-liners have any real zing.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tape', 2001, 'Tape''s stagebound feel is balanced by the engrossing psychodrama of its storyline, which allows a committed cast to shine.', TO_DATE('2001-09-06', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tape', 2020, 'Tape''s palpable energy and honorable intentions are often undermined by uneven filmmaking, but it remains an intriguing, rage-fueled rallying cry.', TO_DATE('2020-03-17', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('targets', 2000, 'A startling directorial debut by Peter Bogdanovich mixes an homage to Boris Karloff horror films with a timely sniper story to create a thriller with modern baggage and old school shock and awe.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tarzan', 2000, 'Disney''s Tarzan takes the well-known story to a new level with spirited animation, a brisk pace, and some thrilling action set-pieces..', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('taxi', 2004, 'Silly and unfunny remake of a French movie of the same name.', TO_DATE('2004-09-19', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('taxi driver', 2000, 'A must-see film for movie lovers, this Martin Scorsese masterpiece is as hard-hitting as it is compelling, with Robert De Niro at his best.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('taxi to the dark side', 2007, 'Taxi to the Dark Side is an intelligent, powerful look into the dark corners of the War on Terror.', TO_DATE('2007-04-28', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tea with the dames nothing like a dame', 2018, 'Tea with the Dames proves there''s plenty of entertainment value to be found in rounding up a quartet of screen legends for a chat -- and is likely to leave audiences wishing these stars would keep brewing up pots for an ongoing series.', TO_DATE('2018-04-26', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('teachers pet', 2004, 'Despite its short running time, Teacher''s Pet is a witty and irreverent family film.', TO_DATE('2004-01-12', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('teaching mrs tingle', 2000, 'As a dark comedy-thriller, this movie lacks humor and thrill.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('team america world police', 2004, 'Team America will either offend you or leave you in stitches. It''ll probably do both.', TO_DATE('2004-10-09', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('fah talai jone tears of the black tiger', 2001, 'With a vibrant pastel color scheme and stylized action sequences, Tears of the Black Tiger is a bizarre, yet thoroughly entertaining Thai western.', TO_DATE('2001-06-29', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tears of the sun', 2003, 'Tries to be high-minded, but in the end, it''s just a stylish action movie.', TO_DATE('2003-03-03', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ted 2', 2015, 'Ted 2 reunites Mark Wahlberg and Seth MacFarlane for another round of sophomoric, scatological humor -- and just as before, your enjoyment will depend on your tolerance for all of the above.', TO_DATE('2015-06-24', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ted', 2012, 'Ted''s "romance versus bromance" plot is familiar, but the film''s held aloft by the high-concept central premise and a very funny (albeit inconsistent) script.', TO_DATE('2012-06-22', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ted bundy', 2002, 'Ted Bundy wastes an impressive performance from Michael Reilly Rourke on an exploitative film devoid of any social context or depth.', TO_DATE('2002-09-10', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('teen spirit', 2018, 'Teen Spirit tells a story we know by heart, but writer-director Max Minghella''s connection to the material and Elle Fanning''s remarkable performance add an effective hook.', TO_DATE('2018-09-09', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('teen titans go to the movies', 2018, 'Teen Titans Go! To the Movies distills the enduring appeal of its colorful characters into a charmingly light-hearted adventure whose wacky humor fuels its infectious fun -- and belies a surprising level of intelligence.', TO_DATE('2018-07-21', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('teen wolf', 2002, 'Though Michael J. Fox is as charismatic as ever, Teen Wolf''s coming-of-age themes can''t help but feel a little stale and formulaic.', TO_DATE('2002-04-03', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('teenage', 2014, 'Using a smartly assembled blend of archival footage and well-made re-enactments, Teenage surveys the rise of adolescent culture with tenderness and wit.', TO_DATE('2014-01-20', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('teenage mutant ninja turtles', 2014, 'Neither entertaining enough to recommend nor remarkably awful, Teenage Mutant Ninja Turtles may bear the distinction of being the dullest movie ever made about talking bipedal reptiles.', TO_DATE('2014-08-03', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('teenage mutant ninja turtles ii the secret of the ooze', 2000, 'Not only is the movie''s juvenile dialogue unbearable for adults, but the turtles'' dopey and casual attitude towards physical violence makes them poor kids'' role models.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('teenage mutant ninja turtles iii', 2000, 'It''s a case of one sequel too many for the heroes in a half shell, with a tired time-travel plot gimmick failing to save the franchise from rapidly diminishing returns.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('teenage mutant ninja turtles out of the shadows', 2016, 'Teenage Mutant Ninja Turtles: Out of the Shadows is a slight improvement over its predecessor, but still lacks the wit or anarchic energy of the comics that birthed the franchise.', TO_DATE('2016-05-30', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('teenage mutant ninja turtles the movie', 2000, 'Teenage Mutant Ninja Turtles is exactly as advertised: one-liners, brawls, and general silliness. Good for the young at heart, irritating for everyone else.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('teeth', 2007, 'Smart, original, and horrifically funny, Teeth puts a fresh feminist spin on horror movie tropes.', TO_DATE('2007-01-21', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tehran taboo', 2017, 'Tehran Taboo is a marvelous chronicle of a country through the prism of rotoscope, with the overlay of striking animation giving writer-director Ali Soozandeh''s acutely observed characters an extra dimension.', TO_DATE('2017-05-22', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tel aviv on fire', 2018, 'Thoughtful and well-acted, Tel Aviv on Fire highlights the awful absurdity of war -- and proves it''s possible to find humor in the midst of cultural conflict.', TO_DATE('2018-09-05', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tell it to the bees', 2018, 'Tell It to the Bees is well-acted and well-intentioned -- but often undermined by its frustratingly didactic storytelling.', TO_DATE('2018-09-10', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tell me who i am', 2019, 'While it may raise more questions than it ultimately answers, Tell Me Who I Am unravels a real-life horror story to devastating effect.', TO_DATE('2019-10-13', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('telstar telstar the joe meek story', 2008, 'Nick Moran''s excellent portrait of an often forgotten pop legend is as eccentric and chaotic as its subject.', TO_DATE('2008-11-06', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the temp', 1993, 'The Temp has an intriguing résumé, but consistently underperforms; immediate reassignment is recommended.', TO_DATE('1993-02-12', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the tempest', 2010, 'Director Julie Taymor''s gender-swapping of roles and some frenzied special effects can''t quite disguise an otherwise stagey, uninspired take on Shakespeare''s classic.', TO_DATE('2010-09-12', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('temple grandin', 2010, 'A heartfelt glimpse into Temple Grandin''s mind, this engrossing biopic reaches its full potential thanks to Claire Danes'' unsentimental performance.', TO_DATE('2010-02-08', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tenacious d in the pick of destiny', 2006, 'Tenacious D fan will find this movie hilarious; everybody else will see only a low-brow concept movie and a small assembly of jokes stretched past the 100 minute mark.', TO_DATE('2006-10-30', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the tenant', 2000, 'A rough-edged thriller that lacks the precision of Polanski''s best work, but makes up for it with its skillful mounting of paranoia, dread, and dark themes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tender mercies', 2000, 'Anchored by a deftly understated performance from Robert Duvall, Tender Mercies is a quiet character study that leaves a lasting emotional impact.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tequila sunrise', 2000, 'Tequila Sunrise unites three of its decade''s most in-demand stars for a slickly packaged crime drama that looks great without ever going anywhere particularly interesting.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('terminal', 2018, 'Worth seeking out for only the most hardcore of Margot Robbie completists, Terminal lives down to the medical definition of its title in dreadfully derivative fashion.', TO_DATE('2018-05-03', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('terminal velocity', 1994, 'More of a string of formulaic set pieces than an actual action thriller, Terminal Velocity ends up going nowhere fast.', TO_DATE('1994-09-23', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the terminator', 1984, 'With its impressive action sequences, taut economic direction, and relentlessly fast pace, it''s clear why The Terminator continues to be an influence on sci-fi and action flicks.', TO_DATE('1984-10-26', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('terminator 2 judgment day', 1991, 'T2 features thrilling action sequences and eye-popping visual effects, but what takes this sci-fi/ action landmark to the next level is the depth of the human (and cyborg) characters.', TO_DATE('1991-07-03', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('terminator 3 rise of the machines', 2003, 'Although T3 never reaches the heights of the second movie, it is a welcome addition to the Terminator franchise.', TO_DATE('2003-03-06', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('terminator salvation', 2009, 'With storytelling as robotic as the film''s iconic villains, Terminator Salvation offers plenty of great effects but lacks the heart of the original films.', TO_DATE('2009-05-18', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('terminator dark fate', 2019, 'Terminator: Dark Fate represents a significant upgrade over its immediate predecessors, even if it lacks the thrilling firepower of the franchise''s best installments.', TO_DATE('2019-10-22', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('terminator genisys', 2015, 'Mired in its muddled mythology, Terminator: Genisys is a lurching retread that lacks the thematic depth, conceptual intelligence, or visual thrills that launched this once-mighty franchise.', TO_DATE('2015-06-24', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('terms of endearment', 2000, 'A classic tearjerker, Terms of Endearment isn''t shy about reaching for the heartstrings -- but is so well-acted and smartly scripted that it''s almost impossible to resist.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('terri', 2011, 'Embodied with compelling sensitivity by newcomer Jacob Wysocki and supported by a wonderful John C. Reilly, Terri is an emotionally powerful character study.', TO_DATE('2011-01-24', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('terribly happy frygtelig lykkelig', 2010, 'Led by Henrik Ruben Ganz''s assured direction, this knotty Danish noir thriller steers audiences into some nicely unexpected territory.', TO_DATE('2010-01-04', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tesla', 2020, 'Appropriately bold and ambitious, Tesla takes a number of risks that don''t always pay off -- but Ethan Hawke''s performance makes those flaws easier to forgive.', TO_DATE('2020-01-28', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tess', 2000, 'A reverent adaptation of Thomas Hardy''s novel, Tess marries painterly cinematography and unhurried pacing to create an epic ode to perseverance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('testament of youth', 2014, 'Testament of Youth is well-acted and beautifully filmed, adding up to an enriching if not adventurous experience for fans of British period dramas.', TO_DATE('2014-10-14', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tetro', 2009, 'A complex meditation on family dynamics, Tetro''s arresting visuals and emotional core compensate for its uneven narrative.', TO_DATE('2009-05-12', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('texas chainsaw', 2013, 'As an ugly and cynical attempt to rebrand Leatherface as horror anti-hero, Texas Chainsaw 3D is a bold move for the franchise.', TO_DATE('2013-01-03', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the texas chainsaw massacre', 2003, 'An unnecessary remake that''s more gory and less scary than the original.', TO_DATE('2003-09-30', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the texas chainsaw massacre 2', 2000, 'The Texas Chainsaw Massacre 2 shocks with a gonzo blend of over-the-top humor and gore, but without the tense atmosphere of its predecessor, the stakes feel lower.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('texas chainsaw massacre the next generation', 1994, 'The Next Generation has the fortune of starring early-career Matthew McConaughey and Renée Zellweger, but it services neither headliner well in a convoluted and cheap-looking slasher that doesn''t live up to the Texas Chainsaw Massacre legacy.', TO_DATE('1994-10-07', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('texas killing fields', 2011, 'Texas Killing Fields is a competent boilerplate crime thriller, brewing up characters and plots used in better films.', TO_DATE('2011-09-09', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thank you for smoking', 2005, 'Loaded with delightfully unscrupulous characters and and a witty, cynical script, Thank You For Smoking is a sharp satire with a brilliantly smarmy lead performance from Aaron Eckhart.', TO_DATE('2005-09-12', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thank you for your service', 2017, 'Thank You for Your Service takes a sobering and powerfully acted -- if necessarily incomplete -- look at soldiers grappling with the horrific emotional impact of war.', TO_DATE('2017-10-24', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thanks for sharing', 2012, 'Thanks For Sharing showcases some fine performances but doesn''t delve into its thorny premise as deeply as it should.', TO_DATE('2012-09-09', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('that awkward moment', 2014, 'Formulaic and unfunny, That Awkward Moment wastes a charming cast on a contrived comedy that falls short of the date movies it seems to be trying to subvert.', TO_DATE('2014-01-15', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('that evening sun', 2009, 'Powered by a formidable leading turn from Hal Holbrook, That Evening Sun is a prime cut of southern gothic that offers plenty of meditative atmosphere for audiences to brood over.', TO_DATE('2009-11-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('that obscure object of desire', 2000, 'That Obscure Object of Desire is a frequently unsettling treatise on the quixotic nature of lust and love.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('that sugar film', 2015, 'That Sugar Film is slick and entertaining, even if it settles for a surface look at a subject that could benefit from a far deeper exploration.', TO_DATE('2015-02-27', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('that summer', 2018, 'Although likely most satisfying for Grey Gardens fans, That Summer adds a slight yet entertaining addendum to its classic predecessor.', TO_DATE('2018-02-15', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('that thing you do', 1996, 'A light, sweet, and thoroughly entertaining debut for director Tom Hanks, That Thing You Do! makes up in charm what it lacks in complexity.', TO_DATE('1996-10-04', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thats my boy', 2012, 'While it does represent a new foray into raunch for the normally PG-13 Sandler, That''s My Boy finds him repeating himself to diminishing effect - and dragging Andy Samberg down with him.', TO_DATE('2012-06-13', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the adventures of sharkboy and lavagirl in 3d', 2005, 'The decision to turn this kiddie fantasy into a 3-D film was a miscalculation.', TO_DATE('2005-05-26', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the amateurs the moguls dirty movie', 2006, 'The Amateurs is a largely unfunny sex comedy that squanders a talented cast.', TO_DATE('2006-04-06', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la demoiselle dhonneur the bridesmaid', 2004, 'Chabrol has crafted another sophisticated, unsettling thriller about sinister doings among the bourgeoisie.', TO_DATE('2004-11-17', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cake eaters', 2009, 'Though light on theme and craftsmanship, The Cake Eaters relies on fine performances and brisk direction to provide an affecting tale of small-town life.', TO_DATE('2009-03-06', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the company men', 2010, 'It might be hard for most viewers to identify with The Company Men''s well-heeled protagonists, but writer/director John Wells uses their plight to make universally resonant points -- and gets the most out of his excellent cast.', TO_DATE('2010-10-22', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the croods', 2013, 'While it may not be as (ahem) evolved as the best modern animated fare, The Croods will prove solidly entertaining for families seeking a fast-paced, funny cartoon adventure.', TO_DATE('2013-02-15', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the debut', 2001, 'Although The Debut offers few surprises, it remains an engaging and well-acted look at the multi-generational immigrant experience.', TO_DATE('2001-04-09', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the eagle', 2011, 'The Eagle has a pleasantly traditional action-adventure appeal, but it''s drowned out by Kevin Macdonald''s stolid direction and Channing Tatum''s uninspired work in the central role.', TO_DATE('2011-02-02', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the evil dead', 1981, 'This classic low budget horror film combines just the right amount of gore and black humor, giving The Evil Dead an equal amount of thrills and laughs.', TO_DATE('1981-10-15', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fall', 2006, 'More visually elaborate than the fragmented story can sometimes support, The Fall walks the line between labor of love and filmmaker self-indulgence.', TO_DATE('2006-09-09', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the family that preys', 2008, 'Tyler Perry''s The Family that Preys treads the filmmaker''s established terrain of family loyalty and moral uprightness, though the occasionally predictable plot slides forward, aided by an excess of soapy melodrama.', TO_DATE('2008-09-12', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the foot fist way', 2006, 'The rough edges and biting humor of this martial arts comedy will keep audiences laughing and cringing in turns.', TO_DATE('2006-01-26', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the great mouse detective', 2000, 'The Great Mouse Detective may not rank with Disney''s classics, but it''s an amiable, entertaining picture with some stylishly dark visuals.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the heart is deceitful above all things', 2004, 'The film aims to shock, but there is no higher reason for the parade of sordid images except to be "cool."', TO_DATE('2004-10-08', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the heart of the game', 2005, 'This group of high school girls and their eccentric basketball coach easily win your heart with their unusual humanity and dynamism.', TO_DATE('2005-06-11', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the killing of john lennon', 2007, 'Despite a committed performance by newcomer Jonas Ball, The Killing of John Lennon is ultimately a flimsy character study.', TO_DATE('2007-11-30', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man', 2005, 'Despite the steely presence of Samuel L. Jackson and the comic timing of Eugene Levy, The Man''s plot is pointless and its jokes rehashed, as it ends up playing out like the Odd Couple with gas.', TO_DATE('2005-09-06', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('professione reporter the passenger', 2000, 'Antonioni''s classic, a tale of lonely, estranged characters on a journey though the mysterious landscapes of identity, shimmers with beauty and uncertainty.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the romantics', 2010, 'The Romantics is visually accomplished, but director Galt Niederhoffer''s adaptation of her own novel never finds the passion on the page or offers audiences a reason to invest in these limp love affairs.', TO_DATE('2010-09-04', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the safety of objects', 2002, 'The large cast of characters and scripting are too unwieldy, and the suburban angst theme feels tired.', TO_DATE('2002-01-10', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the secret of kells', 2009, 'Beautifully drawn and refreshingly calm, The Secret of Kells hearkens back to animation''s golden age with an enchanting tale inspired by Irish mythology.', TO_DATE('2009-02-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the secret of roan inish', 1995, 'The Secret of Roan Inish is a gentle fairy tale filled with optimism that''s suitable for the whole family.', TO_DATE('1995-02-03', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the social network', 2010, 'Impeccably scripted, beautifully directed, and filled with fine performances, The Social Network is a riveting, ambitious example of modern filmmaking at its finest.', TO_DATE('2010-09-18', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the tigger movie', 2000, 'Tigger Movie may lack the technological flash and underlying adult sophistication of other recent animated movies, but it''s fun and charming.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the warriors way', 2010, 'Perfectly, thoroughly divisive, The Warrior''s Way will either be delightful or unbearable, depending on your tolerance for surreal, shamelessly over the top collisions of eastern and western clichés.', TO_DATE('2010-12-03', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the 100yearold man who climbed out the window and disappeared', 2014, 'Its efforts to earn laughs can be as ungainly as its title, but for viewers in tune with its absurdist humor, The 100-Year-Old Man Who Climbed Out the Window and Disappeared offers much to recommend.', TO_DATE('2014-02-27', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the 1517 to paris', 2018, 'The 15:17 to Paris pays clumsily well-intentioned tribute to an act of heroism, but by casting the real-life individuals involved, director Clint Eastwood fatally derails his own efforts.', TO_DATE('2018-02-07', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the 24th', 2020, 'The 24th might have told its fact-based story more fully, but despite its flaws, it remains an overall compelling -- and woefully overdue -- reckoning with history.', TO_DATE('2020-08-18', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the 33', 2015, 'The 33 offers an appropriately inspirational account of real-life heroism, but its stirring story and solid performances are undermined by a flawed focus and an overreliance on formula.', TO_DATE('2015-08-25', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the 9th life of louis drax', 2016, 'The 9th Life of Louis Drax is intriguing and visually compelling, but its disparate parts are never truly woven into a satisfying whole.', TO_DATE('2016-08-30', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the abcs of death', 2012, 'As is often the case with anthology films, The ABCs of Death is wildly uneven, with several legitimately scary entries and a bunch more that miss the mark.', TO_DATE('2012-09-13', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the accountant', 2016, 'The Accountant writes off a committed performance from Ben Affleck, leaving viewers with a scattershot action thriller beset by an array of ill-advised deductions.', TO_DATE('2016-10-12', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the act of killing', 2012, 'Raw, terrifying, and painfully difficult to watch, The Act of Killing offers a haunting testament to the edifying, confrontational power of documentary cinema.', TO_DATE('2012-09-10', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the addams family', 2019, 'The Addams Family''s starry voice cast and eye-catching animation aren''t enough to outweigh its saccharine handling of the delightfully dark source material.', TO_DATE('2019-10-10', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the adderall diaries', 2016, 'Stylistically overwrought and tedious, The Adderal Diaries aspires for profundity but instead feels like a shambolic class project thrown together right before it was due.', TO_DATE('2016-01-28', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the adventures of buckaroo banzai', 2000, 'Sci-fi parodies like these usually struggle to work, but Buckaroo Banzai succeeds through total devotion to its own lunacy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the adventures of tintin', 2010, 'Drawing deep from the classic Raiders of the Lost Ark playbook, Steven Spielberg has crafted another spirited, thrilling adventure in the form of Tintin.', TO_DATE('2010-02-19', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the african queen', 2000, 'Perfectly cast, smartly written, and beautifully filmed, The African Queen remains thrilling, funny, and effortlessly absorbing even after more than half a century''s worth of adventure movies borrowing liberally from its creative DNA.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the aftermath', 2019, 'Tasteful to a fault, The Aftermath is worth seeking out only for the most passionate period drama enthusiasts.', TO_DATE('2019-02-19', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the age of adaline', 2015, 'The Age of Adaline ruminates on mortality less compellingly than similarly themed films, but is set apart by memorable performances from Blake Lively and Harrison Ford.', TO_DATE('2015-04-10', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the air i breathe', 2007, 'The Air I Breathe is a jumbled indie production that accomplishes little save for the squandering of a talented cast.', TO_DATE('2007-05-02', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the amazing spiderman', 2012, 'A well-chosen cast and sure-handed direction allow The Amazing Spider-Man to thrill, despite revisiting many of the same plot points from 2002''s Spider-Man.', TO_DATE('2012-06-19', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the amazing spiderman 2', 2014, 'While the cast is outstanding and the special effects are top-notch, the latest installment of the Spidey saga suffers from an unfocused narrative and an overabundance of characters.', TO_DATE('2014-04-08', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the american', 2010, 'As beautifully shot as it is emotionally restrained, The American is an unusually divisive spy thriller -- and one that rests on an unusually subdued performance from George Clooney.', TO_DATE('2010-08-30', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the american meme', 2018, 'The American Meme dives into the shallow end of modern celebrity, emerging with a series of fascinating -- and surprisingly deep -- observations.', TO_DATE('2018-05-02', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the amityville horror', 2000, 'Dull and disappointing, the best that can be said for The Amityville Horror is that it set a low bar for its many sequels and remakes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the angels share', 2012, 'The Angels'' Share is a surprisingly delightful, uplifting comedy that successfully blends a charming story of redemption with bits of dark humor and a social message.', TO_DATE('2012-05-21', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the angry birds movie', 2016, 'The Angry Birds Movie is substantially more entertaining than any film adapted from an app has any right to be -- which may or may not be much of an endorsement.', TO_DATE('2016-05-07', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the angry birds movie 2', 2019, 'Like its non-aerodynamic title characters, The Angry Birds Movie 2 takes improbable yet delightfully entertaining flight, landing humorous hits along the way.', TO_DATE('2019-07-29', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the apparition', 2012, 'The Apparition fails to offer anything original, isn''t particularly scary, and offers so little in the way of dramatic momentum that it''s more likely to put you to sleep than thrill you.', TO_DATE('2012-08-23', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the apparition lapparition', 2018, 'The Apparition intrigues on a purely narrative level while also managing to tackle thorny questions of faith with suitably sober intelligence.', TO_DATE('2018-05-24', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the arbor', 2010, 'Smart and inventive, The Arbor offers some intensely memorable twists on tired documentary tropes.', TO_DATE('2010-10-13', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the armstrong lie', 2013, 'Smartly constructed and scathingly sharp, The Armstrong Lie presents an effective indictment of its unscrupulous subject -- as well as the sports culture that spawned him.', TO_DATE('2013-09-04', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the art of getting by', 2011, 'A sitcom-level twee mess that bakes in the typical manic pixie dream girl and boring, withdrawn boy hero.', TO_DATE('2011-01-24', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the art of racing in the rain', 2019, 'Its heartstring-tugging overtures may be difficult for dog lovers to resist, but The Art of Racing in the Rain is sentimental and contrived.', TO_DATE('2019-08-05', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the art of selfdefense', 2019, 'The Art of Self-Defense grapples compellingly with modern American masculinity -- and serves as an outstanding calling card for writer-director Riley Stearns.', TO_DATE('2019-03-11', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the art of the steal', 2013, 'It boasts a terrific cast led by the always-watchable Kurt Russell and Terence Stamp, but The Art of the Steal wastes its stars on a formulaic plot that borrows too obviously from superior heist pictures.', TO_DATE('2013-09-19', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the artist', 2011, 'A crowd-pleasing tribute to the magic of silent cinema, The Artist is a clever, joyous film with delightful performances and visual style to spare.', TO_DATE('2011-08-25', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the assassin', 2015, 'The Assassin''s thrilling visuals mark a fresh highlight for director Hsiao-hsien Hou, even if its glacial pace may keep some viewers at arm''s length.', TO_DATE('2015-05-28', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the assignment', 2016, 'The Assignment''s premise is bizarrely intriguing; unfortunately, it''s also just one of many ingredients fumbled in a disappointing misfire from director Walter Hill.', TO_DATE('2016-09-12', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the attack', 2012, 'Tense and suspenseful while remaining smart and understated, The Attack honors its complex subject with an intelligent script and captivating performances.', TO_DATE('2012-09-12', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the audition das vorspiel', 2019, 'It may occasionally veer into discordant territory, but The Audition remains a darkly illuminating character study led by a forceful turn from Nina Hoss.', TO_DATE('2019-09-08', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the autopsy of jane doe', 2016, 'The Autopsy of Jane Doe subverts the gruesome expectations triggered by its title to deliver a smart, suggestively creepy thriller that bolsters director André Ovredal''s growing reputation.', TO_DATE('2016-09-16', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the awakening', 2011, 'The Awakening never quite quickens the pulse the way it should, yet it remains a well-acted and handsomely assembled example of an old-fashioned supernatural thriller.', TO_DATE('2011-09-13', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the babadook', 2014, 'The Babadook relies on real horror rather than cheap jump scares -- and boasts a heartfelt, genuinely moving story to boot.', TO_DATE('2014-01-22', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the babymakers', 2012, 'The Babymakers mistakes raunch for humor and, despite a few sporadic laughs, wastes its otherwise capable cast on gross-out gags and misfired one-liners.', TO_DATE('2012-03-11', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the babysitter', 2017, 'Enjoyable if not particularly original, The Babysitter makes the most of its familiar genre ingredients with energetic direction and a killer cast.', TO_DATE('2017-10-12', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bad batch', 2016, 'The Bad Batch has its moments, but it''s too thinly written and self-indulgent to justify its length or compensate for its slow narrative drift.', TO_DATE('2016-09-06', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bag man', 2014, 'Busy with attitude and light on intrigue, The Bag Man is a mystery box with nothing surprising inside.', TO_DATE('2014-02-24', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ballad of buster scruggs', 2018, 'The Ballad of Buster Scruggs avoids anthology pitfalls with a consistent collection tied together by the Coen brothers'' signature blend of dark drama and black humor.', TO_DATE('2018-08-31', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bands visit', 2007, 'The Band''s Visit is both a clever, subtle slice-of-life comedy, and poignant cross-cultural exploration.', TO_DATE('2007-05-20', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the battle of algiers la battaglia di algeri', 2003, 'A documentary-like depiction of a nation''s real-life efforts to expel a colonizing force, The Battle of Algiers puts viewers on the front lines with gripping realism.', TO_DATE('2003-10-23', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bay', 2012, 'Barry Levinson''s eco-horror flick cleverly utilizes familiar found-footage methods in service of a gruesome yet atmospheric chiller.', TO_DATE('2012-09-22', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bay of silence', 2020, 'The Bay of Silence''s committed performances may be enough for thriller fans, but its twist heavy plot adds up to a muddled affair.', TO_DATE('2020-08-10', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the beach bum', 2019, 'The role of a lifetime for Matthew McConaughey, The Beach Bum is set apart by Harmony Korine''s distinctive style, but that isn''t always enough to offset the unfocused story.', TO_DATE('2019-03-10', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the beatles eight days a week the touring years', 2016, 'We love them, yeah, yeah, yeah -- and with archival footage like that, you know The Beatles: Eight Days a Week -- The Touring Years can''t be bad.', TO_DATE('2016-08-12', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the beaver', 2011, 'Jodie Foster''s visual instincts and Mel Gibson''s all-in performance sell this earnest, straightforward movie.', TO_DATE('2011-03-17', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the beguiled', 2017, 'The Beguiled adds just enough extra depth to its source material to set itself apart, and director Sofia Coppola''s restrained touch is enlivened by strong performances from the cast.', TO_DATE('2017-05-24', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the believer', 2001, 'Gosling commands the screen with a raw, electrifying performance.', TO_DATE('2001-02-09', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the belko experiment', 2016, 'The Belko Experiment offers a few moments of lurid fun for genre enthusiasts, but lacks enough subversive smarts to consistently engage once the carnage kicks in.', TO_DATE('2016-09-12', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the benefactor', 2015, 'The Benefactor has Richard Gere and Dakota Fanning, but no clear idea of what to do with either of them, resulting in a drama that never comes anywhere near its intriguing potential.', TO_DATE('2015-04-27', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the best exotic marigold hotel', 2012, 'The Best Exotic Marigold Hotel isn''t groundbreaking storytelling, but it''s a sweet story about the senior set featuring a top-notch cast of veteran actors.', TO_DATE('2012-02-09', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the best man holiday', 2013, 'The Best Man Holiday manages honest laughs out of broad humor, and affects convincing drama from a deeply conventional plot.', TO_DATE('2013-11-12', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the best of enemies', 2019, 'The Best of Enemies has the best of intentions, but they''re derailed by a problematic perspective and a disappointing lack of insight.', TO_DATE('2019-04-03', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the best of me', 2014, 'At nine films and counting, the line between Nicholas Sparks film fans and detractors is clear, and The Best of Me will change few minds on either side of the divide.', TO_DATE('2014-10-13', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the better angels', 2014, 'Malick-inspired but not as inspired as Malick, The Better Angels muffles an interesting idea under ponderous execution.', TO_DATE('2014-01-31', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bfg', 2016, 'The BFG minimizes the darker elements of Roald Dahl''s classic in favor of a resolutely good-natured, visually stunning, and largely successful family-friendly adventure.', TO_DATE('2016-05-14', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the big kahuna', 2000, 'Wonderful adaptation of the stage play.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the big lebowski', 1998, 'Typically stunning visuals and sharp dialogue from the Coen Brothers, brought to life with strong performances from Goodman and Bridges.', TO_DATE('1998-03-06', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the big short', 2015, 'The Big Short approaches a serious, complicated subject with an impressive attention to detail -- and manages to deliver a well-acted, scathingly funny indictment of its real-life villains in the bargain.', TO_DATE('2015-11-13', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the big sick', 2017, 'Funny, heartfelt, and intelligent, The Big Sick uses its appealing leads and cross-cultural themes to prove the standard romcom formula still has some fresh angles left to explore.', TO_DATE('2017-01-21', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the big wedding', 2013, 'The Big Wedding''s all-star cast is stranded in a contrived, strained plot that features broad stabs at humor but few laughs.', TO_DATE('2013-04-24', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the big year', 2011, 'Though made with care and affection for its characters, The Big Year plods along, rarely reaching any comedic heights.', TO_DATE('2011-10-10', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the birth of a nation', 2016, 'The Birth of a Nation overpowers its narrative flaws and uneven execution through sheer conviction, rising on Nate Parker''s assured direction and the strength of its vital message.', TO_DATE('2016-01-25', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bishops wife', 2001, 'The Bishop''s Wife succeeds thanks to the strength of winning performances from a stellar cast, which includes Cary Grant and Loretta Young.', TO_DATE('2001-08-21', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the black panthers vanguard of the revolution', 2015, 'The Black Panthers: Vanguard Of The Revolution offers a fascinating -- if somewhat rudimentary -- introduction to a movement, and an era, that remains soberingly relevant today.', TO_DATE('2015-04-09', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the blackcoats daughter february', 2015, 'Slow-building and atmospheric, The Blackcoat''s Daughter resists girls-in-peril clichés in a supernatural thriller that serves as a strong calling card for debuting writer-director Oz Perkins.', TO_DATE('2015-09-14', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bling ring', 2013, 'While it''s certainly timely and beautifully filmed, The Bling Ring suffers from director Sofia Coppola''s failure to delve beneath the surface of its shallow protagonists'' real-life crimes.', TO_DATE('2013-05-16', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the blob', 2000, 'In spite of its chortle-worthy premise and dated special effects, The Blob remains a prime example of how satisfying cheesy B-movie monster thrills can be.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the blob', 2000, 'The Blob can''t replicate the B-movie charms of the original, though its fast pace and gory thrills pack enough of a punch to make it a worthwhile update.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the body remembers when the world broke open', 2019, 'The Body Remembers When the World Broke Open uses an encounter between two strangers as the catalyst for a thoughtful drama as poetic as its title.', TO_DATE('2019-09-12', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bodyguard', 2000, 'The Bodyguard is a cheesy, melodramatic potboiler with occasional moments of electricity from Whitney Houston.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the book of eli', 2010, 'It''s certainly uneven, and many viewers will find that its reach exceeds its grasp, but The Book of Eli finds the Hughes brothers injecting some fresh stylish fun into the kind of post-apocalyptic wasteland filmgoers have seen more than enough of lately.', TO_DATE('2010-01-10', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the book of henry', 2017, 'The Book of Henry deserves a few points for ambition, but its tonal juggling act -- and a deeply maudlin twist -- may leave viewers gaping in disbelief rather than choking back tears.', TO_DATE('2017-06-14', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the book of life', 2014, 'The Book of Life''s gorgeous animation is a treat, but it''s a pity that its story lacks the same level of craft and detail that its thrilling visuals provide.', TO_DATE('2014-10-11', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the book thief', 2013, 'A bit too safe in its handling of its Nazi Germany setting, The Book Thief counters its constraints with a respectful tone and strong performances.', TO_DATE('2013-10-30', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bookshop', 2017, 'A rare adaptation that sticks too closely to its source material, The Bookshop''s meticulously crafted world building gets lost in its meandering pace.', TO_DATE('2017-11-08', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the boss', 2016, 'Melissa McCarthy remains as fiercely talented as ever, but her efforts aren''t enough to prop up the baggy mess of inconsistent gags and tissue-thin writing that brings down The Boss.', TO_DATE('2016-04-05', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the boss baby', 2017, 'The Boss Baby''s talented cast, glimmers of wit, and flashes of visual inventiveness can''t make up for a thin premise and a disappointing willingness to settle for doody jokes.', TO_DATE('2017-03-12', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bourne legacy', 2012, 'It isn''t quite as compelling as the earlier trilogy, but The Bourne Legacy proves the franchise has stories left to tell -- and benefits from Jeremy Renner''s magnetic work in the starring role.', TO_DATE('2012-08-06', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the boxer', 2000, 'The Boxer is a standard drama that packs a true emotional wallop thanks to the highly tuned central performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the boxtrolls', 2014, 'While it''s far from Laika''s best offering, The Boxtrolls is still packed with enough offbeat wit and visual splendor to offer a healthy dose of all-ages entertainment.', TO_DATE('2014-08-30', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the boy', 2016, 'The Boy could have gone in any number of scary or interesting directions, but instead settles for usual jump scares scattered throughout a pedestrian plot.', TO_DATE('2016-01-21', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the boy and the beast bakemono no ko', 2015, 'The Boy and the Beast combines familiar parts to create a gripping, beautifully animated adventure with inventive storytelling to match its visual appeal.', TO_DATE('2015-09-24', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the boy next door', 2015, 'The Boy Next Door may get a few howls out of fans of stalker thrillers, but for most viewers, it won''t even rise to "so bad it''s good" status.', TO_DATE('2015-01-21', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the boy who harnessed the wind', 2019, 'The Boy Who Harnessed the Wind earns its predictably uplifting arc through strong performances and impressive work from debuting director Chiwetel Ejiofor.', TO_DATE('2019-01-26', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the boys and girl from county clare', 2004, 'The Boys and Girl from County Clare is a charming - if entirely predictable - story about sibling rivalry featuring lively traditional Irish music.', TO_DATE('2004-08-21', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the brady bunch movie', 1995, 'Though lightweight and silly, The Brady Bunch Movie still charms as homage to the 70s sitcom.', TO_DATE('1995-02-17', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the brand new testament le tout nouveau testament', 2015, 'The Brand New Testament takes a surreal, subversive, and funny look at Biblical themes through a modern -- and refreshingly original -- lens.', TO_DATE('2015-07-17', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the breadwinner', 2017, 'The Breadwinner''s stunning visuals are matched by a story that dares to confront sobering real-life issues with uncommon -- and richly rewarding -- honesty.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the breaker upperers', 2018, 'The Breaker Upperers brings the laughs early and often, thanks to the dry wit -- and effervescent chemistry -- of writer-director-star duo Jackie van Beek and Madeleine Sami.', TO_DATE('2018-03-16', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the brink', 2019, 'The Brink won''t change many minds about its subject, but it remains a compelling -- if perhaps difficult to watch -- look at a divisive ideological lightning rod.', TO_DATE('2019-01-29', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the broken circle breakdown', 2013, 'The Broken Circle Breakdown''s reach occasionally exceeds its grasp, but overall, it''s an intoxicating, finely wrought romance -- and one with a terrific soundtrack to boot.', TO_DATE('2013-07-07', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bronze', 2015, 'Enthusiastically unpleasant and mostly unfunny, The Bronze fails to stick the landing -- or much else along the way.', TO_DATE('2015-01-23', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the brother from another planet', 2002, 'Featuring director John Sayles trademark humanity and an expressive performance from Joe Morton, The Brother from Another Planet is an observant, dryly comic sci-fi gem.', TO_DATE('2002-03-04', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the brothers grimsby', 2016, 'The Brothers Grimsby showers viewers with a steady stream of Sacha Baron Cohen''s edgy humor, but too many gags hit the wrong side of the line between audacious and desperate.', TO_DATE('2016-02-22', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the burbs', 1989, 'The ''Burbs has an engaging premise, likable cast, and Joe Dante at the helm -- so the mixed-up genre exercise they produce can''t help but feel like a disappointment.', TO_DATE('1989-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the bye bye man', 2017, 'The Bye Bye Man clumsily mashes together elements from better horror films, adding up to a derivative effort as short on originality as it is on narrative coherency or satisfying scares.', TO_DATE('2017-01-11', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cabin in the woods', 2012, 'The Cabin in the Woods is an astonishing meta-feat, capable of being funny, strange, and scary -- frequently all at the same time.', TO_DATE('2012-03-09', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cabinet of dr caligari das cabinet des dr caligari', 2000, 'Arguably the first true horror film, The Cabinet of Dr. Caligari set a brilliantly high bar for the genre -- and remains terrifying nearly a century after it first stalked the screen.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the call', 2013, 'The Call builds plenty of suspense before taking a problematic turn in the third act.', TO_DATE('2013-03-12', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the calling', 2014, 'The Calling offers an excellent cast and a few decent thrills, but that isn''t enough to overcome its lack of suspense or original ideas.', TO_DATE('2014-08-03', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the camden 28', 2007, 'Despite the fact the events chronicled in The Camden 28 occurred 30 years ago, this poignant and compassionate doc about Vietnam protesters is both powerful and timely.', TO_DATE('2007-07-05', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the campaign', 2012, 'Its crude brand of political satire isn''t quite as smart or sharp as one might hope in an election year, but The Campaign manages to generate a sufficient number of laughs thanks to its well-matched leads.', TO_DATE('2012-08-06', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the canyons', 2013, 'Oppressively misanthropic and ineptly made, The Canyons serves as a sour footnote in Paul Schrader''s career -- but it does feature some decent late-period work from Lindsay Lohan.', TO_DATE('2013-07-28', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the captain der hauptmann', 2017, 'The Captain makes chillingly persuasive points about the dark side of human nature -- and underscores how little certain tendencies ever really change.', TO_DATE('2017-09-08', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the captive', 2014, 'Wan and lugubrious, The Captive represents another atmospheric, beautifully filmed misfire from director Atom Egoyan.', TO_DATE('2014-05-16', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cartel', 2009, 'Director Bob Bowdon may make some strong points in The Cartel, but they''re drowned out by his grating screen presence and amateurish filmmaking.', TO_DATE('2009-10-08', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the case for christ', 2017, 'The Case for Christ shouldn''t be dismissed, but like many faith-based productions, it''s better at preaching to the choir than reaching the unconverted.', TO_DATE('2017-04-06', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the castle', 1999, 'Home is where the heart is in The Castle, a rousing Australian comedy that gives audiences an endearing family to root for.', TO_DATE('1999-05-07', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cat o nine tails il gatto a nove code', 2001, 'The Cat O''Nine Tails is a solidly entertaining Argento outing elevated by a well-chosen cast and the director''s distinctive visual style.', TO_DATE('2001-11-08', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cat returns', 2005, 'Sweetly charming and beautifully animated, The Cat Returns offers anime adventure suitable for the very young and young at heart.', TO_DATE('2005-02-26', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the catcher was a spy', 2018, 'The Catcher Was a Spy loses sight of the most interesting elements of its fact-based story, dropping the ball and leaving likable lead Paul Rudd stranded.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the celestine prophecy', 2006, 'Adapted from the bestselling self-help tome, The Celestine Prophesy is indifferently directed and acted, and its plotting is virtually tension-free.', TO_DATE('2006-04-21', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cell', 2000, 'The Cell offers disturbing, stunning eye candy, but its visual pleasures are no match for a confused storyline that undermines the movie''s inventive aesthetic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the changeup', 2011, 'There''s a certain amount of fun to be had from watching Bateman and Reynolds play against type, but it isn''t enough to carry The Change-Up through its crude humor and formulaic plot.', TO_DATE('2011-08-01', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the changeover', 2017, 'The Changeover may not bite deep enough for more seasoned horror fans, but it''s spooky enough for its younger target demographic.', TO_DATE('2017-09-28', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the chaser chugyeogja', 2008, 'A frantic and taut Korean serial killer thriller. One classy, if bloody and messy, gut wrencher of a movie.', TO_DATE('2008-02-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cherry orchard', 2002, 'This adaptation of The Cherry Orchard is too tedious to hold interest.', TO_DATE('2002-02-19', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the childhood of a leader', 2016, 'The Childhood of a Leader mirrors the rise of fascism in post-WWI Europe with a well-acted, confidently crafted look at one young man''s unsettling coming of age.', TO_DATE('2016-06-14', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the children act', 2017, 'The Children Act showcases yet another powerful performance from Emma Thompson, who elevates this undeniably flawed picture into an affecting adult drama.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the china hustle', 2017, 'The China Hustle may not have enough anger to wholly satisfy, but Jed Rothstein''s slick documentary is an informative primer on financial fraud on a geopolitical scale.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the choice', 2016, 'Like the 10 Nicholas Sparks movies before it, The Choice finds tragedy striking star-crossed lovers in the sun-dappled South -- yet even for those who loved its predecessors, this gauzy melodrama may feel painfully formulaic.', TO_DATE('2016-02-03', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the christmas chronicles', 2018, 'Viewers seeking a fresh holiday viewing option -- or those simply in the mood for Santa Kurt Russell -- should find The Christmas Chronicles well worth a yuletide stream.', TO_DATE('2018-11-14', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the circle', 2017, 'The Circle assembles an impressive cast, but this digitally driven thriller spins aimlessly in its half-hearted exploration of timely themes.', TO_DATE('2017-04-26', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the clapper', 2017, 'The Clapper is tugged along by the valiant efforts of a talented cast, but it''s ultimately not enough to make this wan romantic comedy worth a watch.', TO_DATE('2017-04-24', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the class', 2008, 'Energetic and bright, this hybrid of documentary style and dramatic plotting looks at the present and future of France through the interactions of a teacher and his students in an inner city high school.', TO_DATE('2008-05-24', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cleanse', 2016, 'The Cleanse uses its unconventional premise as the framework for a suitably eerie and solidly well-acted horror outing with some surprising emotional heft.', TO_DATE('2016-03-18', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the clovehitch killer', 2018, 'The Clovehitch Killer patiently dials up the tension with a story that makes up for a lack of surprises with strong performances and a chilling wit.', TO_DATE('2018-09-27', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cobbler', 2014, 'The Cobbler represents a slight step up from Adam Sandler''s recent comedies, but while its cloying sentiment proves a more palatable substitute for his usual crass humor, it still isn''t terribly compelling.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the collection', 2012, 'The Collection offers more grisly thrills and twisted humor than its predecessor; in other words, fun for genre fans, but unpleasant for anyone else.', TO_DATE('2012-09-22', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the colony', 2013, 'A formulaic sci-fi thriller, The Colony features cliched dialogue, cheesy special effects, and underdeveloped characters.', TO_DATE('2013-04-23', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the color wheel', 2011, 'The Color Wheel takes audiences along for a darkly entertaining ride, getting a surprising amount of mileage from utterly unlikable central characters along the way.', TO_DATE('2011-11-30', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the comedian', 2016, 'The Comedian boasts an incredibly talented cast, but they''re put to poor use in an aimless rom-com whose handful of memorable moments never add up to a compelling story.', TO_DATE('2016-11-11', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the comedy', 2012, 'Tim Heidecker''s misanthropic role proves him capable as a dramatic performer, yet The Comedy''s study of privilege unchecked is never as illuminating nor engaging as it should be.', TO_DATE('2012-01-24', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the command kursk', 2018, 'The Command plumbs the depths of real-life disaster to tell an uneven yet reasonably diverting story of lives caught between bureaucracy and certain doom.', TO_DATE('2018-09-07', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the commune kollektivet', 2016, 'The Commune may not stand with Thomas Vinterberg''s greatest work, but the end results remain thought-provoking and overall absorbing.', TO_DATE('2016-02-18', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the commuter', 2017, 'The Commuter''s cast is better than its workmanlike script - which helps make this reasonably diverting Liam Neeson action thriller worth the price of a matinee ticket or rental, if not a full-price ticket.', TO_DATE('2017-12-29', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the company you keep', 2012, 'The Company You Keep is a (frustratingly) slow-burning thriller about very contemporary issues.', TO_DATE('2012-09-06', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the conformist', 2000, 'A commentary on fascism and beauty alike, Bernardo Bertolucci''s The Conformist is acclaimed for its sumptuous visuals and extravagant, artful cinematography.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the congress', 2013, 'The Congress rises on the strength of Robin Wright''s powerful performance, with enough ambitious storytelling and technical thrills to overcome its somewhat messy structure.', TO_DATE('2013-05-16', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the conjuring', 2013, 'Well-crafted and gleefully creepy, The Conjuring ratchets up dread through a series of effective old-school scares.', TO_DATE('2013-06-22', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the conjuring 2', 2016, 'The Conjuring 2 can''t help but lose a bit of its predecessor''s chilly sting through familiarity, but what remains is still a superior ghost story told with spine-tingling skill.', TO_DATE('2016-06-02', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the connection', 2014, 'The Connection doesn''t do itself any favors by forcing comparisons to The French Connection, but it''s a reasonably entertaining thriller in its own right.', TO_DATE('2014-09-04', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the conquest', 2011, 'The Conquest commendably dramatizes French President Nicholas Sarkozy''s rise to power, with a persuasive ensemble and a politically astute script handsomely compensating for a generic visual presentation.', TO_DATE('2011-05-19', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the conspirator', 2010, 'The Conspirator is well cast and tells a worthy story, but many viewers will lack the patience for Redford''s deliberate, stagebound approach.', TO_DATE('2010-09-14', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the counselor', 2013, 'The Counselor raises expectations with its talented cast and creative crew -- then subverts them with a wordy and clumsy suspense thriller that''s mercilessly short on suspense or thrills.', TO_DATE('2013-10-23', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the counterfeiters', 2007, 'The Counterfeiters is a gripping account of one prisoner''s moral dilemma, superbly portrayed by Karl Markovics.', TO_DATE('2007-03-14', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the crash reel', 2013, 'Smart, compassionate, and moving, The Crash Reel uses the familiar sport-doc formula to subvert expectations and ask challenging questions about ambition and achievement.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the crocodile hunter collision course', 2002, 'Aside from the unnecessary plot about a downed US spy satellite, there''s not much difference between the movie and the TV show.', TO_DATE('2002-07-02', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the cured', 2017, 'The zombie apocalypse genre is crowded with clichés, but The Cured sets itself slightly apart with some extra BRAAAAAAAAAAINS and thematic depth.', TO_DATE('2017-09-12', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the current war directors cut', 2019, 'If it lacks the powerful voltage that its impressive cast suggests, The Current War: Director''s Cut represents a significant improvement over previous versions.', TO_DATE('2019-10-19', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the curse of la llorona', 2019, 'Content to coast on jump scares rather than tap into its story''s creepy potential, The Curse of La Llorona arrives in theaters already broken.', TO_DATE('2019-03-16', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dalai lama scientist', 2020, 'Much like the public figure it follows, The Dalai Lama: Scientist explores the meeting places of faith and science, seeing the best in both.', TO_DATE('2020-04-03', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the danish girl', 2015, 'The Danish Girl serves as another showcase for Eddie Redmayne''s talent -- and poignantly explores thought-provoking themes with a beautifully filmed biopic drama.', TO_DATE('2015-09-05', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dark horse', 2014, 'Led by an outstanding performance from Cliff Curtis, The Dark Horse tackles complex themes with a richly layered, unpredictable, and deeply affecting story.', TO_DATE('2014-07-17', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dark knight', 2008, 'Dark, complex, and unforgettable, The Dark Knight succeeds not just as an entertaining comic book film, but as a richly thrilling crime saga.', TO_DATE('2008-06-25', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dark knight rises', 2012, 'The Dark Knight Rises is an ambitious, thoughtful, and potent action film that concludes Christopher Nolan''s franchise in spectacular fashion.', TO_DATE('2012-07-16', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dark tower', 2017, 'Go then, there are other Stephen King adaptations than these.', TO_DATE('2017-08-03', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the darkest hour', 2011, 'Devoid of believable characters or convincing visual effects, this may be The Darkest Hour for the careers of all involved.', TO_DATE('2011-12-25', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the darkest minds', 2018, 'The Darkest Minds does little to differentiate itself in a crowded field of YA adaptations, leaving all but the least demanding viewers feeling dystopian déjà vu.', TO_DATE('2018-07-31', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the darkness', 2016, 'The Darkness clumsily relies on an assortment of genre tropes, leaving only the decidedly non-frightening ghost of superior horror films in its wake.', TO_DATE('2016-05-12', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the day shall come', 2019, 'Absurd yet anchored in knotty real-world themes, The Day Shall Come adds another bleakly funny satire to director/co-writer Christopher Morris'' filmography.', TO_DATE('2019-03-12', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dead dont die', 2019, 'The Dead Don''t Die dabbles with tones and themes to varying degrees of success, but sharp wit and a strong cast make this a zom-com with enough brains to consume.', TO_DATE('2019-05-14', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dead lands', 2014, 'The Dead Lands doesn''t add anything new to the primeval quest genre, but its battle scenes boast enough visceral thrills to carry viewers through the more mundane moments.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the deal', 2005, 'Dense with detail but light on entertainment value, The Deal turns a potentially riveting subject into a sloppily assembled -- and progressively more implausible -- misfire.', TO_DATE('2005-06-03', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the death and life of john f donovan', 2018, 'The Death and Life of John F. Donovan finds writer-director Xavier Dolan flailing at profundity with a technically assured drama that never makes sense of its own ideas.', TO_DATE('2018-09-11', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the death and life of marsha p johnson', 2017, 'The Death and Life of Marsha P. Johnson uses its belated investigation into an activist''s murder as the framework for a sobering look at the ongoing battle for equal rights.', TO_DATE('2017-04-23', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the death of dick long', 2019, 'The Death of Dick Long mixes dark humor with provocative ideas to produce a sharp blend that''s admittedly uneven but uniquely satisfying.', TO_DATE('2019-01-27', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the death of mr lazarescu', 2005, 'Shot in naturalistic style, this is a powerful indictment of absurdity and indifference in the face of human suffering.', TO_DATE('2005-09-19', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the death of stalin', 2017, 'The Death of Stalin finds director/co-writer Arnando Iannucci in riotous form, bringing his scabrous political humor to bear on a chapter in history with painfully timely parallels.', TO_DATE('2017-09-09', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the deep blue sea', 2011, 'Featuring an outstanding performance by Rachel Weisz, The Deep Blue Sea is a visually stunning, melancholy tale of subsumed passion.', TO_DATE('2011-09-12', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the deer hunter', 2000, 'Its greatness is blunted by its length and one-sided point of view, but the film''s weaknesses are overpowered by Michael Cimino''s sympathetic direction and a series of heartbreaking performances from Robert De Niro, Meryl Streep, and Christopher Walken.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the descendants', 2011, 'Funny, moving, and beautifully acted, The Descendants captures the unpredictable messiness of life with eloquence and uncommon grace.', TO_DATE('2011-09-03', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the descent 2', 2009, 'The Descent 2 goes spelunking for its predecessors'' unnerving power but never digs beyond surface chills, although this efficient splatterfest contains enough nasty set pieces to sate the gore-prone.', TO_DATE('2009-05-17', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the devil inside', 2012, 'The Devil Inside is a cheap, choppy unscary mess, featuring one of the worst endings in recent memory.', TO_DATE('2012-01-04', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the devil wears prada', 2006, 'A rare film that surpasses the quality of its source novel, this Devil is a witty expose of New York''s fashion scene, with Meryl Streep in top form and Anne Hathaway more than holding her own.', TO_DATE('2006-06-17', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the devils candy', 2015, 'The Devil''s Candy playfully subverts horror tropes while serving up more than enough stylish thrills to satisfy genre enthusiasts.', TO_DATE('2015-09-16', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the devils double', 2011, 'The Devil''s Double has plenty of gangster spectacle and Dominic Cooper ably playing off his dual roles, but this crime epic struggles to balance the fun of bad behavior with the dead serious crimes of its subject.', TO_DATE('2011-01-24', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the devils miner', 2005, 'A visually arresting documentary that offers a powerful and unforgettable look into the silver mining industry and child labor.', TO_DATE('2005-04-22', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the diary of a teenage girl', 2015, 'Boldly unconventional and refreshingly honest, Diary of a Teenage Girl is a frank coming-of-age story that addresses its themes -- and its protagonist -- without judgment.', TO_DATE('2015-01-24', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dictator', 2012, 'Wildly uneven but consistently provocative, The Dictator is a decent entry in the poli-slapstick comedy genre.', TO_DATE('2012-05-10', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dilemma', 2011, 'It boasts a likable cast and an interesting premise, but The Dilemma can''t decide what to do with them; the result is an uneven blend of cheesy slapstick and surprisingly dark comedy.', TO_DATE('2011-01-10', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dinner', 2017, 'The Dinner''s strong ensemble isn''t enough to overcome a screenplay that merely skims the surface of its source material''s wit and insight.', TO_DATE('2017-02-10', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dirt', 2019, 'The Dirt celebrates the rude debauchery that Mötley Crüe''s fans enjoy -- but does so with the dispiriting lack of substance that the group''s critics have long decried.', TO_DATE('2019-03-22', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the disappearance of eleanor rigby them', 2013, 'Led by strong performances from Jessica Chastain and James McAvoy, The Disappearance of Eleanor Rigby is a hauntingly original rumination on love and loss.', TO_DATE('2013-09-27', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the disappointments room', 2016, 'The Disappointments Room lives down to its title with a thrill-free thriller that presumably left its stars filled with regret - and threatens to do the same for audiences.', TO_DATE('2016-09-09', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the disaster artist', 2017, 'Oh, hai Mark. The Disaster Artist is a surprisingly poignant and charming movie-about-a-movie that explores the creative process with unexpected delicacy.', TO_DATE('2017-03-13', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the discovery', 2017, 'The Discovery looks fascinating on paper, but in spite of its thought-provoking premise and starry ensemble, it''s a disappointing case of untapped potential.', TO_DATE('2017-01-21', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the divergent series allegiant', 2016, 'Allegiant improves on previous entries in The Divergent Series on a few superficial levels, but they aren''t enough to counteract a sense of growing boredom with a franchise that''s gone on too long.', TO_DATE('2016-03-06', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the divine order die göttliche ordnung', 2017, 'The likable cast carries The Divine Order, a crowd-pleasing film that delivers a rousing -- if surface level -- account of the Swiss women''s suffrage movement.', TO_DATE('2017-10-06', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the diving bell and the butterfly', 2007, 'Breathtaking visuals and dynamic performances make The Diving Bell and the Butterfly a powerful biopic.', TO_DATE('2007-05-23', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dog', 2013, 'Fascinating, evocative, and as unconventional as its subject, The Dog offers a colorful window into the real-life story behind a classic film.', TO_DATE('2013-09-23', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the double', 2011, 'Riddled with hollow characters and ludicrous plotting, The Double just isn''t worth the trouble.', TO_DATE('2011-09-19', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the double', 2013, 'Hauntingly bleak and thrillingly ambitious, The Double offers Jesse Eisenberg a pair of compelling roles while reaffirming writer-director Richard Ayoade''s remarkable talent.', TO_DATE('2013-09-09', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dresser', 2016, 'The Dresser brilliantly showcases two of the most gifted actors of their generation within a thoughtful, well-executed production offering intelligent commentary on the human condition.', TO_DATE('2016-05-25', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the dressmaker', 2015, 'The Dressmaker boasts a strong central performance by Kate Winslet and a captivating array of narrative weirdness -- all of which may or may not be a comfortable fit with viewers.', TO_DATE('2015-09-14', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the drop', 2014, 'There''s no shortage of similarly themed crime dramas, but The Drop rises above the pack with a smartly written script and strong cast.', TO_DATE('2014-09-05', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the duff', 2015, 'The DUFF doesn''t achieve teen-movie greatness, but offers enough of a postmodern twist on the genre to recommend -- and boasts typically great work from star Mae Whitman.', TO_DATE('2015-02-18', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the duke of burgundy', 2014, 'Stylish, sensual, and smart, The Duke of Burgundy proves that erotic cinema can have genuine substance.', TO_DATE('2014-09-08', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the eagle huntress', 2016, 'Effectively stirring and bolstered by thrilling visuals, The Eagle Huntress uses its heartwarming message to fill up a feature that might have made for an even more powerful short film.', TO_DATE('2016-01-29', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the earrings of madame de madame de', 2000, 'Ophüls'' graceful camerawork and visual portrayal of luxury and loss make Earrings a powerful French drama.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the east', 2013, 'Tense, thoughtful, and deftly paced, The East is a political thriller that never loses sight of the human element.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the edge of democracy', 2019, 'Assembled with absorbing insight and passion by director Petra Costa, The Edge of Democracy is a disturbing and expansive overview of how a democratic nation can teeter into autocracy.', TO_DATE('2019-01-26', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the edge of seventeen', 2016, 'The Edge of Seventeen''s sharp script -- and Hailee Steinfeld''s outstanding lead performance -- make this more than just another coming-of-age dramedy.', TO_DATE('2016-09-16', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the edukators', 2004, 'The Edukators engagingly plays out the clash between youthful idealism and older pragmaticism.', TO_DATE('2004-11-06', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the elephant queen', 2018, 'Informative, compassionate, and beautifully filmed, The Elephant Queen should satisfy nature documentary lovers of all ages.', TO_DATE('2018-09-12', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the emoji movie', 2017, '🚫', TO_DATE('2017-07-27', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the end of the tour', 2015, 'Brilliantly performed and smartly unconventional, The End of the Tour pays fitting tribute to a singular talent while offering profoundly poignant observations on the human condition.', TO_DATE('2015-01-24', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the endless', 2017, 'The Endless benefits from its grounded approach to an increasingly bizarre story, elevated by believable performances by filmmakers Justin Benson and Aaron Moorhead.', TO_DATE('2017-04-21', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the equalizer', 2014, 'The Equalizer is more stylishly violent than meaningful, but with Antoine Fuqua behind the cameras and Denzel Washington dispensing justice, it delivers.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the escape', 2017, 'The Escape probes gender mores while surveying the wreckage of a marriage -- and offering the underrated Gemma Arterton another opportunity to prove her dramatic mettle.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('evil dead', 2013, 'It may lack the absurd humor that underlined the original, but the new-look Evil Dead compensates with brutal terror, gory scares, and gleefully bloody violence.', TO_DATE('2013-03-08', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the exception the kaisers last kiss', 2016, 'The Exception (The Kaiser''s Last Kiss) elegantly blends well-dressed period romance and war drama into a solidly crafted story further elevated by Christopher Plummer''s excellent work and the efforts of a talented supporting cast.', TO_DATE('2016-09-16', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the expendables', 2010, 'It makes good on the old-school action it promises, but given all the talent on display, The Expendables should hit harder.', TO_DATE('2010-08-04', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the expendables 2', 2012, 'Taut, violent, and suitably self-deprecating, The Expendables 2 gives classic action fans everything they can reasonably expect from a star-studded shoot-''em-up -- for better and for worse.', TO_DATE('2012-08-12', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the expendables 3', 2014, 'Like its predecessors, Expendables 3 offers a modicum of all-star thrills for old-school action thriller aficionados -- but given all the talent assembled, it should have been a lot more fun.', TO_DATE('2014-08-04', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the exterminating angel el ángel exterminador', 2000, 'Societal etiquette devolves into depravity in Luis Buñuel''s existential comedy, effectively playing the absurdity of civilization for mordant laughs.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the eyes of my mother', 2016, 'The Eyes of My Mother uses a shocking trauma to fuel a hauntingly hypnotic odyssey whose nightmarish chill lingers long after the closing credits.', TO_DATE('2016-01-23', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the face of an angel', 2014, 'The Face of an Angel finds director Michael Winterbottom in pursuit of ideas that remain frustratingly diffuse and agonizingly out of his grasp.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the face of love', 2013, 'Perhaps worth checking out if only for the opportunity to see reliably powerful work from Annette Bening and Ed Harris, The Face of Love undermines its leads'' performances with a scattershot script and aimless direction.', TO_DATE('2013-09-16', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fall of the house of usher', 1960, 'Scary, strange, and maybe a little silly, House of Usher represents an early high mark for Vincent Price and a career triumph for director Roger Corman.', TO_DATE('1960-05-22', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the falling', 2014, 'Well-acted and overall unsettling, The Falling delivers thought-provoking thrills -- and suggests a bright future for writer-director Carol Morley.', TO_DATE('2014-10-10', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the family', 2013, 'Luc Besson''s The Family suffers from an overly familiar setup and a number of jarring tonal shifts.', TO_DATE('2013-09-12', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the family fang', 2015, 'Layered performances from Nicole Kidman and director-star Jason Bateman add extra depth to The Family Fang''s sharply observed look at domestic dysfunction.', TO_DATE('2015-09-14', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fanatic', 2019, 'John Travolta gives it his oddly coiffed all, but The Fanatic rings hollow as an examination of the way fan appreciation can curdle into toxic obsession.', TO_DATE('2019-08-26', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the farewell', 2019, 'The Farewell deftly captures complicated family dynamics with a poignant, well-acted drama that marries cultural specificity with universally relatable themes.', TO_DATE('2019-01-26', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fate of the furious', 2017, 'The Fate of the Furious opens a new chapter in the franchise, fueled by the same infectious cast chemistry and over-the-top action fans have come to expect.', TO_DATE('2017-04-09', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fault in our stars', 2014, 'Wise, funny, and heartbreaking without resorting to exploitation, The Fault In Our Stars does right by its bestselling source material.', TO_DATE('2014-05-20', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the favourite', 2018, 'The Favourite sees Yorgos Lanthimos balancing a period setting against rich, timely subtext - and getting roundly stellar performances from his well-chosen stars.', TO_DATE('2018-08-30', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fearless vampire killers', 2000, 'This uneven but amiable 1967 vampire picture is part horror spoof, part central European epic, and 100 percent Roman Polanski, whose signature sensibility colors every frame.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fifth estate', 2013, 'Heavy on detail and melodrama but missing the spark from its remarkable real-life inspiration, The Fifth Estate mostly serves as a middling showcase for Benedict Cumberbatch''s remarkable talent.', TO_DATE('2013-09-05', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the 5th wave', 2016, 'With unimpressive effects and plot points seemingly pieced together from previous dystopian YA sci-fi films, The 5th Wave ends up feeling like more of a limp, derivative wriggle.', TO_DATE('2016-01-13', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fight', 2020, 'The Fight takes an engaging look at some of the people working on the front lines for the ACLU -- and makes a passionate case for the legal battles they wage.', TO_DATE('2020-01-25', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fighter', 2010, 'Led by a trio of captivating performances from Mark Wahlberg, Christian Bale, and Amy Adams, The Fighter is a solidly entertaining, albeit predictable, entry in the boxing drama genre.', TO_DATE('2010-11-10', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the final girls', 2015, 'The Final Girls offers an affectionate nod to slasher tropes while adding a surprising layer of genuine emotion to go with the meta amusement.', TO_DATE('2015-03-14', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the final member', 2012, 'The Final Member refuses to coast on its provocative subject matter, delivering an engrossing documentary of economic length and impressive depth.', TO_DATE('2012-10-13', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the final year', 2017, 'The Final Year uses director Greg Barker''s wide-ranging access to take a detailed inside look at the closing months of the Obama administration.', TO_DATE('2017-09-09', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the finest hours', 2016, 'Old-fashioned to a fault, The Finest Hours will satisfy those seeking a traditional rescue drama - but may leave more adventurous viewers wanting more.', TO_DATE('2016-01-18', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the first monday in may', 2016, 'First Monday in May may not resonate far beyond its target demographic, but for fashion aficionados, it should prove utterly absorbing.', TO_DATE('2016-04-13', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the first purge', 2018, 'The First Purge should satisfy fans of the franchise and filmgoers in the mood for violent vicarious thrills, even if its subtextual reach exceeds its grasp.', TO_DATE('2018-07-03', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fits', 2016, 'As gripping as it is unique, the thrillingly kinetic The Fits marks debuting writer-director Anna Rose Holmer as a singular talent.', TO_DATE('2016-01-29', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fiveyear engagement', 2012, 'While certainly overlong, The Five-Year Engagement benefits from the easy chemistry of its leads and a funny, romantic script with surprising depth and intelligence.', TO_DATE('2012-04-19', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the flintstones', 1994, 'The Flintstones wastes beloved source material and imaginative production design on a tepid script that plunks Bedrock''s favorite family into a cynical story awash with lame puns.', TO_DATE('1994-05-25', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the flood', 2019, 'Imperfect yet ultimately honorable, The Flood takes an empathetic look at the plight of asylum seekers in the 21st century.', TO_DATE('2019-06-17', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the florida project', 2017, 'The Florida Project offers a colorfully empathetic look at an underrepresented part of the population that proves absorbing even as it raises sobering questions about modern America.', TO_DATE('2017-05-23', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the flower of my secret la flor de mi secreto', 2000, 'The Flower of My Secret finds Almodóvar revisiting old themes in a new, more subdued key, yielding a slight but vivacious work that delivers the pleasure of a punchy novella.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the flowers of war', 2011, 'Zhang Yimou''s stylistic flair is in full bloom during The Flowers of War, but his colorful treatment of a historical genocide ultimately does a disservice to the horrifying events'' inherent drama.', TO_DATE('2011-12-18', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fluffer', 2001, 'Though it begins promisingly enough, The Fluffer eventually descends into melodrama.', TO_DATE('2001-10-05', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fog', 2002, 'A well-crafted return to horror for genre giant John Carpenter, The Fog rolls in and wraps viewers in suitably slow-building chills.', TO_DATE('2002-01-27', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fog of war eleven lessons from the life of robert s mcnamara', 2003, 'The Fog of War draws on decades of bitter experience to offer a piercing perspective on the Cold War from one of its major architects.', TO_DATE('2003-06-11', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the forbidden room', 2015, 'The Forbidden Room may frustrate viewers looking for a linear experience, but those seeking a challenge -- or already familiar with director Guy Maddin''s work -- will be rewarded.', TO_DATE('2015-01-27', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the foreigner', 2017, 'The Foreigner adheres strictly to action thriller formula, but benefits from committed -- and out of character -- performances from its talented veteran stars.', TO_DATE('2017-09-27', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the forest', 2016, 'The Forest offers Natalie Dormer a few chances to showcase her range in a dual role, but they aren''t enough to offset the fact that the movie''s simply not all that scary.', TO_DATE('2016-01-06', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the forger', 2014, 'So rote that its star is overshadowed by his wig, The Forger offers nary a thrill nor a scintilla of suspense that couldn''t be overpowered by a decent basic-cable drama.', TO_DATE('2014-09-09', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the forgiveness of blood', 2011, 'Acutely observed with naturalistic performances, The Forgiveness of Blood reaffirms director Joshua Marston''s gift for cultural commentary through intimate storytelling.', TO_DATE('2011-06-14', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the founder', 2016, 'The Founder puts Michael Keaton''s magnetic performance at the center of a smart, satisfying biopic that traces the rise of one of America''s most influential businessmen -- and the birth of one of its most far-reaching industries.', TO_DATE('2016-11-20', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fountain', 2006, 'The Fountain -- a movie about metaphysics, universal patterns, Biblical symbolism, and boundless love spread across one thousand years -- is visually rich but suffers from its own unfocused ambitions.', TO_DATE('2006-07-13', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the four times le quattro volte', 2010, 'Birth, death, and transformation are examined in Le Quattro Volte, a profound and often funny mediation on the cycles of life on earth.', TO_DATE('2010-09-22', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fox the child', 2008, 'Jackanory-esque voiceover from Winslet lends a syrupy tone to this mawkish and slow, but beautifully shot, human/beastie buddy movie.', TO_DATE('2008-01-14', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the frighteners', 1996, 'Boasting top-notch special effects and exuberant direction from Peter Jackson, The Frighteners is visually striking but tonally uneven.', TO_DATE('1996-07-19', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the frisco kid', 2000, 'Not even a genial Gene Wilder or a dashing Harrison Ford can rescue The Frisco Kid from a monotonous procession of gently comedic sketches that never cohere into a memorable yarn.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the front runner', 2018, 'The Front Runner exhumes the wreckage of a political campaign with well-acted wit, even if it neglects to truly analyze the issues it raises.', TO_DATE('2018-09-01', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the frozen ground', 2013, 'Though this by-the-numbers true procedural seems basic, The Frozen Ground presents a welcome return for Nicolas Cage in a solid performance.', TO_DATE('2013-07-09', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the fundamentals of caring', 2016, 'The Fundamentals of Caring gets maximum mileage out of the chemistry between its well-matched leads as it follows a fairly well-worn coming-of-age road trip route.', TO_DATE('2016-01-23', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the future', 2011, 'A dark and whimsical exploration of human existence that challenges viewers as much as it rewards them.', TO_DATE('2011-01-31', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the future of food', 2005, 'The Future of Food is a one-sided, but revelatory documentary about the dangers of genetically modified food.', TO_DATE('2005-08-18', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the galapagos affair satan came to eden', 2014, 'It doesn''t quite live up to its marvelously lurid premise, but The Galapagos Affair is still stranger than fiction in a very entertaining way.', TO_DATE('2014-03-31', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the gallows', 2015, 'Narratively contrived and visually a mess, The Gallows sends viewers on a shaky tumble to the bottom of the found-footage horror barrel.', TO_DATE('2015-07-07', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the gambler', 2014, 'Well-paced and reasonably entertaining in its own right, The Gambler still suffers from comparisons to the James Caan classic that inspired it.', TO_DATE('2014-11-10', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the game plan', 2007, 'Despite The Rock''s abundant charisma, The Game Plan is just another run-of-the-mill Disney comedy.', TO_DATE('2007-09-18', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the gangster the cop the devil', 2019, 'An odd couple cop thriller with a twist, The Gangster, The Cop, The Devil tells its entertaining story with a blend of humor and hard-hitting action.', TO_DATE('2019-05-15', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the garden left behind', 2019, 'The Garden Left Behind draws on one immigrant''s journey to offer graceful, thought-provoking commentary on timely sociopolitical themes.', TO_DATE('2019-03-10', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('hemingways garden of eden', 2010, 'Garden of Eden dramatizes Ernest Hemingway''s clipped storytelling without carrying over the intelligence that undergirded the author''s writing, yielding a thin drama full of artifice and no feeling.', TO_DATE('2010-11-04', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the gatekeepers', 2012, 'Strikingly stark, brutally honest, and rivetingly assembled, The Gatekeepers offers essential perspective on a seemingly intractable war from some of the men who fought it.', TO_DATE('2012-09-09', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the gentlemen', 2019, 'It may not win writer-director Guy Ritchie many new converts, but for those already attuned to the filmmaker''s brash wavelength, The Gentlemen stands tall.', TO_DATE('2019-12-19', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the german doctor', 2013, 'The German Doctor applies a refreshing level of restraint to its intriguing premise, and boasts solid performances from a talented cast.', TO_DATE('2013-05-23', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ghost of peter sellers', 2018, 'A soul-searching act of therapy for its director, The Ghost of Peter Sellers offers absorbing insight into how some decisions -- and people -- can haunt us long after they''re gone.', TO_DATE('2018-09-05', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the gift', 2015, 'The Gift is wickedly smart and playfully subversive, challenging the audience''s expectations while leaving them leaning on the edges of their seats.', TO_DATE('2015-07-22', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the girl in the spiders web', 2018, 'The Girl in the Spider''s Web focuses on the action elements of its source material for a less complex -- and only sporadically effective -- franchise reboot.', TO_DATE('2018-10-24', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the girl on the train', 2016, 'Emily Blunt''s outstanding performance isn''t enough to keep The Girl on the Train from sliding sluggishly into exploitative melodrama.', TO_DATE('2016-10-03', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the girl', 2013, 'The Girl may be too prosaic to properly evoke its subject, but sterling performances by Toby Jones and Sienna Miller bring to life one of cinematic history''s most horrific abuses of power.', TO_DATE('2013-01-10', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the girl who kicked the hornets nest', 2010, 'Slow and mostly devoid of the stellar chemistry between its two leads, The Girl Who Kicked The Hornet''s Nest is a disappointingly uneven conclusion to the Millennium trilogy.', TO_DATE('2010-07-29', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the girl who leapt through time', 2008, 'An imaginative and thoughtfully engaging anime film with a highly effective visual design. This coming-of-age comedy drama has mad inventiveness to spare.', TO_DATE('2008-06-11', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the girl with all the gifts', 2016, 'The Girl with All the Gifts grapples with thought-provoking questions without skimping on the scares -- and finds a few fresh wrinkles in the well-worn zombie horror genre along the way.', TO_DATE('2016-08-03', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the girl with the dragon tattoo', 2010, 'Brutal yet captivating, The Girl With the Dragon Tattoo is the result of David Fincher working at his lurid best with total role commitment from star Rooney Mara.', TO_DATE('2010-08-23', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the girl with the dragon tattoo', 2009, 'Its graphic violence and sprawling length will prove too much for some viewers to take, but Noomi Rapace''s gripping performance makes The Girl with the Dragon Tattoo an unforgettable viewing experience.', TO_DATE('2009-02-27', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the giver', 2014, 'Phillip Noyce directs The Giver with visual grace, but the movie doesn''t dig deep enough into the classic source material''s thought-provoking ideas.', TO_DATE('2014-08-11', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the glass castle', 2017, 'The Glass Castle has an affecting real-life story and a hard-working cast in its corner, but they aren''t enough to outweigh a fundamentally misguided approach to the material.', TO_DATE('2017-08-06', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the glass shield', 2000, 'The Glass Shield struggles under the weight of its worthy themes, but emerges as a flawed yet powerful look at systemic racism in modern America.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the gleaners and i', 2000, 'The Gleaners and I takes a compassionate look at a rarely considered subculture whose individualism resonates powerfully with director Agnès Varda''s humanistic approach.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the gogetter', 2007, 'A hipster take on the well-traveled road movie, The Go-Getter features nice performances, but ultimately fails to carve its own path.', TO_DATE('2007-01-25', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the gold rush', 2000, 'A delightful blend of slapstick humor, poignant emotion, and social commentary, The Gold Rush encapsulates Chaplin''s strengths as a writer, director, and star.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the golden dream la jaula de oro', 2013, 'With The Golden Dream, director Diego Quemada-Díez weaves a compassionate tale built on piercing honesty -- and outstanding work from an inexperienced cast.', TO_DATE('2013-05-23', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the golem', 2018, 'A chillingly effective horror story rooted in rich folklore, The Golem blends centuries-old stories with timely themes to powerful effect.', TO_DATE('2018-08-30', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the good dinosaur', 2015, 'The Good Dinosaur delivers thrillingly beautiful animation in service of a worthy story that, even if it doesn''t quite live up to the lofty standards set by Pixar, still adds up to charming, family-friendly entertainment.', TO_DATE('2015-11-13', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the good lie', 2014, 'The Good Lie sacrifices real-life nuance in order to turn its true story into a Hollywood production, but the results still add up to a compelling, well-acted, and deeply moving drama.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the good the bad and the ugly', 2000, 'Arguably the greatest of the spaghetti westerns, this epic features a compelling story, memorable performances, breathtaking landscapes, and a haunting score.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the good the bad the weird joheunnom nabbeunnom isanghannom', 2008, 'Whilst never taking itself too seriously, this riotous and rollicking Sergio Leone-inspired Korean Western is serious fun.', TO_DATE('2008-09-05', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the gospel of john', 2003, 'The Gospel of John takes a reverent approach to its story without ever bringing it to life, proving that cribbing from the Good Book isn''t enough to guarantee a good movie.', TO_DATE('2003-09-25', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the grace card', 2011, 'Tailored for a very specific audience, The Grace Card delivers its noble religious message via implausible plot twists and preachy dialogue.', TO_DATE('2011-02-22', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the grand budapest hotel', 2014, 'Typically stylish but deceptively thoughtful, The Grand Budapest Hotel finds Wes Anderson once again using ornate visual environments to explore deeply emotional ideas.', TO_DATE('2014-02-06', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the grand seduction', 2014, 'The Grand Seduction can''t quite live up to the classic dramedies it seems to consciously evoke, but ambles sweetly enough to charm viewers in its own right.', TO_DATE('2014-05-23', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the grandmaster', 2013, 'Though its storytelling is a tad muddled, Wong Kar Wai''s The Grandmaster still exhibits the auteur''s stylistic flourishes in gorgeous cinematography and explosive action set pieces.', TO_DATE('2013-01-08', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the great beauty', 2013, 'Dazzlingly ambitious, beautifully filmed, and thoroughly enthralling, The Great Beauty offers virtuoso filmmaking from writer/director Paolo Sorrentino.', TO_DATE('2013-05-21', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the great buster a celebration', 2018, 'The Great Buster: A Celebration isn''t as breathlessly entertaining as the filmography that inspired it, but as a long-overdue primer, it''s close to essential.', TO_DATE('2018-08-30', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the great escape', 2000, 'With its impeccably slow-building story and a cast for the ages, The Great Escape is an all-time action classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the great gatsby', 2013, 'While certainly ambitious -- and every bit as visually dazzling as one might expect -- Baz Luhrmann''s The Great Gatsby emphasizes visual splendor at the expense of its source material''s vibrant heart.', TO_DATE('2013-05-05', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the great hack', 2019, 'The Great Hack offers an alarming glimpse of the way data is being weaponized for political gain -- and what it might mean for future elections.', TO_DATE('2019-01-27', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the great train robbery', 2000, 'Laboriously paced and overly talky, The Great Train Robbery nevertheless pulls off a thrillingly staged finale anchored by winning performances from Donald Sutherland and Sean Connery.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the great wall', 2016, 'For a Yimou Zhang film featuring Matt Damon and Willem Dafoe battling ancient monsters, The Great Wall is neither as exciting nor as entertainingly bonkers as one might hope.', TO_DATE('2016-12-15', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the greatest showman', 2017, 'The Greatest Showman tries hard to dazzle the audience with a Barnum-style sense of wonder -- but at the expense of its complex subject''s far more intriguing real-life story.', TO_DATE('2017-12-20', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the green butchers', 2004, 'The Green Butchers isn''t exactly grade A, but this dark comedy carves some genuinely satisfying moments out of a story that finds genuine emotion in a gory premise.', TO_DATE('2004-06-24', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the green inferno', 2013, 'The Green Inferno may not win writer-director Eli Roth many new converts, but fans of his flair for gory spectacle should find it a suitably gruesome diversion.', TO_DATE('2013-09-09', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the green prince', 2014, 'The Green Prince doesn''t answer all the questions it raises, but it''s still timely, gripping -- and ultimately uplifting -- viewing.', TO_DATE('2014-01-17', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the grey', 2011, 'The Grey is an exciting tale of survival, populated with fleshed-out characters and a surprising philosophical agenda.', TO_DATE('2011-12-15', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the grey zone', 2001, 'A grim and devastating tale of the Holocaust.', TO_DATE('2001-09-11', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the grinch', 2018, 'The Grinch gives the classic Seuss source material a brightly animated update that''s solidly suitable for younger viewers without adding substantially to the story''s legacy.', TO_DATE('2018-11-07', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ground truth', 2006, 'The stories the soldiers have to tell are eye-opening and wrenching to hear; collectively it''s a searing peek into the toll of war both during and after.', TO_DATE('2006-01-22', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the grudge', 2004, 'There''s some creepy imagery to be found, but not much in the way of logic or truly jarring scares.', TO_DATE('2004-10-19', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the grudge', 2019, 'Dull and derivative, the rebooted Grudge wastes a talented cast and filmmaker on watered-down scares that may leave viewers nursing grievances of their own.', TO_DATE('2019-12-30', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the guard', 2011, 'A violent, crackerjack comedy with a strong Irish flavor and an eminently likable Brendan Gleeson in the main role.', TO_DATE('2011-01-22', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the guardian', 2006, 'The Coast Guard gets its chance for a heroic movie tribute, but The Guardian does it no justice, borrowing cliche after cliche from other (and better) military branch movies.', TO_DATE('2006-09-06', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the guardians les gardiennes', 2017, 'The Guardians proves that the oft-unraveled canvas of World War I still has fresh stories to tell -- and adds another gorgeously filmed entry to Xavier Beauvois'' filmography.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the guernsey literary and potato peel pie society', 2018, 'Far more traditional and straightforward than its unwieldy title, The Guernsey Literary and Potato Peel Society offers delightful comfort food for fans of period drama.', TO_DATE('2018-04-12', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the guest', 2014, 'Boasting enough intelligence to bolster its darkly violent thrills, The Guest offers another treat for genre fans from director Adam Wingard.', TO_DATE('2014-01-18', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the guilt trip', 2012, 'Seth Rogen and Barbra Streisand have enough chemistry to drive a solidly assembled comedy; unfortunately, The Guilt Trip has a lemon of a script and is perilously low on comedic fuel.', TO_DATE('2012-12-13', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the guilty den skyldige', 2018, 'Sleek, well-acted, and intelligently crafted, The Guilty is a high-concept thriller that wrings maximum impact out of a handful of basic - and effective - ingredients.', TO_DATE('2018-01-20', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the gunman', 2015, 'With an uninspired plot and rote set pieces that are overshadowed by its star''s physique, The Gunman proves a muddled misfire in the rapidly aging Over-50 Action Hero genre.', TO_DATE('2015-03-06', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the half of it', 2020, 'For viewers in search of an uncommonly smart, tender, and funny coming-of-age story, The Half of It has everything.', TO_DATE('2020-04-29', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hallow the woods', 2015, 'Drenched in dark atmosphere and bolstered with some real emotion underneath all the chills, The Hallow suggests a wonderfully horrifying future for director Corin Hardy.', TO_DATE('2015-01-29', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the handmaiden ahgassi', 2016, 'The Handmaiden uses a Victorian crime novel as the loose inspiration for another visually sumptuous and absorbingly idiosyncratic outing from director Park Chan-wook.', TO_DATE('2016-05-15', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hangover part ii', 2011, 'A crueler, darker, raunchier carbon copy of the first installment, The Hangover Part II lacks the element of surprise -- and most of the joy -- that helped make the original a hit.', TO_DATE('2011-05-23', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hangover part iii', 2013, 'Less a comedy than an angrily dark action thriller, The Hangover Part III diverges from the series'' rote formula but offers nothing compelling in its place.', TO_DATE('2013-05-20', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the happy prince', 2018, 'A passion project for writer, director, and star Rupert Everett, The Happy Prince pays effective tribute to Oscar Wilde with a poignant look at his tragic final days.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the happytime murders', 2018, 'The Happytime Murders wastes its intriguingly transgressive premise on a witless comedy that blindly pushes buttons instead of attempting to tell an entertaining story.', TO_DATE('2018-08-22', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the harmonists', 1999, 'Reflecting historical upheaval through the group dynamics of a talented troupe, The Harmonists is a spirited depiction of entertainment and politics intersecting.', TO_DATE('1999-02-13', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the harvest', 2014, 'The Harvest sows enough well-acted, slow-burning tension to satisfy, even if viewers expecting to reap all-out horror may come away wanting more.', TO_DATE('2014-07-24', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hate u give', 2018, 'Led by a breakout turn from Amandla Stenberg, the hard-hitting The Hate U Give emphatically proves the YA genre has room for much more than magic and romance.', TO_DATE('2018-09-08', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hateful eight', 2015, 'The Hateful Eight offers another well-aimed round from Quentin Tarantino''s signature blend of action, humor, and over-the-top violence -- all while demonstrating an even stronger grip on his filmmaking craft.', TO_DATE('2015-12-15', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the haunting of sharon tate', 2019, 'The Haunting of Sharon Tate dishonors the events it seeks to dramatize with a poorly acted and offensively exploitative take on real-life tragedy.', TO_DATE('2019-03-10', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the heartbreak kid', 2007, 'Despite some amiable performances, The Heartbreak Kid is neither as daring nor as funny as the Farrelly Brothers'' earlier films.', TO_DATE('2007-09-10', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the heat', 2013, 'The Heat is predictable, but Melissa McCarthy is reliably funny and Sandra Bullock proves a capable foil.', TO_DATE('2013-06-25', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the help', 2011, 'Though it fails to fully engage with its racial themes, The Help rises on the strength of its cast -- particularly Viola Davis, whose performance is powerful enough to carry the film on its own.', TO_DATE('2011-08-05', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hero', 2017, 'The Hero rests on Sam Elliott''s understated performance, which proves more than capable of carrying the film through the less inspired moments of its somewhat clichéd story.', TO_DATE('2017-01-22', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the high note', 2020, 'The High Note doesn''t quite soar above rom-com formula, but audiences seeking some comfort viewing should find themselves solidly in harmony with this well-acted genre entry.', TO_DATE('2020-05-25', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the highwaymen', 2019, 'The Highwaymen depicts law enforcement''s side of the Bonnie and Clyde manhunt -- a story that''s unfortunately not quite as entertaining despite its marquee leads.', TO_DATE('2019-03-11', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hitmans bodyguard', 2017, 'The Hitman''s Bodyguard coasts on Samuel L. Jackson and Ryan Reynolds'' banter -- but doesn''t get enough mileage to power past an overabundance of action-comedy clichés.', TO_DATE('2017-08-11', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hobbit an unexpected journey', 2008, 'Peter Jackson''s return to Middle-earth is an earnest, visually resplendent trip, but the film''s deliberate pace robs the material of some of its majesty.', TO_DATE('2008-08-20', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hobbit the battle of the five armies', 2013, 'Though somewhat overwhelmed by its own spectacle, The Hobbit: The Battle of the Five Armies ends Peter Jackson''s second Middle-earth trilogy on a reasonably satisfying note.', TO_DATE('2013-02-03', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hobbit the desolation of smaug', 2013, 'While still slightly hamstrung by "middle chapter" narrative problems and its formidable length, The Desolation of Smaug represents a more confident, exciting second chapter for the Hobbit series.', TO_DATE('2013-12-06', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hole in the ground', 2019, 'The Hole in the Ground artfully exploits parental fears with a well-made horror outing that makes up in sheer effectiveness what it lacks in originality.', TO_DATE('2019-01-26', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the holiday', 2006, 'While it''s certainly sweet and even somewhat touching, The Holiday is so thoroughly predictable that audiences may end up opting for an early check-out time.', TO_DATE('2006-11-30', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hollars', 2016, 'The Hollars gathers an impressive assortment of talented stars; unfortunately, it''s all in service of a story that''s been played out more effectively in countless other indie dramedies.', TO_DATE('2016-01-24', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the homesman', 2014, 'A squarely traditional yet somewhat progressive Western, The Homesman adds another absorbing entry to Tommy Lee Jones'' directorial résumé.', TO_DATE('2014-05-18', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the host', 2006, 'As populace pleasing as it is intellectually satisfying, The Host combines scares, laughs, and satire into a riveting, monster movie.', TO_DATE('2006-05-25', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the host', 2013, 'Poorly scripted and dramatically ineffective, The Host is mostly stale and tedious, with moments of unintentional hilarity.', TO_DATE('2013-03-26', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the house', 2017, 'The House squanders a decent premise and a talented cast on thin characterizations and a shortage of comic momentum.', TO_DATE('2017-06-28', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the house of the devil', 2009, 'Though its underlying themes are familiar, House of the Devil effectively sheds the loud and gory cliches of contemporary horror to deliver a tense, slowly building throwback to the fright flicks of decades past.', TO_DATE('2009-05-03', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the house of the spirits', 2000, 'An enviable collection of sterling actors are all woefully miscast in The House of the Spirits, a plodding saga of magical realism that lacks much magic or realism.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the house that jack built', 2018, 'The House That Jack Built presents writer-director Lars von Trier at his most proudly uncompromising: hard to ignore, and for many viewers, just as difficult to digest.', TO_DATE('2018-05-15', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the house with a clock in its walls', 2018, 'An entertaining PG detour for gore maestro Eli Roth, The House with a Clock in Its Walls is a family-friendly blend of humor and horror with an infectious sense of fun.', TO_DATE('2018-09-17', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the housemaid', 2010, 'Im Sang-soo''s remake of The Housemaid struggles to escape the shadow of the original, but offers its own unique -- and decidedly sensual -- pleasures.', TO_DATE('2010-08-17', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the human centipede ii full sequence', 2011, 'The Human Centipede II (Full Sequence) attempts to weave in social commentary but as the movie wears on, it loses its ability to repulse and shock and ends up obnoxious and annoying.', TO_DATE('2011-09-23', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the human centipede iii final sequence', 2015, 'Human Centipede fans may find enough extreme body horror in the third installment to satisfy, but filmgoers of every other persuasion are strongly advised to stay far, far away from Final Sequence.', TO_DATE('2015-05-19', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the humbling', 2014, 'The Humbling is an inarguable highlight of Al Pacino''s late-period filmography, but that''s an admittedly low bar that it doesn''t always clear by a very wide margin.', TO_DATE('2014-08-29', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hummingbird project', 2018, 'Smart and well-acted, The Hummingbird Project marks a flawed yet undeniably intriguing addition to writer-director Kim Nguyen''s filmography.', TO_DATE('2018-09-10', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hundredfoot journey', 2014, 'Director Lasse Hallström does lovely work and Helen Mirren is always worth watching, but The Hundred-Foot Journey travels predictable ground already covered by countless feel-good dramedies.', TO_DATE('2014-07-25', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hunger', 2000, 'Stylish yet hollow, The Hunger is a well-cast vampire thriller that mistakes erotic moments for a satisfying story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hunger games', 2012, 'Thrilling and superbly acted, The Hunger Games captures the dramatic violence, raw emotion, and ambitious scope of its source novel.', TO_DATE('2012-03-15', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hunger games catching fire', 2012, 'Smart, smoothly directed, and enriched with a deeper exploration of the franchise''s thought-provoking themes, Catching Fire proves a thoroughly compelling second installment in the Hunger Games series.', TO_DATE('2012-02-24', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hunger games mockingjay part 1', 2014, 'The Hunger Games: Mockingjay - Part 1 sets up the franchise finale with a penultimate chapter loaded with solid performances and smart political subtext, though it comes up short on the action front.', TO_DATE('2014-11-10', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hunger games mockingjay part 2', 2015, 'With the unflinchingly grim Mockingjay Part 2, The Hunger Games comes to an exciting, poignant, and overall satisfying conclusion.', TO_DATE('2015-11-04', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hunt jagten', 2012, 'Anchored by Mads Mikkelsen''s sympathetic performance, The Hunt asks difficult questions with the courage to pursue answers head on.', TO_DATE('2012-05-20', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hunt', 2020, 'The Hunt is successful enough as a darkly humorous action thriller, but it shoots wide of the mark when it aims for timely social satire.', TO_DATE('2020-03-11', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hunter', 2011, 'The Hunter occasionally suffers from predictability, but Willem Dafoe gives a terrific performance as an obsessive hunter on the trail of a mysterious beast.', TO_DATE('2011-09-09', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hunting ground', 2015, 'The Hunting Ground isn''t director Kirby Dick''s strongest work as a filmmaker, but the movie''s powerful message more than trumps any technical weaknesses.', TO_DATE('2015-01-24', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hunting of the president', 2004, 'Though this doc has an obvious partisan bias, it presents a compelling case.', TO_DATE('2004-05-15', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the huntsman winters war', 2016, 'The Huntsman: Winter''s War is visually arresting and boasts a stellar cast, but neither are enough to recommend this entirely unnecessary sequel.', TO_DATE('2016-04-04', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hurricane heist', 2018, 'The Hurricane Heist is a throwback to the overblown action thrillers of yesteryear -- and a thoroughly middling example of why they don''t make ''em like this anymore.', TO_DATE('2018-03-01', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hurt locker', 2008, 'A well-acted, intensely shot, action filled war epic, Kathryn Bigelow''s The Hurt Locker is thus far the best of the recent dramatizations of the Iraq War.', TO_DATE('2008-09-04', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the hustle', 2019, 'The Hustle''s stars might make an effective comedy team in a different setting, but this gender-flipped remake of a remake adds little beyond its feminine twist.', TO_DATE('2019-05-08', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the iceman', 2012, 'While it deserved stronger direction and a more fully realized script, Michael Shannon''s riveting performance in the title role is more than enough to make The Iceman recommended viewing.', TO_DATE('2012-08-30', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the identical', 2014, 'With nearly every element ringing as hollow as the ersatz Elvis at the story''s core, The Identical looks destined for a bright future on the ironic viewing circuit.', TO_DATE('2014-08-30', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ides of march', 2011, 'While not exactly exposing revelatory truths, The Ides of March is supremely well-acted drama that moves at a measured, confident clip.', TO_DATE('2011-08-31', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the illusionist lillusionniste', 2010, 'An engrossing love letter to fans of adult animation, The Illusionist offers a fine antidote to garish mainstream fare.', TO_DATE('2010-06-17', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the imaginarium of doctor parnassus', 2009, 'Terry Gilliam remains as indulgent as ever, but The Imaginarium of Doctor Parnassus represents a return to the intoxicatingly imaginative, darkly beautiful power of his earlier work, with fine performances to match all the visual spectacle.', TO_DATE('2009-05-22', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the imitation game', 2014, 'With an outstanding starring performance from Benedict Cumberbatch illuminating its fact-based story, The Imitation Game serves as an eminently well-made entry in the "prestige biopic" genre.', TO_DATE('2014-08-30', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the immigrant', 2013, 'Beautiful visuals, James Gray''s confident direction, and a powerful performance from Marion Cotillard combine to make The Immigrant a richly rewarding period drama.', TO_DATE('2013-05-24', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the impossible', 2012, 'The screenplay isn''t quite as powerful as the direction or the acting, but with such an astonishing real-life story at its center, The Impossible is never less than compelling.', TO_DATE('2012-09-11', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the imposter', 2012, 'Despite its true-crime trappings, The Imposter is an utterly gripping and sometimes heartbreaking documentary thriller cleverly told with narrative flair.', TO_DATE('2012-01-24', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the inbetweeners', 2011, 'It arguably plays most strongly to fans of the British series, but even viewers who have never seen The Inbetweeners on TV may find themselves won over by the film''s surprisingly tender ribaldry.', TO_DATE('2011-08-17', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the incredible burt wonderstone', 2013, 'The Incredible Burt Wonderstone serves up some goofy laughs, but given its outrageous conceit, it''s surprisingly safe and predictable.', TO_DATE('2013-03-08', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the incredible hulk', 2008, 'The Incredible Hulk may not be quite the smashing success that fans of Marvel''s raging behemoth might hope for, but it offers more than enough big green action to make up for its occasionally puny narrative.', TO_DATE('2008-06-03', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the incredible jessica james', 2017, 'The Incredible Jessica James makes its standard storyline feel new, almost purely on the strength of a captivating, potentially star-making performance from Jessica Williams.', TO_DATE('2017-01-20', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the inevitable defeat of mister pete', 2013, 'The Inevitable Defeat of Mister & Pete uses its compelling streetwise setting -- and powerful performances from its young leads -- to offer a refreshing twist on the coming-of-age formula.', TO_DATE('2013-04-28', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the infiltrator', 2016, 'The Infiltrator''s compelling fact-based story and tremendously talented cast are often just enough to balance out its derivative narrative and occasionally clunky execution.', TO_DATE('2016-07-01', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the infiltrators', 2019, 'The Infiltrators takes a unique stylistic approach to an important topic, leaving audiences with a viewing experience that demands -- and rewards -- attention.', TO_DATE('2019-01-26', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the innkeepers', 2011, 'It doesn''t break any rules of the genre, but The Innkeepers serves as additional proof that Ti West is a young director that discriminating horror fans can trust.', TO_DATE('2011-03-14', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the insult linsulte', 2017, 'The Insult uses its familiar courtroom drama framework to deliver a hard-hitting statement on modern Middle Eastern politics that''s as gripping as it is thought-provoking.', TO_DATE('2017-08-31', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the intended', 2003, 'Predictable and pointless melodrama.', TO_DATE('2003-01-02', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the intern', 2015, 'The Intern doesn''t do enough with its timely premise, but benefits from the unorthodox chemistry of its talented leads.', TO_DATE('2015-09-21', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the internets own boy the story of aaron swartz', 2014, 'Informative and enraging in equal measure, The Internet''s Own Boy: The Story of Aaron Swartz uses its subject''s tragic tale to deliver an impassioned call to action.', TO_DATE('2014-01-22', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the internship', 2013, 'The Internship weighs down Vince Vaughn and Owen Wilson''s comic charisma with a formulaic script and padded running time that leans heavily on its stars'' easygoing interplay.', TO_DATE('2013-06-03', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the interrupters', 2011, 'Impeccably crafted and edited, The Interrupters is a tough and honest documentary about street violence that truly has the power to inspire change.', TO_DATE('2011-07-12', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the intervention', 2016, 'The Intervention''s familiar plot is enlivened by complex character dynamics and a likable cast.', TO_DATE('2016-01-27', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the interview', 2014, 'Unfortunately overshadowed by controversy (and under-screened as a result), The Interview''s screenplay offers middling laughs bolstered by its two likable leads.', TO_DATE('2014-12-11', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the intouchables', 2012, 'It handles its potentially prickly subject matter with kid gloves, but Intouchables gets by thanks to its strong cast and some remarkably sensitive direction.', TO_DATE('2012-02-23', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the intruder', 2019, 'The Intruder might appeal to fans of shout-at-the-screen cinema, but this thriller''s ludicrous plot robs it of suspense -- and undermines Dennis Quaid''s suitably over-the-top performance.', TO_DATE('2019-04-29', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the inventor out for blood in silicon valley', 2019, 'Alex Gibey''s The Inventor declines to outright condemn the actions by Theranos founder Elizabeth Holmes, but instead provides a comprehensive overview of the scandal that allows viewers to mull over its implications towards the broader Silicon Valley.', TO_DATE('2019-01-25', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the invisible man', 2020, 'Smart, well-acted, and above all scary, The Invisible Man proves that sometimes, the classic source material for a fresh reboot can be hiding in plain sight.', TO_DATE('2020-02-21', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the invisible war', 2012, 'The Invisible War is a vital and frank expose on sexual assault in the U.S. military, shot by master filmmaker Kirby Dick (This Film is Not Yet Rated).', TO_DATE('2012-01-26', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the invisible woman', 2013, 'Its deliberate pace will frustrate some viewers, but for fans of handsomely mounted period drama, The Invisible Woman offers visual as well as emotional cinematic nourishment.', TO_DATE('2013-09-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the invitation', 2015, 'The Invitation makes brilliant use of its tension-rich premise to deliver a uniquely effective -- and surprisingly clever -- slow-building thriller.', TO_DATE('2015-05-25', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the irishman', 2019, 'An epic gangster drama that earns its extended runtime, The Irishman finds Martin Scorsese revisiting familiar themes to poignant, funny, and profound effect.', TO_DATE('2019-09-27', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the iron ladies', 2001, 'The sports movie Iron Ladies is as predictable and sentimental as many of its American counterparts.', TO_DATE('2001-07-06', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the iron lady', 2011, 'Meryl Streep''s performance as The Iron Lady is reliably perfect, but it''s mired in bland, self-important storytelling.', TO_DATE('2011-11-15', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the island president', 2011, 'An eye-opening and appealing documentary about an earnest politician up against the closed door drama of climate change.', TO_DATE('2011-12-07', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ivory game', 2016, 'Hard-hitting and ambitious to a fault, The Ivory Game serves as a fittingly urgent call to action against a looming threat against vulnerable wildlife and a fragile ecosystem.', TO_DATE('2016-09-02', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the journey', 2016, 'The Journey''s narrative deficiencies undermine a powerful fact-based story, but those problems are often offset by solid work from Colm Meaney and Timothy Spall.', TO_DATE('2016-09-07', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the judge', 2014, 'Solidly cast and beautifully filmed but thoroughly clichéd, The Judge seems destined to preside over a large jurisdiction of the basic cable afternoon-viewing circuit.', TO_DATE('2014-09-04', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the jungle book', 2014, 'As lovely to behold as it is engrossing to watch, The Jungle Book is the rare remake that actually improves upon its predecessors -- all while setting a new standard for CGI.', TO_DATE('2014-09-09', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the karate kid part iii', 2000, 'Inspiration is in short supply in this third Karate Kid film, which recycles the basic narrative from its predecessors but adds scenery-chewing performances and a surprising amount of violence.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kid', 2000, 'Critics find The Kid to be too sweet and the movie''s message to be annoyingly simplistic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kid', 2019, 'Well-framed, well-cast, and well-intentioned, The Kid still largely fails to set itself apart from the multitude of other westerns covering similar territory.', TO_DATE('2019-03-06', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kid who would be king', 2019, 'The Kid Who Would Be King recalls classic all-ages adventures -- and repurposes a timeless legend -- for a thoroughly enjoyable new addition to the family movie canon.', TO_DATE('2019-01-12', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kid with a bike', 2011, 'Thanks to the Dardenne brothers'' typically fine direction, The Kid with a Bike is a heart-wrenching, thematically and spiritually rich drama.', TO_DATE('2011-05-14', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kill team', 2014, 'Urgent, mesmerizing, and infuriating, The Kill Team looks at American foreign policy from a rarely considered perspective.', TO_DATE('2014-01-23', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kill team', 2019, 'Flawed yet viscerally effective, The Kill Team interrogates battlefield morality with a hard-hitting intensity further amplified by a talented cast.', TO_DATE('2019-04-29', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the killer inside me', 2010, 'The Killer Inside Me is stylish and beautifully shot, but Michael Winterbottom''s distance from his characters robs this often brutally violent film of crucial emotional context.', TO_DATE('2010-01-25', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the killing of a sacred deer', 2017, 'The Killing of a Sacred Deer continues director Yorgos Lanthimos'' stubbornly idiosyncratic streak -- and demonstrates again that his is a talent not to be ignored.', TO_DATE('2017-05-22', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kindergarten teacher haganenet', 2014, 'The Kindergarten Teacher''s crypticness can needlessly feel like homework, but Nadav Lapid''s provocative direction and committed performances give this tale of mentorship and possession a disquieting sting.', TO_DATE('2014-10-16', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kindergarten teacher', 2018, 'Elevated by a bravura performance from Maggie Gyllenhaal, The Kindergarten Teacher is one American remake that retains its impact the second time around.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kindness of strangers', 2019, 'A talented onscreen ensemble is done no favors by The Kindness of Strangers, which searches for meaning and comes up empty.', TO_DATE('2019-02-07', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the king', 2005, 'This disturbing film about the past coming back demanding its due evokes classical tragedy, but is ultimately too heavy-handed.', TO_DATE('2005-05-16', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the king', 2019, 'While The King is sometimes less than the sum of its impressive parts, strong source material and gripping performances make this a period drama worth hailing.', TO_DATE('2019-09-02', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the king is alive', 2000, 'Though the plot feels rather contrived, the ensemble acting in this Dogme 95 film is good.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the king of staten island', 2020, 'The King of Staten Island''s uncertain tone and indulgent length blunt this coming-of-age dramedy''s ability to find itself, but Pete Davidson''s soulful performance holds it together.', TO_DATE('2020-06-08', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kingdom', 2007, 'While providing several top-notch action scenes, The Kingdom ultimately collapses under the weight of formula and muddled politics.', TO_DATE('2007-08-12', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kingdom of dreams and madness', 2014, 'The Kingdom of Dreams and Madness is a captivating treat for Studio Ghibli fans -- and may prove nearly as entertaining and enlightening for the unconverted.', TO_DATE('2014-11-06', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kings of summer', 2013, 'Thanks to charming performances and endearingly off-kilter spirit, The Kings of Summer proves to be a slight, sweet entry in the crowded coming-of-age genre.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kings speech', 2010, 'Colin Firth gives a masterful performance in The King''s Speech, a predictable but stylishly produced and rousing period drama.', TO_DATE('2010-09-05', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kissing booth', 2018, 'The Kissing Booth deploys every rom-com cliché in the book with little care given to achieving any real sentiment.', TO_DATE('2018-05-11', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the kitchen', 2019, 'With three talented leads struggling to prop up a sagging story, The Kitchen is a jumbled crime thriller in urgent need of some heavy-duty renovation.', TO_DATE('2019-08-07', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the knight before christmas', 2019, 'While its plot borders on the absurd, The Knight Before Christmas is endearing and charming enough to make it a worthy addition to the holiday rom-com genre.', TO_DATE('2019-11-08', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lady', 2011, 'Even as The Lady focuses on Aung San Suu Kyi''s romantic life parallel to her political ascendancy, Luc Besson''s saccharine direction is too concerned with deifying the Nobel Prize-winner for her humanity to actually shine through.', TO_DATE('2011-11-10', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lady from shanghai', 2000, 'Energetic and inventive, The Lady from Shanghai overcomes its script deficiencies with some of Orson Welles'' brilliantly conceived set pieces.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lady in the van', 2015, 'Led by a marvelous performance from Maggie Smith, Lady in the Van wrings poignant, often hilarious insight from its fact-based source material.', TO_DATE('2015-09-12', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the land of steady habits', 2018, 'With typically sharp work from writer-director Nicole Holofcener and finely layered performances, The Land of Steady Habits is one mid-life crisis worth watching.', TO_DATE('2018-09-13', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last 5 years', 2014, 'The Last Five Years hits a few awkward notes in its transition from stage to screen, but its freshness and sincere charm -- and well-matched stars -- offer their own rewards.', TO_DATE('2014-09-04', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last black man in san francisco', 2019, 'An affecting story powerfully told, The Last Black Man in San Francisco immediately establishes director Joe Talbot as a filmmaker to watch.', TO_DATE('2019-01-27', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last days on mars', 2013, 'Neither intelligent enough to work as thought-provoking sci-fi nor trashy enough to provide B-movie thrills, The Last Days on Mars proves as cinematically barren as the titular planet.', TO_DATE('2013-05-23', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last dragon', 2002, 'The Last Dragon is a flamboyant genre mashup brimming with style, romance, and an infectious fondness for kung fu, but audiences may find the tonal whiplash more goofy than endearing.', TO_DATE('2002-11-22', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last exorcism part ii', 2013, 'The Last Exorcism Part II ditches the found footage format for relatively earnest but deadly tedious psychological terror that devolves into hokum anyways.', TO_DATE('2013-02-15', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last face', 2016, 'The Last Face''s noble intentions are nowhere near enough to carry a fundamentally misguided story that arguably demeans the demographic it wants to defend.', TO_DATE('2016-05-20', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last full measure', 2020, 'The Last Full Measure struggles to capture the incidents that inspired it, but ultimately prevails thanks to strong performances in service of a remarkable true story.', TO_DATE('2020-01-20', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last laugh', 2019, 'Chevy Chase and Richard Dreyfuss are a sight for sore eyes, but they unfortunately do not get The Last Laugh in a generic buddy comedy that never musters any jokes worthy of their comedic chops.', TO_DATE('2019-01-11', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last man on the moon', 2015, 'The Last Man on the Moon takes a justifiably reverent look at a largely unexplored chapter in the history of American space exploration -- and a side of astronaut''s lives that''s rarely considered.', TO_DATE('2015-03-27', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last movie star', 2017, 'The Last Movie Star has a few poignant moments thanks to Burt Reynolds and Ariel Winter, but their performances are stranded in a middling drama unworthy of their efforts.', TO_DATE('2017-04-23', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last of robin hood', 2013, 'Kevin Kline''s performance is spot on, but in every other respect, The Last of Robin Hood disappoints.', TO_DATE('2013-09-12', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last of the unjust', 2013, 'Documentarian Claude Lanzmann brings the ghosts of the Holocaust back to vivid life once again The Last of the Unjust, a dense and haunting investigation into complicity and moral quandary.', TO_DATE('2013-09-18', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last seduction', 1994, 'Like Body Heat, The Last Seduction updates film noir techniques for a modern era, imbuing this erotic film with ''90s snark.', TO_DATE('1994-06-18', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last shot', 2004, 'Wildly uneven comedy.', TO_DATE('2004-09-18', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last starfighter', 2002, 'The plot is as barebones a space movie will allow, but The Last Starfighter captures an era and eager style of filmmaking well.', TO_DATE('2002-04-13', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last suit el último traje', 2017, 'The Last Suit occasionally falters while juggling disparate tones, but is ultimately held together by an affecting sweetness and Miguel Ángel Solá''s central performance.', TO_DATE('2017-11-08', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last thing he wanted', 2020, 'It''ll be the last thing most viewers want, too.', TO_DATE('2020-01-28', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last waltz', 2002, 'Among one of, if not the best rock movie ever made, The Last Waltz is a revealing, electrifying view of the classic band at their height.', TO_DATE('2002-04-04', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last witch hunter', 2015, 'Grim, plodding, and an overall ill fit for Vin Diesel''s particular charms, The Last Witch Hunter will bore and/or confuse all but the least demanding action-fantasy fans.', TO_DATE('2015-10-19', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the last word', 2017, 'The Last Word proves Shirley MacLaine remains a wonderfully magnetic screen presence -- and deserving of a far better vehicle for her considerable talents.', TO_DATE('2017-01-25', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the laundromat', 2019, 'The Laundromat misuses its incredible cast by taking a disappointingly blunt and unfocused approach to dramatizing the real-life events that inspired it.', TO_DATE('2019-09-01', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lazarus effect', 2015, 'The Lazarus Effect has a talented cast and the glimmer of an interesting idea, but wastes it all on insipid characters and dull, recycled plot points.', TO_DATE('2015-02-24', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the legacy of a whitetail deer hunter', 2018, 'The Legacy of a Whitetail Deer Hunter wastes a promising premise and talented cast on a frustratingly uneven comedy that lacks enough laughs to forgive its narrative flaws.', TO_DATE('2018-03-12', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the legend of cocaine island', 2018, 'Rodney Hyden''s quixotic quest for riches makes The Legend of Cocaine Island a mirthful adventure, although director Theo Love''s stylistic flourishes are often counterproductive in conveying the inherent interest of this true story.', TO_DATE('2018-05-09', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the legend of hercules', 2014, 'Cheap-looking, poorly acted, and dull, The Legend of Hercules is neither fun enough to qualify as an action movie nor absorbing enough to work on a dramatic level.', TO_DATE('2014-01-09', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the legend of tarzan', 2016, 'The Legend of Tarzan has more on its mind than many movies starring the classic character, but that isn''t enough to make up for its generic plot or sluggish pace.', TO_DATE('2016-06-29', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lego batman movie', 2017, 'The Lego Batman Movie continues its block-buster franchise''s winning streak with another round of dizzyingly funny -- and beautifully animated -- family-friendly mayhem.', TO_DATE('2017-02-02', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lego movie', 2014, 'Boasting beautiful animation, a charming voice cast, laugh-a-minute gags, and a surprisingly thoughtful story, The Lego Movie is colorful fun for all ages.', TO_DATE('2014-02-02', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lego movie 2 the second part', 2019, 'While it isn''t quite as much fun as its predecessor, The LEGO Movie 2: The Second Part fits neatly into an animated all-ages franchise with heart and humor to spare.', TO_DATE('2019-01-26', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lego ninjago movie', 2017, 'Despite ample charm and a few solid gags, The Lego Ninjago Movie suggests this franchise''s formula isn''t clicking like it used to.', TO_DATE('2017-09-20', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the leisure seeker', 2017, 'The Leisure Seeker certainly doesn''t suffer from any shortage of acting talent, but it''s largely squandered on a predictable, diffuse drama with little to say.', TO_DATE('2017-09-03', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the leopard', 2003, 'Lavish and wistful, The Leopard features epic battles, sumptuous costumes, and a ballroom waltz that competes for most beautiful sequence committed to film.', TO_DATE('2003-05-24', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the letters', 2015, 'The Letters tries to honor Mother Teresa with an unstintingly positive portrayal of her life and works, but ends up smothering a fascinating real-life story under a bland hagiography.', TO_DATE('2015-11-24', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the life and times of hank greenberg', 2000, 'The Life and Times of Hank Greenberg is an affectionate, often very funny portrait of a baseball pioneer.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the light between oceans', 2016, 'The Light Between Oceans presents a well-acted and handsomely mounted adaptation of its bestselling source material, but ultimately tugs on the heartstrings too often to be effective.', TO_DATE('2016-08-29', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lighthouse', 2019, 'A gripping story brilliantly filmed and led by a pair of powerhouse performances, The Lighthouse further establishes Robert Eggers as a filmmaker of exceptional talent.', TO_DATE('2019-05-19', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the limehouse golem', 2016, 'The Limehouse Golem offers old-school Hammer-style horror anchored by rich period detail and strong work from a solid cast.', TO_DATE('2016-09-11', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lion king', 2000, 'Emotionally stirring, richly drawn, and beautifully animated, The Lion King is a pride within Disney''s pantheon of classic family films.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lion king', 2019, 'While it can take pride in its visual achievements,The Lion King is a by-the-numbers retelling that lacks the energy and heart that made the original so beloved--though for some fans that may just be enough.', TO_DATE('2019-07-11', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the little death', 2014, 'The Little Death may appeal to fans of dark, risqué comedy, but it''s ultimately too rough and uneven to hang together as a wholly satisfying viewing experience.', TO_DATE('2014-09-11', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the little hours', 2017, 'The Little Hours gets plenty of goofy mileage out of its gifted ensemble, anchoring its ribald laughs in a period comedy with some surprisingly timely subtext.', TO_DATE('2017-01-20', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the little mermaid', 2000, 'The Little Mermaid ushered in a new golden era for Disney animation with warm and charming hand-drawn characters and catchy musical sequences.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the little stranger', 2018, 'The Little Stranger''s reliance on atmosphere may satisfy audiences in the mood for sophisticated horror fare -- while frustrating those seeking more visceral thrills.', TO_DATE('2018-08-26', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lives of others', 2006, 'Unlike more traditional spy films, The Lives of Others doesn''t sacrifice character for cloak and dagger chases, and the performances (notably that by the late Ulrich Muhe) stay with you.', TO_DATE('2006-09-02', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lobster', 2015, 'As strange as it is thrillingly ambitious, The Lobster is definitely an acquired taste -- but for viewers with the fortitude to crack through Yorgos Lanthimos'' offbeat sensibilities, it should prove a savory cinematic treat.', TO_DATE('2015-07-20', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lodgers', 2017, 'Like many real-life long-term visitors, The Lodgers starts out with a modicum of mystery and excitement, but eventually overstays its welcome.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the loft', 2015, 'Populated with characters as unpleasant as its sleazy storyline, The Loft is uninhabitable for all but the least demanding erotic thriller fans.', TO_DATE('2015-01-29', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lone ranger', 2013, 'Armie Hammer and Johnny Depp make for an appealing pair of leads, but they''re not enough to make up for The Lone Ranger''s bland script, bloated length, and blaring action overkill.', TO_DATE('2013-06-29', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the loneliest planet', 2011, 'The source material that inspired The Loneliest Planet may be brief, but this adaptation of a Tom Bissell short story compensates with studious, finely detailed filmmaking, haunting visuals, and thought-provoking subtext.', TO_DATE('2011-09-24', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lonely island presents the unauthorized bash brothers experience', 2019, 'A visually striking, hilarious searing visual album, The Unauthorized Bash Brothers Experience is a home run.', TO_DATE('2019-05-24', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the long dumb road', 2018, 'The Long Dumb Road navigates the odd couple road trip comedy formula fairly smoothly, thanks mainly to the chemistry between Tony Revolori and Jason Mantzoukas.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the long good friday', 2000, 'Bob Hoskins commands a deviously sinister performance in The Long Good Friday -- a gangster flick with ferocious intelligence, tight plotting and razor-edged thrills.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the longest ride', 2015, 'The Longest Ride is less manipulative than the average Nicholas Sparks film, but it''s still saccharine and hopelessly contrived -- not that it''ll matter to the target audience.', TO_DATE('2015-04-06', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the look of love', 2013, 'While it may not add up to the definitive Paul Raymond biopic -- or take full advantage of Steve Coogan''s many gifts -- The Look of Love still proves an entertainingly old-fashioned look at the Swinging London of the 1960s.', TO_DATE('2013-01-20', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the look of silence', 2014, 'The Look of Silence delivers a less shocking -- yet just as terribly compelling -- companion piece to Joshua Oppenheimer''s The Act of Killing.', TO_DATE('2014-09-08', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('dr seuss the lorax', 2012, 'Dr. Seuss'' The Lorax is cute and funny enough but the moral simplicity of the book gets lost with the zany Hollywood production values.', TO_DATE('2012-02-26', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lord of the rings the fellowship of the ring', 2001, 'Full of eye-popping special effects, and featuring a pitch-perfect cast, The Lord of the Rings: The Fellowship of the Ring brings J.R.R. Tolkien''s classic to vivid life.', TO_DATE('2001-12-03', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lord of the rings the return of the king', 2003, 'Visually breathtaking and emotionally powerful, The Lord of the Rings - The Return of the King is a moving and satisfying conclusion to a great trilogy.', TO_DATE('2003-05-24', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lord of the rings the two towers', 2002, 'The Two Towers balances spectacular action with emotional storytelling, leaving audiences both wholly satisfied and eager for the final chapter.', TO_DATE('2002-12-05', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lords of salem', 2012, 'The Lords of Salem has lots of atmospheric portent, but it''s unfortunately short on scares.', TO_DATE('2012-09-11', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lost city of z', 2016, 'The Lost City of Z''s stately pace and visual grandeur hearken back to classic exploration epics, and Charlie Hunnam turns in a masterful performance as its complex protagonist.', TO_DATE('2016-10-15', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lost husband', 2020, 'It won''t set hearts a-flutter for anyone who isn''t a dedicated romantic, but audiences in the mood for love might like The Lost Husband.', TO_DATE('2020-04-06', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the love letter', 2000, 'Poor character development and scripting hamper any romantic chemistry.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the love punch', 2013, 'In spite of a pair of extremely talented leads and a premise that should lend itself to entertaining action and comedy, The Love Punch manages to waste it all on a bungled attempt at classic caper cinema.', TO_DATE('2013-09-09', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the love witch', 2016, 'The Love Witch offers an absorbing visual homage to a bygone era, arranged subtly in service of a thought-provoking meditation on the battle of the sexes.', TO_DATE('2016-04-05', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the loved ones', 2009, 'Successfully mixing the conventions of the teen and horror genres with a twist, Australian director Sean Byrne makes a striking directorial debut with The Loved Ones.', TO_DATE('2009-09-18', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lovers and the despot', 2016, 'The Lovers and the Despot offers a compelling -- albeit by no means comprehensive -- look at one of the more bizarrely stranger-than-fiction episodes in cinematic history.', TO_DATE('2016-03-30', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lucky one', 2012, 'While it provides the requisite amount of escapist melodrama, The Lucky One ultimately relies on too many schmaltzy clichés to appeal to anyone not already familiar with the Nicholas Sparks formula.', TO_DATE('2012-04-10', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the lunchbox', 2013, 'Warm, affectionate, and sweet but not cloying, The Lunchbox is a clever crowd-pleaser from first-time director Ritesh Batra.', TO_DATE('2013-05-23', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the machine', 2014, 'The Machine proves an audacious debut for writer-director Caradog James and a solid entry in modern British sci-fi, with thematic heft to match its genre thrills.', TO_DATE('2014-01-22', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the magic of belle isle', 2012, 'Neither Rob Reiner nor Morgan Freeman are able to conjure up their old magic in this dull trifle, with both director and star appearing content to tread through the paces of the saccharine script.', TO_DATE('2012-06-15', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the magnificent seven', 2016, 'The Magnificent Seven never really lives up to the superlative in its title -- or the classics from which it draws inspiration -- but remains a moderately diverting action thriller on its own merits.', TO_DATE('2016-09-08', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man from london a londoni férfi', 2007, 'This dark, demanding film from art-house favorite Bela Tarr is by no means a typical crime procedural, but patient viewers will find much to admire.', TO_DATE('2007-05-24', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man from uncle', 2015, 'The Man from U.N.C.L.E. tries to distract from an unremarkable story with charismatic stars and fizzy set pieces, adding up to an uneven action thriller with just enough style to overcome its lack of substance.', TO_DATE('2015-08-10', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man on the train lhomme du train', 2002, 'A lovely, contemplative character study with two wonderful performances at its center.', TO_DATE('2002-10-02', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man who invented christmas', 2017, 'The Man Who Invented Christmas adds holiday magic to the writing of A Christmas Carol, putting a sweetly revisionist spin on the story behind a classic yuletide tale.', TO_DATE('2017-10-27', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man who killed don quixote', 2018, 'The Man Who Killed Don Quixote may not live up to long-gestating expectations, but it bears enough of director Terry Gilliam''s signature creative stamp to satisfy fans.', TO_DATE('2018-05-18', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man who killed hitler and then the bigfoot', 2018, 'The Man Who Killed Hitler and Then the Bigfoot just about lives up to the wild promise of its title, due in no small part to Sam Elliott''s world-weary work in the title role.', TO_DATE('2018-07-20', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man who knew infinity', 2015, 'The Man Who Knew Infinity might be a tad too conventional to truly do its subject justice, but Dev Patel and Jeremy Irons elevate the end result beyond mere biopic formula.', TO_DATE('2015-09-15', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man who knew too much', 2000, 'Remaking his own 1934 film, Hitchcock imbues The Man Who Knew Too Much with picturesque locales and international intrigue, and is helped by a brilliantly befuddled performance from James Stewart.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the man with the iron fists', 2012, 'Messy kung-fu homage The Man with the Iron Fists demonstrates a slavish affection for the genre it mimics, for better or worse.', TO_DATE('2012-11-01', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the marriage of maria braun die ehe der maria braun', 2000, 'Hanna Schygulla is a knockout in The Marriage of Maria Braun, an intimate epic that reaffirms Rainer Werner Fassbinder''s mastery of examining multifaceted people and a complicated nation.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the martian', 2015, 'Smart, thrilling, and surprisingly funny, The Martian offers a faithful adaptation of the bestselling book that brings out the best in leading man Matt Damon and director Ridley Scott.', TO_DATE('2015-09-11', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the master', 2012, 'Smart and solidly engrossing, The Master extends Paul Thomas Anderson''s winning streak of challenging films for serious audiences.', TO_DATE('2012-08-20', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the maze runner', 2014, 'With strong acting, a solid premise, and a refreshingly dark approach to its dystopian setting, The Maze Runner stands out from the crowded field of YA sci-fi adventures.', TO_DATE('2014-08-18', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the meddler', 2015, 'The Meddler transcends its cutesy title and familiar premise with a heartfelt look at family dynamics that''s honored by a marvelous performance from Susan Sarandon.', TO_DATE('2015-09-14', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the meg', 2018, 'The Meg sets audiences up for a good old-fashioned B-movie creature feature, but lacks the genre thrills -- or the cheesy bite -- to make it worth diving in.', TO_DATE('2018-08-08', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mercy', 2018, 'The Mercy sails on Colin Firth''s layered central performance, which adds necessary depth and nuance that the story sometimes lacks.', TO_DATE('2018-01-30', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the messengers', 2007, 'The Messengers is an atmospheric but derivative rip-off of countless other horror movies.', TO_DATE('2007-02-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the meyerowitz stories new and selected', 2017, 'The Meyerowitz Stories (New and Selected) observes the family dynamic through writer-director Noah Baumbach''s bittersweet lens and the impressive efforts of a remarkable cast.', TO_DATE('2017-05-21', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the midwife sage femme', 2017, 'The Midwife takes a rewardingly patient approach to potentially melodramatic material, emerging with a well-acted, emotionally resonant character study.', TO_DATE('2017-02-14', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mighty macs', 2011, 'Its heart is obviously in the right place, but The Mighty Macs is too blandly formulaic to transcend the genre''s many clichés.', TO_DATE('2011-10-16', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the minds eye', 2015, 'The Mind''s Eye packs a bloody B-movie punch, although its gleeful indulgence in gore may test the limits of all but the least squeamish.', TO_DATE('2015-09-19', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the miracle season', 2018, 'The Miracle Season has a worthy real-life story to tell, but one-dimensional characters and aggressively maudlin storytelling undercut any emotional uplift.', TO_DATE('2018-04-05', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the miseducation of cameron post', 2018, 'The Miseducation of Cameron Post tells its timely coming-of-age story with wit, compassion, and an affecting overall generosity of spirit.', TO_DATE('2018-01-23', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the missing picture', 2013, 'Thrillingly unorthodox and emotionally searing without being didactic, The Missing Picture is a uniquely poignant documentary -- and so much more.', TO_DATE('2013-09-26', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mole agent', 2020, 'Warm and funny, The Mole Agent offers audiences a poignant reminder that it''s never too late to forge new connections and embark on new adventures.', TO_DATE('2020-01-25', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the monster', 2016, 'The Monster uses its effectively simple setup and a powerful lead performance from Zoe Kazan to deliver a traditional yet subtly subversive -- and thoroughly entertaining -- horror story.', TO_DATE('2016-10-23', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the monuments men', 2014, 'Its intentions are noble and its cast is impressive, but neither can compensate for The Monuments Men''s stiffly nostalgic tone and curiously slack narrative.', TO_DATE('2014-01-29', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mortal instruments city of bones', 2013, 'The Mortal Instruments: City of Bones borrows ingredients from seemingly every fantasy franchise of the last 30 years -- but can''t seem to figure out what to do with them.', TO_DATE('2013-08-19', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the motel life', 2013, 'The Motel Life transcends its frustratingly uneven screenplay with some outstanding work from a talented cast.', TO_DATE('2013-11-04', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the motorcycle diaries', 2004, 'The Motorcycle Diaries is heartfelt and profound in its rendering of the formative experiences that turn Ernesto "Che" Guerva into a famous revolutionary.', TO_DATE('2004-01-25', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mountain between us', 2017, 'The Mountain Between Us may be too far-fetched for some viewers to appreciate, but it''s elevated by reliably engaging performances from Idris Elba and Kate Winslet.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mule', 2018, 'A flawed yet enjoyable late-period Eastwood entry, The Mule stubbornly retains its footing despite a few missteps on its occasionally unpredictable path.', TO_DATE('2018-12-12', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mummy', 2017, 'Lacking the campy fun of the franchise''s most recent entries and failing to deliver many monster-movie thrills, The Mummy suggests a speedy unraveling for the Dark Universe.', TO_DATE('2017-06-07', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the muppets', 2011, 'Clever, charming, and heartfelt, The Muppets is a welcome big screen return for Jim Henson''s lovable creations that will both win new fans and delight longtime devotees.', TO_DATE('2011-11-17', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the music never stopped', 2011, 'An involving, if sentimental and predictable family drama elevated by J.K. Simmons'' sympathetic lead performance.', TO_DATE('2011-01-22', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the music of strangers yoyo ma and the silk road ensemble', 2016, 'The Music of Strangers: Yo-Yo Ma and the Silk Road Ensemble offers a thrilling and too-rare glimpse of art''s power to bridge personal and cultural divides.', TO_DATE('2016-02-18', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the mustang', 2019, 'The Mustang finds fresh perspectives in a familiar redemption tale brought brilliantly to life by powerful performances from Bruce Dern and Matthias Schoenaerts.', TO_DATE('2019-02-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the naked gun 33 13 the final insult', 1994, 'Naked Gun 33 1/3: The Final Insult can''t help but be sporadically funny thanks to Leslie Nielsen''s dependably solid work, but it''s still a steep comedown from the original.', TO_DATE('1994-03-18', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the naked gun from the files of police squad', 2000, 'The Naked Gun is loaded chock full of gags that are goofy, unapologetically crass, and ultimately hilarious.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the neon demon', 2016, 'The Neon Demon is seductively stylish, but Nicolas Winding Refn''s assured eye can''t quite compensate for an underdeveloped plot and thinly written characters.', TO_DATE('2016-05-19', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the neverending story', 2000, 'A magical journey about the power of a young boy''s imagination to save a dying fantasy land, The NeverEnding Story remains a much-loved kids adventure.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the new girlfriend', 2014, 'While flirting with camp, François Ozon''s The New Girlfriend offers thoughtful -- and humorous -- commentary on sexual and gender identity.', TO_DATE('2014-09-06', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the new romantic', 2018, 'The New Romantic doesn''t quite achieve the level of storytelling sophistication it aspires to, but Jessica Barden''s performance elevates this enjoyable rom-com with a twist.', TO_DATE('2018-03-14', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the nice guys', 2016, 'The Nice Guys hearkens back to the buddy comedies of a bygone era while adding something extra courtesy of a knowing script and the irresistible chemistry of its leads.', TO_DATE('2016-05-15', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the night before', 2015, 'The Night Before provokes enough belly laughs to qualify as a worthwhile addition to the list of Christmas comedies worth revisiting, even if it isn''t quite as consistent as the classics.', TO_DATE('2015-11-16', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the night clerk', 2020, 'With a pair of charismatic leads struggling to enliven a poorly conceived story, The Night Clerk checks out early -- and viewers may want to follow suit.', TO_DATE('2020-02-16', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the night comes for us', 2018, 'A bloody thrill ride designed to test the limits of more squeamish viewers, The Night Comes for Us wields a stylishly violent, action-packed punch.', TO_DATE('2018-09-24', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the night eats the world la nuit a dévoré le monde', 2018, 'The Night Eats the World finds a few unexplored corners in the crowded zombie genre, with a refreshing emphasis on atmosphere and character development.', TO_DATE('2018-03-07', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the night listener', 2006, 'This psychological thriller compels by blurring the line between truth and fiction; unfortunately, the film itself gets muddled in a hazy account of Maupin''s original novel.', TO_DATE('2006-02-07', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the nightmare', 2015, 'Part documentary, part thriller, The Nightmare works just well enough in both respects to deliver a uniquely disturbing viewing experience.', TO_DATE('2015-01-28', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the nines', 2007, 'Though The Nines doesn''t solidify as well as writer/director John August would hope for, Ryan Reynolds''s strong performance makes each of the film''s intriguing segments worth watching.', TO_DATE('2007-01-23', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the normal heart', 2014, 'Thanks to Emmy-worthy performances from a reputable cast, The Normal Heart is not only a powerful, heartbreaking drama, but also a vital document of events leading up to and through the early AIDS crisis.', TO_DATE('2014-05-19', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the november man', 2014, 'The November Man has a few of the ingredients necessary for a better-than-average spy thriller, making it all the more disappointing that it falls back on dull genre clichés.', TO_DATE('2014-08-13', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the number 23', 2007, 'Jim Carrey has been sharp in a number of non-comedic roles, but this lurid, overheated, and self-serious potboiler is not one of them. The Number 23 is clumsy, unengaging, and mostly confusing.', TO_DATE('2007-02-07', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the nun', 2018, 'The Nun boasts strong performances, spooky atmospherics, and a couple decent set-pieces, but its sins include inconsistent logic and narrative slackness.', TO_DATE('2018-09-05', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the nut job', 2014, 'Hampered by an unlikable central character and source material stretched too thin to cover its brief running time, The Nut Job will provoke an allergic reaction in all but the least demanding moviegoers.', TO_DATE('2014-01-12', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the nut job 2 nutty by nature', 2017, 'The Nut Job 2: Nutty by Nature may be a slight improvement over its predecessor, but its frantic animated antics still offer minimal entertainment to all but the least discriminating viewers.', TO_DATE('2017-08-09', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the nutcracker and the four realms', 2018, 'Lacking a transporting yuletide story or dazzling dance routines, The Nutcracker and the Four Realms is a hollow holiday confection that''s lovely to look at -- and easy to forget.', TO_DATE('2018-10-31', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the oath', 2018, 'The Oath draws on hyper-partisan modern politics for a pointedly funny satire that hits its targets hard and often enough to more than achieve its desired discomfort.', TO_DATE('2018-09-26', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the occupant hogar', 2020, 'Meandering character development undercuts The Occupant''s exciting premise, though Javier Gutiérrez''s exceptional performance makes the proceedings work.', TO_DATE('2020-03-26', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the odd life of timothy green', 2012, 'It means well, but The Odd Life of Timothy Green is ultimately too cloyingly sentimental -- and thinly scripted -- to satisfy all but the least demanding viewers.', TO_DATE('2012-08-11', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the old man the gun', 2018, 'A well-told story brought to life by a beautifully matched cast, The Old Man & the Gun is pure, easygoing entertainment for film fans - and a fitting farewell to a legend.', TO_DATE('2018-09-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the one', 2001, 'The One plays more like a video game than a movie and borrows freely from other, better sci-fi actioners, burying Jet Li''s spectacular talents under heaps of editing and special effects.', TO_DATE('2001-10-23', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the one i love', 2014, 'The One I Love doesn''t take its intriguing premise quite as far as it could, but it still adds up to an ambitious, well-acted look at love and marriage.', TO_DATE('2014-01-22', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ones below', 2015, 'Creepy and well-crafted overall, The Ones Below marks an auspicious feature-length debut for writer-director David Farr.', TO_DATE('2015-10-04', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the oogieloves in the big balloon adventure', 2012, 'Although it may serve as a passing diversion for very young viewers, The Oogieloves fails to offer much more than several brightly colored examples of the worst stereotypes of modern children''s entertainment.', TO_DATE('2012-08-28', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the oranges', 2011, 'Despite the efforts of its accomplished cast, The Oranges suffers from a mediocre script that fails to deliver well-rounded characters, dramatic tension, or sufficient laughs.', TO_DATE('2011-09-17', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the order', 2003, 'A religious thriller that''s more lethargic and silly than thrilling.', TO_DATE('2003-09-05', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the order of myths', 2008, 'More than a documentary about the oldest Mardi Gras celebration in the south, Order of Myths encompasses the eccentric characters of Mobile and the still-lingering racial tensions that surround them.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the orphanage', 2007, 'Deeply unnerving and surprisingly poignant, The Orphanage is an atmospheric, beautifully crafted haunted house horror film that earns scares with a minimum of blood.', TO_DATE('2007-05-22', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the other lamb', 2019, 'Smartly directed by Malgorzata Szumowska, The Other Lamb uses a young woman''s coming-of-age story to explore the powerful hold cults can have on their followers.', TO_DATE('2019-09-07', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the other side of heaven', 2002, 'The Other Side of Heaven preaches to the converted; others will likely consider it simplistic, even offensive, propaganda.', TO_DATE('2002-01-03', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the other side of the door', 2016, 'Laden with flimsy jump scares and cheap stereotypes, The Other Side of the Door wastes solid work from Sarah Wayne Callies on thoroughly middling horror fare.', TO_DATE('2016-02-23', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the other side of the wind', 2018, 'A satisfying must-watch for diehard cineastes, The Other Side of the Wind offers the opportunity to witness a long-lost chapter in a brilliant filmmaker''s career.', TO_DATE('2018-08-31', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the other woman', 2011, 'Natalie Portman and Lisa Kudrow deliver fine performances in The Other Woman, but they''re muted by Don Roos'' clumsy direction and cluttered, melodramatic script.', TO_DATE('2011-01-03', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the other woman', 2014, 'The Other Woman definitely boasts a talented pedigree, but all that skill is never fully brought to bear on a story that settles for cheap laughs instead of reaching its empowering potential.', TO_DATE('2014-04-04', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the outoftowners', 1999, 'Solid source material and a cast of talented comedians aren''t enough to make The Out-of-Towners worth hosting on a screen of any size.', TO_DATE('1999-04-02', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the outpost', 2020, 'Told with gripping realism, The Outpost is a thrilling technical feat and a worthy tribute to military heroes.', TO_DATE('2020-06-26', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the outsider', 2018, 'Starring a disengaged Jared Leto and stuffed with gangster cliches, The Outsider never distinguishes itself enough to gain admittance into the inner circle of good yakuza pictures.', TO_DATE('2018-03-08', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the outsider', 2019, 'The Outsider may satisfy Western fans, but despite a winning performance from Country music legend Trace Adkins it''s too predictable to really leave a mark.', TO_DATE('2019-06-01', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the overnight', 2015, 'Witty and unpredictable, The Overnight benefits from writer-director Patrick Brice''s sure-handed touch and strong performances from a talented cast.', TO_DATE('2015-01-24', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the overnighters', 2014, 'Hard-hitting, absorbing, and painfully relevant, The Overnighters offers an urgent and compassionate picture of life in 21st century America.', TO_DATE('2014-01-23', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the package', 2018, 'The Package learns the hard way that a penis joke does not a movie make.', TO_DATE('2018-08-09', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the painted bird', 2019, 'Brutally uncompromising in its portrayal of Nazi Germany, The Painted Bird is a difficult watch that justifies its stark horror with searing impact.', TO_DATE('2019-09-03', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the painter and the thief', 2020, 'The Painter and the Thief uses the unlikely bond between a criminal and his victim as the canvas for a compelling portrait of compassion and forgiveness.', TO_DATE('2020-01-24', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the pale door', 2020, 'Beyond The Pale Door lies an intriguing western/horror hybrid -- albeit one that struggles to fashion its halves into a compelling whole.', TO_DATE('2020-08-17', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the paperboy', 2012, 'Trashy and melodramatic, The Paperboy is enlivened by a strong cast and a steamy, sordid plot, but it''s uneven and often veers into camp.', TO_DATE('2012-05-24', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the party', 2017, 'Old-fashioned charm meets sharp wit and modern social satire in The Party, a biting comedy carried by a shining performance from Patricia Clarkson.', TO_DATE('2017-02-13', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the patience stone', 2013, 'It may prove frustratingly slow for some viewers, but more contemplative filmgoers will find themselves rewarded by The Patience Stone''s quietly fierce storytelling, as well as a searing starring turn from Golshifteh Farahani.', TO_DATE('2013-03-24', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the peanut butter falcon', 2019, 'A feelgood adventure brought to life by outstanding performances, The Peanut Butter Falcon finds rich modern resonance in classic American fiction.', TO_DATE('2019-03-10', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the peanuts movie', 2015, 'The Peanuts Movie offers a colorful gateway into the world of its classic characters and a sweetly nostalgic -- if relatively unambitious -- treat for the adults who grew up with them.', TO_DATE('2015-11-02', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the perfect date', 2019, 'Though it may not be the perfect romcom, The Perfect Date''s endearing leads still manage to show viewers a fun -- if overly familiar -- time.', TO_DATE('2019-04-12', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the perfect guy', 2015, 'The Perfect Guy threatens to tip into enjoyably depraved territory, but ultimately settles for timid thriller clichés.', TO_DATE('2015-09-11', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the perfection', 2018, 'Led by a pair of compelling performances, The Perfection is a smart, gripping thriller that barbs its wild twists with cutting wit.', TO_DATE('2018-09-27', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the perks of being a wallflower', 2012, 'The Perks of Being a Wallflower is a heartfelt and sincere adaptation that''s bolstered by strong lead performances.', TO_DATE('2012-09-04', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the phenom', 2016, 'Powerfully acted and emotionally affecting, The Phenom proves a baseball movie can step away from the mound and still deliver a heater down the middle.', TO_DATE('2016-04-18', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the photograph', 2020, 'Gorgeous visuals, an affecting love story, and simmering chemistry between Issa Rae and Lakeith Stanfield keep The Photograph solidly in focus.', TO_DATE('2020-02-12', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the piano tuner of earthquakes', 2005, 'Though visually stunning and brilliantly original, the film fails to resonate emotionally.', TO_DATE('2005-09-10', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the pillow book', 1997, 'The Pillow Book is undeniably sensual and visually ravishing, but the film''s narrative lacks the hypnotic pull of its imagery.', TO_DATE('1997-06-06', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the pirates band of misfits', 2012, 'It may not quite scale Aardman''s customary delirious heights, but The Pirates! still represents some of the smartest, most skillfully animated fare that modern cinema has to offer.', TO_DATE('2012-03-19', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the place beyond the pines', 2012, 'Ambitious to a fault, The Place Beyond the Pines finds writer/director Derek Cianfrance reaching for -- and often grasping -- thorny themes of family, fatherhood, and fate.', TO_DATE('2012-09-09', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the platform el hoyo', 2019, 'While it may feel muddled at times, The Platform is an inventive and captivating dystopian thriller.', TO_DATE('2019-09-06', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the polka king', 2017, 'Despite moments of hilarity and a talented ensemble, discordant direction and a sloppy script keep The Polka King from truly singing.', TO_DATE('2017-01-23', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the pool', 2007, 'Beautifully crafted with loosely drawn characters and a lilting, natural pace, Chris Smith''s The Pool features a universal message to which everyone can relate.', TO_DATE('2007-01-29', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the possession', 2012, 'It may be based on a true story, but that doesn''t excuse the way The Possession repeatedly falls back on hoary ghost movie clichés -- or the uninentional laughs it provides.', TO_DATE('2012-08-28', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the possession of hannah grace', 2018, 'The Possession of Hannah Grace feints at real horror just often enough to offer hints of the movie it should have been -- and further frustrate viewers seeking a good scare.', TO_DATE('2018-11-29', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the post', 2017, 'The Post''s period setting belies its bitingly timely themes, brought compellingly to life by director Steven Spielberg and an outstanding ensemble cast.', TO_DATE('2017-12-05', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the predator', 2018, 'The Predator has violence and quips to spare, but its chaotically hollow action adds up to another missed opportunity for a franchise increasingly defined by disappointment.', TO_DATE('2018-09-07', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the prince me', 2004, 'A bland, fluffy, and predictable bit of wish fulfillment.', TO_DATE('2004-03-13', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the princess switch', 2018, 'The Princess Switch offers a healthy dose of charming, light-hearted, twin-swap fun and is delightful viewing for any hopeless romantic.', TO_DATE('2018-11-16', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the prodigy', 2019, 'The Prodigy doesn''t take the bad seed genre to any truly new places, but for horror fans in search of an evil child to fear, it might still be worth a watch.', TO_DATE('2019-02-06', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the professor', 2018, 'A muddled story populated with thinly written characters and arranged around a misguided Johnny Depp performance, The Professor fails early and often.', TO_DATE('2018-10-06', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the program', 2015, 'Ben Foster''s impressive efforts to channel Lance Armstrong are often enough to power The Program past director Stephen Frears'' frustrating unwillingness to delve deeper into its real-life story.', TO_DATE('2015-09-14', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the promise', 2016, 'The Promise wastes an outstanding cast and powerful real-life story on a love triangle that frustratingly fails to engage.', TO_DATE('2016-09-12', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('kahlil gibrans the prophet', 2015, 'Kahlil Gibran''s the Prophet is a thrillingly lovely adaptation of the classic text, albeit one that doesn''t quite capture the magic of its source material.', TO_DATE('2015-03-22', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the public', 2018, 'Its intentions are sometimes easier to appreciate than its execution, but The Public remains an earnest and reasonably engaging social advocacy drama.', TO_DATE('2018-09-10', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the puffy chair', 2005, 'First-timer Duplass offers a realistic and thoughtful romantic comedy.', TO_DATE('2005-03-22', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the punk singer', 2013, 'It verges on hagiography, but given the deeply compelling nature of its subject''s story, The Punk Singer can be forgiven its lack of objectivity.', TO_DATE('2013-04-03', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the purge', 2013, 'Half social allegory, half home-invasion thriller, The Purge attempts to make an intelligent point, but ultimately devolves into numbing violence and tired clichés.', TO_DATE('2013-05-07', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the purge anarchy', 2014, 'Gritty, grisly, and uncommonly ambitious, The Purge: Anarchy represents a slight improvement over its predecessor, but it''s still never as smart or resonant as it tries to be.', TO_DATE('2014-07-16', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the purge election year', 2016, 'It isn''t particularly subtle, but The Purge: Election Year''s blend of potent jolts and timely themes still add up to a nastily effective diversion.', TO_DATE('2016-06-28', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the pyramid', 2014, 'Poorly lit and thinly writ, The Pyramid houses little more than clunky dialogue, amateurish acting, and dusty found-footage scares.', TO_DATE('2014-12-02', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the quake skjelvet', 2018, 'A satisfyingly smart action thriller, The Quake delivers plenty of nail-biting tension without sacrificing character development or common sense.', TO_DATE('2018-10-17', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the queen', 2000, 'Celebrating its subjects without ever losing sight of their story, The Queen is a fascinating time capsule that has only gained resonance since its release.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the queen of versailles', 2012, 'The Queen of Versailles is a timely, engaging, and richly drawn portrait of the American Dream improbably composed of equal parts compassion and schadenfreude.', TO_DATE('2012-01-20', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the quiet', 2005, 'This psychological thriller''s talented cast is undercut by leaden pacing and a problematic plot.', TO_DATE('2005-09-22', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the quiet one', 2019, 'Generally entertaining if not particularly illuminating, The Quiet One offers a suitably muted appraisal of a rock veteran''s incredible life and career.', TO_DATE('2019-05-03', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the quiet ones', 2014, 'While it definitely sports a few palpable scares, The Quiet Ones finds Hammer Films trading too heavily on past glories.', TO_DATE('2014-04-02', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rachel divide', 2018, 'Compelling and disturbing in occasionally unintended ways, The Rachel Divide uses one woman''s infamy to examine modern American race relations.', TO_DATE('2018-04-24', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the raid 2', 2014, 'Although its high-energy plot and over-the-top violence may play better with genre aficionados, The Raid 2 definitely delivers more of everything audiences loved about its predecessor.', TO_DATE('2014-01-22', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the raid redemption', 2011, 'No frills and all thrills, The Raid: Redemption is an inventive action film expertly paced and edited for maximum entertainment.', TO_DATE('2011-09-13', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the railway man', 2013, 'Understated to a fault, The Railway Man transcends its occasionally stodgy pacing with a touching, fact-based story and the quiet chemistry of its stars.', TO_DATE('2013-09-08', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the raven', 2012, 'Thinly scripted, unevenly acted, and overall preposterous, The Raven disgraces the legacy of Edgar Allen Poe with a rote murder mystery that''s more silly than scary.', TO_DATE('2012-03-05', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the real dirt on farmer john', 2005, 'Ostensibly a bio about an eccentric farmer, The Real Dirt on Farmer John also doubles as a stirring exploration of man''s common struggle with loss and prejudice.', TO_DATE('2005-06-02', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the red sea diving resort', 2019, 'The Red Sea Diving Resort makes uninspired use of actual events, using thinly written characters to tell a story derailed by its own good intentions.', TO_DATE('2019-07-29', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the red turtle la tortue rouge', 2016, 'The Red Turtle adds to Studio Ghibli''s estimable legacy with a beautifully animated effort whose deceptively simple story boasts narrative layers as richly absorbing as its lovely visuals.', TO_DATE('2016-05-18', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the red violin le violon rouge', 1999, 'A symphony of storytelling whose lulls lead to satisfying crescendos, The Red Violin weaves a centuries-long saga with the journey of a single instrument.', TO_DATE('1999-06-11', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the reluctant fundamentalist', 2012, 'The Reluctant Fundamentalist is technically proficient, with solid acting and cinematography, but its message is so ambitious and heavy-handed that some of its power is robbed.', TO_DATE('2012-10-29', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rental', 2020, 'Some tricky genre juggling makes The Rental a bit of a fixer-upper, but effective chills and a solid cast make this a fine destination for horror fans.', TO_DATE('2020-06-15', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rescuers', 2000, 'Featuring superlative animation, off-kilter characters, and affectionate voice work by Bob Newhart and Eva Gabor, The Rescuers represents a bright spot in Disney''s post-golden age.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the return', 2004, 'A suspenseful but perplexing thriller.', TO_DATE('2004-01-15', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the revenant', 2015, 'As starkly beautiful as it is harshly uncompromising, The Revenant uses Leonardo DiCaprio''s committed performance as fuel for an absorbing drama that offers punishing challenges -- and rich rewards.', TO_DATE('2015-12-04', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rewrite', 2014, 'The Rewrite''s unremarkable plot is enlivened considerably by its likable cast, adding up to a comedy that coasts capably on the charms of Hugh Grant and his co-stars.', TO_DATE('2014-10-07', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rhythm section', 2020, 'Blake Lively delivers an impressive lead performance, but The Rhythm Section plods predictably through a story that could have used some flashier riffs.', TO_DATE('2020-01-29', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rider', 2017, 'The Rider''s hard-hitting drama is only made more effective through writer-director Chloé Zhao''s use of untrained actors to tell the movie''s fact-based tale.', TO_DATE('2017-05-22', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the riot club posh', 2014, 'The Riot Club may not be subtle, but it makes its points with power, using dark humor and a talented cast to offer a scathing indictment of unearned privilege.', TO_DATE('2014-09-06', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rite', 2011, 'Anthony Hopkins is as excellent as ever, but he''s no match for The Rite''s dawdling pace and lack of chills -- or Colin O''Donoghue''s tentative performance in the leading role.', TO_DATE('2011-01-25', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ritual', 2017, 'Director David Bruckner makes evocative use of the Scandinavian setting and a dedicated cast to deliver a handsome -- if familiar -- horror story.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the river', 2000, 'Jean Renoir''s first film shot in color takes full advantage of its broadened palette, yielding a visually virtuosic coming of age tale filled with moving performances and vibrant hues.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the robber', 2011, 'The Robber draws on real-life events for a complex character-driven drama that draws viewers in even as it avoids hitting traditional thriller beats.', TO_DATE('2011-02-04', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rocket', 2013, 'A feel-good success crafted with care, Kim Mordaunt''s story of two young kids in Laos is a heartfelt audience pleaser while remaining sensitive toward its subjects.', TO_DATE('2013-04-25', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rocky horror picture show lets do the time warp again', 2016, 'Laverne Cox''s fabulous portrayal of Frank N. Furter leads a strong ensemble effort, but the stars can''t infuse this reimagining with enough energy, creativity, and quirk to make TRHPS: Let''s Do the Time Warp Again a worthwhile endeavor.', TO_DATE('2016-10-13', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the roommate', 2011, 'Devoid of chills, thrills, or even cheap titillation, The Roommate isn''t even bad enough to be good.', TO_DATE('2011-02-04', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rover', 2014, 'Fueled by engaging performances from Guy Pearce and Robert Pattinson, the tension-filled The Rover overcomes its narrative faults through sheer watchability.', TO_DATE('2014-05-09', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the royal tenenbaums', 2001, 'The Royal Tenenbaums is a delightful adult comedy with many quirks and a sense of poignancy. Many critics especially praised Hackman''s performance.', TO_DATE('2001-10-03', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ruins', 2008, 'Despite a solid cast and truly frightening source material, The Ruins founders, thanks to a weak script and an excess of gore.', TO_DATE('2008-04-03', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rules of the game la règle du jeu', 2000, 'Its genius escaped many viewers at the time, but in retrospect, The Rules of the Game stands as one of Jean Renoir''s -- and cinema''s -- finest works.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the runaways', 2010, 'Viewers expecting an in-depth biopic will be disappointed, but The Runaways is as electric as the band''s music, largely thanks to strong performances from Michael Shannon, Dakota Fanning, and Kristen Stewart.', TO_DATE('2010-01-25', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the rundown', 2003, 'The Rundown doesn''t break any new ground, but it''s a smart, funny buddy action picture with terrific comic chemistry between Dwayne "The Rock" Johnson and Seann William Scott.', TO_DATE('2003-09-13', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the runner', 2015, 'In spite of a promising premise and a roundly talented cast, The Runner is a disappointing outing to be viewed by only the staunchest of Nicolas Cage completists.', TO_DATE('2015-08-04', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sacrament', 2013, 'While it may be a bit too slow for some, The Sacrament offers enough tense atmosphere and intriguing ideas to satisfy discerning horror buffs.', TO_DATE('2013-09-04', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sacrifice', 2000, 'Formally impressive, visually accomplished, and narratively rewarding, The Sacrifice places a fittingly solid capstone on a brilliant filmmaking career.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the salesman forushande', 2016, 'The Salesman takes an ambitiously complex look at thought-provoking themes, and the well-acted results prove another consistently absorbing entry in writer-director Asghar Farhadi''s distinguished filmography.', TO_DATE('2016-05-26', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the salt of the earth', 2014, 'While the work it honors may pose thorny ethical questions that Salt of the Earth neglects to answer, it remains a shattering, thought-provoking testament to Sebastião Salgado''s career.', TO_DATE('2014-05-20', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the salvation', 2014, 'It''s all but impossible to add anything new or fresh to the traditional Western, but -- thanks in no small part to Mads Mikkelson''s performance -- The Salvation comes close.', TO_DATE('2014-05-16', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the samaritan', 2012, 'The Samaritan is a ludicrous neo-noir starring a seemingly bored Samuel L. Jackson.', TO_DATE('2012-03-09', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the santa clause 2', 2002, 'Though it''s harmless as family entertainment and has moments of charm, The Santa Clause 2 is also predictable and forgettable.', TO_DATE('2002-10-12', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sapphires', 2012, 'While it''s plenty predictable and sentimental, The Sapphires also has an irresistible feel-good vibe, winning music and charming performances to spare.', TO_DATE('2012-05-20', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the science of sleep', 2006, 'Lovely and diffuse, Sleep isn''t as immediately absorbing as Gondry''s previous work, but its messy beauty is its own reward.', TO_DATE('2006-01-23', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sea of trees', 2015, 'Dull, maudlin, and fundamentally empty, The Sea of Trees extinguishes the contributions of a talented cast and marks a depressing low point in director Gus Van Sant''s career.', TO_DATE('2015-05-15', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the seagull', 2018, 'The latest iteration of The Seagull does little to distinguish itself from other Chekhov adaptations but provides a pleasing showcase for its sterling cast.', TO_DATE('2018-04-19', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the second best exotic marigold hotel', 2015, 'The Second Best Exotic Marigold Hotel is about as original as its title -- but with a cast this talented and effortlessly charming, that hardly matters.', TO_DATE('2015-02-17', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the second mother que horas ela volta', 2015, 'The Second Mother''s compelling characters serve an artfully drawn, thought-provoking story that''s beautifully brought to life by a talented cast.', TO_DATE('2015-02-19', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the secret dare to dream', 2020, 'For those who Dare to Dream of a worthy dramatic adaptation of The Secret, this sodden romance will prove a disappointment too painful to visualize.', TO_DATE('2020-07-30', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the secret garden', 2020, 'Faithful in spirit while putting its own spin on the source material, The Secret Garden adds a charming entry to the long list of this beloved book''s adaptations.', TO_DATE('2020-08-05', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the secret life of pets', 2016, 'Fast-paced, funny, and blessed with a talented voice cast, The Secret Life of Pets offers a beautifully animated, cheerfully undemanding family-friendly diversion.', TO_DATE('2016-06-16', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the secret life of pets 2', 2019, 'The Secret Life of Pets 2 doesn''t teach its animated stars any new narrative tricks -- but for fans of the original, this funny, energetic sequel should still satisfy.', TO_DATE('2019-05-23', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the secret life of walter mitty', 2013, 'It doesn''t lack for ambition, but The Secret Life of Walter Mitty fails to back up its grand designs with enough substance to anchor the spectacle.', TO_DATE('2013-10-05', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the secret life of words', 2005, 'The Secret Life of Words is a slow, mannered drama, but with a revelatory and powerful ending that rewards the patient viewer.', TO_DATE('2005-09-19', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the secret scripture', 2016, 'The Secret Scripture has acclaimed source material and a well-chosen cast in its corner, but despite its stars'' valiant efforts, this adaptation was better left on the page.', TO_DATE('2016-09-11', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the secret world of arrietty', 2011, 'Visually lush, refreshingly free of family-friendly clatter, and anchored with soulful depth, The Secret World of Arrietty lives up to Studio Ghibli''s reputation.', TO_DATE('2011-02-16', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the selfish giant', 2013, 'Starkly emotional and beautifully directed, The Selfish Giant uses a lovely script and some powerful performances to present some of the best that modern British cinema has to offer.', TO_DATE('2013-05-17', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sense of an ending', 2017, 'Anchored by a strong starring performance by Jim Broadbent, The Sense of an Ending proves consistently gripping even as it skims the narrative surface of its literary source material.', TO_DATE('2017-01-06', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sessions', 2012, 'Tender, funny, and touching, The Sessions provides an acting showcase for its talented stars and proves it''s possible for Hollywood to produce a grown-up movie about sex.', TO_DATE('2012-01-24', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the shack', 2017, 'The Shack''s undeniably worthy message is ill-served by a script that confuses spiritual uplift with melodramatic clichés and heavy-handed sermonizing.', TO_DATE('2017-03-02', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('calm with horses the shadow of violence', 2019, 'The Shadow of Violence presents a grimly effective portrait of one man''s struggle with divided loyalties, elevated by standout performances from a stellar cast.', TO_DATE('2019-09-07', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the shallows', 2016, 'Lean and solidly crafted, The Shallows transcends tired shark-attack tropes with nasty thrills and a powerful performance from Blake Lively.', TO_DATE('2016-06-22', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the shape of water', 2017, 'The Shape of Water finds Guillermo del Toro at his visually distinctive best -- and matched by an emotionally absorbing story brought to life by a stellar Sally Hawkins performance.', TO_DATE('2017-08-31', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the short history of the long road', 2019, 'A potential breakout vehicle for its writer-director as well as its star, The Short History of the Long Road finds fresh byways along its well-traveled path.', TO_DATE('2019-04-29', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the signal', 2014, 'Director William Eubank clearly has big ideas and an impressive level of technical expertise; unfortunately, The Signal fritters them away on a poorly constructed story.', TO_DATE('2014-01-30', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the silence', 2011, 'Unsettling and at times lurid, Baran bo Odar''s The Silence is a thrilling foray into film noir.', TO_DATE('2011-10-26', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the silence', 2019, 'The Silence has nothing new to say with a derivative premise and placid pacing -- even a wasted Stanley Tucci is unable to elevate the stodgy material a decibel above dreadful.', TO_DATE('2019-04-10', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the similars los parecidos', 2015, 'A smart homage to genre filmmaking, The Similars is a fun and frightening film that balances socio-political issues with aplomb.', TO_DATE('2015-10-20', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the singing revolution', 2007, 'An inspiring true story, The Singing Revolution proves the pressure for political change can be induced through any number of surprising -- and non-violent -- means.', TO_DATE('2007-10-25', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the single moms club', 2014, 'The Single Moms'' Club finds Tyler Perry avoiding some of the pitfalls of his earlier work, but continuing to rely on heavy-handed melodrama at the expense of sensible characters or absorbing storylines.', TO_DATE('2014-03-13', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sisters brothers', 2018, 'The Sisters Brothers rides familiar genre trails in occasionally unexpected ways - a satisfying journey further elevated by its well-matched leading men.', TO_DATE('2018-09-04', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sitter', 2011, 'With its recycled plot, misguided gags, and formula performance from Jonah Hill, The Sitter adds up to another disappointing entry from director David Gordon Green.', TO_DATE('2011-12-07', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the skeleton twins', 2014, 'Led by powerful performances from Kristen Wiig and Bill Hader, The Skeleton Twins effectively mines laughs and tears from family drama.', TO_DATE('2014-01-19', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the skin i live in', 2011, 'The Skin I Live In lacks Almodovar''s famously charged romance, replaced with a wonderfully bizarre and unpredictable detour into arthouse ick.', TO_DATE('2011-05-19', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the smurfs', 2011, 'The Smurfs assembles an undeniably talented cast of voice actors and live-action stars -- then crushes them beneath a blue mound of lowest-common-denominator kiddie fare.', TO_DATE('2011-07-24', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the smurfs 2', 2013, 'Like its predecessor, Smurfs 2 may amuse small children, but it''s largely an unambitious, charm-free collection of slapstick gags and one-liners.', TO_DATE('2013-07-28', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the snowman', 2017, 'A mystery that feels as mashed together and perishable as its title, The Snowman squanders its bestselling source material as well as a top-notch ensemble cast.', TO_DATE('2017-10-11', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the snowtown murders', 2011, 'It''s a bleak and brutal endurance test, but for viewers with the strength and patience to make it to the end, Snowtown will prove an uncommonly powerful viewing experience.', TO_DATE('2011-03-30', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the son of no one', 2011, 'Needless stylistic flourishes and wholly illogical storytelling make The Son of No One a grisly, repugnant journey.', TO_DATE('2011-01-25', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the song of names', 2019, 'The Song of Names is made from intriguing ingredients, but they never quite coalesce into a drama that satisfies the way it should.', TO_DATE('2019-09-09', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the song of sway lake', 2017, 'The Song of Sway Lake benefits from alluring, evocative atmosphere, although it isn''t always enough to compensate for a shaggy narrative and overall lack of focus.', TO_DATE('2017-07-06', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sound of music live', 2013, 'The Sound of Music is definitely there, but without the necessary feeling to make it feel truly alive.', TO_DATE('2013-12-06', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sound of silence', 2019, 'The Sound of Silence occasionally struggles to control its tone and convey its message, but it benefits from compelling performances and intriguing ideas.', TO_DATE('2019-01-28', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the souvenir', 2019, 'Made by a filmmaker in command of her craft and a star perfectly matched with the material, The Souvenir is a uniquely impactful coming of age drama.', TO_DATE('2019-01-28', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the space between us', 2017, 'The Space Between Us strands its star-crossed young lovers in a mind-numbingly vast expanse of shameless cheese that will send all but the most forgiving viewers eye-rolling for the exits.', TO_DATE('2017-02-02', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the special relationship', 2010, 'Well-cast and compellingly directed, The Special Relationship offers an intelligent look into the complex dynamic between two world leaders.', TO_DATE('2010-06-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the spectacular now', 2013, 'The Spectacular Now is an adroit, sensitive film that avoids typical coming-of-age story trappings.', TO_DATE('2013-01-20', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the spirit', 2008, 'Though its visuals are unique, The Spirit''s plot is almost incomprehensible, the dialogue is ludicrously mannered, and the characters are unmemorable.', TO_DATE('2008-12-18', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the spongebob movie sponge out of water', 2015, 'The SpongeBob Movie: Sponge Out of Water won''t win over many viewers who aren''t fans of the show, but for the converted, it''s another colorful burst of manic fun.', TO_DATE('2015-01-31', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the spy who dumped me', 2018, 'The Spy Who Dumped Me isn''t the funniest or most inventive spy comedy, but Kate McKinnon remains as compulsively watchable as ever.', TO_DATE('2018-07-26', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the square', 1800, 'The Square may not quite live up to the modern noir classics that inspired it, but with twists and tension to spare, it comes admirably close.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the square al midan', 2013, 'The Square offers an electrifying -- and edifying -- ground-level glimpse of life inside a real-life political revolution.', TO_DATE('2013-09-13', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the square', 2017, 'The Square finds writer-director Ruben Östlund as ambitious as ever -- and delivering an unforgettably unusual work whose challenging themes pay thought-provoking dividends.', TO_DATE('2017-05-22', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the standoff at sparrow creek', 2018, 'Taut and unpredictable, The Standoff at Sparrow Creek should satisfy suspense fans in the mood for a well-told story topped with a generous helping of violence.', TO_DATE('2018-09-09', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the stanford prison experiment', 2015, 'As chillingly thought-provoking as it is absorbing and well-acted, The Stanford Prison Experiment offers historical drama that packs a timelessly relevant punch.', TO_DATE('2015-01-27', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the star', 2017, 'The Star may not leave audiences singing "Hallelujah," but its offbeat yet sincere approach to the nativity story makes for acceptably diverting holiday viewing.', TO_DATE('2017-11-14', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the strange color of your bodys tears', 2013, 'Bursting with visual style but suffering from a dearth of discernible narrative, The Strange Color of Your Body''s Tears is recommended only for giallo enthusiasts.', TO_DATE('2013-09-09', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the strangers', 2008, 'The Strangers has a handful of genuinely scary moments, but they''re not enough to elevate the end results above standard slasher fare.', TO_DATE('2008-05-21', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the strangers prey at night', 2018, 'The Strangers: Prey at Night may appeal to fans of the original who''ve been jonesing for a sequel, but its thin story and ironic embrace of genre tropes add up to a bloody step back.', TO_DATE('2018-03-07', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sugarland express', 2000, 'Its plot may ape the countercultural road movies of its era, but Steven Spielberg''s feature debut displays many of the crowd-pleasing elements he''d refine in subsequent films.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the summit', 2013, 'While it could use more clarity than director Nick Ryan brings to bear, the real-life story behind The Summit still makes for compelling viewing.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sun is also a star', 2019, 'The Sun Is Also a Star has a pair of easy-to-love leads, but tests the audience''s affection with a storyline that strains credulity past the breaking point.', TO_DATE('2019-05-15', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sunlit night', 2019, 'Jenny Slate remains as charming as ever, but her winsome performance isn''t enough to overcome The Sunlit Night''s grating tone and meandering plot.', TO_DATE('2019-01-27', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sunset limited', 2011, 'The Sunset Limited''s ambition is undercut by arch dialogue and a claustrophobic setting, but Tommy Lee Jones and Samuel L. Jackson''s dueling performances bring heft to this battle of wills.', TO_DATE('2011-02-14', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the survivalist', 2015, 'The Survivalist''s deliberate pace pays gripping dividends with a tautly told post-apocalyptic drama that offers some uniquely thought-provoking twists.', TO_DATE('2015-10-20', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the sweeney', 2012, 'Ray Winstone exudes tough-guy bravado, but this cop thriller otherwise feels thoroughly generic.', TO_DATE('2012-06-27', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the swerve', 2019, 'Bound together by Azura Skye''s riveting work in the central role, The Swerve paints a harrowing portrait of a life unmoored.', TO_DATE('2019-10-23', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the switch', 2010, 'The Switch has an interesting premise and a charming cast; unfortunately, it also has a trite script that hews too close to tired rom-com formulas.', TO_DATE('2010-08-17', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the taking of pelham one two three', 2002, 'Breezy, thrilling, and quite funny, The Taking of Pelham One Two Three sees Walter Matthau and Robert Shaw pitted against each other in effortlessly high form.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the tax collector', 2020, 'A taxing and ill-advised crime drama, The Tax Collector fails to accrue much meaningful interest.', TO_DATE('2020-08-03', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the texas chainsaw massacre the beginning', 2006, 'The Texas Chainsaw Massacre: The Beginning is full of blood and gore, but not enough scares or a coherent story to make for a successful horror film.', TO_DATE('2006-09-25', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the theory of everything', 2014, 'Part biopic, part love story, The Theory of Everything rises on James Marsh''s polished direction and the strength of its two leads.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the thief of bagdad', 2002, 'It requires some viewing commitment, but this beautifully assembled showcase for Douglas Fairbanks'' acting offers some splendid treats for classic film fans.', TO_DATE('2002-08-22', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the thing', 2011, 'It serves the bare serviceable minimum for a horror flick, but The Thing is all boo-scares and a slave to the far superior John Carpenter version.', TO_DATE('2011-10-10', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the third man', 1949, 'This atmospheric thriller is one of the undisputed masterpieces of cinema, and boasts iconic performances from Joseph Cotten and Orson Welles.', TO_DATE('1949-09-03', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the third murder sandome no satsujin', 2017, 'The Third Murder makes satisfying work of its weighty themes, even if it doesn''t quite stand with writer-director Hirokazu Koreeda''s best efforts.', TO_DATE('2017-09-05', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the thorn in the heart', 2009, 'Michel Gondry''s directorial style is as bewitching as ever, but his intensely personal subject matter may leave viewers wondering why The Thorn in the Heart didn''t stay in the family.', TO_DATE('2009-05-16', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the three caballeros', 2000, 'One of Disney''s more abstract creations, The Three Caballeros is a dazzling, colorful picture that shows the company at an artistic acme.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the three musketeers', 2011, 'It plays admirably fast and loose with Alexandre Dumas'' classic tale, but in every other respect, The Three Musketeers offers nothing to recommend -- or to set it apart from the many other film adaptations.', TO_DATE('2011-03-01', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the tillman story', 2010, 'Passionate, angry, and insightful, The Tillman Story offers a revealing portrait of its subject''s inspiring life and untimely death.', TO_DATE('2010-01-26', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the times of harvey milk', 2002, 'True to its title, The Times of Harvey Milk looks back on the life of the titular politician and activist -- and the era he helped define with his trailblazing career.', TO_DATE('2002-04-15', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the to do list', 2013, 'The To Do List may play things disappointingly safe given its rather daring premise, but writer-director Maggie Carey''s sure hand -- and Aubrey Plaza''s performance -- keep the laughs coming.', TO_DATE('2013-07-21', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the tomorrow man', 2019, 'John Lithgow and Blythe Danner are almost enough to save The Tomorrow Man, but their efforts are overwhelmed by a problematic story.', TO_DATE('2019-01-31', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the town', 2010, 'Tense, smartly written, and wonderfully cast, The Town proves that Ben Affleck has rediscovered his muse -- and that he''s a director to be reckoned with.', TO_DATE('2010-09-08', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the traitor', 2019, 'While it doesn''t probe particularly far below the surface of its central character, The Traitor tells its fact-based story with enough energy to entertain.', TO_DATE('2019-05-23', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the transporter refueled', 2015, 'The Transporter Refueled has little to offer beyond a handful of decent action sequences, leaving this reboot''s title feeling more like wishful thinking than a restatement of purpose.', TO_DATE('2015-09-02', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the treasure', 2015, 'The Treasure digs deep into Romanian history and yields a rich comedy full of deadpan laughs and winsome observations.', TO_DATE('2015-10-05', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the tree', 2010, 'Though it leans rather heavily on its central metaphor, The Tree is a moving and ultimately hopeful meditation on grief with shades of magical realism.', TO_DATE('2010-09-23', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the tree of life', 2011, 'Terrence Malick''s singularly deliberate style may prove unrewarding for some, but for patient viewers, Tree of Life is an emotional as well as visual treat.', TO_DATE('2011-05-16', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the trials of muhammad ali', 2013, 'Director Bill Siegel doesn''t explore any new boundaries of the documentary with The Trials of Muhammad Ali, but his subject is so inherently fascinating that the movie proves gripping in spite of its familiar beats.', TO_DATE('2013-06-20', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the tribe', 2014, 'A bleak, haunting drama whose wordless dialogue speaks volumes, The Tribe is a bold, innovative take on silent films for a contemporary audience.', TO_DATE('2014-05-30', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the tribes of palos verdes', 2017, 'The Tribes of Palos Verdes serves up a minor -- albeit alluringly atmospheric -- variation on the coming-of-age story, led by a strong performance from Maika Monroe.', TO_DATE('2017-10-08', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the trip', 2011, 'Amiable, funny and sometimes insightful, The Trip works as both a showcase for the enduring chemistry between stars Steve Coogan and Rob Brydon and an unexpected perusal of men entering mid-life crises.', TO_DATE('2011-03-16', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the trip to greece', 2020, 'The Trip to Greece sees this series subject to the laws of diminishing returns, but Rob Brydon and Steve Coogan remain reliably enjoying company.', TO_DATE('2020-05-17', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the trip to italy', 2014, 'While perhaps not quite as fresh as Coogan and Brydon''s original voyage in The Trip, The Trip to Italy still proves a thoroughly agreeable sequel.', TO_DATE('2014-01-21', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the trip to spain', 2017, 'The Trip to Spain offers more of the same scenery, food, and conversation that filled Steve Coogan and Rob Brydon''s first two Trips -- which is to say, more of a good thing.', TO_DATE('2017-04-24', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the triplets of belleville', 2003, 'Richly detailed and loaded with surreal touches, The Triplets of Belleville is an odd, delightful charmer.', TO_DATE('2003-07-16', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the triumph of love', 2002, 'Not as charming as it could have been, Triumph of Love plays too broadly and amounts to little more than a trifle.', TO_DATE('2002-01-10', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the trust', 2016, 'The Trust may not be an all-time heist classic, but its solidly workmanlike plot -- and the chemistry between Nicolas Cage and Elijah Wood -- should satisfy genre enthusiasts.', TO_DATE('2016-03-14', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the turin horse', 2011, 'Uncompromisingly bold and hauntingly beautiful, Bela Tarr''s bleak parable tells a simple story with weighty conviction.', TO_DATE('2011-02-15', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the twilight saga breaking dawn part 1', 2011, 'Slow, joyless, and loaded with unintentionally humorous moments, Breaking Dawn Part 1 may satisfy the Twilight faithful, but it''s strictly for fans of the franchise.', TO_DATE('2011-11-11', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the twilight saga breaking dawn part 2', 2012, 'It''s the most entertaining Twilight, but that''s not enough to make Breaking Dawn Part 2 worth watching for filmgoers who don''t already count themselves among the franchise converts.', TO_DATE('2012-11-13', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the two faces of january', 2014, 'With striking visuals, complex characters, and Hitchcockian plot twists, The Two Faces of January offers a pleasantly pungent treat for fans of romantic thrillers.', TO_DATE('2014-02-11', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the two popes', 2019, 'Led by outstanding performances from its well-matched leads, The Two Popes draws absorbing drama from a pivotal moment in modern organized religion.', TO_DATE('2019-09-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the unforeseen', 2007, 'A calm documentary that doesn''t resort to shrill polemics, The Unforeseen also benefits from great interview subjects and jaw-dropping cinematography.', TO_DATE('2007-01-27', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the unknown girl la fille inconnue', 2016, 'The Unknown Girl isn''t quite up to the standards of the Dardenne brothers'' best work, but remains a well-acted effort that pays poignant -- albeit limited -- dividends.', TO_DATE('2016-05-18', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the unknown known', 2013, 'Viewers hoping to see Donald Rumsfeld admit making mistakes in public office (or hoping Errol Morris will force him to give straight answers) may find The Unknown Known frustrating -- but no less fascinating.', TO_DATE('2013-09-04', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the upside', 2017, 'Preachy, manipulative, and frustratingly clichéd, The Upside showcases Bryan Cranston and Kevin Hart''s chemistry without ever taking full advantage of it.', TO_DATE('2017-09-09', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the valet', 2006, 'Like much of director Francis Veber''s work, The Valet is a witty, madcap farce with memorably zany characters.', TO_DATE('2006-12-08', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the vanishing', 2018, 'Suspenseful atmosphere, an evocative setting, and a strong cast keep audiences invested throughout The Vanishing''s patient approach to unraveling its mystery.', TO_DATE('2018-12-29', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the vatican tapes', 2015, 'A loud, rote exorcism thriller that presents nothing new to an already overpopulated subgenre.', TO_DATE('2015-07-21', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the villainess aknyeo', 2017, 'The Villainess offers enough pure kinetic thrills to satisfy genre enthusiasts -- and carve out a bloody niche for itself in modern Korean action cinema.', TO_DATE('2017-05-22', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the virginity hit', 2010, 'A found footage farce without any trace of believability, The Virginity Hit is a painfully unfunny sex comedy that is even more amateurish than its hapless protagonist.', TO_DATE('2010-09-09', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the visit', 2015, 'The Visit provides horror fans with a satisfying blend of thrills and laughs -- and also signals a welcome return to form for writer-director M. Night Shyamalan.', TO_DATE('2015-02-06', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the voices', 2014, 'The Voices gives Ryan Reynolds an opportunity to deliver a highlight-reel performance -- and offers an off-kilter treat for fans of black comedies.', TO_DATE('2014-01-20', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the void', 2016, 'The Void offers a nostalgic rush for fans of low-budget 1980s horror -- and legitimate thrills for hardcore genre enthusiasts of all ages.', TO_DATE('2016-09-28', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the vow', 2012, 'Channing Tatum and Rachel McAdams do their best with what they''re given, but The Vow is too shallow and familiar to satisfy the discriminating date-night filmgoer.', TO_DATE('2012-02-03', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wailing goksung', 2016, 'The Wailing delivers an atmospheric, cleverly constructed mystery whose supernatural thrills more than justify its imposing length.', TO_DATE('2016-05-19', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the walk', 2015, 'The Walk attempts a tricky balancing act between thrilling visuals and fact-based drama -- and like its wire-walking protagonist, pulls it off with impressive élan.', TO_DATE('2015-09-26', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wall', 2017, 'The Wall makes the most of its limitations -- albeit perhaps not quite enough to stretch its tight-focused action into a consistently gripping feature-length thriller.', TO_DATE('2017-04-28', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the war of the worlds', 2000, 'Though it''s dated in spots, The War of the Worlds retains an unnerving power, updating H.G. Wells'' classic sci-fi tale to the Cold War era and featuring some of the best special effects of any 1950s film.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the war within', 2005, 'The War Within attempts to get into the mind of a terrorist, and the result is believable and unsettling.', TO_DATE('2005-09-09', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ward', 2010, 'Lacking the hallmarks of his best work, The Ward proves to be a disappointingly mundane swan song for director John Carpenter.', TO_DATE('2010-09-15', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the watch', 2012, 'The Watch uneasily mixes sci-fi elements with gross-out gags and strands its talented cast with a script that favors vulgarity over wit at nearly every turn.', TO_DATE('2012-07-25', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the water diviner', 2014, 'The Water Diviner finds Russell Crowe on somewhat uncertain footing as a director, but he''s rescued by a strong performance from himself in the leading role.', TO_DATE('2014-12-08', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wave bolgen', 2015, 'Well-acted and blessed with a refreshingly humanistic focus, The Wave is a disaster film that makes uncommonly smart use of disaster film clichés.', TO_DATE('2015-10-19', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wave', 2019, 'Much like its addled protagonist, The Wave struggles to stay on target, but Justin Long''s performance helps this pleasantly offbeat sci-fi fantasy find its way.', TO_DATE('2019-09-24', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the way back', 2010, 'It isn''t as emotionally involving as it should be, but this Peter Weir epic offers sweeping ambition and strong performances to go with its grand visual spectacle.', TO_DATE('2010-09-04', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the way back', 2020, 'The Way Back''s occasionally frustrating treatment of a formulaic story is often outweighed by Ben Affleck''s outstanding work in the central role.', TO_DATE('2020-03-04', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the way he looks', 2014, 'Compassionate, emotionally detailed, and populated with resonant characters, The Way He Looks leaves a warmth that lingers.', TO_DATE('2014-04-29', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the way way back', 2013, 'Despite its familiar themes, The Way Way Back makes use of its talented cast, finely tuned script, and an abundance of charm to deliver a funny and satisfying coming-of-age story.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the we and the i', 2012, 'Michel Gondry''s whimsical dramedy is occasionally unfocused, but it''s still an imaginative and poignant take on the emotional complexities of young people.', TO_DATE('2012-05-17', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the weather underground', 2003, 'Fascinating documentary about the militant Weathermen.', TO_DATE('2003-02-18', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wedding guest', 2018, 'The Wedding Guest makes a compelling argument for Dev Patel as an actor worthy of diverse leading roles, even if the movie''s less than the sum of its action thriller parts.', TO_DATE('2018-09-10', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wedding plan', 2016, 'The Wedding Plan is steeped in convention, but has a thoroughly charming star and enough fresh twists to set it pleasantly apart.', TO_DATE('2016-09-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wedding ringer', 2015, 'Kevin Hart and Josh Gad might be two great comedians that go great together, but there''s little evidence of it on display in The Wedding Ringer.', TO_DATE('2015-01-14', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the week of', 2018, 'The Week Of suggests promise in further collaborations between Sandler and Robert Smigel, but its shopworn premise and listless execution aren''t enough to recommend it.', TO_DATE('2018-04-26', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the weekend', 2018, 'Led by a potentially star-making performance from Sasheer Zamata, The Weekend takes a well-acted, smartly written approach to familiar character dynamics.', TO_DATE('2018-09-13', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the whistleblower', 2010, 'Rachel Weisz puts on a compelling smoldering act though the film suffers from a literal-minded approach to the material.', TO_DATE('2010-09-18', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the white crow', 2018, 'The White Crow lacks the nimble grace of its subject, but as a reasonably diverting primer on a pivotal period in the life of a brilliant artist, it just about sticks the landing.', TO_DATE('2018-09-06', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the whole truth', 2016, 'The Whole Truth, unfortunately, is that courtroom drama fans have already seen better examples of everything this lazy entry in the genre has to offer.', TO_DATE('2016-10-17', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wicker man', 2000, 'This intelligent horror film is subtle in its thrills and chills, with an ending that is both shocking and truly memorable.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wicker man', 2006, 'Puzzlingly misguided, Neil LaBute''s update The Wicker Man struggles against unintentional comedy and fails.', TO_DATE('2006-08-31', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wife', 2017, 'The Wife relies on the strength of Glenn Close''s performance to drive home the power of its story -- and she proves thoroughly, grippingly up to the task.', TO_DATE('2017-09-12', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wild', 2006, 'With a rehashed plot and unimpressive animation, there''s nothing wild about The Wild.', TO_DATE('2006-04-11', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wild life', 2016, 'The Wild Life uses its classic source material as a half-hearted springboard into a colorfully animated but essentially empty experience that only the youngest of viewers will find at all entertaining.', TO_DATE('2016-03-27', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the willoughbys', 2020, 'An appealing animated adventure whose silliness is anchored in genuine emotion, The Willoughbys offers fanciful fun the entire family can enjoy.', TO_DATE('2020-04-20', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wind', 2018, 'Imperfect yet intriguing, The Wind offers horror fans an admirably ambitious story further distinguished by its fresh perspective and effective scares.', TO_DATE('2018-09-12', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wind rises', 2013, 'The Wind Rises is a fittingly bittersweet swan song for director Hayao Miyazaki.', TO_DATE('2013-09-02', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wind will carry us', 2000, 'The Wind Will Carry Us slowly casts its transporting spell as writer-director Abbas Kiarostami explores ineffable themes with patience and grace.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the witch', 2015, 'As thought-provoking as it is visually compelling, The Witch delivers a deeply unsettling exercise in slow-building horror that suggests great things for debuting writer-director Robert Eggers.', TO_DATE('2015-01-23', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the witches', 1990, 'With a deliciously wicked performance from Angelica Huston and imaginative puppetry by Jim Henson''s creature shop, Nicolas Roeg''s dark and witty movie captures the spirit of Roald Dahl''s writing like few other adaptations.', TO_DATE('1990-02-16', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wizard of lies', 2017, 'The Wizard of Lies doesn''t really shed much new light on its fact-based story, but thanks to solid direction and a talented cast, it still proves consistently watchable.', TO_DATE('2017-04-25', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wizard of oz', 2000, 'An absolute masterpiece whose groundbreaking visuals and deft storytelling are still every bit as resonant, The Wizard of Oz is a must-see film for young and old.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wolf of wall street', 2013, 'Funny, self-referential, and irreverent to a fault, The Wolf of Wall Street finds Martin Scorsese and Leonardo DiCaprio at their most infectiously dynamic.', TO_DATE('2013-12-16', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wolfpack', 2015, 'Offering a unique look at modern fears and our fascination with film, The Wolfpack is a fascinating -- and ultimately haunting -- urban fable.', TO_DATE('2015-01-26', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wolfs call le chant du loup', 2019, 'The Wolf''s Call is a classic submarine action-thriller that will keep you at the edge of your seat.', TO_DATE('2019-03-12', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wolverine', 2013, 'Although its final act succumbs to the usual cartoonish antics, The Wolverine is one superhero movie that manages to stay true to the comics while keeping casual viewers entertained.', TO_DATE('2013-07-17', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the woman', 2011, 'Strange, audacious, and aggressive, The Woman is an uneven horror flick that game viewers with a wildly bloody finale.', TO_DATE('2011-02-03', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the woman in black', 2012, 'Traditional to a fault, The Woman in Black foregoes gore for chills -- although it may not provide enough of them for viewers attuned to more modern, high-stakes horror.', TO_DATE('2012-01-24', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the woman in black 2 angel of death', 2014, 'The Woman in Black 2: Angel of Death is atmospheric and visually sharp, but it''s short on tension and scares.', TO_DATE('2014-12-20', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the womens balcony ismach hatani', 2016, 'With rich characters and a thoughtful approach to timely themes, The Women''s Balcony tackles complicated subjects with intelligence, compassion, and wit.', TO_DATE('2016-10-10', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the words', 2012, 'Neither as clever nor as interesting as it appears to think it is, The Words maroons its talented stars in an overly complex, dramatically inert literary thriller that''s ultimately a poor substitute for a good book.', TO_DATE('2012-01-21', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the world before your feet', 2018, 'The World Before Your Feet offers a perspective on New York City that might be entrancingly unfamiliar even to residents -- and beckons viewers toward a more attentive way of life.', TO_DATE('2018-03-12', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the world of apu', 2000, 'Achingly poignant, beautifully shot, and evocatively atmospheric, The World of Apu closes out Satyajit Ray''s classic trilogy on a high note.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the worlds end', 2013, 'Madcap and heartfelt, Edgar Wright''s apocalypse comedy The World''s End benefits from the typically hilarious Simon Pegg and Nick Frost, with a plethora of supporting players.', TO_DATE('2013-07-08', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wrestler', 2008, 'Mickey Rourke gives a performance for the ages in The Wrestler, a richly affecting, heart-wrenching yet ultimately rewarding drama.', TO_DATE('2008-09-04', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wretched', 2019, 'The Wretched stirs up a savory blend of witch-in-the-woods horror ingredients that should leave genre fans hungry for a second helping from writer-directors Brett and Drew T. Pierce.', TO_DATE('2019-07-24', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wrong missy', 2020, 'Lauren Lapkus lifts The Wrong Missy above abject failure, but this lazy comedy will be the wrong option for all but the most Happy Madison-starved viewers.', TO_DATE('2020-05-13', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the year of the yao', 2004, 'This sports bio documentary is given a few fresh angles, including culture clash issues, and the friendship that develops between Yao and his interpreter.', TO_DATE('2004-11-06', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the yellow birds', 2017, 'The Yellow Birds has a strong cast and a worthy message, but they''re both lost in this war drama''s rote, clichéd story.', TO_DATE('2017-01-21', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the young girls of rochefort les demoiselles de rochefort', 2000, 'The Young Girls of Rochefort pays colorful homage to classic Hollywood musicals while earning its own emotionally affecting place of honor in the genre.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the young karl marx le jeune karl marx', 2017, 'The Young Karl Marx makes a valiant attempt to make the philosophical cinematic, but lacks sufficient depth to tackle its complex themes.', TO_DATE('2017-02-13', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the young unknown', 2002, 'A movie about uninteresting people doing uninteresting things.', TO_DATE('2002-08-28', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the zero theorem', 2013, 'Fans of director Terry Gilliam''s trademark visual aesthetic will find everything they''ve bargained for, but for the unconverted, The Zero Theorem may prove too muddled to enjoy.', TO_DATE('2013-09-02', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the zookeepers wife', 2017, 'The Zookeeper''s Wife has noble intentions, but is ultimately unable to bring its fact-based story to life with quite as much impact as it deserves.', TO_DATE('2017-03-20', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('theater of blood theatre of blood much ado about murder', 2000, 'Deliciously campy and wonderfully funny, Theater of Blood features Vincent Price at his melodramatic best.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('theeb', 2015, 'Led by an outstanding performance from Jacir Eid Al-Hwietat in the title role, Theeb is a startlingly assured first effort from director/co-writer Naji Abu Nowar.', TO_DATE('2015-02-18', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('their finest', 2016, 'Carried along by a winning performance from Gemma Arterton, Their Finest smoothly combines comedy and wartime drama to crowd-pleasing effect.', TO_DATE('2016-09-12', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thelma', 2017, 'Thelma plays with genre tropes in unexpected ways, delivering a thoughtfully twisty supernatural thriller with a lingering impact.', TO_DATE('2017-09-09', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thelma louise', 2000, 'Simultaneously funny, heartbreaking, and peppered with action, Ridley Scott''s Thelma & Louise is a potent, well-acted road movie that transcends the feminist message at its core.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('them', 2007, 'Suspenseful and tense from start to finish, the French horror film Them proves that a lack of gore doesn''t mean a dearth of scares.', TO_DATE('2007-01-26', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('them that follow', 2019, 'Them That Follow never quite captures the spiritual fervor of its setting, but the cast''s committed performances make for an intermittently satisfying character study.', TO_DATE('2019-01-28', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('then she found me', 2007, 'A threadbare story anchored by strong performances, Then She Found Me is a mostly successful directorial debut by Helen Hunt.', TO_DATE('2007-09-07', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('there will be blood', 2007, 'Widely touted as a masterpiece, this sparse and sprawling epic about the underhanded "heroes" of capitalism boasts incredible performances by leads Daniel Day-Lewis and Paul Dano, and is director Paul Thomas Anderson''s best work to date.', TO_DATE('2007-09-28', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('theres something about mary', 2000, 'There''s Something About Mary proves that unrelentingly, unabashedly peurile humor doesn''t necessarily come at the expense of a film''s heart.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('these final hours', 2014, 'Writer-director Zak Hilditch''s thought-provoking screenplay -- and a stellar performance from young Angourie Rice -- make These Final Hours worth watching, even if its end-of-the-world premise is overly familiar.', TO_DATE('2014-06-18', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('they came together', 2014, 'They Came Together is surprisingly messy and perhaps too smart for its own good, but Amy Poehler and Paul Rudd''s chemistry is enough to overcome many of the movie''s flaws.', TO_DATE('2014-01-26', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('they live', 2000, 'A politically subversive blend of horror and sci fi, They Live is an underrated genre film from John Carpenter.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('they remain', 2017, 'They Remain relies on rich atmosphere to effectively establish a sense of creeping dread that''s almost enough to cover for its nagging narrative deficiencies.', TO_DATE('2017-10-12', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('theyll love me when im dead', 2018, 'They''ll Love Me When I''m Dead opens an entertaining window into the creative process - and late-period professional travails - of a brilliant filmmaker.', TO_DATE('2018-09-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the thin man', 2000, 'Featuring an involving mystery and sparkling repartee between William Powell and Myrna Loy, The Thin Man is an endlessly charming romp.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the thing about my folks', 2005, 'The Thing About My Folks lacks cohesiveness, and the cloying tone makes the talkiness grating.', TO_DATE('2005-08-08', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the thing called love', 2000, 'The last film River Phoenix completed before his death, The Thing Called Love doesn''t have much new to say about show business, but it''s energetic and well acted.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('things to come', 2000, 'Eerily prescient in its presentation of a dystopian future, Things to Come''s special effects may be somewhat dated, but its potent ideas haven''t aged at all.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('things to come lavenir', 2016, 'A union to cherish between a writer-director and star working at peak power, Things to Come offers quietly profound observations on life, love, and the irrevocable passage of time.', TO_DATE('2016-02-14', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('things to do in denver when youre dead', 1995, 'Just watch a Tarantino movie instead -- and buy a Warren Zevon record while you''re at it.', TO_DATE('1995-12-01', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('things we lost in the fire', 2007, 'Things We Lost in the Fire is a well-acted, beautifully filmed reflection on love, loss, addiction and recovery from life''s obstacles.', TO_DATE('2007-10-04', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('think like a man', 2012, 'In Think Like a Man, an otherwise standard rom-com is partially elevated by a committed -- and attractive -- cast, resulting in a funny take on modern romance.', TO_DATE('2012-04-11', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('think like a man too', 2014, 'Think Like a Man Too reunites its predecessor''s talented cast, but fails to take their characters in new or interesting directions.', TO_DATE('2014-06-18', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('stephen kings thinner', 1996, 'A bland, weightless horror film that seems to want to mock itself as the proceedings drag on.', TO_DATE('1996-10-25', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('third person', 2013, 'Third Person finds writer-director Paul Haggis working with a stellar cast and a worthy premise; unfortunately, he fails to fashion a consistently compelling movie out of the intriguing ingredients at his disposal.', TO_DATE('2013-09-11', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thirteen', 2003, 'An emotionally wrenching, not to mention terrifying, film about the perils of being a teenager.', TO_DATE('2003-02-26', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thirteen conversations about one thing', 2002, 'Thirteen Conversations About One Thing is an intelligent and poignant look at lives intersecting.', TO_DATE('2002-01-04', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thirteen days', 2000, 'Thirteen Days offers a compelling look at the Cuban Missile Crisis, and its talented cast deftly portrays the real-life people who were involved.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thirteen ghosts 13 ghosts', 2001, 'The production design is first-rate, but 13 Ghosts is distinctly lacking in scares.', TO_DATE('2001-10-22', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thirty two short films about glenn gould', 1993, 'Befitting its singularly brilliant subject, Thirty Two Short Films About Glenn Gould captures the essence of a life and legacy while flouting biopic conventions.', TO_DATE('1993-09-14', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('this boys life', 1993, 'A harrowing, moving drama about a young boy, his single mother, and his abusive stepfather, This Boy''s Life benefits from its terrific cast, and features a breakout performance from a young Leonardo DiCaprio.', TO_DATE('1993-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('this christmas', 2007, 'This Christmas features strong performances and a sharp portrayal of family dynamics, but relies too heavily on holiday movie clichés.', TO_DATE('2007-10-26', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('this divided state', 2005, 'This Divided State takes a flawed yet engrossing ground-level look at how ideological differences can fuel discord -- and how quickly it can spread.', TO_DATE('2005-08-09', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('this is 40', 2012, 'Judd Apatow definitely delivers funny and perceptive scenes in This is 40, even if they are buried in aimless self-indulgence.', TO_DATE('2012-11-18', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('this is england', 2006, 'A moving coming-of-age tale that captures the despair among England''s working-class youth in the 1980s.', TO_DATE('2006-09-14', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('this is martin bonner', 2013, 'Solemn but heartfelt, This is Martin Bonner is a slow-burning drama with an outstanding performance by Paul Eenhoorn as the title character.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('this is not a film', 2011, 'Through simple means and filming, This is Not a Film presents a vital political statement and a snapshot of life in Iran as enemy of the state.', TO_DATE('2011-09-08', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('this is not berlin', 2019, 'This Is Not Berlin uses one young man''s sexual and cultural awakening as the fuel for a personal story with widely resonant themes.', TO_DATE('2019-01-26', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('this is spinal tap', 1984, 'Smartly directed, brilliantly acted, and packed with endlessly quotable moments, This Is Spinal Tap is an all-time comedy classic.', TO_DATE('1984-03-02', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('this is the end', 2013, 'Energetic, self-deprecating performances and enough guffaw-inducing humor make up for the flaws in This Is the End loosely written script.', TO_DATE('2013-05-31', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('one direction this is us', 2013, 'It''s mostly for the converted, but One Direction: This Is Us will be fun for fans -- and it offers just enough slickly edited concert footage to entertain the casual viewer.', TO_DATE('2013-08-20', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('this is where i leave you', 2014, 'This Is Where I Leave You has its moments, but given the amount of talent assembled onscreen, the rather pedestrian results can''t help but feel like a letdown.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('this means war', 2012, 'A career lowlight for all three of its likable stars, This Means War is loud, clumsily edited, and neither romantic nor funny.', TO_DATE('2012-01-30', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('this must be the place', 2011, 'This Must Be the Place may feature too many wayward detours to satisfy some passengers, but Sean Penn''s beguiling performance and Paolo Sorrentino''s scenic visuals make this a road trip worth following.', TO_DATE('2011-05-20', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('this sporting life', 2000, 'Appropriately hard-hitting on narrative as well as physical levels, The Sporting Life remains a British "kitchen sink" classic that''s beautiful to look at and leaves a lingering mark.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thomas and the magic railroad', 2000, 'Kids these days demand cutting edge special effects or at least a clever plot with cute charectors. This movie has neither, having lost in its Americanization what the British original did so right.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the thomas crown affair', 2000, 'Steve McQueen settles into the role with ease and aplomb, in a film that whisks viewers to an exotic world with style and sex appeal.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the thomas crown affair', 2000, 'Sleek, stylish, and painlessly diverting, The Thomas Crown Affair is a remake of uncommon charm.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thor', 2011, 'A dazzling blockbuster that tempers its sweeping scope with wit, humor, and human drama, Thor is mighty Marvel entertainment.', TO_DATE('2011-04-17', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thor ragnarok', 2017, 'Exciting, funny, and above all fun, Thor: Ragnarok is a colorful cosmic adventure that sets a new standard for its franchise -- and the rest of the Marvel Cinematic Universe.', TO_DATE('2017-10-19', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thor the dark world', 2013, 'It may not be the finest film to come from the Marvel Universe, but Thor: The Dark World still offers plenty of the humor and high-stakes action that fans have come to expect.', TO_DATE('2013-10-22', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thoroughbreds', 2017, 'Thoroughbreds juggles genres with panache, delivering a well-written and refreshingly unpredictable entry in the teen thriller genre.', TO_DATE('2017-01-22', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('three billboards outside ebbing missouri', 2017, 'Three Billboards Outside Ebbing, Missouri deftly balances black comedy against searing drama -- and draws unforgettable performances from its veteran cast along the way.', TO_DATE('2017-09-04', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the three burials of melquiades estrada', 2005, 'Tommy Lee Jones'' directorial debut is both a potent western and a powerful morality tale.', TO_DATE('2005-05-20', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('three christs', 2017, 'Three Christs is far from an unholy mess, but this fact-based drama forsakes its talented cast with a disappointingly facile treatment of genuinely interesting themes.', TO_DATE('2017-09-13', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('three colors blue trois couleurs bleu', 2000, 'Three Colors: Blue contains some of director/co-writer Krzysztof Kieslowski''s most visually arresting, emotionally resonant work -- and boasts an outstanding performance from Juliette Binoche in the bargain.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('three colors white trois couleurs blanc', 1994, 'Taking a lighter tone than the other films of the Three Colors trilogy, White is a witty, bittersweet comedy with heavier themes on its mind than one might at first realize.', TO_DATE('1994-02-18', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('three days of the condor', 2000, 'This post-Watergate thriller captures the paranoid tenor of the times, thanks to Syndey Pollack''s taut direction and excellent performances from Robert Redford and Faye Dunaway.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('three identical strangers', 2018, 'Surreal and surprising, Three Identical Strangers effectively questions the nature of reality and identity.', TO_DATE('2018-01-20', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('three kings', 2000, 'Three Kings successfully blends elements of action, drama, and comedy into a thoughtful, exciting movie on the Gulf War.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('three men and a baby 3 men and a baby', 2000, 'The American remake of the popular French comedy mostly works a charm under the combined talents of the three leads, who play nicely against type -- although forced plot elements and sentimentality at times dampen the fun.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('three times zui hao de shi guang', 2005, 'Slowly paced, understated, and exquisitely shot, these are three lovely odes to love and longing.', TO_DATE('2005-05-30', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('three to tango', 2000, 'A mediocre episode of Friends has more humor and less offensive gay jokes.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('threeextremes saam gaang yi', 2005, 'This anthology contains brutal, powerful horror stories by three of Asia''s top directors.', TO_DATE('2005-02-17', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('threesome', 1994, 'Threesome''s titillating title belies a dreadfully dull drama whose attractive stars are handily outmatched by a shallow script.', TO_DATE('1994-04-08', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thriller', 2019, 'Thriller has an appealing cast and a fresh perspective on its genre, but those elements aren''t enough to outweigh a bland and predictable story.', TO_DATE('2019-04-12', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('throne of blood', 2000, 'A career high point for Akira Kurosawa -- and one of the best film adaptations of a Shakespeare play.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('throw momma from the train', 2000, 'Danny DeVito''s direction is too broad to offer the kind of nastiness that would have made Throw Momma from the Train truly special, but DeVito''s on-screen chemistry with co-star Billy Crystal makes this a smoothly entertaining comedy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thumbsucker', 2005, 'Though quirky coming-of-age themes are common in indie films, this one boasts a smart script and a great cast.', TO_DATE('2005-01-29', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thunder and the house of magic', 2014, 'Thunder and the House of Magic lacks real narrative depth, but its visual splendor offers sufficient compensation for younger viewers.', TO_DATE('2014-06-27', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thunder road', 2018, 'Thunder Road deftly balances emotionally affecting drama against bruising comedy - and serves as an outstanding calling card for writer-director-star Jim Cummings.', TO_DATE('2018-03-14', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thunderball', 1965, 'Lavishly rendered set pieces and Sean Connery''s enduring charm make Thunderball a big, fun adventure, even if it doesn''t quite measure up to the series'' previous heights.', TO_DATE('1965-12-20', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thunderbirds', 2004, 'Live-action cartoon for kids.', TO_DATE('2004-01-06', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thunderbolt and lightfoot', 2000, 'This likable buddy/road picture deftly mixes action and comedy, and features excellent work from stars Clint Eastwood and Jeff Bridges and first-time director Michael Cimino.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('thx 1138', 2000, 'George Lucas'' feature debut presents a spare, bleak, dystopian future, and features evocatively minimal set design and creepy sound effects.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tideland', 2005, 'Tideland is a disturbing, and mostly unwatchable effort from Terry Gilliam.', TO_DATE('2005-09-14', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('átame tie me up tie me down', 1990, 'Tie Me Up! Tie Me Down! undermines its own effectiveness with an excess of camp, but writer-director Pedro Almodóvar and an attractive cast make it all worth watching.', TO_DATE('1990-01-22', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('la tigre e la neve the tiger and the snow', 2005, 'The Tiger and the Snow proves Roberto Benigni''s antics are bizarrely ill-suited for a film seeking to strike the unwieldy balance between romance, comedy, and wartime drama.', TO_DATE('2005-12-06', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tigerland', 2000, 'A great cast and the gritty feel of the film help elevate Tigerland above the familiarity of the subject matter.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tigertail', 2020, 'Uneven yet revealing, Tigertail offers a well-acted -- and ultimately valuable -- look at the immigrant experience in America.', TO_DATE('2020-04-10', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('till human voices wake us', 2002, 'What is meant to be dreamy and romantic instead comes off as sluggish and dull.', TO_DATE('2002-09-04', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tim and erics billion dollar movie', 2012, 'Tim & Eric''s Billion Dollar Movie is on a gleeful quest to repulse audiences, but sometimes less is more with this sketchy duo.', TO_DATE('2012-01-21', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('timbuktu', 2014, 'Gracefully assembled and ultimately disquieting, Timbuktu is a timely film with a powerful message.', TO_DATE('2014-05-15', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('time after time', 2000, 'With the three principal actors clearly having fun with their roles, Time After Time becomes an amusing, light-hearted fantasy lark.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('time bandits', 1981, 'Time Bandits is a remarkable time-travel fantasy from Terry Gilliam, who utilizes fantastic set design and homemade special effects to create a vivid, original universe.', TO_DATE('1981-11-06', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('los cronocrímenes timecrimes', 2008, 'Timecrimes is a low-budget thriller that''s well-crafted and loaded with dark humor and bizarre twists.', TO_DATE('2008-01-30', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('time of the wolf', 2003, 'A lean and unsettlingly thriller.', TO_DATE('2003-05-22', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('time out of mind', 2014, 'Time Out of Mind demands patience, yet its noble intentions -- and Richard Gere''s committed performance -- are difficult to deny.', TO_DATE('2014-09-08', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('time regained', 2000, 'Time Regained''s unorthodox approach to adapting its classic source material is flawed, but the end result remains a curiously compelling drama.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('time share tiempo compartido', 2018, 'Sharp, funny, and delightfully dark, Time Share (Tiempo Compartido) offers genre fans a complex thriller that sinks its hooks in fast and doesn''t let go until the closing credits.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the time travelers wife', 2009, 'Though it may satisfy fans of the novel, The Time Traveler''s Wife''s plot contrivances and illogical narrative hamper its big screen effectiveness.', TO_DATE('2009-08-10', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('timecode', 2000, 'Not much of a story, but the execution is interesting.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('timecop', 2000, 'It''s no Terminator, but for those willing to suspend disbelief and rational thought, Timecop provides limited sci-fi action rewards.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('timeline', 2003, 'This incoherently plotted addition to the time-travel genre looks and sounds cheesy.', TO_DATE('2003-08-12', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tims vermeer', 2013, 'Entertaining and profound in equal measure, Tim''s Vermeer uses its seemingly esoteric subject to pose fascinating questions about art and obsession.', TO_DATE('2013-09-06', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tin cup', 2000, 'Breezy and predictable, Tin Cup is a likeable sports comedy that benefits greatly from Kevin Costner''s amiable lead performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tinker tailor soldier spy', 2011, 'Tinker Tailor Soldier Spy is a dense puzzle of anxiety, paranoia, and espionage that director Tomas Alfredson pieces together with utmost skill.', TO_DATE('2011-09-05', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tiny furniture', 2010, 'Agonizingly funny, Tiny Furniture marks an observant study of a failure to launch and an auspicious debut for writer-director Lena Dunham.', TO_DATE('2010-11-07', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('titan ae', 2000, 'Great visuals, but the story feels like a cut-and-paste job of other sci-fi movies.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('titanic', 1997, 'A mostly unqualified triumph for James Cameron, who offers a dizzying blend of spectacular visuals and old-fashioned melodrama.', TO_DATE('1997-12-19', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tmnt', 2007, 'TMNT''s art direction is splendid, but the plot is non-existent and the dialogue lacks the irony and goofy wit of the earlier Ninja Turtles movies.', TO_DATE('2007-03-18', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('to all the boys ive loved before', 2018, 'To All the Boys I''ve Loved Before plays by the teen rom-com rules, but relatable characters and a thoroughly charming cast more than make up for a lack of surprises.', TO_DATE('2018-08-15', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('to all the boys ps i still love you', 2020, 'To All the Boys: P.S. I Still Love You may feel like little more than an amiable postscript to its predecessor, but fans of the original should still find this a swoonworthy sequel.', TO_DATE('2020-02-10', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('to be takei', 2014, 'To Be Takei rests almost entirely on its subject''s inherent likability -- and, for the most part, that''s more than enough.', TO_DATE('2014-01-19', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('to catch a thief', 1800, 'It may occasionally be guilty of coasting on pure charm, but To Catch a Thief has it in spades -- as well as a pair of perfectly matched stars in Cary Grant and Grace Kelly.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('to have and have not', 2000, 'With Howard Hawks directing and Bogey and Bacall in front of the cameras, To Have and Have Not benefits from several levels of fine-tuned chemistry -- all of which ignite on screen.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('to kill a mockingbird', 2000, 'To Kill a Mockingbird is a textbook example of a message movie done right -- sober-minded and earnest, but never letting its social conscience get in the way of gripping drama.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('to rome with love', 2012, 'To Rome With Love sees Woody Allen cobbling together an Italian postcard of farce, fantasy, and comedy with only middling success.', TO_DATE('2012-06-15', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('to sir with love', 2000, 'While it''s a bit dated and overly schmaltzy, To Sir, With Love remains compelling because of Sidney Poitier''s outstanding performance -- and the catchy theme song is a classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('to sleep with anger', 1990, 'To Sleep with Anger examines cultural tensions with a deft hand and a potent blend of comedy and drama, stirred skillfully to life by a strong cast led by Danny Glover.', TO_DATE('1990-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('to the bone', 2017, 'To the Bone offers an insightful, empathetic look at a widespread issue, led by exemplary work from Lily Collins in the central role.', TO_DATE('2017-01-22', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('to the stars', 2019, 'Its reach may occasionally exceed its grasp, but To the Stars uses its period setting as an effective backdrop for an insightful look at female friendship.', TO_DATE('2019-01-26', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('to the wonder', 2012, 'To the Wonder demonstrates Terrence Malick''s gift for beautiful images, but its narrative is overly somber and emotionally unsatisfying.', TO_DATE('2012-09-03', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('to wong foo thanks for everything julie newmar', 1995, 'To Wong Foo, Thanks for Everything! Julie Newmar seeks to celebrate individuality, but is too timid and predictable to achieve its admittedly noble aims.', TO_DATE('1995-09-08', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('together', 2001, 'Managing to be both satirical and warm-hearted in its look at the inhabitants of a commune, Together successfully captures the spirit of a time.', TO_DATE('2001-06-27', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('rage', 2014, 'Depressingly dull and all-around poorly made, Rage is the rare Nicolas Cage action thriller lacking enough energy to reach "so bad it''s good" territory.', TO_DATE('2014-06-10', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tokyo godfathers', 2004, 'Beautiful and substantive, Tokyo Godfathers adds a moving -- and somewhat unconventional -- entry to the animated Christmas canon.', TO_DATE('2004-01-13', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tokyo sonata tokyo sonata', 2008, 'J-Horror director Kiyoshi Kurosawa turns successfully to dramedy and gives a unique (and specifically national) perspective to the universal subjects of family and identity.', TO_DATE('2008-08-20', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tokyo story tôkyô monogatari', 1953, 'Tokyo Story is a Yasujiro Ozu masterpiece whose rewarding complexity has lost none of its power more than half a century on.', TO_DATE('1953-11-03', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tokyo tribe', 2014, 'Tokyo Tribe''s wild mishmash of tones and genres isn''t always as much fun as it ought to be, but it''ll hit the spot for filmgoers in search of something different.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tolkien', 2019, 'Tolkien has the period trappings and strong performances of a worthy biopic, but lacks the imagination required to truly do its subject justice.', TO_DATE('2019-04-29', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tom jones', 2000, 'A frantic, irreverent adaptation of the novel, bolstered by Albert Finney''s courageous performance and arresting visuals.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tom of finland', 2017, 'Tom of Finland honors its subject with an empathetic, even-handed, and above all entertaining look at the pioneering art he produced from private turmoil.', TO_DATE('2017-02-12', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tomb raider', 2018, 'Tomb Raider reboots the franchise with a more grounded approach and a star who''s clearly more than up to the task -- neither of which are well served by an uninspired origin story.', TO_DATE('2018-03-08', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tomboy', 2011, 'In tune with the emotion and tribulations of childhood, Tomboy is a charming movie that treats its main subject with warmth and heart.', TO_DATE('2011-06-17', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tomcats', 2001, 'Why even bother? You already know if you''re going to see it or not.', TO_DATE('2001-03-20', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tommaso', 2019, 'While admittedly a self-indulgent exercise, Tommaso is powerfully anchored by an outstanding central performance from Willem Dafoe.', TO_DATE('2019-05-21', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tommy boy', 1995, 'Though it benefits from the comic charms of its two leads, Tommy Boy too often feels like a familiar sketch stretched thin.', TO_DATE('1995-03-31', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tomorrow never dies', 1997, 'A competent, if sometimes by-the-numbers entry to the 007 franchise, Tomorrow Never Dies may not boast the most original plot but its action sequences are genuinely thrilling.', TO_DATE('1997-12-19', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tomorrowland', 2015, 'Ambitious and visually stunning, Tomorrowland is unfortunately weighted down by uneven storytelling.', TO_DATE('2015-05-17', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tonedeaf', 2019, 'A messy horror-comedy hybrid that makes poor use of a talented cast, Tone-Deaf aims for social commentary, but tumbles down the generation gap.', TO_DATE('2019-03-13', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('toni erdmann', 2016, 'Toni Erdmann pairs carefully constructed, three-dimensional characters in a tenderly funny character study that''s both genuinely moving and impressively ambitious.', TO_DATE('2016-05-14', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('too big to fail', 2012, 'Too Big to Fail has too sharp a script and superlative a cast to ever feel disposable, even when it teeters toward being an efficient explainer of recent history instead of a fully-realized drama.', TO_DATE('2012-06-21', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tootsie', 2000, 'Tootsie doesn''t squander its high-concept comedy premise with fine dialogue and sympathetic treatment of the characters.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('top end wedding', 2019, 'Familiar in form but winsome in its execution, Top End Wedding takes audiences on a romantic road trip with an appealing view.', TO_DATE('2019-01-31', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('top five', 2014, 'As smart, funny, and trenchant as writer-director-star Chris Rock''s best standup work, Top Five is a career highlight for its creator -- and one of the comedy standouts of 2014.', TO_DATE('2014-09-09', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('top gun', 2000, 'Though it features some of the most memorable and electrifying aereial footage shot with an expert eye for action, Top Gun offers too little for non-adolescent viewers to chew on when its characters aren''t in the air.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('top hat', 2000, 'A glamorous and enthralling Depression-era diversion, Top Hat is nearly flawless, with acrobatics by Fred Astaire and Ginger Rogers that make the hardest physical stunts seem light as air.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tora tora tora', 2000, 'Tora! Tora! Tora! is scrupulously accurate and lays out of the tragedy of Pearl Harbor with intricate detail, but the film''s clinical approach to the sound and fury signifies little feeling.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tortilla soup', 2001, 'An English remake of Ang Lee''s Eat Drink Man Woman, Tortilla Soup is as charming and flavorful as the dishes it features.', TO_DATE('2001-06-11', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('total recall', 2000, 'Under Paul Verhoeven''s frenetic direction, Total Recall is a fast-paced rush of violence, gore, and humor that never slacks.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('total recall', 2012, 'While it boasts some impressive action sequences, Total Recall lacks the intricate plotting, wry humor, and fleshed out characters that made the original a sci-fi classic.', TO_DATE('2012-08-01', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('touch the sound', 2004, 'Not only does this documentary introduce viewers to Glennie, it gives them a taste of how she perceives the world.', TO_DATE('2004-11-03', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a touch of zen', 2003, 'A brilliantly directed feast for the eyes with an epic story to match, A Touch of Zen marks a groundbreaking achievement in the wuxia genre.', TO_DATE('2003-05-24', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('touching the void', 2003, 'Gripping even though the outcome is known.', TO_DATE('2003-10-22', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('touchy feely', 2013, 'Well-acted but overly quirky, Touchy Feely is a tonally uneven dramedy with some interesting ideas but a lack of follow-through.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the tourist', 2010, 'The scenery and the stars are undeniably beautiful, but they can''t make up for The Tourist''s slow, muddled plot, or the lack of chemistry between Johnny Depp and Angelina Jolie.', TO_DATE('2010-12-08', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('towelhead', 2007, 'This story of politics, race and, sexual awakening has moments that pack a punch, but overall, Towelhead never quite achieves the nuance of helmer Alan Ball''s television work.', TO_DATE('2007-09-13', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tower', 2016, 'Tower probes into a painful chapter of American history with sensitivity and grace -- and revisits its events from a valuable new perspective.', TO_DATE('2016-03-23', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tower heist', 2011, 'Tower Heist is a true Brett Ratner joint: little brains to this caper, but it''s fun fluff, exciting to watch, and showcases a welcome return to form for Eddie Murphy.', TO_DATE('2011-10-28', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the towering inferno', 2000, 'Although it is not consistently engaging enough to fully justify its towering runtime, The Towering Inferno is a blustery spectacle that executes its disaster premise with flair.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('town country', 2000, 'Afflicted with extensive re-editing and re-writing, this sex comedy feels confusingly choppy. Also, the main characters are so wealthy and privileged that it''s difficult to feel sympathy for their problems.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the toxic avenger', 2000, 'A silly and ribald superhero spoof, Toxic Avenger uninhibited humor hits more than it misses.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('toy story', 1995, 'Entertaining as it is innovative, Toy Story reinvigorated animation while heralding the arrival of Pixar as a family-friendly force to be reckoned with.', TO_DATE('1995-11-22', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('toy story 2', 1999, 'The rare sequel that arguably improves on its predecessor, Toy Story 2 uses inventive storytelling, gorgeous animation, and a talented cast to deliver another rich moviegoing experience for all ages.', TO_DATE('1999-11-24', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('toy story 3', 2010, 'Deftly blending comedy, adventure, and honest emotion, Toy Story 3 is a rare second sequel that really works.', TO_DATE('2010-06-08', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('toy story 4', 2019, 'Heartwarming, funny, and beautifully animated, Toy Story 4 manages the unlikely feat of extending -- and perhaps concluding -- a practically perfect animated saga.', TO_DATE('2019-06-13', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('toys', 1992, 'Like a colorfully overengineered gewgaw on the shelf, Toys might look like fun, but its seemingly limitless possibilities lead mainly to confusion and disappointment.', TO_DATE('1992-12-18', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trading places', 2001, 'Featuring deft interplay between Eddie Murphy and Dan Aykroyd, Trading Places is an immensely appealing social satire.', TO_DATE('2001-06-13', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('traffik', 2018, 'Traffik highlights Paula Patton''s impressive dramatic chops -- and smothers them in a thoroughly underwhelming exploitation thriller.', TO_DATE('2018-04-20', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trailer park boys the movie', 2006, 'Trailer Park Boys suffers from its small-screen origins, and its tasteless humor is not for everyone, but it will satisfy fans of the genre.', TO_DATE('2006-10-06', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('train to busan busanhaeng', 2016, 'Train to Busan delivers a thrillingly unique -- and purely entertaining -- take on the zombie genre, with fully realized characters and plenty of social commentary to underscore the bursts of skillfully staged action.', TO_DATE('2016-05-15', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('training day', 2001, 'The ending may be less than satisfying, but Denzel Washington reminds us why he''s such a great actor in this taut and brutal police drama.', TO_DATE('2001-07-31', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trainspotting', 2000, 'A brutal, often times funny, other times terrifying portrayal of drug addiction in Edinburgh. Not for the faint of heart, but well worth viewing as a realistic and entertaining reminder of the horrors of drug use.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trainwreck', 2015, 'Trainwreck drags commitment out of all but the most rom-com-phobic filmgoers with sharp humor, relatable characters, and hilarious work from Amy Schumer.', TO_DATE('2015-03-16', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('traitor', 2008, 'Despite another reliable performance from Don Cheadle, Traitor suffers from too many cliches and an unfocused narrative.', TO_DATE('2008-08-18', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tramps', 2016, 'Sweet, breezy, and unexpected, Tramps traipses through its romcom premise with earnestness and ease.', TO_DATE('2016-09-11', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trance', 2013, 'As stylish as ever, director Danny Boyle seems to be treading water with the surprisingly thinly written Trance -- but for fans of Boyle''s work, it should still prove a trippily entertaining distraction.', TO_DATE('2013-03-12', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('transamerica', 2005, 'A terrific performance by Felicity Huffman carries this unconventional but touching transgender road movie.', TO_DATE('2005-07-06', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('transcendence', 2014, 'In his directorial debut, ace cinematographer Wally Pfister remains a distinctive visual stylist, but Transcendence''s thought-provoking themes exceed the movie''s narrative grasp.', TO_DATE('2014-04-15', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('transformers age of extinction', 2014, 'With the fourth installment in Michael Bay''s blockbuster Transformers franchise, nothing is in disguise: Fans of loud, effects-driven action will find satisfaction, and all others need not apply.', TO_DATE('2014-06-22', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('transformers dark of the moon', 2011, 'Its special effects -- and 3D shots -- are undeniably impressive, but they aren''t enough to fill up its loud, bloated running time, or mask its thin, indifferent script.', TO_DATE('2011-06-26', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('transformers revenge of the fallen', 2009, 'Transformers: Revenge of the Fallen is a noisy, underplotted, and overlong special effects extravaganza that lacks a human touch.', TO_DATE('2009-06-15', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('transformers the last knight', 2017, 'Cacophonous, thinly plotted, and boasting state-of-the-art special effects, The Last Knight is pretty much what you''d expect from the fifth installment of the Transformers franchise.', TO_DATE('2017-06-20', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('transformers', 2007, 'While believable characters are hard to come by in Transformers, the effects are staggering and the action is exhilarating.', TO_DATE('2007-06-21', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the transformers the movie', 2002, 'A surprisingly dark, emotional, and almost excessively cynical experience for Transformers fans.', TO_DATE('2002-07-26', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('transit', 2018, 'Transit lives up to its title with a challenging drama that captures characters - and puts the audience - in a state of flux and exerts an unsettling pull.', TO_DATE('2018-02-19', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the transporter', 2002, 'The Transporter delivers the action at the expense of coherent storytelling.', TO_DATE('2002-09-10', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('transporter 2', 2005, 'A stylish and more focused sequel to The Transporter, the movie is over-the-top fun for fans of the first movie.', TO_DATE('2005-08-30', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('transporter 3', 2008, 'This middling installment in the Transporter franchise is a few steps down from its predecessors, featuring generic stunts and a lack of energy.', TO_DATE('2008-11-18', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('transsiberian', 2008, 'Traditional in form yet effective in execution, this taut thriller updates the "danger on a train" scenario with atmospheric sense.', TO_DATE('2008-01-20', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('transylmania', 2009, 'Never aiming higher than threadbare jokes and offensive attempts at politically incorrect humor, Transylmania is a vampire comedy that truly sucks.', TO_DATE('2009-12-04', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trapped in paradise', 2000, 'Loaded with talent but borderline unwatchable, Trapped in Paradise will leave viewers feeling the first part of the title and pining for the last.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trash humpers', 2009, 'It''s oddly affecting in a deeply discomfiting way, but Trash Humpers pales in comparison with Harmony Korine''s earlier, truly transgressive work.', TO_DATE('2009-11-18', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trash', 2014, 'Action-packed, funny, and thought-provoking, Trash finds feel-good cinema in real-life squalor without resorting to cheap sentimentality.', TO_DATE('2014-10-08', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('travelers and magicians', 2005, 'Interwined tales of spiritual discovery are set against a gorgeous, evocative landscape in this pleasant, engaging import.', TO_DATE('2005-01-04', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the treasure of the sierra madre', 2000, 'Remade but never duplicated, this darkly humorous morality tale represents John Huston at his finest.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('treasure planet', 2002, 'Though its characterizations are weaker than usual, Treasure Planet offers a fast-paced, beautifully rendered vision of outer space.', TO_DATE('2002-11-10', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the treatment', 2006, 'A comedy for grown-ups, The Treatment overcomes some technical lapses by virtue of a sharp cast.', TO_DATE('2006-04-28', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('treeless mountain', 2008, 'Intermittently wondrous and harsh, this sensitive drama about two abandoned sisters gives time and space to the intimate and beautiful moments of childhood.', TO_DATE('2008-09-08', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trembling before gd', 2001, 'Trembling Before G-d looks at the effects of religious morality on believers whose sexuality falls outside the accepted norm with intelligence and compassion.', TO_DATE('2001-09-04', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tremors', 2000, 'An affectionate throwback to 1950s creature features, Tremors reinvigorates its genre tropes with a finely balanced combination of horror and humor.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trespass', 2000, 'Trespass pits public servants against gangsters in a race for stolen loot -- and thanks to a killer cast and Walter Hill''s assured direction, the audience wins.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trespass', 2011, 'Another claustrophobic thriller that Joel Schumacher can churn out in his sleep, Trespass is nasty and aggressive, more unpleasant than entertaining.', TO_DATE('2011-09-13', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trespass against us', 2016, 'Trespass Against Us benefits from Michael Fassbender and Brendan Gleeson''s typically strong performances, even when they aren''t quite enough to balance the story''s narrative drift and awkward tonal shifts.', TO_DATE('2016-09-11', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trial by fire', 2018, 'Trial by Fire has a worthy -- and heartbreaking -- story to tell, but this well-acted dramatization is undermined by its aggressively manipulative approach.', TO_DATE('2018-09-04', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the trials of henry kissinger', 2002, 'This compelling unauthorized biography takes a muckraker''s view of the controversial diplomat.', TO_DATE('2002-09-17', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trickfilme', 2000, 'By portraying its love story as nothing less than conventional, Trick avoids genre tropes to create a simple, effective romance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trick r treat', 2008, 'A deftly crafted tribute to Halloween legends, Trick ''r'' Treat hits all the genre marks with gusto and old fashioned suspense.', TO_DATE('2008-10-12', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the trigger effect', 1996, 'The Trigger Effect offers a captivating tale of paranoia and societal collapse, even if it runs out of thrills early on.', TO_DATE('1996-08-30', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('triple 9', 2016, 'Triple 9''s pulpy potboiler thrills don''t quite live up to the ferocious talents of its cast, but the film''s efficient, solidly crafted genre fun is often enough to balance its troublesome flaws.', TO_DATE('2016-02-15', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('triple frontier', 2019, 'An outstanding cast and ambitious story help Triple Frontier overcome an uneven narrative -- and elevate the end result above a crowded field of grim and gritty heist thrillers.', TO_DATE('2019-03-06', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('triple threat', 2019, 'Triple Threat might have made better use of its attention-getting cast, but action fans should still find the end results entertaining enough to rate a rental.', TO_DATE('2019-03-15', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tristram shandy a cock bull story', 2005, 'Steve Coogan and Rob Brydon add madcap, knowing performances to the mix, and the result is a fun, postmodern romp.', TO_DATE('2005-09-15', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('triumph des willens triumph of the will', 2000, 'Triumph of the Will is impossible to separate from its repugnant political context -- and impossible to deny as a powerfully made piece of cinematic propaganda.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('troll 2', 2002, 'Oh my God.', TO_DATE('2002-07-29', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trollhunter', 2011, 'Trollhunter is a mockumentary with an appropriate level of creeping dread, but one that also benefits from generous helpings of dry wit.', TO_DATE('2011-01-20', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trolls', 2016, 'Trolls brings its instantly recognizable characters to the big screen in a colorful adventure that, while geared toward the younger set, isn''t without rewards for parents.', TO_DATE('2016-10-08', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trolls world tour', 2020, 'A fun follow-up for fans of the original, Trolls World Tour offers a second helping of colorful animation, infectious energy, and sing-along songs.', TO_DATE('2020-03-13', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tron', 2000, 'Though perhaps not as strong dramatically as it is technologically, TRON is an original and visually stunning piece of science fiction that represents a landmark work in the history of computer animation.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tropic thunder', 2007, 'With biting satire, plenty of subversive humor, and an unforgettable turn by Robert Downey, Jr., Tropic Thunder is a triumphant late Summer comedy.', TO_DATE('2007-12-28', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trouble every day gargoyle', 2001, 'An erotic thriller dulled by a messy narrative.', TO_DATE('2001-09-11', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trouble the water', 2008, 'This incredible documentary displays the tragedy and mismanagement of Katrina along with the heroism of strangers and survivors.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trouble with the curve', 2012, 'Though predictable and somewhat dramatically underwhelming, Trouble with the Curve benefits from Clint Eastwood''s grizzled charisma and his easy chemistry with a charming Amy Adams.', TO_DATE('2012-09-16', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('troy', 2003, 'A brawny, entertaining spectacle, but lacking emotional resonance.', TO_DATE('2003-12-02', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trucker', 2008, 'Excellent performances by Michelle Monaghan and Nathan Fillion and keenly-observed details of small town life elevate this otherwise predictable and inconsistent melodrama.', TO_DATE('2008-05-14', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trudell', 2006, 'John Trudell has led a fascinating life -- unfortunately, Trudell the documentary largely fails to translate it into a compelling viewing experience.', TO_DATE('2006-01-27', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('true believer', 2000, 'A compelling mystery, social themes, and powerful performances from a pair of well-matched leads make True Believer a legal thriller that definitely passes the bar.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('true grit', 2001, 'True Grit rides along on the strength of a lived-in late-period John Wayne performance, adding its own entertaining spin to the oft-adapted source material.', TO_DATE('2001-02-27', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('true grit', 2010, 'Girded by strong performances from Jeff Bridges, Matt Damon, and newcomer Hailee Steinfeld, and lifted by some of the Coens'' most finely tuned, unaffected work, True Grit is a worthy companion to the Charles Portis book.', TO_DATE('2010-12-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('true history of the kelly gang', 2019, 'Its unusual approach won''t be for all viewers, but True History of the Kelly Gang takes a distinctively postmodern look at Australia''s past.', TO_DATE('2019-09-06', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('true romance', 2000, 'Fueled by Quentin Tarantino''s savvy screenplay and a gallery of oddball performances, Tony Scott''s True Romance is a funny and violent action jaunt in the best sense.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('true stories', 2000, 'Its kitschy leanings may wear thin on some, but True Stories is a disarmingly big-hearted, dreamy vision of Americana.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('true story', 2015, 'James Franco and Jonah Hill make a watchable pair, but True Story loses their performances -- and the viewer''s interest -- in a muddled movie that bungles its fact-based tale.', TO_DATE('2015-01-24', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the truman show', 2000, 'A funny, tender, and thought-provoking film, The Truman Show is all the more noteworthy for its remarkably prescient vision of runaway celebrity culture and a nation with an insatiable thirst for the private details of ordinary lives.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trumbo', 2015, 'Trumbo serves as an honorable and well-acted tribute to a brilliant writer''s principled stand, even if it doesn''t quite achieve the greatness of its subject''s own classic screenplays.', TO_DATE('2015-09-13', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the trumpet of the swan', 2000, 'An uninspired E.B. White adaptation that''s targeted at the very young.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trust', 2010, 'Director David Schwimmer gets some gut-wrenching performances out of his actors but he still lacks the chops to fully ratchet up story tension.', TO_DATE('2010-09-15', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('trust the man', 2005, 'What aspires to be a sophisticated, unconventional romantic comedy turns out to be a contrivance-filled pretender to other, better films of its genre.', TO_DATE('2005-09-16', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('truth', 2015, 'Truth''s terrific cast and compelling message are often enough to overcome its occasionally didactic and facile dramatization of a nuanced real-life tale.', TO_DATE('2015-09-12', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the truth about cats dogs', 2000, 'Sharp, witty, and charming, The Truth About Cats and Dogs features a standout performance from Janeane Garofalo.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the truth about charlie', 2002, 'Newton has star quality, but this exercise in style can''t hold a candle to the original.', TO_DATE('2002-10-07', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tsotsi thug', 2005, 'Chweneyagae''s powerful performance carries this simple yet searing tale of a shantytown teenager''s redemption.', TO_DATE('2005-09-10', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tuck everlasting', 2002, 'Though slow-moving, Tuck Everlasting raises big issues and explores them with sensitivity.', TO_DATE('2002-08-07', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tucker and dale vs evil', 2010, 'Like the best horror/comedies, Tucker & Dale vs. Evil mines its central crazy joke for some incredible scares, laughs, and -- believe it or not -- heart.', TO_DATE('2010-01-28', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tucker the man and his dream', 2000, 'Though it may not be as comprehensive as some would like, Francis Ford Coppola''s cheerful biopic of the failed automotive designer features sparkling direction and a strong central performance from Jeff Bridges.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tulip fever', 2017, 'Tulip Fever is a lush, handsomely-mounted period piece undone by uninspired dialogue and excessive plotting.', TO_DATE('2017-08-30', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tully', 2002, 'A beautifully acted, quietly moving little film.', TO_DATE('2002-08-28', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tully', 2018, 'Tully delves into the modern parenthood experience with an admirably deft blend of humor and raw honesty, brought to life by an outstanding performance by Charlize Theron.', TO_DATE('2018-01-26', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('turbo', 2013, 'It''s nowhere near as inventive as its off-the-wall premise might suggest, but Turbo boasts just enough colorful visual thrills and sharp voice acting to recommend as undemanding family-friendly fare.', TO_DATE('2013-07-10', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('turbo a power rangers movie', 2000, 'No no, Power Rangers.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('turistas paradise lost', 2006, 'Beautiful scenery and cinematography can''t save Turistas from its wooden acting and stale and predictable plot.', TO_DATE('2006-11-23', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('turn it up', 2000, 'Reviewers say Turn It Up has a derivative feel, running through too many urban movie cliches.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('turner and hooch', 2000, 'Tom Hanks makes Turner and Hooch more entertaining than it might look on paper, but ultimately, this is still a deeply silly comedy about a cop and a canine.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tusk', 2014, 'Tusk is pleasantly ridiculous and charmingly self-deprecating, but that isn''t enough to compensate for its thin, overstretched story.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the tuxedo', 2002, 'Chan is as charming as ever, but his talents are squandered by special effects and bad writing.', TO_DATE('2002-07-24', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tuyas marriage', 2008, 'The breathtaking landscapes of Inner Mongolia are a powerful backdrop for this quietly intense, dryly comical film.', TO_DATE('2008-03-31', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the tv set', 2006, 'Offering both broad and insider jokes, The TV Set is a sharp satire that will please both the average moviegoers and pop culture aficionados.', TO_DATE('2006-06-06', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('twelfth night', 2000, 'Director Trevor Nunn makes some questionable choices, but his stellar cast -- which includes Helena Bonham-Carter, Ben Kingsley, and Nigel Hawthorne -- more than rises to the material.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('12', 2007, 'Loosely based on 1957''s 12 Angry Men, Nikita Mikhalkov''s superbly acted 12 is clever and gripping like its predecessor, but with a distinctly Russian feel.', TO_DATE('2007-09-07', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('twelve', 2010, 'As pretentious as it is hopelessly clichéd, this Twelve is closer to zero.', TO_DATE('2010-05-25', 'YYYY-MM-DD'), 3.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('twelve and holding', 2005, 'This shocking pre-teen drama manages, through realistic performances and a sense of empathy, to avoid exploitation and instead deliver something honest and haunting.', TO_DATE('2005-09-15', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('twentynine palms', 2003, 'A muddled and inconsequential drama.', TO_DATE('2003-12-03', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('twilight', 2008, 'Having lost much of its bite transitioning to the big screen, Twilight will please its devoted fans, but do little for the uninitiated.', TO_DATE('2008-11-14', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the twilight saga new moon', 2009, 'The Twilight Saga''s second installment may satisfy hardcore fans of the series, but outsiders are likely to be turned off by its slow pace, relentlessly downcast tone, and excessive length.', TO_DATE('2009-11-17', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('twilight zone the movie', 2000, 'The Twilight Zone: The Movie suffers from the typical anthology-film highs and lows; thankfully, the former outnumber the latter.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('twin dragons shuang long hui brother vs brother', 1999, 'Despite some entertaining action, this movie has serious plot holes and bad direction.', TO_DATE('1999-04-09', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('twin peaks fire walk with me', 2000, 'For better or worse, Twin Peaks: Fire Walk With Me is every bit as strange and twisted as you''d expect from David Lynch.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('twist of faith', 2005, 'With Twist of Faith, documentarian Kirby Dick follows one man''s story in a gripping attempt to unravel the history of sexual abuse within the Catholic Church.', TO_DATE('2005-01-25', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('twisted', 2004, 'An implausible, overheated potboiler that squanders a stellar cast, Twisted is a clichéd, risible whodunit.', TO_DATE('2004-02-24', 'YYYY-MM-DD'), 1.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('two brothers', 2004, 'A charming family-friendly movie with stunning cinematography.', TO_DATE('2004-04-09', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('two can play that game', 2001, 'As a romantic comedy, Two Can Play That Game is more mean-spirited than romantic. Also, some critics say the movie is misogynistic in its attitudes and has too many blatant product placements.', TO_DATE('2001-08-31', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('two days one night', 2014, 'Another profoundly affecting work from the Dardenne brothers, Two Days, One Night delivers its timely message with honesty and clear-eyed compassion.', TO_DATE('2014-05-20', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('two for the money', 2005, 'Despite its sportsmanlike swagger, Two for the Money''s aimless plot isn''t worth betting on.', TO_DATE('2005-10-01', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('two girls and a guy', 1998, 'Two Girls and a Guy has an intriguing premise and a talented trio of leads, but doesn''t do quite enough with any of them to make the end result truly worth a watch.', TO_DATE('1998-04-24', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('two lovers', 2008, 'Two Lovers is a complex, intriguing, richly-acted romantic drama', TO_DATE('2008-05-19', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('two men went to war', 2003, 'Two Men Went to War bungles an incredible fact-based story on a frustratingly uneven dramatization that turns wartime heroism into middling dramedy.', TO_DATE('2003-10-28', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('two night stand', 2014, 'Two Night Stand proves even a pair of well-matched leads isn''t enough to take a rom-com all the way from interesting idea to watchable feature.', TO_DATE('2014-09-22', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('two thousand maniacs', 2002, 'It didn''t take much to thrill early splatter fans, and Two Thousand Maniacs! proves it with its shrill soundtrack, basement-level theatrics, and goofy flesh-tearing gore.', TO_DATE('2002-05-07', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('two weeks', 2006, 'Sally Field gives it her all, but this excessively maudlin family drama feels like it takes Two Weeks to finish.', TO_DATE('2006-11-28', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('two weeks notice', 2002, 'Though Two Weeks Notice has nothing new to add to the crowded genre, Hugh Grant and Sandra Bullock make the movie a pleasant, if predictable, sit.', TO_DATE('2002-12-16', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('oligarkh tycoon tycoon a new russian', 2003, 'Wants to be The Godfather, but the movie''s Citizen Kane-style narrative limits its effectiveness.', TO_DATE('2003-02-26', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tying the knot', 2004, 'Tying the Knot untangles a hot button political issue by putting a personal face on it -- and making its arguments with an effective blend of facts and feelings.', TO_DATE('2004-06-02', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tyler perrys a fall from grace', 2020, 'Drama for drama''s sake does not a great movie make, but boy is it fun to watch A Fall From Grace unravel.', TO_DATE('2020-01-17', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tyler perrys a madea christmas', 2013, 'It boasts a few laughs, but overall, Tyler Perry''s A Madea Christmas ranks among Perry''s least entertaining or substantive works.', TO_DATE('2013-12-12', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tyler perrys a madea family funeral', 2019, 'A lackluster conclusion to Tyler Perry''s long-running franchise, A Madea Family Funeral proves saying goodbye can be painful for all the wrong reasons.', TO_DATE('2019-03-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tyler perrys acrimony', 2018, 'Tyler Perry''s Acrimony might be of interest to hardcore Tyler Perry fans, but all other viewers are advised to make time for another Fatal Attraction screening instead.', TO_DATE('2018-03-30', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tyler perrys boo a madea halloween', 2016, 'Boo! A Madea Halloween won''t win Tyler Perry''s long-running franchise many new converts -- but at nine films and counting, it hardly needs to.', TO_DATE('2016-10-20', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tyler perrys good deeds', 2012, 'Tyler Perry''s craftmanship as a director continues to improve, but his stories are still the same ol'' hoary, pretentious melodramas.', TO_DATE('2012-02-19', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tyrannosaur', 2011, 'Tyrannosaur is a brutal, frank, and ultimately rewarding story of violent men seeking far-off redemption.', TO_DATE('2011-01-21', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('tyrel', 2018, 'Tyrel uses its seemingly innocuous setup to take an admirably uncomfortable -- albeit occasionally somewhat diffuse -- look at modern American race relations.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('u571', 2000, 'Excellent cinematography and an interesting plot accompanied by a talented cast and crew make U-571 a tense thriller.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('uturn', 2000, 'U-Turn is a lurid, stylish lark that boasts striking moments but lacks the focus and weight of Oliver Stone best work.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ugetsu ugetsu monogatari', 2000, 'With its thought-provoking themes, rich atmosphere, and brilliant direction, Kenji Mizoguchi''s Ugetsu monogatari is a towering classic of world cinema.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ugly truth', 2009, 'Despite the best efforts of Butler and Heigl, The Ugly Truth suffers from a weak script that relies on romantic comedy formula, with little charm or comedic payoff.', TO_DATE('2009-07-20', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('uglydolls', 2019, 'Very young viewers may be entertained by UglyDolls -- if only because they''re less likely to recognize the many familiar elements in its affirmative yet formulaic story.', TO_DATE('2019-05-01', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('uhf', 2000, 'UHF is bizarre, freewheeling, and spotty, though its anarchic spirit cannot be denied.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ulees gold', 1997, 'Led by an outstanding Peter Fonda performance, Ulee''s Gold movingly depicts a family in crisis -- and a patriarch willing to sacrifice for the good of others.', TO_DATE('1997-06-13', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the ultimate gift', 2006, 'Though The Ultimate Gift avoids religious speechifying like other Fox Faith films, it''s dramatically inert with flat direction.', TO_DATE('2006-10-20', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('umberto d', 2001, 'Anchored by Carlo Battisti''s moving performance as Umberto D, Vittorio de Sica''s deeply empathetic character study is a bracing glimpse into the lives of the downtrodden.', TO_DATE('2001-07-24', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('un amour de jeunesse goodbye first love', 2011, 'Goodbye First Love captures teen ardor with a patiently naturalistic approach, further proving writer-director Mia Hansen-Løve is a major talent to watch.', TO_DATE('2011-07-08', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('una', 2016, 'Una''s well-matched leads bring an uncomfortable story fearlessly to life, keeping the movie consistently gripping as it navigates the tricky journey from stage to screen.', TO_DATE('2016-08-29', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unaccompanied minors', 2006, 'Unaccompanied Minors, while featuring credible performances by its mostly young cast, is simply a rehash of other, funnier movies.', TO_DATE('2006-11-27', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the unbearable lightness of being', 1988, 'Exploring sexual mores against the backdrop of real-life social upheaval, The Unbearable Lightness of Being artfully blends the political and the erotic.', TO_DATE('1988-02-05', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unbreakable', 2000, 'With a weaker ending, Unbreakable is not as a good as The Sixth Sense. However, it is a quietly suspenseful film that intrigues and engages, taking the audience through unpredictable twists and turns along the way.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unbroken', 2014, 'Unbroken is undoubtedly well-intentioned, but it hits a few too many of the expected prestige-pic beats to register as strongly as it should.', TO_DATE('2014-12-01', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unbroken path to redemption', 2018, 'Unbroken: Path to Redemption overestimates the power of its inspirational real-life story, settling for a dull drama that too often preaches to the choir.', TO_DATE('2018-09-10', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('uncertainty', 2008, 'Uncertainty benefits from an evocative setting and likable leads, but its gimmicky gambit fails to pay off, fatally undermining its impact.', TO_DATE('2008-11-24', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('uncle boonmee who can recall his past lives', 2010, 'Languorous and deeply enigmatic, Palme d''Or winner Uncle Boonmee represents an original take on the ghosts that haunt us.', TO_DATE('2010-05-25', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('uncle buck', 2000, 'Uncle Buck has its ups and downs, but there''s undeniable comedic magic that comes from uniting John Hughes, John Candy, and a house full of precocious kids.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('uncle drew', 2018, 'Kyrie Irving''s crossover to comedy is amiable enough to score with basketball fans, but Uncle Drew is held back by formulaic plotting and too much product placement.', TO_DATE('2018-06-19', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('uncorked', 2020, 'Like a good wine, once you let Uncorked breathe, its heartfelt tenderness will yield a sweet time.', TO_DATE('2020-03-27', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('uncut gems', 2019, 'Uncut Gems reaffirms the Safdies as masters of anxiety-inducing cinema -- and proves Adam Sandler remains a formidable dramatic actor when given the right material.', TO_DATE('2019-08-31', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('undead', 2003, 'This low-budget homage to the zombie genre borrows heavily from superior predecessors and revels in a pile of its own campiness -- neither original nor watchable enough to entertain.', TO_DATE('2003-09-08', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('undefeated', 2011, 'It covers familiar sports documentary territory, but Undefeated proves there are still powerful stories to be told on the high school gridiron.', TO_DATE('2011-09-09', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('under our skin', 2008, 'A scathing indictment of the American medical system, Under Our Skin is timely, frightening stuff.', TO_DATE('2008-05-05', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('under siege', 1992, 'A well-directed action thriller that makes the most of its confined setting, Under Siege marks a high point for early ''90s action -- and its star''s spotty filmography.', TO_DATE('1992-10-09', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('under siege 2 dark territory', 1995, 'Utterly forgettable and completely unnecessary, Under Siege 2 represents a steep comedown from its predecessor -- and an unfortunate return to form for its star.', TO_DATE('1995-07-14', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('under the cherry moon', 2000, 'Under the Cherry Moon may satisfy the most rabid Prince fans, but everyone else will be better served with this vanity project''s far superior soundtrack.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('under the same moon', 2007, 'If Under the Same Moon is often manipulative, it is also heartfelt, and features strong performances from its leads.', TO_DATE('2007-01-24', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('sous le sable under the sand', 2000, 'Rampling carries the film with her finely nuanced performance of a woman coping with her husband''s death.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('under the shadow', 2016, 'Under the Shadow deftly blends seemingly disparate genres to deliver an effective chiller with timely themes and thought-provoking social subtext.', TO_DATE('2016-02-23', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('under the silver lake', 2018, 'Under the Silver Lake hits its stride slightly more often than it stumbles, but it''s hard not to admire - or be drawn in by - writer-director David Robert Mitchell''s ambition.', TO_DATE('2018-05-16', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('under the skin', 2013, 'Its message may prove elusive for some, but with absorbing imagery and a mesmerizing performance from Scarlett Johansson, Under the Skin is a haunting viewing experience.', TO_DATE('2013-08-30', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('under the tuscan sun', 2003, 'Though formulaic and superficial, Under the Tuscan Sun is redeemed by Lane''s vibrant performance.', TO_DATE('2003-08-25', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('underclassman', 2005, 'Despite the appealing presence of Nick Cannon, Underclassman is a shopworn Beverly Hills Cop/ 21 Jump Street knockoff.', TO_DATE('2005-08-15', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('undercover brother', 2002, 'Fast-paced and filled with racial gags, Undercover Brother serves up plenty of laughs and sharp satire.', TO_DATE('2002-05-28', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('underdog', 2007, 'Underdog is a mostly forgettable adaptation that relies far too heavily on recycled material and sloppy production.', TO_DATE('2007-08-02', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('undertow', 2004, 'Undertow''s gently fantastical elements are balanced by fully realized characters and a story with genuine, steadily accumulating emotional weight.', TO_DATE('2004-09-12', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('undertow', 2010, 'A drama as beautifully filmed as it is finely detailed, Undertow is a wonderfully unique love story with a touch of magic.', TO_DATE('2010-06-15', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('underwater', 2020, 'Underwater''s strong cast and stylish direction aren''t enough to distract from the strong sense of déjà vu provoked by this claustrophobic thriller''s derivative story.', TO_DATE('2020-01-07', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('underworld', 2003, 'Though stylish to look at, Underworld is tedious and derivative.', TO_DATE('2003-09-10', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('underworld awakening', 2012, 'There''s more vapid action and less story in Underworld Awakening than previous installments, making the whole affair feel inconsequential.', TO_DATE('2012-01-15', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('underworld blood wars', 2016, 'Underworld: Blood Wars delivers another round of the stylized violence that the series is known for, but -- like many fifth franchise installments -- offers precious little of interest to the unconverted.', TO_DATE('2016-11-28', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('underworld evolution', 2006, 'A visual and aural assault on the senses, this vampire-werewolf sequel makes a lot of noise and features a heavy-handed, overly convoluted story.', TO_DATE('2006-01-16', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('underworld the rise of the lycans', 2009, 'Despite the best efforts of its competent cast, Underworld: Rise of the Lycans is an indistinguishable and unnecessary prequel.', TO_DATE('2009-01-15', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('undiscovered', 2005, 'Undiscovered, a film about aspiring actresses and musicians, lacks originality and a convincing plot.', TO_DATE('2005-08-25', 'YYYY-MM-DD'), 8.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('undisputed', 2002, 'While not the deepest boxing movie out there, Undisputed is successful at hitting its aspiration of being nothing more than a genre picture.', TO_DATE('2002-08-13', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('une vieille maîtresse the last mistress an old mistress', 2007, 'More complicated than your average bodice ripper, Catherine Breillat''s Last Mistress features beautiful costumes, wrought romances, and a feral performance from Argento.', TO_DATE('2007-05-25', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unexpected', 2015, 'Unexpected proves a thoughtful and well-acted -- if somewhat mild -- look at worthy, thought-provoking themes.', TO_DATE('2015-01-26', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unfaithful', 2002, 'Diane Lane shines in the role, but the movie adds nothing new to the genre and the resolution is unsatisfying.', TO_DATE('2002-05-02', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unfinished business', 2015, 'Unfocused and unfunny, Unfinished Business lives down to its title with a slipshod screenplay and poorly directed performances that would have been better left unreleased.', TO_DATE('2015-03-04', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an unfinished life', 2005, 'A story of disjointed family members yearning for true emotional depth, An Unfinished Life teeters between overtly saccharine sentiments and moments of real intimacy.', TO_DATE('2005-08-22', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unfinished song', 2012, 'It''s unabashedly sentimental, but thanks to reliably powerful performances from a well-rounded veteran cast, Unfinished Song proves a sweetly compelling character piece.', TO_DATE('2012-09-14', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unforgettable', 2017, 'Unforgettable''s talented cast makes this domestic thriller consistently watchable, even if its failure to fully embrace its premise''s campy possibilities prevents it from living up to its title.', TO_DATE('2017-04-20', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unfriended', 2015, 'Unfriended subverts found-footage horror clichés to deliver a surprisingly scary entry in the teen slasher genre with a technological twist.', TO_DATE('2015-03-13', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unfriended dark web', 2018, 'Unfriended: Dark Web is more interested in chills than an exploration of its timely themes, but horror fans should still find this sequel to be steadily, undeniably effective.', TO_DATE('2018-03-12', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unicorn store', 2017, 'It''ll be best enjoyed by audiences with a high tolerance for colorful whimsy, but Unicorn Store is easy to like -- and it suggests Brie Larson has a future behind the camera.', TO_DATE('2017-09-13', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the uninvited', 2009, 'The Uninvited is moody and reasonably involving, but suffers from predictable plot twists.', TO_DATE('2009-01-28', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('united 93', 2006, 'Potent and sobering, United 93 treats the subject matter with respect, never resorting to Hollywood aggrandizement.', TO_DATE('2006-04-16', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the united states of leland', 2003, 'The United States of Leland has its moments, but they''re undermined by a muddled plot, unsympathetic characters, and frustratingly uneven performances.', TO_DATE('2003-01-24', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('universal soldier', 1992, 'Universal Soldier unites a pair of veteran action stars behind a potentially intriguing premise, but on this battlefield, entertainment value is largely AWOL.', TO_DATE('1992-07-10', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('universal soldier day of reckoning', 2012, 'The mooted final installment in the long-running series is a hyper-violent, often grim throwback to action movies of yore -- which will appeal to some audiences just as emphatically as it deters others.', TO_DATE('2012-09-23', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('universal soldier the return', 2000, 'Universal Soldier - The Return fails on almost every level, from its generic story to its second rate action and subpar performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unknown', 2011, 'Liam Neeson elevates the proceedings considerably, but Unknown is ultimately too derivative -- and implausible -- to take advantage of its intriguing premise.', TO_DATE('2011-02-13', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unlawful entry', 1992, 'Unlawful Entry may not depict a particularly novel or believable situation, but tense direction and a roundly committed cast make it easy to get caught up in the moment.', TO_DATE('1992-06-26', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unlocked', 2017, 'Unlocked strands an all-star cast in a spy thriller whose embrace of old-school formula might be refreshing if it weren''t bogged down in genre clichés and a predictable plot.', TO_DATE('2017-04-25', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unmistaken child', 2009, 'Nati Baratz''s thoughtful, beautifully filmed documentary is a moving testament to the power of faith.', TO_DATE('2009-02-09', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unplanned', 2019, 'A dramatic approach to a hot-button topic whose agenda is immediately clear, Unplanned will only reinforce the feelings of viewers on either side of the issue.', TO_DATE('2019-03-25', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('an unreasonable man', 2006, 'A compelling documentary that humanizes the controversial, polarizing politician.', TO_DATE('2006-01-26', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unsane', 2018, 'Unsane unleashes Steven Soderbergh''s inner B-movie maestro, wading into timeless psychological thriller territory and giving it a high-tech filmmaking spin.', TO_DATE('2018-02-21', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unstoppable', 2010, 'As fast, loud, and relentless as the train at the center of the story, Unstoppable is perfect popcorn entertainment -- and director Tony Scott''s best movie in years.', TO_DATE('2010-11-07', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('unstrung heroes', 1995, 'Sensitive direction and a terrific cast help Unstrung Heroes get at the heart of human grief -- and depict the relationships that can start the healing process.', TO_DATE('1995-09-15', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('untamed heart', 1993, 'Untamed Heart offers moderately moving evidence of just how much a flawed screenplay can be elevated by the right cast -- and how sometimes, it still isn''t quite enough.', TO_DATE('1993-01-01', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('untitled', 2009, 'This satire on the art world is at times both clever and shallow, but its top-notch cast generates plenty of goodwill.', TO_DATE('2009-10-13', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('client 9 the rise and fall of eliot spitzer', 2010, 'Client 9: The Rise and Fall of Eliot Spitzer finds director Alex Gibney once again probing the dark corners of politics with thought-provoking insights and hard-hitting evidence.', TO_DATE('2010-09-12', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('untouchable', 2019, 'While subsequent documentaries on the subject might be more comprehensive, Untouchable offers a gut-wrenching look at horrific abuses of power.', TO_DATE('2019-01-14', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the untouchables', 2000, 'Slick on the surface but loaded with artful touches, Brian DePalma''s classical gangster thriller is a sharp look at period Chicago crime, featuring excellent performances from a top-notch cast.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('up', 2009, 'An exciting, funny, and poignant adventure, Up offers an impeccably crafted story told with wit and arranged with depth, as well as yet another visual Pixar treat.', TO_DATE('2009-04-23', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('up and down horem pádem loop the loop', 2005, 'A tragi-comic exploration of the universal search for stability in post-Communist Prague.', TO_DATE('2005-02-19', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('up close personal', 1996, 'Up Close & Personal wastes its superstar leads and compelling fact-inspired story on a treacly romance bereft of onscreen chemistry.', TO_DATE('1996-03-01', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('up for grabs', 2004, 'You don''t have to be a baseball fan to be entertained by the absurdities, obsessions, and greed on display in this documentary.', TO_DATE('2004-04-06', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('up in smoke', 2002, 'Oft-quoted but undeniably flawed, Up In Smoke is a seminal piece of stoner cinema thanks to the likability of its two counterculture icons.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('up in the air', 2009, 'Led by charismatic performances by its three leads, director Jason Reitman delivers a smart blend of humor and emotion with just enough edge for mainstream audiences.', TO_DATE('2009-09-08', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('up the yangtze', 2008, 'Up the Yangtze is a visually stunning meditation about the changes confronting modern China.', TO_DATE('2008-01-30', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('upgrade', 2018, 'Like its augmented protagonist, Upgrade''s old-fashioned innards get a high-tech boost -- one made even more powerful thanks to sharp humor and a solidly well-told story.', TO_DATE('2018-03-12', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('upside down', 2013, 'In spite of its wonderfully unusual premise and talented cast, Upside Down fails to offer much in the way of compelling drama to anchor its admittedly dazzling visuals.', TO_DATE('2013-03-11', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the upside of anger', 2005, 'A comedy/ drama for grown-ups, with fine performances by Joan Allen and Kevin Costner.', TO_DATE('2005-01-27', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('upstream color', 2013, 'As technically brilliant as it is narratively abstract, Upstream Color represents experimental American cinema at its finest -- and reaffirms Shane Carruth as a talent to watch.', TO_DATE('2013-01-21', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('uptown girls', 2003, 'With two obnoxious lead characters and an uneven screenplay, Uptown Girls fails to charm.', TO_DATE('2003-04-17', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('urban hymn', 2015, 'Urban Hymn follows a familiar outline, but does so with enough palpable feeling that it''s easy to forgive the film''s flaws.', TO_DATE('2015-09-22', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('urban legend', 2000, 'Elements of Scream reappear in a vastly inferior vehicle.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('urban legends final cut', 2000, 'This teen horror movie brings nothing new to an already exhausted genre. And it''s bad. Really bad.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('us', 2019, 'With Jordan Peele''s second inventive, ambitious horror film, we have seen how to beat the sophomore jinx, and it is Us.', TO_DATE('2019-03-09', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('us marshals', 1997, 'A rote albeit well-cast action thriller, U.S. Marshals suffers badly in comparison to the beloved blockbuster that preceded it.', TO_DATE('1997-06-01', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the us vs john lennon', 2006, 'Though it glosses over anything negative about Lennon, this documentary offers a lot of fascinating archival footage, plus its political issues still have relevance for today.', TO_DATE('2006-08-31', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('used cars', 2002, 'Robert Zemeckis'' pitch-black satire of American culture doesn''t always hit the mark, but it''s got enough manic comic energy to warrant a spin.', TO_DATE('2002-02-04', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('ushpizin', 2005, 'Ushpizin offers a rare and warmly intimate look into ultra-Orthodox Jewish culture.', TO_DATE('2005-09-13', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the usual suspects', 1995, 'Expertly shot and edited, The Usual Suspects gives the audience a simple plot and then piles on layers of deceit, twists, and violence before pulling out the rug from underneath.', TO_DATE('1995-08-16', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('v for vendetta', 2005, 'Visually stunning and thought-provoking, V For Vendetta''s political pronouncements may rile some, but its story and impressive set pieces will nevertheless entertain.', TO_DATE('2005-07-30', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('in the fog', 2012, 'While it treads familiar narrative ground -- and is a mite predictable at times -- In the Fog proves a smart, thought-provoking antidote to Hollywood action movies.', TO_DATE('2012-05-25', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('va savoir', 2001, 'Constructed with grace and wit, Va Savoir is a light-hearted yet cerebral romantic comedy of intertwining relations.', TO_DATE('2001-07-17', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vacancy', 2007, 'Vacancy''s restraint with gore is commendable, the thin characters and B-movie cliches less so.', TO_DATE('2007-04-16', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vacation', 2015, 'Borrowing a basic storyline from the film that inspired it but forgetting the charm, wit, and heart, Vacation is yet another nostalgia-driven retread that misses the mark.', TO_DATE('2015-07-27', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('valentine', 2001, 'Valentine is basically a formulaic throwback to conventional pre-Scream slasher flicks. Critics say it doesn''t offer enough suspense or scares to justify its addition to the genre.', TO_DATE('2001-02-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('valentines day', 2009, 'Eager to please and stuffed with stars, Valentine''s Day squanders its promise with a frantic, episodic plot and an abundance of rom-com cliches.', TO_DATE('2009-10-13', 'YYYY-MM-DD'), 18.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('valentino the last emperor', 2009, 'Valentino: the Last Emperor utilizes its access to the fashion icon to the fullest, and the result is a glitzy, dishy, and insightful documentary.', TO_DATE('2009-03-06', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('valerian and the city of a thousand planets', 2017, 'Valerian and the City of a Thousand Planets uses sheer kinetic energy and visual thrills to overcome narrative obstacles and offer a viewing experience whose surreal pleasures often outweigh its flaws.', TO_DATE('2017-07-11', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('valhalla rising', 2009, 'Visually gripping and anchored by a magnetic Mads Mikkelsen, Valhalla Rising delves into violence and faith in brutally uncompromising fashion.', TO_DATE('2009-10-27', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('valiant', 2005, 'Valiant has a good collection of voice talents, but the story is strictly by-the-numbers.', TO_DATE('2005-02-24', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('valkyrie', 2008, 'Given the subject matter, Valkyrie could have been an outstanding historical thriller, but settles for being a mildly entertaining, but disposable yarn.', TO_DATE('2008-12-11', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('valley girl', 2020, 'Valley Girl won''t, like, make you forget the original or anything, but as a breezy jukebox musicals go, it''s still fairly rad.', TO_DATE('2020-05-07', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('valley of the dolls', 2000, 'Trashy, campy, soapy, and melodramatic, Valley of the Dolls may be a dud as a Hollywood expose, but has nonetheless endured as a kitsch classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('valmont', 2000, 'Valmont undermines the essential qualities of its main character''s literary counterpart, but solid casting and Milo Forman''s deft direction help mitigate those flaws.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vampire academy', 2014, 'Though it may appeal to its built-in fanbase, Vampire Academy''s Twilight-meets-Mean Girls conceit borrows lazily from its predecessors and offers few laughs or thrills to complement its overstuffed backstory.', TO_DATE('2014-02-07', 'YYYY-MM-DD'), 16.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vampire in brooklyn', 2000, 'Neither scary nor very funny, this misguided effort never lives up to its premise.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('cirque du freak the vampires assistant', 2009, 'This overstuffed, scattershot vampire flick suffers from poor characterization and an unwieldy mix of scares and chuckles.', TO_DATE('2009-09-27', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vampires kiss', 2000, 'He''s a vampire! He''s a vampire! He''s a vampire!', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vampires suck', 2010, 'Witlessly broad and utterly devoid of laughs, Vampires Suck represents a slight step forward for the Friedberg-Seltzer team.', TO_DATE('2010-07-30', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vampyr der traum des allan grey', 2000, 'Full of disorienting visual effects, Carl Theodor Dreyer''s Vampyr is as theoretically unsettling as it is conceptually disturbing.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('van helsing', 2004, 'A hollow creature feature that suffers from CGI overload.', TO_DATE('2004-03-31', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('van wilder the rise of taj van wilder 2', 2006, 'A low-brow comedy, minus the comedy.', TO_DATE('2006-11-30', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vanilla sky', 2001, 'An ambitious mix of genres, Vanilla Sky collapses into an incoherent jumble. Cruise''s performance lacks depth, and it''s hard to feel sympathy for his narcissistic character.', TO_DATE('2001-10-29', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vanity fair', 2004, 'A more likable Becky Sharp makes for a less interesting movie.', TO_DATE('2004-08-25', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vantage point', 2008, 'Vantage Point has an interesting premise that is completely undermined by fractured storytelling and wooden performances.', TO_DATE('2008-02-16', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vanya on 42nd street', 2000, 'Beautiful performances and the subtle hand of master Louis Malle make this adaptation of Chekov''s Uncle Vanya an eccentric presentation of an enduring classic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('varsity blues', 2000, 'This is a predictable football movie that lacks intensity.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vatel', 2000, 'Visually sumptuous, but unengaging.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vegas vacation', 2000, 'The Vacation franchise hits rock-bottom in this corny and tepid trip to sinfully laugh-free city.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vehicle 19', 2013, 'It starts with an interesting premise and Paul Walker is as handsomely brooding as ever, but Vehicle 19''s incoherently shot action sequences make it a poor substitute for his work in the Fast & Furious movies.', TO_DATE('2013-05-03', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('velvet buzzsaw', 2019, 'If you only watch one art-world satire with horror overtones this year -- or most others -- it should probably be Velvet Buzzsaw.', TO_DATE('2019-01-28', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('velvet goldmine', 1998, 'Velvet Goldmine takes a visual and narrative approach befitting its larger-than-life subject, although it''s still disappointingly less than the sum of its parts.', TO_DATE('1998-11-06', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('venom', 2018, 'Venom''s first standalone movie turns out to be like the comics character in all the wrong ways - chaotic, noisy, and in desperate need of a stronger attachment to Spider-Man.', TO_DATE('2018-10-03', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('venus', 2006, 'Audiences may attend to witness Peter O''Toole''s Oscar-worthy performance, but they''ll also be treated to a humane, tender exploration of maturing with both dignity and irreverence.', TO_DATE('2006-09-05', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('venus and serena', 2013, 'Venus and Serena may not take fans as deeply into the story of its subjects as they''d like, but it remains an overall engaging look at a pair of global sports stars.', TO_DATE('2013-05-06', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('venus in fur', 2013, 'Provocative, funny, and brilliantly acted, Venus in Fur finds Roman Polanski in top late-period form.', TO_DATE('2013-05-25', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vera drake', 2004, 'With a piercingly powerful performance by Imelda Staunton, Vera Drake brings teeming humanity to the controversial subject of abortion.', TO_DATE('2004-09-09', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the verdict', 2002, 'Paul Newman is at the peak of his powers as an attorney who never lived up to his potential in The Verdict, supported by David Mamet''s crackling script and Sidney Lumet''s confident direction.', TO_DATE('2002-01-17', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('verdict on auschwitz the frankfurt trial 19631965', 2007, 'Using audiotapes from the Auschwitz Trail, intermixed with archival footage and photographs, Verdict on Auschwitz is an illuminating historical document and a damning indictment of the people who perpetuated those horrors.', TO_DATE('2007-01-08', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('veronica guerin', 2003, 'Cate Blanchett gives another great performance in a movie that doesn''t shed much light on its title character.', TO_DATE('2003-06-12', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('veronica mars', 2014, 'It might be a more entertaining watch for diehard fans of the show, but Veronica Mars offers enough sharp writing and solid performances to entertain viewers in the mood for a character-driven thriller.', TO_DATE('2014-03-08', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vertical limit', 2000, 'The plot in Vertical Limit is ludicrously contrived and cliched. Meanwhile, the action sequences are so over-the-top and piled one on top of another, they lessen the impact on the viewer.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vertigo', 1958, 'An unpredictable scary thriller that doubles as a mournful meditation on love, loss, and human comfort.', TO_DATE('1958-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('very bad things', 1998, 'Mean-spirited and empty.', TO_DATE('1998-11-25', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('very good girls', 2013, 'Resting on a love triangle played out by poorly drawn characters, Very Good Girls succeeds mainly in making viewers want a better project for Dakota Fanning and Elizabeth Olsen.', TO_DATE('2013-01-23', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a very harold kumar christmas', 2011, 'Still raunchy, still irreverent, and still hit-and-miss, this Harold & Kumar outing also has a Christmas miracle: The audience gets to see the sweeter side of the duo.', TO_DATE('2011-11-02', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vfw', 2019, 'VFW''s solid cast, deft direction, and surprisingly weighty subtext add extra heft to a gory thriller that should hold buckets of sanguine appeal for grindhouse fans.', TO_DATE('2019-09-23', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vhs', 2012, 'An uneven collection of found-footage horror films, V/H/S has some inventive scares but its execution is hit-and-miss.', TO_DATE('2012-01-25', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vhs viral', 2014, 'V/H/S/: Viral is hardly a sensation as it cycles through the franchise''s least frightening vignettes yet.', TO_DATE('2014-08-29', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vhyes', 2019, 'VHYes is a unique film for specific tastes -- and a rare, albeit grimy gift for viewers who can appreciate its retro aesthetic and absurd humor.', TO_DATE('2019-09-23', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vice', 2015, 'Bruce Willis and Thomas Jane are visibly bored by the dreary material in this sci-fi hodgepodge, proving that star power in service of a lousy script is no virtue.', TO_DATE('2015-01-12', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vice', 2018, 'Vice takes scattershot aim at its targets, but writer-director Adam McKay hits some satisfying bullseyes -- and Christian Bale''s transformation is a sight to behold.', TO_DATE('2018-12-13', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('viceroys house', 2017, 'Viceroy''s House brings a balanced perspective to its worthy, historically grounded story while taking care to enliven the details with absorbing drama.', TO_DATE('2017-02-12', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vicky cristina barcelona', 2008, 'A beguiling tragicomedy, Vicky Cristina Barcelona charms with beautiful views of the Spanish city and a marvelously well-matched cast.', TO_DATE('2008-05-16', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('victim', 2003, 'Further elevated by a strong central performance from Dirk Bogarde, Victim offers an eloquent and emotionally affecting argument against prejudice.', TO_DATE('2003-03-28', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('victor victoria', 2000, 'Driven by a fantastic lead turn from Julie Andrews, Blake Edwards'' musical gender-bender is sharp, funny and all-round entertaining.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('victor frankenstein', 2015, 'A re-imagining without the imagining, Victor Frankenstein plays at providing a fresh perspective on an oft-told tale, but ultimately offers little of interest that viewers haven''t already seen in superior Frankenstein films.', TO_DATE('2015-11-23', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('victoria', 2015, 'Victoria''s single-take production is undeniably impressive, but it''s also an effective drama in its own right -- and one that juggles its tonal shifts as deftly as its technical complexities.', TO_DATE('2015-06-14', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('victoria abdul', 2017, 'Victoria & Abdul reunites Dame Judi Dench with the role of Queen Victoria -- which is all this period drama needs to overcome its imbalanced narrative.', TO_DATE('2017-09-03', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('videodrome', 2000, 'Visually audacious, disorienting, and just plain weird, Videodrome''s musings on technology, entertainment, and politics still feel fresh today.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('view from the top', 2003, 'Uneven in tone and badly edited, A View From the Top wastes the talents of its cast and condescends to its characters.', TO_DATE('2003-03-18', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a view to a kill', 1985, 'Absurd even by Bond standards, A View to a Kill is weighted down by campy jokes and a noticeable lack of energy.', TO_DATE('1985-05-24', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the vikings', 2002, 'Despite moments of excess, The Vikings has enough balance in its larger-than-life action sequences and characters to entertain.', TO_DATE('2002-08-12', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the village', 2004, 'The Village is appropriately creepy, but Shyamalan''s signature twist ending disappoints.', TO_DATE('2004-07-25', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('villain', 2020, 'Much like its taciturn hero, Villain isn''t particularly flashy or creative about getting the job done, but it''s still undeniably effective.', TO_DATE('2020-02-27', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vincere', 2009, 'Part political treatise, part melodrama, Marco Bellocchio''s Mussolini biopic forsakes historical details in favor of absorbing emotion -- and provides a showcase for a stunning performance from Giovanna Mezzogiorno.', TO_DATE('2009-05-20', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('violet daisy', 2011, 'Arch and too cute by half, Violet & Daisy cycles through too many bad ideas to make use of Alexis Bledel and Saoirse Ronan''s combined talents.', TO_DATE('2011-09-16', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('violette', 2013, 'Led by an outstanding performance from Emmanuelle Devos, Violette is a rewarding, bracingly honest look at social mores and the literary life.', TO_DATE('2013-12-05', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the virgin suicides', 2000, 'The Virgin Suicides drifts with a dreamlike melancholy that may strike some audiences as tedious, but Sofia Coppola''s feature debut is a mature meditation on disaffected youth.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('virtuosity', 1995, 'Woefully deficient in thrills or common sense, Virtuosity strands its talented stars in a story whose vision of the future is depressingly short on imagination.', TO_DATE('1995-08-04', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('visitors', 2013, 'While director Godfrey Reggio''s filmmaking style has lost some of its initial thrill, Visitors finds him returning to his familiar milieu with customary élan.', TO_DATE('2013-09-09', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vita virginia', 2018, 'Vita & Virginia takes a well-acted and initially intriguing look at the relationship between its real-life protagonists, but is undone by unsatisfying storytelling.', TO_DATE('2018-09-09', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('viva las vegas', 2000, 'Ann-Margret keeps Elvis on his toes and together they elevate Viva Las Vegas into a naughty and rockin'' mild delight.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('viva riva', 2011, 'Vibrant and violent, Viva Riva is a stylish, fast-paced crime drama.', TO_DATE('2011-05-25', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vivarium', 2019, 'Vivarium may confound almost as often as it intrigues, but this well-acted sci-fi/horror hybrid has interesting ideas -- and explores them with style.', TO_DATE('2019-05-18', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('voice from the stone', 2017, 'Voice from the Stone strands some solid performances in a would-be thriller distinctly devoid of spine-tingling moments.', TO_DATE('2017-03-28', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('volver', 2006, 'Volver catches director Pedro Almodovar and star Penelope Cruz at the peak of their respective powers, in service of a layered, thought-provoking film.', TO_DATE('2006-03-28', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the thief vor 104210861088', 2000, 'As beautiful to look at as it is thought-provoking, The Thief interrogates Europe''s past through the experiences of a family in crisis.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vox lux', 2018, 'Intriguing albeit flawed, Vox Lux probes the allures and pitfalls of modern celebrity with intelligence, visual style, and an assured Natalie Portman performance.', TO_DATE('2018-09-04', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('voyeur', 2017, 'Absorbing, unpredictable, and overall compelling, Voyeur is a singularly unusual -- and utterly memorable -- documentary experience.', TO_DATE('2017-10-05', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vulgar', 2001, 'Vulgar more than lives up to its title.', TO_DATE('2001-06-07', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('w', 2008, 'A surprisingly sympathetic portrayal of the 43rd American president, W. is fascinating in spots, but merely rudimentary as a whole.', TO_DATE('2008-10-07', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('w kamau bell private school negro', 2018, 'W. Kamau Bell''s affable charisma makes Private School Negro a mirthful dissection of modern America, although although seasoned fans may find the material a bit familiar.', TO_DATE('2018-07-02', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wackness', 2008, 'Sympathetic characters and a clever script help The Wackness overcome a familiar plot to make for a charming coming-of-age comedy.', TO_DATE('2008-01-20', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wadjda', 2012, 'Transgressive in the best possible way, Wadjda presents a startlingly assured new voice from a corner of the globe where cinema has been all but silenced.', TO_DATE('2012-10-14', 'YYYY-MM-DD'), 99.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wag the dog', 2000, 'Smart, well-acted, and uncomfortably prescient political satire from director Barry Levinson and and all-star cast.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wages of fear', 2000, 'An existential suspense classic, The Wages of Fear blends nonstop suspense with biting satire; its influence is still being felt on today''s thrillers.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wagons east', 2000, 'Wagons East! is a witless, toothless satire of Westerns that falls far below the standard set by Blazing Saddles, and is notable only for being John Candy''s final screen performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 0.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wahwah', 2005, 'The ensemble cast is strong, but they get overpowered by the muddled stew of melodrama.', TO_DATE('2005-09-20', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waist deep', 2006, 'A well-meaning B-movie that suffers from a cliche-ridden script and poorly drawn characters that fail to inspire much sympathy.', TO_DATE('2006-06-21', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wait until dark', 2001, 'Nail-bitingly tense and brilliantly acted, Wait Until Dark is a compact thriller that makes the most of its fiendishly clever premise.', TO_DATE('2001-02-27', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waiting', 2005, 'Waiting... is a gross-out comedy that is more gross than comic.', TO_DATE('2005-10-04', 'YYYY-MM-DD'), 30.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waiting for guffman', 2000, 'This riotously deadpan mockumentary about aspiring community theater performers never stoops to ridicule oft-ridiculous characters.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waiting for superman', 2010, 'Gripping, heartbreaking, and ultimately hopeful, Waiting for Superman is an impassioned indictment of the American school system from An Inconvenient Truth director Davis Guggenheim.', TO_DATE('2010-04-06', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waiting for the barbarians', 2019, 'Admirable in theory but disappointing in execution, Waiting for the Barbarians struggles to turn strong performances and worthy themes into affecting drama.', TO_DATE('2019-09-06', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waiting to exhale', 1995, 'Waiting to Exhale looks at life''s ups and downs from an underseen perspective -- albeit one that''s poorly served by uneven acting and a sporadically interesting story.', TO_DATE('1995-12-22', 'YYYY-MM-DD'), 56.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waitress', 2007, 'Sweet, smart, and quirky, Waitress hits the right, bittersweet notes through this romantic comedy through its witty script and a superb performance by Keri Russell.', TO_DATE('2007-01-25', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wake in fright', 2009, 'A disquieting classic of Australian cinema, Wake in Fright surveys a landscape both sun-drenched and ruthlessly dark.', TO_DATE('2009-08-26', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wakefield', 2016, 'Thanks to a committed, powerhouse performance by Bryan Cranston, Wakefield is a fascinating character study of a decidedly unpleasant character.', TO_DATE('2016-09-04', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waking life', 2001, 'Waking Life''s inventive animated aesthetic adds a distinctive visual component to a film that could easily have rested on its smart screenplay and talented ensemble cast.', TO_DATE('2001-01-19', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waking ned devine', 1998, 'A heartwarming comedy with a delightfully light touch, Waking Ned Devine finds feel-good humor in some unexpected -- and unexpectedly effective -- places.', TO_DATE('1998-11-20', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waking sleeping beauty', 2010, 'It doesn''t probe as deep -- or tell as many hard truths -- as it could have, but Don Hahn''s look at Disney''s rebirth offers a fascinating and surprisingly candorous glimpse into the studio''s past.', TO_DATE('2010-02-25', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waking up in reno', 2001, 'The humor is on the level of a corny sitcom, and the tone is condescending.', TO_DATE('2001-08-08', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('walmart the high cost of low price', 2005, 'Clearly one-sided but thoroughly compelling, Wal-Mart: The High Cost of Low Price represents advocacy filmmaking at its most passionate and persuasive.', TO_DATE('2005-11-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('walk hard the dewey cox story', 2007, 'A parody that pokes fun at rock stars and reductive biopics alike, this comedy sings in large part because of stellar performances and clever original music.', TO_DATE('2007-11-28', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a walk in the clouds', 1995, 'A Walk in the Clouds aims for sweeping period romance, but quickly unravels thanks to a miscast leading man and a story that relies on cheap melodrama.', TO_DATE('1995-08-11', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('walk of shame', 2014, 'Incoherent, unfunny, and borderline misogynist, Walk of Shame lives up to its title for filmgoers entering and leaving the theater.', TO_DATE('2014-05-02', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a walk on the moon', 1999, 'An impressive showcase for Diane Lane and an assured debut from director Tony Goldwyn, A Walk on the Moon finds absorbing period drama within a family at a crossroads.', TO_DATE('1999-03-26', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('walk on water', 2004, 'Politically complex and ambitious, Walk on Water delivers a memorable story of guilt, revenge, and human connectivity.', TO_DATE('2004-11-08', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('walk the line', 2005, 'Superior acting and authentic crooning capture the emotional subtleties of the legend of Johnny Cash with a freshness that is a pleasure to watch.', TO_DATE('2005-09-04', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a walk to remember', 2002, 'Though wholesome, the Mandy Moore vehicle A Walk to Remember is also bland and oppressively syrupy.', TO_DATE('2002-01-23', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('walk with me', 2017, 'Walk with Me offers an appropriately -- and refreshingly -- meditative look at lives lived in the pursuit of mindfulness.', TO_DATE('2017-03-12', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('walkabout', 1971, 'With its harrowingly beautiful depiction of the Australian Outback and spare narrative of culture clash, Walkabout is a peculiar survival epic.', TO_DATE('1971-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('walking on sunshine', 2014, 'It desperately wants to be frothy and fun, but Walking on Sunshine is crass and calculated -- and a poor substitute for the jukebox musicals it attempts to emulate.', TO_DATE('2014-06-19', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('walking out', 2017, 'Beautifully filmed and powerfully acted, Walking Out effectively balances tense father-son drama against an affecting wilderness survival story.', TO_DATE('2017-01-22', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('walking tall', 2004, 'The Rock makes a competent hero, but the movie is content to let a 2x4 do all the talking.', TO_DATE('2004-03-29', 'YYYY-MM-DD'), 26.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('walking with dinosaurs', 2013, 'Walking with Dinosaurs boasts painstaking visual brilliance, but it''s unfortunately clouded by a clumsy script that''s dominated by juvenile humor.', TO_DATE('2013-12-16', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('walking with the enemy', 2014, 'While Walking With the Enemy tells a stirring and little-known true story, it''s ultimately too heavy-handed to fully resonate.', TO_DATE('2014-04-23', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('walle', 2007, 'Wall-E''s stellar visuals testify once again to Pixar''s ingenuity, while its charming star will captivate younger viewers -- and its timely story offers thought-provoking subtext.', TO_DATE('2007-11-09', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wall street', 1987, 'With Wall Street, Oliver Stone delivers a blunt but effective -- and thoroughly well-acted -- jeremiad against its era''s veneration of greed as a means to its own end.', TO_DATE('1987-12-11', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wall street money never sleeps', 2010, 'It''s more entertaining than many sequels, but with Oliver Stone directing, a terrific cast, and a timely storyline that picks up where the original left off, Wall Street: Money Never Sleeps should be better.', TO_DATE('2010-05-14', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wallace gromit the curse of the wererabbit', 2005, 'The Curse of the Were-Rabbit is a subtly touching and wonderfully eccentric adventure featuring Wallace and Gromit.', TO_DATE('2005-09-09', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waltz with bashir', 2008, 'A wholly innovative, original, and vital history lesson, with pioneering animation, Waltz With Bashir delivers its message about the Middle East in a mesmerizing fashion.', TO_DATE('2008-05-15', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wanderlust', 2012, 'It isn''t always as funny as it should be, but Wanderlust benefits from an extremely talented cast and some of David Wain''s most confident, assured work behind the camera.', TO_DATE('2012-02-22', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('war rogue assassin', 2007, 'Jet Li and Jason Statham find themselves on opposing sides in the immensely boring War, which is full of clichés but short on action.', TO_DATE('2007-08-24', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('war dogs', 2016, 'War Dogs rises on the strength of Jonah Hill''s compelling performance to take a lightly entertaining look at troubling real-world events.', TO_DATE('2016-08-15', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('war for the planet of the apes', 2017, 'War for the Planet of the Apes combines breathtaking special effects and a powerful, poignant narrative to conclude this rebooted trilogy on a powerful -- and truly blockbuster -- note.', TO_DATE('2017-06-26', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('war horse', 2011, 'Technically superb, proudly sentimental, and unabashedly old-fashioned, War Horse is an emotional drama that tugs the heartstrings with Spielberg''s customary flair.', TO_DATE('2011-11-10', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('war inc', 2008, 'War, Inc. attempts to satirize the military industrial complex, but more often than not it misses its target.', TO_DATE('2008-04-25', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('war machine', 2017, 'War Machine''s uneven execution keeps its fact-based story from cleanly hitting its targets, but those flaws are frequently offset by sharp wit and solid acting.', TO_DATE('2017-05-22', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the war of the roses', 1989, 'The War of the Roses is a black comedy made even funnier by hanging onto its caustic convictions -- and further distinguished by Danny DeVito''s stylish direction.', TO_DATE('1989-12-08', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('war of the worlds', 2005, 'Steven Spielberg''s adaptation of War of the Worlds delivers on the thrill and paranoia of H.G. Wells'' classic novel while impressively updating the action and effects for modern audiences.', TO_DATE('2005-06-27', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('war on everyone', 2016, 'War on Everyone boasts just enough dark humor and infectious energy to make this somewhat middling entry from writer-director John Michael McDonagh an entertaining diversion.', TO_DATE('2016-02-12', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the war room', 1993, 'Eye-opening in its access to an array of colorful campaign operatives, The War Room is a valuable time capsule and a riveting study in the art of politicking.', TO_DATE('1993-10-13', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the war tapes', 2006, 'Candid, eye-opening footage gives viewers a close-up -- and educational -- look at the experiences of American soldiers in Iraq, a viewpoint not normally seen.', TO_DATE('2006-05-09', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('war witch', 2012, 'War Witch is a mature, intense drama that embraces the bruatlity of its subject and invites the audience to sympathize with its protagonist''s nightmarish circumstances.', TO_DATE('2012-09-08', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('warcraft', 2016, 'Warcraft has visual thrills to spare, but they -- and director Duncan Jones'' distinctive gifts -- are wasted on a sluggish and derivative adaptation of a bestselling game with little evident cinematic value.', TO_DATE('2016-05-24', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wargames war games', 2000, 'Part delightfully tense techno-thriller, part refreshingly unpatronizing teen drama, WarGames is one of the more inventive -- and genuinely suspenseful -- Cold War movies of the 1980s.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('warlords tau ming chong', 2008, 'Slightly stodgy historical Chinese epic with impressive battles.', TO_DATE('2008-10-18', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('warm bodies', 2013, 'Warm Bodies offers a sweet, well-acted spin on a genre that all too often lives down to its brain-dead protagonists.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('warm water under a red bridge akai hashi no shita noo nurui mizu', 2001, 'A whimsically engaging sex comedy.', TO_DATE('2001-09-25', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wasabi', 2002, 'Jean Reno''s efforts aren''t enough to add dramatic ballast to Wasabi''s bursts of kinetic -- yet frustratingly hollow -- action.', TO_DATE('2002-09-24', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wassup rockers', 2005, 'As usual with Clark''s films, the fixation on kids is rather creepy, plus the plot eventually runs off the rails into camp.', TO_DATE('2005-09-22', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waste land', 2010, 'Waste Land begins with an eco-friendly premise, but quickly transforms into an uplifting portrait of the power of art and the dignity of the human spirit.', TO_DATE('2010-08-23', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the watcher', 2000, 'The Watcher has Keanu Reeves cast against type, but the movie is short on thrills, suspense, and believability.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('watchers of the sky', 2014, 'Watchers of the Sky offers a consistently gripping look at one man''s incredible legacy, even if it can''t hope to offer a comprehensive overview of a huge, complicated subject.', TO_DATE('2014-01-29', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('watchmen', 2009, 'Gritty and visually striking, Watchmen is a faithful adaptation of Alan Moore''s graphic novel, but its complex narrative structure may make it difficult for it to appeal to viewers not already familiar with the source material.', TO_DATE('2009-02-23', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('water', 2005, 'This compassionate work of social criticism is also luminous, due to both its lyrical imagery and cast.', TO_DATE('2005-09-09', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('water for elephants', 2011, 'It''s a tale tastefully told and beautifully filmed, but Water for Elephants suffers from a pronounced lack of chemistry between its leads.', TO_DATE('2011-04-20', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the water horse legend of the deep', 2007, 'The Water Horse is a fine family film. It takes a classic tale and infuses it with extra imagination, sly humor, heart, and inventive special effects.', TO_DATE('2007-12-12', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the waterboy', 2000, 'This is an insult to its genre with low humor and cheap gags.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('watermark', 2013, 'Although their lack of context may bewilder some viewers, the array of beautiful imagery collected within Watermark offers its own rich rewards.', TO_DATE('2013-09-25', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('watership down', 2000, 'Aimed at adults perhaps more than children, this is a respectful, beautifully animated adaptation of Richard Adams'' beloved book.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waterworld', 1995, 'Though it suffered from toxic buzz at the time of its release, Waterworld is ultimately an ambitious misfire: an extravagant sci-fi flick with some decent moments and a lot of silly ones.', TO_DATE('1995-07-28', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waves', 2019, 'An up-close look at one family''s emotional ups and downs, Waves captures complicated dynamics with tenderness and grace.', TO_DATE('2019-08-31', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the way home jibeuro', 2002, 'A simple story told with much warmth and compassion.', TO_DATE('2002-09-20', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the way of the gun', 2000, 'Christopher McQuarrie may exhibit a way behind the camera in the stylish The Way of the Gun, but his script falters with dull characterization and a plot so needlessly twisty that most viewers will be ready to tune out before the final reveal.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the way we were', 2000, 'The Way We Were is not politically confrontational enough for its story of ideological opposites falling in love to feel authentic, but Barbra Streisand and Robert Redford''s beaming star power gives this melodrama romantic lift.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waynes world', 2000, 'An oddball comedy that revels in its silliness and memorable catch phrases, Wayne''s World is also fondly regarded because of its endearing characters.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('waynes world 2', 1993, 'The characters are still endearing, but the jokes in Wayne''s World 2 are more hit-and-miss the second time around.', TO_DATE('1993-12-10', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we', 2011, 'W.E. exhibits director Madonna''s keen eye for striking style, but this shallow biopic is too enamored with aesthetics to offer any insight into its subject.', TO_DATE('2011-09-01', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we are little zombies', 2019, 'We Are Little Zombies mixes the playful and the profane with a stylish and visually inventive look at death, abandonment, and the grieving process.', TO_DATE('2019-01-25', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we are marshall', 2006, 'Matthew McConaughey almost runs We Are Marshall to the end zone, but can''t stop it from taking the easy, feel-good route in memorializing this historic event in American sports.', TO_DATE('2006-11-16', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we are still here', 2015, 'Smart, powerfully acted, and devilishly clever, We Are Still Here offers some novel twists on familiar territory -- and heralds the arrival of a major talent in writer-director Ted Geoghegan.', TO_DATE('2015-03-16', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we are the best', 2013, 'Sweet, empathetic, and shot through with a palpable joy, We Are the Best! offers a tender tribute to the bittersweet tumult of adolescence.', TO_DATE('2013-09-14', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we are what we are', 2013, 'A compelling story cleverly told, We Are What We Are quenches horror buffs'' thirst for gore while serving up serious-minded filmmaking and solid acting.', TO_DATE('2013-01-22', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we are your friends', 2015, 'We Are Your Friends boasts magnetic stars and glimmers of insight, but they''re lost in a clichéd coming-of-age story as programmed as the soundtrack''s beats.', TO_DATE('2015-08-25', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we bought a zoo', 2011, 'We Bought a Zoo is a transparently cloying effort by director Cameron Crowe, but Matt Damon makes for a sympathetic central character.', TO_DATE('2011-11-27', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we dont live here anymore', 2004, 'We Don''t Live Here Anymore is often overly moody and grim, but it''s made watchable by the strong performances for its four principal actors.', TO_DATE('2004-01-27', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we need to talk about kevin', 2011, 'We Need to Talk About Kevin is a masterful blend of drama and horror, with fantastic performances across the board (Tilda Swinton especially, delivering one of her very best).', TO_DATE('2011-05-12', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we own the night', 2007, 'Bland characters, clichéd dialogue and rickety plotting ensure We Own The Night never lives up to its potential.', TO_DATE('2007-05-29', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we steal secrets the story of wikileaks', 2013, 'As fascinating as it is provocative, We Steal Secrets: The Story of Wikileaks presents another documentary triumph for director Alex Gibney, as well as a troubling look at one of the more meaningful issues of our time.', TO_DATE('2013-01-23', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we summon the darkness', 2019, 'We Summon the Darkness makes the most of its rather pedestrian plot with palpable affection for genre formula, an appealing cast, and a sharp sense of humor.', TO_DATE('2019-09-26', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we the animals', 2018, 'Dreamlike and haunting, We the Animals approaches the coming-of-age odyssey with a uniquely documentarian eye.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we were here', 2011, 'We Were Here revisits the crises facing the gay community in the early 1980s -- and offers a powerful tribute to the inspiring resolve shown at a time of turmoil.', TO_DATE('2011-01-28', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('we were soldiers', 2002, 'The war cliches are laid on a bit thick, but the movie succeeds at putting a human face on soldiers of both sides in the Vietnam War.', TO_DATE('2002-02-17', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the weather man', 2005, 'With fine performances and a dark, dry sense of humor, The Weather Man is mostly cloudy with occasional rays of sunshine.', TO_DATE('2005-09-29', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('web junkie', 2014, 'While neither as deep nor as skillfully constructed as its subject might deserve, Web Junkie remains a chillingly serious look at a nightmarish problem.', TO_DATE('2014-01-22', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wedding banquet xi yan', 2000, 'Ang Lee''s funny and ultimately poignant comedy of manners reveals the filmmaker''s skill across genres.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wedding crashers', 2005, 'Wedding Crashers is both raunchy and sweet, and features top-notch comic performances from Vince Vaughn and Owen Wilson.', TO_DATE('2005-06-28', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wedding date', 2005, 'Critics are leaving The Wedding Date at the alter, calling it shopworn, bland, and lightweight.', TO_DATE('2005-01-31', 'YYYY-MM-DD'), 11.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wedding planner', 2000, 'Instead of being light and charming, this romantic comedy is heavy-handed and contrived in its execution. Also, it''s too unoriginal.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wedding singer', 1997, 'It''s decidedly uneven -- and surprisingly sappy for an early Adam Sandler comedy -- but The Wedding Singer is also sweet, funny, and beguiling.', TO_DATE('1997-06-01', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('weekend', 2011, 'It may be a chamber piece but Weekend''s revelations on modern sexuality expand far beyond the modest setting.', TO_DATE('2011-03-25', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('weekend at bernies', 2000, 'Weekend at Bernie''s wrings a surprising amount of laughs out of its corpse-driven slapstick premise, but one joke can only carry a film so far.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('weekend at bernies ii', 1800, 'It would appear to be all but impossible to make a worthwhile sequel to a comedy about a corpse''s exploits -- odds Weekend at Bernie''s II never comes close to beating.', TO_DATE('1800-01-01', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the weight of water', 2002, 'The story is too muddled to build any interest.', TO_DATE('2002-06-05', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('weiner', 2016, 'Weiner uses sharp insight and untrammeled access to offer a portrait of a political and personal collapse that''s as queasy as it is undeniably compelling.', TO_DATE('2016-01-24', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('weirdsville', 2007, 'Though it can be confusing at times, Weirdsville is funny and quirky in equal measure.', TO_DATE('2007-01-19', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('welcome home roscoe jenkins', 2008, 'Welcome Home Roscoe Jenkins has moments of comic inspiration -- and long stretches of overdone slapstick.', TO_DATE('2008-02-05', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('welcome to collinwood', 2002, 'Contains some funny moments, but it''s still a very lightweight comedy.', TO_DATE('2002-06-04', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('welcome to marwen', 2018, 'Welcome to Marwen has dazzling effects and a sadly compelling story, but the movie''s disjointed feel and clumsy screenplay make this invitation easy to decline.', TO_DATE('2018-12-19', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('welcome to me', 2014, 'A transfixing central performance by Kristen Wiig performance holds Welcome to Me together and compensates for its uneven stretches.', TO_DATE('2014-09-11', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('welcome to mooseport', 2004, 'A bland comedy that squanders a talented cast.', TO_DATE('2004-02-16', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('welcome to new york', 2014, 'Led by a fearless performance from Gerard Depardieu, Welcome to New York is director Abel Ferrara at his most repulsive -- and most compulsively watchable.', TO_DATE('2014-05-18', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('welcome to the dollhouse', 1995, 'An outstanding sophomore feature, Welcome to the Dollhouse sees writer-director Todd Solondz mining suburban teen angst for black, biting comedy.', TO_DATE('1995-09-10', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('welcome to the punch', 2013, 'Welcome to the Punch is a little deeper and more thoughtful than most police dramas -- but not quite enough to surmount its thinly written characters and numbing violence.', TO_DATE('2013-02-26', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('welcome to the rileys', 2010, 'Despite earnest performances, Welcome to the Rileys cannot escape its belabored over-sentimentality and sluggish delivery.', TO_DATE('2010-01-25', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wendigo', 2001, 'An artsy horror flick, Wendigo effectively creates an eerie atmosphere.', TO_DATE('2001-12-21', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wendy and lucy', 2008, 'Michelle Williams gives a heartbreaking performance in Wendy and Lucy, a timely portrait of loneliness and struggle.', TO_DATE('2008-05-22', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('were the millers', 2013, 'We''re the Millers squanders its potential with an uneven, lazily assembled story..', TO_DATE('2013-08-05', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('were the world mine', 2008, 'Charming, endearing, and a little clunky, Were the World Mine is an entertaining, if somewhat unnecessary, musical adaptation.', TO_DATE('2008-05-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wes cravens new nightmare', 1994, 'Wes Craven''s New Nightmare adds an unexpectedly satisfying - not to mention intelligent - meta layer to a horror franchise that had long since lost its way.', TO_DATE('1994-10-14', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('west of memphis', 2012, 'Both a sobering look at a true crime story and a scathing indictment of the American justice system, West of Memphis is a real-life horror story told with fury and compassion.', TO_DATE('2012-01-20', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('west side story', 2000, 'Buoyed by Robert Wise''s dazzling direction, Leonard Bernstein''s score, and Stephen Sondheim''s lyrics, West Side Story remains perhaps the most iconic of all the Shakespeare adaptations to visit the big screen.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('western', 2017, 'Western earns the viewer''s attention with an unpredictable, patiently told tale that evokes the spirit of the titular genre while adding its own unique touches.', TO_DATE('2017-05-18', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('westworld', 2000, 'Yul Brynner gives a memorable performance as a robotic cowboy in this amusing sci-fi/western hybrid.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wet hot american summer', 2001, 'Wet Hot American Summer''s incredibly talented cast is too often outmatched by a deeply silly script that misses its targets at least as often as it skewers them.', TO_DATE('2001-04-20', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whale rider', 2003, 'An empowering and uplifting movie, with a wonderful performance by Castle-Hughes.', TO_DATE('2003-03-10', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what a girl wants', 2003, 'Little girls will definitely enjoy it, but it''s too syrupy and predictable for adults.', TO_DATE('2003-03-21', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what about bob', 1991, 'Bill Murray and Richard Dreyfuss'' chemistry helps make the most of a familiar yet durable premise, elevating What About Bob? into the upper ranks of ''90s comedies.', TO_DATE('1991-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what alice found', 2003, 'A modest, nicely acted road movie.', TO_DATE('2003-09-24', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what dreams may come', 2000, 'An insubstantial plot overshadows the beautiful, surreal scenery.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what ever happened to baby jane', 2000, 'What Ever Happened to Baby Jane? combines powerhouse acting, rich atmosphere, and absorbing melodrama in service of a taut thriller with thought-provoking subtext.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what happened miss simone', 2015, 'What Happened, Miss Simone? is a compelling -- albeit necessarily incomplete -- overview of its complex subject''s singular artistic legacy and fascinating life.', TO_DATE('2015-01-23', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what if', 2013, 'Its narrative framework may be familiar, but What If transcends its derivative elements with sharp dialogue and the effervescent chemistry of stars Daniel Radcliffe and Zoe Kazan.', TO_DATE('2013-09-08', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what just happened', 2008, 'What Just Happened has some inspired comic moments, but this inside-baseball take on Hollywood lacks satirical bite.', TO_DATE('2008-01-19', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what keeps you alive', 2018, 'Smart, stylish, and well-acted, What Keeps You Alive proves it''s still possible to spin an engrossing horror yarn without fundamentally altering established formula.', TO_DATE('2018-03-15', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what lies beneath', 2000, 'Robert Zemeckis is unable to salvage an uncompelling and unoriginal film.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what maisie knew', 2012, 'It''s undeniably difficult to watch at times, but What Maisie Knew ultimately rises on the strength of its solidly sourced script, powerful performances, and empathetic direction.', TO_DATE('2012-09-09', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what men want', 2019, 'Admittedly uneven but easy to like, What Men Want proves a gender-swapped remake can work -- and the odds are substantially improved with Taraji P. Henson in the lead.', TO_DATE('2019-02-05', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what richard did', 2012, 'Guided by a vividly sympathetic turn from Jack Reynor, What Richard Did explores its devastating story with probing, disquieting realism.', TO_DATE('2012-09-20', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what she said the art of pauline kael', 2018, 'What She Said: The Art of Pauline Kael clearly outlines the gifts that made its subject special while offering an engaging overview of her remarkable life and career.', TO_DATE('2018-11-13', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what the bleep do we know', 2004, 'Educational, but as entertainment, it''ll have viewers asking, ''What the bleep?''', TO_DATE('2004-05-20', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what they had', 2018, 'What They Had finds laughter and tears in its portrait of a family at a crossroads, with writer-director Elizabeth Chomko getting outstanding performances out of a talented cast.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what to expect when youre expecting', 2012, 'The cast is stocked with likable performers, but What to Expect When You''re Expecting is too disjointed -- and too reliant on stock rom-com cliches -- to live up to its distinguished literary namesake.', TO_DATE('2012-05-11', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what we did on our holiday', 2014, 'Witty and well-cast, What We Did on Our Holiday injects unlikely laughs into a story dealing with dark, difficult themes.', TO_DATE('2014-09-17', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what we do in the shadows', 2014, 'Smarter, fresher, and funnier than a modern vampire movie has any right to be, What We Do in the Shadows is bloody good fun.', TO_DATE('2014-01-21', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what we do is secret', 2007, 'Despite its dynamic subject and reckless anti-glamor, this biopic about the legendary punk rocker Darby Crash fails to translate the excitement its subject generated.', TO_DATE('2007-09-17', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what women want', 2000, 'Even though Gibson is a good sport in his role, What Women Want is a rather conventional, fluffy comedy-romance that doesn''t make good use of its premise.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('what you gonna do when the worlds on fire', 2018, 'What You Gonna Do When the World''s On Fire? traces the aftershocks of race-motivated violence in thoughtful, impressionistic fashion.', TO_DATE('2018-09-04', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whatever works', 2009, 'Based upon a script written in the 1970s, Woody Allen''s Whatever Works suffers from a lack of fresh ideas.', TO_DATE('2009-04-24', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whats cooking', 2000, 'What''s Cooking? is well-acted, but the scenes sometimes sink into melodrama as characters scream at each other, and the movie as a whole is too lightweight and forgettable.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whats eating gilbert grape', 1993, 'It''s sentimental and somewhat predictable, but those are small complaints, given the tender atmosphere and moving performances at the heart of What''s Eating Gilbert Grape.', TO_DATE('1993-12-25', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whats love got to do with it', 2000, 'With a fascinating real-life story and powerhouse performances from Angela Bassett and Laurence Fishburne, What''s Love Got to Do With It? is a can''t miss biopic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whats the worst that could happen', 2000, 'Talented cast is squandered by an uninvolving script filled with unfunny gags.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whats up doc', 2000, 'Barbra Streisand was never more likable than in this energetic, often hilarious screwball farce from director Peter Bogdanovich.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whats your number', 2011, 'The comic timing of Anna Faris is sharp as always, but it''s wasted away in this predictable, boilerplate comedy.', TO_DATE('2011-09-21', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wheelman', 2017, 'Wheelman takes B-movie action lovers on an uncommonly smooth ride, with taut plotting and exciting action topped off with solid work from Frank Grillo in the title role.', TO_DATE('2017-09-23', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('when a man loves a woman', 1994, 'When a Man Loves a Woman delves into the complex dynamics of a marriage shadowed by addiction, aided by strong performances from Andy Garcia and Meg Ryan.', TO_DATE('1994-04-29', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('when a stranger calls', 2006, 'When a Stranger Calls ranks among the more misguided remakes in horror history, offering little more than a rote, largely fright-free update to the original.', TO_DATE('2006-02-02', 'YYYY-MM-DD'), 9.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('when did you last see your father', 2007, 'Sensitive to a fault, Tucker''s adaptation of the Morrison novel is nonetheless solidly scripted and well-acted; guard your heartstrings.', TO_DATE('2007-08-18', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('when harry met sally', 2000, 'Rob Reiner''s touching, funny film set a new standard for romantic comedies, and he was ably abetted by the sharp interplay between Billy Crystal and Meg Ryan.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('when in rome', 2010, 'A pair of young, attractive leads can''t overcome When in Rome''s reliance on unfunny gags and threadbare rom-com clichés.', TO_DATE('2010-01-28', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('when marnie was there', 2014, 'When Marnie Was There is still blessed with enough visual and narrative beauty to recommend, even if it isn''t quite as magical as Studio Ghibli''s greatest works.', TO_DATE('2014-12-16', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('when the bough breaks', 2016, 'Shallow, clichéd, and silly instead of suspenseful, When the Bough Breaks offers nothing domestic thriller fans haven''t already seen before -- and done far better.', TO_DATE('2016-09-09', 'YYYY-MM-DD'), 12.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('when the game stands tall', 2014, 'An uneasy blend of solid game sequences and threadbare inspirational sports drama clichés, When the Game Stands Tall is overshadowed by better players in a crowded field.', TO_DATE('2014-08-21', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('when the levees broke a requiem in four acts', 2006, 'When the Levees Broke offers a heart-rending elegy for an American city overflowing with culture, beset by natural disaster, and betrayed by institutional indifference.', TO_DATE('2006-08-22', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('when we first met', 2018, 'Much like its protagonist, When We First Met struggles in the cinematic "friend zone" -- and will face a slew of viewer breakups before finding much in the way of true love.', TO_DATE('2018-02-06', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('when will i be loved', 2004, 'Neve Campbell bares all in this seemingly misogynistic trifle.', TO_DATE('2004-08-17', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('when youre strange', 2009, 'It''s far from a critical assessment of the band''s music or its legacy, but When You''re Strange gives fans a beautifully filmed, lovingly assembled tribute to the Doors.', TO_DATE('2009-01-20', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('where hands touch', 2018, 'Where Hands Touch is noteworthy for its exploration of a little-discussed corner of World War II, even if its story leaves something to be desired in the telling.', TO_DATE('2018-09-10', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('where in the world is osama bin laden', 2008, 'Morgan Sprulock''s doc offers occasional insights but gets bogged down by the director/subject''s gimmicky schtick.', TO_DATE('2008-01-22', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('where is kyra', 2017, 'Where Is Kyra? rests on Michelle Pfeiffer''s magnetically raw performance -- and lives up to it with a trenchant, hard-hitting story.', TO_DATE('2017-01-25', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('where the buffalo roam', 2001, 'Bill Murray delivers a noteworthy portrayal of Hunter S. Thompson, but Where the Buffalo Roam strains to get through its rambling narrative.', TO_DATE('2001-02-13', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('where the money is', 2000, 'The acting in Where the Money Is is excellent. However, the movie feels like a made-for-TV movie that''s plain and forgettable.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('where the truth lies', 2005, 'The belabored noir plotting feels unbelievable, thus removing any sense of suspense. Also, Lohman is badly miscast.', TO_DATE('2005-05-13', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('where the wild things are', 2009, 'Some may find its dark tone and slender narrative off-putting, but Spike Jonze''s heartfelt adaptation of the classic children''s book is as beautiful as it is uncompromising.', TO_DATE('2009-10-03', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('where to invade next', 2015, 'Where to Invade Next finds documentarian Michael Moore approaching progressive politics with renewed -- albeit unabashedly one-sided -- vigor.', TO_DATE('2015-09-11', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whered you go bernadette', 2019, 'Where''d You Go, Bernadette offers dispiriting proof that a talented director, bestselling source material, and terrific cast can add up to far less than the sum of their parts.', TO_DATE('2019-08-09', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wheres my roy cohn', 2019, 'It''s blunt rather than balanced, but Where''s My Roy Cohn? does what it sets out to do, offering a disquieting summary of its subject''s life and legacy.', TO_DATE('2019-01-26', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('while were young', 2014, 'Poignant and piercingly honest, While We''re Young finds writer-director Noah Baumbach delivering some of his funniest lines through some of his most relatable characters.', TO_DATE('2014-09-07', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('while you were sleeping', 2000, 'While You Were Sleeping is built wholly from familiar ingredients, but assembled with such skill -- and with such a charming performance from Sandra Bullock -- that it gives formula a good name.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whip it', 2009, 'While made from overly familiar ingredients, Drew Barrymore''s directorial debut has enough charm, energy, and good-natured humor to transcend its many cliches.', TO_DATE('2009-09-14', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whiplash', 2014, 'Intense, inspiring, and well-acted, Whiplash is a brilliant sophomore effort from director Damien Chazelle and a riveting vehicle for stars J.K. Simmons and Miles Teller.', TO_DATE('2014-01-17', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whipped', 2000, 'The sex jokes in Whipped are tiresomely vulgar and unfunny. Critics also condemn the movie as cynical and mean-spirited, with no likable characters.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whiskey tango foxtrot', 2016, 'While WTF is far from FUBAR, Tina Fey and Martin Freeman are just barely enough to overcome the picture''s glib predictability and limited worldview.', TO_DATE('2016-02-28', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('white bird in a blizzard', 2014, 'Part suburban thriller, part sexual awakening drama -- and fully convincing as neither -- White Bird in a Blizzard rests a little too heavily on Shailene Woodley''s typically superlative work.', TO_DATE('2014-01-21', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('white boy rick', 2018, 'Solid work from the cast - particularly a scene-stealing Matthew McConaughey - helps White Boy Rick make up for a number of missed opportunities in the script.', TO_DATE('2018-09-01', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('white chicks', 2004, 'Scattershot comedy that''s silly and obvious.', TO_DATE('2004-06-18', 'YYYY-MM-DD'), 15.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the white countess', 2005, 'High production values and fine performances get bogged down by a lifeless story that fails to engage the viewer.', TO_DATE('2005-11-14', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('white god', 2014, 'White God isn''t an easy watch, but its soaring ambition and powerful acting -- human and canine alike -- make it well worth the effort.', TO_DATE('2014-05-18', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('white heat', 2000, 'Raoul Walsh''s crime drama goes further into the psychology of a gangster than most fear to tread and James Cagney''s portrayal of the tragic anti-hero is constantly volatile.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('white house down', 2013, 'White House Down benefits from the leads'' chemistry, but director Roland Emmerich smothers the film with narrative clichés and choppily edited action.', TO_DATE('2013-06-25', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('white hunter black heart', 2000, 'White Hunter Black Heart is powerful, intelligent, and subtly moving, a fascinating meditation on masculinity and the insecurities of artists.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('white material', 2009, 'Isabelle Huppert is an immoveable object surrounded by unstoppable forces in White Material, an incendiary character study and political thriller that showcases director Claire Denis'' expertise in ratcheting tension.', TO_DATE('2009-10-09', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('white men cant jump', 2000, 'White Men Can''t Jump provides a fresh take on the sports comedy genre, with a clever script and a charismatic trio of leads.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('white noise', 2005, 'While there are some built-in scares, the movie is muddled and unsatisfying.', TO_DATE('2005-01-04', 'YYYY-MM-DD'), 7.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('white oleander', 2002, 'Strong performances by the lead actresses make White Oleander a compelling female melodrama.', TO_DATE('2002-08-30', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the white ribbon das weisse band', 2009, 'The White Ribbon effectively utilizes tension and a bleak atmosphere to deliver a thought-provoking examination of nascent fascism.', TO_DATE('2009-05-22', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('white squall', 1996, 'Though it gets occasionally bogged down by touchy-feely sentiment, White Squall benefits greatly from Jeff Bridges'' assured lead performance and Ridley Scott''s visceral, exciting direction.', TO_DATE('1996-02-02', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whitey united states of america v james j bulger', 2014, 'An admirable yet incomplete effort to cover a sprawling subject, Whitey: United States of America v. James J. Bulger will leave viewers wanting more -- in good ways as well as bad.', TO_DATE('2014-01-23', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whitney', 2018, 'Whitney shifts from soaring highs to heartbreaking lows with palpable emotion and grace befitting its singular subject.', TO_DATE('2018-05-17', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('who killed nancy', 2009, 'The titular question remains unanswered. We still don''t know after this inconclusive, and shallow investigation into the seedier depths of Punk.', TO_DATE('2009-02-05', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('who framed roger rabbit', 1988, 'Who Framed Roger Rabbit is an innovative and entertaining film that features a groundbreaking mix of live action and animation, with a touching and original story to boot.', TO_DATE('1988-06-22', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('who killed the electric car', 2006, 'A searing indictment of big business and greed, Who Killed The Electric Car? is a well-tuned doc that simultaneously entertains and enrages.', TO_DATE('2006-01-26', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the whole nine yards', 2000, 'Despite a charming cast, The Whole Nine Yards can''t tickle funny bones consistently enough to distract from its sitcom-like story.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the whole ten yards', 2004, 'A strained, laugh-free sequel, The Whole Ten Yards recycles its predecessor''s cast and plot but not its wit or reason for being.', TO_DATE('2004-04-05', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whos afraid of virginia woolf', 2000, 'Led by a volcanic performance from Elizabeth Taylor, Who''s Afraid of Virginia Woolf? is a scathing adaptation of the Edward Albee play that serves as a brilliant calling card for debuting director Mike Nichols.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('whos your caddy', 2007, 'A juvenile, uninspired retread of Caddyshack, Who''s Your Caddy? is unoriginal, unfunny, and just plain forgettable.', TO_DATE('2007-07-27', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('why did i get married', 2007, 'Despite some poignant observations on modern marriages, Why Did I Get Married? is too preachy and melodramatic.', TO_DATE('2007-10-12', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('why did i get married too', 2010, 'It''s bolstered by a strong performance from Janet Jackson, but ultimately, Tyler Perry''s Why Did I Get Married Too? doesn''t add anything new to Perry''s melodramatic formula.', TO_DATE('2010-03-31', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('why do fools fall in love', 2000, 'This is a fun comedy with delightful musical numbers.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('why dont you just die papa sdokhni', 2018, 'As wickedly smart as it is energetic, Why Don''t You Just Die! should satisfy audiences in the mood for a gore-soaked good time.', TO_DATE('2018-12-13', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('why dont you play in hell', 2013, 'Deliriously manic and gleefully tasteless, Why Don''t You Play in Hell? delivers infectious genre fun.', TO_DATE('2013-08-30', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('why him', 2016, 'Solidly cast but overall misconceived, Why Him? offers the odd chuckle, but ultimately adds disappointingly little to its tired father-vs.-fiancé formula.', TO_DATE('2016-12-12', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wicker park', 2004, 'Implausible coincidences and an overly convoluted structure make the movie hard to follow or believe.', TO_DATE('2004-06-12', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the widow of saintpierre the widow of st pierre la veuve de saintpierre', 2001, 'Critics are impressed with The Widow of St. Pierre''s intriguing story and beautiful cinematography.', TO_DATE('2001-01-31', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('widows', 2018, 'Widows rounds up a stellar ensemble for a heist thriller that mixes popcorn entertainment with a message - and marks another artistic leap for director Steve McQueen.', TO_DATE('2018-09-09', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wienerdog', 2016, 'For filmgoers predisposed to enjoy Todd Solondz'' brand of black comedy, Wiener-Dog won''t disappoint -- but those put off by previous works need not apply.', TO_DATE('2016-01-23', 'YYYY-MM-DD'), 74.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wild', 2014, 'Powerfully moving and emotionally resonant, Wild finds director Jean-Marc Vallée and star Reese Witherspoon working at the peak of their respective powers.', TO_DATE('2014-08-31', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wild america', 2000, 'Wild America has the appearance of an old-school wilderness adventure, but lacks an involving story to anchor all the outdoor action.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wild bill', 1996, 'Crowded with talent on either side of the camera, Wild Bill shoots itself in the foot with a surprisingly muddled take on the story of the titular folk hero.', TO_DATE('1996-06-01', 'YYYY-MM-DD'), 44.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wild hogs', 2007, 'Wild Hogs is a dreadful combination of fish-out-of-water jokes, slapstick, and lazy stereotypes.', TO_DATE('2007-02-23', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wild parrots of telegraph hill', 2004, 'Interesting and appealing as both a study of man and nature.', TO_DATE('2004-12-23', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wild rose', 2018, 'There''s no shortage of star-is-born stories, but Wild Rose proves they can still be thoroughly entertaining -- and marks its own transcendent moment for lead Jessie Buckley.', TO_DATE('2018-09-09', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wild strawberries', 2000, 'Wild Strawberries were never so bittersweet as Ingmar Bergman''s beautifully written and filmed look at one man''s nostalgic journey into the past.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wild tales', 2014, 'Wickedly hilarious and delightfully deranged, Wild Tales is a subversive satire that doubles as a uniformly entertaining anthology film.', TO_DATE('2014-05-19', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wild target', 2010, 'An ineptly staged farce that dishonors the original film and squanders the comedic potential of its fine actors.', TO_DATE('2010-06-16', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wild things', 1998, 'Wild Things is a delightfully salacious, flesh-exposed romp that also requires a high degree of love for trash cinema.', TO_DATE('1998-03-20', 'YYYY-MM-DD'), 62.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wild thornberrys movie', 2002, 'The Wild Thornberrys Movie brings its beloved clan to the big screen for an animated adventure that should prove entertaining for all ages.', TO_DATE('2002-09-27', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('vince vaughns wild west comedy show 30 days 30 nights hollywood to the heartland', 2006, 'Vince Vaughn''s Wild West Comedy Show has some entertaining moments, but is a mostly hit-and-miss documentary.', TO_DATE('2006-09-12', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wild wild west', 2000, 'Bombastic, manic, and largely laugh-free, Wild Wild West is a bizarre misfire in which greater care was lavished upon the special effects than on the script.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wilde', 1998, 'Wilde can''t hope to communicate the entirety of its subject''s fascinating life or outsize talent, but Stephen Fry''s stellar performance offers abundant compensation.', TO_DATE('1998-05-01', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wildlife', 2018, 'Wildlife''s portrait of a family in crisis is beautifully composed by director Paul Dano -- and brought brilliantly to life by a career-best performance from Carey Mulligan.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wildling', 2018, 'Wildling''s feminist themes - and the ferocious Bel Powley performance that brings them to life - are often enough to make up for its narrative deficiencies.', TO_DATE('2018-03-13', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('willard', 2003, 'In this creepy story of a man and his rodents, Glover seems born to play the oddball title character.', TO_DATE('2003-03-07', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('romeo juliet', 2000, 'Baz Luhrmann''s visual aesthetic is as divisive as it is fresh and inventive.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('willow', 1988, 'State-of-the-art special effects and an appealing performance from Warwick Davis can''t quite save Willow from its slow pace and generic story.', TO_DATE('1988-05-20', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('willow creek', 2013, 'Writer-director Bobcat Goldthwait''s first foray into horror doesn''t break any new ground, but it does wring fresh terror from a well-worn genre formula -- and offers a few nasty laughs in the bargain.', TO_DATE('2013-08-05', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('willy wonka and the chocolate factory', 2000, 'Willy Wonka and the Chocolate Factory is strange yet comforting, full of narrative detours that don''t always work but express the film''s uniqueness.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wilson', 2017, 'Woody Harrelson delivers a solid performance as Wilson''s titular grump, but the movie surrounding him can''t quite manage to make the character''s sour outlook consistently relatable.', TO_DATE('2017-01-22', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wimbledon', 2004, 'A predictable, bland rom-com, but Bettany proves to be an appealing lead.', TO_DATE('2004-03-21', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('win a date with tad hamilton', 2004, 'Formulaic romantic comedy works better than it should thanks to a charming cast.', TO_DATE('2004-01-02', 'YYYY-MM-DD'), 54.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('win it all', 2017, 'Win It All finds writer-director Joe Swanberg working in a comparatively mainstream vein -- and striking another collaborative spark with leading man Jake Johnson.', TO_DATE('2017-03-12', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('win win', 2011, 'Rich, wonderful characters and strong performances populate Win Win, with writer/director Thomas McCarthy continuing to emerge as a great American humanist.', TO_DATE('2011-01-23', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('winchester', 2018, 'Like a grand staircase within the famous mansion that inspired it, Winchester appears poised to get a rise out of audiences, but ultimately leads nowhere.', TO_DATE('2018-02-02', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wind chill', 2007, 'Wind Chill is a ghost story with a clunky and unpolished script that fails to keep viewers in suspense.', TO_DATE('2007-04-27', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wind river', 2017, 'Wind River lures viewers into a character-driven mystery with smart writing, a strong cast, and a skillfully rendered setting that delivers the bitter chill promised by its title.', TO_DATE('2017-01-22', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wind that shakes the barley', 2006, 'Bleak and uncompromising, but director Ken Loach brightens his film with gorgeous cinematography and tight pacing, and features a fine performance from Cillian Murphy.', TO_DATE('2006-05-18', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the windmill movie', 2008, 'A haunting hybrid of documentary and fiction, The Windmill Movie presents a thoroughly unique and utterly compelling glimpse of a filmmaker''s final days.', TO_DATE('2008-09-24', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('windtalkers', 2002, 'The action sequences are expertly staged. Windtalkers, however, sinks under too many clichés and only superficially touches upon the story of the code talkers.', TO_DATE('2002-04-09', 'YYYY-MM-DD'), 33.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wine country', 2019, 'Wine Country''s comedy might not be quite as robust as fans of this ensemble will expect, but it''s got sweetness on the nose and a nicely balanced finish.', TO_DATE('2019-05-07', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wing commander', 1999, 'The low budget may explain Wing Commander''s cheesy special effects, but can''t excuse the lame dialogue or the movie''s obsessive reliance on sci-fi cliches.', TO_DATE('1999-03-12', 'YYYY-MM-DD'), 10.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('winged migration', 2002, 'A marvel to watch.', TO_DATE('2002-05-06', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wings', 1927, 'Subsequent war epics may have borrowed heavily from the original Best Picture winner, but they''ve all lacked Clara Bow''s luminous screen presence and William Wellman''s deft direction.', TO_DATE('1927-08-12', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wings of desire', 2000, 'Beyond ravishing, Wings of Desire is Wim Wenders'' is aching and heartbreaking exploration of how love makes us human.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wings of the dove', 1997, 'The Wings of the Dove patiently explores class divisions in early 20th century Europe through the well-written and beautifully acted travails of star-crossed lovers.', TO_DATE('1997-11-07', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('winnebago man', 2009, 'Though it doesn''t quite answer all of the questions it raises, Winnebago Man is nevertheless a fascinating, hilarious, and surprisingly poignant look at a geniunely colorful internet celebrity.', TO_DATE('2009-04-03', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('winnie mandela', 2011, 'Winnie Mandela takes few chances and delves only superficially into its subject''s life, making it feel more like a too-earnest made-for-TV movie than a proper biopic.', TO_DATE('2011-09-18', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('winnie the pooh', 2011, 'Short, nostalgic, and gently whimsical, Winnie the Pooh offers young audiences -- and their parents -- a sweetly traditional family treat.', TO_DATE('2011-04-01', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('winter in wartime', 2008, 'A gripping, handsomely shot World War II melodrama with thriller elements successfully mixed in.', TO_DATE('2008-11-17', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('winter passing', 2005, 'This dour coming-of-age story has nothing to distinguish it from similarly themed indie fare.', TO_DATE('2005-09-22', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('winter solstice', 2005, 'A deliberately paced, realistic portrait of a family''s grief and healing.', TO_DATE('2005-03-31', 'YYYY-MM-DD'), 60.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('winters tale', 2014, 'Winter''s Tale tries to retain the grandiose sweep of its source novel, but fails to fill it in with characters worth rooting for or a sensible plot.', TO_DATE('2014-02-10', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wise blood', 2000, 'Director John Huston and author Flannery O''Connor prove a formidable creative match in Wise Blood, a gothic satire anchored by Brad Dourif''s vinegary performance.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wish i was here', 2014, 'There''s no denying Wish I Was Here is heartfelt, but it covers narrative ground that''s already been well trod -- particularly by director Zach Braff''s previous features.', TO_DATE('2014-01-18', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wish upon', 2017, 'Wish Upon is neither scary nor original, but its fundamental flaws as a horror movie may make it destination viewing for after-midnight camp genre enthusiasts.', TO_DATE('2017-07-13', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wish you were here', 2012, 'Smart, slick, and thrilling, Wish You Were Here benefits from a compelling mystery at the center of its tightly wound plot, as well as strong performances from a cast that includes Joel Edgerton.', TO_DATE('2012-01-20', 'YYYY-MM-DD'), 71.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wishmaster', 1997, 'Wishmaster searches for horror in the exploits of a supernatural being -- one whose powers, alas, evidently do not include the ability to summon a compelling script.', TO_DATE('1997-06-01', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the witches of eastwick', 2000, 'A wickedly funny tale of three witches and their duel with the Devil, fuelled by some delicious fantasy and arch comedic performances.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('witching and bitching', 2013, 'Dark, nasty, and delightfully subversive, Witching and Bitching is gross-out genre fun with a heaping helping of warped comedy for good measure.', TO_DATE('2013-09-23', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('with a friend like harry', 2000, 'A darkly funny thriller that''s reminiscent of Hitchcock.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 96.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('with honors', 1994, 'While it''s admittedly well-meaning, With Honors handles its themes in strictly remedial fashion.', TO_DATE('1994-04-29', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('withnail and i', 2000, 'Richard E. Grant and Paul McGann prove irresistibly hilarious as two misanthropic slackers in Withnail and I, a biting examination of artists living on the fringes of prosperity and good taste.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('without a paddle', 2004, 'Without a Paddle has a few laughs, but not enough to sustain its running time.', TO_DATE('2004-08-06', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('without limits', 1998, 'This drama about American track star and hero Steve Prefontaine intelligently looks at the character of this oft mythologized athlete and features a fantastic performance by Donald Sutherland as Prefontaine''s trainer.', TO_DATE('1998-09-11', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('witless protection', 2008, 'Larry the Cable Guy continues his critical losing streak with this insipid, tasteless caper comedy.', TO_DATE('2008-02-22', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wiz', 2000, 'This workmanlike movie musical lacks the electricity of the stage version (and its cinematic inspiration), but it''s bolstered by strong performances by Diana Ross and Michael Jackson.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wizards', 2000, 'Its central metaphor is a bit too on the nose, but Wizards is an otherwise psychedelic, freaky trip into an alternate version of our world.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wolf creek', 2005, 'Though Wolf Creek is effectively horrific, it is still tasteless exploitation.', TO_DATE('2005-02-04', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wolf creek 2', 2014, 'After a strong start, Wolf Creek 2 devolves into an unnecessary -- and disappointingly predictable -- sequel.', TO_DATE('2014-02-17', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wolf man', 2000, 'A handsomely told tale with an affecting performance from Lon Chaney, Jr., The Wolf Man remains one of the classics of the Universal horror stable.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wolf totem', 2015, 'As a visual experience, Wolf Totem boasts thrills that compensate for the significant narrative sacrifices made in bringing Jiang Rong''s novel to the screen.', TO_DATE('2015-09-02', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wolfen', 2002, 'Police procedural meets werewolf flick in Wolfen, a creepy creature feature with a surprisingly profound side.', TO_DATE('2002-01-27', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wolke neun cloud 9', 2009, 'A raw, intimate and emotional insight into romance for the superannuated featuring taboo-breaking insight into the sex-lives of the over 60s.', TO_DATE('2009-04-13', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('xmen origins wolverine', 2009, 'Though Hugh Jackman gives his all, he can''t help X-Men Origins: Wolverine overcome a cliche-ridden script and familiar narrative.', TO_DATE('2009-04-23', 'YYYY-MM-DD'), 37.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('woman in gold', 2015, 'Woman in Gold benefits from its talented leads, but strong work from Helen Mirren and Ryan Reynolds isn''t enough to overpower a disappointingly dull treatment of a fascinating true story.', TO_DATE('2015-02-09', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('woman of the year', 2000, 'In the first romantic comedy pairing of Tracy and Hepburn, the stars'' chemistry is off to a working start and the film''s sparkling comedy smooths out any rough patches.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('woman on top', 2000, 'Despite Penelope Cruz''s beauty and charm, the movie is too tepid to be a romance and too silly to be believable. And the movie is too eager to please with an ending that seems more like a cop out.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('woman thou art loosed', 2004, 'While Woman is a little less heavy-handed than other message movies, it still feels like an After School Special.', TO_DATE('2004-09-21', 'YYYY-MM-DD'), 51.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('a woman under the influence', 2000, 'Electrified by searing performances from Gena Rowlands and Peter Falk, A Woman Under the Influence finds pioneering independent filmmaker John Cassavetes working at his artistic peak.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('woman walks ahead', 2017, 'Woman Walks Ahead gets some extra mileage out of watchable work from Jessica Chastain and Michael Greyeyes, but uneven pacing and two-dimensional characters undermine their efforts.', TO_DATE('2017-09-11', 'YYYY-MM-DD'), 53.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('women art revolution', 2010, 'Though a tad messy in spots, !Women Art Revolution is a worthy chronicle of an influential art movement seldom explored or documented.', TO_DATE('2010-09-23', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('women in trouble', 2009, 'Sebastian Gutierrez certainly has an eye for the beauty of the female form, but Women in Trouble lacks a compelling script or point of view to go with its curvaceous visual appeal.', TO_DATE('2009-03-18', 'YYYY-MM-DD'), 29.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('women on the verge of a nervous breakdown mujeres al borde de un ataque de nervios', 2000, 'Women on the Verge of a Nervous Breakdown finds writer-director Pedro Almodóvar working in a distinctly feminist vein, with richly rewarding results.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wonder', 2017, 'Wonder doesn''t shy away from its bestselling source material''s sentiment, but this well-acted and overall winsome drama earns its tugs at the heartstrings.', TO_DATE('2017-11-12', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wonder boys', 2000, 'Michael Douglas and Tobey Maguire do wonders in this clever dark comedy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wonder park', 2019, 'Colorful and energetic but lacking a compelling story, Wonder Park is little more than a competently made diversion for very young viewers.', TO_DATE('2019-03-13', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wonder wheel', 2017, 'Wonder Wheel gathers a charming cast in an inviting period setting, but they aren''t enough to consistently breathe life into a Woody Allen project that never quite comes together.', TO_DATE('2017-10-13', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wonder woman', 2017, 'Thrilling, earnest, and buoyed by Gal Gadot''s charismatic performance, Wonder Woman succeeds in spectacular fashion.', TO_DATE('2017-05-29', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wonderland', 2003, 'A sordid and pointless movie with some good preformances.', TO_DATE('2003-09-04', 'YYYY-MM-DD'), 34.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wonderstruck', 2017, 'Wonderstruck''s efforts to juggle timelines and tonal shifts aren''t always smooth, but the end result still adds up to an emotional journey whose visual thrills live up to its title.', TO_DATE('2017-05-18', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wont back down', 2012, 'Despite the best efforts of its talented leads, Won''t Back Down fails to lend sufficient dramatic heft or sophistication to the hot-button issue of education reform.', TO_DATE('2012-09-26', 'YYYY-MM-DD'), 35.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wont you be my neighbor', 2018, 'Won''t You Be My Neighbor? takes a fittingly patient and honest look at the life and legacy of a television pioneer whose work has enriched generations.', TO_DATE('2018-01-22', 'YYYY-MM-DD'), 97.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the wood', 2000, 'A charming piece of work with believable characters.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('woodshock', 2017, 'Woodshock''s engages visually, but its half-baked premise is as underwhelming as it is unsatisfying.', TO_DATE('2017-09-03', 'YYYY-MM-DD'), 24.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the woodsman', 2004, 'Kevin Bacon''s performance as a pedophile who is trying to start fresh has drawn raves from critics, who have praised the Woodsman as compelling, creepy, complex and well-crafted.', TO_DATE('2004-02-02', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('woodstock 3 days of peace music', 1970, 'By documenting arguably the most renowned music festival in history, Woodstock: 3 Days of Peace & Music achieves the rare feat of capturing the unique spirit of its time.', TO_DATE('1970-03-26', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('woodstock three days that defined a generation', 2019, 'Woodstock: Three Days That Defined a Generation lives up to its title with an entertaining contextualization of the titular festival and its cultural impact.', TO_DATE('2019-04-26', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('word wars', 2004, 'Fascinating look inside the world of competitive Scrabble.', TO_DATE('2004-05-07', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wordplay', 2006, 'You see them hunched over with their brows furrowed, folded newspaper in hand as they attempt to complete the crossword puzzle. This may even describe you. This ingeniously edited documentary introduces viewers to some of the more dedicated fans of this solitary pastime, none more well-known the puzzle editor for the New York Times, Will Shortz. This underground world provides a surprising amount of crowd-pleasing entertainment and suspense, especially at the annual crossword tournament. Didn''t know there was one, did you?', TO_DATE('2006-01-23', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('words and pictures', 2014, 'While both talented performers in their own right, Juliette Binoche and Clive Owen are decidedly mismatched in Words and Pictures, and they aren''t done many favors by the movie''s awkwardly constructed screenplay.', TO_DATE('2014-02-21', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('working girl', 2000, 'A buoyant corporate Cinderella story, Working Girl has the right cast, right story, and right director to make it all come together.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 84.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('working man', 2019, 'A too-rare showcase for an ensemble of talented veteran actors, Working Man quietly builds into an absorbing -- and timely -- character study.', TO_DATE('2019-02-10', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('world war z', 2013, 'It''s uneven and diverges from the source book, but World War Z still brings smart, fast-moving thrills and a solid performance from Brad Pitt to the zombie genre.', TO_DATE('2013-06-02', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the world is not enough', 1999, 'Plagued by mediocre writing, uneven acting, and a fairly by-the-numbers plot, The World Is Not Enough is partially saved by some entertaining and truly Bond-worthy action sequences.', TO_DATE('1999-11-19', 'YYYY-MM-DD'), 52.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('world trade center', 2006, 'As a visually stunning tribute to lives lost in tragedy, World Trade Center succeeds unequivocally, and it is more politically muted than many of Stone''s other works.', TO_DATE('2006-07-18', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the worlds fastest indian', 2005, 'Overcomes its formulaic storyline thanks to Anthony Hopkins'' warm and endearing portrayal of an age-defying thrill seeker.', TO_DATE('2005-09-18', 'YYYY-MM-DD'), 82.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('would you rather', 2013, 'Though restrained by most torture porn standards, Would You Rather''s brilliant premise is ultimately harmed by its tendency towards blood and guts.', TO_DATE('2013-02-05', 'YYYY-MM-DD'), 59.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wounds', 2019, 'Wounds isn''t without its creepy-crawly charms, but they -- and the efforts of a talented cast -- get squished by a story that never quite gets completely under the skin.', TO_DATE('2019-01-27', 'YYYY-MM-DD'), 49.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wreckit ralph', 2012, 'Equally entertaining for both kids and parents old enough to catch the references, Wreck-It Ralph is a clever, colorful adventure built on familiar themes and joyful nostalgia.', TO_DATE('2012-10-24', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wrestling ernest hemingway', 2000, 'Predictable but moving, Wrestling Ernest Hemingway is an understated and melancholic drama that gets plenty of mileage out of an outstanding cast that includes Robert Duvall, Richard Harris, Shirley MacLaine, and Sandra Bullock.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wrinkles', 2012, 'Poignant and tender without succumbing to schmaltz, Wrinkles offers a thoughtful -- and beautifully animated -- look at old age.', TO_DATE('2012-03-01', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wristcutters a love story', 2006, 'Wristcutters: A Love Story sounds like a normal enough indie flick. Boy meets girl. Boy gets separated from girl. Boy goes on a road trip with friends to find girl and gains a new perspective on life. Except everybody''s dead.', TO_DATE('2006-01-24', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wrong', 2012, 'Wrong is strange and meandering, but its absurdist vignettes reveal a unique, wry wit.', TO_DATE('2012-01-22', 'YYYY-MM-DD'), 67.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wrong turn', 2003, 'An unremarkable slasher flick that fails to distinguished itself from others of its ilk.', TO_DATE('2003-05-29', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wrongfully accused', 1998, 'Wrongfully Accused of being a comedy worthy of Leslie Nielsen''s involvement, this misbegotten spoof might have fewer laughs than the straight-faced thriller that inspired it.', TO_DATE('1998-08-21', 'YYYY-MM-DD'), 21.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('wuthering heights', 2011, 'Director Andrea Arnold''s gritty, naturalistic re-imagining of the Emily Bronte classic stays true to the book''s spirit while utilizing an unconventional approach to explore the romantic yearning at the heart of the story.', TO_DATE('2011-09-06', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('x2 xmen united', 2003, 'Tightly scripted, solidly acted, and impressively ambitious, X2: X-Men United is bigger and better than its predecessor -- and a benchmark for comic sequels in general.', TO_DATE('2003-03-17', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the xfiles i want to believe the x files 2', 2008, 'The chemistry between leads David Duchovny and Gillian Anderson do live up to The X-Files'' televised legacy, but the roving plot and droning routines make it hard to identify just what we''re meant to believe in.', TO_DATE('2008-07-21', 'YYYY-MM-DD'), 31.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('xmen the last stand', 2006, 'X-Men: The Last Stand provides plenty of mutant action for fans of the franchise, even if it does so at the expense of its predecessors'' deeper character moments.', TO_DATE('2006-05-14', 'YYYY-MM-DD'), 57.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('xmen apocalypse', 2016, 'Overloaded action and a cliched villain take the focus away from otherwise strong performers and resonant themes, making X-Men: Apocalypse a middling chapter of the venerable superhero franchise.', TO_DATE('2016-05-09', 'YYYY-MM-DD'), 47.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('xmen days of future past', 2014, 'X-Men: Days of Future Past combines the best elements of the series to produce a satisfyingly fast-paced outing that ranks among the franchise''s finest installments.', TO_DATE('2014-05-12', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('xmen first class', 2011, 'With a strong script, stylish direction, and powerful performances from its well-rounded cast, X-Men: First Class is a welcome return to form for the franchise.', TO_DATE('2011-05-24', 'YYYY-MM-DD'), 86.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('xthe man with the xray eyes', 2001, 'By turns lurid and disturbing, The Man with the X-Ray Eyes is a compelling piece of sci-fi pulp and one of Roger Corman''s most effective movies.', TO_DATE('2001-06-27', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('xanadu', 2000, 'Not even spandex and over-the-top musical numbers can save Xanadu from questionable acting, unimpressive effects, and a story unencumbered by logic.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 27.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the xfiles fight the future', 2000, 'Results may vary for newcomers, but fans of the series will enjoy its big-screen transition.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('xmen', 2000, 'Faithful to the comics and filled with action, X-Men brings a crowded slate of classic Marvel characters to the screen with a talented ensemble cast and surprisingly sharp narrative focus.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 81.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('xx', 2017, 'XX''s array of distinct female filmmaking voices -- and the empowerment their collection represents -- offer enough thrills to make up for the overall uneven quality that plagues most anthology projects.', TO_DATE('2017-01-24', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('xxxy', 2002, 'The characters are both unsympathetic and uninteresting.', TO_DATE('2002-07-29', 'YYYY-MM-DD'), 43.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('xxx', 2002, 'It has an endearing lack of seriousness, and Vin Diesel has more than enough muscle for the starring role, but ultimately, XXX is a missed opportunity to breathe new life into the spy thriller genre.', TO_DATE('2002-08-01', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('xxx return of xander cage', 2017, 'xXx: Return of Xander Cage should satisfy fans of the first two installments, but its preponderance of set pieces can''t quite make up for a tired storyline that fails to take the franchise -- or action fans -- anywhere new.', TO_DATE('2017-01-13', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('xxx state of the union', 2005, 'Even more absurd and implausible than the first XXX movie, State of the Union is less inspired and technically competent than its predecessor.', TO_DATE('2005-04-18', 'YYYY-MM-DD'), 17.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('xxy', 2007, 'This sharp directorial debut by Lucia Puenzo treats the challenging subject of intersexuality with intelligence and sensitivity.', TO_DATE('2007-05-20', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('y tu mama tambien', 2001, 'A road movie that''s not only sexy, but intelligent as well.', TO_DATE('2001-07-17', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('yakuza apocalypse', 2015, 'Yakuza Apocalypse lives up to the oddball promise of its title with a cinematic whirlwind that represents director Takashi Miike at his most delightfully unhinged.', TO_DATE('2015-09-14', 'YYYY-MM-DD'), 61.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('yankee doodle dandy', 2000, 'James Cagney deploys his musical gifts to galvanizing effect in Yankee Doodle Dandy, a celebration of patriotic fervor as much as it is a biopic of George M. Cohan.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 90.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the yards', 2000, 'Featuring strong performances and direction, The Yards is a richly textured crime thriller with an authentic feel.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the year of living dangerously', 2000, 'Both a smart, suspenseful tale of intrigue and a sweeping romance, The Year of Living Dangerously features excellent performances from Mel Gibson and Sigourney Weaver as a pair of journalists covering political unrest in Indonesia.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('year of the dog', 2007, 'Year of the Dog is a warm and quirky comedy that never condescends to its eccentric characters.', TO_DATE('2007-01-21', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('year of the fish', 2007, 'This modernized and rotoscope-animated update on the Cinderella story is charming at times and visually impressive, but audiences may find it to be too coarse for children and too superficial for adults.', TO_DATE('2007-01-31', 'YYYY-MM-DD'), 58.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('year one', 2009, 'Year One is a poorly executed, slapdash comedy in which the talent both in front of and behind the camera never seem to be on the same page.', TO_DATE('2009-06-15', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('yella', 2007, 'Chilly and haunting, Yella''s atmosphere gets under the skin.', TO_DATE('2007-03-21', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('yes god yes', 2019, 'Natalia Dyer''s charming performance -- and writer-director Karen Maine''s sensitive work -- will leave audiences saying Yes, God, Yes to this coming-of-age dramedy.', TO_DATE('2019-03-09', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('yes man', 2008, 'Jim Carrey''s comic convulsions are the only bright spots in this otherwise dim and predictable comedy.', TO_DATE('2008-12-15', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the yes men', 2004, 'Shining a spotlight on activists as unorthodox as they are entertaining, The Yes Men proves advocating for social change can be seriously funny.', TO_DATE('2004-04-03', 'YYYY-MM-DD'), 85.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the yes men fix the world', 2009, 'The Yes Men aim their barbs at the capitalist fat-cats with gutsy and hilarious performance pranks.', TO_DATE('2009-02-12', 'YYYY-MM-DD'), 75.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('yesterday', 2019, 'Yesterday may fall short of fab, but the end result is still a sweetly charming fantasy with an intriguing -- albeit somewhat under-explored -- premise.', TO_DATE('2019-05-05', 'YYYY-MM-DD'), 63.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('yoga hosers', 2016, 'Undisciplined, unfunny, and bereft of evident purpose, Yoga Hosers represents a particularly grating low point in Kevin Smith''s once-promising career.', TO_DATE('2016-01-25', 'YYYY-MM-DD'), 23.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('yogi bear', 2010, 'Yogi Bear''s 3D effects and all-star voice cast are cold comfort for its aggressively mediocre screenplay.', TO_DATE('2010-12-13', 'YYYY-MM-DD'), 13.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('yojimbo', 2000, 'As effortlessly engaging as it is widely influential, Yojimbo represents Kurosawa at the peak of his powers -- and lays the groundwork for the modern American western.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('yonkers joe', 2008, 'A solid cast adds subtlety to this otherwise schmaltzy and sometimes awkward gambling-flick-cum-family-drama.', TO_DATE('2008-06-23', 'YYYY-MM-DD'), 55.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('yossi', 2012, 'Smart, moving, and deeply empathetic, Yossi is a thoughtful examination of love and grief.', TO_DATE('2012-11-27', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('you dont know jack', 2010, 'Led by strong direction from Barry Levinson and outstanding work from Al Pacino, You Don''t Know Jack makes compelling viewing out of real-life drama.', TO_DATE('2010-04-26', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('you again', 2010, 'You Again represents a rare opportunity to see some of Hollywood''s finest female veterans together onscreen - and, unfortunately, wastes their talents almost completely.', TO_DATE('2010-09-22', 'YYYY-MM-DD'), 19.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('you can count on me', 2000, 'You Can Count On Me may look like it belongs on the small screen, but the movie surprises with its simple yet affecting story. Beautifully acted and crafted, the movie will simply draw you in.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 95.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('you cannot kill david arquette', 2020, 'You Cannot Kill David Arquette -- nor can you deny the sheer watchability of this unusual and surprisingly affecting documentary.', TO_DATE('2020-08-25', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('you cant take it with you', 1938, 'It''s predictably uplifting fare from Frank Capra, perhaps the most consciously uplifting of all great American directors -- but thanks to immensely appealing performances and a nimble script, You Can''t Take It With You is hard not to love.', TO_DATE('1938-08-23', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('you dont mess with the zohan', 2008, 'You Don''t Mess With the Zohan features intermittent laughs, and will please Sandler diehards, but after awhile the leaky premise wears thin.', TO_DATE('2008-05-30', 'YYYY-MM-DD'), 38.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('you dont nomi', 2019, 'It may not change many minds regarding Showgirls, but You Don''t Nomi is a solidly entertaining postmortem of an infamous flop.', TO_DATE('2019-04-28', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('you got served', 2004, 'The dance sequences are exhilarating, but everything else about this movie is sloppy and generic.', TO_DATE('2004-01-28', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('you me and dupree', 2006, 'A rather generic entry into the arrested development subgenre, with themes borrowed from other more successful and funnier films. Dupree wears out its welcome.', TO_DATE('2006-07-07', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('you only live twice', 1967, 'With exotic locales, impressive special effects, and a worthy central villain, You Only Live Twice overcomes a messy and implausible story to deliver another memorable early Bond flick.', TO_DATE('1967-06-13', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('you should have left', 2020, 'You Should Have Left hints at a genuinely creepy experience, but never quite manages to distill its intriguing ingredients into a consistently satisfying whole.', TO_DATE('2020-06-18', 'YYYY-MM-DD'), 40.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('you were never really here', 2017, 'Bracingly elevated by a typically committed lead performance from Joaquin Phoenix, You Were Never Really Here confirms writer-director Lynne Ramsay as one of modern cinema''s most unique -- and uncompromising -- voices.', TO_DATE('2017-05-26', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('you will be my son', 2012, 'Niels Arestrup gives a powerful performance in this tale of familial tension that plays out like a taut, arresting thriller.', TO_DATE('2012-03-22', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('you will meet a tall dark stranger', 2010, 'It''s sporadically amusing, and typically well-cast, but You Will Meet a Tall Dark Stranger isn''t one of Woody Allen''s more inspired late-period efforts.', TO_DATE('2010-05-17', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('young adult', 2011, 'Despite its somewhat dour approach, Young Adult is a funny and ultimately powerful no-holds-barred examination of prolonged adolescence, thanks largely to a convincing performance by Charlize Theron.', TO_DATE('2011-10-25', 'YYYY-MM-DD'), 80.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('young beautiful jeune et jolie', 2013, 'Ozon may not explore his themes as fully as he should, but Young & Beautiful poses enough intriguing questions -- and features a strong enough performance from Marine Vacth -- to compensate for its frustrations.', TO_DATE('2013-05-16', 'YYYY-MM-DD'), 73.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the young black stallion', 2003, 'It may strike a chord with very young equine enthusiasts, but gorgeous cinematography isn''t enough to make up for The Young Black Stallion''s uninspired script.', TO_DATE('2003-12-20', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('young einstein', 2000, 'Young Einstein suggests Yahoo Serious could be an effective leading man in the right comedic setting -- but this disappointingly uneven outing isn''t it.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 36.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('young frankenstein', 2000, 'Made with obvious affection for the original, Young Frankenstein is a riotously silly spoof featuring a fantastic performance by Gene Wilder.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 94.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('young guns', 2000, 'Young Guns rounds up a posse of attractive young leads, but this cheerfully shallow Brat Pack Western ultimately has too much hat and not enough cattle.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 41.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('young mr lincoln', 2003, 'Young Mr. Lincoln smartly sidesteps the grandeur of the 16th president''s historical significance and instead hones in on his modest decency, powerfully embodied by Henry Fonda.', TO_DATE('2003-05-20', 'YYYY-MM-DD'), 100.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('young ones', 2014, 'Visually compelling but narratively barren, Young Ones adds little to the dystopian Western genre.', TO_DATE('2014-01-19', 'YYYY-MM-DD'), 50.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('young sherlock holmes', 1985, 'Young Sherlock Holmes is a charming, if unnecessarily flashy, take on the master sleuth.', TO_DATE('1985-12-01', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('the young victoria', 2009, 'Emily Blunt shines as Victoria in this romantic but plodding royal portrait.', TO_DATE('2009-02-06', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('youngheart', 2008, 'Full of endearing characters, this doc about a choir of "seniors behaving badly" is uplifting and delightful.', TO_DATE('2008-01-17', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('your friends neighbors', 2000, 'Though it may strike some viewers as cold and unpleasant, Neil LaBute''s Your Friends & Neighbors is an incisive critique of sexual politics wrapped up in a scathing black comedy.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 77.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('your highness', 2011, 'Big budgets and costumes in service of scatalogical jokes may seem funny on paper, but in execution this is a highly monotonous romp that registers only occasional laughs.', TO_DATE('2011-03-30', 'YYYY-MM-DD'), 28.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('your mommy kills animals', 2007, 'A thoroughly fascinating, well-presented examination of the animal rights debate that is both provocative and thought-provoking.', TO_DATE('2007-04-03', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('your name kimi no na wa', 2016, 'As beautifully animated as it is emotionally satisfying, Your Name adds another outstanding chapter to writer-director Makoto Shinkai''s filmography.', TO_DATE('2016-08-31', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('your sisters sister', 2011, 'Superbly acted and satisfyingly engaging, Your Sister''s Sister subverts rom-com conventions with sensitive direction, an unconventional screenplay, and a big heart.', TO_DATE('2011-09-13', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('youre next', 2011, 'You''re Next''s energetic and effective mix of brutal gore and pitch black humor will please horror buffs and beyond.', TO_DATE('2011-10-01', 'YYYY-MM-DD'), 78.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('youre not you', 2014, 'Despite the best efforts of its two talented female leads, You''re Not You is not a consistently satisfying adaptation of its source material.', TO_DATE('2014-10-06', 'YYYY-MM-DD'), 48.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('yours mine ours', 2005, 'The initial set-up is unbelievable, the plotting is predictable and stale, and the comedy depends on repetitive pratfalls that soon get old.', TO_DATE('2005-11-20', 'YYYY-MM-DD'), 6.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('youssou ndour i bring what i love', 2009, 'It never gets close enough to its subject, and it''s curiously light on music, but this documentary is nonetheless a long-overdue tribute to a brilliant musician.', TO_DATE('2009-06-03', 'YYYY-MM-DD'), 83.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('youth', 2015, 'Gorgeously filmed and beautifully acted, Youth offers an enticing -- albeit flawed -- opportunity to witness an impressive array of seasoned veterans combining their cinematic might.', TO_DATE('2015-08-27', 'YYYY-MM-DD'), 72.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('youth in revolt', 2009, 'It may not entirely do its source material justice, but Miguel Arteta''s Youth in Revolt is a fun, funny comic romp that lets Michael Cera stretch a little and introduces filmgoers to a major find in Portia Doubleday.', TO_DATE('2009-09-14', 'YYYY-MM-DD'), 66.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('youth without youth', 2007, 'Although visually appealing, Coppola''s latest film mixes too many genres with a very confusing plot.', TO_DATE('2007-10-19', 'YYYY-MM-DD'), 32.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('youve got mail', 2000, 'Great chemistry between the leads made this a warm and charming delight.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 70.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('yugioh the movie', 2004, 'Don''t watch the TV show or play the card game? Then this movie is not for you.', TO_DATE('2004-08-10', 'YYYY-MM-DD'), 5.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('z', 1969, 'Powerfully effective, this anti-fascist political thriller stands out as both high-conscience melodrama and high-tempo action movie.', TO_DATE('1969-02-26', 'YYYY-MM-DD'), 93.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('z for zachariah', 2015, 'Z for Zachariah wrings compelling drama out of its simplistic premise -- albeit at a pace that may test the patience of less contemplative viewers.', TO_DATE('2015-01-24', 'YYYY-MM-DD'), 79.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zardoz', 2000, 'Zardoz is ambitious and epic in scope, but its philosophical musings are rendered ineffective by its supreme weirdness and rickety execution.', TO_DATE('2000-01-01', 'YYYY-MM-DD'), 45.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zathura a space adventure', 2005, 'Dazzling special effects for the kids + well-crafted storytelling for the ''rents = cinematic satisfaction for the whole family.', TO_DATE('2005-10-10', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zatôichi the blind swordsman zatoichi', 2003, 'Colorful, rich with action and wonderfully choreographed, Takeshi Kitano takes on the classic samurai character with his own brand of cinematic flair.', TO_DATE('2003-09-20', 'YYYY-MM-DD'), 87.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zaytoun', 2012, 'It has a lot on its mind, including a timely storyline with real-world significance; unfortunately, Zaytoun''s reach exceeds its grasp, partly due to the presence of a miscast Stephen Dorff.', TO_DATE('2012-10-14', 'YYYY-MM-DD'), 46.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zero charisma', 2013, 'Zero Charisma takes a refreshingly empathetic -- and often quite funny -- look at characters historically marginalized as one-dimensional archetypes.', TO_DATE('2013-03-15', 'YYYY-MM-DD'), 76.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zero dark thirty', 2012, 'Gripping, suspenseful, and brilliantly crafted, Zero Dark Thirty dramatizes the hunt for Osama bin Laden with intelligence and an eye for detail.', TO_DATE('2012-11-26', 'YYYY-MM-DD'), 91.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zero days', 2016, 'Factors beyond Gibney''s control prevent Zero Days from offering a comprehensive look at its subject, but the partial picture that emerges remains as frightening as it is impossible to ignore.', TO_DATE('2016-02-17', 'YYYY-MM-DD'), 92.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zero effect', 1997, 'A promising debut for writer/director Jake Kasdan, Zero Effect overcomes its flaws with its off-kilter humor and likeable leads.', TO_DATE('1997-06-01', 'YYYY-MM-DD'), 65.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zero motivation', 2014, 'Darkly funny and understatedly absurd, Zero Motivation is a refreshing addition to the canon of irreverent war comedies -- and an intriguing calling card for writer-director Talya Lavie.', TO_DATE('2014-04-23', 'YYYY-MM-DD'), 88.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zerophilia', 2005, 'Zerophilia has some intriguing ideas, but they''re imparted with a frustrating lack of wit, daring, or valuable insight.', TO_DATE('2005-10-26', 'YYYY-MM-DD'), 25.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zipper', 2015, 'Patrick Wilson tries his best to elevate tawdry material, but Zipper is a morality tale that makes its points so clumsily that they inspire more unintentional laughter than thought.', TO_DATE('2015-01-28', 'YYYY-MM-DD'), 20.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zodiac', 2007, 'A quiet, dialogue-driven thriller that delivers with scene after scene of gut-wrenching anxiety. David Fincher also spends more time illustrating nuances of his characters and recreating the mood of the 70s than he does on gory details of murder.', TO_DATE('2007-02-17', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zombeavers', 2014, 'Zombeavers obviously isn''t high art, but it delivers just enough of the gory insanity promised by the title to earn a recommendation for genre fans.', TO_DATE('2014-04-26', 'YYYY-MM-DD'), 69.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zombie zombi 2', 2002, 'Zombi 2 is an absurdly graphic zombie movie legendary for some gory scenes and nothing in between.', TO_DATE('2002-07-25', 'YYYY-MM-DD'), 42.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zombie for sale', 2019, 'An auspicious feature debut for director Lee Min-jae, Zombie for Sale puts a light yet surprisingly poignant spin on predictable genre formula.', TO_DATE('2019-02-01', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zombie strippers', 2008, 'Though intentionally campy, Zombie Strippers suffers from poor execution, and never rises above its silly premise.', TO_DATE('2008-04-07', 'YYYY-MM-DD'), 39.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zombieland', 2009, 'Wickedly funny and featuring plenty of gore, Zombieland is proof that the zombie subgenre is far from dead.', TO_DATE('2009-09-14', 'YYYY-MM-DD'), 89.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zombieland double tap', 2019, 'Zombieland: Double Tap makes up for a lack of fresh brains with an enjoyable reunion that recaptures the spirit of the original and adds a few fun twists.', TO_DATE('2019-10-16', 'YYYY-MM-DD'), 68.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zookeeper', 2011, 'Zookeeper smothers Kevin James''s with a sodden script and a surfeit of jokes inappropriate for the young viewers who would be intrigued by its juvenile storyline.', TO_DATE('2011-07-06', 'YYYY-MM-DD'), 14.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zoolander', 2001, 'A wacky satire on the fashion industry, Zoolander is one of those deliberately dumb comedies that can deliver genuine laughs.', TO_DATE('2001-09-26', 'YYYY-MM-DD'), 64.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zoolander 2', 2016, 'Zoolander No. 2 has more celebrity cameos than laughs -- and its meager handful of memorable gags outnumbers the few worthwhile ideas discernible in its scattershot rehash of a script.', TO_DATE('2016-01-26', 'YYYY-MM-DD'), 22.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zoom', 2006, 'Lacking the punch and good cheer of The Incredibles and Sky High, Zoom is a dull and laugh-free affair.', TO_DATE('2006-08-11', 'YYYY-MM-DD'), 4.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zootopia', 2016, 'The brilliantly well-rounded Zootopia offers a thoughtful, inclusive message that''s as rich and timely as its sumptuously state-of-the-art animation -- all while remaining fast and funny enough to keep younger viewers entertained.', TO_DATE('2016-02-12', 'YYYY-MM-DD'), 98.0);
INSERT INTO rt_reviews (norm_title, year, critics_consensus, review_date, tomatometer_rating) VALUES ('zulu', 1964, 'Zulu patiently establishes a cast of colorful characters and insurmountable stakes before unleashing its white-knuckle spectacle, delivering an unforgettable war epic in the bargain.', TO_DATE('1964-06-17', 'YYYY-MM-DD'), 96.0);
